ALTER PROCEDURE RECOSTRUIR_INDEX AS 
declare variable INDEX_NAME varchar(31);
BEGIN
 FOR SELECT R.RDB$INDEX_NAME
 FROM RDB$INDICES R
 WHERE R.RDB$SYSTEM_FLAG <> 1
 INTO :INDEX_NAME DO
  BEGIN
    EXECUTE STATEMENT 'ALTER INDEX '  || :INDEX_NAME || ' ACTIVE;';
  END
END ^

ALTER PROCEDURE SOMAREGISTROS RETURNS (TABELA VARCHAR(31) CHARACTER SET NONE,
QTD_REG INTEGER)
AS 
declare variable COMANDO varchar(100);
declare variable QTDTOT integer;
declare variable QTDTAB integer;
begin 
 qtdtot = 0; 
 qtdtab = 0;


 for select rdb$relation_name 
   from rdb$relations 
   where rdb$flags = 1 and rdb$view_blr is null 
   order by 1 
   into :tabela do 
 begin 
   qtdtab = qtdtab + 1;
   comando = 'select count(*) from ' || :tabela; 
   execute statement :comando into :qtd_reg; 
   qtdtot = :qtdtot + :qtd_reg; 
   suspend; 
 end 
 tabela = :qtdtab || ' Tabelas - Total:'; 
 qtd_reg = :qtdtot; 
 suspend; 
end ^

ALTER PROCEDURE SP_ABCFARMA_ATUALIZA RETURNS (ID_PRODUTO DOUBLE PRECISION,
EAN VARCHAR(14) CHARACTER SET NONE,
REGISTRO_ANVISA VARCHAR(13) CHARACTER SET NONE,
GGREM VARCHAR(15) CHARACTER SET NONE,
NOME VARCHAR(50) CHARACTER SET NONE,
DESCRICAO VARCHAR(45) CHARACTER SET NONE,
COMPOSICAO VARCHAR(254) CHARACTER SET NONE,
QTD_EMBALAGEM NUMERIC(3, 0),
PF_20 NUMERIC(15, 2),
PMC_20 NUMERIC(15, 2),
PF_18 NUMERIC(15, 2),
PMC_18 NUMERIC(15, 2),
PF_17 NUMERIC(15, 2),
PMC_17 NUMERIC(15, 2),
PF_17_5 NUMERIC(15, 2),
PMC_17_5 NUMERIC(15, 2),
PF_12 NUMERIC(15, 2),
PMC_12 NUMERIC(15, 2),
PF_0 NUMERIC(15, 2),
PMC_0 NUMERIC(15, 2),
PERCENTUAL_IPI NUMERIC(15, 2),
DATA_VIGENCIA DATE,
NOVO VARCHAR(1) CHARACTER SET NONE,
VARIACAO_PRECO VARCHAR(1) CHARACTER SET NONE,
PF_17_ALC NUMERIC(15, 2),
PMC_17_ALC NUMERIC(15, 2),
PF_17_5_ALC NUMERIC(15, 2),
PMC_17_5_ALC NUMERIC(15, 2),
PF_18_ALC NUMERIC(15, 2),
PMC_18_ALC NUMERIC(15, 2),
NCM VARCHAR(10) CHARACTER SET NONE,
ID_TARJA VARCHAR(2) CHARACTER SET NONE,
CLASSE_TERAPEUTICA VARCHAR(100) CHARACTER SET NONE,
PORTARIA_344_98 VARCHAR(2) CHARACTER SET NONE,
PRODUTO_REFERENCIA VARCHAR(50) CHARACTER SET NONE,
CAS VARCHAR(90) CHARACTER SET NONE,
DCB VARCHAR(240) CHARACTER SET NONE,
ATC_CODE VARCHAR(7) CHARACTER SET NONE,
CAP VARCHAR(1) CHARACTER SET NONE,
CONFAZ_87 VARCHAR(1) CHARACTER SET NONE,
TISS_TUSS VARCHAR(8) CHARACTER SET NONE,
CEST VARCHAR(9) CHARACTER SET NONE,
ID_FABRICANTE NUMERIC(15, 0),
NOME_FABRICANTE VARCHAR(30) CHARACTER SET NONE,
ID_LCCT VARCHAR(1) CHARACTER SET NONE,
DESCRICAO_LISTA VARCHAR(15) CHARACTER SET NONE,
ID_REGIME_PRECO VARCHAR(1) CHARACTER SET NONE,
DESCRICAO_REGIME_PRECO VARCHAR(30) CHARACTER SET NONE,
ID_TIPO_PRODUTO VARCHAR(1) CHARACTER SET NONE,
DESCRICAO_TIPO_PRODUTO VARCHAR(20) CHARACTER SET NONE)
AS 
declare variable CDCB varchar(90);
declare variable CBARRA varchar(13);
declare variable CMEDLAB varchar(6);
declare variable CNOME varchar(45);
declare variable CDPRODUTO varchar(9);
BEGIN
  DELETE FROM ABCFARMA;
  FOR SELECT ID_PRODUTO,EAN,REGISTRO_ANVISA,GGREM,NOME,DESCRICAO,COMPOSICAO,QTD_EMBALAGEM,PF_20,PMC_20,PF_18,PMC_18,
             PF_17,PMC_17,PF_17_5,PMC_17_5,PF_12,PMC_12,PF_0,PMC_0,PERCENTUAL_IPI,DATA_VIGENCIA,NOVO,VARIACAO_PRECO,
             PF_17_ALC,PMC_17_ALC,PF_17_5_ALC,PMC_17_5_ALC,PF_18_ALC,PMC_18_ALC,NCM,ID_TARJA,CLASSE_TERAPEUTICA,
             PORTARIA_344_98,PRODUTO_REFERENCIA,CAS,DCB,ATC_CODE,CAP,CONFAZ_87,TISS_TUSS,CEST,ID_FABRICANTE,NOME_FABRICANTE,
             ID_LCCT,DESCRICAO_LISTA,ID_REGIME_PRECO,DESCRICAO_REGIME_PRECO,ID_TIPO_PRODUTO,DESCRICAO_TIPO_PRODUTO
      FROM ABCFARMA_NOVO
      ORDER BY ABCFARMA_NOVO.ID_PRODUTO
      INTO :ID_PRODUTO,:EAN,:REGISTRO_ANVISA,:GGREM,:NOME,:DESCRICAO,
           :COMPOSICAO,:QTD_EMBALAGEM,:PF_20,:PMC_20,:PF_18,:PMC_18,:PF_17,
           :PMC_17,:PF_17_5,:PMC_17_5,:PF_12,:PMC_12,:PF_0,:PMC_0,
           :PERCENTUAL_IPI,:DATA_VIGENCIA,:NOVO,:VARIACAO_PRECO,
           :PF_17_ALC,:PMC_17_ALC,:PF_17_5_ALC,:PMC_17_5_ALC,:PF_18_ALC,
           :PMC_18_ALC,:NCM,:ID_TARJA,:CLASSE_TERAPEUTICA,:PORTARIA_344_98,
           :PRODUTO_REFERENCIA,:CAS,:DCB,:ATC_CODE,:CAP,:CONFAZ_87,
           :TISS_TUSS,:CEST,:ID_FABRICANTE,:NOME_FABRICANTE,:ID_LCCT,
           :DESCRICAO_LISTA,:ID_REGIME_PRECO,:DESCRICAO_REGIME_PRECO,
           :ID_TIPO_PRODUTO,:DESCRICAO_TIPO_PRODUTO
  DO
  BEGIN
  CDPRODUTO = REPLACE(LPAD(CAST(ID_PRODUTO AS INT),9,'0'), '.', '');
  CMEDLAB = REPLACE(LPAD(CAST(ID_FABRICANTE AS INT),6,'0'), '.', '');
  CBARRA = SUBSTRING(EAN FROM 1 FOR 13);
  CDCB = SUBSTRING(DCB FROM 1 FOR 90);
  CNOME = SUBSTRING(NOME FROM 1 FOR 45);
  INSERT INTO ABCFARMA (
    MED_ABC,MED_CTR,MED_LAB,LAB_NOM,MED_DES,MED_APR,MED_PLA20,MED_PCO20,
    MED_FRA20,MED_PLA18,MED_PCO18,MED_FRA18,MED_PLA17,MED_PCO17,MED_FRA17,
    MED_PLA175,MED_PCO175,MED_FRA175,MED_PLA12,MED_PCO12,MED_FRA12,MED_PLA0,
    MED_PCO0,MED_FRA0,MED_PLAZ18,MED_PCOZ18,MED_FRAZ18,MED_PLZ175,MED_PCZ175,
    MED_FRZ175,MED_PLAZ17,MED_PCOZ17,MED_FRAZ17,MED_UNI,MED_IPI,MED_DTVIG,
    EXP_13,MED_VARPRE,MED_BARRA,MED_REGIMS,MED_REF,MED_TIPMED,MED_NEGPOS,
    MED_NCM,MED_DCB,MED_CAS,MED_PRINCI,MED_ATC,MED_CLATER,MED_TARJA,
    MED_POR344,MED_TISS,MED_CONF87,MED_CAP)
  VALUES (
    :CDPRODUTO,:ID_REGIME_PRECO,:CMEDLAB,:NOME_FABRICANTE,:CNOME,:DESCRICAO,:PF_20,:PMC_20,0,:PF_18,:PMC_18,0,:PF_17,:PMC_17,0,:PF_17_5,:PMC_17_5,
    0,:PF_12,:PMC_12,0,:PF_0,:PMC_0,0,:PF_18_ALC,:PMC_18_ALC,0,:PF_17_5_ALC,:PMC_17_5_ALC,0,:PF_17_ALC,:PMC_17_ALC,0,0,:PERCENTUAL_IPI,
    :DATA_VIGENCIA, 0,:VARIACAO_PRECO,:CBARRA, :REGISTRO_ANVISA,'', :DESCRICAO_TIPO_PRODUTO,:ID_LCCT,
    :NCM,:CDCB,:CAS,:COMPOSICAO,:ATC_CODE,:CLASSE_TERAPEUTICA,:ID_TARJA,:PORTARIA_344_98,:TISS_TUSS,:CONFAZ_87,'N');
  END
END ^

ALTER PROCEDURE SP_ACERTA_CFOP_SINTEGRA (DATAINICIAL DATE,
DATAFINAL DATE)
AS 
declare variable UFLOJA varchar(2);
declare variable UF varchar(2);
declare variable CODIGO double precision;
BEGIN
  SELECT UF FROM PARAMETROS INTO :UFLOJA;
  FOR
    SELECT
     SINTEGRA_NF_ENTRADA.COD_NF_ENTRADA,
     SINTEGRA_NF_ENTRADA.UF_FORNECEDOR
    FROM
     SINTEGRA_NF_ENTRADA
    WHERE
     SINTEGRA_NF_ENTRADA.DATAHORA >= :DATAINICIAL AND
     SINTEGRA_NF_ENTRADA.DATAHORA <= :DATAFINAL AND
     SINTEGRA_NF_ENTRADA.EMITENTE_NF = 'T'
    INTO
     :CODIGO,
     :UF
  DO
   BEGIN
     IF (:UF = :UFLOJA) THEN
      BEGIN
        UPDATE SINTEGRA_NF_ENTRADA_ITENS SET
         SINTEGRA_NF_ENTRADA_ITENS.CFOP = '1403'
        WHERE
         SINTEGRA_NF_ENTRADA_ITENS.COD_NF_ENTRADA = :CODIGO AND
         SINTEGRA_NF_ENTRADA_ITENS.S_TRIB = '60' AND
         (SINTEGRA_NF_ENTRADA_ITENS.CFOP <> '1910' AND
          SINTEGRA_NF_ENTRADA_ITENS.CFOP <> '2910');

        UPDATE SINTEGRA_NF_ENTRADA_ITENS SET
         SINTEGRA_NF_ENTRADA_ITENS.CFOP = '1102'
        WHERE
         SINTEGRA_NF_ENTRADA_ITENS.COD_NF_ENTRADA = :CODIGO AND
         (SINTEGRA_NF_ENTRADA_ITENS.S_TRIB = '10' OR
         SINTEGRA_NF_ENTRADA_ITENS.S_TRIB = '20' OR
         SINTEGRA_NF_ENTRADA_ITENS.S_TRIB = '30' OR
         SINTEGRA_NF_ENTRADA_ITENS.S_TRIB = '40' OR
         SINTEGRA_NF_ENTRADA_ITENS.S_TRIB = '50' OR
         SINTEGRA_NF_ENTRADA_ITENS.S_TRIB = '70' OR
         SINTEGRA_NF_ENTRADA_ITENS.S_TRIB = '80' OR
         SINTEGRA_NF_ENTRADA_ITENS.S_TRIB = '90') AND
         (SINTEGRA_NF_ENTRADA_ITENS.CFOP <> '1910' AND
          SINTEGRA_NF_ENTRADA_ITENS.CFOP <> '2910');
      END
     ELSE
      BEGIN
        UPDATE SINTEGRA_NF_ENTRADA_ITENS SET
         SINTEGRA_NF_ENTRADA_ITENS.CFOP = '2403'
        WHERE
         SINTEGRA_NF_ENTRADA_ITENS.COD_NF_ENTRADA = :CODIGO AND
         SINTEGRA_NF_ENTRADA_ITENS.S_TRIB = '60' AND
         (SINTEGRA_NF_ENTRADA_ITENS.CFOP <> '1910' AND
          SINTEGRA_NF_ENTRADA_ITENS.CFOP <> '2910');

        UPDATE SINTEGRA_NF_ENTRADA_ITENS SET
         SINTEGRA_NF_ENTRADA_ITENS.CFOP = '2102'
        WHERE
         SINTEGRA_NF_ENTRADA_ITENS.COD_NF_ENTRADA = :CODIGO AND
         (SINTEGRA_NF_ENTRADA_ITENS.S_TRIB = '10' OR
         SINTEGRA_NF_ENTRADA_ITENS.S_TRIB = '20' OR
         SINTEGRA_NF_ENTRADA_ITENS.S_TRIB = '30' OR
         SINTEGRA_NF_ENTRADA_ITENS.S_TRIB = '40' OR
         SINTEGRA_NF_ENTRADA_ITENS.S_TRIB = '50' OR
         SINTEGRA_NF_ENTRADA_ITENS.S_TRIB = '70' OR
         SINTEGRA_NF_ENTRADA_ITENS.S_TRIB = '80' OR
         SINTEGRA_NF_ENTRADA_ITENS.S_TRIB = '90') AND
         (SINTEGRA_NF_ENTRADA_ITENS.CFOP <> '1910' AND
          SINTEGRA_NF_ENTRADA_ITENS.CFOP <> '2910');
      END
   END

END ^

