ALTER PROCEDURE SP_ACERTA_CST_PIS_COFINS (DATAINICIAL DATE,
DATAFINAL DATE,
ALIQUOTAPIS NUMERIC(15, 2),
ALIQUOTACOFINS NUMERIC(15, 2))
AS 
BEGIN
     UPDATE SINTEGRA_NF_ENTRADA_ITENS SET
       SINTEGRA_NF_ENTRADA_ITENS.PIS_CST = '04',
       SINTEGRA_NF_ENTRADA_ITENS.COFINS_CST = '04'
     WHERE
       CAST(SINTEGRA_NF_ENTRADA_ITENS.DATAHORA AS DATE) >= :DATAINICIAL AND
       CAST(SINTEGRA_NF_ENTRADA_ITENS.DATAHORA AS DATE) <= :DATAFINAL AND
       SINTEGRA_NF_ENTRADA_ITENS.CFOP = '5405';

     UPDATE SINTEGRA_NF_ENTRADA_ITENS SET
       SINTEGRA_NF_ENTRADA_ITENS.PIS_PERCENTUAL = :ALIQUOTAPIS,
       SINTEGRA_NF_ENTRADA_ITENS.PIS_BASE_CALCULO = SINTEGRA_NF_ENTRADA_ITENS.SUBTOTAL,
       SINTEGRA_NF_ENTRADA_ITENS.PIS_VALOR = (SINTEGRA_NF_ENTRADA_ITENS.SUBTOTAL * :ALIQUOTAPIS) / 100
     WHERE
       CAST(SINTEGRA_NF_ENTRADA_ITENS.DATAHORA AS DATE) >= :DATAINICIAL AND
       CAST(SINTEGRA_NF_ENTRADA_ITENS.DATAHORA AS DATE) <= :DATAFINAL AND
       SINTEGRA_NF_ENTRADA_ITENS.PIS_CST = '01' AND
       SINTEGRA_NF_ENTRADA_ITENS.PIS_VALOR = 0;

     UPDATE SINTEGRA_NF_ENTRADA_ITENS SET
       SINTEGRA_NF_ENTRADA_ITENS.COFINS_PERCENTUAL = :ALIQUOTACOFINS,
       SINTEGRA_NF_ENTRADA_ITENS.COFINS_BASE_CALCULO = SINTEGRA_NF_ENTRADA_ITENS.SUBTOTAL,
       SINTEGRA_NF_ENTRADA_ITENS.COFINS_VALOR = (SINTEGRA_NF_ENTRADA_ITENS.SUBTOTAL * :ALIQUOTACOFINS) / 100
     WHERE
       CAST(SINTEGRA_NF_ENTRADA_ITENS.DATAHORA AS DATE) >= :DATAINICIAL AND
       CAST(SINTEGRA_NF_ENTRADA_ITENS.DATAHORA AS DATE) <= :DATAFINAL AND
       SINTEGRA_NF_ENTRADA_ITENS.COFINS_CST = '01' AND
       SINTEGRA_NF_ENTRADA_ITENS.COFINS_VALOR = 0;

END ^

ALTER PROCEDURE SP_ACERTA_DATA_CADASTRO_FISCOBE AS 
declare variable ID double precision;
declare variable DT date;
BEGIN
  FOR
    SELECT ID_PRODUTO, DT_CADASTRO FROM PRODUTOS WHERE STATUS = 'A' INTO :ID, :DT
  DO
   BEGIN
     UPDATE PRODUTOS_FISCO SET DT_CADASTRO = :DT WHERE ID_PRODUTO = :ID;
   END
END ^

ALTER PROCEDURE SP_ACERTA_DTMOVIMENTO_PAFR04 (DATAINICIAL VARCHAR(10) CHARACTER SET NONE,
DATAFINAL VARCHAR(10) CHARACTER SET NONE)
AS 
declare variable ECFAUX varchar(100);
declare variable ECF varchar(100);
declare variable COOINICIAL varchar(10);
declare variable COOFINAL varchar(10);
declare variable DATA_MOVIMENTO varchar(10);
BEGIN
  COOINICIAL = '0';
  ECFAUX = '';
  FOR
    SELECT
     PAF_R02.NUMERO_FABRICACAO,
     PAF_R02.DATA_MOVIMENTO,
     PAF_R02.COO
    FROM
     PAF_R02
    WHERE
     PAF_R02.DATA_MOVIMENTO >= :DATAINICIAL AND
     PAF_R02.DATA_MOVIMENTO <= :DATAFINAL
    GROUP BY
     PAF_R02.NUMERO_FABRICACAO,
     PAF_R02.DATA_MOVIMENTO,
     PAF_R02.COO
    ORDER BY
     PAF_R02.NUMERO_FABRICACAO,
     PAF_R02.COO
    INTO
     :ECF,
     :DATA_MOVIMENTO,
     :COOFINAL
  DO
   BEGIN
     IF (:ECFAUX = '') THEN
        ECFAUX = :ECF;

     IF (:ECF <> :ECFAUX) THEN
      BEGIN
        ECFAUX = :ECF;
        COOINICIAL = '0';
      END

     IF (:COOINICIAL = '0') THEN
      BEGIN
        UPDATE PAF_R04 SET DATA_INICIO_EMISSAO = :DATA_MOVIMENTO
        WHERE NUMERO_FABRICACAO = :ECF AND COO < :COOFINAL;
      END
     ELSE
      BEGIN
        UPDATE PAF_R04 SET DATA_INICIO_EMISSAO = :DATA_MOVIMENTO
        WHERE NUMERO_FABRICACAO = :ECF AND COO > :COOINICIAL AND COO < :COOFINAL;
      END
     COOINICIAL = :COOFINAL;
   END
END ^

ALTER PROCEDURE SP_ACERTA_GRUPO AS 
DECLARE VARIABLE ID_PRODUTO DOUBLE PRECISION;
BEGIN
  FOR
   SELECT
    DISTINCT LANCAMENTOS.ID_PRODUTO
   FROM
    LANCAMENTOS
   INTO
    :ID_PRODUTO
  DO
   BEGIN
     UPDATE LANCAMENTOS SET
      LANCAMENTOS.CD_GRUPO = (SELECT CD_GRUPO FROM PRODUTOS WHERE ID_PRODUTO = :ID_PRODUTO)
     WHERE
      ID_PRODUTO = :ID_PRODUTO;
   END
END ^

ALTER PROCEDURE SP_ACERTA_MARGENS_CADASTRO AS 
DECLARE VARIABLE CD_GRUPO DOUBLE PRECISION;
DECLARE VARIABLE MARCACAO DOUBLE PRECISION;
BEGIN
  FOR
   SELECT
     GRUPOS.CD_GRUPO,
     GRUPOS.TX_MARCACAO
   FROM
    GRUPOS
   INTO
     :CD_GRUPO,
     :MARCACAO

   DO
    BEGIN
      UPDATE PRODUTOS SET PRODUTOS.MARGEM = :MARCACAO
       WHERE (MARGEM = 0) OR (MARGEM IS NULL) AND CD_GRUPO = :CD_GRUPO;
    END
END ^

ALTER PROCEDURE SP_ACERTA_PI_TEMP_MATRICIAL AS 
DECLARE VARIABLE ID VARCHAR(14);
DECLARE VARIABLE DESCRICAO VARCHAR(60);
BEGIN
  FOR
   SELECT
    DISTINCT REF_PRODUTOS
   FROM
    SINTEGRA_PEDIDOS_ITENS_TEMP
   ORDER BY
    REF_PRODUTOS
   INTO
    :ID
  DO
   BEGIN
     SELECT DESCRICAO FROM PRODUTOS WHERE CODIGO_BARRAS_1 = :ID INTO :DESCRICAO;
     IF (:DESCRICAO IS NULL) THEN
        DESCRICAO = '';
     UPDATE SINTEGRA_PEDIDOS_ITENS_TEMP SET PRODUTO = :DESCRICAO WHERE REF_PRODUTOS = :ID;
   END
END ^

ALTER PROCEDURE SP_ACERTA_PRODUTOS_FIDELIDADE AS 
declare variable ID_PRODUTO double precision;
declare variable CD_GRUPO double precision;
declare variable CD_LABORATORIO double precision;
declare variable DESCRICAO varchar(100);
declare variable TIPOLOJA varchar(1);
BEGIN
  SELECT TIPO_LOJA FROM PARAMETROS INTO :TIPOLOJA;
  IF (:TIPOLOJA = 'M') THEN
   BEGIN
     FOR
       SELECT DISTINCT ID_PRODUTO FROM FILIAIS_FIDELIDADE INTO :ID_PRODUTO
     DO
      BEGIN
        SELECT CD_GRUPO, CD_LABORATORIO, DESCRICAO FROM PRODUTOS WHERE ID_PRODUTO = :ID_PRODUTO INTO :CD_GRUPO, CD_LABORATORIO, :DESCRICAO;
        UPDATE FILIAIS_FIDELIDADE SET
         CD_GRUPO = :CD_GRUPO,
         CD_LABORATORIO = :CD_LABORATORIO,
         DESCRICAO = :DESCRICAO
        WHERE ID_PRODUTO = :ID_PRODUTO;
      END
   END
  ELSE
   BEGIN
     FOR
       SELECT DISTINCT ID_PRODUTO FROM PRODUTOS_FIDELIDADE INTO :ID_PRODUTO
     DO
      BEGIN
        SELECT CD_GRUPO, CD_LABORATORIO, DESCRICAO FROM PRODUTOS WHERE ID_PRODUTO = :ID_PRODUTO INTO :CD_GRUPO, CD_LABORATORIO, :DESCRICAO;
        UPDATE PRODUTOS_FIDELIDADE SET
         CD_GRUPO = :CD_GRUPO,
         CD_LABORATORIO = :CD_LABORATORIO,
         DESCRICAO = :DESCRICAO
        WHERE ID_PRODUTO = :ID_PRODUTO;
      END
   END
END ^

ALTER PROCEDURE SP_ACERTA_R60I_TEMP_MATRICIAL AS 
