ALTER PROCEDURE SP_ACERTA_REF_PRODUTOS (DATAINICIAL DATE,
DATAFINAL DATE)
AS 
declare variable PRODUTO varchar(100);
declare variable CODIGO varchar(14);
BEGIN
  FOR
    SELECT SINTEGRA_NF_ENTRADA_ITENS.PRODUTO
    FROM SINTEGRA_NF_ENTRADA_ITENS
    WHERE
     SINTEGRA_NF_ENTRADA_ITENS.DATAHORA >= :DATAINICIAL AND
     SINTEGRA_NF_ENTRADA_ITENS.DATAHORA <= :DATAFINAL AND
     ((SINTEGRA_NF_ENTRADA_ITENS.REF_PRODUTOS IS NULL) OR
      (TRIM(SINTEGRA_NF_ENTRADA_ITENS.REF_PRODUTOS) = ''))
    INTO
     :PRODUTO
  DO
   BEGIN
     SELECT FIRST 1 CODIGO_BARRAS_1 FROM PRODUTOS WHERE DESCRICAO = :PRODUTO INTO :CODIGO;
     UPDATE SINTEGRA_NF_ENTRADA_ITENS SET
      REF_PRODUTOS = :CODIGO
     WHERE PRODUTO = :PRODUTO;
   END
END ^

ALTER PROCEDURE SP_ACERTA_SALDO_CLIENTE AS 
declare variable FILIAL double precision;
declare variable CLIENTE double precision;
declare variable SALDO double precision;
BEGIN
  UPDATE CLIENTES SET CLIENTES.SALDO = 0 WHERE CLIENTES.CD_CLIENTE <> 999999 AND CLIENTES.LIMITE_CREDITO IS NOT NULL AND CLIENTES.LIMITE_CREDITO > 0 AND SALDO <= 0;
  SELECT PARAMETROS.CD_FILIAL FROM PARAMETROS INTO :FILIAL;
 FOR
   SELECT CONTAS_RECEBER.CD_CLIENTE
   FROM CONTAS_RECEBER
   WHERE CONTAS_RECEBER.CD_CLIENTE <> 999999
   GROUP BY CONTAS_RECEBER.CD_CLIENTE
   INTO :CLIENTE
 DO
  BEGIN
    FOR
      SELECT
       CLIENTES.CD_CLIENTE
      FROM
       CLIENTES
      WHERE
       CLIENTES.CD_FILIAL = :FILIAL AND
       CLIENTES.CD_CLIENTE = :CLIENTE
      INTO
       :CLIENTE
    DO
     BEGIN
         SELECT
          SUM(CONTAS_RECEBER.VL_SALDO)
         FROM
          CONTAS_RECEBER
         WHERE
          CONTAS_RECEBER.CD_CLIENTE = :CLIENTE AND
          (CONTAS_RECEBER.CD_FORMA_PAGAMENTO = 3 OR CONTAS_RECEBER.CD_FORMA_PAGAMENTO = 5) AND
          CONTAS_RECEBER.VL_SALDO IS NOT NULL AND
          CONTAS_RECEBER.VL_SALDO > 0 AND
          CONTAS_RECEBER.STATUS <> 'C'
         INTO
          :SALDO;
    
         IF (:SALDO IS NULL) THEN
            SALDO = 0;
    
         UPDATE CLIENTES SET
          CLIENTES.SALDO = :SALDO
         WHERE
          CLIENTES.CD_CLIENTE = :CLIENTE AND
          CLIENTES.CD_FILIAL = :FILIAL;
     END
  END
END ^

ALTER PROCEDURE SP_ACERTA_SALDO_CLIENTE_M AS 
declare variable CLIENTE double precision;
declare variable SALDO double precision;
declare variable EXISTE integer;
declare variable CD_FILIAL double precision;
BEGIN
 UPDATE CLIENTES SET CLIENTES.SALDO = 0
 WHERE CLIENTES.CD_CLIENTE <> 999999 AND CLIENTES.LIMITE_CREDITO IS NOT NULL AND CLIENTES.LIMITE_CREDITO > 0 AND CLIENTES.SALDO <> 0;

 FOR
  SELECT CONTAS_RECEBER.CD_CLIENTE
  FROM CONTAS_RECEBER
  WHERE CONTAS_RECEBER.CD_CLIENTE <> 999999
  GROUP BY CONTAS_RECEBER.CD_CLIENTE
  INTO :CLIENTE
 DO
  BEGIN
     SELECT
      SUM(CONTAS_RECEBER.VALOR)
     FROM
      CONTAS_RECEBER
     WHERE
      CONTAS_RECEBER.CD_CLIENTE = :CLIENTE AND
      (CONTAS_RECEBER.CD_FORMA_PAGAMENTO = 3 OR CONTAS_RECEBER.CD_FORMA_PAGAMENTO = 5) AND
      CONTAS_RECEBER.VALOR IS NOT NULL AND
      CONTAS_RECEBER.VALOR > 0 AND
      CONTAS_RECEBER.STATUS = 'A'
     INTO
      :SALDO;

     IF (:SALDO IS NULL) THEN
        SALDO = 0;

     UPDATE CLIENTES SET
      SALDO = :SALDO
     WHERE
      CLIENTES.CD_CLIENTE = :CLIENTE;

  END

  UPDATE CLIENTES SET
    CLIENTES.SALDO = 0
  WHERE CLIENTES.CD_CLIENTE <> 999999 AND CLIENTES.SALDO < 0;
END ^

ALTER PROCEDURE SP_ACERTA_SALDO_CLIENTE_UNICO (CD_CLIENTE DOUBLE PRECISION)
AS 
declare variable SALDO double precision;
BEGIN
  UPDATE CLIENTES SET CLIENTES.SALDO = 0
  WHERE CLIENTES.CD_CLIENTE = :CD_CLIENTE;

  SELECT
   SUM(CONTAS_RECEBER.VALOR)
  FROM
   CONTAS_RECEBER
  WHERE
   CONTAS_RECEBER.CD_CLIENTE = :CD_CLIENTE AND
   CONTAS_RECEBER.VALOR IS NOT NULL AND
   CONTAS_RECEBER.VALOR > 0 AND
   CONTAS_RECEBER.STATUS = 'A' AND
   (CONTAS_RECEBER.CD_FORMA_PAGAMENTO = 3 OR CONTAS_RECEBER.CD_FORMA_PAGAMENTO = 5)
  INTO
   :SALDO;
  
  IF (:SALDO IS NULL) THEN
     SALDO = 0;

  UPDATE CLIENTES SET
   CLIENTES.SALDO = :SALDO
  WHERE
   CLIENTES.CD_CLIENTE = :CD_CLIENTE;
END ^

ALTER PROCEDURE SP_ACERTA_SUBGRUPO (DATAINICIAL DATE)
AS 
declare variable SUBGRUPO double precision;
declare variable ID_PRODUTO double precision;
BEGIN
  FOR
    SELECT
     CD_SUBGRUPO
    FROM
     SUBGRUPOS
    INTO
     :SUBGRUPO
  DO
   BEGIN
     FOR
       SELECT
        ID_PRODUTO
       FROM
        PRODUTOS
       WHERE
        CD_SUBGRUPO = :SUBGRUPO
       INTO
        :ID_PRODUTO
     DO
      BEGIN
        UPDATE LANCAMENTOS SET
         CD_SUBGRUPO = :SUBGRUPO
        WHERE
         DATA_LANCAMENTO >= :DATAINICIAL AND
         ID_PRODUTO = :ID_PRODUTO;
      END
   END
END ^

ALTER PROCEDURE SP_ACERTA_TERMINAL (CD_FILIAL DOUBLE PRECISION,
DATA DATE)
AS 
DECLARE VARIABLE ID_OPERADORCAIXA INTEGER;
DECLARE VARIABLE TERMINAL INTEGER;
BEGIN
  FOR
    SELECT ID_OPERADORCAIXA, TERMINAL
    FROM OPERADORES
    WHERE CD_FILIAL = :CD_FILIAL AND
          DATA_ABERTURA = :DATA
    INTO :ID_OPERADORCAIXA, :TERMINAL
  DO
   BEGIN
    UPDATE CAIXA SET DATA_CAIXA = DATA, TERMINAL = :TERMINAL
    WHERE ID_OPERADORCAIXA = :ID_OPERADORCAIXA AND
          (TIPO_VENDA = 'V' OR TIPO_VENDA = 'D' OR TIPO_VENDA = 'S' OR TIPO_VENDA = 'U' OR TIPO_VENDA = 'R');

    UPDATE LANCAMENTOS SET TERMINAL = :TERMINAL
    WHERE ID_OPERADORCAIXA = :ID_OPERADORCAIXA AND
          (TIPO_VENDA = 'V' OR TIPO_VENDA = 'D' OR TIPO_VENDA = 'S' OR TIPO_VENDA = 'U' OR TIPO_VENDA = 'R');
   END
END ^

ALTER PROCEDURE SP_ACERTA_TIPO_PRODUTO AS 
declare variable CD_CLASSE double precision;
declare variable TIPO_PRODUTO varchar(10);
BEGIN
  FOR
    SELECT CD_CLASSE, TIPO
    FROM CLASSES
    INTO :CD_CLASSE, :TIPO_PRODUTO
  DO
   BEGIN
     UPDATE PRODUTOS SET
      TIPO_PRODUTO = :TIPO_PRODUTO
     WHERE CD_CLASSE = :CD_CLASSE;
   END
END ^

ALTER PROCEDURE SP_ACERTA_TOTAL_NF_SINTEGRA (DATAINICIAL DATE,
DATAFINAL DATE)
AS 
DECLARE VARIABLE CODIGO DOUBLE PRECISION;
DECLARE VARIABLE TOTAL NUMERIC(15,2);
BEGIN
  FOR
      SELECT SINTEGRA_NF_ENTRADA.COD_NF_ENTRADA
      FROM SINTEGRA_NF_ENTRADA
      WHERE SINTEGRA_NF_ENTRADA.DATAHORA >= :DATAINICIAL AND
            SINTEGRA_NF_ENTRADA.DATAHORA <= :DATAFINAL
      INTO :CODIGO
  DO
   BEGIN
      SELECT SUM(SINTEGRA_NF_ENTRADA_ITENS.SUBTOTAL)
      FROM SINTEGRA_NF_ENTRADA_ITENS
      WHERE SINTEGRA_NF_ENTRADA_ITENS.COD_NF_ENTRADA = :CODIGO
      INTO :TOTAL;

      UPDATE SINTEGRA_NF_ENTRADA SET
       SINTEGRA_NF_ENTRADA.VALOR_TOTALPRODUTO = :TOTAL,
       SINTEGRA_NF_ENTRADA.VALOR_TOTALNF = :TOTAL
      WHERE SINTEGRA_NF_ENTRADA.COD_NF_ENTRADA = :CODIGO;
   END
END ^

ALTER PROCEDURE SP_ACERTA_TROCA_CAIXA AS 
DECLARE VARIABLE CD_VENDA DOUBLE PRECISION;
DECLARE VARIABLE CD_FILIAL DOUBLE PRECISION;
DECLARE VARIABLE TROCA VARCHAR(1);
BEGIN
  UPDATE LANCAMENTOS SET TROCA = 'F' WHERE TROCA = 'N';
  UPDATE LANCAMENTOS SET TROCA = 'T' WHERE TROCA = 'S';
  FOR
    SELECT
     CD_VENDA,
     CD_FILIAL,
     TROCA
    FROM
     LANCAMENTOS
    WHERE
     TROCA <> ''
    GROUP BY
     CD_VENDA,
     CD_FILIAL,
     TROCA
    INTO
     :CD_VENDA,
     :CD_FILIAL,
     :TROCA
  DO
   BEGIN
     UPDATE CAIXA SET
      TROCA = :TROCA
     WHERE
      CD_VENDA = :CD_VENDA AND CD_FILIAL = :CD_FILIAL;
   END
END ^

ALTER PROCEDURE SP_ACERTA_VENDEDOR_TROCA (DATA_INICIAL DATE,
DATA_FINAL DATE)
RETURNS (CD_VENDA_TROCA DOUBLE PRECISION,
ID_PRODUTO DOUBLE PRECISION,
CD_VENDA_ORIGINAL DOUBLE PRECISION,
CD_VENDEDOR_TROCA DOUBLE PRECISION,
CD_VENDEDOR_ORIGINAL DOUBLE PRECISION)
AS 
BEGIN
  FOR
    SELECT
     CD_VENDA, CD_VENDEDOR, ID_PRODUTO
    FROM
     LANCAMENTOS
    WHERE
     DATA_LANCAMENTO >= :DATA_INICIAL AND
     DATA_LANCAMENTO <= :DATA_FINAL AND
     TIPO_VENDA = 'D' AND
     TROCA = 'T'
    INTO
     :CD_VENDA_TROCA,
     :CD_VENDEDOR_TROCA,
     :ID_PRODUTO
  DO
   BEGIN
     SELECT DISTINCT CD_VENDA_TROCA
     FROM VENDAS
     WHERE CD_VENDA = :CD_VENDA_TROCA AND ID_PRODUTO = :ID_PRODUTO AND CD_VENDA_TROCA > 0 AND CD_VENDA_TROCA < 100000 INTO :CD_VENDA_ORIGINAL;

     SELECT CD_VENDEDOR
     FROM VENDAS
     WHERE CD_VENDA = :CD_VENDA_ORIGINAL AND ID_PRODUTO = :ID_PRODUTO INTO :CD_VENDEDOR_ORIGINAL;

     IF ((:CD_VENDA_ORIGINAL <> 0) AND (:CD_VENDEDOR_TROCA <> :CD_VENDEDOR_ORIGINAL)) THEN
      BEGIN
        UPDATE LANCAMENTOS SET
          CD_VENDEDOR = :CD_VENDEDOR_ORIGINAL
        WHERE CD_VENDA = :CD_VENDA_TROCA AND ID_PRODUTO = :ID_PRODUTO AND TIPO_VENDA = 'D' AND TROCA = 'T';

        UPDATE VENDAS SET
          CD_VENDEDOR = :CD_VENDEDOR_ORIGINAL
        WHERE CD_VENDA = :CD_VENDA_TROCA AND ID_PRODUTO = :ID_PRODUTO AND TIPO_VENDA = 'D' AND TROCA = 'T';

--        SUSPEND;
      END
   END
END ^

ALTER PROCEDURE SP_ACUMULADO_METAS_REDE (MESREF INTEGER,
ANOREF INTEGER)
AS 
declare variable CD_FILIAL double precision;
declare variable VALOR double precision;
declare variable QUANTIDADE double precision;
declare variable CLIENTES double precision;
declare variable TICKET double precision;
declare variable VALORCANCELADO double precision;
declare variable QUANTIDADECANCELADA double precision;
declare variable CLIENTESCANCELADOS double precision;
declare variable ULTIMODIAMES integer;
declare variable ANOBISEXTO integer;
declare variable DATA date;
BEGIN
  DATA = CAST(:MESREF||'/01/'||:ANOREF AS DATE);
  SELECT RESULTADO FROM SP_BISEXTO(:DATA) INTO :ANOBISEXTO;
     IF ((:MESREF = 1) OR (:MESREF = 3) OR (:MESREF = 5) OR (:MESREF = 7) OR (:MESREF = 8) OR (:MESREF = 10) OR (:MESREF = 12)) THEN
        ULTIMODIAMES = 31;
     ELSE
     IF (:MESREF = 2) THEN
      BEGIN
        IF (:ANOBISEXTO = 1) THEN
           ULTIMODIAMES = 29;
        ELSE
           ULTIMODIAMES = 28;
      END
     ELSE
        ULTIMODIAMES = 30;

  FOR
    SELECT
      CD_FILIAL
    FROM
      FILIAIS
    WHERE
      STATUS = 'A'
    INTO
      :CD_FILIAL
  DO
   BEGIN
     SELECT
      SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
      SUM(LANCAMENTOS.QUANTIDADE),
      COUNT(DISTINCT LANCAMENTOS.CD_VENDA)
     FROM
      LANCAMENTOS
     WHERE
      LANCAMENTOS.DATA_LANCAMENTO >= CAST(:MESREF||'/01/'||:ANOREF AS DATE) AND
      LANCAMENTOS.DATA_LANCAMENTO <= CAST(:MESREF||'/'||:ULTIMODIAMES||'/'||:ANOREF AS DATE) AND
      LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
      LANCAMENTOS.TIPO_VENDA = 'V' AND
      LANCAMENTOS.CUSTO_UNITARIO > 0
     INTO
      :VALOR,
      :QUANTIDADE,
      :CLIENTES;

     IF (:VALOR IS NULL) THEN
        VALOR = 0;
     IF (:QUANTIDADE IS NULL) THEN
        QUANTIDADE = 0;
     IF (:CLIENTES IS NULL) THEN
        CLIENTES = 0;

     SELECT
      SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
      SUM(LANCAMENTOS.QUANTIDADE),
      COUNT(DISTINCT LANCAMENTOS.CD_VENDA)
     FROM
      LANCAMENTOS
     WHERE
      LANCAMENTOS.DATA_LANCAMENTO >= CAST(:MESREF||'/01/'||:ANOREF AS DATE) AND
      LANCAMENTOS.DATA_LANCAMENTO <= CAST(:MESREF||'/'||:ULTIMODIAMES||'/'||:ANOREF AS DATE) AND
      LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
      LANCAMENTOS.TIPO_VENDA = 'D' AND
      LANCAMENTOS.CUSTO_UNITARIO > 0
     INTO
      :VALORCANCELADO,
      :QUANTIDADECANCELADA,
      :CLIENTESCANCELADOS;

     IF (:VALORCANCELADO IS NULL) THEN
        VALORCANCELADO = 0;
     IF (:QUANTIDADECANCELADA IS NULL) THEN
        QUANTIDADECANCELADA = 0;
     IF (:CLIENTESCANCELADOS IS NULL) THEN
        CLIENTESCANCELADOS = 0;

     VALOR = :VALOR - :VALORCANCELADO;
     QUANTIDADE = :QUANTIDADE - :QUANTIDADECANCELADA;
     CLIENTES = :CLIENTES - :CLIENTESCANCELADOS;
     IF (:CLIENTES > 0) THEN
        TICKET = :VALOR / CLIENTES;

     UPDATE METAS_FILIAIS SET
      ACUMULADOVALOR = :VALOR,
      ACUMULADOQUANTIDADE = :QUANTIDADE,
      ACUMULADOCLIENTES = :CLIENTES,
      ACUMULADOTICKET = :TICKET
     WHERE CD_FILIAL = :CD_FILIAL AND MESREF = :MESREF AND ANOREF = :ANOREF;
   END
END ^

