  UPDATE CAIXA SET
   ENVIADO = 0
  WHERE DATA >= :DATAINICIAL AND DATA <= :DATAFINAL;
  UPDATE CHEQUESRECEBIDOS SET
    ENVIADO = 0
  WHERE DATA_VENCIMENTO >= :DATAINICIAL AND DATA_VENCIMENTO <= :DATAFINAL;
  UPDATE COMPRAS SET
    ENVIADO = 0
  WHERE DT_PEDIDO >= :DATAINICIAL AND DT_PEDIDO <= :DATAFINAL;
