    ENVIADO = 0
  WHERE DT_LANCAMENTO >= :DATAINICIAL AND DT_LANCAMENTO <= :DATAFINAL;
  UPDATE ENTREGAS SET
    ENVIADO = 0
  WHERE DATA >= :DATAINICIAL AND DATA <= :DATAFINAL;
  UPDATE ITENS_COMPRA SET
    ENVIADO = 0
  WHERE CD_COMPRAS IN (SELECT CD_COMPRAS FROM COMPRAS WHERE DT_PEDIDO >= :DATAINICIAL AND DT_PEDIDO <= :DATAFINAL);
  UPDATE LANCAMENTOS SET
    ENVIADO = 0
