  UPDATE OPERADORES SET
    ENVIADO = 0
  WHERE DATA_ABERTURA >= :DATAINICIAL AND DATA_ABERTURA <= :DATAFINAL;
  UPDATE CRM SET
    ENVIADO = 0
  WHERE DATA >= :DATAINICIAL AND DATA <= :DATAFINAL;
END ^

