ALTER PROCEDURE SP_ALTERA_MODULO_INFORMANTE AS 
declare variable MODULO varchar(100);
declare variable DESCRICAO varchar(100);
BEGIN
  FOR
    SELECT DISTINCT MODULO FROM INFORMANTE INTO :MODULO
  DO
   BEGIN
     SELECT DESCRICAO FROM MODULOS WHERE NOME = :MODULO INTO :DESCRICAO;
     UPDATE INFORMANTE SET MODULO = :DESCRICAO WHERE MODULO = :MODULO;
   END
END ^

ALTER PROCEDURE SP_ALTERA_PRECO_FAMILIA (ID_FAMILIA DOUBLE PRECISION,
ID_PRODUTO DOUBLE PRECISION)
AS 
DECLARE VARIABLE PRECO_VENDA DOUBLE PRECISION;
DECLARE VARIABLE PRECO_PROMOCAO DOUBLE PRECISION;
DECLARE VARIABLE DT_VENCIMENTO_PROMOCAO DATE;
DECLARE VARIABLE ALTERAPRECOFAMILIA VARCHAR(1);
BEGIN
 SELECT ALTERAPRECOFAMILIA FROM FAMILIAS WHERE ID_FAMILIA = :ID_FAMILIA INTO :ALTERAPRECOFAMILIA;

 IF (:ALTERAPRECOFAMILIA = 'S') THEN
  BEGIN
     SELECT PRECO_VENDA, PRECO_PROMOCAO, DT_VENCIMENTO_PROMOCAO FROM PRODUTOS WHERE ID_PRODUTO = :ID_PRODUTO
     INTO :PRECO_VENDA, :PRECO_PROMOCAO, :DT_VENCIMENTO_PROMOCAO;
    
     UPDATE PRODUTOS SET
      PRECO_VENDA = :PRECO_VENDA,
      PRECO_PROMOCAO = :PRECO_PROMOCAO,
      DT_VENCIMENTO_PROMOCAO = :DT_VENCIMENTO_PROMOCAO
     WHERE
      ID_FAMILIA = :ID_FAMILIA AND
      ((PRECO_VENDA <> :PRECO_VENDA) OR
       (PRECO_PROMOCAO <> :PRECO_PROMOCAO) OR
       (DT_VENCIMENTO_PROMOCAO <> :DT_VENCIMENTO_PROMOCAO));
  END
END ^

ALTER PROCEDURE SP_ALTERA_SPEDPISCOFINS_CG (CD_CLASSE DOUBLE PRECISION,
CD_GRUPO DOUBLE PRECISION,
PIS_ENTRADA_LR VARCHAR(3) CHARACTER SET NONE,
PIS_SAIDA_LR VARCHAR(3) CHARACTER SET NONE,
COFINS_ENTRADA_LR VARCHAR(3) CHARACTER SET NONE,
COFINS_SAIDA_LR VARCHAR(3) CHARACTER SET NONE,
PIS_ENTRADA_LP VARCHAR(3) CHARACTER SET NONE,
PIS_SAIDA_LP VARCHAR(3) CHARACTER SET NONE,
COFINS_ENTRADA_LP VARCHAR(3) CHARACTER SET NONE,
COFINS_SAIDA_LP VARCHAR(3) CHARACTER SET NONE,
PIS_ENTRADA_SN VARCHAR(3) CHARACTER SET NONE,
PIS_SAIDA_SN VARCHAR(3) CHARACTER SET NONE,
COFINS_ENTRADA_SN VARCHAR(3) CHARACTER SET NONE,
COFINS_SAIDA_SN VARCHAR(3) CHARACTER SET NONE)
AS 
declare variable COMANDO varchar(1000);
declare variable COMANDO2 varchar(1000);
declare variable VIRGULA varchar(1);
declare variable CODIGO_BARRAS_1 varchar(14);
declare variable CODIGO_BARRAS_2 varchar(14);
declare variable VARIAVEL varchar(10);
declare variable VARIAVEL2 varchar(10);
BEGIN
  COMANDO = '';
  VARIAVEL = '';
  COMANDO = 'SELECT CODIGO_BARRAS_1, CODIGO_BARRAS_2 FROM PRODUTOS WHERE ';
  IF (:CD_CLASSE > 0) THEN
   BEGIN
     COMANDO = :COMANDO || :VARIAVEL || ' CD_CLASSE = ' || CAST(:CD_CLASSE AS INTEGER);
     VARIAVEL = ' AND ';
   END
  IF (:CD_GRUPO > 0) THEN
     COMANDO = :COMANDO || :VARIAVEL || ' CD_GRUPO = ' || CAST(:CD_GRUPO AS INTEGER);
  FOR
    EXECUTE STATEMENT :COMANDO INTO :CODIGO_BARRAS_1, :CODIGO_BARRAS_2
  DO
   BEGIN
     VIRGULA = '';
     COMANDO2 = '';
     COMANDO2 = 'UPDATE SPED_PIS_COFINS SET ';
     IF (:PIS_ENTRADA_LR <> '') THEN
      BEGIN
        COMANDO2 = :COMANDO2 || :VIRGULA || 'PIS_ENTRADA_LR = ''' || :PIS_ENTRADA_LR || '''';
        VIRGULA = ',';
      END
     IF (:PIS_SAIDA_LR <> '') THEN
      BEGIN
        COMANDO2 = :COMANDO2 || :VIRGULA || 'PIS_SAIDA_LR = ''' || :PIS_SAIDA_LR ||'''';
        VIRGULA = ',';
      END
     IF (:COFINS_ENTRADA_LR <> '') THEN
      BEGIN
        COMANDO2 = :COMANDO2 || :VIRGULA || 'COFINS_ENTRADA_LR = ''' || :COFINS_ENTRADA_LR ||'''';
        VIRGULA = ',';
      END
     IF (:COFINS_SAIDA_LR <> '') THEN
      BEGIN
        COMANDO2 = :COMANDO2 || :VIRGULA || 'COFINS_SAIDA_LR = ''' || :COFINS_SAIDA_LR ||'''';
        VIRGULA = ',';
      END
     IF (:PIS_ENTRADA_LP <> '') THEN
      BEGIN
        COMANDO2 = :COMANDO2 || :VIRGULA || 'PIS_ENTRADA_LP = ''' || :PIS_ENTRADA_LP ||'''';
        VIRGULA = ',';
      END
     IF (:PIS_SAIDA_LP <> '') THEN
      BEGIN
        COMANDO2 = :COMANDO2 || :VIRGULA || 'PIS_SAIDA_LP = ''' || :PIS_SAIDA_LP ||'''';
        VIRGULA = ',';
      END
     IF (:COFINS_ENTRADA_LP <> '') THEN
      BEGIN
        COMANDO2 = :COMANDO2 || :VIRGULA || 'COFINS_ENTRADA_LP = ''' || :COFINS_ENTRADA_LP || '''';
        VIRGULA = ',';
      END
     IF (:COFINS_SAIDA_LP <> '') THEN
      BEGIN
        COMANDO2 = :COMANDO2 || :VIRGULA || 'COFINS_SAIDA_LP = ''' || :COFINS_SAIDA_LP ||'''';
        VIRGULA = ',';
      END
     IF (:PIS_ENTRADA_SN <> '') THEN
      BEGIN
        COMANDO2 = :COMANDO2 || :VIRGULA || 'PIS_ENTRADA_SN = ''' || :PIS_ENTRADA_SN ||'''';
        VIRGULA = ',';
      END
     IF (:PIS_SAIDA_SN <> '') THEN
      BEGIN
        COMANDO2 = :COMANDO2 || :VIRGULA || 'PIS_SAIDA_SN = ''' || :PIS_SAIDA_SN ||'''';
        VIRGULA = ',';
      END
     IF (:COFINS_ENTRADA_SN <> '') THEN
      BEGIN
        COMANDO2 = :COMANDO2 || :VIRGULA || 'COFINS_ENTRADA_SN = ''' || :COFINS_ENTRADA_SN ||'''';
        VIRGULA = ',';
      END
     IF (:COFINS_SAIDA_SN <> '') THEN
      BEGIN
        COMANDO2 = :COMANDO2 || :VIRGULA || 'COFINS_SAIDA_SN = ''' || :COFINS_SAIDA_SN ||'''';
        VIRGULA = ',';
      END
     VARIAVEL2 = '';
     IF ((:CODIGO_BARRAS_1 IS NOT NULL) AND (:CODIGO_BARRAS_1 <> '')) THEN
      BEGIN
        COMANDO2 = :COMANDO2 || ' WHERE BARRA = ''' || :CODIGO_BARRAS_1 || '''';
        VARIAVEL2 = ' OR ';
      END
     IF ((:CODIGO_BARRAS_2 IS NOT NULL) AND (:CODIGO_BARRAS_2 <> '')) THEN
      BEGIN
        COMANDO2 = :COMANDO2 || :VARIAVEL2 || ' BARRA = ''' || :CODIGO_BARRAS_2 || '''';
        VARIAVEL2 = ' OR ';
      END
     EXECUTE STATEMENT :COMANDO2;
   END
END ^

ALTER PROCEDURE SP_ALTERA_VENCIMENTO_CONVENIO AS 
DECLARE VARIABLE CONVENIO DOUBLE PRECISION;
DECLARE VARIABLE CD_CONTA DOUBLE PRECISION;
DECLARE VARIABLE DT_VENCIMENTO INTEGER;
DECLARE VARIABLE DT_LANCAMENTO DATE;
DECLARE VARIABLE DATA DATE;
BEGIN
  FOR
   SELECT
    CD_CONTAS_RECEBER,
    CD_CONVENIO,
    DT_LANCAMENTO
   FROM
    CONTAS_RECEBER
   WHERE
    CD_CONVENIO > 0 AND STATUS = 'P' AND DT_LANCAMENTO >= '03/01/2009'
   ORDER BY CD_CONTAS_RECEBER
   INTO
    :CD_CONTA,
    :CONVENIO,
    :DT_LANCAMENTO
  DO
   BEGIN
    SELECT DT_VENCIMENTO FROM CONVENIOS WHERE CD_CONVENIO = :CONVENIO INTO :DT_VENCIMENTO;
    IF (:DT_VENCIMENTO > 0) THEN
        BEGIN
            IF (CAST(EXTRACT(DAY FROM :DT_LANCAMENTO) AS INTEGER) >= :DT_VENCIMENTO)  THEN
              DATA = CAST(CAST(EXTRACT(MONTH FROM :DT_LANCAMENTO)+1 AS INTEGER) || '/' || :DT_VENCIMENTO || '/2009' AS DATE);

            IF (CAST(EXTRACT(DAY FROM :DT_LANCAMENTO) AS INTEGER) < :DT_VENCIMENTO)  THEN
               DATA = CAST(CAST(EXTRACT(MONTH FROM :DT_LANCAMENTO) AS INTEGER) || '/' ||:DT_VENCIMENTO || '/2009' AS DATE);
        
            UPDATE CONTAS_RECEBER SET
              DT_VENCIMENTO = :DATA
            WHERE
              CD_CONTAS_RECEBER = :CD_CONTA;
        END
   END
END ^

ALTER PROCEDURE SP_ANALISE_PRECO_CONCORRENTE (CD_FILIAL DOUBLE PRECISION,
ID_CONCORRENTE DOUBLE PRECISION)
RETURNS (ID_PRODUTO DOUBLE PRECISION,
PRODUTO VARCHAR(100) CHARACTER SET NONE,
PRECO_CONCORRENTE DOUBLE PRECISION,
PRECO_VENDA DOUBLE PRECISION,
CUSTO DOUBLE PRECISION,
MARGEM DOUBLE PRECISION,
LUCRO DOUBLE PRECISION,
MARGEM_CONCORRENTE DOUBLE PRECISION,
LUCRO_CONCORRENTE DOUBLE PRECISION,
ESTOQUE DOUBLE PRECISION)
AS 
DECLARE VARIABLE COMANDO VARCHAR(2000);
BEGIN
  FOR
   SELECT
     PROD_CONCORRENTES.ID_PRODUTO,
     PROD_CONCORRENTES.PRODUTO,
     PROD_CONCORRENTES.PRECO
   FROM
     PROD_CONCORRENTES
   WHERE
     PROD_CONCORRENTES.ID_FILIAL = :CD_FILIAL AND
     PROD_CONCORRENTES.ID_CONCORRENTE = :ID_CONCORRENTE
   INTO
     :ID_PRODUTO,
     :PRODUTO,
     :PRECO_CONCORRENTE
  DO
   BEGIN
     COMANDO = 'SELECT ESTOQUE_'||CAST(:CD_FILIAL AS INTEGER)||', PRECO_VENDA_'||CAST(:CD_FILIAL AS INTEGER)||', CUSTO_UNITARIO_'||CAST(:CD_FILIAL AS INTEGER)||
               ' FROM PRODUTOS WHERE ID_PRODUTO = '||:ID_PRODUTO;
     FOR
       EXECUTE STATEMENT :COMANDO INTO :ESTOQUE, :PRECO_VENDA, :CUSTO
     DO
      BEGIN
        MARGEM = 100 - ((:CUSTO * 100) / :PRECO_VENDA);
        LUCRO = PRECO_VENDA - CUSTO;

        MARGEM_CONCORRENTE = 100 - ((:CUSTO * 100) / :PRECO_CONCORRENTE);
        LUCRO_CONCORRENTE = PRECO_CONCORRENTE - CUSTO;
        SUSPEND;
      END
   END
END ^

ALTER PROCEDURE SP_APAGA_DADOS_ANTIGOS AS 
declare variable TIPOLOJA varchar(1);
BEGIN
  DELETE FROM ITENS_AUDITORIA WHERE ID_AUDITORIA IN (SELECT ID_AUDITORIA FROM AUDITORIA WHERE DATA <= CURRENT_DATE - 30);
  DELETE FROM AUDITORIA WHERE DATA <= CURRENT_DATE - 30;
  DELETE FROM ERROS_LOG WHERE DATA <= CURRENT_DATE - 30;
  DELETE FROM LOGINTERLIGACAO WHERE DATA <= CURRENT_DATE - 20;
  DELETE FROM ITENS_COMPRA WHERE ITENS_COMPRA.CD_COMPRAS IN (SELECT CD_COMPRAS FROM COMPRAS WHERE COMPRAS.DT_PEDIDO < CURRENT_DATE - 30 AND STATUS = 'G');
  DELETE FROM COMPRAS WHERE COMPRAS.DT_PEDIDO < CURRENT_DATE - 30 AND STATUS = 'G';
  DELETE FROM REAJUSTE WHERE REAJUSTE.DATA <= CURRENT_DATE - 90;

  SELECT TIPO_LOJA FROM PARAMETROS INTO :TIPOLOJA;
  IF (:TIPOLOJA = 'L') THEN
   BEGIN
     DELETE FROM POSICAOESTOQUEDATA WHERE DATA < CURRENT_DATE - 30;
   END

END ^

ALTER PROCEDURE SP_APAGA_ESTOQUEIMS AS 
BEGIN
  DELETE FROM ESTOQUEIMS WHERE DATA <= CURRENT_DATE - 30;
END ^

ALTER PROCEDURE SP_APAGA_INDICES AS 
BEGIN
    DELETE FROM RDB$INDICES WHERE RDB$INDEX_NAME IN
    (SELECT
      RDB$INDEX_NAME
     FROM
      RDB$INDICES
     WHERE
      RDB$INDEX_NAME LIKE 'PK%' AND
      RDB$INDEX_NAME NOT IN
      (SELECT RDB$INDEX_NAME FROM RDB$RELATION_CONSTRAINTS WHERE RDB$INDEX_NAME IS NOT NULL)
    );
END ^

ALTER PROCEDURE SP_APAGA_ITENS_COTACAO_0 (ID_COTACAO DOUBLE PRECISION)
AS 
BEGIN
  DELETE FROM ITENS_COTACOES WHERE ID_COTACAO = :ID_COTACAO AND (PRECO = 0 OR PRECO IS NULL);
END ^

ALTER PROCEDURE SP_APAGA_PEDIDOGESTAO_INATIVO AS 
declare variable CD_COMPRAS double precision;
declare variable COMANDO varchar(1000);
declare variable EXISTE integer;
BEGIN
  FOR
    SELECT CD_COMPRAS FROM PEDIDOS_GESTAO WHERE STATUS = 'I' INTO :CD_COMPRAS
  DO
   BEGIN
      COMANDO = '';
      COMANDO = 'SELECT COUNT(*) FROM RDB$RELATIONS WHERE RDB$SYSTEM_FLAG=0 AND RDB$RELATION_NAME = ''TPG'||CAST(:CD_COMPRAS AS INTEGER)||'''';
      EXECUTE STATEMENT :COMANDO INTO :EXISTE;
      IF (:EXISTE > 0) THEN
       BEGIN
         COMANDO = 'DROP TABLE TPG'||CAST(:CD_COMPRAS AS INTEGER);
         EXECUTE STATEMENT :COMANDO;
       END
   END
  DELETE FROM PEDIDOS_GESTAO WHERE STATUS = 'I';
END ^

ALTER PROCEDURE SP_APAGA_PEDIDOGESTAO_VAZIO AS 
declare variable CD_COMPRAS double precision;
declare variable data date;
declare variable COMANDO varchar(100);
declare variable EXISTE integer;
BEGIN
  FOR
    SELECT CD_COMPRAS, DATA FROM PEDIDOS_GESTAO WHERE DATA <= CURRENT_DATE - 10 INTO :CD_COMPRAS, :DATA
  DO
   BEGIN
      COMANDO = '';
      COMANDO = 'SELECT COUNT(*) FROM RDB$RELATIONS WHERE RDB$SYSTEM_FLAG=0 AND RDB$RELATION_NAME = ''TPG'||CAST(:CD_COMPRAS AS INTEGER)||'''';
      EXECUTE STATEMENT :COMANDO INTO :EXISTE;
      IF (:EXISTE > 0) THEN
       BEGIN
         COMANDO = '';
         COMANDO = 'DROP TABLE TPG'||CAST(:CD_COMPRAS AS INTEGER);
         EXECUTE STATEMENT :COMANDO;
       END
   END
  DELETE FROM PEDIDOS_GESTAO WHERE DATA <= CURRENT_DATE - 10;
END ^

ALTER PROCEDURE SP_APAGA_PRODDISTRDUPLICADO AS 
declare variable CD_DISTRIBUIDOR double precision;
BEGIN
  DELETE FROM PROD_DISTR WHERE ID_PRODUTO = 0;
  DELETE FROM PROD_DISTR WHERE CODIGO_BARRAS_1 IS NULL;
  UPDATE PROD_DISTR SET QT_EMBALAGEM = 1 WHERE ((QT_EMBALAGEM = 0) OR (QT_EMBALAGEM IS NULL));

  FOR
    SELECT DISTINCT CD_DISTRIBUIDOR FROM PROD_DISTR INTO :CD_DISTRIBUIDOR
  DO
   BEGIN
     DELETE FROM PROD_DISTR WHERE CD_DISTRIBUIDOR = :CD_DISTRIBUIDOR AND ID_PRODUTO IN
     (SELECT ID_PRODUTO FROM PROD_DISTR WHERE CD_DISTRIBUIDOR = :CD_DISTRIBUIDOR
      GROUP BY ID_PRODUTO HAVING COUNT(ID_PRODUTO) > 1);
   END
END ^

ALTER PROCEDURE SP_APAGA_TEMPLANCAMENTOSAPRAZO (CD_FILIAL_DESTINO DOUBLE PRECISION)
AS 
