ALTER PROCEDURE SP_APLICA_CUSTO_APLICADO RETURNS (ID_PRODUTO DOUBLE PRECISION,
CUSTO_APLICADO NUMERIC(15, 2),
CUSTO_UNITARIO NUMERIC(15, 2),
CD_COMPRAS DOUBLE PRECISION,
DT_ENTRADA DATE)
AS 
BEGIN
  FOR
    SELECT ID_PRODUTO FROM PRODUTOS INTO :ID_PRODUTO
  DO
   BEGIN
     CUSTO_APLICADO = 0;

     SELECT FIRST 1 COMPRAS.CD_COMPRAS, ITENS_COMPRA.CUSTO_APLICADO, COMPRAS.DT_ENTRADA
     FROM COMPRAS, ITENS_COMPRA
     WHERE
       COMPRAS.STATUS = 'C' AND
       --COMPRAS.BONIFICACAO = 'N' AND
       COMPRAS.CD_COMPRAS = ITENS_COMPRA.CD_COMPRAS AND
       ITENS_COMPRA.ID_PRODUTO = :ID_PRODUTO
     ORDER BY COMPRAS.DT_ENTRADA DESC
     INTO :CD_COMPRAS, :CUSTO_APLICADO, :DT_ENTRADA;

     IF ((:CUSTO_APLICADO IS NOT NULL) AND (:CUSTO_APLICADO > 0)) THEN
      BEGIN
        SELECT CUSTO_UNITARIO_1 FROM PRODUTOS WHERE ID_PRODUTO = :ID_PRODUTO INTO :CUSTO_UNITARIO;
        IF (:CUSTO_APLICADO <> :CUSTO_UNITARIO) THEN
           SUSPEND;
      END
   END
END ^

ALTER PROCEDURE SP_APLICA_JUROS_CONTASRECEBER (TIPO VARCHAR(1) CHARACTER SET NONE,
CODIGO DOUBLE PRECISION,
CD_CONTAS_RECEBER DOUBLE PRECISION)
AS 
DECLARE VARIABLE PERCENTUAL DOUBLE PRECISION;
DECLARE VARIABLE DIAS_CARENCIA DOUBLE PRECISION;
BEGIN
  SELECT
   PERCENTUALJUROSCONTASRECEBER,
   DIAS_CARENCIA_JUROS_CR
  FROM
   PARAMETROS
  INTO
   :PERCENTUAL,
   :DIAS_CARENCIA;

  IF (:DIAS_CARENCIA IS NULL) THEN
     DIAS_CARENCIA = 0;
  IF ((:PERCENTUAL IS NOT NULL) AND (:PERCENTUAL > 0)) THEN
   BEGIN
     IF (:TIPO = 'V') THEN
      BEGIN
         UPDATE CONTAS_RECEBER SET
            VL_SALDO = CAST(VALOR + ((VALOR * :PERCENTUAL) / 100) * ((CURRENT_DATE - :DIAS_CARENCIA) - DT_VENCIMENTO) AS NUMERIC(15,2)),
            VL_JUROS = CAST(((VALOR * :PERCENTUAL) / 100) * ((CURRENT_DATE - :DIAS_CARENCIA) - DT_VENCIMENTO) AS NUMERIC(15,2))
         WHERE
          CD_CONVENIO = :CODIGO AND
          DT_VENCIMENTO < CURRENT_DATE AND
          CD_PLANO_CONTAS = 5 AND
          STATUS = 'A' AND
          ((CURRENT_DATE - :DIAS_CARENCIA) - DT_VENCIMENTO) > 0;
      END
     ELSE
     IF (:TIPO = 'X') THEN
      BEGIN
         UPDATE CONTAS_RECEBER SET
            VL_SALDO = CAST(VALOR + ((VALOR * :PERCENTUAL) / 100) * ((CURRENT_DATE - :DIAS_CARENCIA) - DT_VENCIMENTO) AS NUMERIC(15,2)),
            VL_JUROS = CAST(((VALOR * :PERCENTUAL) / 100) * ((CURRENT_DATE - :DIAS_CARENCIA) - DT_VENCIMENTO) AS NUMERIC(15,2))
         WHERE
          CD_CONTAS_RECEBER = :CD_CONTAS_RECEBER AND
          ((CURRENT_DATE - :DIAS_CARENCIA) - DT_VENCIMENTO) > 0;
      END
     ELSE
      BEGIN
         UPDATE CONTAS_RECEBER SET
            VL_SALDO = CAST(VALOR + ((VALOR * :PERCENTUAL) / 100) * ((CURRENT_DATE - :DIAS_CARENCIA) - DT_VENCIMENTO) AS NUMERIC(15,2)),
            VL_JUROS = CAST(((VALOR * :PERCENTUAL) / 100) * ((CURRENT_DATE - :DIAS_CARENCIA) - DT_VENCIMENTO) AS NUMERIC(15,2))
         WHERE
          CD_CLIENTE = :CODIGO AND
          DT_VENCIMENTO < CURRENT_DATE AND
          CD_PLANO_CONTAS <> 3 AND
          CD_PLANO_CONTAS <> 4 AND
          STATUS = 'A' AND
          ((CURRENT_DATE - :DIAS_CARENCIA) - DT_VENCIMENTO) > 0;
      END
   END
END ^

ALTER PROCEDURE SP_APLICA_JUROS_CR_ANTERIOR AS 
DECLARE VARIABLE DIAS_CARENCIA INTEGER;
DECLARE VARIABLE PERCENTUAL DOUBLE PRECISION;
BEGIN
  SELECT
   PARAMETROS.PERCENTUALJUROSCONTASRECEBER,
   PARAMETROS.DIAS_CARENCIA_JUROS_CR
  FROM
   PARAMETROS
  INTO
   :PERCENTUAL,
   :DIAS_CARENCIA;

  IF (:DIAS_CARENCIA IS NULL) THEN DIAS_CARENCIA = 0;
  IF ((:PERCENTUAL IS NOT NULL) AND (:PERCENTUAL > 0)) THEN
   BEGIN
     UPDATE CONTAS_RECEBER SET
      VL_SALDO = CAST(VALOR + ((VALOR * :PERCENTUAL) / 100) * ((CURRENT_DATE - :DIAS_CARENCIA) - DT_VENCIMENTO) AS NUMERIC(15,2)),
      VL_JUROS = CAST(((VALOR * :PERCENTUAL) / 100) * ((CURRENT_DATE - :DIAS_CARENCIA) - DT_VENCIMENTO) AS NUMERIC(15,2))
     WHERE
      CD_CLIENTE <> 999999 AND 
      DT_VENCIMENTO < CURRENT_DATE AND
      STATUS = 'A' AND
      ((CURRENT_DATE - :DIAS_CARENCIA) - DT_VENCIMENTO) > 0;
   END
END ^

ALTER PROCEDURE SP_APLICA_SLEEP_ENCARTE AS 
declare variable ID_PRODUTO double precision;
declare variable PRECO_VENDA double precision;
declare variable PRECO_PROMOCAO double precision;
declare variable DT_VENCIMENTO_PROMOCAO date;
BEGIN
  FOR
    SELECT
     ID_PRODUTO,
     PRECO_NOVO,
     PRECO_PROMOCAO_NOVO,
     VENCIMENTO_PROMOCAO_NOVO
    FROM
     REAJUSTE
    WHERE
     DATA_REAJUSTE = CURRENT_DATE
    INTO
     :ID_PRODUTO,
     :PRECO_VENDA,
     :PRECO_PROMOCAO,
     :DT_VENCIMENTO_PROMOCAO
  DO
   BEGIN
     UPDATE PRODUTOS SET
      PRECO_VENDA = :PRECO_VENDA,
      PRECO_PROMOCAO = :PRECO_PROMOCAO,
      DT_VENCIMENTO_PROMOCAO = :DT_VENCIMENTO_PROMOCAO,
      DT_REAJUSTE = CURRENT_DATE
     WHERE
      ID_PRODUTO = :ID_PRODUTO;

     UPDATE REAJUSTE SET
      REAJUSTADO = 'S'
     WHERE
      ID_PRODUTO = :ID_PRODUTO AND DATA_REAJUSTE = CURRENT_DATE;
   END
END ^

ALTER PROCEDURE SP_APURACAO (ANO VARCHAR(4) CHARACTER SET NONE)
AS 
declare variable CONTA1 varchar(50) = ' 1 - Vendas                             ';
declare variable CONTA2 varchar(50) = ' 2 - Custo das Mercadorias              ';
declare variable CONTA3 varchar(50) = ' 3 - Lucro Bruto (1 - 2)                ';
declare variable CONTA4 varchar(50) = ' 4 - Despesas Variaveis                 ';
declare variable CONTA5 varchar(50) = ' 5 - Margem de Contribuicao  (3 - 4)    ';
declare variable CONTA6 varchar(50) = ' 6 - Despesas Fixas                     ';
declare variable CONTA7 varchar(50) = ' 7 - Despesas Financeiras               ';
declare variable CONTA8 varchar(50) = ' 8 - Resultado Liquido                  ';
declare variable RECEITAS double precision;
declare variable CUSTO double precision;
declare variable LUCRO double precision;
declare variable VARIAVEIS double precision;
declare variable MARGEM double precision;
declare variable FIXAS double precision;
declare variable RESULTADO double precision;
declare variable MES varchar(2);
declare variable CD_FILIAL double precision;
declare variable EXISTE integer;
declare variable FINANCEIRAS double precision;
BEGIN
 --Gerando valor das Vendas, Custos das Mercadorias e Lucro Bruto
 FOR
     SELECT
      LANCAMENTOS.CD_FILIAL,

      EXTRACT(MONTH FROM DATA_CAIXA),

      SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO), /* VENDAS */

      SUM(LANCAMENTOS.QUANTIDADE * LANCAMENTOS.CUSTO_UNITARIO), /* CUSTO */

      (SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO) -
      SUM(LANCAMENTOS.QUANTIDADE * LANCAMENTOS.CUSTO_UNITARIO)) /* LUCRO */

     FROM
      LANCAMENTOS
     WHERE
      (LANCAMENTOS.TIPO_VENDA = 'V' OR LANCAMENTOS.TIPO_VENDA = 'D') AND
      EXTRACT(YEAR FROM LANCAMENTOS.DATA_CAIXA) = :ANO
     GROUP BY
      LANCAMENTOS.CD_FILIAL,
      EXTRACT(MONTH FROM DATA_CAIXA)
     INTO
      :CD_FILIAL,
      :MES,
      :RECEITAS,
      :CUSTO,
      :LUCRO
 DO
  BEGIN
     SELECT
      COUNT(*)
     FROM
      APURACAO
     WHERE
      FILIAL = :CD_FILIAL AND MES = :MES AND ANO = :ANO
     INTO
      :EXISTE;

     IF (EXISTE = 0) THEN
      BEGIN
         INSERT INTO APURACAO VALUES (:CD_FILIAL, :MES, :ANO, :CONTA1 ,:RECEITAS, 100, :RECEITAS);
         INSERT INTO APURACAO VALUES (:CD_FILIAL, :MES, :ANO, :CONTA2 ,:CUSTO, :CUSTO / :RECEITAS * 100, :RECEITAS);
         INSERT INTO APURACAO VALUES (:CD_FILIAL, :MES, :ANO, :CONTA3 ,:LUCRO, :LUCRO / :RECEITAS * 100, :RECEITAS);
         INSERT INTO APURACAO VALUES (:CD_FILIAL, :MES, :ANO, :CONTA4 ,0, 0,:RECEITAS);
         INSERT INTO APURACAO VALUES (:CD_FILIAL, :MES, :ANO, :CONTA5 ,0, 0,:RECEITAS);
         INSERT INTO APURACAO VALUES (:CD_FILIAL, :MES, :ANO, :CONTA6 ,0, 0,:RECEITAS);
         INSERT INTO APURACAO VALUES (:CD_FILIAL, :MES, :ANO, :CONTA7 ,0, 0,:RECEITAS);
         INSERT INTO APURACAO VALUES (:CD_FILIAL, :MES, :ANO, :CONTA8 ,0, 0,:RECEITAS);
      END
     ELSE
      BEGIN
         UPDATE APURACAO SET VALOR = :RECEITAS, INDICE = 100                   WHERE FILIAL = :CD_FILIAL AND MES = :MES AND ANO = :ANO AND NOME_DA_CONTA = :CONTA1;
         UPDATE APURACAO SET VALOR = :CUSTO, INDICE = :CUSTO / :RECEITAS * 100 WHERE FILIAL = :CD_FILIAL AND MES = :MES AND ANO = :ANO AND NOME_DA_CONTA = :CONTA2;
         UPDATE APURACAO SET VALOR = :LUCRO, INDICE = :LUCRO / :RECEITAS * 100 WHERE FILIAL = :CD_FILIAL AND MES = :MES AND ANO = :ANO AND NOME_DA_CONTA = :CONTA3;
         UPDATE APURACAO SET VALOR = 0, TEMPORARIO = :RECEITAS  WHERE FILIAL = :CD_FILIAL AND MES = :MES AND ANO = :ANO AND NOME_DA_CONTA = :CONTA4;
         UPDATE APURACAO SET VALOR = 0, TEMPORARIO = :RECEITAS  WHERE FILIAL = :CD_FILIAL AND MES = :MES AND ANO = :ANO AND NOME_DA_CONTA = :CONTA5;
         UPDATE APURACAO SET VALOR = 0, TEMPORARIO = :RECEITAS  WHERE FILIAL = :CD_FILIAL AND MES = :MES AND ANO = :ANO AND NOME_DA_CONTA = :CONTA6;
         UPDATE APURACAO SET VALOR = 0, TEMPORARIO = :RECEITAS  WHERE FILIAL = :CD_FILIAL AND MES = :MES AND ANO = :ANO AND NOME_DA_CONTA = :CONTA7;
         UPDATE APURACAO SET VALOR = 0, TEMPORARIO = :RECEITAS  WHERE FILIAL = :CD_FILIAL AND MES = :MES AND ANO = :ANO AND NOME_DA_CONTA = :CONTA8;
      END
  END

 --Gerando Despesas Fixas
 FOR
   SELECT
    MOVIMENTOCAIXA.CD_FILIAL,
    EXTRACT(MONTH FROM MOVIMENTOCAIXA.DATA),
    SUM(MOVIMENTOCAIXA.VALOR)
   FROM
    MOVIMENTOCAIXA,
    PLANO_CONTAS
   WHERE
    MOVIMENTOCAIXA.CD_PLANO_CONTAS = PLANO_CONTAS.CD_PLANO_CONTAS AND
    EXTRACT(YEAR FROM MOVIMENTOCAIXA.DATA) = :ANO AND
    PLANO_CONTAS.CD_HISTORICO LIKE '2.10.%'
   GROUP BY
    MOVIMENTOCAIXA.CD_FILIAL,
    EXTRACT(MONTH FROM MOVIMENTOCAIXA.DATA)
   INTO
    :CD_FILIAL,
    :MES,
    :FIXAS
 DO
  BEGIN
     SELECT
      COUNT(*)
     FROM
      APURACAO
     WHERE
      FILIAL = :CD_FILIAL AND MES = :MES AND ANO = :ANO AND NOME_DA_CONTA = :CONTA6
     INTO
      :EXISTE;

     IF (EXISTE = 0) THEN
      BEGIN
         INSERT INTO APURACAO VALUES (:CD_FILIAL, :MES, :ANO, :CONTA6 ,:FIXAS, 0, 0);
      END
     ELSE
      BEGIN
         UPDATE APURACAO SET VALOR = :FIXAS, INDICE = :FIXAS / TEMPORARIO * 100 WHERE FILIAL = :CD_FILIAL AND MES = :MES AND ANO = :ANO AND NOME_DA_CONTA = :CONTA6;
      END
  END

 --Gerando as Despesas Variaveis e Calculo das Comissoes
 FOR
   SELECT
    LANCAMENTOS.CD_FILIAL,
    EXTRACT(MONTH FROM LANCAMENTOS.DATA_CAIXA),
    SUM(((LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO) * GRUPOS.TX_COMISSAO) / 100)
   FROM
    LANCAMENTOS LEFT OUTER JOIN VENDEDORES ON LANCAMENTOS.CD_VENDEDOR = VENDEDORES.CD_VENDEDOR,
    GRUPOS
   WHERE
    LANCAMENTOS.CD_FILIAL = VENDEDORES.CD_FILIAL AND
    LANCAMENTOS.CD_GRUPO = GRUPOS.CD_GRUPO AND
    EXTRACT(YEAR FROM LANCAMENTOS.DATA_CAIXA) = :ANO AND
    (LANCAMENTOS.TIPO_VENDA = 'V' OR LANCAMENTOS.TIPO_VENDA = 'D')
   GROUP BY
    LANCAMENTOS.CD_FILIAL,
    EXTRACT(MONTH FROM LANCAMENTOS.DATA_CAIXA)
   INTO
    :CD_FILIAL,
    :MES,
    :VARIAVEIS
 DO
  BEGIN
     SELECT
      COUNT(*)
     FROM
      APURACAO
     WHERE
      FILIAL = :CD_FILIAL AND MES = :MES AND ANO = :ANO AND NOME_DA_CONTA = :CONTA4
     INTO
      :EXISTE;

     IF (EXISTE = 0) THEN
      BEGIN
        INSERT INTO APURACAO VALUES (:CD_FILIAL, :MES, :ANO, :CONTA4 ,:VARIAVEIS, 0, 0);
      END
     ELSE
      BEGIN
         UPDATE APURACAO SET VALOR = :VARIAVEIS, INDICE = :VARIAVEIS / TEMPORARIO * 100 WHERE FILIAL = :CD_FILIAL AND MES = :MES AND ANO = :ANO AND NOME_DA_CONTA = :CONTA4;
      END
  END

 --Calculo do Custo Operacional
 FOR
   SELECT
    LANCAMENTOS.CD_FILIAL,
    EXTRACT(MONTH FROM LANCAMENTOS.DATA_CAIXA),
    SUM(((LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO) * PARAMETROS.CUSTO_OPERACIONAL) / 100)
   FROM
    LANCAMENTOS,
    PARAMETROS
   WHERE
    EXTRACT(YEAR FROM LANCAMENTOS.DATA_CAIXA) = :ANO AND
    (LANCAMENTOS.TIPO_VENDA = 'V' OR LANCAMENTOS.TIPO_VENDA = 'D')
   GROUP BY
    LANCAMENTOS.CD_FILIAL,
    EXTRACT(MONTH FROM LANCAMENTOS.DATA_CAIXA)
   INTO
    :CD_FILIAL,
    :MES,
    :VARIAVEIS
 DO
  BEGIN
     SELECT
      COUNT(*)
     FROM
      APURACAO
     WHERE
      FILIAL = :CD_FILIAL AND MES = :MES AND ANO = :ANO AND NOME_DA_CONTA = :CONTA4
     INTO
      :EXISTE;

     IF (EXISTE = 0) THEN
      BEGIN
        INSERT INTO APURACAO VALUES (:CD_FILIAL, :MES, :ANO, :CONTA4 ,:VARIAVEIS, 0, 0);
      END
     ELSE
      BEGIN
         UPDATE APURACAO SET VALOR = VALOR + :VARIAVEIS, INDICE = (VALOR + :VARIAVEIS) / TEMPORARIO * 100 WHERE FILIAL = :CD_FILIAL AND MES = :MES AND ANO = :ANO AND NOME_DA_CONTA = :CONTA4;
      END
  END


 --Gerando Despesas Financeiras
 FOR
   SELECT
    MOVIMENTOCAIXA.CD_FILIAL,
    EXTRACT(MONTH FROM MOVIMENTOCAIXA.DATA),
    SUM(MOVIMENTOCAIXA.VALOR)
   FROM
    MOVIMENTOCAIXA,
    PLANO_CONTAS
   WHERE
    MOVIMENTOCAIXA.CD_PLANO_CONTAS = PLANO_CONTAS.CD_PLANO_CONTAS AND
    EXTRACT(YEAR FROM MOVIMENTOCAIXA.DATA) = :ANO AND
    PLANO_CONTAS.CD_HISTORICO LIKE '2.12.%'
   GROUP BY
    MOVIMENTOCAIXA.CD_FILIAL,
    EXTRACT(MONTH FROM MOVIMENTOCAIXA.DATA)
   INTO
    :CD_FILIAL,
    :MES,
    :FINANCEIRAS
 DO
  BEGIN
     SELECT
      COUNT(*)
     FROM
      APURACAO
     WHERE
      FILIAL = :CD_FILIAL AND MES = :MES AND ANO = :ANO AND NOME_DA_CONTA = :CONTA7
     INTO
      :EXISTE;

     IF (EXISTE = 0) THEN
      BEGIN
        INSERT INTO APURACAO VALUES (:CD_FILIAL, :MES, :ANO, :CONTA7 ,:FINANCEIRAS, 0, 0);
      END
     ELSE
      BEGIN
         UPDATE APURACAO SET VALOR = :FINANCEIRAS, INDICE = :FINANCEIRAS / TEMPORARIO * 100 WHERE FILIAL = :CD_FILIAL AND MES = :MES AND ANO = :ANO AND NOME_DA_CONTA = :CONTA7;
      END
  END

 --Gerando Margem de Contribuicao e Lucro Liquido
 FOR
   SELECT
     FILIAL,
     MES
   FROM
    APURACAO
   WHERE
     ANO = :ANO
   INTO
    :CD_FILIAL,
    :MES
 DO
  BEGIN
     --Lucro Bruto
     SELECT
      SUM(VALOR)
     FROM
      APURACAO
     WHERE
      FILIAL = :CD_FILIAL AND MES = :MES AND ANO = :ANO AND NOME_DA_CONTA = :CONTA3
     INTO
      :LUCRO;

     --Despesas Variaveis
     SELECT
      SUM(VALOR)
     FROM
      APURACAO
     WHERE
      FILIAL = :CD_FILIAL AND MES = :MES AND ANO = :ANO AND NOME_DA_CONTA = :CONTA4
     INTO
      :VARIAVEIS;

     --Despesas Fixas
     SELECT
      SUM(VALOR)
     FROM
      APURACAO
     WHERE
      FILIAL = :CD_FILIAL AND MES = :MES AND ANO = :ANO AND NOME_DA_CONTA = :CONTA6
     INTO
      :FIXAS;

     --Despesas Financeiras
     SELECT
      SUM(VALOR)
     FROM
      APURACAO
     WHERE
      FILIAL = :CD_FILIAL AND MES = :MES AND ANO = :ANO AND NOME_DA_CONTA = :CONTA7
     INTO
      :FINANCEIRAS;

     --Calculando Margem e Resultado Liquido
     MARGEM = :LUCRO - :VARIAVEIS;
     RESULTADO = :MARGEM - :FIXAS - :FINANCEIRAS;

     --Incluindo / alterando a Margem de Contribuicao
     SELECT
      COUNT(*)
     FROM
      APURACAO
     WHERE
      FILIAL = :CD_FILIAL AND MES = :MES AND ANO = :ANO AND NOME_DA_CONTA = :CONTA5
     INTO
      :EXISTE;

     IF (EXISTE = 0) THEN
      BEGIN
        INSERT INTO APURACAO VALUES (:CD_FILIAL, :MES, :ANO, :CONTA5 ,:MARGEM, 0, 0);
      END
     ELSE
      BEGIN
         UPDATE APURACAO SET VALOR = :MARGEM, INDICE = :MARGEM / TEMPORARIO * 100 WHERE FILIAL = :CD_FILIAL AND MES = :MES AND ANO = :ANO AND NOME_DA_CONTA = :CONTA5;
      END

     --Incluindo / Alterando Lucro Liquido
     SELECT
      COUNT(*)
     FROM
      APURACAO
     WHERE
      FILIAL = :CD_FILIAL AND MES = :MES AND ANO = :ANO AND NOME_DA_CONTA = :CONTA8
     INTO
      :EXISTE;

     IF (EXISTE = 0) THEN
      BEGIN
        INSERT INTO APURACAO VALUES (:CD_FILIAL, :MES, :ANO, :CONTA8 ,:RESULTADO, 0, 0);
      END
     ELSE
      BEGIN
         UPDATE APURACAO SET VALOR = :RESULTADO, INDICE = :RESULTADO / TEMPORARIO * 100 WHERE FILIAL = :CD_FILIAL AND MES = :MES AND ANO = :ANO AND NOME_DA_CONTA = :CONTA8;
      END

  END


END ^

ALTER PROCEDURE SP_APURACAO_PLANOCONTAS (PARCODIGO VARCHAR(8) CHARACTER SET NONE,
CD_FILIAL DOUBLE PRECISION,
PARDATAINICIAL DATE,
PARDATAFINAL DATE)
AS 
declare variable CD_PLANO double precision;
declare variable CD_HISTORICO varchar(10);
declare variable HISTORICO varchar(100);
declare variable FILIAL double precision;
declare variable TIPO varchar(1);
declare variable DATA date;
declare variable VALOR double precision;
BEGIN

 DELETE FROM TEMP_APURACAORESULTADO;

 FOR
    SELECT
       PLANO_CONTAS.CD_PLANO_CONTAS,
       PLANO_CONTAS.CD_HISTORICO,
       PLANO_CONTAS.HISTORICO,
       MOVIMENTOCAIXA.CD_FILIAL,
       MOVIMENTOCAIXA.TIPO_MOVIMENTO,
       SUM(MOVIMENTOCAIXA.VALOR) AS VALOR
    
    FROM 
       PLANO_CONTAS LEFT JOIN MOVIMENTOCAIXA ON
       PLANO_CONTAS.CD_PLANO_CONTAS = MOVIMENTOCAIXA.CD_PLANO_CONTAS
       
    WHERE 
       PLANO_CONTAS.GRAU = '3' AND
       PLANO_CONTAS.CD_HISTORICO LIKE :PARCODIGO AND
       MOVIMENTOCAIXA.CD_FILIAL = :CD_FILIAL AND
       MOVIMENTOCAIXA.DATA >= :PARDATAINICIAL AND
       MOVIMENTOCAIXA.DATA <= :PARDATAFINAL
    
    GROUP BY
       PLANO_CONTAS.CD_PLANO_CONTAS,
       PLANO_CONTAS.CD_HISTORICO,
       PLANO_CONTAS.HISTORICO,
       MOVIMENTOCAIXA.CD_FILIAL,
       MOVIMENTOCAIXA.TIPO_MOVIMENTO
    INTO
       :CD_PLANO,
       :CD_HISTORICO,
       :HISTORICO,
       :FILIAL,
       :TIPO,
       :VALOR
 DO
  BEGIN
   IF (:TIPO = 'C') THEN
      INSERT INTO TEMP_APURACAORESULTADO VALUES (:FILIAL, :CD_PLANO, :CD_HISTORICO, :HISTORICO, 0, :VALOR);
   ELSE
      INSERT INTO TEMP_APURACAORESULTADO VALUES (:FILIAL, :CD_PLANO, :CD_HISTORICO, :HISTORICO, :VALOR, 0);
  END

 FOR
    SELECT
      PLANO_CONTAS.CD_PLANO_CONTAS,
      PLANO_CONTAS.CD_HISTORICO,
      PLANO_CONTAS.HISTORICO
    FROM
      PLANO_CONTAS
    WHERE
      PLANO_CONTAS.CD_HISTORICO LIKE :PARCODIGO AND
      PLANO_CONTAS.GRAU < '3'
    INTO
      :CD_PLANO,
      :CD_HISTORICO,
      :HISTORICO
 DO
  BEGIN
      INSERT INTO TEMP_APURACAORESULTADO VALUES (:FILIAL, :CD_PLANO, :CD_HISTORICO, :HISTORICO, 0, 0);
  END
END ^

ALTER PROCEDURE SP_APURACAO_RESULTADO (ANO VARCHAR(4) CHARACTER SET NONE)
AS 
DECLARE VARIABLE VENDAS DOUBLE PRECISION;
DECLARE VARIABLE EXISTE INTEGER;
DECLARE VARIABLE CUSTO DOUBLE PRECISION;
DECLARE VARIABLE LUCRO DOUBLE PRECISION;
DECLARE VARIABLE VARIAVEIS DOUBLE PRECISION;
DECLARE VARIABLE MARGEM DOUBLE PRECISION;
DECLARE VARIABLE FIXAS DOUBLE PRECISION;
DECLARE VARIABLE RESULTADO DOUBLE PRECISION;
DECLARE VARIABLE MES VARCHAR(2);
DECLARE VARIABLE CD_FILIAL DOUBLE PRECISION;
BEGIN
 FOR
     SELECT
      LANCAMENTOS.CD_FILIAL,

      EXTRACT(MONTH FROM DATA_LANCAMENTO),

      SUM(LANCAMENTOS.VALOR),

      SUM(LANCAMENTOS.QUANTIDADE * LANCAMENTOS.CUSTO_UNITARIO),

      (SUM(LANCAMENTOS.VALOR) -
      SUM(LANCAMENTOS.QUANTIDADE * LANCAMENTOS.CUSTO_UNITARIO)),

      (SUM(LANCAMENTOS.VALOR) * 0.05),

      ((SUM(LANCAMENTOS.VALOR) -
      SUM(LANCAMENTOS.QUANTIDADE * LANCAMENTOS.CUSTO_UNITARIO)) -
      (SUM(LANCAMENTOS.VALOR) * 0.05)),
                                                                      
      (SUM(LANCAMENTOS.VALOR) * 0.245),

      (((SUM(LANCAMENTOS.VALOR) -
      SUM(LANCAMENTOS.QUANTIDADE * LANCAMENTOS.CUSTO_UNITARIO)) -
      (SUM(LANCAMENTOS.VALOR) * 0.05)) -
      (SUM(LANCAMENTOS.VALOR) * 0.245))
     FROM
      LANCAMENTOS
     WHERE
      LANCAMENTOS.TIPO_VENDA = 'V' AND
      EXTRACT(YEAR FROM LANCAMENTOS.DATA_LANCAMENTO) = :ANO
     GROUP BY
      LANCAMENTOS.CD_FILIAL,
      EXTRACT(MONTH FROM DATA_LANCAMENTO)
     INTO
      :CD_FILIAL,
      :MES,
      :VENDAS,
      :CUSTO,
      :LUCRO,
      :VARIAVEIS,
      :MARGEM,
      :FIXAS,
      :RESULTADO
 DO
  BEGIN
     SELECT
      COUNT(*)
     FROM
      APURACAO_RESULTADO
     WHERE
      FILIAL = :CD_FILIAL AND MES = :MES AND ANO = :ANO
     INTO
      :EXISTE;

     IF (EXISTE = 0) THEN
      BEGIN
         INSERT INTO APURACAO_RESULTADO VALUES (:CD_FILIAL, :MES, :ANO, :VENDAS, :CUSTO, :LUCRO, :VARIAVEIS, :MARGEM, :FIXAS,0, :RESULTADO);
      END
     ELSE
      BEGIN
        UPDATE APURACAO_RESULTADO SET
         VENDAS = :VENDAS,
         CUSTOS_MERCADORIA = :CUSTO,
         LUCRO_BRUTO = :LUCRO,
         DESPESAS_VARIAVEIS = :VARIAVEIS,
         MARGEM_CONTRIBUICAO = :MARGEM,
         DESPESAS_FIXAS = :FIXAS,
         RESULTADO_LIQUIDO = :RESULTADO
        WHERE FILIAL = :CD_FILIAL AND MES = :MES AND ANO = :ANO;
      END
  END
END ^

ALTER PROCEDURE SP_ARMAZENA_ESTOQUEIMS AS 
declare variable ID_PRODUTO double precision;
declare variable ESTOQUE double precision;
declare variable USAIMS varchar(1);
BEGIN
  SELECT USAIMS FROM PARAMETROS INTO :USAIMS;
  IF (:USAIMS = 'S') THEN
   BEGIN
     FOR
       SELECT ID_PRODUTO, ESTOQUE_0 FROM PRODUTOS WHERE STATUS = 'A' INTO :ID_PRODUTO, :ESTOQUE
     DO
      BEGIN
        INSERT INTO ESTOQUEIMS VALUES (CURRENT_DATE, :ID_PRODUTO,  :ESTOQUE);
      END
   END
END ^

ALTER PROCEDURE SP_ARMAZENA_POSICAOESTOQUE AS 
DECLARE VARIABLE CD_FILIAL DOUBLE PRECISION;
DECLARE VARIABLE ID_PRODUTO DOUBLE PRECISION;
DECLARE VARIABLE ESTOQUE DOUBLE PRECISION;
DECLARE VARIABLE CUSTO DOUBLE PRECISION;
DECLARE VARIABLE VENDA DOUBLE PRECISION;
DECLARE VARIABLE COMANDO VARCHAR(1000);
DECLARE VARIABLE POSICAOESTOQUEDATA VARCHAR(1);
BEGIN
  SELECT CD_FILIAL, ARMAZENAPOSICAOESTOQUEDATA FROM PARAMETROS INTO :CD_FILIAL, :POSICAOESTOQUEDATA;
  COMANDO = 'SELECT ID_PRODUTO, ESTOQUE_'||CAST(:CD_FILIAL AS INTEGER)||', PRECO_VENDA, CUSTO_UNITARIO_'||CAST(:CD_FILIAL AS INTEGER)||' FROM PRODUTOS WHERE STATUS = '''||'A'||'''';
  FOR
    EXECUTE STATEMENT :COMANDO INTO :ID_PRODUTO, :ESTOQUE, :VENDA, :CUSTO
  DO
   BEGIN
     INSERT INTO POSICAOESTOQUEDATA VALUES (CURRENT_DATE, :CD_FILIAL, :ID_PRODUTO,  :ESTOQUE, CAST(:CUSTO AS NUMERIC(15,2)), CAST(:VENDA AS NUMERIC(15,2)), '');
   END
END ^

ALTER PROCEDURE SP_ARREDONDA_PRECO_FIDELIDADE (ARREDONDAMENTO NUMERIC(15, 2))
RETURNS (CD_FILIAL DOUBLE PRECISION,
ID_PRODUTO DOUBLE PRECISION,
PRECO NUMERIC(15, 2),
INTEIRO INTEGER,
SINTEIRO VARCHAR(100) CHARACTER SET NONE,
DECIMAIS NUMERIC(15, 2),
SDECIMAIS VARCHAR(100) CHARACTER SET NONE,
DECIMAIS_NOVO VARCHAR(100) CHARACTER SET NONE,
SNOVOPRECO VARCHAR(100) CHARACTER SET NONE,
NOVOPRECO NUMERIC(15, 2))
AS 
BEGIN
  FOR
    SELECT CD_FILIAL, ID_PRODUTO, PRECO FROM FILIAIS_FIDELIDADE INTO :CD_FILIAL, :ID_PRODUTO, :PRECO
  DO
   BEGIN
     DECIMAIS_NOVO = '';
     INTEIRO = TRUNC(:PRECO);
     SINTEIRO = TRUNC(:PRECO);
     DECIMAIS = :PRECO - TRUNC(:PRECO);
     SDECIMAIS = :PRECO - TRUNC(:PRECO);
     IF (:ARREDONDAMENTO = 0.05) THEN
      BEGIN
         IF ((SUBSTRING(:SDECIMAIS FROM 4 FOR 1) > 0) AND (SUBSTRING(:SDECIMAIS FROM 4 FOR 1) < 5)) THEN
          BEGIN
            DECIMAIS_NOVO = SUBSTRING(:SDECIMAIS FROM 1 FOR 3) || '5';
          END
         ELSE
         IF (SUBSTRING(:DECIMAIS FROM 4 FOR 1) > 5) THEN
          BEGIN
            IF (:DECIMAIS >= 0.9) THEN
             BEGIN
               INTEIRO = :INTEIRO + 1;
               SINTEIRO = CAST(:INTEIRO AS VARCHAR(100));
             END
            DECIMAIS = :DECIMAIS + 0.1;
            SDECIMAIS = CAST(:DECIMAIS AS VARCHAR(100));
            DECIMAIS_NOVO = SUBSTRING(:SDECIMAIS FROM 1 FOR 3) || '0';
          END
         ELSE
          BEGIN
            DECIMAIS_NOVO = :SDECIMAIS;
          END
      END
     ELSE
     IF (:ARREDONDAMENTO = 0.10) THEN
      BEGIN
         IF (SUBSTRING(:SDECIMAIS FROM 4 FOR 1) >= 5) THEN
          BEGIN
            IF (SUBSTRING(SDECIMAIS FROM 3 FOR 1) < 9) THEN
             BEGIN
               DECIMAIS = :DECIMAIS + 0.1;
               SDECIMAIS = CAST(:DECIMAIS AS VARCHAR(100));
               DECIMAIS_NOVO = SUBSTRING(:SDECIMAIS FROM 1 FOR 3) || '0';
             END
            ELSE
            IF (SUBSTRING(SDECIMAIS FROM 3 FOR 1) = 9) THEN
             BEGIN
               INTEIRO = :INTEIRO + 1;
               DECIMAIS_NOVO = SUBSTRING(:SDECIMAIS FROM 1 FOR 2) || '00';
             END
          END
         ELSE
         IF (SUBSTRING(:SDECIMAIS FROM 4 FOR 1) < 5) THEN
          BEGIN
            DECIMAIS_NOVO = SUBSTRING(:SDECIMAIS FROM 1 FOR 3) || '0';
          END
         ELSE
          BEGIN
            DECIMAIS_NOVO = :SDECIMAIS;
          END
      END
     ELSE
     IF (:ARREDONDAMENTO = 0.50) THEN
      BEGIN
         IF (DECIMAIS <> 0.00) THEN
          BEGIN
             IF (SUBSTRING(:SDECIMAIS FROM 3 FOR 1) >= 5) THEN
              BEGIN
                INTEIRO = :INTEIRO + 1;
                SINTEIRO = CAST(:INTEIRO AS VARCHAR(100));
                DECIMAIS_NOVO = '0.00';
              END
             ELSE
             IF (SUBSTRING(:SDECIMAIS FROM 3 FOR 1) < 5) THEN
              BEGIN
                DECIMAIS_NOVO = SUBSTRING(:SDECIMAIS FROM 1 FOR 2) || '00';
              END
             ELSE
              BEGIN
                DECIMAIS_NOVO = :SDECIMAIS;
              END
          END
      END

     SNOVOPRECO = INTEIRO || SUBSTRING(:DECIMAIS_NOVO FROM 2 FOR 3);
     NOVOPRECO = CAST(:SNOVOPRECO AS NUMERIC(15,2));

     IF (:PRECO <> :NOVOPRECO) THEN
      BEGIN
         UPDATE FILIAIS_FIDELIDADE SET
          PRECO = :SNOVOPRECO
         WHERE CD_FILIAL = :CD_FILIAL AND ID_PRODUTO = :ID_PRODUTO;
      END

     --SUSPEND;
   END
END ^

