END ^

ALTER PROCEDURE SP_ATUALIZACONTASRECEBERCARTAO AS 
DECLARE VARIABLE CARTAO DOUBLE PRECISION;
DECLARE VARIABLE TAXA DOUBLE PRECISION;
BEGIN
  FOR
    SELECT
     CD_CARTAO,
     TX_ADM
    FROM
     CARTOES
    INTO
     :CARTAO,
     :TAXA
  DO
   BEGIN
      UPDATE CONTAS_RECEBER SET
       VL_DESCONTO = (VALOR * :TAXA) / 100,
       VL_SALDO = VALOR - VL_DESCONTO
      WHERE
       STATUS <> 'P' AND CD_FORMA_PAGAMENTO = 2;
   END
END ^

ALTER PROCEDURE SP_ATUALIZA_BALANCO (ID_BALANCO DOUBLE PRECISION,
ID_MOTIVO DOUBLE PRECISION,
DATA DATE,
HORA TIME,
DATA_ABERTURA DATE,
HORA_ABERTURA TIME,
DATA_CONTAGEM DATE,
HORA_CONTAGEM TIME,
DATA_CONCLUSAO DATE,
HORA_CONCLUSAO TIME,
CD_FILIAL DOUBLE PRECISION,
ID_PRODUTO DOUBLE PRECISION,
CD_PRODUTO VARCHAR(6) CHARACTER SET NONE,
CODIGO_BARRAS_1 VARCHAR(14) CHARACTER SET NONE,
CODIGO_BARRAS_2 VARCHAR(14) CHARACTER SET NONE,
DESCRICAO VARCHAR(100) CHARACTER SET NONE,
CD_GRUPO DOUBLE PRECISION,
GRUPO VARCHAR(100) CHARACTER SET NONE,
CD_LABORATORIO DOUBLE PRECISION,
LABORATORIO VARCHAR(100) CHARACTER SET NONE,
CD_CLASSE DOUBLE PRECISION,
CLASSE VARCHAR(100) CHARACTER SET NONE,
CUSTO_UNITARIO DOUBLE PRECISION,
PRECO_VENDA DOUBLE PRECISION,
PRECO_VENDA_ANTERIOR DOUBLE PRECISION,
ESTOQUE DOUBLE PRECISION,
ESTOQUE_ANTERIOR DOUBLE PRECISION,
SUBSTITUIESTOQUE VARCHAR(1) CHARACTER SET NONE,
STATUS VARCHAR(1) CHARACTER SET NONE,
ENVIADO VARCHAR(1) CHARACTER SET NONE,
CD_SUBGRUPO DOUBLE PRECISION,
USUARIO_ABERTURA VARCHAR(100) CHARACTER SET NONE,
USUARIO_CONCLUSAO VARCHAR(100) CHARACTER SET NONE)
AS 
declare variable EXISTE integer;
BEGIN
  SELECT COUNT(*) FROM BALANCO WHERE ID_BALANCO = :ID_BALANCO AND ID_PRODUTO = :ID_PRODUTO INTO :EXISTE;
  /*IF (:DATA = '31.12.1899') THEN
      DATA = NULL;
  IF (:HORA = '31.12.1899') THEN
      HORA = NULL;
  IF (:DATA_ABERTURA = '31.12.1899') THEN
      DATA_ABERTURA = NULL;
  IF (:HORA_ABERTURA = '31.12.1899') THEN
      HORA_ABERTURA = NULL;
  IF (:DATA_CONCLUSAO = '31.12.1899') THEN
      DATA_CONCLUSAO = NULL;
  IF (:HORA_CONCLUSAO = '31.12.1899') THEN
      HORA_CONCLUSAO = NULL;
  IF (:DATA_CONTAGEM = '31.12.1899') THEN
      DATA_CONTAGEM = NULL;
  IF (:HORA_CONTAGEM = '31.12.1899') THEN
      HORA_CONTAGEM = NULL;*/

  IF (:EXISTE > 0) THEN
   BEGIN
     UPDATE BALANCO SET
          ID_BALANCO            = :ID_BALANCO,
          ID_MOTIVO             = :ID_MOTIVO,
          DATA                  = :DATA,
          HORA                  = :HORA,
          DATA_ABERTURA         = :DATA_ABERTURA,
          HORA_ABERTURA         = :HORA_ABERTURA,
          DATA_CONTAGEM         = :DATA_CONTAGEM,
          HORA_CONTAGEM         = :HORA_CONTAGEM,
          DATA_CONCLUSAO        = :DATA_CONCLUSAO,
          HORA_CONCLUSAO        = :HORA_CONCLUSAO,
          CD_FILIAL             = :CD_FILIAL,
          ID_PRODUTO            = :ID_PRODUTO,
          CD_PRODUTO            = :CD_PRODUTO,
          CODIGO_BARRAS_1       = :CODIGO_BARRAS_1,
          CODIGO_BARRAS_2       = :CODIGO_BARRAS_2,
