          SUBSTITUIESTOQUE      = :SUBSTITUIESTOQUE,
          STATUS                = :STATUS,
          ENVIADO               = '2', --:ENVIADO, -- FML - 12.05.2016
          CD_SUBGRUPO           = :CD_SUBGRUPO,
          USUARIO_ABERTURA      = :USUARIO_ABERTURA,
          USUARIO_CONCLUSAO     = :USUARIO_CONCLUSAO
     WHERE ID_BALANCO = :ID_BALANCO AND ID_PRODUTO = :ID_PRODUTO;
   END
  ELSE
