          SUBSTITUIESTOQUE,
          STATUS,
          ENVIADO,
          CD_SUBGRUPO,
          USUARIO_ABERTURA,
          USUARIO_CONCLUSAO
       )
     VALUES(
          :ID_BALANCO,
          :ID_MOTIVO,
          :DATA,
          :HORA,
          :DATA_ABERTURA,
          :HORA_ABERTURA,
