ALTER PROCEDURE SP_ATUALIZA_CARTOES (CD_CARTAO DOUBLE PRECISION,
CD_CONTA DOUBLE PRECISION,
DESCRICAO VARCHAR(40) CHARACTER SET NONE,
TIPO_CARTAO VARCHAR(1) CHARACTER SET NONE,
