REDEVESPAGUE VARCHAR(50) CHARACTER SET NONE,
ENVIADO VARCHAR(1) CHARACTER SET NONE)
AS 
declare variable EXISTE integer;
BEGIN
  SELECT COUNT(*) FROM CARTOES WHERE CD_CARTAO = :CD_CARTAO INTO :EXISTE;
