     UPDATE CARTOES SET
        CD_CARTAO     = :CD_CARTAO,
        CD_CONTA      = :CD_CONTA,
        DESCRICAO     = :DESCRICAO,
        TIPO_CARTAO   = :TIPO_CARTAO,
        IMAGEM        = :IMAGEM,
        USATEF        = :USATEF,
        TRNCENTRE     = :TRNCENTRE,
        FIDELIZE      = :FIDELIZE,
        HIPERCARD     = :HIPERCARD,
        REDEVESPAGUE  = :REDEVESPAGUE,
        ENVIADO       = :ENVIADO
     WHERE CD_CARTAO = :CD_CARTAO;
   END
  ELSE
   BEGIN
     INSERT INTO CARTOES
     (
        CD_CARTAO,
        CD_CONTA,
        DESCRICAO,
        TIPO_CARTAO,
        TX_ADM,
        TX_ADM_PARC,
        PRAZO_PG,
        IMAGEM,
        USATEF,
        TRNCENTRE,
        FIDELIZE,
        HIPERCARD,
        REDEVESPAGUE,
        ENVIADO
