        :CD_CONTA,
        :DESCRICAO,
        :TIPO_CARTAO,
        :TX_ADM,
        :TX_ADM_PARC,
        :PRAZO_PG,
        :IMAGEM,
        :USATEF,
        :TRNCENTRE,
        :FIDELIZE,
        :HIPERCARD,
        :REDEVESPAGUE,
        :ENVIADO
       );
   END
END ^

