ALTER PROCEDURE SP_ATUALIZA_CODIGO_DISTRIBUIDOR (BARRAS VARCHAR(14) CHARACTER SET NONE,
DISTRIBUIDOR DOUBLE PRECISION,
CODIGO DOUBLE PRECISION)
AS 
DECLARE VARIABLE ID_PRODUTO DOUBLE PRECISION;
DECLARE VARIABLE CD_PRODUTO VARCHAR(6);
DECLARE VARIABLE EXISTE INTEGER;
BEGIN
  SELECT
   COUNT(*)
  FROM
   PROD_DISTR
  WHERE
   CODIGO = :CODIGO AND
   CD_DISTRIBUIDOR = :DISTRIBUIDOR
  INTO
   :EXISTE;

  IF (EXISTE > 0) THEN
   BEGIN
     UPDATE PROD_DISTR SET
      CODIGO_BARRAS_1 = :BARRAS
     WHERE
      CODIGO = :CODIGO  AND
      CD_DISTRIBUIDOR = :DISTRIBUIDOR;
   END
  ELSE
   BEGIN
      SELECT FIRST 1
       ID_PRODUTO,
       CD_PRODUTO
      FROM
       PRODUTOS
      WHERE
        (CODIGO_BARRAS_1 = :BARRAS OR CODIGO_BARRAS_2 = :BARRAS)
      INTO
       :ID_PRODUTO, 
       :CD_PRODUTO;

      IF ((:ID_PRODUTO IS NOT NULL) AND (:ID_PRODUTO > 0)) THEN
         INSERT INTO PROD_DISTR VALUES (:ID_PRODUTO, :DISTRIBUIDOR, :CD_PRODUTO, :CODIGO, :BARRAS, 1, ' ');
   END
END ^

ALTER PROCEDURE SP_ATUALIZA_COD_DISTRIBUIDOR2 AS 
DECLARE VARIABLE ID_PRODUTO DOUBLE PRECISION;
DECLARE VARIABLE CD_PRODUTO VARCHAR(6);
DECLARE VARIABLE DISTRIBUIDOR DOUBLE PRECISION;
DECLARE VARIABLE CODIGO_BARRAS VARCHAR(14);
DECLARE VARIABLE QTEMBALAGEM DOUBLE PRECISION;
DECLARE VARIABLE CODIGO DOUBLE PRECISION;
DECLARE VARIABLE EXISTE INTEGER;
BEGIN
  SELECT
   COMPRAS.CD_DISTRIBUIDOR,
   ITENS_COMPRA.ID_PRODUTO,
   ITENS_COMPRA.CD_PRODUTO,
   ITENS_COMPRA.CODIGO,
   ITENS_COMPRA.CODIGO_BARRAS,
   ITENS_COMPRA.QT_EMBALAGEM
  FROM
   COMPRAS, ITENS_COMPRA
  WHERE
   COMPRAS.CD_COMPRAS = ITENS_COMPRA.CD_COMPRAS AND
   ITENS_COMPRA.CODIGO <> 0
  INTO
   :DISTRIBUIDOR, :ID_PRODUTO, :CD_PRODUTO, :CODIGO,  :CODIGO_BARRAS, :QTEMBALAGEM;

  SELECT COUNT(*) FROM PROD_DISTR WHERE CD_DISTRIBUIDOR = :DISTRIBUIDOR AND ID_PRODUTO = :ID_PRODUTO INTO :EXISTE;

  IF (EXISTE = 0) THEN
   BEGIN
     INSERT INTO PROD_DISTR VALUES(:ID_PRODUTO, :DISTRIBUIDOR, :CD_PRODUTO, :CODIGO, :CODIGO_BARRAS, :QTEMBALAGEM, '');
   END
END ^

