ICMSDESONERACAO NUMERIC(15, 2))
AS 
declare variable EXISTE integer;
declare variable LOCALGERACAOCOMPRA varchar(1);
declare variable STATUSCOMPRA varchar(1);
BEGIN
  /*SELECT COUNT(*) FROM COMPRAS WHERE CD_COMPRAS = :CD_COMPRAS AND CD_FILIAL = :CD_FILIAL INTO :EXISTE;*/
  SELECT LOCALGERACAO, STATUS FROM COMPRAS WHERE CD_COMPRAS = :CD_COMPRAS AND CD_FILIAL = :CD_FILIAL INTO :LOCALGERACAOCOMPRA,  :STATUSCOMPRA;
  /*IF (:EXISTE > 0) THEN*/
