   BEGIN
     /*SELECT LOCALGERACAO, STATUS FROM COMPRAS WHERE CD_COMPRAS = :CD_COMPRAS AND CD_FILIAL = :CD_FILIAL INTO :LOCALGERACAOCOMPRA,  :STATUSCOMPRA;*/
     IF ((:LOCALGERACAOCOMPRA = 'L') OR (:STATUS = 'C') OR (:STATUS = 'D')) THEN
      BEGIN
        IF ((:STATUSCOMPRA <> 'C') OR (:STATUS = 'D')) THEN
         BEGIN
           UPDATE COMPRAS SET
              CD_COMPRAS              = :CD_COMPRAS,
              CD_FILIAL               = :CD_FILIAL,
              CD_DISTRIBUIDOR         = :CD_DISTRIBUIDOR,
              CD_PLANO_CONTAS         = :CD_PLANO_CONTAS,
