ALTER PROCEDURE SP_ATUALIZA_COMPRAS_BOLETOS (CD_COMPRAS DOUBLE PRECISION,
CD_BOLETO DOUBLE PRECISION,
NUMERO VARCHAR(100) CHARACTER SET NONE,
VENCIMENTO DATE,
JUROS NUMERIC(15, 2),
DEDUCOES NUMERIC(15, 2),
DESPESASFINANCEIRAS NUMERIC(15, 2),
VALOR NUMERIC(15, 2))
AS 
declare variable EXISTE integer;
BEGIN
  SELECT COUNT(*) FROM COMPRAS_BOLETOS WHERE CD_COMPRAS = :CD_COMPRAS AND CD_BOLETO = :CD_BOLETO INTO :EXISTE;
  IF (EXISTE > 0) THEN
   BEGIN
     UPDATE COMPRAS_BOLETOS SET
        CD_COMPRAS            = :CD_COMPRAS,
        CD_BOLETO             = :CD_BOLETO,
        NUMERO                = :NUMERO,
        VENCIMENTO            = :VENCIMENTO,
        JUROS                 = :JUROS,
        DEDUCOES              = :DEDUCOES,
        DESPESASFINANCEIRAS   = :DESPESASFINANCEIRAS,
        VALOR                 = :VALOR
     WHERE CD_COMPRAS = :CD_COMPRAS AND CD_BOLETO = :CD_BOLETO;
   END
  ELSE
   BEGIN
     INSERT INTO COMPRAS_BOLETOS(
        CD_COMPRAS,
        CD_BOLETO,
        NUMERO,
        VENCIMENTO,
        JUROS,
        DEDUCOES,
        DESPESASFINANCEIRAS,
        VALOR
       )
     VALUES(
        :CD_COMPRAS,
        :CD_BOLETO,
        :NUMERO,
        :VENCIMENTO,
        :JUROS,
        :DEDUCOES,
        :DESPESASFINANCEIRAS,
        :VALOR
       );
   END
END ^

