AS 
declare variable EXISTE integer;
declare variable STATUSCOMPRA varchar(1);
BEGIN
  /*SELECT COUNT(*) FROM COMPRAS WHERE CD_COMPRAS = :CD_COMPRAS AND CD_FILIAL = :CD_FILIAL INTO :EXISTE;
  IF (:EXISTE > 0) THEN*/
  SELECT STATUS FROM COMPRAS WHERE CD_COMPRAS = :CD_COMPRAS AND CD_FILIAL = :CD_FILIAL INTO :STATUSCOMPRA;
  IF (:STATUSCOMPRA IS NOT NULL) THEN
   BEGIN
     /*SELECT STATUS FROM COMPRAS WHERE CD_COMPRAS = :CD_COMPRAS AND CD_FILIAL = :CD_FILIAL INTO :STATUSCOMPRA;*/
     IF (((:STATUS = 'G') AND (:STATUSCOMPRA = 'G')) OR
         ((:STATUS = 'E') AND ((:STATUSCOMPRA = 'G') OR (:STATUSCOMPRA = 'E')))) THEN
      BEGIN
         UPDATE COMPRAS SET
            CD_COMPRAS              = :CD_COMPRAS,
            CD_FILIAL               = :CD_FILIAL,
            CD_DISTRIBUIDOR         = :CD_DISTRIBUIDOR,
            CD_PLANO_CONTAS         = :CD_PLANO_CONTAS,
            CD_OBSERVACAO           = :CD_OBSERVACAO,
            CD_TRANSPORTADORA       = :CD_TRANSPORTADORA,
            DT_PEDIDO               = :DT_PEDIDO,
