            ICM_BASE_CALCULO        = :ICM_BASE_CALCULO,
            ICM_ISENTO              = :ICM_ISENTO,
            ICM_OUTROS              = :ICM_OUTROS,
            ICM_BASESUBST           = :ICM_BASESUBST,
            ICM_VALORSUBST          = :ICM_VALORSUBST,
            VL_TOTALPRODUTOS        = :VL_TOTALPRODUTOS,
            VL_SEGURO               = :VL_SEGURO,
            OUTRAS_DESPESAS         = :OUTRAS_DESPESAS,
            VL_FRETE                = :VL_FRETE,
            IPI_BASE_CALCULO        = :IPI_BASE_CALCULO,
            IPI_ISENTO              = :IPI_ISENTO,
            IPI_OUTROS              = :IPI_OUTROS,
            D_ICMV                  = :D_ICMV,
            D_IPIV                  = :D_IPIV,
            D_TOTNT                 = :D_TOTNT,
            UNIDADES                = :UNIDADES,
            NUMERO_ITENS            = :NUMERO_ITENS,
            FATURAMENTO             = :FATURAMENTO,
            MOTIVO                  = :MOTIVO,
            ENVIADO                 = :ENVIADO,
            STATUS                  = :STATUS,
            VL_DESCONTO_NOTA        = :VL_DESCONTO_NOTA,
            CD_USUARIO_CRIACAO      = :CD_USUARIO_CRIACAO,
            USUARIO_DIGITACAO       = :USUARIO_DIGITACAO,
