            VL_FCPSTRET             = :VL_FCPSTRET,
            VL_II                   = :VL_II,
            ICM_BASESUBSTRET        = :ICM_BASESUBSTRET,
            ICM_VALORSUBSTRET       = :ICM_VALORSUBSTRET,
            ICMSDESONERACAO         = :ICMSDESONERACAO
         WHERE CD_COMPRAS = :CD_COMPRAS AND CD_FILIAL = :CD_FILIAL;
      END
     ELSE
