ALTER PROCEDURE SP_ATUALIZA_CONCLUIDO_VENDA AS 
DECLARE VARIABLE VENDA DOUBLE PRECISION;
BEGIN
 UPDATE VENDAS SET
  CONCLUIDO = 'S'
 WHERE
  STATUS = 'V';

 FOR
   SELECT
    CD_VENDA
   FROM
    VENDAS
   WHERE
    CONCLUIDO = 'S'
   INTO
    :VENDA
 DO
  BEGIN
    UPDATE VENDAS SET
     CONCLUIDO = 'S'
    WHERE
     CD_VENDA = :VENDA;
  END

 UPDATE VENDAS SET
  CONCLUIDO = 'N'
 WHERE
  CONCLUIDO IS NULL;
END ^

ALTER PROCEDURE SP_ATUALIZA_CONFERENCIA_NOTA (ID_CONFERENCIANOTA DOUBLE PRECISION,
CD_COMPRAS DOUBLE PRECISION,
CD_FILIAL DOUBLE PRECISION,
NOTA_FISCAL VARCHAR(7) CHARACTER SET NONE,
ID_PRODUTO DOUBLE PRECISION,
CD_PRODUTO VARCHAR(6) CHARACTER SET NONE,
CODIGO_BARRAS_1 VARCHAR(13) CHARACTER SET NONE,
DESCRICAO VARCHAR(100) CHARACTER SET NONE,
CD_CLASSE DOUBLE PRECISION,
CD_GRUPO DOUBLE PRECISION,
CD_LABORATORIO DOUBLE PRECISION,
CLASSE VARCHAR(100) CHARACTER SET NONE,
GRUPO VARCHAR(100) CHARACTER SET NONE,
LABORATORIO VARCHAR(100) CHARACTER SET NONE,
VL_UNITARIO DOUBLE PRECISION,
VL_UNITARIO_NOTA DOUBLE PRECISION,
QUANTIDADE DOUBLE PRECISION,
QUANTIDADE_NOTA DOUBLE PRECISION,
STATUS VARCHAR(1) CHARACTER SET NONE,
STATUSCONFERENCIA VARCHAR(1) CHARACTER SET NONE,
CD_USUARIO_CONFERENCIA DOUBLE PRECISION,
USUARIO_CONFERENCIA VARCHAR(20) CHARACTER SET NONE,
ENVIADO VARCHAR(1) CHARACTER SET NONE,
CD_SUBGRUPO DOUBLE PRECISION)
AS 
declare variable EXISTE integer;
BEGIN
  SELECT COUNT(*) FROM CONFERENCIA_NOTA WHERE ID_CONFERENCIANOTA = :ID_CONFERENCIANOTA AND CD_FILIAL = :CD_FILIAL AND ID_PRODUTO = :ID_PRODUTO INTO :EXISTE;
  IF (:EXISTE > 0) THEN
   BEGIN
     UPDATE CONFERENCIA_NOTA SET
      ID_CONFERENCIANOTA      = :ID_CONFERENCIANOTA,
      CD_COMPRAS              = :CD_COMPRAS,
      CD_FILIAL               = :CD_FILIAL,
      NOTA_FISCAL             = :NOTA_FISCAL,
      ID_PRODUTO              = :ID_PRODUTO,
      CD_PRODUTO              = :CD_PRODUTO,
      CODIGO_BARRAS_1         = :CODIGO_BARRAS_1,
      DESCRICAO               = :DESCRICAO,
      CD_CLASSE               = :CD_CLASSE,
      CD_GRUPO                = :CD_GRUPO,
      CD_LABORATORIO          = :CD_LABORATORIO,
      CLASSE                  = :CLASSE,
      GRUPO                   = :GRUPO,
      LABORATORIO             = :LABORATORIO,
      VL_UNITARIO             = :VL_UNITARIO,
      VL_UNITARIO_NOTA        = :VL_UNITARIO_NOTA,
      QUANTIDADE              = :QUANTIDADE,
      QUANTIDADE_NOTA         = :QUANTIDADE_NOTA,
      STATUS                  = :STATUS,
      STATUSCONFERENCIA       = :STATUSCONFERENCIA,
      CD_USUARIO_CONFERENCIA  = :CD_USUARIO_CONFERENCIA,
      USUARIO_CONFERENCIA     = :USUARIO_CONFERENCIA,
      ENVIADO                 = :ENVIADO,
      CD_SUBGRUPO             = :CD_SUBGRUPO
     WHERE ID_CONFERENCIANOTA = :ID_CONFERENCIANOTA AND
           CD_FILIAL = :CD_FILIAL AND
           ID_PRODUTO = :ID_PRODUTO;
   END
  ELSE
   BEGIN
     INSERT INTO CONFERENCIA_NOTA(
        ID_CONFERENCIANOTA      ,
        CD_COMPRAS              ,
        CD_FILIAL               ,
        NOTA_FISCAL             ,
        ID_PRODUTO              ,
        CD_PRODUTO              ,
        CODIGO_BARRAS_1         ,
        DESCRICAO               ,
        CD_CLASSE               ,
        CD_GRUPO                ,
        CD_LABORATORIO          ,
        CLASSE                  ,
        GRUPO                   ,
        LABORATORIO             ,
        VL_UNITARIO             ,
        VL_UNITARIO_NOTA        ,
        QUANTIDADE              ,
        QUANTIDADE_NOTA         ,
        STATUS                  ,
        STATUSCONFERENCIA       ,
        CD_USUARIO_CONFERENCIA  ,
        USUARIO_CONFERENCIA     ,
        ENVIADO                 ,
        CD_SUBGRUPO
       )
     VALUES(
        :ID_CONFERENCIANOTA      ,
        :CD_COMPRAS              ,
        :CD_FILIAL               ,
        :NOTA_FISCAL             ,
        :ID_PRODUTO              ,
        :CD_PRODUTO              ,
        :CODIGO_BARRAS_1         ,
        :DESCRICAO               ,
        :CD_CLASSE               ,
        :CD_GRUPO                ,
        :CD_LABORATORIO          ,
        :CLASSE                  ,
        :GRUPO                   ,
        :LABORATORIO             ,
        :VL_UNITARIO             ,
        :VL_UNITARIO_NOTA        ,
        :QUANTIDADE              ,
        :QUANTIDADE_NOTA         ,
        :STATUS                  ,
        :STATUSCONFERENCIA       ,
        :CD_USUARIO_CONFERENCIA  ,
        :USUARIO_CONFERENCIA     ,
        :ENVIADO                 ,
        :CD_SUBGRUPO
       );
   END
END ^

ALTER PROCEDURE SP_ATUALIZA_CONTASPAGARCOMPRAS (CD_FILIAL DOUBLE PRECISION,
CD_CONTAS_PAGAR DOUBLE PRECISION,
CD_COMPRAS DOUBLE PRECISION,
DT_EMISSAO DATE,
NOTA_FISCAL VARCHAR(100) CHARACTER SET NONE,
VALOR NUMERIC(15, 2))
AS 
DECLARE VARIABLE EXISTE INTEGER;
BEGIN
  SELECT COUNT(*) FROM CONTAS_PAGAR_COMPRAS WHERE CD_COMPRAS = :CD_COMPRAS AND CD_CONTAS_PAGAR = :CD_CONTAS_PAGAR AND CD_FILIAL = :CD_FILIAL INTO :EXISTE;
  IF (EXISTE > 0) THEN
   BEGIN
     UPDATE CONTAS_PAGAR_COMPRAS SET
        DT_EMISSAO  = :DT_EMISSAO,
        NOTA_FISCAL = :NOTA_FISCAL,
        VALOR       = :VALOR
     WHERE CD_COMPRAS = :CD_COMPRAS AND CD_CONTAS_PAGAR = :CD_CONTAS_PAGAR AND CD_FILIAL = :CD_FILIAL;
   END
  ELSE
   BEGIN
     INSERT INTO CONTAS_PAGAR_COMPRAS(
        CD_FILIAL,
        CD_CONTAS_PAGAR,
        CD_COMPRAS,
        DT_EMISSAO,
        NOTA_FISCAL,
        VALOR
       )
     VALUES(
        :CD_FILIAL,
        :CD_CONTAS_PAGAR,
        :CD_COMPRAS,
        :DT_EMISSAO,
        :NOTA_FISCAL,
        :VALOR
       );
   END
END ^

