VL_PAGAMENTO DOUBLE PRECISION,
VL_JUROS DOUBLE PRECISION,
VL_DESCONTO DOUBLE PRECISION,
VL_SALDO DOUBLE PRECISION,
NOSSO_NUMERO VARCHAR(20) CHARACTER SET NONE,
BANCO VARCHAR(3) CHARACTER SET NONE,
AGENCIA VARCHAR(6) CHARACTER SET NONE,
CONTA VARCHAR(15) CHARACTER SET NONE,
HISTORICO VARCHAR(50) CHARACTER SET NONE,
NR_CHEQUE VARCHAR(10) CHARACTER SET NONE,
STATUS VARCHAR(1) CHARACTER SET NONE,
ENVIADO VARCHAR(1) CHARACTER SET NONE,
DESPESAFINANCEIRA DOUBLE PRECISION)
AS 
declare variable EXISTE integer;
declare variable STATUSCONTA varchar(1);
BEGIN
  IF (:DT_PAGAMENTO = CAST('30.12.1899' AS DATE)) THEN
     DT_PAGAMENTO = NULL;
  IF (:DT_VENCIMENTO = CAST('30.12.1899' AS DATE)) THEN
     DT_VENCIMENTO = NULL;
  IF (:DT_LANCAMENTO = CAST('30.12.1899' AS DATE)) THEN
     DT_LANCAMENTO = NULL;
  IF (:DT_NOTA = CAST('30.12.1899' AS DATE)) THEN
     DT_NOTA = NULL;
  IF (:DT_ENTRADA = CAST('30.12.1899' AS DATE)) THEN
     DT_ENTRADA = NULL;
  IF (:DT_BOLETO = CAST('30.12.1899' AS DATE)) THEN
     DT_BOLETO = NULL;
  SELECT COUNT(*) FROM CONTAS_PAGAR WHERE CD_CONTAS_PAGAR = :CD_CONTAS_PAGAR AND CD_FILIAL = :CD_FILIAL INTO EXISTE;
  IF (:EXISTE > 0) THEN
   BEGIN
     SELECT STATUS FROM CONTAS_PAGAR WHERE CD_CONTAS_PAGAR = :CD_CONTAS_PAGAR AND CD_FILIAL = :CD_FILIAL INTO :STATUSCONTA;
     IF (:STATUSCONTA <> 'P') THEN
      BEGIN
        UPDATE CONTAS_PAGAR SET
          CD_CONTAS_PAGAR     = :CD_CONTAS_PAGAR,
          CD_FILIAL      = :CD_FILIAL, 
          CD_DISTRIBUIDOR     = :CD_DISTRIBUIDOR,
          CD_COMPRAS      = :CD_COMPRAS, 
          CD_CONTA      = :CD_CONTA, 
          CD_FORMA_PAGAMENTO  = :CD_FORMA_PAGAMENTO,
          CD_PLANO_CONTAS     = :CD_PLANO_CONTAS,
          NUMERO_NOTA      = :NUMERO_NOTA, 
          SERIAL_NOTA      = :SERIAL_NOTA, 
          DOCUMENTO      = :DOCUMENTO, 
          DT_NOTA             = :DT_NOTA,
          DT_VENCIMENTO      = :DT_VENCIMENTO, 
          VALOR        = :VALOR, 
          DT_LANCAMENTO      = :DT_LANCAMENTO, 
          DT_PAGAMENTO      = :DT_PAGAMENTO, 
          DT_BOLETO      = :DT_BOLETO, 
          DT_ENTRADA      = :DT_ENTRADA, 
          VL_PAGAMENTO      = :VL_PAGAMENTO, 
          VL_JUROS      = :VL_JUROS, 
          VL_DESCONTO      = :VL_DESCONTO, 
          VL_SALDO      = :VL_SALDO, 
          NOSSO_NUMERO      = :NOSSO_NUMERO, 
          BANCO        = :BANCO, 
          AGENCIA             = :AGENCIA,
          CONTA        = :CONTA, 
          HISTORICO      = :HISTORICO, 
          NR_CHEQUE      = :NR_CHEQUE, 
          STATUS        = :STATUS, 
          ENVIADO        = :ENVIADO,
          DESPESAFINANCEIRA = :DESPESAFINANCEIRA
        WHERE CD_CONTAS_PAGAR = :CD_CONTAS_PAGAR AND CD_FILIAL = :CD_FILIAL;
      END
   END
  ELSE
   BEGIN
     INSERT INTO CONTAS_PAGAR(
          CD_CONTAS_PAGAR,
          CD_FILIAL,
          CD_DISTRIBUIDOR,
          CD_COMPRAS,
          CD_CONTA,
          CD_FORMA_PAGAMENTO,
          CD_PLANO_CONTAS,
          NUMERO_NOTA,
          SERIAL_NOTA,
          DOCUMENTO,
          DT_NOTA,
          DT_VENCIMENTO,
          VALOR,
          DT_LANCAMENTO,
          DT_PAGAMENTO,
          DT_BOLETO,
          DT_ENTRADA,
          VL_PAGAMENTO,
          VL_JUROS,
          VL_DESCONTO,
          VL_SALDO,
          NOSSO_NUMERO,
          BANCO,
          AGENCIA,
          CONTA,
          HISTORICO,
          NR_CHEQUE,
          STATUS,
          ENVIADO,
          DESPESAFINANCEIRA
       )
      VALUES(
          :CD_CONTAS_PAGAR,
          :CD_FILIAL,
          :CD_DISTRIBUIDOR,
          :CD_COMPRAS,
          :CD_CONTA,
          :CD_FORMA_PAGAMENTO,
          :CD_PLANO_CONTAS,
          :NUMERO_NOTA,
          :SERIAL_NOTA,
          :DOCUMENTO,
          :DT_NOTA,
          :DT_VENCIMENTO,
          :VALOR,
          :DT_LANCAMENTO,
          :DT_PAGAMENTO,
          :DT_BOLETO,
          :DT_ENTRADA,
          :VL_PAGAMENTO,
          :VL_JUROS,
          :VL_DESCONTO,
          :VL_SALDO,
          :NOSSO_NUMERO,
          :BANCO,
          :AGENCIA,
          :CONTA,
          :HISTORICO,
          :NR_CHEQUE,
          :STATUS,
          :ENVIADO,
          :DESPESAFINANCEIRA
        );
   END
END ^

