ALTER PROCEDURE SP_ATUALIZA_CONTROLE3 AS 
declare variable CD_FILIAL double precision;
declare variable VARTEMP double precision;
declare variable VENDACAIXA double precision;
declare variable VENDALANCAMENTO double precision;
declare variable VENDAVENDA double precision;
declare variable CD_VENDAPARAMETRO double precision;
BEGIN
  UPDATE CONTROLE SET VALOR = (SELECT MAX(ID_DOCUMENTO) FROM TIPO_DOCUMENTO) WHERE CAMPO = 'ID_DOCUMENTO';
  UPDATE CONTROLE SET VALOR = (SELECT MAX(ID_LIVRO) FROM TIPO_LIVROS) WHERE CAMPO = 'ID_LIVRO';
  UPDATE CONTROLE SET VALOR = (SELECT MAX(ID_PERDA) FROM TIPO_MOTIVOPERDA) WHERE CAMPO = 'ID_PERDA';
  UPDATE CONTROLE SET VALOR = (SELECT MAX(ID_OPERACAONOTAFISCAL) FROM TIPO_OPERACAONOTAFISCAL) WHERE CAMPO = 'ID_OPERACAONOTAFISCAL';
  UPDATE CONTROLE SET VALOR = (SELECT MAX(ID_RECEITUARIO) FROM TIPO_RECEITUARIO) WHERE CAMPO = 'ID_RECEITUARIO';
  UPDATE CONTROLE SET VALOR = (SELECT MAX(ID_USOMEDICAMENTO) FROM TIPO_USOMEDICAMENTO) WHERE CAMPO = 'ID_USOMEDICAMENTO';
  UPDATE CONTROLE SET VALOR = (SELECT MAX(CD_TRANSPORTADORA) FROM TRANSPORTADORAS) WHERE CAMPO = 'CD_TRANSPORTADORA';
  UPDATE CONTROLE SET VALOR = (SELECT MAX(CD_USUARIO) FROM USUARIOS) WHERE CAMPO = 'CD_USUARIO';
  UPDATE CONTROLE SET VALOR = (SELECT MAX(ID_VENDA) FROM VENDASSNGPC) WHERE CAMPO = 'ID_VENDA';
  UPDATE CONTROLE SET VALOR = (SELECT MAX(CD_VENDEDOR) FROM VENDEDORES) WHERE CAMPO = 'CD_VENDEDOR';
  UPDATE CONTROLE SET VALOR = (SELECT MAX(ID_NFCE) FROM NFCE) WHERE CAMPO = 'ID_NFCE';

  -----------------------------------------------------------------------------------------------------------------------------

  SELECT CD_FILIAL FROM PARAMETROS INTO :CD_FILIAL;

  /*BALANCOS*/
  UPDATE CONTROLE SET VALOR = (SELECT MAX(ID_BALANCO) FROM BALANCO) WHERE CAMPO = 'ID_BALANCO';
  SELECT VALOR FROM CONTROLE WHERE CAMPO = 'ID_BALANCO' INTO :VARTEMP;
  IF ((:VARTEMP IS NULL) AND (:CD_FILIAL > 0)) THEN
     UPDATE CONTROLE SET VALOR = (:CD_FILIAL * 1000000) WHERE CAMPO = 'ID_BALANCO';
  IF ((:VARTEMP < 1000000) AND (:CD_FILIAL > 0)) THEN
     UPDATE CONTROLE SET VALOR = (SELECT MAX(ID_BALANCO) FROM BALANCO) + (:CD_FILIAL * 1000000) WHERE CAMPO = 'ID_BALANCO';

  /* CLIENTES*/
  UPDATE CONTROLE SET
  VALOR = (SELECT MAX(CD_CLIENTE) FROM CLIENTES
           WHERE CD_FILIAL = :CD_FILIAL AND
                 CD_CLIENTE >= (:CD_FILIAL * 1000000) AND
                 CD_CLIENTE < ((:CD_FILIAL + 1) * 1000000))
  WHERE CAMPO = 'CD_CLIENTE';
  SELECT VALOR FROM CONTROLE WHERE CAMPO = 'CD_CLIENTE' INTO :VARTEMP;
  IF ((:VARTEMP IS NULL) AND (:CD_FILIAL > 0)) THEN
     UPDATE CONTROLE SET VALOR = (:CD_FILIAL * 1000000) WHERE CAMPO = 'CD_CLIENTE';
  IF ((:VARTEMP < 1000000) AND (:CD_FILIAL > 0)) THEN
     UPDATE CONTROLE SET VALOR = (SELECT MAX(CD_CLIENTE) FROM CLIENTES) + (:CD_FILIAL * 1000000) WHERE CAMPO = 'CD_CLIENTE';

  /*COMPRAS*/
  UPDATE CONTROLE SET VALOR = (SELECT MAX(CD_COMPRAS) FROM COMPRAS WHERE CD_COMPRAS < 1000000000) WHERE CAMPO = 'CD_COMPRAS';
  SELECT VALOR FROM CONTROLE WHERE CAMPO = 'CD_COMPRAS' INTO :VARTEMP;
  IF ((:VARTEMP IS NULL) AND (:CD_FILIAL > 0)) THEN
     UPDATE CONTROLE SET VALOR = (:CD_FILIAL * 1000000) WHERE CAMPO = 'CD_COMPRAS';
  IF ((:VARTEMP < 1000000) AND (:CD_FILIAL > 0)) THEN
     UPDATE CONTROLE SET VALOR = (SELECT MAX(CD_COMPRAS) FROM COMPRAS WHERE CD_COMPRAS < 1000000000) + (:CD_FILIAL * 1000000) WHERE CAMPO = 'CD_COMPRAS';
  UPDATE CONTROLE SET VALOR = (SELECT MAX(ID_CONCORRENTE) FROM CONCORRENTES) WHERE CAMPO = 'ID_CONCORRENTE';

  /*CONTAS_PAGAR*/
  UPDATE CONTROLE SET VALOR = (SELECT MAX(CD_CONTAS_PAGAR) FROM CONTAS_PAGAR) WHERE CAMPO = 'CD_CONTAS_PAGAR';
  SELECT VALOR FROM CONTROLE WHERE CAMPO = 'CD_CONTAS_PAGAR' INTO :VARTEMP;
  IF ((:VARTEMP IS NULL) AND (:CD_FILIAL > 0)) THEN
     UPDATE CONTROLE SET VALOR = (:CD_FILIAL * 1000000) WHERE CAMPO = 'CD_CONTAS_PAGAR';
  IF ((:VARTEMP < 1000000) AND (:CD_FILIAL > 0)) THEN
     UPDATE CONTROLE SET VALOR = (SELECT MAX(CD_CONTAS_PAGAR) FROM CONTAS_PAGAR) + (:CD_FILIAL * 1000000) WHERE CAMPO = 'CD_CONTAS_PAGAR';

  /*CONTAS_RECEBER*/
  UPDATE CONTROLE SET
  VALOR = (SELECT MAX(CD_CONTAS_RECEBER) FROM CONTAS_RECEBER
           WHERE CD_FILIAL = :CD_FILIAL AND
                 CD_CONTAS_RECEBER >= (:CD_FILIAL * 1000000) AND
                 CD_CONTAS_RECEBER < ((:CD_FILIAL + 1) * 1000000))
  WHERE CAMPO = 'CD_CONTAS_RECEBER';
  SELECT VALOR FROM CONTROLE WHERE CAMPO = 'CD_CONTAS_RECEBER' INTO :VARTEMP;
  IF ((:VARTEMP IS NULL) AND (:CD_FILIAL > 0)) THEN
     UPDATE CONTROLE SET VALOR = (:CD_FILIAL * 1000000) WHERE CAMPO = 'CD_CONTAS_RECEBER';
  IF ((:VARTEMP < 1000000) AND (:CD_FILIAL > 0)) THEN
     UPDATE CONTROLE SET VALOR = (SELECT MAX(CD_CONTAS_RECEBER) FROM CONTAS_RECEBER) + (:CD_FILIAL * 1000000) WHERE CAMPO = 'CD_CONTAS_RECEBER';

  /*TRANSFER*/
  UPDATE CONTROLE SET
  VALOR = (SELECT MAX(CD_TRANSFER) FROM TRANSFER WHERE CD_TRANSFER >= (:CD_FILIAL * 1000000) AND CD_TRANSFER < ((:CD_FILIAL + 1) * 1000000))
  WHERE CAMPO = 'CD_TRANSFER';
  SELECT VALOR FROM CONTROLE WHERE CAMPO = 'CD_TRANSFER' INTO :VARTEMP;
  IF ((:VARTEMP IS NULL) AND (:CD_FILIAL > 0)) THEN
     UPDATE CONTROLE SET VALOR = (:CD_FILIAL * 1000000) WHERE CAMPO = 'CD_TRANSFER';
  IF ((:VARTEMP < 1000000) AND (:CD_FILIAL > 0)) THEN
     UPDATE CONTROLE SET VALOR = (SELECT MAX(CD_TRANSFER) FROM TRANSFER) + (:CD_FILIAL * 1000000) WHERE CAMPO = 'CD_TRANSFER';
  UPDATE CONTROLE SET VALOR = 0 WHERE VALOR IS NULL;

  /* PRODUTOS */
  UPDATE CONTROLE SET VALOR = (SELECT MAX(ID_PRODUTO) FROM PRODUTOS) WHERE CAMPO = 'ID_PRODUTO';

  /* VENDAS */
  SELECT MAX(CD_VENDA) FROM VENDAS INTO :VENDAVENDA;
  SELECT MAX(CD_VENDA) FROM CAIXA WHERE (TIPO_VENDA = 'V') OR (TIPO_VENDA = 'D') INTO :VENDACAIXA;
  SELECT MAX(CD_VENDA) FROM LANCAMENTOS WHERE (TIPO_VENDA = 'V') OR (TIPO_VENDA = 'D') INTO :VENDALANCAMENTO;
  IF (:VENDAVENDA IS NULL) THEN
     VENDAVENDA = 0;
  IF (:VENDACAIXA IS NULL) THEN
     VENDACAIXA = 0;
  IF (:VENDALANCAMENTO IS NULL) THEN
     VENDALANCAMENTO = 0;
  IF ((:VENDAVENDA > :VENDACAIXA) AND (:VENDAVENDA > :VENDALANCAMENTO)) THEN
   BEGIN
     UPDATE CONTROLE SET VALOR = :VENDAVENDA WHERE CAMPO = 'CD_VENDA';
     CD_VENDAPARAMETRO = :VENDAVENDA;
   END
  ELSE
  IF ((:VENDACAIXA > :VENDAVENDA) AND (:VENDACAIXA >= :VENDALANCAMENTO)) THEN
   BEGIN
     UPDATE CONTROLE SET VALOR = :VENDACAIXA WHERE CAMPO = 'CD_VENDA';
     CD_VENDAPARAMETRO = :VENDACAIXA;
   END
  ELSE
  IF ((:VENDALANCAMENTO > :VENDAVENDA) AND (:VENDALANCAMENTO >= :VENDACAIXA)) THEN
   BEGIN
     UPDATE CONTROLE SET VALOR = :VENDALANCAMENTO WHERE CAMPO = 'CD_VENDA';
     CD_VENDAPARAMETRO = :VENDAVENDA;
   END
  ELSE
   BEGIN
     UPDATE CONTROLE SET VALOR = 0 WHERE CAMPO = 'CD_VENDA';
     CD_VENDAPARAMETRO = 0;
   END
  UPDATE PARAMETROS SET CD_VENDA = :CD_VENDAPARAMETRO;
END ^

