ALTER PROCEDURE SP_ATUALIZA_CONVENIOSPBM (ID_CONVENIOPBM DOUBLE PRECISION,
NOME VARCHAR(100) CHARACTER SET NONE,
URL VARCHAR(1000) CHARACTER SET NONE,
ENVIADO VARCHAR(1) CHARACTER SET NONE)
AS 
declare variable EXISTE integer;
BEGIN
  SELECT COUNT(*) FROM CONVENIOS_PBM WHERE ID_CONVENIOPBM = :ID_CONVENIOPBM INTO :EXISTE;
  IF (:EXISTE > 0) THEN
   BEGIN
     UPDATE CONVENIOS_PBM SET
        NOME           = :NOME,
        URL            = :URL,
        ENVIADO        = :ENVIADO
     WHERE ID_CONVENIOPBM = :ID_CONVENIOPBM;
   END
  ELSE
   BEGIN
     INSERT INTO CONVENIOS_PBM
     (
        ID_CONVENIOPBM,
        NOME,
        URL,
        ENVIADO
       )
     VALUES(
        :ID_CONVENIOPBM,
        :NOME,
        :URL,
        :ENVIADO
       );
   END
END ^

ALTER PROCEDURE SP_ATUALIZA_CONVENIO_CLIENTE AS 
DECLARE VARIABLE CLIENTE DOUBLE PRECISION;
DECLARE VARIABLE CONVENIO DOUBLE PRECISION;
BEGIN
  FOR
    SELECT
     DISTINCT CD_CLIENTE
    FROM
     CONTAS_RECEBER
    INTO
     :CLIENTE
  DO
   BEGIN
     SELECT CD_CONVENIO FROM CLIENTES WHERE CD_CLIENTE = :CLIENTE INTO :CONVENIO;
     UPDATE VENDAS SET CD_CONVENIO = :CONVENIO WHERE CD_CLIENTE = :CLIENTE;
     UPDATE LANCAMENTOS SET CD_CONVENIO = :CONVENIO WHERE CD_CLIENTE = :CLIENTE;
     UPDATE CAIXA SET CD_CONVENIO = :CONVENIO WHERE CD_CLIENTE = :CLIENTE;
     UPDATE CONTAS_RECEBER SET CD_CONVENIO = :CONVENIO WHERE CD_CLIENTE = :CLIENTE;
   END
END ^

ALTER PROCEDURE SP_ATUALIZA_DADOS_TRANSFER AS 
DECLARE VARIABLE ID_PRODUTO DOUBLE PRECISION;
DECLARE VARIABLE CD_CLASSE DOUBLE PRECISION;
BEGIN
  FOR
   SELECT
    DISTINCT ID_PRODUTO
   FROM
    ITENS_TRANSFER
   WHERE
    CD_CLASSE IS NULL OR CD_CLASSE = 0
   INTO
    :ID_PRODUTO
  DO
   BEGIN
     SELECT CD_CLASSE FROM PRODUTOS WHERE ID_PRODUTO = :ID_PRODUTO INTO :CD_CLASSE;
     IF (CD_CLASSE IS NOT NULL) THEN
        UPDATE ITENS_TRANSFER SET CD_CLASSE = :CD_CLASSE WHERE ID_PRODUTO = :ID_PRODUTO;
   END
END ^

ALTER PROCEDURE SP_ATUALIZA_DELETADOS (TABELA VARCHAR(100) CHARACTER SET NONE,
CAMPO VARCHAR(100) CHARACTER SET NONE,
VALOR VARCHAR(100) CHARACTER SET NONE)
AS 
DECLARE VARIABLE COMANDO VARCHAR(1000);
BEGIN
  COMANDO = 'DELETE FROM '||:TABELA||' WHERE '||:CAMPO||' = '||:VALOR;
  EXECUTE STATEMENT :COMANDO;
END ^

