ALTER PROCEDURE SP_ATUALIZA_ENTREGAS (CD_FILIAL DOUBLE PRECISION,
CD_VENDA DOUBLE PRECISION,
CD_ENTREGADOR DOUBLE PRECISION,
CD_CLIENTE DOUBLE PRECISION,
NOME VARCHAR(50) CHARACTER SET NONE,
ENDERECO VARCHAR(50) CHARACTER SET NONE,
BAIRRO VARCHAR(50) CHARACTER SET NONE,
REFERENCIA VARCHAR(100) CHARACTER SET NONE,
DATA DATE,
HORA_SAIDA TIME,
HORA_CHEGADA TIME,
TROCO DOUBLE PRECISION,
VALORRETORNO DOUBLE PRECISION,
ENVIADO VARCHAR(1) CHARACTER SET NONE,
STATUS VARCHAR(1) CHARACTER SET NONE)
AS 
DECLARE VARIABLE EXISTE INTEGER;
BEGIN
  SELECT COUNT(*) FROM ENTREGAS WHERE CD_VENDA = :CD_VENDA AND CD_FILIAL = :CD_FILIAL INTO :EXISTE;
  IF (:EXISTE > 0) THEN
   BEGIN
     UPDATE ENTREGAS SET
        CD_FILIAL      = :CD_FILIAL,
        CD_VENDA       = :CD_VENDA,
        CD_ENTREGADOR  = :CD_ENTREGADOR,
        CD_CLIENTE     = :CD_CLIENTE,
        NOME           = :NOME,
        ENDERECO       = :ENDERECO,
        BAIRRO         = :BAIRRO,
        REFERENCIA     = :REFERENCIA,
        DATA           = :DATA,
        HORA_SAIDA     = :HORA_SAIDA,
        HORA_CHEGADA   = :HORA_CHEGADA,
        TROCO          = :TROCO,
        VALORRETORNO   = :VALORRETORNO,
        ENVIADO        = :ENVIADO,
        STATUS         = :STATUS
     WHERE CD_VENDA = :CD_VENDA AND CD_FILIAL = :CD_FILIAL;
   END
  ELSE
   BEGIN
     INSERT INTO ENTREGAS(
        CD_FILIAL,
        CD_VENDA,
        CD_ENTREGADOR,
        CD_CLIENTE,
        NOME,
        ENDERECO,
        BAIRRO,
        REFERENCIA,
        DATA,
        HORA_SAIDA,
        HORA_CHEGADA,
        TROCO,
        VALORRETORNO,
        ENVIADO,
        STATUS
       )
     VALUES(
        :CD_FILIAL,
        :CD_VENDA,
        :CD_ENTREGADOR,
        :CD_CLIENTE,
        :NOME,
        :ENDERECO,
        :BAIRRO,
        :REFERENCIA,
        :DATA,
        :HORA_SAIDA,
        :HORA_CHEGADA,
        :TROCO,
        :VALORRETORNO,
        :ENVIADO,
        :STATUS
       );
   END
END ^

