ALTER PROCEDURE SP_ATUALIZA_ESTOQUEMINIMO (CD_FILIAL DOUBLE PRECISION,
ID_PRODUTO DOUBLE PRECISION,
ESTOQUE DOUBLE PRECISION,
CUSTO_UNITARIO DOUBLE PRECISION,
CUSTO_MEDIO DOUBLE PRECISION,
IDENTIFICADOR VARCHAR(1) CHARACTER SET NONE,
FACE DOUBLE PRECISION,
DT_ULT_VENDA VARCHAR(15) CHARACTER SET NONE,
DT_ULT_COMPRA VARCHAR(15) CHARACTER SET NONE)
AS 
DECLARE VARIABLE COMANDO VARCHAR(1000);
BEGIN
  COMANDO = 'UPDATE PRODUTOS SET ESTOQUE_'||CAST(:CD_FILIAL AS INTEGER)||' = '||:ESTOQUE||
            ', CUSTO_UNITARIO_'||CAST(:CD_FILIAL AS INTEGER)||' = '||:CUSTO_UNITARIO||
            ', CUSTO_MEDIO_'||CAST(:CD_FILIAL AS INTEGER)||' = '||:CUSTO_MEDIO;
  IF ((:IDENTIFICADOR IS NULL ) OR (:IDENTIFICADOR = '') OR (:IDENTIFICADOR = 'L')) THEN
    COMANDO = :COMANDO||', CUSTO_UNITARIO = '||:CUSTO_UNITARIO;
  IF (:FACE IS NOT NULL) THEN
    COMANDO = :COMANDO||' , FACE_'||CAST(:CD_FILIAL AS INTEGER)||' = '||:FACE;
  IF (:DT_ULT_VENDA <> '') THEN
    COMANDO = :COMANDO||' , DT_ULT_VENDA_'||CAST(:CD_FILIAL AS INTEGER)||' = '''||:DT_ULT_VENDA||'''';
  IF (:DT_ULT_COMPRA <> '') THEN
    COMANDO = :COMANDO||' , DT_ULT_COMPRA_'||CAST(:CD_FILIAL AS INTEGER)||' = '''||:DT_ULT_COMPRA||'''';

  COMANDO = :COMANDO||' WHERE ID_PRODUTO = '||:ID_PRODUTO;

  EXECUTE STATEMENT :COMANDO;

END ^

ALTER PROCEDURE SP_ATUALIZA_ESTOQUE_TPG (TABELA VARCHAR(100) CHARACTER SET NONE)
AS 
declare variable COMANDOFILIAL varchar(1000);
declare variable COMANDOPRODUTO varchar(1000);
declare variable COMANDOESTOQUE varchar(1000);
declare variable COMANDOUPDATE varchar(1000);
declare variable FILIAIS integer;
declare variable FILIAL varchar(10);
declare variable ID_PRODUTO integer;
declare variable ESTOQUE integer;
BEGIN
  COMANDOFILIAL = 'SELECT SUBSTRING(RDB$FIELD_NAME FROM 2 FOR 2) FROM RDB$RELATION_FIELDS WHERE RDB$SYSTEM_FLAG=0 AND' ||
                  ' RDB$RELATION_NAME = ''' || :TABELA || ''' AND RDB$FIELD_NAME LIKE ''' || 'F%' ||'''';

  COMANDOPRODUTO = 'SELECT ID_PRODUTO FROM ' || :TABELA;
  FOR
    EXECUTE STATEMENT :COMANDOPRODUTO INTO :ID_PRODUTO
  DO
   BEGIN
      FOR
        EXECUTE STATEMENT :COMANDOFILIAL INTO :FILIAL
      DO
       BEGIN
         COMANDOESTOQUE = 'SELECT ESTOQUE_' || :FILIAL || ' FROM PRODUTOS WHERE ID_PRODUTO = ' || :ID_PRODUTO;
         EXECUTE STATEMENT :COMANDOESTOQUE INTO :ESTOQUE;
         COMANDOUPDATE = 'UPDATE ' || :TABELA || ' SET ESTOQUE_' || :FILIAL || ' = ' || :ESTOQUE || ' WHERE ID_PRODUTO = ' || :ID_PRODUTO;
         EXECUTE STATEMENT :COMANDOUPDATE;
       END
   END
END ^

ALTER PROCEDURE SP_ATUALIZA_EST_PRODUTOS_SITE (CD_FILIAL DOUBLE PRECISION)
AS 
declare variable ID_PRODUTO double precision;
declare variable ESTOQUE double precision;
declare variable COMANDO varchar(1000);
declare variable CD_GRUPO double precision;
declare variable CD_CLASSE double precision;
declare variable CD_LABORATORIO double precision;
declare variable CD_SUBGRUPO double precision;
declare variable DESCRICAO varchar(100);
BEGIN
  FOR
    SELECT ID_PRODUTO FROM PRODUTOS_SITE INTO :ID_PRODUTO
  DO
   BEGIN
     COMANDO = '';
     COMANDO = 'SELECT DESCRICAO, CD_GRUPO, CD_LABORATORIO, CD_CLASSE, CD_SUBGRUPO,  ESTOQUE_'||CAST(:CD_FILIAL AS INTEGER)  ||' FROM PRODUTOS WHERE ID_PRODUTO = '||:ID_PRODUTO;
     EXECUTE STATEMENT :COMANDO INTO :DESCRICAO, :CD_GRUPO, :CD_LABORATORIO, :CD_CLASSE, :CD_SUBGRUPO, :ESTOQUE;

     UPDATE PRODUTOS_SITE SET
       DESCRICAO_LOJA = :DESCRICAO,
       CD_LABORATORIO = :CD_LABORATORIO,
       --CD_GRUPO = :CD_GRUPO,
       --CD_CLASSE = :CD_CLASSE,
       CD_SUBGRUPO = :CD_SUBGRUPO,
       ESTOQUE = :ESTOQUE
     WHERE ID_PRODUTO = :ID_PRODUTO;
   END
END ^

ALTER PROCEDURE SP_ATUALIZA_FAMILIAS (ID_FAMILIA DOUBLE PRECISION,
DESCRICAO VARCHAR(100) CHARACTER SET NONE,
STATUS VARCHAR(1) CHARACTER SET NONE,
DT_ALTERACAO DATE,
ALTERAPRECOFAMILIA VARCHAR(1) CHARACTER SET NONE,
ENVIADO VARCHAR(1) CHARACTER SET NONE)
AS 
DECLARE VARIABLE EXISTE INTEGER;
BEGIN
  SELECT COUNT(*) FROM FAMILIAS WHERE ID_FAMILIA = :ID_FAMILIA INTO :EXISTE;
  IF (:EXISTE > 0) THEN
   BEGIN
     UPDATE FAMILIAS SET
        ID_FAMILIA          = :ID_FAMILIA,
        DESCRICAO           = :DESCRICAO,
        STATUS              = :STATUS,
        DT_ALTERACAO        = :DT_ALTERACAO,
        ALTERAPRECOFAMILIA  = :ALTERAPRECOFAMILIA,
        ENVIADO             = :ENVIADO
     WHERE ID_FAMILIA = :ID_FAMILIA;
   END
  ELSE
   BEGIN
     INSERT INTO FAMILIAS (
        ID_FAMILIA,
        DESCRICAO,
        STATUS,
        DT_ALTERACAO,
        ALTERAPRECOFAMILIA,
        ENVIADO
       )
     VALUES(
        :ID_FAMILIA,
        :DESCRICAO,
        :STATUS,
        :DT_ALTERACAO,
        :ALTERAPRECOFAMILIA,
        :ENVIADO
       );
   END
END ^

ALTER PROCEDURE SP_ATUALIZA_FILIAIS (CD_FILIAL DOUBLE PRECISION,
