DECLARE VARIABLE EXISTE INTEGER;
BEGIN
  SELECT COUNT(*) FROM FILIAIS WHERE CD_FILIAL = :CD_FILIAL INTO :EXISTE;
  IF (:EXISTE > 0) THEN
   BEGIN
     UPDATE FILIAIS SET
        CD_FILIAL           = :CD_FILIAL,
        NOME                = :NOME,
        RAZAO               = :RAZAO,
        CNPJ                = :CNPJ,
        INSCRICAO           = :INSCRICAO,
