        FONE_1              = :FONE_1,
        FAX                 = :FAX,
        CONTATO             = :CONTATO,
        CD_DISTRIBUIDOR     = :CD_DISTRIBUIDOR,
        CD_CLIENTE          = :CD_CLIENTE,
        ENDERECOWEB         = :ENDERECOWEB,
        EXPORTAR            = :EXPORTAR,
        METROSQUADRADOS     = :METROSQUADRADOS,
        NUMEROFUNCIONARIOS  = :NUMEROFUNCIONARIOS,
        NUMEROPDVS          = :NUMEROPDVS,
        STATUS              = :STATUS,
        CD_MUNICIPIO        = :CD_MUNICIPIO,
        IFOOD_CLIENT_ID     = :IFOOD_CLIENT_ID,
