ALTER PROCEDURE SP_ATUALIZA_FILIAISGRUPOS (CD_GRUPO DOUBLE PRECISION,
TX_COMISSAO DOUBLE PRECISION,
DESCONTO VARCHAR(1) CHARACTER SET NONE,
TX_DESCONTO DOUBLE PRECISION,
TX_DESCONTO_MAXIMO DOUBLE PRECISION)
AS 
declare variable EXISTE integer;
BEGIN
  SELECT COUNT(*) FROM GRUPOS WHERE CD_GRUPO = :CD_GRUPO INTO :EXISTE;
  IF (:EXISTE > 0) THEN
   BEGIN
     UPDATE GRUPOS SET
        TX_COMISSAO   = :TX_COMISSAO,
        DESCONTO      = :DESCONTO,
        TX_DESCONTO   = :TX_DESCONTO,
        TX_DESCONTO_MAXIMO = :TX_DESCONTO_MAXIMO
     WHERE CD_GRUPO = :CD_GRUPO;
   END
END ^

