ALTER PROCEDURE SP_ATUALIZA_GRUPO_CLASSE_SITE AS 
declare variable ID_PRODUTO double precision;
declare variable CD_GRUPO double precision;
declare variable CD_CLASSE double precision;
declare variable CD_LABORATORIO double precision;
declare variable CD_SUBGRUPO double precision;
BEGIN
  FOR
    SELECT ID_PRODUTO FROM PRODUTOS_SITE INTO :ID_PRODUTO
  DO
   BEGIN
     SELECT CD_GRUPO, CD_CLASSE, CD_LABORATORIO, CD_SUBGRUPO
     FROM PRODUTOS
     WHERE ID_PRODUTO = :ID_PRODUTO
     INTO :CD_GRUPO, :CD_CLASSE, :CD_LABORATORIO, :CD_SUBGRUPO;

     UPDATE PRODUTOS_SITE SET
      CD_GRUPO = :CD_GRUPO,
      CD_CLASSE = :CD_CLASSE,
      CD_LABORATORIO = :CD_LABORATORIO,
      CD_SUBGRUPO = :CD_SUBGRUPO
     WHERE
      ID_PRODUTO = :ID_PRODUTO;
   END
END ^

