ALTER PROCEDURE SP_ATUALIZA_ITENS_TRANSFER (CD_TRANSFER DOUBLE PRECISION,
ID_PRODUTO DOUBLE PRECISION,
CD_PRODUTO DOUBLE PRECISION,
CD_CLASSE DOUBLE PRECISION,
CD_GRUPO DOUBLE PRECISION,
CD_LABORATORIO DOUBLE PRECISION,
DESCRICAO VARCHAR(60) CHARACTER SET NONE,
QUANTIDADE_SOLICITADA DOUBLE PRECISION,
QUANTIDADE_ENVIADA DOUBLE PRECISION,
QUANTIDADE_RECEBIDA DOUBLE PRECISION,
VALOR DOUBLE PRECISION,
OBSERVACOES VARCHAR(255) CHARACTER SET NONE,
STATUS VARCHAR(1) CHARACTER SET NONE)
AS 
DECLARE VARIABLE EXISTE INTEGER;
DECLARE VARIABLE STATUSTRANSFER VARCHAR(1);
BEGIN
  SELECT COUNT(*) FROM ITENS_TRANSFER WHERE CD_TRANSFER = :CD_TRANSFER AND ID_PRODUTO = :ID_PRODUTO INTO :EXISTE;
  IF (:EXISTE > 0) THEN
   BEGIN
     SELECT STATUS FROM ITENS_TRANSFER WHERE CD_TRANSFER = :CD_TRANSFER AND ID_PRODUTO = :ID_PRODUTO INTO :STATUSTRANSFER;
     IF (((:STATUSTRANSFER = 'G') AND (:STATUS <> 'G')) OR
         ((:STATUSTRANSFER = 'E') AND ((:STATUS = 'C') OR (STATUS = 'X')))) THEN
      BEGIN
        UPDATE ITENS_TRANSFER SET
            CD_TRANSFER            = :CD_TRANSFER,
            ID_PRODUTO             = :ID_PRODUTO,
            CD_PRODUTO             = :CD_PRODUTO,
            CD_CLASSE              = :CD_CLASSE,
            CD_GRUPO               = :CD_GRUPO,
            CD_LABORATORIO         = :CD_LABORATORIO,
            DESCRICAO              = :DESCRICAO,
            QUANTIDADE_SOLICITADA  = :QUANTIDADE_SOLICITADA,
            QUANTIDADE_ENVIADA     = :QUANTIDADE_ENVIADA,
            QUANTIDADE_RECEBIDA    = :QUANTIDADE_RECEBIDA,
            VALOR                  = :VALOR,
            OBSERVACOES            = :OBSERVACOES,
            STATUS                 = :STATUS
        WHERE CD_TRANSFER = :CD_TRANSFER AND ID_PRODUTO = :ID_PRODUTO;
      END
   END
  ELSE
   BEGIN
     INSERT INTO ITENS_TRANSFER(
        CD_TRANSFER,
        ID_PRODUTO,
        CD_PRODUTO,
        CD_CLASSE,
        CD_GRUPO,
        CD_LABORATORIO,
        DESCRICAO,
        QUANTIDADE_SOLICITADA,
        QUANTIDADE_ENVIADA,
        QUANTIDADE_RECEBIDA,
        VALOR,
        OBSERVACOES,
        STATUS
       )
     VALUES(
        :CD_TRANSFER,
        :ID_PRODUTO,
        :CD_PRODUTO,
        :CD_CLASSE,
        :CD_GRUPO,
        :CD_LABORATORIO,
        :DESCRICAO,
        :QUANTIDADE_SOLICITADA,
        :QUANTIDADE_ENVIADA,
        :QUANTIDADE_RECEBIDA,
        :VALOR,
        :OBSERVACOES,
        :STATUS
       );
   END
END ^

ALTER PROCEDURE SP_ATUALIZA_LABORATORIOS (CD_LABORATORIO DOUBLE PRECISION,
ID_AREA DOUBLE PRECISION,
NOME VARCHAR(40) CHARACTER SET NONE,
RAZAO VARCHAR(40) CHARACTER SET NONE,
CNPJ VARCHAR(18) CHARACTER SET NONE,
ENDERECO VARCHAR(50) CHARACTER SET NONE,
CIDADE VARCHAR(30) CHARACTER SET NONE,
FONE VARCHAR(40) CHARACTER SET NONE,
CONTATO VARCHAR(20) CHARACTER SET NONE,
TX_DESCONTO DOUBLE PRECISION,
CONTROLE VARCHAR(1) CHARACTER SET NONE,
DT_ALTERACAO DATE,
NPRODUTOS DOUBLE PRECISION,
NITENS DOUBLE PRECISION,
VPRODUTOS DOUBLE PRECISION,
CPRODUTOS DOUBLE PRECISION,
ENVIADO VARCHAR(1) CHARACTER SET NONE)
AS 
declare variable EXISTE integer;
BEGIN
  SELECT COUNT(*) FROM LABORATORIOS WHERE CD_LABORATORIO = :CD_LABORATORIO INTO :EXISTE;
  IF (:EXISTE > 0) THEN
   BEGIN
     UPDATE LABORATORIOS SET
        CD_LABORATORIO  = :CD_LABORATORIO,
        ID_AREA         = :ID_AREA,
        NOME            = :NOME,
        RAZAO           = :RAZAO,
        CNPJ            = :CNPJ,
        ENDERECO        = :ENDERECO,
        CIDADE          = :CIDADE,
        FONE            = :FONE,
        CONTATO         = :CONTATO,
        TX_DESCONTO     = :TX_DESCONTO,
        CONTROLE        = :CONTROLE,
        DT_ALTERACAO    = :DT_ALTERACAO,
        NPRODUTOS       = :NPRODUTOS,
        NITENS          = :NITENS,
        VPRODUTOS       = :VPRODUTOS,
        CPRODUTOS       = :CPRODUTOS,
        ENVIADO         = :ENVIADO
     WHERE CD_LABORATORIO = :CD_LABORATORIO;
   END
  ELSE
   BEGIN
     INSERT INTO LABORATORIOS(
        CD_LABORATORIO,
        ID_AREA,
        NOME,
        RAZAO,
        CNPJ,
        ENDERECO,
        CIDADE,
        FONE,
        CONTATO,
        TX_DESCONTO,
        CONTROLE,
        DT_ALTERACAO,
        NPRODUTOS,
        NITENS,
        VPRODUTOS,
        CPRODUTOS,
        ENVIADO
       )
     VALUES(
        :CD_LABORATORIO,
        :ID_AREA,
        :NOME,
        :RAZAO,
        :CNPJ,
        :ENDERECO,
        :CIDADE,
        :FONE,
        :CONTATO,
        :TX_DESCONTO,
        :CONTROLE,
        :DT_ALTERACAO,
        :NPRODUTOS,
        :NITENS,
        :VPRODUTOS,
        :CPRODUTOS,
        :ENVIADO
       );
   END
END ^

