ALTER PROCEDURE SP_ATUALIZA_NCM_PRODUTOS AS 
declare variable BARRA varchar(14);
declare variable NCM varchar(8);
BEGIN
  FOR
    SELECT
     CODIGO_BARRAS,
     NCM
    FROM
     DICIONARIONCM
    INTO
     :BARRA,
     :NCM
  DO
   BEGIN
     UPDATE PRODUTOS SET
      NCM = :NCM
     WHERE
      ((CODIGO_BARRAS_1 = :BARRA) OR (CODIGO_BARRAS_2 = :BARRA)) AND
      LPAD(NCM, 8) = '99999999';
   END
END ^

ALTER PROCEDURE SP_ATUALIZA_PERMISSOES_MODULOS AS 
declare variable MODULO double precision;
declare variable PERMISSAO double precision;
declare variable MODULO2 double precision;
BEGIN
  FOR
    SELECT
     CD_MODULO
    FROM
     MODULOS
    INTO
     :MODULO
  DO
   BEGIN
      FOR
       SELECT
        CD_PERMISSAO
       FROM
        PERMISSOES
       INTO
        :PERMISSAO
      DO
       BEGIN
         MODULO2 = 0;
         SELECT
           CD_MODULO
         FROM
           PERMISSOES_MODULOS
         WHERE
           CD_MODULO = :MODULO AND
           CD_PERMISSAO = :PERMISSAO
         INTO
           :MODULO2;
         IF (:MODULO2 = 0) then
          BEGIN
            IF (:PERMISSAO = 1) THEN
              INSERT INTO PERMISSOES_MODULOS VALUES (:PERMISSAO, :MODULO, 'S', 'S', 'S', 'S', 'S', '');
            ELSE
              INSERT INTO PERMISSOES_MODULOS VALUES (:PERMISSAO, :MODULO, 'N', 'N', 'N', 'N', 'N', '');
          END
       END
   END
   UPDATE PERMISSOES_MODULOS SET INCLUSAO = 'N' WHERE (INCLUSAO IS NULL) OR (INCLUSAO = '');
   UPDATE PERMISSOES_MODULOS SET ALTERACAO = 'N' WHERE (ALTERACAO IS NULL) OR (ALTERACAO = '');
   UPDATE PERMISSOES_MODULOS SET EXCLUSAO = 'N' WHERE (EXCLUSAO IS NULL) OR (EXCLUSAO = '');
   UPDATE PERMISSOES_MODULOS SET IMPRESSAO = 'N' WHERE (IMPRESSAO IS NULL) OR (IMPRESSAO = '');
END ^

