ALTER PROCEDURE SP_ATUALIZA_PRECOS_DISTR (CD_DISTR DOUBLE PRECISION,
CODIGO DOUBLE PRECISION,
PRECO_VENDA DOUBLE PRECISION,
CUSTO_UNITARIO DOUBLE PRECISION,
ATUALIZARLOJAS VARCHAR(1) CHARACTER SET NONE)
AS 
declare variable ID_PRODUTO double precision;
declare variable TIPOLOJA varchar(1);
declare variable CD_FILIAL double precision;
declare variable COMANDO varchar(1000);
BEGIN
  SELECT TIPO_LOJA FROM PARAMETROS INTO :TIPOLOJA;
  FOR
    SELECT
     PROD_DISTR.ID_PRODUTO
    FROM
     PROD_DISTR
    WHERE
     CD_DISTRIBUIDOR = :CD_DISTR AND
     CODIGO = :CODIGO
    INTO
     :ID_PRODUTO
  DO
   BEGIN
     UPDATE PRODUTOS SET
      PRECO_VENDA = :PRECO_VENDA ,
      CUSTO_UNITARIO = :CUSTO_UNITARIO,
      DT_REAJUSTE = CURRENT_DATE
     WHERE
      ID_PRODUTO = :ID_PRODUTO AND
      PRECO_VENDA <> :PRECO_VENDA;

    IF ((:ATUALIZARLOJAS = 'S') AND (:TIPOLOJA = 'M')) THEN
     BEGIN
       FOR
         SELECT CD_FILIAL FROM FILIAIS WHERE EXPORTAR = 'S' INTO :CD_FILIAL
       DO
        BEGIN
          COMANDO = '';
          COMANDO = 'UPDATE PRODUTOS SET PRECO_VENDA_' || CAST(:CD_FILIAL AS INTEGER) || ' = ' || CAST(:PRECO_VENDA AS NUMERIC(15,2)) || ', ' ||
                    'CUSTO_UNITARIO_' || CAST(:CD_FILIAL AS INTEGER) || ' = ' || CAST(:CUSTO_UNITARIO AS NUMERIC(15,2)) || ', ' ||
                    'DT_REAJUSTE_' || CAST(:CD_FILIAL AS INTEGER) || ' = ''' || CURRENT_DATE || '''' ||
                    ' WHERE ID_PRODUTO = ' || :ID_PRODUTO || ' AND ' ||
                    ' PRECO_VENDA_' || CAST(:CD_FILIAL AS INTEGER) || ' <> ' || CAST(:PRECO_VENDA AS NUMERIC(15,2));
          EXECUTE STATEMENT :COMANDO;
        END
     END
   END
END ^

