AS 
declare variable EXISTE integer;
BEGIN
  SELECT COUNT(*) FROM PRODUTOS_FIDELIDADE WHERE ID_PRODUTO = :ID_PRODUTO INTO :EXISTE;
  IF (:EXISTE > 0) THEN
   BEGIN
     UPDATE PRODUTOS_FIDELIDADE SET
        DESCRICAO = :DESCRICAO, 
        PRECO  = :PRECO,
        CD_GRUPO = :CD_GRUPO,
        CD_LABORATORIO = :CD_LABORATORIO,
        DT_ALTERACAO = :DT_ALTERACAO
     WHERE ID_PRODUTO = :ID_PRODUTO;
   END
  ELSE
   BEGIN
     INSERT INTO PRODUTOS_FIDELIDADE(
        ID_PRODUTO,
        CD_PRODUTO,
        CD_LABORATORIO,
        DESCRICAO,
        PRECO,
        CD_GRUPO,
        DT_ALTERACAO
       )
     VALUES(
        :ID_PRODUTO,
        :CD_PRODUTO,
        :CD_LABORATORIO,
        :DESCRICAO,
        :PRECO,
        :CD_GRUPO,
        :DT_ALTERACAO
       );
   END
END ^

