ALTER PROCEDURE SP_ATUALIZA_QT_PRODUTOS_M RETURNS (FILIAL INTEGER,
CLASSE DOUBLE PRECISION,
GRUPO DOUBLE PRECISION,
LABORATORIO DOUBLE PRECISION,
QUANTIDADE INTEGER,
CUSTO DOUBLE PRECISION,
VENDA DOUBLE PRECISION,
ITENS DOUBLE PRECISION)
AS 
DECLARE VARIABLE COMANDOLABORATORIO VARCHAR(255);
DECLARE VARIABLE COMANDOCLASSE VARCHAR(255);
DECLARE VARIABLE COMANDOGRUPO VARCHAR(255);
DECLARE VARIABLE VARCASTVENDA VARCHAR(100);
DECLARE VARIABLE VARCASTCUSTO VARCHAR(100);
BEGIN
  UPDATE GRUPOS SET NITENS = 0, NPRODUTOS = 0, CPRODUTOS = 0, VPRODUTOS = 0;
  UPDATE LABORATORIOS SET NITENS = 0, NPRODUTOS = 0, CPRODUTOS = 0, VPRODUTOS = 0;
  UPDATE CLASSES SET NITENS = 0, NPRODUTOS = 0, CPRODUTOS = 0, VPRODUTOS = 0;

  FOR
   SELECT CD_LABORATORIO
   FROM LABORATORIOS
   INTO :LABORATORIO
  DO
   BEGIN
     SELECT COUNT(*) FROM PRODUTOS WHERE CD_LABORATORIO = :LABORATORIO INTO :QUANTIDADE;
     IF (:QUANTIDADE IS NULL) THEN
         QUANTIDADE = 0;
     UPDATE LABORATORIOS SET NPRODUTOS = :QUANTIDADE WHERE CD_LABORATORIO = :LABORATORIO;
   END

  FOR
   SELECT CD_GRUPO
   FROM GRUPOS
   INTO :GRUPO
  DO
   BEGIN
     SELECT COUNT(*) FROM PRODUTOS WHERE CD_GRUPO = :GRUPO INTO :QUANTIDADE;
     IF (:QUANTIDADE IS NULL) THEN
         QUANTIDADE = 0;
     UPDATE GRUPOS SET NPRODUTOS = :QUANTIDADE WHERE CD_GRUPO = :GRUPO;
   END

  FOR
   SELECT CD_CLASSE
   FROM CLASSES
   INTO :CLASSE
  DO
   BEGIN
     SELECT COUNT(*) FROM PRODUTOS WHERE CD_CLASSE = :CLASSE INTO :QUANTIDADE;
     IF (:QUANTIDADE IS NULL) THEN
         QUANTIDADE = 0;
     UPDATE CLASSES SET NPRODUTOS = :QUANTIDADE WHERE CD_CLASSE = :CLASSE;
   END


  FOR
   SELECT CD_FILIAL
   FROM FILIAIS
   WHERE EXPORTAR = 'S'
   INTO :FILIAL
  DO
   BEGIN
      VARCASTCUSTO = 'CAST(CUSTO_MEDIO_'||:FILIAL||' AS NUMERIC(15,2))';
      VARCASTVENDA = 'CAST(PRECO_VENDA_'||:FILIAL||' AS NUMERIC(15,2))';

      COMANDOLABORATORIO = 'SELECT CD_LABORATORIO, SUM('||:VARCASTVENDA||'*ESTOQUE_'||FILIAL||'), SUM('||:VARCASTCUSTO||'*ESTOQUE_'||FILIAL||'), SUM(ESTOQUE_'||FILIAL||') FROM PRODUTOS WHERE STATUS = '''||'A'||''' GROUP BY CD_LABORATORIO';
      COMANDOGRUPO = 'SELECT CD_GRUPO, SUM('||:VARCASTVENDA||'*ESTOQUE_'||FILIAL||'), SUM('||:VARCASTCUSTO||'*ESTOQUE_'||FILIAL||'), SUM(ESTOQUE_'||FILIAL||') FROM PRODUTOS WHERE STATUS = '''||'A'||''' GROUP BY CD_GRUPO';
      COMANDOCLASSE = 'SELECT CD_CLASSE, SUM('||:VARCASTVENDA||'*ESTOQUE_'||FILIAL||'), SUM('||:VARCASTCUSTO||'*ESTOQUE_'||FILIAL||'), SUM(ESTOQUE_'||FILIAL||') FROM PRODUTOS WHERE STATUS = '''||'A'||''' GROUP BY CD_CLASSE';

      FOR
        EXECUTE STATEMENT :COMANDOLABORATORIO
        INTO :LABORATORIO, :VENDA, :CUSTO, :ITENS
      DO
       BEGIN
        UPDATE LABORATORIOS SET
          VPRODUTOS = VPRODUTOS + CAST(:VENDA AS NUMERIC(15,2)) ,
          CPRODUTOS = CPRODUTOS + CAST(:CUSTO AS NUMERIC(15,2)),
          NITENS    = NITENS + :ITENS
        WHERE
          CD_LABORATORIO = :LABORATORIO;
       END

      FOR
        EXECUTE STATEMENT :COMANDOGRUPO
        INTO :GRUPO, :VENDA, :CUSTO, :ITENS
      DO
       BEGIN
        UPDATE GRUPOS SET
          VPRODUTOS = VPRODUTOS + CAST(:VENDA AS NUMERIC(15,2)),
          CPRODUTOS = CPRODUTOS + CAST(:CUSTO AS NUMERIC(15,2)),
          NITENS    = NITENS + :ITENS
        WHERE
          CD_GRUPO = :GRUPO;
       END

      FOR
        EXECUTE STATEMENT :COMANDOCLASSE
        INTO :CLASSE, :VENDA, :CUSTO, :ITENS
      DO
       BEGIN
        UPDATE CLASSES SET
          VPRODUTOS = VPRODUTOS + CAST(:VENDA AS NUMERIC(15,2)),
          CPRODUTOS = CPRODUTOS + CAST(:CUSTO AS NUMERIC(15,2)),
          NITENS    = NITENS + :ITENS
        WHERE
          CD_CLASSE = :CLASSE;
       END

   END

END ^

ALTER PROCEDURE SP_ATUALIZA_QT_PRODUTOS_TODOS (FILIAL VARCHAR(10) CHARACTER SET NONE,
TIPOCUSTO VARCHAR(1) CHARACTER SET NONE)
RETURNS (CLASSE INTEGER,
GRUPO INTEGER,
LABORATORIO INTEGER,
QUANTIDADE INTEGER,
CUSTO DOUBLE PRECISION,
VENDA DOUBLE PRECISION,
ITENS DOUBLE PRECISION)
AS 
DECLARE VARIABLE COMANDO VARCHAR(255);
DECLARE VARIABLE COMANDO1 VARCHAR(255);
DECLARE VARIABLE VARCASTVENDA VARCHAR(100);
DECLARE VARIABLE VARCASTCUSTO VARCHAR(100);
DECLARE VARIABLE VARCASTVENDAFILIAL VARCHAR(100);
DECLARE VARIABLE VARCASTCUSTOFILIAL VARCHAR(100);
BEGIN
  VARCASTVENDA = 'CAST(PRECO_VENDA_'||:FILIAL||' AS NUMERIC(15,2))';
  VARCASTCUSTO = 'CAST(CUSTO_UNITARIO AS NUMERIC(15,2))';
  VARCASTVENDAFILIAL = 'CAST(PRECO_VENDA AS NUMERIC(15,2))';
  VARCASTCUSTOFILIAL = 'CAST(CUSTO_MEDIO_'||:FILIAL||' AS NUMERIC(15,2))';

  UPDATE GRUPOS SET NITENS = 0, NPRODUTOS = 0, CPRODUTOS = 0, VPRODUTOS= 0;
  UPDATE LABORATORIOS SET NITENS = 0, NPRODUTOS = 0, CPRODUTOS = 0, VPRODUTOS= 0;
  UPDATE CLASSES SET NITENS = 0, NPRODUTOS = 0, CPRODUTOS = 0, VPRODUTOS= 0;

  IF (:FILIAL = 0) THEN
     COMANDO = 'SELECT SUM('||:VARCASTVENDAFILIAL||'*ESTOQUE_'||FILIAL||'), SUM('||:VARCASTCUSTO||'*ESTOQUE_'||FILIAL||'), SUM(ESTOQUE_'||FILIAL||') FROM PRODUTOS';
  ELSE
   BEGIN
     IF (:TIPOCUSTO = 'L') THEN
      BEGIN
        COMANDO = 'SELECT SUM('||:VARCASTVENDA||'*ESTOQUE_'||FILIAL||'), SUM('||:VARCASTCUSTOFILIAL||'*ESTOQUE_'||FILIAL||'), SUM(ESTOQUE_'||FILIAL||') FROM PRODUTOS';
      END
     ELSE
      BEGIN
        COMANDO = 'SELECT SUM('||:VARCASTVENDAFILIAL||'*ESTOQUE_'||FILIAL||'), SUM('||:VARCASTCUSTO||'*ESTOQUE_'||FILIAL||'), SUM(ESTOQUE_'||FILIAL||') FROM PRODUTOS';
      END
   END
  FOR
    SELECT CD_LABORATORIO FROM PRODUTOS GROUP BY CD_LABORATORIO INTO :LABORATORIO
  DO
   BEGIN
    COMANDO1 = :COMANDO || ' WHERE CD_LABORATORIO = '||:LABORATORIO||' AND STATUS = '''||'A'||''' AND ESTOQUE_'||FILIAL||' > 0';
    EXECUTE STATEMENT :COMANDO1 INTO :VENDA, :CUSTO, :ITENS;
    IF (:VENDA IS NULL) THEN
        VENDA = 0;
    IF (:CUSTO IS NULL) THEN
        CUSTO = 0;
    IF (:ITENS IS NULL) THEN
        ITENS = 0;
    SELECT COUNT(*) FROM PRODUTOS WHERE CD_LABORATORIO = :LABORATORIO INTO :QUANTIDADE;
    UPDATE LABORATORIOS SET
      NPRODUTOS = :QUANTIDADE,
      VPRODUTOS = CAST(:VENDA AS NUMERIC(15,2)) ,
      CPRODUTOS = CAST(:CUSTO AS NUMERIC(15,2)),
      NITENS    = :ITENS
    WHERE
      CD_LABORATORIO = :LABORATORIO;
   END

  FOR
    SELECT CD_GRUPO FROM PRODUTOS GROUP BY CD_GRUPO INTO :GRUPO
  DO
   BEGIN
    COMANDO1 = :COMANDO || ' WHERE CD_GRUPO = '||:GRUPO||' AND STATUS = '''||'A'||''' AND ESTOQUE_'||FILIAL||' > 0';
    EXECUTE STATEMENT :COMANDO1 INTO :VENDA, :CUSTO, :ITENS;
    IF (:VENDA IS NULL) THEN
        VENDA = 0;
    IF (:CUSTO IS NULL) THEN
        CUSTO = 0;
    IF (:ITENS IS NULL) THEN
        ITENS = 0;
    SELECT COUNT(*) FROM PRODUTOS WHERE CD_GRUPO = :GRUPO INTO :QUANTIDADE;
    UPDATE GRUPOS SET
      NPRODUTOS = :QUANTIDADE,
      VPRODUTOS = CAST(:VENDA AS NUMERIC(15,2)),
      CPRODUTOS = CAST(:CUSTO AS NUMERIC(15,2)),
      NITENS    = :ITENS
    WHERE
      CD_GRUPO = :GRUPO;
   END

  FOR
    SELECT CD_CLASSE FROM PRODUTOS GROUP BY CD_CLASSE INTO :CLASSE
  DO
   BEGIN
    COMANDO1 = :COMANDO || ' WHERE CD_CLASSE = '||:CLASSE||' AND STATUS = '''||'A'||''' AND ESTOQUE_'||FILIAL||' > 0';
    EXECUTE STATEMENT :COMANDO1 INTO :VENDA, :CUSTO, :ITENS;
    IF (:VENDA IS NULL) THEN
        VENDA = 0;
    IF (:CUSTO IS NULL) THEN
        CUSTO = 0;
    IF (:ITENS IS NULL) THEN
        ITENS = 0;
    SELECT COUNT(*) FROM PRODUTOS WHERE CD_CLASSE = :CLASSE INTO :QUANTIDADE;
    UPDATE CLASSES SET
      NPRODUTOS = :QUANTIDADE,
      VPRODUTOS = CAST(:VENDA AS NUMERIC(15,2)),
      CPRODUTOS = CAST(:CUSTO AS NUMERIC(15,2)),
      NITENS    = :ITENS
    WHERE
      CD_CLASSE = :CLASSE;
   END

END ^

