CHAVENFE VARCHAR(100) CHARACTER SET NONE)
AS 
declare variable EXISTE integer;
BEGIN
  SELECT COUNT(*) FROM SINTEGRA_NF_ENTRADA WHERE COD_NF_ENTRADA = :COD_NF_ENTRADA AND CD_FILIAL = :CD_FILIAL INTO :EXISTE;

  IF (:VENCIMENTO_01 = CAST('30.12.1899' AS DATE)) THEN
     VENCIMENTO_01 = NULL;
  IF (:VENCIMENTO_02 = CAST('30.12.1899' AS DATE)) THEN
     VENCIMENTO_02 = NULL;
  IF (:VENCIMENTO_03 = CAST('30.12.1899' AS DATE)) THEN
     VENCIMENTO_03 = NULL;
  IF (:DATAHORA = CAST('30.12.1899' AS DATE)) THEN
     DATAHORA = NULL;
  IF (:ULTATUAL = CAST('30.12.1899' AS DATE)) THEN
     ULTATUAL = NULL;

  IF (:EXISTE > 0) THEN
   BEGIN
     UPDATE SINTEGRA_NF_ENTRADA SET
          COD_NF_ENTRADA         = :COD_NF_ENTRADA,
          CD_FILIAL              = :CD_FILIAL,
          NUM_FORM               = :NUM_FORM,
