          BASE_ICMS_SUBST        = :BASE_ICMS_SUBST,
          OUTRAS_DESPESAS        = :OUTRAS_DESPESAS,
          VALOR_ICMS_SUBST       = :VALOR_ICMS_SUBST,
          VALOR_IPI              = :VALOR_IPI,
          VALOR_ISENTO_IPI       = :VALOR_ISENTO_IPI,
