ALTER PROCEDURE SP_ATUALIZA_SINTEGRANFITENS (COD_NF_ENTRADA_ITENS INTEGER,
CD_FILIAL INTEGER,
COD_NF_ENTRADA INTEGER,
COD_PRODUTOS INTEGER,
REF_PRODUTOS VARCHAR(30) CHARACTER SET NONE,
NUM_ITEM INTEGER,
CL_FIS VARCHAR(15) CHARACTER SET NONE,
S_TRIB VARCHAR(15) CHARACTER SET NONE,
PRODUTO VARCHAR(60) CHARACTER SET NONE,
COD_GRUPOP INTEGER,
COD_SUBGRUPOP INTEGER,
DATAHORA TIMESTAMP,
QUANTIDADE NUMERIC(15, 3),
PRC_CUSTO NUMERIC(15, 3),
VALOR_DESCONTO NUMERIC(15, 4),
VALOR_IPI NUMERIC(15, 3),
SUBTOTAL NUMERIC(15, 3),
BASE_ICMS NUMERIC(15, 3),
BASE_ICMS_SUBST NUMERIC(15, 3),
VALOR_ICMS NUMERIC(15, 3),
ENABLE_NUMSERIE INTEGER,
OBS VARCHAR(255) CHARACTER SET NONE,
ENABLED INTEGER,
ULTATUAL TIMESTAMP,
ULTATUALCODSETOR INTEGER,
ULTATUALCODSETORUSER INTEGER,
APR_UND VARCHAR(6) CHARACTER SET NONE,
PERC_DESCONTO NUMERIC(15, 3),
ALIQUOTA_IPI NUMERIC(15, 2),
ALIQUOTA_ICMS NUMERIC(15, 2),
REDUCAO_BASE_ICMS NUMERIC(15, 3),
ENVIADO VARCHAR(1) CHARACTER SET NONE,
CFOP VARCHAR(10) CHARACTER SET NONE,
VALOR_ICMS_SUBTITUICAO NUMERIC(15, 2),
MARGEM_VALOR_AGREGADO NUMERIC(15, 2),
REDUCAO_ICMS_ST NUMERIC(15, 2),
PERCENTUAL_ICMS_ST NUMERIC(15, 2),
PIS_CST VARCHAR(3) CHARACTER SET NONE,
PIS_BASE_CALCULO NUMERIC(15, 2),
PIS_PERCENTUAL NUMERIC(15, 2),
PIS_VALOR NUMERIC(15, 2),
COFINS_CST VARCHAR(3) CHARACTER SET NONE,
COFINS_BASE_CALCULO NUMERIC(15, 2),
COFINS_PERCENTUAL NUMERIC(15, 2),
COFINS_VALOR NUMERIC(15, 2),
VALOR_OUTRASDESPESAS NUMERIC(15, 2),
VALOR_FRETE NUMERIC(15, 2),
VALOR_SEGURO NUMERIC(15, 2),
VALOR_ISENTO NUMERIC(15, 2))
AS 
declare variable EXISTE integer;
BEGIN
 SELECT COUNT(*) FROM SINTEGRA_NF_ENTRADA_ITENS WHERE CD_FILIAL = :CD_FILIAL AND COD_NF_ENTRADA = :COD_NF_ENTRADA AND COD_NF_ENTRADA_ITENS = :COD_NF_ENTRADA_ITENS INTO :EXISTE;
 IF (:EXISTE > 0) THEN
  BEGIN
    UPDATE SINTEGRA_NF_ENTRADA_ITENS SET
      COD_NF_ENTRADA_ITENS  = :COD_NF_ENTRADA_ITENS,
      CD_FILIAL             = :CD_FILIAL,
      COD_NF_ENTRADA        = :COD_NF_ENTRADA,
      COD_PRODUTOS          = :COD_PRODUTOS,
      REF_PRODUTOS          = :REF_PRODUTOS,
      NUM_ITEM              = :NUM_ITEM,
      CL_FIS                = :CL_FIS,
      S_TRIB                = :S_TRIB,
      PRODUTO               = :PRODUTO,
      COD_GRUPOP            = :COD_GRUPOP,
      COD_SUBGRUPOP         = :COD_SUBGRUPOP,
      DATAHORA              = :DATAHORA,
      QUANTIDADE            = :QUANTIDADE,
      PRC_CUSTO             = :PRC_CUSTO,
      VALOR_DESCONTO        = :VALOR_DESCONTO,
      VALOR_IPI             = :VALOR_IPI,
      SUBTOTAL              = :SUBTOTAL,
      BASE_ICMS             = :BASE_ICMS,
      BASE_ICMS_SUBST       = :BASE_ICMS_SUBST,
      VALOR_ICMS            = :VALOR_ICMS,
      ENABLE_NUMSERIE       = :ENABLE_NUMSERIE,
      OBS                   = :OBS,
      ENABLED               = :ENABLED,
      ULTATUAL              = :ULTATUAL,
      ULTATUALCODSETOR      = :ULTATUALCODSETOR,
      ULTATUALCODSETORUSER  = :ULTATUALCODSETORUSER,
      APR_UND               = :APR_UND,
      PERC_DESCONTO         = :PERC_DESCONTO,
      ALIQUOTA_IPI          = :ALIQUOTA_IPI,
      ALIQUOTA_ICMS         = :ALIQUOTA_ICMS,
      REDUCAO_BASE_ICMS     = :REDUCAO_BASE_ICMS,
      ENVIADO               = :ENVIADO,
      CFOP                  = :CFOP,
      VALOR_ICMS_SUBTITUICAO= :VALOR_ICMS_SUBTITUICAO,
      MARGEM_VALOR_AGREGADO = :MARGEM_VALOR_AGREGADO,
      REDUCAO_ICMS_ST       = :REDUCAO_ICMS_ST,
      PERCENTUAL_ICMS_ST    = :PERCENTUAL_ICMS_ST,
      PIS_CST               = :PIS_CST,
      PIS_BASE_CALCULO      = :PIS_BASE_CALCULO,
      PIS_PERCENTUAL        = :PIS_PERCENTUAL,
      PIS_VALOR             = :PIS_VALOR,
      COFINS_CST            = :COFINS_CST,
      COFINS_BASE_CALCULO   = :COFINS_BASE_CALCULO,
      COFINS_PERCENTUAL     = :COFINS_PERCENTUAL,
      COFINS_VALOR          = :COFINS_VALOR,
      VALOR_OUTRASDESPESAS  = :VALOR_OUTRASDESPESAS,
      VALOR_FRETE           = :VALOR_FRETE,
      VALOR_SEGURO          = :VALOR_SEGURO,
      VALOR_ISENTO          = :VALOR_ISENTO
    WHERE CD_FILIAL = :CD_FILIAL AND COD_NF_ENTRADA = :COD_NF_ENTRADA AND COD_NF_ENTRADA_ITENS = :COD_NF_ENTRADA_ITENS;
  END
 ELSE
  BEGIN
    INSERT INTO SINTEGRA_NF_ENTRADA_ITENS (
      COD_NF_ENTRADA_ITENS,
      CD_FILIAL,
      COD_NF_ENTRADA,
      COD_PRODUTOS,
      REF_PRODUTOS,
      NUM_ITEM,
      CL_FIS,
      S_TRIB,
      PRODUTO,
      COD_GRUPOP,
      COD_SUBGRUPOP,
      DATAHORA,
      QUANTIDADE,
      PRC_CUSTO,
      VALOR_DESCONTO,
      VALOR_IPI,
      SUBTOTAL,
      BASE_ICMS,
      BASE_ICMS_SUBST,
      VALOR_ICMS,
      ENABLE_NUMSERIE,
      OBS,
      ENABLED,
      ULTATUAL,
      ULTATUALCODSETOR,
      ULTATUALCODSETORUSER,
      APR_UND,
      PERC_DESCONTO,
      ALIQUOTA_IPI,
      ALIQUOTA_ICMS,
      REDUCAO_BASE_ICMS,
      ENVIADO,
      CFOP,
      VALOR_ICMS_SUBTITUICAO,
      MARGEM_VALOR_AGREGADO,
      REDUCAO_ICMS_ST,
      PERCENTUAL_ICMS_ST,
      PIS_CST,
      PIS_BASE_CALCULO,
      PIS_PERCENTUAL,
      PIS_VALOR,
      COFINS_CST,
      COFINS_BASE_CALCULO,
      COFINS_PERCENTUAL,
      COFINS_VALOR,
      VALOR_OUTRASDESPESAS,
      VALOR_FRETE,
      VALOR_SEGURO,
      VALOR_ISENTO
     )
    VALUES(
      :COD_NF_ENTRADA_ITENS,
      :CD_FILIAL,
      :COD_NF_ENTRADA,
      :COD_PRODUTOS,
      :REF_PRODUTOS,
      :NUM_ITEM,
      :CL_FIS,
      :S_TRIB,
      :PRODUTO,
      :COD_GRUPOP,
      :COD_SUBGRUPOP,
      :DATAHORA,
      :QUANTIDADE,
      :PRC_CUSTO,
      :VALOR_DESCONTO,
      :VALOR_IPI,
      :SUBTOTAL,
      :BASE_ICMS,
      :BASE_ICMS_SUBST,
      :VALOR_ICMS,
      :ENABLE_NUMSERIE,
      :OBS,
      :ENABLED,
      :ULTATUAL,
      :ULTATUALCODSETOR,
      :ULTATUALCODSETORUSER,
      :APR_UND,
      :PERC_DESCONTO,
      :ALIQUOTA_IPI,
      :ALIQUOTA_ICMS,
      :REDUCAO_BASE_ICMS,
      :ENVIADO,
      :CFOP,
      :VALOR_ICMS_SUBTITUICAO,
      :MARGEM_VALOR_AGREGADO,
      :REDUCAO_ICMS_ST,
      :PERCENTUAL_ICMS_ST,
      :PIS_CST,
      :PIS_BASE_CALCULO,
      :PIS_PERCENTUAL,
      :PIS_VALOR,
      :COFINS_CST,
      :COFINS_BASE_CALCULO,
      :COFINS_PERCENTUAL,
      :COFINS_VALOR,
      :VALOR_OUTRASDESPESAS,
      :VALOR_FRETE,
      :VALOR_SEGURO,
      :VALOR_ISENTO
    );
  END
END ^

ALTER PROCEDURE SP_ATUALIZA_SPEDPISCOFINS AS 
declare variable ID_PRODUTO double precision;
declare variable BARRA varchar(14);
declare variable BARRA2 varchar(14);
declare variable DESCRICAO varchar(60);
declare variable NCM varchar(8);
declare variable EXISTE integer;
declare variable LISTA varchar(10);
declare variable PIS_ENTRADA_LR varchar(3);
declare variable PIS_SAIDA_LR varchar(3);
declare variable COFINS_ENTRADA_LR varchar(3);
declare variable COFINS_SAIDA_LR varchar(3);
declare variable PIS_ENTRADA_LP varchar(3);
declare variable PIS_SAIDA_LP varchar(3);
declare variable COFINS_ENTRADA_LP varchar(3);
declare variable COFINS_SAIDA_LP varchar(3);
declare variable PIS_ENTRADA_SN varchar(3);
declare variable PIS_SAIDA_SN varchar(3);
declare variable COFINS_ENTRADA_SN varchar(3);
declare variable COFINS_SAIDA_SN varchar(3);
declare variable CFOP varchar(4);
BEGIN
  UPDATE PRODUTOS SET CODIGO_BARRAS_2 = '0'||CD_PRODUTO WHERE (SELECT LEN FROM TAMANHO(CODIGO_BARRAS_2)) < 7;
  UPDATE PRODUTOS SET CODIGO_BARRAS_1 = CODIGO_BARRAS_2, CODIGO_BARRAS_2 = '0'||CD_PRODUTO WHERE CODIGO_BARRAS_1 IS NULL OR TRIM(CODIGO_BARRAS_1) = '';
  UPDATE PRODUTOS SET CODIGO_BARRAS_2 = '0'||CD_PRODUTO WHERE CODIGO_BARRAS_2 IS NULL OR TRIM(CODIGO_BARRAS_2) = '';

  DELETE FROM SPED_PIS_COFINS WHERE BARRA IN (SELECT BARRA FROM SPED_PIS_COFINS GROUP BY BARRA HAVING COUNT(BARRA) > 1);

  FOR
   SELECT
    BARRA
   FROM
    SPED_PIS_COFINS
   INTO
    :BARRA
  DO
   BEGIN
     IF (CAST(:BARRA AS DOUBLE PRECISION) < 1000000) THEN
      BEGIN
        SELECT COUNT(*) FROM PRODUTOS WHERE CODIGO_BARRAS_1 = :BARRA INTO :EXISTE;
        IF (:EXISTE = 0) THEN
           DELETE FROM SPED_PIS_COFINS WHERE BARRA = :BARRA;
      END
   END

  UPDATE PRODUTOS SET NCM = '30049099' WHERE NCM <> LPAD(NCM,8) OR NCM IS NULL OR TRIM(NCM) = '';


  FOR
    SELECT
      ID_PRODUTO,
      CODIGO_BARRAS_1,
      CODIGO_BARRAS_2,
      DESCRICAO,
      LPAD(NCM, 8),
      LPAD(CD_CFOP, 4)
    FROM
     PRODUTOS
    INTO
     :ID_PRODUTO,
     :BARRA,
     :BARRA2,
     :DESCRICAO,
     :NCM,
     :CFOP
  DO
   BEGIN
     LISTA = '';
     PIS_ENTRADA_LR = '';
     PIS_SAIDA_LR = '';
     COFINS_ENTRADA_LR = '';
     COFINS_SAIDA_LR = '';
     PIS_ENTRADA_LP = '';
     PIS_SAIDA_LP = '';
     COFINS_ENTRADA_LP = '';
     COFINS_SAIDA_LP = '';
     PIS_ENTRADA_SN = '';
     PIS_SAIDA_SN = '';
     COFINS_ENTRADA_SN = '';
     COFINS_SAIDA_SN = '';

     IF ((:NCM IS NOT NULL) AND (:NCM <> '')) THEN
      BEGIN
         SELECT COUNT(*) FROM SPED_PIS_COFINS WHERE BARRA = :BARRA AND NCM = :NCM INTO :EXISTE;
         IF (:EXISTE = 0) THEN
          BEGIN
             SELECT COUNT(*) FROM SPED_PIS_COFINS WHERE NCM = :NCM INTO :EXISTE;
             IF (:EXISTE > 0) THEN
              BEGIN
                SELECT
                 FIRST 1
                 SPED_PIS_COFINS.LISTA,
                 SPED_PIS_COFINS.PIS_ENTRADA_LR,
                 SPED_PIS_COFINS.PIS_SAIDA_LR,
                 SPED_PIS_COFINS.COFINS_ENTRADA_LR,
                 SPED_PIS_COFINS.COFINS_SAIDA_LR,
                 SPED_PIS_COFINS.PIS_ENTRADA_LP,
                 SPED_PIS_COFINS.PIS_SAIDA_LP,
                 SPED_PIS_COFINS.COFINS_ENTRADA_LP,
                 SPED_PIS_COFINS.COFINS_SAIDA_LP,
                 SPED_PIS_COFINS.PIS_ENTRADA_SN,
                 SPED_PIS_COFINS.PIS_SAIDA_SN,
                 SPED_PIS_COFINS.COFINS_ENTRADA_SN,
                 SPED_PIS_COFINS.COFINS_SAIDA_SN
                FROM
                 SPED_PIS_COFINS
                WHERE
                 NCM = :NCM
                INTO
                 :LISTA,
                 :PIS_ENTRADA_LR,
                 :PIS_SAIDA_LR,
                 :COFINS_ENTRADA_LR,
                 :COFINS_SAIDA_LR,
                 :PIS_ENTRADA_LP,
                 :PIS_SAIDA_LP,
                 :COFINS_ENTRADA_LP,
                 :COFINS_SAIDA_LP,
                 :PIS_ENTRADA_SN,
                 :PIS_SAIDA_SN,
                 :COFINS_ENTRADA_SN,
                 :COFINS_SAIDA_SN;

                INSERT INTO SPED_PIS_COFINS VALUES (:BARRA, :DESCRICAO, :NCM,  :LISTA, :CFOP,
                                                    :PIS_ENTRADA_LR, :PIS_SAIDA_LR, :COFINS_ENTRADA_LR, :COFINS_SAIDA_LR,
                                                    :PIS_ENTRADA_LP, :PIS_SAIDA_LP, :COFINS_ENTRADA_LP, :COFINS_SAIDA_LP,
                                                    :PIS_ENTRADA_SN, :PIS_SAIDA_SN, :COFINS_ENTRADA_SN, :COFINS_SAIDA_SN,
                                                    CAST(:BARRA AS NUMERIC(15,0)), :BARRA2,  CAST(:BARRA2 AS NUMERIC(15,0)));

              END
             ELSE
              BEGIN
                INSERT INTO SPED_PIS_COFINS VALUES (:BARRA, :DESCRICAO, :NCM, :LISTA, :CFOP,
                                                    :PIS_ENTRADA_LR, :PIS_SAIDA_LR, :COFINS_ENTRADA_LR, :COFINS_SAIDA_LR,
                                                    :PIS_ENTRADA_LP, :PIS_SAIDA_LP, :COFINS_ENTRADA_LP, :COFINS_SAIDA_LP,
                                                    :PIS_ENTRADA_SN, :PIS_SAIDA_SN, :COFINS_ENTRADA_SN, :COFINS_SAIDA_SN,
                                                    CAST(:BARRA AS NUMERIC(15,0)), :BARRA2,  CAST(:BARRA2 AS NUMERIC(15,0)));

              END
          END
         ELSE
          BEGIN
            UPDATE SPED_PIS_COFINS SET
             BARRA2 = :BARRA2, BARRA_NUM2 = CAST(:BARRA2 AS NUMERIC(15,0))
            WHERE BARRA = :BARRA;
          END
      END
     ELSE
      BEGIN
        SELECT COUNT(*) FROM SPED_PIS_COFINS WHERE BARRA = :BARRA INTO :EXISTE;
        IF (:EXISTE > 0) THEN
         BEGIN
            SELECT
             FIRST 1
             SPED_PIS_COFINS.NCM,
             SPED_PIS_COFINS.LISTA,
             SPED_PIS_COFINS.CFOP,
             SPED_PIS_COFINS.PIS_ENTRADA_LR,
             SPED_PIS_COFINS.PIS_SAIDA_LR,
             SPED_PIS_COFINS.COFINS_ENTRADA_LR,
             SPED_PIS_COFINS.COFINS_SAIDA_LR,
             SPED_PIS_COFINS.PIS_ENTRADA_LP,
             SPED_PIS_COFINS.PIS_SAIDA_LP,
             SPED_PIS_COFINS.COFINS_ENTRADA_LP,
             SPED_PIS_COFINS.COFINS_SAIDA_LP,
             SPED_PIS_COFINS.PIS_ENTRADA_SN,
             SPED_PIS_COFINS.PIS_SAIDA_SN,
             SPED_PIS_COFINS.COFINS_ENTRADA_SN,
             SPED_PIS_COFINS.COFINS_SAIDA_SN
            FROM
             SPED_PIS_COFINS
            WHERE
             BARRA = :BARRA
            INTO
             :NCM,
             :LISTA,
             :CFOP,
             :PIS_ENTRADA_LR,
             :PIS_SAIDA_LR,
             :COFINS_ENTRADA_LR,
             :COFINS_SAIDA_LR,
             :PIS_ENTRADA_LP,
             :PIS_SAIDA_LP,
             :COFINS_ENTRADA_LP,
             :COFINS_SAIDA_LP,
             :PIS_ENTRADA_SN,
             :PIS_SAIDA_SN,
             :COFINS_ENTRADA_SN,
             :COFINS_SAIDA_SN;
         
            UPDATE PRODUTOS SET NCM = LPAD(:NCM,8) WHERE ID_PRODUTO = :ID_PRODUTO;
            INSERT INTO SPED_PIS_COFINS VALUES (:BARRA, :DESCRICAO, :NCM, :LISTA, :CFOP,
                                                :PIS_ENTRADA_LR, :PIS_SAIDA_LR, :COFINS_ENTRADA_LR, :COFINS_SAIDA_LR,
                                                :PIS_ENTRADA_LP, :PIS_SAIDA_LP, :COFINS_ENTRADA_LP, :COFINS_SAIDA_LP,
                                                :PIS_ENTRADA_SN, :PIS_SAIDA_SN, :COFINS_ENTRADA_SN, :COFINS_SAIDA_SN,
                                                CAST(:BARRA AS NUMERIC(15,0)), :BARRA2, CAST(:BARRA2 AS NUMERIC(15,0)));

         END
      END
   END


  FOR
   SELECT
    DISTINCT NCM
   FROM
    SPED_PIS_COFINS
   INTO
    :NCM
  DO
   BEGIN
     SELECT
       FIRST 1
       SPED_PIS_COFINS.LISTA,
       SPED_PIS_COFINS.CFOP,
       SPED_PIS_COFINS.PIS_ENTRADA_LR,
       SPED_PIS_COFINS.PIS_SAIDA_LR,
       SPED_PIS_COFINS.COFINS_ENTRADA_LR,
       SPED_PIS_COFINS.COFINS_SAIDA_LR,
       SPED_PIS_COFINS.PIS_ENTRADA_LP,
       SPED_PIS_COFINS.PIS_SAIDA_LP,
       SPED_PIS_COFINS.COFINS_ENTRADA_LP,
       SPED_PIS_COFINS.COFINS_SAIDA_LP,
       SPED_PIS_COFINS.PIS_ENTRADA_SN,
       SPED_PIS_COFINS.PIS_SAIDA_SN,
       SPED_PIS_COFINS.COFINS_ENTRADA_SN,
       SPED_PIS_COFINS.COFINS_SAIDA_SN
      FROM
       SPED_PIS_COFINS
      WHERE
       NCM = :NCM
      INTO
       :LISTA,
       :CFOP,
       :PIS_ENTRADA_LR,
       :PIS_SAIDA_LR,
       :COFINS_ENTRADA_LR,
       :COFINS_SAIDA_LR,
       :PIS_ENTRADA_LP,
       :PIS_SAIDA_LP,
       :COFINS_ENTRADA_LP,
       :COFINS_SAIDA_LP,
       :PIS_ENTRADA_SN,
       :PIS_SAIDA_SN,
       :COFINS_ENTRADA_SN,
       :COFINS_SAIDA_SN;

       IF ((:PIS_ENTRADA_LR IS NULL) OR (:PIS_ENTRADA_LR = '')) THEN
          PIS_ENTRADA_LR = '50';
       IF ((:PIS_ENTRADA_LP IS NULL) OR (:PIS_ENTRADA_LP = '')) THEN
          PIS_ENTRADA_LP = '50';
       IF ((:PIS_ENTRADA_SN IS NULL) OR (:PIS_ENTRADA_SN = '')) THEN
          PIS_ENTRADA_SN = '50';

       IF ((:PIS_SAIDA_LR IS NULL) OR (:PIS_SAIDA_LR = '')) THEN
          PIS_SAIDA_LR = '01';
       IF ((:PIS_SAIDA_LP IS NULL) OR (:PIS_SAIDA_LP = '')) THEN
          PIS_SAIDA_LP = '01';
       IF ((:PIS_SAIDA_SN IS NULL) OR (:PIS_SAIDA_SN = '')) THEN
          PIS_SAIDA_SN = '01';

       IF ((:COFINS_ENTRADA_LR IS NULL) OR (:COFINS_ENTRADA_LR = '')) THEN
          COFINS_ENTRADA_LR = '50';
       IF ((:COFINS_ENTRADA_LP IS NULL) OR (:COFINS_ENTRADA_LP = '')) THEN
          COFINS_ENTRADA_LP = '50';
       IF ((:COFINS_ENTRADA_SN IS NULL) OR (:COFINS_ENTRADA_SN = '')) THEN
          COFINS_ENTRADA_SN = '50';

       IF ((:COFINS_SAIDA_LR IS NULL) OR (:COFINS_SAIDA_LR = '')) THEN
          COFINS_SAIDA_LR = '01';
       IF ((:COFINS_SAIDA_LP IS NULL) OR (:COFINS_SAIDA_LP = '')) THEN
          COFINS_SAIDA_LP = '01';
       IF ((:COFINS_SAIDA_SN IS NULL) OR (:COFINS_SAIDA_SN = '')) THEN
          COFINS_SAIDA_SN = '01';

      UPDATE SPED_PIS_COFINS SET
        LISTA = :LISTA,
        CFOP = :CFOP,
        PIS_ENTRADA_LR = :PIS_ENTRADA_LR,
        PIS_SAIDA_LR = :PIS_SAIDA_LR,
        COFINS_ENTRADA_LR = :COFINS_ENTRADA_LR,
        COFINS_SAIDA_LR = :COFINS_SAIDA_LR,
        PIS_ENTRADA_LP = :PIS_ENTRADA_LP,
        PIS_SAIDA_LP = :PIS_SAIDA_LP,
        COFINS_ENTRADA_LP = :COFINS_ENTRADA_LP,
        COFINS_SAIDA_LP = :COFINS_SAIDA_LP,
        PIS_ENTRADA_SN = :PIS_ENTRADA_SN,
        PIS_SAIDA_SN = :PIS_SAIDA_SN,
        COFINS_ENTRADA_SN = :COFINS_ENTRADA_SN,
        COFINS_SAIDA_SN = :COFINS_SAIDA_SN
       WHERE NCM = :NCM;
   END

END ^

ALTER PROCEDURE SP_ATUALIZA_SUBGRUPOS (CD_SUBGRUPO DOUBLE PRECISION,
CD_GRUPO DOUBLE PRECISION,
DESCRICAO VARCHAR(100) CHARACTER SET NONE,
DT_ALTERACAO DATE,
ENVIADO VARCHAR(1) CHARACTER SET NONE)
AS 
declare variable EXISTE integer;
BEGIN
  SELECT COUNT(*) FROM SUBGRUPOS WHERE CD_SUBGRUPO = :CD_SUBGRUPO INTO :EXISTE;
  IF (:EXISTE > 0) THEN
   BEGIN
     UPDATE SUBGRUPOS SET
        CD_SUBGRUPO           = :CD_SUBGRUPO,
        CD_GRUPO              = :CD_GRUPO,
        DESCRICAO             = :DESCRICAO,
        DT_ALTERACAO          = :DT_ALTERACAO,
        ENVIADO               = :ENVIADO
     WHERE CD_SUBGRUPO = :CD_SUBGRUPO;
   END
  ELSE
   BEGIN
     INSERT INTO SUBGRUPOS(
        CD_SUBGRUPO,
        CD_GRUPO,
        DESCRICAO,
        DT_ALTERACAO,
        ENVIADO
       )
     VALUES(
        :CD_SUBGRUPO,
        :CD_GRUPO,
        :DESCRICAO,
        :DT_ALTERACAO,
        :ENVIADO
       );
   END
END ^

ALTER PROCEDURE SP_ATUALIZA_TERMINAL_LANCAMENTO AS 
DECLARE VARIABLE VENDA DOUBLE PRECISION;
BEGIN
  FOR
    SELECT
     CD_VENDA
    FROM
     LANCAMENTOS
    WHERE
     TERMINAL IS NULL
    GROUP BY
     CD_VENDA
    INTO
     :VENDA
  DO
   BEGIN
     UPDATE LANCAMENTOS SET
      TERMINAL = (SELECT TERMINAL FROM CAIXA WHERE CD_VENDA = :VENDA GROUP BY TERMINAL)
     WHERE TERMINAL IS NULL;
   END
END ^

ALTER PROCEDURE SP_ATUALIZA_TRANSFER (CD_TRANSFER DOUBLE PRECISION,
DATA_GERACAO VARCHAR(15) CHARACTER SET NONE,
HORA_GERACAO VARCHAR(15) CHARACTER SET NONE,
DATA_ENVIO VARCHAR(15) CHARACTER SET NONE,
HORA_ENVIO VARCHAR(15) CHARACTER SET NONE,
DATA_CONCLUSAO VARCHAR(15) CHARACTER SET NONE,
HORA_CONCLUSAO VARCHAR(15) CHARACTER SET NONE,
CD_FILIAL_ORIGEM DOUBLE PRECISION,
CD_FILIAL_DESTINO DOUBLE PRECISION,
CD_USUARIO_ORIGEM DOUBLE PRECISION,
CD_USUARIO_DESTINO DOUBLE PRECISION,
OBSERVACOES VARCHAR(255) CHARACTER SET NONE,
ENVIADO VARCHAR(1) CHARACTER SET NONE,
STATUS VARCHAR(1) CHARACTER SET NONE)
AS 
DECLARE VARIABLE EXISTE INTEGER;
DECLARE VARIABLE STATUSTRANSFER VARCHAR(1);
DECLARE VARIABLE COMANDO VARCHAR(1000);
BEGIN
  COMANDO = '';
  SELECT COUNT(*) FROM TRANSFER WHERE CD_TRANSFER = :CD_TRANSFER INTO :EXISTE;
  IF (:EXISTE > 0) THEN
   BEGIN
     SELECT STATUS FROM TRANSFER WHERE CD_TRANSFER = :CD_TRANSFER INTO :STATUSTRANSFER;
     IF (((:STATUSTRANSFER = 'G') AND (:STATUS <> 'G')) OR
         ((:STATUSTRANSFER = 'E') AND ((:STATUS = 'C') OR (STATUS = 'X')))) THEN
      BEGIN
        COMANDO = 'UPDATE TRANSFER SET '||
                  'CD_TRANSFER         = '||CAST(:CD_TRANSFER AS INTEGER)||
                  ',CD_FILIAL_ORIGEM    = '||CAST(:CD_FILIAL_ORIGEM AS INTEGER)||
                  ',CD_FILIAL_DESTINO   = '||CAST(:CD_FILIAL_DESTINO AS INTEGER)||
                  ',CD_USUARIO_ORIGEM   = '||CAST(:CD_USUARIO_ORIGEM AS INTEGER)||
                  ',CD_USUARIO_DESTINO  = '||CAST(:CD_USUARIO_DESTINO AS INTEGER)||
                  ',OBSERVACOES         = '''||:OBSERVACOES||''''||
                  ',ENVIADO             = '''||:ENVIADO||''''||
                  ',STATUS              = '''||:STATUS||'''';
        IF (:DATA_GERACAO <> '') THEN
          COMANDO = :COMANDO||',DATA_GERACAO        = '''||:DATA_GERACAO||'''';
        ELSE
          COMANDO = :COMANDO||',DATA_GERACAO        = NULL';
        IF (:HORA_GERACAO <> '') THEN
          COMANDO = :COMANDO||',HORA_GERACAO        = '''||:HORA_GERACAO||'''';
        ELSE
          COMANDO = :COMANDO||',HORA_GERACAO        = NULL';
        IF (:DATA_CONCLUSAO <> '') THEN
          COMANDO = :COMANDO||',DATA_CONCLUSAO        = '''||:DATA_CONCLUSAO||'''';
        ELSE
          COMANDO = :COMANDO||',DATA_CONCLUSAO        = NULL';
        IF (:HORA_CONCLUSAO <> '') THEN
          COMANDO = :COMANDO||',HORA_CONCLUSAO        = '''||:HORA_CONCLUSAO||'''';
        ELSE
          COMANDO = :COMANDO||',HORA_CONCLUSAO        = NULL';
        IF (:DATA_ENVIO <> '') THEN
          COMANDO = :COMANDO||',DATA_ENVIO        = '''||:DATA_ENVIO||'''';
        ELSE
          COMANDO = :COMANDO||',DATA_ENVIO        = NULL';
        IF (:HORA_ENVIO <> '') THEN
          COMANDO = :COMANDO||',HORA_ENVIO        = '''||:HORA_ENVIO||'''';
        ELSE
          COMANDO = :COMANDO||',HORA_ENVIO        = NULL ';
          
        COMANDO = :COMANDO||'WHERE CD_TRANSFER = '||CAST(:CD_TRANSFER AS INTEGER);
        
        EXECUTE STATEMENT :COMANDO;
      END
   END
  ELSE
   BEGIN
      COMANDO = :COMANDO||'INSERT INTO TRANSFER(CD_TRANSFER,CD_FILIAL_ORIGEM,CD_FILIAL_DESTINO,CD_USUARIO_ORIGEM,CD_USUARIO_DESTINO,OBSERVACOES,'||
                         'ENVIADO,STATUS,DATA_GERACAO,HORA_GERACAO,DATA_CONCLUSAO,HORA_CONCLUSAO,DATA_ENVIO,HORA_ENVIO) VALUES('||CAST(:CD_TRANSFER AS INTEGER)||','||CAST(:CD_FILIAL_ORIGEM AS INTEGER)||
                         ','||CAST(:CD_FILIAL_DESTINO AS INTEGER)||','||CAST(:CD_USUARIO_ORIGEM AS INTEGER)||','||CAST(:CD_USUARIO_DESTINO AS INTEGER)||
                         ','''||:OBSERVACOES||''','''||:ENVIADO||''','''||:STATUS||'''';
      IF (:DATA_GERACAO <> '') THEN
        COMANDO = :COMANDO||','''||:DATA_GERACAO||'''';
      ELSE
        COMANDO = :COMANDO||',NULL';
      IF (:HORA_GERACAO <> '') THEN
        COMANDO = :COMANDO||','''||:HORA_GERACAO||'''';
      ELSE
        COMANDO = :COMANDO||',NULL';
      IF (:DATA_CONCLUSAO <> '') THEN
        COMANDO = :COMANDO||','''||:DATA_CONCLUSAO||'''';
      ELSE
        COMANDO = :COMANDO||',NULL';
      IF (:HORA_CONCLUSAO <> '') THEN
        COMANDO = :COMANDO||','''||:HORA_CONCLUSAO||'''';
      ELSE
        COMANDO = :COMANDO||',NULL';
      IF (:DATA_ENVIO <> '') THEN
        COMANDO = :COMANDO||','''||:DATA_ENVIO||'''';
      ELSE
        COMANDO = :COMANDO||',NULL';
      IF (:HORA_ENVIO <> '') THEN
        COMANDO = :COMANDO||','''||:HORA_ENVIO||'''';
      ELSE
        COMANDO = :COMANDO||',NULL';

      COMANDO = :COMANDO||');';
     
     EXECUTE STATEMENT :COMANDO;
   END
END ^

ALTER PROCEDURE SP_ATUALIZA_TRANSPORTADORAS (CD_TRANSPORTADORA DOUBLE PRECISION,
NOME VARCHAR(100) CHARACTER SET NONE,
RAZAO VARCHAR(100) CHARACTER SET NONE,
CNPJ VARCHAR(18) CHARACTER SET NONE,
INSCRICAO VARCHAR(14) CHARACTER SET NONE,
ENDERECO VARCHAR(100) CHARACTER SET NONE,
NUMERO VARCHAR(10) CHARACTER SET NONE,
COMPLEMENTO VARCHAR(100) CHARACTER SET NONE,
BAIRRO VARCHAR(100) CHARACTER SET NONE,
CIDADE VARCHAR(100) CHARACTER SET NONE,
UF VARCHAR(2) CHARACTER SET NONE,
CEP VARCHAR(8) CHARACTER SET NONE,
CD_MUNICIPIO VARCHAR(7) CHARACTER SET NONE,
FONE VARCHAR(40) CHARACTER SET NONE,
FAX VARCHAR(10) CHARACTER SET NONE,
CAIXA_POSTAL VARCHAR(10) CHARACTER SET NONE,
CONTATO VARCHAR(100) CHARACTER SET NONE,
EMAIL VARCHAR(100) CHARACTER SET NONE,
URL VARCHAR(100) CHARACTER SET NONE,
CD_PAIS VARCHAR(4) CHARACTER SET NONE,
PAIS VARCHAR(100) CHARACTER SET NONE,
DT_ALTERACAO DATE,
ENVIADO VARCHAR(1) CHARACTER SET NONE)
AS 
DECLARE VARIABLE EXISTE INTEGER;
BEGIN
  SELECT COUNT(*) FROM TRANSPORTADORAS WHERE CD_TRANSPORTADORA = :CD_TRANSPORTADORA INTO :EXISTE;
  IF (:EXISTE > 0) THEN
   BEGIN
     UPDATE TRANSPORTADORAS SET
        CD_TRANSPORTADORA  = :CD_TRANSPORTADORA,
        NOME               = :NOME,
        RAZAO              = :RAZAO,
        CNPJ               = :CNPJ,
        INSCRICAO          = :INSCRICAO,
        ENDERECO           = :ENDERECO,
        NUMERO             = :NUMERO,
        COMPLEMENTO        = :COMPLEMENTO,
        BAIRRO             = :BAIRRO,
        CIDADE             = :CIDADE,
        UF                 = :UF,
        CEP                = :CEP,
        CD_MUNICIPIO       = :CD_MUNICIPIO,
        FONE               = :FONE,
        FAX                = :FAX,
        CAIXA_POSTAL       = :CAIXA_POSTAL,
        CONTATO            = :CONTATO,
        EMAIL              = :EMAIL,
        URL                = :URL,
        CD_PAIS            = :CD_PAIS,
        PAIS               = :PAIS,
        DT_ALTERACAO       = :DT_ALTERACAO,
        ENVIADO            = :ENVIADO
     WHERE CD_TRANSPORTADORA = :CD_TRANSPORTADORA;
   END
  ELSE
   BEGIN
     INSERT INTO TRANSPORTADORAS(
        CD_TRANSPORTADORA,
        NOME,
        RAZAO,
        CNPJ,
        INSCRICAO,
        ENDERECO,
        NUMERO,
        COMPLEMENTO,
        BAIRRO,
        CIDADE,
        UF,
        CEP,
        CD_MUNICIPIO,
        FONE,
        FAX,
        CAIXA_POSTAL,
        CONTATO,
        EMAIL,
        URL,
        CD_PAIS,
        PAIS,
        DT_ALTERACAO,
        ENVIADO
       )
     VALUES(
        :CD_TRANSPORTADORA,
        :NOME,
        :RAZAO,
        :CNPJ,
        :INSCRICAO,
        :ENDERECO,
        :NUMERO,
        :COMPLEMENTO,
        :BAIRRO,
        :CIDADE,
        :UF,
        :CEP,
        :CD_MUNICIPIO,
        :FONE,
        :FAX,
        :CAIXA_POSTAL,
        :CONTATO,
        :EMAIL,
        :URL,
        :CD_PAIS,
        :PAIS,
        :DT_ALTERACAO,
        :ENVIADO
       );
   END
END ^

