ALTER PROCEDURE SP_ATUALIZA_VENDEDORES_CLASSES AS 
DECLARE VARIABLE CD_VENDEDOR DOUBLE PRECISION;
DECLARE VARIABLE CD_CLASSE DOUBLE PRECISION;
DECLARE VARIABLE CLASSE VARCHAR(100);
BEGIN
  DELETE FROM VENDEDORES_CLASSES;
  FOR
    SELECT
     CD_VENDEDOR
    FROM
     VENDEDORES
    INTO
     :CD_VENDEDOR
  DO
   BEGIN
      FOR
        SELECT
         CD_CLASSE,
         DESCRICAO
        FROM
         CLASSES
        INTO
         :CD_CLASSE,
         :CLASSE
      DO
       BEGIN
         INSERT INTO VENDEDORES_CLASSES VALUES (:CD_VENDEDOR, :CD_CLASSE, :CLASSE, 'S', '');
       END
   END
END ^

ALTER PROCEDURE SP_AVALIA_VENDA_PRODUTO (CODPRODUTO VARCHAR(6) CHARACTER SET NONE,
DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (ID_PRODUTO DOUBLE PRECISION,
PRODUTO VARCHAR(60) CHARACTER SET NONE,
GRUPO VARCHAR(40) CHARACTER SET NONE,
QUANTIDADE DOUBLE PRECISION,
VALOR DOUBLE PRECISION)
AS 
BEGIN
  DELETE FROM TEMP_VENDAPRODUTO;
  INSERT INTO TEMP_VENDAPRODUTO
      SELECT DISTINCT CD_VENDA FROM LANCAMENTOS
      WHERE ID_PRODUTO = :CODPRODUTO AND DATA_LANCAMENTO >= :DATAINICIAL AND DATA_LANCAMENTO <= :DATAFINAL AND TIPO_VENDA = 'V';

   FOR
    SELECT
     LANCAMENTOS.ID_PRODUTO,
     LANCAMENTOS.DESCRICAO,
     GRUPOS.DESCRICAO,
     SUM(LANCAMENTOS.QUANTIDADE),
     SUM(LANCAMENTOS.VALOR)
    FROM
     LANCAMENTOS,
     GRUPOS
    WHERE
     LANCAMENTOS.CD_GRUPO = GRUPOS.CD_GRUPO AND
     LANCAMENTOS.CD_VENDA IN (SELECT CD_VENDA FROM TEMP_VENDAPRODUTO) AND
     LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
     LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
     LANCAMENTOS.TIPO_VENDA = 'V' AND
     LANCAMENTOS.ID_PRODUTO <> :CODPRODUTO
    GROUP BY
     LANCAMENTOS.ID_PRODUTO,
     LANCAMENTOS.DESCRICAO,
     GRUPOS.DESCRICAO
    INTO
     :ID_PRODUTO,
     :PRODUTO,
     :GRUPO,
     :QUANTIDADE,
     :VALOR
   DO
    BEGIN
     SUSPEND;
    END
END ^

ALTER PROCEDURE SP_BAIXAAUTOMATICACHEQUEPRE AS 
BEGIN
  UPDATE CONTAS_RECEBER SET
   CONTAS_RECEBER.DT_PAGAMENTO = CURRENT_DATE, 
   CONTAS_RECEBER.VL_PAGAMENTO = CONTAS_RECEBER.VALOR,
   CONTAS_RECEBER.VL_SALDO = 0,
   CONTAS_RECEBER.STATUS = 'P'
  WHERE
   CONTAS_RECEBER.CD_FORMA_PAGAMENTO = 4 AND
   CONTAS_RECEBER.DT_VENCIMENTO = CURRENT_DATE;
END ^

ALTER PROCEDURE SP_BAIXACR_NAOPAGAS (DIAS DOUBLE PRECISION,
BAIXARCONTAS VARCHAR(1) CHARACTER SET NONE)
RETURNS (CD_CONTAS_RECEBER DOUBLE PRECISION,
FILIAL DOUBLE PRECISION,
CLIENTE DOUBLE PRECISION,
VENDA DOUBLE PRECISION,
FORMA DOUBLE PRECISION,
LANCAMENTO DATE,
VENCIMENTO DATE,
VL DOUBLE PRECISION)
AS 
DECLARE VARIABLE CD_FILIAL DOUBLE PRECISION;
DECLARE VARIABLE CD_CLIENTE DOUBLE PRECISION;
DECLARE VARIABLE NUMERO DOUBLE PRECISION;
DECLARE VARIABLE DATA_LANCAMENTO DATE;
DECLARE VARIABLE VALOR DOUBLE PRECISION;
DECLARE VARIABLE DT DATE;
BEGIN
  DT = CURRENT_DATE - :DIAS;
  DELETE FROM TEMP_CRPAGAS_NAOBAIXADAS;
  DELETE FROM TEMP_CRNAOBAIXADAS;
  INSERT INTO TEMP_CRPAGAS_NAOBAIXADAS SELECT CD_FILIAL, CD_CLIENTE, NUMERO, DATA_LANCAMENTO, VALOR FROM LANCAMENTOS
                                       WHERE DATA_LANCAMENTO > :DT AND TIPO_VENDA = 'R';
  FOR
   SELECT CD_FILIAL, CD_CLIENTE, NUMERO, DATA_LANCAMENTO, VALOR
   FROM TEMP_CRPAGAS_NAOBAIXADAS
   INTO :CD_FILIAL, :CD_CLIENTE, :NUMERO, :DATA_LANCAMENTO, :VALOR
  DO
   BEGIN
     INSERT INTO TEMP_CRNAOBAIXADAS
     SELECT CD_CONTAS_RECEBER, CD_FILIAL, CD_CLIENTE, CD_VENDA, CD_FORMA_PAGAMENTO, DT_LANCAMENTO, DT_VENCIMENTO, VALOR
     FROM CONTAS_RECEBER
     WHERE CD_FILIAL = :CD_FILIAL AND CD_CLIENTE = :CD_CLIENTE AND
           CD_VENDA = :NUMERO AND NOSSO_NUMERO = :NUMERO AND STATUS IS NOT NULL AND STATUS <> 'P';

     IF (:BAIXARCONTAS = 'S') THEN
      BEGIN
         UPDATE CONTAS_RECEBER SET
           CONTAS_RECEBER.VL_PAGAMENTO = :VALOR,
           CONTAS_RECEBER.VL_SALDO = 0,
           CONTAS_RECEBER.DT_PAGAMENTO = :DATA_LANCAMENTO,
           CONTAS_RECEBER.STATUS = 'P'
         WHERE
           CD_FILIAL = :CD_FILIAL AND
           CD_CLIENTE = :CD_CLIENTE AND
           CD_VENDA = :NUMERO AND
           NOSSO_NUMERO = :NUMERO AND
           STATUS IS NOT NULL AND
           STATUS <> 'P';
      END
   END
  IF (:BAIXARCONTAS <> 'S') THEN
   BEGIN
    FOR
      SELECT CD_CONTAS_RECEBER, CD_FILIAL, CD_CLIENTE, CD_VENDA, CD_FORMA_PAGAMENTO, DT_LANCAMENTO, DT_VENCIMENTO, VALOR
      FROM TEMP_CRNAOBAIXADAS
      INTO :CD_CONTAS_RECEBER, :FILIAL, :CLIENTE, :VENDA, :FORMA, :LANCAMENTO, :VENCIMENTO, :VL
    DO
     BEGIN
      SUSPEND;
     END
   END
END ^

ALTER PROCEDURE SP_BAIXA_CONVENIO (CONVENIO DOUBLE PRECISION)
AS 
DECLARE VARIABLE FILIAL DOUBLE PRECISION;
DECLARE VARIABLE CLIENTE DOUBLE PRECISION;
BEGIN
  FOR
   SELECT
    CD_CLIENTE,
    CD_FILIAL
   FROM
    CLIENTES
   WHERE
    CD_CONVENIO = :CONVENIO
   INTO
    :CLIENTE,
    :FILIAL
  DO
   BEGIN
     UPDATE CONTAS_RECEBER SET
      VL_PAGAMENTO = VALOR,
      VL_SALDO = 0,
      VL_JUROS = 0,
      VL_DESCONTO = 0,
      STATUS = 'P'
     WHERE
      CD_CLIENTE = :CLIENTE AND
      CD_FILIAL = :FILIAL AND
      CD_CONVENIO = :CONVENIO;
   END
END ^

ALTER PROCEDURE SP_BISEXTO (DATA DATE)
RETURNS (RESULTADO INTEGER)
AS 
BEGIN
   IF (((MOD(EXTRACT(YEAR FROM :data), 4) = 0) AND
       (MOD(EXTRACT(YEAR FROM :data), 100) <> 0)) OR
       (MOD(EXTRACT(YEAR FROM :data), 400) = 0)) THEN
     resultado = 1;
   ELSE
     resultado = 0;
   SUSPEND;
END ^

ALTER PROCEDURE SP_BLOQUEADESBLOQUEACONVENIADOS (CONVENIO DOUBLE PRECISION,
BLOQUEA VARCHAR(1) CHARACTER SET NONE)
AS 
BEGIN
  UPDATE CLIENTES SET COMPRAOUTRALOJA = :BLOQUEA WHERE CD_CONVENIO = :CONVENIO;
END ^

ALTER PROCEDURE SP_BLOQUEIACLIENTEATRASO AS 
DECLARE VARIABLE CD_CLIENTE DOUBLE PRECISION;
DECLARE VARIABLE DIASATRASO INTEGER;
BEGIN
 SELECT DIASBLOQUEIOCLIENTE FROM PARAMETROS INTO :DIASATRASO;
 IF (:DIASATRASO IS NOT NULL) THEN
  BEGIN
     FOR
      SELECT
        DISTINCT CD_CLIENTE
      FROM
        CONTAS_RECEBER
      WHERE
        STATUS = 'A' AND
        DT_VENCIMENTO <= CAST(CURRENT_DATE - :DIASATRASO AS DATE) AND
        CD_PLANO_CONTAS <> 3 AND
        CD_PLANO_CONTAS <> 4
      INTO
       :CD_CLIENTE
     DO
      BEGIN
        UPDATE CLIENTES SET STATUS = 'B' WHERE CD_CLIENTE = :CD_CLIENTE AND STATUS <> 'I';
      END
  END
END ^

ALTER PROCEDURE SP_BUSCA_CEST (NCM VARCHAR(100) CHARACTER SET NONE)
RETURNS (CEST VARCHAR(1000) CHARACTER SET NONE)
AS 
declare variable EXISTE integer;
declare variable CESTAUXILIAR varchar(100);
BEGIN
  CEST = '';
  CESTAUXILIAR = '';
  SELECT COUNT(*) FROM CEST WHERE NCM = :NCM INTO :EXISTE;
  IF (:EXISTE = 0) THEN
   BEGIN
     NCM = SUBSTRING(:NCM FROM 1 FOR 7);
     SELECT COUNT(*) FROM CEST WHERE NCM = :NCM INTO :EXISTE;
     IF (:EXISTE = 0) THEN
      BEGIN
        NCM = SUBSTRING(:NCM FROM 1 FOR 6);
        SELECT COUNT(*) FROM CEST WHERE NCM = :NCM INTO :EXISTE;
        IF (:EXISTE = 0) THEN
         BEGIN
           NCM = SUBSTRING(:NCM FROM 1 FOR 5);
           SELECT COUNT(*) FROM CEST WHERE NCM = :NCM INTO :EXISTE;
           IF (:EXISTE = 0) THEN
            BEGIN
              NCM = SUBSTRING(:NCM FROM 1 FOR 4);
              SELECT COUNT(*) FROM CEST WHERE NCM = :NCM INTO :EXISTE;
              IF (:EXISTE = 0) THEN
               BEGIN
                 NCM = SUBSTRING(:NCM FROM 1 FOR 2);
                 SELECT COUNT(*) FROM CEST WHERE NCM = :NCM INTO :EXISTE;
               END
            END
         END
      END
   END
  IF (:EXISTE = 1) THEN
   BEGIN
     SELECT CEST FROM CEST WHERE NCM = :NCM INTO :CEST;
     SUSPEND;
   END
  ELSE
  IF (:EXISTE > 1) THEN
   BEGIN
     FOR
       SELECT CEST FROM CEST WHERE NCM = :NCM INTO :CESTAUXILIAR
     DO
      BEGIN
        IF (:CEST = '') THEN
         BEGIN
           CEST = :CESTAUXILIAR;
         END
        ELSE
         BEGIN
           CEST = :CEST ||','||:CESTAUXILIAR;
         END
      END
     SUSPEND;
   END
END ^

ALTER PROCEDURE SP_CAIXA (FILIAL DOUBLE PRECISION,
DATAINICIAL DATE,
DATAFINAL DATE,
TERMINAL DOUBLE PRECISION)
RETURNS (CD_FILIAL DOUBLE PRECISION,
DATACAIXA DATE,
OPERADOR DOUBLE PRECISION,
DINHEIRO DOUBLE PRECISION,
CARTAO DOUBLE PRECISION,
CONVENIO DOUBLE PRECISION,
CHEQUE_PRE DOUBLE PRECISION,
CREDIARIO DOUBLE PRECISION,
CHEQUE_A_VISTA DOUBLE PRECISION,
RETIRADAS DOUBLE PRECISION,
TOTAL DOUBLE PRECISION)
AS 
BEGIN
 FOR
  SELECT
   CAIXA.CD_FILIAL,
   CAIXA.DATA,
   CAIXA.CD_OPERADOR
  FROM
   CAIXA
  WHERE
   CAIXA.DATA >= :DATAINICIAL AND
   CAIXA.DATA <= :DATAFINAL AND
   CAIXA.CD_FILIAL = :FILIAL AND
   CAIXA.CD_OPERADOR <> 0
  GROUP BY
   CAIXA.CD_FILIAL,
   CAIXA.DATA,
   CAIXA.CD_OPERADOR
  INTO
   :CD_FILIAL,
   :DATACAIXA,
   :OPERADOR
 DO
  BEGIN
    SELECT
     SUM(CAIXA.VALOR)
    FROM
     CAIXA
    WHERE
     CAIXA.DATA = :DATACAIXA AND
     CAIXA.CD_FILIAL = :FILIAL AND
     CAIXA.TERMINAL = :TERMINAL AND
     CAIXA.CD_OPERADOR = :OPERADOR AND
     CAIXA.CD_FORMA_PAGAMENTO = 1 AND
     CAIXA.STATUS = 'F'
    INTO
     :DINHEIRO;
    
    SELECT
     SUM(CAIXA.VALOR)
    FROM
     CAIXA
    WHERE
     CAIXA.DATA = :DATACAIXA AND
     CAIXA.CD_FILIAL = :FILIAL AND
     CAIXA.TERMINAL = :TERMINAL AND
     CAIXA.CD_OPERADOR = :OPERADOR AND
     CAIXA.CD_FORMA_PAGAMENTO = 2 AND
     CAIXA.STATUS = 'F'
    INTO
     :CARTAO;

    SELECT
     SUM(CAIXA.VALOR)
    FROM
     CAIXA
    WHERE
     CAIXA.DATA = :DATACAIXA AND
     CAIXA.CD_FILIAL = :FILIAL AND
     CAIXA.TERMINAL = :TERMINAL AND
     CAIXA.CD_OPERADOR = :OPERADOR AND
     CAIXA.CD_FORMA_PAGAMENTO = 3 AND
     CAIXA.STATUS = 'F'
    INTO
     :CONVENIO;

    SELECT
     SUM(CAIXA.VALOR)
    FROM
     CAIXA
    WHERE
     CAIXA.DATA = :DATACAIXA AND
     CAIXA.CD_FILIAL = :FILIAL AND
     CAIXA.TERMINAL = :TERMINAL AND
     CAIXA.CD_OPERADOR = :OPERADOR AND
     CAIXA.CD_FORMA_PAGAMENTO = 4 AND
     CAIXA.STATUS = 'F'
    INTO
     :CHEQUE_PRE;

    SELECT
     SUM(CAIXA.VALOR)
    FROM
     CAIXA
    WHERE
     CAIXA.DATA = :DATACAIXA AND
     CAIXA.CD_FILIAL = :FILIAL AND
     CAIXA.TERMINAL = :TERMINAL AND
     CAIXA.CD_OPERADOR = :OPERADOR AND
     CAIXA.CD_FORMA_PAGAMENTO = 5 AND
     CAIXA.STATUS = 'F'
    INTO
     :CREDIARIO;

    SELECT
     SUM(CAIXA.VALOR)
    FROM
     CAIXA
    WHERE
     CAIXA.DATA = :DATACAIXA AND
     CAIXA.CD_FILIAL = :FILIAL AND
     CAIXA.TERMINAL = :TERMINAL AND
     CAIXA.CD_OPERADOR = :OPERADOR AND
     CAIXA.CD_FORMA_PAGAMENTO = 6 AND
     CAIXA.STATUS = 'F'
    INTO
     :CHEQUE_A_VISTA;

    SELECT
     SUM(CAIXA.VALOR)
    FROM
     CAIXA
    WHERE
     CAIXA.DATA = :DATACAIXA AND
     CAIXA.CD_FILIAL = :FILIAL AND
     CAIXA.TERMINAL = :TERMINAL AND
     CAIXA.CD_OPERADOR = :OPERADOR AND
     CAIXA.CD_FORMA_PAGAMENTO IS NULL AND
     CAIXA.STATUS = 'F'
    INTO
     :RETIRADAS;

    IF ((:DINHEIRO IS NOT NULL) OR
        (:CARTAO IS NOT NULL) OR
        (:CONVENIO IS NOT NULL) OR
        (:CHEQUE_PRE IS NOT NULL) OR
        (:CREDIARIO IS NOT NULL) OR
        (:CHEQUE_A_VISTA IS NOT NULL) OR
        (:RETIRADAS IS NOT NULL)) THEN
      BEGIN
            IF (:DINHEIRO IS NULL) THEN DINHEIRO = 0;
            IF (:CARTAO IS NULL) THEN CARTAO = 0;
            IF (:CONVENIO IS NULL) THEN CONVENIO = 0;
            IF (:CHEQUE_PRE IS NULL) THEN CHEQUE_PRE = 0;
            IF (:CREDIARIO IS NULL) THEN CREDIARIO = 0;
            IF (:CHEQUE_A_VISTA IS NULL) THEN CHEQUE_A_VISTA = 0;
            IF (:RETIRADAS IS NULL) THEN RETIRADAS = 0;
        
            TOTAL = :DINHEIRO + :CARTAO + :CONVENIO + :CHEQUE_PRE + :CREDIARIO + :CHEQUE_A_VISTA - :RETIRADAS;
        
            SUSPEND;
      END
  END
END ^

ALTER PROCEDURE SP_CAIXAPLANOCONTASENTREGA_DATA (CD_FILIAL DOUBLE PRECISION,
DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (OPERADOR DOUBLE PRECISION,
TERMINAL DOUBLE PRECISION,
CD_PLANO DOUBLE PRECISION,
PLANO VARCHAR(100) CHARACTER SET NONE,
FORMA INTEGER,
TIPO VARCHAR(1) CHARACTER SET NONE,
NVENDAS DOUBLE PRECISION,
VALOR DOUBLE PRECISION,
VMEDIO DOUBLE PRECISION)
AS 
DECLARE VARIABLE CANCELAMENTOS DOUBLE PRECISION;
DECLARE VARIABLE GRAU DOUBLE PRECISION;
BEGIN
 FOR
   SELECT
     CAIXA.CD_OPERADOR,
     CAIXA.TERMINAL,
     CAIXA.CD_PLANO_CONTAS,
     PLANO_CONTAS.HISTORICO,
     CAIXA.CD_FORMA_PAGAMENTO,
     PLANO_CONTAS.GRAU,
     PLANO_CONTAS.TIPO_CONTA
   FROM
     CAIXA, PLANO_CONTAS
   WHERE
     CAIXA.CD_PLANO_CONTAS = PLANO_CONTAS.CD_PLANO_CONTAS AND
     CAIXA.CD_FILIAL = :CD_FILIAL AND
     CAIXA.DATA_CAIXA >= :DATAINICIAL AND
     CAIXA.DATA_CAIXA <= :DATAFINAL AND
     (CAIXA.TIPO_VENDA = 'V' OR
      CAIXA.TIPO_VENDA = 'D') AND
     CAIXA.ENTREGA = 'S'
   GROUP BY
     CAIXA.CD_OPERADOR,
     CAIXA.TERMINAL,
     CAIXA.CD_PLANO_CONTAS,
     PLANO_CONTAS.HISTORICO,
     CAIXA.CD_FORMA_PAGAMENTO,
     PLANO_CONTAS.GRAU,
     PLANO_CONTAS.TIPO_CONTA
   HAVING
     PLANO_CONTAS.GRAU = 3
   INTO
    :OPERADOR,
    :TERMINAL,
    :CD_PLANO,
    :PLANO,
    :FORMA,
    :GRAU,
    :TIPO
 DO
  BEGIN
   SELECT
     COUNT(*),
     SUM(CAIXA.VALOR),
     (SUM(CAIXA.VALOR) / COUNT(*))
   FROM
     CAIXA
   WHERE
     CAIXA.CD_FILIAL = :CD_FILIAL AND
     CAIXA.DATA_CAIXA >= :DATAINICIAL AND
     CAIXA.DATA_CAIXA <= :DATAFINAL AND
     CAIXA.TIPO_VENDA = 'V' AND
     CAIXA.ENTREGA = 'S' AND
     CAIXA.CD_OPERADOR = :OPERADOR AND
     CAIXA.TERMINAL = :TERMINAL AND
     CAIXA.CD_PLANO_CONTAS = :CD_PLANO AND
     CAIXA.CD_FORMA_PAGAMENTO = :FORMA
   INTO
    :NVENDAS,
    :VALOR,
    :VMEDIO;

   IF (:NVENDAS IS NULL) THEN
      NVENDAS = 0;
   IF (:VALOR IS NULL) THEN
      VALOR = 0;
   IF (:VMEDIO IS NULL) THEN
      VMEDIO = 0;


   CANCELAMENTOS = 0;
   SELECT
     SUM(CAIXA.VALOR)
   FROM
     CAIXA
   WHERE
     CAIXA.CD_FILIAL = :CD_FILIAL AND
     CAIXA.DATA_CAIXA >= :DATAINICIAL AND
     CAIXA.DATA_CAIXA <= :DATAFINAL AND
     CAIXA.TIPO_VENDA = 'D'  AND
     CAIXA.ENTREGA = 'S' AND
     CAIXA.CD_OPERADOR = :OPERADOR AND
     CAIXA.TERMINAL = :TERMINAL AND
     CAIXA.CD_PLANO_CONTAS = :CD_PLANO AND
     CAIXA.CD_FORMA_PAGAMENTO = :FORMA
   INTO
    :CANCELAMENTOS;

   IF (:CANCELAMENTOS IS NULL) THEN
      CANCELAMENTOS = 0;
   VALOR = :VALOR - :CANCELAMENTOS;

   SUSPEND;
  END
END ^

ALTER PROCEDURE SP_CAIXA_ARREDONDAMENTO (CD_FILIAL DOUBLE PRECISION,
ID DOUBLE PRECISION)
RETURNS (OPERADOR DOUBLE PRECISION,
TERMINAL DOUBLE PRECISION,
NVENDAS DOUBLE PRECISION,
VALOR DOUBLE PRECISION)
AS 
BEGIN
  FOR
    SELECT
     CAIXA.CD_OPERADOR,
     CAIXA.TERMINAL,
     COUNT(*),
     SUM(CAIXA.ARREDONDAMENTO)
    FROM
     CAIXA
    WHERE
     CAIXA.CD_FILIAL = :CD_FILIAL AND
     CAIXA.ID_OPERADORCAIXA = :ID AND
     TIPO_VENDA = 'V'
    GROUP BY
     CAIXA.CD_OPERADOR,
     CAIXA.TERMINAL
    INTO
     :OPERADOR,
     :TERMINAL,
     :NVENDAS,
     :VALOR
  DO
   BEGIN
     SUSPEND;
   END
END ^

