ALTER PROCEDURE SP_CAIXA_CARTAO (CD_FILIAL DOUBLE PRECISION,
ID DOUBLE PRECISION)
RETURNS (OPERADOR DOUBLE PRECISION,
TERMINAL DOUBLE PRECISION,
CARTAO VARCHAR(100) CHARACTER SET NONE,
NVENDAS DOUBLE PRECISION,
VALOR DOUBLE PRECISION)
AS 
DECLARE VARIABLE CANCELAMENTOS DOUBLE PRECISION;
DECLARE VARIABLE NVENDASCANCELADAS INTEGER;
DECLARE VARIABLE CD_CARTAO DOUBLE PRECISION;
BEGIN
  FOR
    SELECT
     CAIXA.CD_OPERADOR,
     CAIXA.TERMINAL,
     CARTOES.DESCRICAO,
     CAIXA.CD_CARTAO,
     COUNT(CAIXA.CD_VENDA),
     SUM(CAIXA.VALOR)
    FROM
     CAIXA, CARTOES
    WHERE
     CAIXA.CD_FILIAL = :CD_FILIAL AND
     CAIXA.ID_OPERADORCAIXA = :ID AND
     CAIXA.CD_CARTAO = CARTOES.CD_CARTAO AND
     CAIXA.CD_FORMA_PAGAMENTO = 2 AND
