    INTO
     :OPERADOR,
     :TERMINAL,
     :CARTAO,
     :CD_CARTAO,
     :NVENDAS,
     :VALOR
  DO
   BEGIN
        CANCELAMENTOS = 0;
        NVENDASCANCELADAS = 0;
        SELECT
         COUNT(CAIXA.CD_VENDA),
         SUM(CAIXA.VALOR)
        FROM
         CAIXA
        WHERE
         CAIXA.CD_FILIAL = :CD_FILIAL AND
         CAIXA.ID_OPERADORCAIXA = :ID AND
         CAIXA.CD_FORMA_PAGAMENTO = 2 AND
         CAIXA.TIPO_VENDA = 'D' AND
         CAIXA.CD_OPERADOR = :OPERADOR AND
         CAIXA.TERMINAL = :TERMINAL AND
         CAIXA.CD_CARTAO = :CD_CARTAO
        INTO
         :NVENDASCANCELADAS,
         :CANCELAMENTOS;

        IF (:CANCELAMENTOS IS NULL) THEN
           CANCELAMENTOS = 0;
        VALOR = :VALOR - :CANCELAMENTOS;

        IF (:NVENDASCANCELADAS IS NULL) THEN
           NVENDASCANCELADAS = 0;
        NVENDAS = :NVENDAS - :NVENDASCANCELADAS;

     IF (:VALOR > 0) THEN
        SUSPEND;
   END
END ^

