ALTER PROCEDURE SP_CAIXA_CHEQUES (CD_FILIAL DOUBLE PRECISION,
ID DOUBLE PRECISION)
RETURNS (OPERADOR DOUBLE PRECISION,
TERMINAL DOUBLE PRECISION,
BANCO VARCHAR(3) CHARACTER SET NONE,
CHEQUE VARCHAR(6) CHARACTER SET NONE,
VENCIMENTO DATE,
VALOR DOUBLE PRECISION)
AS 
DECLARE VARIABLE CD_VENDA DOUBLE PRECISION;
DECLARE VARIABLE NVENDAS INTEGER;
BEGIN
 FOR
   SELECT
     CAIXA.CD_OPERADOR,
     CAIXA.TERMINAL,
     CAIXA.CD_VENDA,
     SUBSTRING(DOCUMENTO FROM 1 FOR 3),
     SUBSTRING(DOCUMENTO FROM 5 FOR 6),
     CAIXA.DATA_VENCIMENTO,
     CAIXA.VALOR
   FROM
     CAIXA
   WHERE
     CAIXA.CD_FILIAL = :CD_FILIAL AND
     CAIXA.ID_OPERADORCAIXA = :ID AND
     (CAIXA.CD_FORMA_PAGAMENTO = 4 OR CAIXA.CD_FORMA_PAGAMENTO = 6) AND
     (CAIXA.TIPO_VENDA = 'V' OR CAIXA.TIPO_VENDA = 'R')
   INTO
     :OPERADOR,
     :TERMINAL,
     :CD_VENDA,
     :BANCO,
     :CHEQUE,
     :VENCIMENTO,
     :VALOR
 DO
  BEGIN
     SELECT
      COUNT(*)
     FROM
      CAIXA
     WHERE
      CAIXA.CD_FILIAL = :CD_FILIAL AND
      CAIXA.ID_OPERADORCAIXA = :ID AND
      CAIXA.CD_VENDA  = :CD_VENDA AND
      CAIXA.TIPO_VENDA = 'D'
     INTO
      :NVENDAS;

     IF (:NVENDAS = 0) THEN
        SUSPEND;
  END
END ^

