ALTER PROCEDURE SP_CAIXA_CLASSE_PRODUTO (CD_FILIAL DOUBLE PRECISION,
ID DOUBLE PRECISION)
RETURNS (OPERADOR DOUBLE PRECISION,
TERMINAL DOUBLE PRECISION,
CLASSE VARCHAR(100) CHARACTER SET NONE,
NVENDAS DOUBLE PRECISION,
VALOR DOUBLE PRECISION)
AS 
DECLARE VARIABLE CD_CLASSE DOUBLE PRECISION;
DECLARE VARIABLE CANCELAMENTOS DOUBLE PRECISION;
DECLARE VARIABLE NVENDASCANCELADAS INTEGER;
BEGIN
 FOR
    SELECT
     LANCAMENTOS.CD_OPERADOR,
     LANCAMENTOS.TERMINAL,
     CLASSES.DESCRICAO,
     CLASSES.CD_CLASSE
    FROM
     CLASSES, LANCAMENTOS
    WHERE
     LANCAMENTOS.ID_OPERADORCAIXA = :ID AND
     (LANCAMENTOS.TIPO_VENDA = 'V' OR LANCAMENTOS.TIPO_VENDA = 'D') AND
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     CLASSES.CD_CLASSE = LANCAMENTOS.CD_CLASSE
    GROUP BY
     LANCAMENTOS.CD_OPERADOR,
     LANCAMENTOS.TERMINAL,
     CLASSES.DESCRICAO,
     CLASSES.CD_CLASSE
    INTO
     :OPERADOR,
     :TERMINAL,
     :CLASSE,
     :CD_CLASSE
 DO
  BEGIN

        SELECT
         SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
         COUNT(DISTINCT LANCAMENTOS.CD_VENDA)
        FROM
         LANCAMENTOS
        WHERE
         LANCAMENTOS.ID_OPERADORCAIXA = :ID AND
         LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
         LANCAMENTOS.TIPO_VENDA = 'V' AND
         LANCAMENTOS.CD_CLASSE = :CD_CLASSE
        INTO
         :VALOR,
         :NVENDAS;

        IF (:VALOR IS NULL) THEN
           VALOR = 0;
        IF (:NVENDAS IS NULL) THEN
           NVENDAS = 0;

        SELECT
         SUM(LANCAMENTOS.VALOR),
         COUNT(DISTINCT LANCAMENTOS.CD_VENDA)
        FROM
         LANCAMENTOS
        WHERE
         LANCAMENTOS.ID_OPERADORCAIXA = :ID AND
         LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
         LANCAMENTOS.TIPO_VENDA = 'D' AND
         LANCAMENTOS.CD_CLASSE = :CD_CLASSE
        INTO
         :CANCELAMENTOS,
         :NVENDASCANCELADAS;

        IF (:CANCELAMENTOS IS NULL) THEN
           CANCELAMENTOS = 0;
        IF (:NVENDASCANCELADAS IS NULL) THEN
           NVENDASCANCELADAS = 0;

        VALOR = :VALOR - :CANCELAMENTOS;
        NVENDAS = :NVENDAS - :NVENDASCANCELADAS;

/*    IF (:VALOR > 0) THEN*/
      SUSPEND;
  END
END ^

