BEGIN
  FOR
    SELECT
     CAIXA.CD_OPERADOR,
     CAIXA.TERMINAL,
     CONVENIOS.NOME,
     CAIXA.CD_CONVENIO,
     COUNT(*),
     SUM(CAIXA.VALOR)
    FROM
     CAIXA, CONVENIOS
    WHERE
     CAIXA.CD_FILIAL = :CD_FILIAL AND
     CAIXA.ID_OPERADORCAIXA = :ID AND
