      SUM(CAIXA.VALOR)
    FROM
     CAIXA, CONVENIOS
    WHERE
     CAIXA.CD_FILIAL = :CD_FILIAL AND
     CAIXA.ID_OPERADORCAIXA = :ID AND
     CAIXA.CD_CONVENIO = CONVENIOS.CD_CONVENIO AND
     CAIXA.CD_FORMA_PAGAMENTO = 3 AND
     CAIXA.TIPO_VENDA = 'D' AND
     CAIXA.TERMINAL = :TERMINAL AND
     CAIXA.CD_OPERADOR = :OPERADOR AND
     CAIXA.CD_CONVENIO = :CD_CONVENIO
     INTO
