ALTER PROCEDURE SP_CAIXA_ENTREGADOR (CD_FILIAL DOUBLE PRECISION,
ID DOUBLE PRECISION)
RETURNS (OPERADOR DOUBLE PRECISION,
TERMINAL DOUBLE PRECISION,
ENTREGADOR VARCHAR(50) CHARACTER SET NONE,
NENTREGAS DOUBLE PRECISION)
AS 
declare variable CANCELAMENTOS integer;
declare variable CD_ENTREGADOR double precision;
BEGIN
  FOR
    SELECT
     ENTREGAS.CD_ENTREGADOR, CAIXA.CD_OPERADOR, CAIXA.TERMINAL, COUNT(DISTINCT CAIXA.CD_VENDA)
    FROM
     CAIXA, ENTREGAS, VENDEDORES
    WHERE
     CAIXA.CD_FILIAL = :CD_FILIAL AND
     CAIXA.ID_OPERADORCAIXA = :ID AND
     CAIXA.TIPO_VENDA = 'V' AND
     CAIXA.ENTREGA = 'S' AND
     CAIXA.CD_VENDA = ENTREGAS.CD_VENDA AND
     ENTREGAS.CD_ENTREGADOR = VENDEDORES.CD_VENDEDOR
    GROUP BY
     ENTREGAS.CD_ENTREGADOR, CAIXA.CD_OPERADOR, CAIXA.TERMINAL
    INTO
     :CD_ENTREGADOR,
     :OPERADOR,
     :TERMINAL,
     :NENTREGAS
  DO
   BEGIN
      SELECT
       COUNT(*)
      FROM
       CAIXA, VENDEDORES, ENTREGAS
      WHERE
       CAIXA.CD_FILIAL = :CD_FILIAL AND
       CAIXA.ID_OPERADORCAIXA = :ID AND
       CAIXA.TIPO_VENDA = 'D' AND
       CAIXA.ENTREGA = 'S' AND
       ENTREGAS.CD_ENTREGADOR = :CD_ENTREGADOR AND
       CAIXA.CD_VENDA = ENTREGAS.CD_VENDA AND
       ENTREGAS.CD_ENTREGADOR = VENDEDORES.CD_VENDEDOR AND
       ENTREGAS.CD_FILIAL = CAIXA.CD_FILIAL
      INTO
       :CANCELAMENTOS;

      IF (:CANCELAMENTOS IS NULL) THEN
        CANCELAMENTOS = 0;

      NENTREGAS = :NENTREGAS - :CANCELAMENTOS;

      SELECT NOME FROM VENDEDORES WHERE CD_VENDEDOR = :CD_ENTREGADOR INTO :ENTREGADOR;

      SUSPEND;
   END
END ^

ALTER PROCEDURE SP_CAIXA_ENTREGADOR_DATA (CD_FILIAL DOUBLE PRECISION,
DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (OPERADOR DOUBLE PRECISION,
TERMINAL DOUBLE PRECISION,
ENTREGADOR VARCHAR(50) CHARACTER SET NONE,
NENTREGAS DOUBLE PRECISION)
AS 
declare variable CD_ENTREGADOR double precision;
declare variable CANCELAMENTOS integer;
declare variable CD_VENDA double precision;
BEGIN
  FOR
    SELECT
     ENTREGAS.CD_ENTREGADOR, CAIXA.CD_OPERADOR, CAIXA.TERMINAL, COUNT(DISTINCT CAIXA.CD_VENDA)
    FROM
     CAIXA, ENTREGAS, VENDEDORES
    WHERE
     CAIXA.CD_FILIAL = :CD_FILIAL AND
     CAIXA.DATA_CAIXA >= :DATAINICIAL AND
     CAIXA.DATA_CAIXA <= :DATAFINAL AND
     CAIXA.TIPO_VENDA = 'V' AND
     CAIXA.ENTREGA = 'S' AND
     CAIXA.CD_VENDA = ENTREGAS.CD_VENDA AND
     ENTREGAS.CD_ENTREGADOR = VENDEDORES.CD_VENDEDOR
    GROUP BY
     ENTREGAS.CD_ENTREGADOR, CAIXA.CD_OPERADOR, CAIXA.TERMINAL
    INTO
     :CD_ENTREGADOR,
     :OPERADOR,
     :TERMINAL,
     :NENTREGAS
  DO
   BEGIN
      SELECT
       COUNT(DISTINCT CAIXA.CD_VENDA)
      FROM
       CAIXA, VENDEDORES, ENTREGAS
      WHERE
       CAIXA.CD_FILIAL = :CD_FILIAL AND
       CAIXA.DATA_CAIXA >= :DATAINICIAL AND
       CAIXA.DATA_CAIXA <= :DATAFINAL AND
       CAIXA.TIPO_VENDA = 'D' AND
       CAIXA.ENTREGA = 'S' AND
       ENTREGAS.CD_ENTREGADOR = :CD_ENTREGADOR AND
       CAIXA.CD_VENDA = ENTREGAS.CD_VENDA AND
       ENTREGAS.CD_ENTREGADOR = VENDEDORES.CD_VENDEDOR AND
       ENTREGAS.CD_FILIAL = CAIXA.CD_FILIAL AND
       CAIXA.CD_OPERADOR = :OPERADOR AND
       CAIXA.TERMINAL = :TERMINAL
      INTO
       :CANCELAMENTOS;

      IF (:CANCELAMENTOS IS NULL) THEN
        CANCELAMENTOS = 0;

      NENTREGAS = :NENTREGAS - :CANCELAMENTOS;

      SELECT NOME FROM VENDEDORES WHERE CD_VENDEDOR = :CD_ENTREGADOR INTO :ENTREGADOR;

      SUSPEND;
   END
END ^

ALTER PROCEDURE SP_CAIXA_ESTATISTICA (CD_FILIAL DOUBLE PRECISION,
ID DOUBLE PRECISION)
RETURNS (OPERADOR DOUBLE PRECISION,
TERMINAL DOUBLE PRECISION,
NVENDAS DOUBLE PRECISION,
VVENDAS DOUBLE PRECISION,
NTROCAS DOUBLE PRECISION,
VTROCAS DOUBLE PRECISION,
NCANCELAMENTOS DOUBLE PRECISION,
VCANCELAMENTOS DOUBLE PRECISION,
NENTREGAS DOUBLE PRECISION,
VENTREGAS DOUBLE PRECISION,
MEDIACUPOM DOUBLE PRECISION,
TOTALDESCONTO DOUBLE PRECISION,
DESCONTOVALOR DOUBLE PRECISION,
DESCONTOPERCENTUAL DOUBLE PRECISION,
TOTALPROMOCAO DOUBLE PRECISION,
PROMOCAOVALOR DOUBLE PRECISION,
PROMOCAOPERCENTUAL DOUBLE PRECISION,
SANGRIADINHEIRO DOUBLE PRECISION,
SANGRIACARTAO DOUBLE PRECISION,
SANGRIACONVENIO DOUBLE PRECISION,
SANGRIACHEQUEPRE DOUBLE PRECISION,
SANGRIACREDITO DOUBLE PRECISION,
SANGRIACHEQUEAVISTA DOUBLE PRECISION,
SANGRIAPIX DOUBLE PRECISION,
SUPRIMENTO DOUBLE PRECISION,
NSANGRIA DOUBLE PRECISION,
NSANGRIADINHEIRO DOUBLE PRECISION,
NSANGRIACARTAO DOUBLE PRECISION,
NSANGRIACONVENIO DOUBLE PRECISION,
NSANGRIACHEQUEPRE DOUBLE PRECISION,
NSANGRIACREDITO DOUBLE PRECISION,
NSANGRIACHEQUEAVISA DOUBLE PRECISION,
NSANGRIAPIX DOUBLE PRECISION,
IFOOD DOUBLE PRECISION,
IFOODCANCELAMENTOS DOUBLE PRECISION,
FARMACIASAPP DOUBLE PRECISION,
FARMACIASAPPCANCELAMENTOS DOUBLE PRECISION)
AS 
declare variable CANCELAMENTOS integer;
declare variable VALORCANCELADO double precision;
declare variable FORMA double precision;
declare variable VALORSANGRIA double precision;
declare variable TOTALDESCONTODEVOLUCOES double precision;
declare variable DESCONTOVALORDEVOLUCOES double precision;
declare variable TOTALPROMOCAODEVOLUCOES double precision;
declare variable PROMOCAOVALORDEVOLUCOES double precision;
BEGIN
  NVENDAS = 0; VVENDAS = 0; NTROCAS = 0; VTROCAS = 0;
  NCANCELAMENTOS = 0; VCANCELAMENTOS = 0; NENTREGAS = 0; VENTREGAS = 0;
  MEDIACUPOM = 0; TOTALDESCONTO = 0; DESCONTOVALOR = 0;

  FOR
    SELECT
     LANCAMENTOS.CD_OPERADOR,
     LANCAMENTOS.TERMINAL
    FROM
     LANCAMENTOS
    WHERE
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.ID_OPERADORCAIXA = :ID AND
     LANCAMENTOS.CD_OPERADOR <> 0 AND
     (LANCAMENTOS.TIPO_VENDA = 'V' OR
      LANCAMENTOS.TIPO_VENDA = 'S' OR
      LANCAMENTOS.TIPO_VENDA = 'U' OR
      LANCAMENTOS.TIPO_VENDA = 'D')
    GROUP BY
     LANCAMENTOS.CD_OPERADOR,
     LANCAMENTOS.TERMINAL
    INTO
     :OPERADOR,
     :TERMINAL
  DO
   BEGIN
      SELECT
       SUM(VALOR),
       COUNT(DISTINCT CAIXA.CD_VENDA)
      FROM
       CAIXA
      WHERE
       CAIXA.CD_FILIAL = :CD_FILIAL AND
       CAIXA.ID_OPERADORCAIXA = :ID AND
       CAIXA.CD_OPERADOR = :OPERADOR AND
       CAIXA.TERMINAL = :TERMINAL AND
       CAIXA.TIPO_VENDA = 'V'
      INTO
       :VVENDAS,
       :NVENDAS;


      SELECT
       COUNT(DISTINCT CAIXA.CD_VENDA),
       SUM(CAIXA.VALOR)
      FROM
       CAIXA
      WHERE
       CAIXA.CD_FILIAL = :CD_FILIAL AND
       CAIXA.ID_OPERADORCAIXA = :ID AND
       CAIXA.TROCA = 'T' AND
       CAIXA.CD_OPERADOR = :OPERADOR AND
       CAIXA.TERMINAL = :TERMINAL
      INTO
       :NTROCAS,
       :VTROCAS;

      IF (:VTROCAS IS NULL) THEN
         VTROCAS = 0;

      SELECT
       COUNT(DISTINCT CAIXA.CD_VENDA),
       SUM(VALOR)
      FROM
       CAIXA
      WHERE
       CAIXA.CD_FILIAL = :CD_FILIAL AND
       CAIXA.ID_OPERADORCAIXA = :ID AND
       CAIXA.TIPO_VENDA = 'D' AND
       CAIXA.TROCA = 'F' AND
       CAIXA.CD_OPERADOR = :OPERADOR AND
       CAIXA.TERMINAL = :TERMINAL
      INTO
       :NCANCELAMENTOS,
       :VCANCELAMENTOS;

      IF (:NCANCELAMENTOS IS NULL) THEN
         NCANCELAMENTOS = 0;
      IF (:VCANCELAMENTOS IS NULL) THEN
         VCANCELAMENTOS = 0;
      NVENDAS = :NVENDAS - :NCANCELAMENTOS;
      VVENDAS = :VVENDAS - :VCANCELAMENTOS;

      IF ((:VVENDAS IS NULL) OR (:NVENDAS IS NULL) OR (:VVENDAS = 0) OR (:NVENDAS = 0)) THEN
       BEGIN
         MEDIACUPOM = 0;
       END
      ELSE
       BEGIN
         MEDIACUPOM = :VVENDAS / :NVENDAS;
       END

      SELECT
       COUNT(DISTINCT CAIXA.CD_VENDA),
       SUM(VALOR)
      FROM
       CAIXA
      WHERE
       CAIXA.CD_FILIAL = :CD_FILIAL AND
       CAIXA.ID_OPERADORCAIXA = :ID AND
       CAIXA.ENTREGA = 'S' AND
       CAIXA.TERMINAL = :TERMINAL AND
       CAIXA.CD_OPERADOR = :OPERADOR AND
       CAIXA.TIPO_VENDA = 'V'
      INTO
       :NENTREGAS,
       :VENTREGAS;
    
      SELECT
       COUNT(DISTINCT CAIXA.CD_VENDA),
       SUM(VALOR)
      FROM
       CAIXA
      WHERE
       CAIXA.CD_FILIAL = :CD_FILIAL AND
       CAIXA.ID_OPERADORCAIXA = :ID AND
       CAIXA.ENTREGA = 'S' AND
       CAIXA.TERMINAL = :TERMINAL AND
       CAIXA.CD_OPERADOR = :OPERADOR AND
       CAIXA.TIPO_VENDA = 'D'
      INTO
       :CANCELAMENTOS,
       :VALORCANCELADO;

      IF (:CANCELAMENTOS IS NULL) THEN
         CANCELAMENTOS = 0;
      NENTREGAS = :NENTREGAS - :CANCELAMENTOS;

      IF (:VALORCANCELADO IS NULL) THEN
         VALORCANCELADO = 0;
      VENTREGAS = :VENTREGAS - :VALORCANCELADO;

      SELECT
       SUM((LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO) + (LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)),
       SUM(LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)
      FROM
       LANCAMENTOS
      WHERE
       LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
       LANCAMENTOS.ID_OPERADORCAIXA = :ID AND
       LANCAMENTOS.TERMINAL = :TERMINAL AND
       LANCAMENTOS.CD_OPERADOR = :OPERADOR AND
       LANCAMENTOS.DESCONTO IS NOT NULL AND
       LANCAMENTOS.DESCONTO > 0 AND
       ((LANCAMENTOS.PROMOCAO IS NULL) OR (LANCAMENTOS.PROMOCAO = 0)) AND
       LANCAMENTOS.TIPO_VENDA = 'V' AND
       LANCAMENTOS.VENDA_QUANTIDADE = 'N' AND
       LANCAMENTOS.VENDA_FIDELIDADE = 'N'
      INTO
       :TOTALDESCONTO,
       :DESCONTOVALOR;

      SELECT
       SUM((LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO) + (LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)),
       SUM(LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)
      FROM
       LANCAMENTOS
      WHERE
       LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
       LANCAMENTOS.ID_OPERADORCAIXA = :ID AND
       LANCAMENTOS.CD_OPERADOR = :OPERADOR AND
       LANCAMENTOS.TERMINAL = :TERMINAL AND
       LANCAMENTOS.DESCONTO IS NOT NULL AND
       LANCAMENTOS.DESCONTO > 0 AND
       ((LANCAMENTOS.PROMOCAO IS NULL) OR (LANCAMENTOS.PROMOCAO = 0)) AND
       LANCAMENTOS.TIPO_VENDA = 'D' AND
       LANCAMENTOS.VENDA_QUANTIDADE = 'N' AND
       LANCAMENTOS.VENDA_FIDELIDADE = 'N'
      INTO
       :TOTALDESCONTODEVOLUCOES,
       :DESCONTOVALORDEVOLUCOES;

      IF (:TOTALDESCONTO IS NULL) THEN
         TOTALDESCONTO = 0;
      IF (:DESCONTOVALOR IS NULL) THEN
         DESCONTOVALOR = 0;
      IF (:TOTALDESCONTODEVOLUCOES IS NULL) THEN
         TOTALDESCONTODEVOLUCOES = 0;
      IF (:DESCONTOVALORDEVOLUCOES IS NULL) THEN
         DESCONTOVALORDEVOLUCOES = 0;
  
      TOTALDESCONTO = :TOTALDESCONTO - :TOTALDESCONTODEVOLUCOES;
      DESCONTOVALOR = :DESCONTOVALOR - :DESCONTOVALORDEVOLUCOES;

      IF (:TOTALDESCONTO > 0) THEN
       BEGIN
         DESCONTOPERCENTUAL = (:DESCONTOVALOR / :TOTALDESCONTO) * 100;
         IF (:DESCONTOPERCENTUAL IS NULL) THEN
            DESCONTOPERCENTUAL = 0;
       END
      ELSE
       BEGIN
        DESCONTOPERCENTUAL = 0;
       END


      SELECT
        SUM((LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO) + (LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)),
        SUM(LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)
      FROM
        LANCAMENTOS
      WHERE
       LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
       LANCAMENTOS.ID_OPERADORCAIXA = :ID AND
       LANCAMENTOS.TIPO_VENDA = 'V' AND
       LANCAMENTOS.PROMOCAO IS NOT NULL AND
       LANCAMENTOS.PROMOCAO > 0 AND
       LANCAMENTOS.TERMINAL = :TERMINAL AND
       LANCAMENTOS.CD_OPERADOR = :OPERADOR AND
       LANCAMENTOS.CUSTO_UNITARIO > 0
      INTO
       :TOTALPROMOCAO,
       :PROMOCAOVALOR;
    
      SELECT
        SUM((LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO) + (LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)),
        SUM(LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)
      FROM
        LANCAMENTOS
      WHERE
       LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
       LANCAMENTOS.ID_OPERADORCAIXA = :ID AND
       LANCAMENTOS.TIPO_VENDA = 'D' AND
       LANCAMENTOS.PROMOCAO IS NOT NULL AND
       LANCAMENTOS.PROMOCAO > 0 AND
       LANCAMENTOS.TERMINAL = :TERMINAL AND
       LANCAMENTOS.CD_OPERADOR = :OPERADOR AND
       LANCAMENTOS.CUSTO_UNITARIO > 0
      INTO
       :TOTALPROMOCAODEVOLUCOES,
       :PROMOCAOVALORDEVOLUCOES;
  
      IF (:TOTALPROMOCAO IS NULL) THEN
         TOTALPROMOCAO = 0;
      IF (:PROMOCAOVALOR IS NULL) THEN
         PROMOCAOVALOR = 0;
      IF (:TOTALPROMOCAODEVOLUCOES IS NULL) THEN
         TOTALPROMOCAODEVOLUCOES = 0;
      IF (:PROMOCAOVALORDEVOLUCOES IS NULL) THEN
         PROMOCAOVALORDEVOLUCOES = 0;
  
      TOTALPROMOCAO = :TOTALPROMOCAO - :TOTALPROMOCAODEVOLUCOES;
      PROMOCAOVALOR = :PROMOCAOVALOR - :PROMOCAOVALORDEVOLUCOES;
  
      IF (:TOTALPROMOCAO > 0) THEN
       BEGIN
         PROMOCAOPERCENTUAL = (:PROMOCAOVALOR / :TOTALPROMOCAO) * 100;
         IF (:PROMOCAOPERCENTUAL IS NULL) THEN
            PROMOCAOPERCENTUAL = 0;
       END
      ELSE
       BEGIN
         PROMOCAOPERCENTUAL = 0;
       END

      SANGRIADINHEIRO = 0;
      SANGRIACARTAO = 0;
      SANGRIACONVENIO = 0;
      SANGRIACHEQUEPRE = 0;
      SANGRIACREDITO = 0;
      SANGRIACHEQUEAVISTA = 0;
      SANGRIAPIX = 0;
      NSANGRIA = 0;
      NSANGRIADINHEIRO = 0;
      NSANGRIACARTAO = 0;
      NSANGRIACONVENIO = 0;
      NSANGRIACHEQUEPRE = 0;
      NSANGRIACREDITO = 0;
      NSANGRIACHEQUEAVISA = 0;
      NSANGRIAPIX = 0;

      FOR
          SELECT
           LANCAMENTOS.CD_FORMA_PAGAMENTO,
           COUNT(LANCAMENTOS.CD_LANCAMENTO),
           SUM(LANCAMENTOS.VALOR)
          FROM
           LANCAMENTOS
          WHERE
           LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
           LANCAMENTOS.ID_OPERADORCAIXA = :ID AND
           LANCAMENTOS.TERMINAL = :TERMINAL AND
           LANCAMENTOS.CD_OPERADOR = :OPERADOR AND
           LANCAMENTOS.TIPO_VENDA = 'S'
          GROUP BY
           LANCAMENTOS.CD_FORMA_PAGAMENTO
          INTO
           :FORMA,
           :NSANGRIA, 
           :VALORSANGRIA
      DO
       BEGIN
           IF (:FORMA = 1) THEN
            BEGIN
              NSANGRIADINHEIRO = :NSANGRIA;
              SANGRIADINHEIRO = :VALORSANGRIA;
            END
           ELSE
           IF (:FORMA = 2) THEN
            BEGIN
              NSANGRIACARTAO = NSANGRIA;
              SANGRIACARTAO = :VALORSANGRIA;
            END
           ELSE
           IF (:FORMA = 3) THEN
            BEGIN
              NSANGRIACONVENIO = NSANGRIA;
              SANGRIACONVENIO = :VALORSANGRIA;
            END
           ELSE
           IF (:FORMA = 4) THEN
            BEGIN
              NSANGRIACHEQUEPRE = NSANGRIA;
              SANGRIACHEQUEPRE = :VALORSANGRIA;
            END
           ELSE
           IF (:FORMA = 5) THEN
            BEGIN
              NSANGRIACREDITO = NSANGRIA;
              SANGRIACREDITO = :VALORSANGRIA;
            END
           ELSE
           IF (:FORMA = 6) THEN
            BEGIN
              NSANGRIACHEQUEAVISA = NSANGRIA;
              SANGRIACHEQUEAVISTA = :VALORSANGRIA;
            END
           ELSE
           IF (:FORMA = 7) THEN
            BEGIN
              NSANGRIAPIX = NSANGRIA;
              SANGRIAPIX = :VALORSANGRIA;
            END
       END

      SELECT
        SUM(LANCAMENTOS.VALOR)
      FROM
       LANCAMENTOS
      WHERE
       LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
       LANCAMENTOS.ID_OPERADORCAIXA = :ID AND
       LANCAMENTOS.TERMINAL = :TERMINAL AND
       LANCAMENTOS.CD_OPERADOR = :OPERADOR AND
       LANCAMENTOS.TIPO_VENDA = 'U'
      INTO
       :SUPRIMENTO;

      SELECT
        SUM(LANCAMENTOS.VALOR)
      FROM
       LANCAMENTOS
      WHERE
       LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
       LANCAMENTOS.ID_OPERADORCAIXA = :ID AND
       LANCAMENTOS.TERMINAL = :TERMINAL AND
       LANCAMENTOS.CD_OPERADOR = :OPERADOR AND
       LANCAMENTOS.TIPO_VENDA = 'V' AND
       LANCAMENTOS.IFOOD = 'S'
      INTO
       :IFOOD;

      SELECT
        SUM(LANCAMENTOS.VALOR)
      FROM
       LANCAMENTOS
      WHERE
       LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
       LANCAMENTOS.ID_OPERADORCAIXA = :ID AND
       LANCAMENTOS.TERMINAL = :TERMINAL AND
       LANCAMENTOS.CD_OPERADOR = :OPERADOR AND
       LANCAMENTOS.TIPO_VENDA = 'D' AND
       LANCAMENTOS.IFOOD = 'S'
      INTO
       :IFOODCANCELAMENTOS;

      IF (:IFOOD IS NULL) THEN
         IFOOD = 0;
      IF (:IFOODCANCELAMENTOS IS NULL) THEN
         IFOODCANCELAMENTOS = 0;

      IFOOD = :IFOOD - :IFOODCANCELAMENTOS;

      SELECT
        SUM(LANCAMENTOS.VALOR)
      FROM
       LANCAMENTOS
      WHERE
       LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
       LANCAMENTOS.ID_OPERADORCAIXA = :ID AND
       LANCAMENTOS.TERMINAL = :TERMINAL AND
       LANCAMENTOS.CD_OPERADOR = :OPERADOR AND
       LANCAMENTOS.TIPO_VENDA = 'V' AND
       LANCAMENTOS.FARMACIASAPP = 'S'
      INTO
       :FARMACIASAPP;

      SELECT
        SUM(LANCAMENTOS.VALOR)
      FROM
       LANCAMENTOS
      WHERE
       LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
       LANCAMENTOS.ID_OPERADORCAIXA = :ID AND
       LANCAMENTOS.TERMINAL = :TERMINAL AND
       LANCAMENTOS.CD_OPERADOR = :OPERADOR AND
       LANCAMENTOS.TIPO_VENDA = 'D' AND
       LANCAMENTOS.FARMACIASAPP = 'S'
      INTO
       :FARMACIASAPPCANCELAMENTOS;

      IF (:FARMACIASAPP IS NULL) THEN
         FARMACIASAPP = 0;
      IF (:FARMACIASAPPCANCELAMENTOS IS NULL) THEN
         FARMACIASAPPCANCELAMENTOS = 0;

      FARMACIASAPP = :FARMACIASAPP - :FARMACIASAPPCANCELAMENTOS;


      IF (:NVENDAS IS NULL) THEN
         NVENDAS = 0;
      IF (:VVENDAS IS NULL)  THEN
         VVENDAS = 0;
      IF (:NTROCAS IS NULL)  THEN
         NTROCAS = 0;
      IF (:VTROCAS IS NULL)  THEN
         VTROCAS = 0;
      IF (:NCANCELAMENTOS IS NULL)  THEN
         NCANCELAMENTOS = 0;
      IF (:VCANCELAMENTOS IS NULL)  THEN
         VCANCELAMENTOS = 0;
      IF (:NENTREGAS IS NULL)  THEN
         NENTREGAS = 0;
      IF (:VENTREGAS IS NULL)  THEN
         VENTREGAS = 0;
      IF (:MEDIACUPOM IS NULL)  THEN
          MEDIACUPOM = 0;
      IF (:TOTALDESCONTO IS NULL)  THEN
          TOTALDESCONTO = 0;
      IF (:DESCONTOVALOR IS NULL)  THEN
          DESCONTOVALOR = 0;
      IF (:DESCONTOPERCENTUAL IS NULL)  THEN
          DESCONTOPERCENTUAL = 0;
      IF (:SANGRIADINHEIRO IS NULL)  THEN
          SANGRIADINHEIRO = 0;
      IF (:SANGRIACARTAO IS NULL)  THEN
          SANGRIACARTAO = 0;
      IF (:SANGRIACONVENIO IS NULL)  THEN
          SANGRIACONVENIO = 0;
      IF (:SANGRIACHEQUEPRE IS NULL)  THEN
          SANGRIACHEQUEPRE = 0;
      IF (:SANGRIACREDITO IS NULL)  THEN
          SANGRIACREDITO = 0;
      IF (:SANGRIACHEQUEAVISTA IS NULL)  THEN
          SANGRIACHEQUEAVISTA = 0;
      IF (:SANGRIAPIX IS NULL)  THEN
          SANGRIAPIX = 0;
      IF (:NSANGRIA IS NULL) THEN
          NSANGRIA = 0;
      IF (:NSANGRIADINHEIRO IS NULL) THEN
          NSANGRIADINHEIRO = 0;
      IF (:NSANGRIACARTAO IS NULL) THEN
          NSANGRIACARTAO = 0;
      IF (:NSANGRIACONVENIO IS NULL) THEN
          NSANGRIACONVENIO = 0;
      IF (:NSANGRIACHEQUEPRE IS NULL) THEN
          NSANGRIACHEQUEPRE = 0;
      IF (:NSANGRIACREDITO IS NULL) THEN
          NSANGRIACREDITO = 0;
      IF (:NSANGRIACHEQUEAVISA IS NULL) THEN
          NSANGRIACHEQUEAVISA = 0;
      IF (:NSANGRIAPIX IS NULL) THEN
          NSANGRIAPIX = 0;
      IF (:SUPRIMENTO IS NULL)  THEN
          SUPRIMENTO = 0;

      SUSPEND;
   END
END ^

ALTER PROCEDURE SP_CAIXA_ESTATISTICA_DATA (CD_FILIAL DOUBLE PRECISION,
DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (OPERADOR DOUBLE PRECISION,
TERMINAL DOUBLE PRECISION,
NVENDAS DOUBLE PRECISION,
VVENDAS DOUBLE PRECISION,
NTROCAS DOUBLE PRECISION,
VTROCAS DOUBLE PRECISION,
NCANCELAMENTOS DOUBLE PRECISION,
VCANCELAMENTOS DOUBLE PRECISION,
NENTREGAS DOUBLE PRECISION,
VENTREGAS DOUBLE PRECISION,
MEDIACUPOM DOUBLE PRECISION,
TOTALDESCONTO DOUBLE PRECISION,
DESCONTOVALOR DOUBLE PRECISION,
DESCONTOPERCENTUAL DOUBLE PRECISION,
TOTALPROMOCAO DOUBLE PRECISION,
PROMOCAOVALOR DOUBLE PRECISION,
PROMOCAOPERCENTUAL DOUBLE PRECISION,
SANGRIADINHEIRO DOUBLE PRECISION,
SANGRIACARTAO DOUBLE PRECISION,
SANGRIACONVENIO DOUBLE PRECISION,
SANGRIACHEQUEPRE DOUBLE PRECISION,
SANGRIACREDITO DOUBLE PRECISION,
SANGRIACHEQUEAVISTA DOUBLE PRECISION,
SANGRIAPIX DOUBLE PRECISION,
SUPRIMENTO DOUBLE PRECISION,
NSANGRIA DOUBLE PRECISION,
NSANGRIADINHEIRO DOUBLE PRECISION,
NSANGRIACARTAO DOUBLE PRECISION,
NSANGRIACONVENIO DOUBLE PRECISION,
NSANGRIACHEQUEPRE DOUBLE PRECISION,
NSANGRIACREDITO DOUBLE PRECISION,
NSANGRIACHEQUEAVISA DOUBLE PRECISION,
NSANGRIAPIX DOUBLE PRECISION,
IFOOD DOUBLE PRECISION,
IFOODCANCELAMENTOS DOUBLE PRECISION,
FARMACIASAPP DOUBLE PRECISION,
FARMACIASAPPCANCELAMENTOS DOUBLE PRECISION)
AS 
declare variable CANCELAMENTOS integer;
declare variable VALORCANCELADO double precision;
declare variable FORMA double precision;
declare variable VALORSANGRIA double precision;
declare variable TOTALDESCONTODEVOLUCOES double precision;
declare variable DESCONTOVALORDEVOLUCOES double precision;
declare variable TOTALPROMOCAODEVOLUCOES double precision;
declare variable PROMOCAOVALORDEVOLUCOES double precision;
BEGIN
  NVENDAS = 0; VVENDAS = 0; NTROCAS = 0; VTROCAS = 0;
  NCANCELAMENTOS = 0; VCANCELAMENTOS = 0; NENTREGAS = 0; VENTREGAS = 0;
  MEDIACUPOM = 0; DESCONTOVALOR = 0; DESCONTOPERCENTUAL = 0;

  FOR
    SELECT
     CAIXA.CD_OPERADOR,
     CAIXA.TERMINAL
    FROM
     CAIXA
    WHERE
     CAIXA.CD_OPERADOR <> 0 AND
     CAIXA.DATA_CAIXA >= :DATAINICIAL AND
     CAIXA.DATA_CAIXA <= :DATAFINAL AND
     CAIXA.CD_FILIAL = :CD_FILIAL AND
     (CAIXA.TIPO_VENDA = 'V' OR
      CAIXA.TIPO_VENDA = 'S' OR
      CAIXA.TIPO_VENDA = 'U' OR
      CAIXA.TIPO_VENDA = 'D')
    GROUP BY
     CAIXA.CD_OPERADOR,
     CAIXA.TERMINAL
    INTO
     :OPERADOR,
     :TERMINAL
  DO
   BEGIN
      SELECT
       SUM(VALOR),
       COUNT(DISTINCT CAIXA.CD_VENDA)
      FROM
       CAIXA
      WHERE
       CAIXA.CD_OPERADOR = :OPERADOR AND
       CAIXA.TERMINAL = :TERMINAL AND
       CAIXA.TIPO_VENDA = 'V' AND
       CAIXA.CD_FILIAL = :CD_FILIAL AND
       CAIXA.DATA_CAIXA >= :DATAINICIAL AND
       CAIXA.DATA_CAIXA <= :DATAFINAL
      INTO
       :VVENDAS,
       :NVENDAS;


      SELECT
       COUNT(DISTINCT CAIXA.CD_VENDA),
       SUM(CAIXA.VALOR)
      FROM
       CAIXA
      WHERE
       CAIXA.TROCA = 'T' AND
       CAIXA.CD_OPERADOR = :OPERADOR AND
       CAIXA.TERMINAL = :TERMINAL AND
       CAIXA.DATA_CAIXA >= :DATAINICIAL AND
       CAIXA.DATA_CAIXA <= :DATAFINAL AND
       CAIXA.CD_FILIAL = :CD_FILIAL
      INTO
       :NTROCAS,
       :VTROCAS;

      IF (:VTROCAS IS NULL) THEN
         VTROCAS = 0;

      SELECT
       COUNT(DISTINCT CAIXA.CD_VENDA),
       SUM(VALOR)
      FROM
       CAIXA
      WHERE
       CAIXA.TIPO_VENDA = 'D' AND
       CAIXA.CD_OPERADOR = :OPERADOR AND
       CAIXA.TERMINAL = :TERMINAL AND
       CAIXA.DATA_CAIXA >= :DATAINICIAL AND
       CAIXA.DATA_CAIXA <= :DATAFINAL AND
       CAIXA.CD_FILIAL = :CD_FILIAL
      INTO
       :NCANCELAMENTOS,
       :VCANCELAMENTOS;

      IF (:VCANCELAMENTOS IS NULL) THEN
         VCANCELAMENTOS = 0;
      IF (:NCANCELAMENTOS IS NULL) THEN
         NCANCELAMENTOS = 0;

      VVENDAS = :VVENDAS - :VCANCELAMENTOS;
      NVENDAS = :NVENDAS - :NCANCELAMENTOS;

      IF ((:VVENDAS IS NULL) OR (:NVENDAS IS NULL) OR (:VVENDAS = 0) OR (:NVENDAS = 0)) THEN
       BEGIN
         MEDIACUPOM = 0;
       END
      ELSE
       BEGIN
         MEDIACUPOM = :VVENDAS / :NVENDAS;
       END

      SELECT
       COUNT(DISTINCT CAIXA.CD_VENDA),
       SUM(VALOR)
      FROM
       CAIXA
      WHERE
       CAIXA.ENTREGA = 'S' AND
       CAIXA.TERMINAL = :TERMINAL AND
       CAIXA.CD_OPERADOR = :OPERADOR AND
       CAIXA.CD_FILIAL = :CD_FILIAL AND
       CAIXA.DATA_CAIXA >= :DATAINICIAL AND
       CAIXA.DATA_CAIXA <= :DATAFINAL AND
       CAIXA.TIPO_VENDA = 'V'
      INTO
       :NENTREGAS,
       :VENTREGAS;
    
      SELECT
       COUNT(DISTINCT CAIXA.CD_VENDA),
       SUM(VALOR)
      FROM
       CAIXA
      WHERE
       CAIXA.ENTREGA = 'S' AND
       CAIXA.TERMINAL = :TERMINAL AND
       CAIXA.CD_OPERADOR = :OPERADOR AND
       CAIXA.CD_FILIAL = :CD_FILIAL AND
       CAIXA.DATA_CAIXA >= :DATAINICIAL AND
       CAIXA.DATA_CAIXA <= :DATAFINAL AND
       CAIXA.TIPO_VENDA = 'D'
      INTO
       :CANCELAMENTOS,
       :VALORCANCELADO;

      IF (:CANCELAMENTOS IS NULL) THEN
         CANCELAMENTOS = 0;
      NENTREGAS = :NENTREGAS - :CANCELAMENTOS;

      IF (:VALORCANCELADO IS NULL) THEN
         VALORCANCELADO = 0;
      VENTREGAS = :VENTREGAS - :VALORCANCELADO;

      SELECT
       SUM((LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO) + (LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)),
       SUM(LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)
      FROM
       LANCAMENTOS
      WHERE
       LANCAMENTOS.TERMINAL = :TERMINAL AND
       LANCAMENTOS.CD_OPERADOR = :OPERADOR AND
       LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
       LANCAMENTOS.DATA_CAIXA >= :DATAINICIAL AND
       LANCAMENTOS.DATA_CAIXA <= :DATAFINAL AND
       LANCAMENTOS.DESCONTO IS NOT NULL AND
       LANCAMENTOS.DESCONTO > 0 AND
       ((LANCAMENTOS.PROMOCAO IS NULL) OR (LANCAMENTOS.PROMOCAO = 0)) AND
       LANCAMENTOS.TIPO_VENDA = 'V' AND
       LANCAMENTOS.VENDA_QUANTIDADE = 'N' AND
       LANCAMENTOS.VENDA_FIDELIDADE = 'N'
      INTO
       :TOTALDESCONTO,
       :DESCONTOVALOR;

      SELECT
       SUM((LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO) + (LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)),
       SUM(LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)
      FROM
       LANCAMENTOS
      WHERE
       LANCAMENTOS.TERMINAL = :TERMINAL AND
       LANCAMENTOS.CD_OPERADOR = :OPERADOR AND
       LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
       LANCAMENTOS.DATA_CAIXA >= :DATAINICIAL AND
       LANCAMENTOS.DATA_CAIXA <= :DATAFINAL AND
       LANCAMENTOS.DESCONTO IS NOT NULL AND
       LANCAMENTOS.DESCONTO > 0 AND
       ((LANCAMENTOS.PROMOCAO IS NULL) OR (LANCAMENTOS.PROMOCAO = 0)) AND
       LANCAMENTOS.TIPO_VENDA = 'D' AND
       LANCAMENTOS.VENDA_QUANTIDADE = 'N' AND
       LANCAMENTOS.VENDA_FIDELIDADE = 'N'
      INTO
       :TOTALDESCONTODEVOLUCOES,
       :DESCONTOVALORDEVOLUCOES;

      IF (:TOTALDESCONTO IS NULL) THEN
         TOTALDESCONTO = 0;
      IF (:DESCONTOVALOR IS NULL) THEN
         DESCONTOVALOR = 0;
      IF (:TOTALDESCONTODEVOLUCOES IS NULL) THEN
         TOTALDESCONTODEVOLUCOES = 0;
      IF (:DESCONTOVALORDEVOLUCOES IS NULL) THEN
         DESCONTOVALORDEVOLUCOES = 0;
  
      TOTALDESCONTO = :TOTALDESCONTO - :TOTALDESCONTODEVOLUCOES;
      DESCONTOVALOR = :DESCONTOVALOR - :DESCONTOVALORDEVOLUCOES;

      IF (:TOTALDESCONTO > 0) THEN
       BEGIN
         DESCONTOPERCENTUAL = (:DESCONTOVALOR / :TOTALDESCONTO) * 100;
         IF (:DESCONTOPERCENTUAL IS NULL) THEN
            DESCONTOPERCENTUAL = 0;
       END
      ELSE
       BEGIN
        DESCONTOPERCENTUAL = 0;
       END

      SELECT
        SUM((LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO) + (LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)),
        SUM(LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)
      FROM
        LANCAMENTOS
      WHERE
       LANCAMENTOS.TIPO_VENDA = 'V' AND
       LANCAMENTOS.PROMOCAO IS NOT NULL AND
       LANCAMENTOS.PROMOCAO > 0 AND
       LANCAMENTOS.TERMINAL = :TERMINAL AND
       LANCAMENTOS.CD_OPERADOR = :OPERADOR AND
       LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
       LANCAMENTOS.DATA_CAIXA >= :DATAINICIAL AND
       LANCAMENTOS.DATA_CAIXA <= :DATAFINAL AND
       LANCAMENTOS.CUSTO_UNITARIO > 0
      INTO
       :TOTALPROMOCAO,
       :PROMOCAOVALOR;
    
      SELECT
        SUM((LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO) + (LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)),
        SUM(LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)
      FROM
        LANCAMENTOS
      WHERE
       LANCAMENTOS.TIPO_VENDA = 'D' AND
       LANCAMENTOS.PROMOCAO IS NOT NULL AND
       LANCAMENTOS.PROMOCAO > 0 AND
       LANCAMENTOS.TERMINAL = :TERMINAL AND
       LANCAMENTOS.CD_OPERADOR = :OPERADOR AND
       LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
       LANCAMENTOS.DATA_CAIXA >= :DATAINICIAL AND
       LANCAMENTOS.DATA_CAIXA <= :DATAFINAL AND
       LANCAMENTOS.CUSTO_UNITARIO > 0
      INTO
       :TOTALPROMOCAODEVOLUCOES,
       :PROMOCAOVALORDEVOLUCOES;
  
      IF (:TOTALPROMOCAO IS NULL) THEN
         TOTALPROMOCAO = 0;
      IF (:PROMOCAOVALOR IS NULL) THEN
         PROMOCAOVALOR = 0;
      IF (:TOTALPROMOCAODEVOLUCOES IS NULL) THEN
         TOTALPROMOCAODEVOLUCOES = 0;
      IF (:PROMOCAOVALORDEVOLUCOES IS NULL) THEN
         PROMOCAOVALORDEVOLUCOES = 0;
  
      TOTALPROMOCAO = :TOTALPROMOCAO - :TOTALPROMOCAODEVOLUCOES;
      PROMOCAOVALOR = :PROMOCAOVALOR - :PROMOCAOVALORDEVOLUCOES;
  
      IF (:TOTALPROMOCAO > 0) THEN
       BEGIN
         PROMOCAOPERCENTUAL = (:PROMOCAOVALOR / :TOTALPROMOCAO) * 100;
         IF (:PROMOCAOPERCENTUAL IS NULL) THEN
            PROMOCAOPERCENTUAL = 0;
       END
      ELSE
       BEGIN
         PROMOCAOPERCENTUAL = 0;
       END

      SANGRIADINHEIRO = 0;
      SANGRIACARTAO = 0;
      SANGRIACONVENIO = 0;
      SANGRIACHEQUEPRE = 0;
      SANGRIACREDITO = 0;
      SANGRIACHEQUEAVISTA = 0;
      SANGRIAPIX = 0;
      NSANGRIA = 0;
      NSANGRIADINHEIRO = 0;
      NSANGRIACARTAO = 0;
      NSANGRIACONVENIO = 0;
      NSANGRIACHEQUEPRE = 0;
      NSANGRIACREDITO = 0;
      NSANGRIACHEQUEAVISA = 0;
      NSANGRIAPIX = 0;

      FOR
          SELECT
           LANCAMENTOS.CD_FORMA_PAGAMENTO,
           COUNT(LANCAMENTOS.CD_LANCAMENTO),
           SUM(LANCAMENTOS.VALOR)
          FROM
           LANCAMENTOS
          WHERE
           LANCAMENTOS.TERMINAL = :TERMINAL AND
           LANCAMENTOS.CD_OPERADOR = :OPERADOR AND
           LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
           LANCAMENTOS.DATA_CAIXA >= :DATAINICIAL AND
           LANCAMENTOS.DATA_CAIXA <= :DATAFINAL AND
           LANCAMENTOS.TIPO_VENDA = 'S'
          GROUP BY
           LANCAMENTOS.CD_FORMA_PAGAMENTO
          INTO
           :FORMA,
           :NSANGRIA,
           :VALORSANGRIA
      DO
       BEGIN
           IF (:FORMA = 1) THEN
            BEGIN
              NSANGRIADINHEIRO = :NSANGRIA;
              SANGRIADINHEIRO = :VALORSANGRIA;
            END
           ELSE
           IF (:FORMA = 2) THEN
            BEGIN
              NSANGRIACARTAO = NSANGRIA;
              SANGRIACARTAO = :VALORSANGRIA;
            END
           ELSE
           IF (:FORMA = 3) THEN
            BEGIN
              NSANGRIACONVENIO = NSANGRIA;
              SANGRIACONVENIO = :VALORSANGRIA;
            END
           ELSE
           IF (:FORMA = 4) THEN
            BEGIN
              NSANGRIACHEQUEPRE = NSANGRIA;
              SANGRIACHEQUEPRE = :VALORSANGRIA;
            END
           ELSE
           IF (:FORMA = 5) THEN
            BEGIN
              NSANGRIACREDITO = NSANGRIA;
              SANGRIACREDITO = :VALORSANGRIA;
            END
           ELSE
           IF (:FORMA = 6) THEN
            BEGIN
              NSANGRIACHEQUEAVISA = NSANGRIA;
              SANGRIACHEQUEAVISTA = :VALORSANGRIA;
            END
           ELSE
           IF (:FORMA = 7) THEN
            BEGIN
              NSANGRIAPIX = NSANGRIA;
              SANGRIAPIX = :VALORSANGRIA;
            END
       END

      SELECT
        SUM(LANCAMENTOS.VALOR)
      FROM
       LANCAMENTOS
      WHERE
       LANCAMENTOS.TERMINAL = :TERMINAL AND
       LANCAMENTOS.CD_OPERADOR = :OPERADOR AND
       LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
       LANCAMENTOS.DATA_CAIXA >= :DATAINICIAL AND
       LANCAMENTOS.DATA_CAIXA <= :DATAFINAL AND
       LANCAMENTOS.TIPO_VENDA = 'U'
      INTO
       :SUPRIMENTO;

      SELECT
        SUM(LANCAMENTOS.VALOR)
      FROM
       LANCAMENTOS
      WHERE
       LANCAMENTOS.TERMINAL = :TERMINAL AND
       LANCAMENTOS.CD_OPERADOR = :OPERADOR AND
       LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
       LANCAMENTOS.DATA_CAIXA >= :DATAINICIAL AND
       LANCAMENTOS.DATA_CAIXA <= :DATAFINAL AND
       LANCAMENTOS.TIPO_VENDA = 'V' AND
       LANCAMENTOS.IFOOD = 'S'
      INTO
       :IFOOD;

      SELECT
        SUM(LANCAMENTOS.VALOR)
      FROM
       LANCAMENTOS
      WHERE
       LANCAMENTOS.TERMINAL = :TERMINAL AND
       LANCAMENTOS.CD_OPERADOR = :OPERADOR AND
       LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
       LANCAMENTOS.DATA_CAIXA >= :DATAINICIAL AND
       LANCAMENTOS.DATA_CAIXA <= :DATAFINAL AND
       LANCAMENTOS.TIPO_VENDA = 'D' AND
       LANCAMENTOS.IFOOD = 'S'
      INTO
       :IFOODCANCELAMENTOS;

      IF (:IFOOD IS NULL) THEN
         IFOOD = 0;
      IF (:IFOODCANCELAMENTOS IS NULL) THEN
         IFOODCANCELAMENTOS = 0;

      IFOOD = :IFOOD - :IFOODCANCELAMENTOS;

      SELECT
        SUM(LANCAMENTOS.VALOR)
      FROM
       LANCAMENTOS
      WHERE
       LANCAMENTOS.TERMINAL = :TERMINAL AND
       LANCAMENTOS.CD_OPERADOR = :OPERADOR AND
       LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
       LANCAMENTOS.DATA_CAIXA >= :DATAINICIAL AND
       LANCAMENTOS.DATA_CAIXA <= :DATAFINAL AND
       LANCAMENTOS.TIPO_VENDA = 'V' AND
       LANCAMENTOS.FARMACIASAPP = 'S'
      INTO
       :FARMACIASAPP;

      SELECT
        SUM(LANCAMENTOS.VALOR)
      FROM
       LANCAMENTOS
      WHERE
       LANCAMENTOS.TERMINAL = :TERMINAL AND
       LANCAMENTOS.CD_OPERADOR = :OPERADOR AND
       LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
       LANCAMENTOS.DATA_CAIXA >= :DATAINICIAL AND
       LANCAMENTOS.DATA_CAIXA <= :DATAFINAL AND
       LANCAMENTOS.TIPO_VENDA = 'D' AND
       LANCAMENTOS.FARMACIASAPP = 'S'
      INTO
       :FARMACIASAPPCANCELAMENTOS;

      IF (:FARMACIASAPP IS NULL) THEN
         FARMACIASAPP = 0;
      IF (:FARMACIASAPPCANCELAMENTOS IS NULL) THEN
         FARMACIASAPPCANCELAMENTOS = 0;

      FARMACIASAPP = :FARMACIASAPP - :FARMACIASAPPCANCELAMENTOS;


      IF (:NVENDAS IS NULL) THEN
         NVENDAS = 0;
      IF (:VVENDAS IS NULL)  THEN
         VVENDAS = 0;
      IF (:NTROCAS IS NULL)  THEN
         NTROCAS = 0;
      IF (:VTROCAS IS NULL)  THEN
         VTROCAS = 0;
      IF (:NCANCELAMENTOS IS NULL)  THEN
         NCANCELAMENTOS = 0;
      IF (:VCANCELAMENTOS IS NULL)  THEN
         VCANCELAMENTOS = 0;
      IF (:NENTREGAS IS NULL)  THEN
         NENTREGAS = 0;
      IF (:VENTREGAS IS NULL)  THEN
         VENTREGAS = 0;
      IF (:MEDIACUPOM IS NULL)  THEN
          MEDIACUPOM = 0;
      IF (:DESCONTOVALOR IS NULL)  THEN
          DESCONTOVALOR = 0;
      IF (:DESCONTOPERCENTUAL IS NULL)  THEN
          DESCONTOPERCENTUAL = 0;
      IF (:SANGRIADINHEIRO IS NULL)  THEN
          SANGRIADINHEIRO = 0;
      IF (:SANGRIACARTAO IS NULL)  THEN
          SANGRIACARTAO = 0;
      IF (:SANGRIACONVENIO IS NULL)  THEN
          SANGRIACONVENIO = 0;
      IF (:SANGRIACHEQUEPRE IS NULL)  THEN
          SANGRIACHEQUEPRE = 0;
      IF (:SANGRIACREDITO IS NULL)  THEN
          SANGRIACREDITO = 0;
      IF (:SANGRIACHEQUEAVISTA IS NULL)  THEN
          SANGRIACHEQUEAVISTA = 0;
      IF (:SANGRIAPIX IS NULL)  THEN
          SANGRIAPIX = 0;
      IF (:NSANGRIA IS NULL) THEN
          NSANGRIA = 0;
      IF (:NSANGRIADINHEIRO IS NULL) THEN
          NSANGRIADINHEIRO = 0;
      IF (:NSANGRIACARTAO IS NULL) THEN
          NSANGRIACARTAO = 0;
      IF (:NSANGRIACONVENIO IS NULL) THEN
          NSANGRIACONVENIO = 0;
      IF (:NSANGRIACHEQUEPRE IS NULL) THEN
          NSANGRIACHEQUEPRE = 0;
      IF (:NSANGRIACREDITO IS NULL) THEN
          NSANGRIACREDITO = 0;
      IF (:NSANGRIACHEQUEAVISA IS NULL) THEN
          NSANGRIACHEQUEAVISA = 0;
      IF (:NSANGRIAPIX IS NULL) THEN
          NSANGRIAPIX = 0;
      IF (:SUPRIMENTO IS NULL)  THEN
          SUPRIMENTO = 0;
      SUSPEND;
   END
END ^

ALTER PROCEDURE SP_CAIXA_ESTATISTICA_DATA2 (CD_FILIAL DOUBLE PRECISION,
DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (NVENDAS DOUBLE PRECISION,
VVENDAS DOUBLE PRECISION,
NTROCAS DOUBLE PRECISION,
VTROCAS DOUBLE PRECISION,
NCANCELAMENTOS DOUBLE PRECISION,
VCANCELAMENTOS DOUBLE PRECISION,
NENTREGAS DOUBLE PRECISION,
VENTREGAS DOUBLE PRECISION,
MEDIACUPOM DOUBLE PRECISION,
TOTALDESCONTO DOUBLE PRECISION,
DESCONTOVALOR DOUBLE PRECISION,
DESCONTOPERCENTUAL DOUBLE PRECISION,
TOTALPROMOCAO DOUBLE PRECISION,
PROMOCAOVALOR DOUBLE PRECISION,
PROMOCAOPERCENTUAL DOUBLE PRECISION,
SANGRIADINHEIRO DOUBLE PRECISION,
SANGRIACARTAO DOUBLE PRECISION,
SANGRIACONVENIO DOUBLE PRECISION,
SANGRIACHEQUEPRE DOUBLE PRECISION,
SANGRIACREDITO DOUBLE PRECISION,
SANGRIACHEQUEAVISTA DOUBLE PRECISION,
SANGRIAPIX DOUBLE PRECISION,
SUPRIMENTO DOUBLE PRECISION,
NSANGRIA DOUBLE PRECISION,
NSANGRIADINHEIRO DOUBLE PRECISION,
NSANGRIACARTAO DOUBLE PRECISION,
NSANGRIACONVENIO DOUBLE PRECISION,
NSANGRIACHEQUEPRE DOUBLE PRECISION,
NSANGRIACREDITO DOUBLE PRECISION,
NSANGRIACHEQUEAVISA DOUBLE PRECISION,
NSANGRIAPIX DOUBLE PRECISION,
IFOOD DOUBLE PRECISION,
IFOODCANCELAMENTOS DOUBLE PRECISION,
FARMACIASAPP DOUBLE PRECISION,
FARMACIASAPPCANCELAMENTOS DOUBLE PRECISION)
AS 
declare variable CANCELAMENTOS integer;
declare variable VALORCANCELADO double precision;
declare variable FORMA double precision;
declare variable VALORSANGRIA double precision;
declare variable TOTALDESCONTODEVOLUCOES double precision;
declare variable DESCONTOVALORDEVOLUCOES double precision;
declare variable TOTALPROMOCAODEVOLUCOES double precision;
declare variable PROMOCAOVALORDEVOLUCOES double precision;
BEGIN
  NVENDAS = 0; VVENDAS = 0; NTROCAS = 0; VTROCAS = 0;
  NCANCELAMENTOS = 0; VCANCELAMENTOS = 0; NENTREGAS = 0; VENTREGAS = 0;
  MEDIACUPOM = 0; DESCONTOVALOR = 0; DESCONTOPERCENTUAL = 0;

  SELECT
   SUM(VALOR),
   COUNT(DISTINCT CAIXA.CD_VENDA)
  FROM
   CAIXA
  WHERE
   CAIXA.TIPO_VENDA = 'V' AND
   CAIXA.CD_FILIAL = :CD_FILIAL AND
   CAIXA.DATA_CAIXA >= :DATAINICIAL AND
   CAIXA.DATA_CAIXA <= :DATAFINAL
  INTO
   :VVENDAS,
   :NVENDAS;


  SELECT
   COUNT(DISTINCT CAIXA.CD_VENDA),
   SUM(CAIXA.VALOR)
  FROM
   CAIXA
  WHERE
   CAIXA.TROCA = 'T' AND
   CAIXA.DATA_CAIXA >= :DATAINICIAL AND
   CAIXA.DATA_CAIXA <= :DATAFINAL AND
   CAIXA.CD_FILIAL = :CD_FILIAL
  INTO
   :NTROCAS,
   :VTROCAS;

  IF (:VTROCAS IS NULL) THEN
     VTROCAS = 0;

  SELECT
   COUNT(DISTINCT CAIXA.CD_VENDA),
   SUM(VALOR)
  FROM
   CAIXA
  WHERE
   CAIXA.TIPO_VENDA = 'D' AND
   CAIXA.DATA_CAIXA >= :DATAINICIAL AND
   CAIXA.DATA_CAIXA <= :DATAFINAL AND
   CAIXA.CD_FILIAL = :CD_FILIAL
  INTO
   :NCANCELAMENTOS,
   :VCANCELAMENTOS;

  IF (:VCANCELAMENTOS IS NULL) THEN
     VCANCELAMENTOS = 0;
  IF (:NCANCELAMENTOS IS NULL) THEN
     NCANCELAMENTOS = 0;

  VVENDAS = :VVENDAS - :VCANCELAMENTOS;
  NVENDAS = :NVENDAS - :NCANCELAMENTOS;

  IF ((:VVENDAS IS NULL) OR (:NVENDAS IS NULL) OR (:VVENDAS = 0) OR (:NVENDAS = 0)) THEN
   BEGIN
     MEDIACUPOM = 0;
   END
  ELSE
   BEGIN
     MEDIACUPOM = :VVENDAS / :NVENDAS;
   END

  SELECT
   COUNT(DISTINCT CAIXA.CD_VENDA),
   SUM(VALOR)
  FROM
   CAIXA
  WHERE
   CAIXA.ENTREGA = 'S' AND
   CAIXA.CD_FILIAL = :CD_FILIAL AND
   CAIXA.DATA_CAIXA >= :DATAINICIAL AND
   CAIXA.DATA_CAIXA <= :DATAFINAL AND
   CAIXA.TIPO_VENDA = 'V'
  INTO
   :NENTREGAS,
   :VENTREGAS;

  SELECT
   COUNT(DISTINCT CAIXA.CD_VENDA),
   SUM(VALOR)
  FROM
   CAIXA
  WHERE
   CAIXA.ENTREGA = 'S' AND
   CAIXA.CD_FILIAL = :CD_FILIAL AND
   CAIXA.DATA_CAIXA >= :DATAINICIAL AND
   CAIXA.DATA_CAIXA <= :DATAFINAL AND
   CAIXA.TIPO_VENDA = 'D'
  INTO
   :CANCELAMENTOS,
   :VALORCANCELADO;

  IF (:CANCELAMENTOS IS NULL) THEN
     CANCELAMENTOS = 0;
  NENTREGAS = :NENTREGAS - :CANCELAMENTOS;

  IF (:VALORCANCELADO IS NULL) THEN
     VALORCANCELADO = 0;
  VENTREGAS = :VENTREGAS - :VALORCANCELADO;

  SELECT
   SUM((LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO) + (LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)),
   SUM(LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)
  FROM
   LANCAMENTOS
  WHERE
   LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
   LANCAMENTOS.DATA_CAIXA >= :DATAINICIAL AND
   LANCAMENTOS.DATA_CAIXA <= :DATAFINAL AND
   LANCAMENTOS.DESCONTO IS NOT NULL AND
   LANCAMENTOS.DESCONTO > 0 AND
   ((LANCAMENTOS.PROMOCAO IS NULL) OR (LANCAMENTOS.PROMOCAO = 0)) AND
   LANCAMENTOS.TIPO_VENDA = 'V' AND
   LANCAMENTOS.VENDA_QUANTIDADE = 'N' AND
   LANCAMENTOS.VENDA_FIDELIDADE = 'N'
  INTO
   :TOTALDESCONTO,
   :DESCONTOVALOR;

  SELECT
   SUM((LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO) + (LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)),
   SUM(LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)
  FROM
   LANCAMENTOS
  WHERE
   LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
   LANCAMENTOS.DATA_CAIXA >= :DATAINICIAL AND
   LANCAMENTOS.DATA_CAIXA <= :DATAFINAL AND
   LANCAMENTOS.DESCONTO IS NOT NULL AND
   LANCAMENTOS.DESCONTO > 0 AND
   ((LANCAMENTOS.PROMOCAO IS NULL) OR (LANCAMENTOS.PROMOCAO = 0)) AND
   LANCAMENTOS.TIPO_VENDA = 'D' AND
   LANCAMENTOS.VENDA_QUANTIDADE = 'N' AND
   LANCAMENTOS.VENDA_FIDELIDADE = 'N'
  INTO
   :TOTALDESCONTODEVOLUCOES,
   :DESCONTOVALORDEVOLUCOES;

  IF (:TOTALDESCONTO IS NULL) THEN
     TOTALDESCONTO = 0;
  IF (:DESCONTOVALOR IS NULL) THEN
     DESCONTOVALOR = 0;
  IF (:TOTALDESCONTODEVOLUCOES IS NULL) THEN
     TOTALDESCONTODEVOLUCOES = 0;
  IF (:DESCONTOVALORDEVOLUCOES IS NULL) THEN
     DESCONTOVALORDEVOLUCOES = 0;

  TOTALDESCONTO = :TOTALDESCONTO - :TOTALDESCONTODEVOLUCOES;
  DESCONTOVALOR = :DESCONTOVALOR - :DESCONTOVALORDEVOLUCOES;

  IF (:TOTALDESCONTO > 0) THEN
   BEGIN
     DESCONTOPERCENTUAL = (:DESCONTOVALOR / :TOTALDESCONTO) * 100;
     IF (:DESCONTOPERCENTUAL IS NULL) THEN
        DESCONTOPERCENTUAL = 0;
   END
  ELSE
   BEGIN
    DESCONTOPERCENTUAL = 0;
   END

  SELECT
    SUM((LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO) + (LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)),
    SUM(LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)
  FROM
    LANCAMENTOS
  WHERE
   LANCAMENTOS.TIPO_VENDA = 'V' AND
   LANCAMENTOS.PROMOCAO IS NOT NULL AND
   LANCAMENTOS.PROMOCAO > 0 AND
   LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
   LANCAMENTOS.DATA_CAIXA >= :DATAINICIAL AND
   LANCAMENTOS.DATA_CAIXA <= :DATAFINAL AND
   LANCAMENTOS.CUSTO_UNITARIO > 0
  INTO
   :TOTALPROMOCAO,
   :PROMOCAOVALOR;

  SELECT
    SUM((LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO) + (LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)),
    SUM(LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)
  FROM
    LANCAMENTOS
  WHERE
   LANCAMENTOS.TIPO_VENDA = 'D' AND
   LANCAMENTOS.PROMOCAO IS NOT NULL AND
   LANCAMENTOS.PROMOCAO > 0 AND
   LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
   LANCAMENTOS.DATA_CAIXA >= :DATAINICIAL AND
   LANCAMENTOS.DATA_CAIXA <= :DATAFINAL AND
   LANCAMENTOS.CUSTO_UNITARIO > 0
  INTO
   :TOTALPROMOCAODEVOLUCOES,
   :PROMOCAOVALORDEVOLUCOES;

  IF (:TOTALPROMOCAO IS NULL) THEN
     TOTALPROMOCAO = 0;
  IF (:PROMOCAOVALOR IS NULL) THEN
     PROMOCAOVALOR = 0;
  IF (:TOTALPROMOCAODEVOLUCOES IS NULL) THEN
     TOTALPROMOCAODEVOLUCOES = 0;
  IF (:PROMOCAOVALORDEVOLUCOES IS NULL) THEN
     PROMOCAOVALORDEVOLUCOES = 0;

  TOTALPROMOCAO = :TOTALPROMOCAO - :TOTALPROMOCAODEVOLUCOES;
  PROMOCAOVALOR = :PROMOCAOVALOR - :PROMOCAOVALORDEVOLUCOES;

  IF (:TOTALPROMOCAO > 0) THEN
   BEGIN
     PROMOCAOPERCENTUAL = (:PROMOCAOVALOR / :TOTALPROMOCAO) * 100;
     IF (:PROMOCAOPERCENTUAL IS NULL) THEN
        PROMOCAOPERCENTUAL = 0;
   END
  ELSE
   BEGIN
     PROMOCAOPERCENTUAL = 0;
   END

  SANGRIADINHEIRO = 0;
  SANGRIACARTAO = 0;
  SANGRIACONVENIO = 0;
  SANGRIACHEQUEPRE = 0;
  SANGRIACREDITO = 0;
  SANGRIACHEQUEAVISTA = 0;
  SANGRIAPIX = 0;
  NSANGRIA = 0;
  NSANGRIADINHEIRO = 0;
  NSANGRIACARTAO = 0;
  NSANGRIACONVENIO = 0;
  NSANGRIACHEQUEPRE = 0;
  NSANGRIACREDITO = 0;
  NSANGRIACHEQUEAVISA = 0;
  NSANGRIAPIX = 0;

  FOR
      SELECT
       LANCAMENTOS.CD_FORMA_PAGAMENTO,
       COUNT(LANCAMENTOS.CD_LANCAMENTO),
       SUM(LANCAMENTOS.VALOR)
      FROM
       LANCAMENTOS
      WHERE
       LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
       LANCAMENTOS.DATA_CAIXA >= :DATAINICIAL AND
       LANCAMENTOS.DATA_CAIXA <= :DATAFINAL AND
       LANCAMENTOS.TIPO_VENDA = 'S'
      GROUP BY
       LANCAMENTOS.CD_FORMA_PAGAMENTO
      INTO
       :FORMA,
       :NSANGRIA,
       :VALORSANGRIA
  DO
   BEGIN
     IF (:FORMA = 1) THEN
      BEGIN
        NSANGRIADINHEIRO = :NSANGRIA;
        SANGRIADINHEIRO = :VALORSANGRIA;
      END
     ELSE
     IF (:FORMA = 2) THEN
      BEGIN
        NSANGRIACARTAO = NSANGRIA;
        SANGRIACARTAO = :VALORSANGRIA;
      END
     ELSE
     IF (:FORMA = 3) THEN
      BEGIN
        NSANGRIACONVENIO = NSANGRIA;
        SANGRIACONVENIO = :VALORSANGRIA;
      END
     ELSE
     IF (:FORMA = 4) THEN
      BEGIN
        NSANGRIACHEQUEPRE = NSANGRIA;
        SANGRIACHEQUEPRE = :VALORSANGRIA;
      END
     ELSE
     IF (:FORMA = 5) THEN
      BEGIN
        NSANGRIACREDITO = NSANGRIA;
        SANGRIACREDITO = :VALORSANGRIA;
      END
     ELSE
     IF (:FORMA = 6) THEN
      BEGIN
        NSANGRIACHEQUEAVISA = NSANGRIA;
        SANGRIACHEQUEAVISTA = :VALORSANGRIA;
      END
     ELSE
     IF (:FORMA = 7) THEN
      BEGIN
        NSANGRIAPIX = NSANGRIA;
        SANGRIAPIX = :VALORSANGRIA;
      END
   END

  SELECT
    SUM(LANCAMENTOS.VALOR)
  FROM
   LANCAMENTOS
  WHERE
   LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
   LANCAMENTOS.DATA_CAIXA >= :DATAINICIAL AND
   LANCAMENTOS.DATA_CAIXA <= :DATAFINAL AND
   LANCAMENTOS.TIPO_VENDA = 'U'
  INTO
   :SUPRIMENTO;

  SELECT
    SUM(LANCAMENTOS.VALOR)
  FROM
   LANCAMENTOS
  WHERE
   LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
   LANCAMENTOS.DATA_CAIXA >= :DATAINICIAL AND
   LANCAMENTOS.DATA_CAIXA <= :DATAFINAL AND
   LANCAMENTOS.TIPO_VENDA = 'V' AND
   LANCAMENTOS.IFOOD = 'S'
  INTO
   :IFOOD;

  SELECT
    SUM(LANCAMENTOS.VALOR)
  FROM
   LANCAMENTOS
  WHERE
   LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
   LANCAMENTOS.DATA_CAIXA >= :DATAINICIAL AND
   LANCAMENTOS.DATA_CAIXA <= :DATAFINAL AND
   LANCAMENTOS.TIPO_VENDA = 'D' AND
   LANCAMENTOS.IFOOD = 'S'
  INTO
   :IFOODCANCELAMENTOS;

  IF (:IFOOD IS NULL) THEN
     IFOOD = 0;
  IF (:IFOODCANCELAMENTOS IS NULL) THEN
     IFOODCANCELAMENTOS = 0;

  IFOOD = :IFOOD - :IFOODCANCELAMENTOS;

  SELECT
    SUM(LANCAMENTOS.VALOR)
  FROM
   LANCAMENTOS
  WHERE
   LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
   LANCAMENTOS.DATA_CAIXA >= :DATAINICIAL AND
   LANCAMENTOS.DATA_CAIXA <= :DATAFINAL AND
   LANCAMENTOS.TIPO_VENDA = 'V' AND
   LANCAMENTOS.FARMACIASAPP = 'S'
  INTO
   :FARMACIASAPP;

  SELECT
    SUM(LANCAMENTOS.VALOR)
  FROM
   LANCAMENTOS
  WHERE
   LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
   LANCAMENTOS.DATA_CAIXA >= :DATAINICIAL AND
   LANCAMENTOS.DATA_CAIXA <= :DATAFINAL AND
   LANCAMENTOS.TIPO_VENDA = 'D' AND
   LANCAMENTOS.FARMACIASAPP = 'S'
  INTO
   :FARMACIASAPPCANCELAMENTOS;

  IF (:FARMACIASAPP IS NULL) THEN
     FARMACIASAPP = 0;
  IF (:FARMACIASAPPCANCELAMENTOS IS NULL) THEN
     FARMACIASAPPCANCELAMENTOS = 0;

  FARMACIASAPP = :FARMACIASAPP - :FARMACIASAPPCANCELAMENTOS;


  IF (:NVENDAS IS NULL) THEN
     NVENDAS = 0;
  IF (:VVENDAS IS NULL)  THEN
     VVENDAS = 0;
  IF (:NTROCAS IS NULL)  THEN
     NTROCAS = 0;
  IF (:VTROCAS IS NULL)  THEN
     VTROCAS = 0;
  IF (:NCANCELAMENTOS IS NULL)  THEN
     NCANCELAMENTOS = 0;
  IF (:VCANCELAMENTOS IS NULL)  THEN
     VCANCELAMENTOS = 0;
  IF (:NENTREGAS IS NULL)  THEN
     NENTREGAS = 0;
  IF (:VENTREGAS IS NULL)  THEN
     VENTREGAS = 0;
  IF (:MEDIACUPOM IS NULL)  THEN
      MEDIACUPOM = 0;
  IF (:DESCONTOVALOR IS NULL)  THEN
      DESCONTOVALOR = 0;
  IF (:DESCONTOPERCENTUAL IS NULL)  THEN
      DESCONTOPERCENTUAL = 0;
  IF (:SANGRIADINHEIRO IS NULL)  THEN
      SANGRIADINHEIRO = 0;
  IF (:SANGRIACARTAO IS NULL)  THEN
      SANGRIACARTAO = 0;
  IF (:SANGRIACONVENIO IS NULL)  THEN
      SANGRIACONVENIO = 0;
  IF (:SANGRIACHEQUEPRE IS NULL)  THEN
      SANGRIACHEQUEPRE = 0;
  IF (:SANGRIACREDITO IS NULL)  THEN
      SANGRIACREDITO = 0;
  IF (:SANGRIACHEQUEAVISTA IS NULL)  THEN
      SANGRIACHEQUEAVISTA = 0;
  IF (:SANGRIAPIX IS NULL)  THEN
      SANGRIAPIX = 0;
  IF (:NSANGRIA IS NULL) THEN
      NSANGRIA = 0;
  IF (:NSANGRIADINHEIRO IS NULL) THEN
      NSANGRIADINHEIRO = 0;
  IF (:NSANGRIACARTAO IS NULL) THEN
      NSANGRIACARTAO = 0;
  IF (:NSANGRIACONVENIO IS NULL) THEN
      NSANGRIACONVENIO = 0;
  IF (:NSANGRIACHEQUEPRE IS NULL) THEN
      NSANGRIACHEQUEPRE = 0;
  IF (:NSANGRIACREDITO IS NULL) THEN
      NSANGRIACREDITO = 0;
  IF (:NSANGRIACHEQUEAVISA IS NULL) THEN
      NSANGRIACHEQUEAVISA = 0;
  IF (:NSANGRIAPIX IS NULL) THEN
      NSANGRIAPIX = 0;
  IF (:SUPRIMENTO IS NULL)  THEN
      SUPRIMENTO = 0;
  SUSPEND;
END ^

ALTER PROCEDURE SP_CAIXA_FORMAS_PAGAMENTO (CD_FILIAL DOUBLE PRECISION,
ID DOUBLE PRECISION)
RETURNS (OPERADOR DOUBLE PRECISION,
TERMINAL DOUBLE PRECISION,
CD_FORMA DOUBLE PRECISION,
FORMA VARCHAR(100) CHARACTER SET NONE,
VALOR DOUBLE PRECISION)
AS 
DECLARE VARIABLE CANCELAMENTOS DOUBLE PRECISION;
DECLARE VARIABLE SANGRIA DOUBLE PRECISION;
DECLARE VARIABLE SUPRIMENTO DOUBLE PRECISION;
BEGIN
 FOR
   SELECT
     CAIXA.CD_OPERADOR,
     CAIXA.TERMINAL,
     FORMAS_PAGAMENTO.CD_FORMA_PAGAMENTO,
     FORMAS_PAGAMENTO.DESCRICAO
   FROM
     CAIXA, FORMAS_PAGAMENTO
   WHERE
     CAIXA.CD_FILIAL = :CD_FILIAL AND
     CAIXA.ID_OPERADORCAIXA = :ID AND
     CAIXA.CD_FORMA_PAGAMENTO = FORMAS_PAGAMENTO.CD_FORMA_PAGAMENTO AND
     CAIXA.TIPO_VENDA = 'V'
   GROUP BY
     CAIXA.CD_OPERADOR,
     CAIXA.TERMINAL,
     FORMAS_PAGAMENTO.CD_FORMA_PAGAMENTO,
     FORMAS_PAGAMENTO.DESCRICAO,
     CAIXA.TIPO_VENDA
   INTO
    :OPERADOR,
    :TERMINAL,
    :CD_FORMA,
    :FORMA
 DO
  BEGIN
    SELECT
     SUM(CAIXA.VALOR)
    FROM
      CAIXA
    WHERE
      CAIXA.CD_FILIAL = :CD_FILIAL AND
      CAIXA.ID_OPERADORCAIXA = :ID AND
      CAIXA.TIPO_VENDA = 'V' AND
      CAIXA.CD_OPERADOR = :OPERADOR AND
      CAIXA.TERMINAL = :TERMINAL AND
      CAIXA.CD_FORMA_PAGAMENTO = :CD_FORMA
    INTO
     :VALOR;

    SELECT
     SUM(CAIXA.VALOR)
    FROM
      CAIXA
    WHERE
      CAIXA.CD_FILIAL = :CD_FILIAL AND
      CAIXA.ID_OPERADORCAIXA = :ID AND
      CAIXA.TIPO_VENDA = 'D' AND
      CAIXA.CD_OPERADOR = :OPERADOR AND
      CAIXA.TERMINAL = :TERMINAL AND
      CAIXA.CD_FORMA_PAGAMENTO = :CD_FORMA
    INTO
     :CANCELAMENTOS;

    SELECT
     SUM(LANCAMENTOS.VALOR)
    FROM
      LANCAMENTOS
    WHERE
      LANCAMENTOS.ID_OPERADORCAIXA = :ID AND
      LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
      LANCAMENTOS.TIPO_VENDA = 'S' AND
      LANCAMENTOS.CD_OPERADOR = :OPERADOR AND
      LANCAMENTOS.TERMINAL = :TERMINAL AND
      LANCAMENTOS.CD_FORMA_PAGAMENTO = :CD_FORMA
    INTO
     :SANGRIA;

    SELECT
     SUM(LANCAMENTOS.VALOR)
    FROM
      LANCAMENTOS
    WHERE
      LANCAMENTOS.ID_OPERADORCAIXA = :ID AND
      LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
      LANCAMENTOS.TIPO_VENDA = 'U' AND
      LANCAMENTOS.CD_OPERADOR = :OPERADOR AND
      LANCAMENTOS.TERMINAL = :TERMINAL AND
      LANCAMENTOS.CD_FORMA_PAGAMENTO = :CD_FORMA
    INTO
     :SUPRIMENTO;

   IF (:CANCELAMENTOS IS NULL) THEN
      CANCELAMENTOS = 0;
   IF (:SANGRIA IS NULL) THEN
      SANGRIA = 0;
   IF (:SUPRIMENTO IS NULL) THEN
      SUPRIMENTO = 0;

   VALOR = :VALOR - :CANCELAMENTOS - :SANGRIA + :SUPRIMENTO;
   IF (:VALOR > 0) THEN
      SUSPEND;
  END
END ^

ALTER PROCEDURE SP_CAIXA_FORMAS_PAGAMENTO_DATA (CD_FILIAL DOUBLE PRECISION,
DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (OPERADOR DOUBLE PRECISION,
TERMINAL DOUBLE PRECISION,
CD_FORMA DOUBLE PRECISION,
FORMA VARCHAR(100) CHARACTER SET NONE,
VALOR DOUBLE PRECISION)
AS 
DECLARE VARIABLE CANCELAMENTOS DOUBLE PRECISION;
BEGIN
 FOR
   SELECT
     CAIXA.CD_OPERADOR,
     CAIXA.TERMINAL,
     FORMAS_PAGAMENTO.CD_FORMA_PAGAMENTO,
     FORMAS_PAGAMENTO.DESCRICAO
   FROM
     CAIXA, FORMAS_PAGAMENTO
   WHERE
     CAIXA.CD_FORMA_PAGAMENTO = FORMAS_PAGAMENTO.CD_FORMA_PAGAMENTO AND
     CAIXA.TIPO_VENDA = 'V' AND
     CAIXA.CD_FILIAL = :CD_FILIAL AND
     CAIXA.DATA_CAIXA >= :DATAINICIAL AND
     CAIXA.DATA_CAIXA <= :DATAFINAL
   GROUP BY
     CAIXA.CD_OPERADOR,
     CAIXA.TERMINAL,
     FORMAS_PAGAMENTO.CD_FORMA_PAGAMENTO,
     FORMAS_PAGAMENTO.DESCRICAO,
     CAIXA.TIPO_VENDA
   INTO
    :OPERADOR,
    :TERMINAL,
    :CD_FORMA,
    :FORMA
 DO
  BEGIN
    SELECT
     SUM(CAIXA.VALOR)
    FROM
      CAIXA
    WHERE
      CAIXA.TIPO_VENDA = 'V' AND
      CAIXA.CD_FILIAL = :CD_FILIAL AND
      CAIXA.DATA_CAIXA >= :DATAINICIAL AND
      CAIXA.DATA_CAIXA <= :DATAFINAL AND
      CAIXA.CD_OPERADOR = :OPERADOR AND
      CAIXA.TERMINAL = :TERMINAL AND
      CAIXA.CD_FORMA_PAGAMENTO = :CD_FORMA
    INTO
     :VALOR;

    SELECT
     SUM(CAIXA.VALOR)
    FROM
      CAIXA
    WHERE
      CAIXA.TIPO_VENDA = 'D' AND
      CAIXA.CD_FILIAL = :CD_FILIAL AND
      CAIXA.DATA_CAIXA >= :DATAINICIAL AND
      CAIXA.DATA_CAIXA <= :DATAFINAL AND
      CAIXA.CD_OPERADOR = :OPERADOR AND
      CAIXA.TERMINAL = :TERMINAL AND
      CAIXA.CD_FORMA_PAGAMENTO = :CD_FORMA
    INTO
     :CANCELAMENTOS;

   IF (:CANCELAMENTOS IS NULL) THEN
      CANCELAMENTOS = 0;
   VALOR = :VALOR - :CANCELAMENTOS;
   IF (:VALOR > 0) THEN
      SUSPEND;
  END
END ^

ALTER PROCEDURE SP_CAIXA_GRUPO_PRODUTO (CD_FILIAL DOUBLE PRECISION,
ID DOUBLE PRECISION)
RETURNS (OPERADOR DOUBLE PRECISION,
TERMINAL DOUBLE PRECISION,
GRUPO VARCHAR(100) CHARACTER SET NONE,
NVENDAS DOUBLE PRECISION,
VALOR DOUBLE PRECISION)
AS 
DECLARE VARIABLE CD_GRUPO DOUBLE PRECISION;
DECLARE VARIABLE CANCELAMENTOS DOUBLE PRECISION;
DECLARE VARIABLE NVENDASCANCELADAS INTEGER;
BEGIN
 FOR
    SELECT
     LANCAMENTOS.CD_OPERADOR,
     LANCAMENTOS.TERMINAL,
     GRUPOS.DESCRICAO,
     GRUPOS.CD_GRUPO
    FROM
     GRUPOS, LANCAMENTOS
    WHERE
     LANCAMENTOS.ID_OPERADORCAIXA = :ID AND
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     (LANCAMENTOS.TIPO_VENDA = 'V' OR LANCAMENTOS.TIPO_VENDA = 'D') AND
     GRUPOS.CD_GRUPO = LANCAMENTOS.CD_GRUPO
    GROUP BY
     LANCAMENTOS.CD_OPERADOR,
     LANCAMENTOS.TERMINAL,
     GRUPOS.DESCRICAO,
     GRUPOS.CD_GRUPO
    INTO
     :OPERADOR,
     :TERMINAL,
     :GRUPO,
     :CD_GRUPO
 DO
  BEGIN
        SELECT
         SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
         COUNT(DISTINCT LANCAMENTOS.CD_VENDA)
        FROM
         LANCAMENTOS
        WHERE
         LANCAMENTOS.ID_OPERADORCAIXA = :ID AND
         LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
         LANCAMENTOS.TIPO_VENDA = 'V' AND
         LANCAMENTOS.CD_OPERADOR = :OPERADOR AND
         LANCAMENTOS.TERMINAL = :TERMINAL AND
         LANCAMENTOS.CD_GRUPO = :CD_GRUPO
        INTO
         :VALOR,
         :NVENDAS;

        IF (:VALOR IS NULL) THEN
           VALOR = 0;
        IF (:NVENDAS IS NULL) THEN
           NVENDAS = 0;

        SELECT
         SUM(LANCAMENTOS.VALOR),
         COUNT(DISTINCT LANCAMENTOS.CD_VENDA)
        FROM
         LANCAMENTOS
        WHERE
         LANCAMENTOS.ID_OPERADORCAIXA = :ID AND
         LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
         LANCAMENTOS.TIPO_VENDA = 'D' AND
         LANCAMENTOS.CD_OPERADOR = :OPERADOR AND
         LANCAMENTOS.TERMINAL = :TERMINAL AND
         LANCAMENTOS.CD_GRUPO = :CD_GRUPO
        INTO
         :CANCELAMENTOS,
         :NVENDASCANCELADAS;


        IF (:CANCELAMENTOS IS NULL) THEN
           CANCELAMENTOS = 0;
        IF (:NVENDASCANCELADAS IS NULL) THEN
           NVENDASCANCELADAS = 0;

        VALOR = :VALOR - :CANCELAMENTOS;
        NVENDAS = :NVENDAS - :NVENDASCANCELADAS;

        /*IF (:VALOR > 0) THEN*/
           SUSPEND;
  END
END ^

ALTER PROCEDURE SP_CAIXA_GRUPO_PRODUTO_DATA (CD_FILIAL DOUBLE PRECISION,
DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (OPERADOR DOUBLE PRECISION,
TERMINAL DOUBLE PRECISION,
GRUPO VARCHAR(100) CHARACTER SET NONE,
NVENDAS DOUBLE PRECISION,
VALOR DOUBLE PRECISION)
AS 
DECLARE VARIABLE CD_GRUPO DOUBLE PRECISION;
DECLARE VARIABLE CANCELAMENTOS DOUBLE PRECISION;
