     GRUPOS.DESCRICAO,
     GRUPOS.CD_GRUPO
    INTO
     :OPERADOR,
     :TERMINAL,
     :GRUPO,
     :CD_GRUPO
 DO
  BEGIN
        SELECT
         SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
         COUNT(DISTINCT LANCAMENTOS.CD_VENDA)
        FROM
         LANCAMENTOS
        WHERE
         LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
         LANCAMENTOS.TIPO_VENDA = 'V' AND
         LANCAMENTOS.TERMINAL = :TERMINAL AND
         LANCAMENTOS.CD_OPERADOR = :OPERADOR AND
         LANCAMENTOS.DATA_CAIXA >= :DATAINICIAL AND
         LANCAMENTOS.DATA_CAIXA <= :DATAFINAL AND
         LANCAMENTOS.CD_GRUPO = :CD_GRUPO
        INTO
         :VALOR,
         :NVENDAS;

        IF (:VALOR IS NULL) THEN
           VALOR = 0;
        IF (:NVENDAS IS NULL) THEN
           NVENDAS = 0;

        SELECT
         SUM(LANCAMENTOS.VALOR),
         COUNT(DISTINCT LANCAMENTOS.CD_VENDA)
        FROM
         LANCAMENTOS
        WHERE
         LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
         LANCAMENTOS.TIPO_VENDA = 'D' AND
         LANCAMENTOS.TERMINAL = :TERMINAL AND
         LANCAMENTOS.CD_OPERADOR = :OPERADOR AND
         LANCAMENTOS.DATA_CAIXA >= :DATAINICIAL AND
         LANCAMENTOS.DATA_CAIXA <= :DATAFINAL AND
         LANCAMENTOS.CD_GRUPO = :CD_GRUPO
        INTO
         :CANCELAMENTOS,
         :NVENDASCANCELADAS;


        IF (:CANCELAMENTOS IS NULL) THEN
           CANCELAMENTOS = 0;
        IF (:NVENDASCANCELADAS IS NULL) THEN
           NVENDASCANCELADAS = 0;

        VALOR = :VALOR - :CANCELAMENTOS;
        NVENDAS = :NVENDAS - :NVENDASCANCELADAS;

        /*IF (:VALOR > 0) THEN*/
           SUSPEND;
  END
END ^

ALTER PROCEDURE SP_CAIXA_LISTA (CD_FILIAL DOUBLE PRECISION,
ID DOUBLE PRECISION)
RETURNS (OPERADOR DOUBLE PRECISION,
TERMINAL DOUBLE PRECISION,
LISTA VARCHAR(50) CHARACTER SET NONE,
VALOR DOUBLE PRECISION)
AS 
DECLARE VARIABLE CD_LISTA DOUBLE PRECISION;
BEGIN
  FOR
    SELECT
     LANCAMENTOS.CD_OPERADOR,
     LANCAMENTOS.TERMINAL,
     PRODUTOS.CD_LISTA,
     SUM(LANCAMENTOS.VALOR)
    FROM
     PRODUTOS, LANCAMENTOS
    WHERE
     LANCAMENTOS.ID_OPERADORCAIXA = :ID AND
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.TIPO_VENDA = 'V' AND
     PRODUTOS.ID_PRODUTO = LANCAMENTOS.ID_PRODUTO
    GROUP BY
     LANCAMENTOS.CD_OPERADOR,
     LANCAMENTOS.TERMINAL,
     PRODUTOS.CD_LISTA
    INTO
     :OPERADOR,
     :TERMINAL,
     :CD_LISTA,
     :VALOR
  DO
   BEGIN
     LISTA = '';
     SELECT DESCRICAO FROM LISTA_MARCACAO WHERE CD_LISTA = :CD_LISTA INTO :LISTA;

     IF ((:LISTA IS NOT NULL) AND (:LISTA <> '')) THEN
        SUSPEND;
   END
END ^

