ALTER PROCEDURE SP_CAIXA_PLANO_CONTAS (CD_FILIAL DOUBLE PRECISION,
ID DOUBLE PRECISION)
RETURNS (OPERADOR DOUBLE PRECISION,
TERMINAL DOUBLE PRECISION,
CD_PLANO DOUBLE PRECISION,
PLANO VARCHAR(100) CHARACTER SET NONE,
FORMA INTEGER,
TIPO VARCHAR(1) CHARACTER SET NONE,
NVENDAS DOUBLE PRECISION,
VALOR DOUBLE PRECISION,
VMEDIO DOUBLE PRECISION)
AS 
declare variable CANCELAMENTOS double precision;
declare variable GRAU double precision;
declare variable NCANCELAMENTOS integer;
BEGIN
 FOR
   SELECT
     CAIXA.CD_OPERADOR,
     CAIXA.TERMINAL,
     CAIXA.CD_PLANO_CONTAS,
     PLANO_CONTAS.HISTORICO,
     CAIXA.CD_FORMA_PAGAMENTO,
     PLANO_CONTAS.GRAU,
     PLANO_CONTAS.TIPO_CONTA
   FROM
     CAIXA, PLANO_CONTAS
   WHERE
     CAIXA.CD_FILIAL = :CD_FILIAL AND
     CAIXA.ID_OPERADORCAIXA = :ID AND
     CAIXA.CD_PLANO_CONTAS = PLANO_CONTAS.CD_PLANO_CONTAS AND
     (CAIXA.TIPO_VENDA = 'V' OR
      CAIXA.TIPO_VENDA = 'R' OR
      CAIXA.TIPO_VENDA = 'S' OR
      CAIXA.TIPO_VENDA = 'M' OR
      CAIXA.TIPO_VENDA = 'D' OR
      CAIXA.TIPO_VENDA = 'C')
   GROUP BY
     CAIXA.CD_OPERADOR,
     CAIXA.TERMINAL,
     CAIXA.CD_PLANO_CONTAS,
     PLANO_CONTAS.HISTORICO,
     CAIXA.CD_FORMA_PAGAMENTO,
     PLANO_CONTAS.GRAU,
     PLANO_CONTAS.TIPO_CONTA
   INTO
    :OPERADOR,
    :TERMINAL,
    :CD_PLANO,
    :PLANO,
    :FORMA,
    :GRAU,
    :TIPO
 DO
  BEGIN
   SELECT
     COUNT(DISTINCT CD_VENDA),
     SUM(CAIXA.VALOR),
     (SUM(CAIXA.VALOR) / COUNT(*))
   FROM
     CAIXA
   WHERE
     CAIXA.CD_FILIAL = :CD_FILIAL AND
     CAIXA.ID_OPERADORCAIXA = :ID AND
     (CAIXA.TIPO_VENDA = 'V' OR
      CAIXA.TIPO_VENDA = 'R' OR
      CAIXA.TIPO_VENDA = 'M' OR
      CAIXA.TIPO_VENDA = 'S' OR
      CAIXA.TIPO_VENDA = 'C') AND
     CAIXA.CD_PLANO_CONTAS = :CD_PLANO AND
     CAIXA.CD_FORMA_PAGAMENTO = :FORMA
   INTO
    :NVENDAS,
    :VALOR,
    :VMEDIO;

   IF (:NVENDAS IS NULL) THEN
      NVENDAS = 0;
   IF (:VALOR IS NULL) THEN
      VALOR = 0;
   IF (:VMEDIO IS NULL) THEN
      VMEDIO = 0;


   CANCELAMENTOS = 0;
   SELECT
     COUNT(DISTINCT CD_VENDA),
     SUM(CAIXA.VALOR)
   FROM
     CAIXA
   WHERE
     CAIXA.CD_FILIAL = :CD_FILIAL AND
     CAIXA.ID_OPERADORCAIXA = :ID AND
     CAIXA.TIPO_VENDA = 'D' AND
     CAIXA.CD_PLANO_CONTAS = :CD_PLANO AND
     CAIXA.CD_FORMA_PAGAMENTO = :FORMA
   INTO
    :NCANCELAMENTOS,
    :CANCELAMENTOS;

   IF (:NCANCELAMENTOS IS NULL) THEN
      NCANCELAMENTOS = 0;
   IF (:CANCELAMENTOS IS NULL) THEN
      CANCELAMENTOS = 0;

   NVENDAS = :NVENDAS - :NCANCELAMENTOS;
   VALOR = :VALOR - :CANCELAMENTOS;

   SUSPEND;
  END
END ^

