ALTER PROCEDURE SP_CALCULA_COMISSAO_ANALITICO (DATAINICIAL DATE,
DATAFINAL DATE,
NOMEGRUPO VARCHAR(60) CHARACTER SET NONE,
CODIGOFILIAL DOUBLE PRECISION,
NOMEVENDEDOR VARCHAR(60) CHARACTER SET NONE)
RETURNS (CD_FILIAL DOUBLE PRECISION,
FILIAL VARCHAR(60) CHARACTER SET NONE,
VENDEDOR VARCHAR(60) CHARACTER SET NONE,
PRODUTO VARCHAR(60) CHARACTER SET NONE,
GRUPO VARCHAR(60) CHARACTER SET NONE,
DATA DATE,
QUANTIDADE DOUBLE PRECISION,
VALOR DOUBLE PRECISION,
TOTAL DOUBLE PRECISION,
COMISSAO DOUBLE PRECISION,
CANCELAMENTOS DOUBLE PRECISION,
VENDASCANCELADAS DOUBLE PRECISION,
QUANTIDADECANCELADA DOUBLE PRECISION)
AS 
declare variable CD_VENDEDOR double precision;
declare variable CD_GRUPO double precision;
declare variable ID_PRODUTO double precision;
BEGIN
    FOR
     SELECT
      FILIAIS.NOME,
      LANCAMENTOS.CD_FILIAL,
      VENDEDORES.NOME,
      LANCAMENTOS.CD_VENDEDOR,
      --GRUPOS.DESCRICAO,
      LANCAMENTOS.CD_GRUPO,
      LANCAMENTOS.ID_PRODUTO,
      LANCAMENTOS.DESCRICAO,
      LANCAMENTOS.DATA_LANCAMENTO
     FROM
      LANCAMENTOS,
      FILIAIS,
      --GRUPOS,
      VENDEDORES
     WHERE
      LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
      LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
      LANCAMENTOS.CD_FILIAL = :CODIGOFILIAL AND
      VENDEDORES.NOME LIKE :NOMEVENDEDOR AND
      --GRUPOS.DESCRICAO LIKE :NOMEGRUPO AND
      (LANCAMENTOS.TIPO_VENDA = 'V' OR LANCAMENTOS.TIPO_VENDA = 'D') AND
      LANCAMENTOS.CD_FILIAL = FILIAIS.CD_FILIAL AND
      LANCAMENTOS.CD_VENDEDOR = VENDEDORES.CD_VENDEDOR
      --LANCAMENTOS.CD_GRUPO = GRUPOS.CD_GRUPO
     GROUP BY
      FILIAIS.NOME,
      LANCAMENTOS.CD_FILIAL,
      VENDEDORES.NOME,
      LANCAMENTOS.CD_VENDEDOR,
      --GRUPOS.DESCRICAO,
      LANCAMENTOS.CD_GRUPO,
      LANCAMENTOS.ID_PRODUTO,
      LANCAMENTOS.DESCRICAO,
      LANCAMENTOS.DATA_LANCAMENTO
     INTO
      :FILIAL,
      :CD_FILIAL,
      :VENDEDOR,
      :CD_VENDEDOR,
      --:GRUPO,
      :CD_GRUPO,
      :ID_PRODUTO,
      :PRODUTO,
      :DATA
    DO
     BEGIN
        SELECT
         SUM(LANCAMENTOS.QUANTIDADE),
         SUM((LANCAMENTOS.VALOR  - LANCAMENTOS.ARREDONDAMENTO) / LANCAMENTOS.QUANTIDADE),
         SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
         SUM(LANCAMENTOS.COMISSAO)
        FROM
         LANCAMENTOS
        WHERE
         LANCAMENTOS.DATA_LANCAMENTO = :DATA AND
         LANCAMENTOS.TIPO_VENDA = 'V' AND
         LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR AND
         LANCAMENTOS.ID_PRODUTO = :ID_PRODUTO AND
         LANCAMENTOS.CD_FILIAL = :CODIGOFILIAL AND
         LANCAMENTOS.CD_GRUPO = :CD_GRUPO
        INTO
         :QUANTIDADE,
         :VALOR,
         :TOTAL,
         :COMISSAO;
    
        CANCELAMENTOS = 0;
        VENDASCANCELADAS = 0;
        SELECT
         SUM(LANCAMENTOS.QUANTIDADE),
         SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
         SUM(LANCAMENTOS.COMISSAO)
        FROM
         LANCAMENTOS
        WHERE
         LANCAMENTOS.DATA_LANCAMENTO = :DATA AND
         LANCAMENTOS.TIPO_VENDA = 'D' AND
         LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR AND
         LANCAMENTOS.ID_PRODUTO = :ID_PRODUTO AND
         LANCAMENTOS.CD_FILIAL =:CODIGOFILIAL AND
         LANCAMENTOS.CD_GRUPO = :CD_GRUPO
        INTO
         :QUANTIDADECANCELADA,
         :VENDASCANCELADAS,
         :CANCELAMENTOS;

        IF (:QUANTIDADE IS NULL) THEN
           QUANTIDADE = 0;
        IF (:VALOR IS NULL) THEN
           VALOR = 0;
        IF (:TOTAL IS NULL) THEN
           TOTAL = 0;
        IF (:COMISSAO IS NULL) THEN
           COMISSAO = 0;
        IF (:QUANTIDADECANCELADA IS NULL) THEN
           QUANTIDADECANCELADA = 0;
        IF (:VENDASCANCELADAS IS NULL) THEN
            VENDASCANCELADAS = 0;
        IF (:CANCELAMENTOS IS NULL) THEN
            CANCELAMENTOS = 0;

        IF ((:COMISSAO > 0) OR (:CANCELAMENTOS > 0)) THEN
         BEGIN
           SELECT DESCRICAO FROM GRUPOS WHERE CD_GRUPO = :CD_GRUPO INTO :GRUPO;
           IF ((:NOMEGRUPO = '%') OR (:NOMEGRUPO = :GRUPO)) THEN
              SUSPEND;
         END
   END
END ^

ALTER PROCEDURE SP_CALCULA_COMISSAO_EVOLUTIVO (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (FILIAL VARCHAR(40) CHARACTER SET NONE,
VENDEDOR VARCHAR(40) CHARACTER SET NONE,
GRUPO VARCHAR(40) CHARACTER SET NONE,
DATA DATE,
VALOR DOUBLE PRECISION,
COMISSAO DOUBLE PRECISION)
AS 
BEGIN
 FOR
    SELECT
     FILIAIS.NOME,
     VENDEDORES.NOME,
     GRUPOS.DESCRICAO,
     LANCAMENTOS.DATA_LANCAMENTO,
     SUM(LANCAMENTOS.VALOR),
     SUM((LANCAMENTOS.VALOR * GRUPOS.TX_COMISSAO) / 100)
    FROM
     FILIAIS,
     VENDEDORES,
     LANCAMENTOS,
     GRUPOS
    WHERE
     FILIAIS.CD_FILIAL = VENDEDORES.CD_FILIAL AND
     VENDEDORES.CD_VENDEDOR = LANCAMENTOS.CD_VENDEDOR AND
     LANCAMENTOS.CD_FILIAL = FILIAIS.CD_FILIAL AND
     LANCAMENTOS.CD_GRUPO = GRUPOS.CD_GRUPO AND
     LANCAMENTOS.TIPO_VENDA = 'V' AND
     LANCAMENTOS.ENTRADA_SAIDA = 'S' AND
     LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
     LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL
    GROUP BY
     FILIAIS.NOME,
     VENDEDORES.NOME,
     GRUPOS.DESCRICAO,
     LANCAMENTOS.DATA_LANCAMENTO
    INTO
     :FILIAL,
     :VENDEDOR,
     :GRUPO,
     :DATA,
     :VALOR,
     :COMISSAO
 DO
  BEGIN
      SUSPEND;
  END
END ^

ALTER PROCEDURE SP_CALCULA_COMISSAO_PRODUTO (DATAINICIAL DATE,
DATAFINAL DATE,
NOMEGRUPO VARCHAR(100) CHARACTER SET NONE,
CODIGOFILIAL DOUBLE PRECISION,
NOMEVENDEDOR VARCHAR(60) CHARACTER SET NONE)
RETURNS (CD_FILIAL DOUBLE PRECISION,
FILIAL VARCHAR(60) CHARACTER SET NONE,
VENDEDOR VARCHAR(60) CHARACTER SET NONE,
PRODUTO VARCHAR(60) CHARACTER SET NONE,
QUANTIDADE DOUBLE PRECISION,
VALOR DOUBLE PRECISION,
TOTAL DOUBLE PRECISION,
COMISSAO DOUBLE PRECISION,
CANCELAMENTOS DOUBLE PRECISION,
VENDASCANCELADAS DOUBLE PRECISION,
QUANTIDADECANCELADA DOUBLE PRECISION)
AS 
declare variable CD_VENDEDOR double precision;
declare variable ID_PRODUTO double precision;
declare variable CD_GRUPO double precision;
declare variable DATA date;
declare variable GRUPO varchar(100);
BEGIN
    FOR
     SELECT
      FILIAIS.NOME,
      LANCAMENTOS.CD_FILIAL,
      VENDEDORES.NOME,
      LANCAMENTOS.CD_VENDEDOR,
      LANCAMENTOS.ID_PRODUTO,
      LANCAMENTOS.CD_GRUPO
     FROM
      LANCAMENTOS,
      FILIAIS,
      --GRUPOS,
      VENDEDORES
     WHERE
      LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
      LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
      LANCAMENTOS.CD_FILIAL = :CODIGOFILIAL AND
      VENDEDORES.NOME LIKE :NOMEVENDEDOR AND
      --GRUPOS.DESCRICAO LIKE :NOMEGRUPO AND
      (LANCAMENTOS.TIPO_VENDA = 'V' OR LANCAMENTOS.TIPO_VENDA = 'D') AND
      LANCAMENTOS.CD_FILIAL = FILIAIS.CD_FILIAL AND
      LANCAMENTOS.CD_VENDEDOR = VENDEDORES.CD_VENDEDOR
      --LANCAMENTOS.CD_GRUPO = GRUPOS.CD_GRUPO
     GROUP BY
      FILIAIS.NOME,
      LANCAMENTOS.CD_FILIAL,
      VENDEDORES.NOME,
      LANCAMENTOS.CD_VENDEDOR,
      LANCAMENTOS.ID_PRODUTO,
      LANCAMENTOS.CD_GRUPO
     INTO
      :FILIAL,
      :CD_FILIAL,
      :VENDEDOR,
      :CD_VENDEDOR,
      :ID_PRODUTO,
      :CD_GRUPO
    DO
     BEGIN
        SELECT
         SUM(LANCAMENTOS.QUANTIDADE),
         SUM(LANCAMENTOS.VALOR / LANCAMENTOS.QUANTIDADE),
         SUM(LANCAMENTOS.VALOR),
         SUM(LANCAMENTOS.COMISSAO)
        FROM
         LANCAMENTOS
        WHERE
         LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
         LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
         LANCAMENTOS.TIPO_VENDA = 'V' AND
         LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR AND
         LANCAMENTOS.ID_PRODUTO = :ID_PRODUTO AND
         LANCAMENTOS.CD_FILIAL = :CODIGOFILIAL AND
         LANCAMENTOS.CD_GRUPO = :CD_GRUPO
        INTO
         :QUANTIDADE,
         :VALOR,
         :TOTAL,
         :COMISSAO;
    
        CANCELAMENTOS = 0;
        VENDASCANCELADAS = 0;
        SELECT
         SUM(LANCAMENTOS.QUANTIDADE),
         SUM(LANCAMENTOS.VALOR),
         SUM(LANCAMENTOS.COMISSAO)
        FROM
         LANCAMENTOS
        WHERE
         LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
         LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
         LANCAMENTOS.TIPO_VENDA = 'D' AND
         LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR AND
         LANCAMENTOS.ID_PRODUTO = :ID_PRODUTO AND
         LANCAMENTOS.CD_FILIAL =:CODIGOFILIAL AND
         LANCAMENTOS.CD_GRUPO = :CD_GRUPO
        INTO
         :QUANTIDADECANCELADA,
         :VENDASCANCELADAS,
         :CANCELAMENTOS;

        IF (:QUANTIDADE IS NULL) THEN
           QUANTIDADE = 0;
        IF (:VALOR IS NULL) THEN
           VALOR = 0;
        IF (:TOTAL IS NULL) THEN
           TOTAL = 0;
        IF (:COMISSAO IS NULL) THEN
           COMISSAO = 0;
        IF (:QUANTIDADECANCELADA IS NULL) THEN
           QUANTIDADECANCELADA = 0;
        IF (:VENDASCANCELADAS IS NULL) THEN
            VENDASCANCELADAS = 0;
        IF (:CANCELAMENTOS IS NULL) THEN
            CANCELAMENTOS = 0;

        IF ((:COMISSAO > 0) OR (:CANCELAMENTOS > 0)) THEN
         BEGIN
           SELECT DESCRICAO FROM GRUPOS WHERE CD_GRUPO = :CD_GRUPO INTO :GRUPO;
           IF ((:NOMEGRUPO = '%') OR (:NOMEGRUPO = :GRUPO)) THEN
            BEGIN
              SELECT DESCRICAO FROM PRODUTOS WHERE ID_PRODUTO = :ID_PRODUTO INTO :PRODUTO;
              SUSPEND;
            END
         END
   END
END ^

ALTER PROCEDURE SP_CALCULA_COMISSAO_SIMPLIFI (DATAINICIAL DATE,
DATAFINAL DATE,
CODIGOFILIAL DOUBLE PRECISION,
NOMEVENDEDOR VARCHAR(60) CHARACTER SET NONE,
NOMEGRUPO VARCHAR(60) CHARACTER SET NONE)
RETURNS (CD_FILIAL DOUBLE PRECISION,
CD_VENDEDOR DOUBLE PRECISION,
FILIAL VARCHAR(60) CHARACTER SET NONE,
VENDEDOR VARCHAR(60) CHARACTER SET NONE,
VALOR DOUBLE PRECISION,
COMISSAO DOUBLE PRECISION,
CANCELAMENTOS DOUBLE PRECISION,
VENDASCANCELADAS DOUBLE PRECISION,
FIDELIDADE INTEGER,
DATA DATE)
AS 
declare variable CD_GRUPO double precision;
declare variable GRUPO varchar(60);
declare variable CD_LANCAMENTO double precision;
BEGIN
 FOR
    SELECT
     FILIAIS.CD_FILIAL,
     FILIAIS.NOME,
     VENDEDORES.NOME,
     VENDEDORES.CD_VENDEDOR,
     LANCAMENTOS.CD_GRUPO,
     LANCAMENTOS.CD_LANCAMENTO
    FROM
     FILIAIS,
     VENDEDORES,
     LANCAMENTOS,
     GRUPOS
    WHERE
     LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
     LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
     LANCAMENTOS.CD_VENDEDOR = VENDEDORES.CD_VENDEDOR AND
     LANCAMENTOS.CD_FILIAL = FILIAIS.CD_FILIAL AND
     LANCAMENTOS.CD_FILIAL = :CODIGOFILIAL AND
     (LANCAMENTOS.TIPO_VENDA = 'V' OR LANCAMENTOS.TIPO_VENDA = 'D') AND
     VENDEDORES.CD_FILIAL = FILIAIS.CD_FILIAL AND
     VENDEDORES.NOME LIKE :NOMEVENDEDOR AND
     LANCAMENTOS.CD_GRUPO = GRUPOS.CD_GRUPO AND
     GRUPOS.DESCRICAO LIKE :NOMEGRUPO AND
     LANCAMENTOS.COMISSAO > 0
    GROUP BY
     FILIAIS.CD_FILIAL,
     FILIAIS.NOME,
     VENDEDORES.NOME,
     VENDEDORES.CD_VENDEDOR,
     LANCAMENTOS.CD_GRUPO,
     LANCAMENTOS.CD_LANCAMENTO
    INTO
     :CD_FILIAL,
     :FILIAL,
     :VENDEDOR,
     :CD_VENDEDOR,
     :CD_GRUPO,
     :CD_LANCAMENTO
 DO
  BEGIN
    VALOR = 0;
    COMISSAO = 0;
    SELECT
     SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
     SUM(LANCAMENTOS.COMISSAO)
    FROM
     LANCAMENTOS
    WHERE
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.CD_LANCAMENTO = :CD_LANCAMENTO AND
     LANCAMENTOS.TIPO_VENDA = 'V'
    INTO
     :VALOR,
     :COMISSAO;
  
    CANCELAMENTOS = 0;
    VENDASCANCELADAS = 0;
    SELECT
     SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
     SUM(LANCAMENTOS.COMISSAO)
    FROM
     LANCAMENTOS
    WHERE
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.CD_LANCAMENTO = :CD_LANCAMENTO AND
     LANCAMENTOS.TIPO_VENDA = 'D'
    INTO
     :VENDASCANCELADAS,
     :CANCELAMENTOS;
  
    IF (:VALOR IS NULL) THEN
       VALOR = 0;
    IF (:COMISSAO IS NULL) THEN
       COMISSAO = 0;
    IF (:VENDASCANCELADAS IS NULL) THEN
       VENDASCANCELADAS = 0;
    IF (:CANCELAMENTOS IS NULL) THEN
       CANCELAMENTOS = 0;
  
    IF ((:COMISSAO > 0) OR (:CANCELAMENTOS > 0)) THEN
     BEGIN
        /*SELECT COUNT(*) FROM CLIENTES
        WHERE DATA_FICHA >= :DATAINICIAL AND DATA_FICHA <= :DATAFINAL AND
              CD_VENDEDOR = :CD_VENDEDOR AND CARTAOFIDELIDADE IS NOT NULL AND TRIM(CARTAOFIDELIDADE) <> ''
        INTO :FIDELIDADE;*/
      
        SELECT DESCRICAO FROM GRUPOS WHERE CD_GRUPO = :CD_GRUPO INTO :GRUPO;
        SUSPEND;
     END
  END
END ^

