    INTO
     :VALOR,
     :COMISSAO;

    CANCELAMENTOS = 0;
    VENDASCANCELADAS = 0;
    SELECT
     SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
     SUM(LANCAMENTOS.COMISSAO)
    FROM
     LANCAMENTOS
    WHERE
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.CD_LANCAMENTO = :CD_LANCAMENTO AND
     LANCAMENTOS.TIPO_VENDA = 'D'
    INTO
     :VENDASCANCELADAS,
