    IF (:VENDASCANCELADAS IS NULL) THEN
       VENDASCANCELADAS = 0;
    IF (:CANCELAMENTOS IS NULL) THEN
       CANCELAMENTOS = 0;

    IF ((:COMISSAO > 0) OR (:CANCELAMENTOS > 0)) THEN
     BEGIN
       SELECT DESCRICAO FROM GRUPOS WHERE CD_GRUPO = :CD_GRUPO INTO :GRUPO;
       IF ((:NOMEGRUPO = '%') OR (:NOMEGRUPO = :GRUPO)) THEN
         SUSPEND;
     END
  END
END ^

