ALTER PROCEDURE SP_CALCULA_CURVA (FILIAL DOUBLE PRECISION,
CLASSE DOUBLE PRECISION,
DATAINICIAL DATE,
DATAFINAL DATE)
AS 
DECLARE VARIABLE PRODUTO DOUBLE PRECISION;
DECLARE VARIABLE PERCENTUAL DOUBLE PRECISION;
DECLARE VARIABLE ACUMULADO DOUBLE PRECISION;
DECLARE VARIABLE CURVA VARCHAR(1);
DECLARE VARIABLE TOTALGRUPO DOUBLE PRECISION;
DECLARE VARIABLE TOTALPRODUTO DOUBLE PRECISION;
DECLARE VARIABLE CURVA_MAXIMA VARCHAR(1);
DECLARE VARIABLE CURVA_MINIMA VARCHAR(1);
DECLARE VARIABLE COMANDO VARCHAR(255);
DECLARE VARIABLE CURVAANTERIOR VARCHAR(1);
DECLARE VARIABLE PERCENTUALACUMULADO DOUBLE PRECISION;
DECLARE VARIABLE PERCENTUALCURVA DOUBLE PRECISION;
DECLARE VARIABLE PERCENTUALCURVAANTERIOR DOUBLE PRECISION;
BEGIN
  /* DEFINE A MAIOR CURVA UNITARIA */
  SELECT
   CURVAS.SIGLA
  FROM
   CURVAS
  WHERE
   CURVAS.PERCENTUAL IN
   (SELECT MAX(CURVAS.PERCENTUAL) FROM CURVAS)
  INTO
   :CURVA_MAXIMA;

  /* DEFINE A MENOR CURVA UNITARIA */
  SELECT
   SIGLA
  FROM
   CURVAS
  WHERE
   PERCENTUAL IN
  (SELECT MIN(PERCENTUAL) FROM CURVAS)
  INTO
  :CURVA_MINIMA;

  /* ALTERA TODOS OS PRODUTOS PARA A MENOR CURVA UNITARIA */
  COMANDO = 'UPDATE PRODUTOS SET '||
            'CURVA_UNITARIA_'||CAST(:FILIAL AS INTEGER)||' = '''||:CURVA_MINIMA||''', '||
            'CURVA_FINANCEIRA_'||CAST(:FILIAL AS INTEGER)||' = '''||:CURVA_MINIMA||''''||
            ' WHERE CD_CLASSE = '||CAST(:CLASSE AS INTEGER);
  EXECUTE STATEMENT :COMANDO;

  /* DEFINE O TOTAL VENDIDO DA CLASSE */
  SELECT
   SUM(LANCAMENTOS.QUANTIDADE)
  FROM
   LANCAMENTOS
  WHERE
    LANCAMENTOS.CD_FILIAL = :FILIAL AND
    LANCAMENTOS.CD_CLASSE = :CLASSE AND
    LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
    LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
    LANCAMENTOS.TIPO_VENDA = 'V'
  INTO
   :TOTALGRUPO;

 /* DEFINE O TOTAL VENDIDO DE CADA PRODUTO DA CLASSE */
 /* CURVA UNITARIA */
 ACUMULADO = 0;
 PERCENTUALCURVAANTERIOR = 0;
 PERCENTUALACUMULADO = 0;
 CURVAANTERIOR = :CURVA_MINIMA;
 FOR
  SELECT
   LANCAMENTOS.ID_PRODUTO,
   SUM(LANCAMENTOS.QUANTIDADE)
  FROM
   LANCAMENTOS
  WHERE
   LANCAMENTOS.CD_FILIAL = :FILIAL AND
   LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
   LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
   LANCAMENTOS.TIPO_VENDA = 'V' AND
   LANCAMENTOS.CD_CLASSE = :CLASSE
  GROUP BY
   LANCAMENTOS.ID_PRODUTO
  ORDER BY
   SUM(LANCAMENTOS.QUANTIDADE)
  INTO
   :PRODUTO,
   :TOTALPRODUTO
 DO
  BEGIN
   /* DEFINE PERCENTUAL DE VENDA DO PRODUTO EM RELACAO AO TOTAL VENDIDO DO GRUPO */
   PERCENTUAL = (:TOTALPRODUTO * 100) / :TOTALGRUPO;
   /* DEFINE O PERCENTUAL ACUMULADO DOS PRODUTOS */
   ACUMULADO = ACUMULADO + PERCENTUAL;
   CURVA = NULL;

   /* DEFINE A CURVA DE ACORDO COM O PERCENTUAL ACUMULADO */
   SELECT
    CURVAS.SIGLA,
    CURVAS.PERCENTUAL
   FROM
    CURVAS
   WHERE
    CURVAS.PERCENTUAL IN
    (SELECT MIN(CURVAS.PERCENTUAL) FROM CURVAS
     WHERE  CURVAS.PERCENTUAL + :PERCENTUALACUMULADO >= :ACUMULADO AND
            CURVAS.PERCENTUAL > :PERCENTUALCURVAANTERIOR)
   INTO
    :CURVA,
    :PERCENTUALCURVA;

   /* VERIFICA SE A CURVA E NULA, CASO SEJA DEFINE A CURVA MAXIMA */
   IF (:CURVA IS NULL) THEN
      CURVA = :CURVA_MAXIMA;

   IF (:CURVA <> :CURVAANTERIOR) THEN
    BEGIN
      SELECT CURVAS.PERCENTUAL FROM CURVAS WHERE SIGLA = :CURVAANTERIOR INTO :PERCENTUALCURVAANTERIOR;
      PERCENTUALACUMULADO = :PERCENTUALACUMULADO + :PERCENTUALCURVAANTERIOR;
      CURVAANTERIOR = :CURVA;
    END

   /* ALTERA A CURVA DOS PRODUTOS  */
   COMANDO = 'UPDATE PRODUTOS SET CURVA_UNITARIA_'||CAST(:FILIAL AS INTEGER)||' = '''||:CURVA||''' WHERE ID_PRODUTO = '||CAST(:PRODUTO AS INTEGER);
   EXECUTE STATEMENT :COMANDO;
  END

  /*=================================================================================================*/
  /* DEFINE A MAIOR CURVA FINANCEIRA */
  SELECT
   CURVAS.SIGLA
  FROM
   CURVAS
  WHERE
   CURVAS.PERCENTUAL_FINANCEIRO IN
   (SELECT MAX(CURVAS.PERCENTUAL_FINANCEIRO) FROM CURVAS)
  INTO
   :CURVA_MAXIMA;

  /* DEFINE A MENOR CURVA FINANCEIRA */
  SELECT
   SIGLA
  FROM
   CURVAS
  WHERE
   PERCENTUAL_FINANCEIRO IN
  (SELECT MIN(PERCENTUAL_FINANCEIRO) FROM CURVAS)
  INTO
  :CURVA_MINIMA;

  /* DEFINE O TOTAL VENDIDO DA CLASSE */
  SELECT
   SUM(LANCAMENTOS.VALOR)
  FROM
   LANCAMENTOS
  WHERE
    LANCAMENTOS.CD_FILIAL = :FILIAL AND
    LANCAMENTOS.CD_CLASSE = :CLASSE AND
    LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
    LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
    LANCAMENTOS.TIPO_VENDA = 'V'
  INTO
   :TOTALGRUPO;

 /* DEFINE O TOTAL VENDIDO DE CADA PRODUTO DA CLASSE */
 /* CURVA UNITARIA */
 ACUMULADO = 0;
 PERCENTUALCURVAANTERIOR = 0;
 PERCENTUALACUMULADO = 0;
 CURVAANTERIOR = :CURVA_MINIMA;
 FOR
  SELECT
   LANCAMENTOS.ID_PRODUTO,
   SUM(LANCAMENTOS.VALOR)
  FROM
   LANCAMENTOS
  WHERE
   LANCAMENTOS.CD_FILIAL = :FILIAL AND
   LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
   LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
   LANCAMENTOS.TIPO_VENDA = 'V' AND
   LANCAMENTOS.CD_CLASSE = :CLASSE
  GROUP BY
   LANCAMENTOS.ID_PRODUTO
  ORDER BY
   SUM(LANCAMENTOS.QUANTIDADE)
  INTO
   :PRODUTO,
   :TOTALPRODUTO
 DO
  BEGIN
   /* DEFINE PERCENTUAL DE VENDA DO PRODUTO EM RELACAO AO TOTAL VENDIDO DO GRUPO */
   PERCENTUAL = (:TOTALPRODUTO * 100) / :TOTALGRUPO;
   /* DEFINE O PERCENTUAL ACUMULADO DOS PRODUTOS */
   ACUMULADO = ACUMULADO + PERCENTUAL;
   CURVA = NULL;

   /* DEFINE A CURVA DE ACORDO COM O PERCENTUAL ACUMULADO */
   SELECT
    CURVAS.SIGLA,
    CURVAS.PERCENTUAL_FINANCEIRO
   FROM
    CURVAS
   WHERE
    CURVAS.PERCENTUAL_FINANCEIRO IN
    (SELECT MIN(CURVAS.PERCENTUAL_FINANCEIRO) FROM CURVAS
     WHERE  CURVAS.PERCENTUAL_FINANCEIRO + :PERCENTUALACUMULADO >= :ACUMULADO AND
            CURVAS.PERCENTUAL_FINANCEIRO > :PERCENTUALCURVAANTERIOR)
   INTO
    :CURVA,
    :PERCENTUALCURVA;

   /* VERIFICA SE A CURVA E NULA, CASO SEJA DEFINE A CURVA MAXIMA */
   IF (:CURVA IS NULL) THEN
      CURVA = :CURVA_MAXIMA;

   IF (:CURVA <> :CURVAANTERIOR) THEN
    BEGIN
      SELECT CURVAS.PERCENTUAL_FINANCEIRO FROM CURVAS WHERE SIGLA = :CURVAANTERIOR INTO :PERCENTUALCURVAANTERIOR;
      PERCENTUALACUMULADO = :PERCENTUALACUMULADO + :PERCENTUALCURVAANTERIOR;
      CURVAANTERIOR = :CURVA;
    END

   /* ALTERA A CURVA DOS PRODUTOS  */
   COMANDO = 'UPDATE PRODUTOS SET CURVA_FINANCEIRA_'||CAST(:FILIAL AS INTEGER)||' = '''||:CURVA||''' WHERE ID_PRODUTO = '||CAST(:PRODUTO AS INTEGER);
   EXECUTE STATEMENT :COMANDO;
  END

 UPDATE CLASSES SET DT_CALCULOCURVA = CURRENT_DATE WHERE CD_CLASSE = :CLASSE;
 UPDATE CURVAS SET CURVAS.DATAULTIMOCALCULO = CURRENT_DATE;
END ^

ALTER PROCEDURE SP_CALCULA_CURVA_TODOS (FILIAL INTEGER)
AS 
DECLARE VARIABLE DATAINICIAL DATE;
DECLARE VARIABLE DATAFINAL DATE;
DECLARE VARIABLE ULTIMODIAMES INTEGER;
DECLARE VARIABLE PRODUTO DOUBLE PRECISION;
DECLARE VARIABLE CLASSE DOUBLE PRECISION;
DECLARE VARIABLE PERCENTUAL DOUBLE PRECISION;
DECLARE VARIABLE PERCENTUAL_FINANCEIRO DOUBLE PRECISION;
DECLARE VARIABLE ACUMULADO DOUBLE PRECISION;
DECLARE VARIABLE ACUMULADO_FINANCEIRO DOUBLE PRECISION;
DECLARE VARIABLE CURVA VARCHAR(1);
DECLARE VARIABLE CURVA_FINANCEIRO VARCHAR(1);
DECLARE VARIABLE TOTALGRUPO DOUBLE PRECISION;
DECLARE VARIABLE TOTALGRUPO_FINANCEIRO DOUBLE PRECISION;
DECLARE VARIABLE TOTALPRODUTO DOUBLE PRECISION;
DECLARE VARIABLE TOTALPRODUTO_FINANCEIRO DOUBLE PRECISION;
DECLARE VARIABLE COMANDO VARCHAR(255);
DECLARE VARIABLE MES INTEGER;
DECLARE VARIABLE ANO INTEGER;
BEGIN
  /*SELECT CD_FILIAL FROM PARAMETROS INTO :FILIAL;*/
  IF (:FILIAL = 0) THEN
    EXIT;

  MES = EXTRACT(MONTH FROM CURRENT_DATE);
  ANO = EXTRACT(YEAR FROM CURRENT_DATE);

  MES = :MES - 1;
  IF (:MES = 0) THEN
   BEGIN
     MES = 12;
     ANO = ANO -1;
   END
  IF ((:MES = 1) OR (:MES = 3) OR (:MES = 5) OR (:MES = 7) OR (:MES = 8) OR (:MES = 10) OR (:MES = 12)) THEN
     ULTIMODIAMES = 31;
  ELSE
  IF ((:MES = 4) OR (:MES = 6) OR (:MES = 9) OR (:MES = 11)) THEN
     ULTIMODIAMES = 30;
  ELSE
     ULTIMODIAMES = 28;
  DATAINICIAL = CAST(:MES||'/01/'||:ANO AS DATE);
  DATAFINAL   = CAST(:MES||'/'||:ULTIMODIAMES||'/'||:ANO AS DATE);

  SELECT SIGLA FROM CURVAS WHERE  PERCENTUAL IN (SELECT MIN(PERCENTUAL) FROM CURVAS)
  INTO   :CURVA;

  SELECT SIGLA FROM   CURVAS  WHERE  PERCENTUAL_FINANCEIRO IN (SELECT MIN(PERCENTUAL_FINANCEIRO) FROM CURVAS)
  INTO   :CURVA_FINANCEIRO;

  COMANDO = 'UPDATE PRODUTOS SET CURVA_UNITARIA_'||CAST(:FILIAL AS INTEGER)||' = '''||:CURVA||''''||
            ', CURVA_FINANCEIRA_'||CAST(:FILIAL AS INTEGER)||' = '''||:CURVA_FINANCEIRO||'''';
  EXECUTE STATEMENT :COMANDO;

  FOR
   SELECT
    LANCAMENTOS.CD_CLASSE,
    SUM(LANCAMENTOS.QUANTIDADE),
    SUM(LANCAMENTOS.VALOR)
   FROM
    LANCAMENTOS
   WHERE
    LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
    LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
    LANCAMENTOS.CD_FILIAL = :FILIAL AND
    LANCAMENTOS.TIPO_VENDA = 'V'
   GROUP BY
    LANCAMENTOS.CD_CLASSE
   INTO
    :CLASSE,
    :TOTALGRUPO,
    :TOTALGRUPO_FINANCEIRO
  DO
   BEGIN
     ACUMULADO = 0;
     FOR
      SELECT
       LANCAMENTOS.ID_PRODUTO,
       SUM(LANCAMENTOS.QUANTIDADE)
      FROM
       LANCAMENTOS
      WHERE
       LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
       LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
       LANCAMENTOS.CD_FILIAL = :FILIAL AND
       LANCAMENTOS.TIPO_VENDA = 'V' AND
       LANCAMENTOS.CD_CLASSE = :CLASSE
      GROUP BY
       LANCAMENTOS.ID_PRODUTO
      ORDER BY
       SUM(LANCAMENTOS.QUANTIDADE) ASCENDING,
       LANCAMENTOS.ID_PRODUTO DESCENDING
      INTO
       :PRODUTO,
       :TOTALPRODUTO
     DO
      BEGIN
       IF (:TOTALGRUPO > 0) THEN
          PERCENTUAL = (:TOTALPRODUTO * 100) / :TOTALGRUPO;
         ELSE
          PERCENTUAL = 0;

       ACUMULADO = ACUMULADO + PERCENTUAL;
       CURVA = NULL;

       SELECT
        CURVAS.SIGLA
       FROM
        CURVAS
       WHERE
        CURVAS.PERCENTUAL IN
        (SELECT MIN(CURVAS.PERCENTUAL) FROM CURVAS
         WHERE  CURVAS.PERCENTUAL >= :ACUMULADO)
       INTO
        :CURVA;

       IF (:CURVA IS NULL) THEN
        BEGIN
         SELECT
          CURVAS.SIGLA
         FROM
          CURVAS
         WHERE
          CURVAS.PERCENTUAL IN
          (SELECT MAX(CURVAS.PERCENTUAL) FROM CURVAS)
         INTO
          :CURVA;
        END
       COMANDO = 'UPDATE PRODUTOS SET CURVA_UNITARIA_'||CAST(:FILIAL AS INTEGER)|| ' = '''||:CURVA||''' WHERE ID_PRODUTO = '||CAST(:PRODUTO AS INTEGER);
       EXECUTE STATEMENT :COMANDO;
      END

     ACUMULADO_FINANCEIRO = 0;
     FOR
      SELECT
       LANCAMENTOS.ID_PRODUTO,
       SUM(LANCAMENTOS.VALOR)
      FROM
       LANCAMENTOS
      WHERE
       LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
       LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
       LANCAMENTOS.CD_FILIAL = :FILIAL AND
       LANCAMENTOS.TIPO_VENDA = 'V' AND
       LANCAMENTOS.CD_CLASSE = :CLASSE
      GROUP BY
       LANCAMENTOS.ID_PRODUTO
      ORDER BY
       SUM(LANCAMENTOS.VALOR) ASCENDING,
       LANCAMENTOS.ID_PRODUTO DESCENDING
      INTO
       :PRODUTO,
       :TOTALPRODUTO_FINANCEIRO
     DO
      BEGIN
       IF (:TOTALGRUPO_FINANCEIRO > 0) THEN
          PERCENTUAL_FINANCEIRO = (:TOTALPRODUTO_FINANCEIRO * 100) / :TOTALGRUPO_FINANCEIRO;
       ELSE
          PERCENTUAL_FINANCEIRO = 0;

       ACUMULADO_FINANCEIRO = ACUMULADO_FINANCEIRO + PERCENTUAL_FINANCEIRO;
       CURVA_FINANCEIRO = NULL;

       SELECT
        CURVAS.SIGLA
       FROM
        CURVAS
       WHERE
        CURVAS.PERCENTUAL_FINANCEIRO IN
        (SELECT MIN(CURVAS.PERCENTUAL_FINANCEIRO) FROM CURVAS
         WHERE  CURVAS.PERCENTUAL_FINANCEIRO >= :ACUMULADO_FINANCEIRO)
       INTO
        :CURVA_FINANCEIRO;

       IF (:CURVA_FINANCEIRO IS NULL) THEN
        BEGIN
         SELECT
          CURVAS.SIGLA
         FROM
          CURVAS
         WHERE
          CURVAS.PERCENTUAL_FINANCEIRO IN
          (SELECT MAX(CURVAS.PERCENTUAL_FINANCEIRO) FROM CURVAS)
         INTO
          :CURVA_FINANCEIRO;
        END

       COMANDO = 'UPDATE PRODUTOS SET CURVA_FINANCEIRA_'||CAST(:FILIAL AS INTEGER)|| ' = '''||
                 :CURVA_FINANCEIRO||''' WHERE ID_PRODUTO = '||CAST(:PRODUTO AS INTEGER);
       EXECUTE STATEMENT :COMANDO;
      END
   END

  UPDATE CLASSES SET DT_CALCULOCURVA = CURRENT_DATE;
  UPDATE CURVAS SET CURVAS.DATAULTIMOCALCULO = CURRENT_DATE;
END ^

ALTER PROCEDURE SP_CALCULA_MEDIAF (FILIAL DOUBLE PRECISION,
MES INTEGER)
AS 
DECLARE VARIABLE PRODUTO DOUBLE PRECISION;
DECLARE VARIABLE GRUPO DOUBLE PRECISION;
DECLARE VARIABLE COMANDO VARCHAR(1000);
DECLARE VARIABLE COMANDOUPDATE VARCHAR(1000);
DECLARE VARIABLE MES1 VARCHAR(10);
DECLARE VARIABLE MES2 VARCHAR(10);
DECLARE VARIABLE MES3 VARCHAR(10);
DECLARE VARIABLE SIGLA VARCHAR(1);
DECLARE VARIABLE MEDIA1 DOUBLE PRECISION;
DECLARE VARIABLE MEDIA2 DOUBLE PRECISION;
DECLARE VARIABLE MEDIA3M DOUBLE PRECISION;
DECLARE VARIABLE P1 DOUBLE PRECISION;
DECLARE VARIABLE P2 DOUBLE PRECISION;
DECLARE VARIABLE P1SAZ DOUBLE PRECISION;
DECLARE VARIABLE P2SAZ DOUBLE PRECISION;
DECLARE VARIABLE PPV DOUBLE PRECISION;
DECLARE VARIABLE PICO DOUBLE PRECISION;
DECLARE VARIABLE VALE DOUBLE PRECISION;
DECLARE VARIABLE VMES1 DOUBLE PRECISION;
DECLARE VARIABLE VMES2 DOUBLE PRECISION;
DECLARE VARIABLE VMES3 DOUBLE PRECISION;
DECLARE VARIABLE MEDIAF DOUBLE PRECISION;
DECLARE VARIABLE SAZONAL VARCHAR(1);
DECLARE VARIABLE JANSAZ VARCHAR(1);
DECLARE VARIABLE FEVSAZ VARCHAR(1);
DECLARE VARIABLE MARSAZ VARCHAR(1);
DECLARE VARIABLE ABRSAZ VARCHAR(1);
DECLARE VARIABLE MAISAZ VARCHAR(1);
DECLARE VARIABLE JUNSAZ VARCHAR(1);
DECLARE VARIABLE JULSAZ VARCHAR(1);
DECLARE VARIABLE AGOSAZ VARCHAR(1);
DECLARE VARIABLE SETSAZ VARCHAR(1);
DECLARE VARIABLE OUTSAZ VARCHAR(1);
DECLARE VARIABLE NOVSAZ VARCHAR(1);
DECLARE VARIABLE DEZSAZ VARCHAR(1);
DECLARE VARIABLE MESATUAL VARCHAR(2);
DECLARE VARIABLE PSAZONAL VARCHAR(1);
BEGIN
 PPV = 0.5;
 COMANDO = 'UPDATE PRODUTOS SET MEDIAF_'||CAST(:FILIAL AS INTEGER)||' = 0';
 EXECUTE STATEMENT :COMANDO;

 IF (:MES = 1) THEN
  BEGIN
    MES1 = 'OUTVENDA';
    MES2 = 'NOVVENDA';
    MES3 = 'DEZVENDA';
  END
 ELSE
 IF (:MES = 2) THEN
  BEGIN
    MES1 = 'NOVVENDA';
    MES2 = 'DEZVENDA';
    MES3 = 'JANVENDA';
  END
 ELSE
 IF (:MES = 3) THEN
  BEGIN
    MES1 = 'DEZVENDA';
    MES2 = 'JANVENDA';
    MES3 = 'FEVVENDA';
  END
 ELSE
 IF (:MES = 4) THEN
  BEGIN
    MES1 = 'JANVENDA';
    MES2 = 'FEVVENDA';
    MES3 = 'MARVENDA';
  END
 ELSE
 IF (:MES = 5) THEN
  BEGIN
    MES1 = 'FEVVENDA';
    MES2 = 'MARVENDA';
    MES3 = 'ABRVENDA';
  END
 ELSE
 IF (:MES = 6) THEN
  BEGIN
    MES1 = 'MARVENDA';
    MES2 = 'ABRVENDA';
    MES3 = 'MAIVENDA';
  END
 ELSE
 IF (:MES = 7) THEN
  BEGIN
    MES1 = 'ABRVENDA';
    MES2 = 'MAIVENDA';
    MES3 = 'JUNVENDA';
  END
 ELSE
 IF (:MES = 8) THEN
  BEGIN
    MES1 = 'MAIVENDA';
    MES2 = 'JUNVENDA';
    MES3 = 'JULVENDA';
  END
 ELSE
 IF (:MES = 9) THEN
  BEGIN
    MES1 = 'JUNVENDA';
    MES2 = 'JULVENDA';
    MES3 = 'AGOVENDA';
  END
 ELSE
 IF (:MES = 10) THEN
  BEGIN
    MES1 = 'JULVENDA';
    MES2 = 'AGOVENDA';
    MES3 = 'SETVENDA';
  END
 ELSE
 IF (:MES = 11) THEN
  BEGIN
    MES1 = 'AGOVENDA';
    MES2 = 'SETVENDA';
    MES3 = 'OUTVENDA';
  END
 ELSE
 IF (:MES = 12) THEN
  BEGIN
    MES1 = 'SETVENDA';
    MES2 = 'OUTVENDA';
    MES3 = 'NOVVENDA';
  END

 FOR
   SELECT
     CD_GRUPO,
     SIGLA,
     P1,
     P2,
     P1SAZ,
     P2SAZ
   FROM
     GRUPOS_CURVAS
   WHERE
     CD_FILIAL = :FILIAL
   INTO
     :GRUPO,
     :SIGLA,
     :P1,
     :P2,
     :P1SAZ,
     :P2SAZ
 DO
  BEGIN
     COMANDO = 'SELECT PRODUTOS.ID_PRODUTO, PRODUTOS.SAZONAL, ' ||
               ' PRODUTOS_TOTAIS.'||:MES1||', PRODUTOS_TOTAIS.'||:MES2||', PRODUTOS_TOTAIS.'||:MES3||
               ' FROM PRODUTOS, PRODUTOS_TOTAIS WHERE ' ||
               ' PRODUTOS_TOTAIS.CD_FILIAL = ' ||CAST(:FILIAL AS INTEGER) || ' AND ' ||
               ' PRODUTOS_TOTAIS.ID_PRODUTO = PRODUTOS.ID_PRODUTO AND ' ||
               ' PRODUTOS.CD_GRUPO = '||CAST(:GRUPO AS INTEGER)|| ' AND ' ||
               ' PRODUTOS.CURVA_UNITARIA_'||CAST(:FILIAL AS INTEGER)||' = '''||:SIGLA||'''';
   FOR
      EXECUTE STATEMENT :COMANDO INTO :PRODUTO, :SAZONAL, :VMES1, :VMES2, :VMES3
   DO
    BEGIN
      IF ((:P1 IS NULL) OR (:P1 = 0)) THEN
         P1 = 0.5;
      IF ((:P2 IS NULL) OR (:P2 = 0)) THEN
         P2 = 0.5;
      IF ((:P1SAZ IS NULL) OR (:P1SAZ = 0)) THEN
         P1SAZ = 0.5;
      IF ((:P2SAZ IS NULL) OR (:P2SAZ = 0)) THEN
         P2SAZ = 0.5;

      IF (:SAZONAL = 'S') THEN
       BEGIN
         SELECT JANSAZ, FEVSAZ, MARSAZ, ABRSAZ, MAISAZ, JUNSAZ, JULSAZ, AGOSAZ, SETSAZ, OUTSAZ, NOVSAZ, DEZSAZ
         FROM PRODUTOS WHERE ID_PRODUTO = :PRODUTO
         INTO :JANSAZ, :FEVSAZ, :MARSAZ, :ABRSAZ, :MAISAZ, :JUNSAZ, :JULSAZ, :AGOSAZ, :SETSAZ, :OUTSAZ, :NOVSAZ, :DEZSAZ;
       END

      PSAZONAL = 'N';
      IF (:SAZONAL = 'S') THEN
       BEGIN
         MESATUAL = EXTRACT(MONTH FROM CURRENT_DATE);
         IF ((:MESATUAL = 1) AND (:JANSAZ = 'S')) THEN
            PSAZONAL = 'S';
         ELSE
         IF ((:MESATUAL = 2) AND (:FEVSAZ = 'S')) THEN
            PSAZONAL = 'S';
         ELSE
         IF ((:MESATUAL = 3) AND (:MARSAZ = 'S')) THEN
            PSAZONAL = 'S';
         ELSE
         IF ((:MESATUAL = 4) AND (:ABRSAZ = 'S')) THEN
            PSAZONAL = 'S';
         ELSE
         IF ((:MESATUAL = 5) AND (:MAISAZ = 'S')) THEN
            PSAZONAL = 'S';
         ELSE
         IF ((:MESATUAL = 6) AND (:JUNSAZ = 'S')) THEN
            PSAZONAL = 'S';
         ELSE
         IF ((:MESATUAL = 7) AND (:JULSAZ = 'S')) THEN
            PSAZONAL = 'S';
         ELSE
         IF ((:MESATUAL = 8) AND (:AGOSAZ = 'S')) THEN
            PSAZONAL = 'S';
         ELSE
         IF ((:MESATUAL = 9) AND (:SETSAZ = 'S')) THEN
            PSAZONAL = 'S';
         ELSE
         IF ((:MESATUAL = 10) AND (:OUTSAZ = 'S')) THEN
            PSAZONAL = 'S';
         ELSE
         IF ((:MESATUAL = 11) AND (:NOVSAZ = 'S')) THEN
            PSAZONAL = 'S';
         ELSE
         IF ((:MESATUAL = 12) AND (:DEZSAZ = 'S')) THEN
            PSAZONAL = 'S';
       END

      SELECT
       SUM(QUANTIDADE)
      FROM
       LANCAMENTOS
      WHERE
       DATA_LANCAMENTO >= CURRENT_DATE - 31 AND
       DATA_LANCAMENTO < CURRENT_DATE AND
       CD_FILIAL = :FILIAL AND
       TIPO_VENDA = 'V' AND
       ID_PRODUTO = :PRODUTO
      INTO
       :MEDIA2;

      IF (:MEDIA2 IS NULL) THEN
         MEDIA2 = 0;

      MEDIA1 = (:VMES1 + :VMES2 + :VMES3) / 3;

      IF (:PSAZONAL = 'N') THEN
         MEDIA3M = (P1 * MEDIA1) + (P2 * MEDIA2);
      ELSE
         MEDIA3M = (P1SAZ * MEDIA1) + (P2SAZ * MEDIA2);

      PICO = MEDIA3M + (MEDIA3M * PPV);
      VALE = MEDIA3M - (MEDIA3M * PPV);

      IF (:VMES1 > :PICO) THEN
       BEGIN
         VMES1 = :PICO;
       END
      ELSE
      IF (:VMES1 < :VALE) THEN
       BEGIN
         VMES1 = :VALE;
       END

      IF (:VMES2 > :PICO) THEN
       BEGIN
         VMES2 = :PICO;
       END
      ELSE
      IF (:VMES2 < :VALE) THEN
       BEGIN
         VMES2 = :VALE;
       END

      IF (:VMES3 > :PICO) THEN
       BEGIN
         VMES3 = :PICO;
       END
      ELSE
      IF (:VMES3 < :VALE) THEN
       BEGIN
         VMES3 = :VALE;
       END

      MEDIA1 = (:VMES1 + :VMES2 + :VMES3) / 3;
      IF (:PSAZONAL = 'N') THEN
         MEDIAF = (P1 * MEDIA1) + (P2 * MEDIA2);
      ELSE
         MEDIAF = (P1SAZ * MEDIA1) + (P2SAZ * MEDIA2);

      MEDIAF = CAST((MEDIAF) AS NUMERIC(9,3));

      COMANDOUPDATE = 'UPDATE PRODUTOS SET MEDIAF_'||CAST(:FILIAL AS INTEGER)||' = '||:MEDIAF ||
                      ', ENVIADO = '''||''||''' WHERE ID_PRODUTO = '||CAST(:PRODUTO AS INTEGER);
      EXECUTE STATEMENT :COMANDOUPDATE;
    END
  END
END ^

ALTER PROCEDURE SP_CALCULA_MEDIAF_ESEG_EMAX (FILIAL DOUBLE PRECISION)
AS 
DECLARE VARIABLE MES INTEGER;
DECLARE VARIABLE PRODUTO DOUBLE PRECISION;
DECLARE VARIABLE GRUPO DOUBLE PRECISION;
DECLARE VARIABLE COMANDO VARCHAR(1000);
DECLARE VARIABLE COMANDOUPDATE VARCHAR(1000);
DECLARE VARIABLE MES1 VARCHAR(10);
DECLARE VARIABLE MES2 VARCHAR(10);
DECLARE VARIABLE MES3 VARCHAR(10);
DECLARE VARIABLE SIGLA VARCHAR(1);
DECLARE VARIABLE MEDIA1 DOUBLE PRECISION;
DECLARE VARIABLE MEDIA2 DOUBLE PRECISION;
DECLARE VARIABLE MEDIA3M DOUBLE PRECISION;
DECLARE VARIABLE P1 DOUBLE PRECISION;
DECLARE VARIABLE P2 DOUBLE PRECISION;
DECLARE VARIABLE P1SAZ DOUBLE PRECISION;
DECLARE VARIABLE P2SAZ DOUBLE PRECISION;
DECLARE VARIABLE PPV DOUBLE PRECISION;
DECLARE VARIABLE PICO DOUBLE PRECISION;
DECLARE VARIABLE VALE DOUBLE PRECISION;
DECLARE VARIABLE VMES1 DOUBLE PRECISION;
DECLARE VARIABLE VMES2 DOUBLE PRECISION;
DECLARE VARIABLE VMES3 DOUBLE PRECISION;
DECLARE VARIABLE MEDIAF DOUBLE PRECISION;
DECLARE VARIABLE SAZONAL VARCHAR(1);
DECLARE VARIABLE JANSAZ VARCHAR(1);
DECLARE VARIABLE FEVSAZ VARCHAR(1);
DECLARE VARIABLE MARSAZ VARCHAR(1);
DECLARE VARIABLE ABRSAZ VARCHAR(1);
DECLARE VARIABLE MAISAZ VARCHAR(1);
DECLARE VARIABLE JUNSAZ VARCHAR(1);
DECLARE VARIABLE JULSAZ VARCHAR(1);
DECLARE VARIABLE AGOSAZ VARCHAR(1);
DECLARE VARIABLE SETSAZ VARCHAR(1);
DECLARE VARIABLE OUTSAZ VARCHAR(1);
DECLARE VARIABLE NOVSAZ VARCHAR(1);
DECLARE VARIABLE DEZSAZ VARCHAR(1);
DECLARE VARIABLE MESATUAL VARCHAR(2);
DECLARE VARIABLE PSAZONAL VARCHAR(1);
DECLARE VARIABLE QMININTEIRO INTEGER;
DECLARE VARIABLE QMAXINTEIRO INTEGER;
DECLARE VARIABLE PERIODOMINIMO DOUBLE PRECISION;
DECLARE VARIABLE PERIODOMAXIMO DOUBLE PRECISION;
DECLARE VARIABLE QMIN INTEGER;
DECLARE VARIABLE QMAX INTEGER;
BEGIN
 PPV = 0.5;
 IF (:FILIAL = 0) THEN EXIT;
 MES = EXTRACT(MONTH FROM CURRENT_DATE);

 COMANDO = 'UPDATE PRODUTOS SET MEDIAF_'||CAST(:FILIAL AS INTEGER)||' = 0, '||
                               'ESTOQUE_MINIMO_'||CAST(:FILIAL AS INTEGER)||' = 0, ' ||
                               'ESTOQUE_MAXIMO_'||CAST(:FILIAL AS INTEGER)||' = 0';
 EXECUTE STATEMENT :COMANDO;

 IF (:MES = 1) THEN
  BEGIN
    MES1 = 'OUTVENDA';
    MES2 = 'NOVVENDA';
    MES3 = 'DEZVENDA';
  END
 ELSE
 IF (:MES = 2) THEN
  BEGIN
    MES1 = 'NOVVENDA';
    MES2 = 'DEZVENDA';
    MES3 = 'JANVENDA';
  END
 ELSE
 IF (:MES = 3) THEN
  BEGIN
    MES1 = 'DEZVENDA';
    MES2 = 'JANVENDA';
    MES3 = 'FEVVENDA';
  END
 ELSE
 IF (:MES = 4) THEN
  BEGIN
    MES1 = 'JANVENDA';
    MES2 = 'FEVVENDA';
    MES3 = 'MARVENDA';
  END
 ELSE
 IF (:MES = 5) THEN
  BEGIN
    MES1 = 'FEVVENDA';
    MES2 = 'MARVENDA';
    MES3 = 'ABRVENDA';
  END
 ELSE
 IF (:MES = 6) THEN
  BEGIN
    MES1 = 'MARVENDA';
    MES2 = 'ABRVENDA';
    MES3 = 'MAIVENDA';
  END
 ELSE
 IF (:MES = 7) THEN
  BEGIN
    MES1 = 'ABRVENDA';
    MES2 = 'MAIVENDA';
    MES3 = 'JUNVENDA';
  END
 ELSE
 IF (:MES = 8) THEN
  BEGIN
    MES1 = 'MAIVENDA';
    MES2 = 'JUNVENDA';
    MES3 = 'JULVENDA';
  END
 ELSE
 IF (:MES = 9) THEN
  BEGIN
    MES1 = 'JUNVENDA';
    MES2 = 'JULVENDA';
    MES3 = 'AGOVENDA';
  END
 ELSE
 IF (:MES = 10) THEN
  BEGIN
    MES1 = 'JULVENDA';
    MES2 = 'AGOVENDA';
    MES3 = 'SETVENDA';
  END
 ELSE
 IF (:MES = 11) THEN
  BEGIN
    MES1 = 'AGOVENDA';
    MES2 = 'SETVENDA';
    MES3 = 'OUTVENDA';
  END
 ELSE
 IF (:MES = 12) THEN
  BEGIN
    MES1 = 'SETVENDA';
    MES2 = 'OUTVENDA';
    MES3 = 'NOVVENDA';
  END

 FOR
   SELECT
     CD_GRUPO,
     SIGLA,
     P1,
     P2,
     P1SAZ,
     P2SAZ,
     ESEG,
     DIASESTOQUE
   FROM
     GRUPOS_CURVAS
   WHERE
     CD_FILIAL = :FILIAL
   INTO
     :GRUPO,
     :SIGLA,
     :P1,
     :P2,
     :P1SAZ,
     :P2SAZ,
     :PERIODOMINIMO,
     :PERIODOMAXIMO
 DO
  BEGIN
     COMANDO = 'SELECT PRODUTOS.ID_PRODUTO, PRODUTOS.SAZONAL, ' ||
               ' PRODUTOS_TOTAIS.'||:MES1||', PRODUTOS_TOTAIS.'||:MES2||', PRODUTOS_TOTAIS.'||:MES3||
               ' FROM PRODUTOS, PRODUTOS_TOTAIS '||
               ' WHERE ' ||
               ' PRODUTOS_TOTAIS.CD_FILIAL = ' ||CAST(:FILIAL AS INTEGER) || ' AND ' ||
               ' PRODUTOS_TOTAIS.ID_PRODUTO = PRODUTOS.ID_PRODUTO AND ' ||
               ' PRODUTOS.CD_GRUPO = '||CAST(:GRUPO AS INTEGER)|| ' AND ' ||
               ' PRODUTOS.CURVA_UNITARIA_'||CAST(:FILIAL AS INTEGER)||' = '''||:SIGLA||'''';
   FOR
      EXECUTE STATEMENT :COMANDO INTO :PRODUTO, :SAZONAL, :VMES1, :VMES2, :VMES3
   DO
    BEGIN
      IF ((:P1 IS NULL) OR (:P1 = 0)) THEN
         P1 = 0.5;
      IF ((:P2 IS NULL) OR (:P2 = 0)) THEN
         P2 = 0.5;
      IF ((:P1SAZ IS NULL) OR (:P1SAZ = 0)) THEN
         P1SAZ = 0.5;
      IF ((:P2SAZ IS NULL) OR (:P2SAZ = 0)) THEN
         P2SAZ = 0.5;

      IF (:SAZONAL = 'S') THEN
       BEGIN
         SELECT JANSAZ, FEVSAZ, MARSAZ, ABRSAZ, MAISAZ, JUNSAZ, JULSAZ, AGOSAZ, SETSAZ, OUTSAZ, NOVSAZ, DEZSAZ
         FROM PRODUTOS WHERE ID_PRODUTO = :PRODUTO
         INTO :JANSAZ, :FEVSAZ, :MARSAZ, :ABRSAZ, :MAISAZ, :JUNSAZ, :JULSAZ, :AGOSAZ, :SETSAZ, :OUTSAZ, :NOVSAZ, :DEZSAZ;
       END

      PSAZONAL = 'N';
      IF (:SAZONAL = 'S') THEN
       BEGIN
         MESATUAL = EXTRACT(MONTH FROM CURRENT_DATE);
         IF ((:MESATUAL = 1) AND (:JANSAZ = 'S')) THEN
            PSAZONAL = 'S';
         ELSE
         IF ((:MESATUAL = 2) AND (:FEVSAZ = 'S')) THEN
            PSAZONAL = 'S';
         ELSE
         IF ((:MESATUAL = 3) AND (:MARSAZ = 'S')) THEN
            PSAZONAL = 'S';
         ELSE
         IF ((:MESATUAL = 4) AND (:ABRSAZ = 'S')) THEN
            PSAZONAL = 'S';
         ELSE
         IF ((:MESATUAL = 5) AND (:MAISAZ = 'S')) THEN
            PSAZONAL = 'S';
         ELSE
         IF ((:MESATUAL = 6) AND (:JUNSAZ = 'S')) THEN
            PSAZONAL = 'S';
         ELSE
         IF ((:MESATUAL = 7) AND (:JULSAZ = 'S')) THEN
            PSAZONAL = 'S';
         ELSE
         IF ((:MESATUAL = 8) AND (:AGOSAZ = 'S')) THEN
            PSAZONAL = 'S';
         ELSE
         IF ((:MESATUAL = 9) AND (:SETSAZ = 'S')) THEN
            PSAZONAL = 'S';
         ELSE
         IF ((:MESATUAL = 10) AND (:OUTSAZ = 'S')) THEN
            PSAZONAL = 'S';
         ELSE
         IF ((:MESATUAL = 11) AND (:NOVSAZ = 'S')) THEN
            PSAZONAL = 'S';
         ELSE
         IF ((:MESATUAL = 12) AND (:DEZSAZ = 'S')) THEN
            PSAZONAL = 'S';
       END

      SELECT
       SUM(QUANTIDADE)
      FROM
       LANCAMENTOS
      WHERE
       DATA_LANCAMENTO >= CURRENT_DATE - 31 AND
       DATA_LANCAMENTO < CURRENT_DATE AND
       CD_FILIAL = :FILIAL AND
       TIPO_VENDA = 'V' AND
       ID_PRODUTO = :PRODUTO
      INTO
       :MEDIA2;

      IF (:MEDIA2 IS NULL) THEN
         MEDIA2 = 0;

      MEDIA1 = (:VMES1 + :VMES2 + :VMES3) / 3;

      IF (:PSAZONAL = 'N') THEN
         MEDIA3M = (P1 * MEDIA1) + (P2 * MEDIA2);
      ELSE
         MEDIA3M = (P1SAZ * MEDIA1) + (P2SAZ * MEDIA2);

      PICO = MEDIA3M + (MEDIA3M * PPV);
      VALE = MEDIA3M - (MEDIA3M * PPV);

      IF (:VMES1 > :PICO) THEN
         VMES1 = :PICO;
      ELSE
      IF (:VMES1 < :VALE) THEN
         VMES1 = :VALE;

      IF (:VMES2 > :PICO) THEN
         VMES2 = :PICO;
      ELSE
      IF (:VMES2 < :VALE) THEN
         VMES2 = :VALE;

      IF (:VMES3 > :PICO) THEN
         VMES3 = :PICO;
      ELSE
      IF (:VMES3 < :VALE) THEN
         VMES3 = :VALE;

      MEDIA1 = (:VMES1 + :VMES2 + :VMES3) / 3;
      IF (:PSAZONAL = 'N') THEN
         MEDIAF = (P1 * MEDIA1) + (P2 * MEDIA2);
      ELSE
         MEDIAF = (P1SAZ * MEDIA1) + (P2SAZ * MEDIA2);

      MEDIAF = CAST((MEDIAF) AS NUMERIC(9,3));

      --CALCULO DOS ESTOQUES DE SEGURANCA E MAXIMO
       IF ((:PERIODOMINIMO IS NOT NULL) AND (:PERIODOMINIMO > 0) AND
           (:PERIODOMAXIMO IS NOT NULL) AND (:PERIODOMAXIMO > 0)) THEN
        BEGIN
          IF ((:MEDIAF < 0) OR (:MEDIAF IS NULL))  THEN
              MEDIAF = 0;
          QMIN = (:MEDIAF / 30) * :PERIODOMINIMO;
          QMAX = (:MEDIAF / 30) * :PERIODOMAXIMO;
          IF ((:QMIN < 0) OR (:QMIN IS NULL)) THEN
             QMIN = 0;
          IF ((:QMAX < 0) OR (:QMAX IS NULL)) THEN
             QMAX = 0;
  
          QMININTEIRO = CAST(:QMIN AS INTEGER);
          QMIN = :QMIN - :QMININTEIRO;
          IF (:QMIN > 0.5) THEN
             QMIN = CAST((:QMININTEIRO + 1) AS FLOAT);
          ELSE
             QMIN = CAST(:QMININTEIRO AS FLOAT);

          QMAXINTEIRO = CAST(:QMAX AS INTEGER);
          QMAX = :QMAX - :QMAXINTEIRO;
          IF (:QMAX > 0.5) THEN
             QMAX = CAST((:QMAXINTEIRO + 1) AS FLOAT);
          ELSE
             QMAX = CAST(:QMAXINTEIRO AS FLOAT);
        END

      COMANDOUPDATE = 'UPDATE PRODUTOS SET MEDIAF_'||CAST(:FILIAL AS INTEGER)||' = '||:MEDIAF ||
                      ', ESTOQUE_MINIMO_'||CAST(:FILIAL AS INTEGER)||' = '||:QMIN ||
                      ', ESTOQUE_MAXIMO_'||CAST(:FILIAL AS INTEGER)||' = '||:QMAX ||
                      ', ENVIADO = '''||''||''' WHERE ID_PRODUTO = '||CAST(:PRODUTO AS INTEGER);

      EXECUTE STATEMENT :COMANDOUPDATE;
    END
  END
END ^

ALTER PROCEDURE SP_CALCULA_MEDIAF_ITEM (FILIAL DOUBLE PRECISION,
MES INTEGER,
ID DOUBLE PRECISION)
AS 
declare variable PRODUTO double precision;
declare variable GRUPO double precision;
declare variable COMANDO varchar(1000);
declare variable COMANDOUPDATE varchar(1000);
declare variable MES1 varchar(10);
declare variable MES2 varchar(10);
declare variable MES3 varchar(10);
declare variable SIGLA varchar(1);
declare variable MEDIA1 double precision;
declare variable MEDIA2 double precision;
declare variable MEDIA3M double precision;
declare variable P1 double precision;
declare variable P2 double precision;
declare variable P1SAZ double precision;
declare variable P2SAZ double precision;
declare variable PPV double precision;
declare variable PICO double precision;
declare variable VALE double precision;
declare variable VMES1 double precision;
declare variable VMES2 double precision;
declare variable VMES3 double precision;
declare variable MEDIAF double precision;
declare variable SAZONAL varchar(1);
declare variable JANSAZ varchar(1);
declare variable FEVSAZ varchar(1);
declare variable MARSAZ varchar(1);
declare variable ABRSAZ varchar(1);
declare variable MAISAZ varchar(1);
declare variable JUNSAZ varchar(1);
declare variable JULSAZ varchar(1);
declare variable AGOSAZ varchar(1);
declare variable SETSAZ varchar(1);
declare variable OUTSAZ varchar(1);
declare variable NOVSAZ varchar(1);
declare variable DEZSAZ varchar(1);
declare variable MESATUAL varchar(2);
declare variable PSAZONAL varchar(1);
BEGIN
 PPV = 0.5;
 COMANDO = 'UPDATE PRODUTOS SET MEDIAF_'||CAST(:FILIAL AS INTEGER)||' = 0 WHERE ID_PRODUTO = '||:ID;
 --EXECUTE STATEMENT :COMANDO;

 IF (:MES = 1) THEN
  BEGIN
    MES1 = 'OUTVENDA';
    MES2 = 'NOVVENDA';
    MES3 = 'DEZVENDA';
  END
 ELSE
 IF (:MES = 2) THEN
  BEGIN
    MES1 = 'NOVVENDA';
    MES2 = 'DEZVENDA';
    MES3 = 'JANVENDA';
  END
 ELSE
 IF (:MES = 3) THEN
  BEGIN
    MES1 = 'DEZVENDA';
    MES2 = 'JANVENDA';
    MES3 = 'FEVVENDA';
  END
 ELSE
 IF (:MES = 4) THEN
  BEGIN
    MES1 = 'JANVENDA';
    MES2 = 'FEVVENDA';
    MES3 = 'MARVENDA';
  END
 ELSE
 IF (:MES = 5) THEN
  BEGIN
    MES1 = 'FEVVENDA';
    MES2 = 'MARVENDA';
    MES3 = 'ABRVENDA';
  END
 ELSE
 IF (:MES = 6) THEN
  BEGIN
    MES1 = 'MARVENDA';
    MES2 = 'ABRVENDA';
    MES3 = 'MAIVENDA';
  END
 ELSE
 IF (:MES = 7) THEN
  BEGIN
    MES1 = 'ABRVENDA';
    MES2 = 'MAIVENDA';
    MES3 = 'JUNVENDA';
  END
 ELSE
 IF (:MES = 8) THEN
  BEGIN
    MES1 = 'MAIVENDA';
    MES2 = 'JUNVENDA';
    MES3 = 'JULVENDA';
  END
 ELSE
 IF (:MES = 9) THEN
  BEGIN
    MES1 = 'JUNVENDA';
    MES2 = 'JULVENDA';
    MES3 = 'AGOVENDA';
  END
 ELSE
 IF (:MES = 10) THEN
  BEGIN
    MES1 = 'JULVENDA';
    MES2 = 'AGOVENDA';
    MES3 = 'SETVENDA';
  END
 ELSE
 IF (:MES = 11) THEN
  BEGIN
    MES1 = 'AGOVENDA';
    MES2 = 'SETVENDA';
    MES3 = 'OUTVENDA';
  END
 ELSE
 IF (:MES = 12) THEN
  BEGIN
    MES1 = 'SETVENDA';
    MES2 = 'OUTVENDA';
    MES3 = 'NOVVENDA';
  END

   COMANDO = 'SELECT PRODUTOS.ID_PRODUTO, PRODUTOS.CD_GRUPO, PRODUTOS.CURVA_UNITARIA_'||CAST(:FILIAL AS INTEGER)||', PRODUTOS.SAZONAL, ' ||
             ' PRODUTOS_TOTAIS.'||:MES1||', PRODUTOS_TOTAIS.'||:MES2||', PRODUTOS_TOTAIS.'||:MES3||
             ' FROM PRODUTOS, PRODUTOS_TOTAIS WHERE ' ||
             ' PRODUTOS.ID_PRODUTO = ' ||CAST(:ID AS INTEGER) || ' AND ' ||
             ' PRODUTOS_TOTAIS.CD_FILIAL = ' ||CAST(:FILIAL AS INTEGER) || ' AND ' ||
             ' PRODUTOS_TOTAIS.ID_PRODUTO = PRODUTOS.ID_PRODUTO';
   FOR
      EXECUTE STATEMENT :COMANDO INTO :PRODUTO, :GRUPO, :SIGLA, :SAZONAL, :VMES1, :VMES2, :VMES3
   DO
    BEGIN
       SELECT
         P1,
         P2,
         P1SAZ,
         P2SAZ
       FROM
         GRUPOS_CURVAS
       WHERE
         CD_FILIAL = :FILIAL AND CD_GRUPO = :GRUPO AND SIGLA = :SIGLA
       INTO
         :P1,
         :P2,
         :P1SAZ,
         :P2SAZ;

      IF ((:P1 IS NULL) OR (:P1 = 0)) THEN
         P1 = 0.5;
      IF ((:P2 IS NULL) OR (:P2 = 0)) THEN
         P2 = 0.5;
      IF ((:P1SAZ IS NULL) OR (:P1SAZ = 0)) THEN
         P1SAZ = 0.5;
      IF ((:P2SAZ IS NULL) OR (:P2SAZ = 0)) THEN
         P2SAZ = 0.5;

      IF (:SAZONAL = 'S') THEN
       BEGIN
         SELECT JANSAZ, FEVSAZ, MARSAZ, ABRSAZ, MAISAZ, JUNSAZ, JULSAZ, AGOSAZ, SETSAZ, OUTSAZ, NOVSAZ, DEZSAZ
         FROM PRODUTOS WHERE ID_PRODUTO = :PRODUTO
         INTO :JANSAZ, :FEVSAZ, :MARSAZ, :ABRSAZ, :MAISAZ, :JUNSAZ, :JULSAZ, :AGOSAZ, :SETSAZ, :OUTSAZ, :NOVSAZ, :DEZSAZ;
       END

      PSAZONAL = 'N';
      IF (:SAZONAL = 'S') THEN
       BEGIN
         MESATUAL = EXTRACT(MONTH FROM CURRENT_DATE);
         IF ((:MESATUAL = 1) AND (:JANSAZ = 'S')) THEN
            PSAZONAL = 'S';
         ELSE
         IF ((:MESATUAL = 2) AND (:FEVSAZ = 'S')) THEN
            PSAZONAL = 'S';
         ELSE
         IF ((:MESATUAL = 3) AND (:MARSAZ = 'S')) THEN
            PSAZONAL = 'S';
         ELSE
         IF ((:MESATUAL = 4) AND (:ABRSAZ = 'S')) THEN
            PSAZONAL = 'S';
         ELSE
         IF ((:MESATUAL = 5) AND (:MAISAZ = 'S')) THEN
            PSAZONAL = 'S';
         ELSE
         IF ((:MESATUAL = 6) AND (:JUNSAZ = 'S')) THEN
            PSAZONAL = 'S';
         ELSE
         IF ((:MESATUAL = 7) AND (:JULSAZ = 'S')) THEN
            PSAZONAL = 'S';
         ELSE
         IF ((:MESATUAL = 8) AND (:AGOSAZ = 'S')) THEN
            PSAZONAL = 'S';
         ELSE
         IF ((:MESATUAL = 9) AND (:SETSAZ = 'S')) THEN
            PSAZONAL = 'S';
         ELSE
         IF ((:MESATUAL = 10) AND (:OUTSAZ = 'S')) THEN
            PSAZONAL = 'S';
         ELSE
         IF ((:MESATUAL = 11) AND (:NOVSAZ = 'S')) THEN
            PSAZONAL = 'S';
         ELSE
         IF ((:MESATUAL = 12) AND (:DEZSAZ = 'S')) THEN
            PSAZONAL = 'S';
       END

      SELECT
       SUM(QUANTIDADE)
      FROM
       LANCAMENTOS
      WHERE
       DATA_LANCAMENTO >= CURRENT_DATE - 31 AND
       DATA_LANCAMENTO < CURRENT_DATE AND
       CD_FILIAL = :FILIAL AND
       TIPO_VENDA = 'V' AND
       ID_PRODUTO = :PRODUTO
      INTO
       :MEDIA2;

      IF (:MEDIA2 IS NULL) THEN
         MEDIA2 = 0;

      MEDIA1 = (:VMES1 + :VMES2 + :VMES3) / 3;

      IF (:PSAZONAL = 'N') THEN
         MEDIA3M = (P1 * MEDIA1) + (P2 * MEDIA2);
      ELSE
         MEDIA3M = (P1SAZ * MEDIA1) + (P2SAZ * MEDIA2);

      PICO = MEDIA3M + (MEDIA3M * PPV);
      VALE = MEDIA3M - (MEDIA3M * PPV);

      IF (:VMES1 > :PICO) THEN
       BEGIN
         VMES1 = :PICO;
       END
      ELSE
      IF (:VMES1 < :VALE) THEN
       BEGIN
         VMES1 = :VALE;
       END

      IF (:VMES2 > :PICO) THEN
       BEGIN
         VMES2 = :PICO;
       END
      ELSE
      IF (:VMES2 < :VALE) THEN
       BEGIN
         VMES2 = :VALE;
       END

      IF (:VMES3 > :PICO) THEN
       BEGIN
         VMES3 = :PICO;
       END
      ELSE
      IF (:VMES3 < :VALE) THEN
       BEGIN
         VMES3 = :VALE;
       END

      MEDIA1 = (:VMES1 + :VMES2 + :VMES3) / 3;
      IF (:PSAZONAL = 'N') THEN
         MEDIAF = (P1 * MEDIA1) + (P2 * MEDIA2);
      ELSE
         MEDIAF = (P1SAZ * MEDIA1) + (P2SAZ * MEDIA2);

      MEDIAF = CAST((MEDIAF) AS NUMERIC(9,3));

      COMANDOUPDATE = 'UPDATE PRODUTOS SET MEDIAF_'||CAST(:FILIAL AS INTEGER)||' = '||:MEDIAF ||
                      ', ENVIADO = '''||''||''' WHERE ID_PRODUTO = '||CAST(:PRODUTO AS INTEGER);
      --EXECUTE STATEMENT :COMANDOUPDATE;
    END
END ^

ALTER PROCEDURE SP_CALCULA_MEDIAF_SP AS 
DECLARE VARIABLE FILIAL DOUBLE PRECISION;
DECLARE VARIABLE MES INTEGER;
DECLARE VARIABLE PRODUTO DOUBLE PRECISION;
DECLARE VARIABLE GRUPO DOUBLE PRECISION;
DECLARE VARIABLE COMANDO VARCHAR(1000);
DECLARE VARIABLE COMANDOUPDATE VARCHAR(1000);
DECLARE VARIABLE MES1 VARCHAR(10);
DECLARE VARIABLE MES2 VARCHAR(10);
DECLARE VARIABLE MES3 VARCHAR(10);
DECLARE VARIABLE SIGLA VARCHAR(1);
DECLARE VARIABLE MEDIA1 DOUBLE PRECISION;
DECLARE VARIABLE MEDIA2 DOUBLE PRECISION;
DECLARE VARIABLE MEDIA3M DOUBLE PRECISION;
DECLARE VARIABLE P1 DOUBLE PRECISION;
DECLARE VARIABLE P2 DOUBLE PRECISION;
DECLARE VARIABLE P1SAZ DOUBLE PRECISION;
DECLARE VARIABLE P2SAZ DOUBLE PRECISION;
DECLARE VARIABLE PPV DOUBLE PRECISION;
DECLARE VARIABLE PICO DOUBLE PRECISION;
DECLARE VARIABLE VALE DOUBLE PRECISION;
DECLARE VARIABLE VMES1 DOUBLE PRECISION;
DECLARE VARIABLE VMES2 DOUBLE PRECISION;
DECLARE VARIABLE VMES3 DOUBLE PRECISION;
DECLARE VARIABLE MEDIAF DOUBLE PRECISION;
DECLARE VARIABLE SAZONAL VARCHAR(1);
DECLARE VARIABLE JANSAZ VARCHAR(1);
DECLARE VARIABLE FEVSAZ VARCHAR(1);
DECLARE VARIABLE MARSAZ VARCHAR(1);
DECLARE VARIABLE ABRSAZ VARCHAR(1);
DECLARE VARIABLE MAISAZ VARCHAR(1);
DECLARE VARIABLE JUNSAZ VARCHAR(1);
DECLARE VARIABLE JULSAZ VARCHAR(1);
DECLARE VARIABLE AGOSAZ VARCHAR(1);
DECLARE VARIABLE SETSAZ VARCHAR(1);
DECLARE VARIABLE OUTSAZ VARCHAR(1);
DECLARE VARIABLE NOVSAZ VARCHAR(1);
DECLARE VARIABLE DEZSAZ VARCHAR(1);
DECLARE VARIABLE MESATUAL VARCHAR(2);
DECLARE VARIABLE PSAZONAL VARCHAR(1);
BEGIN
 SELECT CD_FILIAL FROM PARAMETROS INTO :FILIAL;
 IF (:FILIAL = 0) THEN
    EXIT;
 MES = EXTRACT(MONTH FROM CURRENT_DATE);
 PPV = 0.5;
 COMANDO = 'UPDATE PRODUTOS SET MEDIAF_'||CAST(:FILIAL AS INTEGER)||' = 0';
 EXECUTE STATEMENT :COMANDO;

 IF (:MES = 1) THEN
  BEGIN
    MES1 = 'OUTVENDA';
    MES2 = 'NOVVENDA';
    MES3 = 'DEZVENDA';
  END
 ELSE
 IF (:MES = 2) THEN
  BEGIN
    MES1 = 'NOVVENDA';
    MES2 = 'DEZVENDA';
    MES3 = 'JANVENDA';
  END
 ELSE
 IF (:MES = 3) THEN
  BEGIN
    MES1 = 'DEZVENDA';
    MES2 = 'JANVENDA';
    MES3 = 'FEVVENDA';
  END
 ELSE
 IF (:MES = 4) THEN
  BEGIN
    MES1 = 'JANVENDA';
    MES2 = 'FEVVENDA';
    MES3 = 'MARVENDA';
  END
 ELSE
 IF (:MES = 5) THEN
  BEGIN
    MES1 = 'FEVVENDA';
    MES2 = 'MARVENDA';
    MES3 = 'ABRVENDA';
  END
 ELSE
 IF (:MES = 6) THEN
  BEGIN
    MES1 = 'MARVENDA';
    MES2 = 'ABRVENDA';
    MES3 = 'MAIVENDA';
  END
 ELSE
 IF (:MES = 7) THEN
  BEGIN
    MES1 = 'ABRVENDA';
    MES2 = 'MAIVENDA';
    MES3 = 'JUNVENDA';
  END
 ELSE
 IF (:MES = 8) THEN
  BEGIN
    MES1 = 'MAIVENDA';
    MES2 = 'JUNVENDA';
    MES3 = 'JULVENDA';
  END
 ELSE
 IF (:MES = 9) THEN
  BEGIN
    MES1 = 'JUNVENDA';
    MES2 = 'JULVENDA';
    MES3 = 'AGOVENDA';
  END
 ELSE
 IF (:MES = 10) THEN
  BEGIN
    MES1 = 'JULVENDA';
    MES2 = 'AGOVENDA';
    MES3 = 'SETVENDA';
  END
 ELSE
 IF (:MES = 11) THEN
  BEGIN
    MES1 = 'AGOVENDA';
    MES2 = 'SETVENDA';
    MES3 = 'OUTVENDA';
  END
 ELSE
 IF (:MES = 12) THEN
  BEGIN
    MES1 = 'SETVENDA';
    MES2 = 'OUTVENDA';
    MES3 = 'NOVVENDA';
  END

 FOR
   SELECT
     CD_GRUPO,
     SIGLA,
     P1,
     P2,
     P1SAZ,
     P2SAZ
   FROM
     GRUPOS_CURVAS
   WHERE
     CD_FILIAL = :FILIAL
   INTO
     :GRUPO,
     :SIGLA,
     :P1,
     :P2,
     :P1SAZ,
     :P2SAZ
 DO
  BEGIN
     COMANDO = 'SELECT PRODUTOS.ID_PRODUTO, PRODUTOS.SAZONAL, ' ||
               ' PRODUTOS_TOTAIS.'||:MES1||', PRODUTOS_TOTAIS.'||:MES2||', PRODUTOS_TOTAIS.'||:MES3||
               ' FROM PRODUTOS, PRODUTOS_TOTAIS WHERE ' ||
               ' PRODUTOS.CD_GRUPO = '||CAST(:GRUPO AS INTEGER)||
               ' AND PRODUTOS.CURVA_UNITARIA_'||CAST(:FILIAL AS INTEGER)||' = '''||:SIGLA||'''' ||
               ' AND PRODUTOS_TOTAIS.CD_FILIAL = ' ||CAST(:FILIAL AS INTEGER) ||
               ' AND PRODUTOS.ID_PRODUTO = PRODUTOS_TOTAIS.ID_PRODUTO';
   FOR
      EXECUTE STATEMENT :COMANDO INTO :PRODUTO, :SAZONAL, :VMES1, :VMES2, :VMES3
   DO
    BEGIN
      IF ((:P1 IS NULL) OR (:P1 = 0)) THEN
         P1 = 0.5;
      IF ((:P2 IS NULL) OR (:P2 = 0)) THEN
         P2 = 0.5;
      IF ((:P1SAZ IS NULL) OR (:P1SAZ = 0)) THEN
         P1SAZ = 0.5;
      IF ((:P2SAZ IS NULL) OR (:P2SAZ = 0)) THEN
         P2SAZ = 0.5;

      IF (:SAZONAL = 'S') THEN
       BEGIN
         SELECT JANSAZ, FEVSAZ, MARSAZ, ABRSAZ, MAISAZ, JUNSAZ, JULSAZ, AGOSAZ, SETSAZ, OUTSAZ, NOVSAZ, DEZSAZ
         FROM PRODUTOS WHERE ID_PRODUTO = :PRODUTO
         INTO :JANSAZ, :FEVSAZ, :MARSAZ, :ABRSAZ, :MAISAZ, :JUNSAZ, :JULSAZ, :AGOSAZ, :SETSAZ, :OUTSAZ, :NOVSAZ, :DEZSAZ;
       END

      PSAZONAL = 'N';
      IF (:SAZONAL = 'S') THEN
       BEGIN
         MESATUAL = EXTRACT(MONTH FROM CURRENT_DATE);
         IF ((:MESATUAL = 1) AND (:JANSAZ = 'S')) THEN
            PSAZONAL = 'S';
         ELSE
         IF ((:MESATUAL = 2) AND (:FEVSAZ = 'S')) THEN
            PSAZONAL = 'S';
         ELSE
         IF ((:MESATUAL = 3) AND (:MARSAZ = 'S')) THEN
            PSAZONAL = 'S';
         ELSE
         IF ((:MESATUAL = 4) AND (:ABRSAZ = 'S')) THEN
            PSAZONAL = 'S';
         ELSE
         IF ((:MESATUAL = 5) AND (:MAISAZ = 'S')) THEN
            PSAZONAL = 'S';
         ELSE
         IF ((:MESATUAL = 6) AND (:JUNSAZ = 'S')) THEN
            PSAZONAL = 'S';
         ELSE
         IF ((:MESATUAL = 7) AND (:JULSAZ = 'S')) THEN
            PSAZONAL = 'S';
         ELSE
         IF ((:MESATUAL = 8) AND (:AGOSAZ = 'S')) THEN
            PSAZONAL = 'S';
         ELSE
         IF ((:MESATUAL = 9) AND (:SETSAZ = 'S')) THEN
            PSAZONAL = 'S';
         ELSE
         IF ((:MESATUAL = 10) AND (:OUTSAZ = 'S')) THEN
            PSAZONAL = 'S';
         ELSE
         IF ((:MESATUAL = 11) AND (:NOVSAZ = 'S')) THEN
            PSAZONAL = 'S';
         ELSE
         IF ((:MESATUAL = 12) AND (:DEZSAZ = 'S')) THEN
            PSAZONAL = 'S';
       END

      SELECT
       SUM(QUANTIDADE)
      FROM
       LANCAMENTOS
      WHERE
       DATA_LANCAMENTO >= CURRENT_DATE - 31 AND
       DATA_LANCAMENTO < CURRENT_DATE AND
       CD_FILIAL = :FILIAL AND
       TIPO_VENDA = 'V' AND
       ID_PRODUTO = :PRODUTO
      INTO
       :MEDIA2;

      IF (:MEDIA2 IS NULL) THEN
         MEDIA2 = 0;

      MEDIA1 = (:VMES1 + :VMES2 + :VMES3) / 3;

      IF (:PSAZONAL = 'N') THEN
         MEDIA3M = (P1 * MEDIA1) + (P2 * MEDIA2);
      ELSE
         MEDIA3M = (P1SAZ * MEDIA1) + (P2SAZ * MEDIA2);

      PICO = MEDIA3M + (MEDIA3M * PPV);
      VALE = MEDIA3M - (MEDIA3M * PPV);

      IF (:VMES1 > :PICO) THEN
       BEGIN
         VMES1 = :PICO;
       END
      ELSE
      IF (:VMES1 < :VALE) THEN
       BEGIN
         VMES1 = :VALE;
       END

      IF (:VMES2 > :PICO) THEN
       BEGIN
         VMES2 = :PICO;
       END
      ELSE
      IF (:VMES2 < :VALE) THEN
       BEGIN
         VMES2 = :VALE;
       END

      IF (:VMES3 > :PICO) THEN
       BEGIN
         VMES3 = :PICO;
       END
      ELSE
      IF (:VMES3 < :VALE) THEN
       BEGIN
         VMES3 = :VALE;
       END

      MEDIA1 = (:VMES1 + :VMES2 + :VMES3) / 3;
      IF (:PSAZONAL = 'N') THEN
         MEDIAF = (P1 * MEDIA1) + (P2 * MEDIA2);
      ELSE
         MEDIAF = (P1SAZ * MEDIA1) + (P2SAZ * MEDIA2);

      MEDIAF = CAST((MEDIAF) AS NUMERIC(9,3));

      COMANDOUPDATE = 'UPDATE PRODUTOS SET MEDIAF_'||CAST(:FILIAL AS INTEGER)||' = '||:MEDIAF ||
                      ', ENVIADO = '''||''||''' WHERE ID_PRODUTO = '||CAST(:PRODUTO AS INTEGER);
      EXECUTE STATEMENT :COMANDOUPDATE;
    END
  END
END ^

ALTER PROCEDURE SP_CALCULA_MOVIMENTO_ESTOQUE (CD_FILIAL DOUBLE PRECISION,
DATA DATE)
RETURNS (ID_PRODUTO DOUBLE PRECISION,
QUANTIDADEENTRADA DOUBLE PRECISION,
QUANTIDADESAIDA DOUBLE PRECISION,
ESTOQUE DOUBLE PRECISION)
AS 
DECLARE VARIABLE COMANDO VARCHAR(1000);
BEGIN
  FOR
   SELECT
    LANCAMENTOS.ID_PRODUTO
   FROM
    LANCAMENTOS
   WHERE
    LANCAMENTOS.DATA_LANCAMENTO >= :DATA AND
    LANCAMENTOS.CD_FILIAL = :CD_FILIAL
   GROUP BY
    LANCAMENTOS.ID_PRODUTO
   INTO
    :ID_PRODUTO
  DO
   BEGIN
     ESTOQUE = 0;
     SELECT
       SUM(LANCAMENTOS.QUANTIDADE)
     FROM
       LANCAMENTOS
     WHERE
       LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
       LANCAMENTOS.ID_PRODUTO = :ID_PRODUTO AND
       LANCAMENTOS.DATA_LANCAMENTO >= :DATA AND
       LANCAMENTOS.ENTRADA_SAIDA = 'E'
     INTO
       :QUANTIDADEENTRADA;

     SELECT
       SUM(LANCAMENTOS.QUANTIDADE)
     FROM
       LANCAMENTOS
     WHERE
       LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
       LANCAMENTOS.ID_PRODUTO = :ID_PRODUTO AND
       LANCAMENTOS.DATA_LANCAMENTO >= :DATA AND
       LANCAMENTOS.ENTRADA_SAIDA = 'S'
     INTO
       :QUANTIDADESAIDA;

     IF (:QUANTIDADEENTRADA IS NULL) THEN
        QUANTIDADEENTRADA = 0;
     IF (:QUANTIDADESAIDA IS NULL) THEN
        QUANTIDADESAIDA = 0;

     ESTOQUE = :QUANTIDADEENTRADA - :QUANTIDADESAIDA;

     COMANDO = 'UPDATE PRODUTOS SET ESTOQUE_'||CAST(:CD_FILIAL AS INTEGER)||' = '||CAST(:ESTOQUE AS INTEGER)||' WHERE ID_PRODUTO = '||CAST(:ID_PRODUTO AS INTEGER);
     EXECUTE STATEMENT :COMANDO;

     SUSPEND;
   END
END ^

ALTER PROCEDURE SP_CALCULO_ESEG_TODOSMEDIAF (FILIAL DOUBLE PRECISION)
AS 
DECLARE VARIABLE PRODUTO DOUBLE PRECISION;
DECLARE VARIABLE MEDIAF DOUBLE PRECISION;
DECLARE VARIABLE QMININTEIRO INTEGER;
DECLARE VARIABLE QMAXINTEIRO INTEGER;
DECLARE VARIABLE PERIODOMINIMO DOUBLE PRECISION;
DECLARE VARIABLE PERIODOMAXIMO DOUBLE PRECISION;
DECLARE VARIABLE GRUPO DOUBLE PRECISION;
DECLARE VARIABLE COMANDO VARCHAR(255);
DECLARE VARIABLE COMANDOUPDATE VARCHAR(255);
DECLARE VARIABLE SIGLA VARCHAR(1);
DECLARE VARIABLE QMIN INTEGER;
DECLARE VARIABLE QMAX INTEGER;
BEGIN
 COMANDOUPDATE = 'UPDATE GRUPOS_CURVAS SET ESEG = 3 WHERE ESEG IS NULL OR ESEG = 0';
 EXECUTE STATEMENT :COMANDOUPDATE;

 COMANDOUPDATE = 'UPDATE PRODUTOS SET ESTOQUE_MINIMO_'||CAST(:FILIAL AS INTEGER)||' = 0';
 EXECUTE STATEMENT :COMANDOUPDATE;

 FOR
   SELECT
     CD_GRUPO,
     SIGLA,
     ESEG,
     DIASESTOQUE
   FROM
     GRUPOS_CURVAS
   WHERE
     CD_FILIAL = :FILIAL
   INTO
     :GRUPO,
     :SIGLA,
     :PERIODOMINIMO,
     :PERIODOMAXIMO
 DO
  BEGIN
     IF ((:PERIODOMINIMO IS NOT NULL) AND (:PERIODOMINIMO > 0) AND
         (:PERIODOMAXIMO IS NOT NULL) AND (:PERIODOMAXIMO > 0)) THEN
      BEGIN
           COMANDO = 'SELECT ID_PRODUTO, MEDIAF_'||CAST(:FILIAL AS INTEGER)||
                     ' FROM PRODUTOS WHERE CD_GRUPO = '||CAST(:GRUPO AS INTEGER)||
                     ' AND CURVA_UNITARIA_'||CAST(:FILIAL AS INTEGER)||' = '''||:SIGLA||'''';
         FOR
            EXECUTE STATEMENT :COMANDO INTO :PRODUTO, :MEDIAF
         DO
          BEGIN
            IF ((:MEDIAF < 0) OR (:MEDIAF IS NULL))  THEN
             BEGIN
                MEDIAF = 0;
             END
            QMIN = (:MEDIAF / 30) * :PERIODOMINIMO;
            QMAX = (:MEDIAF / 30) * :PERIODOMAXIMO;
            IF ((:QMIN < 0) OR (:QMIN IS NULL)) THEN
               QMIN = 0;
            IF ((:QMAX < 0) OR (:QMAX IS NULL)) THEN
               QMAX = 0;

            QMININTEIRO = CAST(:QMIN AS INTEGER);
            QMIN = :QMIN - :QMININTEIRO;
            IF (:QMIN > 0.5) THEN
             BEGIN
               QMIN = CAST((:QMININTEIRO + 1) AS FLOAT);
             END
            ELSE
             BEGIN
               QMIN = CAST(:QMININTEIRO AS FLOAT);
             END

            QMAXINTEIRO = CAST(:QMAX AS INTEGER);
            QMAX = :QMAX - :QMAXINTEIRO;
            IF (:QMAX > 0.5) THEN
             BEGIN
               QMAX = CAST((:QMAXINTEIRO + 1) AS FLOAT);
             END
            ELSE
             BEGIN
               QMAX = CAST(:QMAXINTEIRO AS FLOAT);
             END

            COMANDOUPDATE = 'UPDATE PRODUTOS SET ESTOQUE_MINIMO_'||CAST(:FILIAL AS INTEGER)||' = '||:QMIN ||
                            ', ESTOQUE_MAXIMO_'||CAST(:FILIAL AS INTEGER)||' = '||:QMAX ||
                            ', ENVIADO = '''||''||''' WHERE ID_PRODUTO = '||CAST(:PRODUTO AS INTEGER);
            EXECUTE STATEMENT :COMANDOUPDATE;
          END
      END
  END
END ^

