ALTER PROCEDURE SP_CANCELAMENTO_ITENS_CUPOM (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (CD_VENDA DOUBLE PRECISION,
DATA_CAIXA DATE,
ID_PRODUTO DOUBLE PRECISION,
CD_PRODUTO VARCHAR(6) CHARACTER SET NONE,
DESCRICAO VARCHAR(100) CHARACTER SET NONE,
PRECO_UNITARIO DOUBLE PRECISION,
QUANTIDADE DOUBLE PRECISION,
TX_DESCONTO DOUBLE PRECISION,
PRECO_TOTAL DOUBLE PRECISION,
TIPO_VENDA VARCHAR(1) CHARACTER SET NONE,
ORDEM DOUBLE PRECISION,
TERMINAL INTEGER)
AS 
BEGIN
  FOR
    SELECT
     DISTINCT CD_VENDA
    FROM
     VENDAS
    WHERE
     DATA_CAIXA >= :DATAINICIAL AND
     DATA_CAIXA <= :DATAFINAL AND
     TIPO_VENDA = 'Y'
    INTO
     :CD_VENDA
  DO
   BEGIN
    FOR
      SELECT
       DATA_CAIXA, ID_PRODUTO, CD_PRODUTO, DESCRICAO, TX_DESCONTO, TIPO_VENDA, ORDEM, TERMINAL, QUANTIDADE, PRECO_UNITARIO, PRECO_TOTAL
      FROM
       VENDAS
      WHERE
       CD_VENDA = :CD_VENDA
      INTO
       :DATA_CAIXA, :ID_PRODUTO, :CD_PRODUTO, :DESCRICAO, :TX_DESCONTO, :TIPO_VENDA, :ORDEM, :TERMINAL, :QUANTIDADE, :PRECO_UNITARIO, :PRECO_TOTAL
    DO
     BEGIN
       SUSPEND;
     END
   END
END ^

ALTER PROCEDURE SP_CODIFICA_NCM AS 
DECLARE VARIABLE CODIGO VARCHAR(10);
DECLARE VARIABLE DESCRICAO VARCHAR(500);
DECLARE VARIABLE ID DOUBLE PRECISION;
BEGIN
/*  FOR
    SELECT CODIGO, DESCRICAO FROM NCM INTO :CODIGO, :DESCRICAO
  DO
   BEGIN
      UPDATE CONTROLE SET VALOR = VALOR + 1 WHERE CAMPO = 'ID_NCM';
      SELECT VALOR FROM CONTROLE WHERE CAMPO = 'ID_NCM' INTO :ID;
      UPDATE NCM SET
       ID_NCM = :ID
      WHERE
       CODIGO = :CODIGO AND
       DESCRICAO = :DESCRICAO;
   END*/

  FOR
    SELECT ID_NCM FROM NCM INTO :ID
  DO
   BEGIN
      UPDATE NCM SET
       RAIZ = SUBSTRING(CODIGO FROM 1 FOR 4)
      WHERE
       ID_NCM = :ID;
   END

END ^

ALTER PROCEDURE SP_COMPARATIVO_VENDAS_COMPRAS (FILIAL DOUBLE PRECISION,
DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (DATA DATE,
VENDAS DOUBLE PRECISION,
QUANTIDADE_VENDIDA DOUBLE PRECISION,
NUMERO_DE_VENDAS DOUBLE PRECISION,
MEDIA_POR_CUPOM DOUBLE PRECISION,
MEDIA_POR_UNIDADE DOUBLE PRECISION,
COMPRAS DOUBLE PRECISION,
INDICE DOUBLE PRECISION,
TRANSFERENCIAS DOUBLE PRECISION,
TRANSFERENCIAS_SAIDA DOUBLE PRECISION,
TOTALENTRADA DOUBLE PRECISION,
TOTALSAIDA DOUBLE PRECISION)
AS 
declare variable VENDAS_C double precision;
declare variable NUMERO_DE_VENDAS_C integer;
declare variable QUANTIDADE_VENDIDA_C double precision;
declare variable CANCELAMENTOCOMPRAS double precision;
BEGIN
  FOR
    SELECT
      LANCAMENTOS.DATA_LANCAMENTO
    FROM
      LANCAMENTOS
    WHERE
      LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
      LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
      LANCAMENTOS.CD_FILIAL = :FILIAL
    GROUP BY
      LANCAMENTOS.DATA_LANCAMENTO
    INTO
      :DATA
  DO
   BEGIN
      COMPRAS = 0;
      VENDAS = 0;
      TRANSFERENCIAS = 0;
      TRANSFERENCIAS_SAIDA = 0;
      TOTALENTRADA = 0;
      INDICE = 0;
      QUANTIDADE_VENDIDA = 0;
      NUMERO_DE_VENDAS = 0;
      MEDIA_POR_CUPOM = 0;
      MEDIA_POR_UNIDADE = 0;
      VENDAS_C = 0;
      QUANTIDADE_VENDIDA_C = 0;
      NUMERO_DE_VENDAS_C = 0;

      SELECT
        SUM(LANCAMENTOS.CUSTO_UNITARIO * LANCAMENTOS.QUANTIDADE)
      FROM
        LANCAMENTOS
      WHERE
        LANCAMENTOS.DATA_LANCAMENTO = :DATA AND
        LANCAMENTOS.CD_FILIAL = :FILIAL AND
        LANCAMENTOS.TIPO_VENDA = 'C'
      INTO
        :COMPRAS;

      IF (:COMPRAS IS NULL) THEN
         COMPRAS = 0;

      SELECT
        SUM(LANCAMENTOS.CUSTO_UNITARIO * LANCAMENTOS.QUANTIDADE)
      FROM
        LANCAMENTOS
      WHERE
        LANCAMENTOS.DATA_LANCAMENTO = :DATA AND
        LANCAMENTOS.CD_FILIAL = :FILIAL AND
        LANCAMENTOS.TIPO_VENDA = 'E'
      INTO
        :CANCELAMENTOCOMPRAS;

      IF (:CANCELAMENTOCOMPRAS IS NULL) THEN
         CANCELAMENTOCOMPRAS = 0;

      COMPRAS = :COMPRAS - CANCELAMENTOCOMPRAS;
      /*IF (:COMPRAS < 0) THEN
         COMPRAS = 0;*/

      SELECT
        SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
        SUM(LANCAMENTOS.QUANTIDADE),
        COUNT(DISTINCT LANCAMENTOS.CD_VENDA)
      FROM
        LANCAMENTOS
      WHERE
        LANCAMENTOS.DATA_LANCAMENTO = :DATA AND
        LANCAMENTOS.CD_FILIAL = :FILIAL AND
        LANCAMENTOS.TIPO_VENDA = 'V'
      INTO
        :VENDAS,
        :QUANTIDADE_VENDIDA,
        :NUMERO_DE_VENDAS;

      IF (:VENDAS IS NULL) THEN
         VENDAS = 0;
      IF (:QUANTIDADE_VENDIDA IS NULL) THEN
         QUANTIDADE_VENDIDA = 0;
      IF (:NUMERO_DE_VENDAS IS NULL) THEN
         NUMERO_DE_VENDAS = 0;

      SELECT
        SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
        SUM(LANCAMENTOS.QUANTIDADE),
        COUNT(DISTINCT LANCAMENTOS.CD_VENDA)
      FROM
        LANCAMENTOS
      WHERE
        LANCAMENTOS.DATA_CAIXA = :DATA AND
        LANCAMENTOS.CD_FILIAL = :FILIAL AND
        LANCAMENTOS.TIPO_VENDA = 'D'
      INTO
        :VENDAS_C,
        :QUANTIDADE_VENDIDA_C,
        :NUMERO_DE_VENDAS_C;

      IF (:VENDAS_C IS NULL) THEN
          VENDAS_C = 0;
      IF (:QUANTIDADE_VENDIDA_C IS NULL) THEN
          QUANTIDADE_VENDIDA_C = 0;
      IF (:NUMERO_DE_VENDAS_C IS NULL) THEN
          NUMERO_DE_VENDAS_C = 0;

      VENDAS = :VENDAS - :VENDAS_C;
      QUANTIDADE_VENDIDA = :QUANTIDADE_VENDIDA - :QUANTIDADE_VENDIDA_C;
      NUMERO_DE_VENDAS = :NUMERO_DE_VENDAS - :NUMERO_DE_VENDAS_C;

      SELECT
        SUM(LANCAMENTOS.VALOR)
      FROM
        LANCAMENTOS
      WHERE
        LANCAMENTOS.DATA_LANCAMENTO = :DATA AND
        LANCAMENTOS.CD_FILIAL = :FILIAL AND
        LANCAMENTOS.TIPO_VENDA = 'T' AND
        LANCAMENTOS.ENTRADA_SAIDA = 'E'
      INTO
        :TRANSFERENCIAS;

      IF (:TRANSFERENCIAS IS NULL) THEN
         TRANSFERENCIAS = 0;

      TOTALENTRADA = :COMPRAS + :TRANSFERENCIAS;

      SELECT
        SUM(LANCAMENTOS.VALOR)
      FROM
        LANCAMENTOS
      WHERE
        LANCAMENTOS.DATA_LANCAMENTO = :DATA AND
        LANCAMENTOS.CD_FILIAL = :FILIAL AND
        LANCAMENTOS.TIPO_VENDA = 'T' AND
        LANCAMENTOS.ENTRADA_SAIDA = 'S'
      INTO
        :TRANSFERENCIAS_SAIDA;

      IF (:TRANSFERENCIAS_SAIDA IS NULL) THEN
         TRANSFERENCIAS_SAIDA = 0;

      TOTALENTRADA = :COMPRAS + :TRANSFERENCIAS;
      TOTALSAIDA = :VENDAS + :TRANSFERENCIAS_SAIDA;

      IF (:VENDAS > 0) THEN
       BEGIN
         INDICE = (:TOTALENTRADA * 100 )/(:TOTALSAIDA);
       END
      ELSE
       BEGIN
        INDICE = 0;
       END
      IF (:NUMERO_DE_VENDAS > 0) THEN
       BEGIN
         MEDIA_POR_CUPOM = :VENDAS / :NUMERO_DE_VENDAS;
       END
      ELSE
       BEGIN
         MEDIA_POR_CUPOM = 0;
       END
      IF (:QUANTIDADE_VENDIDA > 0) THEN
       BEGIN
         MEDIA_POR_UNIDADE = :VENDAS / :QUANTIDADE_VENDIDA;
       END
      ELSE
       BEGIN
         MEDIA_POR_UNIDADE = 0;
       END

      IF (:INDICE IS NULL) THEN
         INDICE = 0;
      IF (:QUANTIDADE_VENDIDA IS NULL) THEN
         QUANTIDADE_VENDIDA = 0;
      IF (:NUMERO_DE_VENDAS IS NULL) THEN
         NUMERO_DE_VENDAS = 0;
      IF (:MEDIA_POR_CUPOM IS NULL) THEN
         MEDIA_POR_CUPOM = 0;
      IF (:MEDIA_POR_UNIDADE IS NULL) THEN
         MEDIA_POR_UNIDADE = 0;

      SUSPEND;
   END
END ^

ALTER PROCEDURE SP_COMPARA_CAIXA_LANCAMENTO (DATA DATE)
RETURNS (CD_VENDA DOUBLE PRECISION,
LANCAMENTOS DOUBLE PRECISION,
CAIXA DOUBLE PRECISION,
DIFERENCA DOUBLE PRECISION)
AS 
BEGIN
 FOR
   SELECT
    CD_VENDA,
    SUM(VALOR)
   FROM
    LANCAMENTOS
   WHERE
    DATA_LANCAMENTO = :DATA AND
    (TIPO_VENDA = 'V' OR TROCA = 'T')
   GROUP BY
    CD_VENDA
   INTO
    :CD_VENDA,
    :LANCAMENTOS
 DO
  BEGIN
    SELECT
     SUM(VALOR+ARREDONDAMENTO)
    FROM
     CAIXA
    WHERE
     CD_VENDA = :CD_VENDA AND
     TIPO_VENDA = 'V' AND
     STATUS = 'A'
    INTO
     :CAIXA;
    DIFERENCA = :LANCAMENTOS - :CAIXA;
    IF (:DIFERENCA >= 0.001) THEN
     BEGIN
       /*UPDATE CAIXA SET
        ARREDONDAMENTO = :DIFERENCA
       WHERE
        CD_VENDA = :CD_VENDA;
     END*/
       SUSPEND;
     END
  END
END ^

ALTER PROCEDURE SP_COMPARA_PRODUTOS_FISCO AS 
declare variable ID_PRODUTO double precision;
declare variable NCM varchar(100);
declare variable CEST varchar(100);
declare variable SITUACAO varchar(100);
declare variable ALIQUOTA numeric(15,2);
declare variable SALIQUOTA varchar(10);
declare variable CST_ICMS varchar(10);
BEGIN
  FOR
    SELECT DISTINCT ID_PRODUTO, NCM, CEST, SITUACAO_TRIBUTARIA, ICMSSAIDA, CST_ICMS
    FROM PRODUTOS_FISCO
    INTO :ID_PRODUTO, :NCM, :CEST, :SITUACAO, :ALIQUOTA, :CST_ICMS
  DO
   BEGIN
     IF (:SITUACAO = 'F') THEN
        SALIQUOTA = 'FF';
     ELSE
     IF (:SITUACAO = 'N') THEN
        SALIQUOTA = 'NN';
     ELSE
     IF (:SITUACAO = 'I') THEN
        SALIQUOTA = 'II';
     ELSE
     IF (:SITUACAO = 'T') THEN
      BEGIN
        SALIQUOTA = CAST(:ALIQUOTA AS VARCHAR(100));
        SALIQUOTA = SUBSTRING(:ALIQUOTA FROM 1 FOR 2);
      END
     ELSE
        SALIQUOTA = 'FF';

     UPDATE PRODUTOS SET
      NCM = :NCM,
      CEST = :CEST,
      ICMS = :SALIQUOTA,
      SITUACAOTRIBUTARIA = :CST_ICMS
     WHERE ID_PRODUTO = :ID_PRODUTO;
   END
END ^

ALTER PROCEDURE SP_COMPARA_PRODUTOS_FISCO_PROD (ID_PRODUTO DOUBLE PRECISION)
AS 
declare variable NCM varchar(100);
declare variable CEST varchar(100);
declare variable SITUACAO varchar(100);
declare variable ALIQUOTA numeric(15,2);
declare variable SALIQUOTA varchar(10);
declare variable CST_ICMS varchar(10);
declare variable CFOP varchar(10);
BEGIN
  FOR
    SELECT DISTINCT CD_CFOP, NCM, CEST, SITUACAO_TRIBUTARIA, ICMSSAIDA, CST_ICMS
    FROM PRODUTOS_FISCO
    WHERE ID_PRODUTO = :ID_PRODUTO
    INTO :CFOP, :NCM, :CEST, :SITUACAO, :ALIQUOTA, :CST_ICMS
  DO
   BEGIN
     IF (:SITUACAO = 'F') THEN
        SALIQUOTA = 'FF';
     ELSE
     IF (:SITUACAO = 'N') THEN
        SALIQUOTA = 'NN';
     ELSE
     IF (:SITUACAO = 'I') THEN
        SALIQUOTA = 'II';
     ELSE
     IF (:SITUACAO = 'T') THEN
      BEGIN
        SALIQUOTA = CAST(:ALIQUOTA AS VARCHAR(100));
        SALIQUOTA = SUBSTRING(:ALIQUOTA FROM 1 FOR 2);
      END
     ELSE
        SALIQUOTA = 'FF';

     UPDATE PRODUTOS SET
      CD_CFOP = :CFOP, 
      NCM = :NCM,
      CEST = :CEST,
      ICMS = :SALIQUOTA,
      SITUACAOTRIBUTARIA = :CST_ICMS
     WHERE ID_PRODUTO = :ID_PRODUTO;
   END
END ^

ALTER PROCEDURE SP_COMP_CONSIST_PRODUTOS RETURNS (PRODUTOSTOTAL INTEGER,
PRDTOTAL INTEGER,
PRODUTOSTEMBARRA INTEGER,
PRDTEMBARRA INTEGER,
PRODUTOSNAOTEMBARRA INTEGER,
PRDNAOTEMBARRA INTEGER,
PRODUTOSEQUIVALENTES INTEGER,
PRODUTOSNAOEQUIVALENTES INTEGER,
PRDEQUIVALENTES INTEGER,
PRDNAOEQUIVALENTES INTEGER,
PRODUTOSBARRADUPLICADA INTEGER,
PRDBARRADUPLICADA INTEGER)
AS 
BEGIN
/* PRODUTOS */
SELECT COUNT(*) FROM PRODUTOS INTO :PRODUTOSTOTAL;
SELECT COUNT(*) FROM PRODUTOS WHERE CODIGO_BARRAS_1 <> CAST(CD_PRODUTO AS DOUBLE PRECISION) INTO :PRODUTOSTEMBARRA;
SELECT COUNT(*) FROM PRODUTOS WHERE CODIGO_BARRAS_1 = CAST(CD_PRODUTO AS DOUBLE PRECISION) INTO :PRODUTOSNAOTEMBARRA;

/* PRD*/
SELECT COUNT(*) FROM PRD INTO :PRDTOTAL;
SELECT COUNT(*) FROM PRD WHERE CD_BARRA1 IS NOT NULL AND CD_BARRA1 <> '' AND CD_BARRA1 <> CAST(CODIGO AS DOUBLE PRECISION) INTO :PRDTEMBARRA;
SELECT COUNT(*) FROM PRD WHERE CD_BARRA1 IS NULL OR CD_BARRA1 = '' OR CD_BARRA1 = CAST(CODIGO AS DOUBLE PRECISION) INTO :PRDNAOTEMBARRA;


/* BARRA DUPLICADA EM PRODUTOS */
SELECT COUNT(DISTINCT CODIGO_BARRAS_1) FROM PRODUTOS
WHERE CODIGO_BARRAS_1 IN
(SELECT CODIGO_BARRAS_1 FROM PRODUTOS GROUP BY CODIGO_BARRAS_1 HAVING COUNT(CODIGO_BARRAS_1) > 1)
INTO :PRODUTOSBARRADUPLICADA;

/* BARRA DUPLICADA EM PRD */
SELECT COUNT(DISTINCT CD_BARRA1) FROM PRD
WHERE CD_BARRA1 IN
(SELECT CD_BARRA1 FROM PRD GROUP BY CD_BARRA1 HAVING COUNT(CD_BARRA1) > 1)
INTO :PRDBARRADUPLICADA;

/* COMPARATIVO PRD - PRODUTOS */
SELECT COUNT(DISTINCT CD_BARRA1) FROM PRD WHERE CD_BARRA1 <> CODIGO AND PRD.CD_BARRA1 IN
(SELECT CODIGO_BARRAS_1 FROM PRODUTOS WHERE CODIGO_BARRAS_1 <> CD_PRODUTO) INTO :PRDEQUIVALENTES;

SELECT COUNT(DISTINCT CD_BARRA1) FROM PRD WHERE CD_BARRA1 <> CODIGO AND PRD.CD_BARRA1 NOT IN
(SELECT CODIGO_BARRAS_1 FROM PRODUTOS WHERE CODIGO_BARRAS_1 <> CD_PRODUTO) INTO :PRDNAOEQUIVALENTES;

/* COMPARATIVO PRODUTOS - PRD */
SELECT COUNT(DISTINCT CODIGO_BARRAS_1) FROM PRODUTOS WHERE CODIGO_BARRAS_1 <> CD_PRODUTO AND PRODUTOS.CODIGO_BARRAS_1 IN
(SELECT CD_BARRA1 FROM PRD WHERE CD_BARRA1 <> CODIGO) INTO :PRODUTOSEQUIVALENTES;

SELECT COUNT(DISTINCT CODIGO_BARRAS_1) FROM PRODUTOS WHERE CODIGO_BARRAS_1 <> CD_PRODUTO AND PRODUTOS.CODIGO_BARRAS_1 NOT IN
(SELECT CD_BARRA1 FROM PRD WHERE CD_BARRA1 <> CODIGO) INTO :PRODUTOSNAOEQUIVALENTES;



SUSPEND;

END ^

ALTER PROCEDURE SP_COMP_VENDAS_COMPRAS_MES (FILIAL DOUBLE PRECISION)
RETURNS (DATA VARCHAR(7) CHARACTER SET NONE,
VENDAS DOUBLE PRECISION,
QUANTIDADE_VENDIDA DOUBLE PRECISION,
NUMERO_DE_VENDAS DOUBLE PRECISION,
MEDIA_POR_CUPOM DOUBLE PRECISION,
MEDIA_POR_UNIDADE DOUBLE PRECISION,
COMPRAS DOUBLE PRECISION,
INDICE DOUBLE PRECISION)
AS 
DECLARE VARIABLE MES INTEGER;
DECLARE VARIABLE ANO INTEGER;
DECLARE VARIABLE VENDAS_C DOUBLE PRECISION;
DECLARE VARIABLE NUMERO_DE_VENDAS_C INTEGER;
DECLARE VARIABLE QUANTIDADE_VENDIDA_C DOUBLE PRECISION;
BEGIN
  MES = EXTRACT(MONTH FROM CURRENT_DATE);
  ANO = EXTRACT(YEAR FROM CURRENT_DATE) - 1;

  FOR
    /* VENDAS */
    SELECT
     CAST(EXTRACT(YEAR FROM DATA_LANCAMENTO) AS VARCHAR(4))||'-'||
     CAST(EXTRACT(MONTH FROM DATA_LANCAMENTO) AS VARCHAR(2)),
     SUM(VALOR),
     SUM(QUANTIDADE),
     COUNT(DISTINCT CD_VENDA)
    FROM
     LANCAMENTOS
    WHERE
     CD_FILIAL = :FILIAL AND
     TIPO_VENDA = 'V' AND
     DATA_LANCAMENTO >= :MES||'/01/'||:ANO
    GROUP BY
     EXTRACT(YEAR FROM DATA_LANCAMENTO),
     EXTRACT(MONTH FROM DATA_LANCAMENTO)
    ORDER BY
     EXTRACT(YEAR FROM DATA_LANCAMENTO),
     EXTRACT(MONTH FROM DATA_LANCAMENTO)
    INTO
     :DATA, :VENDAS, :QUANTIDADE_VENDIDA, :NUMERO_DE_VENDAS
  DO
   BEGIN
     /* CANCELAMENTOS */
     SELECT
      SUM(VALOR),
      SUM(QUANTIDADE),
      COUNT(DISTINCT CD_VENDA)
     FROM
      LANCAMENTOS
     WHERE
      CD_FILIAL = :FILIAL AND
      TIPO_VENDA = 'D' AND
      EXTRACT(YEAR FROM DATA_LANCAMENTO) = :ANO AND
      EXTRACT(MONTH FROM DATA_LANCAMENTO) = :MES
     INTO
      :VENDAS_C, :QUANTIDADE_VENDIDA_C, :NUMERO_DE_VENDAS_C;

     IF (:VENDAS_C IS NULL) THEN
        VENDAS_C = 0;
     IF (:QUANTIDADE_VENDIDA_C IS NULL) THEN
        QUANTIDADE_VENDIDA_C = 0;
     IF (:NUMERO_DE_VENDAS_C IS NULL) THEN
        NUMERO_DE_VENDAS_C = 0;

     /* TOTALIZANDO : VENDAS - CANCELAMENTOS */
     VENDAS = :VENDAS - :VENDAS_C;
     QUANTIDADE_VENDIDA = :QUANTIDADE_VENDIDA - :QUANTIDADE_VENDIDA_C;
     NUMERO_DE_VENDAS = :NUMERO_DE_VENDAS - :NUMERO_DE_VENDAS_C;

     /* COMPRAS */
     SELECT
      SUM(VALOR)
     FROM
      LANCAMENTOS
     WHERE
      CD_FILIAL = :FILIAL AND
      TIPO_VENDA = 'C' AND
      EXTRACT(YEAR FROM DATA_LANCAMENTO) = :ANO AND
      EXTRACT(MONTH FROM DATA_LANCAMENTO) = :MES
     INTO
      :COMPRAS;

     IF (:COMPRAS IS NULL) THEN
        COMPRAS = 0;

     /* GERANDO INDICES E MEDIAS */
     INDICE = (:COMPRAS * 100 )/:VENDAS;
     MEDIA_POR_CUPOM = :VENDAS / :NUMERO_DE_VENDAS;
     MEDIA_POR_UNIDADE = :VENDAS / :QUANTIDADE_VENDIDA;

     SUSPEND;

     MES = :MES + 1;
     IF (:MES = 13) THEN
      BEGIN
        MES = 1;
        ANO = :ANO + 1;
      END
   END
END ^

ALTER PROCEDURE SP_CONCLUI_COTACAO (ID_COTACAO DOUBLE PRECISION)
AS 
DECLARE VARIABLE CD_DISTRIBUIDOR DOUBLE PRECISION;
DECLARE VARIABLE ID_PRODUTO DOUBLE PRECISION;
DECLARE VARIABLE DATA_FECHAMENTO DATE;
BEGIN
 SELECT DATA_FECHAMENTO FROM COTACOES WHERE ID_COTACAO = :ID_COTACAO INTO :DATA_FECHAMENTO;

 FOR
  SELECT
   DISTINCT ID_PRODUTO
  FROM
   ITENS_COTACOES
  WHERE
   ID_COTACAO = :ID_COTACAO
  INTO
   :ID_PRODUTO
 DO
  BEGIN
    SELECT FIRST 1 CD_DISTRIBUIDOR
    FROM ITENS_COTACOES
    WHERE ID_COTACAO = :ID_COTACAO AND ID_PRODUTO = :ID_PRODUTO AND PRECO IS NOT NULL AND PRECO > 0
    ORDER BY PRECO
    INTO :CD_DISTRIBUIDOR;

    IF (:CD_DISTRIBUIDOR IS NOT NULL) THEN
     BEGIN
       UPDATE ITENS_COTACOES SET
        GERARPEDIDO = 'S'
       WHERE ID_COTACAO = :ID_COTACAO AND
             CD_DISTRIBUIDOR = :CD_DISTRIBUIDOR AND
             ID_PRODUTO = :ID_PRODUTO;
     END
  END

 IF (:DATA_FECHAMENTO IS NULL) THEN
  BEGIN
    UPDATE COTACOES SET
      DATA_FECHAMENTO = CURRENT_DATE,
      STATUS = 'C'
    WHERE ID_COTACAO = :ID_COTACAO;
  END
 ELSE
  BEGIN
    UPDATE COTACOES SET
      STATUS = 'C'
    WHERE ID_COTACAO = :ID_COTACAO;
  END
END ^

ALTER PROCEDURE SP_CONFERENCIA_CAIXA (FILIAL DOUBLE PRECISION,
DATA DATE)
RETURNS (CD_FILIAL DOUBLE PRECISION,
DATACAIXA DATE,
OPERADOR DOUBLE PRECISION,
DINHEIRO DOUBLE PRECISION,
CARTAO DOUBLE PRECISION,
CONVENIO DOUBLE PRECISION,
CHEQUE_PRE DOUBLE PRECISION,
CREDIARIO DOUBLE PRECISION,
CHEQUE_A_VISTA DOUBLE PRECISION,
RETIRADAS DOUBLE PRECISION,
TOTAL DOUBLE PRECISION)
AS 
BEGIN
 FOR
  SELECT
   CAIXA.CD_FILIAL,
   CAIXA.DATA,
   CAIXA.CD_OPERADOR
  FROM
   CAIXA
  WHERE
   CAIXA.CD_FILIAL = :FILIAL AND
   CAIXA.DATA = :DATA AND
   CAIXA.CD_OPERADOR <> 0
  GROUP BY
   CAIXA.CD_FILIAL,
   CAIXA.DATA,
   CAIXA.CD_OPERADOR
  INTO
   :CD_FILIAL,
   :DATACAIXA,
   :OPERADOR
 DO
  BEGIN
    SELECT
     SUM(CAIXA.VALOR)
    FROM
     CAIXA
    WHERE
     CAIXA.CD_FILIAL = :FILIAL AND
     CAIXA.DATA = :DATA AND
     CAIXA.CD_OPERADOR = :OPERADOR AND
     CAIXA.CD_FORMA_PAGAMENTO = 1
    INTO
     :DINHEIRO;
    
    SELECT
     SUM(CAIXA.VALOR)
    FROM
     CAIXA
    WHERE
     CAIXA.CD_FILIAL = :FILIAL AND
     CAIXA.DATA = :DATA AND
     CAIXA.CD_OPERADOR = :OPERADOR AND
     CAIXA.CD_FORMA_PAGAMENTO = 2
    INTO
     :CARTAO;

    SELECT
     SUM(CAIXA.VALOR)
    FROM
     CAIXA
    WHERE
     CAIXA.CD_FILIAL = :FILIAL AND
     CAIXA.DATA = :DATA AND
     CAIXA.CD_OPERADOR = :OPERADOR AND
     CAIXA.CD_FORMA_PAGAMENTO = 3
    INTO
     :CONVENIO;

    SELECT
     SUM(CAIXA.VALOR)
    FROM
     CAIXA
    WHERE
     CAIXA.CD_FILIAL = :FILIAL AND
     CAIXA.DATA = :DATA AND
     CAIXA.CD_OPERADOR = :OPERADOR AND
     CAIXA.CD_FORMA_PAGAMENTO = 4
    INTO
     :CHEQUE_PRE;

    SELECT
     SUM(CAIXA.VALOR)
    FROM
     CAIXA
    WHERE
     CAIXA.CD_FILIAL = :FILIAL AND
     CAIXA.DATA = :DATA AND
     CAIXA.CD_OPERADOR = :OPERADOR AND
     CAIXA.CD_FORMA_PAGAMENTO = 5
    INTO
     :CREDIARIO;

    SELECT
     SUM(CAIXA.VALOR)
    FROM
     CAIXA
    WHERE
     CAIXA.CD_FILIAL = :FILIAL AND
     CAIXA.DATA = :DATA AND
     CAIXA.CD_OPERADOR = :OPERADOR AND
     CAIXA.CD_FORMA_PAGAMENTO = 6
    INTO
     :CHEQUE_A_VISTA;

    SELECT
     SUM(CAIXA.VALOR)
    FROM
     CAIXA
    WHERE
     CAIXA.CD_FILIAL = :FILIAL AND
     CAIXA.DATA = :DATA AND
     CAIXA.CD_OPERADOR = :OPERADOR AND
     CAIXA.CD_FORMA_PAGAMENTO IS NULL
    INTO
     :RETIRADAS;

    IF ((:DINHEIRO IS NOT NULL) OR
        (:CARTAO IS NOT NULL) OR
        (:CONVENIO IS NOT NULL) OR
        (:CHEQUE_PRE IS NOT NULL) OR
        (:CREDIARIO IS NOT NULL) OR
        (:CHEQUE_A_VISTA IS NOT NULL) OR
        (:RETIRADAS IS NOT NULL)) THEN
      BEGIN
            IF (:DINHEIRO IS NULL) THEN DINHEIRO = 0;
            IF (:CARTAO IS NULL) THEN CARTAO = 0;
            IF (:CONVENIO IS NULL) THEN CONVENIO = 0;
            IF (:CHEQUE_PRE IS NULL) THEN CHEQUE_PRE = 0;
            IF (:CREDIARIO IS NULL) THEN CREDIARIO = 0;
            IF (:CHEQUE_A_VISTA IS NULL) THEN CHEQUE_A_VISTA = 0;
            IF (:RETIRADAS IS NULL) THEN RETIRADAS = 0;
        
            TOTAL = :DINHEIRO + :CARTAO + :CONVENIO + :CHEQUE_PRE + :CREDIARIO + :CHEQUE_A_VISTA - :RETIRADAS;
        
            SUSPEND;
      END
  END
END ^

