ALTER PROCEDURE SP_CONSISTENCIA_CADASTRO_2 AS 
declare variable EXISTE double precision;
BEGIN
   UPDATE PRODUTOS SET CODIGO_BARRAS_1 = CD_PRODUTO WHERE (CODIGO_BARRAS_1 = ' ') OR (CODIGO_BARRAS_1 IS NULL) OR (CAST(CODIGO_BARRAS_1 AS FLOAT) = 0);
   UPDATE PRODUTOS SET CD_CLASSE = 49 WHERE CD_CLASSE NOT IN (SELECT CD_CLASSE FROM CLASSES);
   UPDATE PRODUTOS SET CD_GRUPO = 99 WHERE CD_GRUPO NOT IN (SELECT CD_GRUPO FROM GRUPOS);
   UPDATE PRODUTOS SET CD_LABORATORIO = 999 WHERE CD_LABORATORIO NOT IN (SELECT CD_LABORATORIO FROM LABORATORIOS);
   UPDATE PRODUTOS SET CD_GRUPOBALANCO = 9999 WHERE CD_GRUPOBALANCO IS NULL OR CD_GRUPOBALANCO NOT IN (SELECT CD_GRUPOBALANCO FROM GRUPOSBALANCO);
   UPDATE PRODUTOS SET CD_GRUPOCOMPRA = 9999 WHERE CD_GRUPOCOMPRA IS NULL OR CD_GRUPOCOMPRA NOT IN (SELECT CD_GRUPOCOMPRA FROM GRUPOSCOMPRAS);
   UPDATE PRODUTOS SET SAZONAL = 'N', JANSAZ = 'N', FEVSAZ = 'N', MARSAZ = 'N', ABRSAZ = 'N', MAISAZ = 'N',
                       JUNSAZ = 'N', JULSAZ = 'N', AGOSAZ = 'N', SETSAZ = 'N', OUTSAZ = 'N', NOVSAZ = 'N', DEZSAZ = 'N';

   /*---------------OUTROS CADASTROS------------------- */
    UPDATE clientes SET saldo = 0 WHERE saldo IS NULL;
    UPDATE clientes SET LIMITE_CREDITO = 0 WHERE LIMITE_CREDITO IS NULL;
    UPDATE clientes SET status = 'A' WHERE status IS NULL;

    UPDATE FILIAIS SET STATUS = 'A';

    UPDATE lancamentos SET comissao = 0, arredondamento = 0;
    UPDATE lancamentos SET tipo_venda = 'V' WHERE TIPO_VENDA = 'P';

    UPDATE contas_receber SET cd_forma_pagamento = CAST(historico AS FLOAT);
    UPDATE contas_receber SET vl_pagamento = 0 WHERE vl_pagamento IS NULL;
    UPDATE contas_receber SET vl_desconto = 0 WHERE vl_desconto IS NULL;
    UPDATE contas_receber SET vl_saldo = 0 WHERE vl_saldo IS NULL;
    UPDATE contas_receber SET status = 'A'  WHERE status IS NULL;
    UPDATE contas_receber SET vl_saldo = valor WHERE status = 'A';

    UPDATE CONTAS_PAGAR SET VL_SALDO = 0 WHERE VL_SALDO IS NULL;
    UPDATE CONTAS_PAGAR SET VL_SALDO = VALOR WHERE STATUS = 'A';
    UPDATE contas_pagar SET cd_plano_contas = 25 where cd_plano_contas is null;
    UPDATE contas_pagar SET nr_cheque = ' ' where nr_cheque is null;

    UPDATE COMPRAS SET VINCULADO = 'N', TEMVINCULADO = 'N', CD_COMPRAS_VINCULADO = CD_COMPRAS;
    UPDATE ITENS_COMPRA SET CD_FILIAL_DESTINO = CD_FILIAL;

   SELECT CD_CLASSE FROM CLASSES WHERE CD_CLASSE = 4 INTO :EXISTE;
   IF (:EXISTE IS NULL) THEN
    BEGIN
      INSERT INTO CLASSES VALUES (4, 'OUTROS', 'OU', 'N', NULL, 30, 0, 0, 0, 0, 'N', '');
    END

   SELECT CD_GRUPO FROM GRUPOS WHERE CD_GRUPO = 99 INTO :EXISTE;
   IF (:EXISTE IS NULL) THEN
    BEGIN
      INSERT INTO GRUPOS VALUES (99, 'DIVERSOS', 0, 'N', 0, 0, 0, 0, 'OU', CURRENT_DATE, 0, 0, 0, 0, 'N', 'S', 'N', null, 0, '');
    END

   SELECT CD_LABORATORIO FROM LABORATORIOS WHERE CD_LABORATORIO = 999 INTO :EXISTE;
   IF (:EXISTE IS NULL) THEN
    BEGIN
      INSERT INTO LABORATORIOS VALUES (999, 0, 'DIVERSOS', 'DIVERSOS', '', '', '', '', '', 0, '', CURRENT_DATE, 0, 0, 0, 0, '');
    END

   SELECT COUNT(*) FROM GRUPOSBALANCO INTO :EXISTE;
   IF (:EXISTE = 0) THEN
    BEGIN
      INSERT INTO GRUPOSBALANCO VALUES (9999, 'TODOS', 'A', CURRENT_DATE, '');
    END

   SELECT COUNT(*) FROM GRUPOSCOMPRAS INTO :EXISTE;
   IF (:EXISTE = 0) THEN
    BEGIN
      INSERT INTO GRUPOSCOMPRAS VALUES (9999, 'TODOS', 'A', CURRENT_DATE, '');
    END

   update GRUPOS_CURVAS set GRUPOS_CURVAS.P1 = 0.5, GRUPOS_CURVAS.P2 = 0.5, GRUPOS_CURVAS.P1SAZ = 0.5, GRUPOS_CURVAS.P2SAZ = 0.5;

   UPDATE CLIENTES SET CLIENTES.FONE = CLIENTES.FAX WHERE (CLIENTES.FONE IS NULL OR CLIENTES.FONE = ' ');

   DELETE FROM EPHARMA;
   DELETE FROM FPAUTORIZACOES;

