ALTER PROCEDURE SP_CONSISTENCIA_DADOS AS 
DECLARE VARIABLE ANOATUAL INTEGER;
DECLARE VARIABLE MESATUAL INTEGER;
DECLARE VARIABLE FILIAL DOUBLE PRECISION;
DECLARE VARIABLE DATAINICIAL DATE;
DECLARE VARIABLE DATAFINAL DATE;
DECLARE VARIABLE ULTIMODIAMES INTEGER;
BEGIN
  SELECT CD_FILIAL FROM PARAMETROS INTO :FILIAL;
  IF (FILIAL = 0) THEN
    EXIT;

  ANOATUAL = CAST(EXTRACT(YEAR FROM CURRENT_DATE) AS INTEGER);
  MESATUAL = CAST(EXTRACT(MONTH FROM CURRENT_DATE) AS INTEGER);

  IF (:MESATUAL = 1) THEN
    BEGIN
      MESATUAL = 12;
      ANOATUAL = ANOATUAL - 1;
    END

  IF (:MESATUAL = 1) THEN
   BEGIN
    ULTIMODIAMES = 31;
   END
  ELSE
  IF (:MESATUAL = 2) THEN
   BEGIN
    ULTIMODIAMES = 28;
   END
  ELSE
  IF (:MESATUAL = 3) THEN
   BEGIN
    ULTIMODIAMES = 31;
   END
  ELSE
  IF (:MESATUAL = 4) THEN
   BEGIN
    ULTIMODIAMES = 30;
   END
  ELSE
  IF (:MESATUAL = 5) THEN
   BEGIN
    ULTIMODIAMES = 31;
   END
  ELSE
  IF (:MESATUAL = 6) THEN
   BEGIN
    ULTIMODIAMES = 30;
   END
  ELSE
  IF (:MESATUAL = 7) THEN
   BEGIN
    ULTIMODIAMES = 31;
   END
  ELSE
  IF (:MESATUAL = 8) THEN
   BEGIN
    ULTIMODIAMES = 30;
   END
  ELSE
  IF (:MESATUAL = 9) THEN
   BEGIN
    ULTIMODIAMES = 30;
   END
  ELSE
  IF (:MESATUAL = 10) THEN
   BEGIN
    ULTIMODIAMES = 31;
   END
  ELSE
  IF (:MESATUAL = 11) THEN
   BEGIN
    ULTIMODIAMES = 30;
   END
  ELSE
  IF (:MESATUAL = 12) THEN
   BEGIN
    ULTIMODIAMES = 31;
   END

  IF (CAST(EXTRACT(MONTH FROM CURRENT_DATE) AS INTEGER) = 1) THEN
    BEGIN
      DATAINICIAL = CAST( (MESATUAL) || '/01' || '/' || (ANOATUAL) AS DATE);
    END
  ELSE
    BEGIN
      DATAINICIAL = CAST( (MESATUAL - 1) || '/01' || '/' || (ANOATUAL) AS DATE);
    END

  IF (CAST(EXTRACT(MONTH FROM CURRENT_DATE) AS INTEGER) = 1) THEN
     BEGIN
      DATAFINAL   = CAST( (MESATUAL)     || '/'   || (ULTIMODIAMES) || '/' || (ANOATUAL) AS DATE);
     END
  ELSE
     BEGIN
      DATAFINAL   = CAST( (MESATUAL - 1) || '/'   || (ULTIMODIAMES) || '/' || (ANOATUAL) AS DATE);
     END

  EXECUTE PROCEDURE SP_PREENCHE_GRUPOS_CURVA;
  EXECUTE PROCEDURE SP_PREENCHE_VENDA_PRODUTO_LOJA;
  EXECUTE PROCEDURE SP_CALCULA_CURVA_TODOS(:FILIAL);
  EXECUTE PROCEDURE SP_CONSISTENCIA_LOJA_RODANDO;
END ^

ALTER PROCEDURE SP_CONSISTENCIA_LOJA AS 
DECLARE VARIABLE CD_FILIAL DOUBLE PRECISION;
BEGIN
  SELECT CD_FILIAL FROM PARAMETROS INTO :CD_FILIAL;

  EXECUTE PROCEDURE SP_PREENCHE_VENDA_PRODUTO_LOJA;
  EXECUTE PROCEDURE SP_PREENCHE_GRUPOS_CURVA;
  EXECUTE PROCEDURE SP_CALCULA_CURVA_TODOS(:CD_FILIAL);
  EXECUTE PROCEDURE SP_CONSISTENCIA_LOJA_RODANDO;
END ^

