ALTER PROCEDURE SP_CONSISTENCIA_PRODUTOS_FISCO AS 
declare variable ID_PRODUTO double precision;
declare variable CODIGO_BARRAS_1 varchar(14);
declare variable DESCRICAO varchar(60);
declare variable CD_CLASSE double precision;
declare variable CD_LISTA double precision;
declare variable CD_CFOP double precision;
declare variable ORIGEM varchar(1);
declare variable SITUACAO_TRIBUTARIA varchar(10);
declare variable CST_ICMS varchar(14);
declare variable CST_PIS_COFINS_ENTRADA varchar(3);
declare variable CST_PIS_COFINS_SAIDA varchar(3);
declare variable ALIQUOTA_ICMS numeric(15,2);
declare variable ALIQUOTA_PIS numeric(15,2);
declare variable ALIQUOTA_COFINS numeric(15,2);
declare variable NATUREZA_RECEITA_PISCOFINS varchar(3);
declare variable NCM varchar(10);
declare variable CEST varchar(10);
declare variable STATUS varchar(1);
declare variable DT_CADASTRO date;
BEGIN
  DELETE FROM PRODUTOS_FISCO WHERE CODIGO_BARRAS NOT IN
  (SELECT CODIGO_BARRAS_1 FROM PRODUTOS);

  FOR
    SELECT
     PRODUTOS.ID_PRODUTO, PRODUTOS.CODIGO_BARRAS_1, PRODUTOS.DESCRICAO,
     PRODUTOS.CD_CLASSE, PRODUTOS.CD_LISTA, PRODUTOS.CD_CFOP, PRODUTOS.ORIGEM,
     CASE
       WHEN (PRODUTOS.ICMS IS NULL) OR
            (PRODUTOS.ICMS = '') OR
            (PRODUTOS.ICMS = 'FF') THEN 'F'
       WHEN PRODUTOS.ICMS = 'II' THEN 'I'
       WHEN PRODUTOS.ICMS = 'NN' THEN 'N'
       ELSE 'T'
     END,
     PRODUTOS.SITUACAOTRIBUTARIA, 0, 0,
     CASE
       WHEN (PRODUTOS.ICMS IS NULL) OR
            (PRODUTOS.ICMS = '') OR
            (PRODUTOS.ICMS = 'FF') OR
            (PRODUTOS.ICMS = 'F') OR
            (PRODUTOS.ICMS = 'II') OR
            (PRODUTOS.ICMS = 'I') OR
            (PRODUTOS.ICMS = 'NN') OR
            (PRODUTOS.ICMS = 'N') THEN 0
       ELSE CAST(PRODUTOS.ICMS AS NUMERIC(15,2))
     END,
     0, 0, 0, PRODUTOS.NCM, PRODUTOS.CEST, PRODUTOS.STATUS, PRODUTOS.DT_CADASTRO
    FROM PRODUTOS
    WHERE ID_PRODUTO NOT IN (SELECT ID_PRODUTO FROM PRODUTOS_FISCO)
    INTO
      :ID_PRODUTO, :CODIGO_BARRAS_1, :DESCRICAO, :CD_CLASSE, :CD_LISTA, :CD_CFOP, :ORIGEM,
      :SITUACAO_TRIBUTARIA, :CST_ICMS, :CST_PIS_COFINS_ENTRADA, :CST_PIS_COFINS_SAIDA,
      :ALIQUOTA_ICMS, :ALIQUOTA_PIS, :ALIQUOTA_COFINS, :NATUREZA_RECEITA_PISCOFINS,
      :NCM, :CEST, :STATUS, :DT_CADASTRO
  DO
   BEGIN
     IF ((:ORIGEM IS NULL) OR (:ORIGEM = '')) THEN
        ORIGEM = '0';
     IF ((:NCM IS NULL) OR (:NCM = '')) THEN
        NCM = '30049099';
     IF ((:CEST IS NULL) OR (:CEST = '')) THEN
        CEST = '2801400';
     IF (:CD_CFOP IS NULL) THEN
        CD_CFOP = 5405;


     INSERT INTO PRODUTOS_FISCO
     (ID_PRODUTO, CODIGO_BARRAS, DESCRICAO, CD_CLASSE, CD_LISTA, CD_CFOP, ORIGEM,
      SITUACAO_TRIBUTARIA, CST_ICMS, CST_PIS_COFINS_ENTRADA, CST_PIS_COFINS_SAIDA,
      ALIQUOTA_ICMS, ALIQUOTA_PIS, ALIQUOTA_COFINS, NATUREZA_RECEITA_PISCOFINS,
      NCM, CEST, STATUS, DT_CADASTRO)
     VALUES
     (:ID_PRODUTO, :CODIGO_BARRAS_1, :DESCRICAO, :CD_CLASSE, :CD_LISTA, :CD_CFOP, :ORIGEM,
      :SITUACAO_TRIBUTARIA, :CST_ICMS, :CST_PIS_COFINS_ENTRADA, :CST_PIS_COFINS_SAIDA,
      :ALIQUOTA_ICMS, :ALIQUOTA_PIS, :ALIQUOTA_COFINS, :NATUREZA_RECEITA_PISCOFINS,
      :NCM, :CEST, :STATUS, :DT_CADASTRO);
   END

   -- COMENTADO FML 03.10.2019
/*  FOR
   SELECT ID_PRODUTO, CODIGO_BARRAS_1, DESCRICAO FROM PRODUTOS WHERE DT_ALTERACAO >= CURRENT_DATE - 1
   INTO :ID_PRODUTO, :CODIGO_BARRAS, :DESCRICAO
  DO
   BEGIN
     UPDATE PRODUTOS_FISCO SET
      CODIGO_BARRAS = :CODIGO_BARRAS,
      DESCRICAO = :DESCRICAO
     WHERE ID_PRODUTO = :ID_PRODUTO;
   END*/

END ^

ALTER PROCEDURE SP_CONSISTENCIA_PRODUTOS_FISCO2 AS 
declare variable ID_PRODUTO double precision;
declare variable CODIGO_BARRAS_1 varchar(14);
declare variable DESCRICAO varchar(60);
declare variable CD_CLASSE double precision;
declare variable CD_LISTA double precision;
declare variable CD_CFOP double precision;
declare variable ORIGEM varchar(1);
declare variable SITUACAO_TRIBUTARIA varchar(1);
declare variable CST_ICMS varchar(14);
declare variable CST_PIS_COFINS_ENTRADA varchar(3);
declare variable CST_PIS_COFINS_SAIDA varchar(3);
declare variable ALIQUOTA_ICMS numeric(15,2);
declare variable ALIQUOTA_PIS numeric(15,2);
declare variable ALIQUOTA_COFINS numeric(15,2);
declare variable NATUREZA_RECEITA_PISCOFINS varchar(3);
declare variable NCM varchar(10);
declare variable CEST varchar(10);
declare variable STATUS varchar(1);
declare variable DT_CADASTRO date;
BEGIN
 FOR
   SELECT CODIGO_BARRAS_1 FROM PRODUTOS WHERE CODIGO_BARRAS_1 NOT IN (SELECT CODIGO_BARRAS FROM PRODUTOS_FISCO) INTO :CODIGO_BARRAS_1
 DO
  BEGIN
    SELECT
     PRODUTOS.ID_PRODUTO, PRODUTOS.DESCRICAO,
     PRODUTOS.CD_CLASSE, PRODUTOS.CD_LISTA, PRODUTOS.CD_CFOP, PRODUTOS.ORIGEM,
     CASE
       WHEN (PRODUTOS.ICMS IS NULL) OR
            (PRODUTOS.ICMS = '') OR
            (PRODUTOS.ICMS = 'FF') THEN 'F'
       WHEN PRODUTOS.ICMS = 'II' THEN 'I'
       WHEN PRODUTOS.ICMS = 'NN' THEN 'N'
       ELSE 'T'
     END,
     PRODUTOS.SITUACAOTRIBUTARIA, 0, 0,
     CASE
       WHEN (PRODUTOS.ICMS IS NULL) OR
            (PRODUTOS.ICMS = '') OR
            (PRODUTOS.ICMS = 'FF') OR
            (PRODUTOS.ICMS = 'II') OR
            (PRODUTOS.ICMS = 'NN') THEN 0
       ELSE CAST(PRODUTOS.ICMS AS NUMERIC(15,2))
     END,
     0, 0, 0, PRODUTOS.NCM, PRODUTOS.CEST, PRODUTOS.STATUS, PRODUTOS.DT_CADASTRO
    FROM PRODUTOS
    WHERE ID_PRODUTO NOT IN (SELECT ID_PRODUTO FROM PRODUTOS_FISCO)
    INTO
      :ID_PRODUTO, :DESCRICAO, :CD_CLASSE, :CD_LISTA, :CD_CFOP, :ORIGEM,
      :SITUACAO_TRIBUTARIA, :CST_ICMS, :CST_PIS_COFINS_ENTRADA, :CST_PIS_COFINS_SAIDA,
      :ALIQUOTA_ICMS, :ALIQUOTA_PIS, :ALIQUOTA_COFINS, :NATUREZA_RECEITA_PISCOFINS,
      :NCM, :CEST, :STATUS, :DT_CADASTRO;

    INSERT INTO PRODUTOS_FISCO
    (ID_PRODUTO, CODIGO_BARRAS, DESCRICAO, CD_CLASSE, CD_LISTA, CD_CFOP, ORIGEM,
     SITUACAO_TRIBUTARIA, CST_ICMS, CST_PIS_COFINS_ENTRADA, CST_PIS_COFINS_SAIDA,
     ALIQUOTA_ICMS, ALIQUOTA_PIS, ALIQUOTA_COFINS, NATUREZA_RECEITA_PISCOFINS,
     NCM, CEST, STATUS, DT_CADASTRO)
    VALUES
    (:ID_PRODUTO, :CODIGO_BARRAS_1, :DESCRICAO, :CD_CLASSE, :CD_LISTA, :CD_CFOP, :ORIGEM,
     :SITUACAO_TRIBUTARIA, :CST_ICMS, :CST_PIS_COFINS_ENTRADA, :CST_PIS_COFINS_SAIDA,
     :ALIQUOTA_ICMS, :ALIQUOTA_PIS, :ALIQUOTA_COFINS, :NATUREZA_RECEITA_PISCOFINS,
     :NCM, :CEST, :STATUS, :DT_CADASTRO);
  END
END ^

ALTER PROCEDURE SP_CONSULTA_ENTREGAS (CD_FILIAL DOUBLE PRECISION,
DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (CD_VENDA DOUBLE PRECISION,
ENTREGADOR DOUBLE PRECISION,
NOME VARCHAR(100) CHARACTER SET NONE,
DATA DATE,
HORA_SAIDA TIME,
HORA_CHEGADA TIME,
STATUS VARCHAR(1) CHARACTER SET NONE,
NUMERO_ITENS INTEGER,
NUMERO_UNIDADES DOUBLE PRECISION,
VALOR DOUBLE PRECISION)
AS 
BEGIN
  DELETE FROM TEMP_ENTREGASDEVOLUCAO;
  FOR
    SELECT
      DISTINCT LANCAMENTOS.CD_VENDA
    FROM
      LANCAMENTOS
    WHERE
      LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
      LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
      LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
      LANCAMENTOS.TIPO_VENDA = 'D' AND
      LANCAMENTOS.TROCA = 'F'
    INTO
     :CD_VENDA
  DO
   BEGIN
      INSERT INTO TEMP_ENTREGASDEVOLUCAO VALUES (:CD_VENDA);
   END

  FOR
    SELECT
      ENTREGAS.CD_VENDA,
      ENTREGAS.CD_ENTREGADOR,
      ENTREGAS.DATA,
      ENTREGAS.HORA_SAIDA,
      ENTREGAS.HORA_CHEGADA,
      --ENTREGAS.STATUS,
      COUNT(LANCAMENTOS.ID_PRODUTO),
      SUM(LANCAMENTOS.QUANTIDADE),
      SUM(LANCAMENTOS.VALOR)
    FROM
      ENTREGAS ,LANCAMENTOS
    WHERE
      LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
      LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
      LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
      LANCAMENTOS.TIPO_VENDA = 'V' AND
      ENTREGAS.CD_FILIAL = :CD_FILIAL AND
      LANCAMENTOS.CD_VENDA = ENTREGAS.CD_VENDA AND
      LANCAMENTOS.CD_VENDA NOT IN (SELECT CD_VENDA FROM TEMP_ENTREGASDEVOLUCAO)
    GROUP BY
      ENTREGAS.CD_VENDA,
      ENTREGAS.CD_ENTREGADOR,
      ENTREGAS.DATA,
      ENTREGAS.HORA_SAIDA,
      ENTREGAS.HORA_CHEGADA/*,
      ENTREGAS.STATUS*/
    ORDER BY
      ENTREGAS.DATA DESC,
      ENTREGAS.HORA_SAIDA DESC
    INTO
      :CD_VENDA,
      :ENTREGADOR,
      :DATA,
      :HORA_SAIDA,
      :HORA_CHEGADA,
      --:STATUS,
      :NUMERO_ITENS,
      :NUMERO_UNIDADES,
      :VALOR
  DO
   BEGIN
     NOME = '';
     SELECT STATUS FROM ENTREGAS WHERE CD_VENDA = :CD_VENDA AND CD_FILIAL = :CD_FILIAL INTO :STATUS;
     SELECT NOME FROM VENDEDORES WHERE CD_VENDEDOR = :ENTREGADOR INTO :NOME;
     SUSPEND;
   END
END ^

ALTER PROCEDURE SP_CONSULTA_ENTREGAS_PRODUTOS (CD_FILIAL DOUBLE PRECISION,
DATAINICIAL DATE,
DATAFINAL DATE,
LISTAPRODUTOS VARCHAR(10000) CHARACTER SET NONE)
RETURNS (ENTREGADOR DOUBLE PRECISION,
NOME VARCHAR(100) CHARACTER SET NONE,
NUMERO_ITENS INTEGER,
NUMERO_UNIDADES DOUBLE PRECISION,
VALOR DOUBLE PRECISION,
ID_PRODUTO DOUBLE PRECISION,
DESCRICAO VARCHAR(100) CHARACTER SET NONE)
AS 
declare variable COMANDO varchar(10000);
declare variable CD_VENDA DOUBLE PRECISION;
BEGIN
  DELETE FROM TEMP_ENTREGASDEVOLUCAO;
  FOR
    SELECT
      DISTINCT CD_VENDA
    FROM
      LANCAMENTOS
    WHERE
      DATA_LANCAMENTO >= :DATAINICIAL AND
      DATA_LANCAMENTO <= :DATAFINAL AND
      CD_FILIAL = :CD_FILIAL AND
      TIPO_VENDA = 'D'
    INTO
     :CD_VENDA
  DO
   BEGIN
      INSERT INTO TEMP_ENTREGASDEVOLUCAO VALUES (:CD_VENDA);
   END

  COMANDO = 'SELECT ENTREGAS.CD_ENTREGADOR, LANCAMENTOS.ID_PRODUTO, COUNT(LANCAMENTOS.CD_LANCAMENTO), SUM(LANCAMENTOS.QUANTIDADE), SUM(LANCAMENTOS.VALOR) ' ||
            'FROM ENTREGAS ,LANCAMENTOS ' ||
            'WHERE LANCAMENTOS.DATA_LANCAMENTO >= ''' || :DATAINICIAL || ''' AND LANCAMENTOS.DATA_LANCAMENTO <= ''' || :DATAFINAL || ''' AND LANCAMENTOS.CD_FILIAL = ' || :CD_FILIAL || ' AND ' ||
            '      LANCAMENTOS.TIPO_VENDA = '''||'V'||''' AND ENTREGAS.CD_FILIAL = ' || :CD_FILIAL || ' AND LANCAMENTOS.CD_VENDA = ENTREGAS.CD_VENDA AND ' ||
            '(' || :LISTAPRODUTOS || ') AND ENTREGAS.STATUS = ''V'' AND '||
            '      LANCAMENTOS.CD_VENDA NOT IN (SELECT CD_VENDA FROM TEMP_ENTREGASDEVOLUCAO) ' ||
            'GROUP BY ENTREGAS.CD_ENTREGADOR, LANCAMENTOS.ID_PRODUTO ';
  FOR
    EXECUTE STATEMENT :COMANDO INTO :ENTREGADOR, :ID_PRODUTO, :NUMERO_ITENS, :NUMERO_UNIDADES, :VALOR
  DO
   BEGIN
     SELECT NOME FROM VENDEDORES WHERE CD_VENDEDOR = :ENTREGADOR INTO :NOME;
     SELECT DESCRICAO FROM PRODUTOS WHERE ID_PRODUTO = :ID_PRODUTO INTO :DESCRICAO;
     SUSPEND;
   END
END ^

ALTER PROCEDURE SP_CONTAS_A_PAGAR (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (FILIAL VARCHAR(40) CHARACTER SET NONE,
DATA DATE,
VALOR DOUBLE PRECISION)
AS 
BEGIN
  FOR
    SELECT
     FILIAIS.NOME,
     CONTAS_PAGAR.DT_VENCIMENTO,
     SUM(CONTAS_PAGAR.VL_SALDO)
    FROM
     CONTAS_PAGAR, FILIAIS
    WHERE
     CONTAS_PAGAR.CD_FILIAL = FILIAIS.CD_FILIAL AND
     CONTAS_PAGAR.DT_VENCIMENTO >= :DATAINICIAL AND
     CONTAS_PAGAR.DT_VENCIMENTO <= :DATAFINAL
    GROUP BY
     FILIAIS.NOME,
     CONTAS_PAGAR.DT_VENCIMENTO
    INTO
     :FILIAL,
     :DATA,
     :VALOR
  DO
   BEGIN
     SUSPEND;
   END
END ^

ALTER PROCEDURE SP_CONTAS_A_RECEBER (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (FILIAL VARCHAR(40) CHARACTER SET NONE,
DATA DATE,
CARTAO DOUBLE PRECISION,
CONVENIO DOUBLE PRECISION,
CHEQUEPRE DOUBLE PRECISION,
CREDITO DOUBLE PRECISION,
CHEQUEAVISTA DOUBLE PRECISION,
VALORTOTAL DOUBLE PRECISION)
AS 
DECLARE VARIABLE VALOR DOUBLE PRECISION;
DECLARE VARIABLE FORMA DOUBLE PRECISION;
BEGIN
  FOR
    SELECT    FILIAIS.NOME, CONTAS_RECEBER.DT_VENCIMENTO, SUM(CONTAS_RECEBER.VL_SALDO)
    FROM      CONTAS_RECEBER, FILIAIS
    WHERE     CONTAS_RECEBER.CD_FILIAL = FILIAIS.CD_FILIAL AND
              CONTAS_RECEBER.DT_VENCIMENTO >= :DATAINICIAL AND
              CONTAS_RECEBER.DT_VENCIMENTO <= :DATAFINAL
    GROUP BY  FILIAIS.NOME, CONTAS_RECEBER.DT_VENCIMENTO
    INTO      :FILIAL, :DATA, :VALORTOTAL
  DO
   BEGIN
     CARTAO = 0; CONVENIO = 0; CHEQUEPRE = 0;  CREDITO = 0;  CHEQUEAVISTA = 0;
     FOR
       SELECT   CONTAS_RECEBER.CD_FORMA_PAGAMENTO, SUM(CONTAS_RECEBER.VL_SALDO)
       FROM     CONTAS_RECEBER
       WHERE    CONTAS_RECEBER.DT_VENCIMENTO = :DATA AND CONTAS_RECEBER.STATUS <> 'C'
       GROUP BY CONTAS_RECEBER.CD_FORMA_PAGAMENTO
       INTO     :FORMA, :VALOR
     DO
      BEGIN
        IF (:FORMA = 2) THEN BEGIN CARTAO = :CARTAO + :VALOR;             END ELSE
        IF (:FORMA = 3) THEN BEGIN CONVENIO = :CONVENIO + :VALOR;         END ELSE
        IF (:FORMA = 4) THEN BEGIN CHEQUEPRE = :CHEQUEPRE + :VALOR;       END ELSE
        IF (:FORMA = 5) THEN BEGIN CREDITO = :CREDITO + :VALOR;           END ELSE
        IF (:FORMA = 6) THEN BEGIN CHEQUEAVISTA = :CHEQUEAVISTA + :VALOR; END
      END
     SUSPEND;
   END
END ^

