ALTER PROCEDURE SP_CONVERTE_ID_PRODUTO AS 
BEGIN
  UPDATE LANCAMENTOS SET
   CD_PRODUTO = '00000' || CAST(CAST(ID_PRODUTO AS INTEGER) AS VARCHAR(6))
  WHERE
   CAST(ID_PRODUTO AS INTEGER) < 10;

  UPDATE LANCAMENTOS SET
   CD_PRODUTO = '0000' || CAST(CAST(ID_PRODUTO AS INTEGER) AS VARCHAR(6))
  WHERE
   CAST(ID_PRODUTO AS INTEGER) < 100 AND CAST(ID_PRODUTO AS INTEGER) >= 10;

  UPDATE LANCAMENTOS SET
   CD_PRODUTO = '000' || CAST(CAST(ID_PRODUTO AS INTEGER) AS VARCHAR(6))
  WHERE
   CAST(ID_PRODUTO AS INTEGER) < 1000 AND CAST(ID_PRODUTO AS INTEGER) >= 100;

  UPDATE LANCAMENTOS SET
   CD_PRODUTO = '00' || CAST(CAST(ID_PRODUTO AS INTEGER) AS VARCHAR(6))
  WHERE
   CAST(ID_PRODUTO AS INTEGER) < 10000 AND CAST(ID_PRODUTO AS INTEGER) >= 1000;

  UPDATE LANCAMENTOS SET
   CD_PRODUTO = '0' || CAST(CAST(ID_PRODUTO AS INTEGER) AS VARCHAR(6))
  WHERE
   CAST(ID_PRODUTO AS INTEGER) < 100000 AND CAST(ID_PRODUTO AS INTEGER) >= 10000;

  UPDATE LANCAMENTOS SET
   CD_PRODUTO = CAST(CAST(ID_PRODUTO AS INTEGER) AS VARCHAR(6))
  WHERE
   CAST(ID_PRODUTO AS INTEGER) > 99999;


/*===================================== PRODUTOS ====================================*/
  UPDATE PRODUTOS SET
   CD_PRODUTO = '00000' || CAST(CAST(ID_PRODUTO AS INTEGER) AS VARCHAR(6))
  WHERE
   CAST(ID_PRODUTO AS INTEGER) < 10;

  UPDATE PRODUTOS SET
   CD_PRODUTO = '0000' || CAST(CAST(ID_PRODUTO AS INTEGER) AS VARCHAR(6))
  WHERE
   CAST(ID_PRODUTO AS INTEGER) < 100 AND CAST(ID_PRODUTO AS INTEGER) >= 10;

  UPDATE PRODUTOS SET
   CD_PRODUTO = '000' || CAST(CAST(ID_PRODUTO AS INTEGER) AS VARCHAR(6))
  WHERE
   CAST(ID_PRODUTO AS INTEGER) < 1000 AND CAST(ID_PRODUTO AS INTEGER) >= 100;

  UPDATE PRODUTOS SET
   CD_PRODUTO = '00' || CAST(CAST(ID_PRODUTO AS INTEGER) AS VARCHAR(6))
  WHERE
   CAST(ID_PRODUTO AS INTEGER) < 10000 AND CAST(ID_PRODUTO AS INTEGER) >= 1000;

  UPDATE PRODUTOS SET
   CD_PRODUTO = '0' || CAST(CAST(ID_PRODUTO AS INTEGER) AS VARCHAR(6))
  WHERE
   CAST(ID_PRODUTO AS INTEGER) < 100000 AND CAST(ID_PRODUTO AS INTEGER) >= 10000;

  UPDATE PRODUTOS SET
   CD_PRODUTO = CAST(CAST(ID_PRODUTO AS INTEGER) AS VARCHAR(6))
  WHERE
   CAST(ID_PRODUTO AS INTEGER) > 99999;
      
END ^

ALTER PROCEDURE SP_CONVERTE_ID_PRODUTO_FASE_1 AS 
DECLARE VARIABLE ID DOUBLE PRECISION;
DECLARE VARIABLE CD DOUBLE PRECISION;
DECLARE VARIABLE BARRA VARCHAR(14);
DECLARE VARIABLE ID_OLD DOUBLE PRECISION;
BEGIN
 FOR
    /* Montagem da tabela de conversao de produtos
    insert into [BANCO2].prconversao
    select id_produto, cd_produto, codigo_barras_1, codigo_barras_1, null as id_old from PRODUTOS*/

    /*fase 1 - acerto de tabela conversao inserindo CODIGO antigo para compatibilidade*/
    SELECT
     PRODUTOS.id_produto,
     SUBSTRING(PRODUTOS.CODIGO_BARRAS_1 FROM 1 FOR 13)
    FROM
     PRODUTOS
    INTO
     :id,
     :barra
 DO
  BEGIN
     UPDATE PRCONVERSAO SET id_old = :id  WHERE codigo_barras_1 = :BARRA ;
  END
END ^

ALTER PROCEDURE SP_CONVERTE_ID_PRODUTO_FASE_2 AS 
DECLARE VARIABLE ID DOUBLE PRECISION;
DECLARE VARIABLE CD VARCHAR(6);
DECLARE VARIABLE BARRA VARCHAR(14);
DECLARE VARIABLE ID_OLD DOUBLE PRECISION;
BEGIN
 FOR
    /*fase 2 - alteracao das tabelas com id e cd produto com base no novo codigo*/
    SELECT
     PRCONVERSAO.id_produto,
     PRCONVERSAO.CD_PRODUTO,
     SUBSTRING(PRCONVERSAO.CODIGO_BARRAS_1 FROM 1 FOR 13),
     PRCONVERSAO.ID_OLD
    FROM
     PRCONVERSAO
    WHERE ID_OLD IS NOT NULL
    INTO
     :id,
     :CD,
     :barra,
     :id_old
 DO
  BEGIN
    UPDATE BALANCO SET ID_PRODUTO = :id, CD_PRODUTO = :cd WHERE id_produto = :ID_OLD;
    UPDATE CADERNO_FALTAS SET ID_PRODUTO = :id, CD_PRODUTO = :cd WHERE id_produto = :ID_OLD;
    UPDATE ITENS_COMPRA SET ID_PRODUTO = :id, CD_PRODUTO = :cd WHERE id_produto = :ID_OLD;
    UPDATE ITENS_TRANSFER SET ID_PRODUTO = :id, CD_PRODUTO = :cd WHERE id_produto = :ID_OLD;
    UPDATE ITENS_COTACOES SET ID_PRODUTO = :id WHERE id_produto = :ID_OLD;
    UPDATE LANCAMENTOS SET ID_PRODUTO = :id, CD_PRODUTO = :cd WHERE id_produto = :ID_OLD;
    UPDATE LANCAMENTOS_APRAZO SET ID_PRODUTO = :id, CD_PRODUTO = :cd WHERE id_produto = :ID_OLD;
    UPDATE PRODUTOS_TOTAIS SET ID_PRODUTO = :id WHERE id_produto = :ID_OLD;
    UPDATE TRANSFERENCIAS SET ID_PRODUTO = :id, CD_PRODUTO = :cd WHERE id_produto = :ID_OLD;
    UPDATE VENDAS SET ID_PRODUTO = :id, CD_PRODUTO = :cd WHERE id_produto = :ID_OLD;
    UPDATE PRODUTOS SET id_produto = :id, cd_produto = :cd WHERE id_produto = :ID_OLD;
    UPDATE PRODUTOS SET codigo_barras_1 = cd_produto WHERE codigo_barras_1 < 999999 ;
  END

END ^

ALTER PROCEDURE SP_CONV_PROD_PHARMACY AS 
DECLARE VARIABLE COMANDO VARCHAR(1000);
DECLARE VARIABLE ID INTEGER;
DECLARE VARIABLE CD INTEGER;
DECLARE VARIABLE ID_PRODUTO INTEGER;
DECLARE VARIABLE DESCRICAO VARCHAR(60);
DECLARE VARIABLE PRECO_PROMOCAO DOUBLE PRECISION;
DECLARE VARIABLE PRECO_VENDA DOUBLE PRECISION;
DECLARE VARIABLE CODIGO_BARRAS VARCHAR(13);
DECLARE VARIABLE STATUS VARCHAR(1);
DECLARE VARIABLE DATA_CADASTRO DATE;
DECLARE VARIABLE DT_ALTERACAO DATE;
DECLARE VARIABLE MARGEM DOUBLE PRECISION;
DECLARE VARIABLE CUSTO_UNITARIO DOUBLE PRECISION;
DECLARE VARIABLE CD_LABORATORIO DOUBLE PRECISION;
DECLARE VARIABLE CD_CLASSE DOUBLE PRECISION;
DECLARE VARIABLE CD_GRUPO DOUBLE PRECISION;
DECLARE VARIABLE USOCONTINUO VARCHAR(1);
DECLARE VARIABLE QT_EMBALAGEM DOUBLE PRECISION;
DECLARE VARIABLE CURVA VARCHAR(1);
DECLARE VARIABLE DT_REAJUSTE DATE;
DECLARE VARIABLE UNIDADE VARCHAR(2);
DECLARE VARIABLE COMISSAO DOUBLE PRECISION;
DECLARE VARIABLE DT_REAJUSTE_LOJA DATE;
DECLARE VARIABLE DT_ULT_VENDA DATE;
DECLARE VARIABLE ESTOQUE DOUBLE PRECISION;
DECLARE VARIABLE CUSTO_UNITARIO_LOJA DOUBLE PRECISION;
DECLARE VARIABLE PRECO_VENDA_LOJA DOUBLE PRECISION;
DECLARE VARIABLE DT_ULT_COMPRA_LOJA DATE;
DECLARE VARIABLE ESTOQUE_MINIMO_LOJA DOUBLE PRECISION;
DECLARE VARIABLE ESTOQUE_MAXIMO_LOJA DOUBLE PRECISION;
DECLARE VARIABLE CURVA_LOJA VARCHAR(1);
BEGIN
 FOR
  SELECT
   PRODUTO.PRODUTO_ID,
   PRODUTO.DESCRICAO,
   PRODUTO.PRECO_PROMOCAO,
   PRODUTO.PRECO_VENDA,
   PRODUTO.CODBARRAS,
   PRODUTO.STS_PRODUTO,
   PRODUTO.DATA_CADASTRO,
   PRODUTO.ALT_CADASTRO,
   PRODUTO.MARK_UP,
   PRODUTO.CUSTO_LISTA,
   PRODUTO.PARCEIRO_ID_FAB,
   PRODUTO.DEPARTAMENTO_ID,
   PRODUTO.SECAO_ID,
   PRODUTO.STS_CONTINUO,
   PRODUTO.FRACAO_VENDA,
   PRODUTO.CLASSE_VALOR,
   PRODUTO.ALT_VENDA,
   PRODUTO.EMB_FABRICA
  FROM
   PRODUTO
  INTO
   :ID_PRODUTO,
   :DESCRICAO,
   :PRECO_PROMOCAO,
   :PRECO_VENDA,
   :CODIGO_BARRAS,
   :STATUS,
   :DATA_CADASTRO,
   :DT_ALTERACAO,
   :MARGEM,
   :CUSTO_UNITARIO,
   :CD_LABORATORIO,
   :CD_CLASSE,
   :CD_GRUPO,
   :USOCONTINUO,
   :QT_EMBALAGEM,
   :CURVA,
   :DT_REAJUSTE,
   :UNIDADE
  DO
   BEGIN
      INSERT INTO PRODUTOS(ID_PRODUTO, CD_PRODUTO, DESCRICAO, PRECO_VENDA, PRECO_PROMOCAO, CODIGO_BARRAS_1,
                           STATUS, DT_CADASTRO, DT_ALTERACAO, MARGEM, CUSTO_UNITARIO, CD_LABORATORIO,
                           CD_CLASSE, CD_GRUPO, USOCONTINUO, QT_EMBALAGEM, CURVA, DT_REAJUSTE, UNIDADE) VALUES
                          (:ID_PRODUTO, :ID_PRODUTO, :DESCRICAO, :PRECO_VENDA, :PRECO_PROMOCAO, :CODIGO_BARRAS,
                           :STATUS, :DATA_CADASTRO, :DT_ALTERACAO, :MARGEM, :CUSTO_UNITARIO, :CD_LABORATORIO, :CD_CLASSE,
                           :CD_GRUPO, :USOCONTINUO, :QT_EMBALAGEM, :CURVA, :DT_REAJUSTE, :UNIDADE);
      FOR
       SELECT
         ID,
         CD
        FROM
         LOJAPHARMACY
        INTO
         :ID,
         :CD
      DO
       BEGIN
         SELECT
          ALOCACAO.COMISSAO,
          ALOCACAO.ALT_VENDA_FIL,
          ALOCACAO.ULT_VENDA, 
          ALOCACAO.ESTOQUE_ATUAL,
          ALOCACAO.PRECO_CUSTO,
          ALOCACAO.PRECO_VENDA_FIL, 
          ALOCACAO.ULT_COMPRA,
          ALOCACAO.EST_SEGURANCA,
          ALOCACAO.DEMANDA_MAX,
          ALOCACAO.CLASSE_VALOR
         FROM
          ALOCACAO
         WHERE
          ALOCACAO.PRODUTO_ID = :ID_PRODUTO AND
          ALOCACAO.PARCEIRO_ID = :CD
         INTO
          :COMISSAO,
          :DT_REAJUSTE_LOJA,
          :DT_ULT_VENDA,
          :ESTOQUE,
          :CUSTO_UNITARIO_LOJA,
          :PRECO_VENDA_LOJA,
          :DT_ULT_COMPRA_LOJA,
          :ESTOQUE_MINIMO_LOJA,
          :ESTOQUE_MAXIMO_LOJA,
          :CURVA_LOJA;

         IF (:DT_REAJUSTE_LOJA IS NULL) THEN
            DT_REAJUSTE_LOJA = :DT_REAJUSTE;
         IF (:CUSTO_UNITARIO_LOJA IS NULL) THEN
            CUSTO_UNITARIO_LOJA = :CUSTO_UNITARIO;
         IF (PRECO_VENDA_LOJA IS NULL) THEN
            PRECO_VENDA_LOJA = :PRECO_VENDA;
         IF (:ESTOQUE_MINIMO_LOJA IS NULL) THEN
             ESTOQUE_MINIMO_LOJA = 0;
         IF (:ESTOQUE_MAXIMO_LOJA IS NULL) THEN
             ESTOQUE_MAXIMO_LOJA = 0;
         IF (:CURVA_LOJA IS NULL) THEN
            CURVA_LOJA = :CURVA;

         COMANDO = '';
         COMANDO = 'UPDATE PRODUTOS SET COMISSAO = '||:COMISSAO||', '||
                   ' ESTOQUE_'||:ID||' = '||:ESTOQUE||', '||
                   ' CUSTO_UNITARIO_'||:ID||' = '||:CUSTO_UNITARIO_LOJA||', '||
                   ' PRECO_VENDA_'||:ID||' = '||:PRECO_VENDA_LOJA||', '||
                   ' ESTOQUE_MINIMO_'||:ID||' = '||:ESTOQUE_MINIMO_LOJA||', '||
                   ' ESTOQUE_MAXIMO_'||:ID||' = '||:ESTOQUE_MAXIMO_LOJA||', '||
                   ' CURVA_UNITARIA_'||:ID||' = '''||:CURVA_LOJA||''', '||
                   ' CURVA_FINANCEIRA_'||:ID||' = '''||:CURVA_LOJA||'''';
         IF (:DT_ULT_COMPRA_LOJA IS NOT NULL) THEN
            COMANDO = :COMANDO ||', DT_ULT_COMPRA_'||:ID||' = '''||:DT_ULT_COMPRA_LOJA||'''';
         IF (:DT_ULT_VENDA IS NOT NULL) THEN
            COMANDO = :COMANDO ||', DT_ULT_VENDA_'||:ID||' = '''||:DT_ULT_VENDA||'''';
         IF (:DT_REAJUSTE_LOJA IS NOT NULL) THEN
            COMANDO = :COMANDO ||', DT_REAJUSTE_'||:ID||' = '''||:DT_REAJUSTE_LOJA||'''';
         COMANDO = :COMANDO || ' WHERE ID_PRODUTO = '||:ID_PRODUTO;
         EXECUTE STATEMENT :COMANDO;
       END
   END
END ^

ALTER PROCEDURE SP_CRIA_COTACAO_PEDIDOGESTAO (TABELA VARCHAR(100) CHARACTER SET NONE,
CD_DISTRIBUIDOR DOUBLE PRECISION,
NOMEDISTRIBUIDOR VARCHAR(1000) CHARACTER SET NONE,
ID_COTACAO DOUBLE PRECISION,
GERARQUANTIDADEZERO VARCHAR(1) CHARACTER SET NONE)
AS 
declare variable COMANDO varchar(10000);
declare variable ID_PRODUTO double precision;
declare variable QUANTIDADE_TOTAL double precision;
declare variable DESCRICAO varchar(100);
declare variable CODIGO_BARRAS varchar(14);
declare variable CD_LABORATORIO double precision;
declare variable ID_FAMILIA double precision;
declare variable NOMELABORATORIO varchar(100);
BEGIN
  COMANDO = '';
  COMANDO = 'SELECT ID_PRODUTO, QUANTIDADE_TOTAL, DESCRICAO FROM ' || :TABELA;
  FOR
   EXECUTE STATEMENT :COMANDO INTO :ID_PRODUTO, :QUANTIDADE_TOTAL, :DESCRICAO
  DO
   BEGIN
     IF ((:QUANTIDADE_TOTAL > 0) OR (:GERARQUANTIDADEZERO = 'S')) THEN
      BEGIN
         SELECT CODIGO_BARRAS_1, CD_LABORATORIO, ID_FAMILIA FROM PRODUTOS WHERE ID_PRODUTO = :ID_PRODUTO
         INTO :CODIGO_BARRAS, :CD_LABORATORIO, :ID_FAMILIA;
    
         SELECT NOME FROM LABORATORIOS WHERE CD_LABORATORIO = :CD_LABORATORIO INTO :NOMELABORATORIO;
    
         INSERT INTO ITENS_COTACOES VALUES (
         :ID_COTACAO, :CD_DISTRIBUIDOR, :NOMEDISTRIBUIDOR, :ID_PRODUTO, :DESCRICAO, :ID_FAMILIA,
         :CD_LABORATORIO, :NOMELABORATORIO, :QUANTIDADE_TOTAL, 0, 'N', :CODIGO_BARRAS);
      END
   END
END ^

ALTER PROCEDURE SP_CRIA_NOVO_BALANCO (ID_BALANCO DOUBLE PRECISION,
METODO VARCHAR(1) CHARACTER SET NONE)
AS 
declare variable COMANDO varchar(1000);
declare variable CD_FILIAL double precision;
declare variable ID double precision;
declare variable CD varchar(6);
declare variable BARRA varchar(14);
declare variable CD_GRUPO double precision;
declare variable CD_CLASSE double precision;
declare variable CD_LABORATORIO double precision;
declare variable DESCRICAO varchar(100);
declare variable CUSTO double precision;
declare variable PRECO double precision;
declare variable ESTOQUE double precision;
declare variable GRUPO varchar(100);
declare variable CLASSE varchar(100);
declare variable LABORATORIO varchar(100);
declare variable ESTOQUE_ANTERIOR double precision;
declare variable BARRA2 varchar(14);
declare variable DATA date;
declare variable HORA time;
declare variable CD_SUBGRUPO double precision;
BEGIN
  SELECT CD_FILIAL FROM PARAMETROS INTO :CD_FILIAL;
  DATA = CURRENT_DATE;
  HORA = CURRENT_TIME;
  COMANDO = 'SELECT PRODUTOS.ID_PRODUTO, PRODUTOS.CD_PRODUTO, PRODUTOS.CODIGO_BARRAS_1, PRODUTOS.CODIGO_BARRAS_2, PRODUTOS.CD_GRUPO, '||
            ' PRODUTOS.CD_SUBGRUPO, PRODUTOS.CD_CLASSE, PRODUTOS.CD_LABORATORIO, PRODUTOS.DESCRICAO, PRODUTOS.CUSTO_UNITARIO_'
            || CAST(:CD_FILIAL AS INTEGER)|| ', PRODUTOS.PRECO_VENDA, PRODUTOS.ESTOQUE_' ||CAST(:CD_FILIAL AS INTEGER)||
            ' FROM PRODUTOS ' ||
            ' WHERE STATUS = ''' || 'A' || ''' AND PRODUTOS.DESCRICAO IS NOT NULL AND PRODUTOS.DESCRICAO <> ''' || ''' ' ||
            ' ORDER BY PRODUTOS.DESCRICAO';

  FOR
   EXECUTE STATEMENT :COMANDO
   INTO :ID, :CD, :BARRA, :BARRA2, :CD_GRUPO, :CD_SUBGRUPO, :CD_CLASSE, :CD_LABORATORIO, :DESCRICAO,
        :CUSTO, :PRECO, :ESTOQUE
  DO
   BEGIN
     CLASSE = '';
     GRUPO = '';
     LABORATORIO = '';
     IF (:CD_CLASSE IS NOT NULL) THEN
      BEGIN
        SELECT DESCRICAO FROM CLASSES WHERE CD_CLASSE = :CD_CLASSE INTO :CLASSE;
      END
     IF (:CD_GRUPO IS NOT NULL) THEN
      BEGIN
        SELECT DESCRICAO FROM GRUPOS WHERE CD_GRUPO = :CD_GRUPO INTO :GRUPO;
      END
     IF (:CD_LABORATORIO IS NOT NULL) THEN
      BEGIN
        SELECT NOME FROM LABORATORIOS WHERE CD_LABORATORIO = :CD_LABORATORIO INTO :LABORATORIO;
      END

     ESTOQUE_ANTERIOR = :ESTOQUE;
     IF (:METODO = 'S') THEN
        ESTOQUE = 0;
/*     INSERT INTO BALANCO VALUES (
      :ID_BALANCO, NULL, :DATA, :HORA, :DATA, :HORA, NULL, NULL, NULL, NULL,
      :CD_FILIAL, :ID, :CD, :BARRA, :BARRA2, :DESCRICAO, :CD_GRUPO, :GRUPO,  :CD_LABORATORIO, :LABORATORIO,
      :CD_CLASSE, :CLASSE, :CUSTO, :PRECO, :PRECO, :ESTOQUE, :ESTOQUE_ANTERIOR, :METODO, 'A', '');*/

     INSERT INTO BALANCO VALUES (
      :ID_BALANCO, NULL, :DATA, :HORA, :DATA, :HORA, NULL, NULL, NULL, NULL,
      :CD_FILIAL, :ID, :CD, :BARRA, :BARRA2, :DESCRICAO, :CD_GRUPO, :GRUPO,  :CD_LABORATORIO, :LABORATORIO,
      :CD_CLASSE, :CLASSE, :CUSTO, :PRECO, :PRECO, :ESTOQUE, NULL, :METODO, 'A', '', :CD_SUBGRUPO, NULL, NULL);
   END
END ^

ALTER PROCEDURE SP_DESBLOQUEIACLIENTEATRASO (CD_CLIENTE DOUBLE PRECISION)
AS 
declare variable DIASATRASO integer;
declare variable ATRASO integer;
BEGIN
 SELECT DIASBLOQUEIOCLIENTE FROM PARAMETROS INTO :DIASATRASO;
 IF (:DIASATRASO IS NOT NULL) THEN
  BEGIN
     SELECT
       COUNT(*)
     FROM
       CONTAS_RECEBER
     WHERE
       CD_CLIENTE = :CD_CLIENTE AND
       DT_VENCIMENTO <= CURRENT_DATE - :DIASATRASO AND
       STATUS = 'A'
     INTO
      :ATRASO;
    
     IF (:ATRASO = 0) THEN
        UPDATE CLIENTES SET STATUS = 'A' WHERE CD_CLIENTE = :CD_CLIENTE;
     ELSE
        UPDATE CLIENTES SET STATUS = 'B' WHERE CD_CLIENTE = :CD_CLIENTE;
  END
END ^

ALTER PROCEDURE SP_DESCONTOS_CLASSES (CD_VENDEDOR DOUBLE PRECISION,
CD_FILIAL DOUBLE PRECISION,
DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (CD_CLASSE DOUBLE PRECISION,
CLASSE VARCHAR(100) CHARACTER SET NONE,
TOTALGERAL DOUBLE PRECISION,
TOTALLIQUIDO DOUBLE PRECISION,
TOTALDESCONTO DOUBLE PRECISION,
DESCONTOVALOR DOUBLE PRECISION,
TOTALDESCONTOPBM DOUBLE PRECISION,
DESCONTOVALORPBM DOUBLE PRECISION,
DESCONTOPERCENTUAL DOUBLE PRECISION,
DESCONTOPERCENTUALPBM DOUBLE PRECISION,
TOTALPROMOCAO DOUBLE PRECISION,
PROMOCAOVALOR DOUBLE PRECISION,
PROMOCAOPERCENTUAL DOUBLE PRECISION,
TOTALDESCONTOFIDELIDADE DOUBLE PRECISION,
DESCONTOVALORFIDELIDADE DOUBLE PRECISION,
DESCONTOPERCENTUALFIDELIDADE DOUBLE PRECISION,
TOTALDESCONTOQUANTIDADE DOUBLE PRECISION,
DESCONTOVALORQUANTIDADE DOUBLE PRECISION,
DESCONTOPERCENTUALQUANTIDADE DOUBLE PRECISION,
DESCONTOSTOTAIS DOUBLE PRECISION,
PERCENTUALTOTAIS DOUBLE PRECISION,
PERCENTUALTOTAIS2 DOUBLE PRECISION)
AS 
declare variable TOTALLIQUIDODEVOLUCOES double precision;
declare variable TOTALDESCONTODEVOLUCOES double precision;
declare variable DESCONTOVALORDEVOLUCOES double precision;
declare variable TOTALDESCONTODEVOLUCOESPBM double precision;
declare variable DESCONTOVALORDEVOLUCOESPBM double precision;
declare variable TOTALPROMOCAODEVOLUCOES double precision;
declare variable PROMOCAOVALORDEVOLUCOES double precision;
declare variable TOTALDESCONTODEVOLUCOESFIDELIDADE double precision;
declare variable DESCONTOVALORDEVOLUCOESFIDELIDADE double precision;
declare variable TOTALDESCONTODEVOLUCOESQUANTIDADE double precision;
declare variable DESCONTOVALORDEVOLUCOESQUANTIDADE double precision;
declare variable SUBSIDIOVENDA double precision;
declare variable SUBSIDIODEVOLUCAO double precision;
BEGIN
 FOR
  SELECT
   LANCAMENTOS.CD_CLASSE
  FROM
   LANCAMENTOS
  WHERE
   ((LANCAMENTOS.TIPO_VENDA = 'V') OR (LANCAMENTOS.TIPO_VENDA = 'D'))  AND
   LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
   LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
   LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
   LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR AND
   LANCAMENTOS.CUSTO_UNITARIO > 0
  GROUP BY
   LANCAMENTOS.CD_CLASSE
  INTO
   :CD_CLASSE
 DO
  BEGIN
    TOTALGERAL = 0;
    TOTALLIQUIDO = 0;
    TOTALDESCONTO = 0;
    DESCONTOVALOR = 0;
    DESCONTOPERCENTUAL = 0;
    TOTALPROMOCAO = 0;
    PROMOCAOVALOR = 0;
    PROMOCAOPERCENTUAL = 0;

    TOTALDESCONTODEVOLUCOES = 0;
    DESCONTOVALORDEVOLUCOES = 0;
    TOTALPROMOCAODEVOLUCOES = 0;
    PROMOCAOVALORDEVOLUCOES = 0;

    SELECT
      SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO)
    FROM
      LANCAMENTOS
    WHERE
     LANCAMENTOS.TIPO_VENDA = 'V' AND
     LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
     LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR AND
     LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
     LANCAMENTOS.CUSTO_UNITARIO > 0
    INTO
     :TOTALLIQUIDO;

    SELECT
      SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO)
    FROM
      LANCAMENTOS
    WHERE
     LANCAMENTOS.TIPO_VENDA = 'D' AND
     LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
     LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR AND
     LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
     LANCAMENTOS.CUSTO_UNITARIO > 0
    INTO
     :TOTALLIQUIDODEVOLUCOES;

    IF (:TOTALLIQUIDO IS NULL) THEN
       TOTALLIQUIDO = 0;
    IF (:TOTALLIQUIDODEVOLUCOES IS NULL) THEN
       TOTALLIQUIDODEVOLUCOES = 0;

    TOTALLIQUIDO = :TOTALLIQUIDO - :TOTALLIQUIDODEVOLUCOES;

    SELECT
      SUM((LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO) + (LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)),
      SUM(LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)
    FROM
      LANCAMENTOS
    WHERE
     LANCAMENTOS.TIPO_VENDA = 'V' AND
     LANCAMENTOS.DESCONTO IS NOT NULL AND
     LANCAMENTOS.DESCONTO > 0 AND
     (LANCAMENTOS.PROMOCAO IS NULL OR LANCAMENTOS.PROMOCAO = 0) AND
     LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
     LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR AND
     LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
     LANCAMENTOS.CUSTO_UNITARIO > 0 AND
     ((LANCAMENTOS.VENDA_FIDELIDADE IS NULL) OR (LANCAMENTOS.VENDA_FIDELIDADE = 'N')) AND
     ((LANCAMENTOS.VENDA_QUANTIDADE IS NULL) OR (LANCAMENTOS.VENDA_QUANTIDADE = 'N')) AND
     (LANCAMENTOS.TRN IS NULL OR LANCAMENTOS.TRN = '' OR LANCAMENTOS.TRN = 'N')
    INTO
     :TOTALDESCONTO,
     :DESCONTOVALOR;

    SELECT
      SUM((LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO) + (LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)),
      SUM(LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)
    FROM
      LANCAMENTOS
    WHERE
     LANCAMENTOS.TIPO_VENDA = 'D' AND
     LANCAMENTOS.DESCONTO IS NOT NULL AND
     LANCAMENTOS.DESCONTO > 0 AND
     (LANCAMENTOS.PROMOCAO IS NULL OR LANCAMENTOS.PROMOCAO = 0) AND
     LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
     LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR AND
     LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
     LANCAMENTOS.CUSTO_UNITARIO > 0 AND
     ((LANCAMENTOS.VENDA_FIDELIDADE IS NULL) OR (LANCAMENTOS.VENDA_FIDELIDADE = 'N')) AND
     ((LANCAMENTOS.VENDA_QUANTIDADE IS NULL) OR (LANCAMENTOS.VENDA_QUANTIDADE = 'N')) AND
     (LANCAMENTOS.TRN IS NULL OR LANCAMENTOS.TRN = '' OR LANCAMENTOS.TRN = 'N')
    INTO
     :TOTALDESCONTODEVOLUCOES,
     :DESCONTOVALORDEVOLUCOES;

    IF (:TOTALDESCONTO IS NULL) THEN
       TOTALDESCONTO = 0;
    IF (:DESCONTOVALOR IS NULL) THEN
       DESCONTOVALOR = 0;
    IF (:TOTALDESCONTODEVOLUCOES IS NULL) THEN
       TOTALDESCONTODEVOLUCOES = 0;
    IF (:DESCONTOVALORDEVOLUCOES IS NULL) THEN
       DESCONTOVALORDEVOLUCOES = 0;

    TOTALDESCONTO = :TOTALDESCONTO - :TOTALDESCONTODEVOLUCOES;
    DESCONTOVALOR = :DESCONTOVALOR - :DESCONTOVALORDEVOLUCOES;

    IF (:TOTALDESCONTO > 0) THEN
     BEGIN
       DESCONTOPERCENTUAL = (:DESCONTOVALOR / :TOTALDESCONTO) * 100;
       IF (:DESCONTOPERCENTUAL IS NULL) THEN
          DESCONTOPERCENTUAL = 0;
     END
    ELSE
     BEGIN
      DESCONTOPERCENTUAL = 0;
     END
  
/* PBM */
    SELECT
      SUM(LANCAMENTOS.SUBSIDIOTRN),
      SUM((LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO) + (LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)),
      --SUM(LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)
      SUM((LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE) + LANCAMENTOS.SUBSIDIOTRN)
    FROM
      LANCAMENTOS
    WHERE
     LANCAMENTOS.TIPO_VENDA = 'V' AND
     ((LANCAMENTOS.DESCONTO IS NOT NULL AND LANCAMENTOS.DESCONTO > 0) OR (LANCAMENTOS.SUBSIDIOTRN IS NOT NULL AND LANCAMENTOS.SUBSIDIOTRN > 0)) AND
     (LANCAMENTOS.PROMOCAO IS NULL OR LANCAMENTOS.PROMOCAO = 0) AND
     LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
     LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR AND
     LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
     LANCAMENTOS.CUSTO_UNITARIO > 0 AND
     (LANCAMENTOS.TRN <> '' AND LANCAMENTOS.TRN IS NOT NULL) AND (LANCAMENTOS.TRN <> 'N')
    INTO
     :SUBSIDIOVENDA,
     :TOTALDESCONTOPBM,
     :DESCONTOVALORPBM;

    SELECT
      SUM(LANCAMENTOS.SUBSIDIOTRN),
      SUM((LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO) + (LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)),
      --SUM(LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)
      SUM((LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE) + LANCAMENTOS.SUBSIDIOTRN)
    FROM
      LANCAMENTOS
    WHERE
     LANCAMENTOS.TIPO_VENDA = 'D' AND
     ((LANCAMENTOS.DESCONTO IS NOT NULL AND LANCAMENTOS.DESCONTO > 0) OR (LANCAMENTOS.SUBSIDIOTRN IS NOT NULL AND LANCAMENTOS.SUBSIDIOTRN > 0)) AND
     (LANCAMENTOS.PROMOCAO IS NULL OR LANCAMENTOS.PROMOCAO = 0) AND
     LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
     LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR AND
     LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
     LANCAMENTOS.CUSTO_UNITARIO > 0 AND
     (LANCAMENTOS.TRN <> '' AND LANCAMENTOS.TRN IS NOT NULL) AND (LANCAMENTOS.TRN <> 'N')
    INTO
     :SUBSIDIODEVOLUCAO, 
     :TOTALDESCONTODEVOLUCOESPBM,
     :DESCONTOVALORDEVOLUCOESPBM;

    IF (:SUBSIDIOVENDA IS NULL) THEN
       SUBSIDIOVENDA = 0;
    IF (:SUBSIDIODEVOLUCAO IS NULL) THEN
       SUBSIDIODEVOLUCAO = 0;
    IF (:TOTALDESCONTOPBM IS NULL) THEN
       TOTALDESCONTOPBM = 0;
    IF (:DESCONTOVALORPBM IS NULL) THEN
       DESCONTOVALORPBM = 0;
    IF (:TOTALDESCONTODEVOLUCOESPBM IS NULL) THEN
       TOTALDESCONTODEVOLUCOESPBM = 0;
    IF (:DESCONTOVALORDEVOLUCOESPBM IS NULL) THEN
       DESCONTOVALORDEVOLUCOESPBM = 0;

    TOTALDESCONTOPBM = :TOTALDESCONTOPBM - :TOTALDESCONTODEVOLUCOESPBM + :SUBSIDIOVENDA - :SUBSIDIODEVOLUCAO;
    DESCONTOVALORPBM = :DESCONTOVALORPBM - :DESCONTOVALORDEVOLUCOESPBM;

    IF (:TOTALDESCONTOPBM > 0) THEN
     BEGIN
       DESCONTOPERCENTUALPBM = (:DESCONTOVALORPBM / :TOTALDESCONTOPBM) * 100;
       IF (:DESCONTOPERCENTUALPBM IS NULL) THEN
          DESCONTOPERCENTUALPBM = 0;
     END
    ELSE
     BEGIN
       DESCONTOPERCENTUALPBM = 0;
     END


    SELECT
      SUM((LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO) + (LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)),
      SUM(LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)
    FROM
      LANCAMENTOS
    WHERE
     LANCAMENTOS.TIPO_VENDA = 'V' AND
     LANCAMENTOS.PROMOCAO IS NOT NULL AND
     LANCAMENTOS.PROMOCAO > 0 AND
     LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
     LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR AND
     LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
     LANCAMENTOS.CUSTO_UNITARIO > 0 AND
     (LANCAMENTOS.TRN IS NULL OR LANCAMENTOS.TRN = '' OR LANCAMENTOS.TRN = 'N')
    INTO
     :TOTALPROMOCAO,
     :PROMOCAOVALOR;
  
    SELECT
      SUM((LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO) + (LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)),
      SUM(LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)
    FROM
      LANCAMENTOS
    WHERE
     LANCAMENTOS.TIPO_VENDA = 'D' AND
     LANCAMENTOS.PROMOCAO IS NOT NULL AND
     LANCAMENTOS.PROMOCAO > 0 AND
     LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
     LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR AND
     LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
     LANCAMENTOS.CUSTO_UNITARIO > 0 AND
     (LANCAMENTOS.TRN IS NULL OR LANCAMENTOS.TRN = '' OR LANCAMENTOS.TRN = 'N')
    INTO
     :TOTALPROMOCAODEVOLUCOES,
     :PROMOCAOVALORDEVOLUCOES;

    IF (:TOTALPROMOCAO IS NULL) THEN
       TOTALPROMOCAO = 0;
    IF (:PROMOCAOVALOR IS NULL) THEN
       PROMOCAOVALOR = 0;
    IF (:TOTALPROMOCAODEVOLUCOES IS NULL) THEN
       TOTALPROMOCAODEVOLUCOES = 0;
    IF (:PROMOCAOVALORDEVOLUCOES IS NULL) THEN
       PROMOCAOVALORDEVOLUCOES = 0;

    TOTALPROMOCAO = :TOTALPROMOCAO - :TOTALPROMOCAODEVOLUCOES;
    PROMOCAOVALOR = :PROMOCAOVALOR - :PROMOCAOVALORDEVOLUCOES;

    IF (:TOTALPROMOCAO > 0) THEN
     BEGIN
       PROMOCAOPERCENTUAL = (:PROMOCAOVALOR / :TOTALPROMOCAO) * 100;
       IF (:PROMOCAOPERCENTUAL IS NULL) THEN
          PROMOCAOPERCENTUAL = 0;
     END
    ELSE
     BEGIN
       PROMOCAOPERCENTUAL = 0;
     END
  
/* FIDELIDADE */
    SELECT
      SUM((LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO) + (LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)),
      SUM(LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)
    FROM
      LANCAMENTOS
    WHERE
     LANCAMENTOS.TIPO_VENDA = 'V' AND
     LANCAMENTOS.DESCONTO IS NOT NULL AND
     LANCAMENTOS.DESCONTO > 0 AND
     (LANCAMENTOS.PROMOCAO IS NULL OR LANCAMENTOS.PROMOCAO = 0) AND
     LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
     LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR AND
     LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
     LANCAMENTOS.CUSTO_UNITARIO > 0 AND
     LANCAMENTOS.VENDA_FIDELIDADE = 'S' AND
     (LANCAMENTOS.TRN IS NULL OR LANCAMENTOS.TRN = '' OR LANCAMENTOS.TRN = 'N')
    INTO
     :TOTALDESCONTOFIDELIDADE,
     :DESCONTOVALORFIDELIDADE;

    SELECT
      SUM((LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO) + (LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)),
      SUM(LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)
    FROM
      LANCAMENTOS
    WHERE
     LANCAMENTOS.TIPO_VENDA = 'D' AND
     LANCAMENTOS.DESCONTO IS NOT NULL AND
     LANCAMENTOS.DESCONTO > 0 AND
     (LANCAMENTOS.PROMOCAO IS NULL OR LANCAMENTOS.PROMOCAO = 0) AND
     LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
     LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR AND
     LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
     LANCAMENTOS.CUSTO_UNITARIO > 0 AND
     LANCAMENTOS.VENDA_FIDELIDADE = 'S' AND
     (LANCAMENTOS.TRN IS NULL OR LANCAMENTOS.TRN = '' OR LANCAMENTOS.TRN = 'N')
    INTO
     :TOTALDESCONTODEVOLUCOESFIDELIDADE,
     :DESCONTOVALORDEVOLUCOESFIDELIDADE;

    IF (:TOTALDESCONTOFIDELIDADE IS NULL) THEN
       TOTALDESCONTOFIDELIDADE = 0;
    IF (:DESCONTOVALORFIDELIDADE IS NULL) THEN
       DESCONTOVALORFIDELIDADE = 0;
    IF (:TOTALDESCONTODEVOLUCOESFIDELIDADE IS NULL) THEN
       TOTALDESCONTODEVOLUCOESFIDELIDADE = 0;
    IF (:DESCONTOVALORDEVOLUCOESFIDELIDADE IS NULL) THEN
       DESCONTOVALORDEVOLUCOESFIDELIDADE = 0;

    TOTALDESCONTOFIDELIDADE = :TOTALDESCONTOFIDELIDADE - :TOTALDESCONTODEVOLUCOESFIDELIDADE;
    DESCONTOVALORFIDELIDADE = :DESCONTOVALORFIDELIDADE - :DESCONTOVALORDEVOLUCOESFIDELIDADE;

    IF (:TOTALDESCONTOFIDELIDADE > 0) THEN
     BEGIN
       DESCONTOPERCENTUALFIDELIDADE = (:DESCONTOVALORFIDELIDADE / :TOTALDESCONTOFIDELIDADE) * 100;
       IF (:DESCONTOPERCENTUALFIDELIDADE IS NULL) THEN
          DESCONTOPERCENTUALFIDELIDADE = 0;
     END
    ELSE
     BEGIN
      DESCONTOPERCENTUALFIDELIDADE = 0;
     END
/* FIDELIDADE */


/* QUANTIDADE */
    SELECT
      SUM((LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO) + (LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)),
      SUM(LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)
    FROM
      LANCAMENTOS
    WHERE
     LANCAMENTOS.TIPO_VENDA = 'V' AND
     LANCAMENTOS.DESCONTO IS NOT NULL AND
     LANCAMENTOS.DESCONTO > 0 AND
     (LANCAMENTOS.PROMOCAO IS NULL OR LANCAMENTOS.PROMOCAO = 0) AND
     LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
     LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR AND
     LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
     LANCAMENTOS.CUSTO_UNITARIO > 0 AND
     LANCAMENTOS.VENDA_QUANTIDADE = 'S' AND
     (LANCAMENTOS.TRN IS NULL OR LANCAMENTOS.TRN = '' OR LANCAMENTOS.TRN = 'N')
    INTO
     :TOTALDESCONTOQUANTIDADE,
     :DESCONTOVALORQUANTIDADE;

    SELECT
      SUM((LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO) + (LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)),
      SUM(LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)
    FROM
      LANCAMENTOS
    WHERE
     LANCAMENTOS.TIPO_VENDA = 'D' AND
     LANCAMENTOS.DESCONTO IS NOT NULL AND
     LANCAMENTOS.DESCONTO > 0 AND
     (LANCAMENTOS.PROMOCAO IS NULL OR LANCAMENTOS.PROMOCAO = 0) AND
     LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
     LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR AND
     LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
     LANCAMENTOS.CUSTO_UNITARIO > 0 AND
     LANCAMENTOS.VENDA_QUANTIDADE = 'S' AND
     (LANCAMENTOS.TRN IS NULL OR LANCAMENTOS.TRN = '' OR LANCAMENTOS.TRN = 'N')
    INTO
     :TOTALDESCONTODEVOLUCOESQUANTIDADE,
     :DESCONTOVALORDEVOLUCOESQUANTIDADE;

    IF (:TOTALDESCONTOQUANTIDADE IS NULL) THEN
       TOTALDESCONTOQUANTIDADE = 0;
    IF (:DESCONTOVALORQUANTIDADE IS NULL) THEN
       DESCONTOVALORQUANTIDADE = 0;
    IF (:TOTALDESCONTODEVOLUCOESQUANTIDADE IS NULL) THEN
       TOTALDESCONTODEVOLUCOESQUANTIDADE = 0;
    IF (:DESCONTOVALORDEVOLUCOESQUANTIDADE IS NULL) THEN
       DESCONTOVALORDEVOLUCOESQUANTIDADE = 0;

    TOTALDESCONTOQUANTIDADE = :TOTALDESCONTOQUANTIDADE - :TOTALDESCONTODEVOLUCOESQUANTIDADE;
    DESCONTOVALORQUANTIDADE = :DESCONTOVALORQUANTIDADE - :DESCONTOVALORDEVOLUCOESQUANTIDADE;

    IF (:TOTALDESCONTOQUANTIDADE > 0) THEN
     BEGIN
       DESCONTOPERCENTUALQUANTIDADE = (:DESCONTOVALORQUANTIDADE / :TOTALDESCONTOQUANTIDADE) * 100;
       IF (:DESCONTOPERCENTUALQUANTIDADE IS NULL) THEN
          DESCONTOPERCENTUALQUANTIDADE = 0;
     END
    ELSE
     BEGIN
      DESCONTOPERCENTUALFIDELIDADE = 0;
     END
/* QUANTIDADE */

   TOTALGERAL = :TOTALLIQUIDO + :DESCONTOVALOR + :PROMOCAOVALOR + :DESCONTOVALORPBM;

   DESCONTOSTOTAIS = :DESCONTOVALOR + :PROMOCAOVALOR + :DESCONTOVALORPBM;
   IF ((:TOTALDESCONTO > 0) OR (:TOTALPROMOCAO > 0) OR (:TOTALDESCONTOPBM > 0) OR (:TOTALDESCONTOFIDELIDADE > 0) OR (:TOTALDESCONTOQUANTIDADE > 0)) THEN
      PERCENTUALTOTAIS = (:DESCONTOSTOTAIS / (:TOTALDESCONTO + :TOTALPROMOCAO + :TOTALDESCONTOPBM + :TOTALDESCONTOFIDELIDADE + :TOTALDESCONTOQUANTIDADE)) * 100;
   ELSE
      PERCENTUALTOTAIS = 0;
   IF (:TOTALGERAL > 0) THEN
      PERCENTUALTOTAIS2 = (:DESCONTOSTOTAIS / :TOTALGERAL) * 100;
   ELSE
      PERCENTUALTOTAIS2 = 0;

   SELECT DESCRICAO FROM CLASSES WHERE CD_CLASSE = :CD_CLASSE INTO :CLASSE;

   SUSPEND;
  END
END ^

ALTER PROCEDURE SP_DESCONTOS_CLASSES_FILIAL (CD_FILIAL DOUBLE PRECISION,
DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (CD_CLASSE DOUBLE PRECISION,
CLASSE VARCHAR(100) CHARACTER SET NONE,
TOTALGERAL DOUBLE PRECISION,
TOTALLIQUIDO DOUBLE PRECISION,
TOTALDESCONTO DOUBLE PRECISION,
DESCONTOVALOR DOUBLE PRECISION,
DESCONTOPERCENTUAL DOUBLE PRECISION,
TOTALDESCONTOPBM DOUBLE PRECISION,
DESCONTOVALORPBM DOUBLE PRECISION,
DESCONTOPERCENTUALPBM DOUBLE PRECISION,
TOTALPROMOCAO DOUBLE PRECISION,
PROMOCAOVALOR DOUBLE PRECISION,
PROMOCAOPERCENTUAL DOUBLE PRECISION,
TOTALDESCONTOFIDELIDADE DOUBLE PRECISION,
DESCONTOVALORFIDELIDADE DOUBLE PRECISION,
DESCONTOPERCENTUALFIDELIDADE DOUBLE PRECISION,
TOTALDESCONTOQUANTIDADE DOUBLE PRECISION,
DESCONTOVALORQUANTIDADE DOUBLE PRECISION,
DESCONTOPERCENTUALQUANTIDADE DOUBLE PRECISION,
DESCONTOSTOTAIS DOUBLE PRECISION,
PERCENTUALTOTAIS DOUBLE PRECISION,
PERCENTUALTOTAIS2 DOUBLE PRECISION)
AS 
declare variable TOTALLIQUIDODEVOLUCOES double precision;
declare variable TOTALDESCONTODEVOLUCOES double precision;
declare variable DESCONTOVALORDEVOLUCOES double precision;
declare variable TOTALDESCONTODEVOLUCOESPBM double precision;
declare variable DESCONTOVALORDEVOLUCOESPBM double precision;
declare variable TOTALPROMOCAODEVOLUCOES double precision;
declare variable PROMOCAOVALORDEVOLUCOES double precision;
declare variable TOTALDESCONTODEVOLUCOESFIDELIDADE double precision;
declare variable DESCONTOVALORDEVOLUCOESFIDELIDADE double precision;
declare variable TOTALDESCONTODEVOLUCOESQUANTIDADE double precision;
declare variable DESCONTOVALORDEVOLUCOESQUANTIDADE double precision;
declare variable SUBSIDIOVENDA double precision;
declare variable SUBSIDIODEVOLUCAO double precision;
BEGIN
 FOR
  SELECT
   LANCAMENTOS.CD_CLASSE
  FROM
   LANCAMENTOS
  WHERE
   ((LANCAMENTOS.TIPO_VENDA = 'V') OR (LANCAMENTOS.TIPO_VENDA = 'D'))  AND
   LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
   LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
   LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
   LANCAMENTOS.CUSTO_UNITARIO > 0
  GROUP BY
   LANCAMENTOS.CD_CLASSE
  INTO
   :CD_CLASSE
 DO
  BEGIN
    TOTALGERAL = 0;
    TOTALLIQUIDO = 0;
    TOTALDESCONTO = 0;
    DESCONTOVALOR = 0;
    DESCONTOPERCENTUAL = 0;
    TOTALPROMOCAO = 0;
    PROMOCAOVALOR = 0;
    PROMOCAOPERCENTUAL = 0;

    TOTALDESCONTODEVOLUCOES = 0;
    DESCONTOVALORDEVOLUCOES = 0;
    TOTALPROMOCAODEVOLUCOES = 0;
    PROMOCAOVALORDEVOLUCOES = 0;
    SUBSIDIOVENDA = 0;
    SUBSIDIODEVOLUCAO = 0;

    SELECT
      SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO)
    FROM
      LANCAMENTOS
    WHERE
     LANCAMENTOS.TIPO_VENDA = 'V' AND
     LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
     LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
     LANCAMENTOS.CUSTO_UNITARIO > 0
    INTO
     :TOTALLIQUIDO;

    SELECT
      SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO)
    FROM
      LANCAMENTOS
    WHERE
     LANCAMENTOS.TIPO_VENDA = 'D' AND
     LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
     LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
     LANCAMENTOS.CUSTO_UNITARIO > 0
    INTO
     :TOTALLIQUIDODEVOLUCOES;

    IF (:TOTALGERAL IS NULL) THEN
       TOTALGERAL = 0;
    IF (:TOTALLIQUIDO IS NULL) THEN
       TOTALLIQUIDO = 0;
    IF (:TOTALLIQUIDODEVOLUCOES IS NULL) THEN
       TOTALLIQUIDODEVOLUCOES = 0;

    TOTALLIQUIDO = :TOTALLIQUIDO - :TOTALLIQUIDODEVOLUCOES;

    SELECT
      SUM((LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO) + (LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)),
      SUM(LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)
    FROM
      LANCAMENTOS
    WHERE
     LANCAMENTOS.TIPO_VENDA = 'V' AND
     LANCAMENTOS.DESCONTO IS NOT NULL AND
     LANCAMENTOS.DESCONTO > 0 AND
     (LANCAMENTOS.PROMOCAO IS NULL OR LANCAMENTOS.PROMOCAO = 0) AND
     LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
     LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
     LANCAMENTOS.CUSTO_UNITARIO > 0 AND
     ((LANCAMENTOS.VENDA_FIDELIDADE IS NULL) OR (LANCAMENTOS.VENDA_FIDELIDADE = 'N')) AND
     ((LANCAMENTOS.VENDA_QUANTIDADE IS NULL) OR (LANCAMENTOS.VENDA_QUANTIDADE = 'N')) AND
     (LANCAMENTOS.TRN = '' OR LANCAMENTOS.TRN IS NULL OR LANCAMENTOS.TRN = 'N')
    INTO
     :TOTALDESCONTO,
     :DESCONTOVALOR;

    SELECT
      SUM((LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO) + (LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)),
      SUM(LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)
    FROM
      LANCAMENTOS
    WHERE
     LANCAMENTOS.TIPO_VENDA = 'D' AND
     LANCAMENTOS.DESCONTO IS NOT NULL AND
     LANCAMENTOS.DESCONTO > 0 AND
     (LANCAMENTOS.PROMOCAO IS NULL OR LANCAMENTOS.PROMOCAO = 0) AND
     LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
     LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
     LANCAMENTOS.CUSTO_UNITARIO > 0 AND
     ((LANCAMENTOS.VENDA_FIDELIDADE IS NULL) OR (LANCAMENTOS.VENDA_FIDELIDADE = 'N')) AND
     ((LANCAMENTOS.VENDA_QUANTIDADE IS NULL) OR (LANCAMENTOS.VENDA_QUANTIDADE = 'N')) AND
     (LANCAMENTOS.TRN = '' OR LANCAMENTOS.TRN IS NULL OR LANCAMENTOS.TRN = 'N')
    INTO
     :TOTALDESCONTODEVOLUCOES,
     :DESCONTOVALORDEVOLUCOES;

    IF (:TOTALDESCONTO IS NULL) THEN
       TOTALDESCONTO = 0;
    IF (:DESCONTOVALOR IS NULL) THEN
       DESCONTOVALOR = 0;
    IF (:TOTALDESCONTODEVOLUCOES IS NULL) THEN
       TOTALDESCONTODEVOLUCOES = 0;
    IF (:DESCONTOVALORDEVOLUCOES IS NULL) THEN
       DESCONTOVALORDEVOLUCOES = 0;

    TOTALDESCONTO = :TOTALDESCONTO - :TOTALDESCONTODEVOLUCOES;
    DESCONTOVALOR = :DESCONTOVALOR - :DESCONTOVALORDEVOLUCOES;

    IF (:TOTALDESCONTO > 0) THEN
     BEGIN
       DESCONTOPERCENTUAL = (:DESCONTOVALOR / :TOTALDESCONTO) * 100;
       IF (:DESCONTOPERCENTUAL IS NULL) THEN
          DESCONTOPERCENTUAL = 0;
     END
    ELSE
     BEGIN
      DESCONTOPERCENTUAL = 0;
     END
  

    SELECT
      SUM(LANCAMENTOS.SUBSIDIOTRN),
      SUM((LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO) + (LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)),
      --SUM(LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)
      SUM((LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE) + LANCAMENTOS.SUBSIDIOTRN)
    FROM
      LANCAMENTOS
    WHERE
     LANCAMENTOS.TIPO_VENDA = 'V' AND
     ((LANCAMENTOS.DESCONTO IS NOT NULL AND LANCAMENTOS.DESCONTO > 0) OR (LANCAMENTOS.SUBSIDIOTRN IS NOT NULL AND LANCAMENTOS.SUBSIDIOTRN > 0)) AND
     LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
     LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
     LANCAMENTOS.CUSTO_UNITARIO > 0 AND
     (LANCAMENTOS.TRN <> '' AND LANCAMENTOS.TRN IS NOT NULL) AND (LANCAMENTOS.TRN <> 'N')
    INTO
     :SUBSIDIOVENDA,
     :TOTALDESCONTOPBM,
     :DESCONTOVALORPBM;

    SELECT
      SUM(LANCAMENTOS.SUBSIDIOTRN),
      SUM((LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO) + (LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)),
      --SUM(LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)
      SUM((LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE) + LANCAMENTOS.SUBSIDIOTRN)
    FROM
      LANCAMENTOS
    WHERE
     LANCAMENTOS.TIPO_VENDA = 'D' AND
     ((LANCAMENTOS.DESCONTO IS NOT NULL AND LANCAMENTOS.DESCONTO > 0) OR (LANCAMENTOS.SUBSIDIOTRN IS NOT NULL AND LANCAMENTOS.SUBSIDIOTRN > 0)) AND
     LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
     LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
     LANCAMENTOS.CUSTO_UNITARIO > 0 AND
     (LANCAMENTOS.TRN <> '' AND LANCAMENTOS.TRN IS NOT NULL AND LANCAMENTOS.TRN <> 'N')
    INTO
     :SUBSIDIODEVOLUCAO, 
     :TOTALDESCONTODEVOLUCOESPBM,
     :DESCONTOVALORDEVOLUCOESPBM;

    IF (:SUBSIDIOVENDA IS NULL) THEN
       SUBSIDIOVENDA = 0;
    IF (:SUBSIDIODEVOLUCAO IS NULL) THEN
       SUBSIDIODEVOLUCAO = 0;
    IF (:TOTALDESCONTOPBM IS NULL) THEN
       TOTALDESCONTOPBM = 0;
    IF (:DESCONTOVALORPBM IS NULL) THEN
       DESCONTOVALORPBM = 0;
    IF (:TOTALDESCONTODEVOLUCOESPBM IS NULL) THEN
       TOTALDESCONTODEVOLUCOESPBM = 0;
    IF (:DESCONTOVALORDEVOLUCOESPBM IS NULL) THEN
       DESCONTOVALORDEVOLUCOESPBM = 0;

    TOTALDESCONTOPBM = :TOTALDESCONTOPBM - :TOTALDESCONTODEVOLUCOESPBM + :SUBSIDIOVENDA - :SUBSIDIODEVOLUCAO;
    DESCONTOVALORPBM = :DESCONTOVALORPBM - :DESCONTOVALORDEVOLUCOESPBM;

    IF (:TOTALDESCONTOPBM > 0) THEN
     BEGIN
       DESCONTOPERCENTUALPBM = (:DESCONTOVALORPBM / :TOTALDESCONTOPBM) * 100;
       IF (:DESCONTOPERCENTUALPBM IS NULL) THEN
          DESCONTOPERCENTUALPBM = 0;
     END
    ELSE
     BEGIN
       DESCONTOPERCENTUALPBM = 0;
     END


    SELECT
      SUM((LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO) + (LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)),
      SUM(LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)
    FROM
      LANCAMENTOS
    WHERE
     LANCAMENTOS.TIPO_VENDA = 'V' AND
     LANCAMENTOS.PROMOCAO IS NOT NULL AND
     LANCAMENTOS.PROMOCAO > 0 AND
     LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
     LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
     LANCAMENTOS.CUSTO_UNITARIO > 0 AND
     (LANCAMENTOS.TRN = '' OR LANCAMENTOS.TRN IS NULL OR LANCAMENTOS.TRN = 'N')
    INTO
     :TOTALPROMOCAO,
     :PROMOCAOVALOR;
  
    SELECT
      SUM((LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO) + (LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)),
      SUM(LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)
    FROM
      LANCAMENTOS
    WHERE
     LANCAMENTOS.TIPO_VENDA = 'D' AND
     LANCAMENTOS.PROMOCAO IS NOT NULL AND
     LANCAMENTOS.PROMOCAO > 0 AND
     LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
     LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
     LANCAMENTOS.CUSTO_UNITARIO > 0 AND
     (LANCAMENTOS.TRN = '' OR LANCAMENTOS.TRN IS NULL OR LANCAMENTOS.TRN = 'N')
    INTO
     :TOTALPROMOCAODEVOLUCOES,
     :PROMOCAOVALORDEVOLUCOES;

    IF (:TOTALPROMOCAO IS NULL) THEN
       TOTALPROMOCAO = 0;
    IF (:PROMOCAOVALOR IS NULL) THEN
       PROMOCAOVALOR = 0;
    IF (:TOTALPROMOCAODEVOLUCOES IS NULL) THEN
       TOTALPROMOCAODEVOLUCOES = 0;
    IF (:PROMOCAOVALORDEVOLUCOES IS NULL) THEN
       PROMOCAOVALORDEVOLUCOES = 0;

    TOTALPROMOCAO = :TOTALPROMOCAO - :TOTALPROMOCAODEVOLUCOES;
    PROMOCAOVALOR = :PROMOCAOVALOR - :PROMOCAOVALORDEVOLUCOES;

    IF (:TOTALPROMOCAO > 0) THEN                                                  
     BEGIN
       PROMOCAOPERCENTUAL = (:PROMOCAOVALOR / :TOTALPROMOCAO) * 100;
       IF (:PROMOCAOPERCENTUAL IS NULL) THEN
          PROMOCAOPERCENTUAL = 0;
     END
    ELSE
     BEGIN
       PROMOCAOPERCENTUAL = 0;
     END
  
/* FIDELIDADE */
    SELECT
      SUM((LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO) + (LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)),
      SUM(LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)
    FROM
      LANCAMENTOS
    WHERE
     LANCAMENTOS.TIPO_VENDA = 'V' AND
     LANCAMENTOS.DESCONTO IS NOT NULL AND
     LANCAMENTOS.DESCONTO > 0 AND
     (LANCAMENTOS.PROMOCAO IS NULL OR LANCAMENTOS.PROMOCAO = 0) AND
     LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
     LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
     LANCAMENTOS.CUSTO_UNITARIO > 0 AND
     LANCAMENTOS.VENDA_FIDELIDADE = 'S' AND
     (LANCAMENTOS.TRN = '' OR LANCAMENTOS.TRN IS NULL OR LANCAMENTOS.TRN = 'N')
    INTO
     :TOTALDESCONTOFIDELIDADE,
     :DESCONTOVALORFIDELIDADE;

    SELECT
      SUM((LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO) + (LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)),
      SUM(LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)
    FROM
      LANCAMENTOS
    WHERE
     LANCAMENTOS.TIPO_VENDA = 'D' AND
     LANCAMENTOS.DESCONTO IS NOT NULL AND
     LANCAMENTOS.DESCONTO > 0 AND
     (LANCAMENTOS.PROMOCAO IS NULL OR LANCAMENTOS.PROMOCAO = 0) AND
     LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
     LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
     LANCAMENTOS.CUSTO_UNITARIO > 0 AND
     LANCAMENTOS.VENDA_FIDELIDADE = 'S' AND
     (LANCAMENTOS.TRN = '' OR LANCAMENTOS.TRN IS NULL OR LANCAMENTOS.TRN = 'N')
    INTO
     :TOTALDESCONTODEVOLUCOESFIDELIDADE,
     :DESCONTOVALORDEVOLUCOESFIDELIDADE;

    IF (:TOTALDESCONTOFIDELIDADE IS NULL) THEN
       TOTALDESCONTOFIDELIDADE = 0;
    IF (:DESCONTOVALORFIDELIDADE IS NULL) THEN
       DESCONTOVALORFIDELIDADE = 0;
    IF (:TOTALDESCONTODEVOLUCOESFIDELIDADE IS NULL) THEN
       TOTALDESCONTODEVOLUCOESFIDELIDADE = 0;
    IF (:DESCONTOVALORDEVOLUCOESFIDELIDADE IS NULL) THEN
       DESCONTOVALORDEVOLUCOESFIDELIDADE = 0;

    TOTALDESCONTOFIDELIDADE = :TOTALDESCONTOFIDELIDADE - :TOTALDESCONTODEVOLUCOESFIDELIDADE;
    DESCONTOVALORFIDELIDADE = :DESCONTOVALORFIDELIDADE - :DESCONTOVALORDEVOLUCOESFIDELIDADE;

    IF (:TOTALDESCONTOFIDELIDADE > 0) THEN
     BEGIN
       DESCONTOPERCENTUALFIDELIDADE = (:DESCONTOVALORFIDELIDADE / :TOTALDESCONTOFIDELIDADE) * 100;
       IF (:DESCONTOPERCENTUALFIDELIDADE IS NULL) THEN
          DESCONTOPERCENTUALFIDELIDADE = 0;
     END
    ELSE
     BEGIN
      DESCONTOPERCENTUALFIDELIDADE = 0;
     END
/* FIDELIDADE */


/* QUANTIDADE */
    SELECT
      SUM((LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO) + (LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)),
      SUM(LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)
    FROM
      LANCAMENTOS
    WHERE
     LANCAMENTOS.TIPO_VENDA = 'V' AND
     LANCAMENTOS.DESCONTO IS NOT NULL AND
     LANCAMENTOS.DESCONTO > 0 AND
     (LANCAMENTOS.PROMOCAO IS NULL OR LANCAMENTOS.PROMOCAO = 0) AND
     LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
     LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
     LANCAMENTOS.CUSTO_UNITARIO > 0 AND
     LANCAMENTOS.VENDA_QUANTIDADE = 'S' AND
     (LANCAMENTOS.TRN = '' OR LANCAMENTOS.TRN IS NULL OR LANCAMENTOS.TRN = 'N')
    INTO
     :TOTALDESCONTOQUANTIDADE,
     :DESCONTOVALORQUANTIDADE;

    SELECT
      SUM((LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO) + (LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)),
      SUM(LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)
    FROM
      LANCAMENTOS
    WHERE
     LANCAMENTOS.TIPO_VENDA = 'D' AND
     LANCAMENTOS.DESCONTO IS NOT NULL AND
     LANCAMENTOS.DESCONTO > 0 AND
     (LANCAMENTOS.PROMOCAO IS NULL OR LANCAMENTOS.PROMOCAO = 0) AND
     LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
     LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
     LANCAMENTOS.CUSTO_UNITARIO > 0 AND
     LANCAMENTOS.VENDA_QUANTIDADE = 'S' AND
     (LANCAMENTOS.TRN = '' OR LANCAMENTOS.TRN IS NULL OR LANCAMENTOS.TRN = 'N')
    INTO
     :TOTALDESCONTODEVOLUCOESQUANTIDADE,
     :DESCONTOVALORDEVOLUCOESQUANTIDADE;

    IF (:TOTALDESCONTOQUANTIDADE IS NULL) THEN
       TOTALDESCONTOQUANTIDADE = 0;
    IF (:DESCONTOVALORQUANTIDADE IS NULL) THEN
       DESCONTOVALORQUANTIDADE = 0;
    IF (:TOTALDESCONTODEVOLUCOESQUANTIDADE IS NULL) THEN
       TOTALDESCONTODEVOLUCOESQUANTIDADE = 0;
    IF (:DESCONTOVALORDEVOLUCOESQUANTIDADE IS NULL) THEN
       DESCONTOVALORDEVOLUCOESQUANTIDADE = 0;

    TOTALDESCONTOQUANTIDADE = :TOTALDESCONTOQUANTIDADE - :TOTALDESCONTODEVOLUCOESQUANTIDADE;
    DESCONTOVALORQUANTIDADE = :DESCONTOVALORQUANTIDADE - :DESCONTOVALORDEVOLUCOESQUANTIDADE;

    IF (:TOTALDESCONTOQUANTIDADE > 0) THEN
     BEGIN
       DESCONTOPERCENTUALQUANTIDADE = (:DESCONTOVALORQUANTIDADE / :TOTALDESCONTOQUANTIDADE) * 100;
       IF (:DESCONTOPERCENTUALQUANTIDADE IS NULL) THEN
          DESCONTOPERCENTUALQUANTIDADE = 0;
     END
    ELSE
     BEGIN
      DESCONTOPERCENTUALQUANTIDADE = 0;
     END
/* QUANTIDADE */


/* TOTAIS */
   TOTALGERAL = :TOTALLIQUIDO + :DESCONTOVALOR + :PROMOCAOVALOR + :DESCONTOVALORPBM;

   DESCONTOSTOTAIS = :DESCONTOVALOR + :PROMOCAOVALOR + :DESCONTOVALORPBM;
   IF ((:TOTALDESCONTO > 0) OR (:TOTALPROMOCAO > 0) OR (:TOTALDESCONTOPBM > 0) OR (:TOTALDESCONTOFIDELIDADE > 0) OR (:TOTALDESCONTOQUANTIDADE > 0)) THEN
      PERCENTUALTOTAIS = (:DESCONTOSTOTAIS / (:TOTALDESCONTO + :TOTALPROMOCAO + :TOTALDESCONTOPBM + :TOTALDESCONTOFIDELIDADE + :TOTALDESCONTOQUANTIDADE)) * 100;
   ELSE
      PERCENTUALTOTAIS = 0;
   IF (:TOTALGERAL > 0) THEN
      PERCENTUALTOTAIS2 = (:DESCONTOSTOTAIS / :TOTALGERAL) * 100;
   ELSE
      PERCENTUALTOTAIS2 = 0;
/* TOTAIS */

   SELECT DESCRICAO FROM CLASSES WHERE CD_CLASSE = :CD_CLASSE INTO :CLASSE;

   SUSPEND;
  END
END ^

ALTER PROCEDURE SP_DESCONTOS_VENDAS (FILIAL DOUBLE PRECISION,
DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (CD_VENDEDOR DOUBLE PRECISION,
VENDEDOR VARCHAR(100) CHARACTER SET NONE,
VALORVENDAS DOUBLE PRECISION,
QUANTIDADEITENS DOUBLE PRECISION,
MEDIAUNITARIA DOUBLE PRECISION,
NUMEROVENDAS DOUBLE PRECISION,
NUMEROVENDAS2 DOUBLE PRECISION,
MEDIACUPOM DOUBLE PRECISION)
AS 
DECLARE VARIABLE VALORCANCELADO DOUBLE PRECISION;
DECLARE VARIABLE QUANTIDADECANCELADA DOUBLE PRECISION;
DECLARE VARIABLE NUMEROCANCELADO DOUBLE PRECISION;
BEGIN
  FOR
    SELECT
     LANCAMENTOS.CD_VENDEDOR
    FROM
     LANCAMENTOS
    WHERE
     ((LANCAMENTOS.TIPO_VENDA = 'V') OR (LANCAMENTOS.TIPO_VENDA = 'D')) AND
     LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
     LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
     LANCAMENTOS.CD_FILIAL = :FILIAL
    GROUP BY
     LANCAMENTOS.CD_VENDEDOR
    INTO
     :CD_VENDEDOR
  DO
   BEGIN
     SELECT
      SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
      SUM(LANCAMENTOS.QUANTIDADE),
      COUNT(DISTINCT LANCAMENTOS.CD_VENDA)
     FROM
      LANCAMENTOS
     WHERE
      LANCAMENTOS.TIPO_VENDA = 'V' AND
      LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR AND
      LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
      LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
      LANCAMENTOS.CD_FILIAL = :FILIAL AND
      LANCAMENTOS.CUSTO_UNITARIO > 0
     INTO
      :VALORVENDAS,
      :QUANTIDADEITENS,
      :NUMEROVENDAS;

     IF (:VALORVENDAS IS NULL) THEN
        VALORVENDAS = 0;
     IF (:QUANTIDADEITENS IS NULL) THEN
        QUANTIDADEITENS = 0;
     IF (:NUMEROVENDAS IS NULL) THEN
        NUMEROVENDAS = 0;

     SELECT
      SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
      SUM(LANCAMENTOS.QUANTIDADE),
      COUNT(DISTINCT LANCAMENTOS.CD_VENDA)
     FROM
      LANCAMENTOS
     WHERE
      LANCAMENTOS.TIPO_VENDA = 'D' AND
      LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR AND
      LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
      LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
      LANCAMENTOS.CD_FILIAL = :FILIAL AND
      LANCAMENTOS.CUSTO_UNITARIO > 0
     INTO
      :VALORCANCELADO,
      :QUANTIDADECANCELADA,
      :NUMEROCANCELADO;

     IF (:VALORCANCELADO IS NULL) THEN
        VALORCANCELADO = 0;
     IF (:QUANTIDADECANCELADA IS NULL) THEN
        QUANTIDADECANCELADA = 0;
     IF (:NUMEROCANCELADO IS NULL) THEN
        NUMEROCANCELADO = 0;


     VALORVENDAS = :VALORVENDAS - :VALORCANCELADO;
     QUANTIDADEITENS = :QUANTIDADEITENS - :QUANTIDADECANCELADA;
     NUMEROVENDAS = :NUMEROVENDAS - :NUMEROCANCELADO;
     IF (:NUMEROVENDAS > 0) THEN
      BEGIN
        MEDIAUNITARIA = :QUANTIDADEITENS / :NUMEROVENDAS;
        MEDIACUPOM = :VALORVENDAS / :NUMEROVENDAS;
      END
     ELSE
      BEGIN
        MEDIAUNITARIA = 0;
        MEDIACUPOM = 0;
      END

     SELECT
      COUNT(DISTINCT LANCAMENTOS.CD_VENDA)
     FROM
      LANCAMENTOS
     WHERE
      LANCAMENTOS.TIPO_VENDA = 'V' AND
      LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR AND
      LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
      LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
      LANCAMENTOS.CD_FILIAL = :FILIAL AND
      LANCAMENTOS.DESCONTO <= 0
     INTO
      :NUMEROVENDAS2;

     SELECT
      COUNT(DISTINCT LANCAMENTOS.CD_VENDA)
     FROM
      LANCAMENTOS
     WHERE
      LANCAMENTOS.TIPO_VENDA = 'D' AND
      LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR AND
      LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
      LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
      LANCAMENTOS.CD_FILIAL = :FILIAL AND
      LANCAMENTOS.DESCONTO <= 0
     INTO
      :NUMEROCANCELADO;


     NUMEROVENDAS2 = :NUMEROVENDAS2 - :NUMEROCANCELADO;

     SELECT NOME FROM VENDEDORES WHERE CD_VENDEDOR = :CD_VENDEDOR INTO :VENDEDOR;

     SUSPEND;
   END
END ^

ALTER PROCEDURE SP_DETALHAMENTO_COMISSAO (FILIAL DOUBLE PRECISION,
VENDEDOR DOUBLE PRECISION,
DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (FORMA DOUBLE PRECISION,
PRODUTO VARCHAR(50) CHARACTER SET NONE,
VALOR DOUBLE PRECISION,
COMISSAO DOUBLE PRECISION)
AS 
DECLARE VARIABLE VENDA DOUBLE PRECISION;
BEGIN
  FOR
     SELECT
      CAIXA.CD_VENDA,
      CAIXA.CD_FORMA_PAGAMENTO
     FROM
      CAIXA
     WHERE
      CAIXA.CD_FILIAL = :FILIAL AND
      CAIXA.CD_VENDEDOR = :VENDEDOR AND
      CAIXA.DATA_CAIXA >= :DATAINICIAL AND
      CAIXA.DATA_CAIXA <= :DATAFINAL AND
      CAIXA.TIPO_VENDA = 'V' AND
      CAIXA.STATUS = 'A'
     INTO
      :VENDA,
      :FORMA
  DO
   BEGIN
     FOR
        SELECT
         LANCAMENTOS.CD_VENDA,
         SUM(LANCAMENTOS.VALOR),
         SUM(LANCAMENTOS.COMISSAO)
        FROM
         LANCAMENTOS
        WHERE
         LANCAMENTOS.TIPO_VENDA = 'V' AND
         LANCAMENTOS.CD_VENDEDOR = :VENDEDOR AND
         LANCAMENTOS.CD_FILIAL = :FILIAL AND
         LANCAMENTOS.CD_VENDA = :VENDA
        GROUP BY
         LANCAMENTOS.CD_VENDA
        HAVING
         SUM(LANCAMENTOS.COMISSAO) > 0
        INTO
         :PRODUTO,
         :VALOR,
         :COMISSAO
     DO
      BEGIN
       SUSPEND;
      END
  END
END ^

ALTER PROCEDURE SP_DETALHAMENTO_PREMIACAO (CD_VENDEDOR DOUBLE PRECISION,
DATAINICIAL DATE,
DATAFINAL DATE,
VALORMINIMO DOUBLE PRECISION)
RETURNS (CD_VENDA DOUBLE PRECISION,
DATA_CAIXA DATE,
VALORTOTAL DOUBLE PRECISION,
PERCENTUALPREMIACAO DOUBLE PRECISION)
AS 
DECLARE VARIABLE VALORVENDIDO DOUBLE PRECISION;
DECLARE VARIABLE VALORCANCELADO DOUBLE PRECISION;
DECLARE VARIABLE VALOR DOUBLE PRECISION;
DECLARE VARIABLE PERCENTUAL DOUBLE PRECISION;
BEGIN
 SELECT VALORMINIMOPREMIACAO, PERCENTUALPREMIACAO FROM PARAMETROS INTO :VALORMINIMO, :PERCENTUAL;

 FOR
    SELECT
     LANCAMENTOS.CD_VENDA,
     LANCAMENTOS.DATA_CAIXA
    FROM
     LANCAMENTOS
    WHERE
     LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR AND
     LANCAMENTOS.DATA_CAIXA >= :DATAINICIAL AND
     LANCAMENTOS.DATA_CAIXA <= :DATAFINAL AND
     (LANCAMENTOS.TIPO_VENDA = 'V' OR LANCAMENTOS.TIPO_VENDA = 'D') AND
     LANCAMENTOS.CD_VENDA IS NOT NULL AND
     LANCAMENTOS.CD_VENDA > 0
    GROUP BY
     LANCAMENTOS.CD_VENDA,
     LANCAMENTOS.DATA_CAIXA
    INTO
     :CD_VENDA,
     :DATA_CAIXA
 DO
  BEGIN
    VALORTOTAL = 0;
    VALORVENDIDO = 0;
    VALORCANCELADO = 0;
    PERCENTUALPREMIACAO = 0;

    SELECT
     SUM(LANCAMENTOS.VALOR) AS TOTALVENDA,
     SUM(LANCAMENTOS.VALOR * :PERCENTUAL / 100) AS TOTALPREMIACAO
    FROM
     LANCAMENTOS
    WHERE
     LANCAMENTOS.CD_VENDA = :CD_VENDA AND
     LANCAMENTOS.TIPO_VENDA = 'V'
    HAVING
     SUM(LANCAMENTOS.VALOR) >= :VALORMINIMO
    INTO
     :VALORVENDIDO,
     :PERCENTUALPREMIACAO;

    IF (:VALORVENDIDO IS NULL) THEN
       VALORVENDIDO = 0;

    SELECT
     SUM(LANCAMENTOS.VALOR) AS TOTALVENDA
    FROM
     LANCAMENTOS
    WHERE
     LANCAMENTOS.CD_VENDA = :CD_VENDA AND
     LANCAMENTOS.TIPO_VENDA = 'D'
    INTO
     :VALORCANCELADO;

    IF (:VALORCANCELADO IS NULL) THEN
       VALORCANCELADO = 0;

    VALORTOTAL = :VALORVENDIDO - :VALORCANCELADO;

    IF (:VALORTOTAL > 0) THEN
       SUSPEND;
  END
END ^

ALTER PROCEDURE SP_DETALHE_COMISSAO (FILIAL DOUBLE PRECISION,
VENDEDOR DOUBLE PRECISION,
FORMA DOUBLE PRECISION,
DATA_CAIXA DATE,
TERMINAL DOUBLE PRECISION,
OPERADOR DOUBLE PRECISION)
RETURNS (VENDA DOUBLE PRECISION,
PRODUTO VARCHAR(50) CHARACTER SET NONE,
VALOR DOUBLE PRECISION,
COMISSAO DOUBLE PRECISION)
AS 
BEGIN
  FOR
     SELECT
      CAIXA.CD_VENDA,
      CAIXA.CD_FORMA_PAGAMENTO
     FROM
      CAIXA
     WHERE
      CAIXA.CD_FILIAL = :FILIAL AND
      CAIXA.DATA = :DATA_CAIXA AND
      CAIXA.TERMINAL = :TERMINAL AND
      CAIXA.CD_OPERADOR = :OPERADOR AND
      CAIXA.CD_FORMA_PAGAMENTO = :FORMA AND
      CAIXA.TIPO_VENDA = 'V' AND
      CAIXA.STATUS = 'A'
     INTO
      :VENDA,
      :FORMA
  DO
   BEGIN
     FOR
        SELECT
         LANCAMENTOS.DESCRICAO,
         LANCAMENTOS.VALOR,
         LANCAMENTOS.COMISSAO
        FROM
         LANCAMENTOS
        WHERE
         LANCAMENTOS.TIPO_VENDA = 'V' AND
         LANCAMENTOS.CD_VENDEDOR = :VENDEDOR AND
         LANCAMENTOS.CD_FILIAL = :FILIAL AND
         LANCAMENTOS.CD_VENDA = :VENDA
        INTO
         :PRODUTO,
         :VALOR,
         :COMISSAO
     DO
      BEGIN
       SUSPEND;
      END
  END
END ^

ALTER PROCEDURE SP_DIFERENCA_BALANCO_DATA (CD_FILIAL DOUBLE PRECISION,
DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (ID_PRODUTO DOUBLE PRECISION,
CD_PRODUTO VARCHAR(6) CHARACTER SET NONE,
DESCRICAO VARCHAR(100) CHARACTER SET NONE,
CD_CLASSE DOUBLE PRECISION,
CLASSE VARCHAR(100) CHARACTER SET NONE,
CD_GRUPO DOUBLE PRECISION,
GRUPO VARCHAR(100) CHARACTER SET NONE,
CD_LABORATORIO DOUBLE PRECISION,
LABORATORIO VARCHAR(100) CHARACTER SET NONE,
DIFERENCA_MAIOR NUMERIC(15, 2),
DIFERENCA_MENOR NUMERIC(15, 2))
AS 
declare variable ID_BALANCO double precision;
declare variable DIFERENCA double precision;
BEGIN
 FOR
    SELECT
     ID_BALANCO,
     ID_PRODUTO,
     CD_PRODUTO,
     DESCRICAO,
     CD_CLASSE,
     CD_GRUPO,
     CD_LABORATORIO,
     SUM(ESTOQUE_ANTERIOR - ESTOQUE)
    FROM
     BALANCO
    WHERE
     CD_FILIAL = :CD_FILIAL AND
     DATA >= :DATAINICIAL AND
     DATA <= :DATAFINAL AND
     STATUS = 'C'
    GROUP BY
     ID_BALANCO,
     ID_PRODUTO,
     CD_PRODUTO,
     DESCRICAO,
     CD_CLASSE,
     CD_GRUPO,
     CD_LABORATORIO
    INTO
     :ID_BALANCO,
     :ID_PRODUTO,
     :CD_PRODUTO,
     :DESCRICAO,
     :CD_CLASSE,
     :CD_GRUPO,
     :CD_LABORATORIO,
     :DIFERENCA
 DO
  BEGIN
    DIFERENCA_MAIOR = 0;
    DIFERENCA_MENOR = 0;

    /*FOR
       SELECT
         ID_BALANCO,
         SUM(ESTOQUE_ANTERIOR - ESTOQUE)
       FROM
         BALANCO
       WHERE
         CD_FILIAL = :CD_FILIAL AND
         DATA >= :DATAINICIAL AND
         DATA <= :DATAFINAL AND
         ID_PRODUTO = :ID_PRODUTO AND
         STATUS = 'C'
       GROUP BY
         ID_BALANCO
       INTO
        :ID_BALANCO,
        :DIFERENCA
    DO
     BEGIN*/
       IF (:DIFERENCA < 0) THEN
          DIFERENCA_MAIOR = :DIFERENCA_MAIOR + (:DIFERENCA * -1);
       ELSE
          DIFERENCA_MENOR = :DIFERENCA_MENOR + (:DIFERENCA);
     --END

    IF ((:DIFERENCA_MAIOR > 0) OR (:DIFERENCA_MENOR > 0)) THEN
     BEGIN
       SELECT DESCRICAO FROM CLASSES WHERE CD_CLASSE = :CD_CLASSE INTO :CLASSE;
       SELECT DESCRICAO FROM GRUPOS WHERE CD_GRUPO = :CD_GRUPO INTO :GRUPO;
       SELECT NOME FROM LABORATORIOS WHERE CD_LABORATORIO = :CD_LABORATORIO INTO :LABORATORIO;
  
       SUSPEND;
     END
  END
END ^

ALTER PROCEDURE SP_ESTATISTICAS_BALANCO (ID_BALANCO DOUBLE PRECISION)
RETURNS (NPRODUTOS INTEGER,
NPRODUTOSCONTADOS INTEGER,
NPRODUTOSPOSITIVOS INTEGER,
NPRODUTOSNEGATIVOS INTEGER,
NPRODUTOSIGUAIS INTEGER,
CUSTOPRODUTOSPOSITIVOS DOUBLE PRECISION,
CUSTOPRODUTOSNEGATIVOS DOUBLE PRECISION,
CUSTOPRODUTOSIGUAIS DOUBLE PRECISION,
PERCENTUALCONTADOS DOUBLE PRECISION,
CUSTOANTERIOR DOUBLE PRECISION,
CUSTOATUAL DOUBLE PRECISION,
DIFERENCACUSTO DOUBLE PRECISION,
PERCENTUALPOSITIVO DOUBLE PRECISION,
PERCENTUALNEGATIVO DOUBLE PRECISION,
PERCENTUALIGUAIS DOUBLE PRECISION,
VENDAPRODUTOSNEGATIVOS DOUBLE PRECISION)
AS 
BEGIN
    DIFERENCACUSTO = 0;
    PERCENTUALCONTADOS = 0;
    PERCENTUALPOSITIVO = 0;
    PERCENTUALNEGATIVO = 0;
    PERCENTUALIGUAIS = 0;

    SELECT COUNT(*) FROM PRODUTOS INTO :NPRODUTOS;

    SELECT COUNT(*), SUM(CUSTO_UNITARIO * ESTOQUE_ANTERIOR), SUM(CUSTO_UNITARIO * ESTOQUE)
    FROM BALANCO WHERE ID_BALANCO = :ID_BALANCO INTO :NPRODUTOSCONTADOS, :CUSTOANTERIOR, :CUSTOATUAL;

    PERCENTUALCONTADOS = ((CAST(:NPRODUTOSCONTADOS AS DOUBLE PRECISION) / CAST(:NPRODUTOS AS DOUBLE PRECISION)) * 100);
    DIFERENCACUSTO = :CUSTOATUAL - :CUSTOANTERIOR;

    SELECT COUNT(*), SUM(CUSTO_UNITARIO * (ESTOQUE - ESTOQUE_ANTERIOR))
    FROM BALANCO WHERE ID_BALANCO = :ID_BALANCO AND ESTOQUE - ESTOQUE_ANTERIOR > 0 INTO :NPRODUTOSPOSITIVOS, :CUSTOPRODUTOSPOSITIVOS;

    PERCENTUALPOSITIVO = ((CAST(:NPRODUTOSPOSITIVOS AS DOUBLE PRECISION) / CAST(:NPRODUTOSCONTADOS AS DOUBLE PRECISION)) * 100);

    SELECT COUNT(*), SUM(CUSTO_UNITARIO * (ESTOQUE - ESTOQUE_ANTERIOR)), SUM(PRECO_VENDA * (ESTOQUE - ESTOQUE_ANTERIOR))
    FROM BALANCO WHERE ID_BALANCO = :ID_BALANCO AND ESTOQUE - ESTOQUE_ANTERIOR < 0 INTO :NPRODUTOSNEGATIVOS, :CUSTOPRODUTOSNEGATIVOS, :VENDAPRODUTOSNEGATIVOS;

    PERCENTUALNEGATIVO = ((CAST(:NPRODUTOSNEGATIVOS AS DOUBLE PRECISION) / CAST(:NPRODUTOSCONTADOS AS DOUBLE PRECISION)) * 100);

    SELECT COUNT(*), SUM(CUSTO_UNITARIO * (ESTOQUE - ESTOQUE_ANTERIOR))
    FROM BALANCO WHERE ID_BALANCO = :ID_BALANCO AND ESTOQUE - ESTOQUE_ANTERIOR = 0 INTO :NPRODUTOSIGUAIS, :CUSTOPRODUTOSIGUAIS;

    PERCENTUALIGUAIS = ((CAST(:NPRODUTOSIGUAIS AS DOUBLE PRECISION) / CAST(:NPRODUTOSCONTADOS AS DOUBLE PRECISION)) * 100);
    SUSPEND;
END ^

ALTER PROCEDURE SP_ESTATISTICAS_BALANCO_PERIODO (CD_FILIAL DOUBLE PRECISION,
DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (NPRODUTOS INTEGER,
NPRODUTOSCONTADOS INTEGER,
NPRODUTOSPOSITIVOS INTEGER,
NPRODUTOSNEGATIVOS INTEGER,
NPRODUTOSIGUAIS INTEGER,
CUSTOPRODUTOSPOSITIVOS DOUBLE PRECISION,
CUSTOPRODUTOSNEGATIVOS DOUBLE PRECISION,
CUSTOPRODUTOSIGUAIS DOUBLE PRECISION,
PERCENTUALCONTADOS DOUBLE PRECISION,
CUSTOANTERIOR DOUBLE PRECISION,
CUSTOATUAL DOUBLE PRECISION,
DIFERENCACUSTO DOUBLE PRECISION,
PERCENTUALPOSITIVO DOUBLE PRECISION,
PERCENTUALNEGATIVO DOUBLE PRECISION,
PERCENTUALIGUAIS DOUBLE PRECISION,
VENDAPRODUTOSNEGATIVOS DOUBLE PRECISION)
AS 
BEGIN
    DIFERENCACUSTO = 0;
    PERCENTUALCONTADOS = 0;
    PERCENTUALPOSITIVO = 0;
    PERCENTUALNEGATIVO = 0;
    PERCENTUALIGUAIS = 0;

    SELECT COUNT(*) FROM PRODUTOS INTO :NPRODUTOS;

    IF ((:CD_FILIAL IS NULL) OR (:CD_FILIAL = 0)) THEN
     BEGIN
       SELECT COUNT(*), SUM(CUSTO_UNITARIO * ESTOQUE_ANTERIOR), SUM(CUSTO_UNITARIO * ESTOQUE)
       FROM BALANCO WHERE DATA_CONCLUSAO >= :DATAINICIAL AND DATA_CONCLUSAO <= :DATAFINAL INTO :NPRODUTOSCONTADOS, :CUSTOANTERIOR, :CUSTOATUAL;
     END
    ELSE
     BEGIN
       SELECT COUNT(*), SUM(CUSTO_UNITARIO * ESTOQUE_ANTERIOR), SUM(CUSTO_UNITARIO * ESTOQUE)
       FROM BALANCO WHERE CD_FILIAL = :CD_FILIAL AND DATA_CONCLUSAO >= :DATAINICIAL AND DATA_CONCLUSAO <= :DATAFINAL INTO :NPRODUTOSCONTADOS, :CUSTOANTERIOR, :CUSTOATUAL;
     END

    PERCENTUALCONTADOS = ((CAST(:NPRODUTOSCONTADOS AS DOUBLE PRECISION) / CAST(:NPRODUTOS AS DOUBLE PRECISION)) * 100);
    DIFERENCACUSTO = :CUSTOATUAL - :CUSTOANTERIOR;

    IF ((:CD_FILIAL IS NULL) OR (:CD_FILIAL = 0)) THEN
     BEGIN
        SELECT COUNT(*), SUM(CUSTO_UNITARIO * (ESTOQUE - ESTOQUE_ANTERIOR))
        FROM BALANCO WHERE DATA_CONCLUSAO >= :DATAINICIAL AND DATA_CONCLUSAO <= :DATAFINAL AND ESTOQUE - ESTOQUE_ANTERIOR > 0 INTO :NPRODUTOSPOSITIVOS, :CUSTOPRODUTOSPOSITIVOS;
     END
    ELSE
     BEGIN
        SELECT COUNT(*), SUM(CUSTO_UNITARIO * (ESTOQUE - ESTOQUE_ANTERIOR))
        FROM BALANCO WHERE CD_FILIAL = :CD_FILIAL AND DATA_CONCLUSAO >= :DATAINICIAL AND DATA_CONCLUSAO <= :DATAFINAL AND ESTOQUE - ESTOQUE_ANTERIOR > 0 INTO :NPRODUTOSPOSITIVOS, :CUSTOPRODUTOSPOSITIVOS;
     END

    PERCENTUALPOSITIVO = ((CAST(:NPRODUTOSPOSITIVOS AS DOUBLE PRECISION) / CAST(:NPRODUTOSCONTADOS AS DOUBLE PRECISION)) * 100);

    IF ((:CD_FILIAL IS NULL) OR (:CD_FILIAL = 0)) THEN
     BEGIN
        SELECT COUNT(*), SUM(CUSTO_UNITARIO * (ESTOQUE - ESTOQUE_ANTERIOR)), SUM(PRECO_VENDA * (ESTOQUE - ESTOQUE_ANTERIOR))
        FROM BALANCO WHERE DATA_CONCLUSAO >= :DATAINICIAL AND DATA_CONCLUSAO <= :DATAFINAL AND ESTOQUE - ESTOQUE_ANTERIOR < 0 INTO :NPRODUTOSNEGATIVOS, :CUSTOPRODUTOSNEGATIVOS, :VENDAPRODUTOSNEGATIVOS;
     END
    ELSE
     BEGIN
        SELECT COUNT(*), SUM(CUSTO_UNITARIO * (ESTOQUE - ESTOQUE_ANTERIOR))
        FROM BALANCO WHERE CD_FILIAL = :CD_FILIAL AND DATA_CONCLUSAO >= :DATAINICIAL AND DATA_CONCLUSAO <= :DATAFINAL AND ESTOQUE - ESTOQUE_ANTERIOR < 0 INTO :NPRODUTOSNEGATIVOS, :CUSTOPRODUTOSNEGATIVOS;
     END

    PERCENTUALNEGATIVO = ((CAST(:NPRODUTOSNEGATIVOS AS DOUBLE PRECISION) / CAST(:NPRODUTOSCONTADOS AS DOUBLE PRECISION)) * 100);

    IF ((:CD_FILIAL IS NULL) OR (:CD_FILIAL = 0)) THEN
     BEGIN
        SELECT COUNT(*), SUM(CUSTO_UNITARIO * (ESTOQUE - ESTOQUE_ANTERIOR))
        FROM BALANCO WHERE DATA_CONCLUSAO >= :DATAINICIAL AND DATA_CONCLUSAO <= :DATAFINAL AND ESTOQUE - ESTOQUE_ANTERIOR = 0 INTO :NPRODUTOSIGUAIS, :CUSTOPRODUTOSIGUAIS;
     END
    ELSE
     BEGIN
        SELECT COUNT(*), SUM(CUSTO_UNITARIO * (ESTOQUE - ESTOQUE_ANTERIOR))
        FROM BALANCO WHERE CD_FILIAL = :CD_FILIAL AND DATA_CONCLUSAO >= :DATAINICIAL AND DATA_CONCLUSAO <= :DATAFINAL AND ESTOQUE - ESTOQUE_ANTERIOR = 0 INTO :NPRODUTOSIGUAIS, :CUSTOPRODUTOSIGUAIS;
     END

    PERCENTUALIGUAIS = ((CAST(:NPRODUTOSIGUAIS AS DOUBLE PRECISION) / CAST(:NPRODUTOSCONTADOS AS DOUBLE PRECISION)) * 100);

    SUSPEND;
END ^

ALTER PROCEDURE SP_ESTATISTICA_COMPRAS (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (FILIAL VARCHAR(40) CHARACTER SET NONE,
DISTRIBUIDOR VARCHAR(40) CHARACTER SET NONE,
DATA DATE,
QUANTIDADE DOUBLE PRECISION,
VALOR DOUBLE PRECISION)
AS 
BEGIN
  FOR
    SELECT
     FILIAIS.NOME,
     DISTRIBUIDORES.NOME,
     LANCAMENTOS.DATA_LANCAMENTO,
     SUM(LANCAMENTOS.QUANTIDADE),
     SUM(LANCAMENTOS.VALOR)
    
    FROM
      FILIAIS,
      LANCAMENTOS,
      DISTRIBUIDORES

    WHERE
      FILIAIS.CD_FILIAL = LANCAMENTOS.CD_FILIAL AND
      FILIAIS.STATUS = 'A' AND
      DISTRIBUIDORES.CD_DISTRIBUIDOR = LANCAMENTOS.CD_CLIENTE AND
      LANCAMENTOS.ENTRADA_SAIDA = 'E' AND
      LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
      LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL
    
    GROUP BY
     FILIAIS.NOME,
     DISTRIBUIDORES.NOME,
     LANCAMENTOS.DATA_LANCAMENTO

    INTO
     :FILIAL,
     :DISTRIBUIDOR,
     :DATA,
     :QUANTIDADE,
     :VALOR
  DO
   BEGIN
      SUSPEND;
   END
END ^

ALTER PROCEDURE SP_ESTATISTICA_PICO_HORARIO (ENTREGA VARCHAR(1) CHARACTER SET NONE,
DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (FILIAL VARCHAR(100) CHARACTER SET NONE,
CD_FILIAL DOUBLE PRECISION,
HORA INTEGER,
NUMERO_VENDAS INTEGER,
VALOR_VENDIDO DOUBLE PRECISION,
NUMERO_ITENS INTEGER,
QUANTIDADE_VENDIDA DOUBLE PRECISION,
DESCONTO_CONCEDIDO DOUBLE PRECISION,
MEDIA_CUPOM DOUBLE PRECISION,
MEDIA_DESCONTO DOUBLE PRECISION)
AS 
BEGIN
  FOR
    SELECT
     LANCAMENTOS.CD_FILIAL,
     FILIAIS.NOME,
     CAST(EXTRACT(HOUR FROM LANCAMENTOS.HORA) AS INTEGER),
     COUNT(DISTINCT LANCAMENTOS.CD_VENDA),
     SUM(LANCAMENTOS.VALOR),
     COUNT(DISTINCT LANCAMENTOS.ID_PRODUTO),
     SUM(LANCAMENTOS.QUANTIDADE),
     SUM(LANCAMENTOS.DESCONTO)
    FROM
     LANCAMENTOS,
     FILIAIS
    WHERE
     LANCAMENTOS.DATA_CAIXA >= :DATAINICIAL AND
     LANCAMENTOS.DATA_CAIXA <= :DATAFINAL AND
     LANCAMENTOS.CD_FILIAL = FILIAIS.CD_FILIAL AND
     LANCAMENTOS.TIPO_VENDA = 'V' AND
     LANCAMENTOS.ENTREGA LIKE :ENTREGA
    GROUP BY
     LANCAMENTOS.CD_FILIAL,
     FILIAIS.NOME,
     EXTRACT(HOUR FROM HORA)
    ORDER BY
     FILIAIS.NOME,
     LANCAMENTOS.CD_FILIAL,
     EXTRACT(HOUR FROM LANCAMENTOS.HORA)
    INTO
     :CD_FILIAL,
     :FILIAL,
     :HORA,
     :NUMERO_VENDAS,
     :VALOR_VENDIDO,
     :NUMERO_ITENS,
     :QUANTIDADE_VENDIDA,
     :DESCONTO_CONCEDIDO
  DO
   BEGIN
     MEDIA_CUPOM = :VALOR_VENDIDO / :NUMERO_VENDAS;
     MEDIA_DESCONTO = (:DESCONTO_CONCEDIDO / (:VALOR_VENDIDO + :DESCONTO_CONCEDIDO)) * 100;
     SUSPEND;
   END
END ^

ALTER PROCEDURE SP_ESTATISTICA_PRODUTO (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (FILIAL VARCHAR(40) CHARACTER SET NONE,
DATA VARCHAR(10) CHARACTER SET NONE,
HORA VARCHAR(10) CHARACTER SET NONE,
QUANTIDADE DOUBLE PRECISION,
VALOR DOUBLE PRECISION)
AS 
BEGIN
FOR
SELECT
  FILIAIS.NOME,
  EXTRACT(DAY FROM LANCAMENTOS.DATA_LANCAMENTO)||'/'||
  EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)||'/'||
  EXTRACT(YEAR FROM LANCAMENTOS.DATA_LANCAMENTO),
  EXTRACT(HOUR FROM LANCAMENTOS.HORA),
  SUM(LANCAMENTOS.QUANTIDADE),
  SUM(LANCAMENTOS.VALOR)

FROM
  LANCAMENTOS, FILIAIS

WHERE
  FILIAIS.CD_FILIAL = LANCAMENTOS.CD_FILIAL AND
  FILIAIS.STATUS = 'A' AND
  LANCAMENTOS.ENTRADA_SAIDA = 'S' AND
  (LANCAMENTOS.TIPO_VENDA = 'P' OR LANCAMENTOS.TIPO_VENDA = 'V') AND
  LANCAMENTOS.ENTREGA IS NOT NULL AND
  LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
  LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL

GROUP BY
  FILIAIS.NOME,
  LANCAMENTOS.DATA_LANCAMENTO,
  EXTRACT(HOUR FROM LANCAMENTOS.HORA)

INTO
 :FILIAL,
 :DATA,
 :HORA,
 :QUANTIDADE,
 :VALOR

DO
 BEGIN
   SUSPEND;
 END
END ^

ALTER PROCEDURE SP_ESTATISTICA_VENDAS (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (DATA DATE,
VENDEDOR VARCHAR(40) CHARACTER SET NONE,
FILIAL VARCHAR(40) CHARACTER SET NONE,
GRUPO VARCHAR(40) CHARACTER SET NONE,
QUANTIDADE DOUBLE PRECISION,
DESCONTOS DOUBLE PRECISION,
PROMOCOES DOUBLE PRECISION,
VALOR DOUBLE PRECISION,
COMISSAO DOUBLE PRECISION)
AS 
BEGIN
 FOR
    SELECT
     FECHAMENTO.DATA,
     VENDEDORES.NOME,
     FILIAIS.NOME,
     GRUPOS.DESCRICAO,
     SUM(FECHAMENTO.QUANTIDADE),
     SUM(FECHAMENTO.DESCONTO),
     SUM(FECHAMENTO.PROMOCAO),
     SUM(FECHAMENTO.VALOR),
     SUM(FECHAMENTO.COMISSAO)
    
    FROM
      VENDEDORES,
      FILIAIS,
      GRUPOS,
      FECHAMENTO
    
    WHERE
      FILIAIS.STATUS = 'A' AND
      FECHAMENTO.DATA >= :DATAINICIAL AND
      FECHAMENTO.DATA <= :DATAFINAL AND
      FILIAIS.CD_FILIAL = FECHAMENTO.CD_FILIAL AND
      VENDEDORES.CD_VENDEDOR = FECHAMENTO.CD_VENDEDOR AND
      VENDEDORES.CD_FILIAL = FILIAIS.CD_FILIAL AND
      FECHAMENTO.CD_GRUPO = GRUPOS.CD_GRUPO

    GROUP BY
     FECHAMENTO.DATA,
     VENDEDORES.NOME,
     FILIAIS.NOME,
     GRUPOS.DESCRICAO

    INTO
     :DATA,
     :VENDEDOR,
     :FILIAL,
     :GRUPO,
     :QUANTIDADE,
     :DESCONTOS,
     :PROMOCOES,
     :VALOR,
     :COMISSAO
  DO
   BEGIN
     SUSPEND;
   END

END ^

ALTER PROCEDURE SP_EVOLUCAO_DIARIA_COMPRA (CD_FILIAL DOUBLE PRECISION,
DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (CD_CLASSE DOUBLE PRECISION,
CLASSE VARCHAR(100) CHARACTER SET NONE,
DATA DATE,
VALOR DOUBLE PRECISION)
AS 
BEGIN
  FOR
    SELECT
     LANCAMENTOS.CD_CLASSE,
     CLASSES.DESCRICAO,
     LANCAMENTOS.DATA_LANCAMENTO,
     SUM(LANCAMENTOS.VALOR)
    FROM
     LANCAMENTOS,
     CLASSES
    WHERE
     LANCAMENTOS.CD_CLASSE = CLASSES.CD_CLASSE AND
     LANCAMENTOS.TIPO_VENDA = 'C' AND
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
     LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL
    GROUP BY
     LANCAMENTOS.CD_CLASSE,
     CLASSES.DESCRICAO,
     LANCAMENTOS.DATA_LANCAMENTO
    INTO
     :CD_CLASSE,
     :CLASSE,
     :DATA,
     :VALOR
  DO
   BEGIN
    SUSPEND;
   END
END ^

