         BEGIN
            FOR
             SELECT CD_FILIAL FROM FILIAIS WHERE EXPORTAR = 'S' INTO :CD_FILIAL
            DO
              BEGIN
                INSERT INTO TEMP_PRODUTOS VALUES (:CD_CLIENTE, :CD_FILIAL, 110, '');
              END
         END
      END
  END
END ^

ALTER PROCEDURE SP_EXPORTACAO_CLIFORNEC_FFACIL RETURNS (LINHA VARCHAR(1000) CHARACTER SET NONE)
AS 
declare variable CNPJ varchar(100);
declare variable IE varchar(100);
declare variable RAZAO varchar(100);
declare variable CODIGO varchar(100);
declare variable ENDERECO varchar(100);
declare variable NUMERO varchar(100);
declare variable COMPLEMENTO varchar(100);
declare variable BAIRRO varchar(100);
declare variable CIDADE varchar(100);
declare variable UF varchar(100);
declare variable CEP varchar(100);
declare variable CD_PAIS integer;
declare variable PAIS varchar(1000);
BEGIN
  FOR
    SELECT
     CNPJ,
     CASE
      WHEN IE IS NULL THEN ''
      ELSE TRIM(IE)
     END,
     TRIM(RAZAO),
     CAST(CD_DISTRIBUIDOR AS INTEGER),
     TRIM(ENDERECO),
     TRIM(NUMERO),
     TRIM(COMPLEMENTO),
     TRIM(BAIRRO),
     TRIM(CIDADE),
     TRIM(UF),
     TRIM(CEP),
     CD_PAIS
    FROM
     DISTRIBUIDORES
    INTO
     :CNPJ,
     :IE,
     :RAZAO,
     :CODIGO,
     :ENDERECO,
     :NUMERO,
     :COMPLEMENTO,
     :BAIRRO,
     :CIDADE,
     :UF,
     :CEP,
     :CD_PAIS
  DO
   BEGIN
     IF (:CNPJ IS NULL) THEN
        CNPJ = '';
     IF (:ENDERECO IS NULL) THEN
        ENDERECO = '';
     IF (:NUMERO IS NULL) THEN
        NUMERO = '';
     IF (:COMPLEMENTO IS NULL) THEN
        COMPLEMENTO = '';
     IF (:BAIRRO IS NULL) THEN
        BAIRRO = '';
     IF (:CIDADE IS NULL) THEN
        CIDADE = '';
     IF (:UF IS NULL) THEN
        UF = '';
     IF (:CEP IS NULL) THEN
        CEP = '';
     IF (:CD_PAIS IS NULL) THEN
        CD_PAIS = 0;

     IF (:CD_PAIS <> 0) THEN
        SELECT NOME FROM NFEPAISES WHERE ID_PAIS = :CD_PAIS INTO :PAIS;
     IF (:PAIS IS NULL) THEN
        PAIS = '';

     LINHA = :CNPJ||'|'||:IE||'|'||:RAZAO||'|'||:CODIGO||'|'||:ENDERECO||'|'||:NUMERO||'|'||:COMPLEMENTO||'|'||:BAIRRO||'|'||:CIDADE||'|'||:UF||'|'||:CEP||'|'||:PAIS;
     SUSPEND;
   END

  FOR
    SELECT
     CASE
      WHEN CNPJ IS NOT NULL AND TRIM(CNPJ) <> '' THEN CNPJ
      ELSE CPF
     END,
     TRIM(NOME),
     CAST(CAST(CD_CLIENTE AS INTEGER) AS VARCHAR(100)),
     TRIM(ENDERECO),
     TRIM(NUMERO),
     TRIM(COMPLEMENTO),
     TRIM(BAIRRO),
     TRIM(CIDADE),
     TRIM(UF),
     TRIM(CEP),
     CASE
      WHEN TRIM(CD_PAIS) IS NULL THEN 0
      ELSE CD_PAIS
     END
    FROM
     CLIENTES
    WHERE
     CD_CLIENTE <> 999999
    INTO
     :CNPJ,
     :RAZAO,
     :CODIGO,
     :ENDERECO,
     :NUMERO,
     :COMPLEMENTO,
     :BAIRRO,
     :CIDADE,
     :UF,
     :CEP,
     :CD_PAIS
  DO
   BEGIN
     IE = '';
     IF (:CNPJ IS NULL) THEN
        CNPJ = '';
     CNPJ = LPAD(:CNPJ, 14, '0');

     IF (:RAZAO IS NULL) THEN
        RAZAO = '';
     IF (:ENDERECO IS NULL) THEN
        ENDERECO = '';
     IF (:NUMERO IS NULL) THEN
        NUMERO = '';
     IF (:COMPLEMENTO IS NULL) THEN
        COMPLEMENTO = '';
     IF (:BAIRRO IS NULL) THEN
        BAIRRO = '';
     IF (:CIDADE IS NULL) THEN
        CIDADE = '';
     IF (:UF IS NULL) THEN
        UF = '';
     IF (:CEP IS NULL) THEN
        CEP = '';
     IF (:CD_PAIS IS NULL) THEN
        CD_PAIS = 0;


     IF (:CD_PAIS <> 0) THEN
        SELECT NOME FROM NFEPAISES WHERE ID_PAIS = :CD_PAIS INTO :PAIS;

     IF (:PAIS IS NULL) THEN
        PAIS = '';

     LINHA = :CNPJ||'|'||:IE||'|'||:RAZAO||'|'||:CODIGO||'|'||:ENDERECO||'|'||:NUMERO||'|'||:COMPLEMENTO||'|'||:BAIRRO||'|'||:CIDADE||'|'||:UF||'|'||:CEP||'|'||:PAIS;
     SUSPEND;
   END
END ^

ALTER PROCEDURE SP_EXPORTACAO_COMPRAS (CD_FILIAL DOUBLE PRECISION,
DATAINICIAL DATE,
DATAFINAL DATE)
AS 
DECLARE VARIABLE CD_COMPRAS DOUBLE PRECISION;
DECLARE VARIABLE ID_PRODUTO DOUBLE PRECISION;
BEGIN
  FOR
   SELECT
    COMPRAS.CD_COMPRAS
   FROM
    COMPRAS
   WHERE
    COMPRAS.DT_PEDIDO >= :DATAINICIAL AND
    COMPRAS.DT_PEDIDO <= :DATAFINAL AND
    COMPRAS.CD_FILIAL = :CD_FILIAL
   INTO
    :CD_COMPRAS
  DO
   BEGIN
     INSERT INTO TEMP_COMPRAS VALUES (:CD_COMPRAS, NULL, :CD_FILIAL, '4', '');
   END

  FOR
   SELECT
    ITENS_COMPRA.CD_COMPRAS,
    ITENS_COMPRA.ID_PRODUTO
   FROM
    ITENS_COMPRA,
    COMPRAS
   WHERE
    COMPRAS.CD_COMPRAS = ITENS_COMPRA.CD_COMPRAS AND
    COMPRAS.DT_PEDIDO >= :DATAINICIAL AND
    COMPRAS.DT_PEDIDO <= :DATAFINAL AND
    COMPRAS.CD_FILIAL = :CD_FILIAL
   INTO
    :CD_COMPRAS,
    :ID_PRODUTO
  DO
   BEGIN
     INSERT INTO TEMP_COMPRAS VALUES (:CD_COMPRAS, :ID_PRODUTO, :CD_FILIAL, '5', '');
   END

END ^

ALTER PROCEDURE SP_EXPORTACAO_CONVENIOS AS 
BEGIN
 UPDATE CONVENIOS SET DT_ALTERACAO = CURRENT_DATE;
END ^

ALTER PROCEDURE SP_EXPORTACAO_CONVENIOS_CLASSES AS 
DECLARE VARIABLE CD_FILIAL DOUBLE PRECISION;
DECLARE VARIABLE CD_CONVENIO DOUBLE PRECISION;
DECLARE VARIABLE EXISTE INTEGER;
BEGIN
  FOR
   SELECT CD_FILIAL FROM FILIAIS WHERE EXPORTAR = 'S' INTO:CD_FILIAL
  DO
   BEGIN
     FOR
      SELECT CD_CONVENIO FROM CONVENIOS INTO :CD_CONVENIO
     DO
      BEGIN
        SELECT COUNT(*) FROM TEMP_PRODUTOS WHERE ID_PRODUTO = :CD_CONVENIO AND CD_FILIAL = :CD_FILIAL AND PROCESSO = 124 INTO :EXISTE;
        IF (:EXISTE = 0) THEN
           INSERT INTO TEMP_PRODUTOS VALUES (:CD_CONVENIO, :CD_FILIAL, 124, ' ');
      END
   END
END ^

ALTER PROCEDURE SP_EXPORTACAO_DISTRIBUIDORES AS 
DECLARE VARIABLE CD_DISTRIBUIDOR DOUBLE PRECISION;
DECLARE VARIABLE CD_FILIAL DOUBLE PRECISION;
DECLARE VARIABLE TIPO_LOJA VARCHAR(1);
DECLARE VARIABLE EXPORTAR VARCHAR(1);
BEGIN
 SELECT CD_FILIAL, TIPO_LOJA FROM PARAMETROS INTO :CD_FILIAL, :TIPO_LOJA;
 IF ((:CD_FILIAL = 0) OR (:TIPO_LOJA = 'U')) THEN
  BEGIN
     FOR
      SELECT
       CD_DISTRIBUIDOR
      FROM
       DISTRIBUIDORES
      INTO
       :CD_DISTRIBUIDOR
     DO
      BEGIN
        FOR
         SELECT CD_FILIAL FROM FILIAIS WHERE EXPORTAR = 'S' INTO :CD_FILIAL
        DO
          BEGIN
             INSERT INTO TEMP_PRODUTOS VALUES (:CD_DISTRIBUIDOR, :CD_FILIAL, 114, '');
          END
      END
  END
END ^

ALTER PROCEDURE SP_EXPORTACAO_ESTOQUE AS 
DECLARE VARIABLE ID_PRODUTO DOUBLE PRECISION;
DECLARE VARIABLE FILIALPRECO DOUBLE PRECISION;
DECLARE VARIABLE NUMERO INTEGER;
BEGIN
  FOR
    SELECT ID_PRODUTO FROM PRODUTOS INTO :ID_PRODUTO
  DO
   BEGIN
      FOR
       SELECT CD_FILIAL FROM FILIAIS WHERE EXPORTAR = 'S' INTO :FILIALPRECO
      DO
        BEGIN
          SELECT COUNT(ID_PRODUTO) FROM TEMP_PRODUTOS
          WHERE ID_PRODUTO = :ID_PRODUTO AND CD_FILIAL = :FILIALPRECO AND PROCESSO = 1191 INTO :NUMERO;
          IF (:NUMERO = 0) THEN
             INSERT INTO TEMP_PRODUTOS VALUES (:ID_PRODUTO, :FILIALPRECO, 1191, '');
        END
   END
END ^

ALTER PROCEDURE SP_EXPORTACAO_GRUPOS AS 
DECLARE VARIABLE CD_GRUPO DOUBLE PRECISION;
DECLARE VARIABLE CD_FILIAL DOUBLE PRECISION;
DECLARE VARIABLE EXPORTAR VARCHAR(1);
DECLARE VARIABLE TIPO_LOJA VARCHAR(1);
BEGIN
 FOR
  SELECT EXPORTAR FROM FILIAIS WHERE EXPORTAR = 'S' INTO :EXPORTAR
 DO
  BEGIN
    IF (:EXPORTAR = 'S') THEN
       EXPORTAR = 'S';
  END
 IF ((:EXPORTAR IS NULL) OR (:EXPORTAR = 'N')) THEN
    EXIT;

 SELECT CD_FILIAL, TIPO_LOJA FROM PARAMETROS INTO :CD_FILIAL, :TIPO_LOJA;
 IF ((:CD_FILIAL = 0) OR (:TIPO_LOJA = 'U')) THEN
  BEGIN
     FOR
      SELECT
       CD_GRUPO
      FROM
       GRUPOS
      INTO
       :CD_GRUPO
     DO
      BEGIN
        FOR
         SELECT CD_FILIAL FROM FILIAIS WHERE EXPORTAR = 'S' INTO :CD_FILIAL
        DO
          BEGIN
            INSERT INTO TEMP_PRODUTOS VALUES (:CD_GRUPO, :CD_FILIAL, 100, '');
          END
      END
  END
END ^

ALTER PROCEDURE SP_EXPORTACAO_INVENTARIO_FFACIL (MES INTEGER)
RETURNS (LINHA VARCHAR(1000) CHARACTER SET NONE)
AS 
declare variable ID_PRODUTO double precision;
declare variable CD_PRODUTO varchar(100);
declare variable DESCRICAO varchar(100);
declare variable UNIDADE varchar(100);
declare variable NCM varchar(100);
declare variable ALIQUOTA varchar(100);
declare variable QUANTIDADE varchar(100);
declare variable TIPOPRODUTO varchar(100);
declare variable SITUACAOTRIBUTARIA varchar(100);
declare variable VALOR varchar(100);
declare variable FQUANTIDADE numeric(15,3);
declare variable FVALOR numeric(15,2);

BEGIN
  FOR
      SELECT 
       ID_PRODUTO,
       CD_PRODUTO,
       DESCRICAO,
       UNIDADE,
       SITUACAOTRIBUTARIA,
       CASE
        WHEN ICMS = 'FF' OR ICMS = 'NN' OR ICMS = 'II' THEN '0'
        ELSE ICMS
       END,
       NCM,
       CASE
         WHEN STATUS = 'A' THEN '00'
         WHEN STATUS = 'P' THEN '08'
         WHEN STATUS = 'C' THEN '07'
       END AS TIPOPRODUTO
      FROM
       PRODUTOS
      WHERE
       STATUS <> 'I'
      INTO
       :ID_PRODUTO,
       :CD_PRODUTO,
       :DESCRICAO,
       :UNIDADE,
       :SITUACAOTRIBUTARIA,
       :ALIQUOTA,
       :NCM,
       :TIPOPRODUTO
  DO
   BEGIN
     CD_PRODUTO = LPAD(CD_PRODUTO, 14, '0');
     IF (:NCM IS NULL) THEN
        NCM = '00000000';

     SELECT QUANTIDADE, (QUANTIDADE * CUSTO) FROM POSICAOESTOQUEDATA WHERE ID_PRODUTO = :ID_PRODUTO AND EXTRACT(DAY FROM DATA) = '1' AND EXTRACT(MONTH FROM DATA) = :MES INTO :FQUANTIDADE, :FVALOR;
     IF ((:FQUANTIDADE IS NOT NULL) AND (:FVALOR IS NOT NULL) AND (:FQUANTIDADE > 0) AND (:FVALOR > 0)) THEN
      BEGIN
        QUANTIDADE = CAST(:FQUANTIDADE AS VARCHAR(100));
        QUANTIDADE = REPLACE(:QUANTIDADE, '.', ',');
        VALOR = CAST(:FVALOR AS VARCHAR(100));
        VALOR = REPLACE(:VALOR, '.', ',');

        LINHA = :CD_PRODUTO||'|'||:DESCRICAO||'|'||:UNIDADE||'|'||:QUANTIDADE||'|'||:VALOR||'|0|'||:SITUACAOTRIBUTARIA||'|'||:ALIQUOTA||'|'||:NCM||'||'||:TIPOPRODUTO;
        SUSPEND;
      END
   END
END ^

ALTER PROCEDURE SP_EXPORTACAO_ITENSNOTAS_FFACIL (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (LINHA VARCHAR(1000) CHARACTER SET NONE)
AS 
declare variable CFOP varchar(100);
declare variable ICMS varchar(100);
declare variable CNPJ varchar(100);
declare variable MODELO varchar(100);
declare variable SERIE varchar(100);
declare variable NUMERONOTA varchar(100);
declare variable EMITENTE varchar(100);
declare variable BASEICMS varchar(100);
declare variable VALORICMS varchar(100);
declare variable TOTALPRODUTOS varchar(100);
declare variable FRETE varchar(100);
declare variable SEGURO varchar(100);
declare variable DESCONTO varchar(100);
declare variable VALORIPI varchar(100);
declare variable OUTRASDESPESAS varchar(100);
declare variable BASEICMSST varchar(100);
declare variable VALORST varchar(100);
declare variable SITUACAOTRIBUTARIA varchar(100);
declare variable SEQUENCIAL varchar(100);
declare variable PERCENTUAL_IPI varchar(100);
declare variable PERCENTUAL_ICMS_ST varchar(100);
declare variable UNIDADE varchar(100);
declare variable NCM varchar(100);
declare variable CST_IPI varchar(100);
declare variable BASE_IPI varchar(100);
declare variable PIS_CST varchar(100);
declare variable PIS_BASE_CALCULO varchar(100);
declare variable PIS_PERCENTUAL varchar(100);
declare variable PIS_VALOR varchar(100);
declare variable COFINS_CST varchar(100);
declare variable COFINS_BASE_CALCULO varchar(100);
declare variable COFINS_PERCENTUAL varchar(100);
declare variable COFINS_VALOR varchar(100);
declare variable NATRECISENTAPIS varchar(100);
declare variable NATRECISENTACOFINS varchar(100);
declare variable CD_PRODUTO varchar(100);
declare variable QUANTIDADE varchar(100);
declare variable NSEQUENCIAL integer;
BEGIN
  NSEQUENCIAL = 1;
  SEQUENCIAL = CAST(:NSEQUENCIAL AS VARCHAR(100));
  FOR
    SELECT
     DISTRIBUIDORES.CNPJ,
     COMPRAS.MODELONF, 
     COMPRAS.SERIE_NOTA_FISCAL,
     COMPRAS.NOTA_FISCAL,
     ITENS_COMPRA.CFOP,
     ITENS_COMPRA.SITUACAOTRIBITARIA,
     CASE
      WHEN (COMPRAS.CD_CFOP < 5000 AND COMPRAS.CD_CFOP <> 1202 AND COMPRAS.CD_CFOP <> 1411 AND COMPRAS.CD_CFOP <> 2202 AND COMPRAS.CD_CFOP <> 2411) OR (COMPRAS.CD_CFOP = 5202) OR (COMPRAS.CD_CFOP = 5411) OR (COMPRAS.CD_CFOP = 6202) OR (COMPRAS.CD_CFOP = 6411) THEN 'T'
      WHEN (COMPRAS.CD_CFOP > 5000 AND COMPRAS.CD_CFOP <> 5202 AND COMPRAS.CD_CFOP <> 5411 AND COMPRAS.CD_CFOP <> 6202 AND COMPRAS.CD_CFOP <> 6411) OR (COMPRAS.CD_CFOP = 1202) OR (COMPRAS.CD_CFOP = 1411) OR (COMPRAS.CD_CFOP = 2202) OR (COMPRAS.CD_CFOP = 2411) THEN 'P'
     END, -- EMITENTE
     ITENS_COMPRA.CD_PRODUTO,
     ITENS_COMPRA.QUANTIDADE,
     ITENS_COMPRA.VL_UNITARIO * ITENS_COMPRA.QUANTIDADE, -- TOTAL PRODUTO
     CASE
      WHEN (COMPRAS.CD_CFOP = 1202) OR (COMPRAS.CD_CFOP = 1411) OR (COMPRAS.CD_CFOP = 2202) OR (COMPRAS.CD_CFOP = 2411) THEN ITENS_COMPRA.VL_DESCONTO
      ELSE ITENS_COMPRA.VL_DESCONTO * ITENS_COMPRA.QUANTIDADE
     END, -- DESCONTO
     ITENS_COMPRA.VALOR_FRETE,
     ITENS_COMPRA.VALOR_OUTRASDESPESAS, -- DESPESAS_ACESSORIAS
     ITENS_COMPRA.VALOR_SEGURO,
     ITENS_COMPRA.BASEICMS,
     ITENS_COMPRA.BASEICMSSUBSTITUICAO,
     ITENS_COMPRA.VL_ICMS,
     ITENS_COMPRA.VALORICMSSUBTITUICAO,
     ITENS_COMPRA.VL_IPI,
     CASE
      WHEN ITENS_COMPRA.ICMS = 'FF' OR ITENS_COMPRA.ICMS = 'NN' OR ITENS_COMPRA.ICMS = 'II' THEN '0'
      ELSE ITENS_COMPRA.ICMS
     END, -- ALIQUOTA
     ITENS_COMPRA.PERCENTUAL_IPI,
     ITENS_COMPRA.PERCENTUAL_ICMS_ST,
     ITENS_COMPRA.UNIDADE,
     PRODUTOS.NCM, 
     ITENS_COMPRA.CST_IPI, -- CST IPI
     ITENS_COMPRA.BASECALCULO_IPI, -- BASE IPI
     ITENS_COMPRA.PIS_CST,
     ITENS_COMPRA.PIS_BASE_CALCULO,
     ITENS_COMPRA.PIS_PERCENTUAL,
     ITENS_COMPRA.PIS_VALOR,
     ITENS_COMPRA.COFINS_CST,
     ITENS_COMPRA.COFINS_BASE_CALCULO,
     ITENS_COMPRA.COFINS_PERCENTUAL,
     ITENS_COMPRA.COFINS_VALOR,
     ITENS_COMPRA.NATUREZA_ISENTA_PIS, -- NATUREZA RECEITA ISENTA PIS
     ITENS_COMPRA.NATUREZA_ISENTA_COFINS  -- NATUREZA RECEITA ISENTA COFINS
    FROM
     ITENS_COMPRA,
     COMPRAS,
     DISTRIBUIDORES,
     PRODUTOS
    WHERE
     COMPRAS.CD_DISTRIBUIDOR = DISTRIBUIDORES.CD_DISTRIBUIDOR AND
     COMPRAS.CD_COMPRAS = ITENS_COMPRA.CD_COMPRAS AND
     ITENS_COMPRA.ID_PRODUTO = PRODUTOS.ID_PRODUTO AND
     COMPRAS.DT_ENTRADA >= :DATAINICIAL AND
     COMPRAS.DT_ENTRADA <= :DATAFINAL AND
     (COMPRAS.STATUS = 'C' OR COMPRAS.STATUS = 'D')
    INTO
     :CNPJ,
     :MODELO,
     :SERIE,
     :NUMERONOTA,
     :CFOP,
     :SITUACAOTRIBUTARIA,
     :EMITENTE,
     :CD_PRODUTO,
     :QUANTIDADE,
     :TOTALPRODUTOS,
     :DESCONTO,
     :FRETE,
     :OUTRASDESPESAS,
     :SEGURO,
     :BASEICMS,
     :BASEICMSST,
     :VALORICMS,
     :VALORST,
     :VALORIPI,
     :ICMS,
     :PERCENTUAL_IPI,
     :PERCENTUAL_ICMS_ST,
     :UNIDADE,
     :NCM,
     :CST_IPI,
     :BASE_IPI,
     :PIS_CST,
     :PIS_BASE_CALCULO,
     :PIS_PERCENTUAL,
     :PIS_VALOR,
     :COFINS_CST,
     :COFINS_BASE_CALCULO,
     :COFINS_PERCENTUAL,
     :COFINS_VALOR,
     :NATRECISENTAPIS,
     :NATRECISENTACOFINS
   DO
    BEGIN
     IF (:CD_PRODUTO IS NULL) THEN
          CD_PRODUTO = '';
     CD_PRODUTO = LPAD(:CD_PRODUTO, 14, '0');
     IF (:CNPJ IS NULL) THEN
          CNPJ = '';
     IF (:MODELO IS NULL) THEN
         MODELO = '';
     IF (:SERIE IS NULL) THEN
        SERIE = '';
     IF (:NUMERONOTA IS NULL) THEN
        NUMERONOTA = '';
     IF (:CFOP IS NULL) THEN
        CFOP = '';
     IF (:SITUACAOTRIBUTARIA IS NULL) THEN
        SITUACAOTRIBUTARIA = '';
     IF (:QUANTIDADE IS NULL) THEN
          QUANTIDADE = '0';
     IF (:TOTALPRODUTOS IS NULL) THEN
          TOTALPRODUTOS = '0';
     IF (:DESCONTO IS NULL) THEN
          DESCONTO = '0';
     IF (:FRETE IS NULL) THEN
          FRETE = '0';
     IF (:OUTRASDESPESAS IS NULL) THEN
          OUTRASDESPESAS = '0';
     IF (:SEGURO IS NULL) THEN
          SEGURO = '0';
     IF (:BASEICMS IS NULL) THEN
          BASEICMS = '0';
     IF (:BASEICMSST IS NULL) THEN
          BASEICMSST = '0';
     IF (:VALORICMS IS NULL) THEN
          VALORICMS = '0';
     IF (:VALORST IS NULL) THEN
          VALORST = '0';
     IF (:VALORIPI IS NULL) THEN
          VALORIPI = '0';
     IF (:ICMS IS NULL) THEN
          ICMS = '0';
     IF (:PERCENTUAL_IPI IS NULL) THEN
          PERCENTUAL_IPI = '0';
     IF (:PERCENTUAL_ICMS_ST IS NULL) THEN
          PERCENTUAL_ICMS_ST = '0';
     IF (:UNIDADE IS NULL) THEN
          UNIDADE = '';
     IF (:NCM IS NULL) THEN
          NCM = '99999999';
     IF (:CST_IPI IS NULL) THEN
          CST_IPI = '';
     IF (:BASE_IPI IS NULL) THEN
          BASE_IPI = '0';
     IF (:PIS_CST IS NULL) THEN
         PIS_CST = '';
     IF (:PIS_BASE_CALCULO IS NULL) THEN
         PIS_BASE_CALCULO = '0';
     IF (:PIS_PERCENTUAL IS NULL) THEN
         PIS_PERCENTUAL = '0';
     IF (:PIS_VALOR IS NULL) THEN
         PIS_VALOR = '0';
     IF (:COFINS_CST IS NULL) THEN
         COFINS_CST = '';
     IF (:COFINS_BASE_CALCULO IS NULL) THEN
         COFINS_BASE_CALCULO = '0';
     IF (:COFINS_PERCENTUAL IS NULL) THEN
         COFINS_PERCENTUAL = '0';
     IF (:COFINS_VALOR IS NULL) THEN
         COFINS_VALOR = '0';
     IF (:NATRECISENTAPIS IS NULL) THEN
        NATRECISENTAPIS = '';
     IF (:NATRECISENTACOFINS IS NULL) THEN
        NATRECISENTACOFINS = '';


     QUANTIDADE = REPLACE(CAST(CAST(:QUANTIDADE AS NUMERIC(15,3)) AS VARCHAR(100)), '.', ',');
     TOTALPRODUTOS = REPLACE(CAST(CAST(:TOTALPRODUTOS AS NUMERIC(15,2)) AS VARCHAR(100)), '.', ',');
     DESCONTO = REPLACE(CAST(CAST(:DESCONTO AS NUMERIC(15,2)) AS VARCHAR(100)), '.', ',');
     FRETE = REPLACE(CAST(CAST(:FRETE AS NUMERIC(15,2)) AS VARCHAR(100)), '.', ',');
     OUTRASDESPESAS = REPLACE(CAST(CAST(:OUTRASDESPESAS AS NUMERIC(15,2)) AS VARCHAR(100)), '.', ',');
     SEGURO = REPLACE(CAST(CAST(:SEGURO AS NUMERIC(15,2)) AS VARCHAR(100)), '.', ',');
     BASEICMS = REPLACE(CAST(CAST(:BASEICMS AS NUMERIC(15,2)) AS VARCHAR(100)), '.', ',');
     BASEICMSST = REPLACE(CAST(CAST(:BASEICMSST AS NUMERIC(15,2)) AS VARCHAR(100)), '.', ',');
     VALORICMS = REPLACE(CAST(CAST(:VALORICMS AS NUMERIC(15,2)) AS VARCHAR(100)), '.', ',');
     VALORST = REPLACE(CAST(CAST(:VALORST AS NUMERIC(15,2)) AS VARCHAR(100)), '.', ',');
     VALORIPI = REPLACE(CAST(CAST(:VALORIPI AS NUMERIC(15,2)) AS VARCHAR(100)), '.', ',');
     PERCENTUAL_IPI = REPLACE(CAST(CAST(:PERCENTUAL_IPI AS NUMERIC(15,3)) AS VARCHAR(100)), '.', ',');
     PERCENTUAL_ICMS_ST = REPLACE(CAST(CAST(:PERCENTUAL_ICMS_ST AS NUMERIC(15,3)) AS VARCHAR(100)), '.', ',');
     BASE_IPI = REPLACE(CAST(CAST(:BASE_IPI AS NUMERIC(15,2)) AS VARCHAR(100)), '.', ',');
     PIS_BASE_CALCULO = REPLACE(CAST(CAST(:PIS_BASE_CALCULO AS NUMERIC(15,2)) AS VARCHAR(100)), '.', ',');
     PIS_PERCENTUAL = REPLACE(CAST(CAST(:PIS_PERCENTUAL AS NUMERIC(15,3)) AS VARCHAR(100)), '.', ',');
     PIS_VALOR = REPLACE(CAST(CAST(:PIS_VALOR AS NUMERIC(15,2)) AS VARCHAR(100)), '.', ',');
     COFINS_BASE_CALCULO = REPLACE(CAST(CAST(:COFINS_BASE_CALCULO AS NUMERIC(15,2)) AS VARCHAR(100)), '.', ',');
     COFINS_PERCENTUAL = REPLACE(CAST(CAST(:COFINS_PERCENTUAL AS NUMERIC(15,3)) AS VARCHAR(100)), '.', ',');
     COFINS_VALOR = REPLACE(CAST(CAST(:COFINS_VALOR AS NUMERIC(15,2)) AS VARCHAR(100)), '.', ',');


      LINHA =
         :CNPJ||'|'||
         :MODELO||'|'||
         :SERIE||'|'||
         :NUMERONOTA||'|'||
         :CFOP||'|'||
         :SITUACAOTRIBUTARIA||'|'||
         :EMITENTE||'|'||
         :SEQUENCIAL||'|'||
         :CD_PRODUTO||'|'||
         :QUANTIDADE||'|'||
         :TOTALPRODUTOS||'|'||
         :DESCONTO||'|'||
         :FRETE||'|'||
         :OUTRASDESPESAS||'|'||
         :SEGURO||'|'||
         :BASEICMS||'|'||
         :BASEICMSST||'|'||
         :VALORICMS||'|'||
         :VALORST||'|'||
         :VALORIPI||'|'||
         :ICMS||'|'||
         :PERCENTUAL_IPI||'|'||
         :PERCENTUAL_ICMS_ST||'|'||
         :UNIDADE||'|'||
         :NCM||'|'||
         :CST_IPI||'|'||
         :BASE_IPI||'|'||
         :PIS_CST||'|'||
         :PIS_BASE_CALCULO||'|'||
         :PIS_PERCENTUAL||'|'||
         :PIS_VALOR||'|'||
         :COFINS_CST||'|'||
         :COFINS_BASE_CALCULO||'|'||
         :COFINS_PERCENTUAL||'|'||
         :COFINS_VALOR||'|'||
         :NATRECISENTAPIS||'|'||
         :NATRECISENTACOFINS;

      NSEQUENCIAL = :NSEQUENCIAL + 1;
      SEQUENCIAL = CAST(:NSEQUENCIAL AS VARCHAR(100));

      SUSPEND;
   END
END ^

ALTER PROCEDURE SP_EXPORTACAO_LABORATORIOS AS 
DECLARE VARIABLE CD_LABORATORIO DOUBLE PRECISION;
DECLARE VARIABLE CD_FILIAL DOUBLE PRECISION;
DECLARE VARIABLE TIPO_LOJA VARCHAR(1);
DECLARE VARIABLE EXPORTAR VARCHAR(1);
BEGIN
 SELECT CD_FILIAL, TIPO_LOJA FROM PARAMETROS INTO :CD_FILIAL, :TIPO_LOJA;
 IF ((:CD_FILIAL = 0) OR (:TIPO_LOJA = 'U')) THEN
  BEGIN
     FOR
      SELECT
       CD_LABORATORIO
      FROM
       LABORATORIOS
      INTO
       :CD_LABORATORIO
     DO
      BEGIN
        FOR
         SELECT CD_FILIAL FROM FILIAIS WHERE EXPORTAR = 'S' INTO :CD_FILIAL
        DO
          BEGIN
               INSERT INTO TEMP_PRODUTOS VALUES (:CD_LABORATORIO, :CD_FILIAL, 101, '');
          END
      END
  END
END ^

ALTER PROCEDURE SP_EXPORTACAO_NOTAS_FFACIL (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (LINHA VARCHAR(1000) CHARACTER SET NONE)
AS 
declare variable CD_COMPRAS double precision;
declare variable CFOP varchar(100);
declare variable ICMS varchar(100);
declare variable CNPJ varchar(100);
declare variable IE varchar(100);
declare variable DATAEMISSAO varchar(100);
declare variable DDATAEMISSAO date;
declare variable DATAENTRADA varchar(100);
declare variable DDATAENTRADA date;
declare variable UF varchar(100);
declare variable MODELO varchar(100);
declare variable SERIE varchar(100);
declare variable NUMERONOTA varchar(100);
declare variable EMITENTE varchar(100);
declare variable TOTALNOTA varchar(100);
declare variable BASEICMS varchar(100);
declare variable VALORICMS varchar(100);
declare variable TOTALPRODUTOS varchar(100);
declare variable FRETE varchar(100);
declare variable SEGURO varchar(100);
declare variable DESCONTO varchar(100);
declare variable BASEIPI varchar(100);
declare variable VALORIPI varchar(100);
declare variable SITUACAO varchar(100);
declare variable OBSCANCELAMENTO varchar(100);
declare variable DESDOBRO varchar(100);
declare variable CHAVENFE varchar(100);
declare variable FORMAPAGAMENTO varchar(100);
declare variable VALORISENTO varchar(100);
declare variable VALOROUTROS varchar(100);
declare variable OUTRASDESPESAS varchar(100);
declare variable BASEICMSST varchar(100);
declare variable VALORST varchar(100);
BEGIN
  FOR
    SELECT
     ITENS_COMPRA.CD_COMPRAS,
     ITENS_COMPRA.CFOP,
     CASE
      WHEN ITENS_COMPRA.ICMS = 'FF' OR ITENS_COMPRA.ICMS = 'NN' OR ITENS_COMPRA.ICMS = 'II' THEN '0'
      ELSE ITENS_COMPRA.ICMS
     END,
     CASE
      WHEN CFOP = '1411' OR CFOP = '1202' OR CFOP = '2411' OR CFOP = '2202' THEN SUM(ITENS_COMPRA.VL_TOTAL + ITENS_COMPRA.VALORICMSSUBTITUICAO + ITENS_COMPRA.VALOR_OUTRASDESPESAS + ITENS_COMPRA.VALOR_SEGURO + ITENS_COMPRA.VALOR_FRETE + ITENS_COMPRA.VL_IPI - ITENS_COMPRA.VL_DESCONTO)
      ELSE SUM(ITENS_COMPRA.VL_TOTAL + ITENS_COMPRA.VALORICMSSUBTITUICAO + ITENS_COMPRA.VALOR_OUTRASDESPESAS + ITENS_COMPRA.VALOR_SEGURO + ITENS_COMPRA.VALOR_FRETE + ITENS_COMPRA.VL_IPI)
     END,
     SUM(ITENS_COMPRA.BASEICMS),
     SUM(ITENS_COMPRA.VL_ICMS),
     SUM(ITENS_COMPRA.VALOR_ISENTO), -- VALORISENTO
     SUM(ITENS_COMPRA.VALOR_OUTRAS), -- VALOR OUTRAS
     SUM(ITENS_COMPRA.VALOR_OUTRASDESPESAS), -- DESPESAS_ACESSORIAS
     SUM(ITENS_COMPRA.BASEICMSSUBSTITUICAO),
     SUM(ITENS_COMPRA.VALORICMSSUBTITUICAO),
     SUM(ITENS_COMPRA.VL_UNITARIO * ITENS_COMPRA.QUANTIDADE),
     SUM(ITENS_COMPRA.VALOR_FRETE),
     SUM(ITENS_COMPRA.VALOR_SEGURO),
     CASE
      WHEN CFOP = '1411' OR CFOP = '1202' OR CFOP = '2411' OR CFOP = '2202' THEN SUM(ITENS_COMPRA.VL_DESCONTO)
      ELSE SUM(ITENS_COMPRA.VL_DESCONTO * ITENS_COMPRA.QUANTIDADE)
     END,
     SUM(ITENS_COMPRA.BASECALCULO_IPI), -- BASE CALCULO IPI
     SUM(ITENS_COMPRA.VL_IPI)
    FROM
     ITENS_COMPRA,
     COMPRAS
    WHERE
     COMPRAS.CD_COMPRAS = ITENS_COMPRA.CD_COMPRAS AND
     COMPRAS.DT_ENTRADA >= :DATAINICIAL AND
     COMPRAS.DT_ENTRADA <= :DATAFINAL AND
     (COMPRAS.STATUS = 'C' OR COMPRAS.STATUS = 'D')
    GROUP BY
     CD_COMPRAS,
     CFOP,
     ICMS
    INTO
     :CD_COMPRAS,
     :CFOP,
     :ICMS,
     :TOTALNOTA,
     :BASEICMS,
     :VALORICMS,
     :VALORISENTO,
     :VALOROUTROS,
     :OUTRASDESPESAS,
     :BASEICMSST,
     :VALORST,
     :TOTALPRODUTOS,
     :FRETE,
     :SEGURO,
     :DESCONTO,
     :BASEIPI,
     :VALORIPI
   DO
    BEGIN
     IF (:ICMS IS NULL) THEN
          ICMS = '0';
     IF (:BASEICMS IS NULL) THEN
          BASEICMS = '0';
     IF (:VALORICMS IS NULL) THEN
          VALORICMS = '0';
     IF (:VALORISENTO IS NULL) THEN
          VALORISENTO = '0';
     IF (:VALOROUTROS IS NULL) THEN
          VALOROUTROS = '0';
     IF (:OUTRASDESPESAS IS NULL) THEN
          OUTRASDESPESAS = '0';
     IF (:BASEICMSST IS NULL) THEN
          BASEICMSST = '0';
     IF (:VALORST IS NULL) THEN
          VALORST = '0';
     IF (:TOTALPRODUTOS IS NULL) THEN
          TOTALPRODUTOS = '0';
     IF (:FRETE IS NULL) THEN
          FRETE = '0';
     IF (:SEGURO IS NULL) THEN
          SEGURO = '0';
     IF (:DESCONTO IS NULL) THEN
          DESCONTO = '0';
     IF (:BASEIPI IS NULL) THEN
          BASEIPI = '0';
     IF (:VALORIPI IS NULL) THEN
          VALORIPI = '0';


     TOTALNOTA = REPLACE(CAST(CAST(:TOTALNOTA AS NUMERIC(15,2)) AS VARCHAR(100)), '.', ',');
     BASEICMS = REPLACE(CAST(CAST(:BASEICMS AS NUMERIC(15,2)) AS VARCHAR(100)), '.', ',');
     VALORICMS = REPLACE(CAST(CAST(:VALORICMS AS NUMERIC(15,2)) AS VARCHAR(100)), '.', ',');
     VALORISENTO = REPLACE(CAST(CAST(:VALORISENTO AS NUMERIC(15,2)) AS VARCHAR(100)), '.', ',');
     VALOROUTROS = REPLACE(CAST(CAST(:VALOROUTROS AS NUMERIC(15,2)) AS VARCHAR(100)), '.', ',');
     OUTRASDESPESAS = REPLACE(CAST(CAST(:OUTRASDESPESAS AS NUMERIC(15,2)) AS VARCHAR(100)), '.', ',');
     BASEICMSST = REPLACE(CAST(CAST(:BASEICMSST AS NUMERIC(15,2)) AS VARCHAR(100)), '.', ',');
     VALORST = REPLACE(CAST(CAST(:VALORST AS NUMERIC(15,2)) AS VARCHAR(100)), '.', ',');
     TOTALPRODUTOS = REPLACE(CAST(CAST(:TOTALPRODUTOS AS NUMERIC(15,2)) AS VARCHAR(100)), '.', ',');
     FRETE = REPLACE(CAST(CAST(:FRETE AS NUMERIC(15,2)) AS VARCHAR(100)), '.', ',');
     SEGURO = REPLACE(CAST(CAST(:SEGURO AS NUMERIC(15,2)) AS VARCHAR(100)), '.', ',');
     DESCONTO = REPLACE(CAST(CAST(:DESCONTO AS NUMERIC(15,2)) AS VARCHAR(100)), '.', ',');
     BASEIPI = REPLACE(CAST(CAST(:BASEIPI AS NUMERIC(15,2)) AS VARCHAR(100)), '.', ',');
     VALORIPI = REPLACE(CAST(CAST(:VALORIPI AS NUMERIC(15,2)) AS VARCHAR(100)), '.', ',');

      SELECT
       DISTRIBUIDORES.CNPJ,
       DISTRIBUIDORES.IE,
       COMPRAS.DT_ENTRADA,
       COMPRAS.DT_ENTRADA,
       DISTRIBUIDORES.UF,
       COMPRAS.MODELONF, 
       COMPRAS.SERIE_NOTA_FISCAL,
       COMPRAS.NOTA_FISCAL,
       CASE
        WHEN (COMPRAS.CD_CFOP < 5000 AND COMPRAS.CD_CFOP <> 1202 AND COMPRAS.CD_CFOP <> 1411) OR (COMPRAS.CD_CFOP = 5202) OR (COMPRAS.CD_CFOP = 5411) THEN 'T'
        WHEN (COMPRAS.CD_CFOP > 5000 AND COMPRAS.CD_CFOP <> 5202 AND COMPRAS.CD_CFOP <> 5411) OR (COMPRAS.CD_CFOP = 1202) OR (COMPRAS.CD_CFOP = 1411) THEN 'P'
       END, -- EMITENTE
       CASE
        WHEN COMPRAS.STATUS = 'C' THEN 'N'
        WHEN COMPRAS.STATUS = 'D' THEN 'S'
       END, -- SITUACAO
       '', -- OBS CANCELAMENTO
       '', -- DESDOBRO
       COMPRAS.CHAVENFE,
       '' -- FORMA PAGAMENTO
      FROM
       DISTRIBUIDORES,
       COMPRAS
      WHERE
       DISTRIBUIDORES.CD_DISTRIBUIDOR = COMPRAS.CD_DISTRIBUIDOR AND
       COMPRAS.CD_COMPRAS = :CD_COMPRAS
      INTO
       :CNPJ,
       :IE,
       :DDATAEMISSAO,
       :DDATAENTRADA,
       :UF,
       :MODELO,
       :SERIE,
       :NUMERONOTA,
       :EMITENTE,
       :SITUACAO,
       :OBSCANCELAMENTO,
       :DESDOBRO,
       :CHAVENFE,
       :FORMAPAGAMENTO;

       IF (:CNPJ IS NULL) THEN
           CNPJ = '';
       IF (:IE IS NULL) THEN
           IE = '';
       IF (:UF IS NULL) THEN
           UF = '';
       IF (:MODELO IS NULL) THEN
           MODELO = '';
       IF (:SERIE IS NULL) THEN
           SERIE = '';
       IF (:NUMERONOTA IS NULL) THEN
           NUMERONOTA = '';
       IF (:EMITENTE IS NULL) THEN
           EMITENTE = '';
       IF (:SITUACAO IS NULL) THEN
           SITUACAO = '';
       IF (:OBSCANCELAMENTO IS NULL) THEN
           OBSCANCELAMENTO = '';
       IF (:DESDOBRO IS NULL) THEN
           DESDOBRO = '';
       IF (:CHAVENFE IS NULL) THEN
           CHAVENFE = '';
       IF (:FORMAPAGAMENTO IS NULL) THEN
           FORMAPAGAMENTO = '';

       DATAEMISSAO = EXTRACT(DAY FROM :DDATAEMISSAO)||'/'||EXTRACT(MONTH FROM :DDATAEMISSAO)||'/'||EXTRACT(YEAR FROM :DDATAEMISSAO);
       DATAENTRADA = EXTRACT(DAY FROM :DDATAENTRADA)||'/'||EXTRACT(MONTH FROM :DDATAENTRADA)||'/'||EXTRACT(YEAR FROM :DDATAENTRADA);

      LINHA =
       :CNPJ||'|'||
       :IE||'|'||
       :DATAEMISSAO||'|'||
       :DATAENTRADA||'|'||
       :UF||'|'||
       :MODELO||'|'||
       :SERIE||'|'||
       :NUMERONOTA||'|'||
       :CFOP||'|'||
       :EMITENTE||'|'||
       :TOTALNOTA||'|'||
       :BASEICMS||'|'||
       :VALORICMS||'|'||
       :VALORISENTO||'|'||
       :VALOROUTROS||'|'||
       :OUTRASDESPESAS||'|'||
       :ICMS||'|'||
       :BASEICMSST||'|'||
       :VALORST||'|'||
       :TOTALPRODUTOS||'|'||
       :FRETE||'|'||
       :SEGURO||'|'||
       :DESCONTO||'|'||
       :BASEIPI||'|'||
       :VALORIPI||'|'||
       :SITUACAO||'|'||
       :OBSCANCELAMENTO||'|'||
       :DESDOBRO||'|'||
       :CHAVENFE||'|'||
       :FORMAPAGAMENTO;


      SUSPEND;
    END
END ^

ALTER PROCEDURE SP_EXPORTACAO_PRECOS (CD_FILIAL VARCHAR(2) CHARACTER SET NONE,
DATA_REAJUSTE VARCHAR(10) CHARACTER SET NONE)
AS 
declare variable ID_PRODUTO double precision;
declare variable PRECO_VENDA_ANTERIOR double precision;
declare variable PRECO_VENDA double precision;
declare variable PRECO_PROMOCAO double precision;
declare variable DT_VENCIMENTO_PROMOCAO date;
declare variable COMANDO varchar(1000);
declare variable EXPORTA varchar(1);
declare variable DT_REAJUSTE date;
declare variable USUARIO varchar(100);
declare variable EXISTE integer;
BEGIN
  SELECT EXPORTAR FROM FILIAIS WHERE CD_FILIAL = :CD_FILIAL INTO :EXPORTA;
  IF (:EXPORTA = 'S') THEN
   BEGIN
    COMANDO = 'SELECT ID_PRODUTO, PRECO_VENDA_ANTERIOR_'||:CD_FILIAL||', PRECO_VENDA_'||:CD_FILIAL||
              ', PRECO_PROMOCAO_'||:CD_FILIAL||', DT_VENCIMENTO_PROMOCAO_'||:CD_FILIAL||', DT_REAJUSTE_'||:CD_FILIAL||
              ' FROM PRODUTOS WHERE DT_REAJUSTE_'||:CD_FILIAL||
              ' >= '''||:DATA_REAJUSTE||'''';
    USUARIO = 'SP';
    FOR EXECUTE STATEMENT :COMANDO INTO :ID_PRODUTO, :PRECO_VENDA_ANTERIOR, :PRECO_VENDA, :PRECO_PROMOCAO, :DT_VENCIMENTO_PROMOCAO, :DT_REAJUSTE
     DO
      BEGIN
        SELECT COUNT(*) FROM REAJUSTE WHERE CD_FILIAL = :CD_FILIAL AND ID_PRODUTO = :ID_PRODUTO AND USUARIO = :USUARIO INTO :EXISTE;
        IF (:EXISTE = 0) THEN
           INSERT INTO REAJUSTE VALUES (:CD_FILIAL, :ID_PRODUTO, :DT_REAJUSTE, CURRENT_TIME, :PRECO_VENDA_ANTERIOR, :PRECO_VENDA, :PRECO_PROMOCAO, :PRECO_PROMOCAO, :DT_VENCIMENTO_PROMOCAO, :DT_VENCIMENTO_PROMOCAO, 'S', :DT_REAJUSTE, :USUARIO, :USUARIO, '');
      END
   END
END ^

ALTER PROCEDURE SP_EXPORTACAO_PRECOS_FIDELIDADE AS 
declare variable CD_FILIAL double precision;
declare variable ID_PRODUTO double precision;
declare variable EXISTE varchar(1);
BEGIN
     FOR SELECT CD_FILIAL FROM FILIAIS WHERE STATUS = 'A' AND EXPORTAR = 'S' INTO :CD_FILIAL DO
      BEGIN
        FOR SELECT ID_PRODUTO FROM FILIAIS_FIDELIDADE WHERE CD_FILIAL = :CD_FILIAL INTO :ID_PRODUTO DO
         BEGIN
            SELECT COUNT(*) FROM TEMP_PRODUTOS WHERE CD_FILIAL = :CD_FILIAL AND ID_PRODUTO = :ID_PRODUTO AND PROCESSO = 158 INTO :EXISTE;
            IF (:EXISTE = 0) THEN
               INSERT INTO TEMP_PRODUTOS VALUES (:ID_PRODUTO, :CD_FILIAL, 158, '');
         END
      END
END ^

