ALTER PROCEDURE SP_EXPORTACAO_PRECOS_TODOS AS 
declare variable CD_FILIAL varchar(10);
declare variable EXPORTA varchar(1);
declare variable ID_PRODUTO double precision;
declare variable PRECO_VENDA_ANTERIOR double precision;
declare variable PRECO_VENDA double precision;
declare variable PRECO_PROMOCAO double precision;
declare variable DT_VENCIMENTO_PROMOCAO date;
declare variable COMANDO varchar(1000);
declare variable DT_REAJUSTE date;
declare variable EXISTE integer;
declare variable CODIGOUSUARIO varchar(10);
BEGIN
  --EXECUTE PROCEDURE SP_CONSISTENCIA_LOJA_RODANDO_2;
  DELETE FROM REAJUSTE WHERE USUARIO = 'SP';
  SELECT CODIGOUSUARIO FROM PARAMETROS INTO :CODIGOUSUARIO;
  IF (:CODIGOUSUARIO <> '2292') THEN
   BEGIN
      FOR
        SELECT
          CD_FILIAL,
          EXPORTAR
        FROM
          FILIAIS
        INTO
          :CD_FILIAL,
          :EXPORTA
      DO
       BEGIN
          IF (:EXPORTA = 'S') THEN
           BEGIN
               BEGIN
                  COMANDO = 'SELECT ID_PRODUTO, PRECO_VENDA_ANTERIOR_'||CAST(:CD_FILIAL AS INTEGER)||', PRECO_VENDA_'||CAST(:CD_FILIAL AS INTEGER)||
                            ', PRECO_PROMOCAO_'||CAST(:CD_FILIAL AS INTEGER)||', DT_VENCIMENTO_PROMOCAO_'||CAST(:CD_FILIAL AS INTEGER)||', DT_REAJUSTE_'||CAST(:CD_FILIAL AS INTEGER)||
                            ' FROM PRODUTOS';
                  FOR EXECUTE STATEMENT :COMANDO INTO :ID_PRODUTO, :PRECO_VENDA_ANTERIOR, :PRECO_VENDA, :PRECO_PROMOCAO, :DT_VENCIMENTO_PROMOCAO, :DT_REAJUSTE
                   DO
                    BEGIN
                      IF (:PRECO_VENDA_ANTERIOR IS NULL) THEN
                         PRECO_VENDA_ANTERIOR = 0;
                      INSERT INTO REAJUSTE VALUES (:CD_FILIAL, :ID_PRODUTO, :DT_REAJUSTE, CURRENT_TIME, :PRECO_VENDA_ANTERIOR, :PRECO_VENDA, :PRECO_PROMOCAO, :PRECO_PROMOCAO, :DT_VENCIMENTO_PROMOCAO, :DT_VENCIMENTO_PROMOCAO, 'S', :DT_REAJUSTE, 'SP', 'SP', '');
                    END
               END
           END
       END
   END
END ^

