ALTER PROCEDURE SP_EXPORTACAO_PRODUTOS_FFACIL RETURNS (LINHA VARCHAR(1000) CHARACTER SET NONE)
AS 
declare variable ENQUADRAMENTOTRIBUTARIO varchar(1);
declare variable CD_PRODUTO varchar(14);
declare variable DESCRICAO varchar(60);
declare variable UNIDADE varchar(2);
declare variable NCM varchar(10);
declare variable ALIQUOTA varchar(4);
declare variable CODIGOBARRAS varchar(14);
declare variable TIPOPRODUTO varchar(2);
declare variable SITUACAOTRIBUTARIA varchar(2);
declare variable PIS_ENTRADA varchar(2);
declare variable PIS_SAIDA varchar(2);
declare variable COFINS_ENTRADA varchar(2);
declare variable COFINS_SAIDA varchar(2);
BEGIN
  SELECT ENQUADRAMENTOTRIBUTARIO FROM PARAMETROS INTO :ENQUADRAMENTOTRIBUTARIO;
  FOR
      SELECT 
       CD_PRODUTO,
       DESCRICAO,
       UNIDADE,
       NCM,
       CASE
        WHEN ICMS = 'FF' OR ICMS = 'NN' OR ICMS = 'II' THEN '0'
        ELSE ICMS
       END,
       CODIGO_BARRAS_1,
       CASE
         WHEN STATUS = 'A' THEN '00'
         WHEN STATUS = 'P' THEN '08'
         WHEN STATUS = 'C' THEN '07'
       END AS TIPOPRODUTO,
       SITUACAOTRIBUTARIA
      FROM
       PRODUTOS
      WHERE
       STATUS <> 'I'
      INTO
       :CD_PRODUTO,
       :DESCRICAO,
       :UNIDADE,
       :NCM,
       :ALIQUOTA,
       :CODIGOBARRAS,
       :TIPOPRODUTO,
       :SITUACAOTRIBUTARIA
  DO
   BEGIN
     CD_PRODUTO = LPAD(CD_PRODUTO, 14, '0');
     IF (:NCM IS NULL) THEN
        NCM = '00000000';

     IF (:ENQUADRAMENTOTRIBUTARIO = 'S') THEN -- Simples Nacional
      BEGIN
        SELECT
         PIS_ENTRADA_SN,
         PIS_SAIDA_SN,
         COFINS_ENTRADA_SN,
         COFINS_SAIDA_SN
        FROM
         SPED_PIS_COFINS
        WHERE
         SPED_PIS_COFINS.BARRA = :CODIGOBARRAS
        INTO
         :PIS_ENTRADA,
         :PIS_SAIDA,
         :COFINS_ENTRADA,
         :COFINS_SAIDA;
      END
     ELSE
     IF (:ENQUADRAMENTOTRIBUTARIO = 'P') THEN -- Lucro Presumido
      BEGIN
        SELECT
         PIS_ENTRADA_LP,
         PIS_SAIDA_LP,
         COFINS_ENTRADA_LP,
         COFINS_SAIDA_LP
        FROM
         SPED_PIS_COFINS
        WHERE
         SPED_PIS_COFINS.BARRA = :CODIGOBARRAS
        INTO
         :PIS_ENTRADA,
         :PIS_SAIDA,
         :COFINS_ENTRADA,
         :COFINS_SAIDA;
      END
     ELSE
     IF (:ENQUADRAMENTOTRIBUTARIO = 'R') THEN -- Lucro Real
      BEGIN
        SELECT
         PIS_ENTRADA_LR,
         PIS_SAIDA_LR,
         COFINS_ENTRADA_LR,
         COFINS_SAIDA_LR
        FROM
         SPED_PIS_COFINS
        WHERE
         SPED_PIS_COFINS.BARRA = :CODIGOBARRAS
        INTO
         :PIS_ENTRADA,
         :PIS_SAIDA,
         :COFINS_ENTRADA,
         :COFINS_SAIDA;
      END
     IF (:PIS_ENTRADA IS NULL) THEN
         PIS_ENTRADA = '';
     IF (:PIS_SAIDA IS NULL) THEN
         PIS_SAIDA = '';
     IF (:COFINS_ENTRADA IS NULL) THEN
         COFINS_ENTRADA = '';
     IF (:COFINS_SAIDA IS NULL) THEN
         COFINS_SAIDA = '';

     LINHA = :CD_PRODUTO||'|'||:DESCRICAO||'|'||:UNIDADE||'|'||:NCM||'|'||:ALIQUOTA||'|0|'||:CODIGOBARRAS||'|'||:TIPOPRODUTO||'|'||:SITUACAOTRIBUTARIA||'||'||:PIS_ENTRADA||'|'||:PIS_SAIDA||'|'||:COFINS_ENTRADA||'|'||:COFINS_SAIDA||'||';

     SUSPEND;
   END
END ^

ALTER PROCEDURE SP_EXPORTACAO_VENDEDORES AS 
