 UPDATE VENDEDORES SET DT_ALTERACAO = CURRENT_DATE;
END ^

ALTER PROCEDURE SP_EXPORTA_ACODE_VENDA (CD_FILIAL DOUBLE PRECISION,
DATA DATE)
RETURNS (CD_VENDA DOUBLE PRECISION,
HORA TIME,
FORMAPAGAMENTO INTEGER,
NUMEROITENS INTEGER,
CD_VENDEDOR DOUBLE PRECISION)
AS 
declare variable TIPOCARTAO varchar(1);
declare variable TRN varchar(1);
declare variable NUMEROFORMAS integer;
BEGIN
  FOR
   SELECT
     LANCAMENTOS.CD_VENDA,
     COUNT(*)
   FROM
     LANCAMENTOS
   WHERE
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.DATA_LANCAMENTO = :DATA AND
     LANCAMENTOS.TIPO_VENDA = 'V' AND
     LANCAMENTOS.CD_VENDA NOT IN
     (SELECT DISTINCT LANCAMENTOS.CD_VENDA
      FROM LANCAMENTOS
      WHERE LANCAMENTOS.DATA_LANCAMENTO = :DATA AND LANCAMENTOS.TIPO_VENDA = 'D')
   GROUP BY
     LANCAMENTOS.CD_VENDA
   INTO
     :CD_VENDA,
     :NUMEROITENS
  DO
   BEGIN
     SELECT FIRST 1 LANCAMENTOS.HORA FROM LANCAMENTOS WHERE CD_FILIAL = :CD_FILIAL AND CD_VENDA = :CD_VENDA INTO :HORA;
     SELECT FIRST 1 LANCAMENTOS.CD_VENDEDOR FROM LANCAMENTOS WHERE CD_FILIAL = :CD_FILIAL AND CD_VENDA = :CD_VENDA INTO :CD_VENDEDOR;

     SELECT COUNT(*) FROM CAIXA
       WHERE CD_FILIAL = :CD_FILIAL AND CD_VENDA = :CD_VENDA
       INTO :NUMEROFORMAS;

     IF (:NUMEROFORMAS > 1) THEN
        FORMAPAGAMENTO = 0;
     ELSE
      BEGIN
         SELECT CD_FORMA_PAGAMENTO, TIPO_CARTAO, TRN FROM CAIXA WHERE CD_FILIAL = :CD_FILIAL AND CD_VENDA = :CD_VENDA
           INTO :FORMAPAGAMENTO, :TIPOCARTAO, :TRN;
         IF (:FORMAPAGAMENTO = 1) THEN
            FORMAPAGAMENTO = 1;
         IF (:FORMAPAGAMENTO = 6) THEN
            FORMAPAGAMENTO = 2;
         IF (:FORMAPAGAMENTO = 4) THEN
            FORMAPAGAMENTO = 3;
         IF (:FORMAPAGAMENTO = 2) THEN
          BEGIN
            IF (:TIPOCARTAO = 'C') THEN
               FORMAPAGAMENTO = 4;
            ELSE
               FORMAPAGAMENTO = 5;
          END
         IF (:FORMAPAGAMENTO = 3) THEN
            FORMAPAGAMENTO = 6;
         IF (:FORMAPAGAMENTO = 5) THEN
            FORMAPAGAMENTO = 9;
         IF ((:TRN IS NOT NULL) AND (:TRN <> 'N')) THEN
            FORMAPAGAMENTO = 7;
      END

     SUSPEND;
   END
END ^

ALTER PROCEDURE SP_EXPORTA_ACODE_VENDA_ITEM (CD_FILIAL DOUBLE PRECISION,
CD_VENDA DOUBLE PRECISION)
RETURNS (CODIGO_BARRAS VARCHAR(13) CHARACTER SET NONE,
QUANTIDADE DOUBLE PRECISION,
VALORLIQUIDO_UNITARIO NUMERIC(15, 2),
VALORLIQUIDO_TOTAL NUMERIC(15, 2),
VALORBRUTO_UNITARIO NUMERIC(15, 2),
VALORBRUTO_TOTAL NUMERIC(15, 2))
AS 
DECLARE VARIABLE ID_PRODUTO DOUBLE PRECISION;
DECLARE VARIABLE CD_PRODUTO VARCHAR(6);
DECLARE VARIABLE CODIGO_BARRAS_1 VARCHAR(13);
DECLARE VARIABLE CODIGO_BARRAS_2 VARCHAR(13);
DECLARE VARIABLE CODIGO VARCHAR(6);
BEGIN
  FOR
   SELECT
     LANCAMENTOS.ID_PRODUTO,
     LANCAMENTOS.CD_PRODUTO,
     LANCAMENTOS.QUANTIDADE,
     LANCAMENTOS.VALOR / LANCAMENTOS.QUANTIDADE, 
     LANCAMENTOS.VALOR,
     (LANCAMENTOS.VALOR / LANCAMENTOS.QUANTIDADE) + (LANCAMENTOS.DESCONTO) + (LANCAMENTOS.PROMOCAO),
     LANCAMENTOS.VALOR + (LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE) + (LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)
   FROM
     LANCAMENTOS
   WHERE
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.CD_VENDA = :CD_VENDA
   INTO
     :ID_PRODUTO,
     :CODIGO,
     :QUANTIDADE,
     :VALORLIQUIDO_UNITARIO,
     :VALORLIQUIDO_TOTAL,
     :VALORBRUTO_UNITARIO,
     :VALORBRUTO_TOTAL
  DO
   BEGIN
     SELECT CD_PRODUTO, CODIGO_BARRAS_1, CODIGO_BARRAS_2 FROM PRODUTOS
       WHERE ID_PRODUTO = :ID_PRODUTO INTO :CD_PRODUTO, :CODIGO_BARRAS_1, :CODIGO_BARRAS_2;

     IF ((:CODIGO_BARRAS_1 IS NOT NULL) AND (:CODIGO_BARRAS_1 <> '')) THEN
        CODIGO_BARRAS = :CODIGO_BARRAS_1;
     ELSE
     IF ((:CODIGO_BARRAS_2 IS NOT NULL) AND (:CODIGO_BARRAS_2 <> '')) THEN
        CODIGO_BARRAS = :CODIGO_BARRAS_2;
     ELSE
     IF ((:CD_PRODUTO IS NOT NULL) AND (:CD_PRODUTO <> '')) THEN
        CODIGO_BARRAS = :CD_PRODUTO;
     ELSE
        CODIGO_BARRAS = :CODIGO;
     SUSPEND;
   END
END ^

