DT_GERA DATE,
CD_DISTR VARCHAR(4) CHARACTER SET NONE,
QUANTID DOUBLE PRECISION,
ITENS DOUBLE PRECISION,
VALOR DOUBLE PRECISION,
MOTIVO VARCHAR(1) CHARACTER SET NONE,
STATUS VARCHAR(1) CHARACTER SET NONE)
AS 
DECLARE VARIABLE CODIGO DOUBLE PRECISION;
BEGIN
 FOR
   SELECT CD_COMPRAS
   FROM COMPRAS
   WHERE (STATUS = 'E') OR (STATUS = 'M')
   INTO :CODIGO
 DO
  BEGIN
     SELECT
        CAST(CAST(CD_FILIAL AS INTEGER) AS VARCHAR(2)),
        CAST(CAST(CD_COMPRAS AS INTEGER) AS VARCHAR(5)),
        DT_PEDIDO          ,
        CAST(CAST(CD_DISTRIBUIDOR AS INTEGER) AS VARCHAR(5)),
        UNIDADES           ,
        NUMERO_ITENS       ,
        TOTAL_NOTA         ,
        MOTIVO             ,
        STATUS
     FROM  COMPRAS
     WHERE CD_COMPRAS = :CODIGO
     INTO
        :CD_FILIAL          ,
        :NR_PED             ,
        :DT_GERA            ,
        :CD_DISTR           ,
        :QUANTID            ,
        :ITENS              ,
        :VALOR              ,
        :MOTIVO             ,
        :STATUS;
     SUSPEND;
  END
END ^

ALTER PROCEDURE SP_EXPORTA_PRODUTOS_NOVOS RETURNS (CD_PRODUTO VARCHAR(6) CHARACTER SET NONE,
CD_BARRA VARCHAR(13) CHARACTER SET NONE,
GRUPO VARCHAR(4) CHARACTER SET NONE,
SUBGRUPO VARCHAR(2) CHARACTER SET NONE,
TP_PROD VARCHAR(2) CHARACTER SET NONE,
CURVA VARCHAR(1) CHARACTER SET NONE,
PRODUTO VARCHAR(100) CHARACTER SET NONE,
IDENTIF VARCHAR(1) CHARACTER SET NONE,
EMBAL INTEGER,
CU NUMERIC(8, 2),
PV NUMERIC(8, 2),
PVP NUMERIC(8, 2),
ICMS VARCHAR(2) CHARACTER SET NONE,
DT_CADAST DATE,
DT_PRECO DATE,
MARGEM NUMERIC(8, 2),
MARGPP NUMERIC(8, 2),
EST_MIN VARCHAR(1) CHARACTER SET NONE)
AS 
BEGIN
   FOR
     SELECT
            CD_PRODUTO, CODIGO_BARRAS_1,
            CAST(CAST(CD_LABORATORIO AS INTEGER) AS VARCHAR(4)),
            CAST(CAST(CD_GRUPO AS INTEGER) AS VARCHAR(2)),
            TIPO_PRODUTO, CURVA, DESCRICAO, IDENTIFICADOR, QT_EMBALAGEM,
            CUSTO_UNITARIO, PRECO_VENDA, PRECO_PROMOCAO, ICMS, DT_CADASTRO,
            DT_REAJUSTE, MARGEM, MARGEM_PROMOCAO, ENTRA_PEDIDO_ELETRONICO
     FROM  PRODUTOS
     WHERE DT_CADASTRO = CURRENT_DATE
     INTO  :CD_PRODUTO,
           :CD_BARRA  ,
           :GRUPO     ,
           :SUBGRUPO  ,
           :TP_PROD   ,
           :CURVA     ,
           :PRODUTO   ,
           :IDENTIF   ,
           :EMBAL     ,
           :CU        ,
           :PV        ,
           :PVP       ,
           :ICMS      ,
           :DT_CADAST ,
           :DT_PRECO  ,
           :MARGEM    ,
           :MARGPP    ,
           :EST_MIN
   DO
    BEGIN
      SUSPEND;
    END
END ^

ALTER PROCEDURE SP_EXTRATO_CONTA (CONTA DOUBLE PRECISION,
DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (DATA_MOVIMENTO DATE,
HISTORICO VARCHAR(100) CHARACTER SET NONE,
DOCUMENTO VARCHAR(100) CHARACTER SET NONE,
TIPO VARCHAR(1) CHARACTER SET NONE,
VALOR DOUBLE PRECISION)
AS 
DECLARE VARIABLE VALOR_CREDITO DOUBLE PRECISION;
DECLARE VARIABLE VALOR_DEBITO DOUBLE PRECISION;
DECLARE VARIABLE CONTA_CUSTO_VENDA DOUBLE PRECISION;
BEGIN
    SELECT CONTACUSTOVENDA FROM PARAMETROS INTO :CONTA_CUSTO_VENDA;
    IF (:CONTA_CUSTO_VENDA IS NULL) THEN
       CONTA_CUSTO_VENDA = 0;

    SELECT
     SALDO.DATA,
     'SALDO INICIAL',
     '',
     '',
     SALDO.SALDO
    FROM
     SALDO
    WHERE
     CD_CONTA = :CONTA AND
     DATA IN (SELECT MAX(DATA) FROM SALDO WHERE DATA < :DATAINICIAL)
    INTO
     :DATA_MOVIMENTO,
     :HISTORICO,
     :DOCUMENTO,
     :TIPO,
     :VALOR;

    IF (:DATA_MOVIMENTO IS NULL) THEN
     BEGIN
       SELECT
         SUM(VALOR)
       FROM
        MOVIMENTOCAIXA
       WHERE
        CD_PLANO_CONTAS <> :CONTA_CUSTO_VENDA AND
        CD_CONTA = :CONTA AND
        DATA <= :DATAINICIAL AND
        TIPO_MOVIMENTO = 'C'
       INTO
        :VALOR_CREDITO;

       SELECT
         SUM(MOVIMENTOCAIXA.VALOR)
       FROM
        MOVIMENTOCAIXA
       WHERE
        MOVIMENTOCAIXA.CD_PLANO_CONTAS <> :CONTA_CUSTO_VENDA AND
        MOVIMENTOCAIXA.CD_CONTA = :CONTA AND
        MOVIMENTOCAIXA.DATA <= :DATAINICIAL AND
        MOVIMENTOCAIXA.TIPO_MOVIMENTO = 'D'
       INTO
        :VALOR_DEBITO;

       VALOR = :VALOR_CREDITO - :VALOR_DEBITO;
     END


    IF (:DATA_MOVIMENTO IS NULL) THEN
     BEGIN
       DATA_MOVIMENTO = :DATAINICIAL;
       HISTORICO = 'SALDO INICIAL';
       DOCUMENTO = '';
       TIPO = '';
     END

    SUSPEND;
    
    FOR
        SELECT
         MOVIMENTOCAIXA.DATA,
         MOVIMENTOCAIXA.HISTORICO,
         MOVIMENTOCAIXA.DOCUMENTO,
         MOVIMENTOCAIXA.TIPO_MOVIMENTO,
         MOVIMENTOCAIXA.VALOR
        FROM
         MOVIMENTOCAIXA
        WHERE
         MOVIMENTOCAIXA.CD_PLANO_CONTAS <> :CONTA_CUSTO_VENDA AND
         MOVIMENTOCAIXA.DATA >= :DATAINICIAL AND
         MOVIMENTOCAIXA.DATA <= :DATAFINAL AND
         MOVIMENTOCAIXA.CD_CONTA = :CONTA
        ORDER BY
         MOVIMENTOCAIXA.DATA
        INTO
         :DATA_MOVIMENTO,
         :HISTORICO,
         :DOCUMENTO,
         :TIPO,
         :VALOR
    DO
     BEGIN
       IF (:TIPO = 'D') THEN
        BEGIN
          VALOR = :VALOR * -1;
        END
       SUSPEND;
     END
    
    SELECT
     SALDO.DATA,
     'SALDO FINAL',
     '',
     '',
     SALDO.SALDO
    FROM
     SALDO
    WHERE
     CD_CONTA = :CONTA AND
     DATA = :DATAFINAL /*IN (SELECT MAX(DATA) FROM SALDO WHERE CD_CONTA = :CONTA)*/
    INTO
     :DATA_MOVIMENTO,
     :HISTORICO,
     :DOCUMENTO,
     :TIPO,
     :VALOR;

     SUSPEND;
END ^

ALTER PROCEDURE SP_FATURA_ANALITICO_LANCAMENTO (DATA_INICIAL DATE,
DATA_FINAL DATE,
CONVENIO DOUBLE PRECISION,
STATUS VARCHAR(1) CHARACTER SET NONE)
RETURNS (PRODUTO VARCHAR(100) CHARACTER SET NONE,
NOME VARCHAR(100) CHARACTER SET NONE,
NOME_1 VARCHAR(100) CHARACTER SET NONE,
CD_VENDA DOUBLE PRECISION,
CD_FILIAL DOUBLE PRECISION,
CD_CLIENTE DOUBLE PRECISION,
DATA_LANCAMENTO DATE,
QUANTIDADE DOUBLE PRECISION,
TRN VARCHAR(1) CHARACTER SET NONE,
AUTORIZACAOTRN VARCHAR(100) CHARACTER SET NONE,
VALOR_BRUTO DOUBLE PRECISION,
DESCONTO DOUBLE PRECISION,
MATRICULA VARCHAR(100) CHARACTER SET NONE,
TOTAL DOUBLE PRECISION,
NUMERO DOUBLE PRECISION)
AS 
declare variable NREGISTROS integer;
BEGIN
 FOR
  SELECT 
    LANCAMENTOS.DESCRICAO, 
    FILIAIS.NOME,
    CLIENTES.NOME, 
    LANCAMENTOS.CD_VENDA,
    LANCAMENTOS.CD_FILIAL, 
    LANCAMENTOS.CD_CLIENTE, 
    LANCAMENTOS.DATA_LANCAMENTO, 
    LANCAMENTOS.QUANTIDADE,
    LANCAMENTOS.TRN, 
    LANCAMENTOS.AUTORIZACAOTRN, 
    CASE
     WHEN LANCAMENTOS.TIPO_VENDA = 'V' THEN SUM((((LANCAMENTOS.VALOR / LANCAMENTOS.QUANTIDADE) - LANCAMENTOS.ARREDONDAMENTO) + LANCAMENTOS.DESCONTO) * LANCAMENTOS.QUANTIDADE)
     WHEN LANCAMENTOS.TIPO_VENDA = 'D' THEN SUM(((((LANCAMENTOS.VALOR / LANCAMENTOS.QUANTIDADE) - LANCAMENTOS.ARREDONDAMENTO) + LANCAMENTOS.DESCONTO) * LANCAMENTOS.QUANTIDADE)) * -1
    END,
    CASE
      WHEN LANCAMENTOS.TIPO_VENDA = 'V' THEN SUM(LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)
      WHEN LANCAMENTOS.TIPO_VENDA = 'D' THEN SUM(LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE) * -1
    END,
    CLIENTES.MATRICULA, 
    CASE
       WHEN LANCAMENTOS.SUBSIDIOTRN IS NOT NULL AND LANCAMENTOS.SUBSIDIOTRN > 0 THEN SUM(LANCAMENTOS.SUBSIDIOTRN)
       WHEN LANCAMENTOS.SUBSIDIOTRN IS NULL OR LANCAMENTOS.SUBSIDIOTRN = 0 THEN
          CASE
             WHEN LANCAMENTOS.TIPO_VENDA = 'V' THEN SUM((LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO))
             WHEN LANCAMENTOS.TIPO_VENDA = 'D' THEN SUM((LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO)) * -1
          END
    END,
    LANCAMENTOS.NUMERO 
  FROM LANCAMENTOS, CLIENTES, FILIAIS, CONTAS_RECEBER 
  WHERE 
    CONTAS_RECEBER.DT_LANCAMENTO >= :DATA_INICIAL AND
    CONTAS_RECEBER.DT_LANCAMENTO <= :DATA_FINAL AND
    CONTAS_RECEBER.CD_CONVENIO = :CONVENIO AND
    CONTAS_RECEBER.CD_FORMA_PAGAMENTO = 3 AND 
    CONTAS_RECEBER.STATUS LIKE :STATUS AND 
    CONTAS_RECEBER.STATUS <> 'C' AND
    CONTAS_RECEBER.CD_FILIAL = FILIAIS.CD_FILIAL AND
    LANCAMENTOS.CD_VENDA = CONTAS_RECEBER.CD_VENDA AND
    LANCAMENTOS.CD_CONVENIO = CONTAS_RECEBER.CD_CONVENIO AND
    (LANCAMENTOS.TIPO_VENDA =  'V' OR LANCAMENTOS.TIPO_VENDA =  'D') AND
    CLIENTES.CD_CLIENTE = LANCAMENTOS.CD_CLIENTE AND
    FILIAIS.STATUS =  'A'
  GROUP BY
    LANCAMENTOS.DESCRICAO, 
    FILIAIS.NOME,
    CLIENTES.NOME, 
    LANCAMENTOS.CD_VENDA,
    LANCAMENTOS.CD_FILIAL, 
    LANCAMENTOS.CD_CLIENTE, 
    LANCAMENTOS.DATA_LANCAMENTO, 
    LANCAMENTOS.QUANTIDADE, 
    LANCAMENTOS.TRN, 
    LANCAMENTOS.AUTORIZACAOTRN, 
    LANCAMENTOS.TIPO_VENDA,
    CLIENTES.MATRICULA,
    LANCAMENTOS.SUBSIDIOTRN,
    LANCAMENTOS.NUMERO,
    LANCAMENTOS.VALOR,
    LANCAMENTOS.ARREDONDAMENTO,
    LANCAMENTOS.DESCONTO
  INTO
   :PRODUTO,
   :NOME,
   :NOME_1,
   :CD_VENDA,
   :CD_FILIAL,
   :CD_CLIENTE,
   :DATA_LANCAMENTO,
   :QUANTIDADE,
   :TRN,
   :AUTORIZACAOTRN,
   :VALOR_BRUTO,
   :DESCONTO,
   :MATRICULA,
   :TOTAL,
   :NUMERO
 DO
  BEGIN
       NREGISTROS = 0;
       SELECT COUNT(CONTAS_RECEBER.CD_CONTAS_RECEBER)
       FROM  CONTAS_RECEBER
       WHERE CONTAS_RECEBER.DT_LANCAMENTO >= :DATA_INICIAL AND
             CONTAS_RECEBER.DT_LANCAMENTO <= :DATA_FINAL AND
             CONTAS_RECEBER.CD_FILIAL = :CD_FILIAL AND
             CONTAS_RECEBER.CD_VENDA = :CD_VENDA
       INTO :NREGISTROS;

       IF (:NREGISTROS > 1) THEN
        BEGIN
          VALOR_BRUTO = :VALOR_BRUTO / :NREGISTROS;
          DESCONTO = :DESCONTO / :NREGISTROS;
          TOTAL = :TOTAL / :NREGISTROS;
        END

       SUSPEND;
  END
END ^

