ALTER PROCEDURE SP_FECHAMENTO_CONVENIO (CD_CONVENIO DOUBLE PRECISION)
AS 
BEGIN
  IF ((:CD_CONVENIO IS NOT NULL) AND (:CD_CONVENIO > 0)) THEN
   BEGIN
     UPDATE CLIENTES SET
      SALDO = 0
     WHERE CD_CONVENIO = :CD_CONVENIO;

     UPDATE CONVENIOS SET
      FATURAFECHADA = 'S'
     WHERE CD_CONVENIO = :CD_CONVENIO;
   END
END ^

ALTER PROCEDURE SP_FECHAMENTO_MES AS 
DECLARE VARIABLE FILIAL DOUBLE PRECISION;
DECLARE VARIABLE FIL VARCHAR(20);
DECLARE VARIABLE GRUPO DOUBLE PRECISION;
DECLARE VARIABLE GRU VARCHAR(20);
DECLARE VARIABLE LABORATORIO DOUBLE PRECISION;
DECLARE VARIABLE LAB VARCHAR(40);
DECLARE VARIABLE VENDEDOR DOUBLE PRECISION;
DECLARE VARIABLE VENDED VARCHAR(40);
DECLARE VARIABLE DATA DATE;
DECLARE VARIABLE QUANTIDADE DOUBLE PRECISION;
DECLARE VARIABLE DESCONTO DOUBLE PRECISION;
DECLARE VARIABLE PROMOCAO DOUBLE PRECISION;
DECLARE VARIABLE VALOR DOUBLE PRECISION;
DECLARE VARIABLE COMISSAO DOUBLE PRECISION;
DECLARE VARIABLE CUSTO DOUBLE PRECISION;
DECLARE VARIABLE CUPONS DOUBLE PRECISION;
BEGIN

   DELETE FROM FECHAMENTO  WHERE DATA >= CURRENT_DATE - 1000;

   FOR
     SELECT
      LANCAMENTOS.CD_FILIAL,
      FILIAIS.NOME,
      LANCAMENTOS.CD_GRUPO,
      GRUPOS.DESCRICAO,
      LANCAMENTOS.CD_LABORATORIO,
      LABORATORIOS.NOME,
      LANCAMENTOS.CD_VENDEDOR,
      VENDEDORES.NOME,
      LANCAMENTOS.DATA_LANCAMENTO,
      SUM(LANCAMENTOS.QUANTIDADE),
      SUM(LANCAMENTOS.DESCONTO),
      SUM(LANCAMENTOS.PROMOCAO),
      SUM(LANCAMENTOS.VALOR),
      SUM((LANCAMENTOS.VALOR * GRUPOS.TX_COMISSAO) / 100),
      SUM(LANCAMENTOS.QUANTIDADE * LANCAMENTOS.CUSTO_UNITARIO),
      COUNT(DISTINCT LANCAMENTOS.CD_VENDA)
     FROM
      LANCAMENTOS,
      FILIAIS,
      GRUPOS,
      LABORATORIOS,
      VENDEDORES
     WHERE
      LANCAMENTOS.CD_FILIAL = FILIAIS.CD_FILIAL AND
      LANCAMENTOS.CD_GRUPO = GRUPOS.CD_GRUPO AND
      LANCAMENTOS.CD_LABORATORIO = LABORATORIOS.CD_LABORATORIO AND
      LANCAMENTOS.CD_VENDEDOR = VENDEDORES.CD_VENDEDOR AND
      VENDEDORES.CD_FILIAL = FILIAIS.CD_FILIAL AND
      ((LANCAMENTOS.TIPO_VENDA = 'V') OR
      (LANCAMENTOS.TIPO_VENDA = 'D' AND LANCAMENTOS.TROCA = 'T')) AND
      LANCAMENTOS.DATA_LANCAMENTO >= CURRENT_DATE - 1000
     GROUP BY
      LANCAMENTOS.CD_FILIAL,
      FILIAIS.NOME,
      LANCAMENTOS.CD_GRUPO,
      GRUPOS.DESCRICAO,
      LANCAMENTOS.CD_LABORATORIO,
      LABORATORIOS.NOME,
      LANCAMENTOS.CD_VENDEDOR,
      VENDEDORES.NOME,
      LANCAMENTOS.DATA_LANCAMENTO
     INTO
      :FILIAL,
      :FIL,
      :GRUPO,
      :GRU,
      :LABORATORIO,
      :LAB,
      :VENDEDOR,
      :VENDED,
      :DATA,
      :QUANTIDADE,
      :DESCONTO,
      :PROMOCAO,
      :VALOR,
      :COMISSAO,
      :CUSTO,
      :CUPONS
   DO
    BEGIN
          INSERT INTO FECHAMENTO VALUES (:FILIAL, :FIL, :GRUPO, :GRU,
                                         :LABORATORIO, :LAB, :VENDEDOR, :VENDED,
                                         :DATA, :QUANTIDADE, :VALOR, :DESCONTO,
                                         :PROMOCAO, :COMISSAO, :CUSTO, :CUPONS);
    END
END ^

ALTER PROCEDURE SP_FILTRA_PRODUTO_COMPRA (CD_COMPRAS DOUBLE PRECISION,
CD_FILIAL DOUBLE PRECISION,
CD_GRUPOCOMPRA VARCHAR(10) CHARACTER SET NONE,
CLASSES BLOB CHARACTER SET NONE,
GRUPOS BLOB CHARACTER SET NONE,
LABORATORIOS BLOB CHARACTER SET NONE,
DIAS INTEGER,
CONSIDERAPEDIDOSGERADOS VARCHAR(1) CHARACTER SET NONE,
QUANTIDADEPEDIDO INTEGER,
COMPRASCONSIDERADAS BLOB CHARACTER SET NONE,
DICIONARIODISTRIBUIDORA VARCHAR(1) CHARACTER SET NONE,
CD_DISTRIBUIDOR DOUBLE PRECISION,
TODOSPRODUTOS VARCHAR(1) CHARACTER SET NONE)
AS 
declare variable ID_PRODUTO double precision;
declare variable CD_PRODUTO varchar(6);
declare variable DESCRICAO varchar(100);
declare variable PRECO_VENDA double precision;
declare variable CD_GRUPO double precision;
declare variable CD_LABORATORIO double precision;
declare variable QT_EMBALAGEM double precision;
declare variable PRECO_PROMOCAO double precision;
declare variable MARGEM double precision;
declare variable CODIGO_BARRAS_1 varchar(14);
declare variable ICMS varchar(2);
declare variable SITUACAOTRIBUTARIA varchar(3);
declare variable UNIDADE varchar(2);
declare variable CUSTO_UNITARIO double precision;
declare variable ESTOQUE double precision;
declare variable ESTOQUE_MINIMO double precision;
declare variable ESTOQUE_MAXIMO double precision;
declare variable CURVA varchar(1);
declare variable MEDIAF double precision;
declare variable LABORATORIO varchar(100);
declare variable GRUPO varchar(100);
declare variable VL_UNITARIO double precision;
declare variable VL_TOTAL double precision;
declare variable QUANTIDADE double precision;
declare variable COMANDO blob sub_type 1 segment size 80;
declare variable NCLASSE varchar(10);
declare variable NGRUPO varchar(10);
declare variable NLABORATORIO varchar(10);
declare variable FILTROCLASSE blob sub_type 1 segment size 80;
declare variable FILTROGRUPO blob sub_type 1 segment size 80;
declare variable FILTROLABORATORIO blob sub_type 1 segment size 80;
declare variable EXISTE integer;
declare variable COMANDO1 blob sub_type 1 segment size 80;
declare variable QT_EMBALAGEM_DISTRIBUIDORA double precision;
BEGIN
   FILTROGRUPO = '';
   FILTROLABORATORIO = '';
   COMANDO = 'SELECT ' ||
     'PRODUTOS.ID_PRODUTO, PRODUTOS.CD_PRODUTO, PRODUTOS.DESCRICAO, PRODUTOS.PRECO_VENDA, ' ||
     'PRODUTOS.CD_GRUPO, PRODUTOS.CD_LABORATORIO, PRODUTOS.QT_EMBALAGEM, PRODUTOS.PRECO_PROMOCAO, PRODUTOS.MARGEM, ' ||
     'PRODUTOS.CODIGO_BARRAS_1, PRODUTOS.ICMS, PRODUTOS.SITUACAOTRIBUTARIA, PRODUTOS.UNIDADE, ' ||
     'PRODUTOS.CUSTO_UNITARIO_'||CAST(:CD_FILIAL AS INTEGER)|| ', ' ||
     'PRODUTOS.ESTOQUE_'||CAST(:CD_FILIAL AS INTEGER)|| ', ' ||
     'PRODUTOS.ESTOQUE_MINIMO_'||CAST(:CD_FILIAL AS INTEGER)|| ', ' ||
     'PRODUTOS.ESTOQUE_MAXIMO_'||CAST(:CD_FILIAL AS INTEGER)|| ', ' ||
     'PRODUTOS.CURVA_UNITARIA_'||CAST(:CD_FILIAL AS INTEGER)|| ', ' ||
     'PRODUTOS.MEDIAF_'||CAST(:CD_FILIAL AS INTEGER)|| ' FROM PRODUTOS';

  IF (:CD_GRUPOCOMPRA <> '') THEN
     COMANDO = :COMANDO || ' WHERE CD_GRUPOCOMPRA = ' || :CD_GRUPOCOMPRA;

  IF (:CLASSES <> '') THEN
   BEGIN
      FILTROCLASSE = '';
      WHILE (POSITION(',', :CLASSES) > 0) DO
       BEGIN
         NCLASSE = SUBSTRING(:CLASSES FROM 1 FOR POSITION(',', :CLASSES) - 1);
         IF (:FILTROCLASSE <> '') THEN
            FILTROCLASSE = :FILTROCLASSE || ' OR CD_CLASSE = ' || :NCLASSE;
         ELSE
            FILTROCLASSE = :FILTROCLASSE || ' CD_CLASSE = ' || :NCLASSE;
         CLASSES = SUBSTRING(:CLASSES FROM POSITION(',', :CLASSES) + 1 FOR 10000);
       END
      IF (TRIM(:FILTROCLASSE) <> '') THEN
         FILTROCLASSE = :FILTROCLASSE || ' OR CD_CLASSE = ' || :CLASSES;
      ELSE
         FILTROCLASSE = ' CD_CLASSE = ' || :CLASSES;
   END


  IF (:GRUPOS <> '') THEN
   BEGIN
      FILTROGRUPO = '';
      WHILE (POSITION(',', :GRUPOS) > 0) DO
       BEGIN
         NGRUPO = SUBSTRING(:GRUPOS FROM 1 FOR POSITION(',', :GRUPOS) - 1);
         IF (:FILTROGRUPO <> '') THEN
            FILTROGRUPO = :FILTROGRUPO || ' OR CD_GRUPO = ' || :NGRUPO;
         ELSE
            FILTROGRUPO = :FILTROGRUPO || ' CD_GRUPO = ' || :NGRUPO;
         GRUPOS = SUBSTRING(:GRUPOS FROM POSITION(',', :GRUPOS) + 1 FOR 10000);
       END
      IF (TRIM(:FILTROGRUPO) <> '') THEN
         FILTROGRUPO = :FILTROGRUPO || ' OR CD_GRUPO = ' || :GRUPOS;
      ELSE
         FILTROGRUPO = ' CD_GRUPO = ' || :GRUPOS;
   END

  IF (:LABORATORIOS <> '') THEN
   BEGIN
      FILTROLABORATORIO = '';
      WHILE (POSITION(',', :LABORATORIOS) > 0) DO
       BEGIN
         NLABORATORIO = SUBSTRING(:LABORATORIOS FROM 1 FOR POSITION(',', :LABORATORIOS) - 1);
         IF (:FILTROLABORATORIO <> '') THEN
            FILTROLABORATORIO = :FILTROLABORATORIO || ' OR CD_LABORATORIO = ' || :NLABORATORIO;
         ELSE
            FILTROLABORATORIO = :FILTROLABORATORIO || ' CD_LABORATORIO = ' || :NLABORATORIO;
         LABORATORIOS = SUBSTRING(:LABORATORIOS FROM POSITION(',', :LABORATORIOS) + 1 FOR 10000);
       END
      IF (TRIM(:FILTROLABORATORIO) <> '') THEN
         FILTROLABORATORIO = :FILTROLABORATORIO || ' OR CD_LABORATORIO = ' || :LABORATORIOS;
      ELSE
         FILTROLABORATORIO = ' CD_LABORATORIO = ' || :LABORATORIOS;
   END

  IF (:FILTROCLASSE <> '') THEN
   BEGIN
     IF (POSITION('WHERE', :COMANDO) = 0) THEN
        COMANDO = :COMANDO || ' WHERE ('||:FILTROCLASSE||' )';
     ELSE
        COMANDO = :COMANDO || 'AND ('||:FILTROCLASSE||' )';
   END

  IF (:FILTROGRUPO <> '') THEN
   BEGIN
     IF (POSITION('WHERE', :COMANDO) = 0) THEN
        COMANDO = :COMANDO || ' WHERE ('||:FILTROGRUPO||' )';
     ELSE
        COMANDO = :COMANDO || 'AND ('||:FILTROGRUPO||' )';
   END

  IF (:FILTROLABORATORIO <> '') THEN
   BEGIN
     IF (POSITION('WHERE', :COMANDO) = 0) THEN
        COMANDO = :COMANDO || ' WHERE ('||:FILTROLABORATORIO||' )';
     ELSE
        COMANDO = :COMANDO || ' AND ('||:FILTROLABORATORIO||' )';
   END

  IF (POSITION('WHERE', :COMANDO) = 0) THEN
     COMANDO = :COMANDO || ' WHERE (STATUS = '''||'A'||''' )';
  ELSE
     COMANDO = :COMANDO || ' AND (STATUS = '''||'A'||''' )';

  IF (:TODOSPRODUTOS = 'N') THEN
   BEGIN
     IF (POSITION('WHERE', :COMANDO) = 0) THEN
        COMANDO = :COMANDO || ' WHERE (ENTRA_PEDIDO_ELETRONICO = '''||'S'||''' )';
     ELSE
        COMANDO = :COMANDO || ' AND (ENTRA_PEDIDO_ELETRONICO = '''||'S'||''' )';
   END

  FOR
   EXECUTE STATEMENT :COMANDO INTO
     :ID_PRODUTO, :CD_PRODUTO, :DESCRICAO, :PRECO_VENDA, :CD_GRUPO, :CD_LABORATORIO, :QT_EMBALAGEM, :PRECO_PROMOCAO, :MARGEM,
     :CODIGO_BARRAS_1, :ICMS, :SITUACAOTRIBUTARIA, :UNIDADE,
     :CUSTO_UNITARIO, :ESTOQUE, :ESTOQUE_MINIMO, :ESTOQUE_MAXIMO, :CURVA, :MEDIAF
  DO
   BEGIN
     EXISTE = 0;

     IF ((:CONSIDERAPEDIDOSGERADOS = 'S') AND (:COMPRASCONSIDERADAS <> '')) THEN
      BEGIN
        COMANDO1 = 'SELECT COUNT(DISTINCT ID_PRODUTO) FROM ITENS_COMPRA WHERE ';
        COMANDO1 = :COMANDO1 || ' ID_PRODUTO = ' || :ID_PRODUTO || ' AND ' || :COMPRASCONSIDERADAS;
        EXECUTE STATEMENT :COMANDO1 INTO :EXISTE;
      END

     IF (:EXISTE = 0) THEN
      BEGIN
         SELECT DESCRICAO FROM GRUPOS WHERE CD_GRUPO = :CD_GRUPO INTO :GRUPO;
         SELECT NOME FROM LABORATORIOS WHERE CD_LABORATORIO = :CD_LABORATORIO INTO :LABORATORIO;
    
         QUANTIDADE = 0;

         IF (:DICIONARIODISTRIBUIDORA = 'S') THEN
          BEGIN
            SELECT QT_EMBALAGEM FROM PROD_DISTR WHERE CD_DISTRIBUIDOR = :CD_DISTRIBUIDOR AND ID_PRODUTO = :ID_PRODUTO INTO :QT_EMBALAGEM_DISTRIBUIDORA;
            IF (:QT_EMBALAGEM_DISTRIBUIDORA IS NOT NULL) THEN
               QT_EMBALAGEM = :QT_EMBALAGEM_DISTRIBUIDORA;
          END
    
         IF ((:QT_EMBALAGEM IS NULL) OR (:QT_EMBALAGEM = 0)) THEN
            QT_EMBALAGEM = :QUANTIDADEPEDIDO;

         VL_UNITARIO = :CUSTO_UNITARIO * QT_EMBALAGEM;

         IF (:DIAS > 0) THEN
          BEGIN
            IF (:ESTOQUE > 0) THEN
               QUANTIDADE = ROUND((((:MEDIAF * :DIAS) / 30) - :ESTOQUE) / :QT_EMBALAGEM);
            ELSE
               QUANTIDADE = ROUND((((:MEDIAF * :DIAS) / 30) / :QT_EMBALAGEM));
          END
         ELSE
          BEGIN
            IF ((:ESTOQUE <= 0) AND (:ESTOQUE_MAXIMO <= 0) AND (:ESTOQUE_MINIMO <= 0)) THEN
             BEGIN
               QUANTIDADE = 0;
             END
            ELSE
            IF (:ESTOQUE <= 0) THEN
             BEGIN
               IF (:ESTOQUE_MAXIMO < :QT_EMBALAGEM) THEN
                  QUANTIDADE = 1;
               ELSE
                  QUANTIDADE = ROUND((:ESTOQUE_MAXIMO / :QT_EMBALAGEM), 0);
             END
            ELSE
             BEGIN
               QUANTIDADE = ROUND(((:ESTOQUE_MAXIMO - :ESTOQUE) / :QT_EMBALAGEM));
             END
          END
    
         IF ((:QUANTIDADE IS NULL) OR (:QUANTIDADE < 0)) THEN
            QUANTIDADE = 0;

         VL_TOTAL = :VL_UNITARIO * :QUANTIDADE;

         INSERT INTO ITENS_COMPRA(
              CD_COMPRAS,
              ID_PRODUTO,
              CD_PRODUTO,
              CD_FILIAL,
              CD_FILIAL_DESTINO,
              DESCRICAO,
              SALDO,
              ESTOQUE_MINIMO,
              ESTOQUE_MAXIMO,
              MEDIAF,
              CURVA,
              LABORATORIO,
              GRUPO,
              QUANTIDADE,
              VL_UNITARIO,
              VL_TOTAL,
              PERCENTUAL_MARGEM,
              CD_ATENDIMENTO,
              NOVO_PRECO,
              PRECO_VENDA,
              QT_EMBALAGEM,
              ULTIMOCUSTO,
              CODIGO_BARRAS,
              UNIDADE,
              ICMS,
              SITUACAOTRIBITARIA,
              PRECO_PROMOCAO_ATUAL,
              PRECO_PROMOCAO
           )
         VALUES(
            :CD_COMPRAS,
            :ID_PRODUTO,
            :CD_PRODUTO,
            :CD_FILIAL,
            :CD_FILIAL,
            :DESCRICAO,
            :ESTOQUE,
            :ESTOQUE_MINIMO,
            :ESTOQUE_MAXIMO,
            :MEDIAF,
            :CURVA,
            :LABORATORIO,
            :GRUPO,
            :QUANTIDADE,
            :VL_UNITARIO,
            :VL_TOTAL,
            :MARGEM,
            'M',
            :PRECO_VENDA,
            :PRECO_VENDA,
            :QT_EMBALAGEM,
            :CUSTO_UNITARIO,
            :CODIGO_BARRAS_1,
            :UNIDADE,
            :ICMS,
            :SITUACAOTRIBUTARIA,
            :PRECO_PROMOCAO,
            :PRECO_PROMOCAO
           );
      END
   END
END ^

ALTER PROCEDURE SP_GERAXMLMOVIMENTO (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (DATA DATE,
VENDA DOUBLE PRECISION,
QUANTIDADEVENDA DOUBLE PRECISION,
DESCONTOVENDA DOUBLE PRECISION,
COMPRA DOUBLE PRECISION,
QUANTIDADECOMPRA DOUBLE PRECISION,
DESCONTOCOMPRA DOUBLE PRECISION,
COMPRADEEMERGENCIA DOUBLE PRECISION,
QUANTIDADEEMERGENCIA DOUBLE PRECISION,
CODIGO VARCHAR(14) CHARACTER SET NONE,
ESTOQUEATUAL DOUBLE PRECISION)
AS 
declare variable PRODUTO double precision;
declare variable COMANDO varchar(100);
declare variable FILIAL integer;
BEGIN
 SELECT CD_FILIAL FROM PARAMETROS INTO :FILIAL;
 FOR
  SELECT
   LANCAMENTOS.ID_PRODUTO,
   LANCAMENTOS.DATA_LANCAMENTO
  FROM
   LANCAMENTOS
  WHERE
   LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
   LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
   ((LANCAMENTOS.TIPO_VENDA = 'V') OR (LANCAMENTOS.TIPO_VENDA = 'C') OR (LANCAMENTOS.TIPO_VENDA = 'M'))
  GROUP BY
   LANCAMENTOS.ID_PRODUTO,
   LANCAMENTOS.DATA_LANCAMENTO
  ORDER BY
   LANCAMENTOS.DATA_LANCAMENTO
  INTO
   :PRODUTO,
   :DATA
 DO
  BEGIN
    SELECT
     SUM(LANCAMENTOS.VALOR + (LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)),
     SUM(LANCAMENTOS.QUANTIDADE),
     SUM(LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)
    FROM
     LANCAMENTOS
    WHERE
     LANCAMENTOS.DATA_LANCAMENTO = :DATA AND
     LANCAMENTOS.ID_PRODUTO = :PRODUTO AND
     LANCAMENTOS.TIPO_VENDA = 'V'
    INTO
     :VENDA,
     :QUANTIDADEVENDA,
     :DESCONTOVENDA;

    SELECT
     SUM(LANCAMENTOS.VALOR),
     SUM(LANCAMENTOS.QUANTIDADE),
     SUM(LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)
    FROM
     LANCAMENTOS
    WHERE
     LANCAMENTOS.DATA_LANCAMENTO = :DATA AND
     LANCAMENTOS.ID_PRODUTO = :PRODUTO AND
     LANCAMENTOS.TIPO_VENDA = 'C'
    INTO
     :COMPRA,
     :QUANTIDADECOMPRA,
     :DESCONTOCOMPRA;

    SELECT
     SUM(LANCAMENTOS.VALOR),
     SUM(LANCAMENTOS.QUANTIDADE)
    FROM
     LANCAMENTOS
    WHERE
     LANCAMENTOS.DATA_LANCAMENTO = :DATA AND
     LANCAMENTOS.ID_PRODUTO = :PRODUTO AND
     LANCAMENTOS.TIPO_VENDA = 'M'
    INTO
     :COMPRADEEMERGENCIA,
     :QUANTIDADEEMERGENCIA;

    COMANDO = 'SELECT CODIGO_BARRAS_1, ESTOQUE_'||:FILIAL||' FROM PRODUTOS WHERE ID_PRODUTO = '||:PRODUTO;
    EXECUTE STATEMENT :COMANDO INTO :CODIGO, :ESTOQUEATUAL;

    IF (:VENDA IS NULL) THEN
       VENDA = 0;
    IF (:QUANTIDADEVENDA IS NULL) THEN
       QUANTIDADEVENDA = 0;
    IF (:DESCONTOVENDA IS NULL) THEN
       DESCONTOVENDA = 0;
    IF (:COMPRA IS NULL) THEN
       COMPRA = 0;
    IF (:QUANTIDADECOMPRA IS NULL) THEN
       QUANTIDADECOMPRA = 0;
    IF (:DESCONTOCOMPRA IS NULL) THEN
       DESCONTOCOMPRA = 0;
    IF (:COMPRADEEMERGENCIA IS NULL) THEN
       COMPRADEEMERGENCIA = 0;
    IF (:QUANTIDADEEMERGENCIA IS NULL) THEN
       QUANTIDADEEMERGENCIA = 0;

    SUSPEND;
  END
END ^

ALTER PROCEDURE SP_GERA_BALANCO_DIFERENCA AS 
declare variable ID_BALANCO double precision;
declare variable CD_FILIAL double precision;
declare variable ID_PRODUTO double precision;
declare variable CD_PRODUTO varchar(6);
declare variable CODIGO_BARRAS_1 varchar(14);
declare variable CODIGO_BARRAS_2 varchar(14);
declare variable DESCRICAO varchar(100);
declare variable CD_GRUPO double precision;
declare variable GRUPO varchar(100);
declare variable CD_LABORATORIO double precision;
declare variable LABORATORIO varchar(100);
declare variable CD_CLASSE double precision;
declare variable CLASSE varchar(100);
declare variable CUSTO_UNITARIO double precision;
declare variable PRECO_VENDA double precision;
declare variable PRECO_VENDA_ANTERIOR double precision;
declare variable ESTOQUE_ANTERIOR double precision;
declare variable CD_SUBGRUPO double precision;
BEGIN
   SELECT VALOR FROM CONTROLE WHERE CAMPO = 'ID_BALANCO' INTO :ID_BALANCO;
   ID_BALANCO = :ID_BALANCO + 1;
   UPDATE CONTROLE SET VALOR = :ID_BALANCO WHERE CAMPO = 'ID_BALANCO';
   FOR
     SELECT
       BALANCO.CD_FILIAL,
       BALANCO.ID_PRODUTO,
       BALANCO.CD_PRODUTO,
       BALANCO.CODIGO_BARRAS_1,
       BALANCO.CODIGO_BARRAS_2,
       BALANCO.DESCRICAO,
       BALANCO.CD_GRUPO,
       BALANCO.GRUPO,
       BALANCO.CD_LABORATORIO,
       BALANCO.LABORATORIO,
       BALANCO.CD_CLASSE,
       BALANCO.CLASSE,
       BALANCO.CUSTO_UNITARIO,
       BALANCO.PRECO_VENDA,
       BALANCO.PRECO_VENDA_ANTERIOR,
       BALANCO.ESTOQUE_ANTERIOR,
       BALANCO.CD_SUBGRUPO
     FROM
       BALANCO
     WHERE
       CD_FILIAL = :CD_FILIAL AND
       ID_BALANCO = :ID_BALANCO AND
       ESTOQUE <> ESTOQUE_ANTERIOR
     INTO
       :CD_FILIAL,
       :ID_PRODUTO,
       :CD_PRODUTO,
       :CODIGO_BARRAS_1,
       :CODIGO_BARRAS_2,
       :DESCRICAO,
       :CD_GRUPO,
       :GRUPO,
       :CD_LABORATORIO,
       :LABORATORIO,
       :CD_CLASSE,
       :CLASSE,
       :CUSTO_UNITARIO,
       :PRECO_VENDA,
       :PRECO_VENDA_ANTERIOR,
       :ESTOQUE_ANTERIOR,
       :CD_SUBGRUPO
   DO
   BEGIN
    INSERT INTO BALANCO VALUES (:ID_BALANCO, NULL, CURRENT_DATE, CURRENT_TIME, NULL, NULL, NULL, NULL, NULL, NULL,
                                :CD_FILIAL,  :ID_PRODUTO, :CD_PRODUTO,  :CODIGO_BARRAS_1, :CODIGO_BARRAS_2,
                                :DESCRICAO, :CD_GRUPO, :GRUPO, :CD_LABORATORIO, :LABORATORIO, :CD_CLASSE, :CLASSE,
                                :CUSTO_UNITARIO, :PRECO_VENDA, :PRECO_VENDA_ANTERIOR, 0, :ESTOQUE_ANTERIOR,
                                'S', 'G', '', :CD_SUBGRUPO, NULL, NULL);
   END
END ^

ALTER PROCEDURE SP_GERA_MOVIMENTOCAIXAITENS (CD_MOVIMENTO_CAIXA DOUBLE PRECISION,
USUARIO VARCHAR(100) CHARACTER SET NONE,
DATA VARCHAR(1) CHARACTER SET NONE,
DATAINICIAL VARCHAR(10) CHARACTER SET NONE,
DATAFINAL VARCHAR(10) CHARACTER SET NONE,
CONVENIO INTEGER)
AS 
DECLARE VARIABLE CD_FILIAL DOUBLE PRECISION;
DECLARE VARIABLE CD_CONVENIO DOUBLE PRECISION;
DECLARE VARIABLE CD_CLIENTE DOUBLE PRECISION;
DECLARE VARIABLE CD_VENDA DOUBLE PRECISION;
DECLARE VARIABLE DATA_LANCAMENTO DATE;
DECLARE VARIABLE DATA_VENCIMENTO DATE;
DECLARE VARIABLE VALOR DOUBLE PRECISION;
DECLARE VARIABLE SALDO DOUBLE PRECISION;
DECLARE VARIABLE COMANDO VARCHAR(1000);
BEGIN
  IF (:DATA = 'L') THEN
   BEGIN
     COMANDO = 'SELECT CD_FILIAL, CD_CONVENIO, CD_CLIENTE, CD_VENDA, DT_LANCAMENTO, DT_VENCIMENTO,'||
               'VALOR, VL_SALDO FROM CONTAS_RECEBER WHERE DT_LANCAMENTO >= ''' || :DATAINICIAL || ''' AND '||
               'DT_LANCAMENTO <= ''' || :DATAFINAL || ''' AND CD_CONVENIO = ' || :CONVENIO || ' AND ' ||
               'CD_FORMA_PAGAMENTO = 3 AND STATUS = ''' || 'A' ||'''';
   END
  ELSE
   BEGIN
     COMANDO = 'SELECT CD_FILIAL, CD_CONVENIO, CD_CLIENTE, CD_VENDA, DT_LANCAMENTO, DT_VENCIMENTO,'||
               'VALOR, VL_SALDO FROM CONTAS_RECEBER WHERE DT_VENCIMENTO >= ''' || :DATAINICIAL || ''' AND '||
               'DT_VENCIMENTO <= ''' || :DATAFINAL || ''' AND CD_CONVENIO = ' || :CONVENIO || ' AND ' ||
               'CD_FORMA_PAGAMENTO = 3 AND STATUS = ''' || 'A' ||'''';
   END
  FOR
    EXECUTE STATEMENT :COMANDO
    INTO :CD_FILIAL, :CD_CONVENIO, :CD_CLIENTE, :CD_VENDA, :DATA_LANCAMENTO,
         :DATA_VENCIMENTO, :VALOR, :SALDO
  DO
   BEGIN
     INSERT INTO MOVIMENTOCAIXAITENS VALUES (:CD_MOVIMENTO_CAIXA,:CD_FILIAL, :CD_CONVENIO, :CD_CLIENTE, :CD_VENDA,
                                             :DATA_LANCAMENTO, :DATA_VENCIMENTO, CURRENT_DATE, CURRENT_TIME, :VALOR, :SALDO, :USUARIO);
   END
END ^

ALTER PROCEDURE SP_GERA_TOTALNOTA_COMPRAS (DATAINICIAL DATE,
DATAFINAL DATE)
AS 
DECLARE VARIABLE CD_COMPRAS DOUBLE PRECISION;
DECLARE VARIABLE CD_FILIAL DOUBLE PRECISION;
BEGIN
  FOR
   SELECT
    CD_COMPRAS,
    CD_FILIAL
   FROM
    COMPRAS
   WHERE
    DT_PEDIDO >= :DATAINICIAL AND
    DT_PEDIDO <= :DATAFINAL
   INTO
    :CD_COMPRAS,
    :CD_FILIAL
  DO
   BEGIN
     UPDATE COMPRAS SET
      TOTAL_NOTA = (SELECT SUM(QUANTIDADE * VL_UNITARIO) FROM ITENS_COMPRA WHERE CD_COMPRAS = :CD_COMPRAS AND CD_FILIAL = :CD_FILIAL)
     WHERE CD_COMPRAS = :CD_COMPRAS AND CD_FILIAL = :CD_FILIAL;
   END
END ^

ALTER PROCEDURE SP_GML (CD_FILIAL DOUBLE PRECISION)
