ALTER PROCEDURE SP_GRAFICO_COTA_COMPRAS (FILIAL DOUBLE PRECISION,
DATAINI DATE,
DATAFIM DATE)
RETURNS (DIA INTEGER,
COTADIARIA DOUBLE PRECISION,
COMPRA DOUBLE PRECISION)
AS 
DECLARE VARIABLE DATA DATE;
DECLARE VARIABLE DIASUTEIS INTEGER;
BEGIN
   SELECT
    COTASCOMPRAS.DIASUTEIS,
    SUM(COTASCOMPRAS.COTA)
   FROM
    COTASCOMPRAS
   WHERE
    COTASCOMPRAS.MES = EXTRACT(MONTH FROM :DATAINI) AND
    COTASCOMPRAS.ANO = EXTRACT(YEAR FROM :DATAFIM) AND
    COTASCOMPRAS.CD_FILIAL = :FILIAL
   GROUP BY
    COTASCOMPRAS.DIASUTEIS
   INTO
    :DIASUTEIS,
    :COTADIARIA;

   COTADIARIA = :COTADIARIA / :DIASUTEIS;

   FOR
     SELECT
      DISTINCT LANCAMENTOS.DATA_LANCAMENTO
     FROM
      LANCAMENTOS
     WHERE
      LANCAMENTOS.DATA_LANCAMENTO >= :DATAINI AND
      LANCAMENTOS.DATA_LANCAMENTO <= :DATAFIM AND
      LANCAMENTOS.TIPO_VENDA = 'C' AND
      LANCAMENTOS.CD_FILIAL = :FILIAL
     INTO
      :DATA
   DO
    BEGIN
       COMPRA = 0;

       SELECT
        SUM(LANCAMENTOS.VALOR)
       FROM
        LANCAMENTOS
       WHERE
        LANCAMENTOS.DATA_LANCAMENTO = :DATA AND
        LANCAMENTOS.TIPO_VENDA = 'C' AND
        LANCAMENTOS.CD_FILIAL = :FILIAL
       INTO
        :COMPRA;

       IF (:COMPRA IS NULL) THEN
          COMPRA = 0;
       DIA = EXTRACT(DAY FROM :DATA);
       SUSPEND;
    END
END ^

ALTER PROCEDURE SP_GRAFICO_META_CONSOL_REDE (DATAINI DATE,
DATAFIM DATE)
RETURNS (DIA INTEGER,
METADIARIA DOUBLE PRECISION,
VENDA DOUBLE PRECISION,
QUANTIDADE DOUBLE PRECISION,
CLIENTES DOUBLE PRECISION,
TICKET DOUBLE PRECISION,
CUSTO DOUBLE PRECISION,
DESCONTO DOUBLE PRECISION,
LUCRO DOUBLE PRECISION)
AS 
declare variable DATA date;
declare variable VENDACANCELADA double precision;
declare variable QUANTIDADECANCELADA double precision;
declare variable CLIENTESCANCELADA double precision;
declare variable CUSTOCANCELADO double precision;
declare variable DESCONTOCANCELADO double precision;
declare variable VENDABRUTA double precision;
declare variable VENDABRUTACANCELADA double precision;
BEGIN
   SELECT
    SUM(METAS_FILIAIS.METAVALOR / METAS_FILIAIS.DIASUTEIS)
   FROM
    METAS_FILIAIS
   WHERE
    METAS_FILIAIS.MESREF = EXTRACT(MONTH FROM :DATAINI) AND
    METAS_FILIAIS.ANOREF = EXTRACT(YEAR FROM :DATAFIM)
   INTO
    :METADIARIA;

   FOR
     SELECT
      DISTINCT LANCAMENTOS.DATA_LANCAMENTO
     FROM
      LANCAMENTOS
     WHERE
      LANCAMENTOS.DATA_LANCAMENTO >= :DATAINI AND
      LANCAMENTOS.DATA_LANCAMENTO <= :DATAFIM AND
      (LANCAMENTOS.TIPO_VENDA = 'V' OR LANCAMENTOS.TIPO_VENDA = 'D')
     INTO
      :DATA
   DO
    BEGIN
       VENDA = 0;
       QUANTIDADE = 0;
       CLIENTES = 0;
       TICKET = 0;

       SELECT
        SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
        SUM(LANCAMENTOS.VALOR + LANCAMENTOS.DESCONTO + LANCAMENTOS.PROMOCAO - LANCAMENTOS.ARREDONDAMENTO),
        SUM(LANCAMENTOS.QUANTIDADE),
        SUM(LANCAMENTOS.CUSTO_UNITARIO * LANCAMENTOS.QUANTIDADE),
        SUM((LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE) + (LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)),
        COUNT(DISTINCT LANCAMENTOS.CD_VENDA)
       FROM
        LANCAMENTOS
       WHERE
        LANCAMENTOS.DATA_LANCAMENTO = :DATA AND
        LANCAMENTOS.TIPO_VENDA = 'V' AND
        LANCAMENTOS.CUSTO_UNITARIO > 0
       INTO
        :VENDA,
        :VENDABRUTA,
        :QUANTIDADE,
        :CUSTO,
        :DESCONTO,
        :CLIENTES;

       IF (:VENDA IS NULL) THEN
          VENDA = 0;
       IF (:QUANTIDADE IS NULL) THEN
          QUANTIDADE = 0;
       IF (:CUSTO IS NULL) THEN
          CUSTO = 0;
       IF (:DESCONTO IS NULL) THEN
          DESCONTO = 0;
       IF (:CLIENTES IS NULL) THEN
          CLIENTES = 0;

       SELECT
        SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
        SUM(LANCAMENTOS.VALOR + LANCAMENTOS.DESCONTO + LANCAMENTOS.PROMOCAO - LANCAMENTOS.ARREDONDAMENTO),
        SUM(LANCAMENTOS.QUANTIDADE),
        SUM(LANCAMENTOS.CUSTO_UNITARIO * LANCAMENTOS.QUANTIDADE),
        SUM((LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE) + (LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)),
        COUNT(DISTINCT LANCAMENTOS.CD_VENDA)
       FROM
        LANCAMENTOS
       WHERE
        LANCAMENTOS.DATA_LANCAMENTO = :DATA AND
        LANCAMENTOS.TIPO_VENDA = 'D' AND
        LANCAMENTOS.CUSTO_UNITARIO > 0
       INTO
        :VENDACANCELADA,
        :VENDABRUTACANCELADA,
        :QUANTIDADECANCELADA,
        :CUSTOCANCELADO,
        :DESCONTOCANCELADO,
        :CLIENTESCANCELADA;

       IF (:VENDACANCELADA IS NULL) THEN
          VENDACANCELADA = 0;
       IF (:VENDABRUTACANCELADA IS NULL) THEN
          VENDABRUTACANCELADA = 0;
       IF (:QUANTIDADECANCELADA IS NULL) THEN
          QUANTIDADECANCELADA = 0;
       IF (:CUSTOCANCELADO IS NULL) THEN
          CUSTOCANCELADO = 0;
       IF (:DESCONTOCANCELADO IS NULL) THEN
          DESCONTOCANCELADO = 0;
       IF (:CLIENTESCANCELADA IS NULL) THEN
          CLIENTESCANCELADA = 0;

       DIA = EXTRACT(DAY FROM :DATA);
       VENDA = :VENDA - :VENDACANCELADA;
       VENDABRUTA = :VENDABRUTA - :VENDABRUTACANCELADA;
       QUANTIDADE = :QUANTIDADE - :QUANTIDADECANCELADA;
       CUSTO = :CUSTO - :CUSTOCANCELADO;
       DESCONTO = :DESCONTO - :DESCONTOCANCELADO;
       IF ((:VENDA IS NULL) OR (:VENDA = 0)) THEN
          LUCRO = 0;
       ELSE
          LUCRO = ((:VENDA - :CUSTO) / :VENDA) * 100;
       IF ((:DESCONTO IS NULL) OR (:DESCONTO = 0)) THEN
          DESCONTO = 0;
       ELSE
          DESCONTO = (:DESCONTO / :VENDABRUTA) * 100;
       CLIENTES = :CLIENTES - :CLIENTESCANCELADA;
       IF (:CLIENTES > 0) THEN
          TICKET = :VENDA / :CLIENTES;

       SUSPEND;
    END
END ^

ALTER PROCEDURE SP_GRAFICO_META_FILIAL (CD_FILIAL DOUBLE PRECISION,
DATAINI DATE,
DATAFIM DATE)
RETURNS (DIA INTEGER,
DATA DATE,
VENDA DOUBLE PRECISION,
METADIARIA DOUBLE PRECISION,
QUANTIDADE DOUBLE PRECISION,
