ALTER PROCEDURE SP_IGUALA_SITE_FILIAL (CD_FILIAL INTEGER)
AS 
declare variable ID_PRODUTO double precision;
declare variable PRECO_VENDA numeric(15,2);
declare variable PRECO_PROMOCAO numeric(15,2);
declare variable PRECO_VENDA_LOJA numeric(15,2);
declare variable PRECO_PROMOCAO_LOJA numeric(15,2);
declare variable COMANDO varchar(1000);
declare variable CODIGO_BARRAS_1 varchar(14);
declare variable CODIGO_BARRAS_2 varchar(14);
declare variable TIPO_LOJA varchar(1);
BEGIN
  SELECT TIPO_LOJA FROM PARAMETROS INTO :TIPO_LOJA;
  FOR
    SELECT ID_PRODUTO FROM PRODUTOS_SITE INTO :ID_PRODUTO
  DO
   BEGIN
     COMANDO = '';
     COMANDO = 'SELECT PRECO_VENDA, PRECO_PROMOCAO, PRECO_VENDA_'||:CD_FILIAL||', PRECO_PROMOCAO_'||:CD_FILIAL||' FROM PRODUTOS WHERE ID_PRODUTO = '||:ID_PRODUTO;
     EXECUTE STATEMENT :COMANDO INTO :PRECO_VENDA, :PRECO_PROMOCAO,  :PRECO_VENDA_LOJA, :PRECO_PROMOCAO_LOJA;

     IF (:TIPO_LOJA = 'U') THEN
      BEGIN
        PRECO_VENDA_LOJA = :PRECO_VENDA;
        PRECO_PROMOCAO_LOJA = :PRECO_PROMOCAO;
      END

     IF (:PRECO_VENDA_LOJA IS NULL) THEN
       PRECO_VENDA_LOJA = 0;
     IF (:PRECO_PROMOCAO_LOJA IS NULL) THEN
       PRECO_PROMOCAO_LOJA = 0;

     COMANDO = '';
     COMANDO = 'UPDATE PRODUTOS_SITE SET PMC = ' || :PRECO_VENDA;

     IF (:PRECO_VENDA_LOJA > 0) THEN
      BEGIN
        COMANDO = :COMANDO || ' ,PRECO_VENDA_LOJA = ' || :PRECO_VENDA_LOJA;
      END

     IF (:PRECO_PROMOCAO_LOJA > 0) THEN
      BEGIN
        IF (:PRECO_VENDA_LOJA > 0) THEN
         BEGIN
           COMANDO = :COMANDO || ' ,PRECO_VENDA_SITE = ' || :PRECO_PROMOCAO_LOJA;
         END
        ELSE
         BEGIN
           COMANDO = :COMANDO || ' PRECO_VENDA_SITE = ' || :PRECO_PROMOCAO_LOJA;
         END
      END
     ELSE
      BEGIN
        IF (:PRECO_VENDA_LOJA > 0) THEN
         BEGIN
           COMANDO = :COMANDO || ' ,PRECO_VENDA_SITE = ' || :PRECO_VENDA_LOJA;
         END
        ELSE
         BEGIN
           COMANDO = :COMANDO || ' PRECO_VENDA_SITE = ' || :PRECO_VENDA_LOJA;
         END
      END

     IF ((:PRECO_VENDA_LOJA > 0) AND (:PRECO_PROMOCAO_LOJA > 0)) THEN
      BEGIN
        COMANDO = :COMANDO || ' ,DESCONTOAPLICADO = 100 - ((' || :PRECO_PROMOCAO_LOJA || ' / ' || :PRECO_VENDA_LOJA || ') * 100)';
      END
     ELSE
      BEGIN
        COMANDO = :COMANDO || ' ,DESCONTOAPLICADO = 0';
      END

     COMANDO = :COMANDO || ' WHERE ID_PRODUTO = ' || :ID_PRODUTO;

     EXECUTE STATEMENT :COMANDO;
   END
END ^

ALTER PROCEDURE SP_IMPORTA_QTD_PRODUTO_PRODDIST (CD_DISTRIBUIDOR DOUBLE PRECISION)
AS 
declare variable ID_PRODUTO double precision;
BEGIN
  FOR
    SELECT
      ID_PRODUTO
    FROM
      PROD_DISTR
    WHERE
      CD_DISTRIBUIDOR = :CD_DISTRIBUIDOR /*AND
      (QT_EMBALAGEM IS NULL OR QT_EMBALAGEM = 0)*/
    INTO
      :ID_PRODUTO
  DO
   BEGIN
     UPDATE PROD_DISTR SET
       PROD_DISTR.QT_EMBALAGEM = (SELECT QT_EMBALAGEM FROM PRODUTOS WHERE ID_PRODUTO = :ID_PRODUTO)
     WHERE
       CD_DISTRIBUIDOR = :CD_DISTRIBUIDOR AND ID_PRODUTO = :ID_PRODUTO;
   END
END ^

ALTER PROCEDURE SP_INCLUI_60I_TEMP_ITENS_TEMP AS 
DECLARE VARIABLE CD_FILIAL INTEGER;
DECLARE VARIABLE REF_PRODUTOS VARCHAR(14);
DECLARE VARIABLE BASECALCULO_ICMS NUMERIC(15,2);
DECLARE VARIABLE DATAHORA TIMESTAMP;
BEGIN
