    SELECT CD_FILIAL, REF_PRODUTOS, BASECALCULO_ICMS, DATAHORA
    FROM SINTEGRA_R60I_TEMP
    INTO :CD_FILIAL, :REF_PRODUTOS, :BASECALCULO_ICMS, :DATAHORA
  DO
   BEGIN
     INSERT INTO SINTEGRA_PEDIDOS_ITENS_TEMP (CD_FILIAL, REF_PRODUTOS, BASE_ICMS_SUBST, DATAHORA) VALUES
     (:CD_FILIAL, :REF_PRODUTOS, :BASECALCULO_ICMS, :DATAHORA);
   END

END ^

ALTER PROCEDURE SP_INCLUI_DADOS_R60I_TEMP (CD_FILIAL DOUBLE PRECISION,
DATAINICIAL DATE,
DATAFINAL DATE)
AS 
DECLARE VARIABLE DATA_LANCAMENTO DATE;
DECLARE VARIABLE NUMERO DOUBLE PRECISION;
DECLARE VARIABLE ID_PRODUTO DOUBLE PRECISION;
DECLARE VARIABLE QUANTIDADE DOUBLE PRECISION;
DECLARE VARIABLE VALOR DOUBLE PRECISION;
DECLARE VARIABLE CD_VENDA DOUBLE PRECISION;
BEGIN
  FOR
    SELECT
     DATA_LANCAMENTO,
     NUMERO,
     ID_PRODUTO,
     QUANTIDADE,
     VALOR,
     CD_VENDA
    FROM
     LANCAMENTOS
    WHERE
     CD_FILIAL = :CD_FILIAL AND
     DATA_LANCAMENTO >= :DATAINICIAL AND
     DATA_LANCAMENTO <= :DATAFINAL AND
     TIPO_VENDA = 'V'
    INTO
     :DATA_LANCAMENTO,
     :NUMERO,
     :ID_PRODUTO,
     :QUANTIDADE,
     :VALOR,
     :CD_VENDA
  DO
   BEGIN
    IF ((:NUMERO IS NULL) OR (:NUMERO = '0')) THEN
       NUMERO = :CD_VENDA;
    INSERT INTO SINTEGRA_R60I_TEMP (DATAHORA, COO, ID_PRODUTO, QUANTIDADE, VALOR_MERCADORIA) VALUES
    (:DATA_LANCAMENTO, :NUMERO, :ID_PRODUTO, :QUANTIDADE, :VALOR);
   END
END ^

ALTER PROCEDURE SP_INCLUI_DADOS_R60I_TEMP_TERM (CD_FILIAL DOUBLE PRECISION,
DATAINICIAL DATE,
DATAFINAL DATE,
TERMINAL INTEGER)
AS 
DECLARE VARIABLE DATA_LANCAMENTO DATE;
DECLARE VARIABLE NUMERO DOUBLE PRECISION;
DECLARE VARIABLE ID_PRODUTO DOUBLE PRECISION;
DECLARE VARIABLE QUANTIDADE DOUBLE PRECISION;
