   BEGIN
    IF ((:NUMERO IS NULL) OR (:NUMERO = 0)) THEN
       NUMERO = :CD_VENDA;
    INSERT INTO SINTEGRA_R60I_TEMP (DATAHORA, COO, ID_PRODUTO, QUANTIDADE, VALOR_MERCADORIA) VALUES
    (:DATA_LANCAMENTO, :NUMERO, :ID_PRODUTO, :QUANTIDADE, :VALOR);
   END
END ^

ALTER PROCEDURE SP_INCLUI_GRUPOS_CURVAS (CD_GRUPO DOUBLE PRECISION)
AS 
declare variable CD_FILIAL double precision;
declare variable GRUPO varchar(100);
declare variable CD_CURVA double precision;
declare variable CURVA varchar(100);
declare variable SIGLA varchar(1);
declare variable EXISTE integer;
BEGIN
  SELECT DESCRICAO FROM GRUPOS WHERE CD_GRUPO = :CD_GRUPO INTO :GRUPO;
  FOR
   SELECT
    CD_FILIAL
   FROM
    FILIAIS
   INTO
    :CD_FILIAL
  DO
   BEGIN
      FOR
       SELECT
        CD_CURVA,
        DESCRICAO,
        SIGLA
       FROM
        CURVAS
       INTO
        :CD_CURVA,
        :CURVA,
        :SIGLA
      DO
       BEGIN
         SELECT COUNT(*) FROM GRUPOS_CURVAS
         WHERE CD_FILIAL = :CD_FILIAL AND CD_GRUPO = :CD_GRUPO AND CD_CURVA = :CD_CURVA
         INTO :EXISTE;

         IF (:EXISTE = 0) THEN
            INSERT INTO GRUPOS_CURVAS VALUES (:CD_FILIAL, :CD_GRUPO, :GRUPO, :CD_CURVA,  :CURVA, :SIGLA, 10, 5, 0.5, 0.5, 0.5, 0.5,CURRENT_DATE);
       END
   END
END ^

