ALTER PROCEDURE SP_INCLUI_PRODUTO_PEDIDOGESTAO (CD_COMPRAS_VINCULADO DOUBLE PRECISION,
ID_PRODUTO DOUBLE PRECISION)
AS 
declare variable CD_PRODUTO varchar(6);
declare variable DESCRICAO varchar(100);
declare variable PRECO_VENDA double precision;
declare variable CD_GRUPO double precision;
declare variable CD_LABORATORIO double precision;
declare variable QT_EMBALAGEM double precision;
declare variable PRECO_PROMOCAO double precision;
declare variable MARGEM double precision;
declare variable CODIGO_BARRAS_1 varchar(14);
declare variable ICMS varchar(2);
declare variable SITUACAOTRIBUTARIA varchar(3);
declare variable UNIDADE varchar(2);
declare variable CUSTO_UNITARIO double precision;
declare variable ESTOQUE double precision;
declare variable ESTOQUE_MINIMO double precision;
declare variable ESTOQUE_MAXIMO double precision;
declare variable CURVA varchar(1);
declare variable MEDIAF double precision;
declare variable LABORATORIO varchar(100);
declare variable GRUPO varchar(100);
declare variable VL_UNITARIO double precision;
declare variable VL_TOTAL double precision;
declare variable QUANTIDADE double precision;
declare variable COMANDO varchar(1000);
declare variable COMANDO1 varchar(1000);
declare variable EXISTE integer;
declare variable AUXILIAR varchar(1000);
declare variable CD_DISTRIBUIDOR double precision;
declare variable DATA date;
declare variable PARAMETRO varchar(1000);
declare variable NOME varchar(1000);
declare variable CD_COMPRAS double precision;
declare variable CD_FILIAL double precision;
BEGIN
   AUXILIAR = 'SELECT DISTINCT DATA, PARAMETRO, NOME FROM TPG'||CAST(:CD_COMPRAS_VINCULADO AS INTEGER);
   EXECUTE STATEMENT :AUXILIAR INTO :DATA, :PARAMETRO, :NOME;

   AUXILIAR = 'SELECT CD_COMPRAS, CD_FILIAL, CD_DISTRIBUIDOR FROM COMPRAS WHERE CD_COMPRAS_VINCULADO = '|| CAST(:CD_COMPRAS_VINCULADO AS INTEGER);
   FOR
     EXECUTE STATEMENT :AUXILIAR INTO :CD_COMPRAS, :CD_FILIAL, :CD_DISTRIBUIDOR
   DO
    BEGIN

       COMANDO = '';
       COMANDO = 'SELECT ' ||
         'PRODUTOS.CD_PRODUTO, PRODUTOS.DESCRICAO, PRODUTOS.PRECO_VENDA, ' ||
         'PRODUTOS.CD_GRUPO, PRODUTOS.CD_LABORATORIO, PRODUTOS.QT_EMBALAGEM, PRODUTOS.PRECO_PROMOCAO, PRODUTOS.MARGEM, ' ||
         'PRODUTOS.CODIGO_BARRAS_1, PRODUTOS.ICMS, PRODUTOS.SITUACAOTRIBUTARIA, PRODUTOS.UNIDADE, ' ||
         'PRODUTOS.CUSTO_UNITARIO_'||CAST(:CD_FILIAL AS INTEGER)|| ', ' ||
         'PRODUTOS.ESTOQUE_'||CAST(:CD_FILIAL AS INTEGER)|| ', ' ||
         'PRODUTOS.ESTOQUE_MINIMO_'||CAST(:CD_FILIAL AS INTEGER)|| ', ' ||
         'PRODUTOS.ESTOQUE_MAXIMO_'||CAST(:CD_FILIAL AS INTEGER)|| ', ' ||
         'PRODUTOS.CURVA_UNITARIA_'||CAST(:CD_FILIAL AS INTEGER)|| ', ' ||
         'PRODUTOS.MEDIAF_'||CAST(:CD_FILIAL AS INTEGER)|| ' FROM PRODUTOS ' ||
         'WHERE ID_PRODUTO = '||CAST(:ID_PRODUTO AS INTEGER);
    
       EXECUTE STATEMENT :COMANDO INTO
         :CD_PRODUTO, :DESCRICAO, :PRECO_VENDA, :CD_GRUPO, :CD_LABORATORIO, :QT_EMBALAGEM, :PRECO_PROMOCAO, :MARGEM,
         :CODIGO_BARRAS_1, :ICMS, :SITUACAOTRIBUTARIA, :UNIDADE,
         :CUSTO_UNITARIO, :ESTOQUE, :ESTOQUE_MINIMO, :ESTOQUE_MAXIMO, :CURVA, :MEDIAF;
    
       SELECT DESCRICAO FROM GRUPOS WHERE CD_GRUPO = :CD_GRUPO INTO :GRUPO;
       SELECT NOME FROM LABORATORIOS WHERE CD_LABORATORIO = :CD_LABORATORIO INTO :LABORATORIO;

       VL_UNITARIO = :CUSTO_UNITARIO * QT_EMBALAGEM;
       VL_TOTAL = :VL_UNITARIO * :ESTOQUE;
       QUANTIDADE = 0;
       IF ((:QT_EMBALAGEM IS NULL) OR (:QT_EMBALAGEM = 0)) THEN
          QT_EMBALAGEM = 1;
  
       IF (:ESTOQUE <= 0) THEN
          QUANTIDADE = ROUND( (:ESTOQUE_MAXIMO / :QT_EMBALAGEM), 0);
       ELSE
          QUANTIDADE = ROUND( ((:ESTOQUE_MAXIMO / :QT_EMBALAGEM) - (:ESTOQUE / :QT_EMBALAGEM)), 0);
  
       IF (:QUANTIDADE < 0) THEN
           QUANTIDADE = 0;
  
       INSERT INTO ITENS_COMPRA(
           CD_COMPRAS, ID_PRODUTO, CD_PRODUTO, CD_FILIAL, CD_FILIAL_DESTINO, DESCRICAO, SALDO, ESTOQUE_MINIMO, ESTOQUE_MAXIMO, MEDIAF,
           CURVA, LABORATORIO, GRUPO, QUANTIDADE, VL_UNITARIO, VL_TOTAL, PERCENTUAL_MARGEM, CD_ATENDIMENTO, NOVO_PRECO, PRECO_VENDA,
           QT_EMBALAGEM, ULTIMOCUSTO, CODIGO_BARRAS, UNIDADE, ICMS, SITUACAOTRIBITARIA, PRECO_PROMOCAO_ATUAL, PRECO_PROMOCAO
         )
       VALUES(
          :CD_COMPRAS, :ID_PRODUTO, :CD_PRODUTO, :CD_FILIAL, :CD_FILIAL, :DESCRICAO, :ESTOQUE, :ESTOQUE_MINIMO, :ESTOQUE_MAXIMO, :MEDIAF,
          :CURVA, :LABORATORIO, :GRUPO, :QUANTIDADE, :VL_UNITARIO, :VL_TOTAL, :MARGEM, 'M', :PRECO_VENDA, :PRECO_VENDA,
          :QT_EMBALAGEM, :CUSTO_UNITARIO, :CODIGO_BARRAS_1, :UNIDADE, :ICMS, :SITUACAOTRIBUTARIA, :PRECO_PROMOCAO, :PRECO_PROMOCAO
         );
  
       COMANDO1 = 'SELECT COUNT(*) FROM TPG'||CAST(:CD_COMPRAS_VINCULADO AS INTEGER)||' WHERE ID_PRODUTO = '||CAST(:ID_PRODUTO AS INTEGER);
       EXECUTE STATEMENT :COMANDO1 INTO :EXISTE;
       IF (:EXISTE = 0) THEN
        BEGIN
          COMANDO1 = 'INSERT INTO TPG'||CAST(:CD_COMPRAS_VINCULADO AS INTEGER)||
                     '(CD_COMPRAS, CD_DISTRIBUIDOR, ID_PRODUTO, CD_PRODUTO, DESCRICAO, CODIGO_BARRAS, PRECO_VENDA, VL_UNITARIO, QUANTIDADE_TOTAL, VL_TOTAL, F'||CAST(:CD_FILIAL AS INTEGER)||', DATA, PARAMETRO, NOME, MEDIAF_'||CAST(:CD_FILIAL AS INTEGER)||', ESTOQUE_'||CAST(:CD_FILIAL AS INTEGER)||', MENORMINIMO_'||CAST(:CD_FILIAL AS INTEGER)||')'||
                     ' VALUES ('||
                     CAST(:CD_COMPRAS_VINCULADO AS INTEGER)||', '||
                     CAST(:CD_DISTRIBUIDOR AS INTEGER)||', '||
                     CAST(:ID_PRODUTO AS INTEGER)||', '||
                     ''''||:CD_PRODUTO||''', '||
                     ''''||:DESCRICAO||''', '||
                     ''''||:CODIGO_BARRAS_1||''', '||
                     :PRECO_VENDA||', '||
                     :VL_UNITARIO||', '||
                     :QUANTIDADE||', '||
                     :VL_TOTAL||', '||
                     :QUANTIDADE||', '||
                     ''''||:DATA||''', '||
                     ''''||:PARAMETRO||''', '||
                     ''''||:NOME||''', '||
                     :MEDIAF||', '||
                     :ESTOQUE;
          IF (:ESTOQUE < :ESTOQUE_MINIMO) THEN
             COMANDO1 = :COMANDO1 || ', ''1'')';
          ELSE
          IF (:ESTOQUE > :ESTOQUE_MAXIMO) THEN
             COMANDO1 = :COMANDO1 || ', ''2'')';
          ELSE
             COMANDO1 = :COMANDO1 || ', ''0'')';

          EXECUTE STATEMENT :COMANDO1;
        END
       ELSE
        BEGIN
          COMANDO1 = 'UPDATE TPG'||CAST(:CD_COMPRAS_VINCULADO AS INTEGER)||
                     ' SET QUANTIDADE_TOTAL = '||:QUANTIDADE||', VL_TOTAL = '||:VL_TOTAL||', F'||CAST(:CD_FILIAL AS INTEGER)||' = '||:QUANTIDADE||', '||
                     ' ESTOQUE_'||CAST(:CD_FILIAL AS INTEGER)||' = '||:ESTOQUE||', MEDIAF_'||CAST(:CD_FILIAL AS INTEGER)||' = '||:MEDIAF;
          IF (:ESTOQUE < :ESTOQUE_MINIMO) THEN
             COMANDO1 = :COMANDO1 || ', MENORMINIMO_'||CAST(:CD_FILIAL AS INTEGER)||' = ''1''';
          ELSE
          IF (:ESTOQUE > :ESTOQUE_MAXIMO) THEN
             COMANDO1 = :COMANDO1 || ', MENORMINIMO_'||CAST(:CD_FILIAL AS INTEGER)||' = ''2''';
          ELSE
             COMANDO1 = :COMANDO1 || ', MENORMINIMO_'||CAST(:CD_FILIAL AS INTEGER)||' = ''0''';

          COMANDO1 = :COMANDO1||' WHERE ID_PRODUTO = '||CAST(:ID_PRODUTO AS INTEGER);
          EXECUTE STATEMENT :COMANDO1;
        END

    END
END ^

