   END
END ^

ALTER PROCEDURE SP_INCONSISTENCIA_PKS AS 
DECLARE VARIABLE COMANDO VARCHAR(3000);
DECLARE VARIABLE COMANDO2 VARCHAR(3000);
DECLARE VARIABLE PK VARCHAR(50);
DECLARE VARIABLE CAMPO VARCHAR(50);
DECLARE VARIABLE CAMPO1 VARCHAR(50);
DECLARE VARIABLE CAMPO2 VARCHAR(50);
DECLARE VARIABLE CAMPO3 VARCHAR(50);
DECLARE VARIABLE CAMPOS VARCHAR(200);
DECLARE VARIABLE VHAVING VARCHAR(200);
DECLARE VARIABLE NOME_TABELA VARCHAR(30);
DECLARE VARIABLE VALOR1 DOUBLE PRECISION;
DECLARE VARIABLE VALOR2 DOUBLE PRECISION;
DECLARE VARIABLE VALOR3 DOUBLE PRECISION;
BEGIN
  FOR
    SELECT RDB$INDEX_NAME, SUBSTRING(RDB$INDEX_NAME FROM 4 FOR 30) FROM RDB$INDEX_SEGMENTS
    WHERE RDB$INDEX_NAME LIKE 'PK_%' AND SUBSTRING(RDB$INDEX_NAME FROM 4 FOR 30) <> 'CONTROLE'
    ORDER BY RDB$INDEX_NAME
    INTO :PK, :NOME_TABELA
  DO
   BEGIN
     CAMPO1 = ''; CAMPO2 = ''; CAMPO3 = '';
     FOR
       SELECT RDB$FIELD_NAME FROM RDB$INDEX_SEGMENTS
       WHERE  RDB$INDEX_NAME = :PK
       ORDER BY RDB$FIELD_POSITION
       INTO :CAMPO
     DO
      BEGIN
        IF (:CAMPO1 = '') THEN
           CAMPO1 = :CAMPO;
        ELSE
        IF (:CAMPO2 = '') THEN
           CAMPO2 = :CAMPO;
        ELSE
           CAMPO3 = :CAMPO;
      END
     CAMPOS = :CAMPO1;
     VHAVING = :CAMPO1;
     IF (:CAMPO2 <> '') THEN
      BEGIN
        CAMPOS = :CAMPOS || ',' || :CAMPO2;
        VHAVING = :VHAVING || '||' || :CAMPO2;
      END
     IF (:CAMPO3 <> '') THEN
      BEGIN
        CAMPOS = :CAMPOS || ',' || :CAMPO3;
        VHAVING = :VHAVING || '||' || :CAMPO3;
      END
     COMANDO = 'SELECT ' || :CAMPOS || ' FROM ' || :NOME_TABELA || 'GROUP BY ' || :CAMPOS || ' HAVING COUNT(' || VHAVING || ') > 1';
     COMANDO2 = 'DELETE FROM ' || :NOME_TABELA || ' WHERE ' || :VHAVING || ' IN ' ||
                '(SELECT ' || VHAVING || ' FROM ' || :NOME_TABELA || 'GROUP BY ' || :CAMPOS || ' HAVING COUNT(' || VHAVING || ') > 1)';
     IF ((:CAMPO2 <> '') AND (:CAMPO3 <> '')) THEN
      BEGIN
         FOR EXECUTE STATEMENT :COMANDO INTO :VALOR1, :VALOR2, :VALOR3 DO
          BEGIN
            EXECUTE STATEMENT :COMANDO2;
            BREAK;
          END
      END
     ELSE
     IF (:CAMPO2 <> '') THEN
      BEGIN
         FOR EXECUTE STATEMENT :COMANDO INTO :VALOR1, :VALOR2 DO
          BEGIN
            EXECUTE STATEMENT :COMANDO2;
            BREAK;
          END
      END
     ELSE
      BEGIN
         FOR EXECUTE STATEMENT :COMANDO INTO :VALOR1 DO
          BEGIN
            EXECUTE STATEMENT :COMANDO2;
            BREAK;
          END
      END
   END
END ^

