ALTER PROCEDURE SP_INICIA_BANCO_DADOS_2 AS 
declare variable DIAS integer;
BEGIN
  SELECT CURRENT_DATE - MAX(DATA_CAIXA) FROM CAIXA INTO :DIAS;
  IF (DIAS > 0) THEN
    BEGIN
      UPDATE CAIXA SET CAIXA.DATA_CAIXA = CAIXA.DATA_CAIXA + :DIAS, CAIXA.DATA_VENCIMENTO = CAIXA.DATA_VENCIMENTO + :DIAS, CAIXA.DATA = CAIXA.DATA + :DIAS;
      UPDATE LANCAMENTOS SET LANCAMENTOS.DATA_LANCAMENTO = LANCAMENTOS.DATA_LANCAMENTO + :DIAS, LANCAMENTOS.DATA_CAIXA = LANCAMENTOS.DATA_CAIXA + :DIAS;
      UPDATE LANCAMENTOS_APRAZO SET LANCAMENTOS_APRAZO.DATA_LANCAMENTO = LANCAMENTOS_APRAZO.DATA_LANCAMENTO + :DIAS, LANCAMENTOS_APRAZO.DATA_CAIXA = LANCAMENTOS_APRAZO.DATA_CAIXA + :DIAS;
      UPDATE VENDAS SET VENDAS.DATA_CAIXA = VENDAS.DATA_CAIXA + :DIAS;
      UPDATE VENDAS_FP SET VENDAS_FP.DATA_VENCIMENTO = VENDAS_FP.DATA_VENCIMENTO + :DIAS;
      UPDATE OPERADORES SET OPERADORES.DATA_ABERTURA = OPERADORES.DATA_ABERTURA + :DIAS;
      UPDATE CONTAS_RECEBER SET CONTAS_RECEBER.DT_LANCAMENTO = CONTAS_RECEBER.DT_LANCAMENTO + :DIAS, CONTAS_RECEBER.DT_VENCIMENTO = CONTAS_RECEBER.DT_VENCIMENTO + :DIAS, CONTAS_RECEBER.DT_NOTA_FISCAL = CONTAS_RECEBER.DT_NOTA_FISCAL + :DIAS;
      UPDATE MOVIMENTOCAIXA SET MOVIMENTOCAIXA.DATA = MOVIMENTOCAIXA.DATA + :DIAS;
      UPDATE CHEQUESRECEBIDOS SET CHEQUESRECEBIDOS.DATA_VENCIMENTO = CHEQUESRECEBIDOS.DATA_VENCIMENTO + :DIAS;
      UPDATE COMPRAS SET COMPRAS.DT_PEDIDO = COMPRAS.DT_PEDIDO + :DIAS, COMPRAS.DT_EMISSAO = COMPRAS.DT_EMISSAO + :DIAS, COMPRAS.DT_BOLETO = COMPRAS.DT_BOLETO + :DIAS,COMPRAS.DT_ENTRADA = COMPRAS.DT_ENTRADA + :DIAS;
      UPDATE CONTAS_PAGAR SET CONTAS_PAGAR.DT_NOTA = CONTAS_PAGAR.DT_NOTA + :DIAS, CONTAS_PAGAR.DT_VENCIMENTO = CONTAS_PAGAR.DT_VENCIMENTO + :DIAS, CONTAS_PAGAR.DT_LANCAMENTO = CONTAS_PAGAR.DT_LANCAMENTO + :DIAS,CONTAS_PAGAR.DT_BOLETO = CONTAS_PAGAR.DT_BOLETO + :DIAS, CONTAS_PAGAR.DT_ENTRADA = CONTAS_PAGAR.DT_ENTRADA + :DIAS;
      UPDATE ENTREGAS SET ENTREGAS.DATA = ENTREGAS.DATA + :DIAS;
      UPDATE MOVIMENTOCAIXA SET MOVIMENTOCAIXA.DATA = MOVIMENTOCAIXA.DATA + :DIAS;
      UPDATE MOVIMENTOCAIXAITENS SET MOVIMENTOCAIXAITENS.DATA_LANCAMENTO = MOVIMENTOCAIXAITENS.DATA_LANCAMENTO + :DIAS, MOVIMENTOCAIXAITENS.DATA_VENCIMENTO = MOVIMENTOCAIXAITENS.DATA_VENCIMENTO + :DIAS;
      --UPDATE OPERADORES SET OPERADORES.DATA_FECHAMENTO = OPERADORES.DATA_FECHAMENTO + :DIAS WHERE OPERADORES.DATA_FECHAMENTO <> NULL;
      --UPDATE CONTAS_RECEBER.DT_PAGAMENTO = CONTAS_RECEBER.DT_PAGAMENTO + :DIAS WHERE CONTAS_RECEBER.DT_PAGAMENTO IS NOT NULL;
    END
END ^

ALTER PROCEDURE SP_INTERLIGACAO RETURNS (ID_LOG DOUBLE PRECISION,
CD_FILIAL DOUBLE PRECISION,
IP VARCHAR(15) CHARACTER SET NONE,
DATA DATE,
HORA TIME,
CHAVE_ACESSO VARCHAR(50) CHARACTER SET NONE,
NUMERO_ITENS DOUBLE PRECISION,
NUMERO_UNIDADES DOUBLE PRECISION,
TOTAL_CUSTO DOUBLE PRECISION,
TOTAL_VENDA DOUBLE PRECISION,
CLASSES DOUBLE PRECISION,
GRUPOS DOUBLE PRECISION,
LABORATORIOS DOUBLE PRECISION,
DISTRIBUIDORES DOUBLE PRECISION,
FAMILIAS DOUBLE PRECISION,
GRUPOSBALANCO DOUBLE PRECISION,
GRUPOSCOMPRAS DOUBLE PRECISION,
CARTOES DOUBLE PRECISION,
TOTAL_PROMOCAO DOUBLE PRECISION,
CNPJ VARCHAR(14) CHARACTER SET NONE,
LANCAMENTOS DOUBLE PRECISION,
CAIXAS DOUBLE PRECISION,
CONTASRECEBER DOUBLE PRECISION)
AS 
BEGIN
  FOR
   SELECT
     FILIAIS.CD_FILIAL,
     FILIAIS.CNPJ
   FROM
     FILIAIS
   INTO
     :CD_FILIAL,
     :CNPJ
  DO
   BEGIN
     SELECT
      FIRST 1
      LOGINTERLIGACAO.ID_LOG,
      LOGINTERLIGACAO.CD_FILIAL,
      LOGINTERLIGACAO.IP,
      LOGINTERLIGACAO.DATA,
      LOGINTERLIGACAO.HORA,
      LOGINTERLIGACAO.CHAVE_ACESSO,
      LOGINTERLIGACAO.NUMERO_ITENS,
      LOGINTERLIGACAO.NUMERO_UNIDADES,
      LOGINTERLIGACAO.TOTAL_CUSTO,
      LOGINTERLIGACAO.TOTAL_VENDA,
      LOGINTERLIGACAO.CLASSES,
      LOGINTERLIGACAO.GRUPOS,
      LOGINTERLIGACAO.LABORATORIOS,
      LOGINTERLIGACAO.DISTRIBUIDORES,
      LOGINTERLIGACAO.FAMILIAS,
      LOGINTERLIGACAO.GRUPOSBALANCO,
      LOGINTERLIGACAO.GRUPOSCOMPRAS,
      LOGINTERLIGACAO.CARTOES,
      LOGINTERLIGACAO.TOTAL_PROMOCAO,
      LOGINTERLIGACAO.LANCAMENTOS,
      LOGINTERLIGACAO.CAIXAS,
      LOGINTERLIGACAO.CONTASRECEBER
     FROM
      LOGINTERLIGACAO
     WHERE
      LOGINTERLIGACAO.CD_FILIAL = :CD_FILIAL
     ORDER BY
      LOGINTERLIGACAO.DATA DESC, LOGINTERLIGACAO.HORA DESC
     INTO
      :ID_LOG,
      :CD_FILIAL,
      :IP,
      :DATA,
      :HORA,
      :CHAVE_ACESSO,
      :NUMERO_ITENS,
      :NUMERO_UNIDADES,
      :TOTAL_CUSTO,
      :TOTAL_VENDA,
      :CLASSES,
      :GRUPOS,
      :LABORATORIOS,
      :DISTRIBUIDORES,
      :FAMILIAS,
      :GRUPOSBALANCO,
      :GRUPOSCOMPRAS,
      :CARTOES,
      :TOTAL_PROMOCAO,
      :LANCAMENTOS,
      :CAIXAS,
      :CONTASRECEBER;
     SUSPEND;
   END
END ^

ALTER PROCEDURE SP_INVENTARIO (CD_FILIAL VARCHAR(2) CHARACTER SET NONE,
CD_GRUPO DOUBLE PRECISION,
CD_LABORATORIO DOUBLE PRECISION)
RETURNS (GRUPO VARCHAR(100) CHARACTER SET NONE,
LABORATORIO VARCHAR(100) CHARACTER SET NONE,
PRODUTO VARCHAR(100) CHARACTER SET NONE,
CUSTO_UNITARIO DOUBLE PRECISION,
CUSTO_MEDIO DOUBLE PRECISION,
PRECO_VENDA DOUBLE PRECISION,
ESTOQUE DOUBLE PRECISION,
TOTAL_CUSTO_UNITARIO DOUBLE PRECISION,
TOTAL_CUSTO_MEDIO DOUBLE PRECISION,
TOTAL_VENDA DOUBLE PRECISION,
UNIDADE VARCHAR(10) CHARACTER SET NONE)
AS 
declare variable COMANDO varchar(1000);
declare variable CODIGOGRUPO double precision;
declare variable CODIGOLABORATORIO double precision;
BEGIN
  COMANDO =
  'SELECT PRODUTOS.CD_GRUPO, PRODUTOS.CD_LABORATORIO, PRODUTOS.DESCRICAO, PRODUTOS.UNIDADE, '||
  '       SUM(PRODUTOS.CUSTO_UNITARIO_'||CAST(:CD_FILIAL AS INTEGER)||'),'||
  '       SUM(PRODUTOS.CUSTO_MEDIO_'||CAST(:CD_FILIAL AS INTEGER)||'),'||
  '       SUM(PRODUTOS.PRECO_VENDA_'||CAST(:CD_FILIAL AS INTEGER)||'),'||
  '       SUM(PRODUTOS.ESTOQUE_'||CAST(:CD_FILIAL AS INTEGER)||'),'||
  '       SUM(PRODUTOS.CUSTO_UNITARIO_'||CAST(:CD_FILIAL AS INTEGER)||
  '           * PRODUTOS.ESTOQUE_'||CAST(:CD_FILIAL AS INTEGER)||'),'||
  '       SUM(PRODUTOS.CUSTO_MEDIO_'||CAST(:CD_FILIAL AS INTEGER)||
  '           * PRODUTOS.ESTOQUE_'||CAST(:CD_FILIAL AS INTEGER)||'),'||
  '       SUM(PRODUTOS.PRECO_VENDA_'||CAST(:CD_FILIAL AS INTEGER)||
  '           * PRODUTOS.ESTOQUE_'||CAST(:CD_FILIAL AS INTEGER)||')'||
  ' FROM PRODUTOS ';
  COMANDO = :COMANDO || ' WHERE ';
  IF (:CD_GRUPO <> 0) THEN
   BEGIN
    COMANDO = :COMANDO || ' PRODUTOS.CD_GRUPO = '||CAST(:CD_GRUPO AS INTEGER)||' AND';
   END
  IF (:CD_LABORATORIO <> 0) THEN
   BEGIN
     COMANDO = :COMANDO || ' PRODUTOS.CD_LABORATORIO = '||CAST(:CD_LABORATORIO AS INTEGER)||' AND';
   END
  COMANDO = :COMANDO||' PRODUTOS.ESTOQUE_'||CAST(:CD_FILIAL AS INTEGER)||' > 0 AND  PRODUTOS.STATUS = '''||'A'||''''||
                      ' GROUP BY PRODUTOS.CD_GRUPO, PRODUTOS.CD_LABORATORIO, PRODUTOS.DESCRICAO, PRODUTOS.UNIDADE';
FOR
  EXECUTE STATEMENT :COMANDO
  INTO
   :CODIGOGRUPO, :CODIGOLABORATORIO, :PRODUTO, :UNIDADE, :CUSTO_UNITARIO, :CUSTO_MEDIO, :PRECO_VENDA, :ESTOQUE,
   :TOTAL_CUSTO_UNITARIO, :TOTAL_CUSTO_MEDIO, :TOTAL_VENDA
DO
 BEGIN
    IF (:TOTAL_CUSTO_UNITARIO IS NULL) THEN
       TOTAL_CUSTO_UNITARIO = 0;
    IF (:TOTAL_CUSTO_MEDIO IS NULL) THEN
       TOTAL_CUSTO_MEDIO = 0;
    IF (:TOTAL_VENDA IS NULL) THEN
       TOTAL_VENDA = 0;

    SELECT DESCRICAO FROM GRUPOS WHERE CD_GRUPO = :CODIGOGRUPO INTO :GRUPO;
    SELECT NOME FROM LABORATORIOS WHERE CD_LABORATORIO = :CODIGOLABORATORIO INTO :LABORATORIO;
    SUSPEND;
 END
END ^

ALTER PROCEDURE SP_INVENTARIO_PED (CD_FILIAL VARCHAR(2) CHARACTER SET NONE,
CD_GRUPO DOUBLE PRECISION,
CD_LABORATORIO DOUBLE PRECISION,
DATA_INVENTARIO DATE)
RETURNS (GRUPO VARCHAR(100) CHARACTER SET NONE,
LABORATORIO VARCHAR(100) CHARACTER SET NONE,
PRODUTO VARCHAR(100) CHARACTER SET NONE,
CUSTO_UNITARIO DOUBLE PRECISION,
CUSTO_MEDIO DOUBLE PRECISION,
PRECO_VENDA DOUBLE PRECISION,
ESTOQUE DOUBLE PRECISION,
TOTAL_CUSTO_UNITARIO DOUBLE PRECISION,
TOTAL_CUSTO_MEDIO DOUBLE PRECISION,
TOTAL_VENDA DOUBLE PRECISION,
UNIDADE VARCHAR(10) CHARACTER SET NONE)
AS 
declare variable COMANDO varchar(1000);
declare variable CODIGOGRUPO double precision;
declare variable CODIGOLABORATORIO double precision;
declare variable ID_PRODUTO double precision;
declare variable EXISTE integer;
BEGIN
  EXISTE = 0;
  SELECT COUNT(*) FROM POSICAOESTOQUEDATA WHERE DATA = :DATA_INVENTARIO AND CD_FILIAL = :CD_FILIAL INTO :EXISTE;
  IF (:EXISTE = 0) THEN
     DATA_INVENTARIO = :DATA_INVENTARIO + 1;

  COMANDO =
  'SELECT PRODUTOS.ID_PRODUTO, PRODUTOS.CD_GRUPO, PRODUTOS.CD_LABORATORIO, PRODUTOS.DESCRICAO, PRODUTOS.UNIDADE '||
  ' FROM PRODUTOS ';
  COMANDO = :COMANDO || ' WHERE ';
  IF (:CD_GRUPO <> 0) THEN
   BEGIN
    COMANDO = :COMANDO || ' PRODUTOS.CD_GRUPO = '||CAST(:CD_GRUPO AS INTEGER)||' AND';
   END
  IF (:CD_LABORATORIO <> 0) THEN
   BEGIN
     COMANDO = :COMANDO || ' PRODUTOS.CD_LABORATORIO = '||CAST(:CD_LABORATORIO AS INTEGER)||' AND';
   END
  COMANDO = :COMANDO||' PRODUTOS.STATUS = '''||'A'||'''';
FOR
  EXECUTE STATEMENT :COMANDO
  INTO
   :ID_PRODUTO, :CODIGOGRUPO, :CODIGOLABORATORIO, :PRODUTO, :UNIDADE
DO
 BEGIN
   FOR
    SELECT QUANTIDADE, CUSTO, VENDA FROM POSICAOESTOQUEDATA WHERE DATA = :DATA_INVENTARIO AND CD_FILIAL = :CD_FILIAL AND ID_PRODUTO = :ID_PRODUTO AND QUANTIDADE > 0
    INTO :ESTOQUE, :CUSTO_MEDIO,  :PRECO_VENDA
  DO
   BEGIN
     IF (:ESTOQUE IS NULL) THEN ESTOQUE = 0;
     IF (:CUSTO_MEDIO IS NULL) THEN CUSTO_MEDIO = 0;
     IF (:PRECO_VENDA IS NULL) THEN PRECO_VENDA = 0;

     TOTAL_CUSTO_MEDIO = :ESTOQUE * :CUSTO_MEDIO;
     TOTAL_VENDA = :ESTOQUE * :PRECO_VENDA;

     SELECT DESCRICAO FROM GRUPOS WHERE CD_GRUPO = :CODIGOGRUPO INTO :GRUPO;
     SELECT NOME FROM LABORATORIOS WHERE CD_LABORATORIO = :CODIGOLABORATORIO INTO :LABORATORIO;
     SUSPEND;
   END
 END
END ^

ALTER PROCEDURE SP_KMENTREGADORES (ID_ENTREGADOR DOUBLE PRECISION,
DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (KMINICIAL DOUBLE PRECISION,
KMFINAL DOUBLE PRECISION,
KMDIFERENCA DOUBLE PRECISION)
AS 
BEGIN
   SELECT FIRST 1 KMINICIAL
   FROM KMENTREGADORES
   WHERE
     ID_ENTREGADOR = :ID_ENTREGADOR AND
     DATA_CAIXA >= :DATAINICIAL AND DATA_CAIXA <= :DATAFINAL
   ORDER BY KMINICIAL
   INTO :KMINICIAL;

   SELECT FIRST 1 KMFINAL
   FROM KMENTREGADORES
   WHERE
     ID_ENTREGADOR = :ID_ENTREGADOR AND
     DATA_CAIXA >= :DATAINICIAL AND DATA_CAIXA <= :DATAFINAL
   ORDER BY KMFINAL DESC
   INTO :KMFINAL;

   KMDIFERENCA = :KMFINAL - KMINICIAL;
   SUSPEND;
END ^

ALTER PROCEDURE SP_LANCA_PEDIDO_ESTOQUE (CD_COMPRAS DOUBLE PRECISION)
AS 
DECLARE VARIABLE CD_FILIAL DOUBLE PRECISION;
DECLARE VARIABLE ID_PRODUTO DOUBLE PRECISION;
DECLARE VARIABLE QUANTIDADE DOUBLE PRECISION;
DECLARE VARIABLE COMANDO VARCHAR(255);
BEGIN
  FOR
    SELECT
     ITENS_COMPRA.CD_FILIAL,
     ITENS_COMPRA.ID_PRODUTO,
     ITENS_COMPRA.QUANTIDADE
    FROM
     ITENS_COMPRA,
     COMPRAS
    WHERE
     COMPRAS.CD_COMPRAS = ITENS_COMPRA.CD_COMPRAS AND
     COMPRAS.CD_COMPRAS = :CD_COMPRAS AND
     COMPRAS.STATUS = 'C'
    INTO
     :CD_FILIAL,
     :ID_PRODUTO,
     :QUANTIDADE
  DO
   BEGIN
     COMANDO = 'UPDATE PRODUTOS SET ESTOQUE_'||CAST(CD_FILIAL AS INTEGER)||' = ESTOQUE_'||CAST(CD_FILIAL AS INTEGER)||' + '||:QUANTIDADE||' WHERE ID_PRODUTO = '||CAST(:ID_PRODUTO AS INTEGER);
     EXECUTE STATEMENT :COMANDO;
   END
END ^

ALTER PROCEDURE SP_MEDIA_DESCONTO_PRODUTO_VENDA (CD_FILIAL DOUBLE PRECISION,
ID_PRODUTO DOUBLE PRECISION,
DATAINICIAL DATE)
RETURNS (MEDIADESCONTO NUMERIC(15, 2))
AS 
BEGIN
  FOR
    SELECT AVG((LANCAMENTOS.DESCONTO /((LANCAMENTOS.VALOR / LANCAMENTOS.QUANTIDADE) + LANCAMENTOS.DESCONTO)) * 100) AS MEDIADESCONTO
    FROM LANCAMENTOS
    WHERE CD_FILIAL = :CD_FILIAL AND ID_PRODUTO = :ID_PRODUTO AND DATA_LANCAMENTO >= :DATAINICIAL AND DESCONTO > 0
    INTO :MEDIADESCONTO
  DO
   BEGIN
    SUSPEND;
   END
END ^

ALTER PROCEDURE SP_MEDIA_DESC_PRODUTO_VENDA_M (ID_PRODUTO DOUBLE PRECISION,
DATAINICIAL DATE)
RETURNS (MEDIADESCONTO NUMERIC(15, 2),
MEDIALUCRO NUMERIC(15, 2))
AS 
BEGIN
    SELECT
     AVG((LANCAMENTOS.DESCONTO /((LANCAMENTOS.VALOR / LANCAMENTOS.QUANTIDADE) + LANCAMENTOS.DESCONTO)) * 100) AS MEDIADESCONTO,
     AVG((((LANCAMENTOS.VALOR / LANCAMENTOS.QUANTIDADE) - LANCAMENTOS.CUSTO_MEDIO) / LANCAMENTOS.CUSTO_MEDIO) * 100)
    FROM LANCAMENTOS
    WHERE ID_PRODUTO = :ID_PRODUTO AND DATA_LANCAMENTO >= :DATAINICIAL AND
          DESCONTO > 0 AND CUSTO_MEDIO > 0 AND QUANTIDADE > 0 AND TIPO_VENDA = 'V'
    INTO :MEDIADESCONTO, :MEDIALUCRO;

    SUSPEND;
END ^

ALTER PROCEDURE SP_MEDIA_VENDAS_MES_CLASSE (MESES DOUBLE PRECISION)
RETURNS (CD_FILIAL DOUBLE PRECISION,
FILIAL VARCHAR(100) CHARACTER SET NONE,
CD_CLASSE DOUBLE PRECISION,
CLASSE VARCHAR(100) CHARACTER SET NONE,
VALORMES DOUBLE PRECISION,
VALORDIA DOUBLE PRECISION,
DIAS DOUBLE PRECISION,
ESTOQUE DOUBLE PRECISION)
AS 
declare variable ANOINICIAL integer;
declare variable ANOFINAL integer;
declare variable MESATUAL integer;
declare variable MESINICIAL integer;
declare variable MESFINAL integer;
declare variable DIAINICIAL date;
declare variable DIAFINAL date;
declare variable COMANDO varchar(1000);
declare variable VALORMESCANCELADO double precision;
BEGIN
  ANOINICIAL = EXTRACT(YEAR FROM CURRENT_DATE);
  ANOFINAL = EXTRACT(YEAR FROM CURRENT_DATE);
  MESATUAL = EXTRACT(MONTH FROM CURRENT_DATE);
  MESINICIAL = :MESATUAL - :MESES;
  IF (:MESINICIAL <= 0) THEN
   BEGIN
     MESINICIAL = :MESINICIAL + 12;
     ANOINICIAL = :ANOINICIAL - 1;
   END
  MESFINAL = :MESATUAL - 1;
  IF (:MESFINAL <= 0) THEN
   BEGIN
      MESFINAL = :MESFINAL + 12;
      ANOFINAL = :ANOFINAL - 1;
   END

  DIAINICIAL = :MESINICIAL||'/01/'||:ANOINICIAL;
  IF ((:MESFINAL = 1) OR (:MESFINAL = 3) OR (:MESFINAL = 5) OR
      (:MESFINAL = 7) OR (:MESFINAL = 8) OR (:MESFINAL = 10) OR (:MESFINAL = 12)) THEN
   BEGIN
     DIAFINAL = :MESFINAL||'/31/'||:ANOFINAL;
   END
  ELSE
  IF ((:MESFINAL = 4) OR (:MESFINAL = 6) OR (:MESFINAL = 9) OR (:MESFINAL = 11)) THEN
   BEGIN
     DIAFINAL = :MESFINAL||'/30/'||:ANOFINAL;
   END
  ELSE
  IF (:MESFINAL = 2) THEN
   BEGIN
     DIAFINAL = :MESFINAL||'/28/'||:ANOFINAL;
   END

  ESTOQUE = 0;
  FOR
    SELECT
     FILIAIS.CD_FILIAL,
     FILIAIS.NOME
    FROM
     FILIAIS
    WHERE FILIAIS.EXPORTAR = 'S'
    ORDER BY
     FILIAIS.CD_FILIAL
    INTO
     :CD_FILIAL,
     :FILIAL
  DO
   BEGIN
      FOR
        SELECT
         CLASSES.CD_CLASSE,
         CLASSES.DESCRICAO
        FROM
         CLASSES
        ORDER BY
         CLASSES.CD_CLASSE
        INTO
         :CD_CLASSE,
         :CLASSE
      DO
       BEGIN
          SELECT
           --SUM(LANCAMENTOS.VALOR)
           SUM(LANCAMENTOS.CUSTO_MEDIO * LANCAMENTOS.QUANTIDADE)
          FROM
           LANCAMENTOS
          WHERE
           LANCAMENTOS.DATA_LANCAMENTO >= CAST(:DIAINICIAL AS DATE)  AND
           LANCAMENTOS.DATA_LANCAMENTO <= CAST(:DIAFINAL AS DATE) AND
           LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
           LANCAMENTOS.TIPO_VENDA = 'V' AND
           LANCAMENTOS.CD_CLASSE = :CD_CLASSE
          INTO
           :VALORMES;

          SELECT
           --SUM(LANCAMENTOS.VALOR)
           SUM(LANCAMENTOS.CUSTO_MEDIO * LANCAMENTOS.QUANTIDADE)
          FROM
           LANCAMENTOS
          WHERE
           LANCAMENTOS.DATA_LANCAMENTO >= CAST(:DIAINICIAL AS DATE)  AND
           LANCAMENTOS.DATA_LANCAMENTO <= CAST(:DIAFINAL AS DATE) AND
           LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
           LANCAMENTOS.TIPO_VENDA = 'D' AND
           LANCAMENTOS.CD_CLASSE = :CD_CLASSE
          INTO
           :VALORMESCANCELADO;

          IF (:VALORMES IS NULL) THEN
             VALORMES = 0;
          IF (:VALORMESCANCELADO IS NULL) THEN
             VALORMESCANCELADO = 0;

          IF (:VALORMES > 0) THEN
           BEGIN
              --VALORMES = :VALORMES - :VALORMESCANCELADO;
              VALORMES = :VALORMES / :MESES;
              VALORDIA = :VALORMES / 30;

              --COMANDO = 'SELECT SUM((ESTOQUE_'||CAST(:CD_FILIAL AS INTEGER)||' * PRECO_VENDA) / '||:VALORDIA||')'||
              COMANDO = 'SELECT SUM((ESTOQUE_'||CAST(:CD_FILIAL AS INTEGER)||' * CUSTO_MEDIO_'||CAST(:CD_FILIAL AS INTEGER)||') / '||:VALORDIA||')'||
                        ' FROM PRODUTOS WHERE CD_CLASSE = '||CAST(:CD_CLASSE AS INTEGER) || ' AND STATUS = ''' || 'A' ||''' AND ESTOQUE_'||CAST(:CD_FILIAL AS INTEGER)||' > 0';
              EXECUTE STATEMENT :COMANDO INTO :DIAS;
           END
          ELSE
           BEGIN
             VALORDIA = 0;
             DIAS = 0;
           END

          --COMANDO = 'SELECT SUM((ESTOQUE_'||CAST(:CD_FILIAL AS INTEGER)||' * PRECO_VENDA_'||CAST(:CD_FILIAL AS INTEGER)||'))'||
          COMANDO = 'SELECT SUM((ESTOQUE_'||CAST(:CD_FILIAL AS INTEGER)||' * CUSTO_MEDIO_'||CAST(:CD_FILIAL AS INTEGER)||'))'||
                    ' FROM PRODUTOS WHERE CD_CLASSE = '||CAST(:CD_CLASSE AS INTEGER) || ' AND STATUS = ''' || 'A' ||''' AND ESTOQUE_'||CAST(:CD_FILIAL AS INTEGER)||' > 0';
          EXECUTE STATEMENT :COMANDO INTO :ESTOQUE;

          SUSPEND;
       END
   END
END ^

ALTER PROCEDURE SP_METAS_CONSOLIDADAS_REDE (MESREF INTEGER,
ANOREF INTEGER)
RETURNS (METROSQUADRADOS DOUBLE PRECISION,
NUMEROFUNCIONARIOS DOUBLE PRECISION,
NUMEROPDVS DOUBLE PRECISION,
DIASUTEIS DOUBLE PRECISION,
METAVALOR DOUBLE PRECISION,
METAQUANTIDADE DOUBLE PRECISION,
METACLIENTES DOUBLE PRECISION,
METATICKET DOUBLE PRECISION,
ACUMULADOVALOR DOUBLE PRECISION,
ACUMULADOQUANTIDADE DOUBLE PRECISION,
ACUMULADOCLIENTES DOUBLE PRECISION,
ACUMULADOTICKET DOUBLE PRECISION)
AS 
DECLARE VARIABLE QUANTIDADEFILIAIS INTEGER;
BEGIN
 SELECT
  COUNT(FILIAIS.CD_FILIAL),
  SUM(FILIAIS.METROSQUADRADOS),
  SUM(FILIAIS.NUMEROFUNCIONARIOS),
  SUM(FILIAIS.NUMEROPDVS)
 FROM
  FILIAIS
 INTO
  :QUANTIDADEFILIAIS,
  :METROSQUADRADOS,
  :NUMEROFUNCIONARIOS,
  :NUMEROPDVS;

 SELECT
  AVG(METAS_FILIAIS.DIASUTEIS),
  SUM(METAS_FILIAIS.METAVALOR),
  SUM(METAS_FILIAIS.METAQUANTIDADE),
  SUM(METAS_FILIAIS.METACLIENTES),
  SUM(METAS_FILIAIS.METATICKET),
  SUM(METAS_FILIAIS.ACUMULADOVALOR),
  SUM(METAS_FILIAIS.ACUMULADOQUANTIDADE),
  SUM(METAS_FILIAIS.ACUMULADOCLIENTES),
  SUM(METAS_FILIAIS.ACUMULADOTICKET)
 FROM
  METAS_FILIAIS
 WHERE
  METAS_FILIAIS.MESREF = :MESREF AND
  METAS_FILIAIS.ANOREF = :ANOREF
 INTO
  :DIASUTEIS,
  :METAVALOR,
  :METAQUANTIDADE,
  :METACLIENTES,
  :METATICKET,
  :ACUMULADOVALOR,
  :ACUMULADOQUANTIDADE,
  :ACUMULADOCLIENTES,
  :ACUMULADOTICKET;

 METATICKET = :METATICKET / :QUANTIDADEFILIAIS;
 ACUMULADOTICKET = :ACUMULADOTICKET / :QUANTIDADEFILIAIS;

 SUSPEND;
END ^

ALTER PROCEDURE SP_METAS_GRUPO_CONSOL_REDE (DATA DATE,
DATAFINAL DATE)
RETURNS (GRUPO VARCHAR(100) CHARACTER SET NONE,
VENDAS DOUBLE PRECISION,
QUANTIDADE DOUBLE PRECISION,
DESCONTO DOUBLE PRECISION,
CUSTO DOUBLE PRECISION,
LUCRO DOUBLE PRECISION)
AS 
declare variable CD_GRUPO double precision;
declare variable VENDASCANCELADAS double precision;
declare variable QUANTIDADECANCELADA double precision;
declare variable DESCONTOCANCELADO double precision;
declare variable CUSTOCANCELADO double precision;
BEGIN
  FOR
    SELECT
     GRUPOS.CD_GRUPO,
     GRUPOS.DESCRICAO
    FROM
     GRUPOS
    ORDER BY
     GRUPOS.CD_GRUPO
    INTO
     :CD_GRUPO,
     :GRUPO
  DO
   BEGIN
     SELECT
      SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
      SUM(LANCAMENTOS.QUANTIDADE),
      SUM((LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE) +
          (LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)),
      SUM(LANCAMENTOS.CUSTO_UNITARIO * LANCAMENTOS.QUANTIDADE)
     FROM
      LANCAMENTOS
     WHERE
      LANCAMENTOS.TIPO_VENDA = 'V' AND
      LANCAMENTOS.CD_GRUPO = :CD_GRUPO AND
      LANCAMENTOS.DATA_LANCAMENTO >= :DATA AND
      LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
      LANCAMENTOS.CUSTO_UNITARIO > 0
     INTO
      :VENDAS,
      :QUANTIDADE,
      :DESCONTO,
      :CUSTO;

     IF (:VENDAS IS NULL) THEN
        VENDAS = 0;
     IF (:QUANTIDADE IS NULL) THEN
        QUANTIDADE = 0;
     IF (:DESCONTO IS NULL) THEN
        DESCONTO = 0;
     IF (:CUSTO IS NULL) THEN
        CUSTO = 0;

     SELECT
      SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
      SUM(LANCAMENTOS.QUANTIDADE),
      SUM((LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE) +
          (LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)),
      SUM(LANCAMENTOS.CUSTO_UNITARIO * LANCAMENTOS.QUANTIDADE)
     FROM
      LANCAMENTOS
     WHERE
      LANCAMENTOS.CD_GRUPO = :CD_GRUPO AND
      LANCAMENTOS.TIPO_VENDA = 'D' AND
      LANCAMENTOS.DATA_LANCAMENTO >= :DATA AND
      LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL
     INTO
      :VENDASCANCELADAS,
      :QUANTIDADECANCELADA,
      :DESCONTOCANCELADO,
      :CUSTOCANCELADO;

     IF (:VENDASCANCELADAS IS NULL) THEN
        VENDASCANCELADAS = 0;
     IF (:QUANTIDADECANCELADA IS NULL) THEN
        QUANTIDADECANCELADA = 0;
     IF (:DESCONTOCANCELADO IS NULL) THEN
        DESCONTOCANCELADO = 0;
     IF (:CUSTOCANCELADO IS NULL) THEN
        CUSTOCANCELADO = 0;

     VENDAS = :VENDAS - :VENDASCANCELADAS;
     QUANTIDADE = :QUANTIDADE - :QUANTIDADECANCELADA;
     CUSTO = :CUSTO - :CUSTOCANCELADO;
     DESCONTO = :DESCONTO - :DESCONTOCANCELADO;
     IF ((:DESCONTO IS NULL) OR (:DESCONTO = 0)) THEN
       DESCONTO = 0;
     ELSE
       DESCONTO = (:DESCONTO / :VENDAS) * 100;
     IF ((:VENDAS = 0) OR (:VENDAS IS NULL)) THEN
        LUCRO = 0;
     ELSE
        LUCRO = ((:VENDAS - :CUSTO) / :VENDAS) * 100;

     IF (:VENDAS > 0) THEN
        SUSPEND;
   END
END ^

