ALTER PROCEDURE SP_METAS_REDE_FILIAL (MESREF INTEGER,
ANOREF INTEGER)
RETURNS (CD_FILIAL DOUBLE PRECISION,
FILIAL VARCHAR(100) CHARACTER SET NONE,
METROSQUADRADOS DOUBLE PRECISION,
NUMEROFUNCIONARIOS DOUBLE PRECISION,
NUMEROPDVS DOUBLE PRECISION,
DIASUTEIS DOUBLE PRECISION,
METAVALOR DOUBLE PRECISION,
METAQUANTIDADE DOUBLE PRECISION,
METACLIENTES DOUBLE PRECISION,
METATICKET DOUBLE PRECISION,
ACUMULADOVALOR DOUBLE PRECISION,
ACUMULADOQUANTIDADE DOUBLE PRECISION,
ACUMULADOCLIENTES DOUBLE PRECISION,
ACUMULADOTICKET DOUBLE PRECISION)
AS 
declare variable QUANTIDADEFILIAIS integer;
BEGIN
 FOR
     SELECT
      METAS_FILIAIS.CD_FILIAL,
      FILIAIS.NOME,
      METAS_FILIAIS.DIASUTEIS,
      METAS_FILIAIS.METAVALOR,
      METAS_FILIAIS.METAQUANTIDADE,
      METAS_FILIAIS.METACLIENTES,
      METAS_FILIAIS.METATICKET,
      METAS_FILIAIS.ACUMULADOVALOR,
      METAS_FILIAIS.ACUMULADOQUANTIDADE,
      METAS_FILIAIS.ACUMULADOCLIENTES,
      METAS_FILIAIS.ACUMULADOTICKET
     FROM
      METAS_FILIAIS, FILIAIS
     WHERE
      METAS_FILIAIS.CD_FILIAL = FILIAIS.CD_FILIAL AND
      METAS_FILIAIS.MESREF = :MESREF AND
      METAS_FILIAIS.ANOREF = :ANOREF
     INTO
      :CD_FILIAL,
      :FILIAL,
      :DIASUTEIS,
      :METAVALOR,
      :METAQUANTIDADE,
      :METACLIENTES,
      :METATICKET,
      :ACUMULADOVALOR,
      :ACUMULADOQUANTIDADE,
      :ACUMULADOCLIENTES,
      :ACUMULADOTICKET
 DO
  BEGIN
    SUSPEND;
  END
END ^

ALTER PROCEDURE SP_MOVE_PRODUTO_ALIQUOTA (ID_PRODUTO DOUBLE PRECISION,
ALIQ_DESTINO DOUBLE PRECISION,
SITUACAO VARCHAR(10) CHARACTER SET NONE)
AS 
BEGIN
   UPDATE PRODUTOS_FISCO SET
    ALIQUOTA_ICMS = :ALIQ_DESTINO,
    SITUACAO_TRIBUTARIA = :SITUACAO
   WHERE
    ID_PRODUTO = :ID_PRODUTO;
END ^

