ALTER PROCEDURE SP_MOVE_PRODUTO_CLASSE (CLASSE_DESTINO DOUBLE PRECISION,
PRODUTO DOUBLE PRECISION)
AS 
DECLARE VARIABLE TIPO VARCHAR(2);
BEGIN
  SELECT TIPO FROM CLASSES WHERE CD_CLASSE = :CLASSE_DESTINO INTO :TIPO;
  UPDATE PRODUTOS SET
   CD_CLASSE = :CLASSE_DESTINO,
   TIPO_PRODUTO = :TIPO
  WHERE
   ID_PRODUTO = :PRODUTO;
END ^

