  WHERE
   ID_PRODUTO = :PRODUTO;
   /*CD_LABORATORIO = :LAB_ORIGEM;*/
END ^

ALTER PROCEDURE SP_MOVE_PRODUTO_LAB_GRUPO (GRUPO DOUBLE PRECISION,
PRODUTO DOUBLE PRECISION)
AS 
BEGIN
  UPDATE PRODUTOS SET
   CD_GRUPO = :GRUPO
  WHERE
   ID_PRODUTO = :PRODUTO;
   /*CD_LABORATORIO = :LABORATORIO;*/
END ^

ALTER PROCEDURE SP_MOVE_PRODUTO_LISTA (LISTA_DESTINO DOUBLE PRECISION,
ID_PRODUTO DOUBLE PRECISION)
AS 
DECLARE VARIABLE MARGEM DOUBLE PRECISION;
BEGIN
  SELECT MARCACAO FROM LISTA_MARCACAO WHERE CD_LISTA = :LISTA_DESTINO INTO :MARGEM;
  UPDATE PRODUTOS SET
   CD_LISTA = :LISTA_DESTINO,
   MARGEM = :MARGEM
  WHERE
   ID_PRODUTO = :ID_PRODUTO;
END ^

ALTER PROCEDURE SP_MOVE_PRODUTO_NCM (ID_PRODUTO DOUBLE PRECISION,
BARRA VARCHAR(14) CHARACTER SET NONE,
NCM VARCHAR(10) CHARACTER SET NONE)
AS 
BEGIN
  UPDATE PRODUTOS SET
   NCM = :NCM
  WHERE ID_PRODUTO = :ID_PRODUTO;

  IF (:BARRA <> '') THEN
   BEGIN
     UPDATE SPED_PIS_COFINS SET
      NCM = :NCM
     WHERE BARRA = :BARRA;
   END
END ^

ALTER PROCEDURE SP_MOVE_PRODUTO_SUBGRUPO (SUBGRUPO_DESTINO DOUBLE PRECISION,
PRODUTO DOUBLE PRECISION)
AS 
BEGIN
  UPDATE PRODUTOS SET
   CD_SUBGRUPO = :SUBGRUPO_DESTINO
  WHERE
   ID_PRODUTO = :PRODUTO;
END ^

ALTER PROCEDURE SP_MOVIMENTO_CAIXA_DETALHADO (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (CD_HISTORICO VARCHAR(10) CHARACTER SET NONE,
HISTORICO VARCHAR(50) CHARACTER SET NONE,
DATA DATE,
MHISTORICO VARCHAR(255) CHARACTER SET NONE,
VALOR DOUBLE PRECISION)
AS 
BEGIN
  FOR
      SELECT
       PLANO_CONTAS.CD_HISTORICO,
       PLANO_CONTAS.HISTORICO,
       MOVIMENTOCAIXA.DATA,
       MOVIMENTOCAIXA.HISTORICO,
       MOVIMENTOCAIXA.VALOR
      FROM
       MOVIMENTOCAIXA,
       PLANO_CONTAS
      WHERE
       MOVIMENTOCAIXA.CD_PLANO_CONTAS = PLANO_CONTAS.CD_PLANO_CONTAS AND
       MOVIMENTOCAIXA.DATA >= :DATAINICIAL AND
       MOVIMENTOCAIXA.DATA <= :DATAFINAL
      INTO
       :CD_HISTORICO,
       :HISTORICO,
       :DATA,
       :MHISTORICO,
       :VALOR
  DO
   BEGIN
       SUSPEND;
   END
END ^

ALTER PROCEDURE SP_NFCE_ELIMINA_TROCO AS 
BEGIN
  UPDATE NFCE SET
   ARQUIVO = SUBSTRING(NFCE.ARQUIVO FROM 1 FOR POSITION('<vTroco>', NFCE.ARQUIVO) - 1) ||
             SUBSTRING(NFCE.ARQUIVO FROM POSITION('</pag>', NFCE.ARQUIVO) FOR 10000)
  WHERE NFCE.TIPOEMISSAO = 'O' AND NFCE.STATUS = 'G' AND ((NFCE.PROTOCOLO IS NULL) OR (NFCE.PROTOCOLO = '')) AND
        (POSITION('<vTroco>', NFCE.ARQUIVO) > 0);
END ^

ALTER PROCEDURE SP_NFCE_REIMPRESSAO (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (ID_NFCE DOUBLE PRECISION,
DATA DATE,
CD_VENDA DOUBLE PRECISION,
ARQUIVO BLOB,
CHAVE VARCHAR(1000) CHARACTER SET NONE,
NUMERO_NOTA VARCHAR(100) CHARACTER SET NONE,
STATUS VARCHAR(1) CHARACTER SET NONE,
CD_CLIENTE DOUBLE PRECISION,
TOTAL NUMERIC(15, 2),
NOME VARCHAR(100) CHARACTER SET NONE,
SERIE_NOTA VARCHAR(100) CHARACTER SET NONE)
AS 
declare variable TOTAL_VENDA numeric(15,2);
declare variable TOTAL_CANCELAMENTO numeric(15,2);
declare variable CD_FILIAL double precision;
BEGIN
  SELECT CD_FILIAL FROM PARAMETROS INTO :CD_FILIAL;
  FOR
    SELECT
     NFCE.ID_NFCE,
     NFCE.DATA,
     NFCE.CD_VENDA,
     NFCE.ARQUIVO,
     NFCE.CHAVE,
     NFCE.NUMERO_NOTA,
     NFCE.SERIE_NOTA,
     NFCE.STATUS
    FROM
     NFCE
    WHERE
     DATA >= :DATAINICIAL AND
     DATA <= :DATAFINAL
    GROUP BY
     NFCE.ID_NFCE,
     NFCE.DATA,
     NFCE.CD_VENDA,
     NFCE.ARQUIVO,
     NFCE.CHAVE,
     NFCE.NUMERO_NOTA,
     NFCE.SERIE_NOTA,
     NFCE.STATUS
    ORDER BY NFCE.NUMERO_NOTA
    INTO
     :ID_NFCE, :DATA, :CD_VENDA, :ARQUIVO, :CHAVE, :NUMERO_NOTA, :SERIE_NOTA, :STATUS
  DO
   BEGIN
     CD_CLIENTE = NULL;
     NOME = '';
     TOTAL = 0;
     TOTAL_VENDA = 0;
     TOTAL_CANCELAMENTO = 0;

     IF (:CD_VENDA IS NOT NULL) THEN
      BEGIN
         SELECT SUM(LANCAMENTOS.VALOR)
         FROM LANCAMENTOS
         WHERE LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND LANCAMENTOS.CD_VENDA = :CD_VENDA AND LANCAMENTOS.TIPO_VENDA = 'V'
         INTO :TOTAL_VENDA;
    
         IF (:TOTAL_VENDA IS NULL) THEN
            TOTAL_VENDA = 0;

         SELECT SUM(LANCAMENTOS.VALOR)
         FROM LANCAMENTOS
         WHERE LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND LANCAMENTOS.CD_VENDA = :CD_VENDA AND LANCAMENTOS.TIPO_VENDA = 'D'
         INTO :TOTAL_CANCELAMENTO;

         IF (:TOTAL_CANCELAMENTO IS NULL) THEN
            TOTAL_CANCELAMENTO = 0;

         TOTAL = :TOTAL_VENDA - :TOTAL_CANCELAMENTO;

         SELECT FIRST 1 CD_CLIENTE FROM LANCAMENTOS
         WHERE LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND LANCAMENTOS.CD_VENDA = :CD_VENDA
         INTO :CD_CLIENTE;

         SELECT NOME FROM CLIENTES WHERE CD_CLIENTE = :CD_CLIENTE INTO :NOME;
         IF (:NOME IS NULL) THEN
             NOME = '';
      END

     SUSPEND;
   END
END ^

ALTER PROCEDURE SP_NFCE_REIMPRESSAO_ARQUIVADAS (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (ID_NFCE DOUBLE PRECISION,
DATA DATE,
CD_VENDA DOUBLE PRECISION,
ARQUIVO BLOB,
CHAVE VARCHAR(1000) CHARACTER SET NONE,
NUMERO_NOTA VARCHAR(100) CHARACTER SET NONE,
STATUS VARCHAR(1) CHARACTER SET NONE,
CD_CLIENTE DOUBLE PRECISION,
TOTAL NUMERIC(15, 2),
NOME VARCHAR(100) CHARACTER SET NONE,
SERIE_NOTA VARCHAR(100) CHARACTER SET NONE)
AS 
DECLARE VARIABLE TOTAL_VENDA NUMERIC(15,2);
DECLARE VARIABLE TOTAL_CANCELAMENTO NUMERIC(15,2);
DECLARE VARIABLE CD_FILIAL DOUBLE PRECISION;
BEGIN
  SELECT CD_FILIAL FROM PARAMETROS INTO :CD_FILIAL;
  FOR
    SELECT
     NFCECOPIA.ID_NFCE,
     NFCECOPIA.DATA,
     NFCECOPIA.CD_VENDA,
     NFCECOPIA.ARQUIVO,
     NFCECOPIA.CHAVE,
     NFCECOPIA.NUMERO_NOTA,
     NFCECOPIA.SERIE_NOTA,
     NFCECOPIA.STATUS
    FROM
     NFCECOPIA
    WHERE
     DATA >= :DATAINICIAL AND
     DATA <= :DATAFINAL
    GROUP BY
     NFCECOPIA.ID_NFCE,
     NFCECOPIA.DATA,
     NFCECOPIA.CD_VENDA,
     NFCECOPIA.ARQUIVO,
     NFCECOPIA.CHAVE,
     NFCECOPIA.NUMERO_NOTA,
     NFCECOPIA.SERIE_NOTA,
     NFCECOPIA.STATUS
    ORDER BY NFCECOPIA.NUMERO_NOTA
    INTO
     :ID_NFCE, :DATA, :CD_VENDA, :ARQUIVO, :CHAVE, :NUMERO_NOTA, :SERIE_NOTA, :STATUS
  DO
   BEGIN
     CD_CLIENTE = NULL;
     NOME = '';
     TOTAL = 0;
     TOTAL_VENDA = 0;
     TOTAL_CANCELAMENTO = 0;

     IF (:CD_VENDA IS NOT NULL) THEN
      BEGIN
         SELECT SUM(LANCAMENTOS.VALOR)
         FROM LANCAMENTOS
         WHERE LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND LANCAMENTOS.CD_VENDA = :CD_VENDA AND LANCAMENTOS.TIPO_VENDA = 'V'
         INTO :TOTAL_VENDA;
    
         IF (:TOTAL_VENDA IS NULL) THEN
            TOTAL_VENDA = 0;

         SELECT SUM(LANCAMENTOS.VALOR)
         FROM LANCAMENTOS
         WHERE LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND LANCAMENTOS.CD_VENDA = :CD_VENDA AND LANCAMENTOS.TIPO_VENDA = 'D'
         INTO :TOTAL_CANCELAMENTO;

         IF (:TOTAL_CANCELAMENTO IS NULL) THEN
            TOTAL_CANCELAMENTO = 0;

         TOTAL = :TOTAL_VENDA - :TOTAL_CANCELAMENTO;

         SELECT FIRST 1 CD_CLIENTE FROM LANCAMENTOS
         WHERE LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND LANCAMENTOS.CD_VENDA = :CD_VENDA
         INTO :CD_CLIENTE;

         SELECT NOME FROM CLIENTES WHERE CD_CLIENTE = :CD_CLIENTE INTO :NOME;
         IF (:NOME IS NULL) THEN
             NOME = '';
      END

     SUSPEND;
   END
END ^

ALTER PROCEDURE SP_OLAP_APURACAO_RESULTADO (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (HISTORICO1 VARCHAR(100) CHARACTER SET NONE,
HISTORICO2 VARCHAR(100) CHARACTER SET NONE,
HISTORICO3 VARCHAR(100) CHARACTER SET NONE,
TIPO VARCHAR(1) CHARACTER SET NONE,
FILIAL VARCHAR(100) CHARACTER SET NONE,
CD_MOVIMENTO DOUBLE PRECISION,
DATAMOVIMENTO DATE,
DATA DATE,
CREDITO DOUBLE PRECISION,
DEBITO DOUBLE PRECISION)
AS 
DECLARE VARIABLE CD_PLANO_CONTAS DOUBLE PRECISION;
DECLARE VARIABLE VALOR DOUBLE PRECISION;
DECLARE VARIABLE CD_FILIAL DOUBLE PRECISION;
DECLARE VARIABLE CD_HISTORICO VARCHAR(10);
BEGIN
  FOR
    SELECT
      FILIAIS.CD_FILIAL,
      FILIAIS.NOME
    FROM
     FILIAIS
    WHERE CD_FILIAL = 1
    ORDER BY
     CD_FILIAL
    INTO
     :CD_FILIAL,
     :FILIAL
  DO
   BEGIN
        FOR
          SELECT
           PLANO_CONTAS.CD_PLANO_CONTAS,
           PLANO_CONTAS.CD_HISTORICO,
           PLANO_CONTAS.CD_HISTORICO||' - '||PLANO_CONTAS.HISTORICO,
           PLANO_CONTAS.TIPO_CONTA
          FROM
           PLANO_CONTAS
          WHERE
           PLANO_CONTAS.GRAU = '1'
          ORDER BY
           PLANO_CONTAS.CD_HISTORICO
          INTO
           :CD_PLANO_CONTAS,
           :CD_HISTORICO,
           :HISTORICO1,
           :TIPO
        DO
         BEGIN
            VALOR = NULL;
            CREDITO = 0;
            DEBITO = 0;
            HISTORICO2 = NULL;
            HISTORICO3 = NULL;
            DATAMOVIMENTO = NULL;
            SELECT
              SUM(MOVIMENTOCAIXA.VALOR)
            FROM
              MOVIMENTOCAIXA,
              PLANO_CONTAS
            WHERE
              MOVIMENTOCAIXA.DATA >= :DATAINICIAL AND
              MOVIMENTOCAIXA.DATA <= :DATAFINAL AND
              MOVIMENTOCAIXA.CD_FILIAL = :CD_FILIAL AND
              MOVIMENTOCAIXA.CD_PLANO_CONTAS = PLANO_CONTAS.CD_PLANO_CONTAS AND
              SUBSTRING(PLANO_CONTAS.CD_HISTORICO FROM 1 FOR 1) = SUBSTRING(:CD_HISTORICO FROM 1 FOR 1)
            INTO
              :VALOR;
      
            IF (:VALOR IS NOT NULL) THEN
             BEGIN
                IF (:TIPO = 'C') THEN
                   CREDITO = :VALOR;
                ELSE
                   DEBITO = :VALOR;
                DATA = :DATAINICIAL;
                CD_MOVIMENTO = 0;
                SUSPEND;
             END

            FOR
              SELECT
               PLANO_CONTAS.CD_PLANO_CONTAS,
               PLANO_CONTAS.CD_HISTORICO,
               PLANO_CONTAS.CD_HISTORICO||' - '||PLANO_CONTAS.HISTORICO,
               PLANO_CONTAS.TIPO_CONTA
              FROM
               PLANO_CONTAS
              WHERE
               PLANO_CONTAS.GRAU = '2' AND
               SUBSTRING(PLANO_CONTAS.CD_HISTORICO FROM 1 FOR 1) = SUBSTRING(:CD_HISTORICO FROM 1 FOR 1)
              ORDER BY
               PLANO_CONTAS.CD_HISTORICO
              INTO
               :CD_PLANO_CONTAS,
               :CD_HISTORICO,
               :HISTORICO2,
               :TIPO
            DO
             BEGIN
                VALOR = NULL;
                CREDITO = 0;
                DEBITO = 0;
                HISTORICO3 = NULL;
                DATAMOVIMENTO = NULL;
                SELECT
                  SUM(MOVIMENTOCAIXA.VALOR)
                FROM
                  MOVIMENTOCAIXA,
                  PLANO_CONTAS
                WHERE
                  MOVIMENTOCAIXA.DATA >= :DATAINICIAL AND
                  MOVIMENTOCAIXA.DATA <= :DATAFINAL AND
                  MOVIMENTOCAIXA.CD_FILIAL = :CD_FILIAL AND
                  MOVIMENTOCAIXA.CD_PLANO_CONTAS = PLANO_CONTAS.CD_PLANO_CONTAS AND
                  SUBSTRING(PLANO_CONTAS.CD_HISTORICO FROM 1 FOR 4) = SUBSTRING(:CD_HISTORICO FROM 1 FOR 4)
                INTO
                  :VALOR;
  
                IF (:VALOR IS NOT NULL) THEN
                 BEGIN
                    IF (:TIPO = 'C') THEN
                       CREDITO = :VALOR;
                    ELSE
                       DEBITO = :VALOR;
                    DATA = :DATAINICIAL;
                    CD_MOVIMENTO = 0;
                    SUSPEND;
                 END

                FOR
                  SELECT
                   PLANO_CONTAS.CD_PLANO_CONTAS,
                   PLANO_CONTAS.CD_HISTORICO,
                   PLANO_CONTAS.CD_HISTORICO||' - '||PLANO_CONTAS.HISTORICO,
                   PLANO_CONTAS.TIPO_CONTA
                  FROM
                   PLANO_CONTAS
                  WHERE
                   PLANO_CONTAS.GRAU = '3' AND
                   SUBSTRING(PLANO_CONTAS.CD_HISTORICO FROM 1 FOR 4) = SUBSTRING(:CD_HISTORICO FROM 1 FOR 4)
                  ORDER BY
                   PLANO_CONTAS.CD_HISTORICO
                  INTO
                   :CD_PLANO_CONTAS,
                   :CD_HISTORICO,
                   :HISTORICO3,
                   :TIPO
                DO
                 BEGIN
                    VALOR = NULL;
                    CREDITO = 0;
                    DEBITO = 0;
                    FOR
                      SELECT
                        MOVIMENTOCAIXA.CD_MOVIMENTOCAIXA,
                        MOVIMENTOCAIXA.DATA,
                        MOVIMENTOCAIXA.DATA,
                        SUM(MOVIMENTOCAIXA.VALOR)
                      FROM
                        MOVIMENTOCAIXA
                      WHERE
                        MOVIMENTOCAIXA.DATA >= :DATAINICIAL AND
                        MOVIMENTOCAIXA.DATA <= :DATAFINAL AND
                        MOVIMENTOCAIXA.CD_FILIAL = :CD_FILIAL AND
                        MOVIMENTOCAIXA.CD_PLANO_CONTAS = :CD_PLANO_CONTAS
                      GROUP BY
                        MOVIMENTOCAIXA.CD_MOVIMENTOCAIXA,
                        MOVIMENTOCAIXA.DATA
                      INTO
                        :CD_MOVIMENTO,
                        :DATAMOVIMENTO,
                        :DATA,
                        :VALOR
                    DO
                     BEGIN
                       IF (:VALOR IS NOT NULL) THEN
                        BEGIN
                           IF (:TIPO = 'C') THEN
                              CREDITO = :VALOR;
                           ELSE
                              DEBITO = :VALOR;
                           SUSPEND;
                        END
                     END
                 END
             END
         END
   END
END ^

ALTER PROCEDURE SP_OLAP_APURACAO_RESULTADO3 (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (HISTORICO VARCHAR(100) CHARACTER SET NONE,
TIPO VARCHAR(1) CHARACTER SET NONE,
FILIAL VARCHAR(100) CHARACTER SET NONE,
CD_MOVIMENTO DOUBLE PRECISION,
DATAMOVIMENTO DATE,
DATA DATE,
CREDITO DOUBLE PRECISION,
DEBITO DOUBLE PRECISION)
AS 
DECLARE VARIABLE CD_PLANO_CONTAS DOUBLE PRECISION;
DECLARE VARIABLE VALOR DOUBLE PRECISION;
DECLARE VARIABLE CD_FILIAL DOUBLE PRECISION;
DECLARE VARIABLE CD_HISTORICO VARCHAR(10);
DECLARE VARIABLE GRAU VARCHAR(1);
BEGIN
  FOR
    SELECT
     PLANO_CONTAS.CD_PLANO_CONTAS,
     PLANO_CONTAS.CD_HISTORICO,
     PLANO_CONTAS.CD_HISTORICO||' - '||PLANO_CONTAS.HISTORICO,
     PLANO_CONTAS.TIPO_CONTA,
     PLANO_CONTAS.GRAU
    FROM
     PLANO_CONTAS
    ORDER BY
     PLANO_CONTAS.CD_HISTORICO
    INTO
     :CD_PLANO_CONTAS,
     :CD_HISTORICO,
     :HISTORICO,
     :TIPO,
     :GRAU
  DO
   BEGIN
      FOR
        SELECT
          FILIAIS.CD_FILIAL,
          FILIAIS.NOME
        FROM
         FILIAIS
        WHERE CD_FILIAL = 1
        ORDER BY
         CD_FILIAL
        INTO
         :CD_FILIAL,
         :FILIAL
      DO
       BEGIN
          IF (:GRAU = '3') THEN
           BEGIN
              VALOR = NULL;
              FOR
                SELECT
                  MOVIMENTOCAIXA.CD_MOVIMENTOCAIXA,
                  MOVIMENTOCAIXA.DATA,
                  MOVIMENTOCAIXA.DATA,
                  SUM(MOVIMENTOCAIXA.VALOR)
                FROM
                  MOVIMENTOCAIXA
                WHERE
                  MOVIMENTOCAIXA.DATA >= :DATAINICIAL AND
                  MOVIMENTOCAIXA.DATA <= :DATAFINAL AND
                  MOVIMENTOCAIXA.CD_FILIAL = :CD_FILIAL AND
                  MOVIMENTOCAIXA.CD_PLANO_CONTAS = :CD_PLANO_CONTAS
                GROUP BY
                  MOVIMENTOCAIXA.CD_MOVIMENTOCAIXA,
                  MOVIMENTOCAIXA.DATA
                INTO
                  :CD_MOVIMENTO,
                  :DATAMOVIMENTO,
                  :DATA,
                  :VALOR
              DO
               BEGIN
                 IF (:TIPO = 'C') THEN
                    CREDITO = :VALOR;
                 ELSE
                    DEBITO = :VALOR;
                 SUSPEND;
               END
              IF (:VALOR IS NULL) THEN
               BEGIN
                 DATA = :DATAINICIAL;
                 CD_MOVIMENTO = 0;
                 CREDITO = 0;
                 DEBITO = 0;
                 SUSPEND;
               END
          END
         ELSE
         IF (:GRAU = '2') THEN
          BEGIN
              VALOR = NULL;
              CREDITO = 0;
              DEBITO = 0;
              SELECT
                SUM(MOVIMENTOCAIXA.VALOR)
              FROM
                MOVIMENTOCAIXA,
                PLANO_CONTAS
              WHERE
                MOVIMENTOCAIXA.DATA >= :DATAINICIAL AND
                MOVIMENTOCAIXA.DATA <= :DATAFINAL AND
                MOVIMENTOCAIXA.CD_FILIAL = :CD_FILIAL AND
                MOVIMENTOCAIXA.CD_PLANO_CONTAS = PLANO_CONTAS.CD_PLANO_CONTAS AND
                SUBSTRING(PLANO_CONTAS.CD_HISTORICO FROM 1 FOR 4) = SUBSTRING(:CD_HISTORICO FROM 1 FOR 4)
              INTO
                :VALOR;

              IF (:VALOR IS NULL) THEN
                  VALOR = 0;
              IF (:TIPO = 'C') THEN
                 CREDITO = :VALOR;
              ELSE
                 DEBITO = :VALOR;
              DATA = :DATAINICIAL;
              DATAMOVIMENTO = :DATAINICIAL;
              CD_MOVIMENTO = 0;
              SUSPEND;
          END
         ELSE
         IF (:GRAU = '1') THEN
          BEGIN
              VALOR = NULL;
              CREDITO = 0;
              DEBITO = 0;
              SELECT
                SUM(MOVIMENTOCAIXA.VALOR)
              FROM
                MOVIMENTOCAIXA,
                PLANO_CONTAS
              WHERE
                MOVIMENTOCAIXA.DATA >= :DATAINICIAL AND
                MOVIMENTOCAIXA.DATA <= :DATAFINAL AND
                MOVIMENTOCAIXA.CD_FILIAL = :CD_FILIAL AND
                MOVIMENTOCAIXA.CD_PLANO_CONTAS = PLANO_CONTAS.CD_PLANO_CONTAS AND
                SUBSTRING(PLANO_CONTAS.CD_HISTORICO FROM 1 FOR 1) = SUBSTRING(:CD_HISTORICO FROM 1 FOR 1)
              INTO
                :VALOR;

              IF (:VALOR IS NULL) THEN
                  VALOR = 0;
              IF (:TIPO = 'C') THEN
                 CREDITO = :VALOR;
              ELSE
                 DEBITO = :VALOR;
              DATA = :DATAINICIAL;
              DATAMOVIMENTO = :DATAINICIAL;
              CD_MOVIMENTO = 0;
              SUSPEND;
          END
       END
   END
END ^

ALTER PROCEDURE SP_OLAP_COMPARATIVO (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (FILIAL VARCHAR(40) CHARACTER SET NONE,
DIA DATE,
COMPRAS DOUBLE PRECISION,
VENDAS DOUBLE PRECISION,
NUMERO_DE_VENDAS DOUBLE PRECISION,
QUANTIDADE_VENDIDA DOUBLE PRECISION,
CLASSE VARCHAR(100) CHARACTER SET NONE,
GRUPO VARCHAR(100) CHARACTER SET NONE,
COMPRAS_BRUTO DOUBLE PRECISION)
AS 
declare variable CD_FILIAL double precision;
declare variable VENDAS_C double precision;
declare variable QUANTIDADE_C integer;
declare variable NUMERO_DE_VENDAS_C integer;
declare variable CD_CLASSE double precision;
declare variable CD_GRUPO double precision;
declare variable COMPRAS_CANCELADAS double precision;
declare variable COMPRAS_CANCELADAS_BRUTO double precision;
BEGIN
  FOR
   SELECT
    LANCAMENTOS.DATA_LANCAMENTO,
    LANCAMENTOS.CD_FILIAL,
    LANCAMENTOS.CD_CLASSE,
    LANCAMENTOS.CD_GRUPO
   FROM
    LANCAMENTOS
   WHERE
    LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
    LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL
   GROUP BY
    LANCAMENTOS.DATA_LANCAMENTO,
    LANCAMENTOS.CD_FILIAL,
    LANCAMENTOS.CD_CLASSE,
    LANCAMENTOS.CD_GRUPO
   INTO
    :DIA,
    :CD_FILIAL,
    :CD_CLASSE,
    :CD_GRUPO
  DO
   BEGIN
      COMPRAS = 0;
      COMPRAS_CANCELADAS = 0;

      SELECT
        SUM(LANCAMENTOS.VALOR),
        SUM(LANCAMENTOS.CUSTO_UNITARIO * LANCAMENTOS.QUANTIDADE)
      FROM
        LANCAMENTOS
      WHERE
        LANCAMENTOS.DATA_LANCAMENTO = :DIA AND
        LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
        LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
        LANCAMENTOS.CD_GRUPO = :CD_GRUPO AND
        LANCAMENTOS.TIPO_VENDA = 'C'
      INTO
        :COMPRAS_BRUTO,
        :COMPRAS;
    
      IF (:COMPRAS_BRUTO IS NULL) THEN
         COMPRAS_BRUTO = 0;
      IF (:COMPRAS IS NULL) THEN
         COMPRAS = 0;
    
      SELECT
        SUM(LANCAMENTOS.VALOR),
        SUM(LANCAMENTOS.CUSTO_UNITARIO * LANCAMENTOS.QUANTIDADE)
      FROM
        LANCAMENTOS
      WHERE
        LANCAMENTOS.DATA_LANCAMENTO = :DIA AND
        LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
        LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
        LANCAMENTOS.CD_GRUPO = :CD_GRUPO AND
        LANCAMENTOS.TIPO_VENDA = 'E'
      INTO
        :COMPRAS_CANCELADAS_BRUTO,
        :COMPRAS_CANCELADAS;

      IF (:COMPRAS_CANCELADAS_BRUTO IS NULL) THEN
         COMPRAS_CANCELADAS_BRUTO = 0;

      IF (:COMPRAS_CANCELADAS IS NULL) THEN
         COMPRAS_CANCELADAS = 0;

      COMPRAS = :COMPRAS - :COMPRAS_CANCELADAS;
      COMPRAS_BRUTO = :COMPRAS_BRUTO - :COMPRAS_CANCELADAS_BRUTO;
      /*IF (:COMPRAS < 0) THEN
         COMPRAS = 0;
      IF (:COMPRAS_BRUTO < 0) THEN
         COMPRAS_BRUTO = 0;*/


      VENDAS = 0;
      QUANTIDADE_VENDIDA = 0;
      NUMERO_DE_VENDAS = 0;

      SELECT
        SUM(LANCAMENTOS.QUANTIDADE),
        COUNT(DISTINCT LANCAMENTOS.CD_VENDA),
        SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO)
      FROM
        LANCAMENTOS
      WHERE
        LANCAMENTOS.DATA_LANCAMENTO = :DIA AND
        LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
        LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
        LANCAMENTOS.CD_GRUPO = :CD_GRUPO AND
        LANCAMENTOS.TIPO_VENDA = 'V'
      INTO
        :QUANTIDADE_VENDIDA,
        :NUMERO_DE_VENDAS,
        :VENDAS;

      IF (:VENDAS IS NULL) THEN
         VENDAS = 0;
      IF (:QUANTIDADE_VENDIDA IS NULL) THEN
         QUANTIDADE_VENDIDA = 0;
      IF (:NUMERO_DE_VENDAS IS NULL) THEN
         NUMERO_DE_VENDAS = 0;

      VENDAS_C = 0;
      QUANTIDADE_C = 0;
      NUMERO_DE_VENDAS_C = 0;

      SELECT
        SUM(LANCAMENTOS.QUANTIDADE),
        COUNT(DISTINCT LANCAMENTOS.CD_VENDA),
        SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO)
      FROM
        LANCAMENTOS
      WHERE
        LANCAMENTOS.DATA_LANCAMENTO = :DIA AND
        LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
        LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
        LANCAMENTOS.CD_GRUPO = :CD_GRUPO AND
        LANCAMENTOS.TIPO_VENDA = 'D'
      INTO
        :QUANTIDADE_C,
        :NUMERO_DE_VENDAS_C,
        :VENDAS_C;

      IF (:VENDAS_C IS NULL) THEN
         VENDAS_C = 0;
      IF (:QUANTIDADE_C IS NULL) THEN
         QUANTIDADE_C = 0;
      IF (:NUMERO_DE_VENDAS_C IS NULL) THEN
         NUMERO_DE_VENDAS_C = 0;

      VENDAS = :VENDAS - :VENDAS_C;
      QUANTIDADE_VENDIDA = :QUANTIDADE_VENDIDA - :QUANTIDADE_C;
      NUMERO_DE_VENDAS = :NUMERO_DE_VENDAS - :NUMERO_DE_VENDAS_C;

      /*IF (:VENDAS < 0) THEN
         VENDAS = 0;
      IF (:QUANTIDADE_VENDIDA < 0) THEN
         QUANTIDADE_VENDIDA = 0;
      IF (:NUMERO_DE_VENDAS < 0) THEN
         NUMERO_DE_VENDAS = 0;*/

      /*IF ((:VENDAS > 0) OR (:COMPRAS > 0)) THEN
       BEGIN*/
          SELECT NOME FROM FILIAIS WHERE CD_FILIAL = :CD_FILIAL INTO :FILIAL;
          SELECT DESCRICAO FROM CLASSES WHERE CD_CLASSE = :CD_CLASSE INTO :CLASSE;
          SELECT DESCRICAO FROM GRUPOS WHERE CD_GRUPO = :CD_GRUPO INTO :GRUPO;
          SUSPEND;
       --END
  END
END ^

ALTER PROCEDURE SP_OLAP_COMPRAS_CLASSE (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (FILIAL VARCHAR(100) CHARACTER SET NONE,
CLASSE VARCHAR(100) CHARACTER SET NONE,
GRUPO VARCHAR(100) CHARACTER SET NONE,
DIA DATE,
PRODUTO VARCHAR(60) CHARACTER SET NONE,
DISTRIBUIDOR VARCHAR(100) CHARACTER SET NONE,
LABORATORIO VARCHAR(100) CHARACTER SET NONE,
QUANTIDADE DOUBLE PRECISION,
TOTAL_BRUTO DOUBLE PRECISION,
TOTAL DOUBLE PRECISION)
AS 
declare variable CD_FILIAL double precision;
declare variable CD_CLASSE double precision;
declare variable CD_GRUPO double precision;
declare variable CD_DISTRIBUIDOR double precision;
declare variable CD_LABORATORIO double precision;
declare variable NOTA_FISCAL varchar(100);
declare variable EXISTECANCELAMENTO integer;
BEGIN
 FOR
    SELECT
     LANCAMENTOS.CD_FILIAL,
     LANCAMENTOS.CD_CLASSE,
     LANCAMENTOS.CD_GRUPO,
     LANCAMENTOS.CD_LABORATORIO,
     LANCAMENTOS.DESCRICAO,
     LANCAMENTOS.CD_CLIENTE,
     LANCAMENTOS.DATA_LANCAMENTO,
     LANCAMENTOS.NOTA_FISCAL,
     SUM(LANCAMENTOS.QUANTIDADE),
     SUM(LANCAMENTOS.CUSTO_UNITARIO * LANCAMENTOS.QUANTIDADE),
     SUM(LANCAMENTOS.VALOR)
    FROM
     LANCAMENTOS
    WHERE
     LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
     LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
     LANCAMENTOS.TIPO_VENDA = 'C'
    GROUP BY
     LANCAMENTOS.CD_FILIAL,
     LANCAMENTOS.CD_CLASSE,
     LANCAMENTOS.CD_GRUPO,
     LANCAMENTOS.CD_LABORATORIO,
     LANCAMENTOS.DESCRICAO,
     LANCAMENTOS.CD_CLIENTE,
     LANCAMENTOS.DATA_LANCAMENTO,
     LANCAMENTOS.NOTA_FISCAL
    INTO
     :CD_FILIAL,
     :CD_CLASSE,
     :CD_GRUPO,
     :CD_LABORATORIO, 
     :PRODUTO,
     :CD_DISTRIBUIDOR,
     :DIA,
     :NOTA_FISCAL,
     :QUANTIDADE,
     :TOTAL,
     :TOTAL_BRUTO
 DO
  BEGIN
   EXISTECANCELAMENTO = 0;
   SELECT FIRST 1 CD_LANCAMENTO FROM LANCAMENTOS
   WHERE LANCAMENTOS.CD_CLIENTE = :CD_DISTRIBUIDOR AND
         LANCAMENTOS.NOTA_FISCAL = :NOTA_FISCAL AND
         LANCAMENTOS.TIPO_VENDA = 'E'
   INTO :EXISTECANCELAMENTO;

   IF (:CD_FILIAL = 2) THEN
      CD_FILIAL = 2;

   IF ((:EXISTECANCELAMENTO IS NULL) OR (:EXISTECANCELAMENTO = 0)) THEN
    BEGIN
       SELECT NOME FROM FILIAIS WHERE CD_FILIAL = :CD_FILIAL INTO :FILIAL;
       SELECT DESCRICAO FROM CLASSES WHERE CD_CLASSE = :CD_CLASSE INTO :CLASSE;
       SELECT DESCRICAO FROM GRUPOS WHERE CD_GRUPO = :CD_GRUPO INTO :GRUPO;
       SELECT NOME FROM DISTRIBUIDORES WHERE CD_DISTRIBUIDOR = :CD_DISTRIBUIDOR INTO :DISTRIBUIDOR;
       SELECT NOME FROM LABORATORIOS WHERE CD_LABORATORIO = :CD_LABORATORIO INTO :LABORATORIO;
       SUSPEND;
    END
  END
END ^

ALTER PROCEDURE SP_OLAP_COMPRAS_DESCONTO (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (FILIAL VARCHAR(100) CHARACTER SET NONE,
DISTRIBUIDOR VARCHAR(100) CHARACTER SET NONE,
DIA DATE,
NOTAFISCAL VARCHAR(20) CHARACTER SET NONE,
GRUPO VARCHAR(100) CHARACTER SET NONE,
ID_PRODUTO DOUBLE PRECISION,
DESCRICAO VARCHAR(100) CHARACTER SET NONE,
PERCENTUALDESCONTO DOUBLE PRECISION,
VALORDESCONTO DOUBLE PRECISION,
QUANTIDADE DOUBLE PRECISION,
TOTAL DOUBLE PRECISION)
AS 
DECLARE VARIABLE CD_FILIAL DOUBLE PRECISION;
DECLARE VARIABLE CD_DISTRIBUIDOR DOUBLE PRECISION;
DECLARE VARIABLE CD_GRUPO DOUBLE PRECISION;
BEGIN
 FOR
    SELECT
     COMPRAS.CD_FILIAL,
     COMPRAS.CD_DISTRIBUIDOR,
     COMPRAS.DT_ENTRADA,
     COMPRAS.NOTA_FISCAL,
     ITENS_COMPRA.ID_PRODUTO,
     ITENS_COMPRA.DESCRICAO,
     ITENS_COMPRA.PERCENTUAL_DESCONTO,
     (ITENS_COMPRA.VL_DESCONTO * ITENS_COMPRA.QUANTIDADE),
     ITENS_COMPRA.QUANTIDADE,
     ((ITENS_COMPRA.VL_UNITARIO * ITENS_COMPRA.QUANTIDADE) - (ITENS_COMPRA.VL_DESCONTO * ITENS_COMPRA.QUANTIDADE))
    FROM
     COMPRAS, ITENS_COMPRA
    WHERE
     COMPRAS.CD_COMPRAS = ITENS_COMPRA.CD_COMPRAS AND
     COMPRAS.DT_ENTRADA >= :DATAINICIAL AND
     COMPRAS.DT_ENTRADA <= :DATAFINAL AND
     COMPRAS.STATUS = 'C'
    INTO
     :CD_FILIAL,
     :CD_DISTRIBUIDOR,
     :DIA,
     :NOTAFISCAL,
     :ID_PRODUTO,
     :DESCRICAO,
     :PERCENTUALDESCONTO,
     :VALORDESCONTO,
     :QUANTIDADE,
     :TOTAL
 DO
  BEGIN
    IF (:PERCENTUALDESCONTO IS NULL) THEN
       PERCENTUALDESCONTO = 0;
    IF (:VALORDESCONTO IS NULL) THEN
       VALORDESCONTO = 0;
    SELECT NOME FROM FILIAIS WHERE CD_FILIAL = :CD_FILIAL INTO :FILIAL;
    SELECT NOME FROM DISTRIBUIDORES WHERE CD_DISTRIBUIDOR = :CD_DISTRIBUIDOR INTO :DISTRIBUIDOR;
    SELECT CD_GRUPO FROM PRODUTOS WHERE ID_PRODUTO = :ID_PRODUTO INTO :CD_GRUPO;
    SELECT DESCRICAO FROM GRUPOS WHERE CD_GRUPO = :CD_GRUPO INTO :GRUPO;
    SUSPEND;
  END
END ^

ALTER PROCEDURE SP_OLAP_COMPRAS_DISTRIBUIDOR (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (FILIAL VARCHAR(100) CHARACTER SET NONE,
DISTRIBUIDOR VARCHAR(100) CHARACTER SET NONE,
DIA DATE,
QUANTIDADE DOUBLE PRECISION,
TOTAL DOUBLE PRECISION,
TOTAL_BRUTO DOUBLE PRECISION)
AS 
declare variable CD_FILIAL double precision;
declare variable CD_DISTRIBUIDOR double precision;
BEGIN
 FOR
    SELECT
     LANCAMENTOS.CD_FILIAL,
     LANCAMENTOS.CD_CLIENTE,
     LANCAMENTOS.DATA_LANCAMENTO,
     SUM(LANCAMENTOS.QUANTIDADE),
     SUM(LANCAMENTOS.CUSTO_UNITARIO * LANCAMENTOS.QUANTIDADE),
     SUM(LANCAMENTOS.VALOR)
    FROM
     LANCAMENTOS
    WHERE
     LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
     LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
     LANCAMENTOS.TIPO_VENDA = 'C'
    GROUP BY
     LANCAMENTOS.CD_FILIAL,
     LANCAMENTOS.CD_CLIENTE,
     LANCAMENTOS.DATA_LANCAMENTO
    INTO
     :CD_FILIAL,
     :CD_DISTRIBUIDOR,
     :DIA,
     :QUANTIDADE,
     :TOTAL,
     :TOTAL_BRUTO
 DO
  BEGIN
    SELECT NOME FROM FILIAIS WHERE CD_FILIAL = :CD_FILIAL INTO :FILIAL;
    SELECT NOME FROM DISTRIBUIDORES WHERE CD_DISTRIBUIDOR = :CD_DISTRIBUIDOR INTO :DISTRIBUIDOR;
    SUSPEND;
  END
END ^

ALTER PROCEDURE SP_OLAP_COMPRAS_DIST_COMPRAS (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (FILIAL VARCHAR(100) CHARACTER SET NONE,
DISTRIBUIDOR VARCHAR(100) CHARACTER SET NONE,
DIA DATE,
NOTA VARCHAR(10) CHARACTER SET NONE,
ICMSSUBSTITUICAO DOUBLE PRECISION,
DESCONTO DOUBLE PRECISION,
FRETE DOUBLE PRECISION,
SEGURO DOUBLE PRECISION,
IPI DOUBLE PRECISION,
OUTRAS_DESPESAS DOUBLE PRECISION,
QUANTIDADE DOUBLE PRECISION,
TOTAL DOUBLE PRECISION,
TOTAL_PRODUTOS DOUBLE PRECISION,
CFOP DOUBLE PRECISION)
AS 
declare variable CD_FILIAL double precision;
declare variable CD_DISTRIBUIDOR double precision;
declare variable NUMERO double precision;
BEGIN
 FOR
    SELECT
     COMPRAS.CD_COMPRAS,
     COMPRAS.CD_FILIAL,
     COMPRAS.CD_DISTRIBUIDOR,
     COMPRAS.DT_PEDIDO,
     COMPRAS.NOTA_FISCAL,
     COMPRAS.ICM_VALORSUBST,
     COMPRAS.VL_DESCONTO_NOTA,
     COMPRAS.VL_FRETE,
     COMPRAS.VL_SEGURO,
     COMPRAS.VL_IPI,
     COMPRAS.OUTRAS_DESPESAS,
     COMPRAS.CD_CFOP,
     COMPRAS.UNIDADES,
     COMPRAS.TOTAL_NOTA,
     COMPRAS.VL_TOTALPRODUTOS
    FROM
     COMPRAS
    WHERE
     COMPRAS.DT_PEDIDO >= :DATAINICIAL AND
     COMPRAS.DT_PEDIDO <= :DATAFINAL AND
     COMPRAS.STATUS = 'C' AND
     COMPRAS.VINCULADO = 'N' AND
     COMPRAS.BONIFICACAO = 'N'
    GROUP BY
     COMPRAS.CD_COMPRAS,
     COMPRAS.CD_FILIAL,
     COMPRAS.CD_DISTRIBUIDOR,
     COMPRAS.DT_PEDIDO,
     COMPRAS.NOTA_FISCAL,
     COMPRAS.ICM_VALORSUBST,
     COMPRAS.VL_DESCONTO_NOTA,
     COMPRAS.VL_FRETE,
     COMPRAS.VL_SEGURO,
     COMPRAS.VL_IPI,
     COMPRAS.OUTRAS_DESPESAS,
     COMPRAS.CD_CFOP,
     COMPRAS.UNIDADES,
     COMPRAS.TOTAL_NOTA,
     COMPRAS.VL_TOTALPRODUTOS
    INTO
     :NUMERO,
     :CD_FILIAL,
     :CD_DISTRIBUIDOR,
     :DIA,
     :NOTA,
     :ICMSSUBSTITUICAO,
     :DESCONTO,
     :FRETE,
     :SEGURO,
     :IPI,
     :OUTRAS_DESPESAS,
     :CFOP,
     :QUANTIDADE,
     :TOTAL,
     :TOTAL_PRODUTOS
 DO
  BEGIN
    SELECT NOME FROM FILIAIS WHERE CD_FILIAL = :CD_FILIAL INTO :FILIAL;
    SELECT NOME FROM DISTRIBUIDORES WHERE CD_DISTRIBUIDOR = :CD_DISTRIBUIDOR INTO :DISTRIBUIDOR;
    SUSPEND;
  END
END ^

ALTER PROCEDURE SP_OLAP_COMPRAS_GRUPO (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (FILIAL VARCHAR(100) CHARACTER SET NONE,
GRUPO VARCHAR(100) CHARACTER SET NONE,
DIA DATE,
PRODUTO VARCHAR(60) CHARACTER SET NONE,
DISTRIBUIDOR VARCHAR(100) CHARACTER SET NONE,
LABORATORIO VARCHAR(100) CHARACTER SET NONE,
QUANTIDADE DOUBLE PRECISION,
TOTAL DOUBLE PRECISION,
TOTAL_BRUTO DOUBLE PRECISION)
AS 
declare variable CD_FILIAL double precision;
declare variable CD_GRUPO double precision;
declare variable CD_DISTRIBUIDOR double precision;
declare variable CD_LABORATORIO double precision;
declare variable ID_PRODUTO double precision;
BEGIN
 FOR
    SELECT
     LANCAMENTOS.CD_FILIAL,
     LANCAMENTOS.CD_GRUPO,
     LANCAMENTOS.CD_LABORATORIO,
     LANCAMENTOS.DESCRICAO,
     LANCAMENTOS.ID_PRODUTO,
     LANCAMENTOS.CD_CLIENTE,
     LANCAMENTOS.DATA_LANCAMENTO
    FROM
     LANCAMENTOS
    WHERE
     LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
     LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
     LANCAMENTOS.TIPO_VENDA = 'C'
    GROUP BY
     LANCAMENTOS.CD_FILIAL,
     LANCAMENTOS.CD_GRUPO,
     LANCAMENTOS.CD_LABORATORIO,
     LANCAMENTOS.DESCRICAO,
     LANCAMENTOS.ID_PRODUTO,
     LANCAMENTOS.CD_CLIENTE,
     LANCAMENTOS.DATA_LANCAMENTO
    INTO
     :CD_FILIAL,
     :CD_GRUPO,
     :CD_LABORATORIO, 
     :PRODUTO,
     :ID_PRODUTO,
     :CD_DISTRIBUIDOR,
     :DIA
 DO
  BEGIN

    SELECT
     SUM(ITENS_COMPRA.VL_TOTAL),
     SUM(ITENS_COMPRA.QUANTIDADE * ITENS_COMPRA.QT_EMBALAGEM),
     SUM(ITENS_COMPRA.CUSTO_APLICADO * ITENS_COMPRA.QUANTIDADE * ITENS_COMPRA.QT_EMBALAGEM)
    FROM
     ITENS_COMPRA, COMPRAS, PRODUTOS
    WHERE
     COMPRAS.CD_DISTRIBUIDOR = :CD_DISTRIBUIDOR AND
     COMPRAS.DT_ENTRADA = :DIA AND
     COMPRAS.CD_FILIAL = :CD_FILIAL AND
     COMPRAS.STATUS = 'C' AND
     ITENS_COMPRA.CD_COMPRAS = COMPRAS.CD_COMPRAS AND
     ITENS_COMPRA.ID_PRODUTO = :ID_PRODUTO AND
     ITENS_COMPRA.ID_PRODUTO = PRODUTOS.ID_PRODUTO AND
     PRODUTOS.CD_LABORATORIO = :CD_LABORATORIO AND
     PRODUTOS.CD_GRUPO = :CD_GRUPO
    INTO
      :TOTAL_BRUTO,
      :QUANTIDADE,
      :TOTAL;

   IF (:TOTAL_BRUTO IS NULL) THEN
       TOTAL_BRUTO = 0;
   IF (:QUANTIDADE IS NULL) THEN
       QUANTIDADE = 0;
   IF (:TOTAL IS NULL) THEN
       TOTAL = 0;

   SELECT NOME FROM FILIAIS WHERE CD_FILIAL = :CD_FILIAL INTO :FILIAL;
   SELECT DESCRICAO FROM GRUPOS WHERE CD_GRUPO = :CD_GRUPO INTO :GRUPO;
   SELECT NOME FROM DISTRIBUIDORES WHERE CD_DISTRIBUIDOR = :CD_DISTRIBUIDOR INTO :DISTRIBUIDOR;
   SELECT NOME FROM LABORATORIOS WHERE CD_LABORATORIO = :CD_LABORATORIO INTO :LABORATORIO;
   SUSPEND;
  END
END ^

ALTER PROCEDURE SP_OLAP_COMPRAS_GRUPOSCOMPRA (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (FILIAL VARCHAR(100) CHARACTER SET NONE,
CLASSE VARCHAR(100) CHARACTER SET NONE,
GRUPO VARCHAR(100) CHARACTER SET NONE,
DIA DATE,
PRODUTO VARCHAR(60) CHARACTER SET NONE,
DISTRIBUIDOR VARCHAR(100) CHARACTER SET NONE,
LABORATORIO VARCHAR(100) CHARACTER SET NONE,
GRUPOCOMPRA VARCHAR(100) CHARACTER SET NONE,
QUANTIDADE DOUBLE PRECISION,
TOTAL_BRUTO DOUBLE PRECISION,
TOTAL DOUBLE PRECISION)
AS 
DECLARE VARIABLE CD_FILIAL DOUBLE PRECISION;
DECLARE VARIABLE CD_CLASSE DOUBLE PRECISION;
DECLARE VARIABLE CD_GRUPO DOUBLE PRECISION;
DECLARE VARIABLE CD_DISTRIBUIDOR DOUBLE PRECISION;
DECLARE VARIABLE CD_LABORATORIO DOUBLE PRECISION;
DECLARE VARIABLE CD_GRUPO_COMPRA DOUBLE PRECISION;
DECLARE VARIABLE NOTA_FISCAL VARCHAR(100);
DECLARE VARIABLE EXISTECANCELAMENTO INTEGER;
BEGIN
 FOR
    SELECT
     LANCAMENTOS.CD_FILIAL,
     LANCAMENTOS.CD_CLASSE,
     LANCAMENTOS.CD_GRUPO,
     LANCAMENTOS.CD_LABORATORIO,
     PRODUTOS.CD_GRUPOCOMPRA,
     LANCAMENTOS.DESCRICAO,
     LANCAMENTOS.CD_CLIENTE,
     LANCAMENTOS.DATA_LANCAMENTO,
     LANCAMENTOS.NOTA_FISCAL,
     SUM(LANCAMENTOS.QUANTIDADE),
     SUM(LANCAMENTOS.CUSTO_UNITARIO * LANCAMENTOS.QUANTIDADE),
     SUM(LANCAMENTOS.VALOR)
    FROM
     LANCAMENTOS INNER JOIN PRODUTOS ON LANCAMENTOS.ID_PRODUTO = PRODUTOS.ID_PRODUTO
    WHERE
     LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
     LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
     LANCAMENTOS.TIPO_VENDA = 'C'
    GROUP BY
     LANCAMENTOS.CD_FILIAL,
     LANCAMENTOS.CD_CLASSE,
     LANCAMENTOS.CD_GRUPO,
     LANCAMENTOS.CD_LABORATORIO,
     PRODUTOS.CD_GRUPOCOMPRA,
     LANCAMENTOS.DESCRICAO,
     LANCAMENTOS.CD_CLIENTE,
     LANCAMENTOS.DATA_LANCAMENTO,
     LANCAMENTOS.NOTA_FISCAL
    INTO
     :CD_FILIAL,
     :CD_CLASSE,
     :CD_GRUPO,
     :CD_LABORATORIO, 
     :CD_GRUPO_COMPRA,
     :PRODUTO,
     :CD_DISTRIBUIDOR,
     :DIA,
     :NOTA_FISCAL,
     :QUANTIDADE,
     :TOTAL,
     :TOTAL_BRUTO
 DO
  BEGIN
   EXISTECANCELAMENTO = 0;
   SELECT FIRST 1 CD_LANCAMENTO FROM LANCAMENTOS
   WHERE LANCAMENTOS.CD_CLIENTE = :CD_DISTRIBUIDOR AND
         LANCAMENTOS.NOTA_FISCAL = :NOTA_FISCAL AND
         LANCAMENTOS.TIPO_VENDA = 'E'
   INTO :EXISTECANCELAMENTO;

   IF (:CD_FILIAL = 2) THEN
      CD_FILIAL = 2;

   IF ((:EXISTECANCELAMENTO IS NULL) OR (:EXISTECANCELAMENTO = 0)) THEN
    BEGIN
       SELECT NOME FROM FILIAIS WHERE CD_FILIAL = :CD_FILIAL INTO :FILIAL;
       SELECT DESCRICAO FROM CLASSES WHERE CD_CLASSE = :CD_CLASSE INTO :CLASSE;
       SELECT DESCRICAO FROM GRUPOS WHERE CD_GRUPO = :CD_GRUPO INTO :GRUPO;
       SELECT NOME FROM DISTRIBUIDORES WHERE CD_DISTRIBUIDOR = :CD_DISTRIBUIDOR INTO :DISTRIBUIDOR;
       SELECT NOME FROM LABORATORIOS WHERE CD_LABORATORIO = :CD_LABORATORIO INTO :LABORATORIO;
       SELECT DESCRICAO FROM GRUPOSCOMPRAS WHERE CD_GRUPOCOMPRA = :CD_GRUPO_COMPRA INTO :GRUPOCOMPRA;
       SUSPEND;
    END
  END
END ^

ALTER PROCEDURE SP_OLAP_COMPRAS_LABORATORIO (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (FILIAL VARCHAR(100) CHARACTER SET NONE,
LABORATORIO VARCHAR(100) CHARACTER SET NONE,
DIA DATE,
QUANTIDADE DOUBLE PRECISION,
TOTAL DOUBLE PRECISION,
TOTAL_BRUTO DOUBLE PRECISION)
AS 
declare variable CD_FILIAL double precision;
declare variable CD_LABORATORIO double precision;
declare variable NOTA_FISCAL varchar(100);
declare variable EXISTECANCELAMENTO integer;
declare variable CD_DISTRIBUIDOR double precision;
BEGIN
 FOR
    SELECT
     LANCAMENTOS.CD_FILIAL,
     LANCAMENTOS.CD_LABORATORIO,
     LANCAMENTOS.DATA_LANCAMENTO,
     LANCAMENTOS.NOTA_FISCAL,
     LANCAMENTOS.CD_CLIENTE,
     SUM(LANCAMENTOS.QUANTIDADE),
     SUM(LANCAMENTOS.CUSTO_UNITARIO * LANCAMENTOS.QUANTIDADE),
     SUM(LANCAMENTOS.VALOR)
    FROM
     LANCAMENTOS
    WHERE
     LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
     LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
     LANCAMENTOS.TIPO_VENDA = 'C'
    GROUP BY
     LANCAMENTOS.CD_FILIAL,
     LANCAMENTOS.CD_LABORATORIO,
     LANCAMENTOS.NOTA_FISCAL,
     LANCAMENTOS.CD_CLIENTE,
     LANCAMENTOS.DATA_LANCAMENTO
    INTO
     :CD_FILIAL,
     :CD_LABORATORIO,
     :DIA,
     :NOTA_FISCAL,
     :CD_DISTRIBUIDOR,
     :QUANTIDADE,
     :TOTAL,
     :TOTAL_BRUTO
 DO
  BEGIN
   EXISTECANCELAMENTO = 0;

   SELECT FIRST 1 CD_LANCAMENTO FROM LANCAMENTOS
   WHERE LANCAMENTOS.CD_CLIENTE = :CD_DISTRIBUIDOR AND
         LANCAMENTOS.NOTA_FISCAL = :NOTA_FISCAL AND
         LANCAMENTOS.TIPO_VENDA = 'E'
   INTO :EXISTECANCELAMENTO;

   IF ((:EXISTECANCELAMENTO IS NULL) OR (:EXISTECANCELAMENTO = 0)) THEN
    BEGIN
       SELECT NOME FROM FILIAIS WHERE CD_FILIAL = :CD_FILIAL INTO :FILIAL;
       SELECT NOME FROM LABORATORIOS WHERE CD_LABORATORIO = :CD_LABORATORIO INTO :LABORATORIO;
       SUSPEND;
    END
  END
END ^

ALTER PROCEDURE SP_OLAP_COMPRAS_MARGEM (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (FILIAL VARCHAR(100) CHARACTER SET NONE,
NOTA_FISCAL VARCHAR(100) CHARACTER SET NONE,
DATA_NOTA DATE,
PRODUTO VARCHAR(100) CHARACTER SET NONE,
ESTOQUE DOUBLE PRECISION,
PMC DOUBLE PRECISION,
MARGEM DOUBLE PRECISION,
QUANTIDADE DOUBLE PRECISION,
VALOR DOUBLE PRECISION,
NOVA_MARGEM DOUBLE PRECISION)
AS 
BEGIN
 FOR
  SELECT
    FILIAIS.NOME,
    COMPRAS.NOTA_FISCAL,
    COMPRAS.DT_EMISSAO,
    ITENS_COMPRA.DESCRICAO,
    ITENS_COMPRA.SALDO,
    ITENS_COMPRA.PRECO_VENDA,
    ITENS_COMPRA.PERCENTUAL_MARGEM,
    ITENS_COMPRA.QUANTIDADE,
    ITENS_COMPRA.VL_UNITARIO,
    CASE
      WHEN (ITENS_COMPRA.VL_UNITARIO IS NOT NULL) AND  (ITENS_COMPRA.VL_UNITARIO > 0) THEN
                  ( (ITENS_COMPRA.PRECO_VENDA * 100) / (ITENS_COMPRA.VL_UNITARIO / ITENS_COMPRA.QT_EMBALAGEM) - 100) 
      WHEN (ITENS_COMPRA.VL_UNITARIO IS NULL) OR  (ITENS_COMPRA.VL_UNITARIO = 0) THEN
                  ( (ITENS_COMPRA.PRECO_VENDA * 100) / (1 / ITENS_COMPRA.QT_EMBALAGEM) - 100) 
    END
  FROM
   COMPRAS,
   ITENS_COMPRA,
   FILIAIS
  WHERE
   COMPRAS.CD_COMPRAS = ITENS_COMPRA.CD_COMPRAS AND
   COMPRAS.CD_FILIAL = FILIAIS.CD_FILIAL AND
   COMPRAS.STATUS = 'C' AND
   COMPRAS.DT_PEDIDO >= :DATAINICIAL AND
   COMPRAS.DT_PEDIDO <= :DATAFINAL
  INTO
   :FILIAL,
   :NOTA_FISCAL,
   :DATA_NOTA, 
   :PRODUTO,
   :ESTOQUE,
   :PMC,
   :MARGEM,
   :QUANTIDADE,
   :VALOR,
   :NOVA_MARGEM
 DO
  BEGIN
    SUSPEND;
  END
END ^

ALTER PROCEDURE SP_OLAP_COMPRAS_PRODUTO (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (FILIAL VARCHAR(100) CHARACTER SET NONE,
PRODUTO VARCHAR(100) CHARACTER SET NONE,
DIA DATE,
QUANTIDADE DOUBLE PRECISION,
TOTAL DOUBLE PRECISION,
CFOP VARCHAR(4) CHARACTER SET NONE,
TOTAL_BRUTO DOUBLE PRECISION)
AS 
declare variable CD_FILIAL double precision;
BEGIN
 FOR
    SELECT
     LANCAMENTOS.CD_FILIAL,
     LANCAMENTOS.DESCRICAO,
     LANCAMENTOS.DATA_LANCAMENTO,
     LANCAMENTOS.CFOP,
     SUM(LANCAMENTOS.QUANTIDADE),
     SUM(LANCAMENTOS.CUSTO_UNITARIO * LANCAMENTOS.QUANTIDADE),
     SUM(LANCAMENTOS.VALOR)
    FROM
     LANCAMENTOS
    WHERE
     LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
     LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
     LANCAMENTOS.TIPO_VENDA = 'C'
    GROUP BY
     LANCAMENTOS.CD_FILIAL,
     LANCAMENTOS.DESCRICAO,
     LANCAMENTOS.DATA_LANCAMENTO,
     LANCAMENTOS.CFOP
    INTO
     :CD_FILIAL,
     :PRODUTO,
     :DIA,
     :CFOP,
     :QUANTIDADE,
     :TOTAL,
     :TOTAL_BRUTO
 DO
  BEGIN
   SELECT NOME FROM FILIAIS WHERE CD_FILIAL = :CD_FILIAL INTO :FILIAL;
   SUSPEND;
  END
END ^

ALTER PROCEDURE SP_OLAP_CONTAS_PAGAR (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (CD_FILIAL DOUBLE PRECISION,
FILIAL VARCHAR(100) CHARACTER SET NONE,
CD_DISTRIBUIDOR DOUBLE PRECISION,
DISTRIBUIDOR VARCHAR(100) CHARACTER SET NONE,
DATA DATE,
VALORAPAGAR DOUBLE PRECISION,
VALORPAGO DOUBLE PRECISION)
AS 
BEGIN
  FOR
    SELECT CD_FILIAL, NOME FROM FILIAIS INTO :CD_FILIAL, :FILIAL
  DO
   BEGIN
     FOR
       SELECT
        CONTAS_PAGAR.CD_DISTRIBUIDOR, 
        CONTAS_PAGAR.DT_VENCIMENTO,
        CONTAS_PAGAR.VL_SALDO,
        CONTAS_PAGAR.VL_PAGAMENTO
       FROM
        CONTAS_PAGAR
       WHERE
        CONTAS_PAGAR.DT_VENCIMENTO >= :DATAINICIAL AND
        CONTAS_PAGAR.DT_VENCIMENTO <= :DATAFINAL AND
        CONTAS_PAGAR.CD_FILIAL = :CD_FILIAL AND
        ((CONTAS_PAGAR.STATUS = 'A') OR (CONTAS_PAGAR.STATUS = 'P'))
       INTO
        :CD_DISTRIBUIDOR,
        :DATA,
        :VALORAPAGAR,
        :VALORPAGO
     DO
      BEGIN
        SELECT NOME FROM DISTRIBUIDORES WHERE CD_DISTRIBUIDOR = :CD_DISTRIBUIDOR INTO :DISTRIBUIDOR;

        SUSPEND;
      END
   END
END ^

ALTER PROCEDURE SP_OLAP_CRM (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (CD_FILIAL DOUBLE PRECISION,
DATA DATE,
CRM VARCHAR(100) CHARACTER SET NONE,
MEDICO VARCHAR(100) CHARACTER SET NONE,
ID_PRODUTO DOUBLE PRECISION,
CD_LABORATORIO DOUBLE PRECISION,
QUANTIDADE INTEGER,
DESCRICAO VARCHAR(100) CHARACTER SET NONE,
LABORATORIO VARCHAR(100) CHARACTER SET NONE,
FILIAL VARCHAR(100) CHARACTER SET NONE)
AS 
BEGIN
  FOR
    SELECT
      FILIAL, DATA, CRM, MEDICO, ID_PRODUTO, CD_LABORATORIO, QUANTIDADE
    FROM
      CRM
    WHERE
      DATA >= :DATAINICIAL AND
      DATA <= :DATAFINAL AND
      FILIAL IS NOT NULL AND
      CRM IS NOT NULL AND
      CRM <> ''
    INTO
      :CD_FILIAL, :DATA, :CRM, :MEDICO, :ID_PRODUTO, :CD_LABORATORIO, :QUANTIDADE
  DO
   BEGIN
     SELECT NOME FROM FILIAIS WHERE CD_FILIAL = :CD_FILIAL INTO :FILIAL;
     SELECT DESCRICAO FROM PRODUTOS WHERE ID_PRODUTO = :ID_PRODUTO INTO :DESCRICAO;
     SELECT NOME FROM LABORATORIOS WHERE CD_LABORATORIO = :CD_LABORATORIO INTO :LABORATORIO;

     SUSPEND;
   END
END ^

ALTER PROCEDURE SP_OLAP_DESCONTO_PROMOCAO (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (DATA DATE,
FILIAL VARCHAR(100) CHARACTER SET NONE,
VENDEDOR VARCHAR(100) CHARACTER SET NONE,
CLASSE VARCHAR(100) CHARACTER SET NONE,
GRUPO VARCHAR(100) CHARACTER SET NONE,
LABORATORIO VARCHAR(100) CHARACTER SET NONE,
PRODUTO VARCHAR(100) CHARACTER SET NONE,
TOTALGERAL DOUBLE PRECISION,
TOTALDESCONTO DOUBLE PRECISION,
TOTALDESCONTOPBM DOUBLE PRECISION,
DESCONTOVALORPBM DOUBLE PRECISION,
DESCONTOPERCENTUALPBM DOUBLE PRECISION,
DESCONTOVALOR DOUBLE PRECISION,
DESCONTOPERCENTUAL DOUBLE PRECISION,
TOTALPROMOCAO DOUBLE PRECISION,
PROMOCAOVALOR DOUBLE PRECISION,
PROMOCAOPERCENTUAL DOUBLE PRECISION)
AS 
declare variable CD_FILIAL double precision;
declare variable CD_VENDEDOR double precision;
declare variable CD_CLASSE double precision;
declare variable CD_GRUPO double precision;
declare variable CD_LABORATORIO double precision;
declare variable ID_PRODUTO double precision;
declare variable TOTALGERALDEVOLUCOES double precision;
declare variable TOTALDESCONTODEVOLUCOES double precision;
declare variable DESCONTOVALORDEVOLUCOES double precision;
declare variable TOTALDESCONTODEVOLUCOESPBM double precision;
declare variable DESCONTOVALORDEVOLUCOESPBM double precision;
declare variable TOTALPROMOCAODEVOLUCOES double precision;
declare variable PROMOCAOVALORDEVOLUCOES double precision;
BEGIN
 FOR
  SELECT
   LANCAMENTOS.CD_FILIAL,
   LANCAMENTOS.CD_VENDEDOR,
   LANCAMENTOS.CD_CLASSE,
   LANCAMENTOS.CD_GRUPO,
   LANCAMENTOS.CD_LABORATORIO,
   LANCAMENTOS.ID_PRODUTO,
   LANCAMENTOS.DESCRICAO,
   LANCAMENTOS.DATA_LANCAMENTO
  FROM
   LANCAMENTOS
  WHERE
   LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
   LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
   ((LANCAMENTOS.TIPO_VENDA = 'V') OR (LANCAMENTOS.TIPO_VENDA = 'D')) /* AND
   LANCAMENTOS.CUSTO_UNITARIO > 0*/
  GROUP BY
   LANCAMENTOS.CD_FILIAL,
   LANCAMENTOS.CD_VENDEDOR,
   LANCAMENTOS.CD_CLASSE,
   LANCAMENTOS.CD_GRUPO,
   LANCAMENTOS.CD_LABORATORIO,
   LANCAMENTOS.ID_PRODUTO,
   LANCAMENTOS.DESCRICAO,
   LANCAMENTOS.DATA_LANCAMENTO
  INTO
   :CD_FILIAL,
   :CD_VENDEDOR,
   :CD_CLASSE,
   :CD_GRUPO,
   :CD_LABORATORIO,
   :ID_PRODUTO,
   :PRODUTO,
   :DATA
 DO
  BEGIN
    SELECT
      SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO + (LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE) + (LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE))
    FROM
      LANCAMENTOS
    WHERE
     LANCAMENTOS.DATA_LANCAMENTO = :DATA AND
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
     LANCAMENTOS.CD_GRUPO = :CD_GRUPO AND
     LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR AND
     LANCAMENTOS.TIPO_VENDA = 'V' AND
     LANCAMENTOS.CD_LABORATORIO = :CD_LABORATORIO AND
     LANCAMENTOS.ID_PRODUTO = :ID_PRODUTO /*AND
     LANCAMENTOS.CUSTO_UNITARIO > 0*/
    INTO
     :TOTALGERAL;

    SELECT
      SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO + (LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE) + (LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE))
    FROM
      LANCAMENTOS
    WHERE
     LANCAMENTOS.DATA_LANCAMENTO = :DATA AND
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
     LANCAMENTOS.CD_GRUPO = :CD_GRUPO AND
     LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR AND
     LANCAMENTOS.TIPO_VENDA = 'D' AND
     --LANCAMENTOS.TROCA = 'F' AND
     LANCAMENTOS.CD_LABORATORIO = :CD_LABORATORIO AND
     LANCAMENTOS.ID_PRODUTO = :ID_PRODUTO /*AND
     LANCAMENTOS.CUSTO_UNITARIO > 0*/
    INTO
     :TOTALGERALDEVOLUCOES;

    IF (:TOTALGERAL IS NULL) THEN
       TOTALGERAL = 0;
    IF (:TOTALGERALDEVOLUCOES IS NULL) THEN
       TOTALGERALDEVOLUCOES = 0;

    TOTALGERAL = :TOTALGERAL - :TOTALGERALDEVOLUCOES;

    SELECT
      SUM((LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO) + (LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)),
      SUM(LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)
    FROM
      LANCAMENTOS
    WHERE
     LANCAMENTOS.DATA_LANCAMENTO = :DATA AND
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
     LANCAMENTOS.CD_GRUPO = :CD_GRUPO AND
     LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR   AND
     LANCAMENTOS.TIPO_VENDA = 'V' AND
     LANCAMENTOS.CD_LABORATORIO = :CD_LABORATORIO AND
     LANCAMENTOS.ID_PRODUTO = :ID_PRODUTO AND
     LANCAMENTOS.DESCONTO IS NOT NULL AND
     LANCAMENTOS.DESCONTO > 0 AND
     (LANCAMENTOS.PROMOCAO IS NULL OR LANCAMENTOS.PROMOCAO = 0) AND
     --LANCAMENTOS.CUSTO_UNITARIO > 0 AND
     ((LANCAMENTOS.TRN IS NULL) OR (LANCAMENTOS.TRN = '') OR (LANCAMENTOS.TRN = '0') OR (LANCAMENTOS.TRN = 'N'))
    INTO
     :TOTALDESCONTO,
     :DESCONTOVALOR;

    SELECT
      SUM((LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO) + (LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)),
      SUM(LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)
    FROM
      LANCAMENTOS
    WHERE
     LANCAMENTOS.DATA_LANCAMENTO = :DATA AND
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
     LANCAMENTOS.CD_GRUPO = :CD_GRUPO AND
     LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR   AND
     LANCAMENTOS.TIPO_VENDA = 'D' AND
     --LANCAMENTOS.TROCA = 'F' AND
     LANCAMENTOS.CD_LABORATORIO = :CD_LABORATORIO AND
     LANCAMENTOS.ID_PRODUTO = :ID_PRODUTO AND
     LANCAMENTOS.DESCONTO IS NOT NULL AND
     LANCAMENTOS.DESCONTO > 0 AND
     (LANCAMENTOS.PROMOCAO IS NULL OR LANCAMENTOS.PROMOCAO = 0) AND
     --LANCAMENTOS.CUSTO_UNITARIO > 0 AND
     ((LANCAMENTOS.TRN IS NULL) OR (LANCAMENTOS.TRN = '') OR (LANCAMENTOS.TRN = '0') OR (LANCAMENTOS.TRN = 'N'))
    INTO
     :TOTALDESCONTODEVOLUCOES,
     :DESCONTOVALORDEVOLUCOES;

    IF (:TOTALDESCONTO IS NULL) THEN
       TOTALDESCONTO = 0;
    IF (:DESCONTOVALOR IS NULL) THEN
       DESCONTOVALOR = 0;
    IF (:TOTALDESCONTODEVOLUCOES IS NULL) THEN
       TOTALDESCONTODEVOLUCOES = 0;
    IF (:DESCONTOVALORDEVOLUCOES IS NULL) THEN
       DESCONTOVALORDEVOLUCOES = 0;

    TOTALDESCONTO = :TOTALDESCONTO - :TOTALDESCONTODEVOLUCOES;
    DESCONTOVALOR = :DESCONTOVALOR - :DESCONTOVALORDEVOLUCOES;

    IF (:TOTALDESCONTO > 0) THEN
     BEGIN
       DESCONTOPERCENTUAL = (:DESCONTOVALOR / :TOTALDESCONTO) * 100;
       IF (:DESCONTOPERCENTUAL IS NULL) THEN
          DESCONTOPERCENTUAL = 0;
     END
    ELSE
     BEGIN
      DESCONTOPERCENTUAL = 0;
     END

/* PBM */
    SELECT
      SUM((LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO) + (LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)),
      SUM(LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)
    FROM
      LANCAMENTOS
    WHERE
     LANCAMENTOS.DATA_LANCAMENTO = :DATA AND
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
     LANCAMENTOS.CD_GRUPO = :CD_GRUPO AND
     LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR   AND
     LANCAMENTOS.TIPO_VENDA = 'V' AND
     LANCAMENTOS.CD_LABORATORIO = :CD_LABORATORIO AND
     LANCAMENTOS.ID_PRODUTO = :ID_PRODUTO AND
     LANCAMENTOS.DESCONTO IS NOT NULL AND
     LANCAMENTOS.DESCONTO > 0 AND
     (LANCAMENTOS.PROMOCAO IS NULL OR LANCAMENTOS.PROMOCAO = 0) AND
     --LANCAMENTOS.CUSTO_UNITARIO > 0 AND
     LANCAMENTOS.TRN IS NOT NULL AND
     LANCAMENTOS.TRN <> '' AND
     LANCAMENTOS.TRN <> 'N'
    INTO
     :TOTALDESCONTOPBM,
     :DESCONTOVALORPBM;

    SELECT
      SUM((LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO) + (LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)),
      SUM(LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE)
    FROM
      LANCAMENTOS
    WHERE
     LANCAMENTOS.DATA_LANCAMENTO = :DATA AND
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
     LANCAMENTOS.CD_GRUPO = :CD_GRUPO AND
     LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR   AND
     LANCAMENTOS.TIPO_VENDA = 'D' AND
     --LANCAMENTOS.TROCA = 'F' AND
     LANCAMENTOS.CD_LABORATORIO = :CD_LABORATORIO AND
     LANCAMENTOS.ID_PRODUTO = :ID_PRODUTO AND
     LANCAMENTOS.DESCONTO IS NOT NULL AND
     LANCAMENTOS.DESCONTO > 0 AND
     (LANCAMENTOS.PROMOCAO IS NULL OR LANCAMENTOS.PROMOCAO = 0) AND
     --LANCAMENTOS.CUSTO_UNITARIO > 0 AND
     LANCAMENTOS.TRN IS NOT NULL AND
     LANCAMENTOS.TRN <> '' AND
     LANCAMENTOS.TRN <> 'N'
    INTO
     :TOTALDESCONTODEVOLUCOESPBM,
     :DESCONTOVALORDEVOLUCOESPBM;

    IF (:TOTALDESCONTOPBM IS NULL) THEN
       TOTALDESCONTOPBM = 0;
    IF (:DESCONTOVALORPBM IS NULL) THEN
       DESCONTOVALORPBM = 0;
    IF (:TOTALDESCONTODEVOLUCOESPBM IS NULL) THEN
       TOTALDESCONTODEVOLUCOESPBM = 0;
    IF (:DESCONTOVALORDEVOLUCOESPBM IS NULL) THEN
       DESCONTOVALORDEVOLUCOESPBM = 0;

    TOTALDESCONTOPBM = :TOTALDESCONTOPBM - :TOTALDESCONTODEVOLUCOESPBM;
    DESCONTOVALORPBM = :DESCONTOVALORPBM - :DESCONTOVALORDEVOLUCOESPBM;

    IF (:TOTALDESCONTOPBM > 0) THEN
     BEGIN
       DESCONTOPERCENTUALPBM = (:DESCONTOVALORPBM / :TOTALDESCONTOPBM) * 100;
       IF (:DESCONTOPERCENTUALPBM IS NULL) THEN
          DESCONTOPERCENTUALPBM = 0;
     END
    ELSE
     BEGIN
      DESCONTOPERCENTUALPBM = 0;
     END
/* PBM */

    SELECT
      SUM((LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO) + (LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)),
      SUM(LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)
    FROM
      LANCAMENTOS
    WHERE
     LANCAMENTOS.DATA_LANCAMENTO = :DATA AND
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
     LANCAMENTOS.CD_GRUPO = :CD_GRUPO AND
     LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR   AND
     LANCAMENTOS.TIPO_VENDA = 'V' AND
     LANCAMENTOS.CD_LABORATORIO = :CD_LABORATORIO AND
     LANCAMENTOS.ID_PRODUTO = :ID_PRODUTO AND
     LANCAMENTOS.PROMOCAO IS NOT NULL AND
     LANCAMENTOS.PROMOCAO > 0 /*AND
     LANCAMENTOS.CUSTO_UNITARIO > 0*/
    INTO
     :TOTALPROMOCAO,
     :PROMOCAOVALOR;
  
    SELECT
      SUM((LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO) + (LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)),
      SUM(LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)
    FROM
      LANCAMENTOS
    WHERE
     LANCAMENTOS.DATA_LANCAMENTO = :DATA AND
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
     LANCAMENTOS.CD_GRUPO = :CD_GRUPO AND
     LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR   AND
     LANCAMENTOS.TIPO_VENDA = 'D' AND
     --LANCAMENTOS.TROCA = 'F' AND
     LANCAMENTOS.CD_LABORATORIO = :CD_LABORATORIO AND
     LANCAMENTOS.ID_PRODUTO = :ID_PRODUTO AND
     LANCAMENTOS.PROMOCAO IS NOT NULL AND
     LANCAMENTOS.PROMOCAO > 0/* AND
     LANCAMENTOS.CUSTO_UNITARIO > 0*/
    INTO
     :TOTALPROMOCAODEVOLUCOES,
     :PROMOCAOVALORDEVOLUCOES;

    IF (:TOTALPROMOCAO IS NULL) THEN
       TOTALPROMOCAO = 0;
    IF (:PROMOCAOVALOR IS NULL) THEN
       PROMOCAOVALOR = 0;
    IF (:TOTALPROMOCAODEVOLUCOES IS NULL) THEN
       TOTALPROMOCAODEVOLUCOES = 0;
    IF (:PROMOCAOVALORDEVOLUCOES IS NULL) THEN
       PROMOCAOVALORDEVOLUCOES = 0;

    TOTALPROMOCAO = :TOTALPROMOCAO - :TOTALPROMOCAODEVOLUCOES;
    PROMOCAOVALOR = :PROMOCAOVALOR - :PROMOCAOVALORDEVOLUCOES;

    IF (:TOTALPROMOCAO > 0) THEN
     BEGIN
       PROMOCAOPERCENTUAL = (:PROMOCAOVALOR / :TOTALPROMOCAO) * 100;
       IF (:PROMOCAOPERCENTUAL IS NULL) THEN
          PROMOCAOPERCENTUAL = 0;
     END
    ELSE
     BEGIN
       PROMOCAOPERCENTUAL = 0;
     END
  
   SELECT NOME FROM FILIAIS WHERE CD_FILIAL = :CD_FILIAL INTO :FILIAL;
   SELECT NOME FROM VENDEDORES WHERE CD_VENDEDOR = :CD_VENDEDOR INTO :VENDEDOR;
   SELECT DESCRICAO FROM CLASSES WHERE CD_CLASSE = :CD_CLASSE INTO :CLASSE;
   SELECT DESCRICAO FROM GRUPOS WHERE CD_GRUPO = :CD_GRUPO INTO GRUPO;
   SELECT NOME FROM LABORATORIOS WHERE CD_LABORATORIO = :CD_LABORATORIO INTO :LABORATORIO;
   SUSPEND;
  END
END ^

ALTER PROCEDURE SP_OLAP_DEVOLUCOES_PRODUTO (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (FILIAL VARCHAR(100) CHARACTER SET NONE,
PRODUTO VARCHAR(100) CHARACTER SET NONE,
DIA DATE,
QUANTIDADE_VENDIDA DOUBLE PRECISION,
VALOR_VENDAS DOUBLE PRECISION,
CUSTO_DAS_VENDAS DOUBLE PRECISION,
COMISSAO DOUBLE PRECISION,
DESCONTO DOUBLE PRECISION,
PROMOCAO DOUBLE PRECISION)
AS 
DECLARE VARIABLE CD_FILIAL DOUBLE PRECISION;
BEGIN
 FOR
    SELECT
     LANCAMENTOS.CD_FILIAL,
     LANCAMENTOS.DESCRICAO,
     LANCAMENTOS.DATA_CAIXA,
     SUM(LANCAMENTOS.QUANTIDADE),
     SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
     SUM(LANCAMENTOS.CUSTO_UNITARIO),
     SUM(LANCAMENTOS.COMISSAO),
     SUM(LANCAMENTOS.DESCONTO),
     SUM(LANCAMENTOS.PROMOCAO)
    FROM
     LANCAMENTOS
    WHERE
     LANCAMENTOS.DATA_CAIXA >= :DATAINICIAL AND
     LANCAMENTOS.DATA_CAIXA <= :DATAFINAL AND
     LANCAMENTOS.TIPO_VENDA = 'D' AND
     LANCAMENTOS.CUSTO_UNITARIO > 0
    GROUP BY
     LANCAMENTOS.CD_FILIAL,
     LANCAMENTOS.DESCRICAO,
     LANCAMENTOS.DATA_CAIXA
    INTO
     :CD_FILIAL,
     :PRODUTO,
     :DIA,
     :QUANTIDADE_VENDIDA,
     :VALOR_VENDAS,
     :CUSTO_DAS_VENDAS,
     :COMISSAO,
     :DESCONTO,
     :PROMOCAO
 DO
  BEGIN
      SELECT NOME FROM FILIAIS WHERE CD_FILIAL = :CD_FILIAL INTO :FILIAL;
      SUSPEND;
  END
END ^

ALTER PROCEDURE SP_OLAP_DISTRIBUICAO_ESTOQUES RETURNS (DATA DATE,
FILIAL VARCHAR(100) CHARACTER SET NONE,
GRUPO VARCHAR(100) CHARACTER SET NONE,
LABORATORIO VARCHAR(100) CHARACTER SET NONE,
CLASSE VARCHAR(100) CHARACTER SET NONE,
PRECO_CUSTO DOUBLE PRECISION,
PRECO_VENDA DOUBLE PRECISION,
ITENS INTEGER,
ESTOQUE DOUBLE PRECISION)
AS 
DECLARE VARIABLE CD_FILIAL INTEGER;
DECLARE VARIABLE CD_GRUPO DOUBLE PRECISION;
DECLARE VARIABLE CD_LABORATORIO DOUBLE PRECISION;
DECLARE VARIABLE CD_CLASSE DOUBLE PRECISION;
DECLARE VARIABLE COMANDO VARCHAR(1000);
BEGIN
 DATA = CURRENT_DATE;
 FOR
    SELECT
     FILIAIS.CD_FILIAL,
     FILIAIS.NOME
    FROM
     FILIAIS
    INTO
     :CD_FILIAL,
     :FILIAL

 DO
  BEGIN
      COMANDO = 'SELECT CD_CLASSE, CD_GRUPO, CD_LABORATORIO, '||
                ' SUM(ESTOQUE_'||CAST(:CD_FILIAL AS INTEGER)||'), '||
                ' SUM(CUSTO_UNITARIO_'||CAST(:CD_FILIAL AS INTEGER)||' * ESTOQUE_'||CAST(:CD_FILIAL AS INTEGER)||'), '||
                ' SUM(PRECO_VENDA_'||CAST(:CD_FILIAL AS INTEGER)||' * ESTOQUE_'||CAST(:CD_FILIAL AS INTEGER)||'), '||
                ' COUNT(ID_PRODUTO) '||
                ' FROM PRODUTOS ' ||
                ' GROUP BY CD_CLASSE, CD_GRUPO, CD_LABORATORIO ';
      FOR
          EXECUTE STATEMENT :COMANDO INTO :CD_CLASSE, :CD_GRUPO, :CD_LABORATORIO, :ESTOQUE, :PRECO_CUSTO, :PRECO_VENDA, :ITENS
      DO
        BEGIN
          SELECT DESCRICAO FROM CLASSES WHERE CD_CLASSE = :CD_CLASSE INTO :CLASSE;
          SELECT DESCRICAO FROM GRUPOS WHERE CD_GRUPO = :CD_GRUPO INTO :GRUPO;
          SELECT NOME FROM LABORATORIOS WHERE CD_LABORATORIO = :CD_LABORATORIO INTO :LABORATORIO;
          SUSPEND;
        END
  END
END ^

ALTER PROCEDURE SP_OLAP_ESTOQUE (DATAPESQUISA DATE,
CODIGOFILIAL DOUBLE PRECISION)
RETURNS (CD_FILIAL DOUBLE PRECISION,
FILIAL VARCHAR(100) CHARACTER SET NONE,
DATA DATE,
ID_PRODUTO DOUBLE PRECISION,
QUANTIDADE DOUBLE PRECISION,
VENDA DOUBLE PRECISION,
CUSTO DOUBLE PRECISION,
TOTALVENDA DOUBLE PRECISION,
TOTALCUSTO DOUBLE PRECISION,
DESCRICAO VARCHAR(100) CHARACTER SET NONE,
CLASSE VARCHAR(100) CHARACTER SET NONE,
GRUPO VARCHAR(100) CHARACTER SET NONE)
AS 
declare variable CD_GRUPO double precision;
declare variable CD_CLASSE double precision;
BEGIN
  FOR
    SELECT
     POSICAOESTOQUEDATA.CD_FILIAL,
     POSICAOESTOQUEDATA.DATA,
     POSICAOESTOQUEDATA.ID_PRODUTO,
     POSICAOESTOQUEDATA.QUANTIDADE,
     POSICAOESTOQUEDATA.VENDA,
     POSICAOESTOQUEDATA.CUSTO,
     SUM(POSICAOESTOQUEDATA.VENDA * POSICAOESTOQUEDATA.QUANTIDADE),
     SUM(POSICAOESTOQUEDATA.CUSTO * POSICAOESTOQUEDATA.QUANTIDADE)
    FROM
     POSICAOESTOQUEDATA
    WHERE
     POSICAOESTOQUEDATA.DATA = :DATAPESQUISA AND
     POSICAOESTOQUEDATA.CD_FILIAL = :CODIGOFILIAL
    GROUP BY
     POSICAOESTOQUEDATA.CD_FILIAL,
     POSICAOESTOQUEDATA.DATA,
     POSICAOESTOQUEDATA.ID_PRODUTO,
     POSICAOESTOQUEDATA.QUANTIDADE,
     POSICAOESTOQUEDATA.VENDA,
     POSICAOESTOQUEDATA.CUSTO
    INTO
     :CD_FILIAL,
     :DATA,
     :ID_PRODUTO,
     :QUANTIDADE,
     :VENDA,
     :CUSTO,
     :TOTALVENDA,
     :TOTALCUSTO
  DO
   BEGIN
/*     IF (:QUANTIDADE < 0) THEN
      BEGIN
        QUANTIDADE = 0;
        TOTALCUSTO = 0;
        TOTALVENDA = 0;
      END*/
     SELECT NOME FROM FILIAIS WHERE CD_FILIAL = :CD_FILIAL INTO :FILIAL;
     SELECT DESCRICAO, CD_GRUPO, CD_CLASSE FROM PRODUTOS WHERE ID_PRODUTO = :ID_PRODUTO INTO :DESCRICAO, :CD_GRUPO, :CD_CLASSE;
     SELECT DESCRICAO FROM GRUPOS WHERE CD_GRUPO = :CD_GRUPO INTO :GRUPO;
     SELECT DESCRICAO FROM CLASSES WHERE CD_CLASSE = :CD_CLASSE INTO :CLASSE;
     SUSPEND;
   END


END ^

ALTER PROCEDURE SP_OLAP_MOVIMENTO_FUNCIONARIO (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (FILIAL VARCHAR(100) CHARACTER SET NONE,
DATA DATE,
VENDEDOR VARCHAR(100) CHARACTER SET NONE,
FUNCAO VARCHAR(100) CHARACTER SET NONE,
COMISSAOVENDA DOUBLE PRECISION,
QUANTIDADEVENDA DOUBLE PRECISION,
VALORVENDA DOUBLE PRECISION,
NUMEROVENDAS DOUBLE PRECISION,
FIDELIDADEVENDA DOUBLE PRECISION,
CRMVENDA DOUBLE PRECISION,
TICKETMEDIO DOUBLE PRECISION,
FIDELIDADE INTEGER,
VALORCAIXA DOUBLE PRECISION)
AS 
declare variable CD_FILIAL double precision;
declare variable CD_VENDEDOR double precision;
declare variable COMISSAOCANCELAMENTO double precision;
declare variable VALORCANCELAMENTO double precision;
declare variable QUANTIDADECANCELAMENTO double precision;
declare variable FIDELIDADECANCELAMENTO double precision;
declare variable CRMCANCELAMENTO double precision;
declare variable NUMEROCANCELAMENTOS double precision;
declare variable VALORCAIXACANCELAMENTO double precision;
declare variable FIDELIDADE_LANCAMENTOS integer;
declare variable FIDELIDADE_CAIXA integer;
BEGIN
  FOR
    SELECT FILIAIS.CD_FILIAL FROM FILIAIS WHERE STATUS = 'A' INTO :CD_FILIAL
  DO
   BEGIN
      FOR
        SELECT CD_VENDEDOR FROM VENDEDORES WHERE CD_FILIAL = :CD_FILIAL AND STATUS = 'A' INTO :CD_VENDEDOR
      DO
       BEGIN
         DATA = :DATAINICIAL;
         WHILE (:DATA <= :DATAFINAL) DO
          BEGIN
              FIDELIDADE = 0;
              VALORCAIXA = 0;
              COMISSAOVENDA = 0;
              VALORVENDA = 0;
              QUANTIDADEVENDA = 0;
              FIDELIDADEVENDA = 0;
              CRMVENDA = 0;
              NUMEROVENDAS = 0;
              TICKETMEDIO = 0;
              FIDELIDADE = 0;
              FIDELIDADE_LANCAMENTOS = 0;
              FIDELIDADE_CAIXA = 0;

              NUMEROCANCELAMENTOS = 0;
              COMISSAOCANCELAMENTO = 0;
              QUANTIDADECANCELAMENTO = 0;
              VALORCANCELAMENTO = 0;

              -- VENDAS
              SELECT
               COUNT(DISTINCT LANCAMENTOS.CD_VENDA),
               SUM(LANCAMENTOS.COMISSAO),
               SUM(LANCAMENTOS.QUANTIDADE),
               SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO)
              FROM
               LANCAMENTOS
              WHERE
               LANCAMENTOS.DATA_LANCAMENTO = :DATA AND
               LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
               LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR AND
               LANCAMENTOS.TIPO_VENDA = 'V'
              INTO
               :NUMEROVENDAS,
               :COMISSAOVENDA,
               :QUANTIDADEVENDA,
               :VALORVENDA;
        
              IF (:NUMEROVENDAS IS NULL) THEN
                 NUMEROVENDAS = 0;
              IF (:COMISSAOVENDA IS NULL) THEN
                 COMISSAOVENDA = 0;
              IF (:QUANTIDADEVENDA IS NULL) THEN
                 QUANTIDADEVENDA = 0;
              IF (:VALORVENDA IS NULL) THEN
                 VALORVENDA = 0;
    
              -- CANCELAMENTOS
              SELECT
               COUNT(DISTINCT LANCAMENTOS.CD_VENDA),
               SUM(LANCAMENTOS.COMISSAO),
               SUM(LANCAMENTOS.QUANTIDADE),
               SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO)
              FROM
               LANCAMENTOS
              WHERE
               LANCAMENTOS.DATA_LANCAMENTO = :DATA AND
               LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
               LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR AND
               LANCAMENTOS.TIPO_VENDA = 'D' AND
               LANCAMENTOS.TROCA = 'F'
              INTO
               :NUMEROCANCELAMENTOS,
               :COMISSAOCANCELAMENTO,
               :QUANTIDADECANCELAMENTO,
               :VALORCANCELAMENTO;
        
              IF (:NUMEROCANCELAMENTOS IS NULL) THEN
                 NUMEROCANCELAMENTOS = 0;
              IF (:COMISSAOCANCELAMENTO IS NULL) THEN
                 COMISSAOCANCELAMENTO = 0;
              IF (:QUANTIDADECANCELAMENTO IS NULL) THEN
                 QUANTIDADECANCELAMENTO = 0;
              IF (:VALORCANCELAMENTO IS NULL) THEN
                 VALORCANCELAMENTO = 0;
        
              NUMEROVENDAS = :NUMEROVENDAS - :NUMEROCANCELAMENTOS;
              COMISSAOVENDA = :COMISSAOVENDA - :COMISSAOCANCELAMENTO;
              QUANTIDADEVENDA = :QUANTIDADEVENDA - :QUANTIDADECANCELAMENTO;
              VALORVENDA = :VALORVENDA - :VALORCANCELAMENTO;

              -- FIDELIDADE VENDAS
              SELECT
               SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO)
              FROM
               LANCAMENTOS, CLIENTES
              WHERE
               LANCAMENTOS.CD_CLIENTE = CLIENTES.CD_CLIENTE AND
               LANCAMENTOS.DATA_LANCAMENTO = :DATA AND
               LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
               LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR AND
               LANCAMENTOS.TIPO_VENDA = 'V' AND
               CLIENTES.CARTAOFIDELIDADE IS NOT NULL AND
               TRIM(CLIENTES.CARTAOFIDELIDADE) <> ''
              INTO
               :FIDELIDADEVENDA;
        
              IF (:FIDELIDADEVENDA IS NULL) THEN
                 FIDELIDADEVENDA = 0;
    
              -- FIDELIDADE CANCELAMENTOS
              SELECT
               SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO)
              FROM
               LANCAMENTOS, CLIENTES
              WHERE
               LANCAMENTOS.DATA_LANCAMENTO = :DATA AND
               LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
               LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR AND
               LANCAMENTOS.TIPO_VENDA = 'D' AND
               LANCAMENTOS.TROCA = 'F' AND
               LANCAMENTOS.CD_CLIENTE = CLIENTES.CD_CLIENTE AND
               CLIENTES.CARTAOFIDELIDADE IS NOT NULL AND
               TRIM(CLIENTES.CARTAOFIDELIDADE) <> ''
              INTO
               :FIDELIDADECANCELAMENTO;
        
              IF (:FIDELIDADECANCELAMENTO IS NULL) THEN
                 FIDELIDADECANCELAMENTO = 0;
        
              FIDELIDADEVENDA = :FIDELIDADEVENDA - :FIDELIDADECANCELAMENTO;

                -- CRM VENDAS
              SELECT 
               COUNT(CRM.CRM)
              FROM
               CRM
              WHERE
               CRM.DATA = :DATA AND
               CRM.CD_FILIAL = :CD_FILIAL AND
               CRM.CD_VENDEDOR = :CD_VENDEDOR
               INTO
                 :CRMVENDA;
      
              IF (:CRMVENDA IS NULL) THEN
                CRMVENDA = 0;
      
              TICKETMEDIO = 0;
              IF (:NUMEROVENDAS > 0) THEN
                TICKETMEDIO = :VALORVENDA / :NUMEROVENDAS;

              SELECT FILIAIS.NOME FROM FILIAIS
              WHERE FILIAIS.CD_FILIAL = :CD_FILIAL
              INTO :FILIAL;
    
              SELECT VENDEDORES.NOME
              FROM VENDEDORES
              WHERE VENDEDORES.CD_VENDEDOR = :CD_VENDEDOR
              INTO :VENDEDOR;

              FUNCAO = 'VENDEDOR';

              SUSPEND;

              FIDELIDADE = 0;
              VALORCAIXA = 0;
              COMISSAOVENDA = 0;
              VALORVENDA = 0;
              QUANTIDADEVENDA = 0;
              FIDELIDADEVENDA = 0;
              CRMVENDA = 0;
              NUMEROVENDAS = 0;
              TICKETMEDIO = 0;
              FIDELIDADE = 0;
              FIDELIDADE_LANCAMENTOS = 0;
              FIDELIDADE_CAIXA = 0;

              NUMEROCANCELAMENTOS = 0;
              COMISSAOCANCELAMENTO = 0;
              QUANTIDADECANCELAMENTO = 0;
              VALORCANCELAMENTO = 0;

              SELECT SUM(CAIXA.VALOR)
              FROM CAIXA
              WHERE
                CAIXA.DATA_CAIXA = :DATA AND
                CAIXA.CD_FILIAL = :CD_FILIAL AND
                CAIXA.CD_OPERADOR = :CD_VENDEDOR AND
                CAIXA.TIPO_VENDA = 'V'
              INTO :VALORCAIXA;
    
              IF (:VALORCAIXA IS NULL) THEN
                 VALORCAIXA = 0;
    
              SELECT SUM(CAIXA.VALOR)
              FROM CAIXA
              WHERE
                CAIXA.DATA_CAIXA = :DATA AND
                CAIXA.CD_FILIAL = :CD_FILIAL AND
                CAIXA.CD_OPERADOR = :CD_VENDEDOR AND
                CAIXA.TIPO_VENDA = 'D'
              INTO :VALORCAIXACANCELAMENTO;
    
              IF (:VALORCAIXACANCELAMENTO IS NULL) THEN
                 VALORCAIXACANCELAMENTO = 0;
    
              VALORCAIXA = :VALORCAIXA - :VALORCAIXACANCELAMENTO;

              SELECT FILIAIS.NOME FROM FILIAIS
              WHERE FILIAIS.CD_FILIAL = :CD_FILIAL
              INTO :FILIAL;
    
              SELECT VENDEDORES.NOME
              FROM VENDEDORES
              WHERE VENDEDORES.CD_VENDEDOR = :CD_VENDEDOR
              INTO :VENDEDOR;
    
              FUNCAO = 'OPERADOR DE CAIXA';

             SELECT COUNT(*) FROM CLIENTES
             WHERE DATA_FICHA = :DATA AND CD_VENDEDOR = :CD_VENDEDOR AND CARTAOFIDELIDADE IS NOT NULL AND TRIM(CARTAOFIDELIDADE) <> ''
             INTO :FIDELIDADE;

             SUSPEND;

             DATA = :DATA + 1;
          END
       END
   END
END ^

ALTER PROCEDURE SP_OLAP_NCM (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (FILIAL VARCHAR(100) CHARACTER SET NONE,
DATA DATE,
NCM VARCHAR(10) CHARACTER SET NONE,
ICMS VARCHAR(4) CHARACTER SET NONE,
CFOP DOUBLE PRECISION,
GRUPO VARCHAR(100) CHARACTER SET NONE,
LABORATORIO VARCHAR(100) CHARACTER SET NONE,
CLASSE VARCHAR(100) CHARACTER SET NONE,
PRODUTO VARCHAR(100) CHARACTER SET NONE,
QUANTIDADE DOUBLE PRECISION,
VALOR DOUBLE PRECISION,
CUSTO DOUBLE PRECISION,
LUCRO DOUBLE PRECISION,
MARGEM DOUBLE PRECISION)
AS 
declare variable QUANTIDADE_C double precision;
declare variable VALOR_C double precision;
declare variable CUSTO_C double precision;
declare variable LUCRO_C double precision;
declare variable MARGEM_C double precision;
declare variable CD_FILIAL double precision;
declare variable CD_GRUPO double precision;
declare variable CD_LABORATORIO double precision;
declare variable ID_PRODUTO double precision;
declare variable CD_CLASSE double precision;
BEGIN
 FOR
    SELECT
     LANCAMENTOS.DATA_LANCAMENTO,
     LANCAMENTOS.CD_FILIAL,
     LANCAMENTOS.CD_GRUPO,
     LANCAMENTOS.ID_PRODUTO,
     LANCAMENTOS.CD_LABORATORIO,
     LANCAMENTOS.CD_CLASSE,
     PRODUTOS.NCM,
     PRODUTOS.ICMS,
     PRODUTOS.CD_CFOP, 
     PRODUTOS.DESCRICAO
    FROM
     LANCAMENTOS,
     PRODUTOS
    WHERE
     LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
     LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
     (LANCAMENTOS.TIPO_VENDA = 'D' OR LANCAMENTOS.TIPO_VENDA = 'V') AND
     LANCAMENTOS.ID_PRODUTO = PRODUTOS.ID_PRODUTO
    GROUP BY
     LANCAMENTOS.DATA_LANCAMENTO,
     LANCAMENTOS.CD_FILIAL, 
     LANCAMENTOS.CD_GRUPO,
     LANCAMENTOS.ID_PRODUTO,
     LANCAMENTOS.CD_LABORATORIO,
     LANCAMENTOS.CD_CLASSE,
     PRODUTOS.NCM,
     PRODUTOS.ICMS,
     PRODUTOS.CD_CFOP, 
     PRODUTOS.DESCRICAO
    INTO
     :DATA,
     :CD_FILIAL,
     :CD_GRUPO,
     :ID_PRODUTO,
     :CD_LABORATORIO,
     :CD_CLASSE,
     :NCM,
     :ICMS,
     :CFOP,
     :PRODUTO
 DO
  BEGIN
    QUANTIDADE = 0;
    VALOR = 0;
    CUSTO = 0;
    LUCRO = 0;
    MARGEM = 0;

    SELECT
      SUM(LANCAMENTOS.QUANTIDADE),
      SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
      SUM(LANCAMENTOS.CUSTO_MEDIO * LANCAMENTOS.QUANTIDADE),
      SUM((LANCAMENTOS.VALOR / LANCAMENTOS.QUANTIDADE) -  LANCAMENTOS.CUSTO_MEDIO),
      SUM((((LANCAMENTOS.VALOR / LANCAMENTOS.QUANTIDADE) - LANCAMENTOS.CUSTO_MEDIO)  * 100) / LANCAMENTOS.CUSTO_MEDIO)
    FROM
      LANCAMENTOS
    WHERE
     LANCAMENTOS.DATA_LANCAMENTO = :DATA AND
     LANCAMENTOS.CD_FILIAL  = :CD_FILIAL AND
     LANCAMENTOS.CD_LABORATORIO = :CD_LABORATORIO AND
     LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
     LANCAMENTOS.TIPO_VENDA = 'V' AND
     LANCAMENTOS.CD_GRUPO = :CD_GRUPO AND
     LANCAMENTOS.ID_PRODUTO = :ID_PRODUTO AND
     --LANCAMENTOS.CUSTO_MEDIO > 0 AND
     LANCAMENTOS.QUANTIDADE > 0
    INTO
     :QUANTIDADE,
     :VALOR,
     :CUSTO,
     :LUCRO,
     :MARGEM;

    IF (:QUANTIDADE IS NULL) THEN
        QUANTIDADE = 0;
    IF (:VALOR IS NULL) THEN
        VALOR = 0;
    IF (:CUSTO IS NULL) THEN
        CUSTO = 0;
    IF (:LUCRO IS NULL) THEN
        LUCRO = 0;
    IF (:MARGEM IS NULL) THEN
        MARGEM = 0;

    QUANTIDADE_C = 0;
    VALOR_C = 0;
    CUSTO_C = 0;
    LUCRO_C = 0;
    MARGEM_C = 0;

    SELECT
     SUM(LANCAMENTOS.QUANTIDADE),
     SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
     SUM(LANCAMENTOS.CUSTO_MEDIO * LANCAMENTOS.QUANTIDADE),
     SUM((LANCAMENTOS.VALOR / LANCAMENTOS.QUANTIDADE) -  LANCAMENTOS.CUSTO_MEDIO),
     SUM((((LANCAMENTOS.VALOR / LANCAMENTOS.QUANTIDADE) - LANCAMENTOS.CUSTO_MEDIO)  * 100) / LANCAMENTOS.CUSTO_MEDIO)
    FROM
     LANCAMENTOS
    WHERE
     LANCAMENTOS.DATA_LANCAMENTO = :DATA AND
     LANCAMENTOS.CD_FILIAL  = :CD_FILIAL AND
     LANCAMENTOS.CD_LABORATORIO = :CD_LABORATORIO AND
     LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
     LANCAMENTOS.TIPO_VENDA = 'D' AND
     --LANCAMENTOS.TROCA = 'F' AND
     LANCAMENTOS.CD_GRUPO = :CD_GRUPO AND
     LANCAMENTOS.ID_PRODUTO = :ID_PRODUTO AND
     --LANCAMENTOS.CUSTO_MEDIO > 0 AND
     LANCAMENTOS.QUANTIDADE > 0
    INTO
     :QUANTIDADE_C,
     :VALOR_C,
     :CUSTO_C,
     :LUCRO_C,
     :MARGEM_C;

     IF (:QUANTIDADE_C IS NULL) THEN
         QUANTIDADE_C = 0;
     IF (:VALOR_C IS NULL) THEN
         VALOR_C = 0;
     IF (:CUSTO_C IS NULL) THEN
         CUSTO_C = 0;
     IF (:LUCRO_C IS NULL) THEN
         LUCRO_C = 0;
     IF (:MARGEM_C IS NULL) THEN
         MARGEM_C = 0;

     QUANTIDADE = :QUANTIDADE - :QUANTIDADE_C;
     VALOR = :VALOR - :VALOR_C;
     CUSTO = :CUSTO - :CUSTO_C;
     LUCRO = :LUCRO - :LUCRO_C;
     MARGEM = :MARGEM - :MARGEM_C;

     SELECT NOME FROM FILIAIS WHERE CD_FILIAL = :CD_FILIAL INTO :FILIAL;
     SELECT DESCRICAO FROM GRUPOS WHERE CD_GRUPO = :CD_GRUPO INTO :GRUPO;
     SELECT NOME FROM LABORATORIOS WHERE CD_LABORATORIO = :CD_LABORATORIO INTO :LABORATORIO;
     SELECT DESCRICAO FROM CLASSES WHERE CD_CLASSE = :CD_CLASSE INTO :CLASSE;
     /*IF (:VALOR > 0) THEN*/
        SUSPEND;
  END
END ^

ALTER PROCEDURE SP_OLAP_RESULTADO_ESTOQUE (DATA_INICIAL DATE,
DATA_FINAL DATE)
RETURNS (CD_FILIAL DOUBLE PRECISION,
FILIAL VARCHAR(100) CHARACTER SET NONE,
CD_CLASSE DOUBLE PRECISION,
CLASSE VARCHAR(100) CHARACTER SET NONE,
CD_GRUPO DOUBLE PRECISION,
GRUPO VARCHAR(100) CHARACTER SET NONE,
VENDAS DOUBLE PRECISION,
DEVOLUCOES DOUBLE PRECISION,
COMPRAS DOUBLE PRECISION,
TRANSFERENCIAS_ENTRADA DOUBLE PRECISION,
TRANSFERENCIAS_SAIDA DOUBLE PRECISION,
CP_TR DOUBLE PRECISION,
POSICAO_INICIAL DOUBLE PRECISION,
POSICAO_FINAL DOUBLE PRECISION,
EVOLUCAO_ESTOQUE DOUBLE PRECISION,
LUCRO_BRUTO DOUBLE PRECISION,
PERCENTUAL_LUCRO_BRUTO DOUBLE PRECISION)
AS 
BEGIN
  FOR
    SELECT
      CD_FILIAL
    FROM
      FILIAIS
    INTO
      :CD_FILIAL
  DO
   BEGIN
      FOR
        SELECT
         PRODUTOS.CD_CLASSE,
         PRODUTOS.CD_GRUPO
        FROM
         PRODUTOS
        GROUP BY
         PRODUTOS.CD_CLASSE,
         PRODUTOS.CD_GRUPO
        INTO
         :CD_CLASSE,
         :CD_GRUPO
      DO
       BEGIN
         SELECT
          SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO)
         FROM
          LANCAMENTOS
         WHERE
          LANCAMENTOS.DATA_LANCAMENTO >= :DATA_INICIAL AND
          LANCAMENTOS.DATA_LANCAMENTO <= :DATA_FINAL AND
          LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
          LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
          LANCAMENTOS.CD_GRUPO = :CD_GRUPO AND
          LANCAMENTOS.TIPO_VENDA = 'V'
         INTO
          :VENDAS;
    
         SELECT
          SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO)
         FROM
          LANCAMENTOS
         WHERE
          LANCAMENTOS.DATA_LANCAMENTO >= :DATA_INICIAL AND
          LANCAMENTOS.DATA_LANCAMENTO <= :DATA_FINAL AND
          LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
          LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
          LANCAMENTOS.CD_GRUPO = :CD_GRUPO AND
          LANCAMENTOS.TIPO_VENDA = 'D'
         INTO
          :DEVOLUCOES;
    
         IF (:VENDAS IS NULL) THEN
            VENDAS = 0;
         IF (:DEVOLUCOES IS NULL) THEN
            DEVOLUCOES = 0;
         VENDAS = :VENDAS - :DEVOLUCOES;
    
         SELECT
          SUM(LANCAMENTOS.VALOR)
         FROM
          LANCAMENTOS
         WHERE
          LANCAMENTOS.DATA_LANCAMENTO >= :DATA_INICIAL AND
          LANCAMENTOS.DATA_LANCAMENTO <= :DATA_FINAL AND
          LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
          LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
          LANCAMENTOS.CD_GRUPO = :CD_GRUPO AND
          LANCAMENTOS.TIPO_VENDA = 'C'
         INTO
          :COMPRAS;
    
         SELECT
          SUM(LANCAMENTOS.VALOR)
         FROM
          LANCAMENTOS
         WHERE
          LANCAMENTOS.DATA_LANCAMENTO >= :DATA_INICIAL AND
          LANCAMENTOS.DATA_LANCAMENTO <= :DATA_FINAL AND
          LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
          LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
          LANCAMENTOS.CD_GRUPO = :CD_GRUPO AND
          LANCAMENTOS.TIPO_VENDA = 'T' AND
          LANCAMENTOS.ENTRADA_SAIDA = 'E'
         INTO
          :TRANSFERENCIAS_ENTRADA;
    
         IF (:COMPRAS IS NULL) THEN
            COMPRAS = 0;
         IF (:TRANSFERENCIAS_ENTRADA IS NULL) THEN
            TRANSFERENCIAS_ENTRADA = 0;
         COMPRAS = :COMPRAS + :TRANSFERENCIAS_ENTRADA;
    
         SELECT
          SUM(LANCAMENTOS.VALOR)
         FROM
          LANCAMENTOS
         WHERE
          LANCAMENTOS.DATA_LANCAMENTO >= :DATA_INICIAL AND
          LANCAMENTOS.DATA_LANCAMENTO <= :DATA_FINAL AND
          LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
          LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
          LANCAMENTOS.CD_GRUPO = :CD_GRUPO AND
          LANCAMENTOS.TIPO_VENDA = 'T' AND
          LANCAMENTOS.ENTRADA_SAIDA = 'S'
         INTO
          :TRANSFERENCIAS_SAIDA;
    
         IF (:TRANSFERENCIAS_SAIDA IS NULL) THEN
            TRANSFERENCIAS_SAIDA = 0;
    
         CP_TR = :COMPRAS - :TRANSFERENCIAS_SAIDA;
    
         SELECT
           SUM(POSICAOESTOQUEDATA.CUSTO * POSICAOESTOQUEDATA.QUANTIDADE)
         FROM
           POSICAOESTOQUEDATA,
           PRODUTOS
         WHERE
           POSICAOESTOQUEDATA.ID_PRODUTO = PRODUTOS.ID_PRODUTO AND
           POSICAOESTOQUEDATA.DATA = :DATA_INICIAL AND
           POSICAOESTOQUEDATA.CD_FILIAL = :CD_FILIAL AND
           PRODUTOS.CD_CLASSE = :CD_CLASSE AND
           PRODUTOS.CD_GRUPO = :CD_GRUPO
         INTO
          :POSICAO_INICIAL;
    
         SELECT
           SUM(POSICAOESTOQUEDATA.CUSTO * POSICAOESTOQUEDATA.QUANTIDADE)
         FROM
           POSICAOESTOQUEDATA,
           PRODUTOS
         WHERE
           POSICAOESTOQUEDATA.ID_PRODUTO = PRODUTOS.ID_PRODUTO AND
           POSICAOESTOQUEDATA.DATA = :DATA_FINAL + 1 AND
           POSICAOESTOQUEDATA.CD_FILIAL = :CD_FILIAL AND
           PRODUTOS.CD_CLASSE = :CD_CLASSE AND
           PRODUTOS.CD_GRUPO = :CD_GRUPO
         INTO
          :POSICAO_FINAL;
    
         IF (:POSICAO_INICIAL IS NULL) THEN
            POSICAO_INICIAL = 0;
         IF (:POSICAO_FINAL IS NULL) THEN
            POSICAO_FINAL = 0;
    
         EVOLUCAO_ESTOQUE = :POSICAO_FINAL - :POSICAO_INICIAL;
    
         LUCRO_BRUTO = :VENDAS - :CP_TR + :EVOLUCAO_ESTOQUE;
    
         IF (:VENDAS > 0) THEN
           PERCENTUAL_LUCRO_BRUTO = (:LUCRO_BRUTO / :VENDAS) * 100;
         ELSE
           PERCENTUAL_LUCRO_BRUTO = 0;
    
         SELECT NOME FROM FILIAIS WHERE CD_FILIAL = :CD_FILIAL INTO :FILIAL;
         SELECT DESCRICAO FROM CLASSES WHERE CD_CLASSE = :CD_CLASSE INTO :CLASSE;
         SELECT DESCRICAO FROM GRUPOS WHERE CD_GRUPO = :CD_GRUPO INTO :GRUPO;
         SUSPEND;
       END
   END
END ^

ALTER PROCEDURE SP_OLAP_TEMP_APURACAO_RESULTADO RETURNS (CD_FILIAL DOUBLE PRECISION,
FILIAL VARCHAR(100) CHARACTER SET NONE,
CD_PLANO DOUBLE PRECISION,
PLANO VARCHAR(100) CHARACTER SET NONE,
CD_HISTORICO DOUBLE PRECISION,
HISTORICO VARCHAR(100) CHARACTER SET NONE,
DEBITO DOUBLE PRECISION,
CREDITO DOUBLE PRECISION)
AS 
BEGIN
 FOR
  SELECT
   TEMP_APURACAORESULTADO.CD_FILIAL,
   FILIAIS.NOME,
   TEMP_APURACAORESULTADO.CD_PLANO,
   PLANO_CONTAS.CD_PLANO_CONTAS,
   TEMP_APURACAORESULTADO.CD_HISTORICO,
   TEMP_APURACAORESULTADO.HISTORICO,
   TEMP_APURACAORESULTADO.DEBITO,
   TEMP_APURACAORESULTADO.CREDITO
  FROM
   TEMP_APURACAORESULTADO,
   FILIAIS,
   PLANO_CONTAS
  WHERE
   TEMP_APURACAORESULTADO.CD_FILIAL = FILIAIS.CD_FILIAL AND
   TEMP_APURACAORESULTADO.CD_PLANO = PLANO_CONTAS.CD_PLANO_CONTAS
  INTO
   :CD_FILIAL,
   :FILIAL,
   :CD_PLANO,
   :PLANO,
   :CD_HISTORICO,
   :HISTORICO,
   :DEBITO,
   :CREDITO
 DO
  BEGIN
    SUSPEND;
  END

END ^

ALTER PROCEDURE SP_OLAP_TRANSFERENCIAS (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (FILIAL VARCHAR(100) CHARACTER SET NONE,
PRODUTO VARCHAR(100) CHARACTER SET NONE,
CLASSE VARCHAR(100) CHARACTER SET NONE,
GRUPO VARCHAR(100) CHARACTER SET NONE,
LABORATORIO VARCHAR(100) CHARACTER SET NONE,
DATA DATE,
HORA TIME,
QUANTIDADESAIDA DOUBLE PRECISION,
QUANTIDADEENTRADA DOUBLE PRECISION,
SALDOQUANTIDADE DOUBLE PRECISION,
VALORSAIDA DOUBLE PRECISION,
VALORENTRADA DOUBLE PRECISION,
SALDOVALOR DOUBLE PRECISION,
VENDASAIDA DOUBLE PRECISION,
VENDAENTRADA DOUBLE PRECISION,
SALDOVENDA DOUBLE PRECISION)
AS 
DECLARE VARIABLE CD_FILIAL DOUBLE PRECISION;
DECLARE VARIABLE ID_PRODUTO DOUBLE PRECISION;
DECLARE VARIABLE CD_CLASSE DOUBLE PRECISION;
DECLARE VARIABLE CD_GRUPO DOUBLE PRECISION;
DECLARE VARIABLE CD_LABORATORIO DOUBLE PRECISION;
BEGIN
  FOR
   SELECT
    CD_FILIAL,
    NOME
   FROM
    FILIAIS
   INTO
    :CD_FILIAL,
    :FILIAL
  DO
   BEGIN
     QUANTIDADESAIDA = 0;
     QUANTIDADEENTRADA = 0;
     VALORSAIDA = 0;
     VALORENTRADA = 0;
     VENDASAIDA = 0;
     VENDAENTRADA = 0;
     SALDOQUANTIDADE = 0;
     SALDOVALOR = 0;
     SALDOVENDA = 0;
      FOR
        SELECT
         PRODUTOS.ID_PRODUTO,
         PRODUTOS.DESCRICAO,
         PRODUTOS.CD_CLASSE,
         PRODUTOS.CD_GRUPO,
         PRODUTOS.CD_LABORATORIO,
         TRANSFER.DATA_CONCLUSAO,
         TRANSFER.HORA_CONCLUSAO
        FROM
         PRODUTOS,
         TRANSFER,
         ITENS_TRANSFER
        WHERE
         TRANSFER.DATA_CONCLUSAO >= :DATAINICIAL AND
         TRANSFER.DATA_CONCLUSAO <= :DATAFINAL AND
         PRODUTOS.ID_PRODUTO = ITENS_TRANSFER.ID_PRODUTO AND
         TRANSFER.CD_TRANSFER = ITENS_TRANSFER.CD_TRANSFER AND
         TRANSFER.STATUS = 'C' AND
         (TRANSFER.CD_FILIAL_ORIGEM = :CD_FILIAL OR
          TRANSFER.CD_FILIAL_DESTINO = :CD_FILIAL)
        GROUP BY
         PRODUTOS.ID_PRODUTO,
         PRODUTOS.DESCRICAO,
         PRODUTOS.CD_CLASSE,
         PRODUTOS.CD_GRUPO,
         PRODUTOS.CD_LABORATORIO,
         TRANSFER.DATA_CONCLUSAO,
         TRANSFER.HORA_CONCLUSAO
        INTO
         :ID_PRODUTO,
         :PRODUTO,
         :CD_CLASSE,
         :CD_GRUPO,
         :CD_LABORATORIO,
         :DATA,
         :HORA
      DO
       BEGIN
         SELECT
          SUM(ITENS_TRANSFER.QUANTIDADE_ENVIADA),
          SUM((ITENS_TRANSFER.QUANTIDADE_ENVIADA * ITENS_TRANSFER.VALOR)),
          SUM((ITENS_TRANSFER.QUANTIDADE_ENVIADA * PRODUTOS.PRECO_VENDA))
         FROM
          PRODUTOS,
          ITENS_TRANSFER,
          TRANSFER
         WHERE
          TRANSFER.CD_TRANSFER = ITENS_TRANSFER.CD_TRANSFER AND
          ITENS_TRANSFER.ID_PRODUTO = PRODUTOS.ID_PRODUTO AND
          TRANSFER.DATA_CONCLUSAO = :DATA AND
          TRANSFER.HORA_CONCLUSAO = :HORA AND
          ITENS_TRANSFER.ID_PRODUTO = :ID_PRODUTO AND
          TRANSFER.CD_FILIAL_ORIGEM = :CD_FILIAL
         INTO
          :QUANTIDADESAIDA,
          :VALORSAIDA,
          :VENDASAIDA;

         SELECT
          SUM(ITENS_TRANSFER.QUANTIDADE_RECEBIDA),
          SUM((ITENS_TRANSFER.QUANTIDADE_RECEBIDA * ITENS_TRANSFER.VALOR)),
          SUM((ITENS_TRANSFER.QUANTIDADE_RECEBIDA * PRODUTOS.PRECO_VENDA))
         FROM
          ITENS_TRANSFER,
          TRANSFER,
          PRODUTOS
         WHERE
          TRANSFER.CD_TRANSFER = ITENS_TRANSFER.CD_TRANSFER AND
          ITENS_TRANSFER.ID_PRODUTO = PRODUTOS.ID_PRODUTO AND
          TRANSFER.DATA_CONCLUSAO = :DATA AND
          TRANSFER.HORA_CONCLUSAO = :HORA AND
          ITENS_TRANSFER.ID_PRODUTO = :ID_PRODUTO AND
          TRANSFER.CD_FILIAL_DESTINO = :CD_FILIAL
         INTO
          :QUANTIDADEENTRADA,
          :VALORENTRADA,
          :VENDAENTRADA;


         IF (:QUANTIDADESAIDA IS NULL) THEN
          BEGIN
             QUANTIDADESAIDA = 0;
          END
         IF (:QUANTIDADEENTRADA IS NULL) THEN
          BEGIN
             QUANTIDADEENTRADA = 0;
          END
         SALDOQUANTIDADE = :QUANTIDADEENTRADA - :QUANTIDADESAIDA;

         IF (:VALORSAIDA IS NULL) THEN
          BEGIN
             VALORSAIDA = 0;
          END
         IF (:VALORENTRADA IS NULL) THEN
          BEGIN
             VALORENTRADA = 0;
          END
         SALDOVALOR = :VALORENTRADA - :VALORSAIDA;

         IF (:VENDASAIDA IS NULL) THEN
          BEGIN
             VENDASAIDA = 0;
          END
         IF (:VENDAENTRADA IS NULL) THEN
          BEGIN
             VENDAENTRADA = 0;
          END
         SALDOVENDA = :VENDAENTRADA - :VENDASAIDA;


         SELECT DESCRICAO FROM CLASSES WHERE CD_CLASSE = :CD_CLASSE INTO :CLASSE;
         SELECT DESCRICAO FROM GRUPOS WHERE CD_GRUPO = :CD_GRUPO INTO :GRUPO;
         SELECT NOME FROM LABORATORIOS WHERE CD_LABORATORIO = :CD_LABORATORIO INTO :LABORATORIO;
         
         IF ((:QUANTIDADEENTRADA > 0) OR (:QUANTIDADESAIDA > 0)) THEN
           SUSPEND;
       END
   END
END ^

ALTER PROCEDURE SP_OLAP_VENDAS_CLASSES (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (FILIAL VARCHAR(100) CHARACTER SET NONE,
CLASSE VARCHAR(100) CHARACTER SET NONE,
DIA DATE,
VENDEDOR VARCHAR(100) CHARACTER SET NONE,
QUANTIDADE_VENDIDA DOUBLE PRECISION,
NUMERO_DE_VENDAS DOUBLE PRECISION,
VALOR_VENDAS DOUBLE PRECISION,
CUSTO_VENDAS DOUBLE PRECISION,
COMISSAO DOUBLE PRECISION,
DESCONTO DOUBLE PRECISION,
PROMOCAO DOUBLE PRECISION,
VALOR_VENDAS_DIA DOUBLE PRECISION)
AS 
declare variable QUANTIDADE_CANCELADA integer;
declare variable NUMERO_DE_CANCELAMENTOS integer;
declare variable VALOR_CANCELAMENTO double precision;
declare variable CUSTO_CANCELAMENTO double precision;
declare variable COMISSAO_CANCELADA double precision;
declare variable DESCONTO_CANCELADO double precision;
declare variable PROMOCAO_CANCELADO double precision;
declare variable CD_FILIAL double precision;
declare variable CD_CLASSE double precision;
declare variable CD_VENDEDOR double precision;
declare variable VALOR_CANCELAMENTO_DIA double precision;
BEGIN
  VALOR_VENDAS_DIA = 0;
  VALOR_CANCELAMENTO_DIA = 0;

  SELECT
   SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO)
  FROM
   LANCAMENTOS
  WHERE
   LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
   LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
   LANCAMENTOS.TIPO_VENDA = 'V' AND
   LANCAMENTOS.CUSTO_MEDIO > 0
  INTO
   :VALOR_VENDAS_DIA;

  SELECT
   SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO)
  FROM
   LANCAMENTOS
  WHERE
   LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
   LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
   LANCAMENTOS.TIPO_VENDA = 'D' --AND
   --LANCAMENTOS.TROCA = 'F' AND
   --LANCAMENTOS.CUSTO_MEDIO > 0
  INTO
   :VALOR_CANCELAMENTO_DIA;

  IF (:VALOR_VENDAS_DIA IS NULL) THEN
     VALOR_VENDAS_DIA = 0;
  IF (:VALOR_CANCELAMENTO_DIA IS NULL) THEN
     VALOR_CANCELAMENTO_DIA = 0;

  VALOR_VENDAS_DIA = :VALOR_VENDAS_DIA - :VALOR_CANCELAMENTO_DIA;


 FOR
    SELECT
     LANCAMENTOS.CD_FILIAL,
     LANCAMENTOS.CD_CLASSE,
     LANCAMENTOS.DATA_LANCAMENTO,
     LANCAMENTOS.CD_VENDEDOR
    FROM
     LANCAMENTOS
    WHERE
     LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
     LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
     (LANCAMENTOS.TIPO_VENDA = 'D' OR LANCAMENTOS.TIPO_VENDA = 'V')

    GROUP BY
     LANCAMENTOS.DATA_LANCAMENTO,
     LANCAMENTOS.CD_CLASSE,
     LANCAMENTOS.CD_FILIAL,
     LANCAMENTOS.CD_VENDEDOR
    INTO
     :CD_FILIAL,
     :CD_CLASSE,
     :DIA,
     :CD_VENDEDOR
 DO
  BEGIN
    QUANTIDADE_VENDIDA = 0;
    NUMERO_DE_VENDAS = 0;
    VALOR_VENDAS = 0;
    CUSTO_VENDAS = 0;
    COMISSAO = 0;
    DESCONTO = 0;

    SELECT
     SUM(LANCAMENTOS.QUANTIDADE),
     COUNT(DISTINCT LANCAMENTOS.CD_VENDA),
     SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
     SUM(LANCAMENTOS.CUSTO_MEDIO * LANCAMENTOS.QUANTIDADE),
     SUM(LANCAMENTOS.COMISSAO),
     SUM(LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE),
     SUM(LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)
    FROM
     LANCAMENTOS
    WHERE
     LANCAMENTOS.DATA_LANCAMENTO = :DIA AND
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
     LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR AND
     LANCAMENTOS.TIPO_VENDA = 'V' /*AND
     LANCAMENTOS.CUSTO_MEDIO > 0*/
    INTO
     :QUANTIDADE_VENDIDA,
     :NUMERO_DE_VENDAS,
     :VALOR_VENDAS,
     :CUSTO_VENDAS,
     :COMISSAO,
     :DESCONTO,
     :PROMOCAO;

    IF (:QUANTIDADE_VENDIDA IS NULL) THEN
       QUANTIDADE_VENDIDA = 0;
    IF (:NUMERO_DE_VENDAS IS NULL) THEN
       NUMERO_DE_VENDAS = 0;
    IF (:VALOR_VENDAS IS NULL) THEN
       VALOR_VENDAS = 0;
    IF (:CUSTO_VENDAS IS NULL) THEN
       CUSTO_VENDAS = 0;
    IF (:COMISSAO IS NULL) THEN
       COMISSAO = 0;
    IF (:DESCONTO IS NULL) THEN
       DESCONTO = 0;
    IF (:PROMOCAO IS NULL) THEN
       PROMOCAO = 0;

    QUANTIDADE_CANCELADA = 0;
    NUMERO_DE_CANCELAMENTOS = 0;
    VALOR_CANCELAMENTO = 0;
    CUSTO_CANCELAMENTO = 0;
    COMISSAO_CANCELADA = 0;
    DESCONTO_CANCELADO = 0;
    PROMOCAO_CANCELADO = 0;

    SELECT
     SUM(LANCAMENTOS.QUANTIDADE),
     COUNT(DISTINCT LANCAMENTOS.CD_VENDA),
     SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
     SUM(LANCAMENTOS.CUSTO_MEDIO * LANCAMENTOS.QUANTIDADE),
     SUM(LANCAMENTOS.COMISSAO),
     SUM(LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE),
     SUM(LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)
    FROM
     LANCAMENTOS
    WHERE
     LANCAMENTOS.DATA_LANCAMENTO = :DIA AND
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
     LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR AND
     LANCAMENTOS.TIPO_VENDA = 'D' --AND
     --LANCAMENTOS.TROCA = 'F' AND
     --LANCAMENTOS.CUSTO_MEDIO > 0
    INTO
     :QUANTIDADE_CANCELADA,
     :NUMERO_DE_CANCELAMENTOS,
     :VALOR_CANCELAMENTO,
     :CUSTO_CANCELAMENTO,
     :COMISSAO_CANCELADA,
     :DESCONTO_CANCELADO,
     :PROMOCAO_CANCELADO;

    IF (:QUANTIDADE_CANCELADA IS NULL) THEN
       QUANTIDADE_CANCELADA = 0;
    IF (:NUMERO_DE_CANCELAMENTOS IS NULL) THEN
       NUMERO_DE_CANCELAMENTOS = 0;
    IF (:VALOR_CANCELAMENTO IS NULL) THEN
       VALOR_CANCELAMENTO = 0;
    IF (:CUSTO_CANCELAMENTO IS NULL) THEN
       CUSTO_CANCELAMENTO = 0;
    IF (:COMISSAO_CANCELADA IS NULL) THEN
       COMISSAO_CANCELADA = 0;
    IF (:DESCONTO_CANCELADO IS NULL) THEN
       DESCONTO_CANCELADO = 0;
    IF (:PROMOCAO_CANCELADO IS NULL) THEN
       PROMOCAO_CANCELADO = 0;

    QUANTIDADE_VENDIDA = :QUANTIDADE_VENDIDA - :QUANTIDADE_CANCELADA;
    NUMERO_DE_VENDAS = :NUMERO_DE_VENDAS - :NUMERO_DE_CANCELAMENTOS;
    VALOR_VENDAS = :VALOR_VENDAS - :VALOR_CANCELAMENTO;
    CUSTO_VENDAS = :CUSTO_VENDAS - :CUSTO_CANCELAMENTO;
    COMISSAO = :COMISSAO - :COMISSAO_CANCELADA;
    DESCONTO = :DESCONTO - :DESCONTO_CANCELADO;
    PROMOCAO = :PROMOCAO - :PROMOCAO_CANCELADO;

    SELECT NOME FROM FILIAIS WHERE CD_FILIAL = :CD_FILIAL INTO :FILIAL;
    SELECT DESCRICAO FROM CLASSES WHERE CD_CLASSE = : CD_CLASSE INTO :CLASSE;
    SELECT NOME FROM VENDEDORES WHERE CD_VENDEDOR = :CD_VENDEDOR INTO :VENDEDOR;
   /* IF (:VALOR_VENDAS > 0) THEN*/
       SUSPEND;
  END
END ^

ALTER PROCEDURE SP_OLAP_VENDAS_CLASSES_IMPOSTOS (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (FILIAL VARCHAR(100) CHARACTER SET NONE,
CLASSE VARCHAR(100) CHARACTER SET NONE,
DIA DATE,
VENDEDOR VARCHAR(100) CHARACTER SET NONE,
QUANTIDADE_VENDIDA DOUBLE PRECISION,
NUMERO_DE_VENDAS DOUBLE PRECISION,
VALOR_VENDAS DOUBLE PRECISION,
CUSTO_VENDAS DOUBLE PRECISION,
COMISSAO DOUBLE PRECISION,
DESCONTO DOUBLE PRECISION,
PROMOCAO DOUBLE PRECISION)
AS 
declare variable QUANTIDADE_CANCELADA integer;
declare variable NUMERO_DE_CANCELAMENTOS integer;
declare variable VALOR_CANCELAMENTO double precision;
declare variable CUSTO_CANCELAMENTO double precision;
declare variable COMISSAO_CANCELADA double precision;
declare variable DESCONTO_CANCELADO double precision;
declare variable PROMOCAO_CANCELADO double precision;
declare variable CD_FILIAL double precision;
declare variable CD_CLASSE double precision;
declare variable CD_VENDEDOR double precision;
BEGIN
 FOR
    SELECT
     LANCAMENTOS.CD_FILIAL,
     LANCAMENTOS.CD_CLASSE,
     LANCAMENTOS.DATA_LANCAMENTO,
     LANCAMENTOS.CD_VENDEDOR
    FROM
     LANCAMENTOS
    WHERE
     LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
     LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
     LANCAMENTOS.NUMERO IS NOT NULL AND
     LANCAMENTOS.NUMERO > 0 AND
     (LANCAMENTOS.TIPO_VENDA = 'D' OR LANCAMENTOS.TIPO_VENDA = 'V')

    GROUP BY
     LANCAMENTOS.DATA_LANCAMENTO,
     LANCAMENTOS.CD_CLASSE,
     LANCAMENTOS.CD_FILIAL,
     LANCAMENTOS.CD_VENDEDOR
    INTO
     :CD_FILIAL,
     :CD_CLASSE,
     :DIA,
     :CD_VENDEDOR
 DO
  BEGIN
    QUANTIDADE_VENDIDA = 0;
    NUMERO_DE_VENDAS = 0;
    VALOR_VENDAS = 0;
    CUSTO_VENDAS = 0;
    COMISSAO = 0;
    DESCONTO = 0;

    SELECT
     SUM(LANCAMENTOS.QUANTIDADE),
     COUNT(DISTINCT LANCAMENTOS.CD_VENDA),
     SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
     SUM(LANCAMENTOS.CUSTO_MEDIO * LANCAMENTOS.QUANTIDADE),
     SUM(LANCAMENTOS.COMISSAO),
     SUM(LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE),
     SUM(LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)
    FROM
     LANCAMENTOS
    WHERE
     LANCAMENTOS.DATA_LANCAMENTO = :DIA AND
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
     LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR AND
     LANCAMENTOS.TIPO_VENDA = 'V' AND
     --LANCAMENTOS.CUSTO_MEDIO > 0 AND
     LANCAMENTOS.NUMERO IS NOT NULL AND
     LANCAMENTOS.NUMERO > 0

    INTO
     :QUANTIDADE_VENDIDA,
     :NUMERO_DE_VENDAS,
     :VALOR_VENDAS,
     :CUSTO_VENDAS,
     :COMISSAO,
     :DESCONTO,
     :PROMOCAO;

    IF (:QUANTIDADE_VENDIDA IS NULL) THEN
       QUANTIDADE_VENDIDA = 0;
    IF (:NUMERO_DE_VENDAS IS NULL) THEN
       NUMERO_DE_VENDAS = 0;
    IF (:VALOR_VENDAS IS NULL) THEN
       VALOR_VENDAS = 0;
    IF (:CUSTO_VENDAS IS NULL) THEN
       CUSTO_VENDAS = 0;
    IF (:COMISSAO IS NULL) THEN
       COMISSAO = 0;
    IF (:DESCONTO IS NULL) THEN
       DESCONTO = 0;
    IF (:PROMOCAO IS NULL) THEN
       PROMOCAO = 0;

    QUANTIDADE_CANCELADA = 0;
    NUMERO_DE_CANCELAMENTOS = 0;
    VALOR_CANCELAMENTO = 0;
    CUSTO_CANCELAMENTO = 0;
    COMISSAO_CANCELADA = 0;
    DESCONTO_CANCELADO = 0;
    PROMOCAO_CANCELADO = 0;

    SELECT
     SUM(LANCAMENTOS.QUANTIDADE),
     COUNT(DISTINCT LANCAMENTOS.CD_VENDA),
     SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
     SUM(LANCAMENTOS.CUSTO_MEDIO * LANCAMENTOS.QUANTIDADE),
     SUM(LANCAMENTOS.COMISSAO),
     SUM(LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE),
     SUM(LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)
    FROM
     LANCAMENTOS
    WHERE
     LANCAMENTOS.DATA_LANCAMENTO = :DIA AND
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
     LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR AND
     LANCAMENTOS.TIPO_VENDA = 'D' AND
     --LANCAMENTOS.TROCA = 'F' AND
     --LANCAMENTOS.CUSTO_MEDIO > 0 AND
     LANCAMENTOS.NUMERO IS NOT NULL AND
     LANCAMENTOS.NUMERO > 0
    INTO
     :QUANTIDADE_CANCELADA,
     :NUMERO_DE_CANCELAMENTOS,
     :VALOR_CANCELAMENTO,
     :CUSTO_CANCELAMENTO,
     :COMISSAO_CANCELADA,
     :DESCONTO_CANCELADO,
     :PROMOCAO_CANCELADO;

    IF (:QUANTIDADE_CANCELADA IS NULL) THEN
       QUANTIDADE_CANCELADA = 0;
    IF (:NUMERO_DE_CANCELAMENTOS IS NULL) THEN
       NUMERO_DE_CANCELAMENTOS = 0;
    IF (:VALOR_CANCELAMENTO IS NULL) THEN
       VALOR_CANCELAMENTO = 0;
    IF (:CUSTO_CANCELAMENTO IS NULL) THEN
       CUSTO_CANCELAMENTO = 0;
    IF (:COMISSAO_CANCELADA IS NULL) THEN
       COMISSAO_CANCELADA = 0;
    IF (:DESCONTO_CANCELADO IS NULL) THEN
       DESCONTO_CANCELADO = 0;
    IF (:PROMOCAO_CANCELADO IS NULL) THEN
       PROMOCAO_CANCELADO = 0;

    QUANTIDADE_VENDIDA = :QUANTIDADE_VENDIDA - :QUANTIDADE_CANCELADA;
    NUMERO_DE_VENDAS = :NUMERO_DE_VENDAS - :NUMERO_DE_CANCELAMENTOS;
    VALOR_VENDAS = :VALOR_VENDAS - :VALOR_CANCELAMENTO;
    CUSTO_VENDAS = :CUSTO_VENDAS - :CUSTO_CANCELAMENTO;
    COMISSAO = :COMISSAO - :COMISSAO_CANCELADA;
    DESCONTO = :DESCONTO - :DESCONTO_CANCELADO;
    PROMOCAO = :PROMOCAO - :PROMOCAO_CANCELADO;

    SELECT NOME FROM FILIAIS WHERE CD_FILIAL = :CD_FILIAL INTO :FILIAL;
    SELECT DESCRICAO FROM CLASSES WHERE CD_CLASSE = : CD_CLASSE INTO :CLASSE;
    SELECT NOME FROM VENDEDORES WHERE CD_VENDEDOR = :CD_VENDEDOR INTO :VENDEDOR;
   /* IF (:VALOR_VENDAS > 0) THEN*/
       SUSPEND;
  END
END ^

ALTER PROCEDURE SP_OLAP_VENDAS_ENTREGA (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (FILIAL VARCHAR(100) CHARACTER SET NONE,
DIA DATE,
CUSTO_DAS_VENDAS DOUBLE PRECISION,
QUANTIDADE_VENDIDA DOUBLE PRECISION,
DESCONTO DOUBLE PRECISION,
PROMOCAO DOUBLE PRECISION,
COMISSAO DOUBLE PRECISION,
VALOR_VENDIDO DOUBLE PRECISION,
NUMERO_DE_VENDAS DOUBLE PRECISION,
CUSTO_DAS_VENDAS_ENTREGA DOUBLE PRECISION,
QUANTIDADE_VENDIDA_ENTREGA DOUBLE PRECISION,
DESCONTO_ENTREGA DOUBLE PRECISION,
PROMOCAO_ENTREGA DOUBLE PRECISION,
COMISSAO_ENTREGA DOUBLE PRECISION,
VALOR_VENDIDO_ENTREGA DOUBLE PRECISION,
NUMERO_DE_VENDAS_ENTREGA DOUBLE PRECISION)
AS 
declare variable QUANTIDADE_CANCELADA integer;
declare variable NUMERO_DE_CANCELAMENTOS integer;
declare variable VALOR_CANCELAMENTO double precision;
declare variable CUSTO_CANCELAMENTO double precision;
declare variable COMISSAO_CANCELADA double precision;
declare variable DESCONTO_CANCELADO double precision;
declare variable PROMOCAO_CANCELADO double precision;
declare variable QUANTIDADE_CANCELADA_ENTREGA integer;
declare variable NUMERO_DE_CANCELAMENTOS_ENTREGA integer;
declare variable VALOR_CANCELAMENTO_ENTREGA double precision;
declare variable CUSTO_CANCELAMENTO_ENTREGA double precision;
declare variable COMISSAO_CANCELADA_ENTREGA double precision;
declare variable DESCONTO_CANCELADO_ENTREGA double precision;
declare variable PROMOCAO_CANCELADO_ENTREGA double precision;
declare variable CD_FILIAL double precision;
declare variable CD_VENDEDOR double precision;
BEGIN
 FOR
    SELECT
     LANCAMENTOS.CD_FILIAL,
     LANCAMENTOS.DATA_LANCAMENTO
    FROM
     LANCAMENTOS
    WHERE
     LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
     LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
     (LANCAMENTOS.TIPO_VENDA = 'D' OR LANCAMENTOS.TIPO_VENDA = 'V')
    GROUP BY
     LANCAMENTOS.DATA_LANCAMENTO,
     LANCAMENTOS.CD_FILIAL
    INTO
     :CD_FILIAL,
     :DIA
 DO
  BEGIN
    SELECT
      COUNT(DISTINCT LANCAMENTOS.CD_VENDA),
      SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
      SUM(LANCAMENTOS.CUSTO_MEDIO * LANCAMENTOS.QUANTIDADE),
      SUM(LANCAMENTOS.QUANTIDADE),
      SUM(LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE),
      SUM(LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE),
      SUM(LANCAMENTOS.COMISSAO)
    FROM
      LANCAMENTOS
    WHERE
      LANCAMENTOS.DATA_LANCAMENTO = :DIA AND
      LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
      LANCAMENTOS.TIPO_VENDA = 'V' AND
      LANCAMENTOS.ENTREGA = 'N'
    INTO
      :NUMERO_DE_VENDAS,
      :VALOR_VENDIDO,
      :CUSTO_DAS_VENDAS,
      :QUANTIDADE_VENDIDA,
      :DESCONTO,
      :PROMOCAO,
      :COMISSAO;

    IF (:NUMERO_DE_VENDAS IS NULL) THEN
       NUMERO_DE_VENDAS = 0;
    IF (:VALOR_VENDIDO IS NULL) THEN
       VALOR_VENDIDO = 0;
    IF (:CUSTO_DAS_VENDAS IS NULL) THEN
       CUSTO_DAS_VENDAS = 0;
    IF (:QUANTIDADE_VENDIDA IS NULL) THEN
       QUANTIDADE_VENDIDA = 0;
    IF (:DESCONTO IS NULL) THEN
       DESCONTO = 0;
    IF (:PROMOCAO IS NULL) THEN
       PROMOCAO = 0;
    IF (:COMISSAO IS NULL) THEN
       COMISSAO = 0;

    QUANTIDADE_CANCELADA = 0;
    NUMERO_DE_CANCELAMENTOS  = 0;
    VALOR_CANCELAMENTO = 0;
    CUSTO_CANCELAMENTO = 0;
    COMISSAO_CANCELADA = 0;
    DESCONTO_CANCELADO = 0;
    PROMOCAO_CANCELADO = 0;

    SELECT
     SUM(LANCAMENTOS.QUANTIDADE),
     COUNT(DISTINCT LANCAMENTOS.CD_VENDA),
     SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
     SUM(LANCAMENTOS.CUSTO_MEDIO),
     SUM(LANCAMENTOS.COMISSAO),
     SUM(LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE),
     SUM(LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)
    FROM
     LANCAMENTOS
    WHERE
     LANCAMENTOS.DATA_LANCAMENTO = :DIA AND
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.TIPO_VENDA = 'D' AND
     --LANCAMENTOS.TROCA = 'F' AND
     LANCAMENTOS.ENTREGA = 'N'
    INTO
     :QUANTIDADE_CANCELADA,
     :NUMERO_DE_CANCELAMENTOS,
     :VALOR_CANCELAMENTO,
     :CUSTO_CANCELAMENTO,
     :COMISSAO_CANCELADA,
     :DESCONTO_CANCELADO,
     :PROMOCAO_CANCELADO;

    IF (:QUANTIDADE_CANCELADA IS NULL) THEN
       QUANTIDADE_CANCELADA = 0;
    IF (:NUMERO_DE_CANCELAMENTOS IS NULL) THEN
       NUMERO_DE_CANCELAMENTOS = 0;
    IF (:VALOR_CANCELAMENTO IS NULL) THEN
       VALOR_CANCELAMENTO = 0;
    IF (:CUSTO_CANCELAMENTO IS NULL) THEN
       CUSTO_CANCELAMENTO = 0;
    IF (:COMISSAO_CANCELADA IS NULL) THEN
       COMISSAO_CANCELADA = 0;
    IF (:DESCONTO_CANCELADO IS NULL) THEN
       DESCONTO_CANCELADO = 0;
    IF (:PROMOCAO_CANCELADO IS NULL) THEN
       PROMOCAO_CANCELADO = 0;

    QUANTIDADE_VENDIDA = :QUANTIDADE_VENDIDA - :QUANTIDADE_CANCELADA;
    NUMERO_DE_VENDAS = :NUMERO_DE_VENDAS - :NUMERO_DE_CANCELAMENTOS;
    VALOR_VENDIDO = :VALOR_VENDIDO - :VALOR_CANCELAMENTO;
    CUSTO_DAS_VENDAS = :CUSTO_DAS_VENDAS - :CUSTO_CANCELAMENTO;
    COMISSAO = :COMISSAO - :COMISSAO_CANCELADA;
    DESCONTO = :DESCONTO - :DESCONTO_CANCELADO;
    PROMOCAO = :PROMOCAO - :PROMOCAO_CANCELADO;

    SELECT
      COUNT(DISTINCT LANCAMENTOS.CD_VENDA),
      SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
      SUM(LANCAMENTOS.CUSTO_MEDIO * LANCAMENTOS.QUANTIDADE),
      SUM(LANCAMENTOS.QUANTIDADE),
      SUM(LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE),
      SUM(LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE),
      SUM(LANCAMENTOS.COMISSAO)
    FROM
      LANCAMENTOS
    WHERE
      LANCAMENTOS.DATA_LANCAMENTO = :DIA AND
      LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
      LANCAMENTOS.TIPO_VENDA = 'V' AND
      LANCAMENTOS.ENTREGA = 'S'
    INTO
      :NUMERO_DE_VENDAS_ENTREGA,
      :VALOR_VENDIDO_ENTREGA,
      :CUSTO_DAS_VENDAS_ENTREGA,
      :QUANTIDADE_VENDIDA_ENTREGA,
      :DESCONTO_ENTREGA,
      :PROMOCAO_ENTREGA,
      :COMISSAO_ENTREGA;

    IF (:NUMERO_DE_VENDAS_ENTREGA IS NULL) THEN
       NUMERO_DE_VENDAS_ENTREGA = 0;
    IF (:VALOR_VENDIDO_ENTREGA IS NULL) THEN
       VALOR_VENDIDO_ENTREGA = 0;
    IF (:CUSTO_DAS_VENDAS_ENTREGA IS NULL) THEN
       CUSTO_DAS_VENDAS_ENTREGA = 0;
    IF (:QUANTIDADE_VENDIDA_ENTREGA IS NULL) THEN
       QUANTIDADE_VENDIDA_ENTREGA = 0;
    IF (:DESCONTO_ENTREGA IS NULL) THEN
       DESCONTO_ENTREGA = 0;
    IF (:PROMOCAO_ENTREGA IS NULL) THEN
       PROMOCAO_ENTREGA = 0;
    IF (:COMISSAO_ENTREGA IS NULL) THEN
       COMISSAO_ENTREGA = 0;

    QUANTIDADE_CANCELADA_ENTREGA = 0;
    NUMERO_DE_CANCELAMENTOS_ENTREGA  = 0;
    VALOR_CANCELAMENTO_ENTREGA = 0;
    CUSTO_CANCELAMENTO_ENTREGA = 0;
    COMISSAO_CANCELADA_ENTREGA = 0;
    DESCONTO_CANCELADO_ENTREGA = 0;
    PROMOCAO_CANCELADO_ENTREGA = 0;

    SELECT
     SUM(LANCAMENTOS.QUANTIDADE),
     COUNT(DISTINCT LANCAMENTOS.CD_VENDA),
     SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
     SUM(LANCAMENTOS.CUSTO_MEDIO),
     SUM(LANCAMENTOS.COMISSAO),
     SUM(LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE),
     SUM(LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)
    FROM
     LANCAMENTOS
    WHERE
     LANCAMENTOS.DATA_LANCAMENTO = :DIA AND
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.TIPO_VENDA = 'D' AND
     --LANCAMENTOS.TROCA = 'F' AND
     LANCAMENTOS.ENTREGA = 'S'
    INTO
     :QUANTIDADE_CANCELADA_ENTREGA,
     :NUMERO_DE_CANCELAMENTOS_ENTREGA,
     :VALOR_CANCELAMENTO_ENTREGA,
     :CUSTO_CANCELAMENTO_ENTREGA,
     :COMISSAO_CANCELADA_ENTREGA,
     :DESCONTO_CANCELADO_ENTREGA,
     :PROMOCAO_CANCELADO_ENTREGA;

    IF (:QUANTIDADE_CANCELADA_ENTREGA IS NULL) THEN
       QUANTIDADE_CANCELADA_ENTREGA = 0;
    IF (:NUMERO_DE_CANCELAMENTOS_ENTREGA IS NULL) THEN
       NUMERO_DE_CANCELAMENTOS_ENTREGA = 0;
    IF (:VALOR_CANCELAMENTO_ENTREGA IS NULL) THEN
       VALOR_CANCELAMENTO_ENTREGA = 0;
    IF (:CUSTO_CANCELAMENTO_ENTREGA IS NULL) THEN
       CUSTO_CANCELAMENTO_ENTREGA = 0;
    IF (:COMISSAO_CANCELADA_ENTREGA IS NULL) THEN
       COMISSAO_CANCELADA_ENTREGA = 0;
    IF (:DESCONTO_CANCELADO_ENTREGA IS NULL) THEN
       DESCONTO_CANCELADO_ENTREGA = 0;
    IF (:PROMOCAO_CANCELADO_ENTREGA IS NULL) THEN
       PROMOCAO_CANCELADO_ENTREGA = 0;

    QUANTIDADE_VENDIDA_ENTREGA = :QUANTIDADE_VENDIDA_ENTREGA - :QUANTIDADE_CANCELADA_ENTREGA;
    NUMERO_DE_VENDAS_ENTREGA = :NUMERO_DE_VENDAS_ENTREGA - :NUMERO_DE_CANCELAMENTOS_ENTREGA;
    VALOR_VENDIDO_ENTREGA = :VALOR_VENDIDO_ENTREGA - :VALOR_CANCELAMENTO_ENTREGA;
    CUSTO_DAS_VENDAS_ENTREGA = :CUSTO_DAS_VENDAS_ENTREGA - :CUSTO_CANCELAMENTO_ENTREGA;
    COMISSAO_ENTREGA = :COMISSAO_ENTREGA - :COMISSAO_CANCELADA_ENTREGA;
    DESCONTO_ENTREGA = :DESCONTO_ENTREGA - :DESCONTO_CANCELADO_ENTREGA;
    PROMOCAO_ENTREGA = :PROMOCAO_ENTREGA - :PROMOCAO_CANCELADO_ENTREGA;

    SELECT NOME FROM FILIAIS WHERE CD_FILIAL = :CD_FILIAL INTO :FILIAL;
    SUSPEND;
  END
END ^

ALTER PROCEDURE SP_OLAP_VENDAS_FORMA_PAGAMENTO (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (FILIAL VARCHAR(100) CHARACTER SET NONE,
DIA DATE,
FORMA_PAGAMENTO VARCHAR(100) CHARACTER SET NONE,
NUMERO_DE_VENDAS DOUBLE PRECISION,
VALOR_VENDIDO DOUBLE PRECISION,
DESCONTO DOUBLE PRECISION,
TICKET DOUBLE PRECISION)
AS 
DECLARE VARIABLE CD_FILIAL DOUBLE PRECISION;
DECLARE VARIABLE CD_FORMA_PAGAMENTO DOUBLE PRECISION;
DECLARE VARIABLE NUMERO_DE_CANCELAMENTOS DOUBLE PRECISION;
DECLARE VARIABLE VALOR_CANCELADO DOUBLE PRECISION;
DECLARE VARIABLE DESCONTO_CANCELADO DOUBLE PRECISION;
BEGIN
 FOR
    SELECT
     CAIXA.CD_FILIAL,
     CAIXA.DATA_CAIXA,
     CAIXA.CD_FORMA_PAGAMENTO
    FROM
     CAIXA
    WHERE
     CAIXA.DATA_CAIXA >= :DATAINICIAL AND
     CAIXA.DATA_CAIXA <= :DATAFINAL AND
     (CAIXA.TIPO_VENDA = 'V' OR CAIXA.TIPO_VENDA = 'D')
    GROUP BY
     CAIXA.CD_FILIAL,
     CAIXA.DATA_CAIXA,
     CAIXA.CD_FORMA_PAGAMENTO
    INTO
     :CD_FILIAL,
     :DIA,
     :CD_FORMA_PAGAMENTO
 DO
  BEGIN
    SELECT
     COUNT(DISTINCT CD_VENDA),
     SUM(VALOR),
     SUM(DESCONTO)
    FROM
     CAIXA
    WHERE
     CAIXA.CD_FILIAL = :CD_FILIAL AND
     CAIXA.CD_FORMA_PAGAMENTO = :CD_FORMA_PAGAMENTO AND
     CAIXA.DATA_CAIXA = :DIA AND
     CAIXA.TIPO_VENDA = 'V'
    INTO
     :NUMERO_DE_VENDAS,
     :VALOR_VENDIDO,
     :DESCONTO;

    IF (:NUMERO_DE_VENDAS IS NULL) THEN
        NUMERO_DE_VENDAS = 0;
    IF (:VALOR_VENDIDO IS NULL) THEN
        VALOR_VENDIDO = 0;
    IF (:DESCONTO IS NULL) THEN
        DESCONTO = 0;

    SELECT
     COUNT(DISTINCT CD_VENDA),
     SUM(VALOR),
     SUM(DESCONTO)
    FROM
     CAIXA
    WHERE
     CAIXA.CD_FILIAL = :CD_FILIAL AND
     CAIXA.CD_FORMA_PAGAMENTO = :CD_FORMA_PAGAMENTO AND
     CAIXA.DATA_CAIXA = :DIA AND
     CAIXA.TIPO_VENDA = 'D'
    INTO
     :NUMERO_DE_CANCELAMENTOS,
     :VALOR_CANCELADO,
     :DESCONTO_CANCELADO;

    IF (:NUMERO_DE_CANCELAMENTOS IS NULL) THEN
        NUMERO_DE_CANCELAMENTOS = 0;
    IF (:VALOR_CANCELADO IS NULL) THEN
        VALOR_CANCELADO = 0;
    IF (:DESCONTO_CANCELADO IS NULL) THEN
        DESCONTO_CANCELADO = 0;

    NUMERO_DE_VENDAS = :NUMERO_DE_VENDAS - :NUMERO_DE_CANCELAMENTOS;
    VALOR_VENDIDO = :VALOR_VENDIDO - :VALOR_CANCELADO;
    DESCONTO = :DESCONTO - :DESCONTO_CANCELADO;
    IF (:NUMERO_DE_VENDAS = 0) THEN
     BEGIN
       TICKET = 0;
     END
    ELSE
     BEGIN
       TICKET = (:VALOR_VENDIDO / :NUMERO_DE_VENDAS);
     END

    SELECT NOME FROM FILIAIS WHERE CD_FILIAL = :CD_FILIAL INTO :FILIAL;
    SELECT DESCRICAO FROM FORMAS_PAGAMENTO WHERE CD_FORMA_PAGAMENTO = :CD_FORMA_PAGAMENTO INTO :FORMA_PAGAMENTO;

    SUSPEND;
  END
END ^

ALTER PROCEDURE SP_OLAP_VENDAS_GRUPO (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (FILIAL VARCHAR(100) CHARACTER SET NONE,
GRUPO VARCHAR(100) CHARACTER SET NONE,
DIA DATE,
VENDEDOR VARCHAR(100) CHARACTER SET NONE,
QUANTIDADE_VENDIDA DOUBLE PRECISION,
NUMERO_DE_VENDAS DOUBLE PRECISION,
VALOR_VENDAS DOUBLE PRECISION,
CUSTO_VENDAS DOUBLE PRECISION,
COMISSAO DOUBLE PRECISION,
DESCONTO DOUBLE PRECISION,
PROMOCAO DOUBLE PRECISION,
VALOR_VENDAS_DIA DOUBLE PRECISION)
AS 
declare variable QUANTIDADE_CANCELADA integer;
declare variable NUMERO_DE_CANCELAMENTOS integer;
declare variable VALOR_CANCELAMENTO double precision;
declare variable CUSTO_CANCELAMENTO double precision;
declare variable COMISSAO_CANCELADA double precision;
declare variable DESCONTO_CANCELADO double precision;
declare variable PROMOCAO_CANCELADO double precision;
declare variable CD_FILIAL double precision;
declare variable CD_GRUPO double precision;
declare variable CD_VENDEDOR double precision;
declare variable CD_CLASSE double precision;
declare variable VALOR_CANCELAMENTO_DIA double precision;
BEGIN
  VALOR_VENDAS_DIA = 0;
  VALOR_CANCELAMENTO_DIA = 0;

  SELECT
   SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO)
  FROM
   LANCAMENTOS
  WHERE
   LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
   LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
   LANCAMENTOS.TIPO_VENDA = 'V' /*AND
   LANCAMENTOS.CUSTO_MEDIO > 0*/
  INTO
   :VALOR_VENDAS_DIA;

  SELECT
   SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO)
  FROM
   LANCAMENTOS
  WHERE
   LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
   LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
   LANCAMENTOS.TIPO_VENDA = 'D' --AND
   --LANCAMENTOS.TROCA = 'F'
   --LANCAMENTOS.CUSTO_MEDIO > 0
  INTO
   :VALOR_CANCELAMENTO_DIA;

  IF (:VALOR_VENDAS_DIA IS NULL) THEN
     VALOR_VENDAS_DIA = 0;
  IF (:VALOR_CANCELAMENTO_DIA IS NULL) THEN
     VALOR_CANCELAMENTO_DIA = 0;

  VALOR_VENDAS_DIA = :VALOR_VENDAS_DIA - :VALOR_CANCELAMENTO_DIA;

 FOR
    SELECT
     LANCAMENTOS.CD_FILIAL,
     LANCAMENTOS.CD_CLASSE,
     LANCAMENTOS.CD_GRUPO,
     LANCAMENTOS.DATA_LANCAMENTO,
     LANCAMENTOS.CD_VENDEDOR
    FROM
     LANCAMENTOS
    WHERE
     LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
     LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
     (LANCAMENTOS.TIPO_VENDA = 'D' OR LANCAMENTOS.TIPO_VENDA = 'V')
    GROUP BY
     LANCAMENTOS.CD_FILIAL,
     LANCAMENTOS.CD_CLASSE,
     LANCAMENTOS.CD_GRUPO,
     LANCAMENTOS.DATA_LANCAMENTO,
     LANCAMENTOS.CD_VENDEDOR
    INTO
     :CD_FILIAL,
     :CD_CLASSE,
     :CD_GRUPO,
     :DIA,
     :CD_VENDEDOR
 DO
  BEGIN
    QUANTIDADE_VENDIDA = 0;
    NUMERO_DE_VENDAS = 0;
    VALOR_VENDAS = 0;
    CUSTO_VENDAS = 0;
    COMISSAO = 0;
    DESCONTO = 0;

    SELECT
     SUM(LANCAMENTOS.QUANTIDADE),
     COUNT(DISTINCT LANCAMENTOS.CD_VENDA),
     SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
     SUM(LANCAMENTOS.CUSTO_MEDIO * LANCAMENTOS.QUANTIDADE),
     SUM(LANCAMENTOS.COMISSAO),
     SUM(LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE),
     SUM(LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)
    FROM
     LANCAMENTOS
    WHERE
     LANCAMENTOS.DATA_LANCAMENTO = :DIA AND
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
     LANCAMENTOS.CD_GRUPO = :CD_GRUPO AND
     LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR AND
     LANCAMENTOS.TIPO_VENDA = 'V' /*AND
     LANCAMENTOS.CUSTO_MEDIO > 0*/
    INTO
     :QUANTIDADE_VENDIDA,
     :NUMERO_DE_VENDAS,
     :VALOR_VENDAS,
     :CUSTO_VENDAS,
     :COMISSAO,
     :DESCONTO,
     :PROMOCAO;

    IF (:QUANTIDADE_VENDIDA IS NULL) THEN
       QUANTIDADE_VENDIDA = 0;
    IF (:NUMERO_DE_VENDAS IS NULL) THEN
       NUMERO_DE_VENDAS = 0;
    IF (:VALOR_VENDAS IS NULL) THEN
       VALOR_VENDAS = 0;
    IF (:CUSTO_VENDAS IS NULL) THEN
       CUSTO_VENDAS = 0;
    IF (:COMISSAO IS NULL) THEN
       COMISSAO = 0;
    IF (:DESCONTO IS NULL) THEN
       DESCONTO = 0;
    IF (:PROMOCAO IS NULL) THEN
       PROMOCAO = 0;

    QUANTIDADE_CANCELADA = 0;
    NUMERO_DE_CANCELAMENTOS = 0;
    VALOR_CANCELAMENTO = 0;
    CUSTO_CANCELAMENTO = 0;
    COMISSAO_CANCELADA = 0;
    DESCONTO_CANCELADO = 0;
    PROMOCAO_CANCELADO = 0;

    SELECT
     SUM(LANCAMENTOS.QUANTIDADE),
     COUNT(DISTINCT LANCAMENTOS.CD_VENDA),
     SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
     SUM(LANCAMENTOS.CUSTO_MEDIO * LANCAMENTOS.QUANTIDADE),
     SUM(LANCAMENTOS.COMISSAO),
     SUM(LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE),
     SUM(LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)
    FROM
     LANCAMENTOS
    WHERE
     LANCAMENTOS.DATA_LANCAMENTO = :DIA AND
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
     LANCAMENTOS.CD_GRUPO = :CD_GRUPO AND
     LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR AND
     LANCAMENTOS.TIPO_VENDA = 'D' /*AND
     LANCAMENTOS.TROCA = 'F' /*AND
     LANCAMENTOS.CUSTO_MEDIO > 0*/
    INTO
     :QUANTIDADE_CANCELADA,
     :NUMERO_DE_CANCELAMENTOS,
     :VALOR_CANCELAMENTO,
     :CUSTO_CANCELAMENTO,
     :COMISSAO_CANCELADA,
     :DESCONTO_CANCELADO,
     :PROMOCAO_CANCELADO;

    IF (:QUANTIDADE_CANCELADA IS NULL) THEN
       QUANTIDADE_CANCELADA = 0;
    IF (:NUMERO_DE_CANCELAMENTOS IS NULL) THEN
       NUMERO_DE_CANCELAMENTOS = 0;
    IF (:VALOR_CANCELAMENTO IS NULL) THEN
       VALOR_CANCELAMENTO = 0;
    IF (:CUSTO_CANCELAMENTO IS NULL) THEN
       CUSTO_CANCELAMENTO = 0;
    IF (:COMISSAO_CANCELADA IS NULL) THEN
       COMISSAO_CANCELADA = 0;
    IF (:DESCONTO_CANCELADO IS NULL) THEN
       DESCONTO_CANCELADO = 0;
    IF (:PROMOCAO_CANCELADO IS NULL) THEN
       PROMOCAO_CANCELADO = 0;

    QUANTIDADE_VENDIDA = :QUANTIDADE_VENDIDA - :QUANTIDADE_CANCELADA;
    NUMERO_DE_VENDAS = :NUMERO_DE_VENDAS - :NUMERO_DE_CANCELAMENTOS;
    VALOR_VENDAS = :VALOR_VENDAS - :VALOR_CANCELAMENTO;
    CUSTO_VENDAS = :CUSTO_VENDAS - :CUSTO_CANCELAMENTO;
    COMISSAO = :COMISSAO - :COMISSAO_CANCELADA;
    DESCONTO = :DESCONTO - :DESCONTO_CANCELADO;
    PROMOCAO = :PROMOCAO - :PROMOCAO_CANCELADO;

    SELECT NOME FROM FILIAIS WHERE CD_FILIAL = :CD_FILIAL INTO :FILIAL;
    SELECT DESCRICAO FROM GRUPOS WHERE CD_GRUPO = :CD_GRUPO INTO :GRUPO;
    SELECT NOME FROM VENDEDORES WHERE CD_VENDEDOR = :CD_VENDEDOR INTO :VENDEDOR;
   /* IF (:VALOR_VENDAS > 0) THEN*/
       SUSPEND;
  END
END ^

ALTER PROCEDURE SP_OLAP_VENDAS_LABORATORIO (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (FILIAL VARCHAR(100) CHARACTER SET NONE,
LABORATORIO VARCHAR(100) CHARACTER SET NONE,
DIA DATE,
VENDEDOR VARCHAR(100) CHARACTER SET NONE,
QUANTIDADE_VENDIDA DOUBLE PRECISION,
NUMERO_DE_VENDAS DOUBLE PRECISION,
VALOR_VENDAS DOUBLE PRECISION,
CUSTO_VENDAS DOUBLE PRECISION,
COMISSAO DOUBLE PRECISION,
DESCONTO DOUBLE PRECISION,
PROMOCAO DOUBLE PRECISION)
AS 
declare variable QUANTIDADE_CANCELADA integer;
declare variable NUMERO_DE_CANCELAMENTOS integer;
declare variable VALOR_CANCELAMENTO double precision;
declare variable CUSTO_CANCELAMENTO double precision;
declare variable COMISSAO_CANCELADA double precision;
declare variable DESCONTO_CANCELADO double precision;
declare variable PROMOCAO_CANCELADO double precision;
declare variable CD_FILIAL double precision;
declare variable CD_LABORATORIO double precision;
declare variable CD_VENDEDOR double precision;
BEGIN
 FOR
    SELECT
     LANCAMENTOS.CD_FILIAL,
     LANCAMENTOS.CD_LABORATORIO,
     LANCAMENTOS.DATA_LANCAMENTO,
     LANCAMENTOS.CD_VENDEDOR
    FROM
     LANCAMENTOS
    WHERE
     LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
     LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
     (LANCAMENTOS.TIPO_VENDA = 'D' OR LANCAMENTOS.TIPO_VENDA = 'V')
    GROUP BY
     LANCAMENTOS.DATA_LANCAMENTO,
     LANCAMENTOS.CD_FILIAL,
     LANCAMENTOS.CD_VENDEDOR,
     LANCAMENTOS.CD_LABORATORIO
    INTO
     :CD_FILIAL,
     :CD_LABORATORIO,
     :DIA,
     :CD_VENDEDOR
 DO
  BEGIN
    QUANTIDADE_VENDIDA = 0;
    NUMERO_DE_VENDAS = 0;
    VALOR_VENDAS = 0;
    CUSTO_VENDAS = 0;
    COMISSAO = 0;
    DESCONTO = 0;

    SELECT
     SUM(LANCAMENTOS.QUANTIDADE),
     COUNT(DISTINCT LANCAMENTOS.CD_VENDA),
     SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
     SUM(LANCAMENTOS.CUSTO_MEDIO * LANCAMENTOS.QUANTIDADE),
     SUM(LANCAMENTOS.COMISSAO),
     SUM(LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE),
     SUM(LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)
    FROM
     LANCAMENTOS
    WHERE
     LANCAMENTOS.DATA_LANCAMENTO = :DIA AND
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.CD_LABORATORIO = :CD_LABORATORIO AND
     LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR AND
     LANCAMENTOS.TIPO_VENDA = 'V'/* AND
     LANCAMENTOS.CUSTO_MEDIO > 0*/
    INTO
     :QUANTIDADE_VENDIDA,
     :NUMERO_DE_VENDAS,
     :VALOR_VENDAS,
     :CUSTO_VENDAS,
     :COMISSAO,
     :DESCONTO,
     :PROMOCAO;

    IF (:QUANTIDADE_VENDIDA IS NULL) THEN
       QUANTIDADE_VENDIDA = 0;
    IF (:NUMERO_DE_VENDAS IS NULL) THEN
       NUMERO_DE_VENDAS = 0;
    IF (:VALOR_VENDAS IS NULL) THEN
       VALOR_VENDAS = 0;
    IF (:CUSTO_VENDAS IS NULL) THEN
       CUSTO_VENDAS = 0;
    IF (:COMISSAO IS NULL) THEN
       COMISSAO = 0;
    IF (:DESCONTO IS NULL) THEN
       DESCONTO = 0;
    IF (:PROMOCAO IS NULL) THEN
       PROMOCAO = 0;

     QUANTIDADE_CANCELADA = 0;
     NUMERO_DE_CANCELAMENTOS  = 0;
     VALOR_CANCELAMENTO = 0;
     CUSTO_CANCELAMENTO = 0;
     COMISSAO_CANCELADA = 0;
     DESCONTO_CANCELADO = 0;
     PROMOCAO_CANCELADO = 0;

    SELECT
     SUM(LANCAMENTOS.QUANTIDADE),
     COUNT(DISTINCT LANCAMENTOS.CD_VENDA),
     SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
     SUM(LANCAMENTOS.CUSTO_MEDIO * LANCAMENTOS.QUANTIDADE),
     SUM(LANCAMENTOS.COMISSAO),
     SUM(LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE),
     SUM(LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)
    FROM
     LANCAMENTOS
    WHERE
     LANCAMENTOS.DATA_LANCAMENTO = :DIA AND
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.CD_LABORATORIO = :CD_LABORATORIO AND
     LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR AND
     LANCAMENTOS.TIPO_VENDA = 'D' /*AND
     LANCAMENTOS.TROCA = 'F' /*AND
     LANCAMENTOS.CUSTO_MEDIO > 0*/
    INTO
     :QUANTIDADE_CANCELADA,
     :NUMERO_DE_CANCELAMENTOS,
     :VALOR_CANCELAMENTO,
     :CUSTO_CANCELAMENTO,
     :COMISSAO_CANCELADA,
     :DESCONTO_CANCELADO,
     :PROMOCAO_CANCELADO;

    IF (:QUANTIDADE_CANCELADA IS NULL) THEN
       QUANTIDADE_CANCELADA = 0;
    IF (:NUMERO_DE_CANCELAMENTOS IS NULL) THEN
       NUMERO_DE_CANCELAMENTOS = 0;
    IF (:VALOR_CANCELAMENTO IS NULL) THEN
       VALOR_CANCELAMENTO = 0;
    IF (:CUSTO_CANCELAMENTO IS NULL) THEN
       CUSTO_CANCELAMENTO = 0;
    IF (:COMISSAO_CANCELADA IS NULL) THEN
       COMISSAO_CANCELADA = 0;
    IF (:DESCONTO_CANCELADO IS NULL) THEN
       DESCONTO_CANCELADO = 0;
    IF (:PROMOCAO_CANCELADO IS NULL) THEN
       PROMOCAO_CANCELADO = 0;

    QUANTIDADE_VENDIDA = :QUANTIDADE_VENDIDA - :QUANTIDADE_CANCELADA;
    NUMERO_DE_VENDAS = :NUMERO_DE_VENDAS - :NUMERO_DE_CANCELAMENTOS;
    VALOR_VENDAS = :VALOR_VENDAS - :VALOR_CANCELAMENTO;
    CUSTO_VENDAS = :CUSTO_VENDAS - :CUSTO_CANCELAMENTO;
    COMISSAO = :COMISSAO - :COMISSAO_CANCELADA;
    DESCONTO = :DESCONTO - :DESCONTO_CANCELADO;
    PROMOCAO = :PROMOCAO - :PROMOCAO_CANCELADO;

    SELECT NOME FROM FILIAIS WHERE CD_FILIAL = :CD_FILIAL INTO :FILIAL;
    SELECT NOME FROM LABORATORIOS WHERE CD_LABORATORIO = :CD_LABORATORIO INTO :LABORATORIO;
    SELECT NOME FROM VENDEDORES WHERE CD_VENDEDOR = :CD_VENDEDOR INTO :VENDEDOR;
    /*IF (:VALOR_VENDAS > 0) THEN */
       SUSPEND;
  END
END ^

ALTER PROCEDURE SP_OLAP_VENDAS_LABORATORIO_PROD (CD_LABORATORIO DOUBLE PRECISION,
DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (CD_FILIAL DOUBLE PRECISION,
FILIAL VARCHAR(100) CHARACTER SET NONE,
ID_PRODUTO DOUBLE PRECISION,
PRODUTO VARCHAR(100) CHARACTER SET NONE,
CODIGOBARRAS VARCHAR(14) CHARACTER SET NONE,
ESTOQUE DOUBLE PRECISION,
LABORATORIO VARCHAR(100) CHARACTER SET NONE,
QUANTIDADE_VENDIDA DOUBLE PRECISION,
NUMERO_DE_VENDAS DOUBLE PRECISION,
VALOR_VENDAS DOUBLE PRECISION,
CUSTO_VENDAS DOUBLE PRECISION,
COMISSAO DOUBLE PRECISION,
DESCONTO DOUBLE PRECISION,
PROMOCAO DOUBLE PRECISION)
AS 
declare variable COMANDO varchar(1000);
declare variable QUANTIDADE_CANCELADA double precision;
declare variable NUMERO_DE_CANCELAMENTOS double precision;
declare variable VALOR_CANCELAMENTO double precision;
declare variable CUSTO_CANCELAMENTO double precision;
declare variable COMISSAO_CANCELADA double precision;
declare variable DESCONTO_CANCELADO double precision;
declare variable PROMOCAO_CANCELADO double precision;
BEGIN
  FOR
    SELECT
     FILIAIS.CD_FILIAL,
     FILIAIS.NOME
    FROM
     FILIAIS
    INTO
     :CD_FILIAL,
     :FILIAL
  DO
   BEGIN
     COMANDO = '';
     COMANDO = 'SELECT PRODUTOS.ID_PRODUTO, PRODUTOS.DESCRICAO, PRODUTOS.CODIGO_BARRAS_1, PRODUTOS.ESTOQUE_' || CAST(:CD_FILIAL AS INTEGER) || ', ' ||
               ' LABORATORIOS.NOME FROM PRODUTOS, LABORATORIOS ' ||
               ' WHERE PRODUTOS.CD_LABORATORIO = LABORATORIOS.CD_LABORATORIO AND LABORATORIOS.CD_LABORATORIO = ' || CAST(:CD_LABORATORIO AS INTEGER) ;
     FOR
       EXECUTE STATEMENT :COMANDO INTO :ID_PRODUTO, :PRODUTO, :CODIGOBARRAS, :ESTOQUE, :LABORATORIO
     DO
      BEGIN
        QUANTIDADE_VENDIDA = 0;
        NUMERO_DE_VENDAS = 0;
        VALOR_VENDAS = 0;
        CUSTO_VENDAS = 0;
        COMISSAO = 0;
        DESCONTO = 0;
    
        SELECT
         SUM(LANCAMENTOS.QUANTIDADE),
         COUNT(DISTINCT LANCAMENTOS.CD_VENDA),
         SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
         SUM(LANCAMENTOS.CUSTO_MEDIO * LANCAMENTOS.QUANTIDADE),
         SUM(LANCAMENTOS.COMISSAO),
         SUM(LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE),
         SUM(LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)
        FROM
         LANCAMENTOS
        WHERE
         LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
         LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
         LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
         LANCAMENTOS.ID_PRODUTO = :ID_PRODUTO AND
         LANCAMENTOS.TIPO_VENDA = 'V'
        INTO
         :QUANTIDADE_VENDIDA,
         :NUMERO_DE_VENDAS,
         :VALOR_VENDAS,
         :CUSTO_VENDAS,
         :COMISSAO,
         :DESCONTO,
         :PROMOCAO;
    
        IF (:QUANTIDADE_VENDIDA IS NULL) THEN
           QUANTIDADE_VENDIDA = 0;
        IF (:NUMERO_DE_VENDAS IS NULL) THEN
           NUMERO_DE_VENDAS = 0;
        IF (:VALOR_VENDAS IS NULL) THEN
           VALOR_VENDAS = 0;
        IF (:CUSTO_VENDAS IS NULL) THEN
           CUSTO_VENDAS = 0;
        IF (:COMISSAO IS NULL) THEN
           COMISSAO = 0;
        IF (:DESCONTO IS NULL) THEN
           DESCONTO = 0;
        IF (:PROMOCAO IS NULL) THEN
           PROMOCAO = 0;
    
         QUANTIDADE_CANCELADA = 0;
         NUMERO_DE_CANCELAMENTOS  = 0;
         VALOR_CANCELAMENTO = 0;
         CUSTO_CANCELAMENTO = 0;
         COMISSAO_CANCELADA = 0;
         DESCONTO_CANCELADO = 0;
         PROMOCAO_CANCELADO = 0;
    
        SELECT
         SUM(LANCAMENTOS.QUANTIDADE),
         COUNT(DISTINCT LANCAMENTOS.CD_VENDA),
         SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
         SUM(LANCAMENTOS.CUSTO_MEDIO * LANCAMENTOS.QUANTIDADE),
         SUM(LANCAMENTOS.COMISSAO),
         SUM(LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE),
         SUM(LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)
        FROM
         LANCAMENTOS
        WHERE
         LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
         LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
         LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
         LANCAMENTOS.ID_PRODUTO = :ID_PRODUTO AND
         LANCAMENTOS.TIPO_VENDA = 'D'
        INTO
         :QUANTIDADE_CANCELADA,
         :NUMERO_DE_CANCELAMENTOS,
         :VALOR_CANCELAMENTO,
         :CUSTO_CANCELAMENTO,
         :COMISSAO_CANCELADA,
         :DESCONTO_CANCELADO,
         :PROMOCAO_CANCELADO;
    
        IF (:QUANTIDADE_CANCELADA IS NULL) THEN
           QUANTIDADE_CANCELADA = 0;
        IF (:NUMERO_DE_CANCELAMENTOS IS NULL) THEN
           NUMERO_DE_CANCELAMENTOS = 0;
        IF (:VALOR_CANCELAMENTO IS NULL) THEN
           VALOR_CANCELAMENTO = 0;
        IF (:CUSTO_CANCELAMENTO IS NULL) THEN
           CUSTO_CANCELAMENTO = 0;
        IF (:COMISSAO_CANCELADA IS NULL) THEN
           COMISSAO_CANCELADA = 0;
        IF (:DESCONTO_CANCELADO IS NULL) THEN
           DESCONTO_CANCELADO = 0;
        IF (:PROMOCAO_CANCELADO IS NULL) THEN
           PROMOCAO_CANCELADO = 0;
    
        QUANTIDADE_VENDIDA = :QUANTIDADE_VENDIDA - :QUANTIDADE_CANCELADA;
        NUMERO_DE_VENDAS = :NUMERO_DE_VENDAS - :NUMERO_DE_CANCELAMENTOS;
        VALOR_VENDAS = :VALOR_VENDAS - :VALOR_CANCELAMENTO;
        CUSTO_VENDAS = :CUSTO_VENDAS - :CUSTO_CANCELAMENTO;
        COMISSAO = :COMISSAO - :COMISSAO_CANCELADA;
        DESCONTO = :DESCONTO - :DESCONTO_CANCELADO;
        PROMOCAO = :PROMOCAO - :PROMOCAO_CANCELADO;
    
        SUSPEND;
      END
   END
END ^

ALTER PROCEDURE SP_OLAP_VENDAS_PRODUTO (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (FILIAL VARCHAR(100) CHARACTER SET NONE,
PRODUTO VARCHAR(100) CHARACTER SET NONE,
DIA DATE,
QUANTIDADE_VENDIDA DOUBLE PRECISION,
VALOR_VENDAS DOUBLE PRECISION,
CUSTO_DAS_VENDAS DOUBLE PRECISION,
COMISSAO DOUBLE PRECISION,
DESCONTO DOUBLE PRECISION,
PROMOCAO DOUBLE PRECISION,
NUMERO_DE_VENDAS DOUBLE PRECISION,
LUCRO_BRUTO DOUBLE PRECISION,
MARGEM DOUBLE PRECISION)
AS 
declare variable QUANTIDADE_CANCELADA integer;
declare variable NUMERO_DE_CANCELAMENTOS integer;
declare variable VALOR_CANCELAMENTO double precision;
declare variable CUSTO_CANCELAMENTO double precision;
declare variable COMISSAO_CANCELADA double precision;
declare variable DESCONTO_CANCELADO double precision;
declare variable PROMOCAO_CANCELADO double precision;
declare variable ID_PRODUTO double precision;
declare variable CD_FILIAL double precision;
declare variable CD_GRUPO double precision;
BEGIN
 FOR
    SELECT
     LANCAMENTOS.CD_FILIAL,
     LANCAMENTOS.DATA_LANCAMENTO
    FROM
     LANCAMENTOS
    WHERE
     LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
     LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
     (LANCAMENTOS.TIPO_VENDA = 'D' OR LANCAMENTOS.TIPO_VENDA = 'V')
    GROUP BY
     LANCAMENTOS.DATA_LANCAMENTO,
     LANCAMENTOS.CD_FILIAL
    INTO
     :CD_FILIAL,
     :DIA
 DO
  BEGIN
    FOR
     SELECT
       LANCAMENTOS.CD_GRUPO,
       LANCAMENTOS.ID_PRODUTO,
       LANCAMENTOS.DESCRICAO
      FROM
       LANCAMENTOS
      WHERE
       LANCAMENTOS.DATA_LANCAMENTO = :DIA AND
       LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
       (LANCAMENTOS.TIPO_VENDA = 'D' OR LANCAMENTOS.TIPO_VENDA = 'V')
      GROUP BY
       LANCAMENTOS.CD_GRUPO,
       LANCAMENTOS.ID_PRODUTO,
       LANCAMENTOS.DESCRICAO
      INTO
       :CD_GRUPO,
       :ID_PRODUTO,
       :PRODUTO
    DO
     BEGIN
        QUANTIDADE_VENDIDA = 0;
        NUMERO_DE_VENDAS = 0;
        VALOR_VENDAS = 0;
        CUSTO_DAS_VENDAS = 0;
        COMISSAO = 0;
        DESCONTO = 0;
        PROMOCAO = 0;
        LUCRO_BRUTO = 0;
        MARGEM = 0;
    
        SELECT
         SUM(LANCAMENTOS.QUANTIDADE),
         COUNT(DISTINCT LANCAMENTOS.CD_VENDA),
         SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
         SUM(LANCAMENTOS.CUSTO_MEDIO * LANCAMENTOS.QUANTIDADE),
         SUM(LANCAMENTOS.COMISSAO),
         SUM(LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE),
         SUM(LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)
        FROM
         LANCAMENTOS
        WHERE
         LANCAMENTOS.DATA_LANCAMENTO = :DIA AND
         LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
         LANCAMENTOS.CD_GRUPO = :CD_GRUPO AND
         LANCAMENTOS.TIPO_VENDA = 'V' AND
         LANCAMENTOS.ID_PRODUTO = :ID_PRODUTO
        INTO
         :QUANTIDADE_VENDIDA,
         :NUMERO_DE_VENDAS,
         :VALOR_VENDAS,
         :CUSTO_DAS_VENDAS,
         :COMISSAO,
         :DESCONTO,
         :PROMOCAO;
    
        IF (:QUANTIDADE_VENDIDA IS NULL) THEN
           QUANTIDADE_VENDIDA = 0;
        IF (:NUMERO_DE_VENDAS IS NULL) THEN
           NUMERO_DE_VENDAS = 0;
        IF (:VALOR_VENDAS IS NULL) THEN
           VALOR_VENDAS = 0;
        IF (:CUSTO_DAS_VENDAS IS NULL) THEN
           CUSTO_DAS_VENDAS = 0;
        IF (:COMISSAO IS NULL) THEN
           COMISSAO = 0;
        IF (:DESCONTO IS NULL) THEN
           DESCONTO = 0;
        IF (:PROMOCAO IS NULL) THEN
           PROMOCAO = 0;

        QUANTIDADE_CANCELADA = 0;
        NUMERO_DE_CANCELAMENTOS  = 0;
        VALOR_CANCELAMENTO = 0;
        CUSTO_CANCELAMENTO = 0;
        COMISSAO_CANCELADA = 0;
        DESCONTO_CANCELADO = 0;
        PROMOCAO_CANCELADO = 0;
    
        SELECT
         SUM(LANCAMENTOS.QUANTIDADE),
         COUNT(DISTINCT LANCAMENTOS.CD_VENDA),
         SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
         SUM(LANCAMENTOS.CUSTO_MEDIO * LANCAMENTOS.QUANTIDADE),
         SUM(LANCAMENTOS.COMISSAO),
         SUM(LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE),
         SUM(LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)
        FROM
         LANCAMENTOS
        WHERE
         LANCAMENTOS.DATA_LANCAMENTO = :DIA AND
         LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
         LANCAMENTOS.CD_GRUPO = :CD_GRUPO AND
         LANCAMENTOS.TIPO_VENDA = 'D' AND
         --LANCAMENTOS.TROCA = 'F' AND
         LANCAMENTOS.ID_PRODUTO = :ID_PRODUTO
        INTO
         :QUANTIDADE_CANCELADA,
         :NUMERO_DE_CANCELAMENTOS,
         :VALOR_CANCELAMENTO,
         :CUSTO_CANCELAMENTO,
         :COMISSAO_CANCELADA,
         :DESCONTO_CANCELADO,
         :PROMOCAO_CANCELADO;
    
        IF (:QUANTIDADE_CANCELADA IS NULL) THEN
           QUANTIDADE_CANCELADA = 0;
        IF (:NUMERO_DE_CANCELAMENTOS IS NULL) THEN
           NUMERO_DE_CANCELAMENTOS = 0;
        IF (:VALOR_CANCELAMENTO IS NULL) THEN
           VALOR_CANCELAMENTO = 0;
        IF (:CUSTO_CANCELAMENTO IS NULL) THEN
           CUSTO_CANCELAMENTO = 0;
        IF (:COMISSAO_CANCELADA IS NULL) THEN
           COMISSAO_CANCELADA = 0;
        IF (:DESCONTO_CANCELADO IS NULL) THEN
           DESCONTO_CANCELADO = 0;
        IF (:PROMOCAO_CANCELADO IS NULL) THEN
           PROMOCAO_CANCELADO = 0;
    
        QUANTIDADE_VENDIDA = :QUANTIDADE_VENDIDA - :QUANTIDADE_CANCELADA;
        NUMERO_DE_VENDAS = :NUMERO_DE_VENDAS - :NUMERO_DE_CANCELAMENTOS;
        VALOR_VENDAS = :VALOR_VENDAS - :VALOR_CANCELAMENTO;
        CUSTO_DAS_VENDAS = :CUSTO_DAS_VENDAS - :CUSTO_CANCELAMENTO;
        COMISSAO = :COMISSAO - :COMISSAO_CANCELADA;
        DESCONTO = :DESCONTO - :DESCONTO_CANCELADO;
        PROMOCAO = :PROMOCAO - :PROMOCAO_CANCELADO;

        IF (:VALOR_VENDAS = 0) THEN
         BEGIN
           MARGEM = 0;
         END
        ELSE
         BEGIN
           LUCRO_BRUTO = :VALOR_VENDAS - :CUSTO_DAS_VENDAS;
           MARGEM = (:VALOR_VENDAS - :CUSTO_DAS_VENDAS)/:VALOR_VENDAS * 100;
           IF ((:MARGEM IS NULL) OR (:MARGEM < 0)) THEN
              MARGEM = 0;
         END

        SELECT NOME FROM FILIAIS WHERE CD_FILIAL = :CD_FILIAL INTO :FILIAL;
        SUSPEND;
     END
  END
END ^

ALTER PROCEDURE SP_OLAP_VENDAS_REALIZADAS (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (FILIAL VARCHAR(100) CHARACTER SET NONE,
DATA DATE,
VENDEDOR VARCHAR(100) CHARACTER SET NONE,
GRUPO VARCHAR(100) CHARACTER SET NONE,
LABORATORIO VARCHAR(100) CHARACTER SET NONE,
CLASSE VARCHAR(100) CHARACTER SET NONE,
PRODUTO VARCHAR(100) CHARACTER SET NONE,
QUANTIDADE DOUBLE PRECISION,
VALOR DOUBLE PRECISION,
CUSTO DOUBLE PRECISION,
LUCRO DOUBLE PRECISION,
MARGEM DOUBLE PRECISION)
AS 
declare variable QUANTIDADE_C double precision;
declare variable VALOR_C double precision;
declare variable CUSTO_C double precision;
declare variable LUCRO_C double precision;
declare variable MARGEM_C double precision;
declare variable CD_FILIAL double precision;
declare variable CD_GRUPO double precision;
declare variable CD_VENDEDOR double precision;
declare variable CD_LABORATORIO double precision;
declare variable ID_PRODUTO double precision;
declare variable CD_CLASSE double precision;
BEGIN
 FOR
    SELECT
     LANCAMENTOS.DATA_LANCAMENTO,
     LANCAMENTOS.CD_FILIAL,
     LANCAMENTOS.CD_GRUPO,
     LANCAMENTOS.ID_PRODUTO,
     LANCAMENTOS.CD_VENDEDOR,
     LANCAMENTOS.CD_LABORATORIO,
     LANCAMENTOS.CD_CLASSE
    FROM
     LANCAMENTOS
    WHERE
     LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
