     SUM(LANCAMENTOS.CUSTO_MEDIO * LANCAMENTOS.QUANTIDADE),
     SUM((LANCAMENTOS.VALOR / LANCAMENTOS.QUANTIDADE) -  LANCAMENTOS.CUSTO_MEDIO),
     SUM((((LANCAMENTOS.VALOR / LANCAMENTOS.QUANTIDADE) - LANCAMENTOS.CUSTO_MEDIO)  * 100) / LANCAMENTOS.CUSTO_MEDIO) /
      COUNT(LANCAMENTOS.CD_LANCAMENTO)
    FROM
     LANCAMENTOS
    WHERE
     LANCAMENTOS.DATA_LANCAMENTO = :DATA AND
     LANCAMENTOS.CD_FILIAL  = :CD_FILIAL AND
     LANCAMENTOS.CD_LABORATORIO = :CD_LABORATORIO AND
     LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR AND
     LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
     LANCAMENTOS.TIPO_VENDA = 'D' AND
     --LANCAMENTOS.TROCA = 'F' AND
     LANCAMENTOS.CD_GRUPO = :CD_GRUPO AND
     LANCAMENTOS.ID_PRODUTO = :ID_PRODUTO AND
     --LANCAMENTOS.CUSTO_MEDIO > 0 AND
     LANCAMENTOS.QUANTIDADE > 0
    INTO
     :QUANTIDADE_C,
     :VALOR_C,
     :CUSTO_C,
     :LUCRO_C,
     :MARGEM_C;

     IF (:QUANTIDADE_C IS NULL) THEN
         QUANTIDADE_C = 0;
     IF (:VALOR_C IS NULL) THEN
         VALOR_C = 0;
     IF (:CUSTO_C IS NULL) THEN
         CUSTO_C = 0;
     IF (:LUCRO_C IS NULL) THEN
         LUCRO_C = 0;
     IF (:MARGEM_C IS NULL) THEN
         MARGEM_C = 0;

     QUANTIDADE = :QUANTIDADE - :QUANTIDADE_C;
     VALOR = :VALOR - :VALOR_C;
     CUSTO = :CUSTO - :CUSTO_C;
     LUCRO = :LUCRO - :LUCRO_C;
     MARGEM = :MARGEM - :MARGEM_C;

     SELECT NOME FROM FILIAIS WHERE CD_FILIAL = :CD_FILIAL INTO :FILIAL;
     SELECT DESCRICAO FROM GRUPOS WHERE CD_GRUPO = :CD_GRUPO INTO :GRUPO;
     SELECT NOME FROM LABORATORIOS WHERE CD_LABORATORIO = :CD_LABORATORIO INTO :LABORATORIO;
     SELECT NOME FROM VENDEDORES WHERE CD_VENDEDOR = :CD_VENDEDOR INTO :VENDEDOR;
     SELECT DESCRICAO FROM CLASSES WHERE CD_CLASSE = :CD_CLASSE INTO :CLASSE;
     COMANDO = '';
     COMANDO = 'SELECT DESCRICAO, ESTOQUE_' || CAST(:CD_FILIAL AS INTEGER) || ' FROM PRODUTOS WHERE ID_PRODUTO = ' || :ID_PRODUTO;
     EXECUTE STATEMENT :COMANDO INTO :PRODUTO, :ESTOQUE;
     /*IF (:VALOR > 0) THEN*/
        SUSPEND;
  END
END ^

ALTER PROCEDURE SP_OLAP_VENDAS_REALIZADAS_PALM (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (FILIAL VARCHAR(100) CHARACTER SET NONE,
DATA DATE,
VENDEDOR VARCHAR(100) CHARACTER SET NONE,
GRUPO VARCHAR(100) CHARACTER SET NONE,
LABORATORIO VARCHAR(100) CHARACTER SET NONE,
CLASSE VARCHAR(100) CHARACTER SET NONE,
PRODUTO VARCHAR(100) CHARACTER SET NONE,
QUANTIDADE DOUBLE PRECISION,
VALOR DOUBLE PRECISION,
CUSTO DOUBLE PRECISION,
LUCRO DOUBLE PRECISION,
MARGEM DOUBLE PRECISION,
FORMA VARCHAR(100) CHARACTER SET NONE,
CLIENTE VARCHAR(100) CHARACTER SET NONE,
OPERADOR VARCHAR(100) CHARACTER SET NONE)
AS 
declare variable QUANTIDADE_C double precision;
declare variable VALOR_C double precision;
declare variable CUSTO_C double precision;
declare variable LUCRO_C double precision;
declare variable MARGEM_C double precision;
declare variable CD_FILIAL double precision;
declare variable CD_GRUPO double precision;
declare variable CD_VENDEDOR double precision;
declare variable CD_LABORATORIO double precision;
declare variable ID_PRODUTO double precision;
declare variable CD_CLASSE double precision;
declare variable CD_FORMA double precision;
declare variable CD_CLIENTE double precision;
declare variable CD_OPERADOR double precision;
BEGIN
 FOR
    SELECT
     LANCAMENTOS.data_caixa,
     LANCAMENTOS.CD_FILIAL,
     LANCAMENTOS.CD_GRUPO,
     LANCAMENTOS.ID_PRODUTO,
     LANCAMENTOS.CD_VENDEDOR,
     LANCAMENTOS.CD_LABORATORIO,
     LANCAMENTOS.CD_CLASSE,
     LANCAMENTOS.CD_CLIENTE,
     LANCAMENTOS.CD_FORMA_PAGAMENTO,
     LANCAMENTOS.CD_OPERADOR
    FROM
     LANCAMENTOS
    WHERE
     LANCAMENTOS.data_caixa >= :DATAINICIAL AND
     LANCAMENTOS.data_caixa <= :DATAFINAL AND
     (LANCAMENTOS.TIPO_VENDA = 'D' OR LANCAMENTOS.TIPO_VENDA = 'V')
    GROUP BY
     LANCAMENTOS.data_caixa,
     LANCAMENTOS.CD_FILIAL, 
     LANCAMENTOS.CD_GRUPO,
     LANCAMENTOS.ID_PRODUTO,
     LANCAMENTOS.CD_VENDEDOR,
     LANCAMENTOS.CD_LABORATORIO,
     LANCAMENTOS.CD_CLASSE,
     LANCAMENTOS.CD_CLIENTE,
     LANCAMENTOS.CD_FORMA_PAGAMENTO,
     LANCAMENTOS.CD_OPERADOR
    INTO
     :DATA,
     :CD_FILIAL,
     :CD_GRUPO,
     :ID_PRODUTO,
     :CD_VENDEDOR,
     :CD_LABORATORIO,
     :CD_CLASSE,
     :CD_CLIENTE,
     :CD_FORMA,
     :CD_OPERADOR
 DO
  BEGIN
    QUANTIDADE = 0;
    VALOR = 0;
    CUSTO = 0;
    LUCRO = 0;
    MARGEM = 0;

    CLIENTE = '';

    SELECT
      SUM(LANCAMENTOS.QUANTIDADE),
      SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
      SUM(LANCAMENTOS.CUSTO_MEDIO * LANCAMENTOS.QUANTIDADE),
      SUM((LANCAMENTOS.VALOR / LANCAMENTOS.QUANTIDADE) -  LANCAMENTOS.CUSTO_MEDIO),
      SUM((((LANCAMENTOS.VALOR / LANCAMENTOS.QUANTIDADE) - LANCAMENTOS.CUSTO_MEDIO)  * 100) / LANCAMENTOS.CUSTO_MEDIO)
    FROM
      LANCAMENTOS
    WHERE
     LANCAMENTOS.data_caixa = :DATA AND
     LANCAMENTOS.CD_FILIAL  = :CD_FILIAL AND
     LANCAMENTOS.CD_LABORATORIO = :CD_LABORATORIO AND
     LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR AND
     LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
     LANCAMENTOS.TIPO_VENDA = 'V' AND
     LANCAMENTOS.CD_GRUPO = :CD_GRUPO AND
     LANCAMENTOS.ID_PRODUTO = :ID_PRODUTO AND
     LANCAMENTOS.CD_CLIENTE = :CD_CLIENTE AND
     LANCAMENTOS.cd_forma_pagamento = :CD_FORMA AND
     LANCAMENTOS.CD_OPERADOR = :CD_OPERADOR AND
     LANCAMENTOS.QUANTIDADE > 0
    INTO
     :QUANTIDADE,
     :VALOR,
     :CUSTO,
     :LUCRO,
     :MARGEM;

    IF (:QUANTIDADE IS NULL) THEN
        QUANTIDADE = 0;
    IF (:VALOR IS NULL) THEN
        VALOR = 0;
    IF (:CUSTO IS NULL) THEN
        CUSTO = 0;
    IF (:LUCRO IS NULL) THEN
        LUCRO = 0;
    IF (:MARGEM IS NULL) THEN
        MARGEM = 0;

    QUANTIDADE_C = 0;
    VALOR_C = 0;
    CUSTO_C = 0;
    LUCRO_C = 0;
    MARGEM_C = 0;

    SELECT
     SUM(LANCAMENTOS.QUANTIDADE),
     SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
     SUM(LANCAMENTOS.CUSTO_MEDIO * LANCAMENTOS.QUANTIDADE),
     SUM((LANCAMENTOS.VALOR / LANCAMENTOS.QUANTIDADE) -  LANCAMENTOS.CUSTO_MEDIO),
     SUM((((LANCAMENTOS.VALOR / LANCAMENTOS.QUANTIDADE) - LANCAMENTOS.CUSTO_MEDIO)  * 100) / LANCAMENTOS.CUSTO_MEDIO)
    FROM
     LANCAMENTOS
    WHERE
     LANCAMENTOS.data_caixa = :DATA AND
     LANCAMENTOS.CD_FILIAL  = :CD_FILIAL AND
     LANCAMENTOS.CD_LABORATORIO = :CD_LABORATORIO AND
     LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR AND
     LANCAMENTOS.CD_CLASSE = :CD_CLASSE AND
     LANCAMENTOS.TIPO_VENDA = 'D' AND
     --LANCAMENTOS.TROCA = 'F' AND
     LANCAMENTOS.CD_GRUPO = :CD_GRUPO AND
     LANCAMENTOS.ID_PRODUTO = :ID_PRODUTO AND
     LANCAMENTOS.CD_CLIENTE = :CD_CLIENTE AND
     LANCAMENTOS.cd_forma_pagamento = :CD_FORMA AND
     LANCAMENTOS.CD_OPERADOR = :CD_OPERADOR AND
     LANCAMENTOS.QUANTIDADE > 0
    INTO
     :QUANTIDADE_C,
     :VALOR_C,
     :CUSTO_C,
     :LUCRO_C,
     :MARGEM_C;

     IF (:QUANTIDADE_C IS NULL) THEN
         QUANTIDADE_C = 0;
     IF (:VALOR_C IS NULL) THEN
         VALOR_C = 0;
     IF (:CUSTO_C IS NULL) THEN
         CUSTO_C = 0;
     IF (:LUCRO_C IS NULL) THEN
         LUCRO_C = 0;
     IF (:MARGEM_C IS NULL) THEN
         MARGEM_C = 0;

     QUANTIDADE = :QUANTIDADE - :QUANTIDADE_C;
     VALOR = :VALOR - :VALOR_C;
     CUSTO = :CUSTO - :CUSTO_C;
     LUCRO = :LUCRO - :LUCRO_C;
     MARGEM = :MARGEM - :MARGEM_C;

     SELECT NOME FROM FILIAIS WHERE CD_FILIAL = :CD_FILIAL INTO :FILIAL;
     SELECT DESCRICAO FROM GRUPOS WHERE CD_GRUPO = :CD_GRUPO INTO :GRUPO;
     SELECT NOME FROM LABORATORIOS WHERE CD_LABORATORIO = :CD_LABORATORIO INTO :LABORATORIO;
     SELECT NOME FROM VENDEDORES WHERE CD_VENDEDOR = :CD_VENDEDOR INTO :VENDEDOR;
     SELECT DESCRICAO FROM CLASSES WHERE CD_CLASSE = :CD_CLASSE INTO :CLASSE;
     SELECT DESCRICAO FROM PRODUTOS WHERE ID_PRODUTO = :ID_PRODUTO INTO :PRODUTO;
     SELECT DESCRICAO FROM FORMAS_PAGAMENTO WHERE CD_FORMA_PAGAMENTO = :CD_FORMA INTO :FORMA;
     SELECT NOME FROM CLIENTES WHERE CD_CLIENTE = :CD_CLIENTE INTO :CLIENTE;
     SELECT FIRST 1 NOME FROM OPERADORES WHERE CD_OPERADOR = :CD_OPERADOR INTO :OPERADOR;
     /*IF (:VALOR > 0) THEN*/
        SUSPEND;
  END
END ^

ALTER PROCEDURE SP_OLAP_VENDAS_REAL_LAB_TODOS (LAB DOUBLE PRECISION,
DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (ID_PRODUTO DOUBLE PRECISION,
PRODUTO VARCHAR(100) CHARACTER SET NONE,
CODIGO_BARRAS_1 VARCHAR(14) CHARACTER SET NONE,
CODIGO_BARRAS_2 VARCHAR(14) CHARACTER SET NONE,
