AS 
declare variable QUANTIDADE_C double precision;
declare variable VALOR_C double precision;
declare variable CUSTO_C double precision;
declare variable LUCRO_C double precision;
declare variable MARGEM_C double precision;
declare variable COMANDO varchar(1000);
BEGIN
 FOR
    SELECT
     PRODUTOS.ID_PRODUTO,
     PRODUTOS.CODIGO_BARRAS_1,
     PRODUTOS.CODIGO_BARRAS_2,
     PRODUTOS.DESCRICAO,
     PRODUTOS.ESTOQUE_0
