     PRODUTOS
    WHERE
     PRODUTOS.CD_LABORATORIO = :LAB
    INTO
     :ID_PRODUTO,
     :CODIGO_BARRAS_1,
     :CODIGO_BARRAS_2,
     :PRODUTO,
     :ESTOQUE
 DO
  BEGIN
    QUANTIDADE = 0;
    VALOR = 0;
    CUSTO = 0;
    LUCRO = 0;
    MARGEM = 0;

    SELECT
      SUM(LANCAMENTOS.QUANTIDADE),
      SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
      SUM(LANCAMENTOS.CUSTO_MEDIO * LANCAMENTOS.QUANTIDADE),
