ALTER PROCEDURE SP_PREENCHE_DISTRIBUIDOR_CP AS 
DECLARE VARIABLE CODIGO DOUBLE PRECISION;
BEGIN
  FOR
   SELECT
    CD_DISTRIBUIDOR
   FROM
    CONTAS_PAGAR
   WHERE
    ((HISTORICO = '') OR (HISTORICO IS NULL))
   INTO
    :CODIGO
  DO
   BEGIN
     UPDATE CONTAS_PAGAR SET
      HISTORICO = (SELECT NOME FROM DISTRIBUIDORES WHERE CD_DISTRIBUIDOR = :CODIGO)
     WHERE
      ((HISTORICO = '') OR (HISTORICO IS NULL)) AND
      CD_DISTRIBUIDOR = :CODIGO;
   END
END ^

ALTER PROCEDURE SP_PREENCHE_ESTANTERIOR_BALANCO (ID_BALANCO DOUBLE PRECISION)
AS 
DECLARE VARIABLE CD_FILIAL INTEGER;
DECLARE VARIABLE ID_PRODUTO DOUBLE PRECISION;
DECLARE VARIABLE COMANDO VARCHAR(3000);
DECLARE VARIABLE ESTOQUEANTERIOR DOUBLE PRECISION;
BEGIN
  SELECT CD_FILIAL FROM PARAMETROS INTO :CD_FILIAL;
  FOR
   SELECT ID_PRODUTO
   FROM BALANCO
   WHERE ID_BALANCO = :ID_BALANCO AND ESTOQUE = 0
   INTO :ID_PRODUTO
  DO
   BEGIN
      COMANDO = 'SELECT ESTOQUE_' || :CD_FILIAL || ' FROM PRODUTOS WHERE ID_PRODUTO = ' || CAST(:ID_PRODUTO AS INTEGER);
      EXECUTE STATEMENT :COMANDO INTO :ESTOQUEANTERIOR;
      IF (:ESTOQUEANTERIOR IS NULL) THEN
          ESTOQUEANTERIOR = 0;
      UPDATE BALANCO SET
        ESTOQUE_ANTERIOR = :ESTOQUEANTERIOR
      WHERE ID_BALANCO = :ID_BALANCO AND ID_PRODUTO = :ID_PRODUTO;
   END
END ^

ALTER PROCEDURE SP_PREENCHE_FILIAIS_FIDELIDADE AS 
