       FROM PRODUTOS_FIDELIDADE
       INTO :ID_PRODUTO, :CD_PRODUTO, :CD_LABORATORIO, :CD_GRUPO, :DESCRICAO, :PRECO, :DT_ALTERACAO
     DO
