           INSERT INTO FILIAIS_FIDELIDADE VALUES (:CD_FILIAL, :ID_PRODUTO, :CD_PRODUTO, :CD_LABORATORIO, :CD_GRUPO, :DESCRICAO,  :PRECO, :DT_ALTERACAO, '');
         END
      END
   END
END ^

