ALTER PROCEDURE SP_PREENCHE_GRUPOS_CURVA AS 
DECLARE VARIABLE CD_FILIAL DOUBLE PRECISION;
DECLARE VARIABLE CD_GRUPO DOUBLE PRECISION;
DECLARE VARIABLE GRUPO VARCHAR(100);
DECLARE VARIABLE DIASESTOQUE DOUBLE PRECISION;
DECLARE VARIABLE CD_CURVA DOUBLE PRECISION;
DECLARE VARIABLE CURVA VARCHAR(100);
DECLARE VARIABLE SIGLA VARCHAR(1);
DECLARE VARIABLE EXISTE INTEGER;
BEGIN
  UPDATE GRUPOS SET DIAS_EST_MIN = 1 WHERE (DIAS_EST_MIN IS NULL) OR (DIAS_EST_MIN = 0);
  FOR SELECT CD_FILIAL FROM FILIAIS INTO :CD_FILIAL DO
   BEGIN
     FOR SELECT CD_GRUPO, DESCRICAO, DIAS_EST_MIN FROM GRUPOS INTO :CD_GRUPO, :GRUPO, :DIASESTOQUE  DO
      BEGIN
        FOR SELECT CD_CURVA, DESCRICAO, SIGLA FROM CURVAS INTO :CD_CURVA, :CURVA, :SIGLA DO
         BEGIN
           SELECT COUNT(*) FROM GRUPOS_CURVAS WHERE CD_FILIAL = :CD_FILIAL AND CD_GRUPO = :CD_GRUPO AND CD_CURVA = :CD_CURVA INTO :EXISTE;
           IF (:EXISTE = 0) THEN
              INSERT INTO GRUPOS_CURVAS VALUES (:CD_FILIAL, :CD_GRUPO, :GRUPO, :CD_CURVA,  :CURVA, :SIGLA, 10, 5, 0.5, 0.5, 0.5, 0.5, CURRENT_DATE);
         END
      END
   END
   UPDATE GRUPOS_CURVAS SET GRUPOS_CURVAS.P1 = 0.5 WHERE (P1 IS NULL) OR (P1 = 0);
   UPDATE GRUPOS_CURVAS SET GRUPOS_CURVAS.P2 = 0.5 WHERE (P2 IS NULL) OR (P2 = 0);
   UPDATE GRUPOS_CURVAS SET GRUPOS_CURVAS.P1SAZ = 0.5 WHERE (P1SAZ IS NULL) OR (P1SAZ = 0);
   UPDATE GRUPOS_CURVAS SET GRUPOS_CURVAS.P2SAZ = 0.5 WHERE (P2SAZ IS NULL) OR (P2SAZ = 0);
END ^

ALTER PROCEDURE SP_PREENCHE_GRUPO_VENDA AS 
DECLARE VARIABLE ID_PRODUTO DOUBLE PRECISION;
BEGIN
  FOR
    SELECT
      VENDAS.ID_PRODUTO
    FROM
      VENDAS
    GROUP BY
      VENDAS.ID_PRODUTO
    INTO
      :ID_PRODUTO
  DO
   BEGIN
      UPDATE VENDAS SET
       CD_GRUPO = (SELECT CD_GRUPO FROM PRODUTOS WHERE ID_PRODUTO = :ID_PRODUTO)
      WHERE ID_PRODUTO = :ID_PRODUTO;
   END
END ^

ALTER PROCEDURE SP_PREENCHE_ID_OPERADORCAIXA (DATAINICIAL DATE)
RETURNS (ID_OPERADORCAIXA DOUBLE PRECISION)
AS 
DECLARE VARIABLE CD_OPERADOR DOUBLE PRECISION;
DECLARE VARIABLE CD_FILIAL DOUBLE PRECISION;
DECLARE VARIABLE TERMINAL DOUBLE PRECISION;
DECLARE VARIABLE DATA_ABERTURA DATE;
BEGIN
  FOR
    SELECT
     OPERADORES.ID_OPERADORCAIXA,
     OPERADORES.CD_OPERADOR,
     OPERADORES.CD_FILIAL,
     OPERADORES.TERMINAL,
     OPERADORES.DATA_ABERTURA
    FROM
     OPERADORES
    WHERE
     OPERADORES.DATA_ABERTURA >= :DATAINICIAL
    INTO
     :ID_OPERADORCAIXA,
     :CD_OPERADOR,
     :CD_FILIAL,
     :TERMINAL,
     :DATA_ABERTURA
  DO
   BEGIN
     UPDATE CAIXA SET
      CAIXA.ID_OPERADORCAIXA = :ID_OPERADORCAIXA
     WHERE
      CAIXA.DATA_CAIXA = :DATA_ABERTURA AND
      CAIXA.CD_FILIAL = :CD_FILIAL AND
      CAIXA.CD_OPERADOR = :CD_OPERADOR AND
      CAIXA.TERMINAL = :TERMINAL AND
      CAIXA.CD_OPERADOR IS NOT NULL AND
      CAIXA.CD_OPERADOR > 0;

     UPDATE LANCAMENTOS SET
      LANCAMENTOS.ID_OPERADORCAIXA = :ID_OPERADORCAIXA
     WHERE
      LANCAMENTOS.DATA_CAIXA = :DATA_ABERTURA AND
      LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
      LANCAMENTOS.CD_OPERADOR = :CD_OPERADOR AND
      LANCAMENTOS.TERMINAL = :TERMINAL AND
      LANCAMENTOS.CD_OPERADOR IS NOT NULL AND
      LANCAMENTOS.CD_OPERADOR > 0;
   END
END ^

ALTER PROCEDURE SP_PREENCHE_LANCAMENTOSAPRAZO AS 
declare variable EXISTE double precision;
declare variable CD_LANCAMENTO double precision;
declare variable ID_PRODUTO double precision;
declare variable CD_FILIAL double precision;
declare variable CD_PRODUTO varchar(6);
declare variable DESCRICAO varchar(60);
declare variable CD_LABORATORIO double precision;
declare variable CD_GRUPO double precision;
declare variable CD_CLASSE double precision;
declare variable CD_CONVENIO double precision;
declare variable CD_CLIENTE double precision;
declare variable CD_VENDEDOR double precision;
declare variable CD_OPERADOR double precision;
declare variable CD_USUARIO double precision;
declare variable CD_FORMA_PAGAMENTO double precision;
declare variable CD_VENDA double precision;
declare variable ID_OPERADORCAIXA double precision;
declare variable CUSTO_MEDIO double precision;
declare variable CUSTO_UNITARIO double precision;
declare variable DATA_LANCAMENTO date;
declare variable DATA_CAIXA date;
declare variable QUANTIDADE double precision;
declare variable VALOR double precision;
declare variable COMISSAO double precision;
declare variable NOTA_FISCAL varchar(10);
declare variable DESCONTO double precision;
declare variable PROMOCAO double precision;
declare variable TIPO_VENDA varchar(1);
declare variable TIPO_PAGAMENTO varchar(1);
declare variable ENTRADA_SAIDA varchar(1);
declare variable ETIQUETA varchar(1);
declare variable ENTREGA varchar(1);
declare variable HORA time;
declare variable ESTOQUE_POSVENDA double precision;
declare variable TROCA varchar(1);
declare variable NUMERO double precision;
declare variable TERMINAL double precision;
declare variable USUARIO varchar(100);
declare variable OBSERVACAO varchar(255);
declare variable ARREDONDAMENTO double precision;
declare variable TRN varchar(1);
declare variable TRANSACAOTRN varchar(12);
declare variable LOTETRN varchar(10);
declare variable AUTORIZACAOTRN varchar(100);
declare variable SUBSIDIOTRN double precision;
declare variable NOTAMANUAL varchar(1);
BEGIN
 FOR
  SELECT
    CD_LANCAMENTO, ID_PRODUTO, CD_FILIAL, CD_PRODUTO, DESCRICAO,
    CD_LABORATORIO, CD_GRUPO, CD_CLASSE, CD_CONVENIO, CD_CLIENTE,
    CD_VENDEDOR, CD_OPERADOR, CD_USUARIO, CD_FORMA_PAGAMENTO, CD_VENDA,
    ID_OPERADORCAIXA, CUSTO_MEDIO, CUSTO_UNITARIO, DATA_LANCAMENTO,
    DATA_CAIXA, QUANTIDADE, VALOR, COMISSAO, NOTA_FISCAL, DESCONTO,
    PROMOCAO, TIPO_VENDA, TIPO_PAGAMENTO, ENTRADA_SAIDA, ETIQUETA,
    ENTREGA, HORA, ESTOQUE_POSVENDA, TROCA, NUMERO,
    TERMINAL, USUARIO, OBSERVACAO, ARREDONDAMENTO, TRN, TRANSACAOTRN,
    LOTETRN, AUTORIZACAOTRN, SUBSIDIOTRN, NOTAMANUAL
  FROM
   LANCAMENTOS
  WHERE
   (TIPO_VENDA = 'V' OR TIPO_VENDA = 'D') AND
   DATA_LANCAMENTO >= CURRENT_DATE - 180 AND
   CD_CLIENTE IS NOT NULL AND
   CD_CLIENTE <> 0 AND
   CD_CLIENTE <> 999999
  INTO
    :CD_LANCAMENTO, :ID_PRODUTO, :CD_FILIAL, :CD_PRODUTO, :DESCRICAO,
    :CD_LABORATORIO, :CD_GRUPO, :CD_CLASSE, :CD_CONVENIO, :CD_CLIENTE,
    :CD_VENDEDOR, :CD_OPERADOR, :CD_USUARIO, :CD_FORMA_PAGAMENTO, :CD_VENDA,
    :ID_OPERADORCAIXA, :CUSTO_MEDIO, :CUSTO_UNITARIO, :DATA_LANCAMENTO,
    :DATA_CAIXA, :QUANTIDADE, :VALOR, COMISSAO, :NOTA_FISCAL, :DESCONTO,
    :PROMOCAO, :TIPO_VENDA, :TIPO_PAGAMENTO, :ENTRADA_SAIDA, :ETIQUETA,
    :ENTREGA, :HORA, :ESTOQUE_POSVENDA, :TROCA, :NUMERO,
    :TERMINAL, :USUARIO, :OBSERVACAO, :ARREDONDAMENTO, :TRN, :TRANSACAOTRN,
    :LOTETRN, :AUTORIZACAOTRN, :SUBSIDIOTRN, :NOTAMANUAL

 DO
  BEGIN
    SELECT CD_LANCAMENTO FROM LANCAMENTOS_APRAZO WHERE CD_LANCAMENTO = :CD_LANCAMENTO INTO :EXISTE;
    IF (:EXISTE IS NULL) THEN
     BEGIN
        INSERT INTO LANCAMENTOS_APRAZO VALUES (
          :CD_LANCAMENTO, :ID_PRODUTO, :CD_FILIAL, :CD_PRODUTO, :DESCRICAO,
          :CD_LABORATORIO, :CD_GRUPO, :CD_CLASSE, :CD_CONVENIO, :CD_CLIENTE,
          :CD_VENDEDOR, :CD_OPERADOR, :CD_USUARIO, :CD_FORMA_PAGAMENTO, :CD_VENDA,
          :ID_OPERADORCAIXA, :CUSTO_MEDIO, :CUSTO_UNITARIO, :DATA_LANCAMENTO,
          :DATA_CAIXA, :QUANTIDADE, :VALOR, :COMISSAO, :NOTA_FISCAL, :DESCONTO,
          :PROMOCAO, :TIPO_VENDA, :TIPO_PAGAMENTO, :ENTRADA_SAIDA, :ETIQUETA,
          :ENTREGA, :HORA, :ESTOQUE_POSVENDA, :TROCA, ' ', :NUMERO,
          :TERMINAL, :USUARIO, :OBSERVACAO, :ARREDONDAMENTO, :TRN, :TRANSACAOTRN,
          :LOTETRN, :AUTORIZACAOTRN, :SUBSIDIOTRN, :NOTAMANUAL);
     END
  END
END ^

ALTER PROCEDURE SP_PREENCHE_METAS_ANTERIORES (CD_FILIAL DOUBLE PRECISION,
MESREF INTEGER,
ANOREF INTEGER,
DIASUTEIS INTEGER)
AS 
declare variable VALOR double precision;
declare variable QUANTIDADE double precision;
declare variable CLIENTES double precision;
declare variable TICKET double precision;
declare variable VALORCANCELADO double precision;
declare variable QUANTIDADECANCELADA double precision;
declare variable CLIENTESCANCELADOS double precision;
declare variable MES integer;
declare variable ANO integer;
BEGIN
  FOR
   SELECT
    EXTRACT(MONTH FROM DATA_LANCAMENTO),
    EXTRACT(YEAR FROM DATA_LANCAMENTO)
   FROM
    LANCAMENTOS
   WHERE
    DATA_LANCAMENTO >= CAST(:MESREF||'/01/'||:ANOREF AS DATE) AND
    DATA_LANCAMENTO < CAST(EXTRACT(MONTH FROM CURRENT_DATE)||'/01/'||EXTRACT(YEAR FROM CURRENT_DATE) AS DATE) AND
    CD_FILIAL = :CD_FILIAL
   GROUP BY
    EXTRACT(MONTH FROM DATA_LANCAMENTO),
    EXTRACT(YEAR FROM DATA_LANCAMENTO)
   INTO
    :MES,
    :ANO
  DO
   BEGIN
     SELECT
      SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO +
         (LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE) +
         (LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)),
      SUM(LANCAMENTOS.QUANTIDADE),
      COUNT(DISTINCT LANCAMENTOS.CD_VENDA)
     FROM
      LANCAMENTOS
     WHERE
      EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO) = :MES AND
      EXTRACT(YEAR FROM LANCAMENTOS.DATA_LANCAMENTO) = :ANO AND
      LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
      LANCAMENTOS.TIPO_VENDA = 'V' AND
      LANCAMENTOS.CUSTO_UNITARIO > 0
     INTO
      :VALOR,
      :QUANTIDADE,
      :CLIENTES;

     IF (:VALOR IS NULL) THEN
        VALOR = 0;
     IF (:QUANTIDADE IS NULL) THEN
        QUANTIDADE = 0;
     IF (:CLIENTES IS NULL) THEN
        CLIENTES = 0;

     SELECT
      SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO +
         (LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE) +
         (LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)),
      SUM(LANCAMENTOS.QUANTIDADE),
      COUNT(DISTINCT LANCAMENTOS.CD_VENDA)
     FROM
      LANCAMENTOS
     WHERE
      EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO) = :MES AND
      EXTRACT(YEAR FROM LANCAMENTOS.DATA_LANCAMENTO) = :ANO AND
      LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
      LANCAMENTOS.TIPO_VENDA = 'D' AND
      LANCAMENTOS.CUSTO_UNITARIO > 0
     INTO
      :VALORCANCELADO,
      :QUANTIDADECANCELADA,
      :CLIENTESCANCELADOS;

     IF (:VALORCANCELADO IS NULL) THEN
        VALORCANCELADO = 0;
     IF (:QUANTIDADECANCELADA IS NULL) THEN
        QUANTIDADECANCELADA = 0;
     IF (:CLIENTESCANCELADOS IS NULL) THEN
        CLIENTESCANCELADOS = 0;

     VALOR = :VALOR - :VALORCANCELADO;
     QUANTIDADE = :QUANTIDADE - :QUANTIDADECANCELADA;
     CLIENTES = :CLIENTES - :CLIENTESCANCELADOS;
     IF (:CLIENTES > 0) THEN
        TICKET = :VALOR / CLIENTES;

     INSERT INTO METAS_FILIAIS VALUES (
      (SELECT ID FROM SP_RETORNAID('ID_META')),
      :CD_FILIAL, :MES, :ANO, :DIASUTEIS, :VALOR, :QUANTIDADE, :CLIENTES,
      :TICKET, :VALOR, :QUANTIDADE, :CLIENTES, :TICKET, 0, 0, 0, '');

     EXECUTE PROCEDURE SP_PREENCHE_ACUMULADO_METAS(:CD_FILIAL,  :MES, :ANO);
  END
END ^

ALTER PROCEDURE SP_PREENCHE_METAS_VEND_ANT (CD_FILIAL DOUBLE PRECISION,
MESREF INTEGER,
ANOREF INTEGER)
AS 
DECLARE VARIABLE VALOR DOUBLE PRECISION;
DECLARE VARIABLE QUANTIDADE DOUBLE PRECISION;
DECLARE VARIABLE CLIENTES DOUBLE PRECISION;
DECLARE VARIABLE TICKET DOUBLE PRECISION;
DECLARE VARIABLE VALORCANCELADO DOUBLE PRECISION;
DECLARE VARIABLE QUANTIDADECANCELADA DOUBLE PRECISION;
DECLARE VARIABLE CLIENTESCANCELADOS DOUBLE PRECISION;
DECLARE VARIABLE MES INTEGER;
DECLARE VARIABLE ANO INTEGER;
DECLARE VARIABLE VENDEDOR DOUBLE PRECISION;
DECLARE VARIABLE META DOUBLE PRECISION;
BEGIN
  FOR
   SELECT
    LANCAMENTOS.CD_VENDEDOR,
    EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO),
    EXTRACT(YEAR FROM LANCAMENTOS.DATA_LANCAMENTO)
   FROM
    LANCAMENTOS
   WHERE
    LANCAMENTOS.DATA_LANCAMENTO >= CAST(:MESREF||'/01/'||:ANOREF AS DATE) AND
    LANCAMENTOS.DATA_LANCAMENTO < CAST(EXTRACT(MONTH FROM CURRENT_DATE)||'/01/'||EXTRACT(YEAR FROM CURRENT_DATE) AS DATE) AND
    LANCAMENTOS.CD_FILIAL = :CD_FILIAL
   GROUP BY
    LANCAMENTOS.CD_VENDEDOR,
    EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO),
    EXTRACT(YEAR FROM LANCAMENTOS.DATA_LANCAMENTO)
   INTO
    :VENDEDOR,
    :MES,
    :ANO
  DO
   BEGIN
     SELECT
      METAS_FILIAIS.ID_META
     FROM
      METAS_FILIAIS
     WHERE
      METAS_FILIAIS.CD_FILIAL = :CD_FILIAL AND
      METAS_FILIAIS.MESREF = :MES AND
      METAS_FILIAIS.ANOREF = :ANO
     INTO
      :META;

     SELECT
      SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO +
         (LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE) +
         (LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)),
      SUM(LANCAMENTOS.QUANTIDADE),
      COUNT(DISTINCT LANCAMENTOS.CD_VENDA)
     FROM
      LANCAMENTOS
     WHERE
      EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO) = :MES AND
      EXTRACT(YEAR FROM LANCAMENTOS.DATA_LANCAMENTO) = :ANO AND
      LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
      LANCAMENTOS.CD_VENDEDOR = :VENDEDOR AND
      LANCAMENTOS.TIPO_VENDA = 'V' AND
      LANCAMENTOS.CUSTO_UNITARIO > 0
     INTO
      :VALOR,
      :QUANTIDADE,
      :CLIENTES;

     IF (:VALOR IS NULL) THEN
        VALOR = 0;
     IF (:QUANTIDADE IS NULL) THEN
        QUANTIDADE = 0;
     IF (:CLIENTES IS NULL) THEN
        CLIENTES = 0;

     SELECT
      SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO +
         (LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE) +
         (LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)),
      SUM(LANCAMENTOS.QUANTIDADE),
      COUNT(DISTINCT LANCAMENTOS.CD_VENDA)
     FROM
      LANCAMENTOS
     WHERE
      EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO) = :MES AND
      EXTRACT(YEAR FROM LANCAMENTOS.DATA_LANCAMENTO) = :ANO AND
      LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
      LANCAMENTOS.CD_VENDEDOR = :VENDEDOR AND
      LANCAMENTOS.TIPO_VENDA = 'D' AND
      LANCAMENTOS.CUSTO_UNITARIO > 0
     INTO
      :VALORCANCELADO,
      :QUANTIDADECANCELADA,
      :CLIENTESCANCELADOS;

     IF (:VALORCANCELADO IS NULL) THEN
        VALORCANCELADO = 0;
     IF (:QUANTIDADECANCELADA IS NULL) THEN
        QUANTIDADECANCELADA = 0;
     IF (:CLIENTESCANCELADOS IS NULL) THEN
        CLIENTESCANCELADOS = 0;

     VALOR = :VALOR - :VALORCANCELADO;
     QUANTIDADE = :QUANTIDADE - :QUANTIDADECANCELADA;
     CLIENTES = :CLIENTES - :CLIENTESCANCELADOS;
     IF (:CLIENTES > 0) THEN
        TICKET = :VALOR / CLIENTES;

     IF (:VALOR > 0) THEN
      BEGIN
       INSERT INTO METAS_VENDEDORES VALUES (
        :META, :VENDEDOR, :VALOR, :QUANTIDADE, :CLIENTES, :TICKET, :VALOR, :QUANTIDADE, :CLIENTES, :TICKET, 0, 0, 0, '');
      END
  END
END ^

ALTER PROCEDURE SP_PREENCHE_META_NOVA (CD_FILIAL DOUBLE PRECISION,
MESREF INTEGER,
ANOREF INTEGER,
DIASUTEIS INTEGER)
AS 
declare variable VALOR double precision;
declare variable QUANTIDADE double precision;
declare variable CLIENTES double precision;
declare variable TICKET double precision;
declare variable VALORCANCELADO double precision;
declare variable QUANTIDADECANCELADA double precision;
declare variable CLIENTESCANCELADOS double precision;
declare variable MES integer;
declare variable ANO integer;
declare variable DATAINICIAL date;
declare variable DATAFINAL date;
BEGIN
   DATAINICIAL = CAST(:MESREF||'/01/'||:ANOREF AS DATE);
   DATAFINAL = CAST(EXTRACT(MONTH FROM CURRENT_DATE)||'/01/'||EXTRACT(YEAR FROM CURRENT_DATE) AS DATE);

   VALOR = 0;
   QUANTIDADE = 0;
   CLIENTES = 0;
   TICKET = 0;

   SELECT
    METAS_FILIAIS.METAVALOR,
    METAS_FILIAIS.METAQUANTIDADE,
    METAS_FILIAIS.METACLIENTES,
    METAS_FILIAIS.METATICKET
   FROM
    METAS_FILIAIS
   WHERE
    METAS_FILIAIS.CD_FILIAL = :CD_FILIAL AND
    METAS_FILIAIS.MESREF = :MESREF AND
    METAS_FILIAIS.ANOREF = :ANOREF
   INTO
    :VALOR,
    :QUANTIDADE,
    :CLIENTES,
    :TICKET;

   IF ((:VALOR IS NULL) OR (:VALOR = 0)) THEN
    BEGIN
       SELECT
        SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO +
           (LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE) +
           (LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)),
        SUM(LANCAMENTOS.QUANTIDADE),
        COUNT(DISTINCT LANCAMENTOS.CD_VENDA)
       FROM
        LANCAMENTOS
       WHERE
        LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
        LANCAMENTOS.DATA_LANCAMENTO < :DATAFINAL AND
        LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
        LANCAMENTOS.TIPO_VENDA = 'V'
       INTO
        :VALOR,
        :QUANTIDADE,
        :CLIENTES;
    
       IF (:VALOR IS NULL) THEN
          VALOR = 0;
       IF (:QUANTIDADE IS NULL) THEN
          QUANTIDADE = 0;
       IF (:CLIENTES IS NULL) THEN
          CLIENTES = 0;
    
       SELECT
        SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO +
           (LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE) +
           (LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)),
        SUM(LANCAMENTOS.QUANTIDADE),
        COUNT(DISTINCT LANCAMENTOS.CD_VENDA)
       FROM
        LANCAMENTOS
       WHERE
        LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
        LANCAMENTOS.DATA_LANCAMENTO < :DATAFINAL AND
        LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
        LANCAMENTOS.TIPO_VENDA = 'D'
       INTO
        :VALORCANCELADO,
        :QUANTIDADECANCELADA,
        :CLIENTESCANCELADOS;
    
       IF (:VALORCANCELADO IS NULL) THEN
          VALORCANCELADO = 0;
       IF (:QUANTIDADECANCELADA IS NULL) THEN
          QUANTIDADECANCELADA = 0;
       IF (:CLIENTESCANCELADOS IS NULL) THEN
          CLIENTESCANCELADOS = 0;
    
       VALOR = :VALOR - :VALORCANCELADO;
       QUANTIDADE = :QUANTIDADE - :QUANTIDADECANCELADA;
       CLIENTES = :CLIENTES - :CLIENTESCANCELADOS;

       IF (:CLIENTES > 0) THEN
          TICKET = :VALOR / CLIENTES;

    END

     MES = EXTRACT(MONTH FROM :DATAINICIAL);
     ANO = EXTRACT(YEAR FROM :DATAINICIAL);

     MES = :MES + 1;
     IF (:MES > 12) THEN
      BEGIN
        MES = 1;
        ANO = :ANO + 1;
      END

     INSERT INTO METAS_FILIAIS VALUES (
      (SELECT ID FROM SP_RETORNAID('ID_META')),
      :CD_FILIAL, :MES, :ANO, :DIASUTEIS, :VALOR, :QUANTIDADE, :CLIENTES,
      :TICKET, 0, 0, 0, 0, 0, 0, 0, '');
END ^

ALTER PROCEDURE SP_PREENCHE_META_NOVA_VEND (CD_FILIAL DOUBLE PRECISION,
MESREF INTEGER,
ANOREF INTEGER)
AS 
declare variable VALOR double precision;
declare variable QUANTIDADE double precision;
declare variable CLIENTES double precision;
declare variable TICKET double precision;
declare variable VALORCANCELADO double precision;
declare variable QUANTIDADECANCELADA double precision;
declare variable CLIENTESCANCELADOS double precision;
declare variable MES integer;
declare variable ANO integer;
declare variable VENDEDOR double precision;
declare variable META double precision;
declare variable DATAINICIAL date;
declare variable DATAFINAL date;
declare variable METAANTERIOR double precision;
BEGIN
  DATAINICIAL = CAST(:MESREF||'/01/'||:ANOREF AS DATE);
  DATAFINAL = CAST(EXTRACT(MONTH FROM CURRENT_DATE)||'/01/'||EXTRACT(YEAR FROM CURRENT_DATE) AS DATE);

  MES = EXTRACT(MONTH FROM :DATAINICIAL);
  ANO = EXTRACT(YEAR FROM :DATAINICIAL);

  MES = :MES + 1;
  IF (:MES > 12) THEN
   BEGIN
     MES = 1;
     ANO = :ANO + 1;
   END

  SELECT
   METAS_FILIAIS.ID_META
  FROM
   METAS_FILIAIS
  WHERE
   METAS_FILIAIS.CD_FILIAL = :CD_FILIAL AND
   METAS_FILIAIS.MESREF = :MESREF AND
   METAS_FILIAIS.ANOREF = :ANOREF
  INTO
   :METAANTERIOR;

  IF (:METAANTERIOR IS NULL) THEN
    EXIT;

  SELECT
   METAS_FILIAIS.ID_META
  FROM
   METAS_FILIAIS
  WHERE
   METAS_FILIAIS.CD_FILIAL = :CD_FILIAL AND
   METAS_FILIAIS.MESREF = :MES AND
   METAS_FILIAIS.ANOREF = :ANO
  INTO
   :META;

  IF (:META IS NULL) THEN
    EXIT;

  VALOR = 0;
  QUANTIDADE = 0;
  CLIENTES = 0;
  TICKET = 0;

  FOR
   SELECT
    METAS_VENDEDORES.CD_VENDEDOR,
    METAS_VENDEDORES.METAVALOR,
    METAS_VENDEDORES.METAQUANTIDADE,
    METAS_VENDEDORES.METACLIENTES,
    METAS_VENDEDORES.METATICKET
   FROM
    METAS_VENDEDORES
   WHERE
    METAS_VENDEDORES.ID_META = :METAANTERIOR
   INTO
    :VENDEDOR,
    :VALOR,
    :QUANTIDADE,
    :CLIENTES,
    :TICKET
  DO
   BEGIN
     IF ((:VALOR IS NULL) OR (:VALOR = 0)) THEN
      BEGIN
         SELECT
          SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO +
             (LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE) +
             (LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)),
          SUM(LANCAMENTOS.QUANTIDADE),
          COUNT(DISTINCT LANCAMENTOS.CD_VENDA)
         FROM
          LANCAMENTOS
         WHERE
          LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
          LANCAMENTOS.DATA_LANCAMENTO < :DATAFINAL AND
          LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
          LANCAMENTOS.CD_VENDEDOR = :VENDEDOR AND
          LANCAMENTOS.TIPO_VENDA = 'V'
         INTO
          :VALOR,
          :QUANTIDADE,
          :CLIENTES;
    
         IF (:VALOR IS NULL) THEN
            VALOR = 0;
         IF (:QUANTIDADE IS NULL) THEN
            QUANTIDADE = 0;
         IF (:CLIENTES IS NULL) THEN
            CLIENTES = 0;
    
         SELECT
          SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO +
             (LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE) +
             (LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)),
          SUM(LANCAMENTOS.QUANTIDADE),
          COUNT(DISTINCT LANCAMENTOS.CD_VENDA)
         FROM
          LANCAMENTOS
         WHERE
          LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
          LANCAMENTOS.DATA_LANCAMENTO < :DATAFINAL AND
          LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
          LANCAMENTOS.CD_VENDEDOR = :VENDEDOR AND
          LANCAMENTOS.TIPO_VENDA = 'D'
         INTO
          :VALORCANCELADO,
          :QUANTIDADECANCELADA,
          :CLIENTESCANCELADOS;
    
         IF (:VALORCANCELADO IS NULL) THEN
            VALORCANCELADO = 0;
         IF (:QUANTIDADECANCELADA IS NULL) THEN
            QUANTIDADECANCELADA = 0;
         IF (:CLIENTESCANCELADOS IS NULL) THEN
            CLIENTESCANCELADOS = 0;

         VALOR = :VALOR - :VALORCANCELADO;
         QUANTIDADE = :QUANTIDADE - :QUANTIDADECANCELADA;
         CLIENTES = :CLIENTES - :CLIENTESCANCELADOS;

         IF (:CLIENTES > 0) THEN
            TICKET = :VALOR / CLIENTES;

      END

     IF (:VALOR > 0) THEN
      BEGIN
       INSERT INTO METAS_VENDEDORES VALUES (
        :META, :VENDEDOR, :VALOR, :QUANTIDADE, :CLIENTES, :TICKET, 0, 0, 0, 0, 0, 0, 0, '');
      END
   END
END ^

ALTER PROCEDURE SP_PREENCHE_MIN_MAX_PRODUTO AS 
DECLARE VARIABLE FILIAL INTEGER;
DECLARE VARIABLE COMANDO VARCHAR(255);
BEGIN
  FOR
    SELECT
     CD_FILIAL
    FROM
     FILIAIS
    INTO
     :FILIAL
  DO
   BEGIN
     COMANDO = 'UPDATE PRODUTOS SET ESTOQUE_'||FILIAL||' = 0 WHERE ESTOQUE_'||FILIAL||' IS NULL';
     EXECUTE STATEMENT :COMANDO;
     COMANDO = 'UPDATE PRODUTOS SET ESTOQUE_MINIMO_'||FILIAL||' = 0 WHERE ESTOQUE_MINIMO_'||FILIAL||' IS NULL';
     EXECUTE STATEMENT :COMANDO;
     COMANDO = 'UPDATE PRODUTOS SET ESTOQUE_MAXIMO_'||FILIAL||' = 0 WHERE ESTOQUE_MAXIMO_'||FILIAL||' IS NULL';
     EXECUTE STATEMENT :COMANDO;
     COMANDO = 'UPDATE PRODUTOS SET CD_GRUPO = 999 WHERE CD_GRUPO IS NULL';
     EXECUTE STATEMENT :COMANDO;
     COMANDO = 'UPDATE PRODUTOS SET CD_CLASSE = 0 WHERE CD_CLASSE IS NULL';
     EXECUTE STATEMENT :COMANDO;
     COMANDO = 'UPDATE PRODUTOS SET CD_LABORATORIO = 9999 WHERE CD_LABORATORIO IS NULL';
     EXECUTE STATEMENT :COMANDO;
     COMANDO = 'UPDATE PRODUTOS SET TIPO_PRODUTO = '''||'OU'||''' WHERE TIPO_PRODUTO IS NULL';
     EXECUTE STATEMENT :COMANDO;
     COMANDO = 'UPDATE PRODUTOS SET STATUS = '''||'A'||''' WHERE STATUS IS NULL';
     EXECUTE STATEMENT :COMANDO;
   END
END ^

ALTER PROCEDURE SP_PREENCHE_MOVIMENTOCUSTOVENDA (FILIAL DOUBLE PRECISION,
DATA_INICIAL DATE,
DATA_FINAL DATE)
RETURNS (DATA DATE,
CUSTOVENDA NUMERIC(15, 2),
CUSTODEVOLUCAO NUMERIC(15, 2),
CUSTOTOTAL NUMERIC(15, 2))
AS 
DECLARE VARIABLE MES VARCHAR(2);
DECLARE VARIABLE ANO VARCHAR(4);
DECLARE VARIABLE CONTACAIXA DOUBLE PRECISION;
DECLARE VARIABLE CD_MOVIMENTO_CAIXA DOUBLE PRECISION;
DECLARE VARIABLE CONTACUSTOVENDA DOUBLE PRECISION;
DECLARE VARIABLE HISTORICO VARCHAR(50);
DECLARE VARIABLE TIPOCONTA VARCHAR(1);
BEGIN
  FOR
   SELECT
     LANCAMENTOS.DATA_CAIXA
   FROM
    LANCAMENTOS
   WHERE
    LANCAMENTOS.DATA_CAIXA >= :DATA_INICIAL AND
    LANCAMENTOS.DATA_CAIXA <= :DATA_FINAL AND
    LANCAMENTOS.CD_FILIAL = :FILIAL
   GROUP BY
    LANCAMENTOS.DATA_CAIXA
   INTO
    :DATA
  DO
   BEGIN
     SELECT
       SUM(CAST(LANCAMENTOS.CUSTO_UNITARIO AS NUMERIC(15,2)) * LANCAMENTOS.QUANTIDADE)
     FROM
      LANCAMENTOS
     WHERE
      LANCAMENTOS.DATA_CAIXA = :DATA AND
      LANCAMENTOS.CD_FILIAL = :FILIAL AND
      LANCAMENTOS.TIPO_VENDA = 'V'
     INTO
      :CUSTOVENDA;

     IF (:CUSTOVENDA IS NULL) THEN
        CUSTOVENDA = 0;

     SELECT
       SUM(CAST(LANCAMENTOS.CUSTO_UNITARIO AS NUMERIC(15,2)) * LANCAMENTOS.QUANTIDADE)
     FROM
      LANCAMENTOS
     WHERE
      LANCAMENTOS.DATA_CAIXA = :DATA AND
      LANCAMENTOS.CD_FILIAL = :FILIAL AND
      LANCAMENTOS.TIPO_VENDA = 'D'
     INTO
      :CUSTODEVOLUCAO;

     IF (:CUSTODEVOLUCAO IS NULL) THEN
        CUSTODEVOLUCAO = 0;

     CUSTOTOTAL = :CUSTOVENDA - :CUSTODEVOLUCAO;

     MES = EXTRACT(MONTH FROM :DATA);
     ANO = EXTRACT(YEAR FROM :DATA);

     SELECT FIRST 1 CD_CONTA FROM CONTAS WHERE TIPO = 'C' INTO :CONTACAIXA;

     UPDATE CONTROLE SET VALOR = VALOR + 1 WHERE CAMPO = 'CD_MOVIMENTOCAIXA';
     SELECT VALOR FROM CONTROLE WHERE CAMPO = 'CD_MOVIMENTOCAIXA' INTO :CD_MOVIMENTO_CAIXA;

     SELECT CONTACUSTOVENDA FROM PARAMETROS INTO :CONTACUSTOVENDA;

     SELECT TIPO_CONTA, HISTORICO FROM PLANO_CONTAS WHERE CD_PLANO_CONTAS = :CONTACUSTOVENDA INTO :TIPOCONTA, :HISTORICO;

     INSERT INTO MOVIMENTOCAIXA VALUES (:CD_MOVIMENTO_CAIXA, :CONTACAIXA, :DATA, :HISTORICO, NULL, :TIPOCONTA, :MES, :ANO,  :CUSTOTOTAL,
                                        :CONTACUSTOVENDA, '', :FILIAL,  NULL, NULL, 'A');
   END
END ^

ALTER PROCEDURE SP_PREENCHE_NCM_SINTEGRA_ITENS AS 
DECLARE VARIABLE REF_PRODUTOS VARCHAR(14);
DECLARE VARIABLE NCM VARCHAR(14);
BEGIN
 FOR
  SELECT
   DISTINCT CAST(REF_PRODUTOS AS DOUBLE PRECISION)
   FROM SINTEGRA_NF_ENTRADA_ITENS
   INTO
    :REF_PRODUTOS
 DO
  BEGIN
    NCM = NULL;
    SELECT NCM FROM PRODUTOS WHERE CAST(CODIGO_BARRAS_1 AS DOUBLE PRECISION) = :REF_PRODUTOS INTO :NCM;
    UPDATE SINTEGRA_NF_ENTRADA_ITENS SET
     CL_FIS = :NCM
    WHERE CAST(REF_PRODUTOS AS DOUBLE PRECISION) = :REF_PRODUTOS;
  END

 FOR
  SELECT
   DISTINCT CAST(REF_PRODUTOS AS DOUBLE PRECISION)
   FROM SINTEGRA_PEDIDOS_ITENS
   INTO
    :REF_PRODUTOS
 DO
  BEGIN
    NCM = NULL;
    SELECT NCM FROM PRODUTOS WHERE CAST(CODIGO_BARRAS_1 AS DOUBLE PRECISION) = :REF_PRODUTOS INTO :NCM;
    UPDATE SINTEGRA_PEDIDOS_ITENS SET
     CL_FIS = :NCM
    WHERE CAST(REF_PRODUTOS AS DOUBLE PRECISION) = :REF_PRODUTOS;
  END
END ^

