    SELECT DISTINCT ID_UF, UF
    FROM NFEMUNICIPIOS
    INTO :ID_UF, :UF
  DO
   BEGIN
     UPDATE CONTROLE SET VALOR = VALOR + 1 WHERE CAMPO = 'ID_NFEUF';
     SELECT VALOR FROM CONTROLE WHERE CAMPO = 'ID_NFEUF' INTO :ID;
     INSERT INTO NFEUF VALUES (:ID, :ID_UF, '', :UF, '');
   END*/

  FOR
   SELECT
     ID_UF,
     REGIAO,
     SIGLA
   FROM
     NFEUF
   INTO
     :ID_UF,
     :REGIAO,
     :SIGLA
  DO
   BEGIN
     UPDATE NFEMUNICIPIOS SET
      REGIAO = :REGIAO,
      SIGLA = :SIGLA
     WHERE ID_UF = :ID_UF;
   END
END ^

ALTER PROCEDURE SP_PREENCHE_OBS_LANCAMENTOS AS 
DECLARE VARIABLE VENDA DOUBLE PRECISION;
DECLARE VARIABLE OBS VARCHAR(100);
BEGIN
  FOR
   SELECT
    CD_VENDA,
    OBSERVACAO
   FROM
    CAIXA
   INTO
    :VENDA,
    :OBS
  DO
   BEGIN
     UPDATE LANCAMENTOS SET
      OBSERVACAO = :OBS
     WHERE CD_VENDA = :VENDA;
   END
END ^

ALTER PROCEDURE SP_PREENCHE_PEDIDOS_GESTAO AS 
declare variable COMANDO varchar(1000);
declare variable TABELA varchar(100);
declare variable DATA date;
declare variable PARAMETRO varchar(1000);
declare variable NOME varchar(1000);
BEGIN
  FOR
    SELECT RDB$RELATION_NAME FROM RDB$RELATIONS WHERE RDB$SYSTEM_FLAG=0 AND RDB$RELATION_NAME LIKE 'TPG%' INTO :TABELA
  DO
   BEGIN
     COMANDO = 'SELECT DISTINCT DATA, PARAMETRO, NOME FROM TPG' || SUBSTRING(:TABELA FROM 4 FOR 10);
     EXECUTE STATEMENT :COMANDO INTO :DATA, :PARAMETRO, :NOME;
     INSERT INTO PEDIDOS_GESTAO VALUES (SUBSTRING(:TABELA FROM 4 FOR 10), :DATA, :PARAMETRO, :NOME, 'A');
   END
END ^

ALTER PROCEDURE SP_PREENCHE_PRECOVENDA_ITENS AS 
DECLARE VARIABLE PRODUTO DOUBLE PRECISION;
BEGIN
 FOR
  SELECT
   DISTINCT ID_PRODUTO
  FROM
   ITENS_COMPRA
  INTO
   :PRODUTO
 DO
  BEGIN
    UPDATE ITENS_COMPRA SET
     PRECO_VENDA = (SELECT PRECO_VENDA FROM PRODUTOS WHERE ID_PRODUTO = :PRODUTO)
    WHERE
     ID_PRODUTO = :PRODUTO;
  END
END ^

ALTER PROCEDURE SP_PREENCHE_PRECO_APLICATIVO AS 
