  UPDATE PRODUTOS_SITE SET
   DESCRICAO_APLICATIVO = DESCRICAO_SITE,
   PRECO_APLICATIVO = PRECO_VENDA_SITE,
   QUANTIDADE_LIMITE = 1,
   DATA_VENCIMENTO = CURRENT_DATE;
END ^

ALTER PROCEDURE SP_PREENCHE_PRECO_BALANCO (ID_BALANCO DOUBLE PRECISION)
AS 
DECLARE VARIABLE ID_PRODUTO DOUBLE PRECISION;
DECLARE VARIABLE PRECO_VENDA DOUBLE PRECISION;
BEGIN
 FOR
  SELECT
    ID_PRODUTO,
    PRECO_VENDA
  FROM
    PRODUTOS
  INTO
   :ID_PRODUTO,
   :PRECO_VENDA
 DO
