ALTER PROCEDURE SP_PREENCHE_PRODUTOS_FISCO AS 
declare variable ID_PRODUTO double precision;
declare variable CODIGO_BARRAS_1 varchar(14);
declare variable DESCRICAO varchar(60);
declare variable CD_CLASSE double precision;
declare variable CD_LISTA double precision;
declare variable CD_CFOP double precision;
declare variable ORIGEM varchar(1);
declare variable SITUACAO_TRIBUTARIA varchar(1);
declare variable CST_ICMS varchar(14);
declare variable CST_PIS_COFINS_ENTRADA varchar(3);
declare variable CST_PIS_COFINS_SAIDA varchar(3);
declare variable ALIQUOTA_ICMS numeric(15,2);
declare variable ALIQUOTA_PIS numeric(15,2);
declare variable ALIQUOTA_COFINS numeric(15,2);
declare variable NATUREZA_RECEITA_PISCOFINS varchar(3);
declare variable NCM varchar(10);
declare variable CEST varchar(10);
declare variable STATUS varchar(1);
declare variable DT_CADASTRO date;
BEGIN
  FOR
    SELECT
     PRODUTOS.ID_PRODUTO, PRODUTOS.CODIGO_BARRAS_1, PRODUTOS.DESCRICAO,
     PRODUTOS.CD_CLASSE, PRODUTOS.CD_LISTA, PRODUTOS.CD_CFOP, PRODUTOS.ORIGEM,
     CASE
       WHEN (PRODUTOS.ICMS IS NULL) OR (PRODUTOS.ICMS = '') OR
            (PRODUTOS.ICMS = 'F') OR (PRODUTOS.ICMS = 'FF') THEN 'F'
       WHEN (PRODUTOS.ICMS = 'I') OR (PRODUTOS.ICMS = 'II') THEN 'I'
       WHEN (PRODUTOS.ICMS = 'N') OR (PRODUTOS.ICMS = 'NN') THEN 'N'
       ELSE 'T'
     END,
     PRODUTOS.SITUACAOTRIBUTARIA, 0, 0,
     CASE
       WHEN (PRODUTOS.ICMS IS NULL) OR
            (PRODUTOS.ICMS = '') OR
            (PRODUTOS.ICMS = 'F') OR
            (PRODUTOS.ICMS = 'FF') OR
            (PRODUTOS.ICMS = 'I') OR
            (PRODUTOS.ICMS = 'II') OR
            (PRODUTOS.ICMS = 'N') OR
            (PRODUTOS.ICMS = 'NN') THEN 0
       ELSE CAST(PRODUTOS.ICMS AS NUMERIC(15,2))
     END,
     0, 0, 0, PRODUTOS.NCM, PRODUTOS.CEST, PRODUTOS.STATUS, PRODUTOS.DT_CADASTRO
    FROM PRODUTOS
    INTO
      :ID_PRODUTO, :CODIGO_BARRAS_1, :DESCRICAO, :CD_CLASSE, :CD_LISTA, :CD_CFOP, :ORIGEM,
      :SITUACAO_TRIBUTARIA, :CST_ICMS, :CST_PIS_COFINS_ENTRADA, :CST_PIS_COFINS_SAIDA,
      :ALIQUOTA_ICMS, :ALIQUOTA_PIS, :ALIQUOTA_COFINS, :NATUREZA_RECEITA_PISCOFINS,
      :NCM, :CEST, :STATUS, :DT_CADASTRO
  DO
   BEGIN
     IF ((:ORIGEM IS NULL) OR (:ORIGEM = '')) THEN
        ORIGEM = '0';
     IF ((:NCM IS NULL) OR (:NCM = '')) THEN
        NCM = '30049099';
     IF ((:CEST IS NULL) OR (:CEST = '')) THEN
        CEST = '2801400';
     IF (:CD_CFOP IS NULL) THEN
        CD_CFOP = 5405;


     INSERT INTO PRODUTOS_FISCO
     (ID_PRODUTO, CODIGO_BARRAS, DESCRICAO, CD_CLASSE, CD_LISTA, CD_CFOP, ORIGEM,
      SITUACAO_TRIBUTARIA, CST_ICMS, CST_PIS_COFINS_ENTRADA, CST_PIS_COFINS_SAIDA,
      ALIQUOTA_ICMS, ALIQUOTA_PIS, ALIQUOTA_COFINS, NATUREZA_RECEITA_PISCOFINS,
      NCM, CEST, STATUS, DT_CADASTRO)
     VALUES
     (:ID_PRODUTO, :CODIGO_BARRAS_1, :DESCRICAO, :CD_CLASSE, :CD_LISTA, :CD_CFOP, :ORIGEM,
      :SITUACAO_TRIBUTARIA, :CST_ICMS, :CST_PIS_COFINS_ENTRADA, :CST_PIS_COFINS_SAIDA,
      :ALIQUOTA_ICMS, :ALIQUOTA_PIS, :ALIQUOTA_COFINS, :NATUREZA_RECEITA_PISCOFINS,
      :NCM, :CEST, :STATUS, :DT_CADASTRO);
   END
END ^

ALTER PROCEDURE SP_PREENCHE_PRODUTOS_LOCAL AS 
DECLARE VARIABLE ID_PRODUTO DOUBLE PRECISION;
DECLARE VARIABLE EXISTE INTEGER;
BEGIN
  FOR
   SELECT
    ID_PRODUTO
   FROM
    PRODUTOS
   INTO
    :ID_PRODUTO
  DO
  BEGIN
    SELECT COUNT(ID_PRODUTO) FROM PRODUTOS_LOCAL WHERE ID_PRODUTO = :ID_PRODUTO INTO :EXISTE;
    IF (:EXISTE = 0) THEN
     BEGIN
       INSERT INTO PRODUTOS_LOCAL VALUES (:ID_PRODUTO, 0);
     END
  END
END ^

ALTER PROCEDURE SP_PREENCHE_QUANTIDADE_SAIDA AS 
DECLARE VARIABLE MES VARCHAR(3);
DECLARE VARIABLE ANO VARCHAR(5);
DECLARE VARIABLE PRODUTO DOUBLE PRECISION;
BEGIN
  ANO = SUBSTRING(CURRENT_DATE FROM 1 FOR 4);
  MES = SUBSTRING(CURRENT_DATE FROM 6 FOR 2);
  FOR
   SELECT
    ID_PRODUTO
   FROM
    PRODUTOS
   WHERE
    QUANTIDADE_SAIDA IS NULL
   INTO
    :PRODUTO
  DO
   BEGIN
     UPDATE PRODUTOS SET QUANTIDADE_SAIDA =
         (SELECT SUM(QUANTIDADE)
          FROM   LANCAMENTOS
          WHERE  DATA_CAIXA >= CAST(:MES||'/01/'||:ANO AS DATE) AND
                 DATA_CAIXA <= CURRENT_DATE AND
                 ID_PRODUTO = :PRODUTO AND
                 TIPO_VENDA = 'V')
     WHERE ID_PRODUTO = :PRODUTO;
   END
  UPDATE PRODUTOS SET QUANTIDADE_SAIDA = 0 WHERE QUANTIDADE_SAIDA IS NULL;
END ^

ALTER PROCEDURE SP_PREENCHE_SALDOCOMISSAO_DATA (DATAINICIAL DATE,
DATAFINAL DATE)
AS 
declare variable CD_FILIAL double precision;
BEGIN
  SELECT CD_FILIAL FROM PARAMETROS INTO :CD_FILIAL;
  WHILE (:DATAINICIAL <= :DATAFINAL) DO
   BEGIN
     EXECUTE PROCEDURE SP_PREENCHE_SALDO_COMISSAO(:DATAINICIAL,  :CD_FILIAL);
     DATAINICIAL = :DATAINICIAL + 1;
   END
END ^

ALTER PROCEDURE SP_PREENCHE_SALDO_COMISSAO (DATA DATE,
CD_FILIAL DOUBLE PRECISION)
AS 
Declare variable CD_VENDEDOR double precision;
Declare variable COMISSAOAVISTA double precision;
Declare variable COMISSAOAVISTACANCELADA double precision;
Declare variable DIFERENCACOMISSAOAVISTA double precision;
Declare variable COMISSAOAPRAZO double precision;
Declare variable COMISSAOAPRAZOCANCELADA double precision;
Declare variable DIFERENCACOMISSAOAPRAZO double precision;
Declare variable COMISSAO double precision;
declare variable EXISTEDIA double precision;
declare variable SALDOCOMISSAOAVISTA double precision;
declare variable SALDOCOMISSAOAPRAZO double precision;
declare variable SALDOAPRAZOLIBERADO double precision;
declare variable VALORAPRAZOLIBERADO double precision;
declare variable CODIGO double precision;
declare variable TIPOLOJA varchar(1);
declare variable PERCENTUALPREMIACAO double precision;
declare variable VALORMINIMOPREMIACAO double precision;
declare variable PREMIACAO double precision;
declare variable SALDOPREMIACAO double precision;
declare variable CD_VENDA double precision;
declare variable PREMIACAOTOTAL double precision;
BEGIN
  DATA = :DATA - 1;
  SELECT
   PARAMETROS.TIPO_LOJA,
   PARAMETROS.PERCENTUALPREMIACAO,
   PARAMETROS.VALORMINIMOPREMIACAO
  FROM
   PARAMETROS
  INTO
   :TIPOLOJA,
   :PERCENTUALPREMIACAO,
   :VALORMINIMOPREMIACAO;

  /*IF ((:TIPOLOJA = 'M') OR (:PERCENTUALPREMIACAO IS NULL AND :VALORMINIMOPREMIACAO IS NULL) OR
      (:PERCENTUALPREMIACAO = 0) OR (:VALORMINIMOPREMIACAO = 0)) THEN
     EXIT;*/

  FOR
   SELECT
    CD_VENDEDOR
   FROM
    VENDEDORES
   WHERE
    CD_FILIAL = :CD_FILIAL
   ORDER BY
    CD_VENDEDOR
   INTO
    :CD_VENDEDOR
  DO
   BEGIN
      DIFERENCACOMISSAOAVISTA = 0;
      DIFERENCACOMISSAOAPRAZO = 0;

      /* BUSCANDO TOTALIZACAO POR FORMA DE PAGAMENTO COM PAGAMENTO DE COMISSAO A VISTA */
      COMISSAOAVISTA = 0;
      COMISSAOAVISTACANCELADA = 0;
      FOR
       SELECT
        SUM(LANCAMENTOS.COMISSAO)
       FROM
        LANCAMENTOS
       WHERE
        LANCAMENTOS.DATA_LANCAMENTO = :DATA AND
        LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR AND
        LANCAMENTOS.TIPO_VENDA = 'V' AND
        LANCAMENTOS.CD_VENDA IN
         (SELECT
           CD_VENDA
          FROM
           CAIXA,
           FORMAS_PAGAMENTO
          WHERE
           CAIXA.CD_FORMA_PAGAMENTO = FORMAS_PAGAMENTO.CD_FORMA_PAGAMENTO AND
           FORMAS_PAGAMENTO.PAGAMENTOCOMISSAOAVISTA = 'S' AND
           FORMAS_PAGAMENTO.CD_FORMA_PAGAMENTO <> 100 AND
           FORMAS_PAGAMENTO.CD_FORMA_PAGAMENTO <> 101
         )
       INTO
        :COMISSAO
      DO
       BEGIN
          IF (:COMISSAO IS NOT NULL) THEN
            COMISSAOAVISTA = :COMISSAOAVISTA + :COMISSAO;
       END
    
      FOR
       SELECT
        SUM(LANCAMENTOS.COMISSAO)
       FROM
        LANCAMENTOS
       WHERE
        LANCAMENTOS.DATA_LANCAMENTO = :DATA AND
        LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR AND
        LANCAMENTOS.TIPO_VENDA = 'D' AND
        LANCAMENTOS.CD_VENDA IN
         (SELECT
           CD_VENDA
          FROM
           CAIXA,
           FORMAS_PAGAMENTO
          WHERE
           CAIXA.CD_FORMA_PAGAMENTO = FORMAS_PAGAMENTO.CD_FORMA_PAGAMENTO AND
           FORMAS_PAGAMENTO.PAGAMENTOCOMISSAOAVISTA = 'S' AND
           FORMAS_PAGAMENTO.CD_FORMA_PAGAMENTO <> 100 AND
           FORMAS_PAGAMENTO.CD_FORMA_PAGAMENTO <> 101
         )
       INTO
        :COMISSAO
      DO
       BEGIN
          IF (:COMISSAO IS NOT NULL) THEN
             COMISSAOAVISTACANCELADA = :COMISSAOAVISTACANCELADA + :COMISSAO;
       END
    
      DIFERENCACOMISSAOAVISTA = :COMISSAOAVISTA - :COMISSAOAVISTACANCELADA;

      /* BUSCANDO TOTALIZACAO POR FORMA DE PAGAMENTO COM PAGAMENTO DE COMISSAO A PRAZO */
      COMISSAOAPRAZO = 0;
      COMISSAOAPRAZOCANCELADA = 0;
      FOR
       SELECT
        SUM(LANCAMENTOS.COMISSAO)
       FROM
        LANCAMENTOS
       WHERE
        LANCAMENTOS.DATA_LANCAMENTO = :DATA AND
        LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR AND
        LANCAMENTOS.TIPO_VENDA = 'V' AND
        LANCAMENTOS.CD_VENDA IN
         (SELECT
           CD_VENDA
          FROM
           CAIXA,
           FORMAS_PAGAMENTO
          WHERE
           CAIXA.CD_FORMA_PAGAMENTO = FORMAS_PAGAMENTO.CD_FORMA_PAGAMENTO AND
           FORMAS_PAGAMENTO.PAGAMENTOCOMISSAOAVISTA = 'N' AND
           FORMAS_PAGAMENTO.CD_FORMA_PAGAMENTO <> 100 AND
           FORMAS_PAGAMENTO.CD_FORMA_PAGAMENTO <> 101
         )
       INTO
        :COMISSAO
      DO
       BEGIN
          IF (:COMISSAO IS NOT NULL) THEN
             COMISSAOAPRAZO = :COMISSAOAPRAZO + :COMISSAO;
       END
    
      FOR
       SELECT
        SUM(LANCAMENTOS.COMISSAO)
       FROM
        LANCAMENTOS
       WHERE
        LANCAMENTOS.DATA_LANCAMENTO = :DATA AND
        LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR AND
        LANCAMENTOS.TIPO_VENDA = 'D' AND
        LANCAMENTOS.CD_VENDA IN
         (SELECT
           CD_VENDA
          FROM
           CAIXA,
           FORMAS_PAGAMENTO
          WHERE
           CAIXA.CD_FORMA_PAGAMENTO = FORMAS_PAGAMENTO.CD_FORMA_PAGAMENTO AND
           FORMAS_PAGAMENTO.PAGAMENTOCOMISSAOAVISTA = 'N' AND
           FORMAS_PAGAMENTO.CD_FORMA_PAGAMENTO <> 100 AND
           FORMAS_PAGAMENTO.CD_FORMA_PAGAMENTO <> 101
         )
       INTO
        :COMISSAO
      DO
       BEGIN
          IF (:COMISSAO IS NOT NULL) THEN
             COMISSAOAPRAZOCANCELADA = :COMISSAOAPRAZOCANCELADA + :COMISSAO;
       END
    
     DIFERENCACOMISSAOAPRAZO = :COMISSAOAPRAZO - :COMISSAOAPRAZOCANCELADA;

     IF (:COMISSAOAVISTA IS NULL) THEN
        COMISSAOAVISTA = 0;
     IF (:COMISSAOAVISTACANCELADA IS NULL) THEN
        COMISSAOAVISTACANCELADA = 0;
     IF (:COMISSAOAPRAZO IS NULL) THEN
        COMISSAOAPRAZO = 0;
     IF (:COMISSAOAPRAZOCANCELADA IS NULL) THEN
        COMISSAOAPRAZOCANCELADA = 0;
     IF (:DIFERENCACOMISSAOAVISTA IS NULL) THEN
        DIFERENCACOMISSAOAVISTA = 0;
     IF (:DIFERENCACOMISSAOAPRAZO IS NULL) THEN
        DIFERENCACOMISSAOAPRAZO = 0;


     IF ((:PERCENTUALPREMIACAO IS NOT NULL) AND (:PERCENTUALPREMIACAO > 0) AND
         (:VALORMINIMOPREMIACAO IS NOT NULL) AND (:VALORMINIMOPREMIACAO > 0)) THEN
      BEGIN
        PREMIACAOTOTAL = 0;
        /* CALCULANDO PREMIACAO SOBRE AS VENDAS */
        FOR
          SELECT
           LANCAMENTOS.CD_VENDA,
           SUM(LANCAMENTOS.VALOR * :PERCENTUALPREMIACAO / 100)
          FROM
           LANCAMENTOS
          WHERE
           LANCAMENTOS.DATA_LANCAMENTO = :DATA AND
           LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR AND
           LANCAMENTOS.TIPO_VENDA = 'V'
          GROUP BY
           LANCAMENTOS.CD_VENDA
          HAVING
           SUM(LANCAMENTOS.VALOR) > :VALORMINIMOPREMIACAO
          INTO
           :CD_VENDA,
           :PREMIACAO
        DO
         BEGIN
           IF (:PREMIACAO IS NULL) THEN
              PREMIACAO = 0;
           PREMIACAOTOTAL = :PREMIACAOTOTAL + :PREMIACAO;
         END

        /* CALCULANDO PREMIACAO SOBRE AS DEVOLUCOES */
        FOR
          SELECT
           LANCAMENTOS.CD_VENDA,
           SUM(LANCAMENTOS.VALOR * :PERCENTUALPREMIACAO / 100)
          FROM
           LANCAMENTOS
          WHERE
           LANCAMENTOS.DATA_LANCAMENTO = :DATA AND
           LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR AND
           LANCAMENTOS.TIPO_VENDA = 'D'
          GROUP BY
           LANCAMENTOS.CD_VENDA
          HAVING
           SUM(LANCAMENTOS.VALOR) > :VALORMINIMOPREMIACAO
          INTO
           :CD_VENDA,
           :PREMIACAO
        DO
         BEGIN
           IF (:PREMIACAO IS NULL) THEN
              PREMIACAO = 0;
           PREMIACAOTOTAL = :PREMIACAOTOTAL - :PREMIACAO;
         END
      END



      /* VERIFICANDO SE O DIA JA EXISTE */
      SELECT COUNT(*) FROM SALDO_COMISSAO WHERE CD_VENDEDOR = :CD_VENDEDOR AND DATA = :DATA + 1 INTO :EXISTEDIA;
  
      IF (:EXISTEDIA = 0) THEN
       BEGIN
          SALDOCOMISSAOAVISTA = 0;
          SALDOCOMISSAOAPRAZO = 0;
          SALDOAPRAZOLIBERADO = 0;
          SALDOPREMIACAO = 0;

         /* BUSCANDO OS SALDOS ANTERIORES */
         SELECT
           SALDO_COMISSAO.SALDOAVISTA,
           SALDO_COMISSAO.SALDOAPRAZO,
           SALDO_COMISSAO.VALORAPRAZOLIBERADO,
           SALDO_COMISSAO.SALDOPREMIACAO
         FROM
           SALDO_COMISSAO
         WHERE
           SALDO_COMISSAO.CD_VENDEDOR = :CD_VENDEDOR AND
           SALDO_COMISSAO.DATA IN
            (SELECT MAX(SALDO_COMISSAO.DATA) FROM SALDO_COMISSAO WHERE SALDO_COMISSAO.CD_VENDEDOR = :CD_VENDEDOR)
         INTO
          :SALDOCOMISSAOAVISTA,
          :SALDOCOMISSAOAPRAZO,
          :SALDOAPRAZOLIBERADO,
          :SALDOPREMIACAO;

         IF (:SALDOCOMISSAOAVISTA IS NULL) THEN
            SALDOCOMISSAOAVISTA = 0;
         IF (:SALDOCOMISSAOAPRAZO IS NULL) THEN
            SALDOCOMISSAOAPRAZO = 0;
         IF (:SALDOAPRAZOLIBERADO IS NULL) THEN
            SALDOAPRAZOLIBERADO = 0;
         IF (:SALDOPREMIACAO IS NULL) THEN
            SALDOPREMIACAO = 0;

         SELECT
          SUM(LANCAMENTOS.COMISSAO)
         FROM
          LANCAMENTOS,
          CONTAS_RECEBER
         WHERE
          CONTAS_RECEBER.CD_VENDA IS NOT NULL AND
          CONTAS_RECEBER.CD_VENDA > 0 AND
          CONTAS_RECEBER.CD_VENDA = LANCAMENTOS.CD_VENDA AND
          CONTAS_RECEBER.DT_PAGAMENTO = :DATA AND
          CONTAS_RECEBER.CD_VENDEDOR = :CD_VENDEDOR AND
          CONTAS_RECEBER.CD_FORMA_PAGAMENTO IN
          (SELECT
            CD_FORMA_PAGAMENTO
           FROM
            FORMAS_PAGAMENTO
           WHERE
            FORMAS_PAGAMENTO.PAGAMENTOCOMISSAOAVISTA = 'N' AND
            FORMAS_PAGAMENTO.CD_FORMA_PAGAMENTO <> 100 AND
            FORMAS_PAGAMENTO.CD_FORMA_PAGAMENTO <> 101
          )
         INTO
          :VALORAPRAZOLIBERADO;

         IF (:VALORAPRAZOLIBERADO IS NULL) THEN
            VALORAPRAZOLIBERADO = 0;

         SELECT VALOR FROM CONTROLE WHERE CAMPO = 'CD_SALDO_COMISSAO' INTO :CODIGO;

         IF (:CODIGO IS NULL) THEN
          BEGIN
            CODIGO = 0;
            INSERT INTO CONTROLE VALUES ('CD_SALDO_COMISSAO', 0);
          END

         CODIGO = :CODIGO + 1;
         UPDATE CONTROLE SET
          VALOR = :CODIGO
         WHERE CAMPO = 'CD_SALDO_COMISSAO';

         /* INCLUINDO NA TABELA DE SALDO_COMISSAO */
         INSERT INTO SALDO_COMISSAO VALUES (:CODIGO, :CD_FILIAL, :CD_VENDEDOR, :DATA + 1, :COMISSAOAVISTA, :COMISSAOAVISTACANCELADA,
                                            :COMISSAOAPRAZO, :COMISSAOAPRAZOCANCELADA,
                                            :SALDOAPRAZOLIBERADO + :VALORAPRAZOLIBERADO,
                                            :SALDOCOMISSAOAVISTA, :SALDOCOMISSAOAVISTA + :DIFERENCACOMISSAOAVISTA,
                                            :SALDOCOMISSAOAPRAZO, :SALDOCOMISSAOAPRAZO + :DIFERENCACOMISSAOAPRAZO,
                                            :SALDOPREMIACAO, :SALDOPREMIACAO + :PREMIACAOTOTAL);
       END
  END
END ^

ALTER PROCEDURE SP_PREENCHE_TEMP_COMPRAS (DATAINICIAL DATE,
DATAFINAL DATE)
AS 
DECLARE VARIABLE CD_COMPRAS DOUBLE PRECISION;
DECLARE VARIABLE CD_FILIAL DOUBLE PRECISION;
DECLARE VARIABLE ID_PRODUTO DOUBLE PRECISION;
BEGIN
  SELECT CD_FILIAL FROM PARAMETROS INTO :CD_FILIAL;
  FOR
   SELECT
    CD_COMPRAS
   FROM
    COMPRAS
   WHERE
    DT_PEDIDO >= :DATAINICIAL AND
    DT_PEDIDO <= :DATAFINAL
   INTO
    :CD_COMPRAS
  DO
   BEGIN
     INSERT INTO TEMP_COMPRAS VALUES (:CD_COMPRAS, NULL, :CD_FILIAL, '4', '');
   END

  FOR
   SELECT
    ITENS_COMPRA.CD_COMPRAS,
    ITENS_COMPRA.ID_PRODUTO
   FROM
    ITENS_COMPRA,
    COMPRAS
   WHERE
    COMPRAS.CD_COMPRAS = ITENS_COMPRA.CD_COMPRAS AND
    COMPRAS.DT_PEDIDO >= :DATAINICIAL AND
    COMPRAS.DT_PEDIDO <= :DATAFINAL
   INTO
    :CD_COMPRAS,
    :ID_PRODUTO
  DO
   BEGIN
     INSERT INTO TEMP_COMPRAS VALUES (:CD_COMPRAS, :ID_PRODUTO, :CD_FILIAL, '5', '');
   END

END ^

ALTER PROCEDURE SP_PREENCHE_TOTAIS (CD_FILIAL DOUBLE PRECISION)
RETURNS (DATA VARCHAR(7) CHARACTER SET NONE,
MESVIRTUAL VARCHAR(3) CHARACTER SET NONE,
MESVIRTUAL1 VARCHAR(12) CHARACTER SET NONE,
VENDAS DOUBLE PRECISION,
QUANTIDADE_VENDIDA DOUBLE PRECISION,
NUMERO_DE_VENDAS DOUBLE PRECISION,
MEDIA_POR_CUPOM DOUBLE PRECISION,
MEDIA_POR_UNIDADE DOUBLE PRECISION,
DESCONTO_VENDAS DOUBLE PRECISION,
COMISSAO_VENDAS DOUBLE PRECISION,
COMPRAS DOUBLE PRECISION,
INDICE DOUBLE PRECISION)
AS 
DECLARE VARIABLE MES INTEGER;
DECLARE VARIABLE ANO INTEGER;
DECLARE VARIABLE VENDAS_CANCELADAS DOUBLE PRECISION;
DECLARE VARIABLE QUANTIDADE_CANCELADA DOUBLE PRECISION;
DECLARE VARIABLE NUMERO_DE_VENDAS_CANCELADAS DOUBLE PRECISION;
DECLARE VARIABLE COMISSAO_CANCELADA DOUBLE PRECISION;
DECLARE VARIABLE DESCONTO_CANCELADO DOUBLE PRECISION;
DECLARE VARIABLE TEMREGISTRO INTEGER;
BEGIN
   MES = EXTRACT(MONTH FROM CURRENT_DATE) - 1;
   ANO = EXTRACT(YEAR FROM CURRENT_DATE);

   SELECT COUNT(*) FROM TEMP_TOTAIS_MES
   WHERE FILIAL = :CD_FILIAL AND MES = :MES AND ANO = :ANO
   INTO :TEMREGISTRO;
   IF ((:TEMREGISTRO IS NOT NULL) OR (:TEMREGISTRO > 0)) THEN
    BEGIN
       DELETE FROM TEMP_TOTAIS_MES
       WHERE FILIAL = :CD_FILIAL AND MES = :MES AND ANO = :ANO;
    END

   FOR
     /* VENDAS */
     SELECT
      CAST(EXTRACT(YEAR FROM LANCAMENTOS.DATA_LANCAMENTO) AS VARCHAR(4))||'-'||
      CAST(EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO) AS VARCHAR(2)),
      CASE
       WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 1 THEN  'JAN'
       WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 2 THEN  'FEV'
       WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 3 THEN  'MAR'
       WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 4 THEN  'ABR'
       WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 5 THEN  'MAI'
       WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 6 THEN  'JUN'
       WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 7 THEN  'JUL'
       WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 8 THEN  'AGO'
       WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 9 THEN  'SET'
       WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 10 THEN 'OUT'
       WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 11 THEN 'NOV'
       WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 12 THEN 'DEZ'
      END,
      CASE
       WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 1 THEN  'Janeiro'
       WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 2 THEN  'Fevereiro'
       WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 3 THEN  'Marco'
       WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 4 THEN  'Abril'
       WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 5 THEN  'Maio'
       WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 6 THEN  'Junho'
       WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 7 THEN  'Julho'
       WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 8 THEN  'Agosto'
       WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 9 THEN  'Setembro'
       WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 10 THEN 'Outubro'
       WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 11 THEN 'Novembro'
       WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 12 THEN 'Dezembro'
      END,
      SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
      SUM(LANCAMENTOS.QUANTIDADE),
      COUNT(DISTINCT LANCAMENTOS.CD_VENDA),
      SUM(LANCAMENTOS.COMISSAO),
      SUM(LANCAMENTOS.DESCONTO)
     FROM
      LANCAMENTOS
     WHERE
      LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
      LANCAMENTOS.TIPO_VENDA = 'V' AND
      EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO) = :MES AND
      EXTRACT(YEAR FROM LANCAMENTOS.DATA_LANCAMENTO) = :ANO
     GROUP BY
      EXTRACT(YEAR FROM LANCAMENTOS.DATA_LANCAMENTO),
      EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)
     ORDER BY
      EXTRACT(YEAR FROM LANCAMENTOS.DATA_LANCAMENTO),
      EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)
     INTO
      :DATA, :MESVIRTUAL, :MESVIRTUAL1, :VENDAS,
      :QUANTIDADE_VENDIDA, :NUMERO_DE_VENDAS,
      :COMISSAO_VENDAS, :DESCONTO_VENDAS
   DO
    BEGIN
       /* CANCELAMENTOS DE VENDAS*/
       SELECT
        SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
        SUM(LANCAMENTOS.QUANTIDADE),
        COUNT(DISTINCT LANCAMENTOS.CD_VENDA),
        SUM(LANCAMENTOS.COMISSAO),
        SUM(LANCAMENTOS.DESCONTO)
       FROM
        LANCAMENTOS
       WHERE
        LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
        LANCAMENTOS.TIPO_VENDA = 'D' AND
        EXTRACT(YEAR FROM LANCAMENTOS.DATA_LANCAMENTO) = :ANO AND
        EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO) = :MES
       INTO
        :VENDAS_CANCELADAS, :QUANTIDADE_CANCELADA, :NUMERO_DE_VENDAS_CANCELADAS,
        :COMISSAO_CANCELADA, :DESCONTO_CANCELADO;

       IF (:VENDAS_CANCELADAS IS NULL) THEN
          VENDAS_CANCELADAS = 0;
       IF (:QUANTIDADE_CANCELADA IS NULL) THEN
          QUANTIDADE_CANCELADA = 0;
       IF (:NUMERO_DE_VENDAS_CANCELADAS IS NULL) THEN
          NUMERO_DE_VENDAS_CANCELADAS = 0;
    
       /* TOTALIZANDO : VENDAS - CANCELAMENTOS */
       VENDAS = :VENDAS - :VENDAS_CANCELADAS;
       QUANTIDADE_VENDIDA = :QUANTIDADE_VENDIDA - :QUANTIDADE_CANCELADA;
       NUMERO_DE_VENDAS = :NUMERO_DE_VENDAS - :NUMERO_DE_VENDAS_CANCELADAS;
       COMISSAO_VENDAS = :COMISSAO_VENDAS - :COMISSAO_CANCELADA;
       DESCONTO_VENDAS = :DESCONTO_VENDAS - :DESCONTO_CANCELADO;
    
       /* COMPRAS */
       SELECT
        SUM(LANCAMENTOS.VALOR)
       FROM
        LANCAMENTOS
       WHERE
        LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
        EXTRACT(YEAR FROM LANCAMENTOS.DATA_LANCAMENTO) = :ANO AND
        EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO) = :MES AND
        LANCAMENTOS.TIPO_VENDA = 'C'
       INTO
        :COMPRAS;
    
       IF (:COMPRAS IS NULL) THEN
          COMPRAS = 0;
    
       /* GERANDO INDICE E MEDIAS */
       INDICE = (:COMPRAS * 100 )/:VENDAS;
       MEDIA_POR_CUPOM = :VENDAS / :NUMERO_DE_VENDAS;
       MEDIA_POR_UNIDADE = :VENDAS / :QUANTIDADE_VENDIDA;

       INSERT INTO TEMP_TOTAIS_MES VALUES
       (:CD_FILIAL, :DATA, :ANO, :MES, :MESVIRTUAL, :MESVIRTUAL1,
        :VENDAS, :QUANTIDADE_VENDIDA, :DESCONTO_VENDAS, :COMISSAO_VENDAS,
        :NUMERO_DE_VENDAS, :MEDIA_POR_CUPOM, :MEDIA_POR_UNIDADE, :COMPRAS,
        :INDICE);
   END
END ^

ALTER PROCEDURE SP_PREENCHE_TOTAIS_CLASSES (CD_FILIAL DOUBLE PRECISION)
RETURNS (CD_CLASSE DOUBLE PRECISION,
DESCRICAO VARCHAR(30) CHARACTER SET NONE,
DATA VARCHAR(7) CHARACTER SET NONE,
MESVIRTUAL VARCHAR(3) CHARACTER SET NONE,
MESVIRTUAL1 VARCHAR(12) CHARACTER SET NONE,
VENDAS DOUBLE PRECISION,
QUANTIDADE_VENDIDA DOUBLE PRECISION,
NUMERO_DE_VENDAS DOUBLE PRECISION,
MEDIA_POR_CUPOM DOUBLE PRECISION,
MEDIA_POR_UNIDADE DOUBLE PRECISION,
DESCONTO_VENDAS DOUBLE PRECISION,
COMISSAO_VENDAS DOUBLE PRECISION,
