           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 10 THEN 'Outubro'
           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 11 THEN 'Novembro'
           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 12 THEN 'Dezembro'
          END,
          SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
          SUM(LANCAMENTOS.QUANTIDADE),
          COUNT(DISTINCT LANCAMENTOS.CD_VENDA),
          SUM(LANCAMENTOS.COMISSAO),
          SUM(LANCAMENTOS.DESCONTO)
         FROM
          LANCAMENTOS
         WHERE
          LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
          LANCAMENTOS.CD_GRUPO = :CD_GRUPO AND
          LANCAMENTOS.TIPO_VENDA = 'V' AND
          LANCAMENTOS.DATA_LANCAMENTO >= :MES||'/1/'||:ANO
          /*EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO) = :MES AND
          EXTRACT(YEAR FROM LANCAMENTOS.DATA_LANCAMENTO) = :ANO*/
         GROUP BY
          EXTRACT(YEAR FROM LANCAMENTOS.DATA_LANCAMENTO),
          EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)
         ORDER BY
          EXTRACT(YEAR FROM LANCAMENTOS.DATA_LANCAMENTO),
          EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)
         INTO
          :DATA, :MESVIRTUAL, :MESVIRTUAL1, :VENDAS,
          :QUANTIDADE_VENDIDA, :NUMERO_DE_VENDAS,
          :COMISSAO_VENDAS, :DESCONTO_VENDAS
       DO
        BEGIN
           /* CANCELAMENTOS DE VENDAS*/
           SELECT
            SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
            SUM(LANCAMENTOS.QUANTIDADE),
            COUNT(DISTINCT LANCAMENTOS.CD_VENDA),
            SUM(LANCAMENTOS.COMISSAO),
            SUM(LANCAMENTOS.DESCONTO)
           FROM
            LANCAMENTOS
           WHERE
            LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
            LANCAMENTOS.CD_GRUPO = :CD_GRUPO AND
            LANCAMENTOS.TIPO_VENDA = 'D' AND
            EXTRACT(YEAR FROM LANCAMENTOS.DATA_LANCAMENTO) = :ANO AND
            EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO) = :MES
           INTO
            :VENDAS_CANCELADAS, :QUANTIDADE_CANCELADA, :NUMERO_DE_VENDAS_CANCELADAS,
            :COMISSAO_CANCELADA, :DESCONTO_CANCELADO;
    
           IF (:VENDAS_CANCELADAS IS NULL) THEN
              VENDAS_CANCELADAS = 0;
           IF (:QUANTIDADE_CANCELADA IS NULL) THEN
              QUANTIDADE_CANCELADA = 0;
           IF (:NUMERO_DE_VENDAS_CANCELADAS IS NULL) THEN
              NUMERO_DE_VENDAS_CANCELADAS = 0;

           /* TOTALIZANDO : VENDAS - CANCELAMENTOS */
           VENDAS = :VENDAS - :VENDAS_CANCELADAS;
           QUANTIDADE_VENDIDA = :QUANTIDADE_VENDIDA - :QUANTIDADE_CANCELADA;
           NUMERO_DE_VENDAS = :NUMERO_DE_VENDAS - :NUMERO_DE_VENDAS_CANCELADAS;
           COMISSAO_VENDAS = :COMISSAO_VENDAS - :COMISSAO_CANCELADA;
           DESCONTO_VENDAS = :DESCONTO_VENDAS - :DESCONTO_CANCELADO;
        
           /* COMPRAS */
           SELECT
            SUM(LANCAMENTOS.VALOR)
           FROM
            LANCAMENTOS
           WHERE
            LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
            LANCAMENTOS.TIPO_VENDA = 'C' AND
            LANCAMENTOS.CD_GRUPO = :CD_GRUPO AND
            EXTRACT(YEAR FROM LANCAMENTOS.DATA_LANCAMENTO) = :ANO AND
            EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO) = :MES
           INTO
            :COMPRAS;
        
           IF (:COMPRAS IS NULL) THEN
              COMPRAS = 0;
        
           /* GERANDO INDICE E MEDIAS */
           IF (:VENDAS > 0) THEN
              INDICE = (:COMPRAS * 100 )/:VENDAS;
           ELSE
              INDICE = 0;
           IF ((:VENDAS > 0) AND (:NUMERO_DE_VENDAS > 0)) THEN
              MEDIA_POR_CUPOM = :VENDAS / :NUMERO_DE_VENDAS;
           ELSE
              MEDIA_POR_CUPOM = 0;
           IF ((:VENDAS > 0) AND (:QUANTIDADE_VENDIDA > 0)) THEN
              MEDIA_POR_UNIDADE = :VENDAS / :QUANTIDADE_VENDIDA;
           ELSE
              MEDIA_POR_UNIDADE = 0;

           INSERT INTO TEMP_TOTAIS_GRUPOS_MES VALUES
           (:CD_FILIAL, :CD_GRUPO, :DESCRICAO, :DATA, :ANO, :MES, :MESVIRTUAL, :MESVIRTUAL1,
            :VENDAS, :QUANTIDADE_VENDIDA, :DESCONTO_VENDAS, :COMISSAO_VENDAS,
            :NUMERO_DE_VENDAS, :COMPRAS);

           MES = :MES + 1;
           IF (:MES = 13) THEN
            BEGIN
              MES = 1;
              ANO = :ANO + 1;
            END
        END
    END
END ^

ALTER PROCEDURE SP_PREENCHE_TOTAIS_LABORATORIOS (CD_FILIAL DOUBLE PRECISION)
RETURNS (CD_LABORATORIO DOUBLE PRECISION,
NOME VARCHAR(30) CHARACTER SET NONE,
DATA VARCHAR(7) CHARACTER SET NONE,
MESVIRTUAL VARCHAR(3) CHARACTER SET NONE,
MESVIRTUAL1 VARCHAR(12) CHARACTER SET NONE,
VENDAS DOUBLE PRECISION,
QUANTIDADE_VENDIDA DOUBLE PRECISION,
NUMERO_DE_VENDAS DOUBLE PRECISION,
MEDIA_POR_CUPOM DOUBLE PRECISION,
MEDIA_POR_UNIDADE DOUBLE PRECISION,
DESCONTO_VENDAS DOUBLE PRECISION,
COMISSAO_VENDAS DOUBLE PRECISION,
COMPRAS DOUBLE PRECISION,
INDICE DOUBLE PRECISION)
AS 
DECLARE VARIABLE MES INTEGER;
DECLARE VARIABLE ANO INTEGER;
DECLARE VARIABLE VENDAS_CANCELADAS DOUBLE PRECISION;
DECLARE VARIABLE QUANTIDADE_CANCELADA DOUBLE PRECISION;
DECLARE VARIABLE NUMERO_DE_VENDAS_CANCELADAS DOUBLE PRECISION;
DECLARE VARIABLE COMISSAO_CANCELADA DOUBLE PRECISION;
DECLARE VARIABLE DESCONTO_CANCELADO DOUBLE PRECISION;
DECLARE VARIABLE TEMREGISTRO INTEGER;
BEGIN
   FOR
    SELECT
     CD_LABORATORIO,
     NOME
    FROM
     LABORATORIOS
    ORDER BY
     CD_LABORATORIO
    INTO
     :CD_LABORATORIO, :NOME
   DO
    BEGIN
       MES = EXTRACT(MONTH FROM CURRENT_DATE);
       ANO = EXTRACT(YEAR FROM CURRENT_DATE) - 1;
    
       /*MES = EXTRACT(MONTH FROM CURRENT_DATE) - 1;
       ANO = EXTRACT(YEAR FROM CURRENT_DATE);
    
       SELECT COUNT(*) FROM TEMP_TOTAIS_LABORATORIOS_MES
       WHERE FILIAL = :CD_FILIAL AND CD_LABORATORIO = :CD_LABORATORIO AND
             MES = :MES AND ANO = :ANO
       INTO :TEMREGISTRO;
       IF ((:TEMREGISTRO IS NOT NULL) OR (:TEMREGISTRO > 0)) THEN
        BEGIN
           DELETE FROM TEMP_TOTAIS_LABORATORIOS_MES
           WHERE FILIAL = :CD_FILIAL AND CD_LABORATORIO = :CD_LABORATORIO AND
                 MES = :MES AND ANO = :ANO;
        END*/

       FOR
         /* VENDAS */
         SELECT
          CAST(EXTRACT(YEAR FROM LANCAMENTOS.DATA_LANCAMENTO) AS VARCHAR(4))||'-'||
          CAST(EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO) AS VARCHAR(2)),
          CASE
           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 1 THEN  'JAN'
           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 2 THEN  'FEV'
           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 3 THEN  'MAR'
           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 4 THEN  'ABR'
           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 5 THEN  'MAI'
           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 6 THEN  'JUN'
           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 7 THEN  'JUL'
           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 8 THEN  'AGO'
           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 9 THEN  'SET'
           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 10 THEN 'OUT'
           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 11 THEN 'NOV'
           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 12 THEN 'DEZ'
          END,
          CASE
           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 1 THEN  'Janeiro'
           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 2 THEN  'Fevereiro'
           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 3 THEN  'Marco'
           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 4 THEN  'Abril'
           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 5 THEN  'Maio'
           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 6 THEN  'Junho'
           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 7 THEN  'Julho'
           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 8 THEN  'Agosto'
           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 9 THEN  'Setembro'
           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 10 THEN 'Outubro'
           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 11 THEN 'Novembro'
           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 12 THEN 'Dezembro'
          END,
          SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
          SUM(LANCAMENTOS.QUANTIDADE),
          COUNT(DISTINCT LANCAMENTOS.CD_VENDA),
          SUM(LANCAMENTOS.COMISSAO),
          SUM(LANCAMENTOS.DESCONTO)
         FROM
          LANCAMENTOS
         WHERE
          LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
          LANCAMENTOS.CD_LABORATORIO = :CD_LABORATORIO AND
          LANCAMENTOS.TIPO_VENDA = 'V' AND
          LANCAMENTOS.DATA_LANCAMENTO >= :MES||'/1/'||:ANO
          /*EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO) = :MES AND
          EXTRACT(YEAR FROM LANCAMENTOS.DATA_LANCAMENTO) = :ANO*/
         GROUP BY
          EXTRACT(YEAR FROM LANCAMENTOS.DATA_LANCAMENTO),
          EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)
         ORDER BY
          EXTRACT(YEAR FROM LANCAMENTOS.DATA_LANCAMENTO),
          EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)
         INTO
          :DATA, :MESVIRTUAL, :MESVIRTUAL1, :VENDAS,
          :QUANTIDADE_VENDIDA, :NUMERO_DE_VENDAS,
          :COMISSAO_VENDAS, :DESCONTO_VENDAS
       DO
        BEGIN
           /* CANCELAMENTOS DE VENDAS*/
           SELECT
            SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
            SUM(LANCAMENTOS.QUANTIDADE),
            COUNT(DISTINCT LANCAMENTOS.CD_VENDA),
            SUM(LANCAMENTOS.COMISSAO),
            SUM(LANCAMENTOS.DESCONTO)
           FROM
            LANCAMENTOS
           WHERE
            LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
            LANCAMENTOS.CD_LABORATORIO = :CD_LABORATORIO AND
            LANCAMENTOS.TIPO_VENDA = 'D' AND
            EXTRACT(YEAR FROM LANCAMENTOS.DATA_LANCAMENTO) = :ANO AND
            EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO) = :MES
           INTO
            :VENDAS_CANCELADAS, :QUANTIDADE_CANCELADA, :NUMERO_DE_VENDAS_CANCELADAS,
            :COMISSAO_CANCELADA, :DESCONTO_CANCELADO;
    
           IF (:VENDAS_CANCELADAS IS NULL) THEN
              VENDAS_CANCELADAS = 0;
           IF (:QUANTIDADE_CANCELADA IS NULL) THEN
              QUANTIDADE_CANCELADA = 0;
           IF (:NUMERO_DE_VENDAS_CANCELADAS IS NULL) THEN
              NUMERO_DE_VENDAS_CANCELADAS = 0;
        
           /* TOTALIZANDO : VENDAS - CANCELAMENTOS */
           VENDAS = :VENDAS - :VENDAS_CANCELADAS;
           QUANTIDADE_VENDIDA = :QUANTIDADE_VENDIDA - :QUANTIDADE_CANCELADA;
           NUMERO_DE_VENDAS = :NUMERO_DE_VENDAS - :NUMERO_DE_VENDAS_CANCELADAS;
           COMISSAO_VENDAS = :COMISSAO_VENDAS - :COMISSAO_CANCELADA;
           DESCONTO_VENDAS = :DESCONTO_VENDAS - :DESCONTO_CANCELADO;
        
           /* COMPRAS */
           SELECT
            SUM(LANCAMENTOS.VALOR)
           FROM
            LANCAMENTOS
           WHERE
            LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
            LANCAMENTOS.TIPO_VENDA = 'C' AND
            LANCAMENTOS.CD_LABORATORIO = :CD_LABORATORIO AND
            EXTRACT(YEAR FROM LANCAMENTOS.DATA_LANCAMENTO) = :ANO AND
            EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO) = :MES
           INTO
            :COMPRAS;
        
           IF (:COMPRAS IS NULL) THEN
              COMPRAS = 0;
        
           /* GERANDO INDICE E MEDIAS */
           INDICE = (:COMPRAS * 100 )/:VENDAS;
           MEDIA_POR_CUPOM = :VENDAS / :NUMERO_DE_VENDAS;
           MEDIA_POR_UNIDADE = :VENDAS / :QUANTIDADE_VENDIDA;
    
           INSERT INTO TEMP_TOTAIS_LABORATORIOS_MES VALUES
           (:CD_FILIAL, :CD_LABORATORIO, :NOME, :DATA, :ANO, :MES, :MESVIRTUAL, :MESVIRTUAL1,
            :VENDAS, :QUANTIDADE_VENDIDA, :DESCONTO_VENDAS, :COMISSAO_VENDAS,
            :NUMERO_DE_VENDAS, :MEDIA_POR_CUPOM, :MEDIA_POR_UNIDADE, :COMPRAS,
            :INDICE);

           MES = :MES + 1;
           IF (:MES = 13) THEN
            BEGIN
              MES = 1;
              ANO = :ANO + 1;
            END
        END
    END
END ^

ALTER PROCEDURE SP_PREENCHE_TOTAIS_VENDEDORES (CD_FILIAL DOUBLE PRECISION)
RETURNS (CD_VENDEDOR DOUBLE PRECISION,
NOME VARCHAR(30) CHARACTER SET NONE,
DATA VARCHAR(7) CHARACTER SET NONE,
MESVIRTUAL VARCHAR(3) CHARACTER SET NONE,
MESVIRTUAL1 VARCHAR(12) CHARACTER SET NONE,
VENDAS DOUBLE PRECISION,
QUANTIDADE_VENDIDA DOUBLE PRECISION,
NUMERO_DE_VENDAS DOUBLE PRECISION,
MEDIA_POR_CUPOM DOUBLE PRECISION,
MEDIA_POR_UNIDADE DOUBLE PRECISION,
DESCONTO_VENDAS DOUBLE PRECISION,
COMISSAO_VENDAS DOUBLE PRECISION)
AS 
DECLARE VARIABLE MES INTEGER;
DECLARE VARIABLE ANO INTEGER;
DECLARE VARIABLE VENDAS_CANCELADAS DOUBLE PRECISION;
DECLARE VARIABLE QUANTIDADE_CANCELADA DOUBLE PRECISION;
DECLARE VARIABLE NUMERO_DE_VENDAS_CANCELADAS DOUBLE PRECISION;
DECLARE VARIABLE COMISSAO_CANCELADA DOUBLE PRECISION;
DECLARE VARIABLE DESCONTO_CANCELADO DOUBLE PRECISION;
DECLARE VARIABLE TEMREGISTRO INTEGER;
BEGIN
   FOR
    SELECT
     CD_VENDEDOR,
     NOME
    FROM
     VENDEDORES
    ORDER BY
     CD_VENDEDOR
    INTO
     :CD_VENDEDOR, :NOME
   DO
    BEGIN
       /*MES = EXTRACT(MONTH FROM CURRENT_DATE);
       ANO = EXTRACT(YEAR FROM CURRENT_DATE) - 1;*/
    
       MES = EXTRACT(MONTH FROM CURRENT_DATE) - 1;
       ANO = EXTRACT(YEAR FROM CURRENT_DATE);
    
       SELECT COUNT(*) FROM TEMP_TOTAIS_VENDEDORES_MES
       WHERE FILIAL = :CD_FILIAL AND CD_VENDEDOR = :CD_VENDEDOR AND
             MES = :MES AND ANO = :ANO
       INTO :TEMREGISTRO;
       IF ((:TEMREGISTRO IS NOT NULL) OR (:TEMREGISTRO > 0)) THEN
        BEGIN
           DELETE FROM TEMP_TOTAIS_VENDEDORES_MES
           WHERE FILIAL = :CD_FILIAL AND CD_VENDEDOR = :CD_VENDEDOR AND
                 MES = :MES AND ANO = :ANO;
        END

       FOR
         /* VENDAS */
         SELECT
          CAST(EXTRACT(YEAR FROM LANCAMENTOS.DATA_LANCAMENTO) AS VARCHAR(4))||'-'||
          CAST(EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO) AS VARCHAR(2)),
          CASE
           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 1 THEN  'JAN'
           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 2 THEN  'FEV'
           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 3 THEN  'MAR'
           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 4 THEN  'ABR'
           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 5 THEN  'MAI'
           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 6 THEN  'JUN'
           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 7 THEN  'JUL'
           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 8 THEN  'AGO'
           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 9 THEN  'SET'
           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 10 THEN 'OUT'
           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 11 THEN 'NOV'
           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 12 THEN 'DEZ'
          END,
          CASE
           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 1 THEN  'Janeiro'
           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 2 THEN  'Fevereiro'
           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 3 THEN  'Marco'
           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 4 THEN  'Abril'
           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 5 THEN  'Maio'
           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 6 THEN  'Junho'
           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 7 THEN  'Julho'
           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 8 THEN  'Agosto'
           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 9 THEN  'Setembro'
           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 10 THEN 'Outubro'
           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 11 THEN 'Novembro'
           WHEN (EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)) = 12 THEN 'Dezembro'
          END,
          SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
          SUM(LANCAMENTOS.QUANTIDADE),
          COUNT(DISTINCT LANCAMENTOS.CD_VENDA),
          SUM(LANCAMENTOS.COMISSAO),
          SUM(LANCAMENTOS.DESCONTO)
         FROM
          LANCAMENTOS
         WHERE
          LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
          LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR AND
          LANCAMENTOS.TIPO_VENDA = 'V' AND
          /*LANCAMENTOS.DATA_LANCAMENTO >= :MES||'/1/'||:ANO*/
          EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO) = :MES AND
          EXTRACT(YEAR FROM LANCAMENTOS.DATA_LANCAMENTO) = :ANO
         GROUP BY
          EXTRACT(YEAR FROM LANCAMENTOS.DATA_LANCAMENTO),
          EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)
         ORDER BY
          EXTRACT(YEAR FROM LANCAMENTOS.DATA_LANCAMENTO),
          EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)
         INTO
          :DATA, :MESVIRTUAL, :MESVIRTUAL1, :VENDAS,
          :QUANTIDADE_VENDIDA, :NUMERO_DE_VENDAS,
          :COMISSAO_VENDAS, :DESCONTO_VENDAS
       DO
        BEGIN
           /* CANCELAMENTOS DE VENDAS*/
           SELECT
            SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
            SUM(LANCAMENTOS.QUANTIDADE),
            COUNT(DISTINCT LANCAMENTOS.CD_VENDA),
            SUM(LANCAMENTOS.COMISSAO),
            SUM(LANCAMENTOS.DESCONTO)
           FROM
            LANCAMENTOS
           WHERE
            LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
            LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR AND
            LANCAMENTOS.TIPO_VENDA = 'D' AND
            EXTRACT(YEAR FROM LANCAMENTOS.DATA_LANCAMENTO) = :ANO AND
            EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO) = :MES
           INTO
            :VENDAS_CANCELADAS, :QUANTIDADE_CANCELADA, :NUMERO_DE_VENDAS_CANCELADAS,
            :COMISSAO_CANCELADA, :DESCONTO_CANCELADO;
    
           IF (:VENDAS_CANCELADAS IS NULL) THEN
              VENDAS_CANCELADAS = 0;
           IF (:QUANTIDADE_CANCELADA IS NULL) THEN
              QUANTIDADE_CANCELADA = 0;
           IF (:NUMERO_DE_VENDAS_CANCELADAS IS NULL) THEN
              NUMERO_DE_VENDAS_CANCELADAS = 0;
        
           /* TOTALIZANDO : VENDAS - CANCELAMENTOS */
           VENDAS = :VENDAS - :VENDAS_CANCELADAS;
           QUANTIDADE_VENDIDA = :QUANTIDADE_VENDIDA - :QUANTIDADE_CANCELADA;
           NUMERO_DE_VENDAS = :NUMERO_DE_VENDAS - :NUMERO_DE_VENDAS_CANCELADAS;
           COMISSAO_VENDAS = :COMISSAO_VENDAS - :COMISSAO_CANCELADA;
           DESCONTO_VENDAS = :DESCONTO_VENDAS - :DESCONTO_CANCELADO;
        
           /* GERANDO INDICE E MEDIAS */
           MEDIA_POR_CUPOM = :VENDAS / :NUMERO_DE_VENDAS;
           MEDIA_POR_UNIDADE = :VENDAS / :QUANTIDADE_VENDIDA;
    
           INSERT INTO TEMP_TOTAIS_VENDEDORES_MES VALUES
           (:CD_FILIAL, :CD_VENDEDOR, :NOME, :DATA, :ANO, :MES, :MESVIRTUAL, :MESVIRTUAL1,
            :VENDAS, :QUANTIDADE_VENDIDA, :DESCONTO_VENDAS, :COMISSAO_VENDAS,
            :NUMERO_DE_VENDAS, :MEDIA_POR_CUPOM, :MEDIA_POR_UNIDADE);

           /*MES = :MES + 1;
           IF (:MES = 13) THEN
            BEGIN
              MES = 1;
              ANO = :ANO + 1;
            END*/
        END
    END
END ^

ALTER PROCEDURE SP_PREENCHE_ULTIMO_MOVIMENTO AS 
declare variable ID_PRODUTO double precision;
declare variable DATA date;
BEGIN
 FOR
    SELECT ID_PRODUTO, MAX(DATA_LANCAMENTO)
    FROM LANCAMENTOS
    WHERE
      DATA_LANCAMENTO >= '22.05.2016' AND
      ((TIPO_VENDA = 'V') OR (TIPO_VENDA = 'C'))
    GROUP BY ID_PRODUTO
    INTO :ID_PRODUTO, :DATA
 DO
  BEGIN
    UPDATE PRODUTOS SET
     DT_ULTIMA_COMPRA = :DATA,
     DT_ULT_VENDA_0 = :DATA
    WHERE ID_PRODUTO = :ID_PRODUTO;
  END
END ^

ALTER PROCEDURE SP_PREENCHE_VENDA_PRODUTO (ANO INTEGER,
MES INTEGER,
FILIAL DOUBLE PRECISION)
AS 
declare variable PRODUTO double precision;
declare variable VALOR double precision;
declare variable VENDA double precision;
declare variable COMPRA double precision;
declare variable DATA1 date;
declare variable DATA2 date;
declare variable ULTIMODIAMES integer;
BEGIN
  /*MONTAGEM DAS VARIAVEIS DATA1 E DATA2*/
  IF ((:MES = 1) OR (:MES = 3) OR (:MES = 5) OR (:MES = 7) OR (:MES = 8) OR (:MES = 10) OR (:MES = 12)) THEN
     ULTIMODIAMES = 31;
  ELSE
  IF ((:MES = 4) OR (:MES = 6) OR (:MES = 9) OR (:MES = 11)) THEN
     ULTIMODIAMES = 30;
  ELSE
     ULTIMODIAMES = 28;
  DATA1 = :MES||'/01/'||:ANO;
  DATA2 = :MES||'/'||:ULTIMODIAMES||'/'||:ANO;
  /*MONTAGEM DAS VARIAVEIS DATA1 E DATA2*/

  /*ZERANDO DADOS DOS PRODUTOS NO MES*/
   IF (:MES = 1) THEN
    BEGIN
      UPDATE PRODUTOS_TOTAIS SET JANVENDA = 0, JANCOMPRA = 0 WHERE CD_FILIAL = :FILIAL;
    END
   ELSE
   IF (:MES = 2) THEN
    BEGIN
      UPDATE PRODUTOS_TOTAIS SET FEVVENDA = 0,FEVCOMPRA = 0 WHERE CD_FILIAL = :FILIAL;
    END
   ELSE
   IF (:MES = 3) THEN
    BEGIN
      UPDATE PRODUTOS_TOTAIS SET MARVENDA = 0, MARCOMPRA = 0 WHERE CD_FILIAL = :FILIAL;
    END
   ELSE
   IF (:MES = 4) THEN
    BEGIN
      UPDATE PRODUTOS_TOTAIS SET ABRVENDA = 0, ABRCOMPRA = 0 WHERE CD_FILIAL = :FILIAL;
    END
   ELSE
   IF (:MES = 5) THEN
    BEGIN
      UPDATE PRODUTOS_TOTAIS SET MAIVENDA = 0, MAICOMPRA = 0 WHERE CD_FILIAL = :FILIAL;
    END
   ELSE
   IF (:MES = 6) THEN
    BEGIN
      UPDATE PRODUTOS_TOTAIS SET JUNVENDA = 0, JUNCOMPRA = 0 WHERE CD_FILIAL = :FILIAL;
    END
   ELSE
   IF (:MES = 7) THEN
    BEGIN
      UPDATE PRODUTOS_TOTAIS SET JULVENDA = 0, JULCOMPRA = 0 WHERE CD_FILIAL = :FILIAL;
    END
   ELSE
   IF (:MES = 8) THEN
    BEGIN
      UPDATE PRODUTOS_TOTAIS SET AGOVENDA = 0, AGOCOMPRA = 0 WHERE CD_FILIAL = :FILIAL;
    END
   ELSE
   IF (:MES = 9) THEN
    BEGIN
      UPDATE PRODUTOS_TOTAIS SET SETVENDA = 0, SETCOMPRA = 0 WHERE CD_FILIAL = :FILIAL;
    END
   ELSE
   IF (:MES = 10) THEN
    BEGIN
      UPDATE PRODUTOS_TOTAIS SET OUTVENDA = 0, OUTCOMPRA = 0 WHERE CD_FILIAL = :FILIAL;
    END
   ELSE
   IF (:MES = 11) THEN
    BEGIN
      UPDATE PRODUTOS_TOTAIS SET NOVVENDA = 0, NOVCOMPRA = 0 WHERE CD_FILIAL = :FILIAL;
    END
   ELSE
   IF (:MES = 12) THEN
    BEGIN
      UPDATE PRODUTOS_TOTAIS SET DEZVENDA = 0, DEZCOMPRA = 0 WHERE CD_FILIAL = :FILIAL;
    END
  /*ZERANDO DADOS DOS PRODUTOS NO MES*/


  IF (:FILIAL > 0) THEN
   BEGIN
      FOR
        SELECT
         ID_PRODUTO,
         SUM(QUANTIDADE)
        FROM
         LANCAMENTOS
        WHERE
         DATA_LANCAMENTO >= :DATA1 AND
         DATA_LANCAMENTO <= :DATA2 AND
         CD_FILIAL = :FILIAL AND
         TIPO_VENDA = 'V' -- Vendas
        GROUP BY
         ID_PRODUTO
        INTO
         :PRODUTO,
         :VALOR
      DO
       BEGIN
         IF ((:MES = 1) AND (:VALOR > 0)) THEN
          BEGIN
            UPDATE PRODUTOS_TOTAIS SET JANVENDA = :VALOR WHERE CD_FILIAL = :FILIAL AND ID_PRODUTO = :PRODUTO;
          END
         ELSE
         IF ((:MES = 2) AND (:VALOR > 0)) THEN
          BEGIN
            UPDATE PRODUTOS_TOTAIS SET FEVVENDA = :VALOR WHERE CD_FILIAL = :FILIAL AND ID_PRODUTO = :PRODUTO;
          END
         ELSE
         IF ((:MES = 3) AND (:VALOR > 0)) THEN
          BEGIN
            UPDATE PRODUTOS_TOTAIS SET MARVENDA = :VALOR WHERE CD_FILIAL = :FILIAL AND ID_PRODUTO = :PRODUTO;
          END
         ELSE
         IF ((:MES = 4) AND (:VALOR > 0)) THEN
          BEGIN
            UPDATE PRODUTOS_TOTAIS SET ABRVENDA = :VALOR WHERE CD_FILIAL = :FILIAL AND ID_PRODUTO = :PRODUTO;
          END
         ELSE
         IF ((:MES = 5) AND (:VALOR > 0)) THEN
          BEGIN
            UPDATE PRODUTOS_TOTAIS SET MAIVENDA = :VALOR WHERE CD_FILIAL = :FILIAL AND ID_PRODUTO = :PRODUTO;
          END
         ELSE
         IF ((:MES = 6) AND (:VALOR > 0)) THEN
          BEGIN
            UPDATE PRODUTOS_TOTAIS SET JUNVENDA = :VALOR WHERE CD_FILIAL = :FILIAL AND ID_PRODUTO = :PRODUTO;
          END
         ELSE
         IF ((:MES = 7) AND (:VALOR > 0)) THEN
          BEGIN
            UPDATE PRODUTOS_TOTAIS SET JULVENDA = :VALOR WHERE CD_FILIAL = :FILIAL AND ID_PRODUTO = :PRODUTO;
          END
         ELSE
         IF ((:MES = 8) AND (:VALOR > 0)) THEN
          BEGIN
            UPDATE PRODUTOS_TOTAIS SET AGOVENDA = :VALOR WHERE CD_FILIAL = :FILIAL AND ID_PRODUTO = :PRODUTO;
          END
         ELSE
         IF ((:MES = 9) AND (:VALOR > 0)) THEN
          BEGIN
            UPDATE PRODUTOS_TOTAIS SET SETVENDA = :VALOR WHERE CD_FILIAL = :FILIAL AND ID_PRODUTO = :PRODUTO;
          END
         ELSE
         IF ((:MES = 10) AND (:VALOR > 0)) THEN
          BEGIN
            UPDATE PRODUTOS_TOTAIS SET OUTVENDA = :VALOR WHERE CD_FILIAL = :FILIAL AND ID_PRODUTO = :PRODUTO;
          END
         ELSE
         IF ((:MES = 11) AND (:VALOR > 0)) THEN
          BEGIN
            UPDATE PRODUTOS_TOTAIS SET NOVVENDA = :VALOR WHERE CD_FILIAL = :FILIAL AND ID_PRODUTO = :PRODUTO;
          END
         ELSE
         IF ((:MES = 12) AND (:VALOR > 0)) THEN
          BEGIN
            UPDATE PRODUTOS_TOTAIS SET DEZVENDA = :VALOR WHERE CD_FILIAL = :FILIAL AND ID_PRODUTO = :PRODUTO;
          END
         VALOR = 0;
       END
       
      FOR
