        INTO
         :PRODUTO,
         :VALOR
      DO
       BEGIN
         IF ((:MES = 1) AND (:VALOR > 0)) THEN
          BEGIN
            UPDATE PRODUTOS_TOTAIS SET JANVENDA = JANVENDA - :VALOR WHERE CD_FILIAL = :FILIAL AND ID_PRODUTO = :PRODUTO;
          END
         ELSE
