         CD_FILIAL = :FILIAL AND
         TIPO_VENDA = 'C' -- Compras
        GROUP BY
         ID_PRODUTO
        INTO
         :PRODUTO,
         :VALOR
      DO
       BEGIN
         IF ((:MES = 1) AND (:VALOR > 0)) THEN
          BEGIN
            UPDATE PRODUTOS_TOTAIS SET JANCOMPRA = :VALOR WHERE CD_FILIAL = :FILIAL AND ID_PRODUTO = :PRODUTO;
          END
         ELSE
         IF ((:MES = 2) AND (:VALOR > 0)) THEN
          BEGIN
            UPDATE PRODUTOS_TOTAIS SET FEVCOMPRA = :VALOR WHERE CD_FILIAL = :FILIAL AND ID_PRODUTO = :PRODUTO;
