         IF ((:MES = 3) AND (:VALOR > 0)) THEN
          BEGIN
            UPDATE PRODUTOS_TOTAIS SET MARCOMPRA = :VALOR WHERE CD_FILIAL = :FILIAL AND ID_PRODUTO = :PRODUTO;
