           BEGIN
             IF ((:MES = 1) AND (:VALOR > 0))THEN
              BEGIN
                UPDATE PRODUTOS_TOTAIS SET JANVENDA = :VALOR  WHERE  CD_FILIAL = :CD_FILIAL AND ID_PRODUTO = :PRODUTO;
              END
