             IF ((:MES = 2) AND (:VALOR > 0)) THEN
              BEGIN
                UPDATE PRODUTOS_TOTAIS SET FEVVENDA = :VALOR WHERE  CD_FILIAL = :CD_FILIAL AND ID_PRODUTO = :PRODUTO;
              END
             ELSE
             IF ((:MES = 3) AND (:VALOR > 0)) THEN
