                UPDATE PRODUTOS_TOTAIS SET MARVENDA = :VALOR WHERE  CD_FILIAL = :CD_FILIAL AND ID_PRODUTO = :PRODUTO;
              END
             ELSE
             IF ((:MES = 4) AND (:VALOR > 0)) THEN
              BEGIN
                UPDATE PRODUTOS_TOTAIS SET ABRVENDA = :VALOR WHERE  CD_FILIAL = :CD_FILIAL AND ID_PRODUTO = :PRODUTO;
              END
             ELSE
             IF ((:MES = 5) AND (:VALOR > 0)) THEN
              BEGIN
                UPDATE PRODUTOS_TOTAIS SET MAIVENDA = :VALOR WHERE  CD_FILIAL = :CD_FILIAL AND ID_PRODUTO = :PRODUTO;
              END
             ELSE
             IF ((:MES = 6) AND (:VALOR > 0)) THEN
              BEGIN
                UPDATE PRODUTOS_TOTAIS SET JUNVENDA = :VALOR WHERE  CD_FILIAL = :CD_FILIAL AND ID_PRODUTO = :PRODUTO;
              END
             ELSE
             IF ((:MES = 7) AND (:VALOR > 0)) THEN
              BEGIN
                UPDATE PRODUTOS_TOTAIS SET JULVENDA = :VALOR WHERE  CD_FILIAL = :CD_FILIAL AND ID_PRODUTO = :PRODUTO;
              END
             ELSE
             IF ((:MES = 8) AND (:VALOR > 0)) THEN
