             IF ((:MES = 12) AND (:VALOR > 0)) THEN
              BEGIN
                UPDATE PRODUTOS_TOTAIS SET DEZCOMPRA = :VALOR WHERE  CD_FILIAL = :CD_FILIAL AND ID_PRODUTO = :PRODUTO;
              END
             VALOR = 0;
           END

          FOR
            SELECT
             DISTINCT ID_PRODUTO,
             SUM(QUANTIDADE),
             EXTRACT(MONTH FROM DATA_LANCAMENTO)
            FROM
             LANCAMENTOS
            WHERE
             DATA_LANCAMENTO >= :DATA1 AND DATA_LANCAMENTO <= :DATA2 AND
             CD_FILIAL = :CD_FILIAL AND
             TIPO_VENDA = 'E'
            GROUP BY
             ID_PRODUTO,
             EXTRACT(MONTH FROM DATA_LANCAMENTO)
            INTO
             :PRODUTO,
             :VALOR,
             :MES
          DO
           BEGIN
             IF ((:MES = 1) AND (:VALOR > 0)) THEN
              BEGIN
                UPDATE PRODUTOS_TOTAIS SET JANCOMPRA = JANCOMPRA - :VALOR WHERE  CD_FILIAL = :CD_FILIAL AND ID_PRODUTO = :PRODUTO;
              END
             ELSE
             IF ((:MES = 2) AND (:VALOR > 0)) THEN
              BEGIN
                UPDATE PRODUTOS_TOTAIS SET FEVCOMPRA = FEVCOMPRA - :VALOR WHERE  CD_FILIAL = :CD_FILIAL AND ID_PRODUTO = :PRODUTO;
              END
             ELSE
             IF ((:MES = 3) AND (:VALOR > 0)) THEN
              BEGIN
                UPDATE PRODUTOS_TOTAIS SET MARCOMPRA = MARCOMPRA - :VALOR WHERE  CD_FILIAL = :CD_FILIAL AND ID_PRODUTO = :PRODUTO;
              END
             ELSE
             IF ((:MES = 4) AND (:VALOR > 0)) THEN
              BEGIN
                UPDATE PRODUTOS_TOTAIS SET ABRCOMPRA = ABRCOMPRA - :VALOR WHERE  CD_FILIAL = :CD_FILIAL AND ID_PRODUTO = :PRODUTO;
              END
             ELSE
             IF ((:MES = 5) AND (:VALOR > 0)) THEN
              BEGIN
                UPDATE PRODUTOS_TOTAIS SET MAICOMPRA = MAICOMPRA - :VALOR WHERE  CD_FILIAL = :CD_FILIAL AND ID_PRODUTO = :PRODUTO;
              END
             ELSE
             IF ((:MES = 6) AND (:VALOR > 0)) THEN
              BEGIN
                UPDATE PRODUTOS_TOTAIS SET JUNCOMPRA = JUNCOMPRA - :VALOR WHERE  CD_FILIAL = :CD_FILIAL AND ID_PRODUTO = :PRODUTO;
              END
             ELSE
             IF ((:MES = 7) AND (:VALOR > 0)) THEN
              BEGIN
                UPDATE PRODUTOS_TOTAIS SET JULCOMPRA = JULCOMPRA - :VALOR WHERE  CD_FILIAL = :CD_FILIAL AND ID_PRODUTO = :PRODUTO;
              END
             ELSE
             IF ((:MES = 8) AND (:VALOR > 0)) THEN
              BEGIN
                UPDATE PRODUTOS_TOTAIS SET AGOCOMPRA = AGOCOMPRA - :VALOR WHERE  CD_FILIAL = :CD_FILIAL AND ID_PRODUTO = :PRODUTO;
              END
             ELSE
             IF ((:MES = 9) AND (:VALOR > 0)) THEN
              BEGIN
                UPDATE PRODUTOS_TOTAIS SET SETCOMPRA = SETCOMPRA - :VALOR WHERE  CD_FILIAL = :CD_FILIAL AND ID_PRODUTO = :PRODUTO;
              END
             ELSE
             IF ((:MES = 10 ) AND (:VALOR > 0)) THEN
              BEGIN
                UPDATE PRODUTOS_TOTAIS SET OUTCOMPRA = OUTCOMPRA - :VALOR WHERE  CD_FILIAL = :CD_FILIAL AND ID_PRODUTO = :PRODUTO;
              END
             ELSE
             IF ((:MES = 11) AND (:VALOR > 0)) THEN
              BEGIN
                UPDATE PRODUTOS_TOTAIS SET NOVCOMPRA = NOVCOMPRA - :VALOR WHERE  CD_FILIAL = :CD_FILIAL AND ID_PRODUTO = :PRODUTO;
              END
             ELSE
             IF ((:MES = 12) AND (:VALOR > 0)) THEN
              BEGIN
                UPDATE PRODUTOS_TOTAIS SET DEZCOMPRA = DEZCOMPRA - :VALOR WHERE  CD_FILIAL = :CD_FILIAL AND ID_PRODUTO = :PRODUTO;
              END
             VALOR = 0;
           END

       END

      EXECUTE PROCEDURE SP_PREENCHE_VENDA_PRODUTO(:ANO, :MES, 0);

      MES = :MES - 1;
      IF (:MES = 0) THEN
       BEGIN
         MES = 12;
         ANO = :ANO - 1;
       END

      /*MONTAGEM DAS VARIAVEIS DATA1 E DATA2*/
      IF ((:MES = 1) OR (:MES = 3) OR (:MES = 5) OR (:MES = 7) OR (:MES = 8) OR (:MES = 10) OR (:MES = 12)) THEN
         ULTIMODIAMES = 31;
      ELSE
      IF ((:MES = 4) OR (:MES = 6) OR (:MES = 9) OR (:MES = 11)) THEN
         ULTIMODIAMES = 30;
      ELSE
         ULTIMODIAMES = 28;
      DATA1 = :MES||'/01/'||:ANO;
      DATA2 = :MES||'/'||:ULTIMODIAMES||'/'||:ANO;
      /*MONTAGEM DAS VARIAVEIS DATA1 E DATA2*/

      I = :I + 1;
   END
END ^

ALTER PROCEDURE SP_PREPARA_DADOS_EXPORTACAO (DATAINICIAL DATE,
DATAFINAL DATE)
AS 
declare variable FILIAL double precision;
declare variable COMANDO varchar(255);
BEGIN
  EXECUTE PROCEDURE SP_INICIA_BANCO_DADOS_0;

  /* LANCAMENTOS */
  UPDATE LANCAMENTOS SET
   ENVIADO = ''
  WHERE DATA_CAIXA >= :DATAINICIAL AND DATA_CAIXA <= :DATAFINAL;
  /* LANCAMENTOS_APRAZO */
  UPDATE LANCAMENTOS_APRAZO SET
   ENVIADO = ''
  WHERE DATA_CAIXA >= :DATAINICIAL AND DATA_CAIXA <= :DATAFINAL;
  /* CAIXA */
  UPDATE CAIXA SET
   ENVIADO = ''
  WHERE DATA_CAIXA >= :DATAINICIAL AND DATA_CAIXA <= :DATAFINAL;
  /* TRANSFERENCIAS */
  UPDATE TRANSFER SET
   ENVIADO = ''
  WHERE DATA_GERACAO >= :DATAINICIAL AND DATA_GERACAO <= :DATAFINAL;
  /* COMPRAS */
  UPDATE COMPRAS SET
   ENVIADO = ''
  WHERE DT_PEDIDO >= :DATAINICIAL AND DT_PEDIDO <= :DATAFINAL;
  /* OPERADORES */
  UPDATE OPERADORES SET
   ENVIADO = ''
  WHERE DATA_ABERTURA >= :DATAINICIAL AND DATA_ABERTURA <= :DATAFINAL;
  /* ENTREGAS */
  UPDATE ENTREGAS SET
   ENVIADO = ''
  WHERE DATA >= :DATAINICIAL AND DATA <= :DATAFINAL;
  /* CONTAS A RECEBER */
  UPDATE CONTAS_RECEBER SET
   ENVIADO = ''
  WHERE DT_LANCAMENTO >= :DATAINICIAL AND DT_LANCAMENTO <= :DATAFINAL;
  /* CONTAS A PAGAR */
  UPDATE CONTAS_PAGAR SET
   ENVIADO = ''
  WHERE DT_LANCAMENTO >= :DATAINICIAL AND DT_LANCAMENTO <= :DATAFINAL;


  /* CRM */
  UPDATE CRM SET
   ENVIADO = ''
  WHERE DATA >= :DATAINICIAL AND DATA <= :DATAFINAL;
  /* CHEQUESRECEBIDOS */
  UPDATE CHEQUESRECEBIDOS SET
   ENVIADO = ''
  WHERE CD_VENDA IN (SELECT CD_VENDA FROM VENDAS WHERE DATA_CAIXA >= :DATAINICIAL AND DATA_CAIXA <= :DATAFINAL);
  /* USUARIOS */
  UPDATE USUARIOS SET
   ENVIADO = '';
  /* SINTEGRA_NF_ENTRADA */
  UPDATE SINTEGRA_NF_ENTRADA SET
   ENVIADO = ''
  WHERE
   DATAHORA_RECEBIMENTO >= :DATAINICIAL AND DATAHORA_RECEBIMENTO <= :DATAFINAL;
  /* SINTEGRA_NF_ENTRADAITENS */
  UPDATE SINTEGRA_NF_ENTRADA_ITENS SET
   ENVIADO = ''
  WHERE
   DATAHORA >= :DATAINICIAL AND DATAHORA <= :DATAFINAL;
  /* SINTEGRA_PEDIDOS_ITENS */
  UPDATE SINTEGRA_PEDIDOS_ITENS SET
   ENVIADO = ''
  WHERE
   DATAHORA >= :DATAINICIAL AND DATAHORA <= :DATAFINAL;
  /* SINTEGRA_R60 */
  UPDATE SINTEGRA_R60 SET
   ENVIADO = ''
  WHERE
   DATA_EMISSAO >= :DATAINICIAL AND DATA_EMISSAO <= :DATAFINAL;
  /* SINTEGRA_R60I */
  UPDATE SINTEGRA_R60I SET
   ENVIADO = ''
  WHERE
   DATAHORA >= :DATAINICIAL AND DATAHORA <= :DATAFINAL;
  /* CLIENTES */
  UPDATE CLIENTES SET
   ENVIADO = ''
  WHERE
   (DATA_FICHA >= :DATAINICIAL AND DATA_FICHA <= :DATAFINAL) OR
   (DT_ALTERACAO >= :DATAINICIAL AND DT_ALTERACAO <= :DATAFINAL);

  /* PRODUTOSTOTAIS */
  UPDATE PRODUTOS_TOTAIS SET
   ENVIADO = '';

  SELECT CD_FILIAL FROM PARAMETROS INTO :FILIAL;
  COMANDO = 'UPDATE PRODUTOS SET ENVIADO = '||''''||' '||''''||
            ' WHERE DT_ULT_VENDA_'||CAST(FILIAL AS INTEGER)||' >= '||''''||DATAINICIAL||
            ''' AND DT_ULT_COMPRA_'||CAST(FILIAL AS INTEGER)||' >= '||''''||DATAINICIAL||'''';
  EXECUTE STATEMENT :COMANDO;
END ^

ALTER PROCEDURE SP_PREVENDAS (CALLCENTER VARCHAR(1) CHARACTER SET NONE,
DATA DATE)
RETURNS (CD_VENDA DOUBLE PRECISION,
DATA_CAIXA DATE,
HORA TIME,
ID_VENDA VARCHAR(13) CHARACTER SET NONE,
TIPO_VENDA VARCHAR(1) CHARACTER SET NONE,
TROCA VARCHAR(1) CHARACTER SET NONE,
ENTREGA VARCHAR(1) CHARACTER SET NONE,
NITENS INTEGER,
TOTAL DOUBLE PRECISION,
CLIENTE VARCHAR(60) CHARACTER SET NONE,
ENDERECO VARCHAR(60) CHARACTER SET NONE,
TELEFONE VARCHAR(60) CHARACTER SET NONE,
STATUS VARCHAR(1) CHARACTER SET NONE,
VENDEDOR VARCHAR(100) CHARACTER SET NONE,
VENDEDORBALCAO VARCHAR(100) CHARACTER SET NONE,
AUTORIZACAOTRN VARCHAR(100) CHARACTER SET NONE,
ARREDONDAMENTO DOUBLE PRECISION)
AS 
declare variable CD_CLIENTE double precision;
declare variable CD_ENTREGADOR double precision;
declare variable CD_VENDEDORBALCAO double precision;
declare variable CD_FILIAL double precision;
BEGIN
  SELECT CD_FILIAL FROM PARAMETROS INTO :CD_FILIAL;
  FOR
    SELECT
     VENDAS.CD_VENDA,
     VENDAS.DATA_CAIXA,
     VENDAS.ID_VENDA,
     VENDAS.TIPO_VENDA,
     VENDAS.TROCA,
     VENDAS.ENTREGA,
     VENDAS.CD_CLIENTE,
     VENDAS.STATUS, 
     COUNT(VENDAS.ORDEM) AS NITENS
    FROM 
     VENDAS
    WHERE
     VENDAS.DATA_CAIXA >= :DATA AND
     (VENDAS.TIPO_VENDA = 'V' OR VENDAS.TIPO_VENDA = 'P' OR VENDAS.TIPO_VENDA = 'R' OR VENDAS.TIPO_VENDA = 'M') AND
     VENDAS.CONCLUIDO = 'N' AND
     VENDAS.STATUS <> 'C' AND
     VENDAS.CALLCENTER = :CALLCENTER AND
     VENDAS.CD_VENDA IS NOT NULL AND
     VENDAS.CD_FILIAL = :CD_FILIAL
    GROUP BY
     VENDAS.CD_VENDA,
     VENDAS.DATA_CAIXA,
     VENDAS.ID_VENDA,
     VENDAS.TIPO_VENDA,
     VENDAS.TROCA,
     VENDAS.ENTREGA,
     VENDAS.CD_CLIENTE,
     VENDAS.STATUS
    ORDER BY
     VENDAS.CD_VENDA
    INTO
     :CD_VENDA,
     :DATA_CAIXA,
     :ID_VENDA,
     :TIPO_VENDA,
     :TROCA,
     :ENTREGA,
     :CD_CLIENTE,
     :STATUS,
     :NITENS
  DO
   BEGIN
    SELECT
     SUM(VENDAS.PRECO_TOTAL - VENDAS.ARREDONDAMENTO)
    FROM
     VENDAS
    WHERE
     VENDAS.CD_VENDA = :CD_VENDA AND
     VENDAS.TIPO_VENDA <> 'Y' AND
     VENDAS.CD_FILIAL = :CD_FILIAL
    INTO
     :TOTAL;

    SELECT
     FIRST 1 VENDAS.HORA
    FROM
     VENDAS
    WHERE
     VENDAS.CD_VENDA = :CD_VENDA AND
     VENDAS.CD_FILIAL = :CD_FILIAL
    INTO
     :HORA;

    ENDERECO = '';
    SELECT
     FIRST 1 VENDAS.TEMPENDERECO
    FROM
     VENDAS
    WHERE
     VENDAS.CD_VENDA = :CD_VENDA AND
     VENDAS.CD_FILIAL = :CD_FILIAL
    INTO
     :ENDERECO;

    SELECT
     FIRST 1 VENDAS.CD_VENDEDOR
    FROM
     VENDAS
    WHERE
     VENDAS.CD_VENDA = :CD_VENDA AND
     VENDAS.CD_FILIAL = :CD_FILIAL
    INTO :CD_VENDEDORBALCAO;

    SELECT
     FIRST 1 VENDAS.AUTORIZACAOTRN
    FROM
     VENDAS
    WHERE
     VENDAS.CD_VENDA = :CD_VENDA AND
     VENDAS.CD_FILIAL = :CD_FILIAL
    INTO :AUTORIZACAOTRN;

    SELECT VENDEDORES.NOME FROM VENDEDORES WHERE VENDEDORES.CD_VENDEDOR = :CD_VENDEDORBALCAO INTO :VENDEDORBALCAO;

    CLIENTE = ''; TELEFONE = '';
    IF ((:CD_CLIENTE IS NOT NULL) AND (:CD_CLIENTE > 0)) THEN
     BEGIN
       SELECT CLIENTES.NOME, FONE FROM CLIENTES
       WHERE CLIENTES.CD_CLIENTE = :CD_CLIENTE --AND CLIENTES.CD_FILIAL = :CD_FILIAL
       INTO :CLIENTE, :TELEFONE;

       SELECT ENTREGAS.CD_ENTREGADOR, VENDEDORES.NOME FROM ENTREGAS, VENDEDORES
       WHERE ENTREGAS.CD_ENTREGADOR = VENDEDORES.CD_VENDEDOR AND ENTREGAS.CD_VENDA = :CD_VENDA
       GROUP BY ENTREGAS.CD_ENTREGADOR, VENDEDORES.NOME
       INTO :CD_ENTREGADOR, :VENDEDOR;
     END

    /* IF (:TOTAL > 0) THEN */
       SUSPEND;
   END
END ^

ALTER PROCEDURE SP_PREVENDASPDV (DATA DATE)
RETURNS (CD_VENDA DOUBLE PRECISION,
ID_VENDA VARCHAR(13) CHARACTER SET NONE,
CD_FILIAL DOUBLE PRECISION,
TIPO_VENDA VARCHAR(1) CHARACTER SET NONE,
TROCA VARCHAR(1) CHARACTER SET NONE,
ENTREGA VARCHAR(1) CHARACTER SET NONE,
CALLCENTER VARCHAR(1) CHARACTER SET NONE,
NITENS INTEGER,
TOTAL DOUBLE PRECISION,
ARREDONDAMENTO DOUBLE PRECISION,
HORA TIME,
DATA_CAIXA DATE,
VENDEDORBALCAO VARCHAR(100) CHARACTER SET NONE,
TRN VARCHAR(1) CHARACTER SET NONE,
DATAENTREGA DATE,
CLIENTE VARCHAR(100) CHARACTER SET NONE,
ENDERECO VARCHAR(100) CHARACTER SET NONE,
IFOOD VARCHAR(1) CHARACTER SET NONE,
FARMACIASAPP VARCHAR(1) CHARACTER SET NONE,
PAGOONLINE VARCHAR(1) CHARACTER SET NONE)
AS 
declare variable CD_VENDEDORBALCAO double precision;
declare variable SUBSIDIOTRN double precision;
declare variable FILIAL double precision;
declare variable CD_CLIENTE double precision;
BEGIN
  SELECT CD_FILIAL FROM PARAMETROS INTO :FILIAL;
  FOR
    SELECT
     VENDAS.CD_VENDA,
     VENDAS.ID_VENDA,
     VENDAS.CD_FILIAL,
     VENDAS.TIPO_VENDA,
     VENDAS.TROCA,
     VENDAS.ENTREGA,
     VENDAS.CALLCENTER,
     VENDAS.DATA_CAIXA,
     VENDAS.CD_CLIENTE,
     VENDAS.IFOOD,
     VENDAS.FARMACIASAPP,
     VENDAS.PAGOONLINE,
     COUNT(*) AS NITENS
    FROM 
     VENDAS
    WHERE
     VENDAS.DATA_CAIXA >= :DATA AND
     VENDAS.CD_VENDA > 0 AND
     (VENDAS.TIPO_VENDA = 'V' OR VENDAS.TIPO_VENDA = 'P' OR VENDAS.TIPO_VENDA = 'R' OR VENDAS.TIPO_VENDA = 'M') AND
     VENDAS.CONCLUIDO = 'N' AND
     VENDAS.STATUS <> 'C' AND
     --CALLCENTER = :TERMINALCALLCENTER AND *** Retirado a pedido de MML em 05.08.2021
     VENDAS.CD_FILIAL = :FILIAL
    GROUP BY
     VENDAS.CD_VENDA,
     VENDAS.ID_VENDA,
     VENDAS.CD_FILIAL,
     VENDAS.TIPO_VENDA,
     VENDAS.TROCA,
     VENDAS.ENTREGA,
     VENDAS.CALLCENTER,
     VENDAS.DATA_CAIXA,
     VENDAS.CD_CLIENTE,
     VENDAS.IFOOD,
     VENDAS.FARMACIASAPP,
     VENDAS.PAGOONLINE
    ORDER BY
     VENDAS.CD_VENDA
    INTO
     :CD_VENDA,
     :ID_VENDA,
     :CD_FILIAL,
     :TIPO_VENDA,
     :TROCA,
     :ENTREGA,
     :CALLCENTER,
     :DATA_CAIXA,
     --:TRN,
     :CD_CLIENTE,
     :IFOOD,
     :FARMACIASAPP,
     :PAGOONLINE,
     :NITENS
  DO
   BEGIN
    CLIENTE = '';

    SELECT FIRST 1 VENDAS.HORA FROM VENDAS WHERE CD_VENDA = :CD_VENDA INTO :HORA;

    ENDERECO = '';
    SELECT
     FIRST 1 VENDAS.TEMPENDERECO
    FROM
     VENDAS
    WHERE
     VENDAS.CD_VENDA = :CD_VENDA AND
     VENDAS.CD_FILIAL = :CD_FILIAL
    INTO
     :ENDERECO;

    SELECT
     SUM(VENDAS.ARREDONDAMENTO),
     SUM(VENDAS.PRECO_TOTAL),
     VENDAS.CD_VENDA
    FROM
     VENDAS
    WHERE
     VENDAS.CD_VENDA = :CD_VENDA AND
     VENDAS.TIPO_VENDA <> 'Y' AND
     VENDAS.CD_FILIAL = :FILIAL
    GROUP BY
      VENDAS.CD_VENDA
    INTO
     :ARREDONDAMENTO,
     :TOTAL,
     :CD_VENDA;

    SELECT
     SUM(VENDAS.SUBSIDIOTRN)
    FROM
     VENDAS
    WHERE
     VENDAS.CD_VENDA = :CD_VENDA AND
     VENDAS.CD_FILIAL = :FILIAL
    GROUP BY
     VENDAS.CD_VENDA
    INTO
     :SUBSIDIOTRN;

   IF (:SUBSIDIOTRN IS NULL) THEN
      SUBSIDIOTRN = 0;
   TOTAL = :TOTAL - :SUBSIDIOTRN;
   IF (:TOTAL = 0) THEN
      TOTAL = 0.01;

   SELECT
     FIRST 1 VENDAS.CD_VENDEDOR
    FROM
     VENDAS
    WHERE
     VENDAS.CD_VENDA = :CD_VENDA AND
     VENDAS.CD_FILIAL = :FILIAL
    INTO :CD_VENDEDORBALCAO;

    SELECT VENDEDORES.NOME FROM VENDEDORES WHERE CD_VENDEDOR = :CD_VENDEDORBALCAO INTO :VENDEDORBALCAO;


    IF (:ARREDONDAMENTO IS NULL) THEN
       ARREDONDAMENTO = 0;

    TOTAL = :TOTAL - :ARREDONDAMENTO;

    SELECT ENTREGAS.DATA FROM ENTREGAS WHERE ENTREGAS.CD_VENDA = :CD_VENDA AND ENTREGAS.DATA >= :DATA_CAIXA INTO :DATAENTREGA;
    SELECT CLIENTES.NOME FROM CLIENTES WHERE CLIENTES.CD_CLIENTE = :CD_CLIENTE --AND CLIENTES.CD_FILIAL = :CD_FILIAL
    INTO :CLIENTE;

    FOR
     SELECT DISTINCT VENDAS.TRN
     FROM VENDAS
     WHERE VENDAS.CD_VENDA = :CD_VENDA
     INTO :TRN
    DO
     BEGIN
       IF (:TRN <> 'N') THEN
          BREAK;
     END

    SUSPEND;
   END
END ^

ALTER PROCEDURE SP_PREVENDASPDVF10 (TERMINAL DOUBLE PRECISION)
RETURNS (CD_VENDA DOUBLE PRECISION,
DATA_CAIXA DATE,
TIPO_VENDA VARCHAR(1) CHARACTER SET NONE,
ENTREGA VARCHAR(1) CHARACTER SET NONE,
NITENS INTEGER,
TOTAL DOUBLE PRECISION,
ARREDONDAMENTO DOUBLE PRECISION)
AS 
BEGIN
  FOR
    SELECT
     FIRST 200
     CD_VENDA,
     DATA_CAIXA,
     TERMINAL,
     TIPO_VENDA,
     ENTREGA,
     COUNT(*) AS NITENS,
     SUM(PRECO_TOTAL) AS TOTAL
    FROM
     VENDAS
    WHERE
     /*TERMINAL = :TERMINAL AND*/
     DATA_CAIXA =  CURRENT_DATE  AND
     CONCLUIDO = 'S' AND
     (((TIPO_VENDA = 'V') AND (NUMERO IS NULL OR NUMERO = 0)) /*OR
      (TIPO_VENDA = 'P')*/) AND
     STATUS <> 'C'  AND
     CD_VENDA IS NOT NULL
    GROUP BY
     CD_VENDA,
     DATA_CAIXA,
     TERMINAL,
     TIPO_VENDA,
     ENTREGA
    ORDER BY
     CD_VENDA DESC
    INTO
     :CD_VENDA,
     :DATA_CAIXA,
     :TERMINAL,
     :TIPO_VENDA,
     :ENTREGA,
     :NITENS,
     :TOTAL
  DO
   BEGIN
    SELECT
     SUM(ARREDONDAMENTO),
     SUM(PRECO_TOTAL),
     CD_VENDA
    FROM
     VENDAS
    WHERE
     CD_VENDA = :CD_VENDA
    GROUP BY
      CD_VENDA
    INTO
     :ARREDONDAMENTO,
     :TOTAL,
     :CD_VENDA;

    IF (:ARREDONDAMENTO IS NULL) THEN
       ARREDONDAMENTO = 0;

    TOTAL = :TOTAL - :ARREDONDAMENTO;

    SUSPEND;
   END
END ^

ALTER PROCEDURE SP_PRIMEIRO_DOCUMENTO_ECF (DATA_DOCUMENTO DATE)
RETURNS (PRIMEIRO VARCHAR(1) CHARACTER SET NONE)
AS 
declare variable EXISTE integer;
declare variable DIA varchar(10);
declare variable MES varchar(10);
declare variable ANO varchar(10);
declare variable DATA varchar(10);
BEGIN
  PRIMEIRO = 'N';
  EXISTE = 0;
  SELECT RESULT FROM STR_ZERO(EXTRACT(DAY FROM :DATA_DOCUMENTO), 2) INTO :DIA;
  SELECT RESULT FROM STR_ZERO(EXTRACT(MONTH FROM :DATA_DOCUMENTO), 2) INTO :MES;
  ANO = SUBSTRING(EXTRACT(YEAR FROM :DATA_DOCUMENTO) FROM 3 FOR 2);
  DATA = :DIA||:MES||:ANO;
  SELECT COUNT(*) FROM PAF_R02
  WHERE
        DATA_EMISSAO IS NOT NULL AND
        DATA_EMISSAO <> '' AND
        DATA_EMISSAO = :DATA
  INTO :EXISTE;

  IF (:EXISTE = 0) THEN
   BEGIN
      SELECT COUNT(*) FROM PAF_R04
      WHERE
            DATA_INICIO_EMISSAO IS NOT NULL AND
            DATA_INICIO_EMISSAO <> '' AND
            DATA_INICIO_EMISSAO = :DATA
      INTO :EXISTE;

      IF (:EXISTE = 0) THEN
       BEGIN
          SELECT COUNT(*) FROM PAF_R06
          WHERE
                DATA_FINAL_EMISSAO IS NOT NULL AND
                DATA_FINAL_EMISSAO <> '' AND
                DATA_FINAL_EMISSAO = :DATA
          INTO :EXISTE;
       END
   END

  IF (:EXISTE = 0) THEN
     PRIMEIRO = 'S';
  SUSPEND;
END ^

ALTER PROCEDURE SP_PRODUTOSEMBARRA (CODLAB VARCHAR(10) CHARACTER SET NONE)
RETURNS (CD_PRODUTO VARCHAR(6) CHARACTER SET NONE,
DESCRICAO VARCHAR(100) CHARACTER SET NONE,
CODIGO_BARRAS_1 VARCHAR(14) CHARACTER SET NONE,
CODIGO_BARRAS_2 VARCHAR(14) CHARACTER SET NONE,
GRUPO VARCHAR(100) CHARACTER SET NONE,
FABRICANTE VARCHAR(100) CHARACTER SET NONE)
AS 
declare variable TAMCOD1 integer;
declare variable TAMCOD2 integer;
BEGIN
 IF ((:CODLAB = '') OR (:CODLAB IS NULL)) THEN
  BEGIN
     FOR
        SELECT 
         PRODUTOS.CD_PRODUTO,
         PRODUTOS.DESCRICAO,
         PRODUTOS.CODIGO_BARRAS_1,
         PRODUTOS.CODIGO_BARRAS_2,
         GRUPOS.DESCRICAO,
         LABORATORIOS.NOME
        FROM
         PRODUTOS,
         GRUPOS,
         LABORATORIOS
        WHERE
         PRODUTOS.CD_GRUPO = GRUPOS.CD_GRUPO AND
         PRODUTOS.CD_LABORATORIO = LABORATORIOS.CD_LABORATORIO
        INTO
         :CD_PRODUTO,
         :DESCRICAO,
         :CODIGO_BARRAS_1,
         :CODIGO_BARRAS_2,
         :GRUPO,
         :FABRICANTE
     DO
      BEGIN
        IF (((:CODIGO_BARRAS_1 IS NULL) OR (:CODIGO_BARRAS_1 = '')) AND
            ((:CODIGO_BARRAS_2 IS NULL) OR (:CODIGO_BARRAS_2 = ''))) THEN
         BEGIN
           SUSPEND;
         END
        ELSE
         BEGIN
           TAMCOD1 = CHAR_LENGTH(:CODIGO_BARRAS_1);
           TAMCOD2 = CHAR_LENGTH(:CODIGO_BARRAS_2);
           IF ((:TAMCOD1 < 7) AND (:TAMCOD2 < 7)) THEN
              SUSPEND;
         END
      END
  END
 ELSE
  BEGIN
     FOR
        SELECT 
         PRODUTOS.CD_PRODUTO,
         PRODUTOS.DESCRICAO,
         PRODUTOS.CODIGO_BARRAS_1,
         PRODUTOS.CODIGO_BARRAS_2,
         GRUPOS.DESCRICAO,
         LABORATORIOS.NOME
        FROM
         PRODUTOS,
         GRUPOS,
         LABORATORIOS
        WHERE
         PRODUTOS.CD_GRUPO = GRUPOS.CD_GRUPO AND
         PRODUTOS.CD_LABORATORIO = LABORATORIOS.CD_LABORATORIO AND
         PRODUTOS.CD_LABORATORIO = :CODLAB
        INTO
         :CD_PRODUTO,
         :DESCRICAO,
         :CODIGO_BARRAS_1,
         :CODIGO_BARRAS_2,
         :GRUPO,
         :FABRICANTE
     DO
      BEGIN
        IF (((:CODIGO_BARRAS_1 IS NULL) OR (:CODIGO_BARRAS_1 = '')) AND
            ((:CODIGO_BARRAS_2 IS NULL) OR (:CODIGO_BARRAS_2 = ''))) THEN
         BEGIN
           SUSPEND;
         END
        ELSE
         BEGIN
           TAMCOD1 = CHAR_LENGTH(:CODIGO_BARRAS_1);
           TAMCOD2 = CHAR_LENGTH(:CODIGO_BARRAS_2);
           IF ((:TAMCOD1 < 7) AND (:TAMCOD2 < 7)) THEN
              SUSPEND;
         END
      END
  END
END ^

ALTER PROCEDURE SP_PRODUTOSFISCOATSEGMENTO AS 
declare variable CD_CFOP double precision;
declare variable ORIGEM varchar(1);
declare variable SITUACAO_TRIBUTARIA varchar(1);
declare variable CST_ICMS varchar(3);
declare variable CST_PIS_COFINS_ENTRADA varchar(3);
declare variable CST_PIS_COFINS_SAIDA varchar(3);
declare variable ALIQUOTA_ICMS numeric(15,2);
declare variable ALIQUOTA_PIS numeric(15,2);
declare variable ALIQUOTA_COFINS numeric(15,2);
declare variable NATUREZA_RECEITA_PISCOFINS varchar(3);
declare variable NCM varchar(10);
declare variable CEST varchar(10);
declare variable DATA_ATAUALIZACAO date;
declare variable STATUS varchar(1);
declare variable ID_SEGMENTO double precision;
declare variable SEGMENTO varchar(100);
declare variable ICMSSAIDA numeric(15,2);
declare variable ICMSLEISAIDA varchar(1000);
declare variable ICMSLEISAIDALINK varchar(1000);
declare variable IPI numeric(15,2);
declare variable ICMSPERCENTUALREDUCAO numeric(15,2);
declare variable ALIQUOTACHEIA numeric(15,2);
declare variable SUBITEMST numeric(15,2);
declare variable MVAINTERNO numeric(15,2);
declare variable MVAEXTERNO numeric(15,2);
declare variable MVAIMPORTADO numeric(15,2);
declare variable BASEREDUZIDA numeric(15,2);
declare variable ICMSLEIINTERNO varchar(1000);
declare variable ICMSLEIINTERNOLINK varchar(1000);
declare variable SITUACAO_TRIBUTARIA_PIS_COFINS varchar(1);
declare variable PISCOFINSLEI varchar(1000);
declare variable PISCOFINSLEILINK varchar(1000);
declare variable PISCOFINS_NATUREZA_RECEITA varchar(3);
declare variable DT_CADASTRO date;
declare variable EXISTE integer;
BEGIN
    FOR
     SELECT DISTINCT ID_SEGMENTO FROM PRODUTOS_FISCO WHERE ID_SEGMENTO IS NOT NULL AND DATA_ATAUALIZACAO IS NULL INTO :ID_SEGMENTO
    DO
     BEGIN
        EXISTE = 0;

        SELECT COUNT(*) FROM PRODUTOS_FISCO
        WHERE ID_SEGMENTO = :ID_SEGMENTO AND DATA_ATAUALIZACAO IS NOT NULL
        INTO :EXISTE;

        IF (:EXISTE > 0) THEN
         BEGIN
            SELECT
              FIRST 1
              CD_CFOP                         ,
              ORIGEM                          ,
              SITUACAO_TRIBUTARIA             ,
              CST_ICMS                        ,
              CST_PIS_COFINS_ENTRADA          ,
              CST_PIS_COFINS_SAIDA            ,
              ALIQUOTA_ICMS                   ,
              ALIQUOTA_PIS                    ,
              ALIQUOTA_COFINS                 ,
              NATUREZA_RECEITA_PISCOFINS      ,
              NCM                             ,
              CEST                            ,
              DATA_ATAUALIZACAO               ,
              STATUS                          ,
              SEGMENTO                        ,
              ICMSSAIDA                       ,
              ICMSLEISAIDA                    ,
              ICMSLEISAIDALINK                ,
              IPI                             ,
              ICMSPERCENTUALREDUCAO           ,
              ALIQUOTACHEIA                   ,
              SUBITEMST                       ,
              MVAINTERNO                      ,
              MVAEXTERNO                      ,
              MVAIMPORTADO                    ,
              BASEREDUZIDA                    ,
              ICMSLEIINTERNO                  ,
              ICMSLEIINTERNOLINK              ,
              SITUACAO_TRIBUTARIA_PIS_COFINS  ,
              PISCOFINSLEI                    ,
              PISCOFINSLEILINK                ,
              PISCOFINS_NATUREZA_RECEITA
            FROM PRODUTOS_FISCO
            WHERE ID_SEGMENTO = :ID_SEGMENTO AND DATA_ATAUALIZACAO IS NOT NULL
            INTO
              :CD_CFOP                         ,
              :ORIGEM                          ,
              :SITUACAO_TRIBUTARIA             ,
              :CST_ICMS                        ,
              :CST_PIS_COFINS_ENTRADA          ,
              :CST_PIS_COFINS_SAIDA            ,
              :ALIQUOTA_ICMS                   ,
              :ALIQUOTA_PIS                    ,
              :ALIQUOTA_COFINS                 ,
              :NATUREZA_RECEITA_PISCOFINS      ,
              :NCM                             ,
              :CEST                            ,
              :DATA_ATAUALIZACAO               ,
              :STATUS                          ,
              :SEGMENTO                        ,
              :ICMSSAIDA                       ,
              :ICMSLEISAIDA                    ,
              :ICMSLEISAIDALINK                ,
              :IPI                             ,
              :ICMSPERCENTUALREDUCAO           ,
              :ALIQUOTACHEIA                   ,
              :SUBITEMST                       ,
              :MVAINTERNO                      ,
              :MVAEXTERNO                      ,
              :MVAIMPORTADO                    ,
              :BASEREDUZIDA                    ,
              :ICMSLEIINTERNO                  ,
              :ICMSLEIINTERNOLINK              ,
              :SITUACAO_TRIBUTARIA_PIS_COFINS  ,
              :PISCOFINSLEI                    ,
              :PISCOFINSLEILINK                ,
              :PISCOFINS_NATUREZA_RECEITA;
            
            UPDATE PRODUTOS_FISCO SET
              CD_CFOP                           = :CD_CFOP,
              ORIGEM                            = :ORIGEM,
              SITUACAO_TRIBUTARIA               = :SITUACAO_TRIBUTARIA,
              CST_ICMS                          = :CST_ICMS,
              CST_PIS_COFINS_ENTRADA            = :CST_PIS_COFINS_ENTRADA,
              CST_PIS_COFINS_SAIDA              = :CST_PIS_COFINS_SAIDA,
              ALIQUOTA_ICMS                     = :ALIQUOTA_ICMS,
              ALIQUOTA_PIS                      = :ALIQUOTA_PIS,
              ALIQUOTA_COFINS                   = :ALIQUOTA_COFINS,
              NATUREZA_RECEITA_PISCOFINS        = :NATUREZA_RECEITA_PISCOFINS,
              NCM                               = :NCM,
              CEST                              = :CEST,
              DATA_ATAUALIZACAO                 = :DATA_ATAUALIZACAO,
              STATUS                            = :STATUS,
              ID_SEGMENTO                       = :ID_SEGMENTO,
              SEGMENTO                          = :SEGMENTO,
              ICMSSAIDA                         = :ICMSSAIDA,
              ICMSLEISAIDA                      = :ICMSLEISAIDA,
              ICMSLEISAIDALINK                  = :ICMSLEISAIDALINK,
              IPI                               = :IPI,
              ICMSPERCENTUALREDUCAO             = :ICMSPERCENTUALREDUCAO,
              ALIQUOTACHEIA                     = :ALIQUOTACHEIA,
              SUBITEMST                         = :SUBITEMST,
              MVAINTERNO                        = :MVAINTERNO,
              MVAEXTERNO                        = :MVAEXTERNO,
              MVAIMPORTADO                      = :MVAIMPORTADO,
              BASEREDUZIDA                      = :BASEREDUZIDA,
              ICMSLEIINTERNO                    = :ICMSLEIINTERNO,
              ICMSLEIINTERNOLINK                = :ICMSLEIINTERNOLINK,
              SITUACAO_TRIBUTARIA_PIS_COFINS    = :SITUACAO_TRIBUTARIA_PIS_COFINS,
              PISCOFINSLEI                      = :PISCOFINSLEI,
              PISCOFINSLEILINK                  = :PISCOFINSLEILINK,
              PISCOFINS_NATUREZA_RECEITA        = :PISCOFINS_NATUREZA_RECEITA
            WHERE ID_SEGMENTO = :ID_SEGMENTO AND DATA_ATAUALIZACAO IS NULL;
         END
     END
END ^

ALTER PROCEDURE SP_PRODUTOSMAISVENDIDOSFILIAIS (ID_PRODUTO DOUBLE PRECISION,
DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (CD_FILIAL DOUBLE PRECISION,
FILIAL VARCHAR(100) CHARACTER SET NONE,
QUANTIDADE DOUBLE PRECISION,
VALOR DOUBLE PRECISION,
ESTOQUE DOUBLE PRECISION)
AS 
DECLARE VARIABLE COMANDO VARCHAR(1000);
BEGIN
  FOR
   SELECT
    CD_FILIAL,
    NOME
   FROM
    FILIAIS
   INTO
    :CD_FILIAL,
    :FILIAL
  DO
   BEGIN
     SELECT
      SUM(QUANTIDADE),
      SUM(VALOR)
     FROM
      LANCAMENTOS
     WHERE
      CD_FILIAL = :CD_FILIAL AND
      ID_PRODUTO = :ID_PRODUTO AND
      TIPO_VENDA = 'V' AND
      DATA_LANCAMENTO >= :DATAINICIAL AND
      DATA_LANCAMENTO <= :DATAFINAL
     INTO
      :QUANTIDADE,
      :VALOR;

     IF (:QUANTIDADE IS NULL) THEN
        QUANTIDADE = 0;
     IF (:VALOR IS NULL) THEN
        VALOR = 0;

     COMANDO = 'SELECT ESTOQUE_'||CAST(:CD_FILIAL AS INTEGER)||' FROM PRODUTOS WHERE ID_PRODUTO = '||CAST(:ID_PRODUTO AS INTEGER);
     EXECUTE STATEMENT :COMANDO INTO :ESTOQUE;

     IF (:ESTOQUE IS NULL) THEN
         ESTOQUE = 0;
     SUSPEND;
   END
END ^

ALTER PROCEDURE SP_PRODUTOS_COMPRA_DISTRIBUIDOR (CD_FILIAL DOUBLE PRECISION,
CD_DISTRIBUIDOR DOUBLE PRECISION)
RETURNS (ID_PRODUTO DOUBLE PRECISION,
CD_PRODUTO VARCHAR(6) CHARACTER SET NONE,
DESCRICAO VARCHAR(100) CHARACTER SET NONE,
CD_GRUPO DOUBLE PRECISION,
CD_CLASSE DOUBLE PRECISION,
CD_LABORATORIO DOUBLE PRECISION,
CD_GRUPOCOMPRA DOUBLE PRECISION,
CUSTO_UNITARIO DOUBLE PRECISION,
PRECO_VENDA DOUBLE PRECISION,
ESTOQUE DOUBLE PRECISION,
MEDIAF DOUBLE PRECISION,
ESTOQUE_MINIMO DOUBLE PRECISION,
ESTOQUE_MAXIMO DOUBLE PRECISION,
MARGEM DOUBLE PRECISION,
CURVA_UNITARIA VARCHAR(1) CHARACTER SET NONE,
QT_EMBALAGEM DOUBLE PRECISION,
CODIGO_BARRAS VARCHAR(13) CHARACTER SET NONE)
AS 
DECLARE VARIABLE COMANDO VARCHAR(1000);
BEGIN
  DELETE FROM TEMP_PRODUTOS_COMPRAS;
  FOR
    SELECT DISTINCT ID_PRODUTO
    FROM
     ITENS_COMPRA, COMPRAS
    WHERE
     ITENS_COMPRA.CD_COMPRAS = COMPRAS.CD_COMPRAS AND
     COMPRAS.CD_DISTRIBUIDOR = :CD_DISTRIBUIDOR AND
     COMPRAS.CD_FILIAL = :CD_FILIAL AND
     COMPRAS.STATUS = 'C'
    INTO
     :ID_PRODUTO
  DO
   BEGIN
     INSERT INTO TEMP_PRODUTOS_COMPRAS VALUES (:ID_PRODUTO);
   END
  
  COMANDO = 'SELECT ID_PRODUTO, CD_PRODUTO, CODIGO_BARRAS_1, DESCRICAO, CD_GRUPO, CD_CLASSE, CD_LABORATORIO, CD_GRUPOCOMPRA,'||
  'CUSTO_UNITARIO, PRECO_VENDA, ESTOQUE_'||CAST(:CD_FILIAL AS INTEGER)||
  ', MEDIAF_'||CAST(:CD_FILIAL AS INTEGER)||', ESTOQUE_MINIMO_'||CAST(:CD_FILIAL AS INTEGER)||
  ', ESTOQUE_MAXIMO_'||CAST(:CD_FILIAL AS INTEGER)||', MARGEM, CURVA_UNITARIA_'||CAST(:CD_FILIAL AS INTEGER)||
  ', QT_EMBALAGEM FROM PRODUTOS WHERE ID_PRODUTO IN (SELECT ID_PRODUTO FROM TEMP_PRODUTOS_COMPRAS)';
  FOR
   EXECUTE STATEMENT :COMANDO
   INTO :ID_PRODUTO, :CD_PRODUTO, :CODIGO_BARRAS, :DESCRICAO, :CD_GRUPO, :CD_CLASSE, :CD_LABORATORIO, :CD_GRUPOCOMPRA,
        :CUSTO_UNITARIO, :PRECO_VENDA, :ESTOQUE, :MEDIAF, :ESTOQUE_MINIMO, :ESTOQUE_MAXIMO,
        :MARGEM, :CURVA_UNITARIA, :QT_EMBALAGEM
  DO
   BEGIN
     SUSPEND;
   END
END ^

ALTER PROCEDURE SP_PRODUTOS_ESTOQUE_C_ERRO RETURNS (CD_LANCAMENTO DOUBLE PRECISION,
ID_PRODUTO DOUBLE PRECISION,
PRIMEIRADATA DATE,
QUANTIDADE DOUBLE PRECISION,
TIPO_VENDA VARCHAR(1) CHARACTER SET NONE,
ENTRADA_SAIDA VARCHAR(1) CHARACTER SET NONE,
ESTOQUE_POSVENDA DOUBLE PRECISION,
TOTAL DOUBLE PRECISION,
STATUS VARCHAR(1) CHARACTER SET NONE,
HORA TIME,
DATA_LANCAMENTO DATE)
AS 
BEGIN
  FOR
    SELECT ID_PRODUTO, MIN(DATA_LANCAMENTO)
    FROM LANCAMENTOS
    WHERE ID_PRODUTO = 1392
    GROUP BY ID_PRODUTO
    INTO :ID_PRODUTO, :PRIMEIRADATA
  DO
   BEGIN
     SELECT FIRST 1 CD_LANCAMENTO, DATA_LANCAMENTO, HORA, ESTOQUE_POSVENDA
     FROM LANCAMENTOS
     WHERE
      DATA_LANCAMENTO = :PRIMEIRADATA AND
      ID_PRODUTO = :ID_PRODUTO
     --ORDER BY DATA_LANCAMENTO, HORA
     ORDER BY CD_LANCAMENTO
     INTO :CD_LANCAMENTO, :DATA_LANCAMENTO, :HORA, :TOTAL;

     SUSPEND;

     FOR
       SELECT CD_LANCAMENTO, QUANTIDADE, TIPO_VENDA, ENTRADA_SAIDA, ESTOQUE_POSVENDA, DATA_LANCAMENTO, HORA
       FROM LANCAMENTOS
       WHERE
        DATA_LANCAMENTO >= :PRIMEIRADATA AND
        ID_PRODUTO = :ID_PRODUTO AND
        CD_LANCAMENTO > :CD_LANCAMENTO
       --ORDER BY DATA_LANCAMENTO, HORA
       ORDER BY CD_LANCAMENTO
       INTO
        :CD_LANCAMENTO,
        :QUANTIDADE,
        :TIPO_VENDA,
        :ENTRADA_SAIDA,
        :ESTOQUE_POSVENDA,
        :DATA_LANCAMENTO,
        :HORA
     DO
      BEGIN
        IF (:TIPO_VENDA = 'B') THEN
           TOTAL = :QUANTIDADE;
        ELSE
        IF (:TIPO_VENDA = 'C') THEN
           TOTAL = TOTAL + :QUANTIDADE;
        ELSE
        IF (:TIPO_VENDA = 'D') THEN
           TOTAL = TOTAL + :QUANTIDADE;
        ELSE
        IF (:TIPO_VENDA = 'E') THEN
           TOTAL = TOTAL - :QUANTIDADE;
        ELSE
        IF (:TIPO_VENDA = 'F') THEN
           TOTAL = TOTAL + :QUANTIDADE;
        ELSE
        IF (:TIPO_VENDA = 'M') THEN
           TOTAL = TOTAL + :QUANTIDADE;
        ELSE
        IF (:TIPO_VENDA = 'N') THEN
           TOTAL = TOTAL - :QUANTIDADE;
        ELSE
        IF (:TIPO_VENDA = 'T') THEN
         BEGIN
           IF (:ENTRADA_SAIDA = 'E') THEN
              TOTAL = TOTAL + :QUANTIDADE;
           ELSE
           IF (:ENTRADA_SAIDA = 'S') THEN
              TOTAL = TOTAL - :QUANTIDADE;
         END
        ELSE
        IF (:TIPO_VENDA = 'V') THEN
           TOTAL = TOTAL - :QUANTIDADE;
        ELSE
        IF (:TIPO_VENDA = 'F') THEN
           TOTAL = TOTAL + :QUANTIDADE;
        ELSE
        IF (:TIPO_VENDA = 'X') THEN
         BEGIN
           IF (:ENTRADA_SAIDA = 'E') THEN
              TOTAL = TOTAL + :QUANTIDADE;
           ELSE
           IF (:ENTRADA_SAIDA = 'S') THEN
              TOTAL = TOTAL - :QUANTIDADE;
         END
        ELSE
        IF (:TIPO_VENDA = 'F') THEN
           TOTAL = TOTAL + :QUANTIDADE;
        ELSE
        IF (:TIPO_VENDA = 'Z') THEN
         BEGIN
           IF (:ENTRADA_SAIDA = 'E') THEN
              TOTAL = TOTAL + :QUANTIDADE;
           ELSE
           IF (:ENTRADA_SAIDA = 'S') THEN
              TOTAL = TOTAL - :QUANTIDADE;
         END



        SUSPEND;

      END
   END
END ^

ALTER PROCEDURE SP_PRODUTOS_MAIS_VENDIDOS (CD_FILIAL DOUBLE PRECISION,
DATAINICIAL DATE,
DATAFINAL DATE,
GRUPO DOUBLE PRECISION,
CLASSE DOUBLE PRECISION,
LABORATORIO DOUBLE PRECISION,
TIPO VARCHAR(1) CHARACTER SET NONE,
NPRODUTOS INTEGER)
RETURNS (CD_GRUPO DOUBLE PRECISION,
CD_CLASSE DOUBLE PRECISION,
CD_LABORATORIO DOUBLE PRECISION,
CODIGO_BARRAS_1 VARCHAR(14) CHARACTER SET NONE,
ID_PRODUTO DOUBLE PRECISION,
DESCRICAO VARCHAR(60) CHARACTER SET NONE,
VENDAS INTEGER,
PMC DOUBLE PRECISION,
ESTOQUE DOUBLE PRECISION,
TOTAL_VALOR DOUBLE PRECISION,
TOTAL_QUANTIDADE DOUBLE PRECISION,
DESCONTO DOUBLE PRECISION,
ESEG DOUBLE PRECISION,
CURVA VARCHAR(1) CHARACTER SET NONE,
CUSTO_MEDIO DOUBLE PRECISION)
AS 
declare variable COMANDO varchar(10000);
declare variable DATA varchar(100);
declare variable DATA_INICIAL varchar(100);
declare variable DATA_FINAL varchar(100);
declare variable VENDAS_CANCELADAS double precision;
declare variable DESCONTO_CANCELADO double precision;
declare variable TOTAL_VALOR_CANCELADO double precision;
declare variable TOTAL_QUANTIDADE_CANCELADO double precision;
BEGIN
  DATA = CAST(:DATAINICIAL AS VARCHAR(100));
  DATA_INICIAL = SUBSTRING(:DATA FROM 6 FOR 2)||'/'||SUBSTRING(:DATA FROM 9 FOR 2)||'/'||SUBSTRING(:DATA FROM 1 FOR 4);
  DATA = CAST(:DATAFINAL AS VARCHAR(100));
  DATA_FINAL = SUBSTRING(:DATA FROM 6 FOR 2)||'/'||SUBSTRING(:DATA FROM 9 FOR 2)||'/'||SUBSTRING(:DATA FROM 1 FOR 4);

  COMANDO = '';
  COMANDO = 'SELECT FIRST ' || NPRODUTOS;
  IF (:CD_FILIAL = 0) THEN
   BEGIN
     COMANDO = :COMANDO ||
     ' PRODUTOS.PRECO_VENDA AS PMC, ' ||
     'PRODUTOS.ESTOQUE_0 AS ESTOQUE, ' ||
     'PRODUTOS.ESTOQUE_MINIMO_0 AS ESEG, ' ||
     'PRODUTOS.CUSTO_MEDIO AS CUSTO_MEDIO, ' ||
     'PRODUTOS.CURVA AS CURVA,';
   END
  ELSE
   BEGIN
     COMANDO = :COMANDO ||
     ' PRODUTOS.PRECO_VENDA_' || CAST(:CD_FILIAL AS INTEGER) || ' AS PMC, ' ||
     'PRODUTOS.ESTOQUE_' || CAST(:CD_FILIAL AS INTEGER) || '  AS ESTOQUE, ' ||
     'PRODUTOS.ESTOQUE_MINIMO_' || CAST(:CD_FILIAL AS INTEGER) || '  AS ESEG, ' ||
     'PRODUTOS.CUSTO_MEDIO_' || CAST(:CD_FILIAL AS INTEGER) || '  AS CUSTO_MEDIO, ' ||
     'PRODUTOS.CURVA_UNITARIA_' || CAST(:CD_FILIAL AS INTEGER) || '  AS CURVA,';
   END

  IF (:TIPO = 'V') THEN
   BEGIN
     COMANDO = :COMANDO ||
     ' PRODUTOS.CD_GRUPO, PRODUTOS.CD_CLASSE, PRODUTOS.CD_LABORATORIO, PRODUTOS.CODIGO_BARRAS_1,' ||
     ' PRODUTOS.ID_PRODUTO, PRODUTOS.DESCRICAO, COUNT(DISTINCT LANCAMENTOS.CD_VENDA) AS VENDAS,' ||
     ' SUM(LANCAMENTOS.VALOR) AS TOTAL_VALOR, ' ||
     ' SUM(LANCAMENTOS.QUANTIDADE) AS TOTAL_QUANTIDADE, ' ||
     ' AVG(((LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE) / (LANCAMENTOS.VALOR + (LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE))) * 100) AS DESCONTO ' ||
     ' FROM LANCAMENTOS, PRODUTOS' ||
     ' WHERE LANCAMENTOS.ID_PRODUTO = PRODUTOS.ID_PRODUTO AND ' ||
     ' LANCAMENTOS.DATA_LANCAMENTO >= ''' || :DATA_INICIAL || ''' AND LANCAMENTOS.DATA_LANCAMENTO <= ''' || :DATA_FINAL || ''' AND' ||
     ' LANCAMENTOS.ID_PRODUTO <> 0 AND LANCAMENTOS.TIPO_VENDA = '''||'V'||''' AND LANCAMENTOS.VALOR > 0 ';
   END
  ELSE
   BEGIN
     COMANDO = :COMANDO ||
      ' PRODUTOS.CD_GRUPO, PRODUTOS.CD_CLASSE, PRODUTOS.CD_LABORATORIO,PRODUTOS.CODIGO_BARRAS_1, ' ||
      ' PRODUTOS.ID_PRODUTO, PRODUTOS.DESCRICAO, COUNT(DISTINCT LANCAMENTOS.CD_VENDA)  AS VENDAS,' ||
      ' SUM(LANCAMENTOS.VALOR) AS TOTAL_VALOR, ' ||
      ' SUM(LANCAMENTOS.QUANTIDADE) AS TOTAL_QUANTIDADE, ' ||
      ' AVG(((LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE) / (LANCAMENTOS.VALOR + (LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE))) * 100) AS DESCONTO ' ||
      ' FROM LANCAMENTOS, PRODUTOS' ||
      ' WHERE LANCAMENTOS.ID_PRODUTO = PRODUTOS.ID_PRODUTO AND' ||
      ' LANCAMENTOS.DATA_LANCAMENTO >= ''' || :DATA_INICIAL || ''' AND LANCAMENTOS.DATA_LANCAMENTO <= ''' || :DATA_FINAL || ''' AND' ||
      ' LANCAMENTOS.ID_PRODUTO <> 0 AND LANCAMENTOS.TIPO_VENDA = '''||'V'||''' AND LANCAMENTOS.VALOR > 0 ';
   END

  IF (:CD_FILIAL > 0) THEN
    COMANDO = :COMANDO || ' AND LANCAMENTOS.CD_FILIAL = ' || CAST(:CD_FILIAL AS INTEGER);

  IF (:GRUPO > 0) THEN
    COMANDO = :COMANDO || ' AND PRODUTOS.CD_GRUPO = ' || CAST(:GRUPO AS INTEGER);

  IF (:CLASSE > 0) THEN
    COMANDO = :COMANDO || ' AND PRODUTOS.CD_CLASSE = ' || CAST(:CLASSE AS INTEGER);

  IF (:LABORATORIO > 0) THEN
    COMANDO = :COMANDO || ' AND PRODUTOS.CD_LABORATORIO = ' || CAST(:LABORATORIO AS INTEGER);

  IF (:CD_FILIAL = 0) THEN
   BEGIN
     COMANDO = :COMANDO ||
     'GROUP BY  PRODUTOS.PRECO_VENDA, PRODUTOS.ESTOQUE_0, PRODUTOS.ESTOQUE_MINIMO_0, PRODUTOS.CUSTO_MEDIO, PRODUTOS.CD_GRUPO ' ||
     ', PRODUTOS.CD_CLASSE, PRODUTOS.CD_LABORATORIO, PRODUTOS.CODIGO_BARRAS_1, PRODUTOS.ID_PRODUTO, PRODUTOS.DESCRICAO ' ||
     ', PRODUTOS.CURVA ';
   END
  ELSE
   BEGIN
     COMANDO = :COMANDO ||
     ' GROUP BY PRODUTOS.PRECO_VENDA_' || CAST(:CD_FILIAL AS INTEGER) ||
     ', PRODUTOS.ESTOQUE_' || CAST(:CD_FILIAL AS INTEGER) ||
     ', PRODUTOS.ESTOQUE_MINIMO_' || CAST(:CD_FILIAL AS INTEGER) ||
     ', PRODUTOS.CUSTO_MEDIO_' || CAST(:CD_FILIAL AS INTEGER) ||
     ', PRODUTOS.CURVA_UNITARIA_' || CAST(:CD_FILIAL AS INTEGER) ||
     ', PRODUTOS.CD_GRUPO, PRODUTOS.CD_CLASSE, PRODUTOS.CD_LABORATORIO, PRODUTOS.CODIGO_BARRAS_1 ' ||
     ', PRODUTOS.ID_PRODUTO, PRODUTOS.DESCRICAO';
   END

  IF (:TIPO = 'V') THEN
   BEGIN
    COMANDO = :COMANDO || ' ORDER BY SUM(LANCAMENTOS.VALOR) DESC';
   END
  ELSE
   BEGIN
    COMANDO = :COMANDO || ' ORDER BY SUM(LANCAMENTOS.QUANTIDADE) DESC';
   END

  FOR
   EXECUTE STATEMENT :COMANDO
   INTO :PMC, :ESTOQUE, :ESEG, :CUSTO_MEDIO, :CURVA, :CD_GRUPO, :CD_CLASSE, :CD_LABORATORIO, :CODIGO_BARRAS_1, :ID_PRODUTO, :DESCRICAO,
        :VENDAS, :TOTAL_VALOR, :TOTAL_QUANTIDADE, :DESCONTO
  DO
   BEGIN
    SELECT
       COUNT(DISTINCT LANCAMENTOS.CD_VENDA)  AS VENDAS_CANCELADAS,
       AVG(((LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE) / (LANCAMENTOS.VALOR + (LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE))) * 100) AS DESCONTO_CANCELADO,
       SUM(LANCAMENTOS.VALOR) AS TOTAL_VALOR_CANCELADO,
       SUM(LANCAMENTOS.QUANTIDADE) AS TOTAL_QUANTIDADE_CANCELADO
    FROM LANCAMENTOS
    WHERE LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
          LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
          LANCAMENTOS.ID_PRODUTO = :ID_PRODUTO AND
          LANCAMENTOS.TIPO_VENDA = 'D' AND
          LANCAMENTOS.VALOR > 0
    INTO :VENDAS_CANCELADAS, :DESCONTO_CANCELADO, :TOTAL_VALOR_CANCELADO, :TOTAL_QUANTIDADE_CANCELADO;

    IF (:VENDAS_CANCELADAS IS NULL) THEN
       VENDAS_CANCELADAS = 0;
    IF (:DESCONTO_CANCELADO IS NULL) THEN
       DESCONTO_CANCELADO = 0;
    IF (:TOTAL_VALOR_CANCELADO IS NULL) THEN
       TOTAL_VALOR_CANCELADO = 0;
    IF (:TOTAL_QUANTIDADE_CANCELADO IS NULL) THEN
       TOTAL_QUANTIDADE_CANCELADO = 0;

    VENDAS = :VENDAS - :VENDAS_CANCELADAS;
    DESCONTO = :DESCONTO - :DESCONTO_CANCELADO;
    TOTAL_VALOR = :TOTAL_VALOR - :TOTAL_VALOR_CANCELADO;
    TOTAL_QUANTIDADE = :TOTAL_QUANTIDADE - :TOTAL_QUANTIDADE_CANCELADO;

    SUSPEND;
   END

END ^

ALTER PROCEDURE SP_PRRENCHE_MESES_PRODUTOS (ANO VARCHAR(4) CHARACTER SET NONE,
CD_FILIAL DOUBLE PRECISION)
RETURNS (PRODUTO DOUBLE PRECISION,
DESCRICAO VARCHAR(60) CHARACTER SET NONE,
JAN DOUBLE PRECISION,
FEV DOUBLE PRECISION,
MAR DOUBLE PRECISION,
ABR DOUBLE PRECISION,
MAI DOUBLE PRECISION,
JUN DOUBLE PRECISION,
JUL DOUBLE PRECISION,
AGO DOUBLE PRECISION,
SET_ DOUBLE PRECISION,
OUT DOUBLE PRECISION,
NOV DOUBLE PRECISION,
DEZ DOUBLE PRECISION,
TOTAL_GERAL DOUBLE PRECISION,
MEDIA DOUBLE PRECISION)
AS 
DECLARE VARIABLE MES VARCHAR(2);
DECLARE VARIABLE TOTAL DOUBLE PRECISION;
DECLARE VARIABLE ID_PRODUTO DOUBLE PRECISION;
BEGIN
 FOR
   SELECT
    PRODUTOS.ID_PRODUTO
   FROM
    PRODUTOS
   INTO
    :ID_PRODUTO
 DO
  BEGIN
   JAN = 0; FEV = 0; MAR = 0; ABR = 0; MAI = 0; JUN = 0;
   JUL = 0; AGO = 0; SET_ = 0; OUT = 0; NOV = 0; DEZ = 0;
   TOTAL_GERAL = 0; MEDIA = 0;
   FOR
     SELECT
      LANCAMENTOS.ID_PRODUTO,
      LANCAMENTOS.DESCRICAO,
      EXTRACT(MONTH FROM DATA_LANCAMENTO),
      SUM(LANCAMENTOS.QUANTIDADE)
     FROM
      LANCAMENTOS
     WHERE
      LANCAMENTOS.ID_PRODUTO = :ID_PRODUTO AND
      EXTRACT(YEAR FROM LANCAMENTOS.DATA_LANCAMENTO) = :ANO AND
      LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
      LANCAMENTOS.TIPO_VENDA = 'V'
     GROUP BY
      LANCAMENTOS.ID_PRODUTO,
      LANCAMENTOS.DESCRICAO,
      EXTRACT(MONTH FROM DATA_LANCAMENTO)
     INTO
      :PRODUTO,
      :DESCRICAO,
      :MES,
      :TOTAL
    DO
      BEGIN
        IF (:MES = '1') THEN
         BEGIN
           JAN = TOTAL;
         END
        ELSE
        IF (:MES = '2') THEN
         BEGIN
           FEV = TOTAL;
         END
        ELSE
        IF (:MES = '3') THEN
         BEGIN
           MAR = TOTAL;
         END
        ELSE
        IF (:MES = '4') THEN
         BEGIN
           ABR = TOTAL;
         END
        ELSE
        IF (:MES = '5') THEN
         BEGIN
           MAI = TOTAL;
         END
        ELSE
        IF (:MES = '6') THEN
         BEGIN
           JUN = TOTAL;
         END
        ELSE
        IF (:MES = '7') THEN
         BEGIN
           JUL = TOTAL;
         END
        ELSE
        IF (:MES = '8') THEN
         BEGIN
           AGO = TOTAL;
         END
        ELSE
        IF (:MES = '9') THEN
         BEGIN
           SET_ = TOTAL;
         END
        ELSE
        IF (:MES = '10') THEN
         BEGIN
           OUT = TOTAL;
         END
        ELSE
        IF (:MES = '11') THEN
         BEGIN
           NOV = TOTAL;
         END
        ELSE
        IF (:MES = '12') THEN
         BEGIN
           DEZ = TOTAL;
         END
      END
     SUSPEND;
   END
END ^

ALTER PROCEDURE SP_RANKING_VENDEDORES_REDE (MES INTEGER,
ANO INTEGER)
RETURNS (VIRTUALVENDEDOR VARCHAR(100) CHARACTER SET NONE,
ACUMULADOVALOR DOUBLE PRECISION,
ACUMULADOQUANTIDADE DOUBLE PRECISION,
ACUMULADOCLIENTES DOUBLE PRECISION,
ACUMULADOTICKET DOUBLE PRECISION,
ACUMULADODESCONTO DOUBLE PRECISION)
AS 
BEGIN
  FOR
    SELECT
     VENDEDORES.NOME,
     SUM(METAS_VENDEDORES.ACUMULADOVALOR),
     SUM(METAS_VENDEDORES.ACUMULADOQUANTIDADE),
     SUM(METAS_VENDEDORES.ACUMULADOCLIENTES),
     AVG(METAS_VENDEDORES.ACUMULADOTICKET),
     SUM(METAS_VENDEDORES.ACUMULADODESCONTO)
    FROM
     METAS_VENDEDORES LEFT OUTER JOIN VENDEDORES ON METAS_VENDEDORES.CD_VENDEDOR = VENDEDORES.CD_VENDEDOR,
     METAS_FILIAIS
    WHERE
     METAS_FILIAIS.ID_META = METAS_VENDEDORES.ID_META AND
     METAS_FILIAIS.MESREF = :MES AND
     METAS_FILIAIS.ANOREF = :ANO
    GROUP BY
     VENDEDORES.NOME
    INTO
     :VIRTUALVENDEDOR,
     :ACUMULADOVALOR,
     :ACUMULADOQUANTIDADE,
     :ACUMULADOCLIENTES,
     :ACUMULADOTICKET,
     :ACUMULADODESCONTO
   DO
    BEGIN
      IF (:VIRTUALVENDEDOR IS NULL) THEN
          VIRTUALVENDEDOR = '';
      IF (:ACUMULADOVALOR IS NULL) THEN
         ACUMULADOVALOR = 0;
      IF (:ACUMULADOQUANTIDADE IS NULL) THEN
         ACUMULADOQUANTIDADE = 0;
      IF (:ACUMULADOCLIENTES IS NULL) THEN
         ACUMULADOCLIENTES = 0;
      IF (:ACUMULADOTICKET IS NULL) THEN
         ACUMULADOTICKET = 0;
      IF (:ACUMULADODESCONTO IS NULL) THEN
         ACUMULADODESCONTO = 0;

      SUSPEND;
    END
END ^

ALTER PROCEDURE SP_RECALCULA_COMISSAO (DATA_INICIAL DATE,
DATA_FINAL DATE,
CD_FILIAL DOUBLE PRECISION)
AS 
declare variable CD_LANCAMENTO double precision;
declare variable CD_VENDEDOR double precision;
declare variable CD_CLASSE double precision;
declare variable CD_GRUPO double precision;
declare variable CD_CONVENIO double precision;
declare variable TX_COMISSAO double precision;
declare variable ID_PRODUTO double precision;
declare variable TEMCOMISSAO integer;
declare variable REDUTOR double precision;
declare variable TX_DESCONTO double precision;
declare variable PAGACOMISSAO varchar(1);
declare variable PRECOFIDELIDADE numeric(15,2);
declare variable VALOR numeric(15,2);
declare variable TIPOLOJA varchar(1);
declare variable PRECOQUANTIDADE integer;
declare variable PROMOCAO double precision;
BEGIN
 SELECT TIPO_LOJA FROM PARAMETROS INTO :TIPOLOJA;

 UPDATE LANCAMENTOS SET
   COMISSAO = 0
 WHERE
   DATA_LANCAMENTO >= :DATA_INICIAL AND
   DATA_LANCAMENTO <= :DATA_FINAL AND
   CD_FILIAL = :CD_FILIAL;

 FOR
  SELECT
   CD_LANCAMENTO,
   ID_PRODUTO,
   CD_VENDEDOR,
   CD_CONVENIO,
   VALOR,
   PROMOCAO, 
   CAST(((CAST(DESCONTO AS NUMERIC(15,2)) * QUANTIDADE)/ (VALOR + (CAST(DESCONTO AS NUMERIC(15,2)) * QUANTIDADE)) * 100) AS NUMERIC(15,2))
  FROM
   LANCAMENTOS
  WHERE
   DATA_LANCAMENTO >= :DATA_INICIAL AND
   DATA_LANCAMENTO <= :DATA_FINAL AND
   CD_FILIAL = :CD_FILIAL AND
   VALOR > 0 AND
   ((TIPO_VENDA = 'V') OR (TIPO_VENDA = 'D'))
  GROUP BY
   CD_LANCAMENTO,
   ID_PRODUTO,
   CD_VENDEDOR,
   CD_CONVENIO,
   DESCONTO,
   QUANTIDADE,
   PROMOCAO,
   VALOR
  INTO
   :CD_LANCAMENTO,
   :ID_PRODUTO, 
   :CD_VENDEDOR,
   :CD_CONVENIO,
   :VALOR,
   :PROMOCAO,
   :TX_DESCONTO
 DO
  BEGIN
   TX_COMISSAO = 0;
   REDUTOR = 0;
   PAGACOMISSAO = NULL;

   SELECT CD_CLASSE, CD_GRUPO, COMISSAO FROM PRODUTOS WHERE ID_PRODUTO = :ID_PRODUTO INTO :CD_CLASSE, :CD_GRUPO, :TX_COMISSAO;
   SELECT COUNT(*) FROM VENDEDORES_CLASSES WHERE CD_VENDEDOR = :CD_VENDEDOR AND CD_CLASSE = :CD_CLASSE AND COMISSAO = 'S' INTO :TEMCOMISSAO;
   SELECT PAGACOMISSAO FROM CONVENIOS WHERE CD_CONVENIO = :CD_CONVENIO INTO :PAGACOMISSAO;
   SELECT PRECO FROM PRODUTOS_FIDELIDADE WHERE ID_PRODUTO = :ID_PRODUTO INTO :PRECOFIDELIDADE;
   SELECT COUNT(*) FROM PRODUTOS_PRECO_QUANTIDADE WHERE ID_PRODUTO = :ID_PRODUTO INTO :PRECOQUANTIDADE;
   IF (:PRECOFIDELIDADE IS NULL) THEN
      PRECOFIDELIDADE = 0;

   IF ((:TEMCOMISSAO > 0) AND ((CD_CONVENIO = 0) OR ((:PAGACOMISSAO IS NULL) OR (:PAGACOMISSAO <> 'N')))) THEN
    BEGIN
      IF ((:TX_COMISSAO IS NULL) OR (:TX_COMISSAO = 0)) THEN
       BEGIN
         IF (:TIPOLOJA = 'M') THEN
            SELECT TX_COMISSAO FROM FILIAIS_GRUPOS WHERE CD_FILIAL = :CD_FILIAL AND CD_GRUPO = :CD_GRUPO INTO :TX_COMISSAO;
         ELSE
            SELECT TX_COMISSAO FROM GRUPOS WHERE CD_GRUPO = :CD_GRUPO INTO :TX_COMISSAO;
         IF (:TX_COMISSAO IS NULL) THEN
            TX_COMISSAO = 0;
       END
      IF (:TX_COMISSAO > 0) THEN
       BEGIN

          SELECT PERCENTUAL FROM FAIXACOMISSAO
          WHERE (INICIAL > 0 OR FINAL > 0) AND (:TX_DESCONTO >= INICIAL AND :TX_DESCONTO <= FINAL)
          INTO :REDUTOR;

          IF (((:REDUTOR IS NOT NULL) AND (:REDUTOR > 0)) AND ((:PRECOFIDELIDADE = 0) OR (:PRECOFIDELIDADE <> :VALOR)) AND
              ((:PROMOCAO IS NULL) OR (:PROMOCAO = 0)) AND (:PRECOQUANTIDADE = 0)) THEN
           BEGIN
              UPDATE LANCAMENTOS SET
                COMISSAO = (((VALOR * :TX_COMISSAO) / 100) * :REDUTOR) / 100
              WHERE
               CD_LANCAMENTO = :CD_LANCAMENTO AND
               CD_FILIAL = :CD_FILIAL AND
               DATA_LANCAMENTO >= :DATA_INICIAL AND
               DATA_LANCAMENTO <= :DATA_FINAL AND
               ID_PRODUTO = :ID_PRODUTO AND
               CD_VENDEDOR = :CD_VENDEDOR AND
               (TIPO_VENDA = 'V' OR TIPO_VENDA = 'D');
           END
          ELSE
           BEGIN
              UPDATE LANCAMENTOS SET
                COMISSAO = (VALOR * :TX_COMISSAO) / 100
              WHERE
               CD_LANCAMENTO = :CD_LANCAMENTO AND
               CD_FILIAL = :CD_FILIAL AND
               DATA_LANCAMENTO >= :DATA_INICIAL AND
               DATA_LANCAMENTO <= :DATA_FINAL AND
               ID_PRODUTO = :ID_PRODUTO AND
               CD_VENDEDOR = :CD_VENDEDOR AND
               (TIPO_VENDA = 'V' OR TIPO_VENDA = 'D');
           END
       END
    END
  END
END ^

ALTER PROCEDURE SP_RECALCULA_CR_LANCAMENTOS AS 
DECLARE VARIABLE VENDA DOUBLE PRECISION;
DECLARE VARIABLE FILIAL DOUBLE PRECISION;
DECLARE VARIABLE VALOR DOUBLE PRECISION;
BEGIN
 FOR
  SELECT
   CD_VENDA,
   CD_FILIAL
  FROM
   CONTAS_RECEBER
  WHERE
   CD_FORMA_PAGAMENTO = 3 AND
   STATUS = 'A'
  INTO
   :VENDA,
   :FILIAL
 DO
  BEGIN
    SELECT
     SUM(VALOR)
    FROM
     LANCAMENTOS
    WHERE
     CD_VENDA = :VENDA AND
     CD_FILIAL = :FILIAL AND
     TIPO_VENDA = 'V'
    INTO
     :VALOR;

    UPDATE CONTAS_RECEBER SET
     VALOR = :VALOR ,
     VL_SALDO = :VALOR
    WHERE
     CD_VENDA = :VENDA AND
     CD_FILIAL = :FILIAL;
  END

 FOR
   SELECT
    CD_VENDA,
    CD_FILIAL
   FROM
    LANCAMENTOS
   WHERE
    TIPO_VENDA = 'D' AND
    TROCA = 'F'
   GROUP BY
    CD_VENDA,
    CD_FILIAL
   INTO
    :VENDA,
    :FILIAL
 DO
  BEGIN
    UPDATE CONTAS_RECEBER SET
     STATUS = 'C'
    WHERE
     CD_VENDA = :VENDA AND
     CD_FILIAL = :FILIAL AND
     CD_FORMA_PAGAMENTO = 3;
  END
END ^

ALTER PROCEDURE SP_RECALCULA_CUSTO_APLICADO RETURNS (CD_COMPRAS DOUBLE PRECISION,
ID_PRODUTO DOUBLE PRECISION,
VL_UNITARIO DOUBLE PRECISION,
VL_IPI DOUBLE PRECISION,
VL_ICMSSUBTITUICAO DOUBLE PRECISION,
VL_FRETE DOUBLE PRECISION,
VL_SEGURO DOUBLE PRECISION,
VL_OUTRASDESPESAS DOUBLE PRECISION,
VL_DESCONTO DOUBLE PRECISION,
QT_EMBALAGEM INTEGER,
CUSTO_APLICADO NUMERIC(15, 2),
CUSTO_UNITARIO NUMERIC(15, 2))
AS 
BEGIN
  CUSTO_APLICADO = 0;
  ID_PRODUTO = 0;
  FOR
    SELECT ID_PRODUTO FROM PRODUTOS INTO :ID_PRODUTO
  DO
   BEGIN
      CD_COMPRAS = 0;
      CUSTO_APLICADO = 0;
      FOR
        SELECT
          FIRST 1 ITENS_COMPRA.CD_COMPRAS, ITENS_COMPRA.VL_UNITARIO,
          (ITENS_COMPRA.VL_IPI / ITENS_COMPRA.QUANTIDADE) , (ITENS_COMPRA.VALORICMSSUBTITUICAO / ITENS_COMPRA.QUANTIDADE),
          (ITENS_COMPRA.VALOR_FRETE / ITENS_COMPRA.QUANTIDADE), (ITENS_COMPRA.VALOR_SEGURO / ITENS_COMPRA.QUANTIDADE),
          (ITENS_COMPRA.VALOR_OUTRASDESPESAS / ITENS_COMPRA.QUANTIDADE), ITENS_COMPRA.VL_DESCONTO, ITENS_COMPRA.QT_EMBALAGEM
        FROM
         ITENS_COMPRA, COMPRAS
        WHERE
         COMPRAS.STATUS = 'C' AND
         COMPRAS.BONIFICACAO = 'N' AND
         COMPRAS.CD_COMPRAS = ITENS_COMPRA.CD_COMPRAS AND
         ITENS_COMPRA.ID_PRODUTO = :ID_PRODUTO AND
         (ITENS_COMPRA.CUSTO_APLICADO IS NULL OR ITENS_COMPRA.CUSTO_APLICADO <= 0)
        INTO
         :CD_COMPRAS, :VL_UNITARIO, :VL_IPI, :VL_ICMSSUBTITUICAO, :VL_FRETE, :VL_SEGURO, :VL_OUTRASDESPESAS, :VL_DESCONTO, :QT_EMBALAGEM
      DO
       BEGIN
        IF ((:CD_COMPRAS IS NOT NULL) AND (:CD_COMPRAS > 0)) THEN
         BEGIN
            CUSTO_APLICADO = ((:VL_UNITARIO + :VL_IPI + :VL_ICMSSUBTITUICAO + :VL_FRETE + :VL_SEGURO + VL_OUTRASDESPESAS) - :VL_DESCONTO) / :QT_EMBALAGEM;
            IF ((:CUSTO_APLICADO IS NOT NULL) AND (:CUSTO_APLICADO > 0)) THEN
             BEGIN
               /*UPDATE ITENS_COMPRA SET
                 CUSTO_APLICADO = :CUSTO_APLICADO
               WHERE
                 CD_COMPRAS = :CD_COMPRAS AND
                 ID_PRODUTO = :ID_PRODUTO;*/

               SELECT CUSTO_UNITARIO_1 FROM PRODUTOS WHERE ID_PRODUTO = :ID_PRODUTO INTO :CUSTO_UNITARIO;
               IF (:CUSTO_UNITARIO <> :CUSTO_APLICADO) THEN
                  SUSPEND;
             END
         END
       END
   END
END ^

ALTER PROCEDURE SP_RECALCULA_ESTOQUE (FILIAL VARCHAR(10) CHARACTER SET NONE,
ID_BALANCO DOUBLE PRECISION)
RETURNS (ESTOQUE_BALANCO DOUBLE PRECISION,
ESTOQUE_TOTAL DOUBLE PRECISION,
PRODUTO DOUBLE PRECISION)
AS 
DECLARE VARIABLE CODIGO_LANCAMENTO DOUBLE PRECISION;
DECLARE VARIABLE QUANTIDADE DOUBLE PRECISION;
DECLARE VARIABLE TIPO_MOVIMENTO VARCHAR(1);
DECLARE VARIABLE COMANDO VARCHAR(1000);
DECLARE VARIABLE DATA_CONCLUSAO DATE;
DECLARE VARIABLE HORA_CONCLUSAO TIME;
DECLARE VARIABLE HORA TIME;
DECLARE VARIABLE DATA DATE;
BEGIN
 COMANDO = 'UPDATE PRODUTOS SET ESTOQUE_'||CAST(:FILIAL AS INTEGER)||' = 0';
 EXECUTE STATEMENT :COMANDO;

 FOR
  SELECT
   ID_PRODUTO,
   DATA_CONTAGEM,
   HORA_CONTAGEM,
   SUM(ESTOQUE)
  FROM
   BALANCO
  WHERE
   ID_BALANCO = :ID_BALANCO AND
   CD_FILIAL = :FILIAL
  GROUP BY
   ID_PRODUTO,
   DATA_CONTAGEM,
   HORA_CONTAGEM
  INTO
   :PRODUTO,
   :DATA_CONCLUSAO,
   :HORA_CONCLUSAO,
   :ESTOQUE_BALANCO
 DO
  BEGIN
    IF (:ESTOQUE_BALANCO > 0) THEN
     BEGIN
        ESTOQUE_TOTAL = :ESTOQUE_BALANCO;
        FOR
         SELECT
          CD_LANCAMENTO,
          DATA_LANCAMENTO,
          HORA,
          QUANTIDADE,
          ENTRADA_SAIDA
         FROM
          LANCAMENTOS
         WHERE
          CD_FILIAL = :FILIAL AND
          ID_PRODUTO = :PRODUTO AND
          DATA_LANCAMENTO >= :DATA_CONCLUSAO AND
          TIPO_VENDA <> 'B'
         INTO
          :CODIGO_LANCAMENTO,
          :DATA,
          :HORA,
          :QUANTIDADE,
          :TIPO_MOVIMENTO
        DO
         BEGIN
           IF (:DATA = :DATA_CONCLUSAO) THEN
            BEGIN
              IF (:HORA >= :HORA_CONCLUSAO) THEN
               BEGIN
                 IF (:TIPO_MOVIMENTO = 'E') THEN
                    ESTOQUE_TOTAL = :ESTOQUE_TOTAL + :QUANTIDADE;
                 ELSE
                 IF (:TIPO_MOVIMENTO = 'S') THEN
                    ESTOQUE_TOTAL = :ESTOQUE_TOTAL - :QUANTIDADE;
                 UPDATE LANCAMENTOS SET ESTOQUE_POSVENDA = :ESTOQUE_TOTAL
                 WHERE CD_LANCAMENTO = :CODIGO_LANCAMENTO AND CD_FILIAL = :FILIAL;
               END
            END
           ELSE
            BEGIN
                 IF (:TIPO_MOVIMENTO = 'E') THEN
                    ESTOQUE_TOTAL = :ESTOQUE_TOTAL + :QUANTIDADE;
                 ELSE
                 IF (:TIPO_MOVIMENTO = 'S') THEN
                    ESTOQUE_TOTAL = :ESTOQUE_TOTAL - :QUANTIDADE;
                 UPDATE LANCAMENTOS SET ESTOQUE_POSVENDA = :ESTOQUE_TOTAL
                 WHERE CD_LANCAMENTO = :CODIGO_LANCAMENTO AND CD_FILIAL = :FILIAL;
            END
         END
        /* ALTERANDO O ESTOQUE DO PRODUTO */
        COMANDO = 'UPDATE PRODUTOS SET ESTOQUE_'||CAST(:FILIAL AS INTEGER)||' = '|| :ESTOQUE_TOTAL ||
                  ' - ESTOQUE_'||CAST(:FILIAL AS INTEGER)||' WHERE ID_PRODUTO = '|| :PRODUTO;
        EXECUTE STATEMENT :COMANDO;
     END
  END
END ^

ALTER PROCEDURE SP_RECALCULA_ESTOQUE_ERRO (DATA_INICIAL DATE)
RETURNS (ESTOQUE_LANCAMENTO DOUBLE PRECISION,
ESTOQUE_TOTAL DOUBLE PRECISION,
PRODUTO DOUBLE PRECISION)
AS 
declare variable CODIGO_LANCAMENTO double precision;
declare variable QUANTIDADE double precision;
declare variable TIPO_MOVIMENTO varchar(1);
declare variable COMANDO varchar(1000);
declare variable DATA_LANCAMENTO date;
declare variable HORA_LANCAMENTO time;
declare variable HORA time;
declare variable DATA date;
declare variable FILIAL double precision;
declare variable TIPO_VENDA varchar(1);
BEGIN
 FOR
  SELECT
   DISTINCT ID_PRODUTO
  FROM
   PRODUTOS
  INTO
   :PRODUTO
 DO
  BEGIN
     FOR
      SELECT
       FIRST 1 CD_FILIAL, DATA_LANCAMENTO, HORA, ESTOQUE_POSVENDA
      FROM
       LANCAMENTOS
      WHERE
       DATA_LANCAMENTO >= :DATA_INICIAL AND
       ID_PRODUTO = :PRODUTO
      ORDER BY
       DATA_LANCAMENTO, HORA
      INTO
       :FILIAL, :DATA_LANCAMENTO, :HORA_LANCAMENTO, :ESTOQUE_LANCAMENTO
     DO
      BEGIN
        ESTOQUE_TOTAL = 0;
        ESTOQUE_TOTAL = :ESTOQUE_LANCAMENTO;
        IF (ESTOQUE_TOTAL IS NULL) THEN ESTOQUE_TOTAL = 0;
        FOR
         SELECT
          CD_LANCAMENTO, DATA_LANCAMENTO, HORA, QUANTIDADE, ENTRADA_SAIDA, TIPO_VENDA
         FROM
          LANCAMENTOS
         WHERE
          ID_PRODUTO = :PRODUTO AND
          CD_FILIAL = :FILIAL AND
          ((DATA_LANCAMENTO = :DATA_LANCAMENTO AND
          HORA > :HORA_LANCAMENTO) OR
          DATA_LANCAMENTO > :DATA_LANCAMENTO)
         ORDER BY
          DATA_LANCAMENTO, HORA
         INTO
          :CODIGO_LANCAMENTO, :DATA, :HORA, :QUANTIDADE, :TIPO_MOVIMENTO, :TIPO_VENDA
        DO
         BEGIN
           IF (:TIPO_VENDA = 'B') THEN
              ESTOQUE_TOTAL = :QUANTIDADE;
           ELSE
            BEGIN
               IF (:DATA = :DATA_LANCAMENTO) THEN
                BEGIN
                  IF (:HORA > :HORA_LANCAMENTO) THEN
                   BEGIN
                     IF (:TIPO_MOVIMENTO = 'E') THEN
                        ESTOQUE_TOTAL = :ESTOQUE_TOTAL + :QUANTIDADE;
                     ELSE
                     IF (:TIPO_MOVIMENTO = 'S') THEN
                        ESTOQUE_TOTAL = :ESTOQUE_TOTAL - :QUANTIDADE;
                     UPDATE LANCAMENTOS SET ESTOQUE_POSVENDA = CAST(:ESTOQUE_TOTAL AS INTEGER)
                     WHERE CD_LANCAMENTO = :CODIGO_LANCAMENTO AND CD_FILIAL = :FILIAL;
                   END
                END
               ELSE
                BEGIN
                     IF (:TIPO_MOVIMENTO = 'E') THEN
                        ESTOQUE_TOTAL = :ESTOQUE_TOTAL + :QUANTIDADE;
                     ELSE
                     IF (:TIPO_MOVIMENTO = 'S') THEN
                        ESTOQUE_TOTAL = :ESTOQUE_TOTAL - :QUANTIDADE;
                     UPDATE LANCAMENTOS SET ESTOQUE_POSVENDA = CAST(:ESTOQUE_TOTAL AS INTEGER)
                     WHERE CD_LANCAMENTO = :CODIGO_LANCAMENTO AND CD_FILIAL = :FILIAL;
                END
           END
         END
        /* ALTERANDO O ESTOQUE DO PRODUTO */
        COMANDO = 'UPDATE PRODUTOS SET ESTOQUE_'||CAST(:FILIAL AS INTEGER)||' = ' || :ESTOQUE_TOTAL || ' WHERE ID_PRODUTO = ' || :PRODUTO;
        EXECUTE STATEMENT :COMANDO;
        /*SUSPEND;*/
      END
   END
END ^

ALTER PROCEDURE SP_RECALCULA_ESTOQUE_ERRO_NOTA (NOTA_FISCAL VARCHAR(100) CHARACTER SET NONE,
DATA_INICIAL DATE)
RETURNS (ESTOQUE_LANCAMENTO DOUBLE PRECISION,
ESTOQUE_TOTAL DOUBLE PRECISION,
PRODUTO DOUBLE PRECISION)
AS 
declare variable CODIGO_LANCAMENTO double precision;
declare variable QUANTIDADE double precision;
declare variable TIPO_MOVIMENTO varchar(1);
declare variable COMANDO varchar(1000);
declare variable DATA_LANCAMENTO date;
declare variable HORA_LANCAMENTO time;
declare variable HORA time;
declare variable DATA date;
declare variable FILIAL double precision;
declare variable TIPO_VENDA varchar(1);
BEGIN
 FOR
  SELECT
   DISTINCT ITENS_COMPRA.ID_PRODUTO
  FROM
   ITENS_COMPRA, COMPRAS
  WHERE
   ITENS_COMPRA.CD_COMPRAS = COMPRAS.CD_COMPRAS AND
   COMPRAS.NOTA_FISCAL = :NOTA_FISCAL
  INTO
   :PRODUTO
 DO
  BEGIN
     FOR
      SELECT
       FIRST 1 CD_FILIAL, DATA_LANCAMENTO, HORA, ESTOQUE_POSVENDA
      FROM
       LANCAMENTOS
      WHERE
       DATA_LANCAMENTO >= :DATA_INICIAL AND
       ID_PRODUTO = :PRODUTO
      ORDER BY
       DATA_LANCAMENTO, HORA
      INTO
       :FILIAL, :DATA_LANCAMENTO, :HORA_LANCAMENTO, :ESTOQUE_LANCAMENTO
     DO
      BEGIN
        ESTOQUE_TOTAL = 0;
        ESTOQUE_TOTAL = :ESTOQUE_LANCAMENTO;
        IF (ESTOQUE_TOTAL IS NULL) THEN ESTOQUE_TOTAL = 0;
        FOR
         SELECT
          CD_LANCAMENTO, DATA_LANCAMENTO, HORA, QUANTIDADE, ENTRADA_SAIDA, TIPO_VENDA
         FROM
          LANCAMENTOS
         WHERE
          ID_PRODUTO = :PRODUTO AND
          CD_FILIAL = :FILIAL AND
          ((DATA_LANCAMENTO = :DATA_LANCAMENTO AND
          HORA > :HORA_LANCAMENTO) OR
          DATA_LANCAMENTO > :DATA_LANCAMENTO)
         ORDER BY
          DATA_LANCAMENTO, HORA
         INTO
          :CODIGO_LANCAMENTO, :DATA, :HORA, :QUANTIDADE, :TIPO_MOVIMENTO, :TIPO_VENDA
        DO
         BEGIN
           IF (:TIPO_VENDA = 'B') THEN
              ESTOQUE_TOTAL = :QUANTIDADE;
           ELSE
            BEGIN
               IF (:DATA = :DATA_LANCAMENTO) THEN
                BEGIN
                  IF (:HORA > :HORA_LANCAMENTO) THEN
                   BEGIN
                     IF (:TIPO_MOVIMENTO = 'E') THEN
                        ESTOQUE_TOTAL = :ESTOQUE_TOTAL + :QUANTIDADE;
                     ELSE
                     IF (:TIPO_MOVIMENTO = 'S') THEN
                        ESTOQUE_TOTAL = :ESTOQUE_TOTAL - :QUANTIDADE;
                     UPDATE LANCAMENTOS SET ESTOQUE_POSVENDA = CAST(:ESTOQUE_TOTAL AS INTEGER)
                     WHERE CD_LANCAMENTO = :CODIGO_LANCAMENTO AND CD_FILIAL = :FILIAL;
                   END
                END
               ELSE
                BEGIN
                     IF (:TIPO_MOVIMENTO = 'E') THEN
                        ESTOQUE_TOTAL = :ESTOQUE_TOTAL + :QUANTIDADE;
                     ELSE
                     IF (:TIPO_MOVIMENTO = 'S') THEN
                        ESTOQUE_TOTAL = :ESTOQUE_TOTAL - :QUANTIDADE;
                     UPDATE LANCAMENTOS SET ESTOQUE_POSVENDA = CAST(:ESTOQUE_TOTAL AS INTEGER)
                     WHERE CD_LANCAMENTO = :CODIGO_LANCAMENTO AND CD_FILIAL = :FILIAL;
                END
           END
         END
        /* ALTERANDO O ESTOQUE DO PRODUTO */
        COMANDO = 'UPDATE PRODUTOS SET ESTOQUE_'||CAST(:FILIAL AS INTEGER)||' = ' || :ESTOQUE_TOTAL || ' WHERE ID_PRODUTO = ' || :PRODUTO;
        EXECUTE STATEMENT :COMANDO;
        /*SUSPEND;*/
      END
   END
END ^

