ALTER PROCEDURE SP_RECALCULA_ESTOQUE_INICIA_DIA (DATA_LANCAMENTO DATE,
PERIODO INTEGER)
AS 
declare variable ID_PRODUTO double precision;
declare variable DATA date;
BEGIN
  DATA = CURRENT_DATE - :PERIODO;
  FOR
    SELECT DISTINCT ID_PRODUTO FROM LANCAMENTOS WHERE DATA_LANCAMENTO >= :DATA_LANCAMENTO INTO :ID_PRODUTO
  DO
   BEGIN
     EXECUTE PROCEDURE SP_RECALCULA_ESTOQUE_ERRO_PROD(:DATA, :ID_PRODUTO);
   END
END ^

