ALTER PROCEDURE SP_RECALCULA_ESTOQUE_PEDIDO (CD_COMPRAS DOUBLE PRECISION)
AS 
declare variable CD_FILIAL double precision;
declare variable ID_PRODUTO double precision;
declare variable ESTOQUE double precision;
declare variable COMANDO varchar(10000);
BEGIN
  SELECT CD_FILIAL FROM COMPRAS WHERE CD_COMPRAS = :CD_COMPRAS INTO :CD_FILIAL;
  FOR
    SELECT ID_PRODUTO FROM ITENS_COMPRA WHERE CD_COMPRAS = :CD_COMPRAS INTO :ID_PRODUTO
  DO
   BEGIN
     ESTOQUE = 0;
     COMANDO = '';
     COMANDO = 'SELECT ESTOQUE_'||CAST(:CD_FILIAL AS INTEGER)||' FROM PRODUTOS WHERE ID_PRODUTO = '||CAST(:ID_PRODUTO AS INTEGER);
     EXECUTE STATEMENT :COMANDO INTO :ESTOQUE;

     UPDATE ITENS_COMPRA SET
       ITENS_COMPRA.SALDO = :ESTOQUE
     WHERE CD_COMPRAS = :CD_COMPRAS AND ID_PRODUTO = :ID_PRODUTO;

   END
END ^

ALTER PROCEDURE SP_RECALCULA_ESTOQUE_SALDO (ID_BALANCO DOUBLE PRECISION)
RETURNS (ESTOQUE_BALANCO DOUBLE PRECISION,
ESTOQUE_TOTAL DOUBLE PRECISION,
PRODUTO DOUBLE PRECISION)
AS 
declare variable CD_FILIAL double precision;
declare variable CODIGO_LANCAMENTO double precision;
declare variable QUANTIDADE double precision;
declare variable TIPO_MOVIMENTO varchar(1);
declare variable COMANDO varchar(1000);
declare variable DATA_CONTAGEM date;
declare variable HORA_CONTAGEM time;
declare variable HORA time;
declare variable data date;
declare variable FILIAL double precision;
declare variable CODIGO_BARRAS_1 varchar(14);
declare variable CODIGO_BARRAS_2 varchar(14);
declare variable PRECO_VENDA double precision;
BEGIN
  FOR
    SELECT
     BALANCO.CD_FILIAL, BALANCO.ID_PRODUTO, BALANCO.CODIGO_BARRAS_1, /*BALANCO.CODIGO_BARRAS_2,*/ BALANCO.PRECO_VENDA, BALANCO.CD_FILIAL, BALANCO.DATA_CONTAGEM, BALANCO.HORA_CONTAGEM, BALANCO.ESTOQUE
    FROM
     BALANCO
    WHERE
     BALANCO.ID_BALANCO = :ID_BALANCO AND
     BALANCO.ESTOQUE >= 0
    INTO
     :CD_FILIAL, :PRODUTO, :CODIGO_BARRAS_1, /*:CODIGO_BARRAS_2,*/ :PRECO_VENDA, :FILIAL, :DATA_CONTAGEM, :HORA_CONTAGEM, :ESTOQUE_BALANCO
  DO
   BEGIN
      COMANDO = '';
      COMANDO = 'UPDATE PRODUTOS SET ESTOQUE_'||CAST(:FILIAL AS INTEGER)||' = ' || CAST(:ESTOQUE_BALANCO AS NUMERIC(15,2));
      IF ((:CODIGO_BARRAS_1 IS NOT NULL) AND (:CODIGO_BARRAS_1 <> '')) THEN
         COMANDO = :COMANDO || ', CODIGO_BARRAS_1 = ''' || :CODIGO_BARRAS_1 || '''';
/*      IF ((:CODIGO_BARRAS_2 IS NOT NULL) AND (:CODIGO_BARRAS_2 <> '')) THEN
         COMANDO = :COMANDO || ', CODIGO_BARRAS_2 = ''' || :CODIGO_BARRAS_2 || '''';*/
      IF ((:PRECO_VENDA IS NOT NULL) AND (:PRECO_VENDA > 0)) THEN
         COMANDO = :COMANDO || ', PRECO_VENDA = '|| CAST(:PRECO_VENDA AS NUMERIC(15,2));
      COMANDO = :COMANDO || ' WHERE ID_PRODUTO = ' || CAST(:PRODUTO AS INTEGER);
      EXECUTE STATEMENT :COMANDO;
   END

  SELECT MIN(DATA_CONTAGEM) FROM BALANCO WHERE ID_BALANCO = :ID_BALANCO AND DATA_CONTAGEM IS NOT NULL INTO :DATA_CONTAGEM;
  FOR
    SELECT
     BALANCO.CD_FILIAL, BALANCO.ID_PRODUTO, BALANCO.CODIGO_BARRAS_1, /*BALANCO.CODIGO_BARRAS_2,*/ BALANCO.PRECO_VENDA, BALANCO.CD_FILIAL, BALANCO.DATA_CONTAGEM, BALANCO.HORA_CONTAGEM, BALANCO.ESTOQUE
    FROM
     LANCAMENTOS, BALANCO
    WHERE
     LANCAMENTOS.ID_PRODUTO = BALANCO.ID_PRODUTO AND
     LANCAMENTOS.DATA_LANCAMENTO >= :DATA_CONTAGEM AND
     LANCAMENTOS.TIPO_VENDA <> 'B' AND
     BALANCO.ID_BALANCO = :ID_BALANCO
    INTO
     :CD_FILIAL, :PRODUTO, :CODIGO_BARRAS_1, /*:CODIGO_BARRAS_2,*/ :PRECO_VENDA, :FILIAL, :DATA_CONTAGEM, :HORA_CONTAGEM, :ESTOQUE_BALANCO
  DO
   BEGIN
     ESTOQUE_TOTAL = 0;
     ESTOQUE_TOTAL = :ESTOQUE_BALANCO;
     IF (ESTOQUE_BALANCO IS NULL) THEN ESTOQUE_BALANCO = 0;
     FOR
       SELECT
        CD_LANCAMENTO, DATA_LANCAMENTO, HORA, QUANTIDADE, ENTRADA_SAIDA
       FROM
        LANCAMENTOS
       WHERE
        CD_FILIAL = :CD_FILIAL AND
        ID_PRODUTO = :PRODUTO AND
        DATA_LANCAMENTO >= :DATA_CONTAGEM AND
        TIPO_VENDA <> 'B'
       ORDER BY
        DATA_LANCAMENTO, HORA
       INTO
        :CODIGO_LANCAMENTO, :DATA, :HORA, :QUANTIDADE, :TIPO_MOVIMENTO
     DO
      BEGIN
         IF (:DATA = :DATA_CONTAGEM) THEN
          BEGIN
            IF (:HORA >= :HORA_CONTAGEM) THEN
             BEGIN
               IF (:TIPO_MOVIMENTO = 'E') THEN
                  ESTOQUE_TOTAL = :ESTOQUE_TOTAL + :QUANTIDADE;
               ELSE
               IF (:TIPO_MOVIMENTO = 'S') THEN
                  ESTOQUE_TOTAL = :ESTOQUE_TOTAL - :QUANTIDADE;
               UPDATE LANCAMENTOS SET ESTOQUE_POSVENDA = :ESTOQUE_TOTAL
               WHERE CD_LANCAMENTO = :CODIGO_LANCAMENTO AND CD_FILIAL = :FILIAL;
             END
          END
         ELSE
          BEGIN
               IF (:TIPO_MOVIMENTO = 'E') THEN
                  ESTOQUE_TOTAL = :ESTOQUE_TOTAL + :QUANTIDADE;
               ELSE
               IF (:TIPO_MOVIMENTO = 'S') THEN
                  ESTOQUE_TOTAL = :ESTOQUE_TOTAL - :QUANTIDADE;
               UPDATE LANCAMENTOS SET ESTOQUE_POSVENDA = :ESTOQUE_TOTAL
               WHERE CD_LANCAMENTO = :CODIGO_LANCAMENTO AND CD_FILIAL = :FILIAL;
          END
      END

      COMANDO = 'UPDATE PRODUTOS SET ESTOQUE_'||CAST(:FILIAL AS INTEGER)||' = ' || CAST(:ESTOQUE_TOTAL AS NUMERIC(15,2));
      IF ((:CODIGO_BARRAS_1 IS NOT NULL) AND (:CODIGO_BARRAS_1 <> '')) THEN
         COMANDO = :COMANDO || ', CODIGO_BARRAS_1 = ''' || :CODIGO_BARRAS_1 || '''';
/*      IF ((:CODIGO_BARRAS_2 IS NOT NULL) AND (:CODIGO_BARRAS_2 <> '')) THEN
         COMANDO = :COMANDO || ', CODIGO_BARRAS_2 = ''' || :CODIGO_BARRAS_2 || '''';*/
      IF ((:PRECO_VENDA IS NOT NULL) AND (:PRECO_VENDA > 0)) THEN
         COMANDO = :COMANDO || ', PRECO_VENDA = '|| CAST(:PRECO_VENDA AS NUMERIC(15,2));
  
      COMANDO = :COMANDO || ' WHERE ID_PRODUTO = ' || CAST(:PRODUTO AS INTEGER);
      EXECUTE STATEMENT :COMANDO;
   END
END ^

ALTER PROCEDURE SP_RECALCULA_MOVIMENTO_BALANCO (DATA_BALANCO DATE)
RETURNS (CD_FILIAL DOUBLE PRECISION,
CD_LANCAMENTO DOUBLE PRECISION,
ID_PRODUTO DOUBLE PRECISION,
DATA_MOVIMENTO DATE,
HORA TIME,
ENTRADA_SAIDA VARCHAR(1) CHARACTER SET NONE,
ULTIMO_ESTOQUE DOUBLE PRECISION,
QUANTIDADE DOUBLE PRECISION,
ESTOQUE DOUBLE PRECISION)
AS 
BEGIN
  FOR
   SELECT
    BALANCO.ID_PRODUTO,
    BALANCO.CD_FILIAL,
    BALANCO.ESTOQUE
   FROM
    BALANCO
   WHERE
    BALANCO.DATA = :DATA_BALANCO
   GROUP BY
    BALANCO.ID_PRODUTO,
    BALANCO.CD_FILIAL,
    BALANCO.ESTOQUE
   INTO
    :ID_PRODUTO,
    :CD_FILIAL,
    :ESTOQUE
  DO
   BEGIN
    ULTIMO_ESTOQUE = :ESTOQUE;
    FOR
     SELECT
      LANCAMENTOS.CD_LANCAMENTO,
      LANCAMENTOS.ENTRADA_SAIDA,
      LANCAMENTOS.DATA_LANCAMENTO,
      LANCAMENTOS.HORA,
      LANCAMENTOS.QUANTIDADE
     FROM
      LANCAMENTOS
     WHERE
      LANCAMENTOS.ID_PRODUTO = :ID_PRODUTO AND
      LANCAMENTOS.DATA_LANCAMENTO >= :DATA_BALANCO AND
      LANCAMENTOS.TIPO_VENDA <> 'B'
     ORDER BY
      LANCAMENTOS.DATA_LANCAMENTO,
      LANCAMENTOS.HORA
     INTO
      :CD_LANCAMENTO,
      :ENTRADA_SAIDA,
      :DATA_MOVIMENTO,
      :HORA,
      :QUANTIDADE
    DO
     BEGIN
       IF (:ENTRADA_SAIDA = 'S') THEN
        BEGIN
          ULTIMO_ESTOQUE = :ULTIMO_ESTOQUE - :QUANTIDADE;
        END
       ELSE
        BEGIN
          ULTIMO_ESTOQUE = :ULTIMO_ESTOQUE + :QUANTIDADE;
        END

       /*UPDATE LANCAMENTOS SET
        ESTOQUE_POSVENDA = :ULTIMO_ESTOQUE
       WHERE
        CD_LANCAMENTO = :CD_LANCAMENTO AND
        CD_FILIAL = :CD_FILIAL;
*/
       SUSPEND;
     END
   END
END ^

ALTER PROCEDURE SP_RECALCULA_MOVIMENTO_PRODUTO (CD_COMPRAS DOUBLE PRECISION)
RETURNS (CD_FILIAL DOUBLE PRECISION,
CD_LANCAMENTO DOUBLE PRECISION,
ID_PRODUTO DOUBLE PRECISION,
DATA DATE,
DATA_MOVIMENTO DATE,
HORA TIME,
ENTRADA_SAIDA VARCHAR(1) CHARACTER SET NONE,
ULTIMO_ESTOQUE DOUBLE PRECISION,
QUANTIDADE DOUBLE PRECISION)
AS 
DECLARE VARIABLE DATALANCAMENTO DATE;
DECLARE VARIABLE HORALANCAMENTO TIME;
BEGIN
  FOR
   SELECT
    LANCAMENTOS.CD_FILIAL,
    LANCAMENTOS.ID_PRODUTO,
    LANCAMENTOS.DATA_LANCAMENTO
   FROM
    LANCAMENTOS
   WHERE
    LANCAMENTOS.NUMERO = :CD_COMPRAS
   INTO
    :CD_FILIAL,
    :ID_PRODUTO,
    :DATA
  DO
   BEGIN
    SELECT MAX(DATA_LANCAMENTO) FROM LANCAMENTOS WHERE DATA_LANCAMENTO < :DATA AND LANCAMENTOS.ID_PRODUTO = :ID_PRODUTO INTO :DATALANCAMENTO;
    SELECT MAX(LANCAMENTOS.HORA) FROM LANCAMENTOS WHERE LANCAMENTOS.ID_PRODUTO = :ID_PRODUTO AND LANCAMENTOS.DATA_LANCAMENTO = :DATA INTO :HORALANCAMENTO;

    SELECT
      LANCAMENTOS.ESTOQUE_POSVENDA
    FROM
      LANCAMENTOS
    WHERE
     LANCAMENTOS.ID_PRODUTO = :ID_PRODUTO AND
     LANCAMENTOS.DATA_LANCAMENTO = :DATALANCAMENTO AND
     LANCAMENTOS.HORA = :HORALANCAMENTO
    GROUP BY
     LANCAMENTOS.ESTOQUE_POSVENDA
    INTO
     :ULTIMO_ESTOQUE;

    IF (:ULTIMO_ESTOQUE IS NULL) THEN
       ULTIMO_ESTOQUE = 0;

    FOR
     SELECT
      LANCAMENTOS.CD_LANCAMENTO,
      LANCAMENTOS.ENTRADA_SAIDA,
      LANCAMENTOS.DATA_LANCAMENTO,
      LANCAMENTOS.HORA,
      LANCAMENTOS.QUANTIDADE
     FROM
      LANCAMENTOS
     WHERE
      LANCAMENTOS.ID_PRODUTO = :ID_PRODUTO AND
      LANCAMENTOS.DATA_LANCAMENTO >= :DATA
     ORDER BY
      LANCAMENTOS.DATA_LANCAMENTO,
      LANCAMENTOS.HORA
     INTO
      :CD_LANCAMENTO,
      :ENTRADA_SAIDA,
      :DATA_MOVIMENTO,
      :HORA,
      :QUANTIDADE
    DO
     BEGIN
       IF (:ENTRADA_SAIDA = 'S') THEN
        BEGIN
          ULTIMO_ESTOQUE = :ULTIMO_ESTOQUE - :QUANTIDADE;
        END
       ELSE
        BEGIN
          ULTIMO_ESTOQUE = :ULTIMO_ESTOQUE + :QUANTIDADE;
        END

       /*UPDATE LANCAMENTOS SET
        ESTOQUE_POSVENDA = :ULTIMO_ESTOQUE
       WHERE
        CD_LANCAMENTO = :CD_LANCAMENTO AND
        CD_FILIAL = :CD_FILIAL;
*/
       SUSPEND;
     END
   END
END ^

ALTER PROCEDURE SP_RECALCULA_PRECO_PROMOCAO AS 
declare variable COMANDO varchar(10000);
declare variable CD_FILIAL double precision;
BEGIN
   COMANDO = 'UPDATE PRODUTOS SET ' ||
             'PRECO_PROMOCAO = PRECO_VENDA - ((PRECO_VENDA * MARGEM_PROMOCAO) / 100) ';

   FOR
     SELECT CD_FILIAL FROM FILIAIS WHERE EXPORTAR = 'S' INTO :CD_FILIAL
   DO
    BEGIN
      COMANDO = :COMANDO || ', PRECO_PROMOCAO_' || CAST(:CD_FILIAL AS INTEGER) ||
                            ' = PRECO_VENDA_' || CAST(:CD_FILIAL AS INTEGER) || ' - ((PRECO_VENDA_' || CAST(:CD_FILIAL AS INTEGER) || ' * MARGEM_PROMOCAO) / 100) ';
    END

   COMANDO = :COMANDO || ' WHERE MARGEM_PROMOCAO IS NOT NULL AND MARGEM_PROMOCAO > 0';

   EXECUTE STATEMENT :COMANDO;
END ^

ALTER PROCEDURE SP_RECALCULA_PRODUTOSTOTAIS AS 
DECLARE VARIABLE ID DOUBLE PRECISION;
DECLARE VARIABLE JANEIROVENDAS DOUBLE PRECISION;
DECLARE VARIABLE FEVEREIROVENDAS DOUBLE PRECISION;
DECLARE VARIABLE MARCOVENDAS DOUBLE PRECISION;
DECLARE VARIABLE ABRILVENDAS DOUBLE PRECISION;
DECLARE VARIABLE MAIOVENDAS DOUBLE PRECISION;
DECLARE VARIABLE JUNHOVENDAS DOUBLE PRECISION;
DECLARE VARIABLE JULHOVENDAS DOUBLE PRECISION;
DECLARE VARIABLE AGOSTOVENDAS DOUBLE PRECISION;
DECLARE VARIABLE SETEMBROVENDAS DOUBLE PRECISION;
DECLARE VARIABLE OUTUBROVENDAS DOUBLE PRECISION;
DECLARE VARIABLE NOVEMBROVENDAS DOUBLE PRECISION;
DECLARE VARIABLE DEZEMBROVENDAS DOUBLE PRECISION;
BEGIN
 FOR
   SELECT ID_PRODUTO,
          SUM(JANVENDA), SUM(FEVVENDA), SUM(MARVENDA), SUM(ABRVENDA), SUM(MAIVENDA), SUM(JUNVENDA),
          SUM(JULVENDA), SUM(AGOVENDA), SUM(SETVENDA), SUM(OUTVENDA), SUM(NOVVENDA), SUM(DEZVENDA)
   FROM PRODUTOS_TOTAIS WHERE CD_FILIAL > 0
   GROUP BY ID_PRODUTO
   INTO
    :ID,
    :JANEIROVENDAS, :FEVEREIROVENDAS, :MARCOVENDAS, :ABRILVENDAS, :MAIOVENDAS, :JUNHOVENDAS,
    :JULHOVENDAS, :AGOSTOVENDAS, :SETEMBROVENDAS, :OUTUBROVENDAS, :NOVEMBROVENDAS, :DEZEMBROVENDAS
 DO
  BEGIN
     UPDATE PRODUTOS_TOTAIS SET
       JANVENDA = :JANEIROVENDAS,
       FEVVENDA = :FEVEREIROVENDAS,
       MARVENDA = :MARCOVENDAS,
       ABRVENDA = :ABRILVENDAS,
       MAIVENDA = :MAIOVENDAS,
       JUNVENDA = :JUNHOVENDAS,
       JULVENDA = :JULHOVENDAS,
       AGOVENDA = :AGOSTOVENDAS,
       SETVENDA = :SETEMBROVENDAS,
       OUTVENDA = :OUTUBROVENDAS,
       NOVVENDA = :NOVEMBROVENDAS,
       DEZVENDA = :DEZEMBROVENDAS
     WHERE
       CD_FILIAL = 0 AND ID_PRODUTO =:ID;
  END
END ^

