ALTER PROCEDURE SP_RECALCULA_SALDOS_ESTOQUE (DATA_INICIAL DATE,
CD_FILIAL DOUBLE PRECISION)
RETURNS (ESTOQUE_LANCAMENTO DOUBLE PRECISION,
ESTOQUE_TOTAL DOUBLE PRECISION,
PRODUTO DOUBLE PRECISION)
AS 
declare variable CODIGO_LANCAMENTO double precision;
declare variable QUANTIDADE double precision;
declare variable TIPO_MOVIMENTO varchar(1);
declare variable COMANDO varchar(1000);
declare variable DATA_LANCAMENTO date;
declare variable HORA_LANCAMENTO time;
declare variable HORA time;
declare variable DATA date;
declare variable FILIAL double precision;
declare variable TIPO_VENDA varchar(1);
declare variable COMANDO1 varchar(1000);
declare variable ESTOQUE_ATUAL double precision;
BEGIN

 DELETE FROM TEMP_SUPORTE;

 COMANDO1 = 'SELECT ID_PRODUTO, ESTOQUE_' || CAST(:CD_FILIAL AS INTEGER) || ' FROM PRODUTOS';
 FOR
  EXECUTE STATEMENT :COMANDO1 INTO :PRODUTO, :ESTOQUE_ATUAL
 DO
  BEGIN
     FOR
      SELECT
       FIRST 1 CD_FILIAL, DATA_LANCAMENTO, HORA, ESTOQUE_POSVENDA
      FROM
       LANCAMENTOS
      WHERE
       DATA_LANCAMENTO >= :DATA_INICIAL AND CD_FILIAL = :CD_FILIAL AND
       ID_PRODUTO = :PRODUTO
      ORDER BY
       DATA_LANCAMENTO, HORA
      INTO
       :FILIAL, :DATA_LANCAMENTO, :HORA_LANCAMENTO, :ESTOQUE_LANCAMENTO
     DO
      BEGIN
        ESTOQUE_TOTAL = 0;
        ESTOQUE_TOTAL = :ESTOQUE_LANCAMENTO;
        IF (ESTOQUE_TOTAL IS NULL) THEN ESTOQUE_TOTAL = 0;
        FOR
         SELECT
          CD_LANCAMENTO, DATA_LANCAMENTO, HORA, QUANTIDADE, ENTRADA_SAIDA, TIPO_VENDA
         FROM
          LANCAMENTOS
         WHERE
          ID_PRODUTO = :PRODUTO AND
          CD_FILIAL = :FILIAL AND
          ((DATA_LANCAMENTO = :DATA_LANCAMENTO AND
          HORA > :HORA_LANCAMENTO) OR
          DATA_LANCAMENTO > :DATA_LANCAMENTO)
         ORDER BY
          DATA_LANCAMENTO, HORA
         INTO
          :CODIGO_LANCAMENTO, :DATA, :HORA, :QUANTIDADE, :TIPO_MOVIMENTO, :TIPO_VENDA
        DO
         BEGIN
           IF (:TIPO_VENDA = 'B') THEN
              ESTOQUE_TOTAL = :QUANTIDADE;
           ELSE
            BEGIN
               IF (:DATA = :DATA_LANCAMENTO) THEN
                BEGIN
                  IF (:HORA > :HORA_LANCAMENTO) THEN
                   BEGIN
                     IF (:TIPO_MOVIMENTO = 'E') THEN
                        ESTOQUE_TOTAL = :ESTOQUE_TOTAL + :QUANTIDADE;
                     ELSE
                     IF (:TIPO_MOVIMENTO = 'S') THEN
                        ESTOQUE_TOTAL = :ESTOQUE_TOTAL - :QUANTIDADE;
                   END
                END
               ELSE
                BEGIN
                     IF (:TIPO_MOVIMENTO = 'E') THEN
                        ESTOQUE_TOTAL = :ESTOQUE_TOTAL + :QUANTIDADE;
                     ELSE
                     IF (:TIPO_MOVIMENTO = 'S') THEN
                        ESTOQUE_TOTAL = :ESTOQUE_TOTAL - :QUANTIDADE;
                END
           END
         END
        IF (:ESTOQUE_TOTAL <> :ESTOQUE_ATUAL) THEN
         BEGIN
           COMANDO = 'INSERT INTO TEMP_SUPORTE VALUES (' || :PRODUTO ||', '''')';
           EXECUTE STATEMENT :COMANDO;
         END
      END
   END

 -- Tratando os produtos alterados
 FOR
  SELECT
   DISTINCT IDENTIFICADOR
  FROM
   TEMP_SUPORTE
  INTO
   :PRODUTO
 DO
  BEGIN
     FOR
      SELECT
       FIRST 1 CD_FILIAL, DATA_LANCAMENTO, HORA, ESTOQUE_POSVENDA
      FROM
       LANCAMENTOS
      WHERE
       DATA_LANCAMENTO >= :DATA_INICIAL AND CD_FILIAL = :CD_FILIAL AND
       ID_PRODUTO = :PRODUTO
      ORDER BY
       DATA_LANCAMENTO, HORA
      INTO
       :FILIAL, :DATA_LANCAMENTO, :HORA_LANCAMENTO, :ESTOQUE_LANCAMENTO
     DO
      BEGIN
        ESTOQUE_TOTAL = 0;
        ESTOQUE_TOTAL = :ESTOQUE_LANCAMENTO;
        IF (ESTOQUE_TOTAL IS NULL) THEN ESTOQUE_TOTAL = 0;
        FOR
         SELECT
          CD_LANCAMENTO, DATA_LANCAMENTO, HORA, QUANTIDADE, ENTRADA_SAIDA, TIPO_VENDA
         FROM
          LANCAMENTOS
         WHERE
          ID_PRODUTO = :PRODUTO AND
          CD_FILIAL = :FILIAL AND
          ((DATA_LANCAMENTO = :DATA_LANCAMENTO AND
          HORA > :HORA_LANCAMENTO) OR
          DATA_LANCAMENTO > :DATA_LANCAMENTO)
         ORDER BY
          DATA_LANCAMENTO, HORA
         INTO
          :CODIGO_LANCAMENTO, :DATA, :HORA, :QUANTIDADE, :TIPO_MOVIMENTO, :TIPO_VENDA
        DO
         BEGIN
           IF (:TIPO_VENDA = 'B') THEN
              ESTOQUE_TOTAL = :QUANTIDADE;
           ELSE
            BEGIN
               IF (:DATA = :DATA_LANCAMENTO) THEN
                BEGIN
                  IF (:HORA > :HORA_LANCAMENTO) THEN
                   BEGIN
                     IF (:TIPO_MOVIMENTO = 'E') THEN
                        ESTOQUE_TOTAL = :ESTOQUE_TOTAL + :QUANTIDADE;
                     ELSE
                     IF (:TIPO_MOVIMENTO = 'S') THEN
                        ESTOQUE_TOTAL = :ESTOQUE_TOTAL - :QUANTIDADE;
                     UPDATE LANCAMENTOS SET ESTOQUE_POSVENDA = :ESTOQUE_TOTAL WHERE CD_LANCAMENTO = :CODIGO_LANCAMENTO AND CD_FILIAL = :FILIAL;
                   END
                END
               ELSE
                BEGIN
                     IF (:TIPO_MOVIMENTO = 'E') THEN
                        ESTOQUE_TOTAL = :ESTOQUE_TOTAL + :QUANTIDADE;
                     ELSE
                     IF (:TIPO_MOVIMENTO = 'S') THEN
                        ESTOQUE_TOTAL = :ESTOQUE_TOTAL - :QUANTIDADE;
                     UPDATE LANCAMENTOS SET ESTOQUE_POSVENDA = :ESTOQUE_TOTAL WHERE CD_LANCAMENTO = :CODIGO_LANCAMENTO AND CD_FILIAL = :FILIAL;
                END
           END
         END
        -- ALTERANDO O ESTOQUE DO PRODUTO
        COMANDO = 'UPDATE PRODUTOS SET ESTOQUE_'||CAST(:FILIAL AS INTEGER)||' = ' || :ESTOQUE_TOTAL || ' WHERE ID_PRODUTO = ' || :PRODUTO;
        EXECUTE STATEMENT :COMANDO;
      END
   END
 -- Tratando os produtos alterados

END ^

ALTER PROCEDURE SP_RECALCULA_SALDO_CONTA (CONTA DOUBLE PRECISION,
DATA DATE)
AS 
declare variable DATAANTERIOR date;
declare variable SALDOANTERIOR double precision;
declare variable CREDITO double precision;
declare variable DEBITO double precision;
declare variable VALORSALDO double precision;
declare variable CMV double precision;
BEGIN
   SELECT CONTACUSTOVENDA FROM PARAMETROS INTO :CMV;

   SALDOANTERIOR = 0;
   CREDITO = 0;
   DEBITO = 0;
   VALORSALDO = 0;

   SELECT
    SUM(VALOR)
   FROM
    MOVIMENTOCAIXA
   WHERE
    DATA = :DATA AND
    CD_CONTA = :CONTA AND
    TIPO_MOVIMENTO = 'C' AND
    CD_PLANO_CONTAS <> :CMV
   INTO
    :CREDITO;

   IF (:CREDITO IS NULL) THEN
    BEGIN
      CREDITO = 0;
    END

   SELECT
    SUM(VALOR)
   FROM
    MOVIMENTOCAIXA
   WHERE
    DATA = :DATA AND
    CD_CONTA = :CONTA AND
    TIPO_MOVIMENTO = 'D' AND
    CD_PLANO_CONTAS <> :CMV
   INTO
    :DEBITO;

   IF (:DEBITO IS NULL) THEN
    BEGIN
      DEBITO = 0;
    END

   SELECT
    MAX(DATA)
   FROM
    SALDO
   WHERE
    CD_CONTA = :CONTA AND
    DATA < :DATA
   INTO
    :DATAANTERIOR;

   IF (:DATAANTERIOR IS NOT NULL) THEN
    BEGIN
       SELECT
        SALDO.SALDO
       FROM
        SALDO
       WHERE
        SALDO.CD_CONTA = :CONTA AND
        SALDO.DATA = :DATAANTERIOR
       INTO
        SALDOANTERIOR;
    END
   ELSE
    BEGIN
       SALDOANTERIOR = 0;
    END

   IF (:SALDOANTERIOR IS NULL) THEN
     SALDOANTERIOR = 0;
   VALORSALDO = :SALDOANTERIOR + :CREDITO - :DEBITO;

   UPDATE SALDO SET
    SALDO = :VALORSALDO
   WHERE CD_CONTA = :CONTA AND DATA = :DATA;

   SUSPEND;

END ^

ALTER PROCEDURE SP_RECALCULA_SALDO_CONTA_DATA (DATA_INICIAL DATE,
CONTA DOUBLE PRECISION)
AS 
BEGIN
  WHILE (:DATA_INICIAL <= CURRENT_DATE) DO
   BEGIN
     EXECUTE PROCEDURE SP_RECALCULA_SALDO_CONTA(:CONTA, :DATA_INICIAL);
     DATA_INICIAL = DATA_INICIAL + 1;
   END
END ^

ALTER PROCEDURE SP_RECALCULA_SALDO_MOV_PRODUTO (DATA DATE)
RETURNS (CD_FILIAL DOUBLE PRECISION,
CD_LANCAMENTO DOUBLE PRECISION,
ID_PRODUTO DOUBLE PRECISION,
DATA_MOVIMENTO DATE,
HORA TIME,
ENTRADA_SAIDA VARCHAR(1) CHARACTER SET NONE,
ULTIMO_ESTOQUE DOUBLE PRECISION,
QUANTIDADE DOUBLE PRECISION)
AS 
BEGIN
  FOR
   SELECT
    DISTINCT
    LANCAMENTOS.CD_FILIAL,
    LANCAMENTOS.ID_PRODUTO
   FROM
    LANCAMENTOS
   WHERE
    LANCAMENTOS.DATA_LANCAMENTO >= :DATA /*AND ID_PRODUTO = 94257*/
   INTO
    :CD_FILIAL,
    :ID_PRODUTO
  DO
   BEGIN
    SELECT
      MAX(LANCAMENTOS.CD_LANCAMENTO)
    FROM
      LANCAMENTOS
    WHERE
     LANCAMENTOS.ID_PRODUTO = :ID_PRODUTO AND
     LANCAMENTOS.DATA_LANCAMENTO < :DATA
    INTO 
     :CD_LANCAMENTO;

    SELECT
      ESTOQUE_POSVENDA
    FROM
      LANCAMENTOS
    WHERE
     LANCAMENTOS.CD_LANCAMENTO = :CD_LANCAMENTO
    INTO
     :ULTIMO_ESTOQUE;

    IF (:ULTIMO_ESTOQUE IS NULL) THEN
       ULTIMO_ESTOQUE = 0;

    FOR
     SELECT
      LANCAMENTOS.CD_LANCAMENTO,
      LANCAMENTOS.ENTRADA_SAIDA,
      LANCAMENTOS.DATA_LANCAMENTO,
      LANCAMENTOS.HORA,
      LANCAMENTOS.QUANTIDADE
     FROM
      LANCAMENTOS
     WHERE
      LANCAMENTOS.ID_PRODUTO = :ID_PRODUTO AND
      LANCAMENTOS.DATA_LANCAMENTO >= :DATA
     ORDER BY
      LANCAMENTOS.DATA_LANCAMENTO,
      LANCAMENTOS.HORA
     INTO
      :CD_LANCAMENTO,
      :ENTRADA_SAIDA,
      :DATA_MOVIMENTO,
      :HORA,
      :QUANTIDADE
    DO
     BEGIN
       IF (:ENTRADA_SAIDA = 'S') THEN
        BEGIN
          ULTIMO_ESTOQUE = :ULTIMO_ESTOQUE - :QUANTIDADE;
        END
       ELSE
        BEGIN
          ULTIMO_ESTOQUE = :ULTIMO_ESTOQUE + :QUANTIDADE;
        END

       UPDATE LANCAMENTOS SET
        ESTOQUE_POSVENDA = :ULTIMO_ESTOQUE
       WHERE
        CD_LANCAMENTO = :CD_LANCAMENTO AND
        CD_FILIAL = :CD_FILIAL;
       SUSPEND;
     END
   END
END ^

