  ICMS_BASE_CALCULO_FCP_ST = 0;
  ICMS_PERCENTUAL_FCP_ST = 0;
  ICMS_VALOR_FCP_ST = 0;
  ICMS_BASE_CALCULO_FCP_ST_RETIDO = 0;
  ICMS_PERCENTUAL_FCP_ST_RETIDO = 0;
  ICMS_VALOR_FCP_ST_RETIDO = 0;

  FOR
    SELECT
      COD_NF_ENTRADA,
      CD_FILIAL,
      DATAHORA,
      NUM_NF
    FROM
      SINTEGRA_NF_ENTRADA
    WHERE
      CAST(DATAHORA AS DATE) >= :DATAINICIAL AND
      CAST(DATAHORA AS DATE) <= :DATAFINAL AND
      EMITENTE_NF = 'P' AND
      COD_NF_ENTRADA NOT IN (SELECT DISTINCT COD_NF_ENTRADA FROM SINTEGRA_NF_ENTRADA_ITENS
                             WHERE CAST(DATAHORA AS DATE) >= :DATAINICIAL AND CAST(DATAHORA AS DATE) <= :DATAFINAL)
    INTO
      :COD_NF_ENTRADA,
      :CD_FILIAL,
      :DATAHORA,
      :NOTAFISCAL
  DO
   BEGIN
      SELECT ID_NFECABECALHO FROM NFECABECALHO WHERE IDENOTAFISCAL = :NOTAFISCAL INTO :ID_NFECABECALHO;

      FOR
        SELECT
         ICMSPERCENTUAL, UNIDADECOMERCIALIZADA, ICMSVALORBASECALCULO, ICMSBASECALCULOSUBSTITUICAO, CFOP,
         ITEM, DESCRICAOPRODUTO, QUANTIDADECOMERCIALIZADA, ICMSPERCENTUALREDUCAOBC, EAN, VALORPRODUTO,
         ICMSCST, VALORUNITARIOCOMERCIALIZADO, VALORDESCONTO, ICMSVALOR,
         IPICST, IPIBASECALCULO, ICMSBASECALCULOSUBSTITUICAORET, ICMSPERCENTUALSTRET, ICMSVALORSUBSTITUICAORET,
         ICMSVALORBCFCP, ICMSPERCENTUALFCP, ICMSVALORFCP, ICMSVALORBCFCPST, ICMSPERCENTUALFCPST, ICMSVALORFCPST,
         ICMSVALORBCFCPSTRET, ICMSPERCENTUALFCPSTRET, ICMSVALORFCPSTRET,
         ICMSCODIGOBENEFICIO, ICMSMOTIVODESONERACAO, ICMSVALORDESONERACAO, ICMSPERCENTUALDESONERACAO
        FROM
         NFEITENS
        WHERE
         ID_NFECABECALHO = :ID_NFECABECALHO
        INTO
         :ALIQUOTA_ICMS, :APR_UND, :BASE_ICMS, :BASE_ICMS_SUBST, :CFOP,
         :NUM_ITEM, :PRODUTO, :QUANTIDADE, :REDUCAO_BASE_ICMS, :REF_PRODUTOS, :SUBTOTAL,
         :S_TRIB, :PRC_CUSTO,:VALOR_DESCONTO, :VALOR_ICMS,
         :IPI_CST, :IPI_BASE_CALCULO, :ICMS_BASE_CALCULO_ST_RETIDO, :ICMS_PERCENTUAL_ST_RETIDO, :ICMS_VALOR_ST_RETIDO,
         :ICMS_BASE_CALCULO_FCP, :ICMS_PERCENTUAL_FCP, :ICMS_VALOR_FCP, :ICMS_BASE_CALCULO_FCP_ST, :ICMS_PERCENTUAL_FCP_ST, :ICMS_VALOR_FCP_ST,
         :ICMS_BASE_CALCULO_FCP_ST_RETIDO, :ICMS_PERCENTUAL_FCP_ST_RETIDO, :ICMS_VALOR_FCP_ST_RETIDO,
         :ICMS_CODBENEFICIO, :ICMS_MOTIVODESONERACAO, :ICMS_VALOR_DESONERACAO, :ICMS_PERCENTUAL_DESONERACAO
      DO
       BEGIN
          SELECT ID FROM SP_RETORNAID('COD_NF_ENTRADA_ITENS') INTO :COD_NF_ENTRADA_ITENS;

          INSERT INTO SINTEGRA_NF_ENTRADA_ITENS VALUES (
          :COD_NF_ENTRADA_ITENS, :CD_FILIAL, :COD_NF_ENTRADA, :COD_PRODUTOS, :REF_PRODUTOS, :NUM_ITEM,
          :CL_FIS, :S_TRIB, :PRODUTO, :COD_GRUPOP, :COD_SUBGRUPOP, :DATAHORA, :QUANTIDADE, :PRC_CUSTO,
          :VALOR_DESCONTO, :VALOR_IPI, :SUBTOTAL, :BASE_ICMS, :BASE_ICMS_SUBST, :VALOR_ICMS,
          :ENABLE_NUMSERIE, :OBS, :ENABLED, :ULTATUAL, :ULTATUALCODSETOR, :ULTATUALCODSETORUSER,
          :APR_UND, :PERC_DESCONTO, :ALIQUOTA_IPI, :ALIQUOTA_ICMS, :REDUCAO_BASE_ICMS, :ENVIADO,
          :CFOP, :VALOR_ICMS_SUBSTITUICAO, :MARGEM_VALOR_AGREGADO, :REDUCAO_ICMS_ST, :PERCENTUAL_ICMS_ST,
          :PIS_CST, :PIS_BASE_CALCULO, :PIS_PERCENTUAL, :PIS_VALOR,
          :COFINS_CST, :COFINS_BASE_CALCULO, :COFINS_PERCENTUAL, :COFINS_VALOR,
          :VALOR_OUTRASDESPESAS, :VALOR_FRETE, :VALOR_SEGURO, :VALOR_ISENTO,
          :IPI_CST, :IPI_BASE_CALCULO,
          :ICMS_BASE_CALCULO_ST_RETIDO, :ICMS_PERCENTUAL_ST_RETIDO, :ICMS_VALOR_ST_RETIDO,
          :ICMS_BASE_CALCULO_FCP, :ICMS_PERCENTUAL_FCP, :ICMS_VALOR_FCP,
          :ICMS_BASE_CALCULO_FCP_ST, :ICMS_PERCENTUAL_FCP_ST, :ICMS_VALOR_FCP_ST,
          :ICMS_BASE_CALCULO_FCP_ST_RETIDO, :ICMS_PERCENTUAL_FCP_ST_RETIDO, :ICMS_VALOR_FCP_ST_RETIDO,
          :REDUCAO_BASE_ICMS, :ICMS_CODBENEFICIO, :ICMS_MOTIVODESONERACAO, :ICMS_VALOR_DESONERACAO, :ICMS_PERCENTUAL_DESONERACAO
          );
       END
   END

FOR
    SELECT
      COD_NF_ENTRADA,
      CD_FILIAL,
      DATAHORA,
      NUM_NF,
      SERIE_NF,
      CNPJ_FORNECEDOR
    FROM
      SINTEGRA_NF_ENTRADA
    WHERE
      CAST(DATAHORA AS DATE) >= :DATAINICIAL AND
      CAST(DATAHORA AS DATE) <= :DATAFINAL AND
      EMITENTE_NF = 'T' AND
      COD_NF_ENTRADA NOT IN (SELECT DISTINCT COD_NF_ENTRADA FROM SINTEGRA_NF_ENTRADA_ITENS
                             WHERE DATAHORA >= :DATAINICIAL AND DATAHORA <= :DATAFINAL)
    INTO
      :COD_NF_ENTRADA,
      :CD_FILIAL,
      :DATAHORA,
      :NOTAFISCAL,
      :SERIE_NF,
      :CNPJ_FORNECEDOR
  DO
   BEGIN
      SELECT CD_COMPRAS FROM COMPRAS
      WHERE DT_ENTRADA >= :DATAINICIAL AND DT_ENTRADA <= :DATAFINAL AND NOTA_FISCAL = :NOTAFISCAL AND SERIE_NOTA_FISCAL = :SERIE_NF AND STATUS = 'C'
      INTO :CD_COMPRAS;

      NUM_ITEM = 1;
      FOR
        SELECT
         ITENS_COMPRA.PERCENTUAL_ICMS, ITENS_COMPRA.UNIDADE, ITENS_COMPRA.BASEICMS, ITENS_COMPRA.BASEICMSSUBSTITUICAO,
         ITENS_COMPRA.CFOP, ITENS_COMPRA.DESCRICAO, ITENS_COMPRA.QUANTIDADE, ITENS_COMPRA.REDUCAO_ICMS,
         ITENS_COMPRA.CODIGO_BARRAS, ITENS_COMPRA.VL_TOTAL, ITENS_COMPRA.SITUACAOTRIBITARIA, ITENS_COMPRA.VL_UNITARIO,
         ITENS_COMPRA.VL_DESCONTO, ITENS_COMPRA.VL_ICMS, ITENS_COMPRA.VALOR_OUTRASDESPESAS,
         ITENS_COMPRA.VALOR_SEGURO, ITENS_COMPRA.VALOR_FRETE, ITENS_COMPRA.VALOR_ISENTO,
         ITENS_COMPRA.CST_IPI, ITENS_COMPRA.BASECALCULO_IPI, ITENS_COMPRA.BASEICMSSUBSTITUICAORET,
         ITENS_COMPRA.PERCENTUAL_ICMS_ST_RET, ITENS_COMPRA.VALORICMSSUBSTITUICAORET,
         ITENS_COMPRA.BASECALCULOFCP, ITENS_COMPRA.ALIQUOTAFCP, ITENS_COMPRA.VALORFCP,
         ITENS_COMPRA.BASECALCULOFCPST, ITENS_COMPRA.ALIQUOTAFCPST, ITENS_COMPRA.VALORFCPST,
         ITENS_COMPRA.BASECALCULOFCPSTRET, ITENS_COMPRA.ALIQUOTAFCPSTRET, ITENS_COMPRA.VALORFCPSTRET,
         ITENS_COMPRA.CODIGOBENEFICIO, ITENS_COMPRA.MOTIVODESONERACAO, ITENS_COMPRA.VALORDESONERACAO, ITENS_COMPRA.PERCENTUALDESONERACAO

        FROM
         ITENS_COMPRA
        WHERE
         CD_COMPRAS = :CD_COMPRAS
        INTO
         :ALIQUOTA_ICMS, :APR_UND, :BASE_ICMS, :BASE_ICMS_SUBST, :CFOP, :PRODUTO, :QUANTIDADE, :REDUCAO_BASE_ICMS,
         :REF_PRODUTOS, :SUBTOTAL, :S_TRIB, :PRC_CUSTO, :VALOR_DESCONTO, :VALOR_ICMS, :VALOR_OUTRASDESPESAS,
         :VALOR_SEGURO, :VALOR_FRETE, :VALOR_ISENTO,
         :IPI_CST, :IPI_BASE_CALCULO,
         :ICMS_BASE_CALCULO_ST_RETIDO, :ICMS_PERCENTUAL_ST_RETIDO, :ICMS_VALOR_ST_RETIDO,
         :ICMS_BASE_CALCULO_FCP, :ICMS_PERCENTUAL_FCP, :ICMS_VALOR_FCP,
         :ICMS_BASE_CALCULO_FCP_ST, :ICMS_PERCENTUAL_FCP_ST, :ICMS_VALOR_FCP_ST,
         :ICMS_BASE_CALCULO_FCP_ST_RETIDO, :ICMS_PERCENTUAL_FCP_ST_RETIDO, :ICMS_VALOR_FCP_ST_RETIDO,
         :ICMS_CODBENEFICIO, :ICMS_MOTIVODESONERACAO, :ICMS_VALOR_DESONERACAO, :ICMS_PERCENTUAL_DESONERACAO

      DO
       BEGIN
          SELECT ID FROM SP_RETORNAID('COD_NF_ENTRADA_ITENS') INTO :COD_NF_ENTRADA_ITENS;

          INSERT INTO SINTEGRA_NF_ENTRADA_ITENS VALUES (
          :COD_NF_ENTRADA_ITENS, :CD_FILIAL, :COD_NF_ENTRADA, :COD_PRODUTOS, :REF_PRODUTOS, :NUM_ITEM, :CL_FIS,
          :S_TRIB, :PRODUTO, :COD_GRUPOP, :COD_SUBGRUPOP, :DATAHORA, :QUANTIDADE, :PRC_CUSTO, :VALOR_DESCONTO,
          :VALOR_IPI, :SUBTOTAL, :BASE_ICMS, :BASE_ICMS_SUBST, :VALOR_ICMS, :ENABLE_NUMSERIE, :OBS, :ENABLED,
          :ULTATUAL, :ULTATUALCODSETOR, :ULTATUALCODSETORUSER, :APR_UND, :PERC_DESCONTO, :ALIQUOTA_IPI,
          :ALIQUOTA_ICMS, :REDUCAO_BASE_ICMS, :ENVIADO, :CFOP, :VALOR_ICMS_SUBSTITUICAO, :MARGEM_VALOR_AGREGADO,
          :REDUCAO_ICMS_ST, :PERCENTUAL_ICMS_ST, :PIS_CST, :PIS_BASE_CALCULO, :PIS_PERCENTUAL, :PIS_VALOR,
          :COFINS_CST, :COFINS_BASE_CALCULO, :COFINS_PERCENTUAL, :COFINS_VALOR, :VALOR_OUTRASDESPESAS, :VALOR_FRETE,
          :VALOR_SEGURO, :VALOR_ISENTO,
          :IPI_CST, :IPI_BASE_CALCULO,
          :ICMS_BASE_CALCULO_ST_RETIDO, :ICMS_PERCENTUAL_ST_RETIDO, :ICMS_VALOR_ST_RETIDO,
          :ICMS_BASE_CALCULO_FCP, :ICMS_PERCENTUAL_FCP, :ICMS_VALOR_FCP,
          :ICMS_BASE_CALCULO_FCP_ST, :ICMS_PERCENTUAL_FCP_ST, :ICMS_VALOR_FCP_ST,
          :ICMS_BASE_CALCULO_FCP_ST_RETIDO, :ICMS_PERCENTUAL_FCP_ST_RETIDO, :ICMS_VALOR_FCP_ST_RETIDO,
          :REDUCAO_BASE_ICMS, :ICMS_CODBENEFICIO, :ICMS_MOTIVODESONERACAO, :ICMS_VALOR_DESONERACAO, :ICMS_PERCENTUAL_DESONERACAO
          );

          NUM_ITEM = NUM_ITEM + 1;
       END
   END
END ^

ALTER PROCEDURE SP_RECUPERA_COMPRAS_NFE (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (CD_COMPRAS DOUBLE PRECISION,
CD_DISTRIBUIDOR DOUBLE PRECISION,
DISTRIBUIDOR VARCHAR(100) CHARACTER SET NONE,
NOTA_FISCAL VARCHAR(20) CHARACTER SET NONE,
DATAEMISSAO DATE,
DATAENTRADA DATE,
VALORTOTALPRODUTOS DOUBLE PRECISION,
VALORTOTALNOTA DOUBLE PRECISION,
STATUS VARCHAR(1) CHARACTER SET NONE,
CHAVENFE VARCHAR(100) CHARACTER SET NONE,
SERIE_NOTA_FISCAL VARCHAR(100) CHARACTER SET NONE,
MODELONF VARCHAR(100) CHARACTER SET NONE,
DT_EMISSAO DATE)
AS 
BEGIN
 FOR
    SELECT
     COMPRAS.CD_COMPRAS,
     COMPRAS.CD_DISTRIBUIDOR,
     DISTRIBUIDORES.NOME,
     COMPRAS.NOTA_FISCAL, 
     COMPRAS.DT_EMISSAO,
     COMPRAS.DT_ENTRADA,
     COMPRAS.VL_TOTALPRODUTOS,
     COMPRAS.TOTAL_NOTA,
     COMPRAS.STATUS,
     COMPRAS.CHAVENFE,
     COMPRAS.SERIE_NOTA_FISCAL,
     COMPRAS.MODELONF,
     COMPRAS.DT_EMISSAO
    FROM
     COMPRAS,
     DISTRIBUIDORES
    WHERE
     COMPRAS.CD_DISTRIBUIDOR = DISTRIBUIDORES.CD_DISTRIBUIDOR AND
     COMPRAS.DT_EMISSAO >= :DATAINICIAL AND
     COMPRAS.DT_EMISSAO <= :DATAFINAL AND
     ((COMPRAS.STATUS = 'C') OR (COMPRAS.STATUS = 'D'))
    INTO
     :CD_COMPRAS, :CD_DISTRIBUIDOR, :DISTRIBUIDOR, :NOTA_FISCAL, :DATAEMISSAO, :DATAENTRADA, :VALORTOTALPRODUTOS, :VALORTOTALNOTA, :STATUS, :CHAVENFE, :SERIE_NOTA_FISCAL, :MODELONF, :DT_EMISSAO
 DO
  BEGIN
    SUSPEND;
  END
END ^

ALTER PROCEDURE SP_RECUPERA_DEVOLUCOES_NFE (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (CD_VENDA DOUBLE PRECISION,
TROCA VARCHAR(1) CHARACTER SET NONE,
DATA_LANCAMENTO DATE,
CD_CLIENTE DOUBLE PRECISION,
NOME VARCHAR(100) CHARACTER SET NONE,
CD_CONVENIO DOUBLE PRECISION,
CONVENIO VARCHAR(100) CHARACTER SET NONE,
CD_FORMA_PAGAMENTO DOUBLE PRECISION,
FORMA_PAGAMENTO VARCHAR(100) CHARACTER SET NONE,
NUMERO DOUBLE PRECISION,
VALOR DOUBLE PRECISION,
TIPO_VENDA VARCHAR(1) CHARACTER SET NONE,
CHAVENFE VARCHAR(100) CHARACTER SET NONE)
AS 
declare variable EXISTEDEVOLUCAO integer;
BEGIN

 FOR
    SELECT 
     CAIXA.CD_VENDA, CAIXA.TROCA, CAIXA.DATA, CAIXA.TIPO_VENDA,
     CAIXA.CD_CLIENTE, CLIENTES.NOME, CAIXA.CD_CONVENIO, CONVENIOS.NOME, CAIXA.NUMERO,
     CAIXA.CD_FORMA_PAGAMENTO, FORMAS_PAGAMENTO.DESCRICAO,
     SUM(CAIXA.VALOR)
    FROM
     CAIXA LEFT OUTER JOIN CLIENTES ON CAIXA.CD_CLIENTE = CLIENTES.CD_CLIENTE
           LEFT OUTER JOIN CONVENIOS ON CAIXA.CD_CONVENIO = CONVENIOS.CD_CONVENIO,
     FORMAS_PAGAMENTO
    WHERE
     CAIXA.CD_FORMA_PAGAMENTO = FORMAS_PAGAMENTO.CD_FORMA_PAGAMENTO AND
     CAIXA.DATA >= :DATAINICIAL AND
     CAIXA.DATA <= :DATAFINAL AND
     (CAIXA.TIPO_VENDA = 'D' OR
      CAIXA.TROCA = 'T')
    GROUP BY
     CAIXA.CD_VENDA, CAIXA.TROCA, CAIXA.DATA, CAIXA.TIPO_VENDA,
     CAIXA.CD_CLIENTE, CLIENTES.NOME, CAIXA.CD_CONVENIO, CONVENIOS.NOME, CAIXA.NUMERO,
     CAIXA.CD_FORMA_PAGAMENTO, FORMAS_PAGAMENTO.DESCRICAO
    INTO
     :CD_VENDA, :TROCA, :DATA_LANCAMENTO, :TIPO_VENDA, :CD_CLIENTE, :NOME, :CD_CONVENIO, :CONVENIO, :NUMERO, :CD_FORMA_PAGAMENTO, :FORMA_PAGAMENTO, :VALOR
 DO
  BEGIN
    CHAVENFE = '';
    SELECT COUNT(*)
    FROM CAIXA
    WHERE
     CD_VENDA = :CD_VENDA AND
     TIPO_VENDA = 'D'
     /*AND
     (TROCA = 'F' OR TROCA = 'N')*/
    INTO
     :EXISTEDEVOLUCAO;

    SELECT NFCE.CHAVE FROM NFCE WHERE CD_VENDA = :CD_VENDA INTO :CHAVENFE;

    --IF (:EXISTEDEVOLUCAO = 0) THEN
       SUSPEND;
  END
END ^

ALTER PROCEDURE SP_RECUPERA_PREVENDAS_NFE (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (CD_VENDA DOUBLE PRECISION,
DATA_CAIXA DATE,
HORA TIME,
ID_VENDA VARCHAR(13) CHARACTER SET NONE,
TIPO_VENDA VARCHAR(1) CHARACTER SET NONE,
TROCA VARCHAR(1) CHARACTER SET NONE,
ENTREGA VARCHAR(1) CHARACTER SET NONE,
NITENS INTEGER,
TOTAL DOUBLE PRECISION,
CLIENTE VARCHAR(60) CHARACTER SET NONE,
ENDERECO VARCHAR(60) CHARACTER SET NONE,
TELEFONE VARCHAR(60) CHARACTER SET NONE,
CONVENIO VARCHAR(60) CHARACTER SET NONE,
STATUS VARCHAR(1) CHARACTER SET NONE,
VENDEDOR VARCHAR(100) CHARACTER SET NONE,
VENDEDORBALCAO VARCHAR(100) CHARACTER SET NONE,
AUTORIZACAOTRN VARCHAR(100) CHARACTER SET NONE,
CD_CLIENTE DOUBLE PRECISION,
CD_CONVENIO DOUBLE PRECISION,
CD_FILIAL DOUBLE PRECISION)
AS 
declare variable CD_ENTREGADOR double precision;
declare variable CD_VENDEDORBALCAO double precision;
BEGIN
  SELECT CD_FILIAL FROM PARAMETROS INTO :CD_FILIAL;
  FOR
    SELECT
     VENDAS.CD_VENDA,
     VENDAS.DATA_CAIXA,
     VENDAS.ID_VENDA,
     VENDAS.TIPO_VENDA,
     VENDAS.TROCA,
     VENDAS.ENTREGA,
     VENDAS.CD_CLIENTE,
     VENDAS.CD_CONVENIO,
     VENDAS.STATUS, 
     COUNT(VENDAS.ORDEM) AS NITENS
    FROM 
     VENDAS
    WHERE
     VENDAS.TIPO_VENDA = 'V' AND
     VENDAS.CONCLUIDO = 'N' AND
     VENDAS.STATUS <> 'C' AND
     VENDAS.CD_VENDA IS NOT NULL AND
     VENDAS.DATA_CAIXA >= :DATAINICIAL AND
     VENDAS.DATA_CAIXA <= :DATAFINAL AND
     VENDAS.CD_FILIAL = :CD_FILIAL
    GROUP BY
     VENDAS.CD_VENDA,
     VENDAS.DATA_CAIXA,
     VENDAS.ID_VENDA,
     VENDAS.TIPO_VENDA,
     VENDAS.TROCA,
     VENDAS.ENTREGA,
     VENDAS.CD_CLIENTE,
     VENDAS.CD_CONVENIO,
     VENDAS.STATUS
    ORDER BY
     VENDAS.CD_VENDA
    INTO
     :CD_VENDA,
     :DATA_CAIXA,
     :ID_VENDA,
     :TIPO_VENDA,
     :TROCA,
     :ENTREGA,
     :CD_CLIENTE,
     :CD_CONVENIO,
     :STATUS,
     :NITENS
  DO
   BEGIN
    SELECT
     SUM(PRECO_TOTAL - ARREDONDAMENTO)
    FROM
     VENDAS
    WHERE
     CD_VENDA = :CD_VENDA AND
     TIPO_VENDA <> 'Y' AND
     CD_FILIAL = :CD_FILIAL
    INTO
     :TOTAL;

    SELECT
     FIRST 1 HORA
    FROM
     VENDAS
    WHERE
     CD_VENDA = :CD_VENDA AND
     CD_FILIAL = :CD_FILIAL
    INTO
     :HORA;

    ENDERECO = '';
    SELECT
     FIRST 1 TEMPENDERECO
    FROM
     VENDAS
    WHERE
     CD_VENDA = :CD_VENDA AND
     CD_FILIAL = :CD_FILIAL
    INTO
     :ENDERECO;

    SELECT
     FIRST 1 VENDAS.CD_VENDEDOR
    FROM
     VENDAS
    WHERE
     VENDAS.CD_VENDA = :CD_VENDA AND
     CD_FILIAL = :CD_FILIAL
    INTO :CD_VENDEDORBALCAO;

    SELECT
     FIRST 1 VENDAS.AUTORIZACAOTRN
    FROM
     VENDAS
    WHERE
     VENDAS.CD_VENDA = :CD_VENDA AND
     CD_FILIAL = :CD_FILIAL
    INTO :AUTORIZACAOTRN;

    SELECT NOME FROM VENDEDORES WHERE CD_VENDEDOR = :CD_VENDEDORBALCAO INTO :VENDEDORBALCAO;

    CLIENTE = ''; TELEFONE = '';
    IF ((:CD_CLIENTE IS NOT NULL) AND (:CD_CLIENTE > 0)) THEN
     BEGIN
       SELECT NOME, FONE FROM CLIENTES
       WHERE CD_CLIENTE = :CD_CLIENTE
       INTO :CLIENTE, :TELEFONE;

       SELECT ENTREGAS.CD_ENTREGADOR, VENDEDORES.NOME FROM ENTREGAS, VENDEDORES
       WHERE ENTREGAS.CD_ENTREGADOR = VENDEDORES.CD_VENDEDOR AND ENTREGAS.CD_VENDA = :CD_VENDA
       GROUP BY ENTREGAS.CD_ENTREGADOR, VENDEDORES.NOME
       INTO :CD_ENTREGADOR, :VENDEDOR;
     END

    CONVENIO = '';
    IF ((:CD_CONVENIO IS NOT NULL) AND (:CD_CONVENIO > 0)) THEN
     BEGIN
       SELECT NOME FROM CONVENIOS
       WHERE CD_CONVENIO = :CD_CONVENIO
       INTO :CONVENIO;

       SELECT ENTREGAS.CD_ENTREGADOR, VENDEDORES.NOME FROM ENTREGAS, VENDEDORES
       WHERE ENTREGAS.CD_ENTREGADOR = VENDEDORES.CD_VENDEDOR AND ENTREGAS.CD_VENDA = :CD_VENDA
       GROUP BY ENTREGAS.CD_ENTREGADOR, VENDEDORES.NOME
       INTO :CD_ENTREGADOR, :VENDEDOR;
     END

     SUSPEND;
   END
END ^

ALTER PROCEDURE SP_RECUPERA_VALORES_SINTEGRA (DATAINICIAL DATE,
DATAFINAL DATE)
AS 
declare variable CD_COMPRAS double precision;
declare variable NOTA_FISCAL varchar(100);
declare variable VL_TOTALPRODUTOS numeric(15,3);
declare variable VL_DESCONTO_NOTA numeric(15,3);
declare variable TOTAL_NOTA numeric(15,3);
declare variable COD_NF_ENTRADA double precision;
declare variable CODIGO_BARRAS varchar(100);
declare variable VL_DESCONTO numeric(15,4);
declare variable VL_TOTAL numeric(15,3);
BEGIN
  FOR
    SELECT COMPRAS.CD_COMPRAS, COMPRAS.NOTA_FISCAL, COMPRAS.VL_TOTALPRODUTOS, COMPRAS.VL_DESCONTO_NOTA, COMPRAS.TOTAL_NOTA
    FROM COMPRAS
    WHERE DT_PEDIDO >= :DATAINICIAL AND DT_PEDIDO <= :DATAFINAL
    INTO :CD_COMPRAS, :NOTA_FISCAL, :VL_TOTALPRODUTOS, :VL_DESCONTO_NOTA, :TOTAL_NOTA
  DO
   BEGIN
     SELECT COD_NF_ENTRADA FROM SINTEGRA_NF_ENTRADA
     WHERE NUM_NF = :NOTA_FISCAL INTO :COD_NF_ENTRADA;

     UPDATE SINTEGRA_NF_ENTRADA SET
       SINTEGRA_NF_ENTRADA.VALOR_TOTALPRODUTO = :VL_TOTALPRODUTOS,
       SINTEGRA_NF_ENTRADA.DESCONTO = :VL_DESCONTO_NOTA,
       SINTEGRA_NF_ENTRADA.VALOR_TOTALNF = :TOTAL_NOTA
     WHERE COD_NF_ENTRADA =:COD_NF_ENTRADA;

     FOR
       SELECT ITENS_COMPRA.CODIGO_BARRAS, (ITENS_COMPRA.VL_DESCONTO * ITENS_COMPRA.QUANTIDADE), ITENS_COMPRA.VL_TOTAL
       FROM ITENS_COMPRA
       WHERE CD_COMPRAS = :CD_COMPRAS
       INTO :CODIGO_BARRAS, :VL_DESCONTO, :VL_TOTAL
     DO
      BEGIN
        UPDATE SINTEGRA_NF_ENTRADA_ITENS SET
          SINTEGRA_NF_ENTRADA_ITENS.VALOR_DESCONTO = :VL_DESCONTO,
          SINTEGRA_NF_ENTRADA_ITENS.SUBTOTAL = :VL_TOTAL
        WHERE SINTEGRA_NF_ENTRADA_ITENS.COD_NF_ENTRADA = :COD_NF_ENTRADA AND SINTEGRA_NF_ENTRADA_ITENS.REF_PRODUTOS = :CODIGO_BARRAS;
      END
   END
END ^

ALTER PROCEDURE SP_RECUPERA_VENDAS (DATA DATE)
RETURNS (CD_VENDA DOUBLE PRECISION)
AS 
declare variable EXISTECAIXA integer;
declare variable EXISTELANCAMENTO integer;
BEGIN
  FOR
   SELECT DISTINCT CD_VENDA
   FROM VENDAS
   WHERE DATA_CAIXA >= :DATA AND
   TIPO_VENDA = 'V'
   INTO :CD_VENDA
  DO
   BEGIN
     SELECT COUNT(*) FROM CAIXA WHERE CD_VENDA = :CD_VENDA AND TIPO_VENDA = 'V' INTO :EXISTECAIXA;
     IF ((:EXISTECAIXA IS NULL) OR (:EXISTECAIXA = 0)) THEN
      BEGIN
        SUSPEND;
      END
     ELSE
      BEGIN
        SELECT COUNT(*) FROM LANCAMENTOS WHERE CD_VENDA = :CD_VENDA AND TIPO_VENDA = 'V' INTO :EXISTELANCAMENTO;
        IF ((:EXISTELANCAMENTO IS NULL) OR (:EXISTELANCAMENTO = 0)) THEN
         BEGIN
           SUSPEND;
         END
      END

   END
END ^

ALTER PROCEDURE SP_RECUPERA_VENDAS_NFE (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (CD_VENDA DOUBLE PRECISION,
TROCA VARCHAR(1) CHARACTER SET NONE,
DATA_LANCAMENTO DATE,
CD_CLIENTE DOUBLE PRECISION,
NOME VARCHAR(100) CHARACTER SET NONE,
CD_CONVENIO DOUBLE PRECISION,
CONVENIO VARCHAR(100) CHARACTER SET NONE,
NUMERO DOUBLE PRECISION,
ECF VARCHAR(100) CHARACTER SET NONE,
VALOR DOUBLE PRECISION,
CD_FILIAL DOUBLE PRECISION)
AS 
declare variable EXISTEDEVOLUCAO integer;
BEGIN
 FOR
    SELECT 
     CAIXA.CD_VENDA, CAIXA.CD_FILIAL, CAIXA.TROCA, CAIXA.DATA,
     CAIXA.CD_CLIENTE, CAIXA.CD_CONVENIO, CONVENIOS.NOME, CAIXA.NUMERO,
     /*CAIXA.CD_FORMA_PAGAMENTO, FORMAS_PAGAMENTO.DESCRICAO,*/ CAIXA.ECF,
     SUM(CAIXA.VALOR)
    FROM
     CAIXA LEFT OUTER JOIN CONVENIOS ON CAIXA.CD_CONVENIO = CONVENIOS.CD_CONVENIO,
     FORMAS_PAGAMENTO
    WHERE
     CAIXA.CD_FORMA_PAGAMENTO = FORMAS_PAGAMENTO.CD_FORMA_PAGAMENTO AND
     CAIXA.DATA >= :DATAINICIAL AND
     CAIXA.DATA <= :DATAFINAL AND
     CAIXA.TIPO_VENDA = 'V'
    GROUP BY
     CAIXA.CD_VENDA, CAIXA.CD_FILIAL, CAIXA.TROCA, CAIXA.DATA,
     CAIXA.CD_CLIENTE, CAIXA.CD_CONVENIO, CONVENIOS.NOME, CAIXA.NUMERO,
     /*CAIXA.CD_FORMA_PAGAMENTO, FORMAS_PAGAMENTO.DESCRICAO,*/ CAIXA.ECF

    INTO
     :CD_VENDA, :CD_FILIAL, :TROCA, :DATA_LANCAMENTO, :CD_CLIENTE, :CD_CONVENIO, :CONVENIO, :NUMERO, /*:CD_FORMA_PAGAMENTO, :FORMA_PAGAMENTO,*/ :ECF, :VALOR
 DO
  BEGIN
    SELECT COUNT(*)
    FROM CAIXA
    WHERE
     CD_VENDA = :CD_VENDA AND
     TIPO_VENDA = 'D' AND
     (TROCA = 'F' OR TROCA = 'N')
    INTO
     :EXISTEDEVOLUCAO;

    NOME = '';
    SELECT FIRST 1 CD_CLIENTE FROM LANCAMENTOS WHERE CD_VENDA = :CD_VENDA AND CD_FILIAL = :CD_FILIAL INTO :CD_CLIENTE;
    IF ((:CD_CLIENTE IS NOT NULL) AND (:CD_CLIENTE <> 0)) THEN
     BEGIN
       SELECT NOME FROM CLIENTES WHERE CD_CLIENTE = :CD_CLIENTE AND CD_FILIAL = :CD_FILIAL INTO :NOME;
       IF ((:NOME IS NULL) OR (:NOME = '')) THEN
        BEGIN
          SELECT NOME FROM CLIENTES WHERE CD_CLIENTE = :CD_CLIENTE INTO :NOME;
          IF ((:NOME IS NULL) OR (:NOME = '')) THEN
             NOME = '';
        END
     END

    IF (:EXISTEDEVOLUCAO = 0) THEN
       SUSPEND;
  END
END ^

ALTER PROCEDURE SP_REENVIA_CONVENIOS_GRUPOS AS 
declare variable CD_FILIAL double precision;
declare variable CD_CONVENIO double precision;
BEGIN
  FOR
    SELECT CD_FILIAL FROM FILIAIS INTO :CD_FILIAL
  DO
   BEGIN
      FOR
        SELECT CD_CONVENIO FROM CONVENIOS INTO :CD_CONVENIO
      DO
       BEGIN
         INSERT INTO TEMP_PRODUTOS VALUES (:CD_CONVENIO, :CD_FILIAL, '136', '');
         INSERT INTO TEMP_PRODUTOS VALUES (:CD_CONVENIO, :CD_FILIAL, '124', '');
       END
   END
END ^

ALTER PROCEDURE SP_REENVIA_CONV_GRUPOS_CLASSES AS 
declare variable CD_FILIAL double precision;
declare variable CD_CONVENIO double precision;
declare variable EXISTE integer;
BEGIN
  FOR
    SELECT CD_FILIAL FROM FILIAIS INTO :CD_FILIAL
  DO
   BEGIN
      FOR
        SELECT CD_CONVENIO FROM CONVENIOS INTO :CD_CONVENIO
      DO
       BEGIN
         EXISTE = 0;
         SELECT COUNT(*) FROM TEMP_PRODUTOS WHERE ID_PRODUTO = :CD_CONVENIO AND CD_FILIAL = :CD_FILIAL AND PROCESSO = '136' INTO :EXISTE;
         IF (:EXISTE = 0) THEN
            INSERT INTO TEMP_PRODUTOS VALUES (:CD_CONVENIO, :CD_FILIAL, '136', '');
         EXISTE = 0;
         SELECT COUNT(*) FROM TEMP_PRODUTOS WHERE ID_PRODUTO = :CD_CONVENIO AND CD_FILIAL = :CD_FILIAL AND PROCESSO = '124' INTO :EXISTE;
         IF (:EXISTE = 0) THEN
            INSERT INTO TEMP_PRODUTOS VALUES (:CD_CONVENIO, :CD_FILIAL, '124', '');
       END
   END
END ^

ALTER PROCEDURE SP_REEXPORTA_SALDO_CLIENTES (CD_FILIAL DOUBLE PRECISION)
AS 
declare variable CD_CLIENTE double precision;
BEGIN
  FOR
   SELECT CD_CLIENTE FROM CLIENTES WHERE STATUS = 'A' AND CD_CLIENTE IN
   (SELECT DISTINCT CD_CLIENTE FROM CONTAS_RECEBER WHERE CD_CLIENTE <> 999999) INTO :CD_CLIENTE
  DO
  BEGIN
    INSERT INTO TEMP_PRODUTOS VALUES (:CD_CLIENTE, :CD_FILIAL, 151, '');
  END
END ^

ALTER PROCEDURE SP_RELACIONA_DUAS_TABELAS AS 
declare variable ID_PRODUTO double precision;
declare variable CD_GRUPO double precision;
BEGIN
  FOR
    SELECT ID_PRODUTO FROM PRODUTOS_FIDELIDADE INTO :ID_PRODUTO
  DO
   BEGIN
     SELECT CD_GRUPO FROM PRODUTOS WHERE ID_PRODUTO = :ID_PRODUTO INTO :CD_GRUPO;
     UPDATE PRODUTOS_FIDELIDADE SET CD_GRUPO = :CD_GRUPO WHERE ID_PRODUTO = :ID_PRODUTO;
   END
END ^

ALTER PROCEDURE SP_RELACIONA_PRODUTOS_APP_NOVO AS 
DECLARE VARIABLE FILIAL DOUBLE PRECISION;
DECLARE VARIABLE TIPO VARCHAR(1);
DECLARE VARIABLE IDPRODUTO INTEGER;
DECLARE VARIABLE PRECOVENDA DOUBLE PRECISION;
DECLARE VARIABLE CONTADOR INTEGER;
DECLARE VARIABLE COMANDO_REDE VARCHAR(255);

BEGIN

    SELECT COUNT(ID_PRODUTO) FROM FARMACIASAPP_OFERTAS INTO :CONTADOR;
    IF (:CONTADOR > 0) THEN
        DELETE FROM FARMACIASAPP_OFERTAS;

    SELECT PARAMETROS.TIPO_LOJA FROM PARAMETROS INTO :TIPO;
    SELECT PARAMETROS.CD_FILIAL FROM PARAMETROS INTO :FILIAL;
    COMANDO_REDE = 'SELECT PRODUTOS.id_produto,PRODUTOS.PRECO_VENDA_'||cast(FILIAL as integer)||' FROM PRODUTOS WHERE STATUS = ''A'' AND PRODUTOS.PRECO_VENDA_'||cast(FILIAL as integer)||' > 0';
        
    IF (:TIPO = 'U') THEN
        FOR
            SELECT PRODUTOS.ID_PRODUTO,PRODUTOS.PRECO_VENDA FROM PRODUTOS WHERE STATUS = 'A' AND PRECO_VENDA > 0
            INTO :IDPRODUTO,:PRECOVENDA
        DO
    BEGIN
        INSERT INTO FARMACIASAPP_OFERTAS (ID_PRODUTO, DE, POR, ENVIADO)
        VALUES (:IDPRODUTO, :PRECOVENDA, 0 , 'F');
    END

    IF (:TIPO = 'L') THEN

        FOR
            EXECUTE STATEMENT :COMANDO_REDE INTO :IDPRODUTO,:PRECOVENDA
        DO
    BEGIN
        INSERT INTO FARMACIASAPP_OFERTAS (ID_PRODUTO, DE, POR, ENVIADO)
        VALUES (:IDPRODUTO, :PRECOVENDA, 0 , 'F');
    END
END ^

