      if (MES = '07') then
          UPDATE PRODUTOS_TOTAIS SET PRODUTOS_TOTAIS.JULCOMPRA = PRODUTOS_TOTAIS.JULCOMPRA + :QDE  WHERE ID_PRODUTO = :ID_PRODUTO;
      if (MES = '08') then
          UPDATE PRODUTOS_TOTAIS SET PRODUTOS_TOTAIS.AGOCOMPRA = PRODUTOS_TOTAIS.AGOCOMPRA + :QDE  WHERE ID_PRODUTO = :ID_PRODUTO;
      if (MES = '09') then
          UPDATE PRODUTOS_TOTAIS SET PRODUTOS_TOTAIS.SETCOMPRA = PRODUTOS_TOTAIS.SETCOMPRA + :QDE  WHERE ID_PRODUTO = :ID_PRODUTO;
      if (MES = '10') then
          UPDATE PRODUTOS_TOTAIS SET PRODUTOS_TOTAIS.OUTCOMPRA = PRODUTOS_TOTAIS.OUTCOMPRA + :QDE  WHERE ID_PRODUTO = :ID_PRODUTO;
      if (MES = '11') then
          UPDATE PRODUTOS_TOTAIS SET PRODUTOS_TOTAIS.NOVCOMPRA = PRODUTOS_TOTAIS.NOVCOMPRA + :QDE  WHERE ID_PRODUTO = :ID_PRODUTO;
      if (MES = '12') then
          UPDATE PRODUTOS_TOTAIS SET PRODUTOS_TOTAIS.DEZCOMPRA = PRODUTOS_TOTAIS.DEZCOMPRA + :QDE  WHERE ID_PRODUTO = :ID_PRODUTO;

  END*/
