ALTER PROCEDURE SP_RELATORIOCOMPRACONFIRMA (CD_COMPRA DOUBLE PRECISION)
RETURNS (CURVA VARCHAR(1) CHARACTER SET NONE,
ID_PRODUTO DOUBLE PRECISION,
DESCRICAO VARCHAR(100) CHARACTER SET NONE,
LABORATORIO VARCHAR(100) CHARACTER SET NONE,
QTEMBALAGEM DOUBLE PRECISION,
QUANTIDADE DOUBLE PRECISION,
CUSTO DOUBLE PRECISION,
ESTOQUE DOUBLE PRECISION,
DTULTIMAVENDA DATE)
AS 
DECLARE VARIABLE FILIAL DOUBLE PRECISION;
DECLARE VARIABLE DATAPEDIDO DATE;
DECLARE VARIABLE CDCOMPRAANTERIORLOJA DOUBLE PRECISION;
DECLARE VARIABLE CDCOMPRAANTERIORREDE DOUBLE PRECISION;
DECLARE VARIABLE COMANDO VARCHAR(1000);
DECLARE VARIABLE CDFORNECEDORANTERIORLOJA DOUBLE PRECISION;
DECLARE VARIABLE CDFORNECEDORANTERIORREDE DOUBLE PRECISION;
DECLARE VARIABLE DATAMAXIMA DATE;
BEGIN
 FOR
  SELECT
   COMPRAS.CD_FILIAL,
   COMPRAS.DT_PEDIDO
  FROM
   COMPRAS
  WHERE
   COMPRAS.CD_COMPRAS = :CD_COMPRA
  INTO
   :FILIAL,
   :DATAPEDIDO
 DO
  BEGIN
    FOR
     SELECT
       CURVAS.SIGLA
     FROM
       CURVAS
     ORDER BY
       CURVAS.SIGLA
     INTO
      :CURVA
    DO
     BEGIN
        COMANDO = 'SELECT ITENS_COMPRA.ID_PRODUTO, ITENS_COMPRA.DESCRICAO, ITENS_COMPRA.LABORATORIO, ITENS_COMPRA.QT_EMBALAGEM, ITENS_COMPRA.QUANTIDADE, ITENS_COMPRA.VL_UNITARIO, PRODUTOS.ESTOQUE_'||CAST(:FILIAL AS INTEGER)||', PRODUTOS.DT_ULT_VENDA_'||CAST(:FILIAL AS INTEGER)||
                  ' FROM ITENS_COMPRA, PRODUTOS '||
                  'WHERE ITENS_COMPRA.CD_COMPRAS = '||:CD_COMPRA||' AND ITENS_COMPRA.CD_FILIAL > 0 AND ITENS_COMPRA.ID_PRODUTO = PRODUTOS.ID_PRODUTO AND '||
                  'PRODUTOS.CURVA_UNITARIA_'||CAST(:FILIAL AS INTEGER)||' = '''||:CURVA||''' ORDER BY ITENS_COMPRA.DESCRICAO';
        FOR
          EXECUTE STATEMENT :COMANDO INTO :ID_PRODUTO, :DESCRICAO, :LABORATORIO, :QTEMBALAGEM, :QUANTIDADE, :CUSTO, :ESTOQUE, :DTULTIMAVENDA
        DO
         BEGIN
           /*DATAPEDIDOANTERIORLOJA = NULL;
           CDFORNECEDORANTERIORLOJA = NULL;
           QUANTIDADEANTERIORLOJA = NULL;
           CUSTOANTERIORLOJA = NULL;
           CDCOMPRAANTERIORLOJA = NULL;

           SELECT
             MAX(COMPRAS.DT_PEDIDO)
           FROM
             COMPRAS,
             ITENS_COMPRA
           WHERE
             COMPRAS.DT_PEDIDO < :DATAPEDIDO AND
             COMPRAS.CD_FILIAL = :FILIAL AND
             COMPRAS.CD_FILIAL = ITENS_COMPRA.CD_FILIAL AND
             ITENS_COMPRA.ID_PRODUTO = :ID_PRODUTO AND
             COMPRAS.CD_COMPRAS = ITENS_COMPRA.CD_COMPRAS
           INTO
            :DATAMAXIMA;

           SELECT
             FIRST 1
             COMPRAS.CD_COMPRAS,
             COMPRAS.DT_PEDIDO,
             COMPRAS.CD_DISTRIBUIDOR,
             ITENS_COMPRA.QUANTIDADE,
             ITENS_COMPRA.VL_UNITARIO
           FROM
             COMPRAS,
             ITENS_COMPRA
           WHERE
             COMPRAS.DT_PEDIDO = :DATAMAXIMA AND
             COMPRAS.CD_FILIAL = :FILIAL AND
             COMPRAS.CD_FILIAL = ITENS_COMPRA.CD_FILIAL AND
             ITENS_COMPRA.ID_PRODUTO = :ID_PRODUTO AND
             COMPRAS.CD_COMPRAS = ITENS_COMPRA.CD_COMPRAS
           INTO
            :CDCOMPRAANTERIORLOJA,
            :DATAPEDIDOANTERIORLOJA,
            :CDFORNECEDORANTERIORLOJA,
            :QUANTIDADEANTERIORLOJA,
            :CUSTOANTERIORLOJA;

           CDCOMPRAANTERIORREDE = NULL;
           DATAPEDIDOANTERIORREDE = NULL;
           FORNECEDORANTERIORREDE = NULL;
           QUANTIDADEANTERIORREDE = NULL;
           CUSTOANTERIORREDE = NULL;
           FILIALANTERIORREDE = '';

           SELECT
             MAX(COMPRAS.DT_PEDIDO)
           FROM
             COMPRAS,
             ITENS_COMPRA
           WHERE
             COMPRAS.DT_PEDIDO < :DATAPEDIDO AND
             COMPRAS.CD_FILIAL = ITENS_COMPRA.CD_FILIAL AND
             ITENS_COMPRA.ID_PRODUTO = :ID_PRODUTO AND
             COMPRAS.CD_COMPRAS = ITENS_COMPRA.CD_COMPRAS
           INTO
            :DATAMAXIMA;

           SELECT
            FIRST 1
            COMPRAS.CD_COMPRAS,
            FILIAIS.NOME,
            COMPRAS.DT_PEDIDO,
            COMPRAS.CD_DISTRIBUIDOR,
            ITENS_COMPRA.QUANTIDADE,
            ITENS_COMPRA.VL_UNITARIO
           FROM
            FILIAIS,
            COMPRAS,
            ITENS_COMPRA
           WHERE
            COMPRAS.DT_PEDIDO = :DATAMAXIMA AND
            FILIAIS.CD_FILIAL = COMPRAS.CD_FILIAL AND
            ITENS_COMPRA.ID_PRODUTO = :ID_PRODUTO AND
            COMPRAS.CD_COMPRAS = ITENS_COMPRA.CD_COMPRAS
           INTO
            :CDCOMPRAANTERIORREDE,
            :FILIALANTERIORREDE,
            :DATAPEDIDOANTERIORREDE,
            :CDFORNECEDORANTERIORREDE,
            :QUANTIDADEANTERIORREDE,
            :CUSTOANTERIORREDE;

           MEDIAVENDA = 0;

           SELECT
            SUM(LANCAMENTOS.QUANTIDADE)
           FROM
            LANCAMENTOS
           WHERE
            LANCAMENTOS.DATA_LANCAMENTO >= CURRENT_DATE - 90 AND
            LANCAMENTOS.DATA_LANCAMENTO <= CURRENT_DATE AND
            LANCAMENTOS.CD_FILIAL = :FILIAL AND
            LANCAMENTOS.TIPO_VENDA = 'V' AND
            LANCAMENTOS.ID_PRODUTO = :ID_PRODUTO
           INTO
            :MEDIAVENDA;

           IF (:MEDIAVENDA IS NULL) THEN
            BEGIN
              MEDIAVENDA = 0;
            END
           ELSE
            BEGIN
              MEDIAVENDA = :MEDIAVENDA / 90;
            END

           IF ((:ESTOQUE > 0) AND (:MEDIAVENDA > 0)) THEN
            BEGIN
              DIASESTOQUE = :ESTOQUE / :MEDIAVENDA;
              DIASESTOQUE = CAST(:DIASESTOQUE AS INTEGER);
            END
           ELSE
              DIASESTOQUE = 0;

           IF (:ESTOQUE > 0) THEN
              DTULTIMAVENDA = NULL;

           SELECT NOME FROM DISTRIBUIDORES WHERE CD_DISTRIBUIDOR = :CDFORNECEDORANTERIORLOJA INTO :FORNECEDORANTERIORLOJA;
           SELECT NOME FROM DISTRIBUIDORES WHERE CD_DISTRIBUIDOR = :CDFORNECEDORANTERIORREDE INTO :FORNECEDORANTERIORREDE;*/
           SUSPEND;
         END
     END
  END
END ^

ALTER PROCEDURE SP_RELATORIOCOMPRANACOES (CD_COMPRA DOUBLE PRECISION)
RETURNS (CURVA VARCHAR(1) CHARACTER SET NONE,
ID_PRODUTO DOUBLE PRECISION,
DESCRICAO VARCHAR(100) CHARACTER SET NONE,
LABORATORIO VARCHAR(100) CHARACTER SET NONE,
QTEMBALAGEM DOUBLE PRECISION,
QUANTIDADE DOUBLE PRECISION,
CUSTO DOUBLE PRECISION,
DATAPEDIDOANTERIORLOJA DATE,
FORNECEDORANTERIORLOJA VARCHAR(100) CHARACTER SET NONE,
QUANTIDADEANTERIORLOJA DOUBLE PRECISION,
CUSTOANTERIORLOJA DOUBLE PRECISION,
DATAPEDIDOANTERIORREDE DATE,
FORNECEDORANTERIORREDE VARCHAR(100) CHARACTER SET NONE,
QUANTIDADEANTERIORREDE DOUBLE PRECISION,
CUSTOANTERIORREDE DOUBLE PRECISION,
FILIALANTERIORREDE VARCHAR(100) CHARACTER SET NONE,
MEDIAVENDA NUMERIC(15, 2),
ESTOQUE DOUBLE PRECISION,
DIASESTOQUE NUMERIC(15, 2),
DTULTIMAVENDA DATE)
AS 
declare variable FILIAL double precision;
declare variable DATAPEDIDO date;
declare variable CDCOMPRAANTERIORLOJA double precision;
declare variable CDCOMPRAANTERIORREDE double precision;
declare variable COMANDO varchar(1000);
declare variable CDFORNECEDORANTERIORLOJA double precision;
declare variable CDFORNECEDORANTERIORREDE double precision;
declare variable DATAMAXIMA date;
declare variable CODIGOCOMPRA double precision;
BEGIN
 FOR
  SELECT
   COMPRAS.CD_FILIAL,
   COMPRAS.DT_PEDIDO
  FROM
   COMPRAS
  WHERE
   COMPRAS.CD_COMPRAS = :CD_COMPRA
  INTO
   :FILIAL,
   :DATAPEDIDO
 DO
  BEGIN
    FOR
     SELECT
       CURVAS.SIGLA
     FROM
       CURVAS
     ORDER BY
       CURVAS.SIGLA
     INTO
      :CURVA
    DO
     BEGIN
        COMANDO = 'SELECT ITENS_COMPRA.ID_PRODUTO, ITENS_COMPRA.DESCRICAO, ITENS_COMPRA.LABORATORIO, ITENS_COMPRA.QT_EMBALAGEM, ITENS_COMPRA.QUANTIDADE, ITENS_COMPRA.VL_UNITARIO, PRODUTOS.ESTOQUE_'||CAST(:FILIAL AS INTEGER)||', PRODUTOS.DT_ULT_VENDA_'||CAST(:FILIAL AS INTEGER)||
                  ' FROM ITENS_COMPRA, PRODUTOS '||
                  'WHERE ITENS_COMPRA.CD_COMPRAS = '||:CD_COMPRA||' AND ITENS_COMPRA.CD_FILIAL > 0 AND ITENS_COMPRA.ID_PRODUTO = PRODUTOS.ID_PRODUTO AND '||
                  'PRODUTOS.CURVA_UNITARIA_'||CAST(:FILIAL AS INTEGER)||' = '''||:CURVA||''' ORDER BY ITENS_COMPRA.DESCRICAO';
        FOR
          EXECUTE STATEMENT :COMANDO INTO :ID_PRODUTO, :DESCRICAO, :LABORATORIO, :QTEMBALAGEM, :QUANTIDADE, :CUSTO, :ESTOQUE, :DTULTIMAVENDA
        DO
         BEGIN
           DATAPEDIDOANTERIORLOJA = NULL;
           CDFORNECEDORANTERIORLOJA = NULL;
           QUANTIDADEANTERIORLOJA = NULL;
           CUSTOANTERIORLOJA = NULL;
           CDCOMPRAANTERIORLOJA = NULL;

           SELECT
             MAX(ITENS_COMPRA.CD_COMPRAS)
           FROM
             ITENS_COMPRA
           WHERE
             ITENS_COMPRA.CD_FILIAL = :FILIAL AND
             ITENS_COMPRA.CD_COMPRAS < :CD_COMPRA AND
             ITENS_COMPRA.ID_PRODUTO = :ID_PRODUTO
           INTO
            :CODIGOCOMPRA;

           SELECT
             COMPRAS.DT_PEDIDO
           FROM
             COMPRAS
           WHERE
             COMPRAS.CD_FILIAL = :FILIAL AND
             COMPRAS.CD_COMPRAS = :CODIGOCOMPRA AND
             COMPRAS.STATUS = 'C'
           INTO
            :DATAMAXIMA;

           SELECT
             COMPRAS.CD_COMPRAS,
             COMPRAS.DT_PEDIDO,
             COMPRAS.CD_DISTRIBUIDOR,
             ITENS_COMPRA.QUANTIDADE,
             ITENS_COMPRA.VL_UNITARIO
           FROM
             COMPRAS,
             ITENS_COMPRA
           WHERE
             COMPRAS.CD_COMPRAS = :CODIGOCOMPRA AND
             ITENS_COMPRA.ID_PRODUTO = :ID_PRODUTO AND
             ITENS_COMPRA.CD_COMPRAS = COMPRAS.CD_COMPRAS AND
             COMPRAS.STATUS = 'C'
           INTO
            :CDCOMPRAANTERIORLOJA,
            :DATAPEDIDOANTERIORLOJA,
            :CDFORNECEDORANTERIORLOJA,
            :QUANTIDADEANTERIORLOJA,
            :CUSTOANTERIORLOJA;

           CDCOMPRAANTERIORREDE = NULL;
           DATAPEDIDOANTERIORREDE = NULL;
           FORNECEDORANTERIORREDE = NULL;
           QUANTIDADEANTERIORREDE = NULL;
           CUSTOANTERIORREDE = NULL;
           FILIALANTERIORREDE = '';

           SELECT
             MAX(ITENS_COMPRA.CD_COMPRAS)
           FROM
             ITENS_COMPRA
           WHERE
             ITENS_COMPRA.CD_COMPRAS < :CD_COMPRA AND
             ITENS_COMPRA.ID_PRODUTO = :ID_PRODUTO
           INTO
            :CODIGOCOMPRA;

           SELECT
             COMPRAS.DT_PEDIDO
           FROM
             COMPRAS
           WHERE
             COMPRAS.CD_COMPRAS = :CODIGOCOMPRA AND
             COMPRAS.STATUS = 'C'
           INTO
            :DATAMAXIMA;

           SELECT
            COMPRAS.CD_COMPRAS,
            FILIAIS.NOME,
            COMPRAS.DT_PEDIDO,
            COMPRAS.CD_DISTRIBUIDOR,
            ITENS_COMPRA.QUANTIDADE,
            ITENS_COMPRA.VL_UNITARIO
           FROM
            FILIAIS,
            COMPRAS,
            ITENS_COMPRA
           WHERE
            COMPRAS.CD_FILIAL = FILIAIS.CD_FILIAL AND
            COMPRAS.CD_COMPRAS = :CODIGOCOMPRA AND
            ITENS_COMPRA.ID_PRODUTO = :ID_PRODUTO AND
            ITENS_COMPRA.CD_COMPRAS = COMPRAS.CD_COMPRAS AND
             COMPRAS.STATUS = 'C'
           INTO
            :CDCOMPRAANTERIORREDE,
            :FILIALANTERIORREDE,
            :DATAPEDIDOANTERIORREDE,
            :CDFORNECEDORANTERIORREDE,
            :QUANTIDADEANTERIORREDE,
            :CUSTOANTERIORREDE;

           MEDIAVENDA = 0;

           SELECT
            SUM(LANCAMENTOS.QUANTIDADE)
           FROM
            LANCAMENTOS
           WHERE
            LANCAMENTOS.CD_FILIAL = :FILIAL AND
            LANCAMENTOS.ID_PRODUTO = :ID_PRODUTO AND
            LANCAMENTOS.TIPO_VENDA = 'V' AND
            LANCAMENTOS.DATA_LANCAMENTO >= CURRENT_DATE - 90 AND
            LANCAMENTOS.DATA_LANCAMENTO <= CURRENT_DATE
           INTO
            :MEDIAVENDA;

           IF (:MEDIAVENDA IS NULL) THEN
            BEGIN
              MEDIAVENDA = 0;
            END
           ELSE
            BEGIN
              MEDIAVENDA = :MEDIAVENDA / 90;
            END

           IF ((:ESTOQUE > 0) AND (:MEDIAVENDA > 0)) THEN
            BEGIN
              DIASESTOQUE = :ESTOQUE / :MEDIAVENDA;
              DIASESTOQUE = CAST(:DIASESTOQUE AS INTEGER);
            END
           ELSE
              DIASESTOQUE = 0;

           IF (:ESTOQUE > 0) THEN
              DTULTIMAVENDA = NULL;

           SELECT NOME FROM DISTRIBUIDORES WHERE CD_DISTRIBUIDOR = :CDFORNECEDORANTERIORLOJA INTO :FORNECEDORANTERIORLOJA;
           SELECT NOME FROM DISTRIBUIDORES WHERE CD_DISTRIBUIDOR = :CDFORNECEDORANTERIORREDE INTO :FORNECEDORANTERIORREDE;
           SUSPEND;
         END
     END
  END
END ^

ALTER PROCEDURE SP_RELPERDAS (DATAINICIAL DATE,
DATAFINAL DATE,
FILIAL VARCHAR(100) CHARACTER SET NONE,
TIPOPAGAMENTO VARCHAR(1) CHARACTER SET NONE,
CD_LABORATORIO DOUBLE PRECISION)
RETURNS (NOMEFILIAL VARCHAR(100) CHARACTER SET NONE,
CD_PRODUTO VARCHAR(6) CHARACTER SET NONE,
DESCRICAO VARCHAR(100) CHARACTER SET NONE,
ENTRADAS DOUBLE PRECISION,
SAIDAS DOUBLE PRECISION,
ENTRADASVALORVENDA DOUBLE PRECISION,
ENTRADASVALORCUSTO DOUBLE PRECISION,
SAIDASVALORVENDA DOUBLE PRECISION,
SAIDASVALORCUSTO DOUBLE PRECISION,
TOTAL DOUBLE PRECISION,
TOTALVALORVENDA DOUBLE PRECISION,
TOTALVALORCUSTO DOUBLE PRECISION)
AS 
declare variable ID_PRODUTO double precision;
declare variable LABORATORIO double precision;
BEGIN
 FOR
   SELECT
    LANCAMENTOS.ID_PRODUTO,
    FILIAIS.NOME,
    LANCAMENTOS.CD_PRODUTO,
    LANCAMENTOS.DESCRICAO,
    LANCAMENTOS.CD_LABORATORIO
   FROM
    LANCAMENTOS, FILIAIS
   WHERE
    LANCAMENTOS.TIPO_VENDA = 'X' AND
    LANCAMENTOS.TIPO_PAGAMENTO LIKE :TIPOPAGAMENTO AND
    LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
    LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
    LANCAMENTOS.CD_FILIAL = FILIAIS.CD_FILIAL AND
    FILIAIS.NOME LIKE :FILIAL
   GROUP BY
    LANCAMENTOS.ID_PRODUTO,
    FILIAIS.NOME,
    LANCAMENTOS.CD_PRODUTO,
    LANCAMENTOS.DESCRICAO,
    LANCAMENTOS.CD_LABORATORIO
   INTO
    :ID_PRODUTO,
    :NOMEFILIAL,
    :CD_PRODUTO,
    :DESCRICAO,
    :LABORATORIO
 DO
  BEGIN
       TOTAL = 0;

       SELECT
        SUM(LANCAMENTOS.QUANTIDADE),
        SUM(LANCAMENTOS.VALOR),
        SUM(LANCAMENTOS.QUANTIDADE * LANCAMENTOS.CUSTO_UNITARIO)
       FROM
        LANCAMENTOS, FILIAIS
       WHERE
        LANCAMENTOS.TIPO_VENDA = 'X' AND
        LANCAMENTOS.TIPO_PAGAMENTO LIKE :TIPOPAGAMENTO AND
        LANCAMENTOS.ENTRADA_SAIDA = 'E' AND
        LANCAMENTOS.ID_PRODUTO = :ID_PRODUTO AND
        LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
        LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
        LANCAMENTOS.CD_FILIAL = FILIAIS.CD_FILIAL AND
        FILIAIS.NOME LIKE :FILIAL
       INTO
        :ENTRADAS,
        :ENTRADASVALORVENDA,
        :ENTRADASVALORCUSTO;

       SELECT
        SUM(LANCAMENTOS.QUANTIDADE),
        SUM(LANCAMENTOS.VALOR),
        SUM(LANCAMENTOS.QUANTIDADE * LANCAMENTOS.CUSTO_UNITARIO)
       FROM
        LANCAMENTOS, FILIAIS
       WHERE
        LANCAMENTOS.TIPO_VENDA = 'X' AND
        LANCAMENTOS.TIPO_PAGAMENTO LIKE :TIPOPAGAMENTO AND
        LANCAMENTOS.ENTRADA_SAIDA = 'S' AND
        LANCAMENTOS.ID_PRODUTO = :ID_PRODUTO AND
        LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
        LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
        LANCAMENTOS.CD_FILIAL = FILIAIS.CD_FILIAL AND
        FILIAIS.NOME LIKE :FILIAL
       INTO
        :SAIDAS,
        :SAIDASVALORVENDA,
        :SAIDASVALORCUSTO;

       IF (:ENTRADAS IS NULL) THEN
          ENTRADAS = 0;
       IF (:SAIDAS IS NULL) THEN
          SAIDAS = 0;
       TOTAL = :ENTRADAS - :SAIDAS;

       IF (:ENTRADASVALORVENDA IS NULL) THEN
          ENTRADASVALORVENDA = 0;
       IF (:SAIDASVALORVENDA IS NULL) THEN
          SAIDASVALORVENDA = 0;
       TOTALVALORVENDA = :ENTRADASVALORVENDA - :SAIDASVALORVENDA;

       IF (:ENTRADASVALORCUSTO IS NULL) THEN
          ENTRADASVALORCUSTO = 0;
       IF (:SAIDASVALORCUSTO IS NULL) THEN
          SAIDASVALORCUSTO = 0;
       TOTALVALORCUSTO = :ENTRADASVALORCUSTO - :SAIDASVALORCUSTO;

       IF ((:CD_LABORATORIO = 0) OR (:CD_LABORATORIO = :LABORATORIO)) THEN
          SUSPEND;
  END
END ^

ALTER PROCEDURE SP_RELTRANSFERCLASSE (FILIALORIGEM DOUBLE PRECISION,
DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (FILIAL DOUBLE PRECISION,
NOME VARCHAR(100) CHARACTER SET NONE,
CD_CLASSE DOUBLE PRECISION,
DESCRICAO VARCHAR(100) CHARACTER SET NONE,
QUANTIDADE1 DOUBLE PRECISION,
QUANTIDADE2 DOUBLE PRECISION,
CUSTO1 DOUBLE PRECISION,
CUSTO2 DOUBLE PRECISION,
VENDA1 DOUBLE PRECISION,
VENDA2 DOUBLE PRECISION)
AS 
BEGIN
  FOR
    SELECT CD_FILIAL, NOME FROM FILIAIS WHERE CD_FILIAL <> :FILIALORIGEM AND FILIAIS.EXPORTAR = 'S' INTO :FILIAL, :NOME
  DO
   BEGIN
      FOR
       SELECT CD_CLASSE, DESCRICAO FROM CLASSES INTO :CD_CLASSE, :DESCRICAO
      DO
       BEGIN
          SELECT
            SUM(ITENS_TRANSFER.QUANTIDADE_RECEBIDA) AS QUANTIDADE,
            SUM(ITENS_TRANSFER.VALOR * ITENS_TRANSFER.QUANTIDADE_RECEBIDA) AS CUSTO,
            SUM(PRODUTOS.PRECO_VENDA * ITENS_TRANSFER.QUANTIDADE_RECEBIDA) AS VENDA
          FROM
           TRANSFER,
           ITENS_TRANSFER,
           PRODUTOS
          WHERE
           TRANSFER.DATA_CONCLUSAO >= :DATAINICIAL AND
           TRANSFER.DATA_CONCLUSAO <= :DATAFINAL AND 
           TRANSFER.STATUS = 'C' AND
           TRANSFER.CD_TRANSFER = ITENS_TRANSFER.CD_TRANSFER AND
           TRANSFER.CD_FILIAL_ORIGEM = :FILIAL AND
           TRANSFER.CD_FILIAL_DESTINO = :FILIALORIGEM AND
           ITENS_TRANSFER.ID_PRODUTO = PRODUTOS.ID_PRODUTO AND
           ITENS_TRANSFER.CD_CLASSE = :CD_CLASSE AND
           ITENS_TRANSFER.QUANTIDADE_RECEBIDA IS NOT NULL AND
           ITENS_TRANSFER.QUANTIDADE_RECEBIDA > 0
          INTO
           :QUANTIDADE1,
           :CUSTO1,
           :VENDA1;
    
          IF (:QUANTIDADE1 IS NULL) THEN
             QUANTIDADE1 = 0;
          IF (:CUSTO1 IS NULL) THEN
             CUSTO1 = 0;
          IF (:VENDA1 IS NULL) THEN
             VENDA1 = 0;
    
          SELECT
            SUM(ITENS_TRANSFER.QUANTIDADE_RECEBIDA) AS QUANTIDADE,
            SUM(ITENS_TRANSFER.VALOR * ITENS_TRANSFER.QUANTIDADE_RECEBIDA) AS CUSTO,
            SUM(PRODUTOS.PRECO_VENDA * ITENS_TRANSFER.QUANTIDADE_RECEBIDA) AS VENDA
          FROM
           TRANSFER,
           ITENS_TRANSFER,
           PRODUTOS
          WHERE
           TRANSFER.CD_TRANSFER = ITENS_TRANSFER.CD_TRANSFER AND
           ITENS_TRANSFER.ID_PRODUTO = PRODUTOS.ID_PRODUTO AND
           ITENS_TRANSFER.CD_CLASSE = :CD_CLASSE AND
           TRANSFER.DATA_CONCLUSAO >= :DATAINICIAL AND
           TRANSFER.DATA_CONCLUSAO <= :DATAFINAL AND 
           TRANSFER.CD_FILIAL_ORIGEM = :FILIALORIGEM AND
           TRANSFER.CD_FILIAL_DESTINO = :FILIAL AND
           TRANSFER.STATUS = 'C' AND
           ITENS_TRANSFER.QUANTIDADE_RECEBIDA IS NOT NULL AND
           ITENS_TRANSFER.QUANTIDADE_RECEBIDA > 0
          INTO
           :QUANTIDADE2,
           :CUSTO2,
           :VENDA2;
    
          IF (:QUANTIDADE2 IS NULL) THEN
             QUANTIDADE2 = 0;
          IF (:CUSTO2 IS NULL) THEN
             CUSTO2 = 0;
          IF (:VENDA2 IS NULL) THEN
             VENDA2 = 0;
    
         SUSPEND;
    
       END

   END

  FILIAL = 0;
  NOME = '';
  QUANTIDADE1 = 0;
  QUANTIDADE2 = 0;
  CUSTO1 = 0;
  CUSTO2 = 2;
  VENDA1 = 0;
  VENDA2 = 0;
  FOR
   SELECT CD_CLASSE, DESCRICAO FROM CLASSES INTO :CD_CLASSE, :DESCRICAO
  DO
   BEGIN
      SELECT
        SUM(ITENS_TRANSFER.QUANTIDADE_RECEBIDA) AS QUANTIDADE,
        SUM(ITENS_TRANSFER.VALOR * ITENS_TRANSFER.QUANTIDADE_RECEBIDA) AS CUSTO,
        SUM(PRODUTOS.PRECO_VENDA * ITENS_TRANSFER.QUANTIDADE_RECEBIDA) AS VENDA
      FROM
       TRANSFER,
       ITENS_TRANSFER,
       PRODUTOS,
       FILIAIS
      WHERE
       TRANSFER.CD_TRANSFER = ITENS_TRANSFER.CD_TRANSFER AND
       ITENS_TRANSFER.ID_PRODUTO = PRODUTOS.ID_PRODUTO AND
       TRANSFER.CD_FILIAL_ORIGEM = FILIAIS.CD_FILIAL AND
       FILIAIS.EXPORTAR = 'S' AND
       FILIAIS.STATUS = 'A' AND
       ITENS_TRANSFER.CD_CLASSE = :CD_CLASSE AND
       TRANSFER.DATA_CONCLUSAO >= :DATAINICIAL AND
       TRANSFER.DATA_CONCLUSAO <= :DATAFINAL AND 
       TRANSFER.CD_FILIAL_DESTINO = :FILIALORIGEM AND
       TRANSFER.STATUS = 'C' AND
       ITENS_TRANSFER.QUANTIDADE_RECEBIDA IS NOT NULL AND
       ITENS_TRANSFER.QUANTIDADE_RECEBIDA > 0
      INTO
       :QUANTIDADE1,
       :CUSTO1,
       :VENDA1;

      IF (:QUANTIDADE1 IS NULL) THEN
         QUANTIDADE1 = 0;
      IF (:CUSTO1 IS NULL) THEN
         CUSTO1 = 0;
      IF (:VENDA1 IS NULL) THEN
         VENDA1 = 0;

      SELECT
        SUM(ITENS_TRANSFER.QUANTIDADE_RECEBIDA) AS QUANTIDADE,
        SUM(ITENS_TRANSFER.VALOR * ITENS_TRANSFER.QUANTIDADE_RECEBIDA) AS CUSTO,
        SUM(PRODUTOS.PRECO_VENDA * ITENS_TRANSFER.QUANTIDADE_RECEBIDA) AS VENDA
      FROM
       TRANSFER,
       ITENS_TRANSFER,
       PRODUTOS,
       FILIAIS
      WHERE
       TRANSFER.CD_TRANSFER = ITENS_TRANSFER.CD_TRANSFER AND
       ITENS_TRANSFER.ID_PRODUTO = PRODUTOS.ID_PRODUTO AND
       TRANSFER.CD_FILIAL_DESTINO = FILIAIS.CD_FILIAL AND
       FILIAIS.EXPORTAR = 'S' AND
       FILIAIS.STATUS = 'A' AND
       ITENS_TRANSFER.CD_CLASSE = :CD_CLASSE AND
       TRANSFER.DATA_CONCLUSAO >= :DATAINICIAL AND
       TRANSFER.DATA_CONCLUSAO <= :DATAFINAL AND 
       TRANSFER.CD_FILIAL_ORIGEM = :FILIALORIGEM AND
       TRANSFER.STATUS = 'C' AND
       ITENS_TRANSFER.QUANTIDADE_RECEBIDA IS NOT NULL AND
       ITENS_TRANSFER.QUANTIDADE_RECEBIDA > 0
      INTO
       :QUANTIDADE2,
       :CUSTO2,
       :VENDA2;

      IF (:QUANTIDADE2 IS NULL) THEN
         QUANTIDADE2 = 0;
      IF (:CUSTO2 IS NULL) THEN
         CUSTO2 = 0;
      IF (:VENDA2 IS NULL) THEN
         VENDA2 = 0;

     SUSPEND;

   END
END ^

ALTER PROCEDURE SP_RETORNADATAHORASERVIDOR RETURNS (DATA DATE,
HORA TIME)
AS 
BEGIN
  DATA = CURRENT_DATE;
  HORA = CURRENT_TIME;
  SUSPEND;
END ^

ALTER PROCEDURE SP_RETORNAESTOQUEMES (FILIAL DOUBLE PRECISION,
DATA_LANCAMENTO DATE)
RETURNS (ID_PRODUTO DOUBLE PRECISION,
DATA DATE,
ESTOQUE DOUBLE PRECISION,
CUSTO DOUBLE PRECISION,
VENDA DOUBLE PRECISION)
AS 
BEGIN
  FOR
    SELECT
      ID_PRODUTO,
      MAX(DATA_LANCAMENTO)
    FROM
      LANCAMENTOS
    WHERE
      DATA_LANCAMENTO <= :DATA_LANCAMENTO AND
      CD_FILIAL = :FILIAL
    GROUP BY
      ID_PRODUTO
    INTO
      :ID_PRODUTO,
      :DATA
  DO
   BEGIN
     SELECT
       FIRST 1 ESTOQUE_POSVENDA,
       (CUSTO_UNITARIO * ESTOQUE_POSVENDA),
       (VALOR * ESTOQUE_POSVENDA)
     FROM
      LANCAMENTOS
     WHERE
      DATA_LANCAMENTO = :DATA AND
      CD_FILIAL = :FILIAL AND
      ID_PRODUTO = :ID_PRODUTO
     ORDER BY
       HORA DESC
     INTO
      :ESTOQUE,
      :CUSTO,
      :VENDA;

    SUSPEND;
   END
END ^

ALTER PROCEDURE SP_RETORNAID (CAMPO VARCHAR(100) CHARACTER SET NONE)
RETURNS (ID DOUBLE PRECISION)
AS 
BEGIN
  UPDATE CONTROLE SET VALOR = VALOR + 1 WHERE CAMPO = :CAMPO;
  SELECT VALOR FROM CONTROLE WHERE CAMPO = :CAMPO INTO :ID;
  SUSPEND;
END ^

ALTER PROCEDURE SP_RETORNA_BARRA_DUPLICADA RETURNS (CODIGO VARCHAR(6) CHARACTER SET NONE,
PRODUTO VARCHAR(100) CHARACTER SET NONE,
BARRA VARCHAR(13) CHARACTER SET NONE)
AS 
BEGIN
 FOR
  SELECT
   CD_PRODUTO,
   DESCRICAO,
   CODIGO_BARRAS_1
  FROM
   PRODUTOS
  WHERE
   CODIGO_BARRAS_1 IN
   (SELECT CODIGO_BARRAS_1 FROM PRODUTOS GROUP BY CODIGO_BARRAS_1 HAVING COUNT(CODIGO_BARRAS_1) > 1)
  INTO
   :CODIGO, :PRODUTO, :BARRA
 DO
  BEGIN
    SUSPEND;
  END
END ^

ALTER PROCEDURE SP_RETORNA_CUSTO_RECEBIMENTO (FILIAL DOUBLE PRECISION,
ID DOUBLE PRECISION,
COMPLEMENTO VARCHAR(10000) CHARACTER SET NONE)
RETURNS (TOTAL DOUBLE PRECISION)
AS 
declare variable CD_VENDA double precision;
declare variable CUSTO double precision;
declare variable COMANDO varchar(10000);
BEGIN
  CUSTO = 0;
  TOTAL = 0;
  COMANDO = '';
  COMANDO = 'SELECT DISTINCT LANCAMENTOS.NUMERO FROM LANCAMENTOS ' ||
            'WHERE  LANCAMENTOS.ID_OPERADORCAIXA = ' || CAST(:ID AS INTEGER) || ' AND ' ||
            'LANCAMENTOS.CD_FILIAL = ' || CAST(:FILIAL AS INTEGER) || ' AND ' ||
            'LANCAMENTOS.TIPO_VENDA = ''R'' AND ' ||
            'LANCAMENTOS.CD_VENDA IN (SELECT DISTINCT CD_VENDA FROM CAIXA ' ||
            'WHERE ID_OPERADORCAIXA = ' || CAST(:ID AS INTEGER) || ' AND ' ||
            '      CD_FILIAL = ' || CAST(:FILIAL AS INTEGER) || ' AND ' ||
            '      CD_PLANO_CONTAS IN (' || :COMPLEMENTO || '))';

  FOR
    EXECUTE STATEMENT :COMANDO INTO :CD_VENDA
  DO
   BEGIN
      SELECT
       SUM(LANCAMENTOS.CUSTO_MEDIO * LANCAMENTOS.QUANTIDADE) AS TOTAL
      FROM LANCAMENTOS
      WHERE
       LANCAMENTOS.CD_FILIAL = :FILIAL AND
       LANCAMENTOS.TIPO_VENDA = 'V' AND
       LANCAMENTOS.CD_VENDA = :CD_VENDA
      INTO :CUSTO;

      TOTAL = :TOTAL + :CUSTO;
   END

  SUSPEND;
END ^

ALTER PROCEDURE SP_RETORNA_DOCUMENTO_ESTOQUEPAF RETURNS (NUMERO_FABRICACAOPAF VARCHAR(100) CHARACTER SET NONE,
MF_ADICIONALPAF VARCHAR(100) CHARACTER SET NONE,
TIPO_ECFPAF VARCHAR(100) CHARACTER SET NONE,
MARCA_ECFPAF VARCHAR(100) CHARACTER SET NONE,
MODELO_ECFPAF VARCHAR(100) CHARACTER SET NONE,
DATAPAF DATE,
HORAPAF TIME)
AS 
declare variable NUMERO_FABRICACAOR02 varchar(20);
declare variable NUMERO_FABRICACAOR04 varchar(20);
declare variable NUMERO_FABRICACAOR06 varchar(20);
declare variable DATAR02 date;
declare variable DATAR04 date;
declare variable DATAR06 date;
declare variable HORAR02 time;
declare variable HORAR04 time;
declare variable HORAR06 time;
BEGIN
    SELECT MAX(PAF_R02.DDATA_EMISSAO)
    FROM PAF_R02
    WHERE PAF_R02.DDATA_EMISSAO IS NOT NULL AND PAF_R02.DDATA_EMISSAO >= CURRENT_DATE - 180
    INTO :DATAR02;
    
    SELECT MAX(PAF_R04.DDATA_INICIO_EMISSAO)
    FROM PAF_R04
    WHERE PAF_R04.DDATA_INICIO_EMISSAO IS NOT NULL AND PAF_R04.DDATA_INICIO_EMISSAO >= CURRENT_DATE - 180
    INTO :DATAR04;
    
    SELECT MAX(PAF_R06.DDATA_FINAL_EMISSAO)
    FROM PAF_R06
    WHERE PAF_R06.DDATA_FINAL_EMISSAO IS NOT NULL AND PAF_R06.DDATA_FINAL_EMISSAO >= CURRENT_DATE - 180
    INTO :DATAR06;

    DATAPAF = :DATAR02;
    IF ((:DATAR04 > :DATAPAF) OR (:DATAPAF IS NULL)) THEN
       DATAPAF = :DATAR04;
    IF ((:DATAR06 > :DATAPAF) OR (:DATAPAF IS NULL)) THEN
       DATAPAF = :DATAR06;

    SELECT
       FIRST 1
       PAF_R02.NUMERO_FABRICACAO,
       PAF_R02.THORA_EMISSAO
    FROM PAF_R02
    WHERE
      PAF_R02.DDATA_EMISSAO = :DATAPAF AND
      PAF_R02.THORA_EMISSAO IS NOT NULL
    ORDER BY
      PAF_R02.DDATA_EMISSAO
    INTO
      :NUMERO_FABRICACAOR02,
      :HORAR02;
    
    SELECT
       FIRST 1
       PAF_R04.NUMERO_FABRICACAO,
       PAF_R04.THORA_INICIO_EMISSAO
    FROM PAF_R04
    WHERE
      PAF_R04.DDATA_INICIO_EMISSAO = :DATAPAF AND
      PAF_R04.HORA_INICIO_EMISSAO IS NOT NULL
    ORDER BY
      PAF_R04.THORA_INICIO_EMISSAO
    INTO
      :NUMERO_FABRICACAOR04,
      :HORAR04;
    
    SELECT
       FIRST 1
       PAF_R06.NUMERO_FABRICACAO,
       PAF_R06.THORA_FINAL_EMISSAO
    FROM PAF_R06
    WHERE
      PAF_R06.DDATA_FINAL_EMISSAO = :DATAPAF AND
      PAF_R06.HORA_FINAL_EMISSAO IS NOT NULL
    ORDER BY
      PAF_R06.THORA_FINAL_EMISSAO
    INTO
      :NUMERO_FABRICACAOR06,
      :HORAR06;

    NUMERO_FABRICACAOPAF = :NUMERO_FABRICACAOR02;
    HORAPAF = :HORAR02;
    IF ((:HORAR04 < :HORAPAF) OR (:HORAPAF IS NULL)) THEN
     BEGIN
       NUMERO_FABRICACAOPAF = :NUMERO_FABRICACAOR04;
       HORAPAF = :HORAR04;
     END
    IF ((:HORAR06 < :HORAPAF) OR (:HORAPAF IS NULL)) THEN
     BEGIN
       NUMERO_FABRICACAOPAF = :NUMERO_FABRICACAOR06;
       HORAPAF = :HORAR06;
     END

    SELECT
      MF_ADICIONAL,
      TIPO_ECF,
      MARCA_ECF,
      MODELO_ECF
    FROM
      PAF_R01
    WHERE
      NUMERO_FABRICACAO = :NUMERO_FABRICACAOPAF
    INTO
      :MF_ADICIONALPAF,
      :TIPO_ECFPAF,
      :MARCA_ECFPAF,
      :MODELO_ECFPAF;

    IF ((:NUMERO_FABRICACAOPAF IS NOT NULL) AND (:NUMERO_FABRICACAOPAF <> '')) THEN
       SUSPEND;
END ^

ALTER PROCEDURE SP_RETORNA_ENTREGAS (DATA DATE)
RETURNS (CD_VENDA DOUBLE PRECISION,
CD_CLIENTE DOUBLE PRECISION,
TROCO DOUBLE PRECISION,
STATUS VARCHAR(1) CHARACTER SET NONE,
TOTAL DOUBLE PRECISION)
AS 
declare variable TOTAL_CANCELADO double precision;
declare variable EXISTE integer;
BEGIN
  FOR
    SELECT
     VENDAS.CD_VENDA,
     VENDAS.CD_CLIENTE,
     VENDAS.TROCO,
     VENDAS.STATUS,
     SUM(VENDAS.PRECO_TOTAL) AS TOTAL
    FROM 
     VENDAS
    WHERE
     VENDAS.DATA_CAIXA >= :DATA AND
     VENDAS.ENTREGA = 'S' AND
     VENDAS.CONCLUIDO = 'S' AND
     VENDAS.STATUS <> 'V' AND VENDAS.STATUS <> 'I' AND VENDAS.STATUS <> 'C' AND
     VENDAS.TIPO_VENDA <> 'D'
    GROUP BY
     VENDAS.CD_VENDA,
     VENDAS.CD_CLIENTE,
     VENDAS.TROCO,
     VENDAS.STATUS,
     VENDAS.TIPO_VENDA
    INTO
     :CD_VENDA, :CD_CLIENTE, :TROCO, :STATUS, :TOTAL
  DO
   BEGIN
        SELECT
         SUM(VENDAS.PRECO_TOTAL) * -1 AS TOTAL
        FROM 
         VENDAS
        WHERE
         VENDAS.CD_VENDA = :CD_VENDA AND
         VENDAS.TIPO_VENDA = 'D'
        INTO
         :TOTAL_CANCELADO;

        IF (:TOTAL_CANCELADO IS NULL) THEN
           TOTAL_CANCELADO = 0;

        TOTAL = :TOTAL - :TOTAL_CANCELADO;
        SELECT COUNT(*) FROM ENTREGAS WHERE CD_VENDA = :CD_VENDA INTO :EXISTE;
        IF ((:EXISTE > 0) AND (:TOTAL > 0)) THEN
           SUSPEND;
   END
END ^

ALTER PROCEDURE SP_RETORNA_FILIAL_ESTOQUE (ID_PRODUTO DOUBLE PRECISION)
RETURNS (CD_FILIAL DOUBLE PRECISION,
NOME VARCHAR(100) CHARACTER SET NONE,
ESTOQUE NUMERIC(15, 2))
AS 
declare variable COMANDO varchar(1000);
BEGIN
  FOR
    SELECT CD_FILIAL, NOME FROM FILIAIS INTO :CD_FILIAL, :NOME
  DO
   BEGIN
     COMANDO = '';
     ESTOQUE = 0;
     COMANDO = 'SELECT ESTOQUE_'||CAST(:CD_FILIAL AS INTEGER)||' FROM PRODUTOS WHERE ID_PRODUTO = '||CAST(:ID_PRODUTO AS INTEGER);
     EXECUTE STATEMENT :COMANDO INTO :ESTOQUE;
     IF (:ESTOQUE > 0) THEN
        SUSPEND;
   END
END ^

