ALTER PROCEDURE SP_RETORNA_MEDIA_METAS (CD_FILIAL DOUBLE PRECISION,
MESES INTEGER)
RETURNS (METAVALOR DOUBLE PRECISION,
METAQUANTIDADE DOUBLE PRECISION,
METACLIENTES DOUBLE PRECISION,
METATICKET DOUBLE PRECISION,
VALOR DOUBLE PRECISION,
QUANTIDADE DOUBLE PRECISION,
CLIENTES DOUBLE PRECISION,
TICKET DOUBLE PRECISION)
AS 
BEGIN
   SELECT
    SUM(SP_RETORNA_ULTIMAS_METAS.METAVALOR),
    SUM(SP_RETORNA_ULTIMAS_METAS.METAQUANTIDADE),
    SUM(SP_RETORNA_ULTIMAS_METAS.METACLIENTES),
    SUM(SP_RETORNA_ULTIMAS_METAS.METATICKET),
    SUM(SP_RETORNA_ULTIMAS_METAS.VALOR),
    SUM(SP_RETORNA_ULTIMAS_METAS.QUANTIDADE),
    SUM(SP_RETORNA_ULTIMAS_METAS.CLIENTES),
    SUM(SP_RETORNA_ULTIMAS_METAS.TICKET)
   FROM
    SP_RETORNA_ULTIMAS_METAS (:CD_FILIAL, :MESES)
   INTO
    :METAVALOR,
    :METAQUANTIDADE,
    :METACLIENTES,
    :METATICKET,
    :VALOR,
    :QUANTIDADE,
    :CLIENTES,
    :TICKET;

   METAVALOR = :METAVALOR / :MESES;
   METAQUANTIDADE = :METAQUANTIDADE / :MESES;
   METACLIENTES = :METACLIENTES / :MESES;
   METATICKET = :METATICKET / :MESES;
   VALOR = :VALOR / :MESES;
   QUANTIDADE = :QUANTIDADE / :MESES;
   CLIENTES = :CLIENTES / :MESES;
   TICKET = :TICKET / :MESES;

   SUSPEND;
END ^

ALTER PROCEDURE SP_RETORNA_MELHORES_CLIENTES (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (CLIENTE DOUBLE PRECISION,
VALOR DOUBLE PRECISION)
AS 
BEGIN
 FOR
    SELECT
     LANCAMENTOS.CD_CLIENTE,
     MAX(LANCAMENTOS.VALOR)
    FROM
     LANCAMENTOS
    WHERE
     (LANCAMENTOS.TIPO_VENDA = 'V' OR
      LANCAMENTOS.TIPO_VENDA = 'D') AND
     LANCAMENTOS.CD_CLIENTE IS NOT NULL AND
     LANCAMENTOS.DATA_CAIXA >= :DATAINICIAL AND
     LANCAMENTOS.DATA_CAIXA <= :DATAFINAL
    GROUP BY
     LANCAMENTOS.CD_CLIENTE
    INTO
     :CLIENTE,
     :VALOR
  DO
   BEGIN
     SUSPEND;
   END
END ^

ALTER PROCEDURE SP_RETORNA_PRODUTOS_NAOCONTADOS (CD_FILIAL DOUBLE PRECISION,
ID_BALANCO DOUBLE PRECISION)
RETURNS (ID_PRODUTO DOUBLE PRECISION,
CD_PRODUTO VARCHAR(6) CHARACTER SET NONE,
DESCRICAO VARCHAR(100) CHARACTER SET NONE,
CD_GRUPO DOUBLE PRECISION,
CD_CLASSE DOUBLE PRECISION,
CD_LABORATORIO DOUBLE PRECISION,
GRUPO VARCHAR(100) CHARACTER SET NONE,
CLASSE VARCHAR(100) CHARACTER SET NONE,
LABORATORIO VARCHAR(100) CHARACTER SET NONE)
AS 
BEGIN
 FOR
   SELECT
    BALANCO.ID_PRODUTO,
    BALANCO.CD_PRODUTO,
    BALANCO.DESCRICAO,
    BALANCO.CD_GRUPO,
    BALANCO.CD_CLASSE,
    BALANCO.CD_LABORATORIO
   FROM
    BALANCO
   WHERE
    BALANCO.CD_FILIAL = :CD_FILIAL AND
    BALANCO.ID_BALANCO = :ID_BALANCO AND
    BALANCO.ESTOQUE = 0
   INTO
    :ID_PRODUTO,
    :CD_PRODUTO,
    :DESCRICAO,
    :CD_GRUPO,
    :CD_CLASSE,
    :CD_LABORATORIO
 DO
  BEGIN
    SELECT DESCRICAO FROM GRUPOS WHERE CD_GRUPO = :CD_GRUPO INTO :GRUPO;
    SELECT DESCRICAO FROM CLASSES WHERE CD_CLASSE = :CD_CLASSE INTO :CLASSE;
    SELECT NOME FROM LABORATORIOS WHERE CD_LABORATORIO = :CD_LABORATORIO INTO :LABORATORIO;
    SUSPEND;
  END
END ^

ALTER PROCEDURE SP_RETORNA_PROXIMA_NFCE RETURNS (NFCENUMERO VARCHAR(100) CHARACTER SET NONE)
AS 
declare variable ULTIMANOTA varchar(100);
declare variable EXISTE integer;
BEGIN
  SELECT COUNT(*) FROM NFCE WHERE STATUS = 'A' INTO :EXISTE;
  IF (:EXISTE = 0) THEN
   BEGIN
     EXECUTE PROCEDURE SP_POPULA_NFCE;
   END

  SELECT MAX(CAST(NUMERO_NOTA AS NUMERIC(15,0))) FROM NFCE
  WHERE DATA >= CURRENT_DATE - 30 AND (STATUS <> 'A')
  INTO :ULTIMANOTA; /* PEGA A ULTIMA NOTA ENVIADA OU GERADA(OFF-LINE) - STATUS <> 'A' E NOS ULTIMOS 30 DIAS */
  IF (:ULTIMANOTA IS NOT NULL) THEN
   BEGIN
     SELECT FIRST 1 NUMERO_NOTA FROM NFCE WHERE CAST(NUMERO_NOTA AS NUMERIC(15,0)) > CAST(:ULTIMANOTA AS NUMERIC(15,0)) AND STATUS = 'A' INTO :NFCENUMERO; /* PEGA O PROXIMO NUMERO DE NOTA A SER UTILIZADA */
     IF (:NFCENUMERO IS NULL) THEN
      BEGIN
        SELECT FIRST 1 NUMERO_NOTA FROM NFCE WHERE STATUS = 'A' INTO :NFCENUMERO;
      END
   END
  ELSE
   BEGIN
     SELECT FIRST 1 NUMERO_NOTA FROM NFCE WHERE STATUS = 'A' INTO :NFCENUMERO;
   END
  UPDATE NFCE SET DATA = CURRENT_DATE, STATUS = 'U' WHERE NUMERO_NOTA = :NFCENUMERO;
  SUSPEND;
END ^

ALTER PROCEDURE SP_RETORNA_ULTIMAS_METAS (CD_FILIAL DOUBLE PRECISION,
MESES INTEGER)
RETURNS (MESREF INTEGER,
ANOREF INTEGER,
DIASUTEIS DOUBLE PRECISION,
METAVALOR DOUBLE PRECISION,
METAQUANTIDADE DOUBLE PRECISION,
METACLIENTES DOUBLE PRECISION,
METATICKET DOUBLE PRECISION,
VALOR DOUBLE PRECISION,
QUANTIDADE DOUBLE PRECISION,
CLIENTES DOUBLE PRECISION,
TICKET DOUBLE PRECISION)
AS 
DECLARE VARIABLE ANOINICIAL INTEGER;
DECLARE VARIABLE ANOFINAL INTEGER;
DECLARE VARIABLE ANOS INTEGER;
DECLARE VARIABLE MESATUAL INTEGER;
DECLARE VARIABLE MESINICIAL INTEGER;
DECLARE VARIABLE MESFINAL INTEGER;
BEGIN
 IF (:MESES > 12) THEN
    EXIT;
 MESATUAL = EXTRACT(MONTH FROM CURRENT_DATE);
 MESFINAL = MESATUAL + 12;  
 ANOS = CAST(MESES / 12 AS INTEGER);
 IF (((:MESATUAL - :MESES) <= 0) AND (:ANOS = 0)) THEN
    ANOS = 1;
 ANOFINAL = EXTRACT(YEAR FROM CURRENT_DATE);
 ANOINICIAL = :ANOFINAL - :ANOS;
 MESINICIAL = MESFINAL - MESES;
 IF (:MESINICIAL > 12) THEN
    MESINICIAL = :MESINICIAL - 12;
 MESFINAL = :MESINICIAL + :MESES;
 IF (:MESFINAL > 12) THEN
  BEGIN
    MESFINAL = (:MESFINAL - 13);
    IF (:MESFINAL = 0) THEN
     BEGIN
       MESFINAL = 12;
       ANOFINAL = :ANOFINAL - 1;
     END
  END

 FOR
   SELECT
    METAS_FILIAIS.MESREF,
    METAS_FILIAIS.ANOREF,
    METAS_FILIAIS.DIASUTEIS,
    METAS_FILIAIS.METAVALOR,
    METAS_FILIAIS.METAQUANTIDADE,
    METAS_FILIAIS.METACLIENTES,
    METAS_FILIAIS.METATICKET,
    METAS_FILIAIS.ACUMULADOVALOR,
    METAS_FILIAIS.ACUMULADOQUANTIDADE,
    METAS_FILIAIS.ACUMULADOCLIENTES,
    METAS_FILIAIS.ACUMULADOTICKET
   FROM
    METAS_FILIAIS
   WHERE
    METAS_FILIAIS.CD_FILIAL = :CD_FILIAL AND
    CAST(METAS_FILIAIS.MESREF||'/01/'||METAS_FILIAIS.ANOREF AS DATE) >=
        CAST(:MESINICIAL||'/01/'||:ANOINICIAL AS DATE) AND
    CAST(METAS_FILIAIS.MESREF||'/01/'||METAS_FILIAIS.ANOREF AS DATE) <=
        CAST(:MESFINAL||'/01/'||(:ANOFINAL) AS DATE)
   INTO
    :MESREF,
    :ANOREF,
    :DIASUTEIS,
    :METAVALOR,
    :METAQUANTIDADE,
    :METACLIENTES,
    :METATICKET,
    :VALOR,
    :QUANTIDADE,
    :CLIENTES,
    :TICKET
 DO
  BEGIN
   SUSPEND;
  END
END ^

