 ANOFINAL = EXTRACT(YEAR FROM CURRENT_DATE);
 ANOINICIAL = :ANOFINAL - :ANOS;
 MESINICIAL = MESFINAL - MESES;
 IF (:MESINICIAL > 12) THEN
