ALTER PROCEDURE SP_RETORNA_ULTIMO_LANC_PROD (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (PRODUTO DOUBLE PRECISION,
LANCAMENTO DOUBLE PRECISION,
ESTOQUEPOS_VENDA DOUBLE PRECISION)
AS 
DECLARE VARIABLE COMANDO VARCHAR(1000);
DECLARE VARIABLE FILIAL DOUBLE PRECISION;
BEGIN
  FOR
   SELECT
    ID_PRODUTO,
    MAX(CD_LANCAMENTO)
   FROM
    LANCAMENTOS
   WHERE
    DATA_CAIXA >= :DATAINICIAL AND
    DATA_CAIXA <= :DATAFINAL
   GROUP BY
    ID_PRODUTO
   INTO
    :PRODUTO,
    :LANCAMENTO
   DO
    BEGIN
      SELECT ESTOQUE_POSVENDA FROM LANCAMENTOS WHERE CD_LANCAMENTO = :LANCAMENTO INTO :ESTOQUEPOS_VENDA;
      SELECT CD_FILIAL FROM PARAMETROS INTO :FILIAL;
      COMANDO = 'UPDATE PRODUTOS SET ESTOQUE_'||CAST(CAST(:FILIAL AS INTEGER) AS VARCHAR(1))||' = '||CAST(:ESTOQUEPOS_VENDA AS VARCHAR(15))||
                ' WHERE ID_PRODUTO = '||:PRODUTO;
      EXECUTE STATEMENT :COMANDO;
    END
END ^

