ALTER PROCEDURE SP_RETORNA_VENDAS_DIARIA (CD_FILIAL DOUBLE PRECISION,
DATAINI DATE,
DATAFIM DATE)
RETURNS (DATA DATE,
DIA VARCHAR(5) CHARACTER SET NONE,
VALOR DOUBLE PRECISION,
QUANTIDADE DOUBLE PRECISION,
CLIENTES DOUBLE PRECISION,
DESCONTO DOUBLE PRECISION,
LUCRO DOUBLE PRECISION,
TICKET DOUBLE PRECISION)
AS 
declare variable VALORCANCELADO double precision;
declare variable QUANTIDADECANCELADA double precision;
declare variable CLIENTESCANCELADOS double precision;
declare variable DESCONTOCANCELADO double precision;
declare variable CUSTO double precision;
declare variable CUSTOCANCELADO double precision;
declare variable VALORBRUTO double precision;
declare variable VALORBRUTOCANCELADO double precision;
BEGIN
  FOR
    SELECT
     LANCAMENTOS.DATA_LANCAMENTO
    FROM
     LANCAMENTOS
    WHERE
     LANCAMENTOS.DATA_LANCAMENTO >= :DATAINI AND
     LANCAMENTOS.DATA_LANCAMENTO <= :DATAFIM AND
     (LANCAMENTOS.TIPO_VENDA = 'V' OR LANCAMENTOS.TIPO_VENDA = 'D') AND
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL
    GROUP BY
     LANCAMENTOS.DATA_LANCAMENTO
    INTO
     :DATA
  DO
   BEGIN
      SELECT
       SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
       SUM(LANCAMENTOS.VALOR + LANCAMENTOS.DESCONTO + LANCAMENTOS.PROMOCAO - LANCAMENTOS.ARREDONDAMENTO),
       SUM(LANCAMENTOS.QUANTIDADE),
       SUM(LANCAMENTOS.CUSTO_UNITARIO * LANCAMENTOS.QUANTIDADE),
       SUM((LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE) + (LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)),
       COUNT(DISTINCT LANCAMENTOS.CD_VENDA)
      FROM
       LANCAMENTOS
      WHERE
       LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
       LANCAMENTOS.TIPO_VENDA = 'V' AND
       LANCAMENTOS.DATA_LANCAMENTO = :DATA AND
       LANCAMENTOS.CUSTO_UNITARIO > 0
      INTO
       :VALOR,
       :VALORBRUTO,
       :QUANTIDADE,
       :CUSTO,
       :DESCONTO,
       :CLIENTES;
    
      IF (:VALOR IS NULL) THEN
         VALOR = 0;
      IF (:VALORBRUTO IS NULL) THEN
         VALORBRUTO = 0;
      IF (:QUANTIDADE IS NULL) THEN
         QUANTIDADE = 0;
      IF (:CLIENTES IS NULL) THEN
         CLIENTES = 0;
      IF (:DESCONTO IS NULL) THEN
         DESCONTO = 0;
      IF (:CUSTO IS NULL) THEN
         CUSTO = 0;
    
      SELECT
       SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
       SUM(LANCAMENTOS.VALOR + LANCAMENTOS.DESCONTO + LANCAMENTOS.PROMOCAO - LANCAMENTOS.ARREDONDAMENTO),
       SUM(LANCAMENTOS.QUANTIDADE),
       SUM(LANCAMENTOS.CUSTO_UNITARIO * LANCAMENTOS.QUANTIDADE),
       SUM((LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE) + (LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)),
       COUNT(DISTINCT LANCAMENTOS.CD_VENDA)
      FROM
       LANCAMENTOS
      WHERE
       LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
       LANCAMENTOS.TIPO_VENDA = 'D' AND
       LANCAMENTOS.DATA_LANCAMENTO = :DATA AND
       LANCAMENTOS.CUSTO_UNITARIO > 0
      INTO
        :VALORCANCELADO,
        :VALORBRUTOCANCELADO,
        :QUANTIDADECANCELADA,
        :CUSTOCANCELADO,
        :DESCONTOCANCELADO,
        :CLIENTESCANCELADOS;

      IF (:VALORCANCELADO IS NULL) THEN
         VALORCANCELADO = 0;
      IF (:VALORBRUTOCANCELADO IS NULL) THEN
         VALORBRUTOCANCELADO = 0;
      IF (:QUANTIDADECANCELADA IS NULL) THEN
         QUANTIDADECANCELADA = 0;
      IF (:CLIENTESCANCELADOS IS NULL) THEN
         CLIENTESCANCELADOS = 0;
      IF (:DESCONTOCANCELADO IS NULL) THEN
         DESCONTOCANCELADO = 0;
      IF (:CUSTOCANCELADO IS NULL) THEN
         CUSTOCANCELADO = 0;
    
      VALOR = :VALOR - :VALORCANCELADO;
      VALORBRUTO = :VALORBRUTO - :VALORBRUTOCANCELADO;
      QUANTIDADE = :QUANTIDADE - :QUANTIDADECANCELADA;
      CLIENTES = :CLIENTES - :CLIENTESCANCELADOS;
      DESCONTO = :DESCONTO - :DESCONTOCANCELADO;
      CUSTO = :CUSTO - :CUSTOCANCELADO;

      IF ((:VALOR IS NULL) OR (:VALOR = 0)) THEN
         LUCRO = 0;
      ELSE
         LUCRO = ((:VALOR - :CUSTO) / :VALOR) * 100;
      IF ((:DESCONTO IS NULL) OR (:DESCONTO = 0)) THEN
         DESCONTO = 0;
      ELSE
         DESCONTO = (:DESCONTO / :VALORBRUTO) * 100;
      IF (:CLIENTES > 0) THEN
         TICKET = :VALOR / :CLIENTES;
      DIA = EXTRACT(DAY FROM :DATA)||'/'||EXTRACT(MONTH FROM :DATA);
    
      SUSPEND;
   END
END ^

ALTER PROCEDURE SP_RETORNA_VENDAS_DUPLICADAS RETURNS (CD_VENDA_DUPLICADA DOUBLE PRECISION,
VALOR_DUPLICADO DOUBLE PRECISION)
AS 
DECLARE VARIABLE CD_VENDA DOUBLE PRECISION;
DECLARE VARIABLE ID_PRODUTO DOUBLE PRECISION;
DECLARE VARIABLE HORA INTEGER;
DECLARE VARIABLE MINUTO INTEGER;
DECLARE VARIABLE SEGUNDO INTEGER;
BEGIN
    FOR
     SELECT
      DISTINCT CD_VENDA,
      ID_PRODUTO,
      CAST(SUBSTRING(HORA FROM 1 FOR 2) AS INTEGER),
      CAST(SUBSTRING(HORA FROM 4 FOR 2) AS INTEGER),
      CAST(SUBSTRING(HORA FROM 7 FOR 2) AS INTEGER)
     FROM
      LANCAMENTOS
     INTO
      :CD_VENDA, :ID_PRODUTO, :HORA, :MINUTO, SEGUNDO
    DO
     BEGIN
       FOR
           SELECT
            CD_VENDA,
            SUM(VALOR)
           FROM
            LANCAMENTOS
           WHERE
            ID_PRODUTO = ID_PRODUTO AND
            CD_VENDA > :CD_VENDA AND
            CAST(SUBSTRING(HORA FROM 1 FOR 2) AS INTEGER) = :HORA AND
            ((CAST(SUBSTRING(HORA FROM 4 FOR 2) AS INTEGER) - :MINUTO) = 0 OR
             (CAST(SUBSTRING(HORA FROM 4 FOR 2) AS INTEGER) - :MINUTO) = 1) AND
            (CAST(SUBSTRING(HORA FROM 7 FOR 2) AS INTEGER) - :SEGUNDO) >= 0 AND
            (CAST(SUBSTRING(HORA FROM 7 FOR 2) AS INTEGER) - :SEGUNDO) <= 3
           GROUP BY
            CD_VENDA
           INTO
            :CD_VENDA_DUPLICADA,
            :VALOR_DUPLICADO
       DO
        BEGIN
               IF ((:CD_VENDA_DUPLICADA IS NOT NULL) AND (:CD_VENDA_DUPLICADA > 0)) THEN
                  SUSPEND;
        END
     END
END ^

ALTER PROCEDURE SP_RETORNA_VENDAS_PERIODO (CD_FILIAL DOUBLE PRECISION,
DATAINI DATE,
DATAFIM DATE)
RETURNS (VALOR DOUBLE PRECISION,
QUANTIDADE DOUBLE PRECISION,
CLIENTES DOUBLE PRECISION,
DESCONTO DOUBLE PRECISION,
LUCRO DOUBLE PRECISION,
TICKET DOUBLE PRECISION)
AS 
declare variable VALORCANCELADO double precision;
declare variable QUANTIDADECANCELADA double precision;
declare variable CLIENTESCANCELADOS double precision;
declare variable DESCONTOCANCELADO double precision;
declare variable CUSTO double precision;
declare variable CUSTOCANCELADO double precision;
declare variable VALORBRUTO double precision;
declare variable VALORBRUTOCANCELADO double precision;
BEGIN
  VALOR = 0;
  VALORBRUTO = 0;
  QUANTIDADE = 0;
  CLIENTES = 0;
  DESCONTO = 0;
  CUSTO = 0;

  SELECT
   SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
   SUM(LANCAMENTOS.VALOR + LANCAMENTOS.DESCONTO + LANCAMENTOS.PROMOCAO - LANCAMENTOS.ARREDONDAMENTO),
   SUM(LANCAMENTOS.QUANTIDADE),
   SUM(LANCAMENTOS.CUSTO_UNITARIO * LANCAMENTOS.QUANTIDADE),
   SUM((LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE) + (LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)),
   COUNT(DISTINCT LANCAMENTOS.CD_VENDA)
  FROM
   LANCAMENTOS
  WHERE
   LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
   LANCAMENTOS.TIPO_VENDA = 'V' AND
   LANCAMENTOS.DATA_LANCAMENTO >= :DATAINI AND
   LANCAMENTOS.DATA_LANCAMENTO <= :DATAFIM AND
   LANCAMENTOS.CUSTO_MEDIO > 0
  INTO
   :VALOR,
   :VALORBRUTO,
   :QUANTIDADE,
   :CUSTO,
   :DESCONTO,
   :CLIENTES;

  IF (:VALOR IS NULL) THEN
     VALOR = 0;
  IF (:VALORBRUTO IS NULL) THEN
     VALORBRUTO = 0;
  IF (:QUANTIDADE IS NULL) THEN
     QUANTIDADE = 0;
  IF (:CLIENTES IS NULL) THEN
     CLIENTES = 0;
  IF (:DESCONTO IS NULL) THEN
     DESCONTO = 0;
  IF (:CUSTO IS NULL) THEN
     CUSTO = 0;

  VALORCANCELADO = 0;
  VALORBRUTOCANCELADO = 0;
  QUANTIDADECANCELADA = 0;
  CLIENTESCANCELADOS = 0;
  DESCONTOCANCELADO = 0;
  CUSTOCANCELADO = 0;

  SELECT
   SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
   SUM(LANCAMENTOS.VALOR + LANCAMENTOS.DESCONTO + LANCAMENTOS.PROMOCAO - LANCAMENTOS.ARREDONDAMENTO),
   SUM(LANCAMENTOS.QUANTIDADE),
   SUM(LANCAMENTOS.CUSTO_UNITARIO * LANCAMENTOS.QUANTIDADE),
   SUM((LANCAMENTOS.DESCONTO * LANCAMENTOS.QUANTIDADE) + (LANCAMENTOS.PROMOCAO * LANCAMENTOS.QUANTIDADE)),
   COUNT(DISTINCT LANCAMENTOS.CD_VENDA)
  FROM
   LANCAMENTOS
  WHERE
   LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
   LANCAMENTOS.TIPO_VENDA = 'D' AND
   LANCAMENTOS.DATA_LANCAMENTO >= :DATAINI AND
   LANCAMENTOS.DATA_LANCAMENTO <= :DATAFIM AND
   LANCAMENTOS.CUSTO_MEDIO > 0
  INTO
   :VALORCANCELADO,
   :VALORBRUTOCANCELADO,
   :QUANTIDADECANCELADA,
   :CUSTOCANCELADO,
   :DESCONTOCANCELADO,
   :CLIENTESCANCELADOS;

  IF (:VALORCANCELADO IS NULL) THEN
     VALORCANCELADO = 0;
  IF (:VALORBRUTOCANCELADO IS NULL) THEN
     VALORBRUTOCANCELADO = 0;
  IF (:QUANTIDADECANCELADA IS NULL) THEN
     QUANTIDADECANCELADA = 0;
  IF (:CLIENTESCANCELADOS IS NULL) THEN
     CLIENTESCANCELADOS = 0;
  IF (:DESCONTOCANCELADO IS NULL) THEN
     DESCONTOCANCELADO = 0;
  IF (:CUSTOCANCELADO IS NULL) THEN
     CUSTOCANCELADO = 0;

  VALOR = :VALOR - :VALORCANCELADO;
  VALORBRUTO = :VALORBRUTO - :VALORBRUTOCANCELADO;
  QUANTIDADE = :QUANTIDADE - :QUANTIDADECANCELADA;
  CLIENTES = :CLIENTES - :CLIENTESCANCELADOS;
  DESCONTO = :DESCONTO - :DESCONTOCANCELADO;
  CUSTO = :CUSTO - :CUSTOCANCELADO;

  IF ((:VALOR IS NULL) OR (:VALOR = 0)) THEN
     LUCRO = 0;
  ELSE
     LUCRO = ((:VALOR - :CUSTO) / :VALOR) * 100;
  IF ((:DESCONTO IS NULL) OR (:DESCONTO = 0)) THEN
     DESCONTO = 0;
  ELSE
     DESCONTO = (:DESCONTO / :VALORBRUTO) * 100;
  IF (:CLIENTES > 0) THEN
     TICKET = :VALOR / :CLIENTES;

  SUSPEND;
END ^

ALTER PROCEDURE SP_RETORNA_VENDAS_REDE (DATAINI DATE,
DATAFIM DATE)
RETURNS (VALOR DOUBLE PRECISION,
QUANTIDADE DOUBLE PRECISION,
CLIENTES DOUBLE PRECISION,
DESCONTO DOUBLE PRECISION,
LUCRO DOUBLE PRECISION,
TICKET DOUBLE PRECISION)
AS 
DECLARE VARIABLE VALORCANCELADO DOUBLE PRECISION;
DECLARE VARIABLE QUANTIDADECANCELADA DOUBLE PRECISION;
DECLARE VARIABLE CLIENTESCANCELADOS DOUBLE PRECISION;
DECLARE VARIABLE DESCONTOCANCELADO DOUBLE PRECISION;
DECLARE VARIABLE CUSTO DOUBLE PRECISION;
DECLARE VARIABLE CUSTOCANCELADO DOUBLE PRECISION;
BEGIN
  SELECT
   SUM(LANCAMENTOS.VALOR),
   SUM(LANCAMENTOS.QUANTIDADE),
   COUNT(DISTINCT LANCAMENTOS.CD_VENDA),
   SUM(LANCAMENTOS.DESCONTO),
   SUM(LANCAMENTOS.CUSTO_UNITARIO * LANCAMENTOS.QUANTIDADE)
  FROM
   LANCAMENTOS
  WHERE
   LANCAMENTOS.TIPO_VENDA = 'V' AND
   LANCAMENTOS.DATA_LANCAMENTO >= :DATAINI AND
   LANCAMENTOS.DATA_LANCAMENTO <= :DATAFIM AND
   LANCAMENTOS.CUSTO_UNITARIO > 0
  INTO
   :VALOR,
   :QUANTIDADE,
   :CLIENTES,
   :DESCONTO,
   :CUSTO;

  IF (:VALOR IS NULL) THEN
     VALOR = 0;
  IF (:QUANTIDADE IS NULL) THEN
     QUANTIDADE = 0;
  IF (:CLIENTES IS NULL) THEN
     CLIENTES = 0;
  IF (:DESCONTO IS NULL) THEN
     DESCONTO = 0;
  IF (:CUSTO IS NULL) THEN
     CUSTO = 0;

  SELECT
   SUM(LANCAMENTOS.VALOR),
   SUM(LANCAMENTOS.QUANTIDADE),
   COUNT(DISTINCT LANCAMENTOS.CD_VENDA),
   SUM(LANCAMENTOS.DESCONTO),
   SUM(LANCAMENTOS.CUSTO_UNITARIO * LANCAMENTOS.QUANTIDADE)
  FROM
   LANCAMENTOS
  WHERE
   LANCAMENTOS.TIPO_VENDA = 'D' AND
   LANCAMENTOS.DATA_LANCAMENTO >= :DATAINI AND
   LANCAMENTOS.DATA_LANCAMENTO <= :DATAFIM AND
   LANCAMENTOS.CUSTO_UNITARIO > 0
  INTO
   :VALORCANCELADO,
   :QUANTIDADECANCELADA,
   :CLIENTESCANCELADOS,
   :DESCONTOCANCELADO,
   :CUSTOCANCELADO;

  IF (:VALORCANCELADO IS NULL) THEN
     VALORCANCELADO = 0;
  IF (:QUANTIDADECANCELADA IS NULL) THEN
     QUANTIDADECANCELADA = 0;
  IF (:CLIENTESCANCELADOS IS NULL) THEN
     CLIENTESCANCELADOS = 0;
  IF (:DESCONTOCANCELADO IS NULL) THEN
     DESCONTOCANCELADO = 0;
  IF (:CUSTOCANCELADO IS NULL) THEN
     CUSTOCANCELADO = 0;

  VALOR = :VALOR - :VALORCANCELADO;
  QUANTIDADE = :QUANTIDADE - :QUANTIDADECANCELADA;
  CLIENTES = :CLIENTES - :CLIENTESCANCELADOS;
  DESCONTO = :DESCONTO - :DESCONTOCANCELADO;
  CUSTO = :CUSTO - :CUSTOCANCELADO;
  IF ((:DESCONTO IS NULL) OR (:DESCONTO = 0)) THEN
     DESCONTO = 0;
  ELSE
     DESCONTO = (:DESCONTO * 100) / (:VALOR + :DESCONTO);
  IF ((:VALOR IS NULL) OR (:VALOR = 0)) THEN
     LUCRO = 0;
  ELSE
     LUCRO = ((:VALOR - :CUSTO) / :VALOR) * 100;
  IF (:CLIENTES > 0) THEN
     TICKET = :VALOR / :CLIENTES;

  SUSPEND;
END ^

ALTER PROCEDURE SP_SALDO_COMISSAO RETURNS (CD_SALDO_COMISSAO DOUBLE PRECISION,
CD_FILIAL DOUBLE PRECISION,
CD_VENDEDOR DOUBLE PRECISION,
DATA DATE,
VALORAVISTA DOUBLE PRECISION,
VALORAVISTACANCELADO DOUBLE PRECISION,
VALORAPRAZO DOUBLE PRECISION,
VALORPRAZOCANCELADO DOUBLE PRECISION,
VALORAPRAZOLIBERADO DOUBLE PRECISION,
SALDOANTERIORAVISTA DOUBLE PRECISION,
SALDOAVISTA DOUBLE PRECISION,
SALDOANTERIORAPRAZO DOUBLE PRECISION,
SALDOAPRAZO DOUBLE PRECISION,
SALDOANTERIORPREMIACAO DOUBLE PRECISION,
SALDOPREMIACAO DOUBLE PRECISION,
VENDEDOR VARCHAR(100) CHARACTER SET NONE,
FILIAL VARCHAR(100) CHARACTER SET NONE)
AS 
BEGIN
 SELECT MAX(DATA) FROM SALDO_COMISSAO INTO :DATA;

 FOR
  SELECT
   SALDO_COMISSAO.CD_SALDO_COMISSAO,
   SALDO_COMISSAO.CD_FILIAL,
   SALDO_COMISSAO.CD_VENDEDOR,
   SALDO_COMISSAO.DATA,
   SALDO_COMISSAO.VALORAVISTA,
   SALDO_COMISSAO.VALORAVISTACANCELADO,
   SALDO_COMISSAO.VALORAPRAZO,
   SALDO_COMISSAO.VALORPRAZOCANCELADO,
   SALDO_COMISSAO.VALORAPRAZOLIBERADO,
   SALDO_COMISSAO.SALDOANTERIORAVISTA,
   SALDO_COMISSAO.SALDOAVISTA,
   SALDO_COMISSAO.SALDOANTERIORAPRAZO,
   SALDO_COMISSAO.SALDOAPRAZO,
   SALDO_COMISSAO.SALDOANTERIORPREMIACAO,
   SALDO_COMISSAO.SALDOPREMIACAO,
   VENDEDORES.NOME,
   FILIAIS.NOME
  FROM
   SALDO_COMISSAO,
   VENDEDORES,
   FILIAIS
  WHERE
   SALDO_COMISSAO.CD_VENDEDOR = VENDEDORES.CD_VENDEDOR AND
   SALDO_COMISSAO.CD_FILIAL = FILIAIS.CD_FILIAL AND
   SALDO_COMISSAO.DATA = :DATA
  INTO
   :CD_SALDO_COMISSAO,
   :CD_FILIAL,
   :CD_VENDEDOR,
   :DATA,
   :VALORAVISTA,
   :VALORAVISTACANCELADO,
   :VALORAPRAZO,
   :VALORPRAZOCANCELADO,
   :VALORAPRAZOLIBERADO,
   :SALDOANTERIORAVISTA,
   :SALDOAVISTA,
   :SALDOANTERIORAPRAZO,
   :SALDOAPRAZO,
   :SALDOANTERIORPREMIACAO,
   :SALDOPREMIACAO,
   :VENDEDOR,
   :FILIAL
 DO
  BEGIN
   SUSPEND;
  END
END ^

ALTER PROCEDURE SP_SINTEGRAR60I_PREENCHE_ORDEM (FILIAL INTEGER,
DATAINICIAL DATE,
DATAFINAL DATE)
AS 
DECLARE VARIABLE ORDEM INTEGER;
DECLARE VARIABLE COO INTEGER;
DECLARE VARIABLE SERIE VARCHAR(20);
DECLARE VARIABLE CODIGO DOUBLE PRECISION;
BEGIN
  FOR
   SELECT
    COO, NRO_SERIE_EQP
   FROM
    SINTEGRA_R60I
   WHERE
    CD_FILIAL = :FILIAL AND
    DATAHORA >= :DATAINICIAL AND
    DATAHORA <= :DATAFINAL
   GROUP BY
    COO, NRO_SERIE_EQP
   INTO
    :COO, :SERIE
  DO
   BEGIN
     ORDEM = 1;

     FOR
      SELECT
       COD_SINTEGRA_R60I
      FROM
       SINTEGRA_R60I
      WHERE
       COO = :COO AND
       NRO_SERIE_EQP = :SERIE
      ORDER BY
       COD_SINTEGRA_R60I
      INTO
       :CODIGO
     DO
      BEGIN
         UPDATE SINTEGRA_R60I SET
          NRO_ORDEM_ITEM = :ORDEM
         WHERE
          CD_FILIAL = :FILIAL AND
          COD_SINTEGRA_R60I = :CODIGO;

         ORDEM = :ORDEM + 1;
      END
   END
END ^

ALTER PROCEDURE SP_SINTEGRA_ACERTA_75 (DATAINICIAL DATE,
DATAFINAL DATE)
AS 
declare variable REF_PRODUTOS varchar(100);
declare variable EXISTE integer;
declare variable COD_PEDIDOS_ITENS double precision;
declare variable CD_FILIAL double precision;
declare variable ALIQUOTA_ICMS double precision;
declare variable DATAHORA timestamp;
declare variable PRODUTO varchar(100);
declare variable APR_UND varchar(100);
declare variable NRO_SERIE_EQP varchar(100);
declare variable SALIQUOTA_ICMS varchar(100);
BEGIN
  FOR
    SELECT DISTINCT REF_PRODUTOS, NRO_SERIE_EQP  FROM SINTEGRA_R60I WHERE DATAHORA >= :DATAINICIAL AND DATAHORA <= :DATAFINAL INTO :REF_PRODUTOS, :NRO_SERIE_EQP
  DO
   BEGIN
    SELECT COUNT(*) FROM SINTEGRA_PEDIDOS_ITENS WHERE DATAHORA >= :DATAINICIAL AND DATAHORA <= :DATAFINAL AND NRO_SERIE_EQP = :NRO_SERIE_EQP AND REF_PRODUTOS = :REF_PRODUTOS INTO :EXISTE;
    IF (:EXISTE = 0) THEN
     BEGIN
        SELECT ID FROM SP_RETORNAID('COD_PEDIDOS_ITENS') INTO :COD_PEDIDOS_ITENS;
        SELECT FIRST 1
          CD_FILIAL,
          REF_PRODUTOS,
          ALIQUOTA_ICMS,
          DATAHORA
        FROM SINTEGRA_R60I
        WHERE DATAHORA >= :DATAINICIAL AND DATAHORA <= :DATAFINAL AND NRO_SERIE_EQP = :NRO_SERIE_EQP AND REF_PRODUTOS = :REF_PRODUTOS
        INTO
          :CD_FILIAL,
          :REF_PRODUTOS,
          :SALIQUOTA_ICMS,
          :DATAHORA;

        IF ((:SALIQUOTA_ICMS <> 'F') AND (:SALIQUOTA_ICMS <> 'I') AND (:SALIQUOTA_ICMS <> 'N') AND (:SALIQUOTA_ICMS <> 'CANC') AND (:SALIQUOTA_ICMS <> 'DESC')) THEN
           ALIQUOTA_ICMS = CAST(:ALIQUOTA_ICMS AS NUMERIC(15,0)) / 100;

        SELECT DESCRICAO, UNIDADE FROM PRODUTOS WHERE CODIGO_BARRAS_1 = :REF_PRODUTOS OR CODIGO_BARRAS_2 = :REF_PRODUTOS INTO :PRODUTO, :APR_UND;
        IF (:PRODUTO IS NULL) THEN
            PRODUTO = '';
        IF ((:APR_UND IS NULL) OR (APR_UND = '')) THEN
           APR_UND = 'UN';

        INSERT INTO SINTEGRA_PEDIDOS_ITENS VALUES (:COD_PEDIDOS_ITENS, :CD_FILIAL, :NRO_SERIE_EQP, :REF_PRODUTOS, NULL, :PRODUTO, :APR_UND, NULL, 0, :ALIQUOTA_ICMS, 0, 0, :DATAHORA,  '');

     END
   END
END ^

ALTER PROCEDURE SP_SINTEGRA_R75 (FILIAL INTEGER,
DATAINICIAL DATE,
DATAFINAL DATE,
DATA74 DATE,
GERA74 VARCHAR(1) CHARACTER SET NONE,
GERA54 VARCHAR(1) CHARACTER SET NONE,
GERA60 VARCHAR(1) CHARACTER SET NONE,
GERA61 VARCHAR(1) CHARACTER SET NONE)
RETURNS (REF_PRODUTOS VARCHAR(30) CHARACTER SET NONE,
CL_FIS VARCHAR(15) CHARACTER SET NONE,
PRODUTO VARCHAR(60) CHARACTER SET NONE,
APR_UND VARCHAR(6) CHARACTER SET NONE,
S_TRIB VARCHAR(15) CHARACTER SET NONE,
ALIQUOTA_IPI NUMERIC(15, 2),
ALIQUOTA_ICMS NUMERIC(15, 2),
REDUCAO_BASE_ICMS NUMERIC(15, 2),
BASE_ICMS_SUBST NUMERIC(15, 2),
DATAHORA TIMESTAMP)
AS 
declare variable EXISTE integer;
declare variable REFERENCIA varchar(14);
declare variable DATA date;
declare variable MES integer;
declare variable ANO integer;
declare variable DIA integer;
BEGIN
  DELETE FROM TEMP_SINTEGRA_R75;

  IF (:GERA74 = 'S') THEN
   BEGIN
      --DIA = EXTRACT(DAY FROM :DATA74);
      --IF (DIA >= 28) THEN
      --   DATA74 = DATA74 + 1;

      MES = EXTRACT(MONTH FROM :DATA74);
      ANO = EXTRACT(YEAR FROM :DATA74);
      DATA = CAST(:MES||'/01/'||:ANO AS DATE);
    
      FOR
        SELECT
         CAST(PRODUTOS.CODIGO_BARRAS_1 AS VARCHAR(30)),
         CAST(PRODUTOS.NCM AS VARCHAR(15)),
         PRODUTOS.DESCRICAO,
         CAST(PRODUTOS.UNIDADE AS VARCHAR(6)),
         CAST(PRODUTOS.SITUACAOTRIBUTARIA AS VARCHAR(15)),
         CAST(0 AS NUMERIC(15,2)),
         CAST(0 AS NUMERIC(15,2)),
         CAST(0 AS NUMERIC(15,2)),
         CAST(0 AS NUMERIC(15,2)),
         CAST(:DATAFINAL AS TIMESTAMP)
        FROM
         PRODUTOS LEFT OUTER JOIN POSICAOESTOQUEDATA ON PRODUTOS.ID_PRODUTO = POSICAOESTOQUEDATA.ID_PRODUTO
                  LEFT OUTER JOIN PRODUTOS_FISCO ON PRODUTOS.ID_PRODUTO = PRODUTOS_FISCO.ID_PRODUTO
        WHERE
         POSICAOESTOQUEDATA.DATA = :DATA AND
         POSICAOESTOQUEDATA.CD_FILIAL = :FILIAL AND
         POSICAOESTOQUEDATA.QUANTIDADE > 0 AND
         PRODUTOS.STATUS <> 'P'
        INTO
         :REF_PRODUTOS,
         :CL_FIS,
         :PRODUTO,
         :APR_UND,
         :S_TRIB,
         :ALIQUOTA_IPI,
         :ALIQUOTA_ICMS,
         :REDUCAO_BASE_ICMS,
         :BASE_ICMS_SUBST,
         :DATAHORA
      DO
       BEGIN
         IF ((:APR_UND IS NULL) OR (:APR_UND = '')) THEN
            APR_UND = 'UN';
         SELECT RESULT FROM STR_ZERO(:REF_PRODUTOS, 14) INTO :REFERENCIA;
         SELECT COUNT(*) FROM TEMP_SINTEGRA_R75 WHERE REF_PRODUTOS = :REFERENCIA INTO :EXISTE;
         IF (:EXISTE = 0) THEN
            INSERT INTO TEMP_SINTEGRA_R75 VALUES (:REFERENCIA, :CL_FIS, :PRODUTO, :APR_UND, :S_TRIB, :ALIQUOTA_IPI, :ALIQUOTA_ICMS, :REDUCAO_BASE_ICMS, :BASE_ICMS_SUBST, :DATAHORA);
       END
   END

  IF (:GERA60 = 'S') THEN
   BEGIN
      FOR
        SELECT
         DISTINCT
         SINTEGRA_PEDIDOS_ITENS.REF_PRODUTOS,
         SINTEGRA_PEDIDOS_ITENS.CL_FIS,
         SINTEGRA_PEDIDOS_ITENS.PRODUTO,
         SINTEGRA_PEDIDOS_ITENS.APR_UND,
         SINTEGRA_PEDIDOS_ITENS.S_TRIB,
         SINTEGRA_PEDIDOS_ITENS.ALIQUOTA_IPI,
         SINTEGRA_PEDIDOS_ITENS.ALIQUOTA_ICMS,
         SINTEGRA_PEDIDOS_ITENS.REDUCAO_BASE_ICMS,
         SINTEGRA_PEDIDOS_ITENS.BASE_ICMS_SUBST,
         SINTEGRA_PEDIDOS_ITENS.DATAHORA
        FROM
         SINTEGRA_PEDIDOS_ITENS
        WHERE
         SINTEGRA_PEDIDOS_ITENS.CD_FILIAL = :FILIAL AND
         CAST(SINTEGRA_PEDIDOS_ITENS.DATAHORA AS DATE) >= :DATAINICIAL AND
         CAST(SINTEGRA_PEDIDOS_ITENS.DATAHORA AS DATE) <= :DATAFINAL
        INTO
         :REF_PRODUTOS,
         :CL_FIS,
         :PRODUTO,
         :APR_UND,
         :S_TRIB,
         :ALIQUOTA_IPI,
         :ALIQUOTA_ICMS,
         :REDUCAO_BASE_ICMS,
         :BASE_ICMS_SUBST,
         :DATAHORA
      DO
       BEGIN
         IF ((:APR_UND IS NULL) OR (:APR_UND = '')) THEN
            APR_UND = 'UN';
         SELECT RESULT FROM STR_ZERO(:REF_PRODUTOS, 14) INTO :REFERENCIA;
         SELECT COUNT(*) FROM TEMP_SINTEGRA_R75 WHERE REF_PRODUTOS = :REFERENCIA INTO :EXISTE;
         IF (:EXISTE = 0) THEN
            INSERT INTO TEMP_SINTEGRA_R75 VALUES (:REFERENCIA, :CL_FIS, :PRODUTO, :APR_UND, :S_TRIB, :ALIQUOTA_IPI, :ALIQUOTA_ICMS, :REDUCAO_BASE_ICMS, :BASE_ICMS_SUBST, :DATAHORA);
       END
   END

  IF (:GERA54 = 'S') THEN
   BEGIN
      FOR
        SELECT
         DISTINCT
         SINTEGRA_NF_ENTRADA_ITENS.REF_PRODUTOS,
         SINTEGRA_NF_ENTRADA_ITENS.CL_FIS,
         SINTEGRA_NF_ENTRADA_ITENS.PRODUTO,
         SINTEGRA_NF_ENTRADA_ITENS.APR_UND,
         SINTEGRA_NF_ENTRADA_ITENS.S_TRIB,
         SINTEGRA_NF_ENTRADA_ITENS.ALIQUOTA_IPI,
         SINTEGRA_NF_ENTRADA_ITENS.ALIQUOTA_ICMS,
         SINTEGRA_NF_ENTRADA_ITENS.REDUCAO_BASE_ICMS,
         SINTEGRA_NF_ENTRADA_ITENS.BASE_ICMS_SUBST,
         SINTEGRA_NF_ENTRADA_ITENS.DATAHORA
        FROM
         SINTEGRA_NF_ENTRADA_ITENS
        WHERE
         SINTEGRA_NF_ENTRADA_ITENS.CD_FILIAL = :FILIAL AND
         CAST(SINTEGRA_NF_ENTRADA_ITENS.DATAHORA AS DATE) >= :DATAINICIAL AND
         CAST(SINTEGRA_NF_ENTRADA_ITENS.DATAHORA AS DATE) <= :DATAFINAL AND
         SINTEGRA_NF_ENTRADA_ITENS.COD_NF_ENTRADA IN
         (
          SELECT
           COD_NF_ENTRADA
          FROM
           SINTEGRA_NF_ENTRADA
          WHERE
           SINTEGRA_NF_ENTRADA.CD_FILIAL = :FILIAL AND
           SINTEGRA_NF_ENTRADA.DATAHORA_RECEBIMENTO >= :DATAINICIAL AND
           SINTEGRA_NF_ENTRADA.DATAHORA_RECEBIMENTO <= :DATAFINAL AND
           (
            (SINTEGRA_NF_ENTRADA.MODELO_NF = '01') OR (SINTEGRA_NF_ENTRADA.MODELO_NF = '1') OR
            (SINTEGRA_NF_ENTRADA.MODELO_NF = '1A') OR
            (SINTEGRA_NF_ENTRADA.MODELO_NF = '03') OR (SINTEGRA_NF_ENTRADA.MODELO_NF = '3') OR
            (SINTEGRA_NF_ENTRADA.MODELO_NF = '06') OR (SINTEGRA_NF_ENTRADA.MODELO_NF = '6') OR
            (SINTEGRA_NF_ENTRADA.MODELO_NF = '55') OR
            (SINTEGRA_NF_ENTRADA.MODELO_NF = '22')
           )
         )
        INTO
         :REF_PRODUTOS,
         :CL_FIS,
         :PRODUTO,
         :APR_UND,
         :S_TRIB,
         :ALIQUOTA_IPI,
         :ALIQUOTA_ICMS,
         :REDUCAO_BASE_ICMS,
         :BASE_ICMS_SUBST,
         :DATAHORA
      DO
       BEGIN
         IF ((:APR_UND IS NULL) OR (:APR_UND = '')) THEN
            APR_UND = 'UN';
         SELECT RESULT FROM STR_ZERO(:REF_PRODUTOS, 14) INTO :REFERENCIA;
         SELECT COUNT(*) FROM TEMP_SINTEGRA_R75 WHERE REF_PRODUTOS = :REFERENCIA INTO :EXISTE;
         IF (:EXISTE = 0) THEN
            INSERT INTO TEMP_SINTEGRA_R75 VALUES (:REFERENCIA, :CL_FIS, :PRODUTO, :APR_UND, :S_TRIB, :ALIQUOTA_IPI, :ALIQUOTA_ICMS, :REDUCAO_BASE_ICMS, :BASE_ICMS_SUBST, :DATAHORA);
       END
   END

  IF (:GERA61 = 'S') THEN
   BEGIN
      FOR
        SELECT
         DISTINCT
         SINTEGRA_61R.CODIGOPRODUTO,
         SINTEGRA_61R.DESCRICAO,
         SINTEGRA_61R.UNIDADE,
         SINTEGRA_61R.CST,
         SINTEGRA_61R.ALIQUOTA,
         SINTEGRA_61R.DATAEMISSAO
        FROM
         SINTEGRA_61R
        WHERE
         CAST(SINTEGRA_61R.DATAEMISSAO AS DATE) >= :DATAINICIAL AND
         CAST(SINTEGRA_61R.DATAEMISSAO AS DATE) <= :DATAFINAL
        INTO
         :REF_PRODUTOS,
         :PRODUTO,
         :APR_UND,
         :S_TRIB,
         :ALIQUOTA_ICMS,
         :DATAHORA
      DO
       BEGIN
         CL_FIS = NULL;
         ALIQUOTA_IPI = 0;
         REDUCAO_BASE_ICMS = 0;
         BASE_ICMS_SUBST = 0;
         IF ((:APR_UND IS NULL) OR (:APR_UND = '')) THEN
            APR_UND = 'UN';
         SELECT RESULT FROM STR_ZERO(:REF_PRODUTOS, 14) INTO :REFERENCIA;
         SELECT COUNT(*) FROM TEMP_SINTEGRA_R75 WHERE REF_PRODUTOS = :REFERENCIA INTO :EXISTE;
         IF (:EXISTE = 0) THEN
            INSERT INTO TEMP_SINTEGRA_R75 VALUES (:REFERENCIA, :CL_FIS, :PRODUTO, :APR_UND, :S_TRIB, :ALIQUOTA_IPI, :ALIQUOTA_ICMS, :REDUCAO_BASE_ICMS, :BASE_ICMS_SUBST, :DATAHORA);
       END
   END

  FOR
    SELECT
     TEMP_SINTEGRA_R75.REF_PRODUTOS,
     TEMP_SINTEGRA_R75.CD_FIS,
     TEMP_SINTEGRA_R75.PRODUTO,
     TEMP_SINTEGRA_R75.APR_UND,
     TEMP_SINTEGRA_R75.S_TRIB,
     TEMP_SINTEGRA_R75.ALIQUOTA_IPI,
     TEMP_SINTEGRA_R75.ALIQUOTA_ICMS,
     TEMP_SINTEGRA_R75.REDUCAO_BASE_ICMS,
     TEMP_SINTEGRA_R75.BASE_ICMS_SUBST,
     TEMP_SINTEGRA_R75.DATAHORA
    FROM
     TEMP_SINTEGRA_R75
    INTO
     :REF_PRODUTOS,
     :CL_FIS,
     :PRODUTO,
     :APR_UND,
     :S_TRIB,
     :ALIQUOTA_IPI,
     :ALIQUOTA_ICMS,
     :REDUCAO_BASE_ICMS,
     :BASE_ICMS_SUBST,
     :DATAHORA
  DO
   BEGIN
     SUSPEND;
   END
END ^

ALTER PROCEDURE SP_SUGERE_REALOCACAO (LABORATORIO DOUBLE PRECISION,
GRUPO DOUBLE PRECISION)
AS 
DECLARE VARIABLE PRODUTO DOUBLE PRECISION;
DECLARE VARIABLE EST1 INTEGER;
DECLARE VARIABLE EST2 INTEGER;
DECLARE VARIABLE EST3 INTEGER;
DECLARE VARIABLE EST4 INTEGER;
DECLARE VARIABLE EST5 INTEGER;
DECLARE VARIABLE MIN1 INTEGER;
DECLARE VARIABLE MIN2 INTEGER;
DECLARE VARIABLE MIN3 INTEGER;
DECLARE VARIABLE MIN4 INTEGER;
DECLARE VARIABLE MIN5 INTEGER;
DECLARE VARIABLE LJ1_LJ2 INTEGER;
DECLARE VARIABLE LJ1_LJ3 INTEGER;
DECLARE VARIABLE LJ1_LJ4 INTEGER;
DECLARE VARIABLE LJ1_LJ5 INTEGER;
DECLARE VARIABLE LJ2_LJ1 INTEGER;
DECLARE VARIABLE LJ2_LJ3 INTEGER;
DECLARE VARIABLE LJ2_LJ4 INTEGER;
DECLARE VARIABLE LJ2_LJ5 INTEGER;
DECLARE VARIABLE LJ3_LJ1 INTEGER;
DECLARE VARIABLE LJ3_LJ2 INTEGER;
DECLARE VARIABLE LJ3_LJ4 INTEGER;
DECLARE VARIABLE LJ3_LJ5 INTEGER;
DECLARE VARIABLE LJ4_LJ1 INTEGER;
DECLARE VARIABLE LJ4_LJ2 INTEGER;
DECLARE VARIABLE LJ4_LJ3 INTEGER;
DECLARE VARIABLE LJ4_LJ5 INTEGER;
DECLARE VARIABLE LJ5_LJ1 INTEGER;
DECLARE VARIABLE LJ5_LJ2 INTEGER;
DECLARE VARIABLE LJ5_LJ3 INTEGER;
DECLARE VARIABLE LJ5_LJ4 INTEGER;
DECLARE VARIABLE CODIGO VARCHAR(6);
DECLARE VARIABLE DESCRI VARCHAR(100);
DECLARE VARIABLE QUANTIDADE INTEGER;
DECLARE VARIABLE LJ1_LJ1 INTEGER;
DECLARE VARIABLE LJ2_LJ2 INTEGER;
DECLARE VARIABLE LJ3_LJ3 INTEGER;
DECLARE VARIABLE LJ4_LJ4 INTEGER;
DECLARE VARIABLE LJ5_LJ5 INTEGER;
BEGIN
  /* Apagando transferencias nao concluidas */
  DELETE FROM TRANSFERENCIAS  WHERE DATA_TRANSFERENCIA IS NULL;
  /* Loop na tabela de produtos */
  FOR
    SELECT
           ID_PRODUTO, CD_PRODUTO, DESCRICAO,
           ESTOQUE_1, ESTOQUE_2, ESTOQUE_3, ESTOQUE_4, ESTOQUE_5,
           ESTOQUE_MINIMO_1, ESTOQUE_MINIMO_2, ESTOQUE_MINIMO_3,
           ESTOQUE_MINIMO_4, ESTOQUE_MINIMO_5
    FROM
           PRODUTOS
    WHERE
           CD_LABORATORIO = :LABORATORIO AND
           CD_GRUPO = :GRUPO
    INTO   :PRODUTO, :CODIGO, :DESCRI,
           :EST1, :EST2, :EST3, :EST4, :EST5,
           :MIN1, :MIN2, :MIN3, :MIN4, :MIN5
  DO
   BEGIN
    QUANTIDADE = 0;
    /* Verificado se o produto estA na relacao de transferencias do dia */
    SELECT COUNT(*) FROM TRANSFERENCIAS
    WHERE ID_PRODUTO = :PRODUTO AND DATA_TRANSFERENCIA = CURRENT_DATE
    INTO :QUANTIDADE;
    /* Se o produto estiver na transferencia do dia sai, senao processa */
    IF (:QUANTIDADE = 0) THEN
     BEGIN
      /* Verificando se alguma filial tem estoque minimo */
      IF ((:MIN1 > 0) OR (:MIN2 > 0) OR (:MIN3 > 0) OR (:MIN4 > 0) OR (:MIN5 > 0)) THEN
       BEGIN
          /* Verificando se alguma filial tem estoque */
          IF ((:EST1 > 0) OR (:EST2 > 0) OR (:EST3 > 0) OR (:EST4 > 0) OR (:EST5 > 0)) THEN
           BEGIN
              /* Zerando as variaveis */
              LJ1_LJ1 = 0; LJ1_LJ2 = 0; LJ1_LJ3 = 0; LJ1_LJ4 = 0; LJ1_LJ5 = 0;
              LJ2_LJ1 = 0; LJ2_LJ2 = 0; LJ2_LJ3 = 0; LJ2_LJ4 = 0; LJ2_LJ5 = 0;
              LJ3_LJ1 = 0; LJ3_LJ2 = 0; LJ3_LJ3 = 0; LJ3_LJ4 = 0; LJ3_LJ5 = 0;
              LJ4_LJ1 = 0; LJ4_LJ2 = 0; LJ4_LJ3 = 0; LJ4_LJ4 = 0; LJ4_LJ5 = 0;
              LJ5_LJ1 = 0; LJ5_LJ2 = 0; LJ5_LJ3 = 0; LJ5_LJ4 = 0; LJ5_LJ5 = 0;
              /* Tratando estoque da loja 1 */
              IF (:EST1 >= :MIN1) THEN
                BEGIN
                  LJ1_LJ1 = :LJ1_LJ1 + :MIN1;
                  EST1 = :EST1 - :MIN1;
                END
              ELSE
                BEGIN
                  LJ1_LJ1 = :LJ1_LJ1 + :EST1;
                  EST1 = 0;
                END
              IF ((:EST2 + :LJ1_LJ2) < :MIN2) THEN
               BEGIN
                   IF (:EST1 >= :MIN2) THEN
                    BEGIN
                      LJ1_LJ2 = :LJ1_LJ2 + :MIN2;
                      EST1 = :EST1 - :MIN2;
                    END
                  ELSE
                    BEGIN
                      LJ1_LJ2 = :LJ1_LJ2 + :EST1;
                      EST1 = 0;
                    END
               END
              IF ((:EST3 + :LJ1_LJ3) < :MIN3) THEN
               BEGIN
                   IF (:EST1 >= :MIN3) THEN
                    BEGIN
                      LJ1_LJ3 = :LJ1_LJ3 + :MIN3;
                      EST1 = :EST1 - :MIN3;
                    END
                  ELSE
                    BEGIN
                      LJ1_LJ3 = :LJ1_LJ3 + :EST1;
                      EST1 = 0;
                    END
               END
              IF ((:EST4 + :LJ1_LJ4) < :MIN4) THEN
               BEGIN
                   IF (:EST1 >= :MIN4) THEN
                    BEGIN
                      LJ1_LJ4 = :LJ1_LJ4 + :MIN4;
                      EST1 = :EST1 - :MIN4;
                    END
                  ELSE
                    BEGIN
                      LJ1_LJ4 = :LJ1_LJ4 + :EST1;
                      EST1 = 0;
                    END
               END
              IF ((:EST5 + :LJ1_LJ5) < :MIN5) THEN
               BEGIN
                   IF (:EST1 >= :MIN5) THEN
                    BEGIN
                      LJ1_LJ5 = :LJ1_LJ5 + :MIN5;
                      EST1 = :EST1 - :MIN5;
                    END
                  ELSE
                    BEGIN
                      LJ1_LJ5 = :LJ1_LJ5 + :EST1;
                      EST1 = 0;
                    END
               END
              EST1 = :EST1 + :LJ1_LJ1;
              LJ1_LJ1 = :EST1;

              /* Tratando estoque da loja 2 */
              IF (:EST2 >= :MIN2) THEN
                BEGIN
                  LJ2_LJ2 = :LJ2_LJ2 + :MIN2;
                  EST2 = :EST2 - :MIN2;
                END
              ELSE
                BEGIN
                  LJ2_LJ2 = :LJ2_LJ2 + :EST2;
                  EST2 = 0;
                END
              IF (:EST1 < :MIN1) THEN
               BEGIN
                   IF (:LJ1_LJ2 = 0) THEN
                    BEGIN
                        IF (:EST2 >= :MIN1) THEN
                         BEGIN
                           LJ2_LJ1 = :LJ2_LJ1 + :MIN1;
                           EST2 = :EST2 - :MIN1;
                         END
                       ELSE
                         BEGIN
                           LJ2_LJ1 = :LJ2_LJ1 + :EST2;
                           EST2 = 0;
                         END
                   END
               END
              IF ((:EST3 + :LJ1_LJ3 + :LJ2_LJ3) < :MIN3) THEN
               BEGIN
                   IF (:EST2 >= :MIN3) THEN
                    BEGIN
                      LJ2_LJ3 = :LJ2_LJ3 + :MIN3;
                      EST2 = :EST2 - :MIN3;
                    END
                  ELSE
                    BEGIN
                      LJ2_LJ3 = :LJ2_LJ3 + :EST2;
                      EST2 = 0;
                    END
               END
              IF ((:EST4 + :LJ1_LJ4 + :LJ2_LJ4) < :MIN4) THEN
               BEGIN
                   IF (:EST2 >= :MIN4) THEN
                    BEGIN
                      LJ2_LJ4 = :LJ2_LJ4 + :MIN4;
                      EST2 = :EST2 - :MIN4;
                    END
                  ELSE
                    BEGIN
                      LJ2_LJ4 = :LJ2_LJ4 + :EST2;
                      EST2 = 0;
                    END
               END
              IF ((:EST5 + :LJ1_LJ5 + :LJ2_LJ5) < :MIN5) THEN
               BEGIN
                   IF (:EST2 >= :MIN5) THEN
                    BEGIN
                      LJ2_LJ5 = :LJ2_LJ5 + :MIN5;
                      EST2 = :EST2 - :MIN5;
                    END
                  ELSE
                    BEGIN
                      LJ2_LJ5 = :LJ2_LJ5 + :EST2;
                      EST2 = 0;
                    END
               END
              EST1 = :EST1 + :LJ2_LJ1;
              EST2 = :EST2 + :LJ2_LJ2;
              LJ2_LJ2 = :EST2;

              /* Tratando estoque da loja 3 */
              IF (:EST3 >= :MIN3) THEN
                BEGIN
                  LJ3_LJ3 = :LJ3_LJ3 + :MIN3;
                  EST3 = :EST3 - :MIN3;
                END
              ELSE
                BEGIN
                  LJ3_LJ3 = :LJ3_LJ3 + :EST3;
                  EST3 = 0;
                END
              IF (:EST1 < :MIN1) THEN
               BEGIN
                   IF (:LJ1_LJ3 = 0) THEN
                    BEGIN
                        IF (:EST3 >= :MIN1) THEN
                         BEGIN
                           LJ3_LJ1 = :LJ3_LJ1 + :MIN1;
                           EST3 = :EST3 - :MIN1;
                         END
                       ELSE
                         BEGIN
                           LJ3_LJ1 = :LJ3_LJ1 + :EST3;
                           EST3 = 0;
                         END
                   END
               END
              IF (:EST2 < :MIN2) THEN
               BEGIN
                   IF (LJ2_LJ3 = 0) THEN
                    BEGIN
                        IF (:EST3 >= :MIN2) THEN
                         BEGIN
                           LJ3_LJ2 = :LJ3_LJ2 + :MIN2;
                           EST3 = :EST3 - :MIN2;
                         END
                       ELSE
                         BEGIN
                           LJ3_LJ2 = :LJ3_LJ2 + :EST3;
                           EST3 = 0;
                         END
                   END
               END
              IF ((:EST4 + :LJ1_LJ4 + :LJ2_LJ4 + :LJ3_LJ4) < :MIN4) THEN
               BEGIN
                   IF (:EST3 >= :MIN4) THEN
                    BEGIN
                      LJ3_LJ4 = :LJ3_LJ4 + :MIN4;
                      EST3 = :EST3 - :MIN4;
                    END
                  ELSE
                    BEGIN
                      LJ3_LJ4 = :LJ3_LJ4 + :EST3;
                      EST3 = 0;
                    END
               END
              IF ((:EST5  + :LJ1_LJ5 + :LJ2_LJ5 + :LJ3_LJ5) < :MIN5) THEN
               BEGIN
                   IF (:EST3 >= :MIN5) THEN
                    BEGIN
                      LJ3_LJ5 = :LJ3_LJ5 + :MIN5;
                      EST3 = :EST3 - :MIN5;
                    END
                  ELSE
                    BEGIN
                      LJ3_LJ5 = :LJ3_LJ5 + :EST3;
                      EST3 = 0;
                    END
               END
              EST1 = :EST1 + :LJ3_LJ1;
              EST2 = :EST2 + :LJ3_LJ2;
              EST3 = :EST3 + :LJ3_LJ3;
              LJ3_LJ3 = :EST3;

              /* Tratando estoque da loja 4 */
              IF (:EST4 >= :MIN4) THEN
                BEGIN
                  LJ4_LJ4 = :LJ4_LJ4 + :MIN4;
                  EST4 = :EST4 - :MIN4;
                END
              ELSE
                BEGIN
                  LJ4_LJ4 = :LJ4_LJ4 + :EST4;
                  EST4 = 0;
                END
              IF (:EST1 < :MIN1) THEN
               BEGIN
                   IF (:LJ1_LJ4 = 0) THEN
                    BEGIN
                        IF (:EST4 >= :MIN1) THEN
                         BEGIN
                           LJ4_LJ1 = :LJ4_LJ1 + :MIN1;
                           EST4 = :EST4 - :MIN1;
                         END
                       ELSE
                         BEGIN
                           LJ4_LJ1 = :LJ4_LJ1 + :EST4;
                           EST4 = 0;
                         END
                    END
               END
              IF (:EST2 < :MIN2) THEN
               BEGIN
                  IF (LJ2_LJ4 = 0) THEN
                   BEGIN
                       IF (:EST4 >= :MIN2) THEN
                         BEGIN
                           LJ4_LJ2 = :LJ4_LJ2 + :MIN2;
                           EST4 = :EST4 - :MIN2;
                         END
                       ELSE
                         BEGIN
                           LJ4_LJ2 = :LJ4_LJ2 + :EST4;
                           EST4 = 0;
                         END
                   END
               END
              IF (:EST3 < :MIN3) THEN
               BEGIN
                   IF (:LJ3_LJ4 = 0) THEN
                    BEGIN
                        IF (:EST4 >= :MIN3) THEN
                         BEGIN
                           LJ4_LJ3 = :LJ4_LJ3 + :MIN3;
                           EST4 = :EST4 - :MIN3;
                         END
                       ELSE
                         BEGIN
                           LJ4_LJ3 = :LJ4_LJ3 + :EST4;
                           EST4 = 0;
                         END
                    END
               END
              IF ((:EST5  + :LJ1_LJ4 + :LJ2_LJ4 + :LJ3_LJ4 + :LJ4_LJ5) < :MIN5) THEN
               BEGIN
                   IF (:EST4 >= :MIN5) THEN
                    BEGIN
                      LJ4_LJ5 = :LJ4_LJ5 + :MIN5;
                      EST4 = :EST4 - :MIN5;
                    END
                  ELSE
                    BEGIN
                      LJ4_LJ5 = :LJ4_LJ5 + :EST4;
                      EST4 = 0;
                    END
               END
              EST1 = :EST1 + :LJ4_LJ1;
              EST2 = :EST2 + :LJ4_LJ2;
              EST3 = :EST3 + :LJ4_LJ3;
              EST4 = :EST4 + :LJ4_LJ4;
              LJ4_LJ4 = :EST4;

              /* Tratando estoque da loja 5 */
              IF (:EST5 >= :MIN5) THEN
                BEGIN
                  LJ5_LJ5 = :LJ5_LJ5 + :MIN5;
                  EST5 = :EST5 - :MIN5;
                END
              ELSE
                BEGIN
                  LJ5_LJ5 = :LJ5_LJ5 + :EST5;
                  EST5 = 0;
                END
              IF (:EST1 < :MIN1) THEN
               BEGIN
                   IF (:LJ1_LJ5 = 0) THEN
                    BEGIN
                        IF (:EST5 >= :MIN1) THEN
                         BEGIN
                           LJ5_LJ1 = :LJ5_LJ1 + :MIN1;
                           EST5 = :EST5 - :MIN1;
                         END
                       ELSE
                         BEGIN
                           LJ5_LJ1 = :LJ5_LJ1 + :EST5;
                           EST5 = 0;
                         END
                    END
               END
              IF (:EST2 < :MIN2) THEN
               BEGIN
                   IF (LJ2_LJ5 = 0) THEN
                    BEGIN
                        IF (:EST5 >= :MIN2) THEN
                         BEGIN
                           LJ5_LJ2 = :LJ5_LJ2 + :MIN2;
                           EST5 = :EST5 - :MIN2;
                         END
                       ELSE
                         BEGIN
                           LJ5_LJ2 = :LJ5_LJ2 + :EST5;
                           EST5 = 0;
                         END
                    END
               END
              IF (:EST3 < :MIN3) THEN
               BEGIN
                   IF (LJ3_LJ5 = 0) THEN
                    BEGIN
                        IF (:EST5 >= :MIN3) THEN
                         BEGIN
                           LJ5_LJ3 = :LJ5_LJ3 + :MIN3;
                           EST5 = :EST5 - :MIN3;
                         END
                       ELSE
                         BEGIN
                           LJ5_LJ3 = :LJ5_LJ3 + :EST5;
                           EST5 = 0;
                         END
                    END
               END
              IF (:EST4 < :MIN4) THEN
               BEGIN
                   IF (LJ4_LJ5 = 0) THEN
                    BEGIN
                        IF (:EST5 >= :MIN4) THEN
                         BEGIN
                           LJ5_LJ4 = :LJ5_LJ4 + :MIN4;
                           EST5 = :EST5 - :MIN4;
                         END
                       ELSE
                         BEGIN
                           LJ5_LJ4 = :LJ5_LJ4 + :EST5;
                           EST5 = 0;
                         END
                    END
               END
              EST1 = :EST1 + :LJ5_LJ1;
              EST2 = :EST2 + :LJ5_LJ2;
              EST3 = :EST3 + :LJ5_LJ3;
              EST4 = :EST4 + :LJ5_LJ4;
              EST4 = :EST4 + :LJ5_LJ4;
              EST5 = :EST5 + :LJ5_LJ5;
              LJ5_LJ5 = :EST5;

              /* Verificando se transferencias sao diferentes de ZERO */
              IF ((:LJ1_LJ2 <> 0) OR (:LJ1_LJ3 <> 0) OR (:LJ1_LJ4 <> 0) OR (:LJ1_LJ5 <> 0) OR
                  (:LJ2_LJ1 <> 0) OR (:LJ2_LJ3 <> 0) OR (:LJ2_LJ4 <> 0) OR (:LJ2_LJ5 <> 0) OR
                  (:LJ3_LJ1 <> 0) OR (:LJ3_LJ2 <> 0) OR (:LJ3_LJ4 <> 0) OR (:LJ3_LJ5 <> 0) OR
                  (:LJ4_LJ1 <> 0) OR (:LJ4_LJ2 <> 0) OR (:LJ4_LJ3 <> 0) OR (:LJ4_LJ5 <> 0) OR
                  (:LJ5_LJ1 <> 0) OR (:LJ5_LJ2 <> 0) OR (:LJ5_LJ3 <> 0) OR (:LJ5_LJ4 <> 0)) THEN
               BEGIN
                  /* Mudando quantidade de zero para nulo para a tabela de transferencias */
                  IF (:LJ1_LJ1 = 0) THEN LJ1_LJ1 = NULL;
                  IF (:LJ1_LJ2 = 0) THEN LJ1_LJ2 = NULL;
                  IF (:LJ1_LJ3 = 0) THEN LJ1_LJ3 = NULL;
                  IF (:LJ1_LJ4 = 0) THEN LJ1_LJ4 = NULL;
                  IF (:LJ1_LJ5 = 0) THEN LJ1_LJ5 = NULL;
                  IF (:LJ2_LJ1 = 0) THEN LJ2_LJ1 = NULL;
                  IF (:LJ2_LJ2 = 0) THEN LJ2_LJ2 = NULL;
                  IF (:LJ2_LJ3 = 0) THEN LJ2_LJ3 = NULL;
                  IF (:LJ2_LJ4 = 0) THEN LJ2_LJ4 = NULL;
                  IF (:LJ2_LJ5 = 0) THEN LJ2_LJ5 = NULL;
                  IF (:LJ3_LJ1 = 0) THEN LJ3_LJ1 = NULL;
                  IF (:LJ3_LJ2 = 0) THEN LJ3_LJ2 = NULL;
                  IF (:LJ3_LJ3 = 0) THEN LJ3_LJ3 = NULL;
                  IF (:LJ3_LJ4 = 0) THEN LJ3_LJ4 = NULL;
                  IF (:LJ3_LJ5 = 0) THEN LJ3_LJ5 = NULL;
                  IF (:LJ4_LJ1 = 0) THEN LJ4_LJ1 = NULL;
                  IF (:LJ4_LJ2 = 0) THEN LJ4_LJ2 = NULL;
                  IF (:LJ4_LJ3 = 0) THEN LJ4_LJ3 = NULL;
                  IF (:LJ4_LJ4 = 0) THEN LJ4_LJ4 = NULL;
                  IF (:LJ4_LJ5 = 0) THEN LJ4_LJ5 = NULL;
                  IF (:LJ5_LJ1 = 0) THEN LJ5_LJ1 = NULL;
                  IF (:LJ5_LJ2 = 0) THEN LJ5_LJ2 = NULL;
                  IF (:LJ5_LJ3 = 0) THEN LJ5_LJ3 = NULL;
                  IF (:LJ5_LJ4 = 0) THEN LJ5_LJ4 = NULL;
                  IF (:LJ5_LJ5 = 0) THEN LJ5_LJ5 = NULL;

                  /* Incluindo dados na tabela de transferencias */
                  INSERT INTO TRANSFERENCIAS
                  ( DATA_GERACAO, DATA_TRANSFERENCIA, ID_PRODUTO, CD_PRODUTO, DESCRICAO,
                    LJ1_LJ1, LJ1_LJ2, LJ1_LJ3, LJ1_LJ4, LJ1_LJ5,
                    LJ2_LJ1, LJ2_LJ2, LJ2_LJ3, LJ2_LJ4, LJ2_LJ5,
                    LJ3_LJ1, LJ3_LJ2, LJ3_LJ3, LJ3_LJ4, LJ3_LJ5,
                    LJ4_LJ1, LJ4_LJ2, LJ4_LJ3, LJ4_LJ4, LJ4_LJ5,
                    LJ5_LJ1, LJ5_LJ2, LJ5_LJ3, LJ5_LJ4, LJ5_LJ5)
                  VALUES (CURRENT_DATE, NULL, :PRODUTO, :CODIGO, :DESCRI,
                    :LJ1_LJ1, :LJ1_LJ2, :LJ1_LJ3, :LJ1_LJ4, :LJ1_LJ5,
                    :LJ2_LJ1, :LJ2_LJ2, :LJ2_LJ3, :LJ2_LJ4, :LJ2_LJ5,
                    :LJ3_LJ1, :LJ3_LJ2, :LJ3_LJ3, :LJ3_LJ4, :LJ3_LJ5,
                    :LJ4_LJ1, :LJ4_LJ2, :LJ4_LJ3, :LJ4_LJ4, :LJ4_LJ5,
                    :LJ5_LJ1, :LJ5_LJ2, :LJ5_LJ3, :LJ5_LJ4, :LJ5_LJ5);
               END
           END
       END
     END
   END
END ^

ALTER PROCEDURE SP_SUPORTE_0200 (DATAINICIAL DATE,
DATAFINAL DATE,
TEMINVENTARIO VARCHAR(1) CHARACTER SET NONE)
RETURNS (LINHA VARCHAR(1000) CHARACTER SET NONE,
COD_BARRA VARCHAR(100) CHARACTER SET NONE,
COD_ITEM VARCHAR(100) CHARACTER SET NONE,
UNIDADE VARCHAR(100) CHARACTER SET NONE,
DESCRICAO VARCHAR(100) CHARACTER SET NONE,
COD_ANT_ITEM VARCHAR(100) CHARACTER SET NONE,
UNID_INV VARCHAR(100) CHARACTER SET NONE,
TIPO_ITEM VARCHAR(100) CHARACTER SET NONE,
COD_NCM VARCHAR(100) CHARACTER SET NONE,
EX_IPI VARCHAR(100) CHARACTER SET NONE,
COD_GEN VARCHAR(100) CHARACTER SET NONE,
COD_LST VARCHAR(100) CHARACTER SET NONE,
ALIQ_ICMS VARCHAR(100) CHARACTER SET NONE,
NCM VARCHAR(100) CHARACTER SET NONE,
CEST VARCHAR(100) CHARACTER SET NONE)
AS 
declare variable ID_PRODUTO varchar(100);
declare variable ICMS varchar(100);
declare variable CODIGO_BARRAS_1 varchar(100);
declare variable CODIGO_BARRAS_2 varchar(100);
declare variable EXISTE integer;
declare variable ID integer;
declare variable DESCR_ITEM varchar(100);
declare variable SDATA varchar(10);
declare variable COMANDO1 varchar(1000);
declare variable TENTATIVAS integer;
declare variable CD_FILIAL double precision;
declare variable TAMANHOVARIAVEL integer;
BEGIN
  ID = 1000000;
  DELETE FROM TEMP_SUPORTE_0200;

  UPDATE PRODUTOS SET CODIGO_BARRAS_1 = CODIGO_BARRAS_2, CODIGO_BARRAS_2 = '0'||CD_PRODUTO  WHERE CODIGO_BARRAS_1 IS NULL OR CODIGO_BARRAS_1 = '';
  UPDATE PRODUTOS SET CODIGO_BARRAS_2 = '0'||CD_PRODUTO WHERE CODIGO_BARRAS_2 IS NULL OR CODIGO_BARRAS_2 = '';

  FOR
      SELECT
       CAST(CAST(PRODUTOS_FISCO.ID_PRODUTO AS INTEGER) AS VARCHAR(100)),
       TRIM(SINTEGRA_NF_ENTRADA_ITENS.PRODUTO),
       CAST(CAST(SINTEGRA_NF_ENTRADA_ITENS.ALIQUOTA_ICMS AS INTEGER) AS VARCHAR(10)),
       SINTEGRA_NF_ENTRADA_ITENS.REF_PRODUTOS,
       PRODUTOS_FISCO.NCM,
       PRODUTOS_FISCO.CEST
      FROM 
        SINTEGRA_NF_ENTRADA_ITENS LEFT OUTER JOIN PRODUTOS_FISCO ON SINTEGRA_NF_ENTRADA_ITENS.REF_PRODUTOS = PRODUTOS_FISCO.CODIGO_BARRAS,
        SINTEGRA_NF_ENTRADA
      WHERE 
       SINTEGRA_NF_ENTRADA.COD_NF_ENTRADA = SINTEGRA_NF_ENTRADA_ITENS.COD_NF_ENTRADA AND
       SINTEGRA_NF_ENTRADA.EMITENTE_NF <> 'P' AND
       --SINTEGRA_NF_ENTRADA.MODELO_NF <> '55' AND
       SINTEGRA_NF_ENTRADA.MODELO_NF <> '65' AND
       SINTEGRA_NF_ENTRADA.DATAHORA_RECEBIMENTO >= :DATAINICIAL AND
       SINTEGRA_NF_ENTRADA.DATAHORA_RECEBIMENTO <= :DATAFINAL
      GROUP BY
       PRODUTOS_FISCO.ID_PRODUTO,
       SINTEGRA_NF_ENTRADA_ITENS.PRODUTO,
       SINTEGRA_NF_ENTRADA_ITENS.ALIQUOTA_ICMS,
       SINTEGRA_NF_ENTRADA_ITENS.REF_PRODUTOS,
       PRODUTOS_FISCO.NCM,
       PRODUTOS_FISCO.CEST
      INTO
       :ID_PRODUTO, 
       :DESCRICAO, 
       :ICMS,
       :CODIGO_BARRAS_1, 
       :NCM,
       :CEST
  DO
   BEGIN
      --NCM = '';
      IF (:ID_PRODUTO IS NULL) THEN
       BEGIN
         ID_PRODUTO = :ID;
         ID = :ID + 1;
       END
      SELECT COUNT(*) FROM TEMP_SUPORTE_0200 WHERE COD_ITEM = :ID_PRODUTO INTO :EXISTE;
      IF (:EXISTE = 0) THEN
       BEGIN
         SELECT COUNT(*) FROM TEMP_SUPORTE_0200 WHERE COD_BARRA_NUMERO = CAST(:CODIGO_BARRAS_1 AS NUMERIC(15,0)) INTO :EXISTE;
         IF (:EXISTE = 0) THEN
          BEGIN
             SELECT
              FIRST 1 DISTINCT SINTEGRA_NF_ENTRADA_ITENS.APR_UND
             FROM
              SINTEGRA_NF_ENTRADA_ITENS, SINTEGRA_NF_ENTRADA
             WHERE
              SINTEGRA_NF_ENTRADA.COD_NF_ENTRADA = SINTEGRA_NF_ENTRADA_ITENS.COD_NF_ENTRADA AND
              SINTEGRA_NF_ENTRADA.DATAHORA_RECEBIMENTO >= :DATAINICIAL AND
              SINTEGRA_NF_ENTRADA.DATAHORA_RECEBIMENTO <= :DATAFINAL AND
              SINTEGRA_NF_ENTRADA_ITENS.REF_PRODUTOS = :CODIGO_BARRAS_1
             INTO
              :UNIDADE;

             IF (((:UNIDADE <> 'UN') AND
                  (:UNIDADE <> 'KG') AND
                  (:UNIDADE <> 'MT') AND
                  (:UNIDADE <> 'LT') AND
                  (:UNIDADE <> 'PC') AND
                  (:UNIDADE <> 'DP') AND
                  (:UNIDADE <> 'FD') AND
                  (:UNIDADE <> 'CX') AND
                  (:UNIDADE <> 'BI') AND
                  (:UNIDADE <> 'BL') AND
                  (:UNIDADE <> 'CT') AND
                  (:UNIDADE <> 'DZ') AND
                  (:UNIDADE <> 'EN') AND
                  (:UNIDADE <> 'FR') AND
                  (:UNIDADE <> 'KT') AND
                  (:UNIDADE <> 'PO') AND
                  (:UNIDADE <> 'TB') AND
                  (:UNIDADE <> 'VD')) OR
                  ((:UNIDADE IS NULL) OR (:UNIDADE = ''))) THEN
                UNIDADE = 'CX';

             IF ((SUBSTRING(:ICMS FROM 1 FOR 1) = 'F') OR (SUBSTRING(:ICMS FROM 1 FOR 1) = 'N') OR (SUBSTRING(:ICMS FROM 1 FOR 1) = 'I')) THEN
                ICMS = '0';
             SELECT LEN FROM TAMANHO(:NCM) INTO :TAMANHOVARIAVEL;
             IF ((:NCM IS NULL) OR (:NCM = '') OR (:NCM = '00000000') OR (:NCM = '99999999') OR (:TAMANHOVARIAVEL <> 8)) THEN
                NCM = '30049099';
             SELECT LEN FROM TAMANHO(:CEST) INTO :TAMANHOVARIAVEL;
             IF ((:CEST IS NULL) OR (:CEST = '') OR (:CEST = '0000000') OR (:CEST = '9999999') OR (:TAMANHOVARIAVEL <> 7)) THEN
                CEST = '1300400';

             INSERT INTO TEMP_SUPORTE_0200 VALUES (:ID_PRODUTO, :DESCRICAO, TRIM(:CODIGO_BARRAS_1), :ID_PRODUTO, :UNIDADE, '00', SUBSTRING(:NCM FROM 1 FOR 8), '', '', '',:ICMS, CAST(TRIM(:CODIGO_BARRAS_1) AS NUMERIC(15,0)), :CEST);
          END
       END
   END

  FOR
    SELECT
     CAST(TRIM(PAF_R05.CODIGO_PRODUTO_SERVICO) AS NUMERIC(15,0)),
     TRIM(PAF_R05.DESCRICAO),
     TRIM(PAF_R05.UNIDADE)
    FROM
     PAF_R05, PAF_R04
    WHERE
     PAF_R04.NUMERO_FABRICACAO = PAF_R05.NUMERO_FABRICACAO AND
     PAF_R04.COO = PAF_R05.COO AND
     PAF_R04.DDATA_INICIO_EMISSAO IS NOT NULL AND
     PAF_R04.DDATA_INICIO_EMISSAO >= :DATAINICIAL AND
     PAF_R04.DDATA_INICIO_EMISSAO <= :DATAFINAL AND
     ((PAF_R04.CANCELAMENTO = 'N') AND (PAF_R05.INDICADOR_CANCELAMENTO = 'N'))
    GROUP BY CODIGO_PRODUTO_SERVICO, DESCRICAO, ALIQUOTA, UNIDADE
    INTO
     :COD_BARRA,
     :DESCRICAO,
     :UNIDADE
  DO
   BEGIN
     SELECT COUNT(*) FROM TEMP_SUPORTE_0200 WHERE COD_BARRA_NUMERO = :COD_BARRA INTO :EXISTE;
     IF (:EXISTE = 0) THEN
      BEGIN
        ID_PRODUTO = '';

        SELECT FIRST 1 CAST(PRODUTOS.ID_PRODUTO AS INTEGER), PRODUTOS.DESCRICAO, TRIM(PRODUTOS.CODIGO_BARRAS_1),
               CAST(CAST(PRODUTOS_FISCO.ALIQUOTA_ICMS AS INTEGER) AS VARCHAR(10)),
               PRODUTOS_FISCO.NCM, PRODUTOS_FISCO.CEST
        FROM PRODUTOS, PRODUTOS_FISCO
        WHERE  PRODUTOS.ID_PRODUTO = PRODUTOS_FISCO.ID_PRODUTO AND CAST(PRODUTOS.CODIGO_BARRAS_1 AS NUMERIC(15,0)) = :COD_BARRA
        INTO :ID_PRODUTO, :DESCRICAO, :CODIGO_BARRAS_1, :ICMS, :NCM, :CEST;

        IF (:ID_PRODUTO = '') THEN
         BEGIN
           SELECT FIRST 1 CAST(PRODUTOS.ID_PRODUTO AS INTEGER), PRODUTOS.DESCRICAO, TRIM(PRODUTOS.CODIGO_BARRAS_1), TRIM(PRODUTOS.CODIGO_BARRAS_2),
                          CAST(CAST(PRODUTOS_FISCO.ALIQUOTA_ICMS AS INTEGER) AS VARCHAR(10)),
                          PRODUTOS_FISCO.NCM, PRODUTOS_FISCO.CEST
           FROM PRODUTOS, PRODUTOS_FISCO
           WHERE PRODUTOS.ID_PRODUTO = PRODUTOS_FISCO.ID_PRODUTO AND CAST(PRODUTOS.CODIGO_BARRAS_2 AS NUMERIC(15,0)) = :COD_BARRA
           INTO :ID_PRODUTO, :DESCRICAO, :CODIGO_BARRAS_1, CODIGO_BARRAS_2, :ICMS, :NCM, :CEST;

           IF (:ID_PRODUTO <> '') THEN
            BEGIN
              SELECT COUNT(*) FROM TEMP_SUPORTE_0200 WHERE COD_BARRA_NUMERO = CAST(:CODIGO_BARRAS_1 AS NUMERIC(15,0)) INTO :EXISTE;
              IF (:EXISTE > 0) THEN
               BEGIN
                 ID_PRODUTO = '';
               END
              ELSE
               BEGIN
                 SELECT COUNT(*) FROM TEMP_SUPORTE_0200 WHERE COD_ITEM = :ID_PRODUTO INTO :EXISTE;
                 IF (:EXISTE > 0) THEN
                    ID_PRODUTO = '';
                 CODIGO_BARRAS_1 = :CODIGO_BARRAS_2;
               END
            END
         END
        ELSE
         BEGIN
           SELECT COUNT(*) FROM TEMP_SUPORTE_0200 WHERE COD_ITEM = :ID_PRODUTO INTO :EXISTE;
           IF (:EXISTE > 0) THEN
               ID_PRODUTO = '';
         END
        SELECT LEN FROM TAMANHO(:NCM) INTO :TAMANHOVARIAVEL;
        IF ((:NCM IS NULL) OR (:NCM = '') OR (:NCM = '00000000') OR (:NCM = '99999999') OR (:TAMANHOVARIAVEL <> 8)) THEN
           NCM = '30049099';
        SELECT LEN FROM TAMANHO(:CEST) INTO :TAMANHOVARIAVEL;
        IF ((:CEST IS NULL) OR (:CEST = '') OR (:CEST = '0000000') OR (:CEST = '9999999') OR (:TAMANHOVARIAVEL <> 7)) THEN
           CEST = '1300400';

        IF ((:UNIDADE IS NULL) OR (:UNIDADE = '')) THEN
           UNIDADE = 'CX';
        IF (:ID_PRODUTO <> '') THEN
         BEGIN
           --IF ((SUBSTRING(:ICMS FROM 1 FOR 1) = 'F') OR (SUBSTRING(:ICMS FROM 1 FOR 1) = 'N') OR (SUBSTRING(:ICMS FROM 1 FOR 1) = 'I')) THEN
           --   ICMS = '0';
           INSERT INTO TEMP_SUPORTE_0200 VALUES (:ID_PRODUTO, :DESCRICAO, TRIM(:CODIGO_BARRAS_1), :ID_PRODUTO, :UNIDADE, '00', SUBSTRING(:NCM FROM 1 FOR 8), '', '', '',:ICMS, CAST(TRIM(:CODIGO_BARRAS_1) AS NUMERIC(15,0)), :CEST);
         END
        ELSE
         BEGIN
           INSERT INTO TEMP_SUPORTE_0200 VALUES (:ID, :DESCRICAO, TRIM(:COD_BARRA), :ID, 'UN', '00', '', '', '', '','0', CAST(TRIM(:COD_BARRA) AS NUMERIC(15,0)), :CEST);
           ID = :ID + 1;
         END
      END
   END

  FOR
    SELECT
     CAST(TRIM(SINTEGRA_61R.CODIGOPRODUTO) AS NUMERIC(15,0)),
     TRIM(SINTEGRA_61R.DESCRICAO),
     TRIM(SINTEGRA_61R.UNIDADE)
    FROM
     SINTEGRA_61R
    WHERE
     SINTEGRA_61R.DATAEMISSAO IS NOT NULL AND
     SINTEGRA_61R.DATAEMISSAO >= :DATAINICIAL AND
     SINTEGRA_61R.DATAEMISSAO <= :DATAFINAL
    GROUP BY CODIGOPRODUTO, DESCRICAO, ALIQUOTA, UNIDADE
    INTO
     :COD_BARRA,
     :DESCRICAO,
     :UNIDADE
  DO
   BEGIN
     SELECT COUNT(*) FROM TEMP_SUPORTE_0200 WHERE COD_BARRA_NUMERO = :COD_BARRA INTO :EXISTE;
     IF (:EXISTE = 0) THEN
      BEGIN
        ID_PRODUTO = '';
        SELECT FIRST 1 CAST(PRODUTOS.ID_PRODUTO AS INTEGER), PRODUTOS.DESCRICAO, TRIM(PRODUTOS.CODIGO_BARRAS_1),
               CAST(CAST(PRODUTOS_FISCO.ALIQUOTA_ICMS AS INTEGER) AS VARCHAR(10)),
               PRODUTOS_FISCO.NCM, PRODUTOS_FISCO.CEST
        FROM PRODUTOS, PRODUTOS_FISCO
        WHERE  PRODUTOS.ID_PRODUTO = PRODUTOS_FISCO.ID_PRODUTO AND CAST(PRODUTOS.CODIGO_BARRAS_1 AS NUMERIC(15,0)) = :COD_BARRA
        INTO :ID_PRODUTO, :DESCRICAO, :CODIGO_BARRAS_1, :ICMS, :NCM, :CEST;

        IF (:ID_PRODUTO = '') THEN
         BEGIN
           SELECT FIRST 1 CAST(PRODUTOS.ID_PRODUTO AS INTEGER), PRODUTOS.DESCRICAO, TRIM(PRODUTOS.CODIGO_BARRAS_1), TRIM(PRODUTOS.CODIGO_BARRAS_2),
                  CAST(CAST(PRODUTOS_FISCO.ALIQUOTA_ICMS AS INTEGER) AS VARCHAR(10)),
                  PRODUTOS_FISCO.NCM, PRODUTOS_FISCO.CEST
           FROM PRODUTOS, PRODUTOS_FISCO
           WHERE PRODUTOS.ID_PRODUTO = PRODUTOS_FISCO.ID_PRODUTO AND CAST(PRODUTOS.CODIGO_BARRAS_2 AS NUMERIC(15,0)) = :COD_BARRA
           INTO :ID_PRODUTO, :DESCRICAO, :CODIGO_BARRAS_1, CODIGO_BARRAS_2, :ICMS, :NCM, :CEST;

           IF (:ID_PRODUTO <> '') THEN
            BEGIN
              SELECT COUNT(*) FROM TEMP_SUPORTE_0200 WHERE COD_BARRA_NUMERO = CAST(:CODIGO_BARRAS_1 AS NUMERIC(15,0)) INTO :EXISTE;
              IF (:EXISTE > 0) THEN
               BEGIN
                 ID_PRODUTO = '';
               END
              ELSE
               BEGIN
                 SELECT COUNT(*) FROM TEMP_SUPORTE_0200 WHERE COD_ITEM = :ID_PRODUTO INTO :EXISTE;
                 IF (:EXISTE > 0) THEN
                    ID_PRODUTO = '';
                 CODIGO_BARRAS_1 = :CODIGO_BARRAS_2;
               END
            END
         END
        ELSE
         BEGIN
           SELECT COUNT(*) FROM TEMP_SUPORTE_0200 WHERE COD_ITEM = :ID_PRODUTO INTO :EXISTE;
           IF (:EXISTE > 0) THEN
               ID_PRODUTO = '';
         END
        SELECT LEN FROM TAMANHO(:NCM) INTO :TAMANHOVARIAVEL;
        IF ((:NCM IS NULL) OR (:NCM = '') OR (:NCM = '00000000') OR (:NCM = '99999999') OR (:TAMANHOVARIAVEL <> 8)) THEN
           NCM = '30049099';
        SELECT LEN FROM TAMANHO(:CEST) INTO :TAMANHOVARIAVEL;
        IF ((:CEST IS NULL) OR (:CEST = '') OR (:CEST = '0000000') OR (:CEST = '9999999') OR (:TAMANHOVARIAVEL <> 7)) THEN
           CEST = '1300400';

        IF ((:UNIDADE IS NULL) OR (:UNIDADE = '')) THEN
           UNIDADE = 'CX';
        IF (:ID_PRODUTO <> '') THEN
         BEGIN
           --IF ((SUBSTRING(:ICMS FROM 1 FOR 1) = 'F') OR (SUBSTRING(:ICMS FROM 1 FOR 1) = 'N') OR (SUBSTRING(:ICMS FROM 1 FOR 1) = 'I')) THEN
           --   ICMS = '0';
           INSERT INTO TEMP_SUPORTE_0200 VALUES (:ID_PRODUTO, :DESCRICAO, TRIM(:CODIGO_BARRAS_1), :ID_PRODUTO, :UNIDADE, '00', SUBSTRING(:NCM FROM 1 FOR 8), '', '', '',:ICMS, CAST(TRIM(:CODIGO_BARRAS_1) AS NUMERIC(15,0)), :CEST);
         END
        ELSE
         BEGIN
           INSERT INTO TEMP_SUPORTE_0200 VALUES (:ID, :DESCRICAO, TRIM(:COD_BARRA), :ID, 'UN', '00', '', '', '', '','0', CAST(TRIM(:COD_BARRA) AS NUMERIC(15,0)), :CEST);
           ID = :ID + 1;
         END
      END
   END

  IF (:TEMINVENTARIO = 'S') THEN
   BEGIN
     SELECT CD_FILIAL FROM PARAMETROS INTO :CD_FILIAL;
     SDATA = CAST(:DATAINICIAL AS VARCHAR(100));
     SDATA = SUBSTRING(:SDATA FROM 9 FOR 2)||'.'||SUBSTRING(:SDATA FROM 6 FOR 2)||'.'||SUBSTRING(:SDATA FROM 1 FOR 4);
     COMANDO1 = 'SELECT COUNT(*) FROM POSICAOESTOQUEDATA WHERE CD_FILIAL = '||:CD_FILIAL||' AND DATA = '''||:SDATA||''' AND QUANTIDADE > 0';
    
     TENTATIVAS = 1;
     EXECUTE STATEMENT :COMANDO1 INTO :EXISTE;
     WHILE ((:EXISTE = 0) AND (:TENTATIVAS < 4)) DO
      BEGIN
         SDATA = CAST(:DATAINICIAL + :TENTATIVAS AS VARCHAR(100));
         SDATA = SUBSTRING(:SDATA FROM 9 FOR 2)||'.'||SUBSTRING(:SDATA FROM 6 FOR 2)||'.'||SUBSTRING(:SDATA FROM 1 FOR 4);
         COMANDO1 = 'SELECT COUNT(*) FROM POSICAOESTOQUEDATA WHERE CD_FILIAL = '||:CD_FILIAL||' AND DATA = '''||:SDATA||''' AND QUANTIDADE > 0';
         EXECUTE STATEMENT :COMANDO1 INTO :EXISTE;
         TENTATIVAS = :TENTATIVAS + 1;
      END

     IF (:EXISTE > 0) THEN
      BEGIN
         COMANDO1 = 'SELECT ID_PRODUTO FROM POSICAOESTOQUEDATA WHERE CD_FILIAL = '||:CD_FILIAL||' AND DATA = '''||:SDATA||''' AND QUANTIDADE > 0';
         FOR
           EXECUTE STATEMENT :COMANDO1 INTO :ID_PRODUTO
         DO
          BEGIN
             FOR
               SELECT CAST(PRODUTOS.ID_PRODUTO AS INTEGER), CAST(PRODUTOS.CODIGO_BARRAS_1 AS NUMERIC(15,0)), TRIM(PRODUTOS.CODIGO_BARRAS_1),
                      PRODUTOS.DESCRICAO, PRODUTOS.UNIDADE, PRODUTOS_FISCO.NCM,
                      CAST(CAST(PRODUTOS_FISCO.ALIQUOTA_ICMS AS INTEGER) AS VARCHAR(10)),
                      PRODUTOS_FISCO.CEST
               FROM PRODUTOS, PRODUTOS_FISCO
               WHERE PRODUTOS.ID_PRODUTO = PRODUTOS_FISCO.ID_PRODUTO AND
                     PRODUTOS.ID_PRODUTO = :ID_PRODUTO
               INTO :ID_PRODUTO, :COD_BARRA, :CODIGO_BARRAS_1, :DESCRICAO, :UNIDADE, :NCM, :ICMS, :CEST
             DO
              BEGIN
                 IF ((:UNIDADE <> 'UN') AND
                     (:UNIDADE <> 'KG') AND
                     (:UNIDADE <> 'MT') AND
                     (:UNIDADE <> 'LT') AND
                     (:UNIDADE <> 'PC') AND
                     (:UNIDADE <> 'DP') AND
                     (:UNIDADE <> 'FD') AND
                     (:UNIDADE <> 'CX') AND
                     (:UNIDADE <> 'BI') AND
                     (:UNIDADE <> 'BL') AND
                     (:UNIDADE <> 'CT') AND
                     (:UNIDADE <> 'DZ') AND
                     (:UNIDADE <> 'EN') AND
                     (:UNIDADE <> 'FR') AND
                     (:UNIDADE <> 'KT') AND
                     (:UNIDADE <> 'PO') AND
                     (:UNIDADE <> 'TB') AND
                     (:UNIDADE <> 'VD')) THEN
                    UNIDADE = 'CX';
    
                SELECT LEN FROM TAMANHO(:NCM) INTO :TAMANHOVARIAVEL;
                IF ((:NCM IS NULL) OR (:NCM = '') OR (:NCM = '00000000') OR (:NCM = '99999999') OR (:TAMANHOVARIAVEL <> 8)) THEN
                   NCM = '30049099';
                SELECT LEN FROM TAMANHO(:CEST) INTO :TAMANHOVARIAVEL;
                IF ((:CEST IS NULL) OR (:CEST = '') OR (:CEST = '0000000') OR (:CEST = '9999999') OR (:TAMANHOVARIAVEL <> 7)) THEN
                   CEST = '1300400';
    
                SELECT COUNT(*) FROM TEMP_SUPORTE_0200 WHERE COD_BARRA_NUMERO = :COD_BARRA INTO :EXISTE;
                IF (:EXISTE = 0) THEN
                 BEGIN
                   SELECT COUNT(*) FROM TEMP_SUPORTE_0200 WHERE COD_ITEM = :ID_PRODUTO INTO :EXISTE;
                   IF (:EXISTE = 0) THEN
                    BEGIN
                       --IF ((SUBSTRING(:ICMS FROM 1 FOR 1) = 'F') OR (SUBSTRING(:ICMS FROM 1 FOR 1) = 'N') OR (SUBSTRING(:ICMS FROM 1 FOR 1) = 'I')) THEN
                       --   ICMS = '0';
                       INSERT INTO TEMP_SUPORTE_0200 VALUES (:ID_PRODUTO, :DESCRICAO, TRIM(:CODIGO_BARRAS_1), :ID_PRODUTO, :UNIDADE, '00', SUBSTRING(:NCM FROM 1 FOR 8), '', '', '',:ICMS, CAST(TRIM(:CODIGO_BARRAS_1) AS NUMERIC(15,0)), :CEST);
                    END
                 END
              END
          END
      END
   END


  FOR
    SELECT
     COD_ITEM, DESCR_ITEM, COD_BARRA, COD_ANT_ITEM,UNID_INV,
     TIPO_ITEM, COD_NCM, EX_IPI, COD_GEN, COD_LST, ALIQ_ICMS,CEST
    FROM
     TEMP_SUPORTE_0200
    GROUP BY
     COD_ITEM, DESCR_ITEM, COD_BARRA, COD_ANT_ITEM, UNID_INV,
     TIPO_ITEM, COD_NCM, EX_IPI, COD_GEN, COD_LST, ALIQ_ICMS, CEST
    INTO
     :COD_ITEM, :DESCR_ITEM, :COD_BARRA, :COD_ANT_ITEM, :UNID_INV,
     :TIPO_ITEM, :COD_NCM, :EX_IPI, :COD_GEN, :COD_LST, :ALIQ_ICMS, :CEST
  DO
   BEGIN
     LINHA = '';
     IF (:COD_NCM IS NULL) THEN
        COD_NCM = '';
     IF ((:UNID_INV <> 'UN') AND
         (:UNID_INV <> 'KG') AND
         (:UNID_INV <> 'MT') AND
         (:UNID_INV <> 'LT') AND
         (:UNID_INV <> 'PC') AND
         (:UNID_INV <> 'DP') AND
         (:UNID_INV <> 'FD') AND
         (:UNID_INV <> 'CX') AND
         (:UNID_INV <> 'BI') AND
         (:UNID_INV <> 'BL') AND
         (:UNID_INV <> 'CT') AND
         (:UNID_INV <> 'DZ') AND
         (:UNID_INV <> 'EN') AND
         (:UNID_INV <> 'FR') AND
         (:UNID_INV <> 'KT') AND
         (:UNID_INV <> 'PO') AND
         (:UNID_INV <> 'TB') AND
         (:UNID_INV <> 'VD')) THEN
        UNID_INV = 'CX';

     IF (:DATAINICIAL >= '01.01.2017') THEN
      BEGIN
        LINHA = '|0200|'||:COD_ITEM||'|'||:DESCR_ITEM||'|'||:COD_BARRA||'||'||:UNID_INV||'|'||:TIPO_ITEM||'|'||:COD_NCM||'|'||:EX_IPI||'|'||:COD_GEN||'|'||:COD_LST||'|'||:ALIQ_ICMS||'|'||:CEST||'|';
      END
     ELSE
      BEGIN
        LINHA = '|0200|'||:COD_ITEM||'|'||:DESCR_ITEM||'|'||:COD_BARRA||'||'||:UNID_INV||'|'||:TIPO_ITEM||'|'||:COD_NCM||'|'||:EX_IPI||'|'||:COD_GEN||'|'||:COD_LST||'|'||:ALIQ_ICMS||'|';
      END
     SUSPEND;
   END
END ^

ALTER PROCEDURE SP_SUPORTE_ACERTA_CANCELAMENTOM RETURNS (CD_FILIAL DOUBLE PRECISION,
CANCELAMENTOCAIXA DOUBLE PRECISION,
QTVENDALANCAMENTO INTEGER,
QTCANCELAMENTOLANCAMENTO INTEGER)
AS 
BEGIN
  FOR
    SELECT
     CD_FILIAL
    FROM
     FILIAIS
    INTO
     :CD_FILIAL
  DO
   BEGIN
      FOR
        SELECT
         DISTINCT CD_VENDA
        FROM
         CAIXA
        WHERE
         CD_FILIAL = :CD_FILIAL AND
         TIPO_VENDA = 'D'
        INTO
         :CANCELAMENTOCAIXA
      DO
       BEGIN
         SELECT
          COUNT(*)
         FROM
          LANCAMENTOS
         WHERE
          CD_FILIAL = :CD_FILIAL AND
          CD_VENDA = :CANCELAMENTOCAIXA AND
          TIPO_VENDA = 'V'
         INTO
          :QTVENDALANCAMENTO;
    
         SELECT
          COUNT(*)
         FROM
          LANCAMENTOS
         WHERE
          CD_FILIAL = :CD_FILIAL AND
          CD_VENDA = :CANCELAMENTOCAIXA AND
          TIPO_VENDA = 'D'
         INTO
          :QTCANCELAMENTOLANCAMENTO;
    
         IF (:QTVENDALANCAMENTO <> :QTCANCELAMENTOLANCAMENTO) THEN
          BEGIN
            DELETE FROM LANCAMENTOS WHERE CD_FILIAL = :CD_FILIAL AND CD_VENDA = :CANCELAMENTOCAIXA AND TIPO_VENDA = 'D';
            /*SUSPEND;*/
          END
       END
   END
END ^

ALTER PROCEDURE SP_SUPORTE_ACERTA_CANCELAMENTOS (CD_FILIAL DOUBLE PRECISION)
RETURNS (CANCELAMENTOCAIXA DOUBLE PRECISION,
DATA_CAIXA DATE,
QTVENDALANCAMENTO INTEGER,
QTCANCELAMENTOLANCAMENTO INTEGER,
ID_PRODUTO DOUBLE PRECISION,
ID_OPERADORCAIXA DOUBLE PRECISION,
DATA DATE,
CD_PRODUTO VARCHAR(6) CHARACTER SET NONE,
DESCRICAO VARCHAR(60) CHARACTER SET NONE,
TERMINAL DOUBLE PRECISION,
CD_OPERADOR DOUBLE PRECISION,
CD_USUARIO DOUBLE PRECISION,
CD_LABORATORIO DOUBLE PRECISION,
CD_GRUPO DOUBLE PRECISION,
CD_CLASSE DOUBLE PRECISION,
CD_CLIENTE DOUBLE PRECISION,
CD_CONVENIO DOUBLE PRECISION,
CD_VENDEDOR DOUBLE PRECISION,
CUSTO_MEDIO DOUBLE PRECISION,
CUSTO_UNITARIO DOUBLE PRECISION,
QUANTIDADE DOUBLE PRECISION,
VALOR DOUBLE PRECISION,
COMISSAO DOUBLE PRECISION,
NOTA_FISCAL VARCHAR(10) CHARACTER SET NONE,
DESCONTO DOUBLE PRECISION,
PROMOCAO DOUBLE PRECISION,
ENTREGA VARCHAR(1) CHARACTER SET NONE,
HORA TIME,
TROCA VARCHAR(1) CHARACTER SET NONE,
NUMERO DOUBLE PRECISION,
USUARIO VARCHAR(100) CHARACTER SET NONE,
ARREDONDAMENTO DOUBLE PRECISION,
CD_LANCAMENTO DOUBLE PRECISION,
CODIGO_BARRAS VARCHAR(14) CHARACTER SET NONE,
ECF VARCHAR(20) CHARACTER SET NONE,
CD_SUBGRUPO DOUBLE PRECISION,
ID_CLIENTE_PROPRIEDADE DOUBLE PRECISION,
CEST VARCHAR(15) CHARACTER SET NONE,
FCP NUMERIC(15, 2),
PERCENTUALREDUCAO NUMERIC(15, 2))
AS 
BEGIN
  FOR
    SELECT
     DISTINCT CD_VENDA,
     DATA_CAIXA
    FROM
     CAIXA
    WHERE
     CD_FILIAL = :CD_FILIAL AND
     TIPO_VENDA = 'D'
    INTO
     :CANCELAMENTOCAIXA,
     :DATA_CAIXA
  DO
   BEGIN
     SELECT
      COUNT(*)
     FROM
      LANCAMENTOS
     WHERE
      CD_FILIAL = :CD_FILIAL AND
      CD_VENDA = :CANCELAMENTOCAIXA AND
      TIPO_VENDA = 'V'
     INTO
      :QTVENDALANCAMENTO;

     SELECT
      COUNT(*)
     FROM
      LANCAMENTOS
     WHERE
      CD_FILIAL = :CD_FILIAL AND
      CD_VENDA = :CANCELAMENTOCAIXA AND
      TIPO_VENDA = 'D'
     INTO
      :QTCANCELAMENTOLANCAMENTO;

     IF (:QTVENDALANCAMENTO <> :QTCANCELAMENTOLANCAMENTO) THEN
      BEGIN
        DELETE FROM LANCAMENTOS WHERE CD_FILIAL = :CD_FILIAL AND CD_VENDA = :CANCELAMENTOCAIXA AND TIPO_VENDA = 'D';
        
        FOR
         SELECT
          ID_PRODUTO, CD_PRODUTO, DESCRICAO, ID_OPERADORCAIXA, TERMINAL, CD_OPERADOR, CD_USUARIO,
          CD_LABORATORIO, CD_GRUPO, CD_CLASSE, CD_CLIENTE, CD_CONVENIO, CD_VENDEDOR,
          CUSTO_MEDIO, CUSTO_UNITARIO, QUANTIDADE, VALOR, COMISSAO, NOTA_FISCAL,
          DESCONTO, PROMOCAO, ENTREGA, HORA, TROCA, NUMERO, USUARIO, ARREDONDAMENTO, DATA_LANCAMENTO,
          CODIGO_BARRAS, ECF, CD_SUBGRUPO, ID_CLIENTE_PROPRIEDADE, CEST, FCP, PERCENTUALREDUCAO
         FROM
          LANCAMENTOS
         WHERE
          CD_FILIAL = :CD_FILIAL AND
          CD_VENDA = :CANCELAMENTOCAIXA AND
          TIPO_VENDA = 'V'
         INTO
          :ID_PRODUTO, :CD_PRODUTO, :DESCRICAO, :ID_OPERADORCAIXA, :TERMINAL, :CD_OPERADOR, :CD_USUARIO,
          :CD_LABORATORIO, :CD_GRUPO, :CD_CLASSE, :CD_CLIENTE, :CD_CONVENIO, :CD_VENDEDOR,
          :CUSTO_MEDIO, :CUSTO_UNITARIO, :QUANTIDADE, :VALOR, :COMISSAO, :NOTA_FISCAL,
          :DESCONTO, :PROMOCAO, :ENTREGA, :HORA, :TROCA, :NUMERO, :USUARIO, :ARREDONDAMENTO, :DATA,
          :CODIGO_BARRAS, :ECF, :CD_SUBGRUPO, :ID_CLIENTE_PROPRIEDADE, :CEST, :FCP, :PERCENTUALREDUCAO
        DO
         BEGIN
          UPDATE CONTROLE SET VALOR = VALOR + 1 WHERE CAMPO = 'CD_LANCAMENTO';
          SELECT VALOR FROM CONTROLE WHERE CAMPO = 'CD_LANCAMENTO' INTO :CD_LANCAMENTO;

          INSERT INTO LANCAMENTOS VALUES (:CD_LANCAMENTO, :ID_PRODUTO, :CD_FILIAL, :CD_PRODUTO, :DESCRICAO,
                                          :CD_LABORATORIO, :CD_GRUPO, :CD_CLASSE, :CD_CONVENIO, :CD_CLIENTE,
                                          :CD_VENDEDOR, :CD_OPERADOR, :CD_USUARIO, NULL, :CANCELAMENTOCAIXA,
                                          :ID_OPERADORCAIXA, :CUSTO_MEDIO,  :CUSTO_UNITARIO, :DATA, :DATA_CAIXA,
                                          :QUANTIDADE, :VALOR, :COMISSAO, :NOTA_FISCAL, :DESCONTO, :PROMOCAO,
                                          'D', NULL, 'E', 'N', :ENTREGA, :HORA, 0, :TROCA, '', :NUMERO,
                                          :TERMINAL, :USUARIO, NULL, :ARREDONDAMENTO,  NULL, NULL, NULL,
                                          NULL,NULL, NULL, NULL, 0, NULL, NULL, NULL, NULL, :CODIGO_BARRAS,  :ECF, :CD_SUBGRUPO, '',
                                          :ID_CLIENTE_PROPRIEDADE, :CEST, :FCP, :PERCENTUALREDUCAO,
                                          'N', :ID_PRODUTO, 'N', 'N', 'N', 'N');
          /*SUSPEND;*/
         END
      END
   END
END ^

ALTER PROCEDURE SP_SUPORTE_ACERTA_DATA_CUPOM RETURNS (NUMERO_FABRICACAO VARCHAR(100) CHARACTER SET NONE,
COOINICIAL VARCHAR(100) CHARACTER SET NONE,
COOFINAL VARCHAR(100) CHARACTER SET NONE,
DATA_MOVIMENTO VARCHAR(100) CHARACTER SET NONE)
AS 
BEGIN
  FOR
    SELECT
     DISTINCT NUMERO_FABRICACAO
    FROM
     PAF_R05
    INTO
     :NUMERO_FABRICACAO
  DO
   BEGIN
    SELECT
     FIRST 1 COO, DATA_MOVIMENTO
    FROM
     PAF_R02
    WHERE
     NUMERO_FABRICACAO = :NUMERO_FABRICACAO
    ORDER BY
     NUMERO_FABRICACAO, COO
    INTO
     :COOFINAL,
     :DATA_MOVIMENTO;

    UPDATE PAF_R04 SET
     DATA_INICIO_EMISSAO = :DATA_MOVIMENTO
    WHERE
     NUMERO_FABRICACAO = :NUMERO_FABRICACAO AND
     COO < :COOFINAL;

    COOINICIAL = :COOFINAL;

    FOR
      SELECT
       COO,
       DATA_MOVIMENTO
      FROM
       PAF_R02
      WHERE
       NUMERO_FABRICACAO = :NUMERO_FABRICACAO AND
       DATA_MOVIMENTO > :DATA_MOVIMENTO
      ORDER BY
       NUMERO_FABRICACAO, COO
      INTO
       :COOFINAL,
       :DATA_MOVIMENTO
    DO
     BEGIN
       SUSPEND;

       UPDATE PAF_R04 SET
        DATA_INICIO_EMISSAO = :DATA_MOVIMENTO
       WHERE
        NUMERO_FABRICACAO = :NUMERO_FABRICACAO AND
        COO > :COOINICIAL AND COO < :COOFINAL;

       COOINICIAL = :COOFINAL;
     END
   END
END ^

ALTER PROCEDURE SP_SUPORTE_ACERTA_MUNICIPIO RETURNS (CIDADE VARCHAR(1000) CHARACTER SET NONE,
CD_MUNICIPIO DOUBLE PRECISION,
UF VARCHAR(2) CHARACTER SET NONE)
AS 
BEGIN
  FOR
    SELECT DISTINCT CIDADE, UF
    FROM DISTRIBUIDORES
    WHERE
      CIDADE IS NOT NULL AND CIDADE <> '' AND
      CD_MUNICIPIO IS NOT NULL AND CD_MUNICIPIO > 0
    INTO :CIDADE, :UF
  DO
   BEGIN
       SELECT DISTINCT ID_MUNICIPIO
       FROM NFEMUNICIPIOS
       WHERE MUNICIPIO = :CIDADE AND SIGLA = :UF
       INTO :CD_MUNICIPIO;

       UPDATE DISTRIBUIDORES SET
        CD_MUNICIPIO = :CD_MUNICIPIO
       WHERE CIDADE = :CIDADE;

       SUSPEND;
   END
END ^

ALTER PROCEDURE SP_SUPORTE_ACERTA_SPED_BARRA AS 
declare variable PV double precision;
declare variable BARRA varchar(14);
declare variable EF double precision;
declare variable ID double precision;
declare variable BARRA2 varchar(14);
declare variable NCM varchar(100);
BEGIN
  UPDATE SPED_PIS_COFINS SET BARRA_NUM = CAST(BARRA AS DOUBLE PRECISION);

  FOR
    SELECT BARRA FROM SPED_PIS_COFINS INTO :BARRA
  DO
   BEGIN
     SELECT FIRST 1 CODIGO_BARRAS_2 FROM PRODUTOS WHERE CODIGO_BARRAS_1 = :BARRA INTO :BARRA2;
     IF (:BARRA2 IS NOT NULL) THEN
        UPDATE SPED_PIS_COFINS SET BARRA2 = :BARRA2, BARRA_NUM2 = CAST(:BARRA2 AS NUMERIC(15,0))
        WHERE BARRA = :BARRA;
   END
END ^

ALTER PROCEDURE SP_SUPORTE_C425 (NUMERO_FABRICACAO VARCHAR(100) CHARACTER SET NONE,
SITUACAO VARCHAR(100) CHARACTER SET NONE)
RETURNS (LINHA VARCHAR(1000) CHARACTER SET NONE,
COO VARCHAR(10) CHARACTER SET NONE,
BASECALCULO VARCHAR(100) CHARACTER SET NONE,
DESCONTO NUMERIC(15, 2),
BASECALCULOFLOAT NUMERIC(15, 2),
VLFLOAT NUMERIC(15, 2))
AS 
declare variable ID_PAF integer;
declare variable COD_ITEM varchar(20);
declare variable DESCRICAO varchar(100);
declare variable COD varchar(20);
declare variable QUANTFLOAT numeric(15,3);
declare variable QUANT_CANC varchar(20);
declare variable QUANTFLOAT_CANC numeric(15,3);
declare variable UNIDADE varchar(20);
declare variable CST varchar(20);
declare variable CFOP varchar(20);
declare variable ALIQ varchar(20);
declare variable ALIQFLOAT numeric(15,2);
declare variable PERCENTUAL_DESCONTO numeric(15,3);
declare variable EXISTE integer;
declare variable VALORCUPOM numeric(15,2);
declare variable QUANT varchar(20);
BEGIN
  DELETE FROM TEMP_SUPORTE_C425;

  FOR
   SELECT
    PAF_R05.CODIGO_PRODUTO_SERVICO,
    CAST(PAF_R05.QUANTIDADE AS NUMERIC(15,0)),
    CAST(PAF_R05.VALOR_TOTAL_LIQUIDO AS NUMERIC(15,0)),
    PAF_R05.COO
   FROM
    PAF_R05, TEMP_COO
   WHERE
    PAF_R05.COO = TEMP_COO.COO AND
    PAF_R05.NUMERO_FABRICACAO = :NUMERO_FABRICACAO AND
    PAF_R05.INDICADOR_CANCELAMENTO = 'N' AND
    PAF_R05.TOTALIZADOR_PARCIAL = :SITUACAO
   INTO
    :COD,
    :QUANTFLOAT,
    :VLFLOAT,
    :COO
  DO
   BEGIN
     QUANTFLOAT = :QUANTFLOAT / 1000;
     VLFLOAT = :VLFLOAT / 100;
     IF (:VLFLOAT = 0) THEN
        VLFLOAT = 0.01;

     COD = TRIM(:COD);
     DESCRICAO = TRIM(:DESCRICAO);
     UNIDADE = TRIM(:UNIDADE);
     COD_ITEM = '';

     DESCONTO = 0;

     SELECT FIRST 1 COD_ITEM, UNID_INV FROM TEMP_SUPORTE_0200 WHERE COD_BARRA_NUMERO = CAST(:COD AS NUMERIC(15,0)) INTO :COD_ITEM, :UNIDADE;

     BASECALCULOFLOAT = :VLFLOAT;
     PERCENTUAL_DESCONTO = 0;
     DESCONTO = 0;
     SELECT PERCENTUAL_DESCONTO FROM SP_PAF_DESCONTO_R04(:NUMERO_FABRICACAO, :COO) INTO :PERCENTUAL_DESCONTO;
     IF ((:PERCENTUAL_DESCONTO IS NOT NULL) AND (:PERCENTUAL_DESCONTO > 0)) THEN
      BEGIN
        DESCONTO = (:VLFLOAT * PERCENTUAL_DESCONTO) / 100;
        BASECALCULOFLOAT = CAST(:VLFLOAT - :DESCONTO AS NUMERIC(15,2));
        IF (:BASECALCULOFLOAT = 0) THEN
           BASECALCULOFLOAT = 0.01;
      END

     SELECT COUNT(*) FROM TEMP_SUPORTE_C425 WHERE COD_ITEM = :COD_ITEM INTO :EXISTE;
     IF (:EXISTE = 0) THEN
      BEGIN
        INSERT INTO TEMP_SUPORTE_C425 VALUES (:COD_ITEM, :QUANTFLOAT, :UNIDADE, :BASECALCULOFLOAT);
      END
     ELSE
      BEGIN
        UPDATE TEMP_SUPORTE_C425 SET
         QUANTIDADE = QUANTIDADE + :QUANTFLOAT,
         VALOR = VALOR + :BASECALCULOFLOAT
        WHERE
         COD_ITEM = :COD_ITEM;
      END
   END

  FOR
    SELECT
     TEMP_SUPORTE_C425.COD_ITEM,
     TEMP_SUPORTE_C425.UNIDADE,
     CAST(TEMP_SUPORTE_C425.QUANTIDADE AS NUMERIC(15,3)),
     TEMP_SUPORTE_C425.VALOR
    FROM
     TEMP_SUPORTE_C425
    WHERE
     TEMP_SUPORTE_C425.COD_ITEM > ''
    INTO
     :COD_ITEM,
     :UNIDADE,
     :QUANTFLOAT,
     :BASECALCULOFLOAT
  DO
   BEGIN
     QUANT = CAST(:QUANTFLOAT AS VARCHAR(100));
     QUANT = REPLACE(:QUANT, '.', ',');

     BASECALCULO = CAST(:BASECALCULOFLOAT AS VARCHAR(100));
     BASECALCULO = REPLACE(:BASECALCULO , '.', ',');

     LINHA = '|C425|'||:COD_ITEM||'|'||:QUANT||'|'||:UNIDADE||'|'||:BASECALCULO||'|||';
     SUSPEND;
   END
END ^

ALTER PROCEDURE SP_SUPORTE_C490 (NUMERO_FABRICACAO VARCHAR(20) CHARACTER SET NONE,
DATAINICIAL DATE)
RETURNS (LINHA VARCHAR(1000) CHARACTER SET NONE,
VALORTOTAL NUMERIC(15, 2),
ALIQUOTANUMERO NUMERIC(15, 2),
VALORADESCONTAR NUMERIC(15, 2),
VALOR_NUMERO NUMERIC(15, 2))
AS 
declare variable CST varchar(100);
declare variable CFOP varchar(100);
declare variable ALIQUOTA varchar(100);
declare variable DATA_INICIO_EMISSAO varchar(100);
declare variable VALOR varchar(100);
declare variable BASECALCULO varchar(100);
declare variable VALORICMS varchar(100);
declare variable VALORICMSNUMERO numeric(15,2);
declare variable PERCENTUAL_DESCONTO numeric(15,3);
declare variable VALORITEM numeric(15,2);
declare variable VALORCUPOM numeric(15,2);
declare variable DESCONTO numeric(15,2);
declare variable COO varchar(6);
declare variable DESCONTOITEM numeric(15,2);
declare variable DATAINICIALSTRING varchar(10);
BEGIN
  DATAINICIALSTRING = CAST(:DATAINICIAL AS VARCHAR(10));
  DATAINICIALSTRING = SUBSTRING(:DATAINICIALSTRING FROM 9 FOR 2)||SUBSTRING(:DATAINICIALSTRING FROM 6 FOR 2)||SUBSTRING(:DATAINICIALSTRING FROM 3 FOR 2);

  FOR
    SELECT 
     PAF_R05.CST,
     PAF_R05.CFOP,
     PAF_R05.ALIQUOTA,
     PAF_R04.DATA_INICIO_EMISSAO,
     SUM(
        CAST(PAF_R05.VALOR_TOTAL_LIQUIDO AS NUMERIC(15,2))
     )
    FROM
     PAF_R04,
     PAF_R05
    WHERE
     PAF_R04.NUMERO_FABRICACAO = :NUMERO_FABRICACAO AND
     PAF_R04.DATA_INICIO_EMISSAO = :DATAINICIALSTRING AND
     PAF_R05.NUMERO_FABRICACAO = PAF_R04.NUMERO_FABRICACAO AND
     PAF_R05.COO = PAF_R04.COO AND
     PAF_R05.VALOR_TOTAL_LIQUIDO IS NOT NULL AND
     PAF_R05.VALOR_TOTAL_LIQUIDO <> '' AND
     PAF_R04.CANCELAMENTO = 'N' AND
     PAF_R05.INDICADOR_CANCELAMENTO = 'N'
    GROUP BY
     PAF_R05.CST,
     PAF_R05.CFOP,
     PAF_R05.ALIQUOTA,
     PAF_R04.DATA_INICIO_EMISSAO
    INTO
     :CST,
     :CFOP,
     :ALIQUOTA,
     :DATA_INICIO_EMISSAO,
     :VALOR_NUMERO
  DO
   BEGIN
     ALIQUOTANUMERO = CAST(:ALIQUOTA AS NUMERIC(15,0));
     ALIQUOTANUMERO = ALIQUOTANUMERO / 100;

     VALOR_NUMERO = :VALOR_NUMERO / 100;

     VALORADESCONTAR = 0;
     /*IF (:ALIQUOTA > 0) THEN
      BEGIN*/
         FOR
             SELECT
              PAF_R04.COO,
              CAST(PAF_R04.SUBTOTAL AS NUMERIC(15,2)),
              CAST(PAF_R04.DESCONTO_SUB_TOTAL AS NUMERIC(15,2))
             FROM
              PAF_R04
             WHERE
              PAF_R04.NUMERO_FABRICACAO = :NUMERO_FABRICACAO AND
              PAF_R04.DATA_INICIO_EMISSAO = :DATAINICIALSTRING AND
              PAF_R04.DESCONTO_SUB_TOTAL > 0 AND
              PAF_R04.CANCELAMENTO = 'N' AND
              PAF_R04.SUBTOTAL > 0
             INTO
              :COO,
              :VALORCUPOM,
              :DESCONTO
         DO
          BEGIN
            DESCONTO = :DESCONTO / 100;
            VALORCUPOM = :VALORCUPOM / 100;
            PERCENTUAL_DESCONTO = ((:DESCONTO / :VALORCUPOM) * 100);
            FOR
              SELECT
                CAST(PAF_R05.VALOR_TOTAL_LIQUIDO AS NUMERIC(15,2))
              FROM
                PAF_R05
              WHERE
                PAF_R05.NUMERO_FABRICACAO = :NUMERO_FABRICACAO AND
                PAF_R05.COO = :COO AND
                PAF_R05.ALIQUOTA = :ALIQUOTA AND
                PAF_R05.CST = :CST AND
                PAF_R05.CFOP = :CFOP AND
                PAF_R05.INDICADOR_CANCELAMENTO = 'N'
              INTO
                :VALORITEM
            DO
             BEGIN
                VALORITEM = :VALORITEM / 100;
                DESCONTOITEM = (:VALORITEM * :PERCENTUAL_DESCONTO) / 100;
                VALORADESCONTAR = :VALORADESCONTAR + DESCONTOITEM;
             END
          END
      --END

     VALOR = CAST((:VALOR_NUMERO) AS VARCHAR(100));
     IF (((:VALORADESCONTAR IS NOT NULL)) AND (:VALORADESCONTAR > 0)) THEN
        BASECALCULO = CAST(((:VALOR_NUMERO) - :VALORADESCONTAR) AS VARCHAR(100));
     ELSE
        BASECALCULO = CAST((:VALOR_NUMERO) AS VARCHAR(100));
     IF (:BASECALCULO < 0.01) THEN
        BASECALCULO = :VALOR;

     VALORTOTAL = CAST(:BASECALCULO AS NUMERIC(15,2));
     VALORICMSNUMERO = 0;
     ALIQUOTANUMERO = CAST(:ALIQUOTA AS NUMERIC(15,2));
     ALIQUOTANUMERO = :ALIQUOTANUMERO / 100;
     IF ((:ALIQUOTA > 0) AND (:BASECALCULO > 0)) THEN
        VALORICMSNUMERO = (CAST(:BASECALCULO AS NUMERIC(15,2)) * :ALIQUOTANUMERO) / 100;
     VALORICMS = CAST(:VALORICMSNUMERO AS VARCHAR(100));

     ALIQUOTA = CAST(:ALIQUOTANUMERO AS VARCHAR(100));
     ALIQUOTA = REPLACE(:ALIQUOTA, '.', ',');
     VALOR = REPLACE(:VALOR, '.', ',');
     BASECALCULO = REPLACE(:BASECALCULO,  '.', ',');
     VALORICMS = REPLACE(:VALORICMS, '.', ',');

     VALOR_NUMERO = :VALOR_NUMERO / 100;

     IF (:ALIQUOTANUMERO = 0) THEN
      BEGIN
        LINHA = '|C490|'||:CST||'|'||:CFOP||'|0|'||:BASECALCULO||'|0|0||';
      END
     ELSE
      BEGIN
        LINHA = '|C490|'||:CST||'|'||:CFOP||'|'||:ALIQUOTA||'|'||:BASECALCULO||'|'||:BASECALCULO||'|'||:VALORICMS||'||';
      END

     SUSPEND;
   END
END ^

ALTER PROCEDURE SP_SUPORTE_CALCULA_PISCOFINS (DATAINICIAL DATE,
DATAFINAL DATE)
AS 
declare variable BARRA varchar(14);
declare variable PIS_ENTRADA_LR varchar(2);
declare variable COFINS_ENTRADA_LR varchar(2);
declare variable PIS_ENTRADA_LP varchar(2);
declare variable COFINS_ENTRADA_LP varchar(2);
declare variable PIS_ENTRADA_SN varchar(2);
declare variable COFINS_ENTRADA_SN varchar(2);
declare variable PIS_SAIDA_LR varchar(2);
declare variable COFINS_SAIDA_LR varchar(2);
declare variable PIS_SAIDA_LP varchar(2);
declare variable COFINS_SAIDA_LP varchar(2);
declare variable PIS_SAIDA_SN varchar(2);
declare variable COFINS_SAIDA_SN varchar(2);
declare variable PIS_ENTRADA varchar(2);
declare variable COFINS_ENTRADA varchar(2);
declare variable PIS_SAIDA varchar(2);
declare variable COFINS_SAIDA varchar(2);
declare variable COMANDO varchar(10000);
declare variable COMANDO1 varchar(10000);
declare variable ENQUADRAMENTOTRIBUTARIO varchar(1);
declare variable PISALIQUOTA numeric(15,2);
declare variable COFINSALIQUOTA numeric(15,2);
BEGIN
  SELECT ENQUADRAMENTOTRIBUTARIO, PISALIQUOTA, COFINSALIQUOTA FROM PARAMETROS INTO :ENQUADRAMENTOTRIBUTARIO, :PISALIQUOTA, :COFINSALIQUOTA;
  IF ((:PISALIQUOTA IS NULL) OR (:PISALIQUOTA = 0)) THEN
     PISALIQUOTA = 1.65;
  IF ((:COFINSALIQUOTA IS NULL) OR (:COFINSALIQUOTA = 0)) THEN
     COFINSALIQUOTA = 7.6;

  DELETE FROM SPED_PIS_COFINS WHERE BARRA IN (SELECT BARRA FROM SPED_PIS_COFINS GROUP BY BARRA HAVING COUNT(BARRA) > 1);

  /* NOTAS DE ENTRADA */
  UPDATE SINTEGRA_NF_ENTRADA_ITENS SET PIS_CST = '70' WHERE DATAHORA >= :DATAINICIAL AND DATAHORA <= :DATAFINAL AND (PIS_CST IS NULL OR PIS_CST = '04') AND COD_NF_ENTRADA IN
  (SELECT COD_NF_ENTRADA FROM SINTEGRA_NF_ENTRADA WHERE DATAHORA_EMISSAO >= :DATAINICIAL AND DATAHORA_EMISSAO <= :DATAFINAL AND EMITENTE_NF = 'T');
  UPDATE SINTEGRA_NF_ENTRADA_ITENS SET COFINS_CST = '70' WHERE DATAHORA >= :DATAINICIAL AND DATAHORA <= :DATAFINAL AND (COFINS_CST IS NULL OR COFINS_CST = '04') AND COD_NF_ENTRADA IN
  (SELECT COD_NF_ENTRADA FROM SINTEGRA_NF_ENTRADA WHERE DATAHORA_EMISSAO >= :DATAINICIAL AND DATAHORA_EMISSAO <= :DATAFINAL AND EMITENTE_NF = 'T');
  UPDATE SINTEGRA_NF_ENTRADA_ITENS SET PIS_CST = '50' WHERE DATAHORA >= :DATAINICIAL AND DATAHORA <= :DATAFINAL AND PIS_CST = '01' AND COD_NF_ENTRADA IN
  (SELECT COD_NF_ENTRADA FROM SINTEGRA_NF_ENTRADA WHERE DATAHORA_EMISSAO >= :DATAINICIAL AND DATAHORA_EMISSAO <= :DATAFINAL AND EMITENTE_NF = 'T');
  UPDATE SINTEGRA_NF_ENTRADA_ITENS SET COFINS_CST = '50' WHERE DATAHORA >= :DATAINICIAL AND DATAHORA <= :DATAFINAL AND COFINS_CST = '01' AND COD_NF_ENTRADA IN
  (SELECT COD_NF_ENTRADA FROM SINTEGRA_NF_ENTRADA WHERE DATAHORA_EMISSAO >= :DATAINICIAL AND DATAHORA_EMISSAO <= :DATAFINAL AND EMITENTE_NF = 'T');
  /* NOTAS DE ENTRADA */

  /* NOTAS DE SAIDA */
  UPDATE SINTEGRA_NF_ENTRADA_ITENS SET PIS_CST = '04' WHERE DATAHORA >= :DATAINICIAL AND DATAHORA <= :DATAFINAL AND (PIS_CST IS NULL OR PIS_CST = '70') AND COD_NF_ENTRADA IN
  (SELECT COD_NF_ENTRADA FROM SINTEGRA_NF_ENTRADA WHERE DATAHORA_EMISSAO >= :DATAINICIAL AND DATAHORA_EMISSAO <= :DATAFINAL AND EMITENTE_NF = 'P');
  UPDATE SINTEGRA_NF_ENTRADA_ITENS SET COFINS_CST = '04' WHERE DATAHORA >= :DATAINICIAL AND DATAHORA <= :DATAFINAL AND (COFINS_CST IS NULL OR COFINS_CST = '70') AND COD_NF_ENTRADA IN
  (SELECT COD_NF_ENTRADA FROM SINTEGRA_NF_ENTRADA WHERE DATAHORA_EMISSAO >= :DATAINICIAL AND DATAHORA_EMISSAO <= :DATAFINAL AND EMITENTE_NF = 'P');
  UPDATE SINTEGRA_NF_ENTRADA_ITENS SET PIS_CST = '01' WHERE DATAHORA >= :DATAINICIAL AND DATAHORA <= :DATAFINAL AND PIS_CST = '50' AND COD_NF_ENTRADA IN
  (SELECT COD_NF_ENTRADA FROM SINTEGRA_NF_ENTRADA WHERE DATAHORA_EMISSAO >= :DATAINICIAL AND DATAHORA_EMISSAO <= :DATAFINAL AND EMITENTE_NF = 'P');
  UPDATE SINTEGRA_NF_ENTRADA_ITENS SET COFINS_CST = '01' WHERE DATAHORA >= :DATAINICIAL AND DATAHORA <= :DATAFINAL AND COFINS_CST = '50' AND COD_NF_ENTRADA IN
  (SELECT COD_NF_ENTRADA FROM SINTEGRA_NF_ENTRADA WHERE DATAHORA_EMISSAO >= :DATAINICIAL AND DATAHORA_EMISSAO <= :DATAFINAL AND EMITENTE_NF = 'P');
  /* NOTAS DE SAIDA */

  /* NOTAS DE ENTRADA */
  FOR
    SELECT
     SINTEGRA_NF_ENTRADA_ITENS.REF_PRODUTOS,
     SPED_PIS_COFINS.PIS_ENTRADA_LR,
     SPED_PIS_COFINS.COFINS_ENTRADA_LR,
     SPED_PIS_COFINS.PIS_ENTRADA_LP,
     SPED_PIS_COFINS.COFINS_ENTRADA_LP,
     SPED_PIS_COFINS.PIS_ENTRADA_SN,
     SPED_PIS_COFINS.COFINS_ENTRADA_SN
    FROM
     SPED_PIS_COFINS, SINTEGRA_NF_ENTRADA_ITENS, SINTEGRA_NF_ENTRADA
    WHERE
     SINTEGRA_NF_ENTRADA.COD_NF_ENTRADA = SINTEGRA_NF_ENTRADA_ITENS.COD_NF_ENTRADA AND
     (SPED_PIS_COFINS.BARRA = SINTEGRA_NF_ENTRADA_ITENS.REF_PRODUTOS OR
      SPED_PIS_COFINS.BARRA2 = SINTEGRA_NF_ENTRADA_ITENS.REF_PRODUTOS) AND
     SINTEGRA_NF_ENTRADA_ITENS.DATAHORA >= :DATAINICIAL AND
     SINTEGRA_NF_ENTRADA_ITENS.DATAHORA <= :DATAFINAL AND
     SINTEGRA_NF_ENTRADA.EMITENTE_NF = 'T'
    GROUP BY
     SINTEGRA_NF_ENTRADA_ITENS.REF_PRODUTOS,
     SPED_PIS_COFINS.PIS_ENTRADA_LR,
     SPED_PIS_COFINS.COFINS_ENTRADA_LR,
     SPED_PIS_COFINS.PIS_ENTRADA_LP,
     SPED_PIS_COFINS.COFINS_ENTRADA_LP,
     SPED_PIS_COFINS.PIS_ENTRADA_SN,
     SPED_PIS_COFINS.COFINS_ENTRADA_SN
    INTO
     :BARRA,
     :PIS_ENTRADA_LR,
     :COFINS_ENTRADA_LR,
     :PIS_ENTRADA_LP,
     :COFINS_ENTRADA_LP,
     :PIS_ENTRADA_SN,
     :COFINS_ENTRADA_SN
  DO
   BEGIN
     IF (:ENQUADRAMENTOTRIBUTARIO = 'S') THEN
      BEGIN
        PIS_ENTRADA = :PIS_ENTRADA_SN;
        COFINS_ENTRADA = :COFINS_ENTRADA_SN;
      END
     ELSE
     IF (:ENQUADRAMENTOTRIBUTARIO = 'R') THEN
      BEGIN
        PIS_ENTRADA = :PIS_ENTRADA_LR;
        COFINS_ENTRADA = :COFINS_ENTRADA_LR;
      END
     ELSE
      BEGIN
        PIS_ENTRADA = :PIS_ENTRADA_LP;
        COFINS_ENTRADA = :COFINS_ENTRADA_LP;
      END

     IF (:PIS_ENTRADA IS NULL) THEN
        PIS_ENTRADA = '70';
     IF (:COFINS_ENTRADA IS NULL) THEN
        COFINS_ENTRADA = '70';

     COMANDO = '';
     COMANDO = 'SINTEGRA_NF_ENTRADA_ITENS.PIS_CST = '''||:PIS_ENTRADA||''', '||
               'SINTEGRA_NF_ENTRADA_ITENS.COFINS_CST = '''||:COFINS_ENTRADA||''', ';

     IF ((:PIS_ENTRADA = '50') OR (:PIS_ENTRADA = '51') OR (:PIS_ENTRADA = '52') OR (:PIS_ENTRADA = '53') OR (:PIS_ENTRADA = '54') OR (:PIS_ENTRADA = '55') OR (:PIS_ENTRADA = '56')) THEN
      BEGIN
        COMANDO = :COMANDO ||
                  'SINTEGRA_NF_ENTRADA_ITENS.PIS_BASE_CALCULO = SINTEGRA_NF_ENTRADA_ITENS.SUBTOTAL - SINTEGRA_NF_ENTRADA_ITENS.VALOR_DESCONTO, '||
                  'SINTEGRA_NF_ENTRADA_ITENS.PIS_PERCENTUAL = ' || :PISALIQUOTA || ', ' ||
                  'SINTEGRA_NF_ENTRADA_ITENS.PIS_VALOR = CAST(((SINTEGRA_NF_ENTRADA_ITENS.SUBTOTAL  - SINTEGRA_NF_ENTRADA_ITENS.VALOR_DESCONTO) * ' || :PIS_ENTRADA || ') / 100 AS NUMERIC(15,2)), ';
      END
     ELSE
      BEGIN
        COMANDO = :COMANDO ||
                  'SINTEGRA_NF_ENTRADA_ITENS.PIS_BASE_CALCULO = 0, '||
                  'SINTEGRA_NF_ENTRADA_ITENS.PIS_PERCENTUAL = 0, '||
                  'SINTEGRA_NF_ENTRADA_ITENS.PIS_VALOR = 0, ';
      END
     IF ((:COFINS_ENTRADA = '50') OR (:COFINS_ENTRADA = '51') OR (:COFINS_ENTRADA = '52') OR (:COFINS_ENTRADA = '53') OR (:COFINS_ENTRADA = '54') OR (:COFINS_ENTRADA = '55') OR (:COFINS_ENTRADA = '56')) THEN
      BEGIN
        COMANDO = :COMANDO ||
                  'SINTEGRA_NF_ENTRADA_ITENS.COFINS_BASE_CALCULO = SINTEGRA_NF_ENTRADA_ITENS.SUBTOTAL - SINTEGRA_NF_ENTRADA_ITENS.VALOR_DESCONTO, '||
                  'SINTEGRA_NF_ENTRADA_ITENS.COFINS_PERCENTUAL = ' || :COFINSALIQUOTA || ', ' ||
                  'SINTEGRA_NF_ENTRADA_ITENS.COFINS_VALOR = CAST(((SINTEGRA_NF_ENTRADA_ITENS.SUBTOTAL - SINTEGRA_NF_ENTRADA_ITENS.VALOR_DESCONTO) * ' || :COFINSALIQUOTA || ') / 100 AS NUMERIC(15,2)) ';
      END
     ELSE
      BEGIN
        COMANDO = :COMANDO ||
                  'SINTEGRA_NF_ENTRADA_ITENS.COFINS_BASE_CALCULO = 0, '||
                  'SINTEGRA_NF_ENTRADA_ITENS.COFINS_PERCENTUAL = 0, '||
                  'SINTEGRA_NF_ENTRADA_ITENS.COFINS_VALOR = 0 ';
      END

     COMANDO1 = 'UPDATE SINTEGRA_NF_ENTRADA_ITENS SET ' || :COMANDO ||
                'WHERE SINTEGRA_NF_ENTRADA_ITENS.DATAHORA >= '''||:DATAINICIAL||''' AND '||
                '      SINTEGRA_NF_ENTRADA_ITENS.DATAHORA <= '''||:DATAFINAL||''' AND '||
                '      SINTEGRA_NF_ENTRADA_ITENS.REF_PRODUTOS = '''||:BARRA||''' AND ' ||
                '      SINTEGRA_NF_ENTRADA_ITENS.COD_NF_ENTRADA IN ' ||
                '      (SELECT COD_NF_ENTRADA FROM SINTEGRA_NF_ENTRADA WHERE DATAHORA_EMISSAO >= '''||:DATAINICIAL||''' AND '||
                '       DATAHORA_EMISSAO <= '''||:DATAFINAL||''' AND EMITENTE_NF = '''||'T'||''')';

     EXECUTE STATEMENT :COMANDO1;
   END
  /* NOTAS DE ENTRADA */

  /* NOTAS DE SAIDA */
  FOR
    SELECT
     SINTEGRA_NF_ENTRADA_ITENS.REF_PRODUTOS,
     SPED_PIS_COFINS.PIS_SAIDA_LR,
     SPED_PIS_COFINS.COFINS_SAIDA_LR,
     SPED_PIS_COFINS.PIS_SAIDA_LP,
     SPED_PIS_COFINS.COFINS_SAIDA_LP,
     SPED_PIS_COFINS.PIS_SAIDA_SN,
     SPED_PIS_COFINS.COFINS_SAIDA_SN
    FROM
     SPED_PIS_COFINS, SINTEGRA_NF_ENTRADA_ITENS, SINTEGRA_NF_ENTRADA
    WHERE
     SINTEGRA_NF_ENTRADA.COD_NF_ENTRADA = SINTEGRA_NF_ENTRADA_ITENS.COD_NF_ENTRADA AND
     (SPED_PIS_COFINS.BARRA = SINTEGRA_NF_ENTRADA_ITENS.REF_PRODUTOS OR
      SPED_PIS_COFINS.BARRA2 = SINTEGRA_NF_ENTRADA_ITENS.REF_PRODUTOS) AND
     SINTEGRA_NF_ENTRADA_ITENS.DATAHORA >= :DATAINICIAL AND
     SINTEGRA_NF_ENTRADA_ITENS.DATAHORA <= :DATAFINAL AND
     SINTEGRA_NF_ENTRADA.EMITENTE_NF = 'P'
    GROUP BY
     SINTEGRA_NF_ENTRADA_ITENS.REF_PRODUTOS,
     SPED_PIS_COFINS.PIS_SAIDA_LR,
     SPED_PIS_COFINS.COFINS_SAIDA_LR,
     SPED_PIS_COFINS.PIS_SAIDA_LP,
     SPED_PIS_COFINS.COFINS_SAIDA_LP,
     SPED_PIS_COFINS.PIS_SAIDA_SN,
     SPED_PIS_COFINS.COFINS_SAIDA_SN
    INTO
     :BARRA,
     :PIS_SAIDA_LR,
     :COFINS_SAIDA_LR,
     :PIS_SAIDA_LP,
     :COFINS_SAIDA_LP,
     :PIS_SAIDA_SN,
     :COFINS_SAIDA_SN
  DO
   BEGIN
     IF (:ENQUADRAMENTOTRIBUTARIO = 'S') THEN
      BEGIN
        PIS_SAIDA = :PIS_SAIDA_SN;
        COFINS_SAIDA = :COFINS_SAIDA_SN;
      END
     ELSE
     IF (:ENQUADRAMENTOTRIBUTARIO = 'R') THEN
      BEGIN
        PIS_SAIDA = :PIS_SAIDA_LR;
        COFINS_SAIDA = :COFINS_SAIDA_LR;
      END
     ELSE
      BEGIN
        PIS_SAIDA = :PIS_SAIDA_LP;
        COFINS_SAIDA = :COFINS_SAIDA_LP;
      END

     IF (:PIS_SAIDA IS NULL) THEN
        PIS_SAIDA = '04';
     IF (:COFINS_SAIDA IS NULL) THEN
        COFINS_SAIDA = '04';

     COMANDO = '';
     COMANDO = 'SINTEGRA_NF_ENTRADA_ITENS.PIS_CST = '''||:PIS_SAIDA||''', '||
               'SINTEGRA_NF_ENTRADA_ITENS.COFINS_CST = '''||:COFINS_SAIDA||''', ';

     IF ((:PIS_SAIDA = '01') OR (:PIS_SAIDA = '02')) THEN
      BEGIN
        COMANDO = :COMANDO ||
                  'SINTEGRA_NF_ENTRADA_ITENS.PIS_BASE_CALCULO = SINTEGRA_NF_ENTRADA_ITENS.SUBTOTAL - SINTEGRA_NF_ENTRADA_ITENS.VALOR_DESCONTO, '||
                  'SINTEGRA_NF_ENTRADA_ITENS.PIS_PERCENTUAL = ' || :PISALIQUOTA || ', ' ||
                  'SINTEGRA_NF_ENTRADA_ITENS.PIS_VALOR = CAST(((SINTEGRA_NF_ENTRADA_ITENS.SUBTOTAL  - SINTEGRA_NF_ENTRADA_ITENS.VALOR_DESCONTO) * ' || :PISALIQUOTA || ') / 100 AS NUMERIC(15,2)), ';
      END
     ELSE
      BEGIN
        COMANDO = :COMANDO ||
                  'SINTEGRA_NF_ENTRADA_ITENS.PIS_BASE_CALCULO = 0, '||
                  'SINTEGRA_NF_ENTRADA_ITENS.PIS_PERCENTUAL = 0, '||
                  'SINTEGRA_NF_ENTRADA_ITENS.PIS_VALOR = 0, ';
      END
     IF ((:COFINS_SAIDA = '01') OR (:COFINS_SAIDA = '02')) THEN
      BEGIN
        COMANDO = :COMANDO ||
                  'SINTEGRA_NF_ENTRADA_ITENS.COFINS_BASE_CALCULO = SINTEGRA_NF_ENTRADA_ITENS.SUBTOTAL - SINTEGRA_NF_ENTRADA_ITENS.VALOR_DESCONTO, '||
                  'SINTEGRA_NF_ENTRADA_ITENS.COFINS_PERCENTUAL = ' || :COFINSALIQUOTA || ', ' ||
                  'SINTEGRA_NF_ENTRADA_ITENS.COFINS_VALOR = CAST(((SINTEGRA_NF_ENTRADA_ITENS.SUBTOTAL  - SINTEGRA_NF_ENTRADA_ITENS.VALOR_DESCONTO) * ' || :COFINSALIQUOTA || ') / 100 AS NUMERIC(15,2)) ';
      END
     ELSE
      BEGIN
        COMANDO = :COMANDO ||
                  'SINTEGRA_NF_ENTRADA_ITENS.COFINS_BASE_CALCULO = 0, '||
                  'SINTEGRA_NF_ENTRADA_ITENS.COFINS_PERCENTUAL = 0, '||
                  'SINTEGRA_NF_ENTRADA_ITENS.COFINS_VALOR = 0 ';
      END

     COMANDO1 = 'UPDATE SINTEGRA_NF_ENTRADA_ITENS SET ' || :COMANDO ||
                'WHERE SINTEGRA_NF_ENTRADA_ITENS.DATAHORA >= '''||:DATAINICIAL||''' AND '||
                '      SINTEGRA_NF_ENTRADA_ITENS.DATAHORA <= '''||:DATAFINAL||''' AND '||
                '      SINTEGRA_NF_ENTRADA_ITENS.REF_PRODUTOS = '''||:BARRA||''' AND ' ||
                '      SINTEGRA_NF_ENTRADA_ITENS.COD_NF_ENTRADA IN ' ||
                '      (SELECT COD_NF_ENTRADA FROM SINTEGRA_NF_ENTRADA WHERE DATAHORA_EMISSAO >= '''||:DATAINICIAL||''' AND '||
                '       DATAHORA_EMISSAO <= '''||:DATAFINAL||''' AND EMITENTE_NF = '''||'P'||''')';

     EXECUTE STATEMENT :COMANDO1;
   END
  /* NOTAS DE SAIDA */
END ^

ALTER PROCEDURE SP_SUPORTE_CORRIGEPRECOPROMOCAO AS 
