ALTER PROCEDURE SP_SUPORTE_CRIA_SINTEGRA61_NFCE (DATAINICIAL DATE,
DATAFINAL DATE)
AS 
declare variable ID double precision;
declare variable DATAHORA_EMISSAO varchar(10);
declare variable SERIE_NF varchar(10);
declare variable NUM_NF varchar(10);
declare variable VALOR_TOTALNF numeric(15,2);
declare variable BASE_ICMS numeric(15,2);
declare variable VALOR_ICMS numeric(15,2);
declare variable DESCONTO numeric(15,2);
BEGIN
  DELETE FROM SINTEGRA_61 WHERE SINTEGRA_61.DATA_EMISSAO >= :DATAINICIAL AND SINTEGRA_61.DATA_EMISSAO <= :DATAFINAL;
  FOR
    SELECT
      SINTEGRA_NF_ENTRADA.DATAHORA_EMISSAO,
      SINTEGRA_NF_ENTRADA.SERIE_NF,
      SINTEGRA_NF_ENTRADA.NUM_NF,
      SINTEGRA_NF_ENTRADA.VALOR_TOTALNF,
      SINTEGRA_NF_ENTRADA.BASE_ICMS, 
      SINTEGRA_NF_ENTRADA.VALOR_ICMS,
      SINTEGRA_NF_ENTRADA.DESCONTO
    FROM
      SINTEGRA_NF_ENTRADA
    WHERE
      SINTEGRA_NF_ENTRADA.DATAHORA_EMISSAO >= :DATAINICIAL AND
      SINTEGRA_NF_ENTRADA.DATAHORA_EMISSAO <= :DATAFINAL AND
      SINTEGRA_NF_ENTRADA.MODELO_NF = '65' AND
      SINTEGRA_NF_ENTRADA.SITUACAO_NF = 'N'
    INTO
      :DATAHORA_EMISSAO,
      :SERIE_NF,
      :NUM_NF,
      :VALOR_TOTALNF,
      :BASE_ICMS, 
      :VALOR_ICMS,
      :DESCONTO
  DO
   BEGIN
      ID = 0;
      SELECT ID FROM SP_RETORNAID('ID_SINTEGRA_61') INTO :ID;
      INSERT INTO SINTEGRA_61 VALUES (:ID, :DATAHORA_EMISSAO, '65', :SERIE_NF, '0', :NUM_NF,
                                      :VALOR_TOTALNF, :BASE_ICMS, :VALOR_ICMS, 0, 0, 0, :DESCONTO,
                                      '', '', '', '', '');
   END
END ^

ALTER PROCEDURE SP_SUPORTE_CSTCFOPALIQUOTA_R05 AS 
BEGIN
  UPDATE PAF_R05 SET
   CST = '000', CFOP = '5102'
  WHERE SUBSTRING(TOTALIZADOR_PARCIAL FROM 3 FOR 1) = 'T';

  UPDATE PAF_R05 SET
   CST = '040', CFOP = '5102', ALIQUOTA = '0000'
  WHERE TOTALIZADOR_PARCIAL = 'I1';

  UPDATE PAF_R05 SET
   CST = '041', CFOP = '5102', ALIQUOTA = '0000'
  WHERE TOTALIZADOR_PARCIAL = 'N1';

  UPDATE PAF_R05 SET
   CST = '060', CFOP = '5405', ALIQUOTA = '0000'
  WHERE TOTALIZADOR_PARCIAL = 'F1';
END ^

ALTER PROCEDURE SP_SUPORTE_DELETA_MOVIMENTO (DATA_FINAL DATE)
AS 
BEGIN
   DELETE FROM LANCAMENTOS
   WHERE DATA_LANCAMENTO <= :DATA_FINAL;

   DELETE FROM CAIXA
   WHERE DATA <= :DATA_FINAL;

   DELETE FROM CONTAS_PAGAR
   WHERE DT_NOTA <= :DATA_FINAL;

   DELETE FROM CONTAS_RECEBER
   WHERE DT_LANCAMENTO <= :DATA_FINAL;

   DELETE FROM ITENS_COMPRA
   WHERE CD_COMPRAS IN
   (
    SELECT CD_COMPRAS FROM COMPRAS
    WHERE DT_EMISSAO <= :DATA_FINAL
   );

   DELETE FROM COMPRAS
   WHERE DT_EMISSAO <= :DATA_FINAL;

   DELETE FROM REAJUSTE
   WHERE DATA <= :DATA_FINAL;

   DELETE FROM POSICAOESTOQUEDATA
   WHERE DATA <= :DATA_FINAL;

   DELETE FROM BALANCO
   WHERE DATA <= :DATA_FINAL;

   DELETE FROM VENDAS_FP
   WHERE CD_VENDA IN
   (
    SELECT CD_VENDA FROM VENDAS
    WHERE DATA_CAIXA <= :DATA_FINAL
   );

   DELETE FROM VENDAS
   WHERE DATA_CAIXA <= :DATA_FINAL;

END ^

ALTER PROCEDURE SP_SUPORTE_DELPRODUTOSBALANCO (ID_BALANCO DOUBLE PRECISION,
DATAVENDA DATE)
AS 
DECLARE VARIABLE ID_PRODUTO DOUBLE PRECISION;
DECLARE VARIABLE NUMEROVENDAS INTEGER;
BEGIN
  FOR
    SELECT
     ID_PRODUTO
    FROM
     BALANCO
    WHERE
     ID_BALANCO = :ID_BALANCO AND
     ESTOQUE = 0 AND
     STATUS = 'C'
    INTO
     :ID_PRODUTO
  DO
   BEGIN
     NUMEROVENDAS = 0;

     SELECT COUNT(*) FROM LANCAMENTOS
     WHERE DATA_LANCAMENTO >= :DATAVENDA AND ID_PRODUTO = :ID_PRODUTO AND TIPO_VENDA = 'V'
     INTO :NUMEROVENDAS;

     IF ((:NUMEROVENDAS IS NULL) OR (:NUMEROVENDAS = 0)) THEN
        DELETE FROM PRODUTOS WHERE ID_PRODUTO = :ID_PRODUTO;
   END
END ^

ALTER PROCEDURE SP_SUPORTE_DESCONTOAPLICADOSITE AS 
BEGIN
  UPDATE PRODUTOS_SITE SET
     DESCONTOAPLICADO = 100 - ((PRECO_VENDA_SITE / PRECO_VENDA_LOJA) * 100);
END ^

ALTER PROCEDURE SP_SUPORTE_DESCONTO_SPED (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (COD_NF_ENTRADA DOUBLE PRECISION,
DESCONTONOTA NUMERIC(15, 4),
DESCONTOITENS NUMERIC(15, 4),
DIFERENCA NUMERIC(15, 4))
AS 
BEGIN
  FOR
    SELECT SINTEGRA_NF_ENTRADA.COD_NF_ENTRADA, SINTEGRA_NF_ENTRADA.DESCONTO
    FROM SINTEGRA_NF_ENTRADA
    WHERE SINTEGRA_NF_ENTRADA.DATAHORA >= :DATAINICIAL AND
          SINTEGRA_NF_ENTRADA.DATAHORA <= :DATAFINAL
    INTO :COD_NF_ENTRADA, DESCONTONOTA
  DO
   BEGIN
     SELECT SUM(SINTEGRA_NF_ENTRADA_ITENS.VALOR_DESCONTO)
     FROM SINTEGRA_NF_ENTRADA_ITENS
     WHERE SINTEGRA_NF_ENTRADA_ITENS.COD_NF_ENTRADA = :COD_NF_ENTRADA
     INTO :DESCONTOITENS;

     DIFERENCA = :DESCONTONOTA - :DESCONTOITENS;
     IF (:DIFERENCA <> 0) THEN
      BEGIN
        --SUSPEND;
        UPDATE SINTEGRA_NF_ENTRADA_ITENS SET
         VALOR_DESCONTO = VALOR_DESCONTO * QUANTIDADE
        WHERE COD_NF_ENTRADA = :COD_NF_ENTRADA;
      END
   END
END ^

ALTER PROCEDURE SP_SUPORTE_EXCLUI_PRODUTOS_SM AS 
declare variable ID_PRODUTO double precision;
declare variable ESTOQUE double precision;
declare variable EXISTEMOVIMENTO integer;
BEGIN
  DELETE FROM TEMP_VENDAPRODUTO;
  INSERT INTO TEMP_VENDAPRODUTO SELECT DISTINCT ID_PRODUTO FROM LANCAMENTOS WHERE DATA_LANCAMENTO >= (CURRENT_DATE - 1825);

  FOR
   SELECT ID_PRODUTO FROM PRODUTOS WHERE ID_PRODUTO NOT IN (SELECT CD_VENDA FROM TEMP_VENDAPRODUTO) INTO :ID_PRODUTO
  DO
   BEGIN
     DELETE FROM PRODUTOS WHERE ID_PRODUTO = :ID_PRODUTO;
   END
END ^

ALTER PROCEDURE SP_SUPORTE_FEBRAFAR RETURNS (CODIGO_BARRAS VARCHAR(14) CHARACTER SET NONE,
DESCRICAO VARCHAR(60) CHARACTER SET NONE,
QUANTIDADE INTEGER,
PMC NUMERIC(15, 2),
VENDA_LIQUIDA NUMERIC(15, 2),
VENDA_BRUTA NUMERIC(15, 2))
AS 
declare variable ID_PRODUTO double precision;
declare variable MEDIA_VALOR_UNITARIO numeric(15,2);
BEGIN
 FOR
    SELECT
     LANCAMENTOS.ID_PRODUTO,
     LANCAMENTOS.CODIGO_BARRAS,
     LANCAMENTOS.DESCRICAO,
     SUM(LANCAMENTOS.QUANTIDADE),
     AVG(LANCAMENTOS.VALOR / LANCAMENTOS.QUANTIDADE)
    FROM
     LANCAMENTOS
    WHERE
     LANCAMENTOS.DATA_LANCAMENTO >= CURRENT_DATE - 90 AND
     LANCAMENTOS.TIPO_VENDA = 'V'
    GROUP BY
     LANCAMENTOS.ID_PRODUTO,
     LANCAMENTOS.CODIGO_BARRAS,
     LANCAMENTOS.DESCRICAO
    INTO
     :ID_PRODUTO,
     :CODIGO_BARRAS,
     :DESCRICAO,
     :QUANTIDADE,
     :MEDIA_VALOR_UNITARIO
 DO
  BEGIN
    VENDA_LIQUIDA = 0;
    VENDA_LIQUIDA = :QUANTIDADE * :MEDIA_VALOR_UNITARIO;


    SUSPEND;

  END
END ^

ALTER PROCEDURE SP_SUPORTE_H010 (DATA DATE)
RETURNS (LINHA VARCHAR(1000) CHARACTER SET NONE,
COD_ITEM NUMERIC(15, 0),
COD_BARRA VARCHAR(100) CHARACTER SET NONE,
UNID VARCHAR(100) CHARACTER SET NONE,
ESTOQUE NUMERIC(15, 2),
PRECO NUMERIC(15, 2),
TOTAL NUMERIC(15, 2))
AS 
declare variable CD_FILIAL integer;
declare variable COMANDO varchar(1000);
declare variable COMANDO1 varchar(1000);
declare variable SESTOQUE varchar(100);
declare variable SPRECO varchar(100);
declare variable STOTAL varchar(100);
declare variable SIR varchar(100);
declare variable SDATA varchar(100);
declare variable EXISTE integer;
declare variable TENTATIVAS integer;
BEGIN
  SELECT CD_FILIAL FROM PARAMETROS INTO :CD_FILIAL;
  SDATA = CAST(:DATA AS VARCHAR(100));
  SDATA = SUBSTRING(:SDATA FROM 9 FOR 2)||'.'||SUBSTRING(:SDATA FROM 6 FOR 2)||'.'||SUBSTRING(:SDATA FROM 1 FOR 4);
  COMANDO1 = 'SELECT COUNT(*) FROM POSICAOESTOQUEDATA WHERE CD_FILIAL = '||:CD_FILIAL||' AND DATA = '''||:SDATA||'''';

  TENTATIVAS = 1;
  EXECUTE STATEMENT :COMANDO1 INTO :EXISTE;
  WHILE ((:EXISTE = 0) AND (:TENTATIVAS < 4)) DO
   BEGIN
      SDATA = CAST(:DATA + :TENTATIVAS AS VARCHAR(100));
      SDATA = SUBSTRING(:SDATA FROM 9 FOR 2)||'.'||SUBSTRING(:SDATA FROM 6 FOR 2)||'.'||SUBSTRING(:SDATA FROM 1 FOR 4);
      COMANDO1 = 'SELECT COUNT(*) FROM POSICAOESTOQUEDATA WHERE CD_FILIAL = '||:CD_FILIAL||' AND DATA = '''||:SDATA||'''';
      EXECUTE STATEMENT :COMANDO1 INTO :EXISTE;
      TENTATIVAS = :TENTATIVAS + 1;
   END

  COMANDO1 = 'SELECT FIRST 1 QUANTIDADE, CUSTO, CAST(QUANTIDADE * CUSTO AS NUMERIC(15,2)) FROM POSICAOESTOQUEDATA WHERE CD_FILIAL = '||:CD_FILIAL||' AND DATA = '''||:SDATA||''' AND QUANTIDADE > 0';
  --COMANDO1 = 'SELECT FIRST 1 ESTOQUE_'||:CD_FILIAL||', PRECO_VENDA_'||:CD_FILIAL||', CAST(ESTOQUE_'||:CD_FILIAL||' * PRECO_VENDA_'||:CD_FILIAL||' AS NUMERIC(15,2)) FROM PRODUTOS';
  FOR
    SELECT
     TEMP_SUPORTE_0200.COD_ITEM,
     TEMP_SUPORTE_0200.COD_BARRA,
     TEMP_SUPORTE_0200.UNID_INV
    FROM
     TEMP_SUPORTE_0200
    INTO
     :COD_ITEM,
     :COD_BARRA,
     :UNID
  DO
   BEGIN
      ESTOQUE =0;
      PRECO = 0;
      TOTAL = 0;
      --COMANDO = COMANDO1||' WHERE CODIGO_BARRAS_1 = '''||:COD_BARRA||'''';
      COMANDO = COMANDO1||' AND ID_PRODUTO = '''||:COD_ITEM||'''';
      EXECUTE STATEMENT :COMANDO INTO :ESTOQUE, :PRECO, :TOTAL;
      IF (:ESTOQUE IS NULL) THEN
       BEGIN
         /*COMANDO = COMANDO1||' WHERE CODIGO_BARRAS_2 = '''||:COD_BARRA||'''';
         EXECUTE STATEMENT :COMANDO INTO :ESTOQUE, :PRECO, :TOTAL;
         IF (:ESTOQUE IS NULL) THEN
          BEGIN*/
            ESTOQUE = 0;
            PRECO = 0.01;
            TOTAL = 0;
          --END
       END
      IF (:ESTOQUE < 0) THEN
       BEGIN
         ESTOQUE = 0;
         TOTAL = 0;
       END
      SESTOQUE = CAST(:ESTOQUE AS VARCHAR(100));
      SESTOQUE = REPLACE(:SESTOQUE, '.', ',');

      SPRECO = CAST(:PRECO AS VARCHAR(100));
      SPRECO = REPLACE(:SPRECO, '.', ',');

      STOTAL = CAST(:TOTAL AS VARCHAR(100));
      STOTAL = REPLACE(:STOTAL, '.', ',');

      SIR = :STOTAL;

      LINHA = '|H010|'||:COD_ITEM||'|'||:UNID||'|'||:SESTOQUE||'|'||:SPRECO||'|'||:STOTAL||'|0|||584|'||:SIR||'|';

      SUSPEND;
   END
END ^

ALTER PROCEDURE SP_SUPORTE_LANCAMENTO_COMPRA (DATAINICIAL DATE)
AS 
declare variable CD_LANCAMENTO double precision;
declare variable CD_COMPRAS double precision;
declare variable CD_DISTRIBUIDOR double precision;
declare variable DT_ENTRADA date;
declare variable NOTAFISCAL varchar(100);
declare variable ID_PRODUTO double precision;
declare variable CD_FILIAL double precision;
declare variable CD_PRODUTO varchar(100);
declare variable DESCRICAO varchar(100);
declare variable VL_UNITARIO double precision;
declare variable QUANTIDADE double precision;
declare variable VL_TOTAL double precision;
declare variable VL_DESCONTO double precision;
declare variable CODIGO_BARRAS varchar(100);
declare variable CD_LABORATORIO double precision;
declare variable CD_GRUPO double precision;
declare variable CD_CLASSE double precision;
declare variable NCM varchar(100);
declare variable CST varchar(100);
declare variable ICMS varchar(100);
declare variable CD_SUBGRUPO double precision;
declare variable CFOP varchar(100);
declare variable TIPO_VENDA varchar(100);
declare variable CEST varchar(15);
BEGIN
  FOR
    SELECT
     CD_COMPRAS, CD_DISTRIBUIDOR, DT_ENTRADA, NOTA_FISCAL,
     CASE
      WHEN BONIFICACAO = 'S' THEN 'F'
      ELSE 'C'
     END
    FROM
     COMPRAS
    WHERE
     DT_ENTRADA >= :DATAINICIAL AND
     STATUS = 'C' AND
     CD_COMPRAS NOT IN
     (SELECT DISTINCT NUMERO FROM LANCAMENTOS WHERE (NUMERO IS NOT NULL) AND ((TIPO_VENDA = 'C') OR (TIPO_VENDA = 'F')))
    INTO
     :CD_COMPRAS,
     :CD_DISTRIBUIDOR,
     :DT_ENTRADA,
     :NOTAFISCAL,
     :TIPO_VENDA
  DO
   BEGIN
     FOR
       SELECT
        ID_PRODUTO, CD_FILIAL, CD_PRODUTO, DESCRICAO, VL_UNITARIO, QUANTIDADE, VL_TOTAL, VL_DESCONTO, CODIGO_BARRAS, CFOP, CEST
       FROM
        ITENS_COMPRA
       WHERE
        CD_COMPRAS = :CD_COMPRAS
       INTO
        :ID_PRODUTO, :CD_FILIAL, :CD_PRODUTO, :DESCRICAO, :VL_UNITARIO,
        :QUANTIDADE, :VL_TOTAL, :VL_DESCONTO, :CODIGO_BARRAS, CFOP, :CEST

     DO
      BEGIN
        SELECT CD_LABORATORIO, CD_GRUPO, CD_CLASSE, NCM, '0'||SITUACAOTRIBUTARIA, ICMS, CD_SUBGRUPO
        FROM PRODUTOS
        WHERE ID_PRODUTO = :ID_PRODUTO
        INTO :CD_LABORATORIO, :CD_GRUPO, :CD_CLASSE, :NCM, :CST, :ICMS, :CD_SUBGRUPO;

        UPDATE CONTROLE SET VALOR = VALOR + 1 WHERE CAMPO = 'CD_LANCAMENTO';
        SELECT VALOR FROM CONTROLE WHERE CAMPO = 'CD_LANCAMENTO' INTO :CD_LANCAMENTO;

        IF (:CD_SUBGRUPO IS NOT NULL) THEN
         BEGIN
            INSERT INTO LANCAMENTOS VALUES (:CD_LANCAMENTO, :ID_PRODUTO, NULL, :CD_FILIAL, :CD_PRODUTO, :DESCRICAO,
                                            :CD_LABORATORIO, :CD_GRUPO, :CD_CLASSE, 0, :CD_DISTRIBUIDOR, NULL,
                                            NULL, NULL, NULL, NULL, NULL, :VL_UNITARIO, :VL_UNITARIO, :DT_ENTRADA, :DT_ENTRADA, :QUANTIDADE, :VL_TOTAL,
                                            0, :NOTAFISCAL, 0, 0, :TIPO_VENDA, NULL, 'E', '', 'N', CURRENT_TIME, :QUANTIDADE, 'N', '', :CD_COMPRAS, NULL, NULL, '',
                                            0, 'N', '', '', '', '', 'N', :CD_FILIAL, :NCM, :CFOP, :CST, :ICMS, :CODIGO_BARRAS, NULL, :CD_SUBGRUPO, '', NULL, :CEST, 0, 0,
                                            'N', :ID_PRODUTO, 'N', 'N', 'N', 'N');
         END
        ELSE
         BEGIN
            INSERT INTO LANCAMENTOS VALUES (:CD_LANCAMENTO, :ID_PRODUTO, NULL, :CD_FILIAL, :CD_PRODUTO, :DESCRICAO,
                                            :CD_LABORATORIO, :CD_GRUPO, :CD_CLASSE, 0, :CD_DISTRIBUIDOR, NULL,
                                            NULL, NULL, NULL, NULL, NULL, :VL_UNITARIO, :VL_UNITARIO, :DT_ENTRADA, :DT_ENTRADA, :QUANTIDADE, :VL_TOTAL,
                                            0, :NOTAFISCAL, 0, 0, :TIPO_VENDA, '', 'E', '', 'N', CURRENT_TIME, :QUANTIDADE, 'N', '', :CD_COMPRAS, NULL, '', '',
                                            0, 'N', '', '', '', NULL, 'N', :CD_FILIAL, :NCM, :CFOP, :CST, :ICMS, :CODIGO_BARRAS, '', NULL, '', NULL, :CEST, 0, 0,
                                            'N', :ID_PRODUTO, 'N', 'N', 'N', 'N');
         END
      END
   END
END ^

ALTER PROCEDURE SP_SUPORTE_NFCE_TROCA_99OUTROS AS 
declare variable TPAG varchar(10000);
BEGIN
  TPAG = '<tPag>05</tPag>';

  UPDATE NFCE SET
   ARQUIVO = SUBSTRING(NFCE.ARQUIVO FROM 1 FOR POSITION('<tPag>99</tPag>', NFCE.ARQUIVO) - 1) ||
             :TPAG ||
             SUBSTRING(NFCE.ARQUIVO FROM POSITION('<tPag>99</tPag>', NFCE.ARQUIVO) + 15 FOR 100000)
             WHERE NFCE.TIPOEMISSAO = 'O' AND NFCE.STATUS = 'G'
             AND ((NFCE.PROTOCOLO IS NULL) OR (NFCE.PROTOCOLO = ''))
             AND (POSITION('<tPag>99</tPag>', NFCE.ARQUIVO) > 0);
END ^

ALTER PROCEDURE SP_SUPORTE_PESQUISAVENDAS (DATA_CAIXA DATE)
RETURNS (CD_VENDA DOUBLE PRECISION)
AS 
BEGIN
  FOR
    SELECT DISTINCT VENDAS.CD_VENDA FROM VENDAS
    WHERE VENDAS.CD_VENDA IS NOT NULL AND VENDAS.DATA_CAIXA >= :DATA_CAIXA AND VENDAS.TIPO_VENDA = 'V' AND VENDAS.CONCLUIDO = 'S' AND
    (VENDAS.STATUS = 'V' OR VENDAS.STATUS = 'R' OR VENDAS.STATUS = 'S') AND VENDAS.CD_VENDA NOT IN (SELECT CD_VENDA FROM LANCAMENTOS WHERE DATA_LANCAMENTO >= :DATA_CAIXA AND TIPO_VENDA = 'V')
    UNION
    SELECT DISTINCT VENDAS.CD_VENDA FROM VENDAS
    WHERE VENDAS.CD_VENDA IS NOT NULL AND VENDAS.DATA_CAIXA >= :DATA_CAIXA AND VENDAS.TIPO_VENDA = 'V' AND VENDAS.CONCLUIDO = 'S' AND
    (VENDAS.STATUS = 'V' OR VENDAS.STATUS = 'R' OR VENDAS.STATUS = 'S') AND VENDAS.CD_VENDA NOT IN (SELECT CD_VENDA FROM CAIXA WHERE DATA_CAIXA >= :DATA_CAIXA AND TIPO_VENDA = 'V')

    INTO :CD_VENDA
  DO
   BEGIN
     SUSPEND;
   END
END ^

ALTER PROCEDURE SP_SUPORTE_POSICAOESTOQUEDATA (CD_FILIAL DOUBLE PRECISION,
DATA DATE)
AS 
declare variable ID_PRODUTO double precision;
declare variable ESTOQUEPRODUTO double precision;
declare variable CUSTO double precision;
declare variable VENDA double precision;
declare variable ESTOQUE double precision;
declare variable COMANDO varchar(1000);
BEGIN
  COMANDO = 'SELECT ID_PRODUTO, ESTOQUE_'||CAST(:CD_FILIAL AS INTEGER)||', CUSTO_UNITARIO_'||CAST(:CD_FILIAL AS INTEGER)||', PRECO_VENDA '||
            'FROM PRODUTOS';
  FOR
   EXECUTE STATEMENT :COMANDO
   INTO :ID_PRODUTO, :ESTOQUEPRODUTO, :CUSTO, :VENDA
  DO
   BEGIN
     ESTOQUE = 0;
     SELECT FIRST 1 ESTOQUE_POSVENDA
     FROM LANCAMENTOS
     WHERE DATA_LANCAMENTO <= :DATA AND ID_PRODUTO = :ID_PRODUTO AND CD_FILIAL = :CD_FILIAL
     ORDER BY DATA_LANCAMENTO DESC, HORA DESC INTO :ESTOQUE;

     IF ((:ESTOQUE IS NULL) OR (:ESTOQUE < 0)) THEN
        ESTOQUE = 0;
     INSERT INTO POSICAOESTOQUEDATA VALUES (:DATA + 1, :CD_FILIAL, :ID_PRODUTO, :ESTOQUE, :CUSTO, :VENDA, '');
   END
END ^

ALTER PROCEDURE SP_SUPORTE_PREENCHE_LOTES_ST AS 
declare variable CD_FILIAL double precision;
declare variable CD_COMPRAS double precision;
declare variable CD_DISTRIBUIDOR double precision;
declare variable DT_ENTRADA date;
declare variable NOTA_FISCAL varchar(100);
declare variable SERIE_NOTA_FISCAL varchar(100);
declare variable ID_PRODUTO double precision;
declare variable MODALIDADEBCST integer;
declare variable MARGEM_VALOR_AGREGADO double precision;
declare variable REDUCAO_ICMS_ST double precision;
declare variable BASEICMSSUBSTITUICAO double precision;
declare variable PERCENTUAL_ICMS_ST double precision;
declare variable VALORICMSSUBTITUICAO double precision;
declare variable BASECALCULOFCPST double precision;
declare variable ALIQUOTAFCPST double precision;
declare variable VALORFCPST double precision;
declare variable LOTE varchar(100);
declare variable QUANTIDADE double precision;
declare variable QUANTIDADE_ENTRADA double precision;
BEGIN
  SELECT CD_FILIAL FROM PARAMETROS INTO :CD_FILIAL;
  FOR
    SELECT
     COMPRAS.CD_COMPRAS,
     COMPRAS.CD_DISTRIBUIDOR,
     COMPRAS.DT_ENTRADA,
     COMPRAS.NOTA_FISCAL, 
     COMPRAS.SERIE_NOTA_FISCAL
    FROM
     COMPRAS
    WHERE
     COMPRAS.DT_ENTRADA >= '01.01.2019' AND
     COMPRAS.CD_FILIAL = :CD_FILIAL
    INTO
     :CD_COMPRAS,
     :CD_DISTRIBUIDOR,
     :DT_ENTRADA,
     :NOTA_FISCAL,
     :SERIE_NOTA_FISCAL
  DO
   BEGIN
     FOR
       SELECT
        ITENS_COMPRA.ID_PRODUTO,
        ITENS_COMPRA.MODALIDADEBCST,
        ITENS_COMPRA.MARGEM_VALOR_AGREGADO,
        ITENS_COMPRA.REDUCAO_ICMS_ST,
        ITENS_COMPRA.BASEICMSSUBSTITUICAO,
        ITENS_COMPRA.PERCENTUAL_ICMS_ST,
        ITENS_COMPRA.VALORICMSSUBTITUICAO,
        ITENS_COMPRA.BASECALCULOFCPST,
        ITENS_COMPRA.ALIQUOTAFCPST,
        ITENS_COMPRA.VALORFCPST
       FROM
        ITENS_COMPRA
       WHERE
        ITENS_COMPRA.CD_COMPRAS = :CD_COMPRAS
       INTO
        :ID_PRODUTO,
        :MODALIDADEBCST,
        :MARGEM_VALOR_AGREGADO,
        :REDUCAO_ICMS_ST,
        :BASEICMSSUBSTITUICAO,
        :PERCENTUAL_ICMS_ST,
        :VALORICMSSUBTITUICAO,
        :BASECALCULOFCPST,
        :ALIQUOTAFCPST,
        :VALORFCPST
     DO
      BEGIN
        FOR
          SELECT
           ITENS_COMPRA_LOTE.LOTE,
           ITENS_COMPRA_LOTE.QUANTIDADE
          FROM
           ITENS_COMPRA_LOTE
          WHERE
           ITENS_COMPRA_LOTE.CD_COMPRAS = :CD_COMPRAS AND
           ITENS_COMPRA_LOTE.CD_FILIAL = :CD_FILIAL AND
           ITENS_COMPRA_LOTE.CD_DISTRIBUIDOR = CD_DISTRIBUIDOR AND
           ITENS_COMPRA_LOTE.NOTA_FISCAL = :NOTA_FISCAL AND
           ITENS_COMPRA_LOTE.ID_PRODUTO = :ID_PRODUTO
          INTO
           :LOTE,
           :QUANTIDADE
        DO
         BEGIN
           INSERT INTO PRODUTOS_LOTES_ST VALUES
           (:ID_PRODUTO, :CD_FILIAL, :DT_ENTRADA, :CD_DISTRIBUIDOR, :NOTA_FISCAL, :SERIE_NOTA_FISCAL,
            :LOTE, :QUANTIDADE, :QUANTIDADE, CAST(:MODALIDADEBCST AS VARCHAR(100)),
            :MARGEM_VALOR_AGREGADO, :PERCENTUAL_ICMS_ST, :BASEICMSSUBSTITUICAO, :PERCENTUAL_ICMS_ST,
            :VALORICMSSUBTITUICAO, :BASECALCULOFCPST, :ALIQUOTAFCPST, :VALORFCPST);
         END
      END
   END

END ^

ALTER PROCEDURE SP_SUPORTE_PRIMEIRA_REDUCAO_ECF (DATAMOVIMENTO VARCHAR(6) CHARACTER SET NONE)
RETURNS (NREDUCOES INTEGER)
AS 
