ALTER PROCEDURE SP_SUPORTE_PRINCIPIO_ATIVO AS 
declare variable PRINCIPIO varchar(1000);
declare variable CD_PRINCIPIO double precision;
declare variable EXISTE integer;
declare variable NOME varchar(1000);
declare variable COMPOSICAO varchar(1000);
declare variable ID double precision;
BEGIN
  ID = 0;
  SELECT COUNT(*) FROM CONTROLE WHERE CAMPO = 'CD_PRINCIPIO' INTO :EXISTE;
  IF (:EXISTE = 0) THEN
     INSERT INTO CONTROLE VALUES ('CD_PRINCIPIO', 0);
  ELSE
   BEGIN
     SELECT MAX(CD_PRINCIPIO) FROM PRINCIPIO_ATIVO INTO :ID;
     UPDATE CONTROLE SET VALOR = :ID WHERE CAMPO = 'CD_PRINCIPIO';
   END

  --DELETE FROM PRINCIPIO_ATIVO;

  FOR
    SELECT
      DISTINCT NOME, COMPOSICAO
     FROM
      ABCFARMA_NOVO
     INTO
      :NOME, :COMPOSICAO
  DO
   BEGIN
     IF (:COMPOSICAO IS NOT NULL) THEN
      BEGIN
         IF (:COMPOSICAO = 'GENERICO') THEN
          BEGIN
            PRINCIPIO = :NOME;
          END
         ELSE
          BEGIN
            PRINCIPIO = :COMPOSICAO;
          END

         SELECT COUNT(*) FROM PRINCIPIO_ATIVO WHERE DESCRICAO = :PRINCIPIO INTO :EXISTE;
         IF (:EXISTE = 0) THEN
          BEGIN
             SELECT ID FROM SP_RETORNAID('CD_PRINCIPIO') INTO :CD_PRINCIPIO;
             INSERT INTO PRINCIPIO_ATIVO VALUES (:CD_PRINCIPIO, :PRINCIPIO);
          END
      END
   END

  FOR
   SELECT
    CD_PRINCIPIO,
    DESCRICAO
   FROM
    PRINCIPIO_ATIVO
   INTO
    :CD_PRINCIPIO,
    :PRINCIPIO
  DO
   BEGIN
      UPDATE PRODUTOS SET
       CD_PRINCIPIO = :CD_PRINCIPIO
      WHERE
       PRINCIPIOATIVO = :PRINCIPIO;
   END
END ^

ALTER PROCEDURE SP_SUPORTE_PRODUTOSFORAABCFARMA RETURNS (ID_PRODUTO DOUBLE PRECISION,
CD_PRODUTO VARCHAR(6) CHARACTER SET NONE,
DESCRICAO VARCHAR(60) CHARACTER SET NONE,
LABORATORIO VARCHAR(60) CHARACTER SET NONE,
GRUPO VARCHAR(60) CHARACTER SET NONE,
CODIGOBARRA VARCHAR(14) CHARACTER SET NONE,
PRECO_VENDA DOUBLE PRECISION)
AS 
declare variable EXISTE integer;
BEGIN
  FOR
    SELECT
     PRODUTOS.ID_PRODUTO,
     PRODUTOS.CD_PRODUTO,
     PRODUTOS.DESCRICAO,
     LABORATORIOS.NOME AS LABORATORIO,
     GRUPOS.DESCRICAO AS GRUPO,
     PRODUTOS.CODIGO_BARRAS_1 AS CODIGOBARRA,
     PRODUTOS.PRECO_VENDA
    FROM
     PRODUTOS, GRUPOS, LABORATORIOS
    WHERE
     PRODUTOS.CD_GRUPO = GRUPOS.CD_GRUPO AND
     PRODUTOS.CD_LABORATORIO = LABORATORIOS.CD_LABORATORIO AND
     PRODUTOS.CODIGO_BARRAS_1 IS NOT NULL AND
     PRODUTOS.CODIGO_BARRAS_1 <> ''
    INTO
     :ID_PRODUTO,
     :CD_PRODUTO,
     :DESCRICAO,
     :LABORATORIO,
     :GRUPO,
     :CODIGOBARRA,
     :PRECO_VENDA
  DO
   BEGIN
     EXISTE = 0;
     SELECT COUNT(*) FROM ABCFARMA_NOVO WHERE EAN = :CODIGOBARRA INTO :EXISTE;
     IF (:EXISTE = 0) THEN
        SUSPEND;
   END
END ^

ALTER PROCEDURE SP_SUPORTE_R04 (NUMERO_FABRICACAO VARCHAR(100) CHARACTER SET NONE)
RETURNS (LINHA VARCHAR(100) CHARACTER SET NONE,
COO VARCHAR(10) CHARACTER SET NONE)
AS 
declare variable DT varchar(20);
declare variable VL varchar(20);
declare variable CANC varchar(1);
declare variable SIT varchar(2);
declare variable VLFLOAT numeric(15,2);
BEGIN
  FOR
   SELECT
    PAF_R04.DATA_INICIO_EMISSAO,
    PAF_R04.COO,
    PAF_R04.VALOR_TOTAL,
    PAF_R04.CANCELAMENTO
   FROM
    PAF_R04
   WHERE
    PAF_R04.NUMERO_FABRICACAO = :NUMERO_FABRICACAO AND
    PAF_R04.VALOR_TOTAL > 0 AND
    PAF_R04.COO IN (SELECT TEMP_COO.COO FROM TEMP_COO)
   INTO
    :DT,
    :COO,
    :VL,
    :CANC
  DO
   BEGIN
     IF (:CANC = 'S') THEN
      BEGIN
        VL = '';
        DT = '';
        SIT = '02';
      END
     ELSE
      BEGIN
        DT = SUBSTRING(DT FROM 1 FOR 4)||'20'||SUBSTRING(DT FROM 5 FOR 2);
        SIT = '00';
      END
     IF ((:VL IS NOT NULL) AND (:VL <> '')) THEN
      BEGIN
        VLFLOAT = CAST(:VL AS NUMERIC(15,2)) / 100;
        VL = CAST(VLFLOAT AS VARCHAR(20));
        VL = REPLACE(VL, '.', ',');
      END

     LINHA = '|C460|2D|'||:SIT||'|'||:COO||'|'||:DT||'|'||:VL||'|||||';

     SUSPEND;
   END
END ^

ALTER PROCEDURE SP_SUPORTE_R05 (NUMERO_FABRICACAO VARCHAR(100) CHARACTER SET NONE,
DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (LINHA VARCHAR(1000) CHARACTER SET NONE,
COO VARCHAR(10) CHARACTER SET NONE,
BASECALCULO VARCHAR(100) CHARACTER SET NONE,
DESCONTO NUMERIC(15, 2),
BASECALCULOFLOAT NUMERIC(15, 2),
VLFLOAT NUMERIC(15, 2))
AS 
declare variable ID_PAF integer;
declare variable COD_ITEM varchar(20);
declare variable DESCRICAO varchar(100);
declare variable COD varchar(20);
declare variable QUANT varchar(20);
declare variable QUANTFLOAT numeric(15,2);
declare variable QUANT_CANC varchar(20);
declare variable QUANTFLOAT_CANC numeric(15,2);
declare variable UNIDADE varchar(20);
declare variable VL varchar(20);
declare variable CST varchar(20);
declare variable CFOP varchar(20);
declare variable ALIQ varchar(20);
declare variable ALIQFLOAT numeric(15,2);
declare variable PERCENTUAL_DESCONTO numeric(15,3);
BEGIN
  DELETE FROM PAF_R05NEXISTE;
  FOR
   SELECT
    PAF_R05.ID_PAF_R05,
    PAF_R05.CODIGO_PRODUTO_SERVICO,
    PAF_R05.DESCRICAO,
    PAF_R05.QUANTIDADE,
    PAF_R05.QUANTIDADE_CANCELADA,
    PAF_R05.UNIDADE,
    --CAST(PAF_R05.VALOR_UNITARIO AS NUMERIC(15,2)) * (CAST(PAF_R05.QUANTIDADE AS NUMERIC(15,2)) / 1000),
    CAST(PAF_R05.VALOR_TOTAL_LIQUIDO AS NUMERIC(15,2)),
    PAF_R05.CST,
    PAF_R05.CFOP, 
    PAF_R05.ALIQUOTA,
    PAF_R05.COO
   FROM
    PAF_R05
   WHERE
    PAF_R05.NUMERO_FABRICACAO = :NUMERO_FABRICACAO AND
    PAF_R05.INDICADOR_CANCELAMENTO = 'N' AND
    PAF_R05.COO IN (SELECT TEMP_COO.COO FROM TEMP_COO)
   INTO
    :ID_PAF,
    :COD,
    :DESCRICAO,
    :QUANT,
    :QUANT_CANC,
    :UNIDADE,
    :VL,
    :CST,
    :CFOP,
    :ALIQ,
    :COO
  DO
   BEGIN
     QUANTFLOAT = CAST(:QUANT AS NUMERIC(15,2)) / 1000;
     QUANT = CAST(:QUANTFLOAT AS VARCHAR(20));
     QUANT = REPLACE(:QUANT, '.', ',');

     QUANTFLOAT_CANC = CAST(:QUANT_CANC AS NUMERIC(15,2)) / 1000;
     QUANT_CANC = CAST(:QUANTFLOAT_CANC AS VARCHAR(20));
     QUANT_CANC = REPLACE(:QUANT_CANC, '.', ',');

     ALIQFLOAT = CAST(:ALIQ AS NUMERIC(15,2)) / 100;
     ALIQ = CAST(:ALIQFLOAT AS VARCHAR(20));
     ALIQ = REPLACE(:ALIQ, '.', ',');

     VLFLOAT = CAST(:VL AS NUMERIC(15,2)) / 100;
     IF (:VLFLOAT = 0) THEN
        VLFLOAT = 0.01;
     VL = CAST(VLFLOAT AS VARCHAR(20));
     VL = REPLACE(VL, '.', ',');

     COD = TRIM(:COD);
     DESCRICAO = TRIM(:DESCRICAO);
     UNIDADE = TRIM(:UNIDADE);
     COD_ITEM = '';

     DESCONTO = 0;

     SELECT FIRST 1 COD_ITEM FROM TEMP_SUPORTE_0200 WHERE COD_BARRA_NUMERO = CAST(:COD AS NUMERIC(15,0)) INTO :COD_ITEM;

     BASECALCULOFLOAT = :VLFLOAT;
     PERCENTUAL_DESCONTO = 0;
     SELECT PERCENTUAL_DESCONTO FROM SP_PAF_DESCONTO_R04(:NUMERO_FABRICACAO, :COO) INTO :PERCENTUAL_DESCONTO;
     IF ((:PERCENTUAL_DESCONTO IS NOT NULL) AND (:PERCENTUAL_DESCONTO > 0)) THEN
      BEGIN
        DESCONTO = (:VLFLOAT * PERCENTUAL_DESCONTO) / 100;
        BASECALCULOFLOAT = CAST(:VLFLOAT - ((:VLFLOAT * PERCENTUAL_DESCONTO) / 100) AS NUMERIC(15,2));
        IF (:BASECALCULOFLOAT = 0) THEN
           BASECALCULOFLOAT = 0.01;
      END

     BASECALCULO = CAST(:BASECALCULOFLOAT AS VARCHAR(100));
     VL = :BASECALCULO;
     VL = REPLACE(:VL, '.', ',');
     IF ((:COD_ITEM IS NULL) OR (:COD_ITEM = '')) THEN
      BEGIN
        INSERT INTO PAF_R05NEXISTE SELECT * FROM LANCAMENTOS WHERE DATA_LANCAMENTO >= :DATAINICIAL AND DATA_LANCAMENTO <= :DATAFINAL AND DESCRICAO = :DESCRICAO;
        LINHA = :COD;
      END
     ELSE
      BEGIN
        LINHA = '|C470|'||:COD_ITEM||'|'||:QUANT||'|'||:QUANT_CANC||'|'||:UNIDADE||'|'||:VL||'|'||:CST||'|'||:CFOP||'|'||:ALIQ||'|||';
      END

     SUSPEND;
   END
END ^

ALTER PROCEDURE SP_SUPORTE_RECUPERA_ENTREGAS AS 
declare variable CD_VENDA double precision;
declare variable CD_FILIAL double precision;
declare variable CD_CLIENTE double precision;
declare variable DATA_CAIXA date;
declare variable TOTAL numeric(15,2);
declare variable NOME varchar(100);
declare variable ENDERECO varchar(100);
declare variable BAIRRO varchar(100);
declare variable REFERENCIA varchar(100);
BEGIN
  FOR
   SELECT
     DISTINCT CD_VENDA
   FROM VENDAS
   WHERE
     CALLCENTER = 'S' AND ENTREGA = 'S' AND TIPO_VENDA = 'V' AND CONCLUIDO = 'S' AND
     CD_VENDA NOT IN (SELECT CD_VENDA FROM ENTREGAS)
   INTO
    :CD_VENDA
  DO
   BEGIN
     NOME = '';
     ENDERECO = '';
     BAIRRO = '';
     REFERENCIA = '';

     SELECT CD_FILIAL, CD_CLIENTE, DATA_CAIXA, SUM(VENDAS.PRECO_TOTAL)
     FROM VENDAS
     WHERE CD_VENDA = :CD_VENDA AND CD_CLIENTE > 0
     GROUP BY CD_FILIAL, CD_VENDA, CD_CLIENTE, DATA_CAIXA
     INTO :CD_FILIAL, :CD_CLIENTE, :DATA_CAIXA, :TOTAL;

     IF (:CD_CLIENTE > 0) THEN
      BEGIN
        SELECT NOME, ENDERECO, BAIRRO, REFERENCIA
        FROM CLIENTES
        WHERE CD_CLIENTE = :CD_CLIENTE
        INTO :NOME, :ENDERECO, :BAIRRO, :REFERENCIA;
  
        INSERT INTO ENTREGAS VALUES (:CD_FILIAL, :CD_VENDA, NULL, :CD_CLIENTE, :NOME, :ENDERECO, :BAIRRO, :REFERENCIA,
                                     :DATA_CAIXA, NULL, NULL, 0, :TOTAL, '', 'S', NULL, NULL, NULL);
     END
   END
END ^

ALTER PROCEDURE SP_SUPORTE_REMOVEINVALIDOS AS 
declare variable ID double precision;
declare variable DESCRICAO varchar(100);
BEGIN
  FOR
    SELECT
     ID_PRODUTO, DESCRICAO
    FROM
     PRODUTOS
    WHERE
     DESCRICAO LIKE '%|%'
    INTO
     :ID, :DESCRICAO
  DO
   BEGIN
     DESCRICAO = REPLACE(:DESCRICAO, '|', '');
     UPDATE PRODUTOS SET
      DESCRICAO = :DESCRICAO
     WHERE
      ID_PRODUTO = :ID;
   END

  FOR
    SELECT
     ID_PRODUTO, DESCRICAO
    FROM
     PRODUTOS
    WHERE
     DESCRICAO LIKE '%<%'
    INTO
     :ID, :DESCRICAO
  DO
   BEGIN
     DESCRICAO = REPLACE(:DESCRICAO, '<', '');
     UPDATE PRODUTOS SET
      DESCRICAO = :DESCRICAO
     WHERE
      ID_PRODUTO = :ID;
   END

  FOR
    SELECT
     ID_PRODUTO, DESCRICAO
    FROM
     PRODUTOS
    WHERE
     DESCRICAO LIKE '%>%'
    INTO
     :ID, :DESCRICAO
  DO
   BEGIN
     DESCRICAO = REPLACE(:DESCRICAO, '>', '');
     UPDATE PRODUTOS SET
      DESCRICAO = :DESCRICAO
     WHERE
      ID_PRODUTO = :ID;
   END

  FOR
    SELECT
     ID_PRODUTO, DESCRICAO
    FROM
     PRODUTOS
    WHERE
     DESCRICAO LIKE '%"%'
    INTO
     :ID, :DESCRICAO
  DO
   BEGIN
     DESCRICAO = REPLACE(:DESCRICAO, '"', '');
     UPDATE PRODUTOS SET
      DESCRICAO = :DESCRICAO
     WHERE
      ID_PRODUTO = :ID;
   END

  FOR
    SELECT
     ID_PRODUTO, DESCRICAO
    FROM
     PRODUTOS
    WHERE
     DESCRICAO LIKE '%''%'
    INTO
     :ID, :DESCRICAO
  DO
   BEGIN
     DESCRICAO = REPLACE(:DESCRICAO, '''', '');
     UPDATE PRODUTOS SET
      DESCRICAO = :DESCRICAO
     WHERE
      ID_PRODUTO = :ID;
   END

  FOR
    SELECT
     ID_PRODUTO, DESCRICAO
    FROM
     PRODUTOS
    WHERE
     DESCRICAO LIKE '%&%'
    INTO
     :ID, :DESCRICAO
  DO
   BEGIN
     DESCRICAO = REPLACE(:DESCRICAO, '&', 'e');
     UPDATE PRODUTOS SET
      DESCRICAO = :DESCRICAO
     WHERE
      ID_PRODUTO = :ID;
   END

  FOR
    SELECT
     REF_PRODUTOS, PRODUTO
    FROM
     SINTEGRA_NF_ENTRADA_ITENS
    WHERE
     PRODUTO LIKE '%|%'
    INTO
     :ID, :DESCRICAO
  DO
   BEGIN
     DESCRICAO = REPLACE(:DESCRICAO, '|', '');
     UPDATE SINTEGRA_NF_ENTRADA_ITENS SET
      PRODUTO = :DESCRICAO
     WHERE
      REF_PRODUTOS = :ID;
   END

  FOR
    SELECT
     CODIGO_PRODUTO_SERVICO, DESCRICAO
    FROM
     PAF_R05
    WHERE
     DESCRICAO LIKE '%|%'
    INTO
     :ID, :DESCRICAO
  DO
   BEGIN
     DESCRICAO = REPLACE(:DESCRICAO, '|', '');
     UPDATE PAF_R05 SET
      DESCRICAO = :DESCRICAO
     WHERE
      CODIGO_PRODUTO_SERVICO = :ID;
   END

END ^

ALTER PROCEDURE SP_SUPORTE_RESTAURAPEDIDOSITENS (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (CD_FILIAL DOUBLE PRECISION,
COD_PEDIDOS_ITENS DOUBLE PRECISION,
NRO_SERIE_EQP VARCHAR(40) CHARACTER SET NONE,
REF_PRODUTOS VARCHAR(40) CHARACTER SET NONE,
BASECALCULO DOUBLE PRECISION,
ALIQUOTA VARCHAR(40) CHARACTER SET NONE,
UNIDADE VARCHAR(40) CHARACTER SET NONE,
DESCRICAO VARCHAR(100) CHARACTER SET NONE,
EXISTE INTEGER)
AS 
BEGIN
  SELECT CD_FILIAL FROM PARAMETROS INTO :CD_FILIAL;
  SELECT VALOR FROM CONTROLE WHERE CAMPO = 'COD_PEDIDOS_ITENS' INTO :COD_PEDIDOS_ITENS;
  FOR
    SELECT DISTINCT NRO_SERIE_EQP
    FROM SINTEGRA_R60
    WHERE DATAHORA >= :DATAINICIAL AND DATAHORA <= :DATAFINAL
    INTO :NRO_SERIE_EQP
  DO
   BEGIN
     FOR
       SELECT DISTINCT REF_PRODUTOS, BASECALCULO_ICMS, ALIQUOTA_ICMS
       FROM SINTEGRA_R60I
       WHERE  NRO_SERIE_EQP = :NRO_SERIE_EQP AND DATAHORA >= :DATAINICIAL AND DATAHORA <= :DATAFINAL
       INTO :REF_PRODUTOS, :BASECALCULO, :ALIQUOTA
     DO
      BEGIN
        SELECT COUNT(*) FROM SINTEGRA_PEDIDOS_ITENS
        WHERE DATAHORA >= :DATAINICIAL AND DATAHORA <= :DATAFINAL AND
              NRO_SERIE_EQP = :NRO_SERIE_EQP AND REF_PRODUTOS = :REF_PRODUTOS
        INTO :EXISTE;
        IF (:EXISTE = 0) THEN
         BEGIN
            IF ((:ALIQUOTA = 'F') OR (:ALIQUOTA = 'N') OR (:ALIQUOTA = 'I')) THEN
               ALIQUOTA = '0';
            SELECT FIRST 1 UNIDADE, DESCRICAO FROM PRODUTOS WHERE CODIGO_BARRAS_1 = :REF_PRODUTOS OR CODIGO_BARRAS_2 = :REF_PRODUTOS INTO :UNIDADE, :DESCRICAO;
    
            COD_PEDIDOS_ITENS = :COD_PEDIDOS_ITENS + 1;
            INSERT INTO SINTEGRA_PEDIDOS_ITENS VALUES (:COD_PEDIDOS_ITENS, :CD_FILIAL, :NRO_SERIE_EQP,  :REF_PRODUTOS, NULL, :DESCRICAO, :UNIDADE, NULL, 0, :ALIQUOTA,  0, :BASECALCULO, :DATAINICIAL, '');
         END
      END
   END
  UPDATE CONTROLE SET VALOR = :COD_PEDIDOS_ITENS WHERE CAMPO = 'COD_PEDIDOS_ITENS';

END ^

ALTER PROCEDURE SP_SUPORTE_SPEDC_0200 (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (REF_PRODUTOS VARCHAR(100) CHARACTER SET NONE,
DESCR_ITEM VARCHAR(100) CHARACTER SET NONE,
APR_UNID VARCHAR(100) CHARACTER SET NONE,
ALIQ_ICMS VARCHAR(100) CHARACTER SET NONE,
NCM VARCHAR(100) CHARACTER SET NONE,
COD_ITEM VARCHAR(100) CHARACTER SET NONE)
AS 
declare variable EXISTE integer;
declare variable COMANDO varchar(1000);
declare variable ID numeric(15,0);
BEGIN
 ID = 1000000;
 DELETE FROM TEMP_SUPORTE_SPEDC_0200;
 FOR
   SELECT
    SINTEGRA_NF_ENTRADA_ITENS.REF_PRODUTOS,
    TRIM(SINTEGRA_NF_ENTRADA_ITENS.PRODUTO),
    SINTEGRA_NF_ENTRADA_ITENS.APR_UND,
    SINTEGRA_NF_ENTRADA_ITENS.ALIQUOTA_ICMS
   FROM
    SINTEGRA_NF_ENTRADA_ITENS,
    SINTEGRA_NF_ENTRADA
   WHERE
    SINTEGRA_NF_ENTRADA_ITENS.COD_NF_ENTRADA = SINTEGRA_NF_ENTRADA.COD_NF_ENTRADA AND
    SINTEGRA_NF_ENTRADA.DATAHORA_RECEBIMENTO >= :DATAINICIAL AND
    SINTEGRA_NF_ENTRADA.DATAHORA_RECEBIMENTO <= :DATAFINAL AND
    ((SINTEGRA_NF_ENTRADA.MODELO_NF = '55') OR
     (SINTEGRA_NF_ENTRADA.MODELO_NF = '1') OR
     (SINTEGRA_NF_ENTRADA.MODELO_NF = '01') OR
     (SINTEGRA_NF_ENTRADA.MODELO_NF = '1B') OR
     (SINTEGRA_NF_ENTRADA.MODELO_NF = '4') OR
     (SINTEGRA_NF_ENTRADA.MODELO_NF = '04'))
  GROUP BY
    SINTEGRA_NF_ENTRADA_ITENS.REF_PRODUTOS,
    SINTEGRA_NF_ENTRADA_ITENS.PRODUTO,
    SINTEGRA_NF_ENTRADA_ITENS.APR_UND,
    SINTEGRA_NF_ENTRADA_ITENS.ALIQUOTA_ICMS
   INTO
    :REF_PRODUTOS,
    :DESCR_ITEM,
    :APR_UNID,
    :ALIQ_ICMS
 DO
  BEGIN
    --NCM = '';
    SELECT FIRST 1 NCM  FROM PRODUTOS_FISCO WHERE CAST(CODIGO_BARRAS AS NUMERIC(15,0)) = CAST(:REF_PRODUTOS AS NUMERIC(15,0)) INTO :NCM;

    SELECT COUNT(*) FROM TEMP_SUPORTE_SPEDC_0200 WHERE COD_BARRA_NUMERO = CAST(:REF_PRODUTOS AS NUMERIC(15,0)) INTO :EXISTE;
    IF (:EXISTE = 0) THEN
     BEGIN
       SELECT FIRST 1 CAST(CAST(ID_PRODUTO AS INTEGER) AS VARCHAR(100)) FROM PRODUTOS WHERE PRODUTOS.CODIGO_BARRAS_1 = :REF_PRODUTOS OR CODIGO_BARRAS_2 = :REF_PRODUTOS INTO :COD_ITEM;
       IF (:COD_ITEM IS NULL) THEN
        BEGIN
          COD_ITEM = :ID;
          ID = :ID + 1;
        END
       SELECT COUNT(*) FROM TEMP_SUPORTE_SPEDC_0200 WHERE COD_ITEM = :COD_ITEM INTO :EXISTE;
       IF (:EXISTE > 0) THEN
        BEGIN
          COD_ITEM = :ID;
          ID = :ID + 1;
        END

       INSERT INTO TEMP_SUPORTE_SPEDC_0200 VALUES (:COD_ITEM, :DESCR_ITEM, :REF_PRODUTOS, :COD_ITEM, :APR_UNID, '00', :NCM, '', '', '', :ALIQ_ICMS, CAST(:REF_PRODUTOS AS NUMERIC(15,0)), :NCM);
       SUSPEND;
     END
  END

  EXECUTE PROCEDURE SP_SUPORTE_SPEDC_TEMPCOO(:DATAINICIAL, :DATAFINAL);
  FOR
     SELECT
      PAF_R05.CODIGO_PRODUTO_SERVICO,
      TRIM(PAF_R05.DESCRICAO),
      PAF_R05.UNIDADE,
      CAST(CAST(PAF_R05.ALIQUOTA AS NUMERIC(15,0)) / 100 AS VARCHAR(100))
     FROM
      PAF_R05
     WHERE
      PAF_R05.INDICADOR_CANCELAMENTO = 'N' AND
      PAF_R05.NUMERO_FABRICACAO||PAF_R05.COO IN (SELECT COO FROM TEMP_COO_C)
     GROUP BY
      PAF_R05.CODIGO_PRODUTO_SERVICO,
      PAF_R05.DESCRICAO,
      PAF_R05.UNIDADE,
      PAF_R05.ALIQUOTA
     INTO
      :REF_PRODUTOS,
      :DESCR_ITEM,
      :APR_UNID,
      :ALIQ_ICMS
  DO
   BEGIN
    --NCM = '';
    SELECT FIRST 1 NCM  FROM PRODUTOS_FISCO WHERE CAST(CODIGO_BARRAS AS NUMERIC(15,0)) = CAST(:REF_PRODUTOS AS NUMERIC(15,0)) INTO :NCM;

    COD_ITEM = NULL;
    SELECT COUNT(*) FROM TEMP_SUPORTE_SPEDC_0200 WHERE COD_BARRA_NUMERO = CAST(:REF_PRODUTOS AS NUMERIC(15,0)) INTO :EXISTE;
    IF (:EXISTE = 0) THEN
     BEGIN
       SELECT FIRST 1 CAST(CAST(ID_PRODUTO AS INTEGER)AS VARCHAR(100)) FROM PRODUTOS WHERE PRODUTOS.CODIGO_BARRAS_1 = :REF_PRODUTOS OR CODIGO_BARRAS_2 = :REF_PRODUTOS INTO :COD_ITEM;
       IF (:COD_ITEM IS NULL) THEN
        BEGIN
          COD_ITEM = :ID;
          ID = :ID + 1;
        END
       SELECT COUNT(*) FROM TEMP_SUPORTE_SPEDC_0200 WHERE COD_ITEM = :COD_ITEM INTO :EXISTE;
       IF (:EXISTE > 0) THEN
        BEGIN
          COD_ITEM = :ID;
          ID = :ID + 1;
        END

       INSERT INTO TEMP_SUPORTE_SPEDC_0200 VALUES (:COD_ITEM, :DESCR_ITEM, :REF_PRODUTOS, :COD_ITEM, :APR_UNID, '00', :NCM, '', '', '', :ALIQ_ICMS, CAST(:REF_PRODUTOS AS NUMERIC(15,0)), :NCM);
       SUSPEND;
     END
   END
END ^

ALTER PROCEDURE SP_SUPORTE_SPEDC_C100 (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (COD_NF_ENTRADA DOUBLE PRECISION,
ENTRADA_SAIDA VARCHAR(1) CHARACTER SET NONE,
EMITENTE_NF VARCHAR(1) CHARACTER SET NONE,
CNPJ_FORNECEDOR VARCHAR(14) CHARACTER SET NONE,
MODELO_NF VARCHAR(100) CHARACTER SET NONE,
SITUACAO VARCHAR(2) CHARACTER SET NONE,
SERIE_NF VARCHAR(100) CHARACTER SET NONE,
NUM_NF VARCHAR(100) CHARACTER SET NONE,
CHAVENFE VARCHAR(100) CHARACTER SET NONE,
DATAHORA_EMISSAO DATE,
DATAHORA_SAIDAENTRADA DATE,
VALOR_TOTALNF NUMERIC(15, 2),
INDICADORPAGAMENTO VARCHAR(1) CHARACTER SET NONE,
VALOR_DESCONTO NUMERIC(15, 2),
VALOR_ABAT_NF NUMERIC(15, 2),
VALOR_MERCADORIA NUMERIC(15, 2),
INDICADOR_FRETE VARCHAR(1) CHARACTER SET NONE,
VALOR_FRETE NUMERIC(15, 2),
VALOR_SEGURO NUMERIC(15, 2),
VALOR_OUTROS NUMERIC(15, 2),
BASE_CALCULO_ICMS NUMERIC(15, 2),
VALOR_ICMS NUMERIC(15, 2),
BASE_CALCULO_ICMS_SUBSTITUICAO NUMERIC(15, 2),
VALOR_ICMS_SUBSTITUICAO NUMERIC(15, 2),
VALOR_IPI NUMERIC(15, 2),
VALOR_PIS NUMERIC(15, 2),
VALOR_COFINS NUMERIC(15, 2))
AS 
BEGIN
--  EXECUTE PROCEDURE SP_SUPORTE_CALCULA_PISCOFINS(:DATAINICIAL, :DATAFINAL);
  FOR
     SELECT
      SINTEGRA_NF_ENTRADA.COD_NF_ENTRADA,
      CASE
        WHEN ((SUBSTRING(SINTEGRA_NF_ENTRADA.CFOP FROM 1 FOR 1) = '1') OR (SUBSTRING(SINTEGRA_NF_ENTRADA.CFOP FROM 1 FOR 1) = '2') OR (SUBSTRING(SINTEGRA_NF_ENTRADA.CFOP FROM 1 FOR 1) = '3')) THEN 'E'
        ELSE 'S'
      END,
      SINTEGRA_NF_ENTRADA.EMITENTE_NF,
      SINTEGRA_NF_ENTRADA.CNPJ_FORNECEDOR,
      SINTEGRA_NF_ENTRADA.MODELO_NF,
      '00',
      SINTEGRA_NF_ENTRADA.SERIE_NF,
      SINTEGRA_NF_ENTRADA.NUM_NF,
      SINTEGRA_NF_ENTRADA.CHAVENFE,
      SINTEGRA_NF_ENTRADA.DATAHORA_EMISSAO,
      SINTEGRA_NF_ENTRADA.DATAHORA_SAIDAENTRADA,
      SINTEGRA_NF_ENTRADA.VALOR_TOTALNF,
      '0',
      SUM(SINTEGRA_NF_ENTRADA_ITENS.VALOR_DESCONTO),
      '0',
      SUM(SINTEGRA_NF_ENTRADA_ITENS.SUBTOTAL),
      '1',
      SUM(SINTEGRA_NF_ENTRADA_ITENS.VALOR_FRETE),
      SUM(SINTEGRA_NF_ENTRADA_ITENS.VALOR_SEGURO),
      SUM(SINTEGRA_NF_ENTRADA_ITENS.VALOR_OUTRASDESPESAS),
      SUM(SINTEGRA_NF_ENTRADA_ITENS.BASE_ICMS),
      SUM(SINTEGRA_NF_ENTRADA_ITENS.VALOR_ICMS),
      SUM(SINTEGRA_NF_ENTRADA_ITENS.BASE_ICMS_SUBST),
      SUM(SINTEGRA_NF_ENTRADA_ITENS.VALOR_ICMS_SUBTITUICAO),
      SUM(SINTEGRA_NF_ENTRADA_ITENS.VALOR_IPI),
      SUM(SINTEGRA_NF_ENTRADA_ITENS.PIS_VALOR),
      SUM(SINTEGRA_NF_ENTRADA_ITENS.COFINS_VALOR)
     FROM
      SINTEGRA_NF_ENTRADA, SINTEGRA_NF_ENTRADA_ITENS
     WHERE
      SINTEGRA_NF_ENTRADA.COD_NF_ENTRADA = SINTEGRA_NF_ENTRADA_ITENS.COD_NF_ENTRADA AND
      SINTEGRA_NF_ENTRADA.DATAHORA_RECEBIMENTO >= :DATAINICIAL AND
      SINTEGRA_NF_ENTRADA.DATAHORA_RECEBIMENTO <= :DATAFINAL
     GROUP BY
      SINTEGRA_NF_ENTRADA.COD_NF_ENTRADA,
      SINTEGRA_NF_ENTRADA.CFOP,
      SINTEGRA_NF_ENTRADA.EMITENTE_NF,
      SINTEGRA_NF_ENTRADA.CNPJ_FORNECEDOR,
      SINTEGRA_NF_ENTRADA.MODELO_NF,
      SINTEGRA_NF_ENTRADA.SERIE_NF,
      SINTEGRA_NF_ENTRADA.NUM_NF,
      SINTEGRA_NF_ENTRADA.CHAVENFE,
      SINTEGRA_NF_ENTRADA.DATAHORA_EMISSAO,
      SINTEGRA_NF_ENTRADA.DATAHORA_SAIDAENTRADA,
      SINTEGRA_NF_ENTRADA.VALOR_TOTALNF
     INTO
      :COD_NF_ENTRADA,
      :ENTRADA_SAIDA,
      :EMITENTE_NF,
      :CNPJ_FORNECEDOR,
      :MODELO_NF,
      :SITUACAO,
      :SERIE_NF,
      :NUM_NF,
      :CHAVENFE,
      :DATAHORA_EMISSAO,
      :DATAHORA_SAIDAENTRADA,
      :VALOR_TOTALNF,
      :INDICADORPAGAMENTO,
      :VALOR_DESCONTO,
      :VALOR_ABAT_NF,
      :VALOR_MERCADORIA,
      :INDICADOR_FRETE,
      :VALOR_FRETE,
      :VALOR_SEGURO,
      :VALOR_OUTROS,
      :BASE_CALCULO_ICMS,
      :VALOR_ICMS,
      :BASE_CALCULO_ICMS_SUBSTITUICAO,
      :VALOR_ICMS_SUBSTITUICAO,
      :VALOR_IPI,
      :VALOR_PIS,
      :VALOR_COFINS
  DO
   BEGIN
     IF ((:MODELO_NF IS NULL) OR (TRIM(:MODELO_NF) = '')) THEN
      BEGIN
        IF ((:CHAVENFE IS NULL) OR (TRIM(:CHAVENFE) = '')) THEN
           MODELO_NF = '01';
        ELSE
           MODELO_NF = '55';
      END
     IF ((:ENTRADA_SAIDA = 'E') AND
         ((:MODELO_NF = '1') OR (:MODELO_NF = '01') OR (:MODELO_NF = '4') OR (:MODELO_NF = '04') OR (:MODELO_NF = '1B') OR (:MODELO_NF = '55')) OR
         (:ENTRADA_SAIDA = 'S') AND ((:MODELO_NF = '55') OR (:MODELO_NF = '65'))) THEN
        SUSPEND;
   END
END ^

ALTER PROCEDURE SP_SUPORTE_SPEDC_C170 (COD_NF_ENTRADA DOUBLE PRECISION)
RETURNS (NUM_ITEM INTEGER,
COD_ITEM VARCHAR(100) CHARACTER SET NONE,
DESCR_COMPL VARCHAR(100) CHARACTER SET NONE,
QTD NUMERIC(15, 2),
UNID VARCHAR(2) CHARACTER SET NONE,
VL_ITEM NUMERIC(15, 2),
VL_DESC NUMERIC(15, 2),
IND_MOV VARCHAR(1) CHARACTER SET NONE,
CST_ICMS VARCHAR(3) CHARACTER SET NONE,
CFOP VARCHAR(4) CHARACTER SET NONE,
COD_NAT VARCHAR(10) CHARACTER SET NONE,
VL_BC_ICMS NUMERIC(15, 2),
ALIQ_ICMS NUMERIC(15, 2),
VL_ICMS NUMERIC(15, 2),
VL_BC_ICMS_ST NUMERIC(15, 2),
ALIQ_ST NUMERIC(15, 2),
VL_ICMS_ST NUMERIC(15, 2),
IND_APUR VARCHAR(1) CHARACTER SET NONE,
CST_IPI VARCHAR(1) CHARACTER SET NONE,
COD_ENQ VARCHAR(1) CHARACTER SET NONE,
VL_BC_IPI NUMERIC(15, 2),
ALIQ_IPI NUMERIC(15, 2),
VL_IPI NUMERIC(15, 2),
CST_PIS VARCHAR(3) CHARACTER SET NONE,
VL_BC_PIS NUMERIC(15, 2),
ALIQ_PIS NUMERIC(15, 2),
QUANT_BC_PIS VARCHAR(1) CHARACTER SET NONE,
ALIQ_PIS_QUANT VARCHAR(1) CHARACTER SET NONE,
VL_PIS NUMERIC(15, 2),
CST_COFINS VARCHAR(3) CHARACTER SET NONE,
VL_BC_COFINS NUMERIC(15, 2),
ALIQ_COFINS NUMERIC(15, 2),
QUANT_BC_COFINS VARCHAR(1) CHARACTER SET NONE,
ALIQ_COFINS_QUANT VARCHAR(1) CHARACTER SET NONE,
VL_COFINS NUMERIC(15, 2),
COD_CTA VARCHAR(1) CHARACTER SET NONE)
AS 
declare variable BARRA varchar(14);
declare variable EXISTE integer;
declare variable PERFIL varchar(1);
declare variable MODELO varchar(2);
BEGIN
  SELECT PARAMETROS.PERFIL FROM PARAMETROS INTO :PERFIL;
  FOR
     SELECT
      SINTEGRA_NF_ENTRADA_ITENS.NUM_ITEM,
      SINTEGRA_NF_ENTRADA_ITENS.REF_PRODUTOS,
      SINTEGRA_NF_ENTRADA_ITENS.PRODUTO,
      SINTEGRA_NF_ENTRADA_ITENS.QUANTIDADE,
      SINTEGRA_NF_ENTRADA_ITENS.APR_UND,
      SINTEGRA_NF_ENTRADA_ITENS.SUBTOTAL,
      SINTEGRA_NF_ENTRADA_ITENS.VALOR_DESCONTO,
      '0', /* IND_MOV 0 - SIM ; 1 - NAO*/
      SINTEGRA_NF_ENTRADA_ITENS.S_TRIB,
      SINTEGRA_NF_ENTRADA_ITENS.CFOP,
      '1', /* COD_NAT - CODIGO DA NATUREZA DA OPERACAO - SEMPRE 1 - COMPRA - TRATAR POSTERIORMENTE SAIDA - VENDA*/
      SINTEGRA_NF_ENTRADA_ITENS.BASE_ICMS,
      SINTEGRA_NF_ENTRADA_ITENS.ALIQUOTA_ICMS,
      SINTEGRA_NF_ENTRADA_ITENS.VALOR_ICMS,
      SINTEGRA_NF_ENTRADA_ITENS.BASE_ICMS_SUBST,
      '0', /* ALIQ_ST - ALIQUOTA DO ICMS DE SUBSTITUICAO TRIBUTARIA - 0 (ZERO) PQ NUNCA VEM NAS NOTAS*/
      SINTEGRA_NF_ENTRADA_ITENS.VALOR_ICMS_SUBTITUICAO,
      '0', /* IND_APUR - INDICADOR DE APURACAO DO IPI - SEMPRE 0 (ZERO)*/
      '', /* CST_IPI*/
      '', /* COD_ENQ - CODIGO DO ENQUADRAMENTO LEGAL DO IPI*/
      '0', /* VL_BC_IPI - VALOR DA BASE DE CALCULO DO IPI*/
      '0', /* ALIQ_IPI - ALIQUOTA DO IPI*/
      '0', /* VL_IPI - VALOR DO IPI*/
      SINTEGRA_NF_ENTRADA_ITENS.PIS_CST,
      SINTEGRA_NF_ENTRADA_ITENS.PIS_BASE_CALCULO,
      SINTEGRA_NF_ENTRADA_ITENS.PIS_PERCENTUAL,
      '0', /* QUANT_BC_PIS - QUANTIDADE DA BASE DE CALCULO DO PIS*/
      '0', /* ALIQ_PIS_QUANT - ALIQUOTA DO PIS EM REAIS*/
      SINTEGRA_NF_ENTRADA_ITENS.PIS_VALOR,
      SINTEGRA_NF_ENTRADA_ITENS.COFINS_CST,
      SINTEGRA_NF_ENTRADA_ITENS.COFINS_BASE_CALCULO,
      SINTEGRA_NF_ENTRADA_ITENS.COFINS_PERCENTUAL,
      '0', /* QUANT_BC_PIS - QUANTIDADE DA BASE DE CALCULO DO PIS*/
      '0', /* ALIQ_PIS_QUANT - ALIQUOTA DO PIS EM REAIS*/
      SINTEGRA_NF_ENTRADA_ITENS.COFINS_VALOR,
      '' /* COD_CTA - CODIGO DA CONTA ANALITICA CONTABIL*/
     FROM
      SINTEGRA_NF_ENTRADA_ITENS
     WHERE
      SINTEGRA_NF_ENTRADA_ITENS.COD_NF_ENTRADA = :COD_NF_ENTRADA
     INTO
      :NUM_ITEM,
      :BARRA,
      :DESCR_COMPL,
      :QTD,
      :UNID,
      :VL_ITEM,
      :VL_DESC,
      :IND_MOV,
      :CST_ICMS,
      :CFOP,
      :COD_NAT,
      :VL_BC_ICMS,
      :ALIQ_ICMS,
      :VL_ICMS,
      :VL_BC_ICMS_ST,
      :ALIQ_ST,
      :VL_ICMS_ST,
      :IND_APUR,
      :CST_IPI,
      :COD_ENQ,
      :VL_BC_IPI,
      :ALIQ_IPI,
      :VL_IPI,
      :CST_PIS,
      :VL_BC_PIS,
      :ALIQ_PIS,
      :QUANT_BC_PIS,
      :ALIQ_PIS_QUANT,
      :VL_PIS,
      :CST_COFINS,
      :VL_BC_COFINS,
      :ALIQ_COFINS,
      :QUANT_BC_COFINS,
      :ALIQ_COFINS_QUANT,
      :VL_COFINS,
      :COD_CTA
  DO
   BEGIN
      SELECT MODELO_NF FROM SINTEGRA_NF_ENTRADA WHERE COD_NF_ENTRADA = :COD_NF_ENTRADA INTO :MODELO;

      /*IF ((PERFIL = 'A') AND (:MODELO <> 55)) THEN
       BEGIN*/
            SELECT FIRST 1 COD_ITEM FROM TEMP_SUPORTE_SPEDC_0200 WHERE COD_BARRA = :BARRA INTO :COD_ITEM;
            IF ((:CFOP = '1101') OR (:CFOP = '1102') OR (:CFOP = '1401') OR (:CFOP = '1403') OR (:CFOP = '1411') OR (:CFOP = '1556') OR
                (:CFOP = '2101') OR (:CFOP = '2102') OR (:CFOP = '2401') OR (:CFOP = '2403') OR (:CFOP = '2411') OR (:CFOP = '2556') OR
                (:CFOP = '1910') OR (:CFOP = '2910') OR
                (:CFOP = '5101') OR (:CFOP = '5102') OR (:CFOP = '5401') OR (:CFOP = '5403') OR (:CFOP = '5405') OR (:CFOP = '5411') OR (:CFOP = '5556') OR
                (:CFOP = '6101') OR (:CFOP = '6102') OR (:CFOP = '6401') OR (:CFOP = '6403') OR (:CFOP = '6411') OR (:CFOP = '6556') OR
                (:CFOP = '5910') OR (:CFOP = '6910') OR (:CFOP = '5929')) THEN
             BEGIN
               SUSPEND;
             END

            -- TRATAR POSTERIORMENTE CFOPS DE DEVOLUCAO DE COMPRA E VENDA
      
            IF ((:CST_PIS = '50') OR (:CST_PIS = '51') OR (:CST_PIS = '52') OR (:CST_PIS = '53') OR (:CST_PIS = '54') OR (:CST_PIS = '55') OR (:CST_PIS = '56')) THEN
             BEGIN
               IF ((:CFOP = '1102') OR (:CFOP = '2102') OR (:CFOP = '1403') OR (:CFOP = '2403')) THEN
                BEGIN
                  SELECT COUNT(*) FROM TEMP_SUPORTE_SPEDC_M105 WHERE NAT_BC_CRED = '01' INTO :EXISTE;
                  IF (:EXISTE = 0) THEN
                     INSERT INTO TEMP_SUPORTE_SPEDC_M105 VALUES ('01', :CST_PIS, :VL_BC_PIS);
                  ELSE
                     UPDATE TEMP_SUPORTE_SPEDC_M105 SET VL_BC_PIS = VL_BC_PIS + :VL_BC_PIS WHERE NAT_BC_CRED = '01';
                END
               ELSE
               IF ((:CFOP = '1101') OR (:CFOP = '2101') OR (:CFOP = '1556') OR (:CFOP = '2556')) THEN
                BEGIN
                  SELECT COUNT(*) FROM TEMP_SUPORTE_SPEDC_M105 WHERE NAT_BC_CRED = '02' INTO :EXISTE;
                  IF (:EXISTE = 0) THEN
                     INSERT INTO TEMP_SUPORTE_SPEDC_M105 VALUES ('02', :CST_PIS, :VL_BC_PIS);
                  ELSE
                     UPDATE TEMP_SUPORTE_SPEDC_M105 SET VL_BC_PIS = VL_BC_PIS + :VL_BC_PIS WHERE NAT_BC_CRED = '02';
                END
             END
      
            IF ((:CST_COFINS = '50') OR (:CST_COFINS = '51') OR (:CST_COFINS = '52') OR (:CST_COFINS = '53') OR (:CST_COFINS = '54') OR (:CST_COFINS = '55') OR (:CST_COFINS = '56')) THEN
             BEGIN
               IF ((:CFOP = '1102') OR (:CFOP = '2102') OR (:CFOP = '1403') OR (:CFOP = '2403')) THEN
                BEGIN
                  SELECT COUNT(*) FROM TEMP_SUPORTE_SPEDC_M505 WHERE NAT_BC_CRED = '01' INTO :EXISTE;
                  IF (:EXISTE = 0) THEN
                     INSERT INTO TEMP_SUPORTE_SPEDC_M505 VALUES ('01', :CST_COFINS, :VL_BC_COFINS);
                  ELSE
                     UPDATE TEMP_SUPORTE_SPEDC_M505 SET VL_BC_COFINS = VL_BC_COFINS + :VL_BC_COFINS WHERE NAT_BC_CRED = '01';
                END
               ELSE
               IF ((:CFOP = '1101') OR (:CFOP = '2101') OR (:CFOP = '1556') OR (:CFOP = '2556')) THEN
                BEGIN
                  SELECT COUNT(*) FROM TEMP_SUPORTE_SPEDC_M505 WHERE NAT_BC_CRED = '02' INTO :EXISTE;
                  IF (:EXISTE = 0) THEN
                     INSERT INTO TEMP_SUPORTE_SPEDC_M505 VALUES ('02', :CST_COFINS, :VL_BC_COFINS);
                  ELSE
                     UPDATE TEMP_SUPORTE_SPEDC_M505 SET VL_BC_COFINS = VL_BC_COFINS + :VL_BC_COFINS WHERE NAT_BC_CRED = '02';
                END
             END
       --END
   END

END ^

ALTER PROCEDURE SP_SUPORTE_SPEDC_C175 (COD_NF_ENTRADA DOUBLE PRECISION)
RETURNS (CFOP VARCHAR(4) CHARACTER SET NONE,
PIS_CST VARCHAR(2) CHARACTER SET NONE,
PIS_BASE_CALCULO NUMERIC(15, 2),
PIS_PERCENTUAL NUMERIC(15, 2),
COFINS_CST VARCHAR(2) CHARACTER SET NONE,
COFINS_BASE_CALCULO NUMERIC(15, 2),
COFINS_PERCENTUAL NUMERIC(15, 2),
TOTAL NUMERIC(15, 2),
PIS_VALOR NUMERIC(15, 2),
COFINS_VALOR NUMERIC(15, 2),
DESCONTO NUMERIC(15, 2))
AS 
declare variable EXISTE integer;
declare variable REF_PRODUTOS varchar(14);
declare variable NCM varchar(100);
declare variable VL_ITEM numeric(15,2);
BEGIN
  /* REGISTRO CRIADO A SEMELHANCA DO C190 POREM SOMENTE PARA NFC-E - MODELO 65 */
  FOR
     SELECT
      SINTEGRA_NF_ENTRADA_ITENS.CFOP,
      SINTEGRA_NF_ENTRADA_ITENS.PIS_CST,
      --SINTEGRA_NF_ENTRADA_ITENS.PIS_BASE_CALCULO,
      SINTEGRA_NF_ENTRADA_ITENS.PIS_PERCENTUAL,
      SINTEGRA_NF_ENTRADA_ITENS.COFINS_CST,
      --SINTEGRA_NF_ENTRADA_ITENS.COFINS_BASE_CALCULO,
      SINTEGRA_NF_ENTRADA_ITENS.COFINS_PERCENTUAL,
      SUM(SINTEGRA_NF_ENTRADA_ITENS.PIS_VALOR),
      SUM(SINTEGRA_NF_ENTRADA_ITENS.COFINS_VALOR),
      SUM(SINTEGRA_NF_ENTRADA_ITENS.SUBTOTAL),
      SUM(SINTEGRA_NF_ENTRADA_ITENS.VALOR_DESCONTO)
     FROM
      SINTEGRA_NF_ENTRADA_ITENS,
      SINTEGRA_NF_ENTRADA
     WHERE
      SINTEGRA_NF_ENTRADA_ITENS.COD_NF_ENTRADA = SINTEGRA_NF_ENTRADA.COD_NF_ENTRADA AND
      SINTEGRA_NF_ENTRADA.COD_NF_ENTRADA = :COD_NF_ENTRADA
     GROUP BY
      SINTEGRA_NF_ENTRADA_ITENS.CFOP,
      SINTEGRA_NF_ENTRADA_ITENS.PIS_CST,
      --SINTEGRA_NF_ENTRADA_ITENS.PIS_BASE_CALCULO,
      SINTEGRA_NF_ENTRADA_ITENS.PIS_PERCENTUAL,
      SINTEGRA_NF_ENTRADA_ITENS.COFINS_CST,
      --SINTEGRA_NF_ENTRADA_ITENS.COFINS_BASE_CALCULO,
      SINTEGRA_NF_ENTRADA_ITENS.COFINS_PERCENTUAL
     INTO
      :CFOP, :PIS_CST, /*:PIS_BASE_CALCULO,*/ :PIS_PERCENTUAL, :COFINS_CST, /*:COFINS_BASE_CALCULO,*/ :COFINS_PERCENTUAL, :PIS_VALOR,  :COFINS_VALOR, :TOTAL, :DESCONTO
  DO
   BEGIN

     SELECT SUM(SINTEGRA_NF_ENTRADA_ITENS.PIS_BASE_CALCULO), SUM(SINTEGRA_NF_ENTRADA_ITENS.COFINS_BASE_CALCULO) FROM SINTEGRA_NF_ENTRADA_ITENS
     WHERE SINTEGRA_NF_ENTRADA_ITENS.COD_NF_ENTRADA = :COD_NF_ENTRADA AND
           SINTEGRA_NF_ENTRADA_ITENS.CFOP = :CFOP AND
           SINTEGRA_NF_ENTRADA_ITENS.PIS_CST = :PIS_CST AND
           SINTEGRA_NF_ENTRADA_ITENS.COFINS_CST = :COFINS_CST AND
           SINTEGRA_NF_ENTRADA_ITENS.PIS_PERCENTUAL = :PIS_PERCENTUAL AND
           SINTEGRA_NF_ENTRADA_ITENS.COFINS_PERCENTUAL = :COFINS_PERCENTUAL
     INTO :PIS_BASE_CALCULO, :COFINS_BASE_CALCULO;


     IF (:PIS_CST = '01') THEN
      BEGIN
         SELECT COUNT(*) FROM TEMP_SUPORTE_SPEDC_M210 WHERE COD_CONTA = '01' INTO :EXISTE;
         IF (:EXISTE = 0) THEN
            INSERT INTO TEMP_SUPORTE_SPEDC_M210 VALUES ('01', :TOTAL, :PIS_BASE_CALCULO); --:TOTAL - :DESCONTO);
         ELSE
            UPDATE TEMP_SUPORTE_SPEDC_M210 SET
             VL_REC_BRT = VL_REC_BRT + :TOTAL,
             VL_BASE_CALCULO = VL_BASE_CALCULO + :PIS_BASE_CALCULO
            WHERE COD_CONTA = '01'; --:TOTAL - :DESCONTO;

         SELECT COUNT(*) FROM TEMP_SUPORTE_SPEDC_M610 WHERE COD_CONTA = '01' INTO :EXISTE;
         IF (:EXISTE = 0) THEN
            INSERT INTO TEMP_SUPORTE_SPEDC_M610 VALUES ('01', :TOTAL, :COFINS_BASE_CALCULO); --:TOTAL - :DESCONTO);
         ELSE
            UPDATE TEMP_SUPORTE_SPEDC_M610 SET
              VL_REC_BRT = VL_REC_BRT + :TOTAL,
             VL_BASE_CALCULO = VL_BASE_CALCULO + :COFINS_BASE_CALCULO
            WHERE COD_CONTA = '01';  --:TOTAL - :DESCONTO;
      END

     IF ((:TOTAL IS NOT NULL) AND (:TOTAL > 0)) THEN
        SUSPEND;
   END


   FOR
    SELECT
     REF_PRODUTOS, PIS_CST, SUM(SINTEGRA_NF_ENTRADA_ITENS.SUBTOTAL)
    FROM
     SINTEGRA_NF_ENTRADA_ITENS
    WHERE
     SINTEGRA_NF_ENTRADA_ITENS.COD_NF_ENTRADA = :COD_NF_ENTRADA
    GROUP BY
     REF_PRODUTOS, PIS_CST
    INTO
     :REF_PRODUTOS, :PIS_CST, :VL_ITEM
   DO
    BEGIN
       IF ((:PIS_CST = '04') OR (:PIS_CST = '06') OR (:PIS_CST = '07') OR (:PIS_CST = '08') OR (:PIS_CST = '09')) THEN
          BEGIN
             SELECT FIRST 1 NCM FROM PRODUTOS_FISCO WHERE CODIGO_BARRAS = :REF_PRODUTOS INTO :NCM;
             IF ((:NCM IS NULL) OR (:NCM = '99999999') OR (:NCM = '00000000') OR (TRIM(:NCM) = ''))  THEN
                NCM = '30049099';
             IF (
                 (SUBSTRING(:NCM FROM 1 FOR 4) = '3001') OR
                 ((SUBSTRING(:NCM FROM 1 FOR 4)= '3003') AND (:NCM <> '30039056')) OR
                 ((SUBSTRING(:NCM FROM 1 FOR 4) = '3004') AND (:NCM <> '30049046')) OR
                 (SUBSTRING(:NCM FROM 1 FOR 7) = '3002101') OR
                 (SUBSTRING(:NCM FROM 1 FOR 7) = '3002102') OR
                 (SUBSTRING(:NCM FROM 1 FOR 7) = '3002103') OR
                 (SUBSTRING(:NCM FROM 1 FOR 7) = '3002201') OR
                 (SUBSTRING(:NCM FROM 1 FOR 7) = '3002202') OR
                 (SUBSTRING(:NCM FROM 1 FOR 7) = '3006301') OR
                 (SUBSTRING(:NCM FROM 1 FOR 7) = '3006302') OR
                 (:NCM ='30029020') OR (:NCM ='30029092') OR (:NCM ='30029099') OR (:NCM ='30051010') OR (:NCM ='30066000')
                ) THEN -- MEDICAMENTOS
               BEGIN
                SELECT COUNT(*) FROM TEMP_SUPORTE_SPEDC_M410 WHERE CST = :PIS_CST AND NAT_REC = '201' INTO :EXISTE;
                IF (:EXISTE = 0) THEN
                   INSERT INTO TEMP_SUPORTE_SPEDC_M410 VALUES (:PIS_CST, '201', :VL_ITEM);
                ELSE
                   UPDATE TEMP_SUPORTE_SPEDC_M410 SET VL_REC = VL_REC + :VL_ITEM WHERE CST = :PIS_CST AND NAT_REC = '201';
               END
              ELSE
               BEGIN -- PERFUMARIA
                 SELECT COUNT(*) FROM TEMP_SUPORTE_SPEDC_M410 WHERE CST = :PIS_CST AND NAT_REC = '202' INTO :EXISTE;
                 IF (:EXISTE = 0) THEN
                    INSERT INTO TEMP_SUPORTE_SPEDC_M410 VALUES (:PIS_CST, '202', :VL_ITEM);
                 ELSE
                    UPDATE TEMP_SUPORTE_SPEDC_M410 SET VL_REC = VL_REC + :VL_ITEM WHERE CST = :PIS_CST AND NAT_REC = '202';
               END
          END
    END

   FOR
    SELECT
     REF_PRODUTOS, COFINS_CST, SUM(SINTEGRA_NF_ENTRADA_ITENS.SUBTOTAL)
    FROM
     SINTEGRA_NF_ENTRADA_ITENS
    WHERE
     SINTEGRA_NF_ENTRADA_ITENS.COD_NF_ENTRADA = :COD_NF_ENTRADA
    GROUP BY
     REF_PRODUTOS, COFINS_CST
    INTO
     :REF_PRODUTOS, :COFINS_CST, :VL_ITEM
   DO
    BEGIN
       IF ((:COFINS_CST = '04') OR (:COFINS_CST = '06') OR (:COFINS_CST = '07') OR (:COFINS_CST = '08') OR (:COFINS_CST = '09')) THEN
          BEGIN
             SELECT FIRST 1 NCM FROM PRODUTOS_FISCO WHERE CODIGO_BARRAS = :REF_PRODUTOS INTO :NCM;
             IF ((:NCM IS NULL) OR (:NCM = '99999999') OR (:NCM = '00000000') OR (TRIM(:NCM) = ''))  THEN
                NCM = '30049099';
             IF (
                 (SUBSTRING(:NCM FROM 1 FOR 4) = '3001') OR
                 ((SUBSTRING(:NCM FROM 1 FOR 4)= '3003') AND (:NCM <> '30039056')) OR
                 ((SUBSTRING(:NCM FROM 1 FOR 4) = '3004') AND (:NCM <> '30049046')) OR
                 (SUBSTRING(:NCM FROM 1 FOR 7) = '3002101') OR
                 (SUBSTRING(:NCM FROM 1 FOR 7) = '3002102') OR
                 (SUBSTRING(:NCM FROM 1 FOR 7) = '3002103') OR
                 (SUBSTRING(:NCM FROM 1 FOR 7) = '3002201') OR
                 (SUBSTRING(:NCM FROM 1 FOR 7) = '3002202') OR
                 (SUBSTRING(:NCM FROM 1 FOR 7) = '3006301') OR
                 (SUBSTRING(:NCM FROM 1 FOR 7) = '3006302') OR
                 (:NCM ='30029020') OR (:NCM ='30029092') OR (:NCM ='30029099') OR (:NCM ='30051010') OR (:NCM ='30066000')
                ) THEN -- MEDICAMENTOS
               BEGIN
                SELECT COUNT(*) FROM TEMP_SUPORTE_SPEDC_M810 WHERE CST = :COFINS_CST AND NAT_REC = '201' INTO :EXISTE;
                IF (:EXISTE = 0) THEN
                   INSERT INTO TEMP_SUPORTE_SPEDC_M810 VALUES (:COFINS_CST, '201', :VL_ITEM);
                ELSE
                   UPDATE TEMP_SUPORTE_SPEDC_M810 SET VL_REC = VL_REC + :VL_ITEM WHERE CST = :COFINS_CST AND NAT_REC = '201';
               END
              ELSE
               BEGIN -- PERFUMARIA
                 SELECT COUNT(*) FROM TEMP_SUPORTE_SPEDC_M810 WHERE CST = :COFINS_CST AND NAT_REC = '202' INTO :EXISTE;
                 IF (:EXISTE = 0) THEN
                    INSERT INTO TEMP_SUPORTE_SPEDC_M810 VALUES (:COFINS_CST, '202', :VL_ITEM);
                 ELSE
                    UPDATE TEMP_SUPORTE_SPEDC_M810 SET VL_REC = VL_REC + :VL_ITEM WHERE CST = :COFINS_CST AND NAT_REC = '202';
               END
          END
    END
END ^

ALTER PROCEDURE SP_SUPORTE_SPEDC_C180 (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (COD_ITEM VARCHAR(100) CHARACTER SET NONE,
REF_PRODUTOS VARCHAR(14) CHARACTER SET NONE,
NCM VARCHAR(20) CHARACTER SET NONE,
TOTALPRODUTO NUMERIC(15, 2))
AS 
declare variable COMANDO varchar(1000);
declare variable EXISTE integer;
BEGIN
  FOR
     SELECT
      SINTEGRA_NF_ENTRADA_ITENS.REF_PRODUTOS,
      SUM(SINTEGRA_NF_ENTRADA_ITENS.SUBTOTAL)
     FROM
      SINTEGRA_NF_ENTRADA_ITENS,
      SINTEGRA_NF_ENTRADA
     WHERE
      SINTEGRA_NF_ENTRADA_ITENS.COD_NF_ENTRADA = SINTEGRA_NF_ENTRADA.COD_NF_ENTRADA AND
      SINTEGRA_NF_ENTRADA.DATAHORA_RECEBIMENTO >= :DATAINICIAL AND
      SINTEGRA_NF_ENTRADA.DATAHORA_RECEBIMENTO <= :DATAFINAL AND
      SINTEGRA_NF_ENTRADA.MODELO_NF = '55' AND
      SINTEGRA_NF_ENTRADA.EMITENTE_NF = 'P' AND
      SINTEGRA_NF_ENTRADA_ITENS.CFOP IS NOT NULL AND
      SINTEGRA_NF_ENTRADA_ITENS.CFOP <> '' AND
      ((SINTEGRA_NF_ENTRADA_ITENS.CFOP >= 5101 AND SINTEGRA_NF_ENTRADA_ITENS.CFOP <= 5123) OR
       (SINTEGRA_NF_ENTRADA_ITENS.CFOP = 5929 OR SINTEGRA_NF_ENTRADA_ITENS.CFOP = 6929) OR
       (SINTEGRA_NF_ENTRADA_ITENS.CFOP >= 6101 AND SINTEGRA_NF_ENTRADA_ITENS.CFOP <= 6123))
     GROUP BY
      SINTEGRA_NF_ENTRADA_ITENS.REF_PRODUTOS
     INTO
      :REF_PRODUTOS,
      :TOTALPRODUTO
  DO
   BEGIN
     IF ((:TOTALPRODUTO IS NOT NULL) AND (:TOTALPRODUTO > 0)) THEN
      BEGIN
        SELECT COUNT(*) FROM PRODUTOS_FISCO WHERE CAST(CODIGO_BARRAS AS NUMERIC(15,0)) = CAST(:REF_PRODUTOS AS NUMERIC(15,0)) INTO :EXISTE;
        IF (:EXISTE > 0) THEN
         BEGIN
           COD_ITEM = 0;
           SELECT COD_ITEM, NCM FROM TEMP_SUPORTE_SPEDC_0200 WHERE COD_BARRA_NUMERO = CAST(:REF_PRODUTOS AS NUMERIC(15,0)) INTO :COD_ITEM, :NCM;
           IF (:COD_ITEM > 0) THEN
              SUSPEND;
         END
      END
   END

END ^

ALTER PROCEDURE SP_SUPORTE_SPEDC_C181C185 (BARRA VARCHAR(14) CHARACTER SET NONE,
DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (CFOP VARCHAR(4) CHARACTER SET NONE,
CST_PIS VARCHAR(3) CHARACTER SET NONE,
CST_COFINS VARCHAR(3) CHARACTER SET NONE,
TOTALDESCONTO NUMERIC(15, 2),
TOTALPRODUTO NUMERIC(15, 2),
BASECALCULO NUMERIC(15, 2))
AS 
declare variable ENQ varchar(2);
declare variable COMANDO varchar(1000);
declare variable NCM varchar(20);
declare variable EXISTE integer;
BEGIN
  SELECT ENQUADRAMENTOTRIBUTARIO FROM PARAMETROS INTO :ENQ;
  IF (:ENQ = 'S') THEN
     ENQ = 'SN';
  ELSE
  IF (:ENQ = 'P') THEN
     ENQ = 'LP';
  ELSE
  IF (:ENQ = 'R') THEN
     ENQ = 'LR';
  ELSE
  IF ((:ENQ IS NULL) OR (:ENQ = '')) THEN
     ENQ = 'SN';

  FOR
     SELECT
      SINTEGRA_NF_ENTRADA_ITENS.CFOP,
      SUM(SINTEGRA_NF_ENTRADA_ITENS.VALOR_DESCONTO),
      SUM(SINTEGRA_NF_ENTRADA_ITENS.SUBTOTAL)
     FROM
      SINTEGRA_NF_ENTRADA_ITENS,
      SINTEGRA_NF_ENTRADA
     WHERE
      SINTEGRA_NF_ENTRADA_ITENS.COD_NF_ENTRADA = SINTEGRA_NF_ENTRADA.COD_NF_ENTRADA AND
      SINTEGRA_NF_ENTRADA.DATAHORA_RECEBIMENTO >= :DATAINICIAL AND
      SINTEGRA_NF_ENTRADA.DATAHORA_RECEBIMENTO <= :DATAFINAL AND
      SINTEGRA_NF_ENTRADA.MODELO_NF = '55' AND
      SINTEGRA_NF_ENTRADA.EMITENTE_NF = 'P' AND
      CAST(SINTEGRA_NF_ENTRADA_ITENS.REF_PRODUTOS AS NUMERIC(15,0)) = CAST(:BARRA AS NUMERIC(15,0)) AND
      SINTEGRA_NF_ENTRADA_ITENS.CFOP IS NOT NULL AND
      SINTEGRA_NF_ENTRADA_ITENS.CFOP <> '' AND
      ((SINTEGRA_NF_ENTRADA_ITENS.CFOP >= 5101 AND SINTEGRA_NF_ENTRADA_ITENS.CFOP <= 5123) OR
       (SINTEGRA_NF_ENTRADA_ITENS.CFOP = 5929 OR SINTEGRA_NF_ENTRADA_ITENS.CFOP = 6929) OR
       (SINTEGRA_NF_ENTRADA_ITENS.CFOP >= 6101 AND SINTEGRA_NF_ENTRADA_ITENS.CFOP <= 6123))
     GROUP BY
      SINTEGRA_NF_ENTRADA_ITENS.CFOP
     INTO
      :CFOP,
      :TOTALDESCONTO,
      :TOTALPRODUTO
  DO
   BEGIN
     IF ((:TOTALPRODUTO IS NOT NULL) AND (:TOTALPRODUTO > 0)) THEN
      BEGIN
        BASECALCULO = :TOTALPRODUTO - :TOTALDESCONTO;

        SELECT FIRST 1 NCM, PRODUTOS_FISCO.CST_PIS_COFINS_SAIDA, PRODUTOS_FISCO.CST_PIS_COFINS_SAIDA
        FROM PRODUTOS_FISCO WHERE CAST(CODIGO_BARRAS AS NUMERIC(15,0)) = CAST(:BARRA AS NUMERIC(15,0))
        INTO :NCM, :CST_PIS, :CST_COFINS;

        IF ((
            (SUBSTRING(NCM FROM 1 FOR 4) = '3001') OR
            (SUBSTRING(NCM FROM 1 FOR 4) = '3003') OR
            (SUBSTRING(NCM FROM 1 FOR 4) = '3004') OR
            (SUBSTRING(NCM FROM 1 FOR 4) = '3005') OR
            (SUBSTRING(NCM FROM 1 FOR 4) = '3006') OR
            (SUBSTRING(NCM FROM 1 FOR 4) = '3007') OR
            (NCM = '30021001') OR
            (NCM = '30021002') OR
            (NCM = '30021003') OR
            (NCM = '30022001') OR
            (NCM = '30022002') OR
            (NCM = '30029020') OR
            (NCM = '30029092') OR
            (NCM = '30029099') OR
            (NCM = '30051010') OR
            (NCM = '30063001') OR
            (NCM = '30063002') OR
            (NCM = '30066000') OR
            (NCM = '34011190') OR
            (NCM = '34012010') OR
            (NCM = '96032100')
           ) AND
            (NCM <> '30039056') AND
            (NCM <> '30049046')) THEN
           SUSPEND;
      END
   END

END ^

