ALTER PROCEDURE SP_SUPORTE_SPEDC_C400 (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (COD_MOD VARCHAR(100) CHARACTER SET NONE,
ECF_MOD VARCHAR(100) CHARACTER SET NONE,
ECF_FAB VARCHAR(100) CHARACTER SET NONE,
ECF_CX VARCHAR(100) CHARACTER SET NONE)
AS 
BEGIN
  FOR
   SELECT
    '2D',
    PAF_R01.MODELO_ECF,
    PAF_R01.NUMERO_FABRICACAO,
    PAF_R01.NUMERO_SEQUENCIAL_ECF
   FROM
    PAF_R01
   WHERE
    ID_PAF_R01 IN
     (
       SELECT ID_PAF_R01
       FROM PAF_R02
       WHERE
         PAF_R02.DDATA_MOVIMENTO IS NOT NULL AND
         PAF_R02.DDATA_MOVIMENTO >= :DATAINICIAL AND
         PAF_R02.DDATA_MOVIMENTO <= :DATAFINAL
         /*PAF_R02.DATA_MOVIMENTO <> '000000' AND
         PAF_R02.DATA_MOVIMENTO <> '' AND
         CAST(PAF_R02.DATA_MOVIMENTO AS INTEGER) > 0 AND
         CAST(SUBSTRING(PAF_R02.DATA_MOVIMENTO FROM 3 FOR 2)||'/'||SUBSTRING(PAF_R02.DATA_MOVIMENTO FROM 1 FOR 2)||'/20'||SUBSTRING(PAF_R02.DATA_MOVIMENTO FROM 5 FOR 2) AS DATE) >= :DATAINICIAL AND
         CAST(SUBSTRING(PAF_R02.DATA_MOVIMENTO FROM 3 FOR 2)||'/'||SUBSTRING(PAF_R02.DATA_MOVIMENTO FROM 1 FOR 2)||'/20'||SUBSTRING(PAF_R02.DATA_MOVIMENTO FROM 5 FOR 2) AS DATE) <= :DATAFINAL*/
      )
   INTO
    :COD_MOD,
    :ECF_MOD,
    :ECF_FAB,
    :ECF_CX
  DO
   BEGIN
     SUSPEND;
   END
END ^

ALTER PROCEDURE SP_SUPORTE_SPEDC_C405 (NUMERO_FABRICACAO VARCHAR(100) CHARACTER SET NONE,
DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (ID_PAF_R02 DOUBLE PRECISION,
DT_DOC VARCHAR(100) CHARACTER SET NONE,
CRO VARCHAR(100) CHARACTER SET NONE,
CRZ VARCHAR(100) CHARACTER SET NONE,
NUM_COO_FIN VARCHAR(100) CHARACTER SET NONE,
GT_FIN NUMERIC(15, 2),
VL_BRT NUMERIC(15, 2))
AS 
BEGIN
  FOR
   SELECT
    PAF_R02.ID_PAF_R02,
    PAF_R02.DATA_MOVIMENTO,
    PAF_R02.CRO,
    PAF_R02.CRZ,
    PAF_R02.COO,
    CAST(SUBSTRING(PAF_R02.GT FROM 1 FOR 13) AS NUMERIC(15,2)) / 100,
    CAST(PAF_R02.VENDA_BRUTA_DIARIA AS NUMERIC(15,2)) / 100
   FROM
    PAF_R02
   WHERE
    PAF_R02.NUMERO_FABRICACAO = :NUMERO_FABRICACAO AND
    PAF_R02.DATA_MOVIMENTO IS NOT NULL AND
    PAF_R02.DATA_MOVIMENTO <> '000000' AND
    PAF_R02.DATA_MOVIMENTO <> '' AND
    CAST(PAF_R02.DATA_MOVIMENTO AS INTEGER) > 0 AND
    CAST(SUBSTRING(PAF_R02.DATA_MOVIMENTO FROM 3 FOR 2)||'/'||SUBSTRING(PAF_R02.DATA_MOVIMENTO FROM 1 FOR 2)||'/20'||SUBSTRING(PAF_R02.DATA_MOVIMENTO FROM 5 FOR 2) AS DATE) >= :DATAINICIAL AND
    CAST(SUBSTRING(PAF_R02.DATA_MOVIMENTO FROM 3 FOR 2)||'/'||SUBSTRING(PAF_R02.DATA_MOVIMENTO FROM 1 FOR 2)||'/20'||SUBSTRING(PAF_R02.DATA_MOVIMENTO FROM 5 FOR 2) AS DATE) <= :DATAFINAL
   INTO
    :ID_PAF_R02,
    :DT_DOC,
    :CRO,
    :CRZ,
    :NUM_COO_FIN,
    :GT_FIN,
    :VL_BRT
  DO
   BEGIN
     SUSPEND;
   END
END ^

ALTER PROCEDURE SP_SUPORTE_SPEDC_C481 (ID_PAF_R02 INTEGER,
ALIQ_PIS NUMERIC(15, 2))
RETURNS (CST_PIS VARCHAR(10) CHARACTER SET NONE,
VL_ITEM NUMERIC(15, 2),
VL_BC_PIS NUMERIC(15, 2),
QUANT_BC_PIS VARCHAR(10) CHARACTER SET NONE,
ALIQ_PIS_QUANT VARCHAR(10) CHARACTER SET NONE,
VL_PIS NUMERIC(15, 2),
COD_ITEM INTEGER,
COD_CTA VARCHAR(1) CHARACTER SET NONE,
BARRA VARCHAR(14) CHARACTER SET NONE)
AS 
declare variable BARRA_NUM numeric(15,2);
declare variable EXISTE integer;
declare variable NCM varchar(10);
BEGIN
  UPDATE PAF_R05 SET BARRA_NUM = CAST(PAF_R05.CODIGO_PRODUTO_SERVICO AS NUMERIC(15,0)) WHERE ID_PAF_R02 = :ID_PAF_R02;
  VL_ITEM = 0;
  FOR
    SELECT
     PRODUTOS_FISCO.CST_PIS_COFINS_SAIDA,
     PAF_R05.BARRA_NUM,
     SUM(CAST(PAF_R05.VALOR_TOTAL_LIQUIDO AS NUMERIC(15,2)) / 100)
    FROM
     PAF_R05 LEFT OUTER JOIN PRODUTOS_FISCO ON PAF_R05.BARRA_NUM = PRODUTOS_FISCO.CODIGO_BARRAS
    WHERE
     PAF_R05.ID_PAF_R02 = :ID_PAF_R02 AND
     PAF_R05.INDICADOR_CANCELAMENTO = 'N'
    GROUP BY
     PRODUTOS_FISCO.CST_PIS_COFINS_SAIDA,
     PAF_R05.BARRA_NUM
    INTO
     :CST_PIS,
     :BARRA_NUM,
     :VL_ITEM
  DO
   BEGIN
       BARRA = CAST(:BARRA_NUM AS NUMERIC(15,0));
       SELECT RESULT FROM STR_ZERO(:BARRA, 14) INTO :BARRA;
       COD_ITEM = 0;
       IF (:CST_PIS IS NULL) THEN
          CST_PIS = '04';
       VL_BC_PIS = 0;
       --ALIQ_PIS = 0;
       QUANT_BC_PIS = '0';
       ALIQ_PIS_QUANT = '0';
       VL_PIS = 0;
       COD_CTA = '';
       IF (:CST_PIS = '01') THEN
        BEGIN
          VL_BC_PIS = :VL_ITEM;
          --ALIQ_PIS = 1.65;
          VL_PIS = CAST((:VL_BC_PIS * ALIQ_PIS) / 100 AS NUMERIC(15,2));
        END
  
       SELECT FIRST 1 COD_ITEM FROM TEMP_SUPORTE_SPEDC_0200 WHERE COD_BARRA_NUMERO = :BARRA_NUM INTO :COD_ITEM;
  
       SUSPEND;
    
       IF (:CST_PIS = '01') THEN
        BEGIN
           SELECT COUNT(*) FROM TEMP_SUPORTE_SPEDC_M210 INTO :EXISTE;
           IF (:EXISTE = 0) THEN
              INSERT INTO TEMP_SUPORTE_SPEDC_M210 VALUES ('01', :VL_BC_PIS, :VL_BC_PIS);
           ELSE
              UPDATE TEMP_SUPORTE_SPEDC_M210 SET
               VL_REC_BRT = VL_REC_BRT + :VL_BC_PIS,
               VL_BASE_CALCULO = VL_BASE_CALCULO + :VL_BC_PIS;
        END
  
     IF ((:CST_PIS = '04') OR (:CST_PIS = '06') OR (:CST_PIS = '07') OR (:CST_PIS = '08') OR (:CST_PIS = '09')) THEN
        BEGIN
           SELECT FIRST 1 NCM FROM PRODUTOS_FISCO WHERE CODIGO_BARRAS = :BARRA_NUM INTO :NCM;
           IF ((:NCM IS NULL) OR (:NCM = '99999999') OR (:NCM = '00000000') OR (TRIM(:NCM) = ''))  THEN
              NCM = '30049099';
           IF (
               (SUBSTRING(:NCM FROM 1 FOR 4) = '3001') OR
               ((SUBSTRING(:NCM FROM 1 FOR 4)= '3003') AND (:NCM <> '30039056')) OR
               ((SUBSTRING(:NCM FROM 1 FOR 4) = '3004') AND (:NCM <> '30049046')) OR
               (SUBSTRING(:NCM FROM 1 FOR 7) = '3002101') OR
               (SUBSTRING(:NCM FROM 1 FOR 7) = '3002102') OR
               (SUBSTRING(:NCM FROM 1 FOR 7) = '3002103') OR
               (SUBSTRING(:NCM FROM 1 FOR 7) = '3002201') OR
               (SUBSTRING(:NCM FROM 1 FOR 7) = '3002202') OR
               (SUBSTRING(:NCM FROM 1 FOR 7) = '3006301') OR
               (SUBSTRING(:NCM FROM 1 FOR 7) = '3006302') OR
               (:NCM ='30029020') OR (:NCM ='30029092') OR (:NCM ='30029099') OR (:NCM ='30051010') OR (:NCM ='30066000')
              ) THEN -- MEDICAMENTOS
             BEGIN
              SELECT COUNT(*) FROM TEMP_SUPORTE_SPEDC_M410 WHERE CST = :CST_PIS AND NAT_REC = '201' INTO :EXISTE;
              IF (:EXISTE = 0) THEN
                 INSERT INTO TEMP_SUPORTE_SPEDC_M410 VALUES (:CST_PIS, '201', :VL_ITEM);
              ELSE
                 UPDATE TEMP_SUPORTE_SPEDC_M410 SET VL_REC = VL_REC + :VL_ITEM WHERE CST = :CST_PIS AND NAT_REC = '201';
             END
            ELSE
             BEGIN -- PERFUMARIA
               SELECT COUNT(*) FROM TEMP_SUPORTE_SPEDC_M410 WHERE CST = :CST_PIS AND NAT_REC = '202' INTO :EXISTE;
               IF (:EXISTE = 0) THEN
                  INSERT INTO TEMP_SUPORTE_SPEDC_M410 VALUES (:CST_PIS, '202', :VL_ITEM);
               ELSE
                  UPDATE TEMP_SUPORTE_SPEDC_M410 SET VL_REC = VL_REC + :VL_ITEM WHERE CST = :CST_PIS AND NAT_REC = '202';
             END
        END
   END
END ^

ALTER PROCEDURE SP_SUPORTE_SPEDC_C485 (ID_PAF_R02 INTEGER,
ALIQ_COFINS NUMERIC(15, 2))
RETURNS (CST_COFINS VARCHAR(10) CHARACTER SET NONE,
VL_ITEM NUMERIC(15, 2),
VL_BC_COFINS NUMERIC(15, 2),
QUANT_BC_COFINS VARCHAR(10) CHARACTER SET NONE,
ALIQ_COFINS_QUANT VARCHAR(10) CHARACTER SET NONE,
VL_COFINS NUMERIC(15, 2),
COD_ITEM INTEGER,
COD_CTA VARCHAR(1) CHARACTER SET NONE,
BARRA VARCHAR(14) CHARACTER SET NONE)
AS 
declare variable EXISTE integer;
declare variable NCM varchar(10);
declare variable BARRA_NUM numeric(15,0);
BEGIN
  UPDATE PAF_R05 SET BARRA_NUM = CAST(PAF_R05.CODIGO_PRODUTO_SERVICO AS NUMERIC(15,0)) WHERE ID_PAF_R02 = :ID_PAF_R02;
  VL_ITEM = 0;
  FOR
    SELECT
     PRODUTOS_FISCO.CST_PIS_COFINS_SAIDA,
     PAF_R05.BARRA_NUM,
     SUM(CAST(PAF_R05.VALOR_TOTAL_LIQUIDO AS NUMERIC(15,2)) / 100)
    FROM
     PAF_R05 LEFT OUTER JOIN PRODUTOS_FISCO ON PAF_R05.BARRA_NUM = PRODUTOS_FISCO.CODIGO_BARRAS
    WHERE
     PAF_R05.ID_PAF_R02 = :ID_PAF_R02 AND
     PAF_R05.INDICADOR_CANCELAMENTO = 'N'
    GROUP BY
     PRODUTOS_FISCO.CST_PIS_COFINS_SAIDA,
     PAF_R05.BARRA_NUM
    INTO
     :CST_COFINS,
     :BARRA_NUM,
     :VL_ITEM
  DO
   BEGIN
       BARRA = CAST(:BARRA_NUM AS NUMERIC(15,0));
       SELECT RESULT FROM STR_ZERO(:BARRA, 14) INTO :BARRA;
       IF (:CST_COFINS IS NULL) THEN
         CST_COFINS = '04';
       VL_BC_COFINS = 0;
       --ALIQ_COFINS = 0;
       QUANT_BC_COFINS = '0';
       ALIQ_COFINS_QUANT = '0';
       VL_COFINS = 0;
       COD_CTA = '';
       IF (:CST_COFINS = '01') THEN
        BEGIN
          VL_BC_COFINS = :VL_ITEM;
          --ALIQ_COFINS = 7.6;
          VL_COFINS = CAST((:VL_BC_COFINS * ALIQ_COFINS) / 100 AS NUMERIC(15,2));
        END
  
       SELECT FIRST 1 COD_ITEM FROM TEMP_SUPORTE_SPEDC_0200 WHERE COD_BARRA_NUMERO = :BARRA_NUM INTO :COD_ITEM;
  
       IF ((:COD_ITEM IS NULL) OR (:COD_ITEM = 0)) THEN
          COD_ITEM = :COD_ITEM;
  
       SUSPEND;
  
       IF (:CST_COFINS = '01') THEN
        BEGIN
           SELECT COUNT(*) FROM TEMP_SUPORTE_SPEDC_M610 INTO :EXISTE;
           IF (:EXISTE = 0) THEN
              INSERT INTO TEMP_SUPORTE_SPEDC_M610 VALUES ('01', :VL_BC_COFINS, :VL_BC_COFINS);
           ELSE
              UPDATE TEMP_SUPORTE_SPEDC_M610 SET
               VL_REC_BRT = VL_REC_BRT + :VL_BC_COFINS,
               VL_BASE_CALCULO = VL_BASE_CALCULO + :VL_BC_COFINS;
        END
  
     IF ((:CST_COFINS = '04') OR (:CST_COFINS = '06') OR (:CST_COFINS = '07') OR (:CST_COFINS = '08') OR (:CST_COFINS = '09')) THEN
        BEGIN
           SELECT FIRST 1 NCM FROM PRODUTOS_FISCO WHERE CODIGO_BARRAS = :BARRA_NUM INTO :NCM;
           IF ((:NCM IS NULL) OR (:NCM = '99999999') OR (:NCM = '00000000') OR (TRIM(:NCM) = ''))  THEN
              NCM = '30049099';
           IF (
               (SUBSTRING(:NCM FROM 1 FOR 4) = '3001') OR
               ((SUBSTRING(:NCM FROM 1 FOR 4)= '3003') AND (:NCM <> '30039056')) OR
               ((SUBSTRING(:NCM FROM 1 FOR 4) = '3004') AND (:NCM <> '30049046')) OR
               (SUBSTRING(:NCM FROM 1 FOR 7) = '3002101') OR
               (SUBSTRING(:NCM FROM 1 FOR 7) = '3002102') OR
               (SUBSTRING(:NCM FROM 1 FOR 7) = '3002103') OR
               (SUBSTRING(:NCM FROM 1 FOR 7) = '3002201') OR
               (SUBSTRING(:NCM FROM 1 FOR 7) = '3002202') OR
               (SUBSTRING(:NCM FROM 1 FOR 7) = '3006301') OR
               (SUBSTRING(:NCM FROM 1 FOR 7) = '3006302') OR
               (:NCM ='30029020') OR (:NCM ='30029092') OR (:NCM ='30029099') OR (:NCM ='30051010') OR (:NCM ='30066000')
              ) THEN -- MEDICAMENTOS
             BEGIN
              SELECT COUNT(*) FROM TEMP_SUPORTE_SPEDC_M810 WHERE CST = :CST_COFINS AND NAT_REC = '201' INTO :EXISTE;
              IF (:EXISTE = 0) THEN
                 INSERT INTO TEMP_SUPORTE_SPEDC_M810 VALUES (:CST_COFINS, '201', :VL_ITEM);
              ELSE
                 UPDATE TEMP_SUPORTE_SPEDC_M810 SET VL_REC = VL_REC + :VL_ITEM WHERE CST = :CST_COFINS AND NAT_REC = '201';
             END
            ELSE
             BEGIN -- PERFUMARIA
               SELECT COUNT(*) FROM TEMP_SUPORTE_SPEDC_M810 WHERE CST = :CST_COFINS AND NAT_REC = '202' INTO :EXISTE;
               IF (:EXISTE = 0) THEN
                  INSERT INTO TEMP_SUPORTE_SPEDC_M810 VALUES (:CST_COFINS,'202', :VL_ITEM);
               ELSE
                  UPDATE TEMP_SUPORTE_SPEDC_M810 SET VL_REC = VL_REC + :VL_ITEM WHERE CST = :CST_COFINS AND NAT_REC = '202';
             END
        END
   END
END ^

ALTER PROCEDURE SP_SUPORTE_SPEDC_C491C495 RETURNS (COD_ITEM VARCHAR(100) CHARACTER SET NONE,
BARRA VARCHAR(14) CHARACTER SET NONE,
CFOP VARCHAR(4) CHARACTER SET NONE,
CST_PIS VARCHAR(3) CHARACTER SET NONE,
CST_COFINS VARCHAR(3) CHARACTER SET NONE,
TOTALPRODUTO NUMERIC(15, 2))
AS 
declare variable ENQ varchar(2);
declare variable COMANDO varchar(1000);
declare variable NCM varchar(20);
declare variable EXISTE integer;
BEGIN
  SELECT ENQUADRAMENTOTRIBUTARIO FROM PARAMETROS INTO :ENQ;
  IF (:ENQ = 'S') THEN
     ENQ = 'SN';
  ELSE
  IF (:ENQ = 'P') THEN
     ENQ = 'LP';
  ELSE
  IF (:ENQ = 'R') THEN
     ENQ = 'LR';
  ELSE
  IF ((:ENQ IS NULL) OR (:ENQ = '')) THEN
     ENQ = 'SN';

  FOR
     SELECT
      PAF_R05.CODIGO_PRODUTO_SERVICO,
      CASE
        WHEN PAF_R05.ALIQUOTA = '0000' THEN '5403'
        ELSE '5102'
      END, 
      SUM((CAST(PAF_R05.VALOR_UNITARIO AS NUMERIC(15,2)) / 100) * (CAST(PAF_R05.QUANTIDADE AS NUMERIC(15,3)) / 1000))
     FROM
      PAF_R05
     WHERE
      PAF_R05.INDICADOR_CANCELAMENTO = 'N' AND
      PAF_R05.NUMERO_FABRICACAO||PAF_R05.COO IN (SELECT COO FROM TEMP_COO_C)
     GROUP BY
      PAF_R05.CODIGO_PRODUTO_SERVICO,
      PAF_R05.ALIQUOTA
     INTO
      :BARRA,
      :CFOP,
      :TOTALPRODUTO
  DO
   BEGIN
     IF ((:TOTALPRODUTO IS NOT NULL) AND (:TOTALPRODUTO > 0)) THEN
      BEGIN
        SELECT COUNT(*) FROM PRODUTOS_FISCO WHERE CAST(CODIGO_BARRAS AS NUMERIC(15,0)) = CAST(:BARRA AS NUMERIC(15,0)) INTO :EXISTE;
        IF (:EXISTE > 0) THEN
         BEGIN
           COD_ITEM = 0;
           SELECT COD_ITEM FROM TEMP_SUPORTE_SPEDC_0200 WHERE COD_BARRA_NUMERO = CAST(:BARRA AS NUMERIC(15,0)) INTO :COD_ITEM;
           IF (:COD_ITEM > 0) THEN
            BEGIN
              SELECT FIRST 1 CST_PIS_COFINS_SAIDA, CST_PIS_COFINS_SAIDA FROM PRODUTOS_FISCO
              WHERE CAST(CODIGO_BARRAS AS NUMERIC(15,0)) = CAST(:BARRA AS NUMERIC(15,0))
              INTO :CST_PIS, :CST_COFINS;

              SUSPEND;
            END
         END
      END
   END

END ^

