ALTER PROCEDURE SP_SUPORTE_SPEDC_TEMPCOO (DATAINICIAL DATE,
DATAFINAL DATE)
AS 
declare variable COO varchar(100);
BEGIN
  DELETE FROM TEMP_COO_C;
  FOR
   SELECT NUMERO_FABRICACAO||COO
   FROM PAF_R04
   WHERE
    DATA_INICIO_EMISSAO IS NOT NULL AND
    TRIM(DATA_INICIO_EMISSAO) <> '' AND
    CAST(SUBSTRING(DATA_INICIO_EMISSAO FROM 1 FOR 2)|| '.'||SUBSTRING(DATA_INICIO_EMISSAO FROM 3 FOR 2)||'.20'||SUBSTRING(DATA_INICIO_EMISSAO FROM 5 FOR 2) AS DATE) >= :DATAINICIAL AND
    CAST(SUBSTRING(DATA_INICIO_EMISSAO FROM 1 FOR 2)|| '.'||SUBSTRING(DATA_INICIO_EMISSAO FROM 3 FOR 2)||'.20'||SUBSTRING(DATA_INICIO_EMISSAO FROM 5 FOR 2) AS DATE) <= :DATAFINAL AND
    CANCELAMENTO = 'N'
   INTO :COO
  DO
   BEGIN
     INSERT INTO TEMP_COO_C VALUES (:COO);
   END
END ^

ALTER PROCEDURE SP_SUPORTE_TRATA_CEST RETURNS (CEST VARCHAR(1000) CHARACTER SET NONE,
NCM VARCHAR(1000) CHARACTER SET NONE,
DESCRICAO VARCHAR(1000) CHARACTER SET NONE)
AS 
declare variable POSICAO integer;
declare variable TEMVIRGULA integer;
declare variable CESTAUXILIAR varchar(100);
BEGIN
 FOR
   SELECT CEST, NCM, DESCRICAO FROM CEST INTO :CEST, :NCM, :DESCRICAO
 DO
  BEGIN
    CESTAUXILIAR = REPLACE(:CEST, '.', '');
    TEMVIRGULA = 0;
    IF (POSITION(',' IN :NCM) > 0) THEN
     BEGIN
       POSICAO = POSITION(',' IN :NCM);
       UPDATE CEST SET
         CEST = :CESTAUXILIAR,
         NCM = SUBSTRING(:NCM FROM 1 FOR :POSICAO - 1)
       WHERE CEST = :CEST;
       NCM = SUBSTRING(:NCM FROM :POSICAO + 1 FOR 1000);

       WHILE (POSITION(',' IN :NCM) > 0) DO
        BEGIN
           TEMVIRGULA = 1;
           POSICAO = POSITION(',' IN :NCM);
           INSERT INTO CEST VALUES (:CESTAUXILIAR, SUBSTRING(:NCM FROM 1 FOR :POSICAO - 1), :DESCRICAO);
           NCM = SUBSTRING(:NCM FROM :POSICAO + 1 FOR 1000);
        END

       INSERT INTO CEST VALUES (:CESTAUXILIAR, :NCM, :DESCRICAO);
     END
    ELSE
     BEGIN
       UPDATE CEST SET
         CEST = :CESTAUXILIAR
       WHERE CEST = :CEST;
     END
  END
END ^

ALTER PROCEDURE SP_SUPORTE_ULTIMA_REDUCAO_ECFS RETURNS (NUMERO_FABRICACAO VARCHAR(100) CHARACTER SET NONE,
CRZ VARCHAR(10) CHARACTER SET NONE,
CRO VARCHAR(10) CHARACTER SET NONE,
VENDA_BRUTA_DIARIA VARCHAR(100) CHARACTER SET NONE)
AS 
BEGIN
  FOR
    SELECT DISTINCT PAF_R01.NUMERO_FABRICACAO FROM PAF_R01 INTO :NUMERO_FABRICACAO
  DO
   BEGIN
    SELECT
     FIRST 1
     PAF_R02.CRZ,
     PAF_R02.CRO, 
     PAF_R02.VENDA_BRUTA_DIARIA
    FROM
     PAF_R02
    WHERE
     PAF_R02.NUMERO_FABRICACAO = :NUMERO_FABRICACAO
    ORDER BY
     CAST(SUBSTRING(DATA_EMISSAO FROM 1 FOR 2)||'.'||
          SUBSTRING(DATA_EMISSAO FROM 3 FOR 2)||'.'||
          SUBSTRING(DATA_EMISSAO FROM 5 FOR 2) AS DATE) DESC
    INTO
     :CRZ, :CRO, :VENDA_BRUTA_DIARIA;

    SUSPEND;

   END
END ^

ALTER PROCEDURE SP_SUPORTE_VALORES_SINTEGRA (DATAINICIAL DATE,
DATAFINAL DATE)
AS 
declare variable CODIGO double precision;
declare variable BASE_ICMS numeric(15,2);
declare variable BASE_ICMS_ST numeric(15,2);
declare variable VALOR_ICMS numeric(15,2);
declare variable VALOR_ICMS_ST numeric(15,2);
declare variable VALOR_DESCONTO numeric(15,4);
declare variable VALOR_IPI numeric(15,2);
declare variable VALOR_OUTRASDESPESAS numeric(15,2);
declare variable VALOR_SEGURO numeric(15,2);
declare variable VALOR_FRETE numeric(15,2);
declare variable SUB_TOTAL numeric(15,2);
BEGIN
  UPDATE SINTEGRA_NF_ENTRADA_ITENS SET VALOR_OUTRASDESPESAS = 0 WHERE VALOR_OUTRASDESPESAS IS NULL;
  UPDATE SINTEGRA_NF_ENTRADA_ITENS SET VALOR_SEGURO = 0 WHERE VALOR_SEGURO IS NULL;
  UPDATE SINTEGRA_NF_ENTRADA_ITENS SET VALOR_FRETE = 0 WHERE VALOR_FRETE IS NULL;
  UPDATE SINTEGRA_NF_ENTRADA_ITENS SET VALOR_ISENTO = 0 WHERE VALOR_ISENTO IS NULL;
  UPDATE SINTEGRA_NF_ENTRADA_ITENS SET VALOR_ICMS_SUBTITUICAO = 0 WHERE VALOR_ICMS_SUBTITUICAO IS NULL;
  UPDATE SINTEGRA_NF_ENTRADA_ITENS SET MARGEM_VALOR_AGREGADO = 0 WHERE MARGEM_VALOR_AGREGADO IS NULL;
  UPDATE SINTEGRA_NF_ENTRADA_ITENS SET REDUCAO_BASE_ICMS = 0 WHERE REDUCAO_BASE_ICMS IS NULL;
  UPDATE SINTEGRA_NF_ENTRADA_ITENS SET REDUCAO_ICMS_ST = 0 WHERE REDUCAO_ICMS_ST IS NULL;
  UPDATE SINTEGRA_NF_ENTRADA_ITENS SET PERCENTUAL_ICMS_ST = 0 WHERE PERCENTUAL_ICMS_ST IS NULL;
  UPDATE SINTEGRA_NF_ENTRADA_ITENS SET PIS_BASE_CALCULO = 0 WHERE PIS_BASE_CALCULO IS NULL;
  UPDATE SINTEGRA_NF_ENTRADA_ITENS SET PIS_PERCENTUAL = 0 WHERE PIS_PERCENTUAL IS NULL;
  UPDATE SINTEGRA_NF_ENTRADA_ITENS SET PIS_VALOR = 0 WHERE PIS_VALOR IS NULL;
  UPDATE SINTEGRA_NF_ENTRADA_ITENS SET COFINS_BASE_CALCULO = 0 WHERE COFINS_BASE_CALCULO IS NULL;
  UPDATE SINTEGRA_NF_ENTRADA_ITENS SET COFINS_PERCENTUAL = 0 WHERE COFINS_PERCENTUAL IS NULL;
  UPDATE SINTEGRA_NF_ENTRADA_ITENS SET COFINS_VALOR = 0 WHERE COFINS_VALOR IS NULL;
  UPDATE SINTEGRA_NF_ENTRADA_ITENS SET S_TRIB = '60' WHERE S_TRIB IS NULL OR S_TRIB = '';
  UPDATE SINTEGRA_NF_ENTRADA_ITENS SET ALIQUOTA_ICMS = 0 WHERE ALIQUOTA_ICMS IS NULL;

  UPDATE SINTEGRA_NF_ENTRADA_ITENS SET
    SINTEGRA_NF_ENTRADA_ITENS.SUBTOTAL = SINTEGRA_NF_ENTRADA_ITENS.PRC_CUSTO * SINTEGRA_NF_ENTRADA_ITENS.QUANTIDADE
  WHERE DATAHORA >= :DATAINICIAL AND DATAHORA <= :DATAFINAL;

  FOR
    SELECT
      SINTEGRA_NF_ENTRADA_ITENS.COD_NF_ENTRADA,
      SUM(SINTEGRA_NF_ENTRADA_ITENS.BASE_ICMS),
      SUM(SINTEGRA_NF_ENTRADA_ITENS.BASE_ICMS_SUBST),
      SUM(SINTEGRA_NF_ENTRADA_ITENS.VALOR_ICMS),
      SUM(SINTEGRA_NF_ENTRADA_ITENS.VALOR_ICMS_SUBTITUICAO),
      SUM(SINTEGRA_NF_ENTRADA_ITENS.VALOR_DESCONTO),
      SUM(SINTEGRA_NF_ENTRADA_ITENS.VALOR_IPI),
      SUM(SINTEGRA_NF_ENTRADA_ITENS.VALOR_OUTRASDESPESAS),
      SUM(SINTEGRA_NF_ENTRADA_ITENS.VALOR_SEGURO),
      SUM(SINTEGRA_NF_ENTRADA_ITENS.VALOR_FRETE),
      SUM(SINTEGRA_NF_ENTRADA_ITENS.SUBTOTAL)
    FROM
      SINTEGRA_NF_ENTRADA_ITENS,
      SINTEGRA_NF_ENTRADA
    WHERE
      SINTEGRA_NF_ENTRADA_ITENS.COD_NF_ENTRADA = SINTEGRA_NF_ENTRADA.COD_NF_ENTRADA AND
      SINTEGRA_NF_ENTRADA.DATAHORA_RECEBIMENTO >= :DATAINICIAL AND
      SINTEGRA_NF_ENTRADA.DATAHORA_RECEBIMENTO <= :DATAFINAL
    GROUP BY
      SINTEGRA_NF_ENTRADA_ITENS.COD_NF_ENTRADA
    INTO
     :CODIGO,
     :BASE_ICMS,
     :BASE_ICMS_ST,
     :VALOR_ICMS,
     :VALOR_ICMS_ST,
     :VALOR_DESCONTO,
     :VALOR_IPI,
     :VALOR_OUTRASDESPESAS,
     :VALOR_SEGURO,
     :VALOR_FRETE,
     :SUB_TOTAL
  DO
   BEGIN
     UPDATE SINTEGRA_NF_ENTRADA SET
       SINTEGRA_NF_ENTRADA.BASE_ICMS = :BASE_ICMS,
       SINTEGRA_NF_ENTRADA.BASE_ICMS_SUBST = :BASE_ICMS_ST,
       SINTEGRA_NF_ENTRADA.VALOR_ICMS = :VALOR_ICMS,
       SINTEGRA_NF_ENTRADA.VALOR_ICMS_SUBST = :VALOR_ICMS_ST,
       SINTEGRA_NF_ENTRADA.DESCONTO = :VALOR_DESCONTO,
       SINTEGRA_NF_ENTRADA.VALOR_IPI = :VALOR_IPI,
       SINTEGRA_NF_ENTRADA.VALOR_SEGURO = :VALOR_SEGURO,
       SINTEGRA_NF_ENTRADA.VALOR_FRETE = :VALOR_FRETE,
       SINTEGRA_NF_ENTRADA.OUTRAS_DESPESAS = :VALOR_OUTRASDESPESAS,
       SINTEGRA_NF_ENTRADA.VALOR_TOTALPRODUTO = :SUB_TOTAL,
       SINTEGRA_NF_ENTRADA.VALOR_TOTALNF = :SUB_TOTAL +
                                           :VALOR_ICMS_ST +
                                           :VALOR_SEGURO +
                                           :VALOR_FRETE +
                                           :VALOR_OUTRASDESPESAS +
                                           :VALOR_IPI -
                                           :VALOR_DESCONTO
     WHERE
       SINTEGRA_NF_ENTRADA.COD_NF_ENTRADA = :CODIGO;
   END

END ^

ALTER PROCEDURE SP_SUPORTE_VERIFICA_COMPRA (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (FILIAL INTEGER,
ID_PRODUTO DOUBLE PRECISION)
AS 
declare variable TIPO_VENDA varchar(1);
declare variable NCOMPRAS integer;
BEGIN
  FOR
    SELECT CD_FILIAL
    FROM FILIAIS
    INTO :FILIAL
  DO
   BEGIN
      FOR
        SELECT ITENS_COMPRA.ID_PRODUTO
        FROM COMPRAS, ITENS_COMPRA
        WHERE
          COMPRAS.CD_FILIAL = :FILIAL AND
          COMPRAS.DT_PEDIDO >= :DATAINICIAL AND COMPRAS.DT_PEDIDO <= :DATAFINAL AND
          COMPRAS.STATUS = 'C' AND
          COMPRAS.CD_COMPRAS = ITENS_COMPRA.CD_COMPRAS
        GROUP BY ITENS_COMPRA.ID_PRODUTO
        INTO :ID_PRODUTO
      DO
       BEGIN
         NCOMPRAS = 0;
         FOR
           SELECT LANCAMENTOS.TIPO_VENDA
           FROM LANCAMENTOS
           WHERE LANCAMENTOS.CD_FILIAL = :FILIAL AND LANCAMENTOS.ID_PRODUTO = :ID_PRODUTO AND
                 LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL
           ORDER BY LANCAMENTOS.DATA_LANCAMENTO, LANCAMENTOS.HORA
           INTO :TIPO_VENDA
         DO
          BEGIN
            IF (:TIPO_VENDA = 'C') THEN
             BEGIN
               IF (NCOMPRAS = 0) THEN
                BEGIN
                  NCOMPRAS = 1;
                END
               ELSE
                BEGIN
                  SUSPEND;
                  BREAK;
                END
             END
            ELSE
             BEGIN
               IF (:TIPO_VENDA = 'V') THEN
                BEGIN
                  NCOMPRAS = 0;
                END
             END
          END
       END
  END
END ^

ALTER PROCEDURE SP_SUPORTE_VERIFICA_COMPRA2 (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (CD_COMPRAS DOUBLE PRECISION,
NOTA_FISCAL VARCHAR(100) CHARACTER SET NONE,
DATA DATE,
TOTALPRODUTOS DOUBLE PRECISION,
TOTALPRODUTOSITENS DOUBLE PRECISION)
AS 
declare variable DIFERENCA double precision;
BEGIN
  FOR
    SELECT COMPRAS.CD_COMPRAS, COMPRAS.NOTA_FISCAL, COMPRAS.DT_PEDIDO, COMPRAS.VL_TOTALPRODUTOS
    FROM COMPRAS
    WHERE
      COMPRAS.DT_PEDIDO >= :DATAINICIAL AND COMPRAS.DT_PEDIDO <= :DATAFINAL AND
      COMPRAS.STATUS = 'C'
    INTO :CD_COMPRAS, :NOTA_FISCAL, :DATA, :TOTALPRODUTOS
  DO
   BEGIN
     SELECT SUM(ITENS_COMPRA.VL_TOTAL)
     FROM ITENS_COMPRA
     WHERE CD_COMPRAS = :CD_COMPRAS
     INTO :TOTALPRODUTOSITENS;

     IF (:TOTALPRODUTOSITENS IS NULL) THEN
        TOTALPRODUTOSITENS = 0;

     DIFERENCA = 0;
     DIFERENCA = :TOTALPRODUTOS - :TOTALPRODUTOSITENS;

     IF ((:DIFERENCA > 0.02) OR (:DIFERENCA < -0.02)) THEN
        SUSPEND;
   END
END ^

ALTER PROCEDURE SP_SUP_POSICAOESTOQUEDATAPAF (CD_FILIAL DOUBLE PRECISION,
DATA DOUBLE PRECISION,
HORA DOUBLE PRECISION)
AS 
declare variable ID_PRODUTO double precision;
declare variable ESTOQUEPRODUTO double precision;
declare variable COMANDO varchar(1000);
BEGIN
  COMANDO = 'SELECT ID_PRODUTO, ESTOQUE_'||CAST(:CD_FILIAL AS INTEGER)||' FROM PRODUTOS';
  FOR
   EXECUTE STATEMENT :COMANDO
   INTO :ID_PRODUTO, :ESTOQUEPRODUTO
  DO
   BEGIN
     UPDATE PRODUTOS SET
      QUANTIDADE_ENTRADA = :DATA,
      QUANTIDADE_SAIDA = :HORA,
      QUANTIDADE_TRANSFERIDA = :ESTOQUEPRODUTO
     WHERE ID_PRODUTO = :ID_PRODUTO;
   END
END ^

ALTER PROCEDURE SP_TEMP_COO (NUMEROFABRICACAO VARCHAR(20) CHARACTER SET NONE,
DATAINICIAL VARCHAR(12) CHARACTER SET NONE)
AS 
declare variable COO varchar(6);
declare variable TOTALIZADOR varchar(100);
declare variable TEMCANCELAMENTO varchar(1);
declare variable CANCELAMENTO varchar(10);
BEGIN
  DELETE FROM TEMP_COO;
  CANCELAMENTO = 'N';
  FOR
    SELECT
     PAF_R03.TOTALIZADOR_PARCIAL
    FROM
     PAF_R03, PAF_R02
    WHERE
     PAF_R02.ID_PAF_R02 = PAF_R03.ID_PAF_R02 AND
     PAF_R02.NUMERO_FABRICACAO = :NUMEROFABRICACAO AND
     PAF_R02.DATA_MOVIMENTO = :DATAINICIAL
    INTO
     :TOTALIZADOR
  DO
   BEGIN
     IF (:TOTALIZADOR = 'Can-T') THEN
      BEGIN
       TEMCANCELAMENTO = 'S';
       BREAK;
      END
   END


  FOR
   SELECT COO, CANCELAMENTO FROM PAF_R04
   WHERE NUMERO_FABRICACAO = :NUMEROFABRICACAO AND
   DATA_INICIO_EMISSAO = :DATAINICIAL AND
   CANCELAMENTO = 'N'
   INTO :COO, :CANCELAMENTO
  DO
   BEGIN
     --IF ((:CANCELAMENTO = 'N') OR ((:CANCELAMENTO = 'S') AND (:TEMCANCELAMENTO = 'S'))) THEN
     INSERT INTO TEMP_COO VALUES (:COO);
   END
END ^

