ALTER PROCEDURE SP_TEMP_COO_PAFR05 (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (BARRA VARCHAR(14) CHARACTER SET NONE,
CODIGO_BARRAS VARCHAR(14) CHARACTER SET NONE)
AS 
declare variable COO varchar(6);
declare variable BARRA2 varchar(14);
declare variable PRIMEIRONUMERO varchar(1);
declare variable EXISTE integer;
declare variable ID_PRODUTO double precision;
BEGIN
  DELETE FROM TEMP_COO;
  FOR
   SELECT COO
   FROM PAF_R04 WHERE
   DATA_INICIO_EMISSAO IS NOT NULL AND
   TRIM(DATA_INICIO_EMISSAO) <> '' AND
    CAST(SUBSTRING(DATA_INICIO_EMISSAO FROM 3 FOR 2)|| '/'||SUBSTRING(DATA_INICIO_EMISSAO FROM 1 FOR 2)||'/20'||SUBSTRING(DATA_INICIO_EMISSAO FROM 5 FOR 2) AS DATE) >= :DATAINICIAL AND
    CAST(SUBSTRING(DATA_INICIO_EMISSAO FROM 3 FOR 2)|| '/'||SUBSTRING(DATA_INICIO_EMISSAO FROM 1 FOR 2)||'/20'||SUBSTRING(DATA_INICIO_EMISSAO FROM 5 FOR 2) AS DATE) <= :DATAFINAL
   INTO :COO
  DO
   BEGIN
     INSERT INTO TEMP_COO VALUES (:COO);
   END

  FOR
   SELECT DISTINCT CODIGO_PRODUTO_SERVICO
   FROM PAF_R05
   WHERE COO IN (SELECT COO FROM TEMP_COO)
   INTO :BARRA
  DO
   BEGIN
     EXISTE = 0;
     ID_PRODUTO = 0;
     CODIGO_BARRAS = '';
     SELECT DISTINCT ID_PRODUTO FROM VENDAS WHERE NUMERO = :COO AND CODIGO_BARRA = :BARRA INTO :ID_PRODUTO;
     IF (ID_PRODUTO > 0) THEN
      BEGIN
        SELECT CODIGO_BARRAS_1 FROM PRODUTOS WHERE ID_PRODUTO = :ID_PRODUTO INTO :CODIGO_BARRAS;
        IF (:CODIGO_BARRAS <> '') THEN
         BEGIN
           UPDATE PAF_R05 SET CODIGO_PRODUTO_SERVICO = :CODIGO_BARRAS WHERE COO = :COO AND CODIGO_PRODUTO_SERVICO = :BARRA;
         END
      END

     IF (:EXISTE = 0) THEN
      BEGIN
        SELECT COUNT(*) FROM PRODUTOS
        WHERE CODIGO_BARRAS_1 = :BARRA OR CODIGO_BARRAS_2 = :BARRA
        INTO :EXISTE;

        IF (:EXISTE = 0) THEN
         BEGIN
           CODIGO_BARRAS = '';
           SELECT CODIGO_BARRAS_1 FROM PRODUTOS WHERE ID_PRODUTO = CAST(:BARRA AS DOUBLE PRECISION) INTO :CODIGO_BARRAS;
           IF (CODIGO_BARRAS = '') THEN
            BEGIN
              BARRA2 = :BARRA;
              PRIMEIRONUMERO = SUBSTRING(:BARRA2 FROM 1 FOR 1);
              WHILE (:PRIMEIRONUMERO = '0') DO
               BEGIN
                 BARRA2 = SUBSTRING(:BARRA2 FROM 2 FOR 14);
                 PRIMEIRONUMERO = SUBSTRING(:BARRA2 FROM 1 FOR 1);
      
                 SELECT COUNT(*) FROM PRODUTOS
                 WHERE CODIGO_BARRAS_1 = :BARRA2 OR CODIGO_BARRAS_2 = :BARRA2
                 INTO :EXISTE;
      
                 IF (:EXISTE > 0) THEN
                  BEGIN
                    BREAK;
                  END
               END

              IF (:EXISTE > 0) THEN
               BEGIN
                 UPDATE PAF_R05 SET CODIGO_PRODUTO_SERVICO = :CODIGO_BARRAS WHERE COO = :COO AND CODIGO_PRODUTO_SERVICO = :BARRA;
               END
              ELSE
               BEGIN
                 SUSPEND;
               END
            END
           ELSE
            BEGIN
              UPDATE PAF_R05 SET CODIGO_PRODUTO_SERVICO = :CODIGO_BARRAS WHERE COO = :COO AND CODIGO_PRODUTO_SERVICO = :BARRA;
            END
         END
      END
   END
END ^

