     CAST(SUBSTRING(DATA_MOVIMENTO FROM 3 FOR 2)||'/'||SUBSTRING(DATA_MOVIMENTO FROM 1 FOR 2)||'/20'||SUBSTRING(DATA_MOVIMENTO FROM 5 FOR 2) AS DATE) <= :DATAFINAL
    INTO
     :CRZ
  DO
   BEGIN
     INSERT INTO TEMP_CRZ VALUES(:CRZ);
   END
END ^

ALTER PROCEDURE SP_TOTALREGISTROSBANCO RETURNS (TABELA VARCHAR(31) CHARACTER SET NONE,
QTD_REG INTEGER)
AS 
declare variable comando varchar(100); 
 declare variable qtdtot integer; 
 declare variable qtdtab integer; 
begin 
 qtdtot = 0; 
 qtdtab = 0;


 for select rdb$relation_name 
   from rdb$relations 
   where rdb$flags = 1 and rdb$view_blr is null 
   order by 1 
   into :tabela do 
 begin 
   qtdtab = qtdtab + 1;
   comando = 'select count(*) from ' || :tabela; 
   execute statement :comando into :qtd_reg; 
   qtdtot = :qtdtot + :qtd_reg; 
   suspend; 
 end 
 tabela = :qtdtab || ' Tabelas - Total:'; 
 qtd_reg = :qtdtot; 
 suspend; 
end ^

ALTER PROCEDURE SP_TROCA_CARTAONFCE AS 
declare variable TPINTEGRA varchar(10000);
BEGIN
  TPINTEGRA = '</vPag><card><tpIntegra>2</tpIntegra></card></detPag></pag>';

  UPDATE NFCE SET
   ARQUIVO = SUBSTRING(NFCE.ARQUIVO FROM 1 FOR POSITION('</vPag>', NFCE.ARQUIVO) - 1) ||
             :TPINTEGRA ||
             SUBSTRING(NFCE.ARQUIVO FROM POSITION('</pag>', NFCE.ARQUIVO) + 6 FOR 10000)
  WHERE NFCE.TIPOEMISSAO = 'O' AND NFCE.STATUS = 'G' AND ((NFCE.PROTOCOLO IS NULL) OR (NFCE.PROTOCOLO = '')) AND
        ((POSITION('<tPag>03', NFCE.ARQUIVO) > 0) OR (POSITION('<tPag>04', NFCE.ARQUIVO) > 0));
END ^

