ALTER PROCEDURE SP_TROCA_VERSAONFCE AS 
declare variable VERSAO varchar(10000);
BEGIN
  VERSAO = '4.00';

  UPDATE NFCE SET
   ARQUIVO = SUBSTRING(NFCE.ARQUIVO FROM 1 FOR POSITION('3.10', NFCE.ARQUIVO) - 1) ||
             :VERSAO ||
             SUBSTRING(NFCE.ARQUIVO FROM POSITION('" Id', NFCE.ARQUIVO) FOR 10000)
  WHERE NFCE.TIPOEMISSAO = 'O' AND NFCE.STATUS = 'G' AND POSITION('"3.10"', NFCE.ARQUIVO) > 0;
