ALTER PROCEDURE SP_ULTIMOCUSTO_PEDIDOGESTAO (TABELA VARCHAR(100) CHARACTER SET NONE)
AS 
declare variable COMANDO varchar(1000);
declare variable COMANDO1 varchar(1000);
declare variable ID_PRODUTO double precision;
declare variable ULTIMOCUSTO double precision;
BEGIN
  COMANDO = '';
  COMANDO = 'SELECT ID_PRODUTO FROM ' || :TABELA;
  FOR
    EXECUTE STATEMENT :COMANDO INTO :ID_PRODUTO
  DO
   BEGIN
      ULTIMOCUSTO = 0;
      SELECT
       FIRST 1
       CASE
        WHEN ITENS_COMPRA.VL_DESCONTO IS NOT NULL  AND ITENS_COMPRA.DESCONTO_OUTROS IS NOT NULL THEN ((ITENS_COMPRA.VL_UNITARIO / ITENS_COMPRA.QT_EMBALAGEM) - ITENS_COMPRA.VL_DESCONTO - ITENS_COMPRA.DESCONTO_OUTROS)
        WHEN ITENS_COMPRA.VL_DESCONTO IS NOT NULL  THEN ((ITENS_COMPRA.VL_UNITARIO / ITENS_COMPRA.QT_EMBALAGEM) - ITENS_COMPRA.VL_DESCONTO)
        WHEN ITENS_COMPRA.DESCONTO_OUTROS IS NOT NULL  THEN ((ITENS_COMPRA.VL_UNITARIO / ITENS_COMPRA.QT_EMBALAGEM) - ITENS_COMPRA.DESCONTO_OUTROS)
        ELSE ITENS_COMPRA.VL_UNITARIO
       END
      FROM ITENS_COMPRA, COMPRAS
      WHERE ITENS_COMPRA.ID_PRODUTO = 141590 AND
            COMPRAS.CD_COMPRAS = ITENS_COMPRA.CD_COMPRAS AND
            COMPRAS.DT_ENTRADA >= CURRENT_DATE - 60 AND
            COMPRAS.STATUS = 'C'
       ORDER BY COMPRAS.DT_ENTRADA DESC
      INTO
       :ULTIMOCUSTO;

      IF ((:ULTIMOCUSTO IS NOT NULL) AND (:ULTIMOCUSTO > 0)) THEN
       BEGIN
         COMANDO1 = '';
         COMANDO1 = 'UPDATE ' || :TABELA || ' SET '||
                    ' VL_UNITARIO = ' || :ULTIMOCUSTO || ' ' ||
                    'WHERE ID_PRODUTO = ' || :ID_PRODUTO;
         EXECUTE STATEMENT :COMANDO1;
       END
   END
END ^

ALTER PROCEDURE SP_VENDASCHEQUE RETURNS (CD_VENDA DOUBLE PRECISION,
ID_VENDA VARCHAR(15) CHARACTER SET NONE,
ENTREGA VARCHAR(3) CHARACTER SET NONE,
CHEQUE VARCHAR(10) CHARACTER SET NONE,
VALOR DOUBLE PRECISION,
CLIENTE VARCHAR(100) CHARACTER SET NONE)
AS 
DECLARE VARIABLE NUMERO_VENDAS INTEGER;
BEGIN
  FOR
   SELECT
    VENDAS.CD_VENDA,
    CASE
     WHEN (VENDAS.ID_VENDA IS NOT NULL) OR (VENDAS.ID_VENDA = '') THEN VENDAS.ID_VENDA
     WHEN VENDAS.ID_VENDA IS NULL THEN 0
    END,
    CASE
      WHEN VENDAS.ENTREGA = 'S' THEN 'SIM'
      WHEN VENDAS.ENTREGA = 'N' THEN 'NAO'
    END
   FROM
    VENDAS
   WHERE
    VENDAS.DATA_CAIXA = CURRENT_DATE AND
    VENDAS.CONCLUIDO = 'S'
   GROUP BY
    VENDAS.CD_VENDA,
    VENDAS.ID_VENDA,
    VENDAS.ENTREGA
   INTO
    :CD_VENDA,
    :ID_VENDA,
    :ENTREGA
  DO
   BEGIN
     NUMERO_VENDAS = 0;
     FOR
       SELECT
        CLIENTES.NOME,
        CASE
          WHEN VENDAS_FP.CD_FORMA_PAGAMENTO = 4 THEN 'PRE-DATADO'
          WHEN VENDAS_FP.CD_FORMA_PAGAMENTO = 6 THEN 'A VISTA'
        END,
        VENDAS_FP.VALOR
       FROM
        VENDAS_FP,
        CLIENTES
       WHERE
        VENDAS_FP.CD_CLIENTE = CLIENTES.CD_CLIENTE AND
        (VENDAS_FP.CD_FORMA_PAGAMENTO = 4 OR VENDAS_FP.CD_FORMA_PAGAMENTO = 6) AND
        VENDAS_FP.CD_VENDA = :CD_VENDA
       INTO
        :CLIENTE,
        :CHEQUE,
        :VALOR
     DO
      BEGIN
        SUSPEND;
      END
   END
END ^

ALTER PROCEDURE SP_VENDAS_FORMA_PAGAMENTO RETURNS (DINHEIRO DOUBLE PRECISION,
CARTAO DOUBLE PRECISION,
CARTAO_CREDITO DOUBLE PRECISION,
CARTAO_DEBITO DOUBLE PRECISION,
MASTERCARD DOUBLE PRECISION,
VISA DOUBLE PRECISION,
DINERS DOUBLE PRECISION,
AMEX DOUBLE PRECISION,
ELECTRON DOUBLE PRECISION,
REDESHOP DOUBLE PRECISION,
CONVENIO DOUBLE PRECISION,
CHEQUE_PRE DOUBLE PRECISION,
CREDIARIO DOUBLE PRECISION,
CHEQUE_A_VISTA DOUBLE PRECISION,
RETIRADAS DOUBLE PRECISION,
VENDAS_VISTA DOUBLE PRECISION,
VENDAS_PRAZO DOUBLE PRECISION,
TOTAL_VENDAS DOUBLE PRECISION,
TOTAL_VENDAS_ANTERIOR DOUBLE PRECISION,
TOTAL_VENDAS_ATUAL DOUBLE PRECISION,
TOTAL_COMPRAS DOUBLE PRECISION,
TOTAL_COMPRAS_ANTERIOR DOUBLE PRECISION,
TOTAL_COMPRAS_ATUAL DOUBLE PRECISION,
TOTAL_CLIENTES_MES DOUBLE PRECISION,
TOTAL_CLIENTES_DIA DOUBLE PRECISION,
MEDIA_CLIENTE DOUBLE PRECISION,
TOTAL_ENTREGAS_DIA DOUBLE PRECISION,
TOTAL_ENTREGAS_MES DOUBLE PRECISION,
MEDIA_ENTREGA DOUBLE PRECISION,
TOTAL_ENTREGAS_VALOR_DIA DOUBLE PRECISION,
TOTAL_ENTREGAS_VALOR_MES DOUBLE PRECISION,
OUTROS DOUBLE PRECISION,
MEDIA_VENDAS DOUBLE PRECISION,
MEDIA_COMPRAS DOUBLE PRECISION,
OUTROS_DEBITO DOUBLE PRECISION)
AS 
DECLARE VARIABLE VALOR DOUBLE PRECISION;
DECLARE VARIABLE TIPO_CARTAO VARCHAR(1);
DECLARE VARIABLE CD_CARTAO DOUBLE PRECISION;
DECLARE VARIABLE DATA_RESUMIDO DATE;
DECLARE VARIABLE DIA_ATUAL VARCHAR(2);
DECLARE VARIABLE MES_ATUAL VARCHAR(2);
DECLARE VARIABLE ANO_ATUAL VARCHAR(4);
DECLARE VARIABLE MES_ANTERIOR VARCHAR(2);
DECLARE VARIABLE ANO_ANTERIOR VARCHAR(4);
DECLARE VARIABLE DATA_INICIAL_ANTERIOR DATE;
DECLARE VARIABLE DATA_FINAL_ANTERIOR DATE;
DECLARE VARIABLE DATA_INICIAL_ATUAL DATE;
DECLARE VARIABLE DIFERENCA INTEGER;
DECLARE VARIABLE DATA_INICIAL DATE;
DECLARE VARIABLE DATA_FINAL DATE;
DECLARE VARIABLE DATA DATE;
DECLARE VARIABLE FILIAL DOUBLE PRECISION;
DECLARE VARIABLE CD_FILIAL DOUBLE PRECISION;
DECLARE VARIABLE NUMERO_DIAS DOUBLE PRECISION;
DECLARE VARIABLE DINHEIRO_C DOUBLE PRECISION;
DECLARE VARIABLE CARTAO_C DOUBLE PRECISION;
DECLARE VARIABLE CONVENIO_C DOUBLE PRECISION;
DECLARE VARIABLE CHEQUE_PRE_C DOUBLE PRECISION;
DECLARE VARIABLE CHEQUE_A_VISTA_C DOUBLE PRECISION;
DECLARE VARIABLE CARTAO_DEBITO_C DOUBLE PRECISION;
DECLARE VARIABLE CARTAO_CREDITO_C DOUBLE PRECISION;
DECLARE VARIABLE VISA_C DOUBLE PRECISION;
DECLARE VARIABLE MASTERCARD_C DOUBLE PRECISION;
DECLARE VARIABLE DINERS_C DOUBLE PRECISION;
DECLARE VARIABLE AMEX_C DOUBLE PRECISION;
DECLARE VARIABLE ELECTRON_C DOUBLE PRECISION;
DECLARE VARIABLE REDESHOP_C DOUBLE PRECISION;
DECLARE VARIABLE OUTROS_C DOUBLE PRECISION;
DECLARE VARIABLE OUTROS_DEBITO_C DOUBLE PRECISION;
DECLARE VARIABLE CREDIARIO_C DOUBLE PRECISION;
DECLARE VARIABLE TOTAL_VENDAS_ANTERIOR_C DOUBLE PRECISION;
DECLARE VARIABLE TOTAL_VENDAS_ATUAL_C DOUBLE PRECISION;
DECLARE VARIABLE TOTAL_CLIENTES_MES_C DOUBLE PRECISION;
DECLARE VARIABLE TOTAL_CLIENTES_DIA_C DOUBLE PRECISION;
DECLARE VARIABLE TOTAL_ENTREGAS_MES_C DOUBLE PRECISION;
DECLARE VARIABLE TOTAL_ENTREGAS_DIA_C DOUBLE PRECISION;
DECLARE VARIABLE TOTAL_ENTREGAS_VALOR_MES_C DOUBLE PRECISION;
DECLARE VARIABLE TOTAL_ENTREGAS_VALOR_DIA_C DOUBLE PRECISION;
BEGIN
  DATA_INICIAL = CURRENT_DATE - 3;
  DATA_FINAL = CURRENT_DATE;
  DIFERENCA = :DATA_FINAL - :DATA_INICIAL;
  WHILE (DIFERENCA <> 0) DO
   BEGIN
    DATA = :DATA_INICIAL + :DIFERENCA;
    NUMERO_DIAS = CAST(EXTRACT(DAY FROM :DATA) AS DOUBLE PRECISION);
    FOR
      SELECT
       CD_FILIAL
      FROM
       FILIAIS
      WHERE
       EXPORTAR = 'S'
      INTO
       :FILIAL
    DO
     BEGIN
            /*VENDAS A DINHEIRO*/
            SELECT
             SUM(CAIXA.VALOR)
            FROM
             CAIXA
            WHERE
             CAIXA.CD_FILIAL = :FILIAL AND
             CAIXA.DATA = :DATA AND
             CAIXA.CD_FORMA_PAGAMENTO = 1 AND
             CAIXA.TIPO_VENDA = 'V'
            INTO
             :DINHEIRO;
            
            /*CANCELAMENTOS A DINHEIRO*/
            SELECT
             SUM(CAIXA.VALOR)
            FROM
             CAIXA
            WHERE
             CAIXA.CD_FILIAL = :FILIAL AND
             CAIXA.DATA = :DATA AND
             CAIXA.CD_FORMA_PAGAMENTO = 1 AND
             CAIXA.TIPO_VENDA = 'D'
            INTO
             :DINHEIRO_C;

            IF (:DINHEIRO IS NULL) THEN
              DINHEIRO = 0;
            IF (:DINHEIRO_C IS NULL) THEN
              DINHEIRO_C = 0;
            DINHEIRO = :DINHEIRO - :DINHEIRO_C;

            /* VENDAS A CARTAO */
            SELECT
             SUM(CAIXA.VALOR)
            FROM
             CAIXA
            WHERE
             CAIXA.CD_FILIAL = :FILIAL AND
             CAIXA.DATA = :DATA AND
             CAIXA.CD_FORMA_PAGAMENTO = 2 AND
             CAIXA.TIPO_VENDA = 'V'
            INTO
             :CARTAO;
        
            /* CANCELAMENTOS A CARTAO */
            SELECT
             SUM(CAIXA.VALOR)
            FROM
             CAIXA
            WHERE
             CAIXA.CD_FILIAL = :FILIAL AND
             CAIXA.DATA = :DATA AND
             CAIXA.CD_FORMA_PAGAMENTO = 2 AND
             CAIXA.TIPO_VENDA = 'D'
            INTO
             :CARTAO;

            IF (:CARTAO IS NULL) THEN
               CARTAO = 0;
            IF (:CARTAO_C IS NULL) THEN
               CARTAO_C = 0;
            CARTAO = :CARTAO - :CARTAO_C;

            CARTAO_DEBITO = 0;
            CARTAO_CREDITO = 0;
            FOR
                SELECT
                 CAIXA.TIPO_CARTAO,
                 SUM(CAIXA.VALOR)
                FROM
                 CAIXA
                WHERE
                 CAIXA.CD_FILIAL = :FILIAL AND
                 CAIXA.DATA = :DATA AND
                 CAIXA.CD_FORMA_PAGAMENTO = 2 AND
                 CAIXA.TIPO_VENDA = 'V'
                GROUP BY
                 CAIXA.TIPO_CARTAO
                INTO
                 :TIPO_CARTAO,
                 :VALOR
            DO
             BEGIN
                IF (TIPO_CARTAO = 'D') THEN
                 BEGIN
                   CARTAO_DEBITO = :CARTAO_DEBITO + :VALOR;
                 END
                ELSE
                 BEGIN
                   CARTAO_CREDITO = :CARTAO_CREDITO + :VALOR;
                 END
             END

            IF (:CARTAO_CREDITO IS NULL) THEN
               CARTAO_CREDITO = 0;
            IF (:CARTAO_DEBITO IS NULL) THEN
               CARTAO_DEBITO = 0;

            CARTAO_DEBITO_C = 0;
            CARTAO_CREDITO_C = 0;
            FOR
                SELECT
                 CAIXA.TIPO_CARTAO,
                 SUM(CAIXA.VALOR)
                FROM
                 CAIXA
                WHERE
                 CAIXA.CD_FILIAL = :FILIAL AND
                 CAIXA.DATA = :DATA AND
                 CAIXA.CD_FORMA_PAGAMENTO = 2 AND
                 CAIXA.TIPO_VENDA = 'D'
                GROUP BY
                 CAIXA.TIPO_CARTAO
                INTO
                 :TIPO_CARTAO,
                 :VALOR
            DO
             BEGIN
                IF (TIPO_CARTAO = 'D') THEN
                 BEGIN
                   CARTAO_DEBITO_C = :CARTAO_DEBITO_C + :VALOR;
                 END
                ELSE
                 BEGIN
                   CARTAO_CREDITO_C = :CARTAO_CREDITO_C + :VALOR;
                 END
             END

            IF (:CARTAO_CREDITO_C IS NULL) THEN
               CARTAO_CREDITO_C = 0;
            IF (:CARTAO_DEBITO_C IS NULL) THEN
               CARTAO_DEBITO_C = 0;

            CARTAO_CREDITO = :CARTAO_CREDITO - :CARTAO_CREDITO_C;
            CARTAO_DEBITO = :CARTAO_DEBITO - :CARTAO_DEBITO_C;

            VISA = 0;
            MASTERCARD = 0;
            DINERS = 0;
            AMEX = 0;
            ELECTRON = 0;
            REDESHOP = 0;
            OUTROS = 0;
            OUTROS_DEBITO = 0;
            FOR
                SELECT
                 CARTOES.CD_CARTAO,
                 CARTOES.TIPO_CARTAO,
                 SUM(CAIXA.VALOR)
                FROM
                 CAIXA, CARTOES
                WHERE
                 CAIXA.CD_CARTAO = CARTOES.CD_CARTAO AND
                 CAIXA.CD_FILIAL = :FILIAL AND
                 CAIXA.DATA = :DATA AND
                 CAIXA.CD_FORMA_PAGAMENTO = 2 AND
                 CAIXA.CD_CARTAO IS NOT NULL AND
                 CAIXA.CD_CARTAO <> 0 AND
                 CAIXA.TIPO_VENDA = 'V'
                GROUP BY
                 CARTOES.CD_CARTAO,
                 CARTOES.TIPO_CARTAO
                INTO
                 :CD_CARTAO,
                 :TIPO_CARTAO,
                 :VALOR
            DO
             BEGIN
                IF (CD_CARTAO = 1) THEN
                 BEGIN
                   VISA = :VISA + :VALOR;
                 END
                ELSE
                IF (CD_CARTAO = 2) THEN
                 BEGIN
                   MASTERCARD = :MASTERCARD + :VALOR;
                 END
                ELSE
                IF (CD_CARTAO = 3) THEN
                 BEGIN
                   DINERS = :DINERS + :VALOR;
                 END
                ELSE
                IF (CD_CARTAO = 4) THEN
                 BEGIN
                   AMEX = :AMEX + :VALOR;
                 END
                ELSE
                IF (CD_CARTAO = 5) THEN
                 BEGIN
                   ELECTRON = :ELECTRON + :VALOR;
                 END
                ELSE
                IF (CD_CARTAO = 6) THEN
                 BEGIN
                   REDESHOP = :REDESHOP + :VALOR;
                 END
                ELSE
                 BEGIN
                   IF (:TIPO_CARTAO = 'C') THEN
                    BEGIN
                      OUTROS = :OUTROS + :VALOR;
                    END
                   ELSE
                    BEGIN
                      OUTROS_DEBITO = :OUTROS_DEBITO + :VALOR;
                    END
                 END
             END
        
            IF (:VISA IS NULL) THEN
                VISA = 0;
            IF (:MASTERCARD IS NULL) THEN
                MASTERCARD = 0;
            IF (:DINERS IS NULL) THEN
                DINERS = 0;
            IF (:AMEX IS NULL) THEN
                AMEX = 0;
            IF (:ELECTRON IS NULL) THEN
                ELECTRON = 0;
            IF (:REDESHOP IS NULL) THEN
                REDESHOP = 0;
            IF (:OUTROS IS NULL) THEN
                OUTROS = 0;
            IF (:OUTROS_DEBITO IS NULL) THEN
                OUTROS_DEBITO = 0;

            VISA_C = 0;
            MASTERCARD_C = 0;
            DINERS_C = 0;
            AMEX_C = 0;
            ELECTRON_C = 0;
            REDESHOP_C = 0;
            OUTROS_C = 0;
            OUTROS_DEBITO_C = 0;
            FOR
                SELECT
                 CARTOES.CD_CARTAO,
                 CARTOES.TIPO_CARTAO,
                 SUM(CAIXA.VALOR)
                FROM
                 CAIXA, CARTOES
                WHERE
                 CAIXA.CD_CARTAO = CARTOES.CD_CARTAO AND
                 CAIXA.CD_FILIAL = :FILIAL AND
                 CAIXA.DATA = :DATA AND
                 CAIXA.CD_FORMA_PAGAMENTO = 2 AND
                 CAIXA.CD_CARTAO IS NOT NULL AND
                 CAIXA.CD_CARTAO <> 0 AND
                 CAIXA.TIPO_VENDA = 'D'
                GROUP BY
                 CARTOES.CD_CARTAO,
                 CARTOES.TIPO_CARTAO
                INTO
                 :CD_CARTAO,
                 :TIPO_CARTAO,
                 :VALOR
            DO
             BEGIN
                IF (CD_CARTAO = 1) THEN
                 BEGIN
                   VISA_C = :VISA_C + :VALOR;
                 END
                ELSE
                IF (CD_CARTAO = 2) THEN
                 BEGIN
                   MASTERCARD_C = :MASTERCARD_C + :VALOR;
                 END
                ELSE
                IF (CD_CARTAO = 3) THEN
                 BEGIN
                   DINERS_C = :DINERS_C + :VALOR;
                 END
                ELSE
                IF (CD_CARTAO = 4) THEN
                 BEGIN
                   AMEX_C = :AMEX_C + :VALOR;
                 END
                ELSE
                IF (CD_CARTAO = 5) THEN
                 BEGIN
                   ELECTRON_C = :ELECTRON_C + :VALOR;
                 END
                ELSE
                IF (CD_CARTAO = 6) THEN
                 BEGIN
                   REDESHOP_C = :REDESHOP_C + :VALOR;
                 END
                ELSE
                 BEGIN
                   IF (:TIPO_CARTAO = 'C') THEN
                    BEGIN
                      OUTROS_C = :OUTROS_C + :VALOR;
                    END
                   ELSE
                    BEGIN
                      OUTROS_DEBITO_C = :OUTROS_DEBITO_C + :VALOR;
                    END
                 END
             END

            IF (:VISA_C IS NULL) THEN
                VISA_C = 0;
            IF (:MASTERCARD_C IS NULL) THEN
                MASTERCARD_C = 0;
            IF (:DINERS_C IS NULL) THEN
                DINERS_C = 0;
            IF (:AMEX_C IS NULL) THEN
                AMEX_C = 0;
            IF (:ELECTRON_C IS NULL) THEN
                ELECTRON_C = 0;
            IF (:REDESHOP_C IS NULL) THEN
                REDESHOP_C = 0;
            IF (:OUTROS_C IS NULL) THEN
                OUTROS_C = 0;
            IF (:OUTROS_DEBITO_C IS NULL) THEN
                OUTROS_DEBITO_c = 0;


            VISA = :VISA - :VISA_C;
            MASTERCARD = :MASTERCARD - :MASTERCARD_C;
            DINERS = :DINERS - :DINERS_C;
            AMEX = :AMEX - :AMEX_C;
            ELECTRON = :ELECTRON - :ELECTRON_C;
            REDESHOP = :REDESHOP - :REDESHOP_C;
            OUTROS = :OUTROS - :OUTROS_C;
            OUTROS_DEBITO = :OUTROS_DEBITO - :OUTROS_DEBITO_C;

            /* VENDAS A CONVENIO */
            SELECT
             SUM(CAIXA.VALOR)
            FROM
             CAIXA
            WHERE
             CAIXA.CD_FILIAL = :FILIAL AND
             CAIXA.DATA = :DATA AND
             CAIXA.CD_FORMA_PAGAMENTO = 3 AND
             CAIXA.TIPO_VENDA = 'V'
            INTO
             :CONVENIO;
        
            /* CANCELAMENTOS A CONVENIO */
            SELECT
             SUM(CAIXA.VALOR)
            FROM
             CAIXA
            WHERE
             CAIXA.CD_FILIAL = :FILIAL AND
             CAIXA.DATA = :DATA AND
             CAIXA.CD_FORMA_PAGAMENTO = 3 AND
             CAIXA.TIPO_VENDA = 'D'
            INTO
             :CONVENIO_C;

            IF (:CONVENIO IS NULL) THEN
               CONVENIO = 0;
            IF (:CONVENIO_C IS NULL) THEN
               CONVENIO_C = 0;
            CONVENIO = :CONVENIO - :CONVENIO_C;

            /* VENDAS A CHEQUE PRE */
            SELECT
             SUM(CAIXA.VALOR)
            FROM
             CAIXA
            WHERE
             CAIXA.CD_FILIAL = :FILIAL AND
             CAIXA.DATA = :DATA AND
             CAIXA.CD_FORMA_PAGAMENTO = 4 AND
             CAIXA.TIPO_VENDA = 'V'
            INTO
             :CHEQUE_PRE;
        
            /* CANCELAMENTOS A CHEQUE PRE */
            SELECT
             SUM(CAIXA.VALOR)
            FROM
             CAIXA
            WHERE
             CAIXA.CD_FILIAL = :FILIAL AND
             CAIXA.DATA = :DATA AND
             CAIXA.CD_FORMA_PAGAMENTO = 4 AND
             CAIXA.TIPO_VENDA = 'D'
            INTO
             :CHEQUE_PRE_C;

            IF (:CHEQUE_PRE IS NULL) THEN
               CHEQUE_PRE = 0;
            IF (:CHEQUE_PRE_C IS NULL) THEN
               CHEQUE_PRE_C = 0;
            CHEQUE_PRE = :CHEQUE_PRE - :CHEQUE_PRE_C;

            /* VENDAS A CREDIARIO */
            SELECT
             SUM(CAIXA.VALOR)
            FROM
             CAIXA
            WHERE
             CAIXA.CD_FILIAL = :FILIAL AND
             CAIXA.DATA = :DATA AND
             CAIXA.CD_FORMA_PAGAMENTO = 5 AND
             CAIXA.TIPO_VENDA = 'V'
            INTO
             :CREDIARIO;
        
            /* CANCELAMENTOS A CREDIARIO */
            SELECT
             SUM(CAIXA.VALOR)
            FROM
             CAIXA
            WHERE
             CAIXA.CD_FILIAL = :FILIAL AND
             CAIXA.DATA = :DATA AND
             CAIXA.CD_FORMA_PAGAMENTO = 5 AND
             CAIXA.TIPO_VENDA = 'D'
            INTO
             :CREDIARIO_C;

            IF (:CREDIARIO IS NULL) THEN
               CREDIARIO = 0;
            IF (:CREDIARIO_C IS NULL) THEN
               CREDIARIO_C = 0;
            CREDIARIO = :CREDIARIO - :CREDIARIO_C;

            /* VENDAS A CHEQUE A VISTA */
            SELECT
             SUM(CAIXA.VALOR)
            FROM
             CAIXA
            WHERE
             CAIXA.CD_FILIAL = :FILIAL AND
             CAIXA.DATA = :DATA AND
             CAIXA.CD_FORMA_PAGAMENTO = 6 AND
             CAIXA.TIPO_VENDA = 'V'
            INTO
             :CHEQUE_A_VISTA;
        
            /* CANCELAMENTOS A CHEQUE A VISTA */
            SELECT
             SUM(CAIXA.VALOR)
            FROM
             CAIXA
            WHERE
             CAIXA.CD_FILIAL = :FILIAL AND
             CAIXA.DATA = :DATA AND
             CAIXA.CD_FORMA_PAGAMENTO = 6 AND
             CAIXA.TIPO_VENDA = 'D'
            INTO
             :CHEQUE_A_VISTA_C;

            IF (:CHEQUE_A_VISTA IS NULL) THEN
               CHEQUE_A_VISTA = 0;
            IF (:CHEQUE_A_VISTA_C IS NULL) THEN
               CHEQUE_A_VISTA_C = 0;
            CHEQUE_A_VISTA = :CHEQUE_A_VISTA - :CHEQUE_A_VISTA_C;

            /* RETIRADAS */
            SELECT
             SUM(CAIXA.VALOR)
            FROM
             CAIXA
            WHERE
             CAIXA.CD_FILIAL = :FILIAL AND
             CAIXA.DATA = :DATA AND
             CAIXA.CD_FORMA_PAGAMENTO IS NULL AND
             CAIXA.TIPO_VENDA = 'R'
            INTO
             :RETIRADAS;
        
            /* TOTAL DE COMPRAS */
            SELECT
              SUM(LANCAMENTOS.VALOR)
            FROM
              LANCAMENTOS
            WHERE
              LANCAMENTOS.DATA_LANCAMENTO = :DATA AND
              LANCAMENTOS.CD_FILIAL = :FILIAL AND
              LANCAMENTOS.ENTRADA_SAIDA = 'E' AND
              LANCAMENTOS.TIPO_VENDA = 'C' AND
              LANCAMENTOS.CD_FORMA_PAGAMENTO <> 100 AND
              LANCAMENTOS.CD_FORMA_PAGAMENTO <> 101
            INTO
             :TOTAL_COMPRAS;
        
            DIA_ATUAL = EXTRACT(DAY FROM :DATA);
            MES_ATUAL = EXTRACT(MONTH FROM :DATA);
            ANO_ATUAL = EXTRACT(YEAR FROM :DATA);
        
            IF (:MES_ATUAL = 1) THEN
             BEGIN
               MES_ANTERIOR = 12;
               ANO_ANTERIOR = CAST(CAST(:ANO_ATUAL AS INTEGER) - 1 AS VARCHAR(4));
             END
            ELSE
             BEGIN
               MES_ANTERIOR = CAST(CAST(:MES_ATUAL AS INTEGER) - 1 AS VARCHAR(2));
               ANO_ANTERIOR = :ANO_ATUAL;
             END
        
            DATA_INICIAL_ATUAL = CAST((:MES_ATUAL||'/01/'||:ANO_ATUAL) AS DATE);
            DATA_INICIAL_ANTERIOR = CAST((:MES_ANTERIOR||'/01/'||:ANO_ANTERIOR) AS DATE);
            IF ((CAST(:MES_ANTERIOR AS INTEGER) = 2) AND (:DIA_ATUAL > '28')) THEN
             BEGIN
               DIA_ATUAL = '28';
             END
            ELSE
            IF (((CAST(:MES_ANTERIOR AS INTEGER) = 4) OR
               (CAST(:MES_ANTERIOR AS INTEGER) = 6) OR
               (CAST(:MES_ANTERIOR AS INTEGER) = 9) OR
               (CAST(:MES_ANTERIOR AS INTEGER) = 11)) AND
               (CAST(:DIA_ATUAL AS INTEGER) = 31)) THEN
             BEGIN
                DIA_ATUAL = '30';
             END
        
            DATA_FINAL_ANTERIOR = CAST((:MES_ANTERIOR||'/'||:DIA_ATUAL||'/'||:ANO_ANTERIOR) AS DATE);
        
            /*COMPRAS*/
            SELECT
             SUM(LANCAMENTOS.VALOR)
            FROM
             LANCAMENTOS
            WHERE
             LANCAMENTOS.DATA_LANCAMENTO >= :DATA_INICIAL_ANTERIOR AND
             LANCAMENTOS.DATA_LANCAMENTO <= :DATA_FINAL_ANTERIOR AND
             LANCAMENTOS.CD_FILIAL = :FILIAL AND
             LANCAMENTOS.ENTRADA_SAIDA = 'E' AND
             LANCAMENTOS.TROCA <> 'S' AND
             LANCAMENTOS.CD_FORMA_PAGAMENTO <> 100 AND
             LANCAMENTOS.CD_FORMA_PAGAMENTO <> 101
            INTO
             :TOTAL_COMPRAS_ANTERIOR;
        
            SELECT
             SUM(LANCAMENTOS.VALOR)
            FROM
             LANCAMENTOS
            WHERE
             LANCAMENTOS.DATA_LANCAMENTO >= :DATA_INICIAL_ATUAL AND
             LANCAMENTOS.DATA_LANCAMENTO <= :DATA AND
             LANCAMENTOS.CD_FILIAL = :FILIAL AND
             LANCAMENTOS.ENTRADA_SAIDA = 'E' AND
             LANCAMENTOS.TROCA <> 'S' AND
             LANCAMENTOS.CD_FORMA_PAGAMENTO <> 100 AND
             LANCAMENTOS.CD_FORMA_PAGAMENTO <> 101
            INTO
             :TOTAL_COMPRAS_ATUAL;
        
        
            /*VENDAS*/
            SELECT
             SUM(CAIXA.VALOR)
            FROM
             CAIXA
            WHERE
             CAIXA.DATA >= :DATA_INICIAL_ANTERIOR AND
             CAIXA.DATA <= :DATA_FINAL_ANTERIOR AND
             CAIXA.CD_FILIAL = :FILIAL AND
             CAIXA.ENTRADA_SAIDA = 'E' AND
             CAIXA.TIPO_VENDA = 'V'
            INTO
             :TOTAL_VENDAS_ANTERIOR;
        
            /*CANCELAMENTOS*/
            SELECT
             SUM(CAIXA.VALOR)
            FROM
             CAIXA
            WHERE
             CAIXA.DATA >= :DATA_INICIAL_ANTERIOR AND
             CAIXA.DATA <= :DATA_FINAL_ANTERIOR AND
             CAIXA.CD_FILIAL = :FILIAL AND
             CAIXA.ENTRADA_SAIDA = 'E' AND
             CAIXA.TIPO_VENDA = 'D'
            INTO
             :TOTAL_VENDAS_ANTERIOR_C;

            IF (:TOTAL_VENDAS_ANTERIOR IS NULL) THEN
               TOTAL_VENDAS_ANTERIOR = 0;
            IF (:TOTAL_VENDAS_ANTERIOR_C IS NULL) THEN
               TOTAL_VENDAS_ANTERIOR_C = 0;
            TOTAL_VENDAS_ANTERIOR = :TOTAL_VENDAS_ANTERIOR - :TOTAL_VENDAS_ANTERIOR_C;

            SELECT
             SUM(CAIXA.VALOR)
            FROM
             CAIXA
            WHERE
             CAIXA.DATA >= :DATA_INICIAL_ATUAL AND
             CAIXA.DATA <= :DATA AND
             CAIXA.CD_FILIAL = :FILIAL AND
             CAIXA.ENTRADA_SAIDA = 'E' AND
             CAIXA.TIPO_VENDA = 'V'
            INTO
             :TOTAL_VENDAS_ATUAL;
        
            SELECT
             SUM(CAIXA.VALOR)
            FROM
             CAIXA
            WHERE
             CAIXA.DATA >= :DATA_INICIAL_ATUAL AND
             CAIXA.DATA <= :DATA AND
             CAIXA.CD_FILIAL = :FILIAL AND
             CAIXA.ENTRADA_SAIDA = 'E' AND
             CAIXA.TIPO_VENDA = 'D'
            INTO
             :TOTAL_VENDAS_ATUAL_C;

            IF (:TOTAL_VENDAS_ATUAL IS NULL) THEN
               TOTAL_VENDAS_ATUAL = 0;
            IF (:TOTAL_VENDAS_ATUAL_C IS NULL) THEN
               TOTAL_VENDAS_ATUAL_C = 0;
            TOTAL_VENDAS_ATUAL = :TOTAL_VENDAS_ATUAL - :TOTAL_VENDAS_ATUAL_C;

        /*CLIENTES*/
           SELECT
            COUNT(DISTINCT LANCAMENTOS.CD_VENDA)
           FROM
            LANCAMENTOS
           WHERE
             LANCAMENTOS.DATA_LANCAMENTO >= :DATA_INICIAL_ATUAL AND
             LANCAMENTOS.DATA_LANCAMENTO <= :DATA AND
             LANCAMENTOS.CD_FILIAL = :FILIAL AND
             LANCAMENTOS.ENTRADA_SAIDA = 'S' AND
             LANCAMENTOS.TIPO_VENDA = 'V' AND
             LANCAMENTOS.CD_FORMA_PAGAMENTO >= 1 AND
             LANCAMENTOS.CD_FORMA_PAGAMENTO <= 6
           INTO
            :TOTAL_CLIENTES_MES;
        
        /*CLIENTES*/
           SELECT
            COUNT(DISTINCT LANCAMENTOS.CD_VENDA)
           FROM
            LANCAMENTOS
           WHERE
             LANCAMENTOS.DATA_LANCAMENTO >= :DATA_INICIAL_ATUAL AND
             LANCAMENTOS.DATA_LANCAMENTO <= :DATA AND
             LANCAMENTOS.CD_FILIAL = :FILIAL AND
             LANCAMENTOS.ENTRADA_SAIDA = 'S' AND
             LANCAMENTOS.TIPO_VENDA = 'D' AND
             LANCAMENTOS.CD_FORMA_PAGAMENTO >= 1 AND
             LANCAMENTOS.CD_FORMA_PAGAMENTO <= 6
           INTO
            :TOTAL_CLIENTES_MES_C;

           IF (:TOTAL_CLIENTES_MES IS NULL) THEN
              TOTAL_CLIENTES_MES = 0;
           IF (:TOTAL_CLIENTES_MES_C IS NULL) THEN
              TOTAL_CLIENTES_MES_C = 0;
           TOTAL_CLIENTES_MES = :TOTAL_CLIENTES_MES - :TOTAL_CLIENTES_MES_C;

           SELECT
            COUNT(DISTINCT LANCAMENTOS.CD_VENDA)
           FROM
            LANCAMENTOS
           WHERE
             LANCAMENTOS.DATA_LANCAMENTO = :DATA AND
             LANCAMENTOS.CD_FILIAL = :FILIAL AND
             LANCAMENTOS.ENTRADA_SAIDA = 'S' AND
             LANCAMENTOS.TIPO_VENDA = 'V' AND
             LANCAMENTOS.CD_FORMA_PAGAMENTO >= 1 AND
             LANCAMENTOS.CD_FORMA_PAGAMENTO <= 6
           INTO
            :TOTAL_CLIENTES_DIA;

           SELECT
            COUNT(DISTINCT LANCAMENTOS.CD_VENDA)
           FROM
            LANCAMENTOS
           WHERE
             LANCAMENTOS.DATA_LANCAMENTO = :DATA AND
             LANCAMENTOS.CD_FILIAL = :FILIAL AND
             LANCAMENTOS.ENTRADA_SAIDA = 'S' AND
             LANCAMENTOS.TIPO_VENDA = 'D' AND
             LANCAMENTOS.CD_FORMA_PAGAMENTO >= 1 AND
             LANCAMENTOS.CD_FORMA_PAGAMENTO <= 6
           INTO
            :TOTAL_CLIENTES_DIA_C;

           IF (:TOTAL_CLIENTES_DIA IS NULL) THEN
              TOTAL_CLIENTES_DIA = 0;
           IF (:TOTAL_CLIENTES_DIA_C IS NULL) THEN
              TOTAL_CLIENTES_DIA_C = 0;
           TOTAL_CLIENTES_DIA = :TOTAL_CLIENTES_DIA - :TOTAL_CLIENTES_DIA_C;
        
           /*ENTREGAS*/
           SELECT
            COUNT(DISTINCT LANCAMENTOS.CD_VENDA),
            SUM(LANCAMENTOS.VALOR)
           FROM
            LANCAMENTOS
           WHERE
             LANCAMENTOS.DATA_LANCAMENTO >= :DATA_INICIAL_ATUAL AND
             LANCAMENTOS.DATA_LANCAMENTO <= :DATA AND
             LANCAMENTOS.CD_FILIAL = :FILIAL AND
             LANCAMENTOS.ENTRADA_SAIDA = 'S' AND
             LANCAMENTOS.ENTREGA = 'S' AND
             LANCAMENTOS.TIPO_VENDA = 'V' AND
             LANCAMENTOS.CD_FORMA_PAGAMENTO >= 1 AND
             LANCAMENTOS.CD_FORMA_PAGAMENTO <= 6
           INTO
            :TOTAL_ENTREGAS_MES,
            :TOTAL_ENTREGAS_VALOR_MES;
        
           /*ENTREGAS*/
           SELECT
            COUNT(DISTINCT LANCAMENTOS.CD_VENDA),
            SUM(LANCAMENTOS.VALOR)
           FROM
            LANCAMENTOS
           WHERE
             LANCAMENTOS.DATA_LANCAMENTO >= :DATA_INICIAL_ATUAL AND
             LANCAMENTOS.DATA_LANCAMENTO <= :DATA AND
             LANCAMENTOS.CD_FILIAL = :FILIAL AND
             LANCAMENTOS.ENTRADA_SAIDA = 'S' AND
             LANCAMENTOS.ENTREGA = 'S' AND
             LANCAMENTOS.TIPO_VENDA = 'D' AND
             LANCAMENTOS.CD_FORMA_PAGAMENTO >= 1 AND
             LANCAMENTOS.CD_FORMA_PAGAMENTO <= 6
           INTO
            :TOTAL_ENTREGAS_MES_C,
            :TOTAL_ENTREGAS_VALOR_MES_C;

            IF (:TOTAL_ENTREGAS_MES IS NULL) THEN
               TOTAL_ENTREGAS_MES = 0;
            IF (:TOTAL_ENTREGAS_VALOR_MES IS NULL) THEN
               TOTAL_ENTREGAS_VALOR_MES = 0;
            IF (:TOTAL_ENTREGAS_MES_C IS NULL) THEN
               TOTAL_ENTREGAS_MES_C = 0;
            IF (:TOTAL_ENTREGAS_VALOR_MES_C IS NULL) THEN
               TOTAL_ENTREGAS_VALOR_MES_C = 0;
            TOTAL_ENTREGAS_MES = :TOTAL_ENTREGAS_MES - :TOTAL_ENTREGAS_MES_C;
            TOTAL_ENTREGAS_VALOR_MES = :TOTAL_ENTREGAS_VALOR_MES - :TOTAL_ENTREGAS_VALOR_MES_C;

           SELECT
            COUNT(DISTINCT LANCAMENTOS.CD_VENDA),
            SUM(LANCAMENTOS.VALOR)
           FROM
            LANCAMENTOS
           WHERE
             LANCAMENTOS.DATA_LANCAMENTO = :DATA AND
             LANCAMENTOS.CD_FILIAL = :FILIAL AND
             LANCAMENTOS.ENTRADA_SAIDA = 'S' AND
             LANCAMENTOS.ENTREGA = 'S' AND
             LANCAMENTOS.TIPO_VENDA = 'V' AND
             LANCAMENTOS.CD_FORMA_PAGAMENTO >= 1 AND
             LANCAMENTOS.CD_FORMA_PAGAMENTO <= 6
           INTO
            :TOTAL_ENTREGAS_DIA,
            :TOTAL_ENTREGAS_VALOR_DIA;
        
           SELECT
            COUNT(DISTINCT LANCAMENTOS.CD_VENDA),
            SUM(LANCAMENTOS.VALOR)
           FROM
            LANCAMENTOS
           WHERE
             LANCAMENTOS.DATA_LANCAMENTO = :DATA AND
             LANCAMENTOS.CD_FILIAL = :FILIAL AND
             LANCAMENTOS.ENTRADA_SAIDA = 'S' AND
             LANCAMENTOS.ENTREGA = 'S' AND
             LANCAMENTOS.TIPO_VENDA = 'D' AND
             LANCAMENTOS.CD_FORMA_PAGAMENTO >= 1 AND
             LANCAMENTOS.CD_FORMA_PAGAMENTO <= 6
           INTO
            :TOTAL_ENTREGAS_DIA_C,
            :TOTAL_ENTREGAS_VALOR_DIA_C;

            IF (:TOTAL_ENTREGAS_DIA IS NULL) THEN
               TOTAL_ENTREGAS_DIA = 0;
            IF (:TOTAL_ENTREGAS_VALOR_DIA IS NULL) THEN
               TOTAL_ENTREGAS_VALOR_DIA = 0;
            IF (:TOTAL_ENTREGAS_DIA_C IS NULL) THEN
               TOTAL_ENTREGAS_DIA_C = 0;
            IF (:TOTAL_ENTREGAS_VALOR_DIA_C IS NULL) THEN
               TOTAL_ENTREGAS_VALOR_DIA_C = 0;
            TOTAL_ENTREGAS_DIA = :TOTAL_ENTREGAS_DIA - :TOTAL_ENTREGAS_DIA_C;
            TOTAL_ENTREGAS_VALOR_DIA = :TOTAL_ENTREGAS_VALOR_DIA - :TOTAL_ENTREGAS_VALOR_DIA_C;

            /*TOTAIS*/
            IF (:DINHEIRO IS NULL) THEN DINHEIRO = 0;
            IF (:CARTAO IS NULL) THEN CARTAO = 0;
            IF (:CARTAO_DEBITO IS NULL) THEN CARTAO_DEBITO = 0;
            IF (:CARTAO_CREDITO IS NULL) THEN CARTAO_CREDITO = 0;
            IF (:CONVENIO IS NULL) THEN CONVENIO = 0;
            IF (:CHEQUE_PRE IS NULL) THEN CHEQUE_PRE = 0;
            IF (:CREDIARIO IS NULL) THEN CREDIARIO = 0;
            IF (:CHEQUE_A_VISTA IS NULL) THEN CHEQUE_A_VISTA = 0;
            IF (:RETIRADAS IS NULL) THEN RETIRADAS = 0;
            IF (:VISA IS NULL) THEN VISA = 0;
            IF (:MASTERCARD IS NULL) THEN MASTERCARD = 0;
            IF (:DINERS IS NULL) THEN DINERS = 0;
            IF (:AMEX IS NULL) THEN AMEX = 0;
            IF (:REDESHOP IS NULL) THEN REDESHOP = 0;
            IF (:ELECTRON IS NULL) THEN ELECTRON = 0;
            IF (:OUTROS IS NULL) THEN OUTROS = 0;
            IF (:TOTAL_VENDAS_ANTERIOR IS NULL) THEN TOTAL_VENDAS_ANTERIOR = 0;
            IF (:TOTAL_VENDAS_ATUAL IS NULL) THEN TOTAL_VENDAS_ATUAL = 0;
            IF (:TOTAL_COMPRAS IS NULL) THEN TOTAL_COMPRAS = 0;
            IF (:TOTAL_COMPRAS_ANTERIOR IS NULL) THEN TOTAL_COMPRAS_ANTERIOR = 0;
            IF (:TOTAL_COMPRAS_ATUAL IS NULL) THEN TOTAL_COMPRAS_ATUAL = 0;
            IF (:TOTAL_CLIENTES_MES IS NULL) THEN TOTAL_CLIENTES_MES = 0;
            IF (:TOTAL_CLIENTES_DIA IS NULL) THEN TOTAL_CLIENTES_DIA = 0;
            IF (:TOTAL_ENTREGAS_DIA IS NULL) THEN TOTAL_ENTREGAS_DIA = 0;
            IF (:TOTAL_ENTREGAS_MES IS NULL) THEN TOTAL_ENTREGAS_MES = 0;
            IF (:TOTAL_ENTREGAS_VALOR_DIA IS NULL) THEN TOTAL_ENTREGAS_VALOR_DIA = 0;
            IF (:TOTAL_ENTREGAS_VALOR_MES IS NULL) THEN TOTAL_ENTREGAS_VALOR_MES = 0;

            TOTAL_VENDAS = 0;
            VENDAS_PRAZO = 0;
            VENDAS_VISTA = 0;

            /* TOTAIS DE VENDAS */
            TOTAL_VENDAS = :DINHEIRO + :CARTAO + :CONVENIO + :CHEQUE_PRE + :CREDIARIO + :CHEQUE_A_VISTA - :RETIRADAS;
            VENDAS_VISTA = :DINHEIRO + :CHEQUE_A_VISTA + :CARTAO_DEBITO;
            VENDAS_PRAZO = :CARTAO_CREDITO + :CREDIARIO + :CHEQUE_PRE + :CONVENIO;
        
            /* MEDIAS */
            MEDIA_CLIENTE = 0;
            MEDIA_ENTREGA = 0;
            MEDIA_VENDAS = 0;
            MEDIA_COMPRAS = 0;
            IF (:TOTAL_CLIENTES_MES <> 0) THEN
             BEGIN
               MEDIA_CLIENTE = :TOTAL_VENDAS_ATUAL / :TOTAL_CLIENTES_MES;
             END
            IF (:TOTAL_ENTREGAS_MES <> 0) THEN
             BEGIN
               MEDIA_ENTREGA = :TOTAL_ENTREGAS_VALOR_MES / :TOTAL_ENTREGAS_MES;
             END
            IF (:TOTAL_VENDAS_ATUAL <> 0) THEN
             BEGIN
               MEDIA_VENDAS = :TOTAL_VENDAS_ATUAL / :NUMERO_DIAS;
             END
            IF (:TOTAL_COMPRAS_ATUAL <> 0) THEN
             BEGIN
               MEDIA_COMPRAS = :TOTAL_COMPRAS_ATUAL / :NUMERO_DIAS;
             END


            IF (:MEDIA_CLIENTE <= 0) THEN
               MEDIA_CLIENTE = 0;
            IF (:MEDIA_ENTREGA <= 0) THEN
               MEDIA_ENTREGA = 0;
        
            /* ATUALIZACAO DA TABELA CAIXA_RESUMIDO */
            SELECT
             DATA,
             CD_FILIAL
            FROM
             CAIXA_RESUMIDO
            WHERE
             CD_FILIAL = :FILIAL AND
             DATA = :DATA
            INTO
             :DATA_RESUMIDO,
             :CD_FILIAL;
        
            IF (:DATA_RESUMIDO IS NULL) THEN
             BEGIN
                INSERT INTO CAIXA_RESUMIDO VALUES (:FILIAL, :DATA, :DINHEIRO, :CARTAO,
                :CARTAO_DEBITO, :CARTAO_CREDITO, :VISA, :MASTERCARD, :DINERS, :AMEX,
                :ELECTRON, :REDESHOP, :CONVENIO, :CHEQUE_PRE, :CREDIARIO, :CHEQUE_A_VISTA,
                NULL, :RETIRADAS, :TOTAL_VENDAS, :VENDAS_VISTA, :VENDAS_PRAZO,
                NULL, :TOTAL_VENDAS_ANTERIOR, :TOTAL_VENDAS_ATUAL, NULL, :TOTAL_COMPRAS,
                NULL, :TOTAL_COMPRAS_ANTERIOR, :TOTAL_COMPRAS_ATUAL, NULL, NULL, NULL, NULL, NULL, NULL,
                :TOTAL_CLIENTES_MES, :TOTAL_CLIENTES_DIA,
                :MEDIA_CLIENTE, :TOTAL_ENTREGAS_DIA, :TOTAL_ENTREGAS_MES,
                :TOTAL_ENTREGAS_VALOR_DIA, :TOTAL_ENTREGAS_VALOR_MES, :MEDIA_ENTREGA,
                :OUTROS, :NUMERO_DIAS, :MEDIA_VENDAS, :MEDIA_COMPRAS, :OUTROS_DEBITO);
             END
            ELSE
             BEGIN
                UPDATE CAIXA_RESUMIDO SET
                CD_FILIAL = :FILIAL, DATA = :DATA, DINHEIRO = :DINHEIRO, CARTAO = :CARTAO,
                CARTAO_DEBITO = :CARTAO_DEBITO, CARTAO_CREDITO = :CARTAO_CREDITO,
                VISA = :VISA, MASTERCARD = :MASTERCARD, DINERS = :DINERS, AMEX = :AMEX,
                ELECTRON = :ELECTRON, REDESHOP = :REDESHOP, CONVENIO = :CONVENIO,
                CHEQUE_PRE = :CHEQUE_PRE, CREDIARIO = :CREDIARIO,
                CHEQUE_A_VISTA = :CHEQUE_A_VISTA, RETIRADAS = :RETIRADAS,
                VENDAS = :TOTAL_VENDAS, VENDAS_VISTA = :VENDAS_VISTA,
                VENDAS_PRAZO = :VENDAS_PRAZO, VENDAS_MES_ATUAL = :TOTAL_VENDAS_ATUAL,
                VENDAS_MES_ANTERIOR = :TOTAL_VENDAS_ANTERIOR, COMPRAS = :TOTAL_COMPRAS,
                COMPRAS_MES_ANTERIOR = :TOTAL_COMPRAS_ANTERIOR,
                COMPRAS_MES = :TOTAL_COMPRAS_ATUAL, CLIENTES_MES = :TOTAL_CLIENTES_MES,
                CLIENTES_DIA = :TOTAL_CLIENTES_DIA, MEDIA_CLIENTE = :MEDIA_CLIENTE,
                ENTREGAS_NUMERO_DIA = :TOTAL_ENTREGAS_DIA,
                ENTREGAS_NUMERO_MES = :TOTAL_ENTREGAS_MES,
                ENTREGAS_VALOR_DIA = :TOTAL_ENTREGAS_VALOR_DIA,
                ENTREGAS_VALOR_MES = :TOTAL_ENTREGAS_VALOR_MES,
                MEDIA_ENTREGAS = :MEDIA_ENTREGA, OUTROS = :OUTROS,
                NUMERO_DIAS = :NUMERO_DIAS, MEDIA_VENDAS = :MEDIA_VENDAS,
                MEDIA_COMPRAS = :MEDIA_COMPRAS, OUTROS_DEBITO = :OUTROS_DEBITO
                WHERE
                 CD_FILIAL = :FILIAL AND
                 DATA = :DATA;
             END
      END /* FOR */
     DIFERENCA = :DIFERENCA - 1;
   END /* END DO WHILE */
END ^

ALTER PROCEDURE SP_VENDAS_NCM (CD_FILIAL DOUBLE PRECISION,
DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (ID_PRODUTO DOUBLE PRECISION,
NCM VARCHAR(100) CHARACTER SET NONE,
PIS VARCHAR(3) CHARACTER SET NONE,
COFINS VARCHAR(3) CHARACTER SET NONE,
ICMS VARCHAR(3) CHARACTER SET NONE,
QUANTIDADE DOUBLE PRECISION,
VALOR_VENDA DOUBLE PRECISION)
AS 
declare variable ENQ varchar(1);
declare variable COMANDOSELECT varchar(1000);
declare variable COMANDOGROUP varchar(1000);
declare variable COMANDO varchar(1000);
declare variable VALORCANCELADO double precision;
declare variable QUANTIDADECANCELADA double precision;
BEGIN
   SELECT ENQUADRAMENTOTRIBUTARIO FROM PARAMETROS INTO ENQ;
   IF ((:ENQ IS NULL) OR (:ENQ = '')) THEN
       ENQ = 'S';
   FOR
    SELECT
     PRODUTOS_FISCO.NCM,
     PRODUTOS_FISCO.CST_ICMS,
     PRODUTOS_FISCO.CST_PIS_COFINS_SAIDA,
     PRODUTOS_FISCO.CST_PIS_COFINS_SAIDA,
     SUM(LANCAMENTOS.QUANTIDADE),
     SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO)
    FROM
     LANCAMENTOS LEFT OUTER JOIN PRODUTOS_FISCO ON LANCAMENTOS.ID_PRODUTO = PRODUTOS_FISCO.ID_PRODUTO
    WHERE
     LANCAMENTOS.TIPO_VENDA = 'V' AND
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
     LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL
    GROUP BY
     PRODUTOS_FISCO.NCM,
     PRODUTOS_FISCO.CST_ICMS,
     PRODUTOS_FISCO.CST_PIS_COFINS_SAIDA
    INTO
     :NCM,
     :ICMS,
     :PIS,
     :COFINS, 
     :QUANTIDADE,
     :VALOR_VENDA
   DO
    BEGIN
     IF ((:QUANTIDADE IS NOT NULL) AND (:VALOR_VENDA IS NOT NULL)) THEN
      BEGIN
        SELECT
         SUM(LANCAMENTOS.QUANTIDADE),
         SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO)
        FROM
         LANCAMENTOS LEFT OUTER JOIN PRODUTOS_FISCO ON LANCAMENTOS.ID_PRODUTO = PRODUTOS_FISCO.ID_PRODUTO
        WHERE
         LANCAMENTOS.TIPO_VENDA = 'D' AND
         LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
         LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
         LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
         PRODUTOS_FISCO.NCM = :NCM AND
         PRODUTOS_FISCO.CST_ICMS = :ICMS AND
         PRODUTOS_FISCO.CST_PIS_COFINS_SAIDA = :PIS
        INTO
         :QUANTIDADECANCELADA,
         :VALORCANCELADO;

        IF ((:QUANTIDADECANCELADA IS NULL) OR (:QUANTIDADECANCELADA < 0)) THEN
           QUANTIDADECANCELADA = 0;
        IF ((:VALORCANCELADO IS NULL) OR (:VALORCANCELADO < 0)) THEN
           VALORCANCELADO = 0;

        VALOR_VENDA = :VALOR_VENDA - :VALORCANCELADO;
        QUANTIDADE = :QUANTIDADE - :QUANTIDADECANCELADA;

        IF (:NCM IS NULL) THEN
           NCM = '30049099';

        SUSPEND;
      END
    END
END ^

ALTER PROCEDURE SP_VENDAS_NCM_PRODUTOS (NCM VARCHAR(100) CHARACTER SET NONE,
SITUACAOTRIBUTARIA VARCHAR(100) CHARACTER SET NONE,
DATAINICIAL DATE,
DATAFINAL DATE,
CD_FILIAL DOUBLE PRECISION)
RETURNS (ID_PRODUTO DOUBLE PRECISION,
DESCRICAO VARCHAR(100) CHARACTER SET NONE,
QUANTIDADE DOUBLE PRECISION,
VALOR DOUBLE PRECISION)
AS 
declare variable QUANTIDADE_CANCELADA double precision;
declare variable VALOR_CANCELADO double precision;
BEGIN
  FOR
    SELECT 
     PRODUTOS.ID_PRODUTO, 
     PRODUTOS.DESCRICAO,
     SUM(LANCAMENTOS.QUANTIDADE),
     SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO)
    FROM 
     LANCAMENTOS, PRODUTOS, PRODUTOS_FISCO
    WHERE
     LANCAMENTOS.ID_PRODUTO = PRODUTOS.ID_PRODUTO AND
     PRODUTOS.ID_PRODUTO = PRODUTOS_FISCO.ID_PRODUTO AND
     LANCAMENTOS.TIPO_VENDA = 'V' AND
     LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
     LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
     LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
     PRODUTOS_FISCO.NCM = :NCM AND
     PRODUTOS_FISCO.CST_ICMS = :SITUACAOTRIBUTARIA
    GROUP BY
     PRODUTOS.ID_PRODUTO,
     PRODUTOS.DESCRICAO
    ORDER BY
     PRODUTOS.DESCRICAO
    INTO
     :ID_PRODUTO,
     :DESCRICAO,
     :QUANTIDADE,
     :VALOR
  DO
   BEGIN
    IF ((:QUANTIDADE IS NOT NULL) AND (:VALOR IS NOT NULL)) THEN
     BEGIN
        SELECT
         SUM(LANCAMENTOS.QUANTIDADE),
         SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO)
        FROM 
         LANCAMENTOS LEFT OUTER JOIN PRODUTOS ON LANCAMENTOS.ID_PRODUTO = PRODUTOS.ID_PRODUTO
        WHERE
         LANCAMENTOS.ID_PRODUTO = :ID_PRODUTO AND
         LANCAMENTOS.TIPO_VENDA = 'D' AND
         LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
         LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
         LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL
        INTO
         :QUANTIDADE_CANCELADA,
         :VALOR_CANCELADO;

        IF ((:QUANTIDADE_CANCELADA IS NULL) OR (:QUANTIDADE_CANCELADA < 0)) THEN
           QUANTIDADE_CANCELADA = 0;
        IF ((:VALOR_CANCELADO IS NULL) OR (:VALOR_CANCELADO < 0)) THEN
           VALOR_CANCELADO = 0;

        QUANTIDADE = :QUANTIDADE - :QUANTIDADE_CANCELADA;
        VALOR = :VALOR - :VALOR_CANCELADO;

        SUSPEND;
     END
   END
END ^

ALTER PROCEDURE SP_VENDAS_PERIODO_CONVENIO (DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (CD_CLIENTE DOUBLE PRECISION,
CLIENTE VARCHAR(100) CHARACTER SET NONE,
CONVENIO VARCHAR(100) CHARACTER SET NONE,
CD_VENDA DOUBLE PRECISION,
CUPOM VARCHAR(20) CHARACTER SET NONE,
DATA DATE,
VALOR NUMERIC(15, 2),
CD_VENDEDOR DOUBLE PRECISION)
AS 
DECLARE VARIABLE VALORDEVOLUCAO NUMERIC(15,2);
BEGIN
  FOR
    SELECT
     LANCAMENTOS.CD_CLIENTE,
     CLIENTES.NOME,
     CONVENIOS.NOME,
     LANCAMENTOS.CD_VENDA,
     CAST(CAST(LANCAMENTOS.NUMERO AS INTEGER) AS VARCHAR(20)),
     LANCAMENTOS.DATA_CAIXA,
     SUM(LANCAMENTOS.VALOR)
    FROM
     LANCAMENTOS,
     CONVENIOS,
     CLIENTES,
     CAIXA
    WHERE
     LANCAMENTOS.CD_CONVENIO = CONVENIOS.CD_CONVENIO AND
     LANCAMENTOS.CD_CLIENTE = CLIENTES.CD_CLIENTE AND
     CAIXA.CD_VENDA = LANCAMENTOS.CD_VENDA AND
     LANCAMENTOS.DATA_CAIXA >= :DATAINICIAL AND
     LANCAMENTOS.DATA_CAIXA <= :DATAFINAL AND
     CAIXA.CD_FORMA_PAGAMENTO = 3 AND
     (LANCAMENTOS.TRN IS NULL OR LANCAMENTOS.TRN = 'N') AND
     LANCAMENTOS.TIPO_VENDA = 'V' AND
     (LANCAMENTOS.NUMERO IS NOT NULL AND LANCAMENTOS.NUMERO <> 0)
    GROUP BY
     LANCAMENTOS.CD_CLIENTE,
     CLIENTES.NOME,
     CONVENIOS.NOME,
     LANCAMENTOS.CD_VENDA,
     LANCAMENTOS.NUMERO,
     LANCAMENTOS.DATA_CAIXA
    INTO
     :CD_CLIENTE,
     :CLIENTE,
     :CONVENIO,
     :CD_VENDA,
     :CUPOM,
     :DATA,
     :VALOR
  DO
   BEGIN
     SELECT SUM(VALOR) FROM LANCAMENTOS WHERE CD_VENDA = :CD_VENDA AND TIPO_VENDA = 'D' INTO :VALORDEVOLUCAO;
     IF (:VALORDEVOLUCAO IS NULL) THEN
         VALORDEVOLUCAO = 0;
     VALOR = :VALOR - :VALORDEVOLUCAO;

     IF (:VALOR > 0) THEN
      BEGIN
        SELECT FIRST 1 CD_VENDEDOR FROM LANCAMENTOS WHERE CD_VENDA = :CD_VENDA INTO :CD_VENDEDOR;
        SUSPEND;
      END
   END
END ^

ALTER PROCEDURE SP_VENDAS_PRODUTO (ID_PRODUTO DOUBLE PRECISION,
DATAINICIAL DATE,
DATAFINAL DATE)
RETURNS (CD_FILIAL DOUBLE PRECISION,
MES VARCHAR(10) CHARACTER SET NONE,
FILIAL VARCHAR(100) CHARACTER SET NONE,
PRODUTO VARCHAR(100) CHARACTER SET NONE,
QUANTIDADE DOUBLE PRECISION,
VALOR DOUBLE PRECISION)
AS 
DECLARE VARIABLE QUANTIDADE_C DOUBLE PRECISION;
DECLARE VARIABLE VALOR_C DOUBLE PRECISION;
BEGIN
 FOR
    SELECT
     LANCAMENTOS.CD_FILIAL,
     EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)
    FROM
     LANCAMENTOS
    WHERE
     LANCAMENTOS.DATA_LANCAMENTO >= :DATAINICIAL AND
     LANCAMENTOS.DATA_LANCAMENTO <= :DATAFINAL AND
     (LANCAMENTOS.TIPO_VENDA = 'D' OR LANCAMENTOS.TIPO_VENDA = 'V') AND
     LANCAMENTOS.ID_PRODUTO = :ID_PRODUTO
    GROUP BY
     LANCAMENTOS.CD_FILIAL,
     EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO)
    INTO
     :CD_FILIAL,
     :MES
 DO
  BEGIN
    QUANTIDADE = 0;
    VALOR = 0;

    SELECT
      SUM(LANCAMENTOS.QUANTIDADE),
      SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO)
    FROM
      LANCAMENTOS
    WHERE
     EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO) = :MES AND
     LANCAMENTOS.CD_FILIAL  = :CD_FILIAL AND
     LANCAMENTOS.TIPO_VENDA = 'V' AND
     LANCAMENTOS.ID_PRODUTO = :ID_PRODUTO AND
     LANCAMENTOS.QUANTIDADE > 0
    INTO
     :QUANTIDADE,
     :VALOR;

    IF (:QUANTIDADE IS NULL) THEN
        QUANTIDADE = 0;
    IF (:VALOR IS NULL) THEN
        VALOR = 0;

    QUANTIDADE_C = 0;
    VALOR_C = 0;

    SELECT
     SUM(LANCAMENTOS.QUANTIDADE),
     SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO)
    FROM
     LANCAMENTOS
    WHERE
     EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO) = :MES AND
     LANCAMENTOS.CD_FILIAL  = :CD_FILIAL AND
     LANCAMENTOS.TIPO_VENDA = 'D' AND
     LANCAMENTOS.ID_PRODUTO = :ID_PRODUTO AND
     LANCAMENTOS.QUANTIDADE > 0
    INTO
     :QUANTIDADE_C,
     :VALOR_C;

     IF (:QUANTIDADE_C IS NULL) THEN
         QUANTIDADE_C = 0;
     IF (:VALOR_C IS NULL) THEN
         VALOR_C = 0;

     QUANTIDADE = :QUANTIDADE - :QUANTIDADE_C;
     VALOR = :VALOR - :VALOR_C;

     SELECT NOME FROM FILIAIS WHERE CD_FILIAL = :CD_FILIAL INTO :FILIAL;
     SELECT DESCRICAO FROM PRODUTOS WHERE ID_PRODUTO = :ID_PRODUTO INTO :PRODUTO;
     /*IF (:VALOR > 0) THEN*/
        SUSPEND;
  END
END ^

ALTER PROCEDURE SP_VENDAS_REALIZADAS_PRODFILTRO (DATAINICIAL DATE,
DATAFINAL DATE,
CD_FILIAL DOUBLE PRECISION,
CD_CLASSE DOUBLE PRECISION,
CD_GRUPO DOUBLE PRECISION,
CD_LABORATORIO DOUBLE PRECISION,
ID_PRODUTO DOUBLE PRECISION,
CD_VENDEDOR DOUBLE PRECISION,
CD_CONVENIO DOUBLE PRECISION,
CD_CLIENTE DOUBLE PRECISION,
PBM VARCHAR(1) CHARACTER SET NONE,
ENTREGA VARCHAR(1) CHARACTER SET NONE,
CD_SUBGRUPO DOUBLE PRECISION)
RETURNS (FILIAL VARCHAR(100) CHARACTER SET NONE,
NOME VARCHAR(100) CHARACTER SET NONE,
PRODUTO VARCHAR(100) CHARACTER SET NONE,
QUANTIDADE DOUBLE PRECISION,
VENDA DOUBLE PRECISION,
CUSTO DOUBLE PRECISION,
MARGEM DOUBLE PRECISION,
TOTALCANCELAMENTOS DOUBLE PRECISION,
CODIGO_BARRAS VARCHAR(14) CHARACTER SET NONE)
AS 
declare variable CODIGOFILIAL double precision;
declare variable CODIGOPRODUTO double precision;
declare variable CODIGOLABORATORIO double precision;
declare variable QUANTIDADEVENDA double precision;
declare variable QUANTIDADEDEVOLUCAO double precision;
declare variable VENDAVENDA double precision;
declare variable VENDADEVOLUCAO double precision;
declare variable CUSTOVENDA double precision;
declare variable CUSTODEVOLUCAO double precision;
declare variable COMANDO varchar(1000);
declare variable DATA1STR varchar(255);
declare variable DATA2STR varchar(255);
declare variable DATA1 varchar(255);
declare variable DATA2 varchar(255);
declare variable CODIGOUSUARIO varchar(10);
BEGIN
  DELETE FROM TEMP_MOVIMENTOPRODUTO;

  SELECT CODIGOUSUARIO FROM PARAMETROS INTO :CODIGOUSUARIO;

  DATA1STR = CAST(:DATAINICIAL AS VARCHAR(255));
  DATA2STR = CAST(:DATAFINAL AS VARCHAR(255));
  DATA1 = SUBSTRING(:DATA1STR FROM 6 FOR 2)||'/'||SUBSTRING(:DATA1STR FROM 9 FOR 2)||'/'||SUBSTRING(:DATA1STR FROM 1 FOR 4);
  DATA2 = SUBSTRING(:DATA2STR FROM 6 FOR 2)||'/'||SUBSTRING(:DATA2STR FROM 9 FOR 2)||'/'||SUBSTRING(:DATA2STR FROM 1 FOR 4);

  COMANDO = '';
  COMANDO = 'SELECT LANCAMENTOS.CD_LABORATORIO, LANCAMENTOS.ID_PRODUTO, LANCAMENTOS.DESCRICAO, '||
            'SUM(LANCAMENTOS.QUANTIDADE), SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO), SUM(LANCAMENTOS.CUSTO_UNITARIO * LANCAMENTOS.QUANTIDADE)'||
            ' FROM FILIAIS, LANCAMENTOS, LABORATORIOS WHERE LANCAMENTOS.CD_FILIAL = FILIAIS.CD_FILIAL AND '||
            ' LANCAMENTOS.CD_LABORATORIO = LABORATORIOS.CD_LABORATORIO AND';
  IF (:CODIGOUSUARIO <> '0006') THEN
   BEGIN
     COMANDO = :COMANDO || ' LANCAMENTOS.DATA_LANCAMENTO >= '''||:DATA1||''' AND LANCAMENTOS.DATA_LANCAMENTO <= '''||:DATA2||''' ';
   END
  ELSE
   BEGIN
     COMANDO = :COMANDO || ' LANCAMENTOS.DATA_CAIXA >= '''||:DATA1||''' AND LANCAMENTOS.DATA_CAIXA <= '''||:DATA2||''' ';
   END

  IF ((:CD_FILIAL IS NOT NULL) AND (:CD_FILIAL <> 0)) THEN
   BEGIN
     COMANDO = :COMANDO || ' AND LANCAMENTOS.CD_FILIAL = ' || :CD_FILIAL;
   END

  COMANDO = :COMANDO || ' AND LANCAMENTOS.TIPO_VENDA = '''||'V'||''' ';

  IF ((:CD_VENDEDOR IS NOT NULL) AND (:CD_VENDEDOR <> 0)) THEN
   BEGIN
     COMANDO = :COMANDO || ' AND LANCAMENTOS.CD_VENDEDOR = ' || :CD_VENDEDOR;
   END
  IF ((:CD_GRUPO IS NOT NULL) AND (:CD_GRUPO <> 0)) THEN
   BEGIN
     COMANDO = :COMANDO || ' AND LANCAMENTOS.CD_GRUPO = ' || :CD_GRUPO;
   END
  IF ((:CD_SUBGRUPO IS NOT NULL) AND (:CD_SUBGRUPO <> 0)) THEN
   BEGIN
     COMANDO = :COMANDO || ' AND LANCAMENTOS.CD_SUBGRUPO = ' || :CD_SUBGRUPO;
   END
  IF ((:ID_PRODUTO IS NOT NULL) AND (:ID_PRODUTO <> 0)) THEN
   BEGIN
     COMANDO = :COMANDO || ' AND LANCAMENTOS.ID_PRODUTO = ' || :ID_PRODUTO;
   END
  IF ((:CD_CLASSE IS NOT NULL) AND (:CD_CLASSE <> 0)) THEN
   BEGIN
     COMANDO = :COMANDO || ' AND LANCAMENTOS.CD_CLASSE = ' || :CD_CLASSE;
   END
  IF ((:CD_LABORATORIO IS NOT NULL) AND (:CD_LABORATORIO <> 0)) THEN
   BEGIN
     COMANDO = :COMANDO || ' AND LANCAMENTOS.CD_LABORATORIO = ' || :CD_LABORATORIO;
   END
  IF ((:CD_CONVENIO IS NOT NULL) AND (:CD_CONVENIO <> 0)) THEN
   BEGIN
     COMANDO = :COMANDO || ' AND LANCAMENTOS.CD_CONVENIO = ' || :CD_CONVENIO;
   END
  IF ((:CD_CLIENTE IS NOT NULL) AND (:CD_CLIENTE <> 0)) THEN
   BEGIN
     COMANDO = :COMANDO || ' AND LANCAMENTOS.CD_CLIENTE = ' || :CD_CLIENTE;
   END
  IF ((:PBM IS NOT NULL) AND (:PBM <> '')) THEN
   BEGIN
     COMANDO = :COMANDO || ' AND LANCAMENTOS.TRN = ''' || :PBM || '''';
   END
  IF ((:ENTREGA IS NOT NULL) AND (:ENTREGA <> '')) THEN
   BEGIN
     COMANDO = :COMANDO || ' AND LANCAMENTOS.ENTREGA = ''' || :ENTREGA || '''';
   END

  COMANDO = :COMANDO || ' GROUP BY LANCAMENTOS.CD_LABORATORIO, LANCAMENTOS.ID_PRODUTO, LANCAMENTOS.DESCRICAO';

  FOR
    EXECUTE STATEMENT :COMANDO INTO :CODIGOLABORATORIO, :CODIGOPRODUTO, :PRODUTO, :QUANTIDADE, :VENDA, :CUSTO
  DO
   BEGIN
     IF (:QUANTIDADEVENDA IS NULL) THEN
        QUANTIDADEVENDA = 0;
     IF (:VENDAVENDA IS NULL) THEN
        VENDAVENDA = 0;
     IF (:CUSTOVENDA IS NULL) THEN
        CUSTOVENDA = 0;

     SELECT NOME FROM FILIAIS WHERE CD_FILIAL = :CODIGOFILIAL INTO :FILIAL;
     IF (:FILIAL IS NULL) THEN
        FILIAL = '';
     SELECT NOME FROM LABORATORIOS WHERE CD_LABORATORIO = :CODIGOLABORATORIO INTO :NOME;

     INSERT INTO TEMP_MOVIMENTOPRODUTO VALUES (:CD_FILIAL, :FILIAL, :CODIGOLABORATORIO, :NOME, :CODIGOPRODUTO, :PRODUTO, :QUANTIDADE, :VENDA,  :CUSTO, :MARGEM);
   END


  COMANDO = '';
  COMANDO = 'SELECT LANCAMENTOS.ID_PRODUTO, '||
            'SUM(LANCAMENTOS.QUANTIDADE), SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO), SUM(LANCAMENTOS.CUSTO_UNITARIO * LANCAMENTOS.QUANTIDADE)'||
            ' FROM FILIAIS, LANCAMENTOS, LABORATORIOS WHERE LANCAMENTOS.CD_FILIAL = FILIAIS.CD_FILIAL AND '||
            ' LANCAMENTOS.CD_LABORATORIO = LABORATORIOS.CD_LABORATORIO AND';

  IF (:CODIGOUSUARIO <> '0006') THEN
   BEGIN
     COMANDO = :COMANDO || ' LANCAMENTOS.DATA_LANCAMENTO >= '''||:DATA1||''' AND LANCAMENTOS.DATA_LANCAMENTO <= '''||:DATA2||''' ';
   END
  ELSE
   BEGIN
     COMANDO = :COMANDO || ' LANCAMENTOS.DATA_CAIXA >= '''||:DATA1||''' AND LANCAMENTOS.DATA_CAIXA <= '''||:DATA2||''' ';
   END

  IF ((:CD_FILIAL IS NOT NULL) AND (:CD_FILIAL <> 0)) THEN
   BEGIN
     COMANDO = :COMANDO || ' AND LANCAMENTOS.CD_FILIAL = ' || :CD_FILIAL;
   END

  COMANDO = :COMANDO || ' AND LANCAMENTOS.TIPO_VENDA = '''||'D'||''' AND TROCA = '''||'F'||'''';

  IF ((:CD_VENDEDOR IS NOT NULL) AND (:CD_VENDEDOR <> 0)) THEN
   BEGIN
     COMANDO = :COMANDO || ' AND LANCAMENTOS.CD_VENDEDOR = ' || :CD_VENDEDOR;
   END
  IF ((:CD_GRUPO IS NOT NULL) AND (:CD_GRUPO <> 0)) THEN
   BEGIN
     COMANDO = :COMANDO || ' AND LANCAMENTOS.CD_GRUPO = ' || :CD_GRUPO;
   END
  IF ((:CD_SUBGRUPO IS NOT NULL) AND (:CD_SUBGRUPO <> 0)) THEN
   BEGIN
     COMANDO = :COMANDO || ' AND LANCAMENTOS.CD_SUBGRUPO = ' || :CD_SUBGRUPO;
   END
  IF ((:ID_PRODUTO IS NOT NULL) AND (:ID_PRODUTO <> 0)) THEN
   BEGIN
     COMANDO = :COMANDO || ' AND LANCAMENTOS.ID_PRODUTO = ' || :ID_PRODUTO;
   END
  IF ((:CD_CLASSE IS NOT NULL) AND (:CD_CLASSE <> 0)) THEN
   BEGIN
     COMANDO = :COMANDO || ' AND LANCAMENTOS.CD_CLASSE = ' || :CD_CLASSE;
   END
  IF ((:CD_LABORATORIO IS NOT NULL) AND (:CD_LABORATORIO <> 0)) THEN
   BEGIN
     COMANDO = :COMANDO || ' AND LANCAMENTOS.CD_LABORATORIO = ' || :CD_LABORATORIO;
   END
  IF ((:CD_CONVENIO IS NOT NULL) AND (:CD_CONVENIO <> 0)) THEN
   BEGIN
     COMANDO = :COMANDO || ' AND LANCAMENTOS.CD_CONVENIO = ' || :CD_CONVENIO;
   END
  IF ((:CD_CLIENTE IS NOT NULL) AND (:CD_CLIENTE <> 0)) THEN
   BEGIN
     COMANDO = :COMANDO || ' AND LANCAMENTOS.CD_CLIENTE = ' || :CD_CLIENTE;
   END
  IF ((:PBM IS NOT NULL) AND (:PBM <> '')) THEN
   BEGIN
     COMANDO = :COMANDO || ' AND LANCAMENTOS.TRN = ''' || :PBM || '''';
   END
  IF ((:ENTREGA IS NOT NULL) AND (:ENTREGA <> '')) THEN
   BEGIN
     COMANDO = :COMANDO || ' AND LANCAMENTOS.ENTREGA = ''' || :ENTREGA || '''';
   END

  COMANDO = :COMANDO || ' GROUP BY LANCAMENTOS.CD_LABORATORIO, LANCAMENTOS.ID_PRODUTO, LANCAMENTOS.DESCRICAO';

  totalcancelamentos = 0;
  FOR
    EXECUTE STATEMENT :COMANDO INTO :CODIGOPRODUTO, :QUANTIDADEDEVOLUCAO, :VENDADEVOLUCAO, :CUSTODEVOLUCAO
  DO
   BEGIN
     IF (:QUANTIDADEDEVOLUCAO IS NULL) THEN
        QUANTIDADEDEVOLUCAO = 0;
     IF (:VENDADEVOLUCAO IS NULL) THEN
        VENDADEVOLUCAO = 0;
     IF (:CUSTODEVOLUCAO IS NULL) THEN
        CUSTODEVOLUCAO = 0;

     IF (:QUANTIDADEDEVOLUCAO > 0) THEN
      BEGIN
        totalcancelamentos = :totalcancelamentos + :vendadevolucao;

        UPDATE TEMP_MOVIMENTOPRODUTO SET
         QUANTIDADE = QUANTIDADE - :QUANTIDADEDEVOLUCAO,
         VENDAVENDA = VENDAVENDA - :VENDADEVOLUCAO,
         CUSTOVENDA = CUSTOVENDA - :CUSTODEVOLUCAO
        WHERE
         CODIGOFILIAL = :CD_FILIAL AND
         CODIGOPRODUTO = :CODIGOPRODUTO;
      END
   END

  DELETE FROM TEMP_MOVIMENTOPRODUTO WHERE QUANTIDADE = 0;

  UPDATE TEMP_MOVIMENTOPRODUTO SET
    MARGEM = CAST(((VENDAVENDA * 100) / CUSTOVENDA) - 100 AS NUMERIC(15,2));

  FOR
    SELECT
      TEMP_MOVIMENTOPRODUTO.CODIGOFILIAL,
      TEMP_MOVIMENTOPRODUTO.FILIAL,
      TEMP_MOVIMENTOPRODUTO.CODIGOLABORATORIO,
      TEMP_MOVIMENTOPRODUTO.NOME,
      TEMP_MOVIMENTOPRODUTO.CODIGOPRODUTO,
      TEMP_MOVIMENTOPRODUTO.PRODUTO,
      TEMP_MOVIMENTOPRODUTO.QUANTIDADE,
      TEMP_MOVIMENTOPRODUTO.VENDAVENDA,
      TEMP_MOVIMENTOPRODUTO.CUSTOVENDA,
      TEMP_MOVIMENTOPRODUTO.MARGEM
    FROM
      TEMP_MOVIMENTOPRODUTO
    INTO
     :CODIGOFILIAL,
     :FILIAL,
     :CODIGOLABORATORIO,
     :NOME,
     :CODIGOPRODUTO,
     :PRODUTO,
     :QUANTIDADE, 
     :VENDA,
     :CUSTO,
     :MARGEM
  DO
   BEGIN
     SELECT CODIGO_BARRAS_1 FROM PRODUTOS WHERE ID_PRODUTO = :codigoproduto INTO :CODIGO_BARRAS;
     SUSPEND;
   END

END ^

ALTER PROCEDURE SP_VENDAS_REALIZADAS_PRODUTO (DATAINICIAL DATE,
DATAFINAL DATE,
CD_FILIAL DOUBLE PRECISION)
RETURNS (FILIAL VARCHAR(100) CHARACTER SET NONE,
NOME VARCHAR(100) CHARACTER SET NONE,
PRODUTO VARCHAR(100) CHARACTER SET NONE,
QUANTIDADE DOUBLE PRECISION,
VENDA DOUBLE PRECISION,
CUSTO DOUBLE PRECISION,
MARGEM DOUBLE PRECISION)
AS 
declare variable ID_PRODUTO double precision;
declare variable CD_LABORATORIO double precision;
declare variable QUANTIDADEVENDA double precision;
declare variable QUANTIDADEDEVOLUCAO double precision;
declare variable VENDAVENDA double precision;
declare variable VENDADEVOLUCAO double precision;
declare variable CUSTOVENDA double precision;
declare variable CUSTODEVOLUCAO double precision;
declare variable COMANDO varchar(10000);
declare variable COMANDO1 varchar(10000);
declare variable CODIGOUSUARIO varchar(10);
BEGIN
  SELECT CODIGOUSUARIO FROM PARAMETROS INTO :CODIGOUSUARIO;
  COMANDO = '';
  COMANDO = 'SELECT LANCAMENTOS.CD_FILIAL, LANCAMENTOS.CD_LABORATORIO, LANCAMENTOS.ID_PRODUTO, LANCAMENTOS.DESCRICAO ' ||
            'FROM FILIAIS, LANCAMENTOS, LABORATORIOS ' ||
            'WHERE LANCAMENTOS.CD_FILIAL = FILIAIS.CD_FILIAL AND LANCAMENTOS.CD_LABORATORIO = LABORATORIOS.CD_LABORATORIO AND ';
  IF (:CODIGOUSUARIO <> '0006') THEN
   BEGIN
     COMANDO = :COMANDO || 'LANCAMENTOS.DATA_LANCAMENTO >= '''||:DATAINICIAL||''' AND LANCAMENTOS.DATA_LANCAMENTO <= '''||:DATAFINAL||''' ';
   END
  ELSE
   BEGIN
     COMANDO = :COMANDO || '(LANCAMENTOS.DATA_CAIXA >= '''||:DATAINICIAL||''')AND '||
                           '(LANCAMENTOS.DATA_CAIXA <= '''||:DATAFINAL||''') ';
   END
  COMANDO = :COMANDO || ' AND LANCAMENTOS.CD_FILIAL = '||:CD_FILIAL||' AND (LANCAMENTOS.TIPO_VENDA = '''||'V'||''' OR LANCAMENTOS.TIPO_VENDA = '''||'D'||''') AND '||
                        'LANCAMENTOS.CUSTO_UNITARIO <> 0 GROUP BY LANCAMENTOS.CD_FILIAL, LANCAMENTOS.CD_LABORATORIO, LANCAMENTOS.ID_PRODUTO, LANCAMENTOS.DESCRICAO ';

  FOR
    EXECUTE STATEMENT :COMANDO INTO :CD_FILIAL, :CD_LABORATORIO, :ID_PRODUTO, :PRODUTO
  DO
   BEGIN
     COMANDO1 = '';
     COMANDO1 = 'SELECT SUM(LANCAMENTOS.QUANTIDADE), SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO), SUM(LANCAMENTOS.CUSTO_UNITARIO * LANCAMENTOS.QUANTIDADE) '||
                'FROM LANCAMENTOS ' ||
                'WHERE LANCAMENTOS.CD_FILIAL = '||:CD_FILIAL||' AND LANCAMENTOS.CD_LABORATORIO = '||:CD_LABORATORIO||' AND LANCAMENTOS.ID_PRODUTO = '||:ID_PRODUTO||' AND ';
     IF (:CODIGOUSUARIO <> '0006') THEN
      BEGIN
        COMANDO1 = :COMANDO1 || 'LANCAMENTOS.DATA_LANCAMENTO >= '''||:DATAINICIAL||''' AND LANCAMENTOS.DATA_LANCAMENTO <= '''||:DATAFINAL||''' ';
      END
     ELSE
      BEGIN
        COMANDO1 = :COMANDO1 || '(LANCAMENTOS.DATA_CAIXA >= '''||:DATAINICIAL||''') AND '||
                                '(LANCAMENTOS.DATA_CAIXA <= '''||:DATAFINAL||''')';
      END
     COMANDO1 = :COMANDO1 || ' AND LANCAMENTOS.TIPO_VENDA = '''||'V'||''' AND LANCAMENTOS.CUSTO_UNITARIO <> 0';

     EXECUTE STATEMENT :COMANDO1 INTO :QUANTIDADEVENDA, :VENDAVENDA, :CUSTOVENDA;

     IF (:QUANTIDADEVENDA IS NULL) THEN
        QUANTIDADEVENDA = 0;
     IF (:VENDAVENDA IS NULL) THEN
        VENDAVENDA = 0;
     IF (:CUSTOVENDA IS NULL) THEN
        CUSTOVENDA = 0;

     COMANDO1 = '';
     COMANDO1 = 'SELECT SUM(LANCAMENTOS.QUANTIDADE), SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO), SUM(LANCAMENTOS.CUSTO_UNITARIO * LANCAMENTOS.QUANTIDADE) '||
                'FROM LANCAMENTOS ' ||
                'WHERE LANCAMENTOS.CD_FILIAL = '||:CD_FILIAL||' AND LANCAMENTOS.CD_LABORATORIO = '||:CD_LABORATORIO||' AND LANCAMENTOS.ID_PRODUTO = '||:ID_PRODUTO||' AND ';
     IF (:CODIGOUSUARIO <> '0006') THEN
      BEGIN
        COMANDO1 = :COMANDO1 || 'LANCAMENTOS.DATA_LANCAMENTO >= '''||:DATAINICIAL||''' AND LANCAMENTOS.DATA_LANCAMENTO <= '''||:DATAFINAL||''' ';
      END
     ELSE
      BEGIN
        COMANDO1 = :COMANDO1 || '(LANCAMENTOS.DATA_CAIXA >= '''||:DATAINICIAL||''') AND '||
                                '(LANCAMENTOS.DATA_CAIXA <= '''||:DATAFINAL||''')';
      END
     COMANDO1 = :COMANDO1 || ' AND LANCAMENTOS.TIPO_VENDA = '''||'D'||''' AND LANCAMENTOS.TROCA = '''||'F'||''' AND LANCAMENTOS.CUSTO_UNITARIO <> 0';

     EXECUTE STATEMENT :COMANDO1 INTO :QUANTIDADEDEVOLUCAO, :VENDADEVOLUCAO, :CUSTODEVOLUCAO;

     IF (:QUANTIDADEDEVOLUCAO IS NULL) THEN
        QUANTIDADEDEVOLUCAO = 0;
     IF (:VENDADEVOLUCAO IS NULL) THEN
        VENDADEVOLUCAO = 0;
     IF (:CUSTODEVOLUCAO IS NULL) THEN
        CUSTODEVOLUCAO = 0;

     QUANTIDADE = :QUANTIDADEVENDA - :QUANTIDADEDEVOLUCAO;
     VENDA = :VENDAVENDA - :VENDADEVOLUCAO;
     CUSTO = :CUSTOVENDA - :CUSTODEVOLUCAO;

     IF (QUANTIDADE > 0) THEN
      BEGIN
        MARGEM = ((:VENDA * 100) / :CUSTO) - 100;

        SELECT NOME FROM FILIAIS WHERE CD_FILIAL = :CD_FILIAL INTO :FILIAL;
        SELECT NOME FROM LABORATORIOS WHERE CD_LABORATORIO = :CD_LABORATORIO INTO :NOME;

        SUSPEND;
      END
   END
END ^

ALTER PROCEDURE SP_VERIFICA_CAIXA_ABERTO RETURNS (NCAIXAS INTEGER)
AS 
BEGIN
  SELECT
   COUNT(*)
  FROM
   OPERADORES
  WHERE
   STATUS = 'E' OR
   STATUS = 'F'
  INTO
   :NCAIXAS;
  SUSPEND;
END ^

ALTER PROCEDURE SP_VERIFICA_CONSISTENCIA (DATA DATE)
RETURNS (VENDA DOUBLE PRECISION,
CAIXA DOUBLE PRECISION,
LANCAMENTO DOUBLE PRECISION,
DIFERENCA DOUBLE PRECISION,
STATUS VARCHAR(1) CHARACTER SET NONE)
AS 
BEGIN
 FOR
  SELECT
   CD_VENDA,
   STATUS,
   SUM(VALOR)
  FROM
   CAIXA
  WHERE
   DATA_CAIXA = :DATA AND
   CD_FILIAL = 1
  GROUP BY
   CD_VENDA,
   STATUS
  INTO
   :VENDA,
   :STATUS,
   :CAIXA
 DO
  BEGIN
    LANCAMENTO = 0;
    SELECT
     SUM(VALOR)
    FROM
     LANCAMENTOS
    WHERE
     CD_FILIAL = 1 AND
     CD_VENDA = :VENDA
    HAVING
     SUM(VALOR) <> :CAIXA
    INTO
     :LANCAMENTO;
    IF (LANCAMENTO IS NULL) THEN
       LANCAMENTO = 0;
    IF (CAIXA IS NULL) THEN
        CAIXA = 0;
    DIFERENCA = :LANCAMENTO - :CAIXA;
    IF (DIFERENCA IS NULL) THEN
       DIFERENCA = 0;
    IF (DIFERENCA >= 0.01) THEN
       SUSPEND;
  END
END ^

ALTER PROCEDURE SP_VERIFICA_ESTOQUE_ERRO (DATA_INICIAL DATE)
RETURNS (ESTOQUE_LANCAMENTO DOUBLE PRECISION,
ESTOQUE_TOTAL DOUBLE PRECISION,
PRODUTO DOUBLE PRECISION)
AS 
DECLARE VARIABLE CODIGO_LANCAMENTO DOUBLE PRECISION;
DECLARE VARIABLE QUANTIDADE DOUBLE PRECISION;
DECLARE VARIABLE TIPO_MOVIMENTO VARCHAR(1);
DECLARE VARIABLE COMANDO VARCHAR(1000);
DECLARE VARIABLE DATA_LANCAMENTO DATE;
DECLARE VARIABLE HORA_LANCAMENTO TIME;
DECLARE VARIABLE HORA TIME;
DECLARE VARIABLE DATA DATE;
DECLARE VARIABLE FILIAL DOUBLE PRECISION;
DECLARE VARIABLE TIPO_VENDA VARCHAR(1);
BEGIN
 FOR
  SELECT
   DISTINCT ID_PRODUTO
  FROM
   PRODUTOS
  INTO
   :PRODUTO
 DO
  BEGIN
     FOR
      SELECT
       FIRST 1 CD_FILIAL, DATA_LANCAMENTO, HORA, ESTOQUE_POSVENDA
      FROM
       LANCAMENTOS
      WHERE
       DATA_LANCAMENTO >= :DATA_INICIAL AND
       ID_PRODUTO = :PRODUTO
      ORDER BY
       DATA_LANCAMENTO, HORA
      INTO
       :FILIAL, :DATA_LANCAMENTO, :HORA_LANCAMENTO, :ESTOQUE_LANCAMENTO
     DO
      BEGIN
        ESTOQUE_TOTAL = 0;
        ESTOQUE_TOTAL = :ESTOQUE_LANCAMENTO;
        FOR
         SELECT
          CD_LANCAMENTO, DATA_LANCAMENTO, HORA, QUANTIDADE, ENTRADA_SAIDA, TIPO_VENDA
         FROM
          LANCAMENTOS
         WHERE
          ID_PRODUTO = :PRODUTO AND
          CD_FILIAL = :FILIAL AND
          ((DATA_LANCAMENTO = :DATA_LANCAMENTO AND
          HORA > :HORA_LANCAMENTO) OR
          DATA_LANCAMENTO > :DATA_LANCAMENTO)
         ORDER BY
          DATA_LANCAMENTO, HORA
         INTO
          :CODIGO_LANCAMENTO, :DATA, :HORA, :QUANTIDADE, :TIPO_MOVIMENTO, :TIPO_VENDA
        DO
         BEGIN
           IF (:TIPO_VENDA = 'B') THEN
              ESTOQUE_TOTAL = :QUANTIDADE;
           ELSE
            BEGIN
               IF (:DATA = :DATA_LANCAMENTO) THEN
                BEGIN
                  IF (:HORA > :HORA_LANCAMENTO) THEN
                   BEGIN
                     IF (:TIPO_MOVIMENTO = 'E') THEN
                        ESTOQUE_TOTAL = :ESTOQUE_TOTAL + :QUANTIDADE;
                     ELSE
                     IF (:TIPO_MOVIMENTO = 'S') THEN
                        ESTOQUE_TOTAL = :ESTOQUE_TOTAL - :QUANTIDADE;
                     /*UPDATE LANCAMENTOS SET AUTORIZACAOTRN = CAST(:ESTOQUE_TOTAL AS INTEGER)
                     WHERE CD_LANCAMENTO = :CODIGO_LANCAMENTO AND CD_FILIAL = :FILIAL;*/
                   END
                END
               ELSE
                BEGIN
                     IF (:TIPO_MOVIMENTO = 'E') THEN
                        ESTOQUE_TOTAL = :ESTOQUE_TOTAL + :QUANTIDADE;
                     ELSE
                     IF (:TIPO_MOVIMENTO = 'S') THEN
                        ESTOQUE_TOTAL = :ESTOQUE_TOTAL - :QUANTIDADE;
                     /*UPDATE LANCAMENTOS SET AUTORIZACAOTRN = CAST(:ESTOQUE_TOTAL AS INTEGER)
                     WHERE CD_LANCAMENTO = :CODIGO_LANCAMENTO AND CD_FILIAL = :FILIAL;*/
                END
           END
         END
        /* ALTERANDO O ESTOQUE DO PRODUTO */
        /*COMANDO = 'UPDATE PRODUTOS SET ESTOQUE_'||CAST(:FILIAL AS INTEGER)||' = ' || :ESTOQUE_TOTAL || ' WHERE ID_PRODUTO = ' || :PRODUTO;
        EXECUTE STATEMENT :COMANDO;
        /*SUSPEND;*/
      END
   END
END ^

ALTER PROCEDURE SP_VERIFICA_ESTOQUE_POS_VENDA (CD_FILIAL DOUBLE PRECISION,
DATA_INICIAL DATE)
RETURNS (ESTOQUE_LANCAMENTO DOUBLE PRECISION,
ESTOQUE_TOTAL DOUBLE PRECISION,
PRODUTO DOUBLE PRECISION)
AS 
DECLARE VARIABLE CODIGO_LANCAMENTO DOUBLE PRECISION;
DECLARE VARIABLE QUANTIDADE DOUBLE PRECISION;
DECLARE VARIABLE TIPO_MOVIMENTO VARCHAR(1);
DECLARE VARIABLE DATA_LANCAMENTO DATE;
DECLARE VARIABLE HORA_LANCAMENTO TIME;
DECLARE VARIABLE HORA TIME;
DECLARE VARIABLE DATA DATE;
DECLARE VARIABLE TIPO_VENDA VARCHAR(1);
DECLARE VARIABLE ESTOQUE_POSVENDA DOUBLE PRECISION;
BEGIN
 DELETE FROM TEMP_ESTOQUEPOSVENDA;
 FOR
  SELECT
   DISTINCT ID_PRODUTO
  FROM
   PRODUTOS
  INTO
   :PRODUTO
 DO
  BEGIN
     FOR
      SELECT
       FIRST 1 CD_LANCAMENTO, DATA_LANCAMENTO, HORA, ESTOQUE_POSVENDA
      FROM
       LANCAMENTOS
      WHERE
       DATA_LANCAMENTO >= :DATA_INICIAL AND
       CD_FILIAL = :CD_FILIAL AND
       ID_PRODUTO = :PRODUTO
      ORDER BY
       CD_LANCAMENTO
      INTO
       :CODIGO_LANCAMENTO, :DATA_LANCAMENTO, :HORA_LANCAMENTO, :ESTOQUE_LANCAMENTO
     DO
      BEGIN
        INSERT INTO TEMP_ESTOQUEPOSVENDA VALUES (:CODIGO_LANCAMENTO, :PRODUTO, :DATA_LANCAMENTO, :HORA_LANCAMENTO, '', '', 0, :ESTOQUE_LANCAMENTO, :ESTOQUE_LANCAMENTO);
        ESTOQUE_TOTAL = 0;
        ESTOQUE_TOTAL = :ESTOQUE_LANCAMENTO;
        IF (:ESTOQUE_TOTAL IS NULL) THEN ESTOQUE_TOTAL = 0;
        FOR
         SELECT
          CD_LANCAMENTO, DATA_LANCAMENTO, HORA, QUANTIDADE, ENTRADA_SAIDA, TIPO_VENDA, ESTOQUE_POSVENDA
         FROM
          LANCAMENTOS
         WHERE
          ID_PRODUTO = :PRODUTO AND
          CD_FILIAL = :CD_FILIAL AND
          ((DATA_LANCAMENTO = :DATA_LANCAMENTO AND
          HORA > :HORA_LANCAMENTO) OR
          DATA_LANCAMENTO > :DATA_LANCAMENTO)
         ORDER BY
          CD_LANCAMENTO
         INTO
          :CODIGO_LANCAMENTO, :DATA, :HORA, :QUANTIDADE, :TIPO_MOVIMENTO, :TIPO_VENDA, :ESTOQUE_POSVENDA
        DO
         BEGIN
           IF (:TIPO_VENDA = 'B') THEN
              ESTOQUE_TOTAL = :QUANTIDADE;
           ELSE
            BEGIN
               IF (:DATA = :DATA_LANCAMENTO) THEN
                BEGIN
                  IF (:HORA > :HORA_LANCAMENTO) THEN
                   BEGIN
                     IF (:TIPO_MOVIMENTO = 'E') THEN
                        ESTOQUE_TOTAL = :ESTOQUE_TOTAL + :QUANTIDADE;
                     ELSE
                     IF (:TIPO_MOVIMENTO = 'S') THEN
                        ESTOQUE_TOTAL = :ESTOQUE_TOTAL - :QUANTIDADE;
                   END
                END
               ELSE
                BEGIN
                     IF (:TIPO_MOVIMENTO = 'E') THEN
                        ESTOQUE_TOTAL = :ESTOQUE_TOTAL + :QUANTIDADE;
                     ELSE
                     IF (:TIPO_MOVIMENTO = 'S') THEN
                        ESTOQUE_TOTAL = :ESTOQUE_TOTAL - :QUANTIDADE;
                END
             INSERT INTO TEMP_ESTOQUEPOSVENDA VALUES (:CODIGO_LANCAMENTO, :PRODUTO, :DATA, :HORA, :TIPO_VENDA, :TIPO_MOVIMENTO, :QUANTIDADE, :ESTOQUE_POSVENDA, :ESTOQUE_TOTAL);
           END
         END
      END
   END
END ^

ALTER PROCEDURE SP_VERIFICA_PEDIDOS (CD_COMPRA_ATUAL DOUBLE PRECISION,
CD_COMPRA_ANTERIOR DOUBLE PRECISION)
RETURNS (RESULT VARCHAR(1) CHARACTER SET NONE)
AS 
declare variable ID_PRODUTO double precision;
declare variable QUANTIDADE_ATUAL double precision;
declare variable QUANTIDADE_ANTERIOR double precision;
declare variable QUANTIDADE_NOVA double precision;
declare variable UNIDADES double precision;
declare variable NITENS double precision;
BEGIN
 --ZERANDO VARIAVEIS
 QUANTIDADE_NOVA = 0;
 NITENS = 0;
 UNIDADES = 0;

 --SELECIONA O ID_PRODUTO E A QUANTIDADE DE CADA PRODUTO DO PEDIDO ATUAL
 FOR
   SELECT
     ID_PRODUTO, QUANTIDADE
   FROM
     ITENS_COMPRA
   WHERE
     CD_COMPRAS = :CD_COMPRA_ATUAL
   INTO
    :ID_PRODUTO,
    :QUANTIDADE_ATUAL
 DO
  BEGIN
    --SELECIONANDO A QUANTIDADE PEDIDA DO PRODUTO CASO EXISTA
    SELECT SUM(QUANTIDADE) FROM ITENS_COMPRA WHERE CD_COMPRAS = :CD_COMPRA_ANTERIOR AND ID_PRODUTO = :ID_PRODUTO INTO :QUANTIDADE_ANTERIOR;
    IF (:QUANTIDADE_ANTERIOR IS NULL) THEN
        QUANTIDADE_ANTERIOR = 0;

    --DESCONTANDO QUANTIDADE JA PEDIDA
    QUANTIDADE_NOVA = :QUANTIDADE_ATUAL - :QUANTIDADE_ANTERIOR;
    IF (:QUANTIDADE_NOVA > 0) THEN
     BEGIN
        --ALTERANDO QUANTIDADE DO PRODUTO NO PEDIDO ATUAL, SE NECESSARIO
        UPDATE ITENS_COMPRA SET
          QUANTIDADE = :QUANTIDADE_NOVA
        WHERE CD_COMPRAS = :CD_COMPRA_ATUAL AND ID_PRODUTO = :ID_PRODUTO;
     END
    ELSE
     BEGIN
       --EXCLUINDO PRODUTO DO PEDIDO ATUAL, SE NECESSARIO
       DELETE FROM ITENS_COMPRA WHERE CD_COMPRAS = :CD_COMPRA_ATUAL AND ID_PRODUTO = :ID_PRODUTO;
     END
  END

 --VERIFICANDO SE SOBRARAM PRODUTOS NO PEDIDO ATUAL
 SELECT SUM(QUANTIDADE), COUNT(*) FROM ITENS_COMPRA WHERE CD_COMPRAS = :CD_COMPRA_ATUAL INTO :UNIDADES, :NITENS;
 IF (:UNIDADES IS NULL) THEN
     UNIDADES = 0;
 IF (:UNIDADES > 0) THEN
  BEGIN
     --SE SOBRARAM PRODUTOS NO PEDIDO ATUAL, ALTERA OS TOTAIS DO PEDIDO
     UPDATE COMPRAS SET
       UNIDADES = :UNIDADES,
       NUMERO_ITENS = :NITENS
     WHERE
      CD_COMPRAS = :CD_COMPRA_ATUAL;
     RESULT = 'S';
  END
 ELSE
  BEGIN
    --SE NAO SOBRARAM PRODUTOS NO PEDIDO ATUAL, EXCLUI O PEDIDO ATUAL
    DELETE FROM COMPRAS WHERE CD_COMPRAS = :CD_COMPRA_ATUAL;
    RESULT = 'N';
  END
 SUSPEND;
END ^

ALTER PROCEDURE SP_VERIFICA_PEDIDOS_GERADOS (CD_FILIAL DOUBLE PRECISION)
RETURNS (NPEDIDOS INTEGER)
AS 
BEGIN
 IF (:CD_FILIAL > 0) THEN
  BEGIN
     SELECT COUNT(*) FROM COMPRAS
     WHERE
      CD_FILIAL = :CD_FILIAL AND
      STATUS <> 'C' AND
      STATUS <> 'D'
     INTO :NPEDIDOS;
  END
 ELSE
  BEGIN
     SELECT COUNT(*) FROM COMPRAS
     WHERE
      STATUS <> 'C' AND
      STATUS <> 'D'
     INTO :NPEDIDOS;
  END
 SUSPEND;
END ^

ALTER PROCEDURE SP_VERIFICA_TRANSF_PENDENTE (FILIAL DOUBLE PRECISION)
RETURNS (NTRANSFER INTEGER)
AS 
BEGIN
  SELECT
   COUNT(*)
  FROM
   TRANSFER
  WHERE
   CD_FILIAL_DESTINO = :FILIAL AND
   (DATA_GERACAO >= CURRENT_DATE - 3 OR DATA_ENVIO = CURRENT_DATE - 3) AND
   STATUS <> 'C' AND STATUS <> 'X'
  INTO
   :NTRANSFER;
  SUSPEND;
END ^

ALTER PROCEDURE SP_VERIFICA_VALOR_DIF_LANCAMENT (CD_FILIAL DOUBLE PRECISION,
DAT_INI DATE,
DAT_FIN DATE)
RETURNS (CD_VENDA_CAIXA DOUBLE PRECISION,
DIFERENCA NUMERIC(15, 2),
VALOR_CAIXA NUMERIC(15, 2),
VALOR_LANCAMENTO NUMERIC(15, 2))
AS 
declare variable VALOR_CANCELAMENTO double precision;
declare variable VALOR_CANCELAMENTO_CAIXA double precision;
BEGIN
 FOR
   SELECT CD_VENDA, SUM(VALOR)
   FROM CAIXA
   WHERE DATA_CAIXA >= :DAT_INI AND DATA_CAIXA <= :DAT_FIN AND CD_FILIAL =:CD_FILIAL AND CAIXA.TIPO_VENDA = 'V'
   GROUP BY CD_VENDA
   INTO :CD_VENDA_CAIXA, :VALOR_CAIXA
 DO
   BEGIN
        SELECT SUM(VALOR)
        FROM CAIXA
        WHERE CD_FILIAL =:CD_FILIAL AND CD_VENDA = :CD_VENDA_CAIXA AND TIPO_VENDA = 'D' 
        INTO :VALOR_CANCELAMENTO_CAIXA;

        IF (:VALOR_CANCELAMENTO_CAIXA IS NULL) THEN
           VALOR_CANCELAMENTO_CAIXA = 0;

        VALOR_CAIXA = :VALOR_CAIXA - :VALOR_CANCELAMENTO_CAIXA;

        SELECT SUM (VALOR - ARREDONDAMENTO)
        FROM LANCAMENTOS
        WHERE CD_FILIAL =:CD_FILIAL AND CD_VENDA = :CD_VENDA_CAIXA AND TIPO_VENDA = 'V' 
        INTO :VALOR_LANCAMENTO;

        SELECT SUM (VALOR - ARREDONDAMENTO)
        FROM LANCAMENTOS
        WHERE CD_FILIAL =:CD_FILIAL AND CD_VENDA = :CD_VENDA_CAIXA AND TIPO_VENDA = 'D'
        INTO :VALOR_CANCELAMENTO;

        IF (:VALOR_CANCELAMENTO IS NULL) THEN
         BEGIN
           VALOR_CANCELAMENTO = 0;
         END

        VALOR_LANCAMENTO = :VALOR_LANCAMENTO - :VALOR_CANCELAMENTO;
        DIFERENCA= :VALOR_CAIXA - :VALOR_LANCAMENTO;

        IF ((VALOR_LANCAMENTO > 0) AND (DIFERENCA > 0)) THEN
         BEGIN
           SUSPEND;
         END
   END
END ^

ALTER PROCEDURE SP_VERIFICA_VALOR_PARA_SANGRIA (ID DOUBLE PRECISION,
SOMENTEDINHEIRO VARCHAR(1) CHARACTER SET NONE)
RETURNS (VALOR DOUBLE PRECISION)
AS 
declare variable VALORRECEBIDO double precision;
declare variable VALORCANCELADO double precision;
declare variable VALORSUPRIMENTO double precision;
declare variable VALORSANGRIA double precision;
BEGIN
  IF ((:SOMENTEDINHEIRO IS NOT NULL) AND (:SOMENTEDINHEIRO = 'S')) THEN
   BEGIN
    SELECT SUM(VALOR) FROM CAIXA WHERE ID_OPERADORCAIXA = :ID AND (TIPO_VENDA = 'V' OR ((TIPO_VENDA = 'R') AND (CD_CLIENTE <> 0))) AND CD_FORMA_PAGAMENTO = 1 INTO :VALORRECEBIDO;
    SELECT SUM(VALOR) FROM CAIXA WHERE ID_OPERADORCAIXA = :ID AND TIPO_VENDA = 'D' AND CD_FORMA_PAGAMENTO = 1 INTO :VALORCANCELADO;
    SELECT SUM(VALOR) FROM LANCAMENTOS WHERE ID_OPERADORCAIXA = :ID AND TIPO_VENDA = 'S' AND CD_FORMA_PAGAMENTO = 1INTO :VALORSANGRIA;
   END
  ELSE
   BEGIN
    SELECT SUM(VALOR) FROM CAIXA WHERE ID_OPERADORCAIXA = :ID AND (TIPO_VENDA = 'V' OR ((TIPO_VENDA = 'R') AND (CD_CLIENTE <> 0))) INTO :VALORRECEBIDO;
    SELECT SUM(VALOR) FROM CAIXA WHERE ID_OPERADORCAIXA = :ID AND TIPO_VENDA = 'D' INTO :VALORCANCELADO;
    SELECT SUM(VALOR) FROM LANCAMENTOS WHERE ID_OPERADORCAIXA = :ID AND TIPO_VENDA = 'S' INTO :VALORSANGRIA;
   END

  SELECT SUM(VALOR) FROM LANCAMENTOS WHERE ID_OPERADORCAIXA = :ID AND TIPO_VENDA = 'U' INTO :VALORSUPRIMENTO;
  /* SUPRIMENTO SOMENTE DINHEIRO */

  IF (:VALORRECEBIDO IS NULL) THEN
     VALORRECEBIDO = 0;
  IF (:VALORCANCELADO IS NULL) THEN
     VALORCANCELADO = 0;
  IF (:VALORSUPRIMENTO IS NULL) THEN
     VALORSUPRIMENTO = 0;
  IF (:VALORSANGRIA IS NULL) THEN
     VALORSANGRIA = 0;
  VALOR = :VALORRECEBIDO + :VALORSUPRIMENTO - :VALORCANCELADO - :VALORSANGRIA;
  SUSPEND;
END ^

ALTER PROCEDURE SP_VIRTUAL_METAS_VENDEDORES (CD_VENDEDOR DOUBLE PRECISION,
CD_FILIAL DOUBLE PRECISION,
MES INTEGER,
ANO INTEGER)
RETURNS (DIAS DOUBLE PRECISION,
VALOR DOUBLE PRECISION,
QUANTIDADE DOUBLE PRECISION,
TICKET DOUBLE PRECISION,
CLIENTE DOUBLE PRECISION)
AS 
DECLARE VARIABLE VALORCANCELADO DOUBLE PRECISION;
DECLARE VARIABLE QUANTIDADECANCELADA DOUBLE PRECISION;
DECLARE VARIABLE CLIENTECANCELADO DOUBLE PRECISION;
BEGIN
  SELECT
   COUNT(DISTINCT LANCAMENTOS.DATA_LANCAMENTO),
   SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
   SUM(LANCAMENTOS.QUANTIDADE),
   COUNT(DISTINCT CD_VENDA)
  FROM
   LANCAMENTOS
  WHERE
   EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO) = :MES AND
   EXTRACT(YEAR FROM LANCAMENTOS.DATA_LANCAMENTO) = :ANO AND
   LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
   LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR AND
   LANCAMENTOS.TIPO_VENDA = 'V'
  INTO
   :DIAS, :VALOR, :QUANTIDADE, :CLIENTE;

  IF (:VALOR IS NULL) THEN
     VALOR = 0;
  IF (:QUANTIDADE IS NULL) THEN
     QUANTIDADE = 0;
  IF (:TICKET IS NULL) THEN
     TICKET = 0;
  IF (:CLIENTE IS NULL) THEN
     CLIENTE = 0;

  SELECT
   SUM(LANCAMENTOS.VALOR - LANCAMENTOS.ARREDONDAMENTO),
   SUM(LANCAMENTOS.QUANTIDADE),
   COUNT(DISTINCT CD_VENDA)
  FROM
   LANCAMENTOS
  WHERE
   LANCAMENTOS.CD_FILIAL = :CD_FILIAL AND
   LANCAMENTOS.CD_VENDEDOR = :CD_VENDEDOR AND
   LANCAMENTOS.TIPO_VENDA = 'D' AND
   EXTRACT(MONTH FROM LANCAMENTOS.DATA_LANCAMENTO) = :MES AND
   EXTRACT(YEAR FROM LANCAMENTOS.DATA_LANCAMENTO) = :ANO
  INTO
   :VALORCANCELADO, :QUANTIDADECANCELADA, :CLIENTECANCELADO;

  IF (:VALORCANCELADO IS NULL) THEN
     VALORCANCELADO = 0;
  IF (:QUANTIDADECANCELADA IS NULL) THEN
     QUANTIDADECANCELADA = 0;
  IF (:CLIENTECANCELADO IS NULL) THEN
     CLIENTECANCELADO = 0;

  VALOR = :VALOR - :VALORCANCELADO;
  QUANTIDADE = :QUANTIDADE - :QUANTIDADECANCELADA;
  CLIENTE = :CLIENTE - :CLIENTECANCELADO;
  IF ((:VALOR <> 0) AND (:CLIENTE <> 0)) THEN
     TICKET = :VALOR / :CLIENTE;
  ELSE
     TICKET = 0;

  SUSPEND;

END ^

