ALTER PROCEDURE SP_ZERA_ESTOQUE_NEGATIVO AS 
declare variable FILIAL varchar(2);
declare variable COMANDOSELECT varchar(255);
declare variable ID_PRODUTO double precision;
declare variable CD_PRODUTO varchar(6);
declare variable DESCRICAO varchar(60);
declare variable CD_CLASSE double precision;
declare variable CD_GRUPO double precision;
declare variable CD_LABORATORIO double precision;
declare variable CUSTO_MEDIO double precision;
declare variable CUSTO_UNITARIO double precision;
declare variable ESTOQUE double precision;
declare variable CD_LANCAMENTO double precision;
declare variable COMANDOUPDATE varchar(255);
declare variable CODIGO_BARRAS varchar(14);
declare variable CD_SUBGRUPO double precision;
declare variable CEST varchar(15);
BEGIN
 SELECT CAST(CAST(CD_FILIAL AS INTEGER) AS VARCHAR(2)) FROM PARAMETROS INTO :FILIAL;
 IF ((:FILIAL = '0') OR (:FILIAL = '00') OR (:FILIAL IS NULL)) THEN
  BEGIN
    EXIT;
  END

 COMANDOSELECT = 'SELECT ID_PRODUTO, CD_PRODUTO, CODIGO_BARRAS_1, DESCRICAO, CD_CLASSE, CD_GRUPO, CD_LABORATORIO, '||
                 'CUSTO_UNITARIO, CUSTO_MEDIO, ESTOQUE_'||FILIAL||', CD_SUBGRUPO, CEST FROM PRODUTOS WHERE ESTOQUE_'||FILIAL||' < 0';
 FOR
   EXECUTE STATEMENT :COMANDOSELECT INTO :ID_PRODUTO, :CD_PRODUTO, :CODIGO_BARRAS, :DESCRICAO, :CD_CLASSE, :CD_GRUPO, :CD_LABORATORIO, :CUSTO_UNITARIO, :CUSTO_MEDIO, :ESTOQUE, :CD_SUBGRUPO, :CEST
 DO
  BEGIN
   UPDATE CONTROLE SET VALOR = VALOR + 1 WHERE CAMPO = 'CD_LANCAMENTO';
   SELECT VALOR FROM CONTROLE WHERE CAMPO = 'CD_LANCAMENTO' INTO :CD_LANCAMENTO;
   ESTOQUE = :ESTOQUE * -1;

   INSERT INTO LANCAMENTOS VALUES (:CD_LANCAMENTO, :ID_PRODUTO, NULL, :FILIAL, :CD_PRODUTO, :DESCRICAO, :CD_LABORATORIO,
                                   :CD_GRUPO, :CD_CLASSE, 0, 0, 0, 0, 0, NULL, :CD_LANCAMENTO, 0, :CUSTO_MEDIO, :CUSTO_UNITARIO,
                                   CURRENT_DATE, CURRENT_DATE, :ESTOQUE, (:CUSTO_UNITARIO * :ESTOQUE),
                                   0, 'ACERTO', 0, 0, 'B', NULL, 'E', 'N', 'N', CURRENT_TIME, 0, 'N', '', :CD_LANCAMENTO,
                                   0, 'SISTEMA', 'ACERTO DE ESTOQUE', 0, NULL, NULL, NULL, NULL, NULL, 'N', 0, '', '', '', '',
                                   :CODIGO_BARRAS, '', :CD_SUBGRUPO, '', 0, :CEST, NULL, NULL, 'N', :ID_PRODUTO,
                                   'N', 'N', 'N', 'N');

   COMANDOUPDATE = 'UPDATE PRODUTOS SET ESTOQUE_'||FILIAL||' = 0 WHERE ID_PRODUTO = '||ID_PRODUTO;
   EXECUTE STATEMENT :COMANDOUPDATE;
  END
END ^

