ALTER PROCEDURE STR_ZERO (STRING VARCHAR(50) CHARACTER SET NONE,
QTD INTEGER)
RETURNS (RESULT VARCHAR(50) CHARACTER SET NONE)
AS 
DECLARE VARIABLE i Integer;
DECLARE VARIABLE T iNTEGER;
BEGIN

i = 0;

RESULT = :STRING;

SELECT * FROM TAMANHO(:STRING) INTO :T;

while (i < (:QTD - :T))do
begin

RESULT = '0' || RESULT;

i = i + 1;

SELECT * FROM TAMANHO(:STRING) INTO :T;

end

SUSPEND;

END ^

ALTER PROCEDURE SUPORTE_TAMANHO_TABELAS RETURNS (TABELA VARCHAR(31) CHARACTER SET NONE,
QTD_REG INTEGER)
AS 
declare variable comando varchar(100); 
 declare variable qtdtot integer; 
 declare variable qtdtab integer; 
begin 
 qtdtot = 0; 
 qtdtab = 0;


 for select rdb$relation_name 
   from rdb$relations 
   where rdb$flags = 1 and rdb$view_blr is null 
   order by 1 
   into :tabela do 
 begin 
   qtdtab = qtdtab + 1;
   comando = 'select count(*) from ' || :tabela; 
   execute statement :comando into :qtd_reg; 
   qtdtot = :qtdtot + :qtd_reg; 
   suspend; 
 end 
 tabela = :qtdtab || ' Tabelas - Total:'; 
 qtd_reg = :qtdtot; 
 suspend; 
end ^

ALTER PROCEDURE TAMANHO (STR VARCHAR(1000) CHARACTER SET NONE)
RETURNS (LEN INTEGER)
AS 
declare variable pat varchar(1000);
BEGIN len = null;
  IF (str IS NULL) THEN
    EXIT;
  pat = '';
  len = 0;

  WHILE (NOT str LIKE pat) DO
  BEGIN
    pat = pat || '_';
    len = len + 1;
  END
  suspend;
END ^
SET TERM ; ^
COMMIT WORK ;
SET AUTODDL ON;
SET TERM ^ ;

