BEGIN
    SELECT TIPO_LOJA FROM PARAMETROS INTO :TIPOLOJA;
    IF (:TIPOLOJA <> 'U') THEN
       INSERT INTO DELETADOS VALUES (OLD.CD_FILIAL, 'BALANCO', CAST(CAST(OLD.ID_BALANCO AS NUMERIC(15,0)) AS VARCHAR(20)), CAST(CAST(OLD.ID_BALANCO AS NUMERIC(15,0)) AS VARCHAR(20)), CURRENT_DATE,  CURRENT_TIME, '', '');
END ^

CREATE TRIGGER CAIXA_BD0 FOR CAIXA 
ACTIVE BEFORE DELETE POSITION 0 
AS
begin
  INSERT INTO CAIXA2 VALUES (OLD.CD_CAIXA,
