CREATE TRIGGER TG_AT_ENVIADO_CLASSES FOR CLASSES 
ACTIVE BEFORE INSERT OR UPDATE POSITION 0 
AS
DECLARE VARIABLE EXISTE INTEGER;
DECLARE VARIABLE CONVENIO DOUBLE PRECISION;
begin
  NEW.ENVIADO = '';

  SELECT COUNT(*) FROM CONVENIOS_CLASSES WHERE CD_CLASSE = NEW.CD_CLASSE INTO :EXISTE;
  IF (:EXISTE = 0) THEN
   BEGIN
     FOR
       SELECT CD_CONVENIO FROM CONVENIOS INTO :CONVENIO
     DO
      BEGIN
        INSERT INTO CONVENIOS_CLASSES VALUES (:CONVENIO, NEW.CD_CLASSE, NEW.DESCRICAO, 0);
      END
   END
  ELSE
   BEGIN
     UPDATE CONVENIOS_CLASSES SET DESCRICAO = NEW.DESCRICAO WHERE CD_CLASSE = NEW.CD_CLASSE;
   END

  SELECT COUNT(*) FROM VENDEDORES_CLASSES WHERE CD_CLASSE = NEW.CD_CLASSE INTO :EXISTE;
  IF (:EXISTE = 0) THEN
   BEGIN
     FOR
       SELECT CD_VENDEDOR FROM VENDEDORES INTO :CONVENIO
     DO
      BEGIN
        INSERT INTO VENDEDORES_CLASSES VALUES (:CONVENIO, NEW.CD_CLASSE, NEW.DESCRICAO, 0, ' ');
      END
   END
  ELSE
   BEGIN
     UPDATE VENDEDORES_CLASSES SET DESCRICAO = NEW.DESCRICAO WHERE CD_CLASSE = NEW.CD_CLASSE;
   END
end ^

