CREATE TRIGGER TG_AT_DT_ALTERACAO_CLIENTES FOR CLIENTES 
ACTIVE BEFORE INSERT OR UPDATE POSITION 0 
AS
DECLARE VARIABLE CD_FILIAL DOUBLE PRECISION;
DECLARE VARIABLE TIPOLOJA VARCHAR(1);
DECLARE VARIABLE EXISTE INTEGER;
BEGIN
  /* Trigger text */
  NEW.DT_ALTERACAO = CURRENT_DATE;
  SELECT CD_FILIAL, TIPO_LOJA FROM PARAMETROS INTO :CD_FILIAL, :TIPOLOJA;
  IF (:TIPOLOJA = 'M') THEN
   BEGIN
    /* popula TEMP_PRODUTOS na MATRIZ para os produtos que sofreram alteracoes de cadastro*/
      FOR
       SELECT CD_FILIAL FROM FILIAIS WHERE EXPORTAR = 'S' INTO :CD_FILIAL
      DO
        BEGIN
           SELECT COUNT(*) FROM TEMP_PRODUTOS WHERE CD_FILIAL = :CD_FILIAL AND ID_PRODUTO = NEW.CD_CLIENTE AND PROCESSO = 110 INTO :EXISTE;
           IF (:EXISTE = 0) THEN
              INSERT INTO TEMP_PRODUTOS VALUES (NEW.CD_CLIENTE, :CD_FILIAL, 110, '');
           IF ((NEW.LIMITE_CREDITO <> OLD.LIMITE_CREDITO) OR
               (NEW.LIMITE_PERCENTUAL <> OLD.LIMITE_PERCENTUAL) OR
               (NEW.SALDO <> OLD.SALDO) OR
               (NEW.STATUS <> OLD.STATUS)) THEN
             BEGIN
               SELECT COUNT(*) FROM TEMP_PRODUTOS WHERE CD_FILIAL = :CD_FILIAL AND ID_PRODUTO = NEW.CD_CLIENTE AND PROCESSO = 151 INTO :EXISTE;
               IF (:EXISTE = 0) THEN
                  INSERT INTO TEMP_PRODUTOS VALUES (NEW.CD_CLIENTE, :CD_FILIAL, 151, '');
             END
        END
   END
  ELSE
   BEGIN
     IF (:TIPOLOJA = 'L') THEN
      BEGIN
        NEW.ENVIADO = ' ';
        SELECT COUNT(*) FROM TEMP_PRODUTOS WHERE CD_FILIAL = :CD_FILIAL AND ID_PRODUTO = NEW.CD_CLIENTE AND PROCESSO = 14 INTO :EXISTE;
        IF (:EXISTE = 0) THEN
           INSERT INTO TEMP_PRODUTOS VALUES (NEW.CD_CLIENTE, :CD_FILIAL, 14, '');
      END
   END
END ^

