CREATE TRIGGER TG_AT_DT_ALTERACAO_CR FOR CONTAS_RECEBER 
ACTIVE BEFORE INSERT OR UPDATE POSITION 0 
AS
DECLARE VARIABLE FILIAL DOUBLE PRECISION;
DECLARE VARIABLE TIPOLOJA VARCHAR(1);
DECLARE VARIABLE EXISTE INTEGER;
BEGIN
  NEW.DT_ALTERACAO = CURRENT_DATE;
  NEW.ENVIADO = ' ';
  SELECT CD_FILIAL, TIPO_LOJA FROM PARAMETROS INTO :FILIAL, :TIPOLOJA;
  IF ((:TIPOLOJA = 'M') AND ((NEW.CD_FORMA_PAGAMENTO = 3) OR (NEW.CD_FORMA_PAGAMENTO = 5))) THEN
   BEGIN
     FOR
       SELECT CD_FILIAL FROM FILIAIS WHERE EXPORTAR = 'S' INTO :FILIAL
     DO
      BEGIN
         SELECT COUNT(*) FROM TEMP_PRODUTOS WHERE CD_FILIAL = :FILIAL AND ID_PRODUTO = NEW.CD_CONTAS_RECEBER AND PROCESSO = 121  INTO :EXISTE;
         IF (:EXISTE = 0) THEN
            INSERT INTO TEMP_PRODUTOS VALUES (NEW.CD_CONTAS_RECEBER, :FILIAL, 121, '');
      END
   END
  ELSE
  IF ((:TIPOLOJA = 'M') AND ((NEW.CD_FORMA_PAGAMENTO = 2) OR (NEW.CD_FORMA_PAGAMENTO = 4) OR (NEW.CD_FORMA_PAGAMENTO = 6)) AND (NEW.STATUS = 'P')) THEN
   BEGIN
       SELECT COUNT(*) FROM TEMP_PRODUTOS WHERE CD_FILIAL = NEW.CD_FILIAL AND ID_PRODUTO = NEW.CD_CONTAS_RECEBER AND PROCESSO = 121  INTO :EXISTE;
       IF (:EXISTE = 0) THEN
          INSERT INTO TEMP_PRODUTOS VALUES (NEW.CD_CONTAS_RECEBER, NEW.CD_FILIAL, 121, '');
   END
  ELSE
  IF (:TIPOLOJA = 'L') THEN
   BEGIN
       SELECT COUNT(*) FROM TEMP_PRODUTOS WHERE CD_FILIAL = :FILIAL AND ID_PRODUTO = NEW.CD_CONTAS_RECEBER AND PROCESSO = 3 INTO :EXISTE;
       IF (:EXISTE = 0) THEN
          INSERT INTO TEMP_PRODUTOS VALUES (NEW.CD_CONTAS_RECEBER, :FILIAL, 3, '');
   END
END ^

