CREATE TRIGGER CONTAS_RECEBER_BU0 FOR CONTAS_RECEBER 
ACTIVE AFTER INSERT OR UPDATE POSITION 0 
AS
DECLARE VARIABLE TIPOLOJA VARCHAR(1);
DECLARE VARIABLE CLIENTETRN DOUBLE PRECISION;
DECLARE VARIABLE CLIENTEORIZON DOUBLE PRECISION;
DECLARE VARIABLE CLIENTEPHARMASYSTEM DOUBLE PRECISION;
DECLARE VARIABLE CLIENTEVIDALINK DOUBLE PRECISION;
DECLARE VARIABLE CLIENTEEPHARMA DOUBLE PRECISION;
DECLARE VARIABLE CLIENTEFUNCIONALCARD DOUBLE PRECISION;
DECLARE VARIABLE CLIENTEWSCONVENIO DOUBLE PRECISION;
DECLARE VARIABLE CLIENTEFARMACIAPOPULAR DOUBLE PRECISION;
BEGIN
 SELECT
  PARAMETROS.CLIENTETRN, PARAMETROS.CLIENTEEPHARMA, PARAMETROS.CLIENTEFUNCIONALCARD,
  PARAMETROS.CLIENTEVIDALINK, PARAMETROS.CLIENTEFARMACIAPOPULAR, PARAMETROS.CLIENTEORIZON,
  PARAMETROS.CLIENTEPHARMASYSTEM, PARAMETROS.CLIENTEWSCONVENIO
 FROM
  PARAMETROS
 INTO
  :CLIENTETRN, :CLIENTEEPHARMA, :CLIENTEFUNCIONALCARD,
  :CLIENTEVIDALINK, :CLIENTEFARMACIAPOPULAR, :CLIENTEORIZON,
  :CLIENTEPHARMASYSTEM, :CLIENTEWSCONVENIO;

 IF ((NEW.CD_CLIENTE <> 999999) AND
     (NEW.CD_CLIENTE <> :CLIENTEEPHARMA) AND (NEW.CD_CLIENTE <> :CLIENTEFARMACIAPOPULAR) AND
     (NEW.CD_CLIENTE <> :CLIENTEFUNCIONALCARD) AND (NEW.CD_CLIENTE <> :CLIENTEORIZON) AND
     (NEW.CD_CLIENTE <> :CLIENTEPHARMASYSTEM) AND (NEW.CD_CLIENTE <> :CLIENTETRN) AND
     (NEW.CD_CLIENTE <> :CLIENTEVIDALINK) AND (NEW.CD_CLIENTE <> :CLIENTEWSCONVENIO)) THEN
  BEGIN
    SELECT TIPO_LOJA FROM PARAMETROS INTO :TIPOLOJA;
    IF (:TIPOLOJA <> 'M') THEN
     BEGIN
        EXECUTE PROCEDURE SP_ACERTA_SALDO_CLIENTE_UNICO(NEW.CD_CLIENTE);
     END
  END
END ^

