CREATE TRIGGER CRM_BIU0 FOR CRM 
ACTIVE BEFORE INSERT OR UPDATE POSITION 0 
AS
DECLARE VARIABLE CD_FILIAL DOUBLE PRECISION;
BEGIN
 NEW.ENVIADO = '';
 IF ((NEW.CD_FILIAL IS NULL) AND (NEW.FILIAL IS NOT NULL)) THEN
  BEGIN
    NEW.CD_FILIAL = NEW.FILIAL;
  END
 ELSE
 IF ((NEW.FILIAL IS NULL) AND (NEW.CD_FILIAL IS NOT NULL)) THEN
  BEGIN
    NEW.FILIAL = NEW.CD_FILIAL;
  END
 ELSE
 IF ((NEW.FILIAL IS NULL) AND (NEW.CD_FILIAL IS NULL)) THEN
  BEGIN
    SELECT CD_FILIAL FROM PARAMETROS INTO :CD_FILIAL;
    IF (:CD_FILIAL > 0) THEN
     BEGIN
       NEW.FILIAL = :CD_FILIAL;
       NEW.CD_FILIAL = :CD_FILIAL;
     END
  END
END ^

