BEGIN
  SELECT TIPO_LOJA FROM PARAMETROS INTO :TIPO_LOJA;

  DELETE FROM PRODUTOS_FIDELIDADE WHERE ID_PRODUTO = OLD.ID_PRODUTO;

  INSERT INTO DELETADOS VALUES (OLD.CD_FILIAL, 'FILIAIS_FIDELIDADE',
                                CAST(CAST(OLD.ID_PRODUTO AS NUMERIC(15,0)) AS VARCHAR(20)),
                                CAST(CAST(OLD.ID_PRODUTO AS NUMERIC(15,0)) AS VARCHAR(20)),
                                CURRENT_DATE, CURRENT_TIME, NULL, '');

  SELECT COUNT(*) FROM TEMP_PRODUTOS WHERE CD_FILIAL = OLD.CD_FILIAL AND PROCESSO = 158 AND ID_PRODUTO = OLD.ID_PRODUTO INTO :EXISTE;
  IF (:EXISTE > 0) THEN
   BEGIN
     DELETE FROM TEMP_PRODUTOS WHERE CD_FILIAL = OLD.CD_FILIAL AND PROCESSO = 158 AND ID_PRODUTO = OLD.ID_PRODUTO;
   END
END ^

CREATE TRIGGER TG_FILIAIS_FIDELIDADE_BU0 FOR FILIAIS_FIDELIDADE 
ACTIVE BEFORE INSERT OR UPDATE POSITION 0 
AS
DECLARE VARIABLE TIPO_LOJA VARCHAR(1);
DECLARE VARIABLE EXISTE INTEGER;
DECLARE VARIABLE PRECO_VENDA DOUBLE PRECISION;
DECLARE VARIABLE COMANDO VARCHAR(100);
BEGIN
  NEW.DT_ALTERACAO = CURRENT_DATE;
  SELECT TIPO_LOJA FROM PARAMETROS INTO :TIPO_LOJA;
  COMANDO = '';
  COMANDO = 'SELECT PRECO_VENDA_' || CAST(NEW.CD_FILIAL AS INTEGER) || ' FROM PRODUTOS WHERE ID_PRODUTO = ' || CAST(NEW.ID_PRODUTO AS INTEGER);
  EXECUTE STATEMENT :COMANDO INTO :PRECO_VENDA;
  IF (:PRECO_VENDA < NEW.PRECO) THEN
     NEW.PRECO = :PRECO_VENDA - 0.01;
  IF (:TIPO_LOJA = 'M') THEN
   BEGIN
      SELECT COUNT(*) FROM TEMP_PRODUTOS WHERE CD_FILIAL = NEW.CD_FILIAL AND PROCESSO = 158 AND ID_PRODUTO = NEW.ID_PRODUTO INTO :EXISTE;
      IF (:EXISTE = 0) THEN
       BEGIN
         INSERT INTO TEMP_PRODUTOS VALUES (NEW.ID_PRODUTO, NEW.CD_FILIAL, 158, '');
       END
   END
  ELSE
  IF (:TIPO_LOJA = 'U') THEN
   BEGIN
     SELECT COUNT(*) FROM PRODUTOS_FIDELIDADE WHERE ID_PRODUTO = NEW.ID_PRODUTO INTO :EXISTE;
     IF (:EXISTE > 0) THEN
      BEGIN
        UPDATE PRODUTOS_FIDELIDADE SET
         PRODUTOS_FIDELIDADE.CD_LABORATORIO = NEW.CD_LABORATORIO,
         PRODUTOS_FIDELIDADE.CD_GRUPO = NEW.CD_GRUPO,
         PRODUTOS_FIDELIDADE.DESCRICAO = NEW.DESCRICAO,
         PRODUTOS_FIDELIDADE.PRECO = NEW.PRECO
        WHERE PRODUTOS_FIDELIDADE.ID_PRODUTO = NEW.ID_PRODUTO;
      END
     ELSE
      BEGIN
        INSERT INTO PRODUTOS_FIDELIDADE VALUES (NEW.ID_PRODUTO, NEW.CD_PRODUTO,  NEW.CD_LABORATORIO, NEW.CD_GRUPO, NEW.DESCRICAO, NEW.PRECO, NEW.DT_ALTERACAO);
      END
   END
END ^

