CREATE TRIGGER FILIAIS_PRECO_QUANTIDADE_BD0 FOR FILIAIS_PRECO_QUANTIDADE 
ACTIVE BEFORE DELETE POSITION 0 
AS
DECLARE VARIABLE EXISTE INTEGER;
DECLARE VARIABLE TIPO_LOJA VARCHAR(1);
BEGIN
  SELECT TIPO_LOJA FROM PARAMETROS INTO :TIPO_LOJA;

  IF (:TIPO_LOJA = 'U') THEN
   BEGIN
     DELETE FROM PRODUTOS_PRECO_QUANTIDADE WHERE ID_PRODUTO = OLD.ID_PRODUTO AND QUANTIDADEINICIAL = OLD.QUANTIDADEINICIAL;
   END
  ELSE
   BEGIN
     IF (:TIPO_LOJA = 'M') THEN
      BEGIN
        SELECT COUNT(*) FROM TEMP_PRODUTOS_QUANTIDADE
        WHERE CD_FILIAL = OLD.CD_FILIAL AND ID_PRODUTO = OLD.ID_PRODUTO AND QUANTIDADEINICIAL = OLD.QUANTIDADEINICIAL
        INTO :EXISTE;

        IF (:EXISTE > 0) THEN
         BEGIN
           DELETE FROM TEMP_PRODUTOS_QUANTIDADE WHERE CD_FILIAL = OLD.CD_FILIAL AND ID_PRODUTO = OLD.ID_PRODUTO AND QUANTIDADEINICIAL = OLD.QUANTIDADEINICIAL;
         END

        SELECT COUNT(*) FROM DELETADOS
        WHERE CD_FILIAL = OLD.CD_FILIAL AND TABELA = 'PRODUTOS_PRECO_QUANTIDADE' AND
              CAMPO1 = CAST(CAST(OLD.ID_PRODUTO AS NUMERIC(15,0)) AS VARCHAR(20)) AND
              CAMPO2 = CAST(CAST(OLD.QUANTIDADEINICIAL AS NUMERIC(15,0)) AS VARCHAR(20))
        INTO :EXISTE;

        IF (:EXISTE = 0) THEN
         BEGIN
          INSERT INTO DELETADOS VALUES (OLD.CD_FILIAL, 'PRODUTOS_PRECO_QUANTIDADE',
                                        CAST(CAST(OLD.ID_PRODUTO AS NUMERIC(15,0)) AS VARCHAR(20)),
                                        CAST(CAST(OLD.QUANTIDADEINICIAL AS NUMERIC(15,0)) AS VARCHAR(20)),
                                        CURRENT_DATE, CURRENT_TIME, NULL, '');
         END
      END
   END
END ^

