        WHERE
         PRODUTOS_PRECO_QUANTIDADE.ID_PRODUTO = NEW.ID_PRODUTO AND
         PRODUTOS_PRECO_QUANTIDADE.QUANTIDADEINICIAL = NEW.QUANTIDADEINICIAL;
