AS
begin
  IF (NEW.CD_ATENDIMENTO IS NULL) THEN
   BEGIN
      NEW.CD_ATENDIMENTO = 'M';
   END
end ^

CREATE TRIGGER TG_EXC_ITENS_COMPRA FOR ITENS_COMPRA 
ACTIVE BEFORE DELETE POSITION 0 
AS
DECLARE VARIABLE CD_FILIAL DOUBLE PRECISION;
DECLARE VARIABLE STATUS VARCHAR(1);
DECLARE VARIABLE TIPOLOJA VARCHAR(1);
BEGIN
  SELECT TIPO_LOJA FROM PARAMETROS INTO :TIPOLOJA;
  IF (:TIPOLOJA <> 'U') THEN
   BEGIN
      SELECT CD_FILIAL, STATUS FROM COMPRAS WHERE CD_COMPRAS = OLD.CD_COMPRAS INTO :CD_FILIAL, :STATUS;
      IF ((:STATUS <> 'G') AND (:STATUS <> 'M')) THEN
       BEGIN
         INSERT INTO DELETADOS VALUES (:CD_FILIAL, 'ITENS_COMPRA',
                                       CAST(CAST(OLD.CD_COMPRAS AS NUMERIC(15,0)) AS VARCHAR(20)),
                                       CAST(CAST(OLD.ID_PRODUTO AS NUMERIC(15,0)) AS VARCHAR(20)),
                                       CURRENT_DATE, CURRENT_TIME, NULL, '');
       END
   END
END ^

CREATE TRIGGER TG_AT_ITENS_COMPRAS FOR ITENS_COMPRA 
ACTIVE BEFORE INSERT OR UPDATE POSITION 1 
AS
DECLARE VARIABLE TIPOLOJA VARCHAR(1);
DECLARE VARIABLE EXISTE INTEGER;
BEGIN
  SELECT TIPO_LOJA FROM PARAMETROS INTO :TIPOLOJA;
  IF (:TIPOLOJA <> 'U') THEN
   BEGIN
     SELECT COUNT(*) FROM TEMP_COMPRAS WHERE CD_COMPRAS = NEW.CD_COMPRAS AND ID_PRODUTO = NEW.ID_PRODUTO AND PROCESSO = '5' INTO :EXISTE;
     IF (:EXISTE = 0) THEN
      BEGIN
        INSERT INTO TEMP_COMPRAS VALUES (NEW.CD_COMPRAS,  NEW.ID_PRODUTO, NEW.CD_FILIAL, '5', '');
      END
   END
END ^

