CREATE TRIGGER TG_EXC_LABORATORIOS FOR LABORATORIOS 
ACTIVE BEFORE DELETE POSITION 0 
AS
DECLARE VARIABLE CD_FILIAL DOUBLE PRECISION;
BEGIN
  SELECT CD_FILIAL FROM PARAMETROS INTO :CD_FILIAL;
  IF (CD_FILIAL = 0) THEN
   BEGIN
      FOR
       SELECT CD_FILIAL FROM FILIAIS WHERE EXPORTAR = 'S' INTO :CD_FILIAL
      DO
       BEGIN
        INSERT INTO DELETADOS VALUES (:CD_FILIAL, 'LABORATORIOS',
                                      CAST(CAST(OLD.CD_LABORATORIO AS NUMERIC(15,0)) AS VARCHAR(20)),
                                      CAST(CAST(OLD.CD_LABORATORIO AS NUMERIC(15,0)) AS VARCHAR(20)),
                                      CURRENT_DATE, CURRENT_TIME, NULL, '');
       END
   END
END ^

CREATE TRIGGER TG_AT_DT_ALTERACAO_LABORATORIOS FOR LABORATORIOS 
ACTIVE BEFORE INSERT OR UPDATE POSITION 0 
AS
DECLARE VARIABLE CD_FILIAL DOUBLE PRECISION;
DECLARE VARIABLE TIPOLOJA VARCHAR(1);
DECLARE VARIABLE EXISTE INTEGER;
BEGIN
  /* Trigger text */
  NEW.DT_ALTERACAO = CURRENT_DATE;
  SELECT CD_FILIAL, TIPO_LOJA FROM PARAMETROS INTO :CD_FILIAL, :TIPOLOJA;
  IF (:TIPOLOJA = 'M') THEN
   BEGIN
      /* popula TEMP_PRODUTOS na MATRIZ para os produtos que sofreram alteracoes de cadastro*/
      FOR
       SELECT CD_FILIAL FROM FILIAIS WHERE EXPORTAR = 'S' INTO :CD_FILIAL
      DO
        BEGIN
          SELECT COUNT(*) FROM TEMP_PRODUTOS WHERE CD_FILIAL = :CD_FILIAL AND ID_PRODUTO = NEW.CD_LABORATORIO AND PROCESSO = 101 INTO :EXISTE;
          IF (:EXISTE = 0) THEN
             INSERT INTO TEMP_PRODUTOS VALUES (NEW.CD_LABORATORIO, :CD_FILIAL, 101, '');
        END
   END
END ^

CREATE TRIGGER LANCAMENTOS_BI0 FOR LANCAMENTOS 
ACTIVE BEFORE INSERT POSITION 0 
AS
DECLARE VARIABLE CD_FILIAL DOUBLE PRECISION;
DECLARE VARIABLE TIPO_LOJA VARCHAR(1);
DECLARE VARIABLE EXISTE INTEGER;
BEGIN
  /* Trigger text */
  IF ((NEW.CUSTO_UNITARIO IS NULL) OR (NEW.CUSTO_UNITARIO <= 0)) THEN
     NEW.CUSTO_UNITARIO = 0.01;

  SELECT CD_FILIAL, TIPO_LOJA FROM PARAMETROS INTO :CD_FILIAL, :TIPO_LOJA;
  IF ((NEW.TIPO_VENDA = 'V') OR (NEW.TIPO_VENDA = 'D')) THEN
   BEGIN
     IF ((NEW.CD_CLIENTE IS NOT NULL) AND (NEW.CD_CLIENTE <> 0) AND (NEW.CD_CLIENTE <> 999999)) THEN
      BEGIN
         IF ((:TIPO_LOJA = 'L') OR (:TIPO_LOJA = 'U')) THEN
          BEGIN
            INSERT INTO LANCAMENTOS_APRAZO VALUES (
              NEW.CD_LANCAMENTO, NEW.ID_PRODUTO, NEW.CD_FILIAL, NEW.CD_PRODUTO, NEW.DESCRICAO,
              NEW.CD_LABORATORIO, NEW.CD_GRUPO, NEW.CD_CLASSE, NEW.CD_CONVENIO, NEW.CD_CLIENTE,
              NEW.CD_VENDEDOR, NEW.CD_OPERADOR, NEW.CD_USUARIO, NEW.CD_FORMA_PAGAMENTO, NEW.CD_VENDA,
              NEW.ID_OPERADORCAIXA, CAST(NEW.CUSTO_MEDIO AS NUMERIC(10,2)), CAST(NEW.CUSTO_UNITARIO AS NUMERIC(10,2)),
              NEW.DATA_LANCAMENTO, NEW.DATA_CAIXA, NEW.QUANTIDADE, CAST(NEW.VALOR AS NUMERIC(10,2)),
              CAST(NEW.COMISSAO AS NUMERIC(10,2)), NEW.NOTA_FISCAL, CAST(NEW.DESCONTO AS NUMERIC(10,2)),
              CAST(NEW.PROMOCAO AS NUMERIC(10,2)), NEW.TIPO_VENDA, NEW.TIPO_PAGAMENTO, NEW.ENTRADA_SAIDA, NEW.ETIQUETA,
              NEW.ENTREGA, NEW.HORA, NEW.ESTOQUE_POSVENDA, NEW.TROCA, ' ', NEW.NUMERO,
              NEW.TERMINAL, NEW.USUARIO, NEW.OBSERVACAO, CAST(NEW.ARREDONDAMENTO AS NUMERIC(10,2)), NEW.TRN, NEW.TRANSACAOTRN,
              NEW.LOTETRN, NEW.AUTORIZACAOTRN, NEW.SUBSIDIOTRN, NEW.NOTAMANUAL);
          END
      END
   END
  IF ((:TIPO_LOJA = 'L') OR (:TIPO_LOJA = 'U')) THEN
   BEGIN
    IF (NEW.ID_PRODUTO > 0) THEN
     BEGIN
        SELECT COUNT(*) FROM ESTOQUEPOSVENDA WHERE ID_PRODUTO = NEW.ID_PRODUTO INTO :EXISTE;
        IF (:EXISTE > 0) THEN
         BEGIN
           UPDATE ESTOQUEPOSVENDA SET ESTOQUEPOSVENDA = NEW.ESTOQUE_POSVENDA WHERE ID_PRODUTO = NEW.ID_PRODUTO;
         END
        ELSE
         BEGIN
           INSERT INTO ESTOQUEPOSVENDA VALUES (NEW.ID_PRODUTO, NEW.ESTOQUE_POSVENDA, NEW.TIPO_VENDA);
         END
     END
   END
END ^

