CREATE TRIGGER LANCAMENTOS_APRAZO_AI0 FOR LANCAMENTOS_APRAZO 
ACTIVE AFTER INSERT POSITION 0 
AS
DECLARE VARIABLE TIPO_LOJA VARCHAR(1);
DECLARE VARIABLE CD_FILIAL DOUBLE PRECISION;
DECLARE VARIABLE FILIAL DOUBLE PRECISION;
BEGIN
  SELECT CD_FILIAL, TIPO_LOJA FROM PARAMETROS INTO :FILIAL, :TIPO_LOJA;
  IF (:TIPO_LOJA = 'M') THEN
   BEGIN
      FOR
       SELECT
        CD_FILIAL
       FROM
        FILIAIS
       WHERE
        CD_FILIAL <> NEW.CD_FILIAL AND
        EXPORTAR = 'S'
       INTO
        :CD_FILIAL
      DO
       BEGIN
        INSERT INTO TEMP_LANCAMENTOS_APRAZO VALUES (NEW.CD_LANCAMENTO, NEW.CD_FILIAL, :CD_FILIAL);
       END
   END
  ELSE
  IF (:TIPO_LOJA = 'L') THEN
   BEGIN
     IF (:FILIAL = NEW.CD_FILIAL) THEN
        INSERT INTO TEMP_LANCAMENTOS_APRAZO VALUES (NEW.CD_LANCAMENTO, 0, 0);
   END
END ^

