CREATE TRIGGER PERMISSOES_BIU0 FOR PERMISSOES 
ACTIVE BEFORE INSERT OR UPDATE POSITION 0 
AS
DECLARE VARIABLE TIPOLOJA VARCHAR(1);
DECLARE VARIABLE CD_FILIAL DOUBLE PRECISION;
DECLARE VARIABLE EXISTE INTEGER;
BEGIN
  NEW.DESCRICAO = UPPER(NEW.DESCRICAO);
  SELECT TIPO_LOJA FROM PARAMETROS INTO :TIPOLOJA;
  IF (:TIPOLOJA = 'M') THEN
   BEGIN
     FOR
      SELECT CD_FILIAL FROM FILIAIS WHERE FILIAIS.EXPORTAR = 'S' INTO :CD_FILIAL
     DO
      BEGIN
        SELECT COUNT(*) FROM TEMP_PRODUTOS WHERE CD_FILIAL = :CD_FILIAL AND ID_PRODUTO = NEW.CD_PERMISSAO AND PROCESSO = 143 INTO :EXISTE;
        IF (:EXISTE = 0) THEN
           INSERT INTO TEMP_PRODUTOS VALUES (NEW.CD_PERMISSAO, :CD_FILIAL,  143, ' ');
      END
   END
END ^

