CREATE TRIGGER TG_EXC_PLANO_CONTAS FOR PLANO_CONTAS 
ACTIVE BEFORE DELETE POSITION 0 
AS
DECLARE VARIABLE CD_FILIAL DOUBLE PRECISION;
BEGIN
  SELECT CD_FILIAL FROM PARAMETROS INTO :CD_FILIAL;
  IF (CD_FILIAL = 0) THEN
   BEGIN
      FOR
       SELECT CD_FILIAL FROM FILIAIS WHERE EXPORTAR = 'S' INTO :CD_FILIAL
      DO
       BEGIN
          INSERT INTO DELETADOS VALUES (:CD_FILIAL, 'PLANO_CONTAS',
                                        CAST(CAST(OLD.CD_PLANO_CONTAS AS NUMERIC(15,0)) AS VARCHAR(20)),
                                        CAST(CAST(OLD.CD_PLANO_CONTAS AS NUMERIC(15,0)) AS VARCHAR(20)),
                                        CURRENT_DATE, CURRENT_TIME, NULL, '');
       END
   END
end ^

CREATE TRIGGER PLANO_CONTAS_BIU0 FOR PLANO_CONTAS 
ACTIVE BEFORE INSERT OR UPDATE POSITION 0 
AS
DECLARE VARIABLE CD_FILIAL DOUBLE PRECISION;
DECLARE VARIABLE TIPOLOJA VARCHAR(1);
DECLARE VARIABLE EXISTE INTEGER;
BEGIN
  /* Trigger text */
  NEW.ENVIADO = '';
  SELECT CD_FILIAL, TIPO_LOJA FROM PARAMETROS INTO :CD_FILIAL, :TIPOLOJA;
  IF (:TIPOLOJA = 'M') THEN
   BEGIN
      /* popula TEMP_PRODUTOS na MATRIZ para os produtos que sofreram alteracoes de cadastro*/
      FOR
       SELECT CD_FILIAL FROM FILIAIS WHERE EXPORTAR = 'S' INTO :CD_FILIAL
      DO
        BEGIN
          SELECT COUNT(*) FROM TEMP_PRODUTOS WHERE CD_FILIAL = :CD_FILIAL AND ID_PRODUTO = NEW.CD_PLANO_CONTAS AND PROCESSO = 109 INTO :EXISTE;
          IF (:EXISTE = 0) THEN
             INSERT INTO TEMP_PRODUTOS VALUES (NEW.CD_PLANO_CONTAS, :CD_FILIAL, 109, '');
        END
   END
END ^

CREATE TRIGGER PNC_CLIENTES_EVENTOS_BI0 FOR PNC_CLIENTES_EVENTOS 
ACTIVE BEFORE INSERT OR UPDATE POSITION 0 
AS
DECLARE VARIABLE VIPS INTEGER;
DECLARE VARIABLE VIPTOTAL INTEGER;
DECLARE VARIABLE EXISTE INTEGER;
BEGIN
  SELECT COUNT(*) FROM PNC_EVENTOS_PROMOTORES WHERE ID_EVENTO = NEW.ID_EVENTO AND ID_PROMOTOR = NEW.ID_PROMOTOR INTO :EXISTE;
  IF (:EXISTE = 0) THEN
   BEGIN
     EXCEPTION EXCEPTION_EVENTO_PROMOTOR_1;
   END
  ELSE
   BEGIN
     SELECT VIPS FROM PNC_EVENTOS_PROMOTORES WHERE ID_EVENTO = NEW.ID_EVENTO AND ID_PROMOTOR = NEW.ID_PROMOTOR INTO :VIPS;
     SELECT COUNT(*) FROM PNC_CLIENTES_EVENTOS WHERE ID_EVENTO = NEW.ID_EVENTO AND ID_PROMOTOR = NEW.ID_PROMOTOR AND VIP = 'S' INTO :VIPTOTAL;
     IF (:VIPTOTAL >= :VIPS) THEN
        EXCEPTION EXCEPTION_EVENTO_PROMOTOR;
   END
END ^

CREATE TRIGGER PONTUACAO_BIU0 FOR PONTUACAO 
ACTIVE BEFORE INSERT OR UPDATE POSITION 0 
AS
BEGIN
  NEW.ENVIADO = '';
END ^

CREATE TRIGGER POSICAOESTOQUEDATA_AI0 FOR POSICAOESTOQUEDATA 
ACTIVE AFTER INSERT POSITION 0 
AS
DECLARE VARIABLE TIPOLOJA VARCHAR(1);
BEGIN
