CREATE TRIGGER PRODUTOS_BI0 FOR PRODUTOS 
ACTIVE BEFORE INSERT POSITION 0 
AS
DECLARE VARIABLE CD_FILIAL DOUBLE PRECISION;
DECLARE VARIABLE TIPOLOJA VARCHAR(1);
DECLARE VARIABLE EXISTE INTEGER;
BEGIN
  SELECT TIPO_LOJA FROM PARAMETROS INTO :TIPOLOJA;
  FOR
    SELECT CD_FILIAL FROM FILIAIS INTO :CD_FILIAL
  DO
   BEGIN
     SELECT COUNT(*) FROM PRODUTOS_APP WHERE CD_FILIAL = :CD_FILIAL AND ID_PRODUTO = NEW.ID_PRODUTO AND DATA = CURRENT_DATE INTO :EXISTE;
     IF (:EXISTE = 0) THEN
        INSERT INTO PRODUTOS_APP VALUES (:CD_FILIAL, NEW.ID_PRODUTO, CURRENT_DATE, CURRENT_TIME,  '');
   END
END ^

