      IF (:EXISTE = 0) THEN INSERT INTO PRODUTOS_LOCAL VALUES (NEW.ID_PRODUTO, 0);
   END
  ELSE
   BEGIN
     FOR
      SELECT CD_FILIAL FROM FILIAIS INTO :FILIAL
     DO
      BEGIN
        SELECT COUNT(*) FROM PRODUTOS_TOTAIS WHERE ID_PRODUTO = NEW.ID_PRODUTO AND CD_FILIAL = :FILIAL INTO EXISTE;
