   BEGIN
     SITUACAOTRIBUTARIA = 'T'; /* TRIBUTADO */
   END
  ELSE
  IF (NEW.SITUACAOTRIBUTARIA = '30') THEN  /* ISENTO OU NAO TRIBUTADO */
   BEGIN
     SITUACAOTRIBUTARIA = 'Z';
   END
  ELSE
  IF (NEW.SITUACAOTRIBUTARIA = '40') THEN /* ISENTO */
   BEGIN
     SITUACAOTRIBUTARIA = 'I';
   END
  ELSE
  IF (NEW.SITUACAOTRIBUTARIA = '41') THEN /* NAO TRIBUTADO */
   BEGIN
     SITUACAOTRIBUTARIA = 'N';
   END
  ELSE
  IF (NEW.SITUACAOTRIBUTARIA = '50') THEN /* SUSPENSAO */
   BEGIN
     SITUACAOTRIBUTARIA = 'S';
   END
  ELSE
  IF (NEW.SITUACAOTRIBUTARIA = '51') THEN /* DIFERIMENTO */
   BEGIN
     SITUACAOTRIBUTARIA = 'D';
   END
  ELSE
