   BEGIN
     SITUACAOTRIBUTARIA = 'F';
   END
  ELSE
  IF (NEW.SITUACAOTRIBUTARIA = '90') THEN /* OUTROS */
   BEGIN
     SITUACAOTRIBUTARIA = 'X';
   END

  IF ((NEW.ICMS = 'FF') OR (NEW.ICMS = 'NN') OR (NEW.ICMS = 'II')) THEN
   BEGIN
     ICMS = 0;
   END
  ELSE
   BEGIN
     ICMS = NEW.ICMS;
   END
  SELECT COUNT(*) FROM PRODUTOS_FISCO WHERE CODIGO_BARRAS = NEW.CODIGO_BARRAS_1 INTO :EXISTE; /* TRATANDO CODIGO DE BARRAS 1 */
