                                         NULL, NULL, NULL, NULL, NULL, 'O', NULL, NULL, NULL, NEW.DT_CADASTRO, 'N', 0, NULL, NULL,
                                         NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL,
                                         NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL,
                                         NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL,
                                         NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL,
                                         NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
   END

  FOR
   SELECT CD_FILIAL FROM FILIAIS WHERE EXPORTAR = 'S' INTO :FILIALPRECO
  DO
    BEGIN
      INSERT INTO TEMP_PRODUTOS VALUES (NEW.ID_PRODUTO, :FILIALPRECO, 103, '');
    END
END ^

CREATE TRIGGER TG_ALT_PRODUTOS_APP FOR PRODUTOS 
ACTIVE BEFORE UPDATE POSITION 0 
AS
DECLARE VARIABLE EXISTE INTEGER;
DECLARE VARIABLE FARMACIASAPP VARCHAR(100);
BEGIN
   FARMACIASAPP = '';
   IF ((NEW.ESTOQUE_1 <> OLD.ESTOQUE_1) OR (NEW.PRECO_VENDA_1 <> OLD.PRECO_VENDA_1) OR (NEW.PRECO_PROMOCAO_1 <> OLD.PRECO_PROMOCAO_1)) THEN
    BEGIN
      SELECT FARMACIASAPP_CLIENT_ID FROM FILIAIS WHERE CD_FILIAL = 1 INTO :FARMACIASAPP;
      IF (:FARMACIASAPP <> '') THEN
       BEGIN
          SELECT COUNT(*) FROM PRODUTOS_APP WHERE CD_FILIAL = 1 AND ID_PRODUTO = NEW.ID_PRODUTO AND DATA = CURRENT_DATE INTO :EXISTE;
          IF (:EXISTE = 0) THEN
           BEGIN
             INSERT INTO PRODUTOS_APP VALUES (1, NEW.ID_PRODUTO,  CURRENT_DATE,  CURRENT_TIME, '');
           END
          ELSE
           BEGIN
             UPDATE PRODUTOS_APP SET HORA = CURRENT_TIME , ENVIADO = '' WHERE CD_FILIAL = 1 AND ID_PRODUTO = NEW.ID_PRODUTO AND DATA = CURRENT_DATE;
           END
       END
