CREATE TRIGGER TG_AT_DT_ALTERACAO_PRECO FOR PRODUTOS 
ACTIVE BEFORE UPDATE POSITION 0 
AS
DECLARE VARIABLE FILIAL DOUBLE PRECISION;
DECLARE VARIABLE FILIALLOJA DOUBLE PRECISION;
DECLARE VARIABLE PRECOUNICO VARCHAR(1);
DECLARE VARIABLE TIPOLOJA VARCHAR(1);
DECLARE VARIABLE EXPORTAR VARCHAR(1);
DECLARE VARIABLE EXISTE INTEGER;
DECLARE VARIABLE PRECO NUMERIC(15,2);
DECLARE VARIABLE PRECOANTERIOR NUMERIC(15,2);
DECLARE VARIABLE PRECOPROMOCAO NUMERIC(15,2);
DECLARE VARIABLE PRECOFIDELIDADE NUMERIC(15,2);
BEGIN
  EXISTE = 0;  NEW.DT_ALTERACAO = CURRENT_DATE; --IF (NEW.STATUS = 'I') THEN  EXIT;
  SELECT CD_FILIAL, TIPO_LOJA, PRECIFICACAO_UNICA FROM PARAMETROS INTO :FILIAL, :TIPOLOJA, :PRECOUNICO;
  IF (:TIPOLOJA = 'M') THEN
    BEGIN
      IF ((NEW.PRECO_VENDA <> OLD.PRECO_VENDA) OR (NEW.PRECO_PROMOCAO <> OLD.PRECO_PROMOCAO) OR (NEW.DT_VENCIMENTO_PROMOCAO <> OLD.DT_VENCIMENTO_PROMOCAO)) THEN
       BEGIN
        IF ((NEW.MARGEM_PROMOCAO IS NOT NULL) AND (NEW.MARGEM_PROMOCAO > 0)) THEN
           NEW.PRECO_PROMOCAO = NEW.PRECO_VENDA - ((NEW.PRECO_VENDA * NEW.MARGEM_PROMOCAO) / 100);
        IF (:PRECOUNICO = 'S') THEN
         BEGIN
            FOR SELECT FILIAIS.CD_FILIAL, FILIAIS.EXPORTAR FROM FILIAIS ORDER BY CD_FILIAL INTO :FILIALLOJA, :EXPORTAR DO
             BEGIN
                IF (:EXPORTAR = 'S') THEN
                 BEGIN
                   SELECT COUNT(*) FROM REAJUSTE WHERE CD_FILIAL = :FILIALLOJA AND ID_PRODUTO = NEW.ID_PRODUTO AND DATA = CURRENT_DATE INTO :EXISTE;
                   IF (:EXISTE > 0) THEN UPDATE REAJUSTE SET ENVIADO = '2' WHERE CD_FILIAL = :FILIALLOJA AND ID_PRODUTO = NEW.ID_PRODUTO AND DATA = CURRENT_DATE;
                   IF (NEW.DT_INVENTARIO IS NOT NULL) THEN
                      INSERT INTO REAJUSTE VALUES (:FILIALLOJA, NEW.ID_PRODUTO, CURRENT_DATE, CURRENT_TIME, OLD.PRECO_VENDA, NEW.PRECO_VENDA, OLD.PRECO_PROMOCAO, NEW.PRECO_PROMOCAO, OLD.DT_VENCIMENTO_PROMOCAO , NEW.DT_VENCIMENTO_PROMOCAO, 'N', NEW.DT_INVENTARIO, '', NEW.USUARIO, '');
                   ELSE
                      INSERT INTO REAJUSTE VALUES (:FILIALLOJA, NEW.ID_PRODUTO, CURRENT_DATE, CURRENT_TIME, OLD.PRECO_VENDA, NEW.PRECO_VENDA, OLD.PRECO_PROMOCAO, NEW.PRECO_PROMOCAO, OLD.DT_VENCIMENTO_PROMOCAO , NEW.DT_VENCIMENTO_PROMOCAO, 'S', NULL, '', NEW.USUARIO, '');
                 END
             END
            IF ((NEW.PRECO_VENDA <> OLD.PRECO_VENDA)) THEN
             BEGIN
               FOR
                SELECT CD_FILIAL FROM FILIAIS WHERE EXPORTAR = 'S' INTO :FILIAL
               DO
                BEGIN
                   SELECT PRECO FROM FILIAIS_FIDELIDADE WHERE CD_FILIAL = :FILIAL AND ID_PRODUTO = NEW.ID_PRODUTO INTO :PRECOFIDELIDADE;
                   IF ((:PRECOFIDELIDADE IS NOT NULL) AND (:PRECOFIDELIDADE > NEW.PRECO_VENDA)) THEN
                    BEGIN
                      UPDATE FILIAIS_FIDELIDADE SET PRECO = NEW.PRECO_VENDA WHERE CD_FILIAL = :FILIAL AND ID_PRODUTO = NEW.ID_PRODUTO;
                    END
                END

               PRECO = CAST(NEW.PRECO_VENDA AS NUMERIC(15,2));
               PRECOANTERIOR = CAST(NEW.PRECO_VENDA_ANTERIOR AS NUMERIC(15,2));
               NEW.PRECO_VENDA_1  = :PRECO; NEW.PRECO_VENDA_2  = :PRECO; NEW.PRECO_VENDA_3  = :PRECO; NEW.PRECO_VENDA_4  = :PRECO; NEW.PRECO_VENDA_5  = :PRECO;
               NEW.PRECO_VENDA_6  = :PRECO; NEW.PRECO_VENDA_7  = :PRECO; NEW.PRECO_VENDA_8  = :PRECO; NEW.PRECO_VENDA_9  = :PRECO; NEW.PRECO_VENDA_10 = :PRECO;
               NEW.PRECO_VENDA_11 = :PRECO; NEW.PRECO_VENDA_12 = :PRECO; NEW.PRECO_VENDA_13 = :PRECO; NEW.PRECO_VENDA_14 = :PRECO; NEW.PRECO_VENDA_15 = :PRECO;
               NEW.PRECO_VENDA_16 = :PRECO; NEW.PRECO_VENDA_17 = :PRECO; NEW.PRECO_VENDA_18 = :PRECO; NEW.PRECO_VENDA_19 = :PRECO; NEW.PRECO_VENDA_20 = :PRECO;
               NEW.PRECO_VENDA_21 = :PRECO; NEW.PRECO_VENDA_22 = :PRECO; NEW.PRECO_VENDA_23 = :PRECO; NEW.PRECO_VENDA_24 = :PRECO; NEW.PRECO_VENDA_25 = :PRECO;
               NEW.PRECO_VENDA_26 = :PRECO; NEW.PRECO_VENDA_27 = :PRECO; NEW.PRECO_VENDA_28 = :PRECO; NEW.PRECO_VENDA_29 = :PRECO; NEW.PRECO_VENDA_30 = :PRECO;
               NEW.DT_REAJUSTE = CURRENT_DATE;
               NEW.DT_REAJUSTE_1  = NEW.DT_REAJUSTE; NEW.DT_REAJUSTE_2  = NEW.DT_REAJUSTE; NEW.DT_REAJUSTE_3  = NEW.DT_REAJUSTE; NEW.DT_REAJUSTE_4  = NEW.DT_REAJUSTE; NEW.DT_REAJUSTE_5  = NEW.DT_REAJUSTE;
               NEW.DT_REAJUSTE_6  = NEW.DT_REAJUSTE; NEW.DT_REAJUSTE_7  = NEW.DT_REAJUSTE; NEW.DT_REAJUSTE_8  = NEW.DT_REAJUSTE; NEW.DT_REAJUSTE_9  = NEW.DT_REAJUSTE; NEW.DT_REAJUSTE_10 = NEW.DT_REAJUSTE;
               NEW.DT_REAJUSTE_11 = NEW.DT_REAJUSTE; NEW.DT_REAJUSTE_12 = NEW.DT_REAJUSTE; NEW.DT_REAJUSTE_13 = NEW.DT_REAJUSTE; NEW.DT_REAJUSTE_14 = NEW.DT_REAJUSTE; NEW.DT_REAJUSTE_15 = NEW.DT_REAJUSTE;
               NEW.DT_REAJUSTE_16 = NEW.DT_REAJUSTE; NEW.DT_REAJUSTE_17 = NEW.DT_REAJUSTE; NEW.DT_REAJUSTE_18 = NEW.DT_REAJUSTE; NEW.DT_REAJUSTE_19 = NEW.DT_REAJUSTE; NEW.DT_REAJUSTE_20 = NEW.DT_REAJUSTE;
               NEW.DT_REAJUSTE_21 = NEW.DT_REAJUSTE; NEW.DT_REAJUSTE_22 = NEW.DT_REAJUSTE; NEW.DT_REAJUSTE_23 = NEW.DT_REAJUSTE; NEW.DT_REAJUSTE_24 = NEW.DT_REAJUSTE; NEW.DT_REAJUSTE_25 = NEW.DT_REAJUSTE;
               NEW.DT_REAJUSTE_26 = NEW.DT_REAJUSTE; NEW.DT_REAJUSTE_27 = NEW.DT_REAJUSTE; NEW.DT_REAJUSTE_28 = NEW.DT_REAJUSTE; NEW.DT_REAJUSTE_29 = NEW.DT_REAJUSTE; NEW.DT_REAJUSTE_30 = NEW.DT_REAJUSTE;
               NEW.PRECO_VENDA_ANTERIOR = OLD.PRECO_VENDA;
               NEW.PRECO_VENDA_ANTERIOR_1  = PRECOANTERIOR; NEW.PRECO_VENDA_ANTERIOR_2  = PRECOANTERIOR; NEW.PRECO_VENDA_ANTERIOR_3  = PRECOANTERIOR; NEW.PRECO_VENDA_ANTERIOR_4  = PRECOANTERIOR; NEW.PRECO_VENDA_ANTERIOR_5  = PRECOANTERIOR;
               NEW.PRECO_VENDA_ANTERIOR_6  = PRECOANTERIOR; NEW.PRECO_VENDA_ANTERIOR_7  = PRECOANTERIOR; NEW.PRECO_VENDA_ANTERIOR_8  = PRECOANTERIOR; NEW.PRECO_VENDA_ANTERIOR_9  = PRECOANTERIOR; NEW.PRECO_VENDA_ANTERIOR_10 = PRECOANTERIOR;
               NEW.PRECO_VENDA_ANTERIOR_11 = PRECOANTERIOR; NEW.PRECO_VENDA_ANTERIOR_12 = PRECOANTERIOR; NEW.PRECO_VENDA_ANTERIOR_13 = PRECOANTERIOR; NEW.PRECO_VENDA_ANTERIOR_14 = PRECOANTERIOR; NEW.PRECO_VENDA_ANTERIOR_15 = PRECOANTERIOR;
               NEW.PRECO_VENDA_ANTERIOR_16 = PRECOANTERIOR; NEW.PRECO_VENDA_ANTERIOR_17 = PRECOANTERIOR; NEW.PRECO_VENDA_ANTERIOR_18 = PRECOANTERIOR; NEW.PRECO_VENDA_ANTERIOR_19 = PRECOANTERIOR; NEW.PRECO_VENDA_ANTERIOR_20 = PRECOANTERIOR;
               NEW.PRECO_VENDA_ANTERIOR_21 = PRECOANTERIOR; NEW.PRECO_VENDA_ANTERIOR_22 = PRECOANTERIOR; NEW.PRECO_VENDA_ANTERIOR_23 = PRECOANTERIOR; NEW.PRECO_VENDA_ANTERIOR_24 = PRECOANTERIOR; NEW.PRECO_VENDA_ANTERIOR_25 = PRECOANTERIOR;
               NEW.PRECO_VENDA_ANTERIOR_26 = PRECOANTERIOR; NEW.PRECO_VENDA_ANTERIOR_27 = PRECOANTERIOR; NEW.PRECO_VENDA_ANTERIOR_28 = PRECOANTERIOR; NEW.PRECO_VENDA_ANTERIOR_29 = PRECOANTERIOR; NEW.PRECO_VENDA_ANTERIOR_30 = PRECOANTERIOR;
             END
            IF ((NEW.PRECO_PROMOCAO <> OLD.PRECO_PROMOCAO)) THEN
             BEGIN
               PRECOPROMOCAO = CAST(NEW.PRECO_PROMOCAO AS NUMERIC(15, 2));
               NEW.PRECO_PROMOCAO_1  = PRECOPROMOCAO; NEW.PRECO_PROMOCAO_2  = PRECOPROMOCAO; NEW.PRECO_PROMOCAO_3  = PRECOPROMOCAO; NEW.PRECO_PROMOCAO_4  = PRECOPROMOCAO; NEW.PRECO_PROMOCAO_5  = PRECOPROMOCAO;
               NEW.PRECO_PROMOCAO_6  = PRECOPROMOCAO; NEW.PRECO_PROMOCAO_7  = PRECOPROMOCAO; NEW.PRECO_PROMOCAO_8  = PRECOPROMOCAO; NEW.PRECO_PROMOCAO_9  = PRECOPROMOCAO; NEW.PRECO_PROMOCAO_10 = PRECOPROMOCAO;
               NEW.PRECO_PROMOCAO_11 = PRECOPROMOCAO; NEW.PRECO_PROMOCAO_12 = PRECOPROMOCAO; NEW.PRECO_PROMOCAO_13 = PRECOPROMOCAO; NEW.PRECO_PROMOCAO_14 = PRECOPROMOCAO; NEW.PRECO_PROMOCAO_15 = PRECOPROMOCAO;
               NEW.PRECO_PROMOCAO_16 = PRECOPROMOCAO; NEW.PRECO_PROMOCAO_17 = PRECOPROMOCAO; NEW.PRECO_PROMOCAO_18 = PRECOPROMOCAO; NEW.PRECO_PROMOCAO_19 = PRECOPROMOCAO; NEW.PRECO_PROMOCAO_20 = PRECOPROMOCAO;
               NEW.PRECO_PROMOCAO_21 = PRECOPROMOCAO; NEW.PRECO_PROMOCAO_22 = PRECOPROMOCAO; NEW.PRECO_PROMOCAO_23 = PRECOPROMOCAO; NEW.PRECO_PROMOCAO_24 = PRECOPROMOCAO; NEW.PRECO_PROMOCAO_25 = PRECOPROMOCAO;
