CREATE TRIGGER TG_AT_DT_ALTERACAO_PRECO2 FOR PRODUTOS 
ACTIVE BEFORE UPDATE POSITION 0 
AS
DECLARE VARIABLE FILIAL DOUBLE PRECISION;
DECLARE VARIABLE PRECOUNICO VARCHAR(1);
DECLARE VARIABLE TIPOLOJA VARCHAR(1);
DECLARE VARIABLE PRECOFIDELIDADE NUMERIC(15,2);
BEGIN
  --IF (NEW.STATUS = 'I') THEN EXIT;

  SELECT CD_FILIAL, TIPO_LOJA, PRECIFICACAO_UNICA FROM PARAMETROS INTO :FILIAL, :TIPOLOJA, :PRECOUNICO;
  /* VERIFICA SE HOUVE ALTERACAO DE PRECOS NA FILIAL E CASO NAO SEJA LOJA UNICA E POPULA TEMP_PRODUTOS COM O PROCESSO 52 (ENVIO DE PRECOS PARA A MATRIZ) */
  IF (:FILIAL <> 0) THEN
   BEGIN
        IF ((NEW.PRECO_VENDA <> OLD.PRECO_VENDA) OR
           (NEW.PRECO_VENDA_1 <> OLD.PRECO_VENDA_1) OR (NEW.PRECO_VENDA_2 <> OLD.PRECO_VENDA_2) OR
           (NEW.PRECO_VENDA_3 <> OLD.PRECO_VENDA_3) OR (NEW.PRECO_VENDA_4 <> OLD.PRECO_VENDA_4) OR
           (NEW.PRECO_VENDA_5 <> OLD.PRECO_VENDA_5) OR (NEW.PRECO_VENDA_6 <> OLD.PRECO_VENDA_6) OR
           (NEW.PRECO_VENDA_7 <> OLD.PRECO_VENDA_7) OR (NEW.PRECO_VENDA_8 <> OLD.PRECO_VENDA_8) OR
           (NEW.PRECO_VENDA_9 <> OLD.PRECO_VENDA_9) OR (NEW.PRECO_VENDA_10 <> OLD.PRECO_VENDA_10) OR
           (NEW.PRECO_VENDA_11 <> OLD.PRECO_VENDA_11) OR (NEW.PRECO_VENDA_12 <> OLD.PRECO_VENDA_12) OR
           (NEW.PRECO_VENDA_13 <> OLD.PRECO_VENDA_13) OR (NEW.PRECO_VENDA_14 <> OLD.PRECO_VENDA_14) OR
           (NEW.PRECO_VENDA_15 <> OLD.PRECO_VENDA_15) OR (NEW.PRECO_VENDA_16 <> OLD.PRECO_VENDA_16) OR
           (NEW.PRECO_VENDA_17 <> OLD.PRECO_VENDA_17) OR (NEW.PRECO_VENDA_18 <> OLD.PRECO_VENDA_18) OR
           (NEW.PRECO_VENDA_19 <> OLD.PRECO_VENDA_19) OR (NEW.PRECO_VENDA_20 <> OLD.PRECO_VENDA_20) OR
           (NEW.PRECO_VENDA_21 <> OLD.PRECO_VENDA_21) OR (NEW.PRECO_VENDA_22 <> OLD.PRECO_VENDA_22) OR
           (NEW.PRECO_VENDA_23 <> OLD.PRECO_VENDA_23) OR (NEW.PRECO_VENDA_24 <> OLD.PRECO_VENDA_24) OR
           (NEW.PRECO_VENDA_25 <> OLD.PRECO_VENDA_25) OR (NEW.PRECO_VENDA_26 <> OLD.PRECO_VENDA_26) OR
           (NEW.PRECO_VENDA_27 <> OLD.PRECO_VENDA_27) OR (NEW.PRECO_VENDA_28 <> OLD.PRECO_VENDA_28) OR
           (NEW.PRECO_VENDA_29 <> OLD.PRECO_VENDA_29) OR (NEW.PRECO_VENDA_30 <> OLD.PRECO_VENDA_30) OR
           (NEW.PRECO_PROMOCAO <> OLD.PRECO_PROMOCAO) OR
           (NEW.PRECO_PROMOCAO_1 <> OLD.PRECO_PROMOCAO_1) OR (NEW.PRECO_PROMOCAO_2 <> OLD.PRECO_PROMOCAO_2) OR
