CREATE TRIGGER TG_AT_DT_ALTERACAO_PRODUTO FOR PRODUTOS 
ACTIVE BEFORE UPDATE POSITION 0 
AS
DECLARE VARIABLE FILIAL DOUBLE PRECISION;
DECLARE VARIABLE FILIALPRECO DOUBLE PRECISION;
DECLARE VARIABLE PRECOUNICO VARCHAR(1);
DECLARE VARIABLE TIPOLOJA VARCHAR(1);
DECLARE VARIABLE NUMERO INTEGER;
DECLARE VARIABLE FILIALEXCLUSAO DOUBLE PRECISION;
BEGIN
  NEW.ENVIADO = '';
  NEW.DT_ALTERACAO = CURRENT_DATE;
  --IF (NEW.STATUS = 'I') THEN EXIT;
  IF ((NEW.QT_EMBALAGEM IS NULL) OR (NEW.QT_EMBALAGEM = 0)) THEN
     NEW.QT_EMBALAGEM = 1;

  /* BUSCA EM PARAMETROS O CODIGO DA FILIAL E PARAMETRO DE PRECO UNICO */
  SELECT CD_FILIAL, TIPO_LOJA, PRECIFICACAO_UNICA FROM PARAMETROS INTO :FILIAL, :TIPOLOJA, :PRECOUNICO;

  /* VERIFICA SE HOUVE ALTERACOES DE CADASTRO E POPULA TEMP_PRODUTOS NA MATRIZ COM PROCESSO 119 */
  IF (:TIPOLOJA = 'M') THEN
    BEGIN
      IF (NEW.STATUS = 'I') THEN
       BEGIN
         DELETE FROM FILIAIS_FIDELIDADE WHERE ID_PRODUTO = NEW.ID_PRODUTO;
       END

      IF (  (NEW.ESTOQUE_1  <> OLD.ESTOQUE_1) OR
            (NEW.ESTOQUE_2  <> OLD.ESTOQUE_2) OR
            (NEW.ESTOQUE_3  <> OLD.ESTOQUE_3) OR
            (NEW.ESTOQUE_4  <> OLD.ESTOQUE_4) OR
            (NEW.ESTOQUE_5  <> OLD.ESTOQUE_5) OR
            (NEW.ESTOQUE_6  <> OLD.ESTOQUE_6) OR
            (NEW.ESTOQUE_7  <> OLD.ESTOQUE_7) OR
            (NEW.ESTOQUE_8  <> OLD.ESTOQUE_8) OR
            (NEW.ESTOQUE_9  <> OLD.ESTOQUE_9) OR
            (NEW.ESTOQUE_10 <> OLD.ESTOQUE_10) OR
            (NEW.ESTOQUE_11 <> OLD.ESTOQUE_11) OR
            (NEW.ESTOQUE_12 <> OLD.ESTOQUE_12) OR
            (NEW.ESTOQUE_13 <> OLD.ESTOQUE_13) OR
            (NEW.ESTOQUE_14 <> OLD.ESTOQUE_14) OR
            (NEW.ESTOQUE_15 <> OLD.ESTOQUE_15) OR
            (NEW.ESTOQUE_16 <> OLD.ESTOQUE_16) OR
            (NEW.ESTOQUE_17 <> OLD.ESTOQUE_17) OR
            (NEW.ESTOQUE_18 <> OLD.ESTOQUE_18) OR
            (NEW.ESTOQUE_19 <> OLD.ESTOQUE_19) OR
            (NEW.ESTOQUE_20 <> OLD.ESTOQUE_20) OR
            (NEW.ESTOQUE_21 <> OLD.ESTOQUE_21) OR
            (NEW.ESTOQUE_22 <> OLD.ESTOQUE_22) OR
            (NEW.ESTOQUE_23 <> OLD.ESTOQUE_23) OR
            (NEW.ESTOQUE_24 <> OLD.ESTOQUE_24) OR
            (NEW.ESTOQUE_25 <> OLD.ESTOQUE_25) OR
            (NEW.ESTOQUE_26 <> OLD.ESTOQUE_26) OR
            (NEW.ESTOQUE_27 <> OLD.ESTOQUE_27) OR
            (NEW.ESTOQUE_28 <> OLD.ESTOQUE_28) OR
            (NEW.ESTOQUE_29 <> OLD.ESTOQUE_29) OR
            (NEW.ESTOQUE_30 <> OLD.ESTOQUE_30)) THEN
       BEGIN
           IF (NEW.ESTOQUE_1 <> OLD.ESTOQUE_1) THEN FILIALEXCLUSAO = 1;
           IF (NEW.ESTOQUE_2 <> OLD.ESTOQUE_2) THEN FILIALEXCLUSAO = 2;
           IF (NEW.ESTOQUE_3 <> OLD.ESTOQUE_3) THEN FILIALEXCLUSAO = 3;
           IF (NEW.ESTOQUE_4 <> OLD.ESTOQUE_4) THEN FILIALEXCLUSAO = 4;
           IF (NEW.ESTOQUE_5 <> OLD.ESTOQUE_5) THEN FILIALEXCLUSAO = 5;
           IF (NEW.ESTOQUE_6 <> OLD.ESTOQUE_6) THEN FILIALEXCLUSAO = 6;
           IF (NEW.ESTOQUE_7 <> OLD.ESTOQUE_7) THEN FILIALEXCLUSAO = 7;
           IF (NEW.ESTOQUE_8 <> OLD.ESTOQUE_8) THEN FILIALEXCLUSAO = 8;
           IF (NEW.ESTOQUE_9 <> OLD.ESTOQUE_9) THEN FILIALEXCLUSAO = 9;
           IF (NEW.ESTOQUE_10 <> OLD.ESTOQUE_10) THEN FILIALEXCLUSAO = 10;
           IF (NEW.ESTOQUE_11 <> OLD.ESTOQUE_11) THEN FILIALEXCLUSAO = 11;
           IF (NEW.ESTOQUE_12 <> OLD.ESTOQUE_12) THEN FILIALEXCLUSAO = 12;
           IF (NEW.ESTOQUE_13 <> OLD.ESTOQUE_13) THEN FILIALEXCLUSAO = 13;
           IF (NEW.ESTOQUE_14 <> OLD.ESTOQUE_14) THEN FILIALEXCLUSAO = 14;
           IF (NEW.ESTOQUE_15 <> OLD.ESTOQUE_15) THEN FILIALEXCLUSAO = 15;
           IF (NEW.ESTOQUE_16 <> OLD.ESTOQUE_16) THEN FILIALEXCLUSAO = 16;
           IF (NEW.ESTOQUE_17 <> OLD.ESTOQUE_17) THEN FILIALEXCLUSAO = 17;
           IF (NEW.ESTOQUE_18 <> OLD.ESTOQUE_18) THEN FILIALEXCLUSAO = 18;
           IF (NEW.ESTOQUE_19 <> OLD.ESTOQUE_19) THEN FILIALEXCLUSAO = 19;
           IF (NEW.ESTOQUE_20 <> OLD.ESTOQUE_20) THEN FILIALEXCLUSAO = 20;
           IF (NEW.ESTOQUE_21 <> OLD.ESTOQUE_21) THEN FILIALEXCLUSAO = 21;
           IF (NEW.ESTOQUE_22 <> OLD.ESTOQUE_22) THEN FILIALEXCLUSAO = 22;
           IF (NEW.ESTOQUE_23 <> OLD.ESTOQUE_23) THEN FILIALEXCLUSAO = 23;
           IF (NEW.ESTOQUE_24 <> OLD.ESTOQUE_24) THEN FILIALEXCLUSAO = 24;
           IF (NEW.ESTOQUE_25 <> OLD.ESTOQUE_25) THEN FILIALEXCLUSAO = 25;
           IF (NEW.ESTOQUE_26 <> OLD.ESTOQUE_26) THEN FILIALEXCLUSAO = 26;
           IF (NEW.ESTOQUE_27 <> OLD.ESTOQUE_27) THEN FILIALEXCLUSAO = 27;
           IF (NEW.ESTOQUE_28 <> OLD.ESTOQUE_28) THEN FILIALEXCLUSAO = 28;
           IF (NEW.ESTOQUE_29 <> OLD.ESTOQUE_29) THEN FILIALEXCLUSAO = 29;
           IF (NEW.ESTOQUE_30 <> OLD.ESTOQUE_30) THEN FILIALEXCLUSAO = 30;

           FOR
            SELECT CD_FILIAL FROM FILIAIS WHERE EXPORTAR = 'S' AND CD_FILIAL <> :FILIALEXCLUSAO INTO :FILIALPRECO
           DO
             BEGIN
               SELECT COUNT(ID_PRODUTO) FROM TEMP_PRODUTOS
               WHERE CD_FILIAL = :FILIALPRECO AND ID_PRODUTO = NEW.ID_PRODUTO AND PROCESSO = 1191 INTO :NUMERO;
               IF (:NUMERO = 0) THEN
                  INSERT INTO TEMP_PRODUTOS VALUES (NEW.ID_PRODUTO, :FILIALPRECO, 1191, '');
             END
       END

      IF (  (NEW.CD_LABORATORIO           <> OLD.CD_LABORATORIO) OR
            (NEW.CD_GRUPO                 <> OLD.CD_GRUPO) OR
            (NEW.CD_SUBGRUPO              <> OLD.CD_SUBGRUPO) OR
            (NEW.CD_CLASSE                <> OLD.CD_CLASSE) OR
            (NEW.CD_LISTA                 <> OLD.CD_LISTA) OR
