                      SELECT COUNT(ID_PRODUTO) FROM TEMP_PRODUTOS
                      WHERE CD_FILIAL = :FILIALPRECO AND ID_PRODUTO = NEW.ID_PRODUTO AND PROCESSO = 119 INTO :NUMERO;
                      IF (:NUMERO = 0) THEN
                         INSERT INTO TEMP_PRODUTOS VALUES (NEW.ID_PRODUTO, :FILIALPRECO, 119, '');
                    END
               END
    END
   ELSE
