       BEGIN
         UPDATE PRODUTOS_FISCO SET CODIGO_BARRAS = NEW.CODIGO_BARRAS_1 WHERE ID_PRODUTO = NEW.ID_PRODUTO AND CODIGO_BARRAS = OLD.CODIGO_BARRAS_1;
       END
      IF (NEW.DESCRICAO <> OLD.DESCRICAO) THEN
       BEGIN
         UPDATE PRODUTOS_FISCO SET DESCRICAO = NEW.DESCRICAO WHERE ID_PRODUTO = NEW.ID_PRODUTO;
       END
    END
END ^

