CREATE TRIGGER TG_EXC_PRODUTOS FOR PRODUTOS 
ACTIVE BEFORE DELETE POSITION 0 
AS
DECLARE VARIABLE CD_FILIAL DOUBLE PRECISION;
BEGIN
  INSERT INTO PRODUTOSDELETADOS VALUES (OLD.ID_PRODUTO,  OLD.DESCRICAO);
  DELETE FROM PROD_DISTR WHERE PROD_DISTR.ID_PRODUTO = OLD.ID_PRODUTO;
  DELETE FROM PRODUTOS_COMPOSTOS WHERE (ID_PRODUTO_PRINCIPAL = OLD.ID_PRODUTO) OR (ID_PRODUTO_COMPOSICAO = OLD.ID_PRODUTO);
  DELETE FROM PRODUTOS_IMPOSTOS WHERE ID_PRODUTO = OLD.ID_PRODUTO;
  DELETE FROM PRODUTOS_LOCAL WHERE ID_PRODUTO = OLD.ID_PRODUTO;
  DELETE FROM PRODUTOS_LOTES WHERE ID_PRODUTO = OLD.ID_PRODUTO;
  DELETE FROM PRODUTOS_RELACIONADOS WHERE (ID_PRODUTO_RELACIONADO = OLD.ID_PRODUTO) OR (ID_PRODUTO = OLD.ID_PRODUTO);
  DELETE FROM PRODUTOS_TOTAIS WHERE ID_PRODUTO = OLD.ID_PRODUTO;
  DELETE FROM FILIAIS_FIDELIDADE WHERE ID_PRODUTO = OLD.ID_PRODUTO;
  DELETE FROM PRODUTOS_FIDELIDADE WHERE ID_PRODUTO = OLD.ID_PRODUTO;
  DELETE FROM PRODUTOS_FARMACIA_POPULAR WHERE ID_PRODUTO = OLD.ID_PRODUTO;
  DELETE FROM PRODUTOS_FISCO WHERE ID_PRODUTO = OLD.ID_PRODUTO;
  DELETE FROM PRODUTOS_PRECO_QUANTIDADE WHERE ID_PRODUTO = OLD.ID_PRODUTO;
  DELETE FROM FILIAIS_PRECO_QUANTIDADE WHERE ID_PRODUTO = OLD.ID_PRODUTO;

  SELECT CD_FILIAL FROM PARAMETROS INTO :CD_FILIAL;
  IF (:CD_FILIAL = 0) THEN
   BEGIN
     FOR
      SELECT CD_FILIAL FROM FILIAIS WHERE EXPORTAR = 'S' INTO :CD_FILIAL
     DO
      BEGIN
         INSERT INTO DELETADOS VALUES (:CD_FILIAL, 'PRODUTOS',OLD.CD_PRODUTO, CAST(CAST(OLD.ID_PRODUTO AS NUMERIC(15,0)) AS VARCHAR(20)), CURRENT_DATE, CURRENT_TIME, NULL, '');
      END
   END
END ^

CREATE TRIGGER PRODUTOS_COMPOSTOS_BD0 FOR PRODUTOS_COMPOSTOS 
ACTIVE BEFORE DELETE POSITION 0 
AS
DECLARE VARIABLE CD_FILIAL DOUBLE PRECISION;
DECLARE VARIABLE TIPOLOJA VARCHAR(1);
BEGIN
  SELECT CD_FILIAL, TIPO_LOJA FROM PARAMETROS INTO :CD_FILIAL, :TIPOLOJA;
  IF ((CD_FILIAL = 0) AND (:TIPOLOJA <> 'U')) THEN
   BEGIN
      FOR
       SELECT CD_FILIAL FROM FILIAIS WHERE EXPORTAR = 'S' INTO :CD_FILIAL
      DO
       BEGIN
         INSERT INTO DELETADOS VALUES (:CD_FILIAL, 'PRODUTOS_COMPOSTOS',
                                       CAST(CAST(OLD.ID_PRODUTO_PRINCIPAL AS NUMERIC(15,0)) AS VARCHAR(20)),
                                       CAST(CAST(OLD.ID_PRODUTO_COMPOSICAO AS NUMERIC(15,0)) AS VARCHAR(20)),
                                       CURRENT_DATE, CURRENT_TIME, NULL, '');
       END
   END
end ^

CREATE TRIGGER PRODUTOS_COMPOSTOS_BI0 FOR PRODUTOS_COMPOSTOS 
ACTIVE BEFORE INSERT OR UPDATE POSITION 0 
AS
DECLARE VARIABLE CD_FILIAL DOUBLE PRECISION;
DECLARE VARIABLE TIPO_LOJA VARCHAR(1);
DECLARE VARIABLE EXISTE INTEGER;
BEGIN
  NEW.ENVIADO = '';
  SELECT TIPO_LOJA FROM PARAMETROS INTO :TIPO_LOJA;
  IF (:TIPO_LOJA = 'M') THEN
   BEGIN
      FOR
        SELECT CD_FILIAL FROM FILIAIS WHERE EXPORTAR = 'S' INTO :CD_FILIAL
      DO
       BEGIN
          SELECT COUNT(*) FROM TEMP_PRODUTOS_COMPOSTOS
          WHERE ID_PRODUTO_PRINCIPAL = NEW.ID_PRODUTO_PRINCIPAL AND
                ID_PRODUTO_COMPOSICAO = NEW.ID_PRODUTO_COMPOSICAO AND
                CD_FILIAL = :CD_FILIAL
          INTO :EXISTE;
          IF (:EXISTE = 0) THEN
           BEGIN
             INSERT INTO TEMP_PRODUTOS_COMPOSTOS VALUES (NEW.ID_PRODUTO_PRINCIPAL, NEW.ID_PRODUTO_COMPOSICAO, :CD_FILIAL, 162, ' ');
           END
       END
   END
END ^

CREATE TRIGGER PRODUTOS_CONVENIOS_PBM_BD0 FOR PRODUTOS_CONVENIOS_PBM 
ACTIVE BEFORE DELETE POSITION 0 
AS
DECLARE VARIABLE CD_FILIAL DOUBLE PRECISION;
BEGIN
  SELECT CD_FILIAL FROM PARAMETROS INTO :CD_FILIAL;
  IF (CD_FILIAL = 0) THEN
   BEGIN
      FOR
       SELECT CD_FILIAL FROM FILIAIS WHERE EXPORTAR = 'S' INTO :CD_FILIAL
      DO
       BEGIN
          INSERT INTO DELETADOS VALUES (:CD_FILIAL, 'PRODUTOS_CONVENIOS_PBM',
                                        CAST(CAST(OLD.ID_PRODUTOSCONVENIOPBM AS NUMERIC(15,0)) AS VARCHAR(20)),
                                        CAST(CAST(OLD.ID_CONVENIOPBM AS NUMERIC(15,0)) AS VARCHAR(20)),
                                        CURRENT_DATE, CURRENT_TIME, NULL, '');
       END
   END
END ^

CREATE TRIGGER PRODUTOS_CONVENIOS_PBM_BU0 FOR PRODUTOS_CONVENIOS_PBM 
ACTIVE BEFORE INSERT OR UPDATE POSITION 0 
AS
DECLARE VARIABLE CD_FILIAL DOUBLE PRECISION;
DECLARE VARIABLE EXISTE INTEGER;
BEGIN
  FOR
    SELECT CD_FILIAL FROM FILIAIS WHERE EXPORTAR = 'S' INTO :CD_FILIAL
  DO
   BEGIN
     EXISTE = 0;
     SELECT COUNT(*) FROM TEMP_PRODUTOS WHERE ID_PRODUTO = NEW.ID_PRODUTOSCONVENIOPBM AND CD_FILIAL = :CD_FILIAL AND PROCESSO = 138 INTO :EXISTE;
