CREATE TRIGGER PRODUTOS_SITE_BU0 FOR PRODUTOS_SITE 
ACTIVE BEFORE INSERT OR UPDATE POSITION 0 
AS
DECLARE VARIABLE EXISTE INTEGER;
DECLARE VARIABLE CD_FILIAL DOUBLE PRECISION;
DECLARE VARIABLE RECEITA VARCHAR(1);
BEGIN
  SELECT CONTROLADO FROM PRODUTOS WHERE ID_PRODUTO = NEW.ID_PRODUTO INTO :RECEITA;
  IF (:RECEITA IS NULL) THEN
   BEGIN
     RECEITA = 'N';
   END
  NEW.RECEITA = :RECEITA;

  SELECT CD_FILIAL FROM PARAMETROS INTO :CD_FILIAL;
  SELECT COUNT(*) FROM PRODUTOS_APP WHERE CD_FILIAL = :CD_FILIAL AND ID_PRODUTO = NEW.ID_PRODUTO AND DATA = CURRENT_DATE INTO :EXISTE;
  IF (:EXISTE = 0) THEN
   BEGIN
     INSERT INTO PRODUTOS_APP VALUES (:CD_FILIAL, NEW.ID_PRODUTO, CURRENT_DATE, CURRENT_TIME,  '');
   END
  ELSE
   BEGIN
     UPDATE PRODUTOS_APP SET HORA = CURRENT_TIME,  ENVIADO = '' WHERE CD_FILIAL = :CD_FILIAL AND ID_PRODUTO = NEW.ID_PRODUTO AND DATA = CURRENT_DATE;
   END
END ^

