CREATE TRIGGER TG_AT_ENVIADO_TRANSFER FOR TRANSFER 
ACTIVE BEFORE INSERT OR UPDATE POSITION 0 
AS
DECLARE VARIABLE CD_FILIAL DOUBLE PRECISION;
BEGIN
  SELECT CD_FILIAL FROM PARAMETROS INTO :CD_FILIAL;
  IF (:CD_FILIAL = 0) THEN
     NEW.ENVIADO = ' ';
  ELSE
   BEGIN
     IF (((:CD_FILIAL = NEW.CD_FILIAL_DESTINO) AND ((NEW.STATUS = 'G') OR (NEW.STATUS = 'C'))) OR
         ((:CD_FILIAL = NEW.CD_FILIAL_ORIGEM) AND (NEW.STATUS = 'E')) OR
         ((:CD_FILIAL = 0) OR ((:CD_FILIAL = NEW.CD_FILIAL_DESTINO) AND (NEW.STATUS = 'X'))))  THEN
        NEW.ENVIADO = ' ';
     ELSE
        NEW.ENVIADO = '2';
   END
END ^

